const RELATIONSHIP_TRACE_ENABLED = false;
let relationshipTraceSeq = 0;
let relationshipActiveTrace = null;
let relationshipReconcileTrace = null;

function relationshipNow() {
  try {
    if (typeof performance !== "undefined" && typeof performance.now === "function") {
      return performance.now();
    }
  } catch (_) {}
  return Date.now();
}

function beginRelationshipTrace(action = "relationship", meta = {}) {
  if (!RELATIONSHIP_TRACE_ENABLED) return null;
  const id = ++relationshipTraceSeq;
  const safeAction = String(action || "relationship").trim() || "relationship";
  const baseLabel = `[relationship:${id}] ${safeAction}`;
  const trace = {
    id,
    action: safeAction,
    baseLabel,
    startedAt: relationshipNow(),
    ended: false,
    deferEnd: false,
  };
  try { console.groupCollapsed(baseLabel); } catch (_) {}
  try { console.time(`${baseLabel} total`); } catch (_) {}
  try { console.log(`${baseLabel} meta`, meta || {}); } catch (_) {}
  return trace;
}

function setRelationshipActiveTrace(trace = null) {
  relationshipActiveTrace = trace || null;
}

function beginRelationshipActionTrace(action = "relationship", meta = {}) {
  const trace = beginRelationshipTrace(action, meta);
  if (trace) setRelationshipActiveTrace(trace);
  relationshipTraceLog(trace, "handler:start", meta || {});
  return trace;
}

function getRelationshipCurrentTrace() {
  return relationshipActiveTrace || relationshipReconcileTrace || null;
}

function relationshipTracePhaseLabel(trace, phase = "") {
  if (!trace) return "";
  return `${trace.baseLabel} :: ${String(phase || "phase").trim() || "phase"}`;
}

function relationshipTraceLog(trace, phase, meta = null) {
  if (!trace || trace.ended) return;
  try {
    if (meta === null || typeof meta === "undefined") console.log(`${trace.baseLabel} ${phase}`);
    else console.log(`${trace.baseLabel} ${phase}`, meta);
  } catch (_) {}
}

function relationshipTracePhaseStart(trace, phase, meta = null) {
  if (!trace || trace.ended) return "";
  const label = relationshipTracePhaseLabel(trace, phase);
  try { console.time(label); } catch (_) {}
  if (meta !== null && typeof meta !== "undefined") relationshipTraceLog(trace, `${phase}:start`, meta);
  return label;
}

function relationshipTracePhaseEnd(trace, label, meta = null) {
  if (!trace || !label || trace.ended) return;
  try { console.timeEnd(label); } catch (_) {}
  if (meta !== null && typeof meta !== "undefined") relationshipTraceLog(trace, `${label.split(" :: ").pop()}:end`, meta);
}

function relationshipTraceMeasureSync(trace, phase, fn, meta = null) {
  if (!trace || trace.ended) return fn();
  const label = relationshipTracePhaseStart(trace, phase, meta);
  try {
    return fn();
  } finally {
    relationshipTracePhaseEnd(trace, label);
  }
}

async function relationshipTraceMeasureAsync(trace, phase, fn, meta = null) {
  if (!trace || trace.ended) return await fn();
  const label = relationshipTracePhaseStart(trace, phase, meta);
  try {
    return await fn();
  } finally {
    relationshipTracePhaseEnd(trace, label);
  }
}

function relationshipTraceSchedulePaint(trace, label = "paint") {
  if (!trace || trace.ended) return;
  const startedAt = relationshipNow();
  requestAnimationFrame(() => {
    relationshipTraceLog(trace, `${label}:raf1`, {
      ms: Number((relationshipNow() - startedAt).toFixed(2)),
    });
    requestAnimationFrame(() => {
      relationshipTraceLog(trace, `${label}:raf2`, {
        ms: Number((relationshipNow() - startedAt).toFixed(2)),
      });
    });
  });
}

function endRelationshipTrace(trace, outcome = "done", meta = null) {
  if (!trace || trace.ended) return;
  trace.ended = true;
  const payload = {
    outcome,
    totalMs: Number((relationshipNow() - Number(trace.startedAt || 0)).toFixed(2)),
    ...(meta && typeof meta === "object" ? meta : {}),
  };
  try { console.log(`${trace.baseLabel} result`, payload); } catch (_) {}
  try { console.timeEnd(`${trace.baseLabel} total`); } catch (_) {}
  try { console.groupEnd(); } catch (_) {}
  if (relationshipActiveTrace === trace) relationshipActiveTrace = null;
  if (relationshipReconcileTrace === trace) relationshipReconcileTrace = null;
}

function deferRelationshipTraceToReconcile(trace, meta = null) {
  if (!trace || trace.ended) return;
  trace.deferEnd = true;
  if (relationshipActiveTrace === trace) relationshipActiveTrace = null;
  relationshipTraceLog(trace, "reconcile:scheduled", meta || {});
}

