let authAccessToken = "";
let unloadSignalDispatched = false;

function setAuthAccessToken(token) {
  authAccessToken = String(token || "").trim();
}

function readAuthSessionFromStorage() {
  try {
    const supaHost = new URL(SUPABASE_URL).host || "";
    const ref = supaHost.split(".")[0] || "";
    const keys = Object.keys(localStorage || {});
    for (const key of keys) {
      if (!key.includes("-auth-token")) continue;
      if (ref && !key.includes(ref)) continue;
      const raw = localStorage.getItem(key);
      if (!raw) continue;
      let parsed = null;
      try { parsed = JSON.parse(raw); } catch (_) {}
      const arrayAccessToken = Array.isArray(parsed)
        ? (
          parsed?.[0]?.access_token
          || parsed?.[1]?.access_token
          || (typeof parsed?.[0] === "string" ? parsed[0] : "")
        )
        : "";
      const arrayRefreshToken = Array.isArray(parsed)
        ? (
          parsed?.[0]?.refresh_token
          || parsed?.[1]?.refresh_token
          || (typeof parsed?.[1] === "string" ? parsed[1] : "")
        )
        : "";
      const accessToken = String(
        parsed?.access_token
        || parsed?.currentSession?.access_token
        || parsed?.session?.access_token
        || parsed?.data?.session?.access_token
        || arrayAccessToken
        || ""
      ).trim();
      const refreshToken = String(
        parsed?.refresh_token
        || parsed?.currentSession?.refresh_token
        || parsed?.session?.refresh_token
        || parsed?.data?.session?.refresh_token
        || arrayRefreshToken
        || ""
      ).trim();
      const userId = String(
        parsed?.user?.id
        || parsed?.currentSession?.user?.id
        || parsed?.session?.user?.id
        || parsed?.data?.session?.user?.id
        || parsed?.user_id
        || parsed?.sub
        || ""
      ).trim();
      if (!accessToken && !refreshToken && !userId) continue;
      return {
        storageKey: key,
        accessToken,
        refreshToken,
        userId,
      };
    }
  } catch (_) {}
  return null;
}

function readAuthTokenFromStorage() {
  return readAuthSessionFromStorage()?.accessToken || "";
}

function getAuthTokenForKeepAlive() {
  if (authAccessToken) return authAccessToken;
  const fromStorage = readAuthTokenFromStorage();
  if (fromStorage) {
    authAccessToken = fromStorage;
    return fromStorage;
  }
  return "";
}

async function primeAuthTokenCache() {
  try {
    const { data } = await supabase.auth.getSession();
    setAuthAccessToken(data?.session?.access_token || "");
  } catch (_) {
    setAuthAccessToken("");
  }
  if (!authAccessToken) setAuthAccessToken(readAuthTokenFromStorage());
}

async function awaitWithTimeout(promiseLike, timeoutMs = 10000, label = "operation") {
  const safeMs = Math.max(1500, Number(timeoutMs) || 10000);
  let timeoutId = null;
  try {
    return await Promise.race([
      Promise.resolve(promiseLike),
      new Promise((_, reject) => {
        timeoutId = setTimeout(() => reject(new Error(`${label} timeout (${safeMs}ms)`)), safeMs);
      }),
    ]);
  } finally {
    if (timeoutId) clearTimeout(timeoutId);
  }
}

async function rpcWithTimeout(rpcName, payload = {}, timeoutMs = RPC_SOFT_TIMEOUT_MS) {
  const rpc = String(rpcName || "").trim();
  if (!rpc) return { data: [], error: { message: "rpc name missing" } };

  const safeMs = Math.max(1500, Number(timeoutMs) || RPC_SOFT_TIMEOUT_MS);
  let timeoutId = null;
  try {
    const result = await Promise.race([
      supabase.rpc(rpc, payload || {}),
      new Promise((resolve) => {
        timeoutId = setTimeout(() => {
          resolve({
            data: [],
            error: { message: `${rpc} timeout (${safeMs}ms)` },
          });
        }, safeMs);
      }),
    ]);
    if (!result || typeof result !== "object") {
      return { data: [], error: { message: `${rpc} empty response` } };
    }
    return result;
  } catch (e) {
    return { data: [], error: { message: e?.message || String(e || `${rpc} failed`) } };
  } finally {
    if (timeoutId) clearTimeout(timeoutId);
  }
}

function postCallSignalKeepAlive(row) {
  const convId = normId(row?.conversation_id || "");
  const fromUserId = normId(row?.from_user_id || state.user?.id || "");
  if (!convId || !fromUserId) return;

  const context = callRealtimeChannelsByConversationId.get(convId);
  if (!context) return;

  const payload = row?.payload && typeof row.payload === "object" && !Array.isArray(row.payload)
    ? { ...row.payload }
    : row?.payload;

  try {
    void broadcastCallSignal(context, {
      type: mapLegacyCallSignalKindToRealtimeType(row?.kind),
      conversationId: convId,
      fromUserId,
      data: (payload && typeof payload === "object" && !Array.isArray(payload))
        ? {
            ...payload,
            signalKind: String(row?.kind || "").trim().toLowerCase(),
            targetUserId: normId(row?.to_user_id || "") || null,
          }
        : {
            value: payload ?? null,
            signalKind: String(row?.kind || "").trim().toLowerCase(),
            targetUserId: normId(row?.to_user_id || "") || null,
          },
      createdAt: new Date().toISOString(),
    }).catch(() => {});
  } catch (_) {}
}

function postRpcKeepAlive(rpcName, payload = {}) {
  const token = getAuthTokenForKeepAlive();
  const rpc = String(rpcName || "").trim();
  if (!token || !rpc) return;
  try {
    fetch(`${SUPABASE_URL}/rest/v1/rpc/${rpc}`, {
      method: "POST",
      keepalive: true,
      mode: "cors",
      headers: {
        apikey: SUPABASE_ANON_KEY,
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
        Prefer: "return=minimal",
      },
      body: JSON.stringify(payload || {}),
    }).catch(() => {});
  } catch (_) {}
}

function notifyCallEndedOnUnload() {
  if (unloadSignalDispatched) return;
  if (!state.user?.id) return;

  const convId = callConversationId || activeDmId || pendingCallInfo?.conversationId || null;
  if (!convId) return;

  const hasCallContext = !!(
    inCall
    || callPc
    || pendingOffer
    || pendingCallInfo
    || ringTimeout
    || privateCallJoinInFlight
    || isPrivateCallRingingOrConnectingState(privateCallState)
  );
  if (!hasCallContext) return;

  unloadSignalDispatched = true;
  const meId = normId(state.user.id);
  if (groupCallMode) {
    postRpcKeepAlive("leave_group_dm_call", { p_conversation_id: convId });
    const cachedIds = groupCallActiveMemberIds.length
      ? groupCallActiveMemberIds.slice()
      : groupCallMemberIds.length
      ? groupCallMemberIds.slice()
      : normalizeUuidArray(getActiveConversationMeta(convId)?.memberIds);
    const targets = Array.from(new Set(cachedIds.map((id) => normId(id)).filter(Boolean)))
      .filter((uid) => uid !== meId);
    if (targets.length) {
      targets.forEach((uid) => {
        postCallSignalKeepAlive({
          conversation_id: convId,
          from_user_id: state.user.id,
          to_user_id: uid,
          kind: "ice",
          payload: { signal: "group_ring_cancel", reason: "page_unload", group_call: true },
        });
        postCallSignalKeepAlive({
          conversation_id: convId,
          from_user_id: state.user.id,
          to_user_id: uid,
          kind: "ice",
          payload: {
            signal: "group_presence_leave",
            group_call: true,
            reason: "page_unload",
            from_label: state.me?.display_name || state.me?.username || t("call.someone", "someone"),
            from_avatar: state.me?.avatar_url || null,
            presence_ts: Date.now(),
          },
        });
      });
      return;
    }
  }

  const targetUserId = normId(callOtherUserId || pendingCallInfo?.fromUserId || "");
  if (!targetUserId) return;
  const usePrivateLiveKitUnloadSignal = !!(
    !groupCallMode
    && convId
    && shouldRoutePrivateDmCallViaLiveKit(convId)
  );
  if (usePrivateLiveKitUnloadSignal) {
    postCallSignalKeepAlive({
      conversation_id: convId,
      from_user_id: state.user.id,
      to_user_id: targetUserId,
      kind: "ice",
      payload: {
        signal: "private_call_cancel",
        reason: "page_unload",
        transport: "livekit",
      },
    });
    return;
  }
  postCallSignalKeepAlive({
    conversation_id: convId,
    from_user_id: state.user.id,
    to_user_id: targetUserId,
    kind: inCall ? "hangup" : "cancel",
    payload: { reason: "page_unload" },
  });
}

function hideCallChromeImmediately() {
  document.body?.classList?.add("boot-hide-call-chrome");

  const stage = document.getElementById("callStage");
  const bar = document.getElementById("callBar");
  const overlay = document.getElementById("globalCallOverlay");

  if (stage) {
    stage.hidden = true;
    stage.classList.remove("is-open");
    stage.setAttribute("aria-hidden", "true");
  }
  if (bar) {
    bar.hidden = true;
    bar.classList.remove("is-open");
    bar.setAttribute("aria-hidden", "true");
  }
  if (overlay) {
    overlay.classList.remove("is-open");
    overlay.style.display = "none";
    overlay.setAttribute("aria-hidden", "true");
  }
}

