let desktopWindowControlsBound = false;
let desktopInboxUiBound = false;
let desktopInboxOpen = false;
let desktopInboxActiveTab = "for_you";

function applyDesktopTitlebarOverlayClass() {
  try {
    const bridge = window?.altaraDesktop;
    const isDesktop = !!bridge && bridge.isDesktopApp === true;
    const platform = String(bridge?.platform || "").trim().toLowerCase();
    const useNativeOverlay = isDesktop && (platform === "win32" || platform === "linux");
    const useShellOverlay = useNativeOverlay || !isDesktop;
    document.body?.classList?.toggle("desktop-titlebar-overlay", useShellOverlay);
    document.body?.classList?.toggle("desktop-native-titlebar-overlay", useNativeOverlay);
    document.getElementById("desktopWindowControls")?.classList?.toggle("hidden", !useNativeOverlay);
    document.getElementById("desktopTitlebarDragRegion")?.classList?.toggle("hidden", !useNativeOverlay);
    const inboxPanel = document.getElementById("desktopInboxPanel");
    if (!useNativeOverlay) {
      desktopInboxOpen = false;
      inboxPanel?.classList?.add("hidden");
      inboxPanel?.setAttribute?.("aria-hidden", "true");
      document.getElementById("btnDesktopInbox")?.setAttribute?.("aria-expanded", "false");
    } else {
      void renderDesktopInboxPanel();
    }
  } catch (_) {}
}

async function refreshDesktopWindowControlsState() {
  const btnMax = document.getElementById("btnDesktopWindowMax");
  if (!btnMax) return;
  const bridge = getDesktopBridge();
  if (!bridge || typeof bridge.isWindowMaximized !== "function") {
    btnMax.classList.remove("is-maximized");
    btnMax.setAttribute("aria-label", "Maximize");
    btnMax.setAttribute("title", "Maximize");
    return;
  }
  try {
    const state = await bridge.isWindowMaximized();
    const isMaximized = !!state?.maximized;
    btnMax.classList.toggle("is-maximized", isMaximized);
    btnMax.setAttribute("aria-label", isMaximized ? "Restore" : "Maximize");
    btnMax.setAttribute("title", isMaximized ? "Restore" : "Maximize");
  } catch (_) {}
}

function bindDesktopWindowControlsOnce() {
  if (desktopWindowControlsBound) return;
  desktopWindowControlsBound = true;
  const controls = document.getElementById("desktopWindowControls");
  const dragRegion = document.getElementById("desktopTitlebarDragRegion");
  const btnInbox = document.getElementById("btnDesktopInbox");
  const btnMin = document.getElementById("btnDesktopWindowMin");
  const btnMax = document.getElementById("btnDesktopWindowMax");
  const btnClose = document.getElementById("btnDesktopWindowClose");
  if (!controls) return;

  const bridge = getDesktopBridge();
  const canUse = !!(
    bridge
    && typeof bridge.minimizeWindow === "function"
    && typeof bridge.toggleMaximizeWindow === "function"
    && typeof bridge.closeWindow === "function"
  );
  controls.classList.toggle("hidden", !canUse);
  if (!canUse) return;

  bindDesktopInboxUiOnce();

  btnInbox?.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    toggleDesktopInboxPanel();
  });

  btnMin?.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    void bridge.minimizeWindow?.();
  });

  const toggleMaximize = () => {
    void Promise.resolve(bridge.toggleMaximizeWindow?.())
      .finally(() => { void refreshDesktopWindowControlsState(); });
  };

  btnMax?.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    toggleMaximize();
  });

  btnClose?.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    void bridge.closeWindow?.();
  });

  dragRegion?.addEventListener("dblclick", () => {
    toggleMaximize();
  });

  window.addEventListener("resize", () => {
    void refreshDesktopWindowControlsState();
  });

  void refreshDesktopWindowControlsState();
}

function normalizeDesktopInboxTab(value) {
  const tab = String(value || "").trim().toLowerCase();
  if (tab === "unreads" || tab === "requests") return tab;
  return "for_you";
}

function isPortugueseAppLanguage() {
  return normalizeAppLanguage(appLanguage, APP_LANG_DEFAULT) === "pt";
}

function formatDesktopInboxRelativeStamp(value) {
  const raw = Number(value);
  const ts = Number.isFinite(raw) && raw > 0
    ? raw
    : (Date.parse(String(value || "")) || 0);
  if (!ts) return "";

  const diff = Math.max(0, Date.now() - ts);
  const minute = 60 * 1000;
  const hour = 60 * minute;
  const day = 24 * hour;
  const month = 30 * day;
  const year = 365 * day;
  const pt = isPortugueseAppLanguage();

  if (diff < minute) return pt ? "agora" : "now";
  if (diff < hour) return `${Math.max(1, Math.floor(diff / minute))}m`;
  if (diff < day) return `${Math.max(1, Math.floor(diff / hour))}h`;
  if (diff < month) return `${Math.max(1, Math.floor(diff / day))}d`;
  if (diff < year) return `${Math.max(1, Math.floor(diff / month))}mo`;
  return `${Math.max(1, Math.floor(diff / year))}y`;
}

function formatDesktopInboxSummaryLegacy(unreadCount = 0, requestCount = 0) {
  const unread = Math.max(0, Number(unreadCount) || 0);
  const requests = Math.max(0, Number(requestCount) || 0);
  const pt = isPortugueseAppLanguage();
  const parts = [];
  if (unread) parts.push(pt ? `${unread} por ler` : `${unread} unread`);
  if (requests) parts.push(pt ? `${requests} pedidos` : `${requests} requests`);
  if (!parts.length) return pt ? "Tudo junto aqui em cima." : "Everything in one place.";
  return parts.join(" â€¢ ");
}

function formatDesktopInboxSummary(unreadCount = 0, requestCount = 0, moderationCount = 0) {
  const unread = Math.max(0, Number(unreadCount) || 0);
  const requests = Math.max(0, Number(requestCount) || 0);
  const moderation = Math.max(0, Number(moderationCount) || 0);
  const pt = isPortugueseAppLanguage();
  const parts = [];
  if (unread) parts.push(pt ? `${unread} por ler` : `${unread} unread`);
  if (requests) parts.push(pt ? `${requests} pedidos` : `${requests} requests`);
  if (moderation) parts.push(pt ? `${moderation} moderacao` : `${moderation} moderation`);
  if (!parts.length) return pt ? "Tudo junto aqui em cima." : "Everything in one place.";
  return parts.join(" | ");
}

function formatDesktopInboxUnreadBody(kind = "dm", unreadCount = 0) {
  const count = Math.max(1, Number(unreadCount) || 1);
  const pt = isPortugueseAppLanguage();
  const base = pt
    ? (count === 1 ? "1 mensagem por ler" : `${count} mensagens por ler`)
    : (count === 1 ? "1 unread message" : `${count} unread messages`);

  if (kind === "server") return pt ? `${base} neste server` : `${base} in this server`;
  if (kind === "group") return pt ? `${base} neste grupo` : `${base} in this group`;
  return pt ? `${base} nesta DM` : `${base} in this DM`;
}

function buildDesktopInboxAvatarHtml({
  label = "",
  avatarUrl = "",
  fallback = "N",
} = {}) {
  const initial = getGroupOrbFallbackChar(label || fallback, fallback);
  const url = String(avatarUrl || "").trim();
  return `
    <span class="desktopInboxItem__avatar" aria-hidden="true">
      ${url ? buildAvatarMediaHtml(url, { alt: "", loading: "lazy" }) : `<span class="desktopInboxItem__avatarFallback">${esc(initial)}</span>`}
    </span>
  `;
}

function compareDesktopInboxEntries(a = {}, b = {}) {
  const priorityDelta = (Number(b.priority) || 0) - (Number(a.priority) || 0);
  if (priorityDelta) return priorityDelta;
  const unreadDelta = (Number(b.unreadCount) || 0) - (Number(a.unreadCount) || 0);
  if (unreadDelta) return unreadDelta;
  const stampDelta = (Number(b.sortStamp) || 0) - (Number(a.sortStamp) || 0);
  if (stampDelta) return stampDelta;
  return String(a.titleText || "").localeCompare(String(b.titleText || ""));
}

function resolveDesktopInboxDmTarget({
  userId = "",
  username = "",
  displayName = "",
  avatarUrl = "",
} = {}) {
  const uid = normId(userId || "");
  const friend = uid
    ? ((state.friends || []).find((f) => normId(f?.other_user_id || f?.id) === uid) || null)
    : ((state.friends || []).find((f) => String(f?.username || "").trim().toLowerCase() === String(username || "").trim().toLowerCase()) || null);
  const cached = uid ? (getCachedProfile(uid) || null) : null;
  const nextUsername = String(
    username
    || friend?.username
    || cached?.username
    || ""
  ).trim();
  const nextDisplay = normalizeConversationLabel(
    displayName
    || (friend ? getFriendDisplayName(friend) : "")
    || cached?.display_name
    || cached?.username
    || nextUsername
    || "DM",
    nextUsername || "DM"
  );
  const nextAvatar = String(
    avatarUrl
    || friend?.avatar_url
    || cached?.avatar_url
    || ""
  ).trim();
  return {
    userId: uid,
    username: nextUsername,
    displayName: nextDisplay,
    avatarUrl: nextAvatar,
  };
}

function getDesktopInboxRequestEntries() {
  const incomingEntries = (Array.isArray(state.incoming) ? state.incoming : []).map((row) => {
    const requestId = String(row?.request_id || row?.id || "").trim();
    if (!requestId) return null;
    const userId = normId(row?.other_user_id || row?.from_user_id || row?.user_id || row?.id || "");
    const cached = userId ? (getCachedProfile(userId) || null) : null;
    const username = String(row?.username || cached?.username || "").trim();
    const displayName = normalizeConversationLabel(
      row?.display_name || cached?.display_name || cached?.username || username || "friend",
      username || "friend"
    );
    return {
      key: `req_in_${requestId}`,
      priority: 300,
      sortStamp: Date.parse(String(row?.created_at || "")) || 0,
      unreadCount: 0,
      type: "request_incoming",
      requestId,
      userId,
      username,
      displayName,
      avatarUrl: String(row?.avatar_url || cached?.avatar_url || "").trim(),
      titleText: displayName,
      bodyText: t("inbox.item.request.incoming", "sent you a friend request."),
      metaText: username ? `@${username}` : "",
      stampText: formatDesktopInboxRelativeStamp(row?.created_at),
    };
  }).filter(Boolean);

  const outgoingEntries = (Array.isArray(state.outgoing) ? state.outgoing : []).map((row) => {
    const requestId = String(row?.request_id || row?.id || "").trim();
    if (!requestId) return null;
    const userId = normId(row?.other_user_id || row?.to_user_id || row?.user_id || row?.id || "");
    const cached = userId ? (getCachedProfile(userId) || null) : null;
    const username = String(row?.username || cached?.username || "").trim();
    const displayName = normalizeConversationLabel(
      row?.display_name || cached?.display_name || cached?.username || username || "friend",
      username || "friend"
    );
    return {
      key: `req_out_${requestId}`,
      priority: 180,
      sortStamp: Date.parse(String(row?.created_at || "")) || 0,
      unreadCount: 0,
      type: "request_outgoing",
      requestId,
      userId,
      username,
      displayName,
      avatarUrl: String(row?.avatar_url || cached?.avatar_url || "").trim(),
      titleText: displayName,
      bodyText: t("inbox.item.request.outgoing", "Waiting for reply to your friend request."),
      metaText: username ? `@${username}` : "",
      stampText: formatDesktopInboxRelativeStamp(row?.created_at),
    };
  }).filter(Boolean);

  const incomingMessageEntries = (Array.isArray(state.messageIncoming) ? state.messageIncoming : []).map((row) => {
    const requestId = String(row?.request_id || row?.id || "").trim();
    if (!requestId) return null;
    const userId = normId(row?.other_user_id || row?.from_user_id || row?.user_id || row?.id || "");
    const cached = userId ? (getCachedProfile(userId) || null) : null;
    const username = String(row?.username || cached?.username || "").trim();
    const displayName = normalizeConversationLabel(
      row?.display_name || cached?.display_name || cached?.username || username || "user",
      username || "user"
    );
    return {
      key: `msg_req_in_${requestId}`,
      priority: 290,
      sortStamp: Date.parse(String(row?.created_at || "")) || 0,
      unreadCount: 0,
      type: "message_request_incoming",
      requestId,
      userId,
      username,
      displayName,
      avatarUrl: String(row?.avatar_url || cached?.avatar_url || "").trim(),
      titleText: displayName,
      bodyText: "sent you a message request.",
      metaText: username ? `@${username}` : "",
      stampText: formatDesktopInboxRelativeStamp(row?.created_at),
    };
  }).filter(Boolean);

  const outgoingMessageEntries = (Array.isArray(state.messageOutgoing) ? state.messageOutgoing : []).map((row) => {
    const requestId = String(row?.request_id || row?.id || "").trim();
    if (!requestId) return null;
    const userId = normId(row?.other_user_id || row?.to_user_id || row?.user_id || row?.id || "");
    const cached = userId ? (getCachedProfile(userId) || null) : null;
    const username = String(row?.username || cached?.username || "").trim();
    const displayName = normalizeConversationLabel(
      row?.display_name || cached?.display_name || cached?.username || username || "user",
      username || "user"
    );
    return {
      key: `msg_req_out_${requestId}`,
      priority: 170,
      sortStamp: Date.parse(String(row?.created_at || "")) || 0,
      unreadCount: 0,
      type: "message_request_outgoing",
      requestId,
      userId,
      username,
      displayName,
      avatarUrl: String(row?.avatar_url || cached?.avatar_url || "").trim(),
      titleText: displayName,
      bodyText: "Waiting for reply to your message request.",
      metaText: username ? `@${username}` : "",
      stampText: formatDesktopInboxRelativeStamp(row?.created_at),
    };
  }).filter(Boolean);

  return [...incomingEntries, ...outgoingEntries, ...incomingMessageEntries, ...outgoingMessageEntries].sort(compareDesktopInboxEntries);
}

function getDesktopInboxModerationEntries() {
  return (Array.isArray(state.moderationInboxActions) ? state.moderationInboxActions : [])
    .map((row) => {
      const action = normalizeOwnerModerationActionRow(row);
      if (!action?.id || !action?.actionType) return null;
      const reasonText = String(action.reason || action.reportReason || "").trim();
      const requiresResponse = shouldModerationActionRequireResponse(action);
      const bodyText = action.actionType === "ban"
        ? t("inbox.item.moderation.ban", "Your ALTARA account was banned by moderation.")
        : action.actionType === "unban"
          ? t("inbox.item.moderation.unban", "Your ALTARA account ban was lifted by moderation.")
          : action.actionType === "request_explanation"
            ? (requiresResponse
              ? t("inbox.item.moderation.request", "ALTARA moderation requested an explanation about a report involving your account.")
              : t("inbox.item.moderation.request_sent", "You already sent your explanation to ALTARA moderation."))
            : t("inbox.item.moderation.warning", "You received a warning from ALTARA moderation.");
      return {
        key: `moderation_${action.id}`,
        priority: action.actionType === "ban"
          ? 320
          : (action.actionType === "request_explanation"
            ? 280
            : (action.actionType === "unban" ? 260 : 245)),
        sortStamp: Date.parse(String(action.createdAt || "")) || 0,
        unreadCount: 0,
        type: `moderation_${action.actionType}`,
        actionId: action.id,
        titleText: t("inbox.item.moderation.title", "ALTARA Moderation"),
        bodyText,
        metaText: reasonText
          ? `${t("inbox.item.moderation.reason_prefix", "Reason")}: ${reasonText}`
          : "",
        stampText: formatDesktopInboxRelativeStamp(action.createdAt),
        requiresResponse,
        replyPending: moderationInboxReplyPendingActionIds.has(action.id),
        badgeable: requiresResponse,
      };
    })
    .filter(Boolean)
    .sort(compareDesktopInboxEntries);
}

function getDesktopInboxUnreadEntries() {
  const directDmEntries = Array.from(dmUnreadByUserId.entries())
    .map(([uidRaw, unreadRaw]) => {
      const userId = normId(uidRaw);
      const unreadCount = Math.max(0, Number(unreadRaw) || 0);
      if (!userId || unreadCount <= 0) return null;
      const target = resolveDesktopInboxDmTarget({ userId });
      return {
        key: `dm_${userId}`,
        priority: 220,
        sortStamp: getDmActivityScore(userId),
        unreadCount,
        type: "dm",
        userId,
        username: target.username,
        displayName: target.displayName,
        avatarUrl: target.avatarUrl,
        titleText: target.displayName,
        bodyText: formatDesktopInboxUnreadBody("dm", unreadCount),
        metaText: target.username ? `@${target.username}` : "DM",
        stampText: formatDesktopInboxRelativeStamp(getDmActivityScore(userId)),
      };
    })
    .filter(Boolean);

  const groupDmEntries = Array.from(dmUnreadByConversationId.entries())
    .map(([convIdRaw, unreadRaw]) => {
      const conversationId = normId(convIdRaw);
      const unreadCount = Math.max(0, Number(unreadRaw) || 0);
      if (!conversationId || unreadCount <= 0) return null;
      const meta = getConversationMeta(conversationId) || {};
      if (isServerConversationKind(meta?.kind) || !isGroupConversationKind(meta?.kind)) return null;
      const displayName = normalizeConversationLabel(meta?.displayName || meta?.name || "Group DM", "Group DM");
      return {
        key: `group_${conversationId}`,
        priority: 205,
        sortStamp: 0,
        unreadCount,
        type: "group",
        conversationId,
        displayName,
        avatarUrl: String(meta?.avatarUrl || "").trim(),
        titleText: displayName,
        bodyText: formatDesktopInboxUnreadBody("group", unreadCount),
        metaText: isPortugueseAppLanguage() ? "Grupo" : "Group DM",
        stampText: "",
      };
    })
    .filter(Boolean);

  const serverEntries = (Array.isArray(state.servers) ? state.servers : [])
    .map((row) => {
      const serverId = normId(row?.serverId || row?.server_id || "");
      if (!serverId) return null;
      const fallbackConversationId = normId(row?.defaultConversationId || row?.default_conversation_id || "");
      const unreadCount = getServerUnreadCount(serverId, fallbackConversationId);
      if (unreadCount <= 0) return null;
      const rememberedConversationId = normId(getRememberedServerLastChannel(serverId) || "");
      const previewMeta = getConversationMeta(rememberedConversationId || fallbackConversationId) || {};
      const displayName = normalizeConversationLabel(row?.name || "Server", "Server");
      return {
        key: `server_${serverId}`,
        priority: 160,
        sortStamp: 0,
        unreadCount,
        type: "server",
        serverId,
        fallbackConversationId,
        displayName,
        avatarUrl: String(row?.iconUrl || row?.icon_url || "").trim(),
        titleText: displayName,
        bodyText: formatDesktopInboxUnreadBody("server", unreadCount),
        metaText: normalizeConversationLabel(
          previewMeta?.displayName || previewMeta?.name || (isPortugueseAppLanguage() ? "Server" : "Server"),
          isPortugueseAppLanguage() ? "Server" : "Server"
        ),
        stampText: "",
      };
    })
    .filter(Boolean);

  return [...directDmEntries, ...groupDmEntries, ...serverEntries].sort(compareDesktopInboxEntries);
}

function buildDesktopInboxItemHtml(entry = {}) {
  const avatarHtml = buildDesktopInboxAvatarHtml({
    label: entry?.displayName || entry?.titleText || "Notification",
    avatarUrl: entry?.avatarUrl || "",
    fallback: entry?.type === "server" ? "S" : "N",
  });
  const countHtml = Number(entry?.unreadCount || 0) > 0
    ? `<span class="desktopInboxItem__count">${esc(formatGroupOrbUnreadBadgeCount(entry.unreadCount))}</span>`
    : "";

  const attrs = [];
  if (entry?.type === "dm") {
    attrs.push(`data-desktop-inbox-open-kind="dm"`);
    attrs.push(`data-desktop-inbox-user-id="${escAttr(entry.userId || "")}"`);
    attrs.push(`data-desktop-inbox-username="${escAttr(entry.username || "")}"`);
    attrs.push(`data-desktop-inbox-display="${escAttr(entry.displayName || entry.titleText || "")}"`);
    attrs.push(`data-desktop-inbox-avatar="${escAttr(entry.avatarUrl || "")}"`);
  } else if (entry?.type === "group") {
    attrs.push(`data-desktop-inbox-open-kind="conversation"`);
    attrs.push(`data-desktop-inbox-conversation-id="${escAttr(entry.conversationId || "")}"`);
  } else if (entry?.type === "server") {
    attrs.push(`data-desktop-inbox-open-kind="server"`);
    attrs.push(`data-desktop-inbox-server-id="${escAttr(entry.serverId || "")}"`);
    attrs.push(`data-desktop-inbox-fallback-conversation-id="${escAttr(entry.fallbackConversationId || "")}"`);
  }

  const clickable = attrs.length > 0;
  const actionButtons = [];
  if (entry?.type === "request_incoming") {
    actionButtons.push(`<button class="smallBtn primary" type="button" data-desktop-inbox-act="accept" data-request-id="${escAttr(entry.requestId || "")}" data-request-kind="friend">${esc(t("inbox.action.accept", "Accept"))}</button>`);
    actionButtons.push(`<button class="smallBtn" type="button" data-desktop-inbox-act="ignore" data-request-id="${escAttr(entry.requestId || "")}" data-request-kind="friend">${esc(t("inbox.action.ignore", "Ignore"))}</button>`);
  } else if (entry?.type === "request_outgoing") {
    actionButtons.push(`<button class="smallBtn" type="button" data-desktop-inbox-act="cancel" data-request-id="${escAttr(entry.requestId || "")}" data-request-kind="friend">${esc(t("inbox.action.cancel", "Cancel"))}</button>`);
  } else if (entry?.type === "message_request_incoming") {
    actionButtons.push(`<button class="smallBtn primary" type="button" data-desktop-inbox-act="accept" data-request-id="${escAttr(entry.requestId || "")}" data-request-kind="message">${esc("Reply")}</button>`);
    actionButtons.push(`<button class="smallBtn" type="button" data-desktop-inbox-act="ignore" data-request-id="${escAttr(entry.requestId || "")}" data-request-kind="message">${esc(t("inbox.action.ignore", "Ignore"))}</button>`);
  } else if (entry?.type === "message_request_outgoing") {
    actionButtons.push(`<button class="smallBtn" type="button" data-desktop-inbox-act="cancel" data-request-id="${escAttr(entry.requestId || "")}" data-request-kind="message">${esc(t("inbox.action.cancel", "Cancel"))}</button>`);
  } else if (entry?.type === "moderation_request_explanation" && entry?.requiresResponse) {
    actionButtons.push(`<button class="smallBtn primary" type="button" data-desktop-inbox-act="reply_moderation" data-moderation-action-id="${escAttr(entry.actionId || "")}" ${entry?.replyPending ? "disabled" : ""}>${esc(t("inbox.action.reply", "Reply"))}</button>`);
  } else if (clickable) {
    actionButtons.push(`<button class="smallBtn" type="button" data-desktop-inbox-act="open">${esc(t("inbox.action.open", "Open"))}</button>`);
  }

  const actionHtml = actionButtons.length
    ? `<div class="desktopInboxItem__actions">${actionButtons.join("")}</div>`
    : "";

  return `
    <div
      class="desktopInboxItem${clickable ? " desktopInboxItem--clickable" : ""}"
      ${clickable ? `role="button" tabindex="0"` : ""}
      ${attrs.join(" ")}
    >
      ${avatarHtml}
      <div class="desktopInboxItem__body">
        <div class="desktopInboxItem__head">
          <div class="desktopInboxItem__headMain">
            <div class="desktopInboxItem__title">${esc(entry?.titleText || "Notification")}</div>
            ${entry?.stampText ? `<div class="desktopInboxItem__stamp">${esc(entry.stampText)}</div>` : ""}
          </div>
          ${countHtml}
        </div>
        ${entry?.bodyText ? `<div class="desktopInboxItem__text">${esc(entry.bodyText)}</div>` : ""}
        ${entry?.metaText ? `<div class="desktopInboxItem__meta">${esc(entry.metaText)}</div>` : ""}
        ${actionHtml}
      </div>
    </div>
  `;
}

function renderDesktopInboxPanel() {
  const btn = document.getElementById("btnDesktopInbox");
  const badge = document.getElementById("desktopInboxBadge");
  const panel = document.getElementById("desktopInboxPanel");
  if (!btn || !badge || !panel) return;

  const requestEntries = getDesktopInboxRequestEntries();
  const incomingRequestEntries = requestEntries.filter((entry) => entry?.type === "request_incoming" || entry?.type === "message_request_incoming");
  const unreadEntries = getDesktopInboxUnreadEntries();
  const moderationEntries = getDesktopInboxModerationEntries();
  const moderationBadgeEntries = moderationEntries.filter((entry) => entry?.badgeable);
  const tabs = {
    for_you: [...incomingRequestEntries, ...unreadEntries, ...moderationEntries].sort(compareDesktopInboxEntries),
    unreads: unreadEntries.slice().sort(compareDesktopInboxEntries),
    requests: requestEntries.slice().sort(compareDesktopInboxEntries),
  };
  desktopInboxActiveTab = normalizeDesktopInboxTab(desktopInboxActiveTab);
  const activeEntries = tabs[desktopInboxActiveTab] || tabs.for_you;
  const badgeCount = incomingRequestEntries.length + unreadEntries.length + moderationBadgeEntries.length;
  const badgeLabel = formatGroupOrbUnreadBadgeCount(badgeCount);
  const buttonLabel = t("inbox.button.aria", "Open inbox");

  if (badgeLabel) {
    badge.style.display = "inline-flex";
    badge.textContent = badgeLabel;
  } else {
    badge.style.display = "none";
    badge.textContent = "0";
  }
  btn.setAttribute("aria-label", badgeCount ? `${buttonLabel} (${badgeCount})` : buttonLabel);
  btn.setAttribute("title", buttonLabel);
  btn.setAttribute("aria-expanded", desktopInboxOpen ? "true" : "false");
  btn.classList.toggle("is-active", !!desktopInboxOpen);

  panel.classList.toggle("hidden", !desktopInboxOpen);
  panel.setAttribute("aria-label", t("inbox.title", "Inbox"));
  panel.setAttribute("aria-hidden", desktopInboxOpen ? "false" : "true");
  if (!desktopInboxOpen) return;

  const emptyText = desktopInboxActiveTab === "requests"
    ? t("inbox.empty.requests", "No pending friend requests.")
    : desktopInboxActiveTab === "unreads"
      ? t("inbox.empty.unreads", "You are all caught up.")
      : t("inbox.empty.for_you", "Nothing waiting for you right now.");
  const summaryText = formatDesktopInboxSummary(tabs.unreads.length, tabs.requests.length, moderationEntries.length);
  const tabRows = [
    { id: "for_you", label: t("inbox.tab.for_you", "For You"), count: tabs.for_you.length },
    { id: "unreads", label: t("inbox.tab.unreads", "Unreads"), count: tabs.unreads.length },
    { id: "requests", label: t("inbox.tab.requests", "Requests"), count: tabs.requests.length },
  ];
  const tabsHtml = tabRows.map((tab) => `
    <button
      class="desktopInboxPanel__tab${desktopInboxActiveTab === tab.id ? " is-active" : ""}"
      type="button"
      data-desktop-inbox-tab="${escAttr(tab.id)}"
    >
      <span>${esc(tab.label)}</span>
      ${tab.count ? `<span class="desktopInboxPanel__tabCount">${esc(formatGroupOrbUnreadBadgeCount(tab.count))}</span>` : ""}
    </button>
  `).join("");
  const listHtml = activeEntries.length
    ? activeEntries.map((entry) => buildDesktopInboxItemHtml(entry)).join("")
    : `<div class="desktopInboxEmpty">${esc(emptyText)}</div>`;

  panel.innerHTML = `
    <div class="desktopInboxPanel__header">
      <div class="desktopInboxPanel__titleWrap">
        <span class="desktopInboxPanel__titleIcon" aria-hidden="true">
          <svg viewBox="0 0 24 24">
            <path d="M4.5 8.5A2.5 2.5 0 0 1 7 6h10a2.5 2.5 0 0 1 2.5 2.5v7A2.5 2.5 0 0 1 17 18H7a2.5 2.5 0 0 1-2.5-2.5z"></path>
            <path d="M4.5 13.5h4l1.4 2h4.2l1.4-2h4"></path>
          </svg>
        </span>
        <div class="desktopInboxPanel__titleText">
          <div class="desktopInboxPanel__title">${esc(t("inbox.title", "Inbox"))}</div>
          <div class="desktopInboxPanel__summary">${esc(summaryText)}</div>
        </div>
      </div>
    </div>
    <div class="desktopInboxPanel__tabs">${tabsHtml}</div>
    <div class="desktopInboxPanel__list">${listHtml}</div>
  `;
}

function closeDesktopInboxPanel({ restoreFocus = false } = {}) {
  if (!desktopInboxOpen && document.getElementById("desktopInboxPanel")?.classList?.contains("hidden")) return;
  desktopInboxOpen = false;
  renderDesktopInboxPanel();
  if (restoreFocus) document.getElementById("btnDesktopInbox")?.focus?.();
}

function toggleDesktopInboxPanel(forceOpen = null) {
  desktopInboxOpen = typeof forceOpen === "boolean" ? forceOpen : !desktopInboxOpen;
  renderDesktopInboxPanel();
}

async function openDesktopInboxEntryFromElement(itemEl) {
  if (!itemEl) return;
  const openKind = String(itemEl.getAttribute("data-desktop-inbox-open-kind") || "").trim().toLowerCase();
  if (!openKind) return;

  if (openKind === "dm") {
    const target = resolveDesktopInboxDmTarget({
      userId: itemEl.getAttribute("data-desktop-inbox-user-id") || "",
      username: itemEl.getAttribute("data-desktop-inbox-username") || "",
      displayName: itemEl.getAttribute("data-desktop-inbox-display") || "",
      avatarUrl: itemEl.getAttribute("data-desktop-inbox-avatar") || "",
    });
    if (!target.username) return;
    await startDmWith(target.username, target.displayName, target.avatarUrl, target.userId || "");
    closeDesktopInboxPanel();
    return;
  }

  if (openKind === "conversation") {
    const conversationId = normId(itemEl.getAttribute("data-desktop-inbox-conversation-id") || "");
    if (!conversationId) return;
    const meta = getConversationMeta(conversationId) || {};
    await openConversationById(conversationId, meta);
    closeDesktopInboxPanel();
    return;
  }

  if (openKind === "server") {
    const serverId = normId(itemEl.getAttribute("data-desktop-inbox-server-id") || "");
    const fallbackConversationId = normId(itemEl.getAttribute("data-desktop-inbox-fallback-conversation-id") || "");
    if (!serverId) return;
    const conversationId = await resolveServerConversationForEntry(serverId, fallbackConversationId);
    if (!conversationId) return;
    const convMeta = getConversationMeta(conversationId) || {};
    const fallbackMeta = getConversationMeta(fallbackConversationId) || {};
    const serverRow = getServerRowById(serverId) || {};
    const serverName = normalizeConversationLabel(serverRow?.name || convMeta?.serverName || fallbackMeta?.serverName || "Server", "Server");
    await openConversationById(conversationId, {
      ...fallbackMeta,
      ...convMeta,
      kind: "server",
      isGroup: true,
      displayName: normalizeConversationLabel(convMeta?.displayName || fallbackMeta?.displayName || serverName, serverName),
      serverId,
      serverName,
      channelType: normalizeConversationChannelType(convMeta?.channelType || fallbackMeta?.channelType || "text"),
    });
    closeDesktopInboxPanel();
  }
}

function bindDesktopInboxUiOnce() {
  if (desktopInboxUiBound) return;
  desktopInboxUiBound = true;
  const panel = document.getElementById("desktopInboxPanel");
  if (!panel) return;

  panel.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;

    const tabBtn = target.closest("[data-desktop-inbox-tab]");
    if (tabBtn) {
      desktopInboxActiveTab = normalizeDesktopInboxTab(tabBtn.getAttribute("data-desktop-inbox-tab") || "");
      renderDesktopInboxPanel();
      return;
    }

    const actionBtn = target.closest("[data-desktop-inbox-act]");
    if (actionBtn) {
      e.preventDefault();
      e.stopPropagation();
      const action = String(actionBtn.getAttribute("data-desktop-inbox-act") || "").trim().toLowerCase();
      const requestId = String(actionBtn.getAttribute("data-request-id") || "").trim();
      const requestKind = String(actionBtn.getAttribute("data-request-kind") || "friend").trim().toLowerCase();
      if (action === "accept" && requestId) {
        if (requestKind === "message") {
          const result = await acceptMessageReq(requestId);
          if (result?.ok && result?.conversationId) {
            await showDm(result.conversationId, { autoAnswerIfPending: true });
          }
        } else {
          await acceptReq(requestId);
        }
        return;
      }
      if (action === "ignore" && requestId) {
        if (requestKind === "message") await rejectMessageReq(requestId);
        else await rejectReq(requestId);
        return;
      }
      if (action === "cancel" && requestId) {
        if (requestKind === "message") await cancelMessageReq(requestId);
        else await cancelReq(requestId);
        return;
      }
      if (action === "reply_moderation") {
        const actionId = normId(actionBtn.getAttribute("data-moderation-action-id") || "");
        if (!actionId) return;
        const currentAction = getModerationInboxActionById(actionId);
        if (!shouldModerationActionRequireResponse(currentAction) || moderationInboxReplyPendingActionIds.has(actionId)) {
          renderDesktopInboxPanel();
        }
        moderationInboxReplyPendingActionIds.add(actionId);
        renderDesktopInboxPanel();
        const responseText = await requestAppPrompt(
          t("moderation.prompt.reply.message", "Reply to ALTARA moderation."),
          {
            title: t("moderation.prompt.reply.title", "Send explanation"),
            placeholder: t("moderation.prompt.reply.placeholder", "Write your explanation here..."),
            label: t("moderation.prompt.label", "Message"),
            hint: t("moderation.prompt.hint", "Press Ctrl+Enter to send."),
            requireValue: true,
          }
        );
        if (responseText === null) {
          moderationInboxReplyPendingActionIds.delete(actionId);
          renderDesktopInboxPanel();
          return;
        }
        const result = await respondToModerationActionRpc(actionId, responseText);
        if (!result?.ok) {
          moderationInboxReplyPendingActionIds.delete(actionId);
          renderDesktopInboxPanel();
          const err = result?.error;
          await requestAppAlert(
            isModerationSqlMissingError(err)
              ? t("settings.reports.moderation.sql_missing", "Moderation actions SQL is missing. Apply the Phase 5.2 patch and reload.")
              : `${t("moderation.error.response", "Could not send your explanation.")} ${err?.message || err || ""}`.trim(),
            {
              title: t("inbox.item.moderation.title", "ALTARA Moderation"),
              okText: t("dialog.notice.ok", "OK"),
              danger: true,
            }
          );
          return;
        }
        moderationInboxReplyPendingActionIds.delete(actionId);
        reconcileModerationInboxActionResponse(actionId, {
          response_text: responseText,
          responded_at: result.respondedAt || new Date().toISOString(),
          response_user_id: state.user?.id || "",
        });
        scheduleModerationInboxRefresh(0, { render: true });
        renderDesktopInboxPanel();
        await requestAppAlert(t("moderation.response.sent", "Your explanation was sent to ALTARA moderation."), {
          title: t("inbox.item.moderation.title", "ALTARA Moderation"),
          okText: t("dialog.notice.ok", "OK"),
        });
        return;
      }
      if (action === "open") {
        const itemEl = actionBtn.closest(".desktopInboxItem");
        if (itemEl) await openDesktopInboxEntryFromElement(itemEl);
        return;
      }
    }

    const itemEl = target.closest(".desktopInboxItem--clickable[data-desktop-inbox-open-kind]");
    if (!itemEl) return;
    await openDesktopInboxEntryFromElement(itemEl);
  });

  panel.addEventListener("keydown", async (e) => {
    if (e.key !== "Enter" && e.key !== " ") return;
    const target = eventTargetElement(e);
    if (!target || target.closest("button, a, input, textarea, select")) return;
    const itemEl = target.closest(".desktopInboxItem--clickable[data-desktop-inbox-open-kind]");
    if (!itemEl) return;
    e.preventDefault();
    await openDesktopInboxEntryFromElement(itemEl);
  });

  document.addEventListener("mousedown", (e) => {
    if (!desktopInboxOpen) return;
    const target = eventTargetElement(e);
    if (target?.closest("#desktopInboxPanel") || target?.closest("#btnDesktopInbox")) return;
    closeDesktopInboxPanel();
  });

  window.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (!desktopInboxOpen) return;
    closeDesktopInboxPanel({ restoreFocus: true });
  });

  window.addEventListener("resize", () => {
    if (!desktopInboxOpen) return;
    renderDesktopInboxPanel();
  });
}

applyDesktopTitlebarOverlayClass();
bindDesktopWindowControlsOnce();

function prefersOsReducedMotionUi() {
  try {
    return !!window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches;
  } catch (_) {
    return false;
  }
}

function prefersReducedMotionUi() {
  return prefersOsReducedMotionUi() || !!desktopBehaviorSettingsCache?.reducedMotion;
}

function applyGlobalMotionMode() {
  const body = document.body;
  if (!body) return;
  if (prefersReducedMotionUi()) {
    body.classList.add("motion-reduced");
    body.classList.remove("motion-ready");
    return;
  }
  body.classList.add("motion-ready");
  body.classList.remove("motion-reduced");
}

function initGlobalMotionMode() {
  // Defer by one frame so the browser completes an initial layout pass
  // before CSS entrance animations start â€” prevents flicker on slow GPUs.
  requestAnimationFrame(() => {
    applyGlobalMotionMode();
  });
}

window.addEventListener("pagehide", () => {
  try {
    notifyCallEndedOnUnload();
    try { presence?.stop?.(); } catch (_) {}
    hideCallChromeImmediately();
    cleanupPeer();
    inCall = false;
    pendingOffer = null;
    pendingCallInfo = null;
  } catch (_) {}
});

window.addEventListener("beforeunload", () => {
  try {
    notifyCallEndedOnUnload();
    try { presence?.stop?.(); } catch (_) {}
  } catch (_) {}
});

window.addEventListener("pageshow", (ev) => {
  if (!ev.persisted) return;
  try {
    unloadSignalDispatched = false;
    hideCallChromeImmediately();
    refreshCallUI();
  } catch (_) {}
});

