function clamp01(v) {
  const n = Number(v);
  if (!Number.isFinite(n)) return 0;
  if (n < 0) return 0;
  if (n > 1) return 1;
  return n;
}

function clampNum(v, min, max, fallback) {
  const n = Number(v);
  if (!Number.isFinite(n)) return fallback;
  if (n < min) return min;
  if (n > max) return max;
  return n;
}

function clampInt(v, min, max, fallback) {
  return Math.round(clampNum(v, min, max, fallback));
}

function normalizeUiZoomFactor(value, fallback = uiZoomCurrentFactor) {
  return clampNum(value, uiZoomMinFactor, uiZoomMaxFactor, fallback);
}

function uiZoomFactorToPercent(factorInput) {
  const factor = normalizeUiZoomFactor(factorInput, UI_ZOOM_DEFAULT_FACTOR);
  const base = Number(UI_ZOOM_DISPLAY_BASE_FACTOR) || UI_ZOOM_DEFAULT_FACTOR || 1;
  return Math.round((factor / base) * 100);
}

function uiZoomPercentToFactor(percentInput, fallback = uiZoomCurrentFactor) {
  const pct = clampInt(
    percentInput,
    uiZoomFactorToPercent(uiZoomMinFactor),
    uiZoomFactorToPercent(uiZoomMaxFactor),
    uiZoomFactorToPercent(fallback)
  );
  const base = Number(UI_ZOOM_DISPLAY_BASE_FACTOR) || UI_ZOOM_DEFAULT_FACTOR || 1;
  return normalizeUiZoomFactor((pct / 100) * base, fallback);
}

function readStoredUiZoomFactor() {
  try {
    const raw = Number.parseFloat(String(localStorage.getItem(UI_ZOOM_STORAGE_KEY) || "").trim());
    if (!Number.isFinite(raw)) return null;
    return normalizeUiZoomFactor(raw, uiZoomCurrentFactor);
  } catch (_) {
    return null;
  }
}

function writeStoredUiZoomFactor(factorInput) {
  const factor = normalizeUiZoomFactor(factorInput, uiZoomCurrentFactor);
  try {
    localStorage.setItem(UI_ZOOM_STORAGE_KEY, String(factor));
  } catch (_) {}
}

function syncDesktopTitlebarOverlayMetrics() {
  try {
    const root = document.body;
    if (!root) return;
    const factor = normalizeUiZoomFactor(uiZoomCurrentFactor, UI_ZOOM_DEFAULT_FACTOR);
    const safeFactor = factor > 0 ? factor : UI_ZOOM_DEFAULT_FACTOR;
    const compensation = 1 / safeFactor;
    root.style.setProperty("--ui-zoom-compensation", String(compensation));
  } catch (_) {}
}

function normalizeThemeBool(v, fallback = false) {
  if (typeof v === "boolean") return v;
  if (typeof v === "number") return v !== 0;
  const s = String(v || "").trim().toLowerCase();
  if (s === "true" || s === "1" || s === "yes" || s === "on") return true;
  if (s === "false" || s === "0" || s === "no" || s === "off") return false;
  return fallback;
}

function normalizeAppLanguage(value, fallback = APP_LANG_DEFAULT) {
  const lang = String(value || "").trim().toLowerCase();
  if (lang === "pt" || lang === "en") return lang;
  return fallback;
}

function normalizeThemeTimeFormat(value, fallback = THEME_DEFAULT_OPTIONS.time_format) {
  const v = String(value || "").trim().toLowerCase();
  if (v === "12h" || v === "12" || v === "ampm" || v === "am/pm") return "12h";
  if (v === "24h" || v === "24") return "24h";
  return String(fallback || "").trim().toLowerCase() === "12h" ? "12h" : "24h";
}

function readStoredAppLanguage() {
  try {
    return normalizeAppLanguage(localStorage.getItem(APP_LANG_STORAGE_KEY), APP_LANG_DEFAULT);
  } catch (_) {
    return APP_LANG_DEFAULT;
  }
}

function writeStoredAppLanguage(lang) {
  try {
    localStorage.setItem(APP_LANG_STORAGE_KEY, normalizeAppLanguage(lang, APP_LANG_DEFAULT));
  } catch (_) {}
}

function t(key, fallback = "") {
  const table = APP_LANG_LABELS[appLanguage] || APP_LANG_LABELS[APP_LANG_DEFAULT];
  if (Object.prototype.hasOwnProperty.call(table, key)) return table[key];
  const baseTable = APP_LANG_LABELS[APP_LANG_DEFAULT] || {};
  if (Object.prototype.hasOwnProperty.call(baseTable, key)) return baseTable[key];
  return fallback || key;
}

function tf(key, params = {}, fallback = "") {
  let out = String(t(key, fallback) || "");
  if (!params || typeof params !== "object") return out;
  Object.entries(params).forEach(([name, value]) => {
    out = out.split(`{${name}}`).join(String(value ?? ""));
  });
  return out;
}

appLanguage = readStoredAppLanguage();

function normalizeHexColor(value, fallback) {
  let s = String(value || "").trim();
  if (!s) return fallback;
  if (!s.startsWith("#")) s = `#${s}`;
  if (/^#[0-9a-f]{3}$/i.test(s)) {
    s = `#${s[1]}${s[1]}${s[2]}${s[2]}${s[3]}${s[3]}`;
  }
  if (!/^#[0-9a-f]{6}$/i.test(s)) return fallback;
  return s.toLowerCase();
}

function normalizeThemeOptionalColor(value) {
  const c = normalizeHexColor(value, "");
  if (!/^#[0-9a-f]{6}$/i.test(c || "")) return "";
  return c.toLowerCase();
}

function normalizeNameColor(value) {
  const c = normalizeHexColor(value, "");
  if (!/^#[0-9a-f]{6}$/i.test(c || "")) return "";
  return c.toLowerCase();
}

function normalizeServerRoleColor(value) {
  const c = normalizeHexColor(value, SERVER_ROLE_DEFAULT_COLOR);
  if (!/^#[0-9a-f]{6}$/i.test(c || "")) return SERVER_ROLE_DEFAULT_COLOR;
  return c.toLowerCase();
}

function normalizeServerRoleName(value) {
  const compact = String(value || "").replace(/\s+/g, " ").trim();
  if (!compact) return "";
  return compact.slice(0, SERVER_ROLE_NAME_MAX_LEN);
}

function normalizeServerRolePermissions(value = {}) {
  const src = (value && typeof value === "object" && !Array.isArray(value)) ? value : {};
  const out = {};
  SERVER_ROLE_PERMISSION_KEYS.forEach((key) => {
    out[key] = !!src[key];
  });
  return out;
}

function countEnabledServerRolePermissions(value = {}) {
  const normalized = normalizeServerRolePermissions(value);
  return SERVER_ROLE_PERMISSION_KEYS.reduce((total, key) => total + (normalized[key] ? 1 : 0), 0);
}

function resolveServerRolePermissionPreset(name = "custom") {
  const key = String(name || "").trim().toLowerCase();
  const preset = SERVER_ROLE_PERMISSION_PRESETS[key] || SERVER_ROLE_PERMISSION_PRESETS.custom || {};
  return normalizeServerRolePermissions(preset);
}

function normalizeCallTileColor(value) {
  const c = normalizeHexColor(value, "");
  if (!/^#[0-9a-f]{6}$/i.test(c || "")) return "";
  return c.toLowerCase();
}

function normalizePronouns(value) {
  const compact = String(value || "").replace(/\s+/g, " ").trim();
  if (!compact) return "";
  return compact.slice(0, PROFILE_PRONOUNS_MAX_LEN);
}

function syncProfileBioFieldUi() {
  const bioInput = document.getElementById("bio");
  if (!(bioInput instanceof HTMLTextAreaElement)) return;

  const rawMax = Number.parseInt(String(bioInput.getAttribute("maxlength") || PROFILE_BIO_MAX_LEN), 10);
  const maxLen = Number.isFinite(rawMax) && rawMax > 0 ? rawMax : PROFILE_BIO_MAX_LEN;
  if (bioInput.value.length > maxLen) {
    bioInput.value = bioInput.value.slice(0, maxLen);
  }

  bioInput.style.height = "auto";
  bioInput.style.height = `${Math.max(92, bioInput.scrollHeight)}px`;

  const counter = document.getElementById("bioCharCount");
  if (counter) {
    const used = bioInput.value.length;
    counter.textContent = `${used}/${maxLen}`;
    counter.classList.toggle("is-limit", used >= maxLen);
  }
}

function clampColorPickerNumber(value, min, max, fallback = min) {
  const n = Number.parseFloat(String(value ?? ""));
  if (!Number.isFinite(n)) return fallback;
  if (n < min) return min;
  if (n > max) return max;
  return n;
}

function hexToHsvColor(value) {
  const safe = normalizeHexColor(value, "#8ea0ff");
  const { r, g, b } = hexToRgb(safe);
  const rr = r / 255;
  const gg = g / 255;
  const bb = b / 255;
  const max = Math.max(rr, gg, bb);
  const min = Math.min(rr, gg, bb);
  const d = max - min;
  let h = 0;
  if (d > 0) {
    if (max === rr) h = ((gg - bb) / d) % 6;
    else if (max === gg) h = ((bb - rr) / d) + 2;
    else h = ((rr - gg) / d) + 4;
    h *= 60;
    if (h < 0) h += 360;
  }
  const s = max === 0 ? 0 : (d / max);
  const v = max;
  return {
    h: Math.round(h),
    s: Math.round(s * 100),
    v: Math.round(v * 100),
  };
}

function hsvToHexColor(hInput, sInput, vInput) {
  const hRaw = clampColorPickerNumber(hInput, 0, 360, 0);
  const h = hRaw >= 360 ? 0 : hRaw;
  const s = clampColorPickerNumber(sInput, 0, 100, 100) / 100;
  const v = clampColorPickerNumber(vInput, 0, 100, 100) / 100;
  const c = v * s;
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1));
  const m = v - c;

  let rr = 0;
  let gg = 0;
  let bb = 0;
  if (h < 60) {
    rr = c; gg = x; bb = 0;
  } else if (h < 120) {
    rr = x; gg = c; bb = 0;
  } else if (h < 180) {
    rr = 0; gg = c; bb = x;
  } else if (h < 240) {
    rr = 0; gg = x; bb = c;
  } else if (h < 300) {
    rr = x; gg = 0; bb = c;
  } else {
    rr = c; gg = 0; bb = x;
  }

  return rgbToHex({
    r: (rr + m) * 255,
    g: (gg + m) * 255,
    b: (bb + m) * 255,
  }).toLowerCase();
}

function isPickerGradientCapableInput(input) {
  if (!(input instanceof HTMLInputElement)) return false;
  if (String(input.dataset.gradientDisabled || "").trim() === "1") return false;
  return PICKER_GRADIENT_CAPABLE_INPUT_IDS.has(String(input.id || "").trim());
}

function isThemeAppearanceColorInput(input) {
  if (!(input instanceof HTMLInputElement)) return false;
  const id = String(input.id || "").trim();
  if (!id.startsWith("theme")) return false;
  return input.classList.contains("themeColorInput");
}

function normalizePickerGradientAngle(value, fallback = 180) {
  return Math.round(clampColorPickerNumber(value, 0, 360, fallback));
}

function readInputGradientState(input) {
  if (!(input instanceof HTMLInputElement)) {
    return { enabled: false, color2: "", angle: 180 };
  }
  const enabled = isPickerGradientCapableInput(input) && input.dataset.gradientEnabled === "1";
  const color2 = enabled ? normalizeHexColor(input.dataset.gradientColor2 || "", "") : "";
  const angle = enabled ? normalizePickerGradientAngle(input.dataset.gradientAngle, 180) : 180;
  return {
    enabled: !!(enabled && color2),
    color2: color2 || "",
    angle,
  };
}

function readThemeGradientFromInput(input, deepKey, angleKey) {
  const grad = readInputGradientState(input);
  return {
    [deepKey]: grad.enabled ? grad.color2 : "",
    [angleKey]: grad.enabled ? grad.angle : 180,
  };
}

function writeThemeGradientToInput(input, color2Input = "", angleInput = 180) {
  if (!(input instanceof HTMLInputElement)) return;
  const supportsGradient = isPickerGradientCapableInput(input);
  const color2 = supportsGradient ? normalizeHexColor(color2Input, "") : "";
  if (supportsGradient && color2) {
    input.dataset.gradientEnabled = "1";
    input.dataset.gradientColor2 = color2;
    input.dataset.gradientAngle = String(normalizePickerGradientAngle(angleInput, 180));
    return;
  }
  delete input.dataset.gradientEnabled;
  delete input.dataset.gradientColor2;
  delete input.dataset.gradientAngle;
}

function readThemeColorIntensityValue() {
  const input = document.getElementById("themeColorIntensity");
  if (!(input instanceof HTMLInputElement)) return THEME_DEFAULT_OPTIONS.color_intensity;
  return clampInt(input.value, 0, 100, THEME_DEFAULT_OPTIONS.color_intensity);
}

function writeThemeColorIntensityValue(valueInput, { emitInput = true } = {}) {
  const input = document.getElementById("themeColorIntensity");
  if (!(input instanceof HTMLInputElement)) return;
  const value = clampInt(valueInput, 0, 100, THEME_DEFAULT_OPTIONS.color_intensity);
  const prev = clampInt(input.value, 0, 100, THEME_DEFAULT_OPTIONS.color_intensity);
  input.value = String(value);
  if (emitInput && value !== prev) {
    input.dispatchEvent(new Event("input", { bubbles: true }));
    input.dispatchEvent(new Event("change", { bubbles: true }));
  }
}

function getCustomColorPickerEls() {
  return {
    root: document.getElementById("appColorPicker"),
    card: document.getElementById("appColorPickerCard"),
    sv: document.getElementById("appColorPickerSv"),
    svHandle: document.getElementById("appColorPickerSvHandle"),
    hue: document.getElementById("appColorPickerHue"),
    swatches: document.getElementById("appColorPickerSwatches"),
    gradientRow: document.getElementById("appColorPickerGradientRow"),
    gradientToggle: document.getElementById("btnAppColorPickerGradient"),
    stopBase: document.getElementById("btnAppColorPickerStopBase"),
    stopAlt: document.getElementById("btnAppColorPickerStopAlt"),
    angle: document.getElementById("appColorPickerAngle"),
    angleValue: document.getElementById("appColorPickerAngleValue"),
    intensityRow: document.getElementById("appColorPickerIntensityRow"),
    intensity: document.getElementById("appColorPickerIntensity"),
    intensityValue: document.getElementById("appColorPickerIntensityValue"),
    preview: document.getElementById("appColorPickerPreview"),
    hex: document.getElementById("appColorPickerHex"),
    eyedropper: document.getElementById("btnAppColorPickerEyedropper"),
    close: document.getElementById("btnAppColorPickerClose"),
  };
}

function ensureCustomColorPickerEl() {
  let root = document.getElementById("appColorPicker");
  if (root) return root;
  if (!document.body) return null;

  const swatchesHtml = CUSTOM_COLOR_SWATCHES
    .map((hex) => `<button class="appColorPicker__swatch" type="button" data-picker-swatch="${escAttr(hex)}" style="--swatch:${escAttr(hex)}" aria-label="Pick ${escAttr(hex)}"></button>`)
    .join("");

  root = document.createElement("div");
  root.id = "appColorPicker";
  root.className = "appColorPicker hidden";
  root.setAttribute("aria-hidden", "true");
  root.innerHTML = `
    <div id="appColorPickerCard" class="appColorPicker__card" role="dialog" aria-modal="true" aria-label="Color picker">
      <div id="appColorPickerSv" class="appColorPicker__sv">
        <span id="appColorPickerSvHandle" class="appColorPicker__svHandle"></span>
      </div>
      <div class="appColorPicker__tools">
        <span id="appColorPickerPreview" class="appColorPicker__preview" aria-hidden="true"></span>
        <input id="appColorPickerHue" class="appColorPicker__hue" type="range" min="0" max="360" step="1" value="0" />
      </div>
      <div id="appColorPickerSwatches" class="appColorPicker__swatches">${swatchesHtml}</div>
      <div id="appColorPickerGradientRow" class="appColorPicker__gradientRow hidden">
        <button id="btnAppColorPickerGradient" class="appColorPicker__chipBtn" type="button">Gradient</button>
        <button id="btnAppColorPickerStopBase" class="appColorPicker__stopBtn is-on" type="button" aria-label="Edit first gradient color">A</button>
        <button id="btnAppColorPickerStopAlt" class="appColorPicker__stopBtn" type="button" aria-label="Edit second gradient color">B</button>
        <input id="appColorPickerAngle" class="appColorPicker__angle" type="range" min="0" max="360" step="1" value="180" />
        <span id="appColorPickerAngleValue" class="appColorPicker__angleValue">180Â°</span>
      </div>
      <div id="appColorPickerIntensityRow" class="appColorPicker__intensityRow hidden">
        <span class="appColorPicker__intensityLabel">Intensity</span>
        <input id="appColorPickerIntensity" class="appColorPicker__intensity" type="range" min="0" max="100" step="1" value="100" />
        <span id="appColorPickerIntensityValue" class="appColorPicker__intensityValue">100%</span>
      </div>
      <div class="appColorPicker__footer">
        <input id="appColorPickerHex" class="input appColorPicker__hex" maxlength="7" value="#8ea0ff" />
        <button id="btnAppColorPickerEyedropper" class="appColorPicker__eyedropperBtn" type="button" title="Pipeta â€” escolher cor do ecrÃ£" aria-label="Pipeta">
          <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 2a4 4 0 0 1 4 4c0 1.5-.6 2.8-1.6 3.8L6 18l-3 1 1-3 8.2-8.4A4 4 0 0 1 12 2z"/><path d="M5.5 18.5 3 21"/></svg>
        </button>
        <button id="btnAppColorPickerClose" class="btn ghost appColorPicker__done" type="button">Done</button>
      </div>
    </div>
  `;
  document.body.appendChild(root);
  return root;
}

function syncThemeColorInputChip(input) {
  if (!(input instanceof HTMLInputElement)) return;
  const safe = normalizeHexColor(input.value, "#8ea0ff");
  if (input.value !== safe) input.value = safe;
  input.style.setProperty("--theme-color-preview", safe);

  const grad = readInputGradientState(input);
  if (grad.enabled) {
    const angle = normalizePickerGradientAngle(grad.angle, 180);
    input.style.setProperty("--theme-color-preview-2", grad.color2);
    input.style.setProperty("--theme-color-preview-bg", `linear-gradient(${angle}deg, ${safe}, ${grad.color2})`);
    input.classList.add("themeColorInput--has-gradient");
  } else {
    input.style.removeProperty("--theme-color-preview-2");
    input.style.setProperty("--theme-color-preview-bg", safe);
    input.classList.remove("themeColorInput--has-gradient");
  }
}

function syncThemeColorInputsUi() {
  const inputs = Array.from(document.querySelectorAll(".themeColorInput"));
  inputs.forEach((input) => syncThemeColorInputChip(input));
}

function ensureThemeColorInputCustomBinding(input) {
  if (!(input instanceof HTMLInputElement)) return false;
  input.classList.add("themeColorInput--custom");
  if (input.type !== "text") input.type = "text";
  input.readOnly = true;
  input.autocomplete = "off";
  input.spellcheck = false;
  input.setAttribute("aria-haspopup", "dialog");
  input.setAttribute("inputmode", "none");
  syncThemeColorInputChip(input);

  if (input.dataset.customPickerBound === "1") return true;
  input.dataset.customPickerBound = "1";
  input.addEventListener("click", (ev) => {
    ev.preventDefault();
    openCustomColorPickerForInput(input);
  });
  input.addEventListener("keydown", (ev) => {
    if (ev.key !== "Enter" && ev.key !== " " && ev.key !== "ArrowDown") return;
    ev.preventDefault();
    openCustomColorPickerForInput(input);
  });
  input.addEventListener("input", () => {
    syncThemeColorInputChip(input);
  });
  return true;
}

function applyColorToInputFromPicker(baseHex, gradientHex = "", gradientAngle = 180, { emitInput = true } = {}) {
  const input = customColorPickerTargetInput;
  if (!(input instanceof HTMLInputElement)) return;
  const safe = normalizeHexColor(baseHex, input.value || "#8ea0ff");
  const supportsGradient = isPickerGradientCapableInput(input);
  const safeGradientHex = supportsGradient ? normalizeHexColor(gradientHex, "") : "";
  const safeGradientAngle = normalizePickerGradientAngle(gradientAngle, 180);
  const nextGradientEnabled = !!safeGradientHex;

  const prevGradientEnabled = input.dataset.gradientEnabled === "1";
  const prevGradientHex = normalizeHexColor(input.dataset.gradientColor2 || "", "");
  const prevGradientAngle = normalizePickerGradientAngle(input.dataset.gradientAngle, 180);

  if (nextGradientEnabled) {
    input.dataset.gradientEnabled = "1";
    input.dataset.gradientColor2 = safeGradientHex;
    input.dataset.gradientAngle = String(safeGradientAngle);
  } else {
    delete input.dataset.gradientEnabled;
    delete input.dataset.gradientColor2;
    delete input.dataset.gradientAngle;
  }

  const changed = input.value !== safe;
  if (changed) input.value = safe;
  syncThemeColorInputChip(input);
  const gradientChanged = (
    prevGradientEnabled !== nextGradientEnabled
    || prevGradientHex !== safeGradientHex
    || prevGradientAngle !== safeGradientAngle
  );
  if (emitInput && (changed || gradientChanged)) {
    input.dispatchEvent(new Event("input", { bubbles: true }));
    input.dispatchEvent(new Event("change", { bubbles: true }));
  }
}

function renderCustomColorPicker() {
  const els = getCustomColorPickerEls();
  if (!els.root || els.root.classList.contains("hidden")) return;
  const intensitySupported = isThemeAppearanceColorInput(customColorPickerTargetInput);
  const intensityValue = readThemeColorIntensityValue();
  const supportsGradient = !!customColorPickerState.gradientSupported;
  const gradientEnabled = supportsGradient && !!customColorPickerState.gradientEnabled;
  const activeStop = gradientEnabled && customColorPickerState.activeStop === "alt" ? "alt" : "base";

  const baseH = clampColorPickerNumber(customColorPickerState.h, 0, 360, 0);
  const baseS = clampColorPickerNumber(customColorPickerState.s, 0, 100, 100);
  const baseV = clampColorPickerNumber(customColorPickerState.v, 0, 100, 100);
  const altH = clampColorPickerNumber(customColorPickerState.gh, 0, 360, baseH);
  const altS = clampColorPickerNumber(customColorPickerState.gs, 0, 100, baseS);
  const altV = clampColorPickerNumber(customColorPickerState.gv, 0, 100, baseV);
  const angle = normalizePickerGradientAngle(customColorPickerState.gradientAngle, 180);

  const activeH = activeStop === "alt" ? altH : baseH;
  const activeS = activeStop === "alt" ? altS : baseS;
  const activeV = activeStop === "alt" ? altV : baseV;
  const hexBase = hsvToHexColor(baseH, baseS, baseV);
  const hexAlt = hsvToHexColor(altH, altS, altV);
  const previewPaint = gradientEnabled
    ? `linear-gradient(${angle}deg, ${hexBase}, ${hexAlt})`
    : hexBase;

  customColorPickerState = {
    ...customColorPickerState,
    h: baseH,
    s: baseS,
    v: baseV,
    gh: altH,
    gs: altS,
    gv: altV,
    gradientEnabled,
    gradientSupported: supportsGradient,
    gradientAngle: angle,
    activeStop,
  };

  if (els.hue instanceof HTMLInputElement) els.hue.value = String(Math.round(activeH));
  if (els.hex instanceof HTMLInputElement) els.hex.value = activeStop === "alt" ? hexAlt : hexBase;
  if (els.preview instanceof HTMLElement) {
    els.preview.style.setProperty("--picker-preview", hexBase);
    els.preview.style.background = previewPaint;
  }
  if (els.sv instanceof HTMLElement) {
    els.sv.style.setProperty("--picker-hue", `hsl(${Math.round(activeH)} 100% 50%)`);
  }
  if (els.svHandle instanceof HTMLElement) {
    els.svHandle.style.left = `${activeS}%`;
    els.svHandle.style.top = `${100 - activeV}%`;
    els.svHandle.style.setProperty("--picker-preview", activeStop === "alt" ? hexAlt : hexBase);
  }
  if (els.gradientRow instanceof HTMLElement) {
    els.gradientRow.classList.toggle("hidden", !supportsGradient);
  }
  if (els.gradientToggle instanceof HTMLButtonElement) {
    els.gradientToggle.classList.toggle("is-on", gradientEnabled);
    els.gradientToggle.textContent = gradientEnabled ? "Gradient On" : "Gradient Off";
  }
  if (els.stopBase instanceof HTMLButtonElement) {
    els.stopBase.classList.toggle("is-on", activeStop === "base");
    els.stopBase.style.setProperty("--picker-stop", hexBase);
    els.stopBase.disabled = !gradientEnabled;
  }
  if (els.stopAlt instanceof HTMLButtonElement) {
    els.stopAlt.classList.toggle("is-on", activeStop === "alt");
    els.stopAlt.style.setProperty("--picker-stop", hexAlt);
    els.stopAlt.disabled = !gradientEnabled;
  }
  if (els.angle instanceof HTMLInputElement) {
    els.angle.value = String(angle);
    els.angle.disabled = !gradientEnabled;
  }
  if (els.angleValue instanceof HTMLElement) {
    els.angleValue.textContent = `${angle}Â°`;
  }
  if (els.intensityRow instanceof HTMLElement) {
    els.intensityRow.classList.toggle("hidden", !intensitySupported);
  }
  if (els.intensity instanceof HTMLInputElement) {
    els.intensity.value = String(intensityValue);
    els.intensity.disabled = !intensitySupported;
  }
  if (els.intensityValue instanceof HTMLElement) {
    els.intensityValue.textContent = `${intensityValue}%`;
  }

  applyColorToInputFromPicker(
    hexBase,
    gradientEnabled ? hexAlt : "",
    angle,
    { emitInput: true }
  );
}

function moveCustomColorPickerSvFromEvent(ev) {
  const els = getCustomColorPickerEls();
  if (!(els.sv instanceof HTMLElement)) return;
  const rect = els.sv.getBoundingClientRect();
  if (!rect.width || !rect.height) return;
  const x = clampColorPickerNumber((ev.clientX - rect.left) / rect.width, 0, 1, 0);
  const y = clampColorPickerNumber((ev.clientY - rect.top) / rect.height, 0, 1, 0);
  const nextS = Math.round(x * 100);
  const nextV = Math.round((1 - y) * 100);
  if (customColorPickerState.gradientEnabled && customColorPickerState.activeStop === "alt") {
    customColorPickerState.gs = nextS;
    customColorPickerState.gv = nextV;
  } else {
    customColorPickerState.s = nextS;
    customColorPickerState.v = nextV;
  }
  renderCustomColorPicker();
}

function moveCustomColorPickerHueFromEvent(ev) {
  const els = getCustomColorPickerEls();
  const hueEl = els.hue;
  if (!(hueEl instanceof HTMLInputElement)) return;
  const rect = hueEl.getBoundingClientRect();
  if (!rect.width) return;
  const ratio = clampColorPickerNumber((ev.clientX - rect.left) / rect.width, 0, 1, 0);
  const hue = Math.round(ratio * 360);
  if (customColorPickerState.gradientEnabled && customColorPickerState.activeStop === "alt") {
    customColorPickerState.gh = hue;
  } else {
    customColorPickerState.h = hue;
  }
  renderCustomColorPicker();
}

function positionCustomColorPicker() {
  const els = getCustomColorPickerEls();
  if (!(els.root instanceof HTMLElement) || !(els.card instanceof HTMLElement)) return;
  if (els.root.classList.contains("hidden")) return;
  const input = customColorPickerTargetInput;
  if (!(input instanceof HTMLInputElement)) return;

  const anchor = customColorPickerAnchorEl instanceof HTMLElement ? customColorPickerAnchorEl : input;
  const rect = customColorPickerAnchorRect || anchor.getBoundingClientRect();
  const cardRect = els.card.getBoundingClientRect();
  const margin = 10;
  let left = rect.left;
  let top = rect.bottom + 8;

  if (left + cardRect.width > window.innerWidth - margin) {
    left = window.innerWidth - cardRect.width - margin;
  }
  if (left < margin) left = margin;
  if (top + cardRect.height > window.innerHeight - margin) {
    top = rect.top - cardRect.height - 8;
  }
  if (top < margin) top = margin;

  els.root.style.left = `${Math.round(left)}px`;
  els.root.style.top = `${Math.round(top)}px`;
}

function closeCustomColorPicker({ restoreFocus = false } = {}) {
  const els = getCustomColorPickerEls();
  if (els.root) {
    els.root.classList.add("hidden");
    els.root.setAttribute("aria-hidden", "true");
  }
  const focusTarget = customColorPickerTargetInput;
  const restoreFocusTarget = (focusTarget instanceof HTMLInputElement && focusTarget.id === "dmFormatColorPicker")
    ? (document.getElementById("dmInput") || focusTarget)
    : focusTarget;
  const lastValue = focusTarget instanceof HTMLInputElement ? normalizeHexColor(focusTarget.value || "", "") : "";
  const gradientState = focusTarget instanceof HTMLInputElement ? readInputGradientState(focusTarget) : { enabled: false, color2: "", angle: 180 };
  customColorPickerTargetInput = null;
  customColorPickerAnchorEl = null;
  customColorPickerAnchorRect = null;
  customColorPickerDragMode = "";
  if (focusTarget instanceof HTMLInputElement) {
    focusTarget.dispatchEvent(new CustomEvent("appcolorpickerclose", {
      bubbles: false,
      detail: {
        value: lastValue,
        gradientEnabled: !!gradientState.enabled,
        gradientColor2: gradientState.color2 || "",
        gradientAngle: gradientState.angle || 180,
      },
    }));
  }
  if (restoreFocus && restoreFocusTarget instanceof HTMLElement) {
    try { restoreFocusTarget.focus({ preventScroll: true }); } catch (_) {}
  }
}

function openCustomColorPickerForInput(input, options = {}) {
  if (!(input instanceof HTMLInputElement)) return;
  const root = ensureCustomColorPickerEl();
  if (!root) return;

  customColorPickerTargetInput = input;
  customColorPickerAnchorEl = options?.anchorEl instanceof HTMLElement ? options.anchorEl : null;
  customColorPickerAnchorRect = null;
  if (options?.freezeAnchorRect) {
    const anchor = customColorPickerAnchorEl instanceof HTMLElement ? customColorPickerAnchorEl : input;
    const rect = anchor?.getBoundingClientRect?.();
    if (rect) {
      customColorPickerAnchorRect = {
        left: Number(rect.left) || 0,
        top: Number(rect.top) || 0,
        right: Number(rect.right) || 0,
        bottom: Number(rect.bottom) || 0,
        width: Number(rect.width) || 0,
        height: Number(rect.height) || 0,
      };
    }
  }
  syncThemeColorInputChip(input);
  const baseHsv = hexToHsvColor(input.value || "#8ea0ff");
  const gradient = readInputGradientState(input);
  const altHsv = gradient.enabled ? hexToHsvColor(gradient.color2) : baseHsv;
  customColorPickerState = {
    h: baseHsv.h,
    s: baseHsv.s,
    v: baseHsv.v,
    gh: altHsv.h,
    gs: altHsv.s,
    gv: altHsv.v,
    gradientEnabled: gradient.enabled,
    gradientSupported: isPickerGradientCapableInput(input),
    gradientAngle: gradient.angle,
    activeStop: "base",
  };

  root.classList.remove("hidden");
  root.setAttribute("aria-hidden", "false");
  const eyedropperBtn = document.getElementById("btnAppColorPickerEyedropper");
  if (eyedropperBtn) eyedropperBtn.hidden = !window.EyeDropper;
  renderCustomColorPicker();
  positionCustomColorPicker();
  requestAnimationFrame(positionCustomColorPicker);
}

function bindCustomThemeColorPickerOnce() {
  const root = ensureCustomColorPickerEl();
  if (!root) return;

  const inputs = Array.from(document.querySelectorAll(".themeColorInput"));
  inputs.forEach((input) => {
    ensureThemeColorInputCustomBinding(input);
  });
  syncThemeColorInputsUi();

  if (customColorPickerBound) return;
  customColorPickerBound = true;

  const els = getCustomColorPickerEls();
  if (!els.root) return;

  els.card?.addEventListener("click", (ev) => ev.stopPropagation());
  els.sv?.addEventListener("mousedown", (ev) => {
    ev.preventDefault();
    customColorPickerDragMode = "sv";
    moveCustomColorPickerSvFromEvent(ev);
  });
  els.hue?.addEventListener("mousedown", (ev) => {
    ev.preventDefault();
    customColorPickerDragMode = "hue";
    moveCustomColorPickerHueFromEvent(ev);
  });
  els.hue?.addEventListener("input", (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    const hue = clampColorPickerNumber(target.value, 0, 360, 0);
    if (customColorPickerState.gradientEnabled && customColorPickerState.activeStop === "alt") {
      customColorPickerState.gh = hue;
    } else {
      customColorPickerState.h = hue;
    }
    renderCustomColorPicker();
  });
  els.swatches?.addEventListener("mousedown", (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLElement)) return;
    if (!target.closest("[data-picker-swatch]")) return;
    ev.preventDefault();
  });
  els.swatches?.addEventListener("click", (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLElement)) return;
    const swatchBtn = target.closest("[data-picker-swatch]");
    if (!(swatchBtn instanceof HTMLElement)) return;
    const swatch = normalizeHexColor(swatchBtn.getAttribute("data-picker-swatch") || "", "");
    if (!swatch) return;
    const hsv = hexToHsvColor(swatch);
    if (customColorPickerState.gradientEnabled && customColorPickerState.activeStop === "alt") {
      customColorPickerState.gh = hsv.h;
      customColorPickerState.gs = hsv.s;
      customColorPickerState.gv = hsv.v;
    } else {
      customColorPickerState.h = hsv.h;
      customColorPickerState.s = hsv.s;
      customColorPickerState.v = hsv.v;
    }
    renderCustomColorPicker();
  });
  els.hex?.addEventListener("change", (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    const hex = normalizeHexColor(target.value, "");
    if (!hex) {
      const resetHex = (customColorPickerState.gradientEnabled && customColorPickerState.activeStop === "alt")
        ? hsvToHexColor(customColorPickerState.gh, customColorPickerState.gs, customColorPickerState.gv)
        : hsvToHexColor(customColorPickerState.h, customColorPickerState.s, customColorPickerState.v);
      target.value = resetHex;
      return;
    }
    const hsv = hexToHsvColor(hex);
    if (customColorPickerState.gradientEnabled && customColorPickerState.activeStop === "alt") {
      customColorPickerState.gh = hsv.h;
      customColorPickerState.gs = hsv.s;
      customColorPickerState.gv = hsv.v;
    } else {
      customColorPickerState.h = hsv.h;
      customColorPickerState.s = hsv.s;
      customColorPickerState.v = hsv.v;
    }
    renderCustomColorPicker();
  });
  els.gradientToggle?.addEventListener("click", () => {
    if (!customColorPickerState.gradientSupported) return;
    customColorPickerState.gradientEnabled = !customColorPickerState.gradientEnabled;
    if (customColorPickerState.gradientEnabled) {
      customColorPickerState.activeStop = customColorPickerState.activeStop === "alt" ? "alt" : "base";
    } else {
      customColorPickerState.activeStop = "base";
    }
    renderCustomColorPicker();
  });
  els.stopBase?.addEventListener("click", () => {
    if (!customColorPickerState.gradientEnabled) return;
    customColorPickerState.activeStop = "base";
    renderCustomColorPicker();
  });
  els.stopAlt?.addEventListener("click", () => {
    if (!customColorPickerState.gradientEnabled) return;
    customColorPickerState.activeStop = "alt";
    renderCustomColorPicker();
  });
  els.angle?.addEventListener("input", (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    customColorPickerState.gradientAngle = normalizePickerGradientAngle(target.value, 180);
    renderCustomColorPicker();
  });
  els.intensity?.addEventListener("input", (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    const supportsIntensity = isThemeAppearanceColorInput(customColorPickerTargetInput);
    if (!supportsIntensity) return;
    writeThemeColorIntensityValue(target.value, { emitInput: true });
    if (els.intensityValue instanceof HTMLElement) {
      const value = clampInt(target.value, 0, 100, THEME_DEFAULT_OPTIONS.color_intensity);
      els.intensityValue.textContent = `${value}%`;
    }
  });
  els.close?.addEventListener("click", () => closeCustomColorPicker({ restoreFocus: true }));

  els.eyedropper?.addEventListener("click", async () => {
    if (!window.EyeDropper) return;
    customColorPickerEyedropperActive = true;
    try {
      const dropper = new window.EyeDropper();
      const result = await dropper.open();
      const hex = normalizeHexColor(result?.sRGBHex || "", "");
      if (hex) {
        const hsv = hexToHsvColor(hex);
        if (customColorPickerState.gradientEnabled && customColorPickerState.activeStop === "alt") {
          customColorPickerState.gh = hsv.h;
          customColorPickerState.gs = hsv.s;
          customColorPickerState.gv = hsv.v;
        } else {
          customColorPickerState.h = hsv.h;
          customColorPickerState.s = hsv.s;
          customColorPickerState.v = hsv.v;
        }
        renderCustomColorPicker();
      }
    } catch (_) {
      // user cancelled or browser denied
    } finally {
      customColorPickerEyedropperActive = false;
    }
  });

  window.addEventListener("mousemove", (ev) => {
    if (customColorPickerDragMode === "sv") {
      moveCustomColorPickerSvFromEvent(ev);
      return;
    }
    if (customColorPickerDragMode === "hue") {
      moveCustomColorPickerHueFromEvent(ev);
    }
  });
  window.addEventListener("mouseup", () => {
    customColorPickerDragMode = "";
  });
  window.addEventListener("resize", () => {
    if (!customColorPickerTargetInput) return;
    positionCustomColorPicker();
  });
  window.addEventListener("scroll", () => {
    if (!customColorPickerTargetInput) return;
    positionCustomColorPicker();
  }, true);
  document.addEventListener("keydown", (ev) => {
    if (ev.key !== "Escape") return;
    const currentRoot = document.getElementById("appColorPicker");
    if (!currentRoot || currentRoot.classList.contains("hidden")) return;
    ev.preventDefault();
    closeCustomColorPicker({ restoreFocus: true });
  });
  document.addEventListener("mousedown", (ev) => {
    if (customColorPickerEyedropperActive) return;
    const currentRoot = document.getElementById("appColorPicker");
    if (!currentRoot || currentRoot.classList.contains("hidden")) return;
    const target = ev.target;
    if (!(target instanceof HTMLElement)) return;
    if (target.closest("#appColorPicker")) return;
    if (target.closest(".themeColorInput--custom")) return;
    closeCustomColorPicker({ restoreFocus: false });
  });
  document.addEventListener("click", (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLElement)) return;
    const input = target.closest(".themeColorInput");
    if (!(input instanceof HTMLInputElement)) return;
    if (target.closest("#appColorPicker")) return;
    ensureThemeColorInputCustomBinding(input);
    ev.preventDefault();
    openCustomColorPickerForInput(input);
  });
  document.addEventListener("focusin", (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLElement)) return;
    const input = target.closest(".themeColorInput");
    if (!(input instanceof HTMLInputElement)) return;
    ensureThemeColorInputCustomBinding(input);
  });
}

if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", () => {
    bindCustomThemeColorPickerOnce();
  }, { once: true });
} else {
  queueMicrotask(() => {
    bindCustomThemeColorPickerOnce();
  });
}

function normalizeBannerUrl(value) {
  const s = String(value || "").trim();
  if (!s) return "";
  if (
    s.startsWith("http://")
    || s.startsWith("https://")
    || s.startsWith("data:image/")
    || s.startsWith("blob:")
    || s.startsWith("./")
    || s.startsWith("../")
    || s.startsWith("/")
  ) return s;
  return "";
}

function normalizeAvatarUrl(value) {
  const s = String(value || "").trim();
  if (!s) return "";
  const lower = s.toLowerCase();
  if (lower === "null" || lower === "undefined" || lower === "[object object]") return "";
  return s;
}

function resolveProfileAvatarUrl(primary = "", fallback = "") {
  const direct = normalizeAvatarUrl(primary);
  if (direct) return direct;
  return normalizeAvatarUrl(fallback);
}

function resolveAvatarUrlFromObject(source = null) {
  if (!source || typeof source !== "object" || Array.isArray(source)) return "";
  const directCandidates = [
    source.avatar_url,
    source.avatarUrl,
    source.avatar,
    source.picture,
    source.picture_url,
    source.profile_image_url,
    source.photo_url,
    source.photoURL,
    source.image,
    source.image_url,
    source.src,
    source.url,
    source.publicUrl,
    source.public_url,
    source.href,
  ];
  for (const candidate of directCandidates) {
    const resolved = normalizeAvatarUrl(candidate);
    if (resolved) return resolved;
  }
  const nestedCandidates = [
    source.data,
    source.profile,
    source.user,
    source.identity_data,
    source.metadata,
    source.user_metadata,
  ];
  for (const nested of nestedCandidates) {
    const resolved = resolveAvatarUrlFromObject(nested);
    if (resolved) return resolved;
  }
  return "";
}

function resolveProfileBannerUrl(primary = "", themeSettings = null, fallback = "") {
  const direct = normalizeBannerUrl(primary);
  if (direct) return direct;
  const themeBanner = normalizeBannerUrl(themeSettings?.banner_url);
  if (themeBanner) return themeBanner;
  return normalizeBannerUrl(fallback);
}

function normalizePresenceStatus(value) {
  const s = String(value || "").trim().toLowerCase();
  if (s === "online" || s === "idle" || s === "dnd" || s === "invisible" || s === "offline") return s;
  return "online";
}

const PRESENCE_STATUS_VALUES = new Set(["online", "idle", "dnd", "invisible", "offline"]);

function readPresenceStatusValue(value) {
  const s = String(value || "").trim().toLowerCase();
  return PRESENCE_STATUS_VALUES.has(s) ? s : "";
}

function resolveAccountPresenceStatus(profileLike = null, fallbackStatus = "") {
  const profile = (profileLike && typeof profileLike === "object") ? profileLike : {};
  const resolved = readPresenceStatusValue(profile?.status)
    || readPresenceStatusValue(profile?.theme_settings?.presence_status)
    || readPresenceStatusValue(fallbackStatus)
    || readPresenceStatusValue(getMyStatus())
    || "online";
  return normalizePresenceStatus(resolved);
}

function resolveMyPresenceStatus(profileLike = null) {
  const stored = readPresenceStatusValue(getStoredMyStatus());
  if (stored) return normalizePresenceStatus(stored);
  return resolveAccountPresenceStatus(profileLike, getMyStatus());
}

let profileNameColorSupported = null;
let profileCallTileColorSupported = null;
let profileBannerUrlSupported = null;
let profileStatusSupported = null;
let profilePronounsSupported = null;
let profileCreatedAtSupported = null;
const profileCache = new Map();
let meHeaderMediaCacheUserId = "";
let meHeaderAvatarCacheUrl = "";
let meHeaderBannerCacheUrl = "";
const ME_AVATAR_CACHE_STORAGE_PREFIX = "altara_me_avatar_cache_";

function syncMeHeaderMediaCacheScope() {
  const meId = String(state.user?.id || "").trim();
  if (meId === meHeaderMediaCacheUserId) return meId;
  meHeaderMediaCacheUserId = meId;
  meHeaderAvatarCacheUrl = "";
  meHeaderBannerCacheUrl = "";
  return meId;
}

function readStoredMeAvatarUrl(userIdInput = "") {
  const uid = String(userIdInput || state.user?.id || "").trim();
  if (!uid) return "";
  try {
    const raw = localStorage.getItem(`${ME_AVATAR_CACHE_STORAGE_PREFIX}${uid}`);
    return resolveProfileAvatarUrl(raw, "");
  } catch (_) {
    return "";
  }
}

function writeStoredMeAvatarUrl(userIdInput = "", avatarUrlInput = "") {
  const uid = String(userIdInput || state.user?.id || "").trim();
  if (!uid) return;
  const avatarUrl = resolveProfileAvatarUrl(avatarUrlInput, "");
  try {
    const key = `${ME_AVATAR_CACHE_STORAGE_PREFIX}${uid}`;
    if (avatarUrl) localStorage.setItem(key, avatarUrl);
    else localStorage.removeItem(key);
  } catch (_) {}
}

function resolveAuthUserAvatarUrl(userInput = state.user) {
  const meta = (userInput?.user_metadata && typeof userInput.user_metadata === "object")
    ? userInput.user_metadata
    : {};
  const rawMeta = (userInput?.raw_user_meta_data && typeof userInput.raw_user_meta_data === "object")
    ? userInput.raw_user_meta_data
    : {};
  const appMeta = (userInput?.app_metadata && typeof userInput.app_metadata === "object")
    ? userInput.app_metadata
    : {};
  const direct = resolveProfileAvatarUrl(
    resolveAvatarUrlFromObject(meta),
    resolveProfileAvatarUrl(
      resolveAvatarUrlFromObject(rawMeta),
      resolveAvatarUrlFromObject(appMeta)
    )
  );
  if (direct) return direct;
  const identities = Array.isArray(userInput?.identities) ? userInput.identities : [];
  for (const identity of identities) {
    const fromIdentity = resolveProfileAvatarUrl(
      resolveAvatarUrlFromObject(identity),
      resolveAvatarUrlFromObject(identity?.identity_data)
    );
    if (fromIdentity) return fromIdentity;
  }
  return "";
}

function getRenderedMeAvatarUrl() {
  if (typeof document === "undefined") return "";
  const src = String(document.querySelector("#meAvatar img")?.getAttribute("src") || "").trim();
  return resolveProfileAvatarUrl(src, "");
}

function getRenderedMeBannerUrl() {
  if (typeof document === "undefined") return "";
  const src = String(document.querySelector("#meProfileCard .profileBannerMedia")?.getAttribute("src") || "").trim();
  return resolveProfileBannerUrl(src, null, "");
}

function cacheProfileRow(row) {
  if (!row || !row.id) return;
  const id = String(row.id || "").trim();
  if (!id) return;

  const prev = profileCache.get(id) || {};
  const next = { ...prev };
  for (const [k, v] of Object.entries(row || {})) {
    if (typeof v !== "undefined") next[k] = v;
  }
  const prevThemeSettings = prev?.theme_settings && typeof prev.theme_settings === "object"
    ? normalizeThemeSettings(prev.theme_settings)
    : null;
  const prevAvatarUrl = resolveProfileAvatarUrl(prev?.avatar_url, "");
  const prevBannerUrl = resolveProfileBannerUrl(prev?.banner_url, prevThemeSettings, "");
  if (typeof next.name_color !== "undefined") {
    next.name_color = normalizeNameColor(next.name_color);
  }
  if (typeof next.call_tile_color !== "undefined") {
    next.call_tile_color = normalizeCallTileColor(next.call_tile_color);
  }
  if (typeof next.pronouns !== "undefined") {
    next.pronouns = normalizePronouns(next.pronouns);
  }
  if (typeof next.created_at !== "undefined") {
    next.created_at = String(next.created_at || "").trim() || null;
  }
  if (typeof next.avatar_url !== "undefined") {
    next.avatar_url = resolveProfileAvatarUrl(next.avatar_url, prevAvatarUrl) || null;
  }
  if (typeof next.banner_url !== "undefined") {
    next.banner_url = resolveProfileBannerUrl(next.banner_url, next.theme_settings, prevBannerUrl);
  }
  if (typeof next.theme_settings !== "undefined" && next.theme_settings !== null) {
    next.theme_settings = normalizeThemeSettings(next.theme_settings);
  } else if ((next.theme_settings === null || typeof next.theme_settings === "undefined") && prevThemeSettings) {
    next.theme_settings = prevThemeSettings;
  }
  const resolvedBannerUrl = resolveProfileBannerUrl(next.banner_url, next.theme_settings, prevBannerUrl);
  if (resolvedBannerUrl) next.banner_url = resolvedBannerUrl;
  if (typeof next.status !== "undefined") {
    next.status = normalizePresenceStatus(next.status);
  } else {
    const fromTheme = readPresenceStatusValue(next?.theme_settings?.presence_status);
    if (fromTheme) next.status = fromTheme;
  }
  profileCache.set(id, next);
}

function cacheProfileRows(rows = []) {
  (rows || []).forEach(cacheProfileRow);
}

function mergeDefinedObjectFields(base = {}, patch = null) {
  const next = { ...((base && typeof base === "object") ? base : {}) };
  if (!patch || typeof patch !== "object") return next;
  for (const [key, value] of Object.entries(patch)) {
    if (typeof value !== "undefined") next[key] = value;
  }
  return next;
}

function getCurrentMeProfileSnapshot(overrides = null) {
  const meId = String(state.user?.id || "").trim();
  const cached = meId ? (profileCache.get(meId) || {}) : {};
  let next = mergeDefinedObjectFields(cached, state.me || {});
  if (overrides && typeof overrides === "object") {
    next = mergeDefinedObjectFields(next, overrides);
  }
  if (meId && !String(next.id || "").trim()) next.id = meId;
  const cachedThemeSettings = cached?.theme_settings && typeof cached.theme_settings === "object"
    ? normalizeThemeSettings(cached.theme_settings)
    : null;
  if (next?.theme_settings && typeof next.theme_settings === "object") {
    next.theme_settings = normalizeThemeSettings(next.theme_settings);
  } else if (cachedThemeSettings) {
    next.theme_settings = cachedThemeSettings;
  }
  const resolvedAvatarUrl = resolveProfileAvatarUrl(
    next?.avatar_url,
    resolveProfileAvatarUrl(cached?.avatar_url, resolveAuthUserAvatarUrl(state.user))
  );
  if (resolvedAvatarUrl) next.avatar_url = resolvedAvatarUrl;
  const resolvedBannerUrl = resolveProfileBannerUrl(
    next?.banner_url,
    next?.theme_settings,
    resolveProfileBannerUrl(cached?.banner_url, cachedThemeSettings, "")
  );
  if (resolvedBannerUrl) next.banner_url = resolvedBannerUrl;
  return next;
}

function getCachedProfile(userId) {
  const id = String(userId || "").trim();
  if (!id) return null;
  if (id === String(state.user?.id || "").trim()) {
    return getCurrentMeProfileSnapshot({ id });
  }
  return profileCache.get(id) || null;
}

function getCurrentMeAvatarUrl() {
  syncMeHeaderMediaCacheScope();
  const me = getCurrentMeProfileSnapshot();
  const resolved = resolveProfileAvatarUrl(
    me?.avatar_url,
    resolveProfileAvatarUrl(
      resolveAuthUserAvatarUrl(state.user),
      resolveProfileAvatarUrl(
        getRenderedMeAvatarUrl(),
        resolveProfileAvatarUrl(
          meHeaderAvatarCacheUrl,
          readStoredMeAvatarUrl(me?.id || state.user?.id || "")
        )
      )
    )
  );
  if (resolved) {
    meHeaderAvatarCacheUrl = resolved;
    writeStoredMeAvatarUrl(me?.id || state.user?.id || "", resolved);
    if (state.me && !resolveProfileAvatarUrl(state.me?.avatar_url, "")) {
      state.me.avatar_url = resolved;
      if (state.user?.id) cacheProfileRow({ id: state.user.id, avatar_url: resolved });
    }
  }
  return resolved;
}

function resolveUserNameColor(userId, fallbackColor = "") {
  const p = getCachedProfile(userId);
  const fromProfile = normalizeNameColor(p?.name_color);
  if (fromProfile) return fromProfile;
  return normalizeNameColor(fallbackColor);
}

function resolveCallTileColor(userId, fallbackColor = "") {
  const p = getCachedProfile(userId);
  const fromProfile = normalizeCallTileColor(p?.call_tile_color);
  if (fromProfile) return fromProfile;
  return normalizeCallTileColor(fallbackColor);
}

function resolveUserBannerUrl(userId, fallbackUrl = "") {
  const p = getCachedProfile(userId);
  const fromProfile = normalizeBannerUrl(p?.banner_url);
  if (fromProfile) return fromProfile;
  const fromTheme = normalizeBannerUrl(p?.theme_settings?.banner_url);
  if (fromTheme) return fromTheme;
  return normalizeBannerUrl(fallbackUrl);
}

function buildUserNameColorAttrs(userId, fallbackColor = "") {
  const color = resolveUserNameColor(userId, fallbackColor);
  if (!color) return { cls: "", style: "" };
  return {
    cls: " userNameCustom",
    style: ` style="--user-name-color:${escAttr(color)}"`,
  };
}

function getPresenceStatusForUser(userId) {
  const id = String(userId || "").trim();
  if (!id) return "offline";
  if (id === String(state.user?.id || "").trim()) {
    return resolveMyPresenceStatus(state.me);
  }
  const p = (presenceList || []).find((x) => String(x?.id || "").trim() === id);
  if (!p?.status || p.status === "invisible") return "offline";
  return p.status;
}

async function fetchProfilesByIds(userIds, { includeBio = false, force = false } = {}) {
  const wanted = Array.from(new Set((userIds || [])
    .map((v) => String(v || "").trim())
    .filter(Boolean)));
  if (!wanted.length) return [];

  const missing = wanted.filter((id) => {
    if (force) return true;
    const cached = getCachedProfile(id);
    if (!cached) return true;
    if (includeBio && typeof cached.bio === "undefined") return true;
    if (includeBio && profilePronounsSupported !== false && typeof cached.pronouns === "undefined") return true;
    if (profileCreatedAtSupported !== false && typeof cached.created_at === "undefined") return true;
    if (profileNameColorSupported !== false && typeof cached.name_color === "undefined") return true;
    if (profileCallTileColorSupported !== false && typeof cached.call_tile_color === "undefined") return true;
    if (profileBannerUrlSupported !== false && typeof cached.banner_url === "undefined") return true;
    return false;
  });

  if (!missing.length) {
    return wanted.map((id) => getCachedProfile(id)).filter(Boolean);
  }

  const baseCols = ["id", "username", "display_name", "avatar_url"];
  if (includeBio) baseCols.push("bio");

  let useNameColor = profileNameColorSupported !== false;
  let useCallTileColor = profileCallTileColorSupported !== false;
  let useBannerUrl = profileBannerUrlSupported !== false;
  let useThemeSettings = true;
  let useStatus = profileStatusSupported !== false;
  let usePronouns = includeBio && profilePronounsSupported !== false;
  let useCreatedAt = profileCreatedAtSupported !== false;
  let selectCols = [
    ...baseCols,
    ...(usePronouns ? ["pronouns"] : []),
    ...(useCreatedAt ? ["created_at"] : []),
    ...(useStatus ? ["status"] : []),
    ...(useThemeSettings ? ["theme_settings"] : []),
    ...(useNameColor ? ["name_color"] : []),
    ...(useCallTileColor ? ["call_tile_color"] : []),
    ...(useBannerUrl ? ["banner_url"] : []),
  ].join(", ");

  let firstFetchResult = null;
  try {
    firstFetchResult = await awaitWithTimeout(
      supabase
        .from("profiles")
        .select(selectCols)
        .in("id", missing),
      PROFILES_FETCH_TIMEOUT_MS,
      "profiles fetch"
    );
  } catch (e) {
    firstFetchResult = { data: [], error: { message: e?.message || String(e || "profiles fetch failed") } };
  }
  let { data, error } = firstFetchResult || { data: [], error: { message: "profiles fetch failed" } };

  if (error && (useNameColor || useCallTileColor || useBannerUrl || useThemeSettings || useStatus || usePronouns || useCreatedAt)) {
    const msg = String(error?.message || "").toLowerCase();
    let changed = false;
    if (usePronouns && msg.includes("pronouns") && msg.includes("column")) {
      profilePronounsSupported = false;
      usePronouns = false;
      changed = true;
    }
    if (useCreatedAt && msg.includes("created_at") && msg.includes("column")) {
      profileCreatedAtSupported = false;
      useCreatedAt = false;
      changed = true;
    }
    if (useStatus && msg.includes("status") && msg.includes("column")) {
      profileStatusSupported = false;
      useStatus = false;
      changed = true;
    }
    if (useNameColor && msg.includes("name_color") && msg.includes("column")) {
      profileNameColorSupported = false;
      useNameColor = false;
      changed = true;
    }
    if (useCallTileColor && msg.includes("call_tile_color") && msg.includes("column")) {
      profileCallTileColorSupported = false;
      useCallTileColor = false;
      changed = true;
    }
    if (useBannerUrl && msg.includes("banner_url") && msg.includes("column")) {
      profileBannerUrlSupported = false;
      useBannerUrl = false;
      changed = true;
    }
    if (useThemeSettings && msg.includes("theme_settings") && msg.includes("column")) {
      useThemeSettings = false;
      changed = true;
    }
    if (changed) {
      selectCols = [
        ...baseCols,
        ...(usePronouns ? ["pronouns"] : []),
        ...(useCreatedAt ? ["created_at"] : []),
        ...(useStatus ? ["status"] : []),
        ...(useThemeSettings ? ["theme_settings"] : []),
        ...(useNameColor ? ["name_color"] : []),
        ...(useCallTileColor ? ["call_tile_color"] : []),
        ...(useBannerUrl ? ["banner_url"] : []),
      ].join(", ");
      let retryResult = null;
      try {
        retryResult = await awaitWithTimeout(
          supabase
            .from("profiles")
            .select(selectCols)
            .in("id", missing),
          PROFILES_FETCH_TIMEOUT_MS,
          "profiles fetch retry"
        );
      } catch (e) {
        retryResult = { data: [], error: { message: e?.message || String(e || "profiles fetch retry failed") } };
      }
      ({ data, error } = retryResult || { data: [], error: { message: "profiles fetch retry failed" } });
    }
  }

  if (error) {
    console.warn("profiles fetch failed:", error?.message || error);
    return wanted.map((id) => getCachedProfile(id)).filter(Boolean);
  }

  if (usePronouns && profilePronounsSupported === null) profilePronounsSupported = true;
  if (useCreatedAt && profileCreatedAtSupported === null) profileCreatedAtSupported = true;
  if (useNameColor && profileNameColorSupported === null) profileNameColorSupported = true;
  if (useCallTileColor && profileCallTileColorSupported === null) profileCallTileColorSupported = true;
  if (useBannerUrl && profileBannerUrlSupported === null) profileBannerUrlSupported = true;
  if (useStatus && profileStatusSupported === null) profileStatusSupported = true;
  if (!usePronouns) {
    (data || []).forEach((row) => {
      if (typeof row.pronouns === "undefined") row.pronouns = null;
    });
  }
  if (!useCreatedAt) {
    (data || []).forEach((row) => {
      if (typeof row.created_at === "undefined") row.created_at = null;
    });
  }
  if (!useStatus) {
    (data || []).forEach((row) => {
      if (typeof row.status === "undefined") row.status = null;
    });
  }
  if (!useNameColor) {
    (data || []).forEach((row) => {
      if (typeof row.name_color === "undefined") row.name_color = null;
    });
  }
  if (!useCallTileColor) {
    (data || []).forEach((row) => {
      if (typeof row.call_tile_color === "undefined") row.call_tile_color = null;
    });
  }
  if (!useBannerUrl) {
    (data || []).forEach((row) => {
      if (typeof row.banner_url === "undefined") row.banner_url = null;
    });
  }

  (data || []).forEach((row) => {
    if (!row || typeof row !== "object") return;
    const directBanner = normalizeBannerUrl(row.banner_url);
    let themeBanner = "";
    if (useThemeSettings && row.theme_settings) {
      const theme = normalizeThemeSettings(row.theme_settings);
      themeBanner = normalizeBannerUrl(theme.banner_url);
      row.theme_settings = theme;
    } else if (typeof row.theme_settings === "undefined") {
      row.theme_settings = null;
    }
    if (!readPresenceStatusValue(row.status) && useThemeSettings && row.theme_settings) {
      row.status = readPresenceStatusValue(row.theme_settings?.presence_status) || null;
    }
    row.banner_url = directBanner || themeBanner || "";
  });

  cacheProfileRows(data || []);
  return wanted.map((id) => getCachedProfile(id)).filter(Boolean);
}

function findKnownUserIdByUsername(usernameInput = "") {
  const wanted = String(usernameInput || "").trim().toLowerCase();
  if (!wanted) return "";

  const selfId = normId(state.user?.id || "");
  const selfUsername = String(state.me?.username || state.user?.user_metadata?.username || "").trim().toLowerCase();
  if (selfId && selfUsername && selfUsername === wanted) return selfId;

  const collections = [
    state.friends || [],
    state.incoming || [],
    state.outgoing || [],
    state.messageIncoming || [],
    state.messageOutgoing || [],
    state.dmContacts || [],
    state.blockedUsers || [],
  ];

  for (const rows of collections) {
    for (const row of rows) {
      const username = String(row?.username || "").trim().toLowerCase();
      if (!username || username !== wanted) continue;
      const uid = normId(
        row?.other_user_id
        || row?.from_user_id
        || row?.to_user_id
        || row?.userId
        || row?.user_id
        || row?.blocked_user_id
        || row?.id
        || ""
      );
      if (uid) return uid;
    }
  }

  for (const [id, row] of profileCache.entries()) {
    const username = String(row?.username || "").trim().toLowerCase();
    if (username && username === wanted) return normId(id);
  }

  return "";
}

async function fetchProfileByUsername(usernameInput, { includeBio = true, force = false } = {}) {
  const uname = String(usernameInput || "").trim();
  if (!uname) return null;

  const knownId = findKnownUserIdByUsername(uname);
  if (knownId) {
    const rows = await fetchProfilesByIds([knownId], { includeBio, force }).catch(() => []);
    return rows?.[0] || getCachedProfile(knownId) || null;
  }

  const baseCols = ["id", "username", "display_name", "avatar_url"];
  if (includeBio) baseCols.push("bio");

  let useBannerUrl = profileBannerUrlSupported !== false;
  let useThemeSettings = true;
  let useStatus = profileStatusSupported !== false;
  let selectCols = [
    ...baseCols,
    ...(useStatus ? ["status"] : []),
    ...(useThemeSettings ? ["theme_settings"] : []),
    ...(useBannerUrl ? ["banner_url"] : []),
  ].join(", ");

  const runQuery = async () => {
    try {
      return await awaitWithTimeout(
        supabase
          .from("profiles")
          .select(selectCols)
          .ilike("username", uname)
          .limit(1),
        PROFILES_FETCH_TIMEOUT_MS,
        "profile username lookup"
      );
    } catch (e) {
      return { data: [], error: { message: e?.message || String(e || "profile username lookup failed") } };
    }
  };

  let { data, error } = await runQuery();
  if (error && (useBannerUrl || useThemeSettings || useStatus)) {
    const msg = String(error?.message || "").toLowerCase();
    let changed = false;
    if (useStatus && msg.includes("status") && msg.includes("column")) {
      profileStatusSupported = false;
      useStatus = false;
      changed = true;
    }
    if (useBannerUrl && msg.includes("banner_url") && msg.includes("column")) {
      profileBannerUrlSupported = false;
      useBannerUrl = false;
      changed = true;
    }
    if (useThemeSettings && msg.includes("theme_settings") && msg.includes("column")) {
      useThemeSettings = false;
      changed = true;
    }
    if (changed) {
      selectCols = [
        ...baseCols,
        ...(useStatus ? ["status"] : []),
        ...(useThemeSettings ? ["theme_settings"] : []),
        ...(useBannerUrl ? ["banner_url"] : []),
      ].join(", ");
      ({ data, error } = await runQuery());
    }
  }

  if (error) {
    console.warn("profile username lookup failed:", error?.message || error);
    return null;
  }

  const row = Array.isArray(data) ? (data[0] || null) : null;
  if (!row || typeof row !== "object") return null;
  if (!useStatus && typeof row.status === "undefined") row.status = null;
  if (!useThemeSettings && typeof row.theme_settings === "undefined") row.theme_settings = null;
  if (!useBannerUrl && typeof row.banner_url === "undefined") row.banner_url = null;

  const directBanner = normalizeBannerUrl(row.banner_url);
  let themeBanner = "";
  if (useThemeSettings && row.theme_settings) {
    const theme = normalizeThemeSettings(row.theme_settings);
    themeBanner = normalizeBannerUrl(theme.banner_url);
    row.theme_settings = theme;
  } else if (typeof row.theme_settings === "undefined") {
    row.theme_settings = null;
  }
  if (!readPresenceStatusValue(row.status) && useThemeSettings && row.theme_settings) {
    row.status = readPresenceStatusValue(row.theme_settings?.presence_status) || null;
  }
  row.banner_url = directBanner || themeBanner || "";

  cacheProfileRow(row);
  return getCachedProfile(row.id) || row;
}

async function hydrateFriendRowsWithProfiles(rows = []) {
  const list = Array.isArray(rows) ? rows : [];
  const ids = list.map((f) => f?.other_user_id).filter(Boolean);
  if (!ids.length) return list;

  await fetchProfilesByIds(ids, { includeBio: false });
  return list.map((f) => {
    const id = String(f?.other_user_id || "").trim();
    const p = getCachedProfile(id);
    if (!p) return f;
    return {
      ...f,
      username: p.username || f.username,
      display_name: p.display_name || f.display_name,
      avatar_url: p.avatar_url || f.avatar_url,
      name_color: normalizeNameColor(p.name_color || f.name_color),
      call_tile_color: normalizeCallTileColor(p.call_tile_color || f.call_tile_color),
      banner_url: normalizeBannerUrl(p.banner_url || f.banner_url),
    };
  });
}

function hydrateRelationshipRowsFromCache(rows = []) {
  const list = Array.isArray(rows) ? rows : [];
  return list.map((row) => {
    const uid = normId(
      row?.other_user_id
      || row?.from_user_id
      || row?.to_user_id
      || row?.userId
      || row?.user_id
      || row?.blocked_user_id
      || row?.id
      || ""
    );
    if (!uid) return row;
    const profile = getCachedProfile(uid);
    if (!profile) return row;
    return {
      ...row,
      username: profile.username || row?.username,
      display_name: profile.display_name || row?.display_name || row?.displayName,
      displayName: profile.display_name || row?.displayName || row?.display_name,
      avatar_url: profile.avatar_url || row?.avatar_url || row?.avatarUrl,
      avatarUrl: profile.avatar_url || row?.avatarUrl || row?.avatar_url,
      name_color: normalizeNameColor(profile.name_color || row?.name_color),
      call_tile_color: normalizeCallTileColor(profile.call_tile_color || row?.call_tile_color),
      banner_url: normalizeBannerUrl(profile.banner_url || row?.banner_url),
    };
  });
}

function hexToRgb(hex) {
  const safe = normalizeHexColor(hex, "#000000");
  return {
    r: Number.parseInt(safe.slice(1, 3), 16),
    g: Number.parseInt(safe.slice(3, 5), 16),
    b: Number.parseInt(safe.slice(5, 7), 16),
  };
}

function rgbToHex(rgb) {
  const toHex = (n) => Math.max(0, Math.min(255, Math.round(n))).toString(16).padStart(2, "0");
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`;
}

function mixHex(a, b, t) {
  const aa = hexToRgb(a);
  const bb = hexToRgb(b);
  const p = clamp01(t);
  return rgbToHex({
    r: aa.r + (bb.r - aa.r) * p,
    g: aa.g + (bb.g - aa.g) * p,
    b: aa.b + (bb.b - aa.b) * p,
  });
}

function rgbaFromHex(hex, alpha) {
  const c = hexToRgb(hex);
  return `rgba(${c.r}, ${c.g}, ${c.b}, ${clamp01(alpha)})`;
}

function relativeLuminance(hex) {
  const c = hexToRgb(hex);
  const channel = (v) => {
    const n = v / 255;
    if (n <= 0.03928) return n / 12.92;
    return ((n + 0.055) / 1.055) ** 2.4;
  };
  return (0.2126 * channel(c.r)) + (0.7152 * channel(c.g)) + (0.0722 * channel(c.b));
}

function contrastRatio(hexA, hexB) {
  const a = relativeLuminance(normalizeHexColor(hexA, "#000000"));
  const b = relativeLuminance(normalizeHexColor(hexB, "#ffffff"));
  const light = Math.max(a, b);
  const dark = Math.min(a, b);
  return (light + 0.05) / (dark + 0.05);
}

function pickReadableTextColor(preferredInput, backgroundsInput = []) {
  const preferred = normalizeHexColor(preferredInput, "#f1f2f5");
  const backgrounds = (Array.isArray(backgroundsInput) ? backgroundsInput : [])
    .map((bg) => normalizeHexColor(bg, ""))
    .filter(Boolean);
  if (!backgrounds.length) return preferred;

  const minContrastOnBackgrounds = (color) => {
    let min = Number.POSITIVE_INFINITY;
    backgrounds.forEach((bg) => {
      min = Math.min(min, contrastRatio(color, bg));
    });
    return min;
  };

  const preferredMin = minContrastOnBackgrounds(preferred);
  if (preferredMin >= 2.8) return preferred;

  const light = "#f1f2f5";
  const dark = "#111318";
  const lightMin = minContrastOnBackgrounds(light);
  const darkMin = minContrastOnBackgrounds(dark);
  return lightMin >= darkMin ? light : dark;
}

function pickReadableTextColorForBackgroundAndTopbar(preferredInput, backgroundInput, topbarInput) {
  const preferred = normalizeHexColor(preferredInput, "#f1f2f5");
  const bg = normalizeHexColor(backgroundInput, "#131417");
  const top = normalizeHexColor(topbarInput, bg);
  const light = "#f1f2f5";
  const dark = "#111318";
  const weightedContrast = (color) => (
    (contrastRatio(color, bg) * 0.8) + (contrastRatio(color, top) * 0.2)
  );

  // Keep user-selected text when it remains readable on the main background.
  if (contrastRatio(preferred, bg) >= 2.8) return preferred;

  return weightedContrast(light) >= weightedContrast(dark) ? light : dark;
}

function isSystemPrefersDark() {
  try {
    return !!window.matchMedia?.("(prefers-color-scheme: dark)")?.matches;
  } catch (_) {
    return true;
  }
}

function normalizeThemeSettings(raw) {
  let source = raw;
  if (typeof source === "string") {
    try {
      source = JSON.parse(source);
    } catch (_) {
      source = {};
    }
  }
  if (!source || typeof source !== "object" || Array.isArray(source)) source = {};
  const normalizedBannerCrop = normalizeMediaCropSnapshot(source.banner_crop, "banner");
  const normalizedAvatarCrop = normalizeMediaCropSnapshot(source.avatar_crop, "avatar");
  const normalized = normalizeThemeSettingsEngine(raw, {
    systemDark: isSystemPrefersDark(),
    sidebarMin: LEFT_SIDEBAR_WIDTH_MIN,
    sidebarMax: LEFT_SIDEBAR_WIDTH_MAX,
  });

  const presetRaw = String(normalized.preset || THEME_DEFAULT_PRESET).toLowerCase();
  normalized.preset = presetRaw === "custom"
    ? "custom"
    : (Object.prototype.hasOwnProperty.call(THEME_PRESETS, presetRaw) ? presetRaw : THEME_DEFAULT_PRESET);
  normalized.roundness = clampInt(normalized.roundness, 0, 100, THEME_DEFAULT_OPTIONS.roundness);
  normalized.left_sidebar_width = clampInt(
    normalized.left_sidebar_width,
    LEFT_SIDEBAR_WIDTH_MIN,
    LEFT_SIDEBAR_WIDTH_MAX,
    THEME_DEFAULT_OPTIONS.left_sidebar_width
  );
  normalized.color_intensity = clampInt(
    normalized.color_intensity,
    0,
    100,
    THEME_DEFAULT_OPTIONS.color_intensity
  );
  normalized.banner_url = normalizeBannerUrl(normalized.banner_url);
  normalized.app_language = normalizeAppLanguage(
    normalized.app_language,
    readStoredAppLanguage()
  );
  normalized.time_format = normalizeThemeTimeFormat(
    normalized.time_format,
    THEME_DEFAULT_OPTIONS.time_format
  );
  normalized.dnd_mute_notifications = normalizeThemeBool(
    normalized.dnd_mute_notifications,
    THEME_DEFAULT_OPTIONS.dnd_mute_notifications
  );
  normalized.profile_card_banner = normalizeThemeBool(
    source.profile_card_banner ?? normalized.profile_card_banner,
    THEME_DEFAULT_OPTIONS.profile_card_banner
  );
  normalized.reduce_motion = normalizeThemeBool(
    source.reduce_motion ?? normalized.reduce_motion,
    THEME_DEFAULT_OPTIONS.reduce_motion
  );
  normalized.pause_gifs_when_unfocused = normalizeThemeBool(
    source.pause_gifs_when_unfocused ?? normalized.pause_gifs_when_unfocused,
    THEME_DEFAULT_OPTIONS.pause_gifs_when_unfocused
  );
  normalized.gifs_play_on_hover = normalizeThemeBool(
    source.gifs_play_on_hover ?? normalized.gifs_play_on_hover,
    THEME_DEFAULT_OPTIONS.gifs_play_on_hover
  );
  normalized.presence_status = readPresenceStatusValue(normalized.presence_status);
  normalized.appearance_theme = normalizeAppearanceThemeChoice(
    source.appearance_theme || source.appearanceTheme || inferAppearanceThemeChoiceFromThemeObject(source),
    APPEARANCE_DEFAULT_THEME
  );
  normalized.appearance_accent = normalizeThemeOptionalColor(
    source.appearance_accent || source.appearanceAccent || source.accent
  ) || APPEARANCE_DEFAULT_ACCENT;
  normalized.background_unified = true;
  if (normalizedBannerCrop) normalized.banner_crop = normalizedBannerCrop;
  if (normalizedAvatarCrop) normalized.avatar_crop = normalizedAvatarCrop;

  return normalized;
}

function normalizeMediaCropSnapshot(raw, kind = "banner") {
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) return null;
  const maxScale = kind === "avatar" ? 4 : 4;
  const scaleValue = Number(raw.scale);
  const xValue = Number(raw.x);
  const yValue = Number(raw.y);
  const scale = Number.isFinite(scaleValue) ? clampValue(scaleValue, 1, maxScale) : 1;
  const x = Number.isFinite(xValue) ? clampValue(xValue, 0, 1) : 0.5;
  const y = Number.isFinite(yValue) ? clampValue(yValue, 0, 1) : 0.5;
  return {
    scale: Math.round(scale * 1000) / 1000,
    x: Math.round(x * 1000) / 1000,
    y: Math.round(y * 1000) / 1000,
  };
}

function getThemeMediaCrop(themeLike, kind = "banner") {
  const theme = normalizeThemeSettings(themeLike || {});
  return kind === "avatar"
    ? normalizeMediaCropSnapshot(theme?.avatar_crop, "avatar")
    : normalizeMediaCropSnapshot(theme?.banner_crop, "banner");
}

function resolveUserBannerCrop(userId = "", fallbackProfile = null) {
  const uid = normId(userId || "");
  const meId = normId(state.user?.id || "");
  if (uid && meId && uid === meId) {
    return getThemeMediaCrop(state.me?.theme_settings || {}, "banner");
  }
  if (fallbackProfile?.theme_settings) {
    return getThemeMediaCrop(fallbackProfile.theme_settings, "banner");
  }
  const cached = uid ? getCachedProfile(uid) || null : null;
  return getThemeMediaCrop(cached?.theme_settings || {}, "banner");
}

function captureBannerEditorCropSnapshot() {
  const canvas = document.getElementById("bannerEditorCanvas");
  const gifWrap = ensureEditorGifUi("banner").wrap || null;
  const targetEl = BE.isGif ? (gifWrap || canvas) : canvas;
  if (!targetEl || !BE.img) return null;
  const rect = targetEl.getBoundingClientRect();
  const info = { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height) };
  const crop = getBannerCropMetrics(info);
  const iw = BE.img.naturalWidth || BE.img.width;
  const ih = BE.img.naturalHeight || BE.img.height;
  if (!iw || !ih) return null;
  const cover = Math.max(crop.w / iw, crop.h / ih);
  const width = iw * BE.scale;
  const height = ih * BE.scale;
  const overflowX = Math.max(0, width - crop.w);
  const overflowY = Math.max(0, height - crop.h);
  const x = overflowX > 0 ? clampValue((crop.x - BE.ox) / overflowX, 0, 1) : 0.5;
  const y = overflowY > 0 ? clampValue((crop.y - BE.oy) / overflowY, 0, 1) : 0.5;
  return normalizeMediaCropSnapshot({
    scale: cover > 0 ? (BE.scale / cover) : 1,
    x,
    y,
  }, "banner");
}

function captureAvatarEditorCropSnapshot() {
  const canvas = document.getElementById("avatarEditorCanvas");
  const targetEl = canvas?.parentElement || document.getElementById("avatarEditorGifPreview")?.parentElement || null;
  if (!targetEl || !AE.img) return null;
  const rect = targetEl.getBoundingClientRect();
  const info = { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height) };
  const crop = getAvatarCropMetrics(info);
  const iw = AE.img.naturalWidth || AE.img.width;
  const ih = AE.img.naturalHeight || AE.img.height;
  if (!iw || !ih) return null;
  const cover = Math.max(crop.size / iw, crop.size / ih);
  const width = iw * AE.scale;
  const height = ih * AE.scale;
  const overflowX = Math.max(0, width - crop.size);
  const overflowY = Math.max(0, height - crop.size);
  const x = overflowX > 0 ? clampValue((crop.left - AE.ox) / overflowX, 0, 1) : 0.5;
  const y = overflowY > 0 ? clampValue((crop.top - AE.oy) / overflowY, 0, 1) : 0.5;
  return normalizeMediaCropSnapshot({
    scale: cover > 0 ? (AE.scale / cover) : 1,
    x,
    y,
  }, "avatar");
}

function computeThemeVars(themeInput) {
  const resolved = resolveThemeEngine(themeInput, {
    systemDark: isSystemPrefersDark(),
    sidebarMin: LEFT_SIDEBAR_WIDTH_MIN,
    sidebarMax: LEFT_SIDEBAR_WIDTH_MAX,
  });
  const theme = normalizeThemeSettings(resolved.theme);
  const vars = { ...(resolved.vars || {}) };
  const warnings = Array.isArray(resolved.warnings) ? resolved.warnings : [];
  const classes = resolved.classes && typeof resolved.classes === "object" ? resolved.classes : {};
  return { theme, vars, warnings, classes };
}

function renderThemeLivePreview(themeInput) {
  const preview = document.getElementById("settingsThemeLivePreview");
  if (!(preview instanceof HTMLElement)) return;
  const computed = computeThemeVars(themeInput);
  Object.entries(computed.vars).forEach(([key, value]) => {
    preview.style.setProperty(key, value);
  });
}

function applyThemeSettings(themeInput) {
  const root = document.documentElement;
  if (!root) return;
  const computed = computeThemeVars(themeInput);
  Object.entries(computed.vars).forEach(([k, v]) => root.style.setProperty(k, v));
  themeRuntimeWarnings = Array.isArray(computed.warnings) ? computed.warnings : [];
  renderThemeLivePreview(computed.theme);
  if (document.body) {
    const body = document.body;
    body.classList.remove("ui-compact");
    body.classList.remove("ui-no-grid");
    body.classList.remove("theme-mode-dark", "theme-mode-light", "theme-style-minimal", "theme-style-soft", "theme-style-glass", "theme-style-solid", "theme-style-gaming", "theme-density-compact", "theme-density-normal", "theme-density-comfortable", "theme-layout-calm", "theme-layout-gaming");
    if (computed.classes?.mode) body.classList.add(computed.classes.mode);
    if (computed.classes?.style) body.classList.add(computed.classes.style);
    if (computed.classes?.density) body.classList.add(computed.classes.density);
    if (computed.classes?.layout) body.classList.add(computed.classes.layout);
    if (computed.theme?.density === "compact") body.classList.add("ui-compact");
    if (computed.theme?.show_grid === false) body.classList.add("ui-no-grid");
  }
  applyAltaraAppearanceRuntime(computed.theme, computed.vars);
  const warningEl = document.getElementById("themeAutoAdjustHint");
  if (warningEl) {
    if (themeRuntimeWarnings.length) {
      warningEl.textContent = `Auto adjustments: ${themeRuntimeWarnings.join(" ")}`;
      warningEl.classList.remove("hidden");
    } else {
      warningEl.textContent = "";
      warningEl.classList.add("hidden");
    }
  }
  bindLeftSidebarDensitySyncOnce();
  syncLeftSidebarDensityClass(computed.theme.left_sidebar_width);
  setSidebarResizerAria(computed.theme.left_sidebar_width);
  applyMeHeaderBannerStyle(computed.theme);
}

