function renderThemePresetSelectOptions() {
  const select = document.getElementById("themePreset");
  if (!(select instanceof HTMLSelectElement)) return;
  const current = String(select.value || "").trim().toLowerCase();
  const options = getThemePresetList();
  const html = [
    ...options.map((item) => `<option value="${escAttr(item.id)}">${esc(item.label)}</option>`),
    `<option value="custom">Custom</option>`,
  ].join("");
  select.innerHTML = html;
  const hasCurrent = options.some((item) => item.id === current);
  if (current === "custom" || hasCurrent) {
    select.value = current;
  } else {
    select.value = THEME_DEFAULT_PRESET;
  }
}

function syncUiZoomFormUi(els = getThemeFormEls()) {
  const zoomInput = els.uiZoom;
  const zoomValue = els.uiZoomValue;
  const zoomHint = els.uiZoomHint;
  if (!zoomInput) {
    if (zoomValue) zoomValue.textContent = `${uiZoomFactorToPercent(uiZoomCurrentFactor)}%`;
    return;
  }

  const minPercent = uiZoomFactorToPercent(uiZoomMinFactor);
  const maxPercent = uiZoomFactorToPercent(uiZoomMaxFactor);
  const currentPercent = uiZoomFactorToPercent(uiZoomCurrentFactor);
  zoomInput.min = String(minPercent);
  zoomInput.max = String(maxPercent);
  zoomInput.step = "1";
  zoomInput.value = String(currentPercent);
  zoomInput.disabled = !uiZoomBridgeAvailable;

  if (zoomValue) zoomValue.textContent = `${currentPercent}%`;
  if (zoomHint) {
    zoomHint.textContent = uiZoomBridgeAvailable
      ? t("settings.zoom.hint", "Tip: configure your zoom shortcut in Binds.")
      : t("settings.zoom.hint.desktop_only", "Desktop app only.");
  }
  syncRangeDefaultMarker(zoomInput, uiZoomFactorToPercent(UI_ZOOM_DEFAULT_FACTOR));
}

function rangeSliderToPercent(valueInput, minInput, maxInput) {
  const min = Number(minInput);
  const max = Number(maxInput);
  if (!Number.isFinite(min) || !Number.isFinite(max) || max <= min) return 0;
  const value = clampNum(valueInput, min, max, min);
  const pct = ((value - min) / (max - min)) * 100;
  return clampNum(pct, 0, 100, 0);
}

function syncRangeDefaultMarker(input, defaultValueInput = null) {
  if (!(input instanceof HTMLInputElement)) return;
  if (input.type !== "range") return;

  const min = Number.parseFloat(String(input.min || "0"));
  const max = Number.parseFloat(String(input.max || "100"));
  const safeMin = Number.isFinite(min) ? min : 0;
  const safeMax = Number.isFinite(max) ? max : 100;
  const current = clampNum(input.value, safeMin, safeMax, safeMin);
  const attrDefault = Number.parseFloat(String(input.getAttribute("value") || ""));
  const dataDefault = Number.parseFloat(String(input.dataset.defaultValue || ""));
  const fallbackDefault = Number.isFinite(attrDefault) ? attrDefault : current;
  const rawDefault = Number.isFinite(dataDefault)
    ? dataDefault
    : (defaultValueInput ?? fallbackDefault);
  const defaultValue = clampNum(rawDefault, safeMin, safeMax, fallbackDefault);
  const sliderStep = Number.parseFloat(String(input.step || "1"));
  const tolerance = Number.isFinite(sliderStep) && sliderStep > 0 ? (sliderStep / 2) : 0.5;
  const atDefault = Math.abs(current - defaultValue) <= tolerance;

  input.dataset.defaultValue = `${defaultValue}`;
  input.dataset.atDefault = atDefault ? "1" : "0";
  input.classList.add("withDefaultMarker");
  input.style.setProperty("--slider-progress", `${rangeSliderToPercent(current, safeMin, safeMax)}%`);
  input.style.setProperty("--slider-default", `${rangeSliderToPercent(defaultValue, safeMin, safeMax)}%`);
}

function readUiZoomFromForm(els = getThemeFormEls()) {
  if (!els.uiZoom) return uiZoomCurrentFactor;
  return uiZoomPercentToFactor(els.uiZoom.value, uiZoomCurrentFactor);
}

async function applyUiZoomFactor(factorInput, { persist = true, syncForm = true } = {}) {
  const nextFactor = normalizeUiZoomFactor(factorInput, uiZoomCurrentFactor);
  uiZoomCurrentFactor = nextFactor;
  syncDesktopTitlebarOverlayMetrics();
  if (persist) writeStoredUiZoomFactor(nextFactor);
  if (syncForm) syncUiZoomFormUi();

  const bridge = getDesktopBridge();
  if (!bridge || typeof bridge.setUiZoom !== "function") return false;

  const ticket = ++uiZoomApplyTicket;
  try {
    const result = await bridge.setUiZoom(nextFactor);
    if (ticket !== uiZoomApplyTicket) return true;
    const appliedFactor = normalizeUiZoomFactor(result?.current, nextFactor);
    uiZoomCurrentFactor = appliedFactor;
    syncDesktopTitlebarOverlayMetrics();
    if (persist) writeStoredUiZoomFactor(appliedFactor);
    if (syncForm) syncUiZoomFormUi();
    return true;
  } catch (_) {
    return false;
  }
}

function onThemeUiZoomInput() {
  const nextFactor = readUiZoomFromForm();
  void applyUiZoomFactor(nextFactor, { persist: true, syncForm: true });
}

function ensureUiZoomHudEl() {
  let el = document.getElementById("uiZoomHud");
  if (el) return el;
  if (!document.body) return null;
  el = document.createElement("div");
  el.id = "uiZoomHud";
  el.className = "uiZoomHud";
  el.setAttribute("aria-hidden", "true");
  document.body.appendChild(el);
  return el;
}

function showUiZoomHud(percentInput) {
  const el = ensureUiZoomHudEl();
  if (!el) return;
  const pct = clampInt(
    percentInput,
    uiZoomFactorToPercent(uiZoomMinFactor),
    uiZoomFactorToPercent(uiZoomMaxFactor),
    uiZoomFactorToPercent(uiZoomCurrentFactor)
  );
  el.textContent = `Zoom ${pct}%`;
  el.classList.add("is-visible");
  el.setAttribute("aria-hidden", "false");
  if (uiZoomHudHideTimer) clearTimeout(uiZoomHudHideTimer);
  uiZoomHudHideTimer = setTimeout(() => {
    uiZoomHudHideTimer = null;
    el.classList.remove("is-visible");
    el.setAttribute("aria-hidden", "true");
  }, 900);
}

function shouldIgnoreAltWheelZoomTarget(targetInput) {
  const target = targetInput instanceof Element ? targetInput : null;
  if (!target) return false;
  if (target.closest("#desktopSharePickerModal")) return true;
  return !!getEditableTypingElementFromTarget(target);
}

function bindUiZoomWheelShortcutOnce() {
  if (uiZoomWheelBound) return;
  uiZoomWheelBound = true;

  document.addEventListener("wheel", (ev) => {
    if (!uiZoomBridgeAvailable) return;
    if (!Number.isFinite(ev.deltaY) || ev.deltaY === 0) return;
    if (callKeybindCaptureAction || appKeybindCaptureAction) return;
    if (!doesWheelEventMatchAppZoomKeybind(ev)) return;
    if (shouldIgnoreAltWheelZoomTarget(eventTargetElement(ev))) return;
    ev.preventDefault();

    const delta = ev.deltaY < 0 ? UI_ZOOM_STEP_FACTOR : -UI_ZOOM_STEP_FACTOR;
    const nextFactor = normalizeUiZoomFactor(uiZoomCurrentFactor + delta, uiZoomCurrentFactor);
    if (Math.abs(nextFactor - uiZoomCurrentFactor) < 0.0005) return;
    showUiZoomHud(uiZoomFactorToPercent(nextFactor));
    void applyUiZoomFactor(nextFactor, { persist: true, syncForm: true });
  }, { passive: false });
}

async function initDesktopUiZoomControls() {
  const bridge = getDesktopBridge();
  uiZoomBridgeAvailable = !!(bridge
    && typeof bridge.getUiZoom === "function"
    && typeof bridge.setUiZoom === "function");
  if (!uiZoomBridgeAvailable) {
    uiZoomCurrentFactor = normalizeUiZoomFactor(readStoredUiZoomFactor(), uiZoomCurrentFactor);
    syncDesktopTitlebarOverlayMetrics();
    syncUiZoomFormUi();
    return;
  }

  try {
    const info = await bridge.getUiZoom();
    uiZoomMinFactor = clampNum(info?.min, 0.5, 2, UI_ZOOM_MIN_FACTOR);
    uiZoomMaxFactor = clampNum(info?.max, uiZoomMinFactor, 2, UI_ZOOM_MAX_FACTOR);
    uiZoomCurrentFactor = normalizeUiZoomFactor(info?.current, uiZoomCurrentFactor);
  } catch (_) {}

  syncDesktopTitlebarOverlayMetrics();

  const storedFactor = readStoredUiZoomFactor();
  if (storedFactor !== null) {
    await applyUiZoomFactor(storedFactor, { persist: true, syncForm: true });
  } else {
    writeStoredUiZoomFactor(uiZoomCurrentFactor);
    syncUiZoomFormUi();
  }
}

function syncThemeOptionLabels(els = getThemeFormEls()) {
  if (els.roundnessValue) {
    const value = clampInt(els.roundness?.value, 0, 100, THEME_DEFAULT_OPTIONS.roundness);
    els.roundnessValue.textContent = `${value}%`;
    syncRangeDefaultMarker(els.roundness, THEME_DEFAULT_OPTIONS.roundness);
  }
  if (els.blurStrengthValue) {
    const value = clampInt(els.blurStrength?.value, 0, 40, THEME_DEFAULT_OPTIONS.blur_strength);
    els.blurStrengthValue.textContent = `${value}px`;
    syncRangeDefaultMarker(els.blurStrength, THEME_DEFAULT_OPTIONS.blur_strength);
  }
  if (els.panelAlphaValue) {
    const value = clampInt(els.panelAlpha?.value, 45, 100, THEME_DEFAULT_OPTIONS.panel_alpha);
    els.panelAlphaValue.textContent = `${value}%`;
    syncRangeDefaultMarker(els.panelAlpha, THEME_DEFAULT_OPTIONS.panel_alpha);
  }
  if (els.borderThicknessValue) {
    const value = clampInt(els.borderThickness?.value, 0, 4, THEME_DEFAULT_OPTIONS.border_thickness);
    els.borderThicknessValue.textContent = `${value}px`;
    syncRangeDefaultMarker(els.borderThickness, THEME_DEFAULT_OPTIONS.border_thickness);
  }
  if (els.shadowStrengthValue) {
    const value = clampInt(els.shadowStrength?.value, 0, 100, THEME_DEFAULT_OPTIONS.shadow_strength);
    els.shadowStrengthValue.textContent = `${value}%`;
    syncRangeDefaultMarker(els.shadowStrength, THEME_DEFAULT_OPTIONS.shadow_strength);
  }
  if (els.spacingScaleValue) {
    const value = clampInt(els.spacingScale?.value, 70, 140, THEME_DEFAULT_OPTIONS.spacing_scale);
    els.spacingScaleValue.textContent = `${value}%`;
    syncRangeDefaultMarker(els.spacingScale, THEME_DEFAULT_OPTIONS.spacing_scale);
  }
  if (els.fontScaleValue) {
    const value = clampInt(els.fontScale?.value, 85, 135, THEME_DEFAULT_OPTIONS.font_scale);
    els.fontScaleValue.textContent = `${value}%`;
    syncRangeDefaultMarker(els.fontScale, THEME_DEFAULT_OPTIONS.font_scale);
  }
  if (els.uiScaleValue) {
    const value = clampInt(els.uiScale?.value, 70, 150, THEME_DEFAULT_OPTIONS.ui_scale);
    els.uiScaleValue.textContent = `${value}%`;
    syncRangeDefaultMarker(els.uiScale, THEME_DEFAULT_OPTIONS.ui_scale);
  }
  if (els.colorIntensityValue) {
    const value = clampInt(els.colorIntensity?.value, 0, 100, THEME_DEFAULT_OPTIONS.color_intensity);
    els.colorIntensityValue.textContent = `${value}%`;
    syncRangeDefaultMarker(els.colorIntensity, THEME_DEFAULT_OPTIONS.color_intensity);
  }
  if (els.leftSidebarWidthValue) {
    const value = clampInt(els.leftSidebarWidth?.value, LEFT_SIDEBAR_WIDTH_MIN, LEFT_SIDEBAR_WIDTH_MAX, THEME_DEFAULT_OPTIONS.left_sidebar_width);
    els.leftSidebarWidthValue.textContent = `${value}px`;
    syncRangeDefaultMarker(els.leftSidebarWidth, THEME_DEFAULT_OPTIONS.left_sidebar_width);
  }
  syncUiZoomFormUi(els);
}

function syncUnifiedBackgroundThemeFields(elsInput = null) {
  const els = elsInput || getThemeFormEls();
  const bgInput = els?.bg;
  if (!(bgInput instanceof HTMLInputElement)) return;

  const bgColor = normalizeHexColor(
    bgInput.value,
    THEME_PRESETS[THEME_DEFAULT_PRESET].background
  );
  if (bgInput.value !== bgColor) bgInput.value = bgColor;
  const bgGradient = readInputGradientState(bgInput);

  const mirrorColorAndGradient = (input) => {
    if (!(input instanceof HTMLInputElement)) return;
    input.value = bgColor;
    writeThemeGradientToInput(
      input,
      bgGradient.enabled ? bgGradient.color2 : "",
      bgGradient.angle
    );
  };

  mirrorColorAndGradient(els.surface);
  mirrorColorAndGradient(els.leftSidebarColor);
  mirrorColorAndGradient(els.shellColor);
  mirrorColorAndGradient(els.topbarColor);
}

function readThemeFromForm() {
  const els = getThemeFormEls();
  syncUnifiedBackgroundThemeFields(els);
  const defaultPreset = THEME_PRESETS[THEME_DEFAULT_PRESET] || { background: "#131417", accent: "#8ea0ff" };
  const bgColor = normalizeHexColor(
    els.bg?.value,
    defaultPreset.background
  );
  const accentColor = normalizeHexColor(
    els.accent?.value,
    defaultPreset.accent
  );
  const colorFromInput = (input, fallback) => {
    const base = normalizeHexColor(input?.value, fallback);
    const gradient = readInputGradientState(input);
    return gradient.enabled ? mixHex(base, gradient.color2, 0.5) : base;
  };
  const bgGradient = readInputGradientState(els.bg);
  const gradientOptions = {
    ...readThemeGradientFromInput(els.bg, "background_deep", "background_angle"),
    surface_deep: bgGradient.enabled ? bgGradient.color2 : "",
    surface_angle: bgGradient.enabled ? bgGradient.angle : 180,
    ...readThemeGradientFromInput(els.accent, "accent_deep", "accent_angle"),
    shell_deep: bgGradient.enabled ? bgGradient.color2 : "",
    shell_angle: bgGradient.enabled ? bgGradient.angle : 180,
    left_sidebar_deep: bgGradient.enabled ? bgGradient.color2 : "",
    left_sidebar_angle: bgGradient.enabled ? bgGradient.angle : 180,
    topbar_deep: bgGradient.enabled ? bgGradient.color2 : "",
    topbar_angle: bgGradient.enabled ? bgGradient.angle : 180,
    ...readThemeGradientFromInput(els.rowColor, "row_deep", "row_angle"),
    ...readThemeGradientFromInput(els.textColor, "text_deep", "text_angle"),
  };
  const options = {
    mode: String(els.mode?.value || THEME_DEFAULT_OPTIONS.mode).trim().toLowerCase(),
    visual_style: String(els.visualStyle?.value || THEME_DEFAULT_OPTIONS.visual_style).trim().toLowerCase(),
    density: String(els.density?.value || THEME_DEFAULT_OPTIONS.density).trim().toLowerCase(),
    layout_mood: String(els.layoutMood?.value || THEME_DEFAULT_OPTIONS.layout_mood).trim().toLowerCase(),
    background_unified: true,
    roundness: clampInt(els.roundness?.value, 0, 100, THEME_DEFAULT_OPTIONS.roundness),
    blur_strength: clampInt(els.blurStrength?.value, 0, 40, THEME_DEFAULT_OPTIONS.blur_strength),
    panel_alpha: clampInt(els.panelAlpha?.value, 45, 100, THEME_DEFAULT_OPTIONS.panel_alpha),
    border_thickness: clampInt(els.borderThickness?.value, 0, 4, THEME_DEFAULT_OPTIONS.border_thickness),
    shadow_strength: clampInt(els.shadowStrength?.value, 0, 100, THEME_DEFAULT_OPTIONS.shadow_strength),
    spacing_scale: clampInt(els.spacingScale?.value, 70, 140, THEME_DEFAULT_OPTIONS.spacing_scale),
    font_scale: clampInt(els.fontScale?.value, 85, 135, THEME_DEFAULT_OPTIONS.font_scale),
    ui_scale: clampInt(els.uiScale?.value, 70, 150, THEME_DEFAULT_OPTIONS.ui_scale),
    density_scale: THEME_DEFAULT_OPTIONS.density_scale,
    color_intensity: clampInt(els.colorIntensity?.value, 0, 100, THEME_DEFAULT_OPTIONS.color_intensity),
    left_sidebar_width: clampInt(els.leftSidebarWidth?.value, LEFT_SIDEBAR_WIDTH_MIN, LEFT_SIDEBAR_WIDTH_MAX, THEME_DEFAULT_OPTIONS.left_sidebar_width),
    glow: clampInt(state.me?.theme_settings?.glow, 0, 100, THEME_DEFAULT_OPTIONS.glow),
    compact_mode: false,
    show_grid: true,
    dnd_mute_notifications: els.dndMuteNotifications
      ? !!els.dndMuteNotifications.checked
      : normalizeThemeBool(
        state.me?.theme_settings?.dnd_mute_notifications,
        THEME_DEFAULT_OPTIONS.dnd_mute_notifications
      ),
    app_language: normalizeAppLanguage(
      els.language?.value,
      appLanguage || readStoredAppLanguage()
    ),
    time_format: normalizeThemeTimeFormat(
      els.timeFormat?.value,
      state.me?.theme_settings?.time_format || THEME_DEFAULT_OPTIONS.time_format
    ),
    profile_card_banner: els.profileCardBanner
      ? !!els.profileCardBanner.checked
      : normalizeThemeBool(
        state.me?.theme_settings?.profile_card_banner,
        THEME_DEFAULT_OPTIONS.profile_card_banner
      ),
    reduce_motion: els.reduceMotion
      ? !!els.reduceMotion.checked
      : normalizeThemeBool(
        state.me?.theme_settings?.reduce_motion,
        THEME_DEFAULT_OPTIONS.reduce_motion
      ),
    banner_url: normalizeBannerUrl(state.me?.banner_url || state.me?.theme_settings?.banner_url || ""),
    background_secondary: normalizeThemeOptionalColor(colorFromInput(els.bgSecondary, mixHex(bgColor, "#000000", 0.24))),
    surface_secondary: normalizeThemeOptionalColor(colorFromInput(els.surfaceSecondary, mixHex(bgColor, "#ffffff", 0.08))),
    accent_secondary: normalizeThemeOptionalColor(colorFromInput(els.accentSecondary, mixHex(accentColor, "#62d1ff", 0.25))),
    shell_color: normalizeThemeOptionalColor(bgColor),
    left_sidebar_color: normalizeThemeOptionalColor(bgColor),
    topbar_color: normalizeThemeOptionalColor(bgColor),
    row_color: normalizeThemeOptionalColor(colorFromInput(els.rowColor, "#121318")),
    text_color: normalizeThemeOptionalColor(colorFromInput(els.textColor, "#f1f2f5")),
    button_primary: normalizeThemeOptionalColor(colorFromInput(els.buttonPrimary, accentColor)),
    button_secondary: normalizeThemeOptionalColor(colorFromInput(els.buttonSecondary, mixHex(bgColor, "#ffffff", 0.15))),
    input_color: normalizeThemeOptionalColor(colorFromInput(els.inputColor, mixHex(bgColor, "#000000", 0.24))),
    border_color: normalizeThemeOptionalColor(colorFromInput(els.borderColor, mixHex(bgColor, "#ffffff", 0.35))),
    hover_color: normalizeThemeOptionalColor(colorFromInput(els.hoverColor, mixHex(bgColor, accentColor, 0.2))),
    active_color: normalizeThemeOptionalColor(colorFromInput(els.activeColor, mixHex(bgColor, accentColor, 0.32))),
    message_sent: normalizeThemeOptionalColor(colorFromInput(els.messageSentColor, mixHex(accentColor, bgColor, 0.45))),
    message_received: normalizeThemeOptionalColor(colorFromInput(els.messageReceivedColor, mixHex(bgColor, "#ffffff", 0.1))),
    link_color: normalizeThemeOptionalColor(colorFromInput(els.linkColor, accentColor)),
    success_color: normalizeThemeOptionalColor(colorFromInput(els.successColor, "#49d17f")),
    warning_color: normalizeThemeOptionalColor(colorFromInput(els.warningColor, "#f5c354")),
    danger_color: normalizeThemeOptionalColor(colorFromInput(els.dangerColor, "#f26f6f")),
    info_color: normalizeThemeOptionalColor(colorFromInput(els.infoColor, "#62d1ff")),
    ...gradientOptions,
  };
  const presetValue = String(els.preset?.value || "custom").toLowerCase();
  if (Object.prototype.hasOwnProperty.call(THEME_PRESETS, presetValue) && presetValue !== "custom") {
    const preset = THEME_PRESETS[presetValue];
    return normalizeThemeSettings({
      preset: presetValue,
      background: bgColor || preset.background,
      surface: bgColor || preset.background,
      accent: accentColor || preset.accent,
      ...options,
    });
  }
  return normalizeThemeSettings({
    preset: "custom",
    background: bgColor,
    surface: bgColor,
    accent: accentColor,
    ...options,
  });
}

function writeThemeToForm(themeInput) {
  const theme = normalizeThemeSettings(themeInput);
  const els = getThemeFormEls();
  if (!els.preset || !els.bg || !els.surface || !els.accent) return;
  const presetValue = theme.preset === "custom" ? "custom" : theme.preset;
  els.preset.value = Array.from(els.preset.options || []).some((opt) => opt.value === presetValue) ? presetValue : "custom";
  if (els.mode) els.mode.value = String(theme.mode || THEME_DEFAULT_OPTIONS.mode).toLowerCase();
  if (els.visualStyle) els.visualStyle.value = String(theme.visual_style || THEME_DEFAULT_OPTIONS.visual_style).toLowerCase();
  if (els.density) els.density.value = String(theme.density || THEME_DEFAULT_OPTIONS.density).toLowerCase();
  if (els.layoutMood) els.layoutMood.value = String(theme.layout_mood || THEME_DEFAULT_OPTIONS.layout_mood).toLowerCase();
  els.bg.value = normalizeHexColor(theme.background, THEME_PRESETS[THEME_DEFAULT_PRESET].background);
  writeThemeGradientToInput(els.bg, theme.background_deep, theme.background_angle);
  syncUnifiedBackgroundThemeFields(els);
  if (els.bgSecondary) els.bgSecondary.value = normalizeHexColor(theme.background_secondary, "#1b1f27");
  if (els.surfaceSecondary) els.surfaceSecondary.value = normalizeHexColor(theme.surface_secondary, "#1f2430");
  els.accent.value = normalizeHexColor(theme.accent, THEME_PRESETS[THEME_DEFAULT_PRESET].accent);
  writeThemeGradientToInput(els.accent, theme.accent_deep, theme.accent_angle);
  if (els.accentSecondary) els.accentSecondary.value = normalizeHexColor(theme.accent_secondary, "#62d1ff");
  if (els.buttonPrimary) els.buttonPrimary.value = normalizeHexColor(theme.button_primary, theme.accent || "#8ea0ff");
  if (els.buttonSecondary) els.buttonSecondary.value = normalizeHexColor(theme.button_secondary, "#283043");
  if (els.inputColor) els.inputColor.value = normalizeHexColor(theme.input_color, "#111722");
  if (els.borderColor) els.borderColor.value = normalizeHexColor(theme.border_color, "#4a5063");
  if (els.hoverColor) els.hoverColor.value = normalizeHexColor(theme.hover_color, "#2a3348");
  if (els.activeColor) els.activeColor.value = normalizeHexColor(theme.active_color, "#3d4b68");
  if (els.messageSentColor) els.messageSentColor.value = normalizeHexColor(theme.message_sent, "#3f5076");
  if (els.messageReceivedColor) els.messageReceivedColor.value = normalizeHexColor(theme.message_received, "#202635");
  if (els.linkColor) els.linkColor.value = normalizeHexColor(theme.link_color, theme.accent || "#8ea0ff");
  if (els.successColor) els.successColor.value = normalizeHexColor(theme.success_color, "#49d17f");
  if (els.warningColor) els.warningColor.value = normalizeHexColor(theme.warning_color, "#f5c354");
  if (els.dangerColor) els.dangerColor.value = normalizeHexColor(theme.danger_color, "#f26f6f");
  if (els.infoColor) els.infoColor.value = normalizeHexColor(theme.info_color, "#62d1ff");
  [
    els.bgSecondary,
    els.surfaceSecondary,
    els.accentSecondary,
    els.buttonPrimary,
    els.buttonSecondary,
    els.inputColor,
    els.borderColor,
    els.hoverColor,
    els.activeColor,
    els.messageSentColor,
    els.messageReceivedColor,
    els.linkColor,
    els.successColor,
    els.warningColor,
    els.dangerColor,
    els.infoColor,
  ].forEach((input) => {
    writeThemeGradientToInput(input, "", 180);
  });
  if (els.roundness) els.roundness.value = String(clampInt(theme.roundness, 0, 100, THEME_DEFAULT_OPTIONS.roundness));
  if (els.blurStrength) els.blurStrength.value = String(clampInt(theme.blur_strength, 0, 40, THEME_DEFAULT_OPTIONS.blur_strength));
  if (els.panelAlpha) els.panelAlpha.value = String(clampInt(theme.panel_alpha, 45, 100, THEME_DEFAULT_OPTIONS.panel_alpha));
  if (els.borderThickness) els.borderThickness.value = String(clampInt(theme.border_thickness, 0, 4, THEME_DEFAULT_OPTIONS.border_thickness));
  if (els.shadowStrength) els.shadowStrength.value = String(clampInt(theme.shadow_strength, 0, 100, THEME_DEFAULT_OPTIONS.shadow_strength));
  if (els.spacingScale) els.spacingScale.value = String(clampInt(theme.spacing_scale, 70, 140, THEME_DEFAULT_OPTIONS.spacing_scale));
  if (els.fontScale) els.fontScale.value = String(clampInt(theme.font_scale, 85, 135, THEME_DEFAULT_OPTIONS.font_scale));
  if (els.uiScale) els.uiScale.value = String(clampInt(theme.ui_scale, 70, 150, THEME_DEFAULT_OPTIONS.ui_scale));
  if (els.colorIntensity) els.colorIntensity.value = String(clampInt(theme.color_intensity, 0, 100, THEME_DEFAULT_OPTIONS.color_intensity));
  if (els.leftSidebarWidth) els.leftSidebarWidth.value = String(clampInt(theme.left_sidebar_width, LEFT_SIDEBAR_WIDTH_MIN, LEFT_SIDEBAR_WIDTH_MAX, THEME_DEFAULT_OPTIONS.left_sidebar_width));
  if (els.profileCardBanner) {
    els.profileCardBanner.checked = normalizeThemeBool(
      theme.profile_card_banner,
      THEME_DEFAULT_OPTIONS.profile_card_banner
    );
  }
  if (els.reduceMotion) {
    els.reduceMotion.checked = normalizeThemeBool(
      theme.reduce_motion,
      THEME_DEFAULT_OPTIONS.reduce_motion
    );
  }
  if (els.dndMuteNotifications) {
    els.dndMuteNotifications.checked = normalizeThemeBool(
      theme.dnd_mute_notifications,
      THEME_DEFAULT_OPTIONS.dnd_mute_notifications
    );
  }
  if (els.language) els.language.value = normalizeAppLanguage(theme.app_language, appLanguage || APP_LANG_DEFAULT);
  if (els.timeFormat) els.timeFormat.value = normalizeThemeTimeFormat(theme.time_format, THEME_DEFAULT_OPTIONS.time_format);
  if (els.rowColor) els.rowColor.value = normalizeHexColor(theme.row_color, "#121318");
  writeThemeGradientToInput(els.rowColor, theme.row_deep, theme.row_angle);
  if (els.textColor) els.textColor.value = normalizeHexColor(theme.text_color, "#f1f2f5");
  writeThemeGradientToInput(els.textColor, theme.text_deep, theme.text_angle);
  syncThemeOptionLabels(els);
  syncThemeColorInputsUi();
  syncAppearanceVisualControls(theme);
  renderThemeLivePreview(theme);
}

function isDndNotificationMuteEnabled(themeInput = null) {
  const source = themeInput && typeof themeInput === "object"
    ? themeInput
    : state.me?.theme_settings;
  return normalizeThemeBool(
    source?.dnd_mute_notifications,
    THEME_DEFAULT_OPTIONS.dnd_mute_notifications
  );
}

function syncNotificationBehaviorSettingsUi(themeInput = null) {
  const toggle = document.getElementById("settingsDndMuteNotifications");
  if (!(toggle instanceof HTMLInputElement)) return;
  toggle.checked = isDndNotificationMuteEnabled(themeInput);
}

async function setDndNotificationMutePreference(enabled, { persist = true } = {}) {
  const nextValue = !!enabled;
  state.me = state.me || {};
  const nextTheme = normalizeThemeSettings({
    ...(state.me.theme_settings || {}),
    dnd_mute_notifications: nextValue,
  });
  state.me.theme_settings = nextTheme;
  syncNotificationBehaviorSettingsUi(nextTheme);
  if (!persist) return true;
  return persistThemeSettings(nextTheme, { showSuccess: false, showError: false });
}

function shouldMuteNotificationSoundsNow() {
  if (!isDndNotificationMuteEnabled()) return false;
  return resolveMyPresenceStatus(state.me) === "dnd";
}

function previewThemeFromForm() {
  const theme = readAppearanceControls();
  applyAppearanceSettings(theme);
  writeThemeEditorDraftToStorage(theme);
  syncAppearanceVisualControls(theme);
}

function onThemePresetChange() {
  const els = getThemeFormEls();
  if (!els.preset) return;
  const preset = String(els.preset.value || "").toLowerCase();
  if (Object.prototype.hasOwnProperty.call(THEME_PRESETS, preset) && preset !== "custom") {
    const current = readThemeFromForm();
    const presetBase = preset === THEME_DEFAULT_PRESET
      ? getDefaultAppearanceSettings()
      : { preset };
    const next = normalizeThemeSettings({
      ...presetBase,
      preset,
      mode: current.mode,
      visual_style: current.visual_style,
      density: current.density,
      layout_mood: current.layout_mood,
      roundness: current.roundness,
      color_intensity: current.color_intensity,
      blur_strength: current.blur_strength,
      panel_alpha: current.panel_alpha,
      border_thickness: current.border_thickness,
      shadow_strength: current.shadow_strength,
      spacing_scale: current.spacing_scale,
      font_scale: current.font_scale,
      ui_scale: current.ui_scale,
      left_sidebar_width: current.left_sidebar_width,
      app_language: current.app_language,
      time_format: current.time_format,
      dnd_mute_notifications: current.dnd_mute_notifications,
      reduce_motion: current.reduce_motion,
      profile_card_banner: current.profile_card_banner,
      banner_url: current.banner_url,
    });
    writeThemeToForm(next);
  }
  previewThemeFromForm();
}

function onThemeColorInput() {
  const els = getThemeFormEls();
  if (els.preset && els.preset.value !== "custom") els.preset.value = "custom";
  syncUnifiedBackgroundThemeFields(els);
  previewThemeFromForm();
}

function onThemeOptionInput() {
  const els = getThemeFormEls();
  if (els.preset && els.preset.value !== "custom") els.preset.value = "custom";
  syncThemeOptionLabels();
  previewThemeFromForm();
}

function onThemeLanguageChange() {
  const langSelect = document.getElementById("themeLanguage");
  const nextLang = normalizeAppLanguage(langSelect?.value, appLanguage || readStoredAppLanguage());
  setAppLanguage(nextLang, { persist: true, rerender: true, syncForm: true });
  const theme = readAppearanceControls();
  applyAppearanceSettings(theme);
  writeThemeEditorDraftToStorage(theme);
}

function onThemeTimeFormatChange() {
  const formatSelect = document.getElementById("themeTimeFormat");
  const nextFormat = normalizeThemeTimeFormat(
    formatSelect?.value,
    state.me?.theme_settings?.time_format || THEME_DEFAULT_OPTIONS.time_format
  );
  if (formatSelect) formatSelect.value = nextFormat;

  const theme = readThemeFromForm();
  theme.time_format = nextFormat;
  state.me = state.me || {};
  state.me.theme_settings = normalizeThemeSettings({
    ...(state.me.theme_settings || {}),
    ...theme,
  });

  renderMessagesFromCache({ keepBottom: true });
  applyAppearanceSettings(theme);
  writeThemeEditorDraftToStorage(theme);
}

function getFallbackThemeSettings() {
  return normalizeThemeSettings({
    preset: THEME_DEFAULT_PRESET,
    ...THEME_PRESETS[THEME_DEFAULT_PRESET],
    ...THEME_DEFAULT_OPTIONS,
    app_language: appLanguage || readStoredAppLanguage() || APP_LANG_DEFAULT,
    ...THEME_DEFAULT_COLOR_TWEAKS,
  });
}

function getDefaultAppearanceSettingsLegacy() {
  return normalizeThemeSettings({
    ...getFallbackThemeSettings(),
    preset: THEME_DEFAULT_PRESET,
    mode: "dark",
    visual_style: "soft",
    density: "normal",
    layout_mood: "calm",
    background: "#101010",
    background_secondary: "#151515",
    surface: "#181818",
    surface_secondary: "#202020",
    accent: "#e8cfae",
    accent_secondary: "#cda97b",
    row_color: "#171717",
    text_color: "#f2f0ec",
    button_primary: "#e8cfae",
    button_secondary: "#202020",
    input_color: "#111111",
    border_color: "#2c2c2c",
    hover_color: "#202020",
    active_color: "#2a241c",
    message_sent: "#30281d",
    message_received: "#1b1b1b",
    link_color: "#f0d3aa",
    reduce_motion: false,
  });
}

function stripProfileMetaFromAppearanceTheme(themeInput) {
  const theme = normalizeThemeSettings(themeInput || getDefaultAppearanceSettings());
  const {
    banner_url,
    banner_crop,
    avatar_crop,
    presence_status,
    dnd_mute_notifications,
    pause_gifs_when_unfocused,
    gifs_play_on_hover,
    ...appearanceTheme
  } = theme;
  return normalizeThemeSettings(appearanceTheme);
}

function getProfileThemeMetaForAppearance() {
  const source = state.me?.theme_settings && typeof state.me.theme_settings === "object"
    ? state.me.theme_settings
    : {};
  const meta = {};
  const bannerUrl = normalizeBannerUrl(source.banner_url || state.me?.banner_url || "");
  if (bannerUrl) meta.banner_url = bannerUrl;
  if (source.banner_crop) meta.banner_crop = source.banner_crop;
  if (source.avatar_crop) meta.avatar_crop = source.avatar_crop;
  const presence = readPresenceStatusValue(source.presence_status);
  if (presence) meta.presence_status = presence;
  [
    "dnd_mute_notifications",
    "pause_gifs_when_unfocused",
    "gifs_play_on_hover",
    "app_language",
    "time_format",
    "profile_card_banner",
    "reduce_motion",
    "left_sidebar_width",
  ].forEach((key) => {
    if (Object.prototype.hasOwnProperty.call(source, key)) meta[key] = source[key];
  });
  return meta;
}

function mergeAppearanceWithProfileThemeLegacy(themeInput) {
  const appearanceTheme = normalizeThemeSettings(themeInput || getDefaultAppearanceSettings());
  return normalizeThemeSettings({
    ...appearanceTheme,
    ...getProfileThemeMetaForAppearance(),
  });
}

function appearanceDensityLabel(themeInput) {
  const density = String(normalizeThemeSettings(themeInput).density || "normal").toLowerCase();
  if (density === "comfortable") return "cozy";
  if (density === "compact") return "compact";
  return "balanced";
}

function appearanceRoundnessToRadiusPx(roundnessInput) {
  const roundness = clampInt(roundnessInput, 0, 100, THEME_DEFAULT_OPTIONS.roundness);
  return Math.round(6 + (roundness * 0.18));
}

function appearanceRadiusPxToRoundness(radiusInput) {
  const radius = Number(radiusInput);
  if (!Number.isFinite(radius)) return THEME_DEFAULT_OPTIONS.roundness;
  if (radius > 40) return clampInt(radius, 0, 100, THEME_DEFAULT_OPTIONS.roundness);
  return clampInt(Math.round(((radius - 6) / 18) * 100), 0, 100, THEME_DEFAULT_OPTIONS.roundness);
}

function normalizeAppearanceDensityValue(value, fallback = THEME_DEFAULT_OPTIONS.density) {
  const raw = String(value || "").trim().toLowerCase();
  if (raw === "cozy") return "comfortable";
  if (raw === "balanced") return "normal";
  if (raw === "comfortable" || raw === "normal" || raw === "compact") return raw;
  return fallback;
}

function getAppearanceCustomTokens(themeInput) {
  const source = themeInput && typeof themeInput === "object" && !Array.isArray(themeInput)
    ? themeInput
    : {};
  const tokenKeys = [
    "background", "background_secondary", "surface", "surface_secondary",
    "accent", "accent_secondary", "row_color", "text_color",
    "button_primary", "button_secondary", "input_color", "border_color",
    "hover_color", "active_color", "message_sent", "message_received",
    "link_color", "success_color", "warning_color", "danger_color", "info_color",
  ];
  const tokens = {};
  tokenKeys.forEach((key) => {
    if (!Object.prototype.hasOwnProperty.call(source, key)) return;
    const value = normalizeThemeOptionalColor(source[key]);
    if (value) tokens[key] = value;
  });
  return tokens;
}

function normalizeAppearancePayloadToTheme(parsed) {
  const base = getDefaultAppearanceSettings();
  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return base;

  const source = parsed.theme && typeof parsed.theme === "object" && !Array.isArray(parsed.theme)
    ? parsed.theme
    : parsed;
  const next = {
    ...base,
    ...source,
  };

  if (typeof parsed.preset !== "undefined") {
    const preset = String(parsed.preset || "").trim().toLowerCase();
    if (preset === "custom" || Object.prototype.hasOwnProperty.call(THEME_PRESETS, preset)) {
      next.preset = preset;
    }
  }
  const accent = normalizeThemeOptionalColor(parsed.accent);
  if (accent) next.accent = accent;
  if (typeof parsed.density !== "undefined") {
    next.density = normalizeAppearanceDensityValue(parsed.density, next.density);
  }
  if (typeof parsed.fontSize !== "undefined") {
    const fontSize = Number(parsed.fontSize);
    if (Number.isFinite(fontSize)) next.font_scale = clampInt(Math.round((fontSize / 16) * 100), 85, 135, next.font_scale);
  }
  if (typeof parsed.messageSpacing !== "undefined") {
    const spacing = Number(parsed.messageSpacing);
    if (Number.isFinite(spacing)) next.spacing_scale = clampInt(Math.round(spacing * 100), 70, 140, next.spacing_scale);
  }
  if (typeof parsed.radius !== "undefined") {
    next.roundness = appearanceRadiusPxToRoundness(parsed.radius);
  }
  if (typeof parsed.reduceMotion !== "undefined") {
    next.reduce_motion = !!parsed.reduceMotion;
  }
  if (parsed.customTokens && typeof parsed.customTokens === "object" && !Array.isArray(parsed.customTokens)) {
    Object.assign(next, getAppearanceCustomTokens(parsed.customTokens));
  }
  return stripProfileMetaFromAppearanceTheme(next);
}

function makeAppearanceStoragePayload(themeInput) {
  const theme = stripProfileMetaFromAppearanceTheme(themeInput || getDefaultAppearanceSettings());
  return {
    version: 1,
    preset: theme.preset || THEME_DEFAULT_PRESET,
    accent: normalizeHexColor(theme.accent, "#e8cfae"),
    density: appearanceDensityLabel(theme),
    fontSize: Math.round(16 * (clampInt(theme.font_scale, 85, 135, THEME_DEFAULT_OPTIONS.font_scale) / 100)),
    messageSpacing: Number((clampInt(theme.spacing_scale, 70, 140, THEME_DEFAULT_OPTIONS.spacing_scale) / 100).toFixed(2)),
    radius: appearanceRoundnessToRadiusPx(theme.roundness),
    reduceMotion: normalizeThemeBool(theme.reduce_motion, THEME_DEFAULT_OPTIONS.reduce_motion),
    customTokens: getAppearanceCustomTokens(theme),
    theme,
  };
}

function loadAppearanceSettingsLegacy({ force = false } = {}) {
  if (appearanceSettingsCache && !force) return appearanceSettingsCache;
  try {
    const cacheKey = getAppearanceCacheStorageKey();
    const raw = cacheKey ? localStorage.getItem(cacheKey) : "";
    if (!raw) {
      appearanceSettingsCache = getDefaultAppearanceSettings();
      return appearanceSettingsCache;
    }
    appearanceSettingsCache = normalizeAppearancePayloadToTheme(JSON.parse(raw));
    return appearanceSettingsCache;
  } catch (err) {
    console.warn("Could not load local appearance settings:", err);
    appearanceSettingsCache = getDefaultAppearanceSettings();
    return appearanceSettingsCache;
  }
}

function saveAppearanceSettingsLegacy(themeInput) {
  const theme = stripProfileMetaFromAppearanceTheme(themeInput || getDefaultAppearanceSettings());
  try {
    const cacheKey = getAppearanceCacheStorageKey();
    if (cacheKey) localStorage.setItem(cacheKey, JSON.stringify(makeAppearanceStoragePayload(theme)));
  } catch (err) {
    console.warn("Could not save local appearance settings:", err);
  }
  appearanceSettingsCache = theme;
  return theme;
}

function applyAltaraAppearanceRuntimeLegacy(themeInput, cssVars = {}) {
  const root = document.documentElement;
  if (!root) return;
  const theme = normalizeThemeSettings(themeInput || getDefaultAppearanceSettings());
  const getVar = (name, fallback) => String(cssVars?.[name] || fallback || "").trim();
  root.style.setProperty("--altara-accent", getVar("--accent", theme.accent || "#e8cfae"));
  root.style.setProperty("--altara-radius", `${appearanceRoundnessToRadiusPx(theme.roundness)}px`);
  root.style.setProperty("--altara-font-scale", String(clampInt(theme.font_scale, 85, 135, THEME_DEFAULT_OPTIONS.font_scale) / 100));
  root.style.setProperty("--altara-message-spacing", String(clampInt(theme.spacing_scale, 70, 140, THEME_DEFAULT_OPTIONS.spacing_scale) / 100));
  root.style.setProperty("--altara-density", appearanceDensityLabel(theme));
  root.style.setProperty("--altara-bg", getVar("--bg-main", theme.background || "#101010"));
  root.style.setProperty("--altara-surface", getVar("--surface-1", theme.surface || "#181818"));
  root.style.setProperty("--altara-border", getVar("--stroke", theme.border_color || "rgba(255,255,255,0.08)"));
  root.style.setProperty("--altara-text", getVar("--text-main", theme.text_color || "#f2f0ec"));
  root.style.setProperty("--altara-muted", getVar("--text-muted", "rgba(242,240,236,0.58)"));

  const preset = String(theme.preset || THEME_DEFAULT_PRESET).toLowerCase();
  const presetClass = preset === "midnight"
    ? "theme-midnight"
    : preset === "high-contrast"
      ? "theme-high-contrast"
      : preset === "custom"
        ? "theme-custom"
        : (preset === "zen-dark" || preset === "frost-glass" ? "theme-soft" : "theme-default");
  const densityClass = `density-${appearanceDensityLabel(theme)}`;
  const reduceMotion = normalizeThemeBool(theme.reduce_motion, THEME_DEFAULT_OPTIONS.reduce_motion);
  [root, document.body].filter(Boolean).forEach((node) => {
    node.classList.remove("theme-default", "theme-midnight", "theme-soft", "theme-high-contrast", "theme-custom");
    node.classList.remove("density-cozy", "density-balanced", "density-compact");
    node.classList.toggle("reduce-motion", reduceMotion);
    node.classList.add(presetClass, densityClass);
  });
}

function applyAppearanceSettingsLegacy(themeInput, { syncForm = false, markCommitted = false } = {}) {
  const appearanceTheme = stripProfileMetaFromAppearanceTheme(themeInput || loadAppearanceSettings());
  appearanceSettingsCache = appearanceTheme;
  const runtimeTheme = mergeAppearanceWithProfileTheme(appearanceTheme);
  state.me = state.me || {};
  state.me.theme_settings = runtimeTheme;
  applyThemeSettings(runtimeTheme);
  if (syncForm) writeThemeToForm(runtimeTheme);
  if (markCommitted) setThemeEditorCommitted(runtimeTheme);
  return runtimeTheme;
}

function readAppearanceControlsLegacy() {
  return stripProfileMetaFromAppearanceTheme(readThemeFromForm());
}

function updateAppearanceControlsLegacy(themeInput) {
  writeThemeToForm(mergeAppearanceWithProfileTheme(themeInput || loadAppearanceSettings()));
}

function syncAppearanceVisualControlsLegacy(themeInput) {
  const theme = normalizeThemeSettings(themeInput || getActiveThemeSettings());
  const preset = String(theme.preset || THEME_DEFAULT_PRESET).toLowerCase();
  const mode = String(theme.mode || THEME_DEFAULT_OPTIONS.mode).toLowerCase();
  document.querySelectorAll("[data-appearance-preset]").forEach((node) => {
    if (!(node instanceof HTMLElement)) return;
    const nodePreset = String(node.dataset.appearancePreset || "").trim().toLowerCase();
    const nodeMode = String(node.dataset.appearanceMode || "").trim().toLowerCase();
    const selected = nodePreset === "custom"
      ? preset === "custom"
      : (nodePreset === preset && (!nodeMode || nodeMode === mode));
    node.classList.toggle("is-selected", selected);
    node.setAttribute("aria-pressed", selected ? "true" : "false");
  });
  const activeAccent = normalizeHexColor(theme.accent, "#e8cfae").toLowerCase();
  document.querySelectorAll("[data-appearance-accent]").forEach((node) => {
    if (!(node instanceof HTMLElement)) return;
    const value = String(node.dataset.appearanceAccent || "").trim().toLowerCase();
    const selected = value !== "custom" && normalizeHexColor(value, "").toLowerCase() === activeAccent;
    node.classList.toggle("is-selected", selected);
    if (value !== "custom") node.setAttribute("aria-pressed", selected ? "true" : "false");
  });
  const activeDensity = String(theme.density || THEME_DEFAULT_OPTIONS.density).toLowerCase();
  document.querySelectorAll("[data-appearance-density]").forEach((node) => {
    if (!(node instanceof HTMLElement)) return;
    const selected = String(node.dataset.appearanceDensity || "").trim().toLowerCase() === activeDensity;
    node.classList.toggle("is-selected", selected);
    node.setAttribute("aria-pressed", selected ? "true" : "false");
  });
}

function bindAppearanceControlsLegacy() {
  if (appearanceControlsBound) return;
  appearanceControlsBound = true;

  document.querySelectorAll("[data-appearance-preset]").forEach((node) => {
    node.addEventListener("click", () => {
      const els = getThemeFormEls();
      const preset = String(node.dataset.appearancePreset || "").trim().toLowerCase();
      const mode = String(node.dataset.appearanceMode || "").trim().toLowerCase();
      if (els.preset && (preset === "custom" || Object.prototype.hasOwnProperty.call(THEME_PRESETS, preset))) {
        els.preset.value = Array.from(els.preset.options || []).some((opt) => opt.value === preset) ? preset : "custom";
      }
      if (els.mode && mode) els.mode.value = mode;
      if (preset === "custom") {
        previewThemeFromForm();
        document.querySelector(".appearanceAdvancedTokens")?.setAttribute("open", "");
      } else {
        onThemePresetChange();
      }
    });
  });

  document.querySelectorAll("[data-appearance-accent]").forEach((node) => {
    node.addEventListener("click", () => {
      const value = String(node.dataset.appearanceAccent || "").trim();
      const els = getThemeFormEls();
      if (value.toLowerCase() === "custom") {
        const advanced = document.querySelector(".appearanceAdvancedTokens");
        if (advanced instanceof HTMLDetailsElement) advanced.open = true;
        els.accent?.focus?.();
        return;
      }
      const accent = normalizeThemeOptionalColor(value);
      if (!accent || !(els.accent instanceof HTMLInputElement)) return;
      els.accent.value = accent;
      onThemeColorInput();
    });
  });

  document.querySelectorAll("[data-appearance-density]").forEach((node) => {
    node.addEventListener("click", () => {
      const density = normalizeAppearanceDensityValue(node.dataset.appearanceDensity, THEME_DEFAULT_OPTIONS.density);
      const els = getThemeFormEls();
      if (els.density) els.density.value = density;
      onThemeOptionInput();
    });
  });
}

function resetAppearanceSettingsLegacy() {
  const theme = getDefaultAppearanceSettings();
  updateAppearanceControls(theme);
  applyAppearanceSettings(theme);
  writeThemeEditorDraftToStorage(theme);
  syncSidebarWidthControls(theme.left_sidebar_width);
  setAppLanguage(theme.app_language, { persist: true, rerender: true, syncForm: false });
  return theme;
}

function getDefaultAppearanceSettings() {
  return {
    theme: APPEARANCE_DEFAULT_THEME,
    accent: APPEARANCE_DEFAULT_ACCENT,
  };
}

function normalizeAppearanceThemeChoice(value, fallback = APPEARANCE_DEFAULT_THEME) {
  const raw = String(value || "").trim().toLowerCase();
  return APPEARANCE_THEME_VALUES.includes(raw) ? raw : fallback;
}

function inferAppearanceThemeChoiceFromThemeObject(raw) {
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) return APPEARANCE_DEFAULT_THEME;
  const mode = String(raw.mode || raw.effective_mode || "").trim().toLowerCase();
  const preset = String(raw.preset || raw.preset_id || "").trim().toLowerCase();
  if (mode === "auto" || preset === "system") return "system";
  if (mode === "light" || preset === "white" || preset === "clean-light") return "white";
  return "default";
}

function normalizeAppearanceSettings(raw) {
  const defaults = getDefaultAppearanceSettings();
  let source = raw;
  if (typeof source === "string") {
    try {
      source = JSON.parse(source);
    } catch (_) {
      source = {};
    }
  }
  if (!source || typeof source !== "object" || Array.isArray(source)) return defaults;

  const oldThemeObject = source.theme && typeof source.theme === "object" && !Array.isArray(source.theme)
    ? source.theme
    : null;
  const explicitTheme = typeof source.theme === "string"
    ? source.theme
    : (typeof source.appearance_theme === "string"
      ? source.appearance_theme
      : (typeof source.appearanceTheme === "string" ? source.appearanceTheme : ""));
  const inferredTheme = explicitTheme || inferAppearanceThemeChoiceFromThemeObject(oldThemeObject || source);
  const accent = normalizeThemeOptionalColor(
    source.appearance_accent ||
    source.appearanceAccent ||
    source.accent ||
    source.accent_color ||
    oldThemeObject?.accent ||
    source.themeAccent ||
    ""
  ) || defaults.accent;

  return {
    theme: normalizeAppearanceThemeChoice(inferredTheme, defaults.theme),
    accent,
  };
}

function isAppearanceSystemLight() {
  return !isSystemPrefersDark();
}

function resolveAppearanceThemeChoice(settingsInput) {
  const settings = normalizeAppearanceSettings(settingsInput || appearanceSettingsCache || getDefaultAppearanceSettings());
  if (settings.theme !== "system") return settings.theme;
  return isAppearanceSystemLight() ? "white" : "default";
}

function buildAppearanceThemeSettings(settingsInput) {
  const settings = normalizeAppearanceSettings(settingsInput);
  const resolvedTheme = resolveAppearanceThemeChoice(settings);
  const accent = normalizeThemeOptionalColor(settings.accent) || APPEARANCE_DEFAULT_ACCENT;
  const common = {
    ...THEME_DEFAULT_OPTIONS,
    accent,
    accent_secondary: mixHex(accent, resolvedTheme === "white" ? "#7d6a52" : "#ffffff", resolvedTheme === "white" ? 0.22 : 0.18),
    button_primary: accent,
    link_color: accent,
    color_intensity: 100,
    roundness: THEME_DEFAULT_OPTIONS.roundness,
    spacing_scale: 100,
    font_scale: 100,
    reduce_motion: false,
    profile_card_banner: true,
  };

  if (resolvedTheme === "white") {
    const theme = normalizeThemeSettings({
      ...common,
      preset: "clean-light",
      mode: "light",
      visual_style: "soft",
      density: "normal",
      layout_mood: "calm",
      background: "#f4f1ea",
      background_secondary: "#ebe6dc",
      surface: "#fffaf4",
      surface_secondary: "#f0eadf",
      row_color: "#f7f1e8",
      text_color: "#211f1a",
      button_secondary: "#eee7dc",
      input_color: "#fffaf4",
      border_color: "#d8cfc1",
      hover_color: "#eee5d8",
      active_color: mixHex("#f4f1ea", accent, 0.2),
      message_sent: mixHex("#f4f1ea", accent, 0.24),
      message_received: "#fbf6ee",
      success_color: "#4d9c67",
      warning_color: "#a57930",
      danger_color: "#bd5f5d",
      info_color: "#5f8fa6",
    });
    theme.appearance_theme = settings.theme;
    theme.appearance_accent = accent;
    return theme;
  }

  const theme = normalizeThemeSettings({
    ...common,
    preset: THEME_DEFAULT_PRESET,
    mode: "dark",
    visual_style: "soft",
    density: "normal",
    layout_mood: "calm",
    background: "#101010",
    background_secondary: "#151515",
    surface: "#181818",
    surface_secondary: "#202020",
    row_color: "#171717",
    text_color: "#f2f0ec",
    button_secondary: "#202020",
    input_color: "#111111",
    border_color: "#2c2c2c",
    hover_color: "#202020",
    active_color: mixHex("#101010", accent, 0.18),
    message_sent: mixHex("#161616", accent, 0.22),
    message_received: "#1b1b1b",
    success_color: "#69b87b",
    warning_color: "#d4aa55",
    danger_color: "#d36c68",
    info_color: "#6fbcb3",
  });
  theme.appearance_theme = settings.theme;
  theme.appearance_accent = accent;
  return theme;
}

function mergeAppearanceWithProfileTheme(settingsInput) {
  return normalizeThemeSettings({
    ...buildAppearanceThemeSettings(settingsInput),
    ...getProfileThemeMetaForAppearance(),
  });
}

function getAppearanceCacheUserId() {
  return normId(state.user?.id || state.me?.id || "");
}

function getAppearanceCacheStorageKey(userIdInput = "") {
  const uid = normId(userIdInput || getAppearanceCacheUserId());
  return uid ? `${APPEARANCE_STORAGE_KEY}:${uid}` : "";
}

function readCachedAppearanceSettingsForUser(userIdInput = "") {
  const key = getAppearanceCacheStorageKey(userIdInput);
  if (!key) return null;
  try {
    const raw = localStorage.getItem(key);
    return raw ? normalizeAppearanceSettings(JSON.parse(raw)) : null;
  } catch (err) {
    console.warn("Could not load cached account appearance settings:", err);
    return null;
  }
}

function writeCachedAppearanceSettingsForUser(settingsInput, userIdInput = "") {
  const key = getAppearanceCacheStorageKey(userIdInput);
  if (!key) return;
  const settings = normalizeAppearanceSettings(settingsInput);
  try {
    localStorage.setItem(key, JSON.stringify(settings));
  } catch (err) {
    console.warn("Could not save cached account appearance settings:", err);
  }
}

function loadAppearanceSettings({ force = false } = {}) {
  const userId = getAppearanceCacheUserId();
  if (appearanceSettingsCache && !force && appearanceSettingsCacheUserId === userId) return appearanceSettingsCache;

  if (state.me?.theme_settings && typeof state.me.theme_settings === "object" && !Array.isArray(state.me.theme_settings)) {
    appearanceSettingsCache = normalizeAppearanceSettings(state.me.theme_settings);
    appearanceSettingsCacheUserId = userId;
    writeCachedAppearanceSettingsForUser(appearanceSettingsCache, userId);
    return appearanceSettingsCache;
  }

  appearanceSettingsCache = readCachedAppearanceSettingsForUser(userId) || getDefaultAppearanceSettings();
  appearanceSettingsCacheUserId = userId;
  return appearanceSettingsCache;
}

function saveAppearanceSettings(settingsInput) {
  const settings = normalizeAppearanceSettings(settingsInput || appearanceSettingsCache || getDefaultAppearanceSettings());
  const userId = getAppearanceCacheUserId();
  appearanceSettingsCache = settings;
  appearanceSettingsCacheUserId = userId;
  writeCachedAppearanceSettingsForUser(settings, userId);
  return settings;
}

function getAppearanceRuntimePalette(settingsInput) {
  const settings = normalizeAppearanceSettings(settingsInput || appearanceSettingsCache || getDefaultAppearanceSettings());
  const resolved = resolveAppearanceThemeChoice(settings);
  const isWhite = resolved === "white";
  const accent = normalizeThemeOptionalColor(settings.accent) || APPEARANCE_DEFAULT_ACCENT;
  const accentStrong = isWhite
    ? mixHex(accent, "#3d3326", 0.42)
    : mixHex(accent, "#ffffff", 0.14);

  if (isWhite) {
    return {
      settings,
      resolved,
      isWhite,
      accent,
      accentStrong,
      bg: "#f5f1e8",
      bgDeep: "#e4dac8",
      bgSoft: "#eee8dd",
      surface: "#fffdf8",
      surface0: "rgba(255, 253, 248, 0.92)",
      surfaceElevated: "#f8f3ea",
      surfacePanel: "#f3ede4",
      row: "rgba(24, 21, 18, 0.045)",
      rowStrong: "#efe7db",
      hover: "#ece4d8",
      active: "rgba(218, 184, 141, 0.22)",
      input: "#f3ede4",
      inputFocus: mixHex("#f3ede4", accent, 0.12),
      border: "rgba(32, 28, 22, 0.14)",
      borderStrong: "rgba(32, 28, 22, 0.22)",
      text: "#181512",
      textSoft: "#8c8174",
      textMuted: "#675f55",
      link: accentStrong,
      shadow: "rgba(61, 48, 34, 0.16)",
      overlay: "rgba(245, 241, 232, 0.72)",
    };
  }

  return {
    settings,
    resolved,
    isWhite,
    accent,
    accentStrong,
    bg: "#101010",
    bgDeep: "#080808",
    bgSoft: "#151515",
    surface: "#181818",
    surface0: "rgba(24, 24, 24, 0.94)",
    surfaceElevated: "#202020",
    surfacePanel: "#1c1c1c",
    row: "rgba(255, 255, 255, 0.035)",
    rowStrong: "#181818",
    hover: "rgba(255, 255, 255, 0.055)",
    active: rgbaFromHex(accent, 0.12),
    input: "#111111",
    inputFocus: mixHex("#111111", accent, 0.1),
    border: "rgba(255, 255, 255, 0.075)",
    borderStrong: "rgba(255, 255, 255, 0.115)",
    text: "#f2f0ec",
    textSoft: "rgba(242, 240, 236, 0.64)",
    textMuted: "rgba(242, 240, 236, 0.44)",
    link: accentStrong,
    shadow: "rgba(0, 0, 0, 0.46)",
    overlay: "rgba(0, 0, 0, 0.68)",
  };
}

function setAppearanceRuntimeVar(root, name, value) {
  if (!root || !name) return;
  root.style.setProperty(name, String(value || ""));
}

function exposeAppearanceDebugHelper() {
  if (typeof window === "undefined") return;
  window.__ALTARA_APPEARANCE_DEBUG__ = () => {
    const root = document.documentElement;
    const styles = getComputedStyle(root);
    let saved = null;
    const userId = getAppearanceCacheUserId();
    const scopedStorageKey = getAppearanceCacheStorageKey(userId);
    try {
      saved = scopedStorageKey
        ? normalizeAppearanceSettings(JSON.parse(localStorage.getItem(scopedStorageKey) || "null"))
        : getDefaultAppearanceSettings();
    } catch (_) {
      saved = getDefaultAppearanceSettings();
    }
    const active = normalizeAppearanceSettings(appearanceSettingsCache || saved);
    return {
      storageKey: APPEARANCE_STORAGE_KEY,
      scopedStorageKey,
      cacheUserId: appearanceSettingsCacheUserId,
      saved,
      active,
      selectedTheme: active.theme,
      resolvedTheme: resolveAppearanceThemeChoice(active),
      rootClasses: Array.from(root.classList),
      bodyClasses: Array.from(document.body?.classList || []),
      variables: {
        "--altara-bg": styles.getPropertyValue("--altara-bg").trim(),
        "--altara-surface": styles.getPropertyValue("--altara-surface").trim(),
        "--altara-surface-elevated": styles.getPropertyValue("--altara-surface-elevated").trim(),
        "--altara-border": styles.getPropertyValue("--altara-border").trim(),
        "--altara-text": styles.getPropertyValue("--altara-text").trim(),
        "--altara-text-muted": styles.getPropertyValue("--altara-text-muted").trim(),
        "--altara-accent": styles.getPropertyValue("--altara-accent").trim(),
        "--bg-main": styles.getPropertyValue("--bg-main").trim(),
        "--surface-1": styles.getPropertyValue("--surface-1").trim(),
        "--ui-shell-bg": styles.getPropertyValue("--ui-shell-bg").trim(),
      },
      bodyVariables: (() => {
        const bodyStyles = getComputedStyle(document.body);
        return {
          "--altara-bg": bodyStyles.getPropertyValue("--altara-bg").trim(),
          "--altara-surface": bodyStyles.getPropertyValue("--altara-surface").trim(),
          "--altara-text": bodyStyles.getPropertyValue("--altara-text").trim(),
          "--altara-text-muted": bodyStyles.getPropertyValue("--altara-text-muted").trim(),
          "--altara-border": bodyStyles.getPropertyValue("--altara-border").trim(),
          "--altara-accent": bodyStyles.getPropertyValue("--altara-accent").trim(),
          "--bg-main": bodyStyles.getPropertyValue("--bg-main").trim(),
          "--ui-shell-bg": bodyStyles.getPropertyValue("--ui-shell-bg").trim(),
        };
      })(),
      appVariables: (() => {
        const appEl = document.querySelector(".app");
        if (!(appEl instanceof HTMLElement)) return null;
        const appStyles = getComputedStyle(appEl);
        return {
          "--altara-bg": appStyles.getPropertyValue("--altara-bg").trim(),
          "--altara-surface": appStyles.getPropertyValue("--altara-surface").trim(),
          "--altara-text": appStyles.getPropertyValue("--altara-text").trim(),
          "--altara-text-muted": appStyles.getPropertyValue("--altara-text-muted").trim(),
          "--altara-border": appStyles.getPropertyValue("--altara-border").trim(),
          "--altara-accent": appStyles.getPropertyValue("--altara-accent").trim(),
          "--bg-main": appStyles.getPropertyValue("--bg-main").trim(),
          "--ui-shell-bg": appStyles.getPropertyValue("--ui-shell-bg").trim(),
        };
      })(),
    };
  };
}

function applyAltaraAppearanceRuntime(themeInput, cssVars = {}) {
  const root = document.documentElement;
  if (!root) return;
  const palette = getAppearanceRuntimePalette(appearanceSettingsCache || loadAppearanceSettings());
  const { settings, resolved, accent, accentStrong, isWhite } = palette;

  const runtimeVars = {
    "--altara-bg": palette.bg,
    "--altara-bg-soft": palette.bgSoft,
    "--altara-surface": palette.surface,
    "--altara-surface-elevated": palette.surfaceElevated,
    "--altara-surface-panel": palette.surfacePanel,
    "--altara-border": palette.border,
    "--altara-border-strong": palette.borderStrong,
    "--altara-text": palette.text,
    "--altara-text-muted": palette.textMuted,
    "--altara-text-soft": palette.textSoft,
    "--altara-input": palette.input,
    "--altara-hover": palette.hover,
    "--altara-active": palette.active,
    "--altara-accent": accent,
    "--altara-accent-strong": accentStrong,
    "--altara-accent-soft": rgbaFromHex(accent, isWhite ? 0.14 : 0.11),
    "--altara-accent-border": rgbaFromHex(accent, isWhite ? 0.34 : 0.28),

    "--bg-main": palette.bg,
    "--bg-deep": palette.bgDeep,
    "--surface-0": palette.surface0,
    "--surface-1": palette.surface,
    "--surface-2": palette.surfaceElevated,
    "--surface-row": palette.row,
    "--surface-row-hover": palette.active,
    "--stroke": palette.border,
    "--stroke-strong": palette.borderStrong,
    "--text-main": palette.text,
    "--text-soft": isWhite ? palette.textMuted : palette.textSoft,
    "--text-muted": palette.textMuted,
    "--color-link": palette.link,
    "--accent": accent,
    "--accent-strong": accentStrong,
    "--accent-soft": rgbaFromHex(accent, isWhite ? 0.16 : 0.14),
    "--focus-ring": rgbaFromHex(accent, isWhite ? 0.28 : 0.34),
    "--selection-bg": rgbaFromHex(accent, isWhite ? 0.36 : 0.58),

    "--ui-shell-bg": palette.bg,
    "--ui-top-bg": palette.bg,
    "--ui-card-bg": palette.surface,
    "--ui-panel-soft-bg": palette.bgSoft,
    "--ui-row-bg": palette.row,
    "--ui-row-strong-bg": palette.rowStrong,
    "--ui-input-bg": palette.input,
    "--ui-input-focus-bg": palette.inputFocus,
    "--ui-btn-bg": palette.surfaceElevated,
    "--ui-btn-border": palette.border,
    "--ui-btn-hover-bg": palette.hover,
    "--ui-btn-hover-border": palette.borderStrong,
    "--ui-primary-bg": rgbaFromHex(accent, isWhite ? 0.14 : 0.16),
    "--ui-primary-border": rgbaFromHex(accent, isWhite ? 0.34 : 0.28),
    "--ui-primary-hover-bg": rgbaFromHex(accent, isWhite ? 0.22 : 0.24),
    "--ui-primary-hover-border": rgbaFromHex(accent, isWhite ? 0.46 : 0.38),
    "--ui-danger-bg": isWhite ? "rgba(189, 95, 93, 0.1)" : "rgba(211, 108, 104, 0.14)",
    "--ui-danger-border": isWhite ? "rgba(189, 95, 93, 0.26)" : "rgba(211, 108, 104, 0.24)",
    "--ui-danger-hover-bg": isWhite ? "rgba(189, 95, 93, 0.16)" : "rgba(211, 108, 104, 0.22)",
    "--ui-danger-hover-border": isWhite ? "rgba(189, 95, 93, 0.38)" : "rgba(211, 108, 104, 0.36)",
    "--ui-debug-bg": palette.surfacePanel,
    "--left-sidebar-bg": palette.bg,
    "--left-sidebar-top-bg": palette.bg,
  };

  [root, document.body, document.querySelector(".app")].filter(Boolean).forEach((target) => {
    Object.entries(runtimeVars).forEach(([name, value]) => setAppearanceRuntimeVar(target, name, value));
  });

  const nodes = [root, document.body].filter(Boolean);
  nodes.forEach((node) => {
    node.classList.remove(
      "theme-default",
      "theme-midnight",
      "theme-soft",
      "theme-high-contrast",
      "theme-custom",
      "theme-white",
      "theme-system",
      "theme-resolved-dark",
      "theme-resolved-light",
      "density-cozy",
      "density-balanced",
      "density-compact",
      "reduce-motion"
    );
    node.classList.add(settings.theme === "system" ? "theme-system" : `theme-${settings.theme}`);
    node.classList.add(isWhite ? "theme-resolved-light" : "theme-resolved-dark");
  });

  const settingsOverlay = document.getElementById("profileOverlay");
  if (settingsOverlay?.classList?.contains("settingsOverlay")) {
    settingsOverlay.style.setProperty("--settings-bg", palette.bg);
    settingsOverlay.style.setProperty("--settings-panel", palette.bgSoft);
    settingsOverlay.style.setProperty("--settings-surface", palette.surface);
    settingsOverlay.style.setProperty("--settings-surface-2", palette.surfacePanel);
    settingsOverlay.style.setProperty("--settings-row", isWhite ? "rgba(33, 31, 26, 0.045)" : "rgba(255, 255, 255, 0.035)");
    settingsOverlay.style.setProperty("--settings-row-hover", rgbaFromHex(accent, isWhite ? 0.12 : 0.07));
    settingsOverlay.style.setProperty("--settings-border", palette.border);
    settingsOverlay.style.setProperty("--settings-border-strong", palette.borderStrong);
    settingsOverlay.style.setProperty("--settings-text", palette.text);
    settingsOverlay.style.setProperty("--settings-soft", palette.textSoft);
    settingsOverlay.style.setProperty("--settings-muted", palette.textMuted);
    settingsOverlay.style.setProperty("--settings-accent", accent);
    settingsOverlay.style.setProperty("--settings-accent-soft", rgbaFromHex(accent, isWhite ? 0.16 : 0.11));
    settingsOverlay.style.setProperty("--settings-accent-border", rgbaFromHex(accent, isWhite ? 0.38 : 0.28));
  }

  exposeAppearanceDebugHelper();
}

function applyAppearanceSettings(settingsInput, { syncForm = false, markCommitted = false } = {}) {
  const settings = normalizeAppearanceSettings(settingsInput || loadAppearanceSettings());
  appearanceSettingsCache = settings;
  appearanceSettingsCacheUserId = getAppearanceCacheUserId();
  const runtimeTheme = mergeAppearanceWithProfileTheme(settings);
  state.me = state.me || {};
  state.me.theme_settings = runtimeTheme;
  applyThemeSettings(runtimeTheme);
  syncAppearanceVisualControls(settings);
  if (syncForm) updateAppearanceControls(settings);
  if (markCommitted) setThemeEditorCommitted(runtimeTheme);
  return runtimeTheme;
}

function readAppearanceControls() {
  return normalizeAppearanceSettings(appearanceSettingsCache || loadAppearanceSettings());
}

function updateAppearanceControls(settingsInput) {
  syncAppearanceVisualControls(settingsInput || appearanceSettingsCache || loadAppearanceSettings());
}

function syncAppearanceVisualControls(settingsInput) {
  const settings = normalizeAppearanceSettings(settingsInput || appearanceSettingsCache || loadAppearanceSettings());
  document.querySelectorAll("[data-appearance-theme]").forEach((node) => {
    if (!(node instanceof HTMLElement)) return;
    const selected = normalizeAppearanceThemeChoice(node.dataset.appearanceTheme) === settings.theme;
    node.classList.toggle("is-selected", selected);
    node.setAttribute("aria-pressed", selected ? "true" : "false");
  });

  const activeAccent = normalizeHexColor(settings.accent, APPEARANCE_DEFAULT_ACCENT).toLowerCase();
  document.querySelectorAll("[data-appearance-accent]").forEach((node) => {
    if (!(node instanceof HTMLElement)) return;
    const value = normalizeHexColor(node.dataset.appearanceAccent, "").toLowerCase();
    const selected = !!value && value === activeAccent;
    node.classList.toggle("is-selected", selected);
    node.setAttribute("aria-pressed", selected ? "true" : "false");
  });
}

function prefersReducedAppearanceFlash() {
  try {
    return !!prefersReducedMotionUi?.()
      || !!document.body?.classList?.contains("motion-reduced")
      || !!document.body?.classList?.contains("reduce-motion")
      || !!document.documentElement?.classList?.contains("reduce-motion")
      || !!window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches;
  } catch (_) {
    return false;
  }
}

function triggerAppearanceWhiteFlash() {
  if (prefersReducedAppearanceFlash()) return;
  const body = document.body;
  if (!body) return;
  let overlay = document.getElementById("appearanceWhiteFlashOverlay");
  if (!(overlay instanceof HTMLElement)) {
    overlay = document.createElement("div");
    overlay.id = "appearanceWhiteFlashOverlay";
    overlay.className = "appearanceWhiteFlashOverlay";
    overlay.setAttribute("aria-hidden", "true");
    body.appendChild(overlay);
  }
  overlay.classList.remove("is-active");
  void overlay.offsetWidth;
  overlay.classList.add("is-active");
  window.setTimeout(() => {
    overlay?.classList?.remove("is-active");
  }, 720);
}

function playAppearanceWhiteEasterEggSound() {
  try {
    if (!APPEARANCE_WHITE_EASTER_EGG_SOUND_URL) return;
    const audio = new Audio(APPEARANCE_WHITE_EASTER_EGG_SOUND_URL);
    audio.volume = 0.3;
    audio.loop = false;
    const result = audio.play();
    if (result && typeof result.catch === "function") {
      result.catch(() => {});
    }
  } catch (_) {}
}

async function confirmAppearanceWhiteThemeSelection(triggerEl = null) {
  if (appearanceWhiteThemeConfirmInFlight) return false;
  appearanceWhiteThemeConfirmInFlight = true;
  const modal = ensureAppConfirmModal?.();
  modal?.classList?.add("appConfirmModal--whiteThemeEasterEgg");
  let confirmed = false;
  try {
    confirmed = await requestAppConfirm(
      t("settings.appearance.white_confirm.body", "Light mode may cause emotional damage."),
      {
        title: t("settings.appearance.white_confirm.title", "Are you sure?"),
        okText: t("settings.appearance.white_confirm.ok", "Yes, flashbang me"),
        cancelText: t("settings.appearance.white_confirm.cancel", "No, take me back to the darkness"),
      }
    );
  } finally {
    appearanceWhiteThemeConfirmInFlight = false;
    modal?.classList?.remove("appConfirmModal--whiteThemeEasterEgg");
    if (triggerEl instanceof HTMLElement) {
      window.requestAnimationFrame(() => {
        try { triggerEl.focus(); } catch (_) {}
      });
    }
  }
  return !!confirmed;
}

function bindAppearanceControls() {
  if (appearanceControlsBound) return;
  appearanceControlsBound = true;

  document.querySelectorAll("[data-appearance-theme]").forEach((node) => {
    node.addEventListener("click", async () => {
      const current = normalizeAppearanceSettings(appearanceSettingsCache || loadAppearanceSettings());
      const theme = normalizeAppearanceThemeChoice(node.dataset.appearanceTheme, current.theme);
      if (theme === "white" && current.theme !== "white") {
        const confirmed = await confirmAppearanceWhiteThemeSelection(node);
        if (!confirmed) {
          syncAppearanceVisualControls(current);
          return;
        }
        playAppearanceWhiteEasterEggSound();
        triggerAppearanceWhiteFlash();
      }
      const next = {
        ...current,
        theme,
      };
      applyAppearanceSettings(next);
    });
  });

  document.querySelectorAll("[data-appearance-accent]").forEach((node) => {
    node.addEventListener("click", () => {
      const accent = normalizeThemeOptionalColor(node.dataset.appearanceAccent);
      if (!accent) return;
      const current = normalizeAppearanceSettings(appearanceSettingsCache || loadAppearanceSettings());
      applyAppearanceSettings({ ...current, accent });
    });
  });
}

function resetAppearanceSettings() {
  const settings = getDefaultAppearanceSettings();
  const runtimeTheme = applyAppearanceSettings(settings);
  clearThemeEditorDraftFromStorage();
  return runtimeTheme;
}

function getActiveThemeSettings() {
  return mergeAppearanceWithProfileTheme(appearanceSettingsCache || loadAppearanceSettings());
}

function bindThemeSystemModeSyncOnce() {
  if (themeSystemModeSyncBound) return;
  themeSystemModeSyncBound = true;
  const media = window.matchMedia?.("(prefers-color-scheme: dark)");
  if (!media) return;
  const handle = () => {
    const activeAppearance = normalizeAppearanceSettings(appearanceSettingsCache || loadAppearanceSettings());
    if (activeAppearance.theme !== "system") return;
    const active = applyAppearanceSettings(activeAppearance);
    const overlay = document.getElementById("profileOverlay");
    if (overlay && !overlay.classList.contains("hidden")) {
      syncAppearanceVisualControls(activeAppearance);
    }
  };
  if (typeof media.addEventListener === "function") {
    media.addEventListener("change", handle);
  } else if (typeof media.addListener === "function") {
    media.addListener(handle);
  }
}

function readThemeEditorDraftFromStorage() {
  try {
    const raw = localStorage.getItem(THEME_EDITOR_DRAFT_STORAGE_KEY);
    if (!raw) return null;
    return normalizeThemeSettings(JSON.parse(raw));
  } catch (_) {
    return null;
  }
}

function writeThemeEditorDraftToStorage(themeInput) {
  try {
    const theme = normalizeThemeSettings(themeInput);
    localStorage.setItem(THEME_EDITOR_DRAFT_STORAGE_KEY, JSON.stringify(theme));
  } catch (_) {}
}

function clearThemeEditorDraftFromStorage() {
  try {
    localStorage.removeItem(THEME_EDITOR_DRAFT_STORAGE_KEY);
  } catch (_) {}
}

function setThemeEditorCommitted(themeInput) {
  themeEditorCommittedSettings = normalizeThemeSettings(themeInput || getActiveThemeSettings());
}

function readCustomThemePresetsFromStorage() {
  try {
    const raw = localStorage.getItem(THEME_CUSTOM_PRESETS_STORAGE_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return {};
    const out = {};
    Object.entries(parsed).forEach(([key, value]) => {
      const id = String(key || "").trim().toLowerCase();
      if (!id) return;
      out[id] = normalizeThemeSettings(value);
    });
    return out;
  } catch (_) {
    return {};
  }
}

function writeCustomThemePresetsToStorage(presetsInput) {
  try {
    const src = (presetsInput && typeof presetsInput === "object" && !Array.isArray(presetsInput))
      ? presetsInput
      : {};
    const out = {};
    Object.entries(src).forEach(([key, value]) => {
      const id = String(key || "").trim().toLowerCase();
      if (!id) return;
      out[id] = normalizeThemeSettings(value);
    });
    localStorage.setItem(THEME_CUSTOM_PRESETS_STORAGE_KEY, JSON.stringify(out));
  } catch (_) {}
}

function slugifyThemePresetName(nameInput) {
  const cleaned = String(nameInput || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return cleaned.slice(0, 48);
}

function ensureThemeCustomPresetsLoaded() {
  if (!themeCustomPresetsCache || typeof themeCustomPresetsCache !== "object" || Array.isArray(themeCustomPresetsCache)) {
    themeCustomPresetsCache = {};
  }
  if (!Object.keys(themeCustomPresetsCache).length) {
    themeCustomPresetsCache = readCustomThemePresetsFromStorage();
  }
  return themeCustomPresetsCache;
}

function renderThemeCustomPresetSelect() {
  const els = getThemeFormEls();
  const select = els.customPresetSelect;
  if (!(select instanceof HTMLSelectElement)) return;
  const presets = ensureThemeCustomPresetsLoaded();
  const current = String(select.value || "").trim().toLowerCase();
  const options = Object.keys(presets).sort((a, b) => a.localeCompare(b));
  const html = [
    `<option value="">None</option>`,
    ...options.map((id) => `<option value="${escAttr(id)}">${esc(id)}</option>`),
  ].join("");
  select.innerHTML = html;
  if (current && options.includes(current)) {
    select.value = current;
  } else {
    select.value = "";
  }
}

function saveCurrentThemeAsCustomPreset() {
  const els = getThemeFormEls();
  const nameRaw = String(els.customPresetName?.value || "").trim();
  if (!nameRaw) {
    alert("Write a preset name first.");
    return;
  }
  const id = slugifyThemePresetName(nameRaw);
  if (!id) {
    alert("Invalid preset name.");
    return;
  }
  const nextTheme = normalizeThemeSettings({ ...readThemeFromForm(), preset: "custom" });
  const presets = ensureThemeCustomPresetsLoaded();
  presets[id] = nextTheme;
  writeCustomThemePresetsToStorage(presets);
  renderThemeCustomPresetSelect();
  if (els.customPresetSelect) els.customPresetSelect.value = id;
}

function applySelectedCustomThemePreset() {
  const els = getThemeFormEls();
  const id = String(els.customPresetSelect?.value || "").trim().toLowerCase();
  if (!id) return;
  const presets = ensureThemeCustomPresetsLoaded();
  const selected = presets[id];
  if (!selected) return;
  writeThemeToForm(normalizeThemeSettings({ ...selected, preset: "custom" }));
  previewThemeFromForm();
}

function deleteSelectedCustomThemePreset() {
  const els = getThemeFormEls();
  const id = String(els.customPresetSelect?.value || "").trim().toLowerCase();
  if (!id) return;
  const presets = ensureThemeCustomPresetsLoaded();
  if (!Object.prototype.hasOwnProperty.call(presets, id)) return;
  delete presets[id];
  writeCustomThemePresetsToStorage(presets);
  renderThemeCustomPresetSelect();
}

function cancelThemeFormChanges() {
  const settings = loadAppearanceSettings({ force: true });
  const theme = mergeAppearanceWithProfileTheme(settings);
  writeThemeToForm(theme);
  applyAppearanceSettings(settings);
  applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
  syncSidebarWidthControls(theme.left_sidebar_width);
  clearThemeEditorDraftFromStorage();
}

function exportThemeFromEditor() {
  const theme = normalizeThemeSettings(readThemeFromForm());
  const payload = serializeThemeExportEngine(theme, {
    profile_id: String(state.user?.id || "").trim(),
  });
  const blob = new Blob([payload], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  const date = new Date().toISOString().slice(0, 10);
  a.href = url;
  a.download = `${THEME_EXPORT_FILENAME_PREFIX}-${date}.json`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => {
    try { URL.revokeObjectURL(url); } catch (_) {}
  }, 1200);
}

async function importThemeFromEditorFile(file) {
  if (!(file instanceof File)) return;
  const text = await file.text();
  const parsed = parseThemeImportEngine(text);
  const merged = normalizeThemeSettings({
    ...readThemeFromForm(),
    ...parsed,
    preset: "custom",
  });
  writeThemeToForm(merged);
  previewThemeFromForm();
}

function getCurrentSidebarWidth() {
  const raw = getComputedStyle(document.documentElement).getPropertyValue("--left-sidebar-width");
  const fromCss = parseInt(String(raw || "").trim(), 10);
  if (Number.isFinite(fromCss)) {
    return clampInt(fromCss, LEFT_SIDEBAR_WIDTH_MIN, LEFT_SIDEBAR_WIDTH_MAX, THEME_DEFAULT_OPTIONS.left_sidebar_width);
  }
  return clampInt(
    state.me?.theme_settings?.left_sidebar_width,
    LEFT_SIDEBAR_WIDTH_MIN,
    LEFT_SIDEBAR_WIDTH_MAX,
    THEME_DEFAULT_OPTIONS.left_sidebar_width
  );
}

function syncLeftSidebarDensityClass(widthInput) {
  const body = document.body;
  if (!body) return;
  const panel = document.querySelector(".panel.left");
  let width = Number(widthInput);
  if (!Number.isFinite(width) || width <= 0) {
    const panelWidth = panel?.getBoundingClientRect?.().width;
    if (Number.isFinite(panelWidth) && panelWidth > 0) width = panelWidth;
  }
  if (!Number.isFinite(width) || width <= 0) width = getCurrentSidebarWidth();
  body.classList.toggle("left-sidebar-tight", width <= LEFT_SIDEBAR_TIGHT_MAX);
}

function bindLeftSidebarDensitySyncOnce() {
  if (leftSidebarDensitySyncBound) return;
  leftSidebarDensitySyncBound = true;
  window.addEventListener("resize", () => {
    syncLeftSidebarDensityClass();
  });
}

function setSidebarResizerAria(widthInput) {
  const handle = document.getElementById("leftSidebarResizer");
  if (!handle) return;
  const width = clampInt(widthInput, LEFT_SIDEBAR_WIDTH_MIN, LEFT_SIDEBAR_WIDTH_MAX, THEME_DEFAULT_OPTIONS.left_sidebar_width);
  handle.setAttribute("aria-valuenow", String(width));
}

function syncSidebarWidthControls(widthInput) {
  const width = clampInt(widthInput, LEFT_SIDEBAR_WIDTH_MIN, LEFT_SIDEBAR_WIDTH_MAX, THEME_DEFAULT_OPTIONS.left_sidebar_width);
  const els = getThemeFormEls();
  if (els.leftSidebarWidth) els.leftSidebarWidth.value = String(width);
  syncThemeOptionLabels(els);
  setSidebarResizerAria(width);
}

function applySidebarWidth(widthInput, { syncForm = true } = {}) {
  const width = clampInt(widthInput, LEFT_SIDEBAR_WIDTH_MIN, LEFT_SIDEBAR_WIDTH_MAX, THEME_DEFAULT_OPTIONS.left_sidebar_width);
  const current = getActiveThemeSettings();
  const nextTheme = normalizeThemeSettings({ ...current, left_sidebar_width: width });
  state.me = state.me || {};
  state.me.theme_settings = nextTheme;
  applyThemeSettings(nextTheme);
  if (syncForm) syncSidebarWidthControls(width);
  return nextTheme;
}

async function persistThemeSettings(themeInput, { showSuccess = false, showError = true } = {}) {
  if (!state.user) return false;
  const theme = normalizeThemeSettings({
    ...(state.me?.theme_settings || {}),
    ...(themeInput || {}),
  });
  const { error } = await supabase
    .from("profiles")
    .update({ theme_settings: theme })
    .eq("id", state.user.id);

  setProfileDebug({ update_theme: { error, theme } });

  if (error) {
    if (showError) {
      const msg = String(error.message || "").toLowerCase();
      if (msg.includes("theme_settings") && msg.includes("column")) {
        alert("Falta a coluna theme_settings no Supabase. Corre o patch SQL novo.");
      } else {
        alert("Erro a guardar cores: " + error.message);
      }
    } else {
      console.warn("theme_settings save failed:", error.message || error);
    }
    return false;
  }

  state.me = state.me || {};
  state.me.theme_settings = theme;
  setThemeEditorCommitted(theme);
  applyThemeSettings(theme);
  syncSidebarWidthControls(theme.left_sidebar_width);
  if (showSuccess) alert("PersonalizaÃ§Ã£o guardada na conta.");
  return true;
}

async function saveThemeSettings() {
  const settings = readAppearanceControls();
  const runtimeTheme = mergeAppearanceWithProfileTheme(settings);
  const saved = await persistThemeSettings(runtimeTheme, { showSuccess: false, showError: true });
  if (!saved) return;
  const savedSettings = saveAppearanceSettings(settings);
  applyAppearanceSettings(savedSettings);
  setThemeEditorCommitted(runtimeTheme);
  clearThemeEditorDraftFromStorage();
  alert(t("settings.theme.saved_account", "Appearance saved to your account."));
}

function queueSidebarWidthPersist(widthInput) {
  const width = clampInt(widthInput, LEFT_SIDEBAR_WIDTH_MIN, LEFT_SIDEBAR_WIDTH_MAX, THEME_DEFAULT_OPTIONS.left_sidebar_width);
  writeLeftSidebarWidthPreference(width);
  if (leftSidebarWidthPersistTimer) clearTimeout(leftSidebarWidthPersistTimer);
  leftSidebarWidthPersistTimer = setTimeout(() => {
    leftSidebarWidthPersistTimer = null;
    const theme = normalizeThemeSettings({ ...getActiveThemeSettings(), left_sidebar_width: width });
    state.me = state.me || {};
    state.me.theme_settings = theme;
    applyThemeSettings(theme);
    setThemeEditorCommitted(theme);
  }, 260);
}

function bindLeftSidebarResizerOnce() {
  if (leftSidebarResizerBound) return;
  const handle = document.getElementById("leftSidebarResizer");
  if (!handle) return;
  leftSidebarResizerBound = true;

  const savedWidth = readLeftSidebarWidthPreference();
  if (savedWidth !== null) applySidebarWidth(savedWidth, { syncForm: false });

  let drag = null;

  const stopDrag = ({ persist = true } = {}) => {
    if (!drag) return;
    const finalWidth = clampInt(
      drag.currentWidth,
      LEFT_SIDEBAR_WIDTH_MIN,
      LEFT_SIDEBAR_WIDTH_MAX,
      THEME_DEFAULT_OPTIONS.left_sidebar_width
    );
    drag = null;
    handle.classList.remove("is-dragging");
    document.body?.classList?.remove("is-resizing-sidebar");
    if (persist) queueSidebarWidthPersist(finalWidth);
  };

  handle.addEventListener("pointerdown", (e) => {
    if (e.button !== 0) return;
    if (window.matchMedia?.("(max-width: 980px)")?.matches) return;
    e.preventDefault();
    const startWidth = getCurrentSidebarWidth();
    drag = { pointerId: e.pointerId, startX: e.clientX, startWidth, currentWidth: startWidth };
    handle.classList.add("is-dragging");
    document.body?.classList?.add("is-resizing-sidebar");
    setSidebarResizerAria(startWidth);
    try { handle.setPointerCapture(e.pointerId); } catch (_) {}
  });

  handle.addEventListener("pointermove", (e) => {
    if (!drag || e.pointerId !== drag.pointerId) return;
    const delta = e.clientX - drag.startX;
    const nextWidth = clampInt(
      drag.startWidth + delta,
      LEFT_SIDEBAR_WIDTH_MIN,
      LEFT_SIDEBAR_WIDTH_MAX,
      THEME_DEFAULT_OPTIONS.left_sidebar_width
    );
    drag.currentWidth = nextWidth;
    applySidebarWidth(nextWidth, { syncForm: true });
  });

  handle.addEventListener("pointerup", (e) => {
    if (!drag || e.pointerId !== drag.pointerId) return;
    stopDrag({ persist: true });
  });

  handle.addEventListener("pointercancel", (e) => {
    if (!drag || e.pointerId !== drag.pointerId) return;
    stopDrag({ persist: false });
  });

  handle.addEventListener("lostpointercapture", () => {
    if (!drag) return;
    stopDrag({ persist: true });
  });

  handle.addEventListener("keydown", (e) => {
    const key = e.key;
    if (key !== "ArrowLeft" && key !== "ArrowRight" && key !== "Home" && key !== "End") return;
    e.preventDefault();
    const step = e.shiftKey ? 24 : 8;
    const current = getCurrentSidebarWidth();
    let next = current;
    if (key === "ArrowLeft") next = current - step;
    if (key === "ArrowRight") next = current + step;
    if (key === "Home") next = LEFT_SIDEBAR_WIDTH_MIN;
    if (key === "End") next = LEFT_SIDEBAR_WIDTH_MAX;
    next = clampInt(next, LEFT_SIDEBAR_WIDTH_MIN, LEFT_SIDEBAR_WIDTH_MAX, THEME_DEFAULT_OPTIONS.left_sidebar_width);
    applySidebarWidth(next, { syncForm: true });
    queueSidebarWidthPersist(next);
  });

  setSidebarResizerAria(getCurrentSidebarWidth());
}

function getSidebarShellEl() {
  return document.querySelector(".app") || document.querySelector(".appGrid");
}

function getSidebarCollapseStorageKey() {
  const uid = normId(state.user?.id || "anon");
  return `altara_sidebar_collapsed:${uid || "anon"}`;
}

function readSidebarCollapsedPreference() {
  try {
    return localStorage.getItem(getSidebarCollapseStorageKey()) === "1";
  } catch (_) {
    return false;
  }
}

function writeSidebarCollapsedPreference(next) {
  try {
    localStorage.setItem(getSidebarCollapseStorageKey(), next ? "1" : "0");
  } catch (_) {}
}

function isSidebarCollapsed() {
  return !!getSidebarShellEl()?.classList?.contains("left-collapsed");
}

function clearLeftSidebarOverlayCloseTimer() {
  if (!leftSidebarOverlayCloseTimer) return;
  clearTimeout(leftSidebarOverlayCloseTimer);
  leftSidebarOverlayCloseTimer = null;
}

function closeLeftSidebarOverlay() {
  const shell = getSidebarShellEl();
  if (!shell) return;
  shell.classList.remove("left-overlay-open");
}

function scheduleLeftSidebarOverlayClose(delay = 170) {
  clearLeftSidebarOverlayCloseTimer();
  leftSidebarOverlayCloseTimer = setTimeout(() => {
    leftSidebarOverlayCloseTimer = null;
    if (leftSidebarPeekHover || leftSidebarPanelHover) return;
    closeLeftSidebarOverlay();
  }, delay);
}

function refreshLeftSidebarOverlayState() {
  const shell = getSidebarShellEl();
  if (!shell) return;
  if (!shell.classList.contains("left-collapsed")) {
    clearLeftSidebarOverlayCloseTimer();
    shell.classList.remove("left-overlay-open");
    return;
  }
  if (leftSidebarPeekHover || leftSidebarPanelHover) {
    clearLeftSidebarOverlayCloseTimer();
    shell.classList.add("left-overlay-open");
    return;
  }
  scheduleLeftSidebarOverlayClose(170);
}

function getEditableTypingElementFromTarget(targetInput) {
  const el = targetInput instanceof Element ? targetInput : null;
  if (!el) return null;
  const candidate = el.closest("input, textarea, select, [contenteditable=''], [contenteditable='true'], [contenteditable='plaintext-only']");
  if (!(candidate instanceof Element)) return null;
  const ariaDisabled = String(candidate.getAttribute("aria-disabled") || "").trim().toLowerCase();
  if (ariaDisabled === "true") return null;
  if (candidate instanceof HTMLInputElement) {
    if (candidate.disabled || candidate.readOnly) return null;
    const type = String(candidate.getAttribute("type") || "text").toLowerCase();
    if (
      type === "checkbox"
      || type === "radio"
      || type === "button"
      || type === "submit"
      || type === "reset"
      || type === "range"
      || type === "file"
      || type === "color"
    ) {
      return null;
    }
    return candidate;
  }
  if (candidate instanceof HTMLTextAreaElement) {
    if (candidate.disabled || candidate.readOnly) return null;
    return candidate;
  }
  if (candidate instanceof HTMLSelectElement) {
    if (candidate.disabled) return null;
    return candidate;
  }
  if (candidate instanceof HTMLElement && candidate.isContentEditable) return candidate;
  return null;
}

function isTextInputFocused() {
  return !!getEditableTypingElementFromTarget(document.activeElement);
}

function tryHandleDmProfileAltSShortcut(e) {
  if (!e) return false;
  if (e.__altaraDmProfileAltSHandled) return true;
  if (callKeybindCaptureAction || appKeybindCaptureAction) return false;
  if (!doesKeyboardEventMatchAppKeybindAction("togglePanels", e)) return false;
  if (isTextInputFocused()) return false;

  const dmMain = document.getElementById("dmMain");
  if (!dmMain || dmMain.style.display === "none") return false;

  const convId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return false;
  const meta = getActiveConversationMeta(convId) || state.activeDm || {};
  const isServerConversation = isServerConversationKind(meta?.kind) || !!normId(meta?.serverId || "");
  if (isServerConversation) return false;

  e.preventDefault();
  e.__altaraDmProfileAltSHandled = true;
  if (dmProfilePanelOpen) {
    closeDmProfilePanel();
    return true;
  }

  const forceGroupMembers = !!(
    isGroupConversationKind(meta?.kind)
    || meta?.isGroup
  );
  void openDmProfilePanel({ force: forceGroupMembers });
  return true;
}

function clearTransientInputLockState() {
  document.body?.classList?.remove("is-resizing-sidebar");
  document.getElementById("leftSidebarResizer")?.classList?.remove("is-dragging");
  document.getElementById("rightSidebarResizer")?.classList?.remove("is-dragging");
}

function bindInputFocusRecoveryOnce() {
  if (inputFocusRecoveryBound) return;
  inputFocusRecoveryBound = true;

  // If the window loses pointer capture mid-drag, remove stale resize lock state.
  window.addEventListener("blur", clearTransientInputLockState);
  window.addEventListener("pointerup", clearTransientInputLockState, true);
  window.addEventListener("pointercancel", clearTransientInputLockState, true);
  document.addEventListener("visibilitychange", () => {
    if (document.visibilityState === "visible") return;
    clearTransientInputLockState();
  });

  // Defensive focus recovery: force focus on editable targets even if a global
  // handler prevented default somewhere else in the click chain.
  document.addEventListener("pointerdown", (ev) => {
    const editableEl = getEditableTypingElementFromTarget(eventTargetElement(ev));
    if (!editableEl) return;
    clearTransientInputLockState();
    requestAnimationFrame(() => {
      if (!editableEl.isConnected) return;
      if (document.activeElement === editableEl) return;
      try {
        editableEl.focus({ preventScroll: true });
      } catch (_) {
        try { editableEl.focus(); } catch (_) {}
      }
    });
  }, true);
}

function setSidebarCollapsed(next, { persist = true } = {}) {
  const shell = getSidebarShellEl();
  if (!shell) return;
  const collapsed = !!next;
  shell.classList.toggle("left-collapsed", collapsed);
  if (!collapsed) {
    leftSidebarPeekHover = false;
    leftSidebarPanelHover = false;
    clearLeftSidebarOverlayCloseTimer();
    shell.classList.remove("left-overlay-open");
  } else {
    refreshLeftSidebarOverlayState();
  }

  const handle = document.getElementById("leftSidebarResizer");
  if (handle) {
    handle.setAttribute("aria-hidden", collapsed ? "true" : "false");
    handle.tabIndex = collapsed ? -1 : 0;
  }
  const peek = document.getElementById("leftSidebarPeekZone");
  if (peek) peek.setAttribute("aria-hidden", collapsed ? "false" : "true");

  if (persist) writeSidebarCollapsedPreference(collapsed);
}

function bindLeftSidebarOverlayOnce() {
  if (leftSidebarOverlayBound) return;
  const shell = getSidebarShellEl();
  const sidebar = document.querySelector(".panel.left");
  const peek = document.getElementById("leftSidebarPeekZone");
  if (!shell || !sidebar || !peek) return;
  leftSidebarOverlayBound = true;

  peek.addEventListener("mouseenter", () => {
    leftSidebarPeekHover = true;
    refreshLeftSidebarOverlayState();
  });
  peek.addEventListener("mouseleave", () => {
    leftSidebarPeekHover = false;
    refreshLeftSidebarOverlayState();
  });

  sidebar.addEventListener("mouseenter", () => {
    leftSidebarPanelHover = true;
    refreshLeftSidebarOverlayState();
  });
  sidebar.addEventListener("mouseleave", () => {
    leftSidebarPanelHover = false;
    refreshLeftSidebarOverlayState();
  });

  document.addEventListener("pointerdown", (e) => {
    if (!isSidebarCollapsed()) return;
    const t = eventTargetElement(e);
    if (!t) return;
    if (t.closest(".panel.left") || t.closest("#leftSidebarPeekZone")) return;
    leftSidebarPeekHover = false;
    leftSidebarPanelHover = false;
    clearLeftSidebarOverlayCloseTimer();
    closeLeftSidebarOverlay();
  });

  document.addEventListener("keydown", (e) => {
    if (tryHandleDmProfileAltSShortcut(e)) return;
    if (callKeybindCaptureAction || appKeybindCaptureAction) return;
    if (!doesKeyboardEventMatchAppKeybindAction("togglePanels", e)) return;
    if (isTextInputFocused()) return;
    e.preventDefault();
    setSidebarCollapsed(!isSidebarCollapsed(), { persist: true });
  });

  setSidebarCollapsed(readSidebarCollapsedPreference(), { persist: false });
}

