function getCurrentRightSidebarWidth() {
  const raw = getComputedStyle(document.documentElement).getPropertyValue("--right-sidebar-width");
  const fromCss = parseInt(String(raw || "").trim(), 10);
  if (Number.isFinite(fromCss)) {
    return clampInt(fromCss, RIGHT_SIDEBAR_WIDTH_MIN, RIGHT_SIDEBAR_WIDTH_MAX, RIGHT_SIDEBAR_WIDTH_DEFAULT);
  }
  return RIGHT_SIDEBAR_WIDTH_DEFAULT;
}

