function isServerConversationUiOpen() {
  const dmMain = document.getElementById("dmMain");
  if (!dmMain || dmMain.style.display === "none") return false;
  const meta = getActiveConversationMeta(activeDmId) || state.activeDm || {};
  return isServerConversationKind(meta?.kind) || !!normId(meta?.serverId || "");
}

function syncServerVoiceStageRightSidebar({ hideMembers = false } = {}) {
  const shouldForceHide = !!(hideMembers && isServerConversationUiOpen());
  if (shouldForceHide) {
    if (!rightSidebarForceHiddenForServerVoiceStage) {
      rightSidebarRestoreCollapsedAfterServerVoiceStage = isRightSidebarCollapsed();
      rightSidebarForceHiddenForServerVoiceStage = true;
    }
    setRightSidebarToServerMembers({ active: false });
    setRightSidebarCollapsed(true, { persist: false });
    return;
  }

  if (!rightSidebarForceHiddenForServerVoiceStage) return;
  const restoreCollapsed = !!rightSidebarRestoreCollapsedAfterServerVoiceStage;
  rightSidebarForceHiddenForServerVoiceStage = false;
  rightSidebarRestoreCollapsedAfterServerVoiceStage = false;

  setRightSidebarCollapsed(restoreCollapsed, { persist: false });
  if (!restoreCollapsed && isServerConversationUiOpen()) {
    void refreshServerConversationUi({ force: false }).catch(() => {});
  }
}

function syncRightSidebarForCall(callActive) {
  // While a call is active, collapse the right sidebar (hides "Active Now").
  // Saves and restores the user's preference when the call ends.
  if (callActive) {
    if (!rightSidebarForceHiddenForCall) {
      rightSidebarRestoreCollapsedAfterCall = isRightSidebarCollapsed();
      rightSidebarForceHiddenForCall = true;
    }
    // Always ensure sidebar stays collapsed for the duration of the call,
    // even if something else (navigation, setRightSidebarInteractionMode) reopened it.
    setRightSidebarCollapsed(true, { persist: false });
    return;
  }
  if (!rightSidebarForceHiddenForCall) return;
  const restoreCollapsed = !!rightSidebarRestoreCollapsedAfterCall;
  rightSidebarForceHiddenForCall = false;
  rightSidebarRestoreCollapsedAfterCall = false;
  setRightSidebarCollapsed(restoreCollapsed, { persist: false });
}

function syncCallStageLayoutState(stageOpen = false) {
  const shell = getSidebarShellEl();
  const active = !!stageOpen;
  if (shell) {
    shell.setAttribute("data-call-stage-open", active ? "true" : "false");
  }
  document.body?.setAttribute?.("data-call-stage-open", active ? "true" : "false");
}

function syncActiveNowPanelForCall(active = false) {
  const activeNowVisible = !active;
  const activeNowEl = document.getElementById("activeNow");
  const offlineListEl = document.getElementById("offlineList");
  const onlineCountEl = document.getElementById("onlineCount");
  const labels = Array.from(document.querySelectorAll(".rightBody .rightSectionLabel"));
  const prevDisplayAttr = "data-call-stage-prev-display";
  const prevAriaAttr = "data-call-stage-prev-aria-hidden";
  const toggleHiddenState = (el, hidden, { withAria = false } = {}) => {
    if (!el) return;
    if (hidden) {
      if (!el.hasAttribute(prevDisplayAttr)) {
        el.setAttribute(prevDisplayAttr, String(el.style.display || ""));
      }
      if (withAria && !el.hasAttribute(prevAriaAttr)) {
        el.setAttribute(
          prevAriaAttr,
          el.hasAttribute("aria-hidden") ? String(el.getAttribute("aria-hidden") || "") : "__missing__"
        );
      }
      el.style.display = "none";
      if (withAria) el.setAttribute("aria-hidden", "true");
      return;
    }
    if (el.hasAttribute(prevDisplayAttr)) {
      const prevDisplay = String(el.getAttribute(prevDisplayAttr) || "");
      el.style.display = prevDisplay;
      el.removeAttribute(prevDisplayAttr);
    } else {
      el.style.display = "";
    }
    if (!withAria) return;
    if (el.hasAttribute(prevAriaAttr)) {
      const prevAria = String(el.getAttribute(prevAriaAttr) || "__missing__");
      if (prevAria === "__missing__") el.removeAttribute("aria-hidden");
      else el.setAttribute("aria-hidden", prevAria);
      el.removeAttribute(prevAriaAttr);
      return;
    }
    el.removeAttribute("aria-hidden");
  };

  if (activeNowEl && !activeNowVisible) activeNowEl.innerHTML = "";
  toggleHiddenState(activeNowEl, !activeNowVisible, { withAria: true });

  if (offlineListEl && !activeNowVisible) offlineListEl.innerHTML = "";
  toggleHiddenState(offlineListEl, !activeNowVisible, { withAria: true });

  if (onlineCountEl) {
    if (!activeNowVisible) onlineCountEl.textContent = "0";
    toggleHiddenState(onlineCountEl, !activeNowVisible);
  }
  labels.forEach((el) => {
    toggleHiddenState(el, !activeNowVisible);
  });
}

function setRightSidebarInteractionModeForConversation({
  serverMode = false,
  forceHidden = false,
  applyCollapsed = true,
} = {}) {
  const shell = getSidebarShellEl();
  if (!shell) return;
  const shouldDisablePeek = !!(serverMode || forceHidden);
  shell.classList.toggle("right-no-peek", shouldDisablePeek);

  if (!applyCollapsed) {
    refreshRightSidebarOverlayState();
    return;
  }

  if (forceHidden) {
    setRightSidebarToServerMembers({ active: false });
    setRightSidebarCollapsed(true, { persist: false });
    return;
  }

  // Don't reopen the sidebar if a call is currently hiding it.
  if (rightSidebarForceHiddenForCall) {
    setRightSidebarCollapsed(true, { persist: false });
    return;
  }

  if (serverMode && rightSidebarForceHiddenForServerVoiceStage) {
    setRightSidebarCollapsed(true, { persist: false });
    return;
  }

  if (serverMode) {
    setRightSidebarCollapsed(!!rightSidebarCollapsedServerMode, { persist: false });
  } else {
    setRightSidebarCollapsed(readRightSidebarCollapsedPreference(), { persist: false });
  }
}

function clearRightSidebarOverlayCloseTimer() {
  if (!rightSidebarOverlayCloseTimer) return;
  clearTimeout(rightSidebarOverlayCloseTimer);
  rightSidebarOverlayCloseTimer = null;
}

function closeRightSidebarOverlay() {
  const shell = getSidebarShellEl();
  if (!shell) return;
  shell.classList.remove("right-overlay-open");
}

function scheduleRightSidebarOverlayClose(delay = 170) {
  clearRightSidebarOverlayCloseTimer();
  rightSidebarOverlayCloseTimer = setTimeout(() => {
    rightSidebarOverlayCloseTimer = null;
    if (rightSidebarPeekHover || rightSidebarPanelHover) return;
    closeRightSidebarOverlay();
  }, delay);
}

function refreshRightSidebarOverlayState() {
  const shell = getSidebarShellEl();
  if (!shell) return;
  if (shell.classList.contains("right-no-peek")) {
    clearRightSidebarOverlayCloseTimer();
    shell.classList.remove("right-overlay-open");
    return;
  }
  if (!shell.classList.contains("right-collapsed")) {
    clearRightSidebarOverlayCloseTimer();
    shell.classList.remove("right-overlay-open");
    return;
  }
  if (rightSidebarPeekHover || rightSidebarPanelHover) {
    clearRightSidebarOverlayCloseTimer();
    shell.classList.add("right-overlay-open");
    return;
  }
  scheduleRightSidebarOverlayClose(170);
}

function setRightSidebarCollapsed(next, { persist = true } = {}) {
  const shell = getSidebarShellEl();
  if (!shell) return;
  const collapsed = !!next;
  shell.classList.toggle("right-collapsed", collapsed);
  if (!collapsed) {
    rightSidebarPeekHover = false;
    rightSidebarPanelHover = false;
    clearRightSidebarOverlayCloseTimer();
    shell.classList.remove("right-overlay-open");
  } else {
    refreshRightSidebarOverlayState();
  }

  const handle = document.getElementById("rightSidebarResizer");
  if (handle) {
    handle.setAttribute("aria-hidden", collapsed ? "true" : "false");
    handle.tabIndex = collapsed ? -1 : 0;
  }
  const peek = document.getElementById("rightSidebarPeekZone");
  if (peek) peek.setAttribute("aria-hidden", collapsed ? "false" : "true");

  if (persist) writeRightSidebarCollapsedPreference(collapsed);

  try {
    window.dispatchEvent(new Event("resize"));
  } catch (_) {}
  if ((document.querySelector("[data-tab].active")?.getAttribute("data-tab") || "") === "widgets") {
    requestAnimationFrame(() => {
      try { renderWidgets(); } catch (_) {}
    });
  }
  try { syncDmPinsPanelState(); } catch (_) {}
}

function bindRightSidebarOverlayOnce() {
  if (rightSidebarOverlayBound) return;
  const shell = getSidebarShellEl();
  const sidebar = document.querySelector(".panel.right");
  const peek = document.getElementById("rightSidebarPeekZone");
  if (!shell || !sidebar || !peek) return;
  rightSidebarOverlayBound = true;

  peek.addEventListener("mouseenter", () => {
    rightSidebarPeekHover = true;
    refreshRightSidebarOverlayState();
  });
  peek.addEventListener("mouseleave", () => {
    rightSidebarPeekHover = false;
    refreshRightSidebarOverlayState();
  });

  sidebar.addEventListener("mouseenter", () => {
    rightSidebarPanelHover = true;
    refreshRightSidebarOverlayState();
  });
  sidebar.addEventListener("mouseleave", () => {
    rightSidebarPanelHover = false;
    refreshRightSidebarOverlayState();
  });

  document.addEventListener("pointerdown", (e) => {
    if (!isRightSidebarCollapsed()) return;
    const t = eventTargetElement(e);
    if (!t) return;
    if (t.closest(".panel.right") || t.closest("#rightSidebarPeekZone")) return;
    rightSidebarPeekHover = false;
    rightSidebarPanelHover = false;
    clearRightSidebarOverlayCloseTimer();
    closeRightSidebarOverlay();
  });

  setRightSidebarCollapsed(readRightSidebarCollapsedPreference(), { persist: false });
}

function resetThemeFormToDefault() {
  resetAppearanceSettings();
}

applyAppearanceSettings(loadAppearanceSettings());
bindThemeSystemModeSyncOnce();

