function hydrateCallPeerMeta() {
  if (!callOtherUserId) return;
  const f = (state.friends || []).find((x) => x.other_user_id === callOtherUserId);
  if (!f) return;
  if ((!callOtherLabel || callOtherLabel === t("call.friend", "friend")) && (f.display_name || f.username)) {
    callOtherLabel = f.display_name || f.username || callOtherLabel;
  }
  if (!callOtherAvatar && f.avatar_url) {
    callOtherAvatar = f.avatar_url;
  }
}

function escapeCssUrl(url) {
  return String(url || "").replace(/["\\\n\r]/g, "\\$&");
}

function resolveUserAvatarCrop(userId = "", fallbackProfile = null) {
  const uid = normId(userId || "");
  const meId = normId(state.user?.id || "");
  if (uid && meId && uid === meId) {
    return getThemeMediaCrop(state.me?.theme_settings || {}, "avatar");
  }
  if (fallbackProfile?.theme_settings) {
    return getThemeMediaCrop(fallbackProfile.theme_settings, "avatar");
  }
  const cached = uid ? getCachedProfile(uid) || null : null;
  return getThemeMediaCrop(cached?.theme_settings || {}, "avatar");
}

function buildMediaCropInlineStyle(cropLike = null, kind = "banner") {
  const crop = normalizeMediaCropSnapshot(cropLike, kind);
  if (!crop) return "";
  const x = Math.round(crop.x * 1000) / 10;
  const y = Math.round(crop.y * 1000) / 10;
  return [
    "width:100%",
    "height:100%",
    "object-fit:cover",
    `object-position:${x}% ${y}%`,
    `transform-origin:${x}% ${y}%`,
    `transform:scale(${crop.scale})`,
  ].join(";");
}

function buildAvatarMediaHtml(url, {
  userId = "",
  profile = null,
  crop = null,
  alt = "avatar",
  loading = "",
  controlledGif = true,
  fallbackChar = "",
} = {}) {
  const safeUrl = String(url || "").trim();
  if (!safeUrl) return "";
  const resolvedCrop = normalizeMediaCropSnapshot(
    crop || resolveUserAvatarCrop(userId, profile),
    "avatar"
  );
  const style = buildMediaCropInlineStyle(resolvedCrop, "avatar");
  const styleAttr = style ? ` style="${escAttr(style)}"` : "";
  const loadingAttr = loading ? ` loading="${escAttr(loading)}"` : "";
  const shouldManageGif = controlledGif !== false && isGifLikeUrl(safeUrl);
  const rootAttrs = shouldManageGif
    ? ` data-managed-gif-root="avatar" data-gif-url="${escAttr(safeUrl)}"`
    : "";
  const mediaAttrs = shouldManageGif ? ' data-managed-gif-media="1"' : "";
  const managedGifAttrs = shouldManageGif ? buildManagedGifMediaHtmlAttrs() : "";
  const fallbackInitial = resolveAvatarFallbackInitial(userId, fallbackChar, alt);
  const onErrorAttr = ' onerror="window.__altaraHandleAvatarImageError && window.__altaraHandleAvatarImageError(this)"';
  const onLoadAttr = ' onload="window.__altaraHandleAvatarImageLoad && window.__altaraHandleAvatarImageLoad(this)"';
  return `<span class="profileAvatarMediaClip" data-avatar-fallback="${escAttr(fallbackInitial)}"${rootAttrs}><img class="profileAvatarMedia" src="${esc(safeUrl)}" data-avatar-src="${escAttr(safeUrl)}" alt="${escAttr(alt)}"${loadingAttr}${styleAttr}${mediaAttrs}${managedGifAttrs}${onErrorAttr}${onLoadAttr} /></span>`;
}

function buildAvatarRetryUrl(url = "", attempt = 1) {
  const raw = String(url || "").trim();
  if (!raw || raw.startsWith("data:image/") || raw.startsWith("blob:")) return raw;
  try {
    const u = new URL(raw, window.location.href);
    u.searchParams.set("_altara_avatar_retry", String(attempt));
    return u.href;
  } catch (_) {
    const joiner = raw.includes("?") ? "&" : "?";
    return `${raw}${joiner}_altara_avatar_retry=${encodeURIComponent(String(attempt))}`;
  }
}

function handleAvatarImageError(imageEl) {
  if (!(imageEl instanceof HTMLImageElement)) return;
  const originalUrl = String(imageEl.dataset.avatarSrc || imageEl.getAttribute("src") || "").trim();
  const attempts = Number.parseInt(String(imageEl.dataset.avatarRetry || "0"), 10) || 0;
  if (originalUrl && attempts < 2 && !originalUrl.startsWith("data:image/") && !originalUrl.startsWith("blob:")) {
    const nextAttempt = attempts + 1;
    imageEl.dataset.avatarRetry = String(nextAttempt);
    setTimeout(() => {
      if (!(imageEl instanceof HTMLImageElement) || !imageEl.isConnected) return;
      imageEl.src = buildAvatarRetryUrl(originalUrl, nextAttempt);
    }, nextAttempt * 250);
    return;
  }
  const clip = imageEl.closest(".profileAvatarMediaClip");
  if (clip) clip.classList.add("is-error");
  imageEl.style.display = "none";
}

function handleAvatarImageLoad(imageEl) {
  if (!(imageEl instanceof HTMLImageElement)) return;
  imageEl.dataset.avatarRetry = "0";
  const clip = imageEl.closest(".profileAvatarMediaClip");
  if (clip) clip.classList.remove("is-error");
  imageEl.style.removeProperty("display");
}

if (typeof window !== "undefined") {
  window.__altaraBuildAvatarMediaHtml = buildAvatarMediaHtml;
  window.__altaraQueueManagedGifPlaybackSync = queueManagedGifPlaybackSync;
  window.__altaraHandleAvatarImageError = handleAvatarImageError;
  window.__altaraHandleAvatarImageLoad = handleAvatarImageLoad;
}

function applyBannerStyle(el, bannerUrl = "", fallbackStart = "", fallbackEnd = "", fallbackGlow = "", options = null) {
  if (!el) return;
  const url = normalizeBannerUrl(bannerUrl);
  let mediaEl = el.querySelector(".profileBannerMedia");
  const previousManagedGifUrl = String(el.getAttribute("data-gif-url") || "").trim();
  if (url) {
    const shouldManageGif = isGifLikeUrl(url);
    const crop = options?.disableCrop
      ? null
      : normalizeMediaCropSnapshot(
        options?.crop || resolveUserBannerCrop(options?.userId || "", options?.profile || null),
        "banner"
      );
    if (!mediaEl) {
      mediaEl = document.createElement("img");
      mediaEl.className = "profileBannerMedia";
      mediaEl.alt = "";
      mediaEl.loading = "lazy";
      mediaEl.decoding = "async";
      el.prepend(mediaEl);
    }
    if (shouldManageGif) {
      if (previousManagedGifUrl && previousManagedGifUrl !== url) {
        mediaEl.removeAttribute("data-gif-live-src");
      }
      el.setAttribute("data-managed-gif-root", "banner");
      el.setAttribute("data-gif-url", url);
      mediaEl.setAttribute("data-managed-gif-media", "1");
      mediaEl.crossOrigin = "anonymous";
      mediaEl.referrerPolicy = "no-referrer";
    } else {
      el.removeAttribute("data-managed-gif-root");
      el.removeAttribute("data-gif-url");
      mediaEl.removeAttribute("data-managed-gif-media");
      mediaEl.removeAttribute("data-gif-live-src");
      mediaEl.removeAttribute("crossorigin");
      mediaEl.removeAttribute("referrerpolicy");
    }
    mediaEl.src = url;
    const mediaStyle = buildMediaCropInlineStyle(crop);
    if (mediaStyle) mediaEl.style.cssText = mediaStyle;
    else mediaEl.removeAttribute("style");
    el.classList.add("has-banner-media");
    const requestedOverlay = String(options?.overlay || "").trim();
    const overlay = requestedOverlay || "linear-gradient(180deg, rgba(7, 10, 18, 0.24), rgba(7, 10, 18, 0.62))";
    const disableOverlay = overlay.toLowerCase() === "none";
    el.style.backgroundImage = disableOverlay
      ? "none"
      : overlay;
    if (disableOverlay) {
      el.style.removeProperty("background-size");
      el.style.removeProperty("background-position");
    } else {
      el.style.backgroundSize = "cover";
      el.style.backgroundPosition = "center";
    }
    if (fallbackStart) el.style.setProperty("--dm-profile-banner-start", fallbackStart);
    if (fallbackEnd) el.style.setProperty("--dm-profile-banner-end", fallbackEnd);
    if (fallbackGlow) el.style.setProperty("--dm-profile-banner-glow", fallbackGlow);
    queueManagedGifPlaybackSync(el);
    return;
  }

  if (mediaEl?.remove) mediaEl.remove();
  el.classList.remove("has-banner-media");
  el.removeAttribute("data-managed-gif-root");
  el.removeAttribute("data-gif-url");
  el.style.removeProperty("background-image");
  el.style.removeProperty("background-size");
  el.style.removeProperty("background-position");
  if (fallbackStart || fallbackEnd || fallbackGlow) {
    if (fallbackStart) el.style.setProperty("--dm-profile-banner-start", fallbackStart);
    else el.style.removeProperty("--dm-profile-banner-start");
    if (fallbackEnd) el.style.setProperty("--dm-profile-banner-end", fallbackEnd);
    else el.style.removeProperty("--dm-profile-banner-end");
    if (fallbackGlow) el.style.setProperty("--dm-profile-banner-glow", fallbackGlow);
    else el.style.removeProperty("--dm-profile-banner-glow");
  }
}

