function normalizeOwnerAllowlistValue(value, { lower = false } = {}) {
  const raw = String(value || "").trim();
  if (!raw) return "";
  if (/^replace-with-owner-/i.test(raw)) return "";
  return lower ? raw.toLowerCase() : raw;
}

function getConfiguredGlobalReportsOwnerUserIds() {
  return GLOBAL_REPORTS_OWNER_USER_IDS
    .map((value) => normalizeOwnerAllowlistValue(value))
    .filter(Boolean);
}

function getConfiguredGlobalReportsOwnerEmails() {
  return GLOBAL_REPORTS_OWNER_EMAILS
    .map((value) => normalizeOwnerAllowlistValue(value, { lower: true }))
    .filter(Boolean);
}

function getCurrentUserEmail(userInput = state.user) {
  const candidates = [
    userInput?.email,
    userInput?.user_metadata?.email,
    userInput?.profile?.email,
    state.user?.email,
    state.user?.user_metadata?.email,
    state.me?.email,
  ];
  return String(candidates.find((value) => String(value || "").trim()) || "").trim().toLowerCase();
}

function getCurrentUserOwnerId(userInput = state.user) {
  const candidates = [
    userInput?.id,
    userInput?.user_id,
    userInput?.userId,
    userInput?.profile?.id,
    state.user?.id,
    state.me?.id,
  ];
  return normId(candidates.find((value) => normId(value || "")) || "");
}

function isCurrentUserOwner(userInput = state.user) {
  const userId = getCurrentUserOwnerId(userInput);
  const email = getCurrentUserEmail(userInput);
  const ownerUserIds = getConfiguredGlobalReportsOwnerUserIds();
  const ownerEmails = getConfiguredGlobalReportsOwnerEmails();
  if (userId && ownerUserIds.includes(userId)) return true;
  if (email && ownerEmails.includes(email)) return true;
  return false;
}

function syncOwnerReportsSettingsAccessUi() {
  const canAccess = isCurrentUserOwner();
  const navButton = document.getElementById("settingsNavReportsButton");
  if (navButton) navButton.hidden = !canAccess;
  const panel = document.querySelector('#profileOverlay [data-settings-panel="reports"]');
  if (panel) panel.hidden = !canAccess;
}

function getUserMetadataObject(userInput = state.user) {
  const meta = userInput?.user_metadata;
  if (!meta || typeof meta !== "object" || Array.isArray(meta)) return {};
  return { ...meta };
}

function normalizeSecurityCodeHash(value) {
  const hash = String(value || "").trim().toLowerCase();
  return /^[a-f0-9]{64}$/.test(hash) ? hash : "";
}

function readSecurityCodeHashFromUser(userInput = state.user) {
  const meta = getUserMetadataObject(userInput);
  return normalizeSecurityCodeHash(meta[SETTINGS_SECURITY_CODE_META_KEY]);
}

function readSecuritySetupDismissedFromUser(userInput = state.user) {
  const meta = getUserMetadataObject(userInput);
  const value = meta[SETTINGS_SECURITY_SETUP_DISMISSED_META_KEY];
  if (value === true || value === 1) return true;
  if (typeof value === "string") {
    const raw = value.trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "yes";
  }
  return false;
}

function normalizeSecurityCodeInput(value) {
  return String(value || "")
    .replace(/\D+/g, "")
    .slice(0, SETTINGS_SECURITY_CODE_MAX_DIGITS);
}

function parseSecurityReauthInput(value) {
  const raw = String(value || "").trim();
  let nonce = "";
  let tokenHash = "";
  if (!raw) return { raw, nonce, tokenHash };

  const assignFromSearchParams = (searchParams) => {
    if (!searchParams || typeof searchParams.get !== "function") return;
    if (!nonce) {
      nonce = String(
        searchParams.get("token")
        || searchParams.get("code")
        || searchParams.get("otp")
        || ""
      ).trim();
    }
    if (!tokenHash) {
      tokenHash = String(searchParams.get("token_hash") || "").trim();
    }
  };

  try {
    const parsed = new URL(raw);
    assignFromSearchParams(parsed.searchParams);
  } catch (_) {}

  if (!nonce || !tokenHash) {
    const readParam = (name) => {
      const match = raw.match(new RegExp(`[?&#]${name}=([^&#\\s]+)`, "i"));
      if (!match?.[1]) return "";
      try {
        return decodeURIComponent(match[1]).trim();
      } catch (_) {
        return String(match[1]).trim();
      }
    };
    if (!nonce) {
      nonce = readParam("token") || readParam("code") || readParam("otp") || "";
    }
    if (!tokenHash) {
      tokenHash = readParam("token_hash");
    }
  }

  if (!nonce && !tokenHash) {
    nonce = raw.replace(/\s+/g, "");
  }
  return { raw, nonce, tokenHash };
}

function isValidSecurityCode(codeInput) {
  const code = normalizeSecurityCodeInput(codeInput);
  return code.length >= SETTINGS_SECURITY_CODE_MIN_DIGITS && code.length <= SETTINGS_SECURITY_CODE_MAX_DIGITS;
}

async function computeSecurityCodeHash(codeInput) {
  const code = String(codeInput || "");
  if (!code) return "";
  const subtle = window?.crypto?.subtle;
  if (!subtle || typeof TextEncoder === "undefined") {
    throw new Error("security_code_crypto_unavailable");
  }
  const payload = new TextEncoder().encode(code);
  const digest = await subtle.digest("SHA-256", payload);
  return Array.from(new Uint8Array(digest))
    .map((value) => value.toString(16).padStart(2, "0"))
    .join("");
}

function clearSecurityCodeInputs() {
  const securityCodeInput = document.getElementById("securityCode");
  if (securityCodeInput) securityCodeInput.value = "";
  const securityCodeConfirmInput = document.getElementById("securityCodeConfirm");
  if (securityCodeConfirmInput) securityCodeConfirmInput.value = "";
  const unlockCodeInput = document.getElementById("securityUnlockCode");
  if (unlockCodeInput) unlockCodeInput.value = "";
  const removeCodeInput = document.getElementById("securityRemoveEmailCode");
  if (removeCodeInput) removeCodeInput.value = "";
  const forgotCodeInput = document.getElementById("securityForgotEmailCode");
  if (forgotCodeInput) forgotCodeInput.value = "";
}

function isNodeVisible(node) {
  if (!(node instanceof HTMLElement)) return false;
  if (node.hidden) return false;
  const style = window.getComputedStyle ? window.getComputedStyle(node) : null;
  if (style && (style.display === "none" || style.visibility === "hidden")) return false;
  const rects = typeof node.getClientRects === "function" ? node.getClientRects() : null;
  return !!(node.offsetWidth || node.offsetHeight || (rects && rects.length));
}

function isSecurityTabVisible() {
  const overlay = document.getElementById("profileOverlay");
  if (!(overlay instanceof HTMLElement)) return false;
  if (overlay.classList.contains("hidden")) return false;
  const panel = overlay.querySelector('[data-settings-panel="security"]');
  return panel instanceof HTMLElement && panel.classList.contains("is-active");
}

function isAppConfirmVisible() {
  const modal = document.getElementById("appConfirmModal");
  if (!(modal instanceof HTMLElement)) return false;
  return !modal.classList.contains("hidden") && modal.getAttribute("aria-hidden") !== "true";
}

function getPreferredSecurityTypingInput() {
  if (!isSecurityTabVisible()) return null;
  const setupScreen = document.getElementById("settingsSecuritySetupScreen");
  if (isNodeVisible(setupScreen)) return null;

  const lockedScreen = document.getElementById("settingsSecurityLockedScreen");
  if (isNodeVisible(lockedScreen)) {
    const forgotVerifyWrap = document.getElementById("settingsSecurityLockedResetWrap");
    if (isNodeVisible(forgotVerifyWrap)) {
      const forgotInput = document.getElementById("securityForgotEmailCode");
      if (forgotInput instanceof HTMLInputElement && !forgotInput.disabled && !forgotInput.readOnly && isNodeVisible(forgotInput)) {
        return forgotInput;
      }
    }
    const unlockInput = document.getElementById("securityUnlockCode");
    if (unlockInput instanceof HTMLInputElement && !unlockInput.disabled && !unlockInput.readOnly && isNodeVisible(unlockInput)) {
      return unlockInput;
    }
  }

  const removeVerifyWrap = document.getElementById("settingsSecurityRemoveVerifyWrap");
  if (isNodeVisible(removeVerifyWrap)) {
    const verifyInput = document.getElementById("securityRemoveEmailCode");
    if (verifyInput instanceof HTMLInputElement && !verifyInput.disabled && !verifyInput.readOnly && isNodeVisible(verifyInput)) {
      return verifyInput;
    }
  }

  const codeInput = document.getElementById("securityCode");
  if (codeInput instanceof HTMLInputElement && !codeInput.disabled && !codeInput.readOnly && isNodeVisible(codeInput)) {
    return codeInput;
  }

  const emailInput = document.getElementById("newEmail");
  if (emailInput instanceof HTMLInputElement && !emailInput.disabled && !emailInput.readOnly && isNodeVisible(emailInput)) {
    return emailInput;
  }

  const currentPassInput = document.getElementById("currentPass");
  if (currentPassInput instanceof HTMLInputElement && !currentPassInput.disabled && !currentPassInput.readOnly && isNodeVisible(currentPassInput)) {
    return currentPassInput;
  }

  const passInput = document.getElementById("newPass");
  if (passInput instanceof HTMLInputElement && !passInput.disabled && !passInput.readOnly && isNodeVisible(passInput)) {
    return passInput;
  }

  return null;
}

function ensureSecurityInputsInteractive() {
  [
    "securityUnlockCode",
    "securityCode",
    "securityCodeConfirm",
    "securityRemoveEmailCode",
    "securityForgotEmailCode",
    "newEmail",
    "currentPass",
    "newPass",
  ].forEach((id) => {
    const input = document.getElementById(id);
    if (!(input instanceof HTMLInputElement)) return;
    if (input.id === "currentEmail") return;
    input.disabled = false;
    if (input.id !== "currentEmail") input.readOnly = false;
    input.removeAttribute("inert");
    input.style.pointerEvents = "auto";
  });
}

function focusSecurityInput(inputEl) {
  if (!(inputEl instanceof HTMLElement)) return;
  try {
    inputEl.focus({ preventScroll: true });
  } catch (_) {
    try { inputEl.focus(); } catch (_) {}
  }
}

function bindSecurityInputRecoveryOnce() {
  if (settingsSecurityInputRecoveryBound) return;
  settingsSecurityInputRecoveryBound = true;

  document.addEventListener("pointerdown", (ev) => {
    if (!isSecurityTabVisible() || isAppConfirmVisible()) return;
    const target = eventTargetElement(ev);
    if (!(target instanceof HTMLElement)) return;
    if (!target.closest('[data-settings-panel="security"]')) return;

    const input = target.closest("input");
    requestAnimationFrame(() => {
      ensureSecurityInputsInteractive();
      if (input instanceof HTMLInputElement) {
        focusSecurityInput(input);
        return;
      }
      if (target.closest("button,a,label,[role='button']")) return;
      const preferred = getPreferredSecurityTypingInput();
      if (preferred) focusSecurityInput(preferred);
    });
  }, true);

  document.addEventListener("keydown", (e) => {
    if (e.defaultPrevented || e.isComposing || e.ctrlKey || e.metaKey || e.altKey) return;
    if (e.key.length !== 1) return;
    if (!isSecurityTabVisible() || isAppConfirmVisible()) return;
    const active = document.activeElement;
    if (getEditableTypingElementFromTarget(active)) return;

    const preferred = getPreferredSecurityTypingInput();
    if (!(preferred instanceof HTMLInputElement)) return;

    ensureSecurityInputsInteractive();
    focusSecurityInput(preferred);
    if (preferred.disabled || preferred.readOnly) return;
    const currentValue = String(preferred.value || "");
    const selStart = Number.isFinite(preferred.selectionStart) ? preferred.selectionStart : currentValue.length;
    const selEnd = Number.isFinite(preferred.selectionEnd) ? preferred.selectionEnd : currentValue.length;
    const nextValue = `${currentValue.slice(0, selStart)}${e.key}${currentValue.slice(selEnd)}`;
    preferred.value = nextValue;
    const cursor = selStart + e.key.length;
    try { preferred.setSelectionRange(cursor, cursor); } catch (_) {}
    preferred.dispatchEvent(new Event("input", { bubbles: true }));
    e.preventDefault();
  }, true);
}

async function persistSecuritySetupDismissedPreference(nextDismissed) {
  if (!state.user) return;
  const currentMeta = getUserMetadataObject(state.user);
  const currentValue = readSecuritySetupDismissedFromUser(state.user);
  const wanted = !!nextDismissed;
  if (currentValue === wanted) return;

  const nextMeta = {
    ...currentMeta,
    [SETTINGS_SECURITY_SETUP_DISMISSED_META_KEY]: wanted ? true : null,
  };
  const { data, error } = await updateUserWithSessionRetry({ data: nextMeta });
  setProfileDebug({ security_setup_dismissed: { wanted, error } });
  if (error) throw error;

  if (data?.user) {
    state.user = data.user;
  } else {
    state.user = state.user || {};
    state.user.user_metadata = nextMeta;
  }
}

async function dismissSecuritySetupPrompt({ focusCodeInput = false } = {}) {
  settingsSecuritySetupDismissed = true;
  renderSecurityAccessUi();
  try {
    await persistSecuritySetupDismissedPreference(true);
  } catch (error) {
    console.warn("persist security setup dismissal failed", error);
  }
  if (!focusCodeInput) return;
  requestAnimationFrame(() => {
    const input = document.getElementById("securityCode");
    if (!(input instanceof HTMLInputElement)) return;
    try {
      input.focus({ preventScroll: true });
    } catch (_) {
      try { input.focus(); } catch (_) {}
    }
  });
}

function syncSecurityCodeStateFromUser(userInput = state.user, { preserveUnlock = false } = {}) {
  const nextHash = readSecurityCodeHashFromUser(userInput);
  const nextDismissed = readSecuritySetupDismissedFromUser(userInput);
  const changed = nextHash !== settingsSecurityCodeHash;
  settingsSecurityCodeHash = nextHash;
  settingsSecuritySetupDismissed = !!nextDismissed;
  if (!settingsSecurityCodeHash) {
    settingsSecurityUnlocked = true;
    settingsSecurityRemoveVerificationPending = false;
    return;
  }
  if (!preserveUnlock || changed) settingsSecurityUnlocked = false;
}

function getDmE2eeBackupStatusText() {
  if (!DM_PRIVATE_RUNTIME_ENABLED) {
    return DM_PRIVATE_RUNTIME_DISABLED_STATUS_TEXT;
  }
  const info = settingsDmE2eeBackupState || {};
  const hasPortableBackup =
    !!info.hasBackup && info.backupPasswordSource === DM_E2EE_BACKUP_PASSWORD_SOURCE_ACCOUNT_LOGIN;
  const hasLegacyBackup = !!info.hasBackup && !hasPortableBackup;
  if (settingsDmE2eeBackupLoading && !info.loaded) {
    return t("settings.security.dm_backup.status.loading", "Loading encrypted DM backup status...");
  }
  if (info.error) {
    if (isMissingTableError(info.error, "dm_e2ee_user_key_backups")) {
      return t("settings.security.dm_backup.status.sql_missing", "Encrypted DM backup SQL is missing. Apply the Phase 4 patch and reload.");
    }
    return String(info.error?.message || info.error || t("error.generic", "Unexpected error."));
  }
  if ((info.identityStatus === "missing_local_private" || info.identityStatus === "not_initialized") && hasLegacyBackup) {
    return t(
      "settings.security.dm_backup.status.needs_portable_refresh",
      "An encrypted Private DM backup exists, but it was not last refreshed with your account password. Sign in on a device that still has the Private DM key to refresh the portable backup."
    );
  }
  if ((info.identityStatus === "missing_local_private" || info.identityStatus === "not_initialized") && hasPortableBackup) {
    return t(
      "settings.security.dm_backup.status.restore_needed",
      "This device is missing the local Private DM key. Sign out and sign in again with your account password so ALTARA can auto-restore it."
    );
  }
  if (info.identityStatus === "missing_local_private") {
    return t(
      "settings.security.dm_backup.status.missing_no_backup",
      "This device is missing the local Private DM key and no portable encrypted backup was found for this account."
    );
  }
  if (info.identityStatus === "ready" && !info.exportable) {
    return t(
      "settings.security.dm_backup.status.legacy",
      "This account still uses an older Private DM key that cannot be exported for portable encrypted backup. If another device already has a compatible backup, sign in there again to refresh it."
    );
  }
  if (hasPortableBackup && info.backupUpdatedAt) {
    return tf(
      "settings.security.dm_backup.status.saved",
      { date: getMessageStamp(info.backupUpdatedAt) },
      "Portable Private DM backup available. Last refreshed on {date}."
    );
  }
  if (hasLegacyBackup) {
    return t(
      "settings.security.dm_backup.status.needs_portable_refresh",
      "An encrypted Private DM backup exists, but it was not last refreshed with your account password. Sign in on a device that still has the Private DM key to refresh the portable backup."
    );
  }
  if (info.identityStatus === "ready" && info.exportable) {
    return t(
      "settings.security.dm_backup.status.auto_backup_next_login",
      "This device has the Private DM key, but no portable encrypted backup is saved yet. Sign out and sign in again with your account password to save it for your other devices."
    );
  }
  if (info.identityStatus === "not_initialized") {
    return t(
      "settings.security.dm_backup.status.not_initialized",
      "This account has not created its Private DM identity yet. ALTARA will create and encrypt it automatically the next time you sign in with your account password."
    );
  }
  return t("settings.security.dm_backup.status.none", "No encrypted Private DM backup saved for this account yet.");
}

function clearDmE2eeBackupInputs({ clearRestore = true } = {}) {
  const savePassword = document.getElementById("settingsDmE2eeBackupPassword");
  if (savePassword instanceof HTMLInputElement) savePassword.value = "";
  const saveConfirm = document.getElementById("settingsDmE2eeBackupPasswordConfirm");
  if (saveConfirm instanceof HTMLInputElement) saveConfirm.value = "";
  if (clearRestore) {
    const restorePassword = document.getElementById("settingsDmE2eeBackupRestorePassword");
    if (restorePassword instanceof HTMLInputElement) restorePassword.value = "";
  }
}

function renderDmE2eeBackupSettingsUi() {
  const card = document.getElementById("settingsDmE2eeBackupCard");
  if (!DM_PRIVATE_RUNTIME_ENABLED) {
    if (card) card.hidden = true;
    return;
  }
  if (card) card.hidden = false;
  const sectionTitle = document.getElementById("settingsSectionDmE2eeBackup");
  if (sectionTitle) sectionTitle.textContent = t("settings.security.dm_backup.section", "Encrypted DM backup");

  const hint = document.getElementById("settingsDmE2eeBackupHint");
  if (hint) {
    hint.textContent = t(
      "settings.security.dm_backup.hint",
      "Private DM uses one encrypted identity per account. ALTARA uses your account password during sign-in to create, protect, or restore that portable key on each device. The password is only used locally and is not kept after sync."
    );
  }

  const status = document.getElementById("settingsDmE2eeBackupStatus");
  if (status) status.textContent = getDmE2eeBackupStatusText();

  const autoHint = document.getElementById("settingsDmE2eeBackupAutoHint");
  if (autoHint) {
    autoHint.textContent = t(
      "settings.security.dm_backup.auto_hint",
      "Automatic Private DM restore runs during password sign-in."
    );
  }
  const limitations = document.getElementById("settingsDmE2eeBackupLimitations");
  if (limitations) {
    limitations.textContent = t(
      "settings.security.dm_backup.limitations",
      "If you change your account password, sign out and sign back in on a device that still has your Private DM key so ALTARA can refresh the portable backup."
    );
  }

  const refreshBtn = document.getElementById("btnSettingsDmE2eeBackupRefresh");
  if (refreshBtn) {
    refreshBtn.textContent = t("settings.security.dm_backup.refresh_btn", "Refresh Private DM status");
    refreshBtn.disabled = !!settingsDmE2eeBackupLoading;
  }
}

async function refreshDmE2eeBackupSettingsState({ force = false } = {}) {
  if (!DM_PRIVATE_RUNTIME_ENABLED) {
    settingsDmE2eeBackupLoading = false;
    settingsDmE2eeBackupState = {
      loaded: true,
      identityStatus: "runtime_disabled",
      exportable: false,
      hasBackup: false,
      backupUpdatedAt: "",
      backupPasswordSource: "",
      error: null,
    };
    renderDmE2eeBackupSettingsUi();
    return settingsDmE2eeBackupState;
  }
  if (!state.user?.id) return settingsDmE2eeBackupState;
  if (settingsDmE2eeBackupLoading && !force) return settingsDmE2eeBackupState;

  settingsDmE2eeBackupLoading = true;
  renderDmE2eeBackupSettingsUi();
  try {
    const [identityState, backupMeta] = await Promise.all([
      getDmE2eeIdentityState({ userId: state.user.id, force }),
      getDmE2eeKeyBackupMetadata({ userId: state.user.id, force }),
    ]);
    settingsDmE2eeBackupState = {
      loaded: true,
      identityStatus: String(identityState?.status || "error"),
      exportable: !!identityState?.localPrivateKeyExportable,
      hasBackup: !!backupMeta,
      backupUpdatedAt: String(backupMeta?.updatedAt || backupMeta?.createdAt || ""),
      backupPasswordSource: getDmE2eeBackupPasswordSource(backupMeta),
      error: identityState?.status === "error" ? (identityState.error || new Error("DM E2EE state unavailable")) : null,
    };
  } catch (error) {
    settingsDmE2eeBackupState = {
      loaded: true,
      identityStatus: "error",
      exportable: false,
      hasBackup: false,
      backupUpdatedAt: "",
      backupPasswordSource: "",
      error,
    };
  } finally {
    settingsDmE2eeBackupLoading = false;
    renderDmE2eeBackupSettingsUi();
  }
  return settingsDmE2eeBackupState;
}

async function saveDmE2eeBackupFromSettings() {
  if (!DM_PRIVATE_RUNTIME_ENABLED) return;
  if (!state.user?.id || settingsDmE2eeBackupSaving) return;
  const passwordInput = document.getElementById("settingsDmE2eeBackupPassword");
  const confirmInput = document.getElementById("settingsDmE2eeBackupPasswordConfirm");
  const password = passwordInput instanceof HTMLInputElement ? String(passwordInput.value || "") : "";
  const confirmPassword = confirmInput instanceof HTMLInputElement ? String(confirmInput.value || "") : "";

  if (password.length < DM_E2EE_BACKUP_PASSWORD_MIN_LENGTH) {
    await showSecurityDialogMessage(
      tf(
        "settings.security.dm_backup.error_password_short",
        { min: DM_E2EE_BACKUP_PASSWORD_MIN_LENGTH },
        "Use your account password with at least {min} characters."
      ),
      { danger: true }
    );
    return;
  }
  if (password !== confirmPassword) {
    await showSecurityDialogMessage(t("settings.security.dm_backup.error_password_match", "Account passwords do not match."), { danger: true });
    return;
  }

  settingsDmE2eeBackupSaving = true;
  renderDmE2eeBackupSettingsUi();
  try {
    await createDmE2eeKeyBackup({
      userId: state.user.id,
      password,
      passwordSource: DM_E2EE_BACKUP_PASSWORD_SOURCE_ACCOUNT_LOGIN,
    });
    clearDmE2eeBackupInputs({ clearRestore: false });
    await refreshDmE2eeBackupSettingsState({ force: true });
    await showSecurityDialogMessage(t("settings.security.dm_backup.saved", "Portable Private DM backup saved."));
  } catch (error) {
    const message = isMissingTableError(error, "dm_e2ee_user_key_backups")
      ? t("settings.security.dm_backup.status.sql_missing", "Encrypted DM backup SQL is missing. Apply the Phase 4 patch and reload.")
      : String(error?.message || error || "Could not save the portable Private DM backup.");
    await showSecurityDialogMessage(message, { danger: true });
  } finally {
    settingsDmE2eeBackupSaving = false;
    renderDmE2eeBackupSettingsUi();
  }
}

async function restoreDmE2eeBackupFromSettings() {
  if (!DM_PRIVATE_RUNTIME_ENABLED) return;
  if (!state.user?.id || settingsDmE2eeBackupRestoring) return;
  const restoreInput = document.getElementById("settingsDmE2eeBackupRestorePassword");
  const password = restoreInput instanceof HTMLInputElement ? String(restoreInput.value || "") : "";
  if (!password) {
    await showSecurityDialogMessage(t("settings.security.dm_backup.error_restore_password", "Enter your account password to restore your encrypted Private DM identity."), { danger: true });
    return;
  }

  settingsDmE2eeBackupRestoring = true;
  renderDmE2eeBackupSettingsUi();
  try {
    await restoreDmE2eeKeyBackup({
      userId: state.user.id,
      password,
    });
    dmE2eeBootstrapPromise = null;
    await ensureDmE2eeBootstrapStarted({ force: true });
    clearDmE2eeBackupInputs({ clearRestore: true });
    await refreshDmE2eeBackupSettingsState({ force: true });
    if (activeDmId && String(state.activeDm?.kind || "").trim().toLowerCase() === "dm") {
      void fetchMessages(activeDmId).catch((error) => {
        console.warn("refresh messages after dm key restore failed", error?.message || error);
      });
    }
    await showSecurityDialogMessage(t("settings.security.dm_backup.restored", "Private DM identity restored on this device."));
  } catch (error) {
    const message = isMissingTableError(error, "dm_e2ee_user_key_backups")
      ? t("settings.security.dm_backup.status.sql_missing", "Encrypted DM backup SQL is missing. Apply the Phase 4 patch and reload.")
      : String(error?.message || error || "Could not restore the Private DM identity on this device.");
    await showSecurityDialogMessage(message, { danger: true });
  } finally {
    settingsDmE2eeBackupRestoring = false;
    renderDmE2eeBackupSettingsUi();
  }
}

function renderSecurityAccessUi() {
  const hasCode = !!settingsSecurityCodeHash;
  const isUnlocked = !hasCode || settingsSecurityUnlocked;
  const isLocked = hasCode && !isUnlocked;
  const showSetupPrompt = !hasCode && !settingsSecuritySetupDismissed;
  const showQuickCreate = !hasCode && settingsSecuritySetupDismissed;

  const navLockIcon = document.getElementById("settingsNavSecurityLock");
  if (navLockIcon) {
    navLockIcon.hidden = !hasCode;
    navLockIcon.classList.toggle("is-unlocked", hasCode && isUnlocked);
  }
  const securityNavBtn = document.querySelector('#profileOverlay [data-settings-tab="security"]');
  if (securityNavBtn) {
    securityNavBtn.classList.toggle("is-locked", isLocked);
    securityNavBtn.title = isLocked
      ? t("settings.security.code.state_locked", "Security is locked. Enter your code to continue.")
      : "";
  }

  const lockedScreen = document.getElementById("settingsSecurityLockedScreen");
  if (lockedScreen) lockedScreen.hidden = !isLocked;
  const setupScreen = document.getElementById("settingsSecuritySetupScreen");
  if (setupScreen) setupScreen.hidden = !showSetupPrompt;
  const securityContent = document.getElementById("settingsSecurityContent");
  if (securityContent) securityContent.hidden = isLocked || showSetupPrompt;

  const lockedTitle = document.getElementById("settingsSecurityLockedTitle");
  if (lockedTitle) lockedTitle.textContent = t("settings.security.locked.title", "Security locked");
  const lockedHint = document.getElementById("settingsSecurityLockedHint");
  if (lockedHint) lockedHint.textContent = t("settings.security.locked.hint", "Enter your security code to access this tab.");

  const sectionTitle = document.getElementById("settingsSectionSecurityCode");
  if (sectionTitle) sectionTitle.textContent = t("settings.security.code.section", "Security code lock");
  const codeHint = document.getElementById("settingsSecurityCodeHint");
  if (codeHint) codeHint.textContent = t("settings.security.code.hint", "Create a code to lock this Security tab. You will need it to open security options later.");
  const stateHint = document.getElementById("settingsSecurityCodeState");
  if (stateHint) {
    const stateKey = !hasCode
      ? (settingsSecuritySetupDismissed
        ? "settings.security.code.state_none_optional"
        : "settings.security.code.state_none")
      : (isUnlocked ? "settings.security.code.state_unlocked" : "settings.security.code.state_locked");
    const fallback = !hasCode
      ? (settingsSecuritySetupDismissed
        ? "No security code configured. You can create one anytime below."
        : "No security code configured.")
      : (isUnlocked ? "Security is unlocked for this session." : "Security is locked. Enter your code to continue.");
    stateHint.textContent = t(stateKey, fallback);
  }

  const setupTitle = document.getElementById("settingsSecuritySetupTitle");
  if (setupTitle) setupTitle.textContent = t("settings.security.setup.title", "Protect this tab with a code?");
  const setupHint = document.getElementById("settingsSecuritySetupHint");
  if (setupHint) setupHint.textContent = t("settings.security.setup.hint", "Create a security code now to lock this tab. You can also skip for now and set it up later.");
  const setupCreateBtn = document.getElementById("btnSecuritySetupCreate");
  if (setupCreateBtn) setupCreateBtn.textContent = t("settings.security.setup.create_btn", "Create security code");
  const setupSkipBtn = document.getElementById("btnSecuritySetupSkip");
  if (setupSkipBtn) setupSkipBtn.textContent = t("settings.security.setup.skip_btn", "Not now");
  const quickCreateWrap = document.getElementById("settingsSecurityQuickCreateWrap");
  if (quickCreateWrap) quickCreateWrap.hidden = !showQuickCreate;
  const quickCreateBtn = document.getElementById("btnSecurityQuickCreate");
  if (quickCreateBtn) quickCreateBtn.textContent = t("settings.security.code.quick_create_btn", "Create security code");

  const unlockLabel = document.querySelector('label[for="securityUnlockCode"]');
  if (unlockLabel) unlockLabel.textContent = t("settings.security.code.enter", "Enter security code");
  const unlockBtn = document.getElementById("btnSecurityUnlock");
  if (unlockBtn) unlockBtn.textContent = t("settings.security.code.unlock_btn", "Unlock security");

  const codeLabel = document.querySelector('label[for="securityCode"]');
  if (codeLabel) codeLabel.textContent = t("settings.security.code.label", "Security code");
  const codeConfirmLabel = document.querySelector('label[for="securityCodeConfirm"]');
  if (codeConfirmLabel) codeConfirmLabel.textContent = t("settings.security.code.confirm", "Confirm code");
  const manageHint = document.getElementById("settingsSecurityManageHint");
  if (manageHint) manageHint.textContent = t("settings.security.code.manage_hint", "Only numbers, between 4 and 10 digits.");
  const saveCodeBtn = document.getElementById("btnSecuritySaveCode");
  if (saveCodeBtn) {
    saveCodeBtn.textContent = hasCode
      ? t("settings.security.code.update_btn", "Update security code")
      : t("settings.security.code.create_btn", "Save security code");
  }
  const removeCodeBtn = document.getElementById("btnSecurityRemoveCode");
  if (removeCodeBtn) {
    removeCodeBtn.textContent = settingsSecurityRemoveVerificationPending
      ? t("settings.security.code.remove_resend_btn", "Resend verification code")
      : t("settings.security.code.remove_btn", "Remove security code");
    removeCodeBtn.disabled = !hasCode || !isUnlocked;
  }
  const forgotCodeBtn = document.getElementById("btnSecurityForgotCode");
  if (forgotCodeBtn) {
    forgotCodeBtn.textContent = settingsSecurityRemoveVerificationPending
      ? t("settings.security.code.forgot_resend_btn", "Resend reset code")
      : t("settings.security.code.forgot_btn", "Forgot security code");
    forgotCodeBtn.disabled = !hasCode;
  }
  const removeCodeLabel = document.querySelector('label[for="securityRemoveEmailCode"]');
  if (removeCodeLabel) removeCodeLabel.textContent = t("settings.security.code.remove_code_label", "Email verification code");
  const forgotCodeLabel = document.querySelector('label[for="securityForgotEmailCode"]');
  if (forgotCodeLabel) forgotCodeLabel.textContent = t("settings.security.code.remove_code_label", "Email verification code");
  const removeCodeInput = document.getElementById("securityRemoveEmailCode");
  if (removeCodeInput) removeCodeInput.setAttribute("placeholder", "123456");
  const forgotCodeInput = document.getElementById("securityForgotEmailCode");
  if (forgotCodeInput) forgotCodeInput.setAttribute("placeholder", "123456");
  const removeCodeHint = document.getElementById("settingsSecurityRemoveVerifyHint");
  if (removeCodeHint) removeCodeHint.textContent = t("settings.security.code.remove_code_hint", "Paste the verification code or confirmation link from your email to remove the security code.");
  const forgotCodeHint = document.getElementById("settingsSecurityLockedResetHint");
  if (forgotCodeHint) forgotCodeHint.textContent = t("settings.security.code.forgot_code_hint", "We sent a verification code to your email. Enter it to reset your security code.");
  const removeCodeConfirmBtn = document.getElementById("btnSecurityConfirmRemoveCode");
  if (removeCodeConfirmBtn) removeCodeConfirmBtn.textContent = t("settings.security.code.remove_confirm_btn", "Confirm remove security code");
  const forgotCodeConfirmBtn = document.getElementById("btnSecurityConfirmForgotCode");
  if (forgotCodeConfirmBtn) forgotCodeConfirmBtn.textContent = t("settings.security.code.forgot_confirm_btn", "Reset security code");
  const removeCodeWrap = document.getElementById("settingsSecurityRemoveVerifyWrap");
  if (removeCodeWrap) removeCodeWrap.hidden = !(hasCode && isUnlocked && settingsSecurityRemoveVerificationPending);
  const forgotCodeWrap = document.getElementById("settingsSecurityLockedResetWrap");
  if (forgotCodeWrap) forgotCodeWrap.hidden = !(hasCode && isLocked && settingsSecurityRemoveVerificationPending);

  const unlockCodeInput = document.getElementById("securityUnlockCode");
  if (unlockCodeInput) unlockCodeInput.setAttribute("placeholder", "1234");
  const codeInput = document.getElementById("securityCode");
  if (codeInput) codeInput.setAttribute("placeholder", "1234");
  const codeConfirmInput = document.getElementById("securityCodeConfirm");
  if (codeConfirmInput) codeConfirmInput.setAttribute("placeholder", "1234");

  if (isLocked) {
    const securityCodeInput = document.getElementById("securityCode");
    if (securityCodeInput) securityCodeInput.value = "";
    const securityCodeConfirmInput = document.getElementById("securityCodeConfirm");
    if (securityCodeConfirmInput) securityCodeConfirmInput.value = "";
  }

  renderDmE2eeBackupSettingsUi();
}

async function showSecurityDialogMessage(message, { danger = false } = {}) {
  await requestAppAlert(String(message || ""), {
    title: t("settings.section.security", "Security"),
    okText: t("dialog.confirm.ok", "OK"),
    danger: !!danger,
  });
}

async function saveSecurityAccessCode() {
  if (!state.user) return;
  const securityCodeInput = document.getElementById("securityCode");
  const securityCodeConfirmInput = document.getElementById("securityCodeConfirm");
  const code = normalizeSecurityCodeInput(securityCodeInput?.value || "");
  const confirmCode = normalizeSecurityCodeInput(securityCodeConfirmInput?.value || "");
  if (securityCodeInput) securityCodeInput.value = code;
  if (securityCodeConfirmInput) securityCodeConfirmInput.value = confirmCode;

  if (!isValidSecurityCode(code)) {
    await showSecurityDialogMessage(t("settings.security.code.error_format", "Use only numbers (4 to 10 digits)."), { danger: true });
    return;
  }
  if (code !== confirmCode) {
    await showSecurityDialogMessage(t("settings.security.code.error_match", "Codes do not match."), { danger: true });
    return;
  }

  let hash = "";
  try {
    hash = await computeSecurityCodeHash(code);
  } catch (_) {
    await showSecurityDialogMessage(t("settings.security.code.error_save", "Could not save security code."), { danger: true });
    return;
  }

  const currentMeta = getUserMetadataObject(state.user);
  const nextMeta = {
    ...currentMeta,
    [SETTINGS_SECURITY_CODE_META_KEY]: hash,
  };
  const { data, error } = await updateUserWithSessionRetry({ data: nextMeta });
  setProfileDebug({ update_security_code: { error, hasCode: !!hash } });
  if (error) {
    await showSecurityDialogMessage(`${t("settings.security.code.error_save", "Could not save security code.")} ${error.message || error}`, { danger: true });
    return;
  }

  if (data?.user) {
    state.user = data.user;
  } else {
    state.user = state.user || {};
    state.user.user_metadata = nextMeta;
  }

  settingsSecurityCodeHash = hash;
  settingsSecurityUnlocked = true;
  settingsSecuritySetupDismissed = true;
  settingsSecurityRemoveVerificationPending = false;
  try {
    await persistSecuritySetupDismissedPreference(true);
  } catch (error) {
    console.warn("persist security setup dismissal failed", error);
  }
  clearSecurityCodeInputs();
  renderSecurityAccessUi();
  await showSecurityDialogMessage(t("settings.security.code.saved", "Security code saved."));
}

async function unlockSecuritySettingsPanel() {
  if (!settingsSecurityCodeHash) {
    settingsSecurityUnlocked = true;
    renderSecurityAccessUi();
    return;
  }
  const unlockCodeInput = document.getElementById("securityUnlockCode");
  const code = normalizeSecurityCodeInput(unlockCodeInput?.value || "");
  if (unlockCodeInput) unlockCodeInput.value = code;

  if (!isValidSecurityCode(code)) {
    await showSecurityDialogMessage(t("settings.security.code.error_format", "Use only numbers (4 to 10 digits)."), { danger: true });
    return;
  }

  let hash = "";
  try {
    hash = await computeSecurityCodeHash(code);
  } catch (_) {
    await showSecurityDialogMessage(t("settings.security.code.error_invalid", "Invalid security code."), { danger: true });
    return;
  }

  if (hash !== settingsSecurityCodeHash) {
    await showSecurityDialogMessage(t("settings.security.code.error_invalid", "Invalid security code."), { danger: true });
    return;
  }

  settingsSecurityUnlocked = true;
  settingsSecuritySetupDismissed = true;
  settingsSecurityRemoveVerificationPending = false;
  if (unlockCodeInput) unlockCodeInput.value = "";
  renderSecurityAccessUi();
}

async function requestSecurityCodeRemovalVerification() {
  if (!state.user || !settingsSecurityCodeHash) return;
  const { error } = await supabase.auth.reauthenticate();
  setProfileDebug({ security_remove_reauth: { error } });
  if (error) {
    await showSecurityDialogMessage(`${t("settings.security.code.error_remove_send", "Could not send verification code.")} ${error.message || error}`, { danger: true });
    return;
  }
  settingsSecurityRemoveVerificationPending = true;
  renderSecurityAccessUi();
  await showSecurityDialogMessage(t("settings.security.code.remove_code_sent", "Verification code sent to your email."));
  requestAnimationFrame(() => {
    const lockedWrapVisible = (() => {
      const wrap = document.getElementById("settingsSecurityLockedResetWrap");
      return !!(wrap instanceof HTMLElement && !wrap.hidden);
    })();
    const input = lockedWrapVisible
      ? document.getElementById("securityForgotEmailCode")
      : document.getElementById("securityRemoveEmailCode");
    if (!(input instanceof HTMLInputElement)) return;
    try {
      input.focus({ preventScroll: true });
    } catch (_) {
      try { input.focus(); } catch (_) {}
    }
  });
}

async function removeSecurityAccessCode() {
  if (!state.user || !settingsSecurityCodeHash) return;
  const removeCodeInput = document.getElementById("securityRemoveEmailCode");
  const forgotCodeInput = document.getElementById("securityForgotEmailCode");
  const lockedWrap = document.getElementById("settingsSecurityLockedResetWrap");
  const lockedWrapVisible = !!(lockedWrap instanceof HTMLElement && !lockedWrap.hidden);
  const sourceInput = lockedWrapVisible
    ? (forgotCodeInput instanceof HTMLInputElement ? forgotCodeInput : removeCodeInput)
    : (removeCodeInput instanceof HTMLInputElement ? removeCodeInput : forgotCodeInput);
  const parsed = parseSecurityReauthInput(sourceInput?.value || "");
  const nonce = String(parsed.nonce || "").trim();
  const tokenHash = String(parsed.tokenHash || "").trim();
  [removeCodeInput, forgotCodeInput].forEach((input) => {
    if (!(input instanceof HTMLInputElement)) return;
    if (nonce) input.value = nonce;
    else if (tokenHash) input.value = tokenHash;
  });

  if (!nonce && !tokenHash) {
    await showSecurityDialogMessage(t("settings.security.code.error_remove_code_required", "Enter the verification code from your email."), { danger: true });
    return;
  }

  let verifiedByLink = false;
  if (tokenHash && !nonce) {
    const verifyResult = await supabase.auth.verifyOtp({
      type: "reauthentication",
      token_hash: tokenHash,
    });
    setProfileDebug({ security_remove_verify_link: { error: verifyResult?.error } });
    if (verifyResult?.error) {
      await showSecurityDialogMessage(t("settings.security.code.error_remove_verify", "Invalid or expired verification code."), { danger: true });
      return;
    }
    verifiedByLink = true;
  }

  const currentMeta = getUserMetadataObject(state.user);
  const nextMeta = {
    ...currentMeta,
    [SETTINGS_SECURITY_CODE_META_KEY]: null,
  };
  const payload = verifiedByLink
    ? { data: nextMeta }
    : { data: nextMeta, nonce };
  const { data, error } = await updateUserWithSessionRetry(payload);
  setProfileDebug({ remove_security_code: { error } });
  if (error) {
    const msg = String(error?.message || error || "").toLowerCase();
    if (msg.includes("nonce") || msg.includes("reauth")) {
      await showSecurityDialogMessage(t("settings.security.code.error_remove_verify", "Invalid or expired verification code."), { danger: true });
    } else {
      await showSecurityDialogMessage(`${t("settings.security.code.error_remove", "Could not remove security code.")} ${error.message || error}`, { danger: true });
    }
    return;
  }

  if (data?.user) {
    state.user = data.user;
  } else {
    state.user = state.user || {};
    state.user.user_metadata = nextMeta;
  }

  settingsSecurityCodeHash = "";
  settingsSecurityUnlocked = true;
  settingsSecuritySetupDismissed = true;
  settingsSecurityRemoveVerificationPending = false;
  try {
    await persistSecuritySetupDismissedPreference(true);
  } catch (errorPersist) {
    console.warn("persist security setup dismissal failed", errorPersist);
  }
  clearSecurityCodeInputs();
  renderSecurityAccessUi();
  if (verifiedByLink) {
    await showSecurityDialogMessage(t("settings.security.code.remove_link_verified", "Verification link accepted. You can now remove the security code."));
  }
  await showSecurityDialogMessage(t("settings.security.code.removed", "Security code removed."));
}

function isAuthSessionMissingError(errorInput) {
  const msg = String(errorInput?.message || errorInput || "").toLowerCase();
  const status = Number(errorInput?.status || errorInput?.statusCode || errorInput?.code || 0);
  if (status === 401) return true;
  return (
    msg.includes("auth session missing")
    || msg.includes("jwt")
    || msg.includes("refresh token")
    || msg.includes("invalid token")
    || msg.includes("not authenticated")
  );
}

async function ensureActiveAuthSession() {
  try {
    const sessionResult = await supabase.auth.getSession();
    if (!sessionResult?.error && sessionResult?.data?.session) return true;
  } catch (_) {}

  try {
    const refreshResult = await supabase.auth.refreshSession();
    if (!refreshResult?.error && refreshResult?.data?.session) return true;
  } catch (_) {}

  return false;
}

function redirectToLoginFromExpiredSession() {
  const msg = t("auth.session.missing.relogin", "Session expired. Sign in again to continue.");
  if (typeof requestAppAlert === "function") {
    void requestAppAlert(msg, {
      title: "Authentication",
      okText: t("dialog.confirm.ok", "OK"),
      danger: true,
    })
      .catch(() => {})
      .finally(() => {
        try {
          window.location.replace("./login.html");
        } catch (_) {}
      });
    return;
  }
  try {
    window.location.replace("./login.html");
  } catch (_) {}
}

function consumeDmE2eeLoginSyncNotice() {
  let raw = "";
  try {
    raw = String(sessionStorage.getItem(DM_E2EE_LOGIN_SYNC_NOTICE_KEY) || "").trim();
  } catch (_) {
    raw = "";
  }
  if (!raw) return;

  try { sessionStorage.removeItem(DM_E2EE_LOGIN_SYNC_NOTICE_KEY); } catch (_) {}

  let payload = null;
  try {
    payload = JSON.parse(raw);
  } catch (_) {
    payload = { message: raw, level: "warning" };
  }
  dmE2eeLastLoginSyncNotice = payload && typeof payload === "object" ? payload : null;

  const message = String(payload?.message || "").trim();
  if (!message) return;
  void requestAppAlert(message, {
    title: t("settings.section.security", "Security"),
    okText: t("dialog.confirm.ok", "OK"),
    danger: String(payload?.level || "").trim().toLowerCase() === "warning",
  }).catch(() => {});
}

async function updateUserWithSessionRetry(payload) {
  const hasSession = await ensureActiveAuthSession();
  if (!hasSession) {
    redirectToLoginFromExpiredSession();
    return { data: null, error: new Error("Auth session missing!") };
  }

  let result = await supabase.auth.updateUser(payload || {});
  if (!result?.error || !isAuthSessionMissingError(result.error)) return result;

  const refreshed = await ensureActiveAuthSession();
  if (!refreshed) {
    redirectToLoginFromExpiredSession();
    return result;
  }

  result = await supabase.auth.updateUser(payload || {});
  if (result?.error && isAuthSessionMissingError(result.error)) {
    redirectToLoginFromExpiredSession();
  }
  return result;
}

function formatBytesShort(bytes) {
  const n = Number(bytes);
  if (!Number.isFinite(n) || n <= 0) return "0B";
  if (n < 1024) return `${Math.round(n)}B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(n < 10 * 1024 ? 1 : 0)}KB`;
  return `${(n / (1024 * 1024)).toFixed(1)}MB`;
}

