function getBlockedUserRowById(userId) {
  const uid = normId(userId || "");
  if (!uid) return null;
  return (state.blockedUsers || []).find((row) => normId(row?.userId || row?.blocked_user_id || row?.id || "") === uid) || null;
}

function getBlockedUserRowByUsername(username = "") {
  const uname = String(username || "").trim().toLowerCase();
  if (!uname) return null;
  return (state.blockedUsers || []).find((row) => String(row?.username || "").trim().toLowerCase() === uname) || null;
}

function isUserBlockedLocally(userId) {
  return !!getBlockedUserRowById(userId);
}

function upsertBlockedUserRow(row = {}) {
  const uid = normId(row?.userId || row?.blocked_user_id || row?.id || "");
  if (!uid) return null;
  const current = getBlockedUserRowById(uid) || {};
  const next = {
    ...current,
    ...row,
    userId: uid,
    username: String(row?.username || current?.username || "").trim(),
    displayName: String(
      row?.displayName
      || row?.display_name
      || current?.displayName
      || current?.display_name
      || row?.username
      || current?.username
      || "User"
    ).trim() || "User",
    avatarUrl: String(row?.avatarUrl || row?.avatar_url || current?.avatarUrl || current?.avatar_url || "").trim(),
    createdAt: String(row?.createdAt || row?.created_at || current?.createdAt || current?.created_at || new Date().toISOString()).trim(),
  };
  state.blockedUsers = [
    next,
    ...(state.blockedUsers || []).filter((item) => normId(item?.userId || item?.blocked_user_id || item?.id || "") !== uid),
  ].sort((a, b) => (Date.parse(String(b?.createdAt || "")) || 0) - (Date.parse(String(a?.createdAt || "")) || 0));
  return next;
}

function removeBlockedUserRowById(userId) {
  const uid = normId(userId || "");
  if (!uid) return;
  state.blockedUsers = (state.blockedUsers || []).filter(
    (row) => normId(row?.userId || row?.blocked_user_id || row?.id || "") !== uid
  );
}

function renderBlockedUsersSettingsRowsFromState() {
  const trace = getRelationshipCurrentTrace();
  const traceLabel = relationshipTracePhaseStart(trace, "renderBlockedUsersSettingsRowsFromState");
  try {
  const listEl = document.getElementById("settingsBlockedUsersList");
  if (!listEl) return;
  const rows = Array.isArray(state.blockedUsers) ? state.blockedUsers : [];
  if (!rows.length) {
    listEl.innerHTML = `<div class="settingsPlaceholder">${esc(t("settings.blocked.empty", "You have no blocked users."))}</div>`;
    return;
  }
  renderBlockedUsersSettingsRows(rows);
  } finally {
    relationshipTracePhaseEnd(trace, traceLabel);
  }
}

async function fetchBlockedUsersForSettings() {
  if (!state.user?.id) return { rows: [], error: null };
  const meId = normId(state.user.id);
  if (!meId) return { rows: [], error: null };

  const { data, error } = await supabase
    .from("user_blocks")
    .select("blocked_user_id, created_at")
    .eq("blocker_user_id", meId)
    .order("created_at", { ascending: false });

  if (error) return { rows: [], error };

  const blockedRows = Array.isArray(data) ? data : [];
  const ids = blockedRows
    .map((row) => normId(row?.blocked_user_id || ""))
    .filter(Boolean);
  if (!ids.length) {
    state.blockedUsers = [];
    return { rows: [], error: null };
  }

  let profileRows = [];
  try {
    profileRows = await fetchProfilesByIds(ids, { includeBio: false, force: true });
  } catch (_) {
    profileRows = [];
  }
  const profileById = new Map((profileRows || []).map((row) => [normId(row?.id || ""), row]));

  const rows = ids.map((uid) => {
    const src = blockedRows.find((row) => normId(row?.blocked_user_id || "") === uid) || {};
    const profile = profileById.get(uid) || {};
    const username = String(profile?.username || "").trim();
    const displayName = String(profile?.display_name || username || "User").trim() || "User";
    return {
      userId: uid,
      username,
      displayName,
      avatarUrl: String(profile?.avatar_url || "").trim(),
      createdAt: src?.created_at || null,
    };
  });
  state.blockedUsers = rows;
  return { rows, error: null };
}

function renderBlockedUsersSettingsRows(rows = []) {
  const listEl = document.getElementById("settingsBlockedUsersList");
  if (!listEl) return;
  const unblockLabel = t("settings.blocked.unblock", "Unblock");
  listEl.innerHTML = rows.map((row) => {
    const uid = normId(row?.userId || "");
    if (!uid) return "";
    const displayName = String(row?.displayName || row?.username || "User").trim() || "User";
    const username = String(row?.username || "").trim();
    const avatarUrl = String(row?.avatarUrl || "").trim();
    const initial = (displayName[0] || "?").toUpperCase();
    const sinceText = row?.createdAt
      ? (() => {
        const ts = Date.parse(String(row.createdAt || ""));
        if (!Number.isFinite(ts)) return "";
        return new Date(ts).toLocaleString();
      })()
      : "";
    const subLabel = username ? `@${username}` : "";
    return `
      <div class="settingsBlockedRow" data-blocked-row="${escAttr(uid)}">
        <div class="settingsBlockedIdentity">
          <div class="settingsBlockedAvatar" aria-hidden="true">
            ${avatarUrl ? buildAvatarMediaHtml(avatarUrl, { userId: uid, alt: "" }) : `<span>${esc(initial)}</span>`}
          </div>
          <div class="settingsBlockedMeta">
            <b>${esc(displayName)}</b>
            <small>${esc([subLabel, sinceText].filter(Boolean).join(" â€¢ "))}</small>
          </div>
        </div>
        <button class="btn ghost" type="button" data-blocked-unblock="${escAttr(uid)}">${esc(unblockLabel)}</button>
      </div>
    `;
  }).join("");
}

async function renderBlockedUsersSettingsUi({ force = false } = {}) {
  const listEl = document.getElementById("settingsBlockedUsersList");
  if (!listEl) return;
  if (settingsBlockedUsersLoading) return;
  if (!force && settingsActiveTab !== "blocked-users") return;

  settingsBlockedUsersLoading = true;
  listEl.innerHTML = `<div class="settingsPlaceholder">${esc(t("settings.blocked.loading", "Loading blocked users..."))}</div>`;
  try {
    const { rows, error } = await fetchBlockedUsersForSettings();
    if (error) {
      const missingSql = isMissingTableError(error, "user_blocks");
      listEl.innerHTML = `<div class="settingsPlaceholder">${esc(
        missingSql
          ? t("settings.blocked.error.missing_sql", "Blocked users SQL is missing. Run SQL/SUPABASE_PATCH_FRIEND_BLOCK_REMOVE.sql and reload.")
          : `${t("settings.blocked.error.load", "Could not load blocked users.")} ${error.message || error}`
      )}</div>`;
      return;
    }
    if (!rows.length) {
      listEl.innerHTML = `<div class="settingsPlaceholder">${esc(t("settings.blocked.empty", "You have no blocked users."))}</div>`;
      return;
    }
    renderBlockedUsersSettingsRows(rows);
  } finally {
    settingsBlockedUsersLoading = false;
  }
}

function normalizeReportStatus(value) {
  const raw = String(value || "").trim().toLowerCase();
  if (raw === "reviewed" || raw === "actioned") return raw;
  return "pending";
}

function getReportStatusLabel(statusInput) {
  const status = normalizeReportStatus(statusInput);
  if (status === "reviewed") return t("settings.reports.status.reviewed", "Reviewed");
  if (status === "actioned") return t("settings.reports.status.actioned", "Actioned");
  return t("settings.reports.status.pending", "Pending");
}

function formatOwnerReportTimestamp(value) {
  const raw = String(value || "").trim();
  const ts = Date.parse(raw);
  if (!Number.isFinite(ts)) return "";
  try {
    return new Date(ts).toLocaleString();
  } catch (_) {
    return raw;
  }
}

function normalizeOwnerReportEvidenceMessage(entry = {}) {
  if (!entry || typeof entry !== "object" || Array.isArray(entry)) return null;
  const id = String(entry?.id || "").trim();
  const userId = normId(entry?.user_id || entry?.author_user_id || "");
  const authorName = String(entry?.author_name || entry?.display_name || entry?.author || "").trim();
  const authorUsername = String(entry?.author_username || entry?.username || "").trim();
  const createdAt = String(entry?.created_at || "").trim();
  const contentType = String(entry?.content_type || entry?.type || "").trim();
  const text = String(entry?.text || entry?.content || "").trim();
  if (!id && !text && !authorName && !createdAt) return null;
  return {
    id,
    userId,
    authorName,
    authorUsername,
    createdAt,
    contentType,
    text,
  };
}

function normalizeOwnerReportEvidence(metadataInput = {}) {
  const metadata = metadataInput && typeof metadataInput === "object" && !Array.isArray(metadataInput)
    ? metadataInput
    : {};
  const raw = metadata?.evidence;
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) return null;
  const type = String(raw?.type || "").trim();
  if (type !== "dm_user_submitted_context") return null;

  const reportedMessage = normalizeOwnerReportEvidenceMessage(raw?.reported_message || {});
  const before = (Array.isArray(raw?.before) ? raw.before : [])
    .map((entry) => normalizeOwnerReportEvidenceMessage(entry))
    .filter(Boolean);
  const after = (Array.isArray(raw?.after) ? raw.after : [])
    .map((entry) => normalizeOwnerReportEvidenceMessage(entry))
    .filter(Boolean);
  const messageIds = Array.isArray(raw?.message_ids)
    ? raw.message_ids.map((entry) => String(entry || "").trim()).filter(Boolean)
    : [];
  const sharedCount = before.length + after.length + (reportedMessage ? 1 : 0);
  if (!reportedMessage && !before.length && !after.length && !messageIds.length) return null;

  return {
    type,
    reportedMessage,
    before,
    after,
    messageIds,
    sharedCount,
  };
}

function buildOwnerReportEvidenceMessageHtml(message = {}, { highlighted = false } = {}) {
  const authorLabel = String(message?.authorName || message?.authorUsername || message?.userId || "").trim()
    || t("settings.reports.user.unknown", "Unknown user");
  const metaParts = [
    authorLabel,
    formatOwnerReportTimestamp(message?.createdAt),
  ].filter(Boolean);
  return `
    <div class="settingsReportsEvidenceItem${highlighted ? " is-reported" : ""}">
      <div class="settingsReportsEvidenceItemMeta">${esc(metaParts.join(" â€¢ "))}</div>
      <div class="settingsReportsEvidenceItemText">${esc(message?.text || "â€”")}</div>
    </div>
  `;
}

function buildOwnerReportEvidenceSectionHtml(evidenceInput = null) {
  const evidence = evidenceInput && typeof evidenceInput === "object" ? evidenceInput : null;
  if (!evidence) return "";

  const groups = [];
  if (evidence.reportedMessage) {
    groups.push(`
      <div class="settingsReportsEvidenceGroup">
        <div class="settingsReportsEvidenceGroupTitle">${esc(t("settings.reports.evidence.reported_message", "Reported message"))}</div>
        <div class="settingsReportsEvidenceList">
          ${buildOwnerReportEvidenceMessageHtml(evidence.reportedMessage, { highlighted: true })}
        </div>
      </div>
    `);
  }
  if (Array.isArray(evidence.before) && evidence.before.length) {
    groups.push(`
      <div class="settingsReportsEvidenceGroup">
        <div class="settingsReportsEvidenceGroupTitle">${esc(t("settings.reports.evidence.before", "Messages before"))}</div>
        <div class="settingsReportsEvidenceList">
          ${evidence.before.map((entry) => buildOwnerReportEvidenceMessageHtml(entry)).join("")}
        </div>
      </div>
    `);
  }
  if (Array.isArray(evidence.after) && evidence.after.length) {
    groups.push(`
      <div class="settingsReportsEvidenceGroup">
        <div class="settingsReportsEvidenceGroupTitle">${esc(t("settings.reports.evidence.after", "Messages after"))}</div>
        <div class="settingsReportsEvidenceList">
          ${evidence.after.map((entry) => buildOwnerReportEvidenceMessageHtml(entry)).join("")}
        </div>
      </div>
    `);
  }
  if (!groups.length) return "";

  return `
    <div class="settingsSectionTitle">${esc(t("settings.reports.evidence.title", "Context submitted by the user at report time"))}</div>
    <div class="settingsReportsEvidenceCard">
      <div class="settingsReportsEvidenceMeta">${esc(`${t("settings.reports.evidence.shared_messages", "Shared messages")}: ${String(evidence.sharedCount || 0)}`)}</div>
      ${groups.join("")}
    </div>
  `;
}

function normalizeOwnerModerationActionType(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  if (raw === "warning" || raw === "request_explanation" || raw === "ban" || raw === "unban") return raw;
  return "";
}

function getOwnerModerationActionTypeLabel(actionTypeInput = "") {
  const actionType = normalizeOwnerModerationActionType(actionTypeInput);
  if (actionType === "warning") return t("settings.reports.action_type.warning", "Warning");
  if (actionType === "request_explanation") return t("settings.reports.action_type.request_explanation", "Request explanation");
  if (actionType === "ban") return t("settings.reports.action_type.ban", "Ban");
  if (actionType === "unban") return t("settings.reports.action_type.unban", "Unban");
  return t("settings.reports.moderation.title", "Moderation actions");
}

function normalizeOwnerModerationActionRow(row = {}) {
  if (!row || typeof row !== "object" || Array.isArray(row)) return null;
  const id = normId(row?.id || "");
  const actionType = normalizeOwnerModerationActionType(row?.action_type || row?.actionType || "");
  if (!id || !actionType) return null;
  const metadata = row?.metadata && typeof row.metadata === "object" && !Array.isArray(row.metadata)
    ? { ...row.metadata }
    : {};
  return {
    id,
    reportId: normId(row?.report_id || row?.reportId || ""),
    targetUserId: normId(row?.target_user_id || row?.targetUserId || ""),
    actorUserId: normId(row?.actor_user_id || row?.actorUserId || ""),
    actionType,
    reason: String(row?.reason || "").trim(),
    metadata,
    createdAt: String(row?.created_at || row?.createdAt || "").trim(),
    responseText: String(metadata?.response_text || metadata?.responseText || "").trim(),
    respondedAt: String(metadata?.responded_at || metadata?.respondedAt || "").trim(),
    responseUserId: normId(metadata?.response_user_id || metadata?.responseUserId || ""),
    reportReason: String(metadata?.report_reason || metadata?.reportReason || "").trim(),
  };
}

function shouldModerationActionRequireResponse(actionInput = null) {
  const action = normalizeOwnerModerationActionRow(actionInput);
  if (!action || action.actionType !== "request_explanation") return false;
  return !action.responseText && !action.respondedAt && !action.responseUserId;
}

function normalizeModerationInboxActionList(rowsInput = []) {
  const byId = new Map();
  (Array.isArray(rowsInput) ? rowsInput : []).forEach((row) => {
    const action = normalizeOwnerModerationActionRow(row);
    if (!action?.id) return;
    const prev = byId.get(action.id);
    if (!prev) {
      byId.set(action.id, action);
      return;
    }
    byId.set(action.id, normalizeOwnerModerationActionRow({
      ...prev,
      ...action,
      metadata: {
        ...(prev.metadata || {}),
        ...(action.metadata || {}),
      },
    }));
  });
  return Array.from(byId.values()).filter(Boolean).sort((a, b) => {
    const aStamp = Date.parse(String(a?.createdAt || "")) || 0;
    const bStamp = Date.parse(String(b?.createdAt || "")) || 0;
    if (aStamp !== bStamp) return bStamp - aStamp;
    return String(b?.id || "").localeCompare(String(a?.id || ""));
  });
}

function setModerationInboxActions(rowsInput = [], { render = true } = {}) {
  state.moderationInboxActions = normalizeModerationInboxActionList(rowsInput);
  if (render) renderDesktopInboxPanel();
  return state.moderationInboxActions;
}

function getModerationInboxActionById(actionIdInput = "") {
  const actionId = normId(actionIdInput || "");
  if (!actionId) return null;
  return normalizeOwnerModerationActionRow(
    (Array.isArray(state.moderationInboxActions) ? state.moderationInboxActions : [])
      .find((entry) => normId(entry?.id || "") === actionId) || null
  );
}

function upsertModerationInboxAction(actionInput, { render = true } = {}) {
  const nextAction = normalizeOwnerModerationActionRow(actionInput);
  if (!nextAction?.id) return state.moderationInboxActions || [];
  const current = Array.isArray(state.moderationInboxActions) ? state.moderationInboxActions : [];
  return setModerationInboxActions([
    nextAction,
    ...current.filter((entry) => normId(entry?.id || "") !== nextAction.id),
  ], { render });
}

function removeModerationInboxAction(actionIdInput, { render = true } = {}) {
  const actionId = normId(actionIdInput || "");
  if (!actionId) return state.moderationInboxActions || [];
  const current = Array.isArray(state.moderationInboxActions) ? state.moderationInboxActions : [];
  return setModerationInboxActions(
    current.filter((entry) => normId(entry?.id || "") !== actionId),
    { render }
  );
}

function reconcileModerationInboxActionResponse(actionIdInput, responseInput = {}) {
  const actionId = normId(actionIdInput || "");
  if (!actionId) return state.moderationInboxActions || [];
  const current = getModerationInboxActionById(actionId);
  if (!current) return state.moderationInboxActions || [];
  const responseText = String(responseInput?.responseText || responseInput?.response_text || "").trim();
  const respondedAt = String(responseInput?.respondedAt || responseInput?.responded_at || new Date().toISOString()).trim();
  const responseUserId = normId(responseInput?.responseUserId || responseInput?.response_user_id || state.user?.id || "");
  return upsertModerationInboxAction({
    ...current,
    metadata: {
      ...(current.metadata || {}),
      ...(responseText ? { response_text: responseText } : {}),
      ...(respondedAt ? { responded_at: respondedAt } : {}),
      ...(responseUserId ? { response_user_id: responseUserId } : {}),
    },
    responseText,
    respondedAt,
    responseUserId,
  });
}

function normalizeUserModerationStateRow(row = {}) {
  if (!row || typeof row !== "object" || Array.isArray(row)) return {
    userId: "",
    isBanned: false,
    banReason: "",
    bannedAt: "",
    bannedByUserId: "",
    metadata: {},
  };
  const metadata = row?.metadata && typeof row.metadata === "object" && !Array.isArray(row.metadata)
    ? { ...row.metadata }
    : {};
  return {
    userId: normId(row?.user_id || row?.userId || ""),
    isBanned: row?.is_banned === true || row?.isBanned === true,
    banReason: String(row?.ban_reason || row?.banReason || "").trim(),
    bannedAt: String(row?.banned_at || row?.bannedAt || "").trim(),
    bannedByUserId: normId(row?.banned_by_user_id || row?.bannedByUserId || ""),
    metadata,
  };
}

function normalizeMyModerationStatePayload(payload = null) {
  if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
    return normalizeUserModerationStateRow({});
  }
  return normalizeUserModerationStateRow(payload);
}

function normalizeOwnerReportRow(row = {}) {
  const metadata = row?.metadata && typeof row.metadata === "object" && !Array.isArray(row.metadata)
    ? { ...row.metadata }
    : {};
  return {
    id: normId(row?.id || ""),
    reporterUserId: normId(row?.reporter_user_id || row?.reporterUserId || ""),
    targetUserId: normId(row?.target_user_id || row?.targetUserId || ""),
    messageId: String(row?.message_id || row?.messageId || "").trim(),
    conversationId: String(row?.conversation_id || row?.conversationId || "").trim(),
    reason: String(row?.reason || "").trim(),
    status: normalizeReportStatus(row?.status),
    createdAt: String(row?.created_at || row?.createdAt || "").trim(),
    metadata,
    evidence: normalizeOwnerReportEvidence(metadata),
    moderationActions: [],
    targetModerationState: null,
    reporterProfile: null,
    targetProfile: null,
  };
}

function buildOwnerReportProfileSummary(userId) {
  const uid = normId(userId || "");
  if (!uid) return null;
  const profile = getCachedProfile(uid) || {};
  const username = String(profile?.username || "").trim();
  const displayName = String(profile?.display_name || username || "").trim()
    || t("settings.reports.user.unknown", "Unknown user");
  return {
    id: uid,
    username,
    displayName,
    avatarUrl: String(profile?.avatar_url || "").trim(),
  };
}

function getOwnerReportUserLabel(summary, fallback = "") {
  return String(
    summary?.displayName
    || summary?.username
    || fallback
    || t("settings.reports.user.unknown", "Unknown user")
  ).trim() || t("settings.reports.user.unknown", "Unknown user");
}

function buildOwnerReportAvatarHtml(summary, fallbackLabel = "") {
  const uid = normId(summary?.id || "");
  const avatarUrl = String(summary?.avatarUrl || "").trim();
  const label = getOwnerReportUserLabel(summary, fallbackLabel);
  if (avatarUrl) {
    return buildAvatarMediaHtml(avatarUrl, { userId: uid || label, alt: label || "avatar" });
  }
  return `<span>${esc((label[0] || "?").toUpperCase())}</span>`;
}

function getOwnerReportTargetStateLabel(stateInput = null) {
  const info = stateInput && typeof stateInput === "object" ? stateInput : null;
  if (info?.isBanned) return t("settings.reports.target_state.banned", "Banned");
  return t("settings.reports.target_state.active", "Active");
}

function buildOwnerReportModerationHistoryHtml(actionsInput = []) {
  const actions = Array.isArray(actionsInput) ? actionsInput.filter(Boolean) : [];
  if (!actions.length) {
    return `<div class="settingsPlaceholder">${esc(t("settings.reports.moderation.history.empty", "No moderation actions recorded for this report yet."))}</div>`;
  }

  return `
    <div class="settingsReportsModerationHistory">
      ${actions.map((action) => {
        const createdLabel = formatOwnerReportTimestamp(action?.createdAt);
        const label = getOwnerModerationActionTypeLabel(action?.actionType);
        const reasonText = String(action?.reason || action?.reportReason || "").trim();
        const respondedLabel = formatOwnerReportTimestamp(action?.respondedAt || "");
        const isRequestExplanation = action?.actionType === "request_explanation";
        return `
          <div class="settingsReportsModerationHistoryItem">
            <div class="settingsReportsModerationHistoryTop">
              <b>${esc(label)}</b>
              <span>${esc(createdLabel || "â€”")}</span>
            </div>
            ${reasonText ? `
              <div class="settingsReportsModerationHistoryMeta">${esc(
                isRequestExplanation
                  ? t("settings.reports.moderation.request_message", "Moderation request")
                  : t("settings.reports.reason", "Reason")
              )}</div>
              <div class="settingsReportsModerationHistoryText">${esc(reasonText)}</div>
            ` : ""}
            ${action?.responseText ? `
              <div class="settingsReportsModerationResponseCard">
                <div class="settingsReportsModerationResponseTop">
                  <b>${esc(t("settings.reports.moderation.reply", "Resposta do utilizador"))}</b>
                  ${respondedLabel ? `<span>${esc(respondedLabel)}</span>` : ""}
                </div>
                <div class="settingsReportsModerationResponseBody">${esc(action.responseText)}</div>
              </div>
            ` : (isRequestExplanation
              ? `<div class="settingsReportsModerationHistoryMeta">${esc(t("settings.reports.moderation.reply_pending", "Waiting for explanation"))}</div>`
              : "")}
          </div>
        `;
      }).join("")}
    </div>
  `;
}

function getSelectedOwnerReport() {
  return settingsOwnerReportsRows.find((row) => row.id === settingsOwnerReportsSelectedId) || null;
}

