async function saveProfile() {
  const display_name = document.getElementById("displayName").value.trim();
  const pronouns = normalizePronouns(document.getElementById("pronouns")?.value || "");
  const bio = document.getElementById("bio").value.trim();
  const nameColor = normalizeNameColor(document.getElementById("nameColor")?.value || "");
  const callTileColor = normalizeCallTileColor(document.getElementById("callTileColor")?.value || "");

  if (display_name.length > 32) return alert("Display name mÃ¡ximo: 32 caracteres");
  if (bio.length > PROFILE_BIO_MAX_LEN) return alert(`Bio mÃ¡xima: ${PROFILE_BIO_MAX_LEN} caracteres`);

  let payload = {
    display_name: display_name || null,
    pronouns: pronouns || null,
    bio: bio || null,
    name_color: nameColor || null,
    call_tile_color: callTileColor || null,
  };
  let { error } = await supabase.from("profiles").update(payload).eq("id", state.user.id);

  let warnedMissingProfileCols = false;
  if (error) {
    const msg = String(error?.message || "").toLowerCase();
    let stripped = false;
    if (msg.includes("pronouns") && msg.includes("column")) {
      profilePronounsSupported = false;
      delete payload.pronouns;
      stripped = true;
    }
    if (msg.includes("name_color") && msg.includes("column")) {
      profileNameColorSupported = false;
      delete payload.name_color;
      stripped = true;
    }
    if (msg.includes("call_tile_color") && msg.includes("column")) {
      profileCallTileColorSupported = false;
      delete payload.call_tile_color;
      stripped = true;
    }
    if (stripped) {
      ({ error } = await supabase.from("profiles").update(payload).eq("id", state.user.id));
      if (!error) {
        alert("Perfil guardado. Falta SQL no Supabase para campos novos (ex.: SQL/SUPABASE_PATCH_PROFILE_PRONOUNS.sql).");
        warnedMissingProfileCols = true;
      }
    }
  }

  setProfileDebug({ update_profile: { error } });
  if (error) return alert("Erro: " + error.message);

  if (!warnedMissingProfileCols) alert("Perfil guardado.");
  state.me = await getMyProfile(state.user.id);
  state.me.name_color = normalizeNameColor(state.me.name_color);
  state.me.call_tile_color = normalizeCallTileColor(state.me.call_tile_color);
  state.me.status = resolveMyPresenceStatus(state.me);
  setMyStatus(state.me.status);
  cacheProfileRow(state.me);
  applyAppearanceSettings(loadAppearanceSettings({ force: true }));
  applyMeHeaderNameStyle();
  $("meName").textContent = state.me.display_name || state.me.username;
  $("meTag").textContent = "@" + state.me.username;
  applyMeHeaderBannerStyle();
  const meLine = document.getElementById("meLine");
  if (meLine) meLine.textContent = state.me.display_name || state.me.username || "â€¦";
  const uidLine = document.getElementById("uidLine");
  if (uidLine) uidLine.textContent = state.me.username ? `@${state.me.username}` : "@...";
  const pronounsLine = document.getElementById("pronounsLine");
  if (pronounsLine) {
    const pronounsValue = normalizePronouns(state.me.pronouns || "");
    pronounsLine.textContent = pronounsValue;
    pronounsLine.hidden = !pronounsValue;
  }
  const settingsUserName = document.getElementById("settingsUserName");
  if (settingsUserName) settingsUserName.textContent = state.me.display_name || state.me.username || "User";
  const settingsUserTag = document.getElementById("settingsUserTag");
  if (settingsUserTag) settingsUserTag.textContent = state.me.username ? `@${state.me.username}` : "@...";
  const settingsBanner = document.getElementById("settingsIdentityBanner");
  if (settingsBanner) {
    const base = normalizeCallTileColor(state.me.call_tile_color) || "#1b2230";
    const left = mixHex(base, "#77c5ff", 0.1);
    const right = mixHex(base, "#05080d", 0.55);
    const glow = rgbaFromHex(base, 0.22);
    const bannerUrl = resolveUserBannerUrl(state.user?.id, state.me.banner_url || state.me.theme_settings?.banner_url || "");
    applyBannerStyle(settingsBanner, bannerUrl, left, right, glow, { userId: state.user?.id || "" });
    if (!bannerUrl) settingsBanner.style.background = `linear-gradient(135deg, ${left}, ${right} 78%)`;
  }
  await presence?.setStatus?.(state.me.status);

  renderFriends();
  updatePresenceRender();
  renderMessagesFromCache({ keepBottom: true });
}

async function updateEmail() {
  if (settingsSecurityCodeHash && !settingsSecurityUnlocked) {
    await showSecurityDialogMessage(t("settings.security.code.state_locked", "Security is locked. Enter your code to continue."), { danger: true });
    return;
  }
  const newEmailInput = document.getElementById("newEmail");
  const currentEmailInput = document.getElementById("currentEmail");
  const email = String(newEmailInput?.value || "").trim();
  if (!email) {
    await showSecurityDialogMessage("Mete um email.", { danger: true });
    return;
  }

  const { data, error } = await updateUserWithSessionRetry({ email });
  setProfileDebug({ update_email: { error, data } });
  if (error) {
    await showSecurityDialogMessage("Erro: " + error.message, { danger: true });
    return;
  }

  const nextEmail = String(data?.user?.email || state.user?.email || email);
  if (state.user) state.user.email = nextEmail;
  if (currentEmailInput) currentEmailInput.value = nextEmail;
  if (newEmailInput) newEmailInput.value = "";
  await showSecurityDialogMessage("Pedido de troca de email feito (pode precisar de confirmaÃ§Ã£o).");
}

async function updatePassword() {
  if (settingsSecurityCodeHash && !settingsSecurityUnlocked) {
    await showSecurityDialogMessage(t("settings.security.code.state_locked", "Security is locked. Enter your code to continue."), { danger: true });
    return;
  }
  const currentPassInput = document.getElementById("currentPass");
  const newPassInput = document.getElementById("newPass");
  const currentPassword = String(currentPassInput?.value || "");
  const password = String(newPassInput?.value || "");
  if (!currentPassword) {
    await showSecurityDialogMessage(t("settings.security.error_current_password_required", "Enter your current password."), { danger: true });
    return;
  }
  if (!password) {
    await showSecurityDialogMessage("Mete uma password.", { danger: true });
    return;
  }

  const btnPass = document.getElementById("btnPass");
  const btnPassDefaultText = String(btnPass?.textContent || t("settings.security.update_password", "Update password"));
  if (btnPass instanceof HTMLButtonElement) {
    btnPass.disabled = true;
    btnPass.textContent = t("settings.security.update_password_pending", "Updating...");
  }
  try {
    const currentEmailInput = document.getElementById("currentEmail");
    const emailCandidates = new Set();
    const pushEmailCandidate = (value) => {
      const emailValue = String(value || "").trim().toLowerCase();
      if (!emailValue || !emailValue.includes("@")) return;
      emailCandidates.add(emailValue);
    };
    pushEmailCandidate(state.user?.email);
    pushEmailCandidate(currentEmailInput?.value);
    pushEmailCandidate(state.me?.email);
    try {
      const authUserRes = await supabase.auth.getUser();
      const authEmail = String(authUserRes?.data?.user?.email || "").trim();
      pushEmailCandidate(authEmail);
      if (authEmail && state.user) state.user.email = authEmail;
    } catch (_) {}

    const isInvalidCredentialsError = (err) => {
      const msg = String(err?.message || "").toLowerCase();
      const code = String(err?.code || "").toLowerCase();
      if (code.includes("invalid_credentials")) return true;
      return msg.includes("invalid login credentials") || msg.includes("invalid credentials");
    };

    let verifiedCurrentPassword = false;
    let verifyError = null;
    for (const email of emailCandidates) {
      const verifyAttempt = await supabase.auth.signInWithPassword({ email, password: currentPassword });
      if (!verifyAttempt?.error) {
        verifiedCurrentPassword = true;
        verifyError = null;
        break;
      }
      verifyError = verifyAttempt.error;
      if (!isInvalidCredentialsError(verifyAttempt.error)) break;
    }

    if (!verifiedCurrentPassword) {
      if (verifyError && !isInvalidCredentialsError(verifyError)) {
        await showSecurityDialogMessage(
          `${t("settings.security.error_current_password_verify", "Could not verify current password. Try again.")} ${verifyError.message || ""}`.trim(),
          { danger: true },
        );
        return;
      }
      await showSecurityDialogMessage(t("settings.security.error_current_password_invalid", "Current password is incorrect."), { danger: true });
      return;
    }

    const { data, error } = await updateUserWithSessionRetry({ password });
    setProfileDebug({ update_pass: { error, data } });
    if (error) {
      await showSecurityDialogMessage("Erro: " + error.message, { danger: true });
      return;
    }

    if (state.user?.id) {
      try {
        const dmIdentityState = await getDmE2eeIdentityState({ userId: state.user.id, force: true });
        if (dmIdentityState?.status === "ready" && dmIdentityState.localPrivateKeyExportable) {
          await createDmE2eeKeyBackup({
            userId: state.user.id,
            password,
            passwordSource: DM_E2EE_BACKUP_PASSWORD_SOURCE_ACCOUNT_LOGIN,
          });
          void refreshDmE2eeBackupSettingsState({ force: true });
        }
      } catch (backupRefreshError) {
        console.warn("dm e2ee backup refresh after password change failed", backupRefreshError?.message || backupRefreshError);
      }
    }

    if (currentPassInput) currentPassInput.value = "";
    if (newPassInput) newPassInput.value = "";
    await showSecurityDialogMessage("Password atualizada.");
  } finally {
    if (btnPass instanceof HTMLButtonElement) {
      btnPass.disabled = false;
      btnPass.textContent = btnPassDefaultText;
    }
  }
}

