function isWidgetTodoCompleted(items) {
  const list = Array.isArray(items) ? items : [];
  if (!list.length) return false;
  return list.every((x) => !!x?.done);
}

function pickWidgetChecklistCompleteMessage() {
  const list = [
    t("widgets.todo.complete.1", "Great! Checklist completed. Keep it up."),
    t("widgets.todo.complete.2", "Nice work. You finished every task."),
    t("widgets.todo.complete.3", "Excellent. All checklist items are done."),
    t("widgets.todo.complete.4", "Mission complete. Checklist finished."),
  ].filter(Boolean);
  if (!Array.isArray(list) || !list.length) return "Checklist completed.";
  if (list.length === 1) {
    widgetChecklistLastMessageIndex = 0;
    return list[0];
  }
  let idx = Math.floor(Math.random() * list.length);
  if (idx === widgetChecklistLastMessageIndex) idx = (idx + 1) % list.length;
  widgetChecklistLastMessageIndex = idx;
  return list[idx];
}

function showWidgetChecklistToast(message, tone = "success") {
  const root = $("tabWidgets");
  if (!root) return;
  let toast = $("widgetChecklistToast");
  if (!toast) {
    toast = document.createElement("div");
    toast.id = "widgetChecklistToast";
    toast.className = "widgetChecklistToast";
    root.appendChild(toast);
  }
  toast.textContent = String(message || "").trim();
  toast.setAttribute("data-tone", tone === "warn" ? "warn" : "success");
  toast.classList.add("is-visible");
  if (widgetChecklistToastTimer) clearTimeout(widgetChecklistToastTimer);
  widgetChecklistToastTimer = setTimeout(() => {
    widgetChecklistToastTimer = null;
    toast.classList.remove("is-visible");
  }, 3200);
}

function maybeCelebrateWidgetTodoCompletion(beforeItems, afterItems) {
  const wasComplete = isWidgetTodoCompleted(beforeItems);
  const isComplete = isWidgetTodoCompleted(afterItems);
  if (wasComplete || !isComplete) return;
  showWidgetChecklistToast(pickWidgetChecklistCompleteMessage());
}

function getWidgetStatusLabel(statusInput) {
  const status = normalizePresenceStatus(statusInput);
  if (status === "dnd") return t("status.dnd", "busy");
  if (status === "idle") return t("status.idle", "away");
  if (status === "invisible") return t("status.invisible", "invisible");
  if (status === "offline") return t("status.offline", "offline");
  return t("status.online", "online");
}

function getWidgetCalendarLocale() {
  const lang = normalizeAppLanguage(appLanguage || readStoredAppLanguage(), APP_LANG_DEFAULT);
  return lang === "pt" ? "pt-PT" : "en-US";
}

function getWidgetCalendarWeekdayLabels(locale, { weekStartsOnMonday = false } = {}) {
  const baseSundayUtc = new Date(Date.UTC(2024, 0, 7)); // Sunday.
  const startShift = weekStartsOnMonday ? 1 : 0;
  const fmt = new Intl.DateTimeFormat(locale, { weekday: "narrow" });
  const out = [];
  for (let i = 0; i < 7; i += 1) {
    const d = new Date(baseSundayUtc);
    d.setUTCDate(baseSundayUtc.getUTCDate() + ((i + startShift) % 7));
    const raw = String(fmt.format(d) || "").trim();
    out.push((raw.charAt(0) || "?").toUpperCase());
  }
  return out;
}

function normalizeWidgetTodoDate(value = "") {
  const raw = String(value || "").trim();
  const match = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return "";
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  const candidate = new Date(year, month - 1, day);
  if (
    candidate.getFullYear() !== year
    || candidate.getMonth() !== (month - 1)
    || candidate.getDate() !== day
  ) return "";
  return `${String(year).padStart(4, "0")}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
}

function normalizeWidgetTodoTime(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return "";
  const match = raw.match(/^([01]\d|2[0-3]):([0-5]\d)(?::([0-5]\d))?$/);
  if (!match) return "";
  return `${match[1]}:${match[2]}`;
}

function normalizeWidgetTodoReminderPreset(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  return WIDGET_TODO_REMINDER_PRESETS.includes(raw) ? raw : "";
}

function normalizeWidgetTodoIso(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return "";
  const dt = new Date(raw);
  return Number.isFinite(dt.getTime()) ? dt.toISOString() : "";
}

function createWidgetTodoId() {
  return `t_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
}

function normalizeWidgetTodoDraftState(rawState = {}) {
  const text = String(rawState?.text || "").replace(/\s+/g, " ").trim().slice(0, WIDGET_TODO_MAX_CHARS);
  const dueDate = normalizeWidgetTodoDate(rawState?.dueDate || rawState?.due_date);
  const dueTime = dueDate ? normalizeWidgetTodoTime(rawState?.dueTime || rawState?.due_time) : "";
  const reminderPreset = dueDate
    ? normalizeWidgetTodoReminderPreset(rawState?.reminderPreset || rawState?.reminder_preset)
    : "";
  return {
    text,
    dueDate,
    dueTime,
    reminderPreset,
  };
}

function getWidgetTodoDraftState() {
  return { ...widgetTodoDraftState };
}

function patchWidgetTodoDraftState(patch = {}) {
  widgetTodoDraftState = normalizeWidgetTodoDraftState({
    ...widgetTodoDraftState,
    ...(patch && typeof patch === "object" ? patch : {}),
  });
  return getWidgetTodoDraftState();
}

function resetWidgetTodoDraftState() {
  widgetTodoEditingId = "";
  widgetTodoDraftState = normalizeWidgetTodoDraftState({});
  return getWidgetTodoDraftState();
}

function getWidgetTodoItemsFingerprint(items = []) {
  return JSON.stringify(
    normalizeWidgetTodoItems(items).map((item) => ({
      id: item.id,
      text: item.text,
      done: item.done,
      dueDate: item.dueDate,
      dueTime: item.dueTime,
      reminderPreset: item.reminderPreset,
      createdAt: item.createdAt,
      updatedAt: item.updatedAt,
      completedAt: item.completedAt,
      notifiedAt: item.notifiedAt,
    }))
  );
}

function normalizeWidgetTodoItems(rawItems) {
  if (!Array.isArray(rawItems)) return [];
  const out = [];
  const nowIso = new Date().toISOString();
  for (const row of rawItems) {
    const id = String(row?.id || row?.task_id || "").trim().slice(0, 96);
    const text = String(row?.text || "").replace(/\s+/g, " ").trim().slice(0, WIDGET_TODO_MAX_CHARS);
    if (!id || !text) continue;

    const dueDate = normalizeWidgetTodoDate(row?.dueDate || row?.due_date);
    const dueTime = dueDate ? normalizeWidgetTodoTime(row?.dueTime || row?.due_time) : "";
    const reminderPreset = dueDate
      ? normalizeWidgetTodoReminderPreset(row?.reminderPreset || row?.reminder_preset)
      : "";
    const createdAt = normalizeWidgetTodoIso(row?.createdAt || row?.created_at)
      || normalizeWidgetTodoIso(row?.updatedAt || row?.updated_at)
      || nowIso;
    const updatedAt = normalizeWidgetTodoIso(row?.updatedAt || row?.updated_at) || createdAt;
    const done = !!(row?.done ?? row?.is_done);
    const completedAt = done
      ? (normalizeWidgetTodoIso(row?.completedAt || row?.completed_at) || updatedAt)
      : "";
    const notifiedAt = normalizeWidgetTodoIso(row?.notifiedAt || row?.notified_at);

    out.push({
      id,
      text,
      done,
      dueDate,
      dueTime,
      reminderPreset,
      createdAt,
      updatedAt,
      completedAt,
      notifiedAt,
    });
    if (out.length >= WIDGET_TODO_MAX_ITEMS) break;
  }
  return out;
}

function isMissingWidgetTodoCloudTableError(error) {
  const code = String(error?.code || "").trim().toLowerCase();
  const msg = String(error?.message || "").trim().toLowerCase();
  const details = String(error?.details || "").trim().toLowerCase();
  if (!code && !msg && !details) return false;
  if (code === "42p01" || code === "pgrst205") return true;
  return (
    (msg.includes(WIDGET_TODO_CLOUD_TABLE) && (msg.includes("not exist") || msg.includes("schema cache")))
    || (details.includes(WIDGET_TODO_CLOUD_TABLE) && details.includes("not exist"))
  );
}

function ensureWidgetTodoState() {
  const key = getWidgetsDataStorageKey("todo");
  if (widgetTodoStorageKey === key) return;
  widgetTodoStorageKey = key;
  resetWidgetTodoDraftState();
  try {
    const parsed = JSON.parse(localStorage.getItem(key) || "[]");
    widgetTodoItemsCache = normalizeWidgetTodoItems(parsed);
  } catch (_) {
    widgetTodoItemsCache = [];
  }
}

function getWidgetTodoItems() {
  ensureWidgetTodoState();
  return widgetTodoItemsCache.slice();
}

function getWidgetTodoDraftText(text) {
  return String(text || "").replace(/\s+/g, " ").trim().slice(0, WIDGET_TODO_MAX_CHARS);
}

function getWidgetTodoItemById(itemId) {
  const id = String(itemId || "").trim();
  if (!id) return null;
  return getWidgetTodoItems().find((item) => item.id === id) || null;
}

function startWidgetTodoEditing(itemId) {
  const item = getWidgetTodoItemById(itemId);
  if (!item) return false;
  widgetTodoEditingId = item.id;
  widgetTodoDraftState = normalizeWidgetTodoDraftState({
    text: item.text,
    dueDate: item.dueDate,
    dueTime: item.dueTime,
    reminderPreset: item.reminderPreset,
  });
  return true;
}

function focusWidgetTodoComposerInput({ selectAll = false } = {}) {
  requestAnimationFrame(() => {
    const input = document.querySelector("[data-widget-id='checklist'] [data-widget-todo-input]");
    if (!(input instanceof HTMLInputElement)) return;
    try {
      input.focus({ preventScroll: true });
      if (selectAll && typeof input.select === "function") input.select();
    } catch (_) {}
  });
}

function reconcileWidgetTodoDraftAgainstItems(itemsInput = widgetTodoItemsCache) {
  const items = Array.isArray(itemsInput) ? itemsInput : [];
  if (!widgetTodoEditingId) return;
  const hit = items.find((item) => item.id === widgetTodoEditingId);
  if (hit) return;
  resetWidgetTodoDraftState();
}

function mergeWidgetTodoCollections(localItems = [], remoteItems = []) {
  const local = normalizeWidgetTodoItems(localItems);
  const remote = normalizeWidgetTodoItems(remoteItems);
  if (!remote.length) return local;
  if (!local.length) return remote;

  const localById = new Map(local.map((item) => [item.id, item]));
  const merged = [];
  remote.forEach((remoteItem) => {
    const localItem = localById.get(remoteItem.id);
    if (!localItem) {
      merged.push(remoteItem);
      return;
    }
    const localUpdated = Date.parse(localItem.updatedAt || localItem.createdAt || "") || 0;
    const remoteUpdated = Date.parse(remoteItem.updatedAt || remoteItem.createdAt || "") || 0;
    merged.push(localUpdated > remoteUpdated ? localItem : remoteItem);
    localById.delete(remoteItem.id);
  });
  localById.forEach((localItem) => merged.push(localItem));
  return normalizeWidgetTodoItems(merged);
}

async function writeWidgetTodoSnapshotToCloud(itemsSnapshot = getWidgetTodoItems(), { remoteIds = null } = {}) {
  const meId = normId(state?.user?.id || "");
  if (!meId) return false;
  if (widgetTodoCloudAvailable === false) return false;

  const snapshot = normalizeWidgetTodoItems(itemsSnapshot);
  let remoteIdList = Array.isArray(remoteIds)
    ? remoteIds.map((value) => String(value || "").trim()).filter(Boolean)
    : null;

  if (!remoteIdList) {
    const { data: remoteRows, error: remoteErr } = await supabase
      .from(WIDGET_TODO_CLOUD_TABLE)
      .select("task_id")
      .eq("user_id", meId);
    if (remoteErr) {
      if (isMissingWidgetTodoCloudTableError(remoteErr)) {
        widgetTodoCloudAvailable = false;
        return false;
      }
      console.warn("widget planner: cloud ids read failed", remoteErr);
      return false;
    }
    remoteIdList = (Array.isArray(remoteRows) ? remoteRows : [])
      .map((row) => String(row?.task_id || "").trim())
      .filter(Boolean);
  }

  const localIdSet = new Set(snapshot.map((item) => item.id));
  const rows = snapshot.map((item, index) => ({
    user_id: meId,
    task_id: item.id,
    sort_order: clampInt(index, 0, 255, index),
    text: item.text,
    is_done: !!item.done,
    due_date: item.dueDate || null,
    due_time: item.dueTime ? `${item.dueTime}:00` : null,
    reminder_preset: item.reminderPreset || null,
    completed_at: item.completedAt || null,
    notified_at: item.notifiedAt || null,
    created_at: item.createdAt || null,
    updated_at: item.updatedAt || null,
  }));

  if (rows.length) {
    const { error: upsertErr } = await supabase
      .from(WIDGET_TODO_CLOUD_TABLE)
      .upsert(rows, { onConflict: "user_id,task_id" });
    if (upsertErr) {
      if (isMissingWidgetTodoCloudTableError(upsertErr)) {
        widgetTodoCloudAvailable = false;
        return false;
      }
      console.warn("widget planner: cloud upsert failed", upsertErr);
      return false;
    }
  }

  const idsToDelete = remoteIdList.filter((id) => !localIdSet.has(id));
  if (idsToDelete.length) {
    const { error: deleteErr } = await supabase
      .from(WIDGET_TODO_CLOUD_TABLE)
      .delete()
      .eq("user_id", meId)
      .in("task_id", idsToDelete);
    if (deleteErr) {
      if (isMissingWidgetTodoCloudTableError(deleteErr)) {
        widgetTodoCloudAvailable = false;
        return false;
      }
      console.warn("widget planner: cloud delete failed", deleteErr);
      return false;
    }
  }

  widgetTodoCloudAvailable = true;
  widgetTodoCloudLastSyncAt = Date.now();
  return true;
}

async function syncWidgetTodoFromCloud({ force = false } = {}) {
  const meId = normId(state?.user?.id || "");
  if (!meId) return false;
  if (!force && widgetTodoCloudSyncInFlight) return widgetTodoCloudSyncInFlight;
  const nowMs = Date.now();
  if (!force && (nowMs - Number(widgetTodoCloudLastSyncAt || 0)) < WIDGET_TODO_CLOUD_SYNC_COOLDOWN_MS) return false;

  const localItems = getWidgetTodoItems();
  const localFp = getWidgetTodoItemsFingerprint(localItems);

  const run = (async () => {
    const { data, error } = await supabase
      .from(WIDGET_TODO_CLOUD_TABLE)
      .select("task_id, sort_order, text, is_done, due_date, due_time, reminder_preset, completed_at, notified_at, created_at, updated_at")
      .eq("user_id", meId)
      .order("sort_order", { ascending: true })
      .order("updated_at", { ascending: true });

    if (error) {
      if (isMissingWidgetTodoCloudTableError(error)) {
        widgetTodoCloudAvailable = false;
        widgetTodoCloudLastSyncAt = Date.now();
        return false;
      }
      console.warn("widget planner: cloud sync read failed", error);
      return false;
    }

    widgetTodoCloudAvailable = true;
    const remoteItems = normalizeWidgetTodoItems(
      (Array.isArray(data) ? data : []).map((row) => ({
        id: row?.task_id,
        text: row?.text,
        done: row?.is_done,
        dueDate: row?.due_date,
        dueTime: row?.due_time,
        reminderPreset: row?.reminder_preset,
        completedAt: row?.completed_at,
        notifiedAt: row?.notified_at,
        createdAt: row?.created_at,
        updatedAt: row?.updated_at,
      }))
    );

    const remoteIds = remoteItems.map((item) => item.id);
    const remoteFp = getWidgetTodoItemsFingerprint(remoteItems);
    const merged = mergeWidgetTodoCollections(localItems, remoteItems);
    const mergedFp = getWidgetTodoItemsFingerprint(merged);
    const localChanged = mergedFp !== localFp;
    const remoteChanged = mergedFp !== remoteFp;

    if (localChanged) saveWidgetTodoItems(merged, { syncCloud: false });
    widgetTodoCloudLastSyncAt = Date.now();

    if (remoteChanged) {
      await writeWidgetTodoSnapshotToCloud(merged, { remoteIds });
    }

    if (localChanged) {
      try { renderWidgets(); } catch (_) {}
    }
    return localChanged || remoteChanged;
  })();

  widgetTodoCloudSyncInFlight = run;
  try {
    return await run;
  } finally {
    if (widgetTodoCloudSyncInFlight === run) widgetTodoCloudSyncInFlight = null;
  }
}

function queueWidgetTodoCloudSnapshotSync(itemsSnapshot = widgetTodoItemsCache) {
  const snapshot = normalizeWidgetTodoItems(itemsSnapshot);
  widgetTodoCloudWriteQueue = widgetTodoCloudWriteQueue
    .catch(() => {})
    .then(() => writeWidgetTodoSnapshotToCloud(snapshot))
    .catch((err) => {
      console.warn("widget planner: cloud write queue failed", err);
    });
  return widgetTodoCloudWriteQueue;
}

function saveWidgetTodoItems(items, { syncCloud = true } = {}) {
  ensureWidgetTodoState();
  const previousFp = getWidgetTodoItemsFingerprint(widgetTodoItemsCache);
  const next = normalizeWidgetTodoItems(items);
  const nextFp = getWidgetTodoItemsFingerprint(next);
  widgetTodoItemsCache = next;
  reconcileWidgetTodoDraftAgainstItems(next);
  try {
    localStorage.setItem(widgetTodoStorageKey, JSON.stringify(widgetTodoItemsCache));
  } catch (_) {}
  if (syncCloud && nextFp !== previousFp) queueWidgetTodoCloudSnapshotSync(next);
  return widgetTodoItemsCache.slice();
}

function addWidgetTodoItem(text) {
  const safeText = getWidgetTodoDraftText(text);
  if (!safeText) return false;
  const current = getWidgetTodoItems();
  if (current.length >= WIDGET_TODO_MAX_ITEMS) return false;
  const nowIso = new Date().toISOString();
  current.push({
    id: createWidgetTodoId(),
    text: safeText,
    done: false,
    dueDate: "",
    dueTime: "",
    reminderPreset: "",
    createdAt: nowIso,
    updatedAt: nowIso,
    completedAt: "",
    notifiedAt: "",
  });
  saveWidgetTodoItems(current);
  return true;
}

function createWidgetTodoDateTime(dueDate, dueTime = "", { fallbackHour = 0, fallbackMinute = 0 } = {}) {
  const safeDate = normalizeWidgetTodoDate(dueDate);
  if (!safeDate) return null;
  const safeTime = normalizeWidgetTodoTime(dueTime);
  const [year, month, day] = safeDate.split("-").map((part) => Number(part));
  const [hour, minute] = safeTime
    ? safeTime.split(":").map((part) => Number(part))
    : [fallbackHour, fallbackMinute];
  const dt = new Date(year, month - 1, day, hour, minute, 0, 0);
  return Number.isFinite(dt.getTime()) ? dt : null;
}

function getWidgetTodoDueDateTime(item, { fallbackHour = 23, fallbackMinute = 59 } = {}) {
  return createWidgetTodoDateTime(item?.dueDate, item?.dueTime, { fallbackHour, fallbackMinute });
}

function getWidgetTodoReminderDateTime(item) {
  const dueDate = normalizeWidgetTodoDate(item?.dueDate);
  const reminderPreset = normalizeWidgetTodoReminderPreset(item?.reminderPreset);
  if (!dueDate || !reminderPreset) return null;
  const base = createWidgetTodoDateTime(dueDate, item?.dueTime, { fallbackHour: 9, fallbackMinute: 0 });
  if (!base) return null;
  const reminderAt = new Date(base.getTime());
  if (reminderPreset === "day_start") {
    reminderAt.setHours(9, 0, 0, 0);
    return reminderAt;
  }
  if (reminderPreset === "1d") reminderAt.setDate(reminderAt.getDate() - 1);
  else if (reminderPreset === "1h") reminderAt.setHours(reminderAt.getHours() - 1);
  else if (reminderPreset === "15m") reminderAt.setMinutes(reminderAt.getMinutes() - 15);
  return reminderAt;
}

function getWidgetTodoTodayDateKey(nowInput = new Date()) {
  const dt = nowInput instanceof Date ? nowInput : new Date(nowInput);
  const year = dt.getFullYear();
  const month = String(dt.getMonth() + 1).padStart(2, "0");
  const day = String(dt.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function getWidgetTodoDiffDays(dueDate, nowInput = new Date()) {
  const target = createWidgetTodoDateTime(dueDate, "", { fallbackHour: 12, fallbackMinute: 0 });
  const now = nowInput instanceof Date ? nowInput : new Date(nowInput);
  const base = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 12, 0, 0, 0);
  if (!target) return Number.NaN;
  return Math.round((target.getTime() - base.getTime()) / 86400000);
}

function formatWidgetTodoDateLabel(dueDate, { compact = false } = {}) {
  const dt = createWidgetTodoDateTime(dueDate, "", { fallbackHour: 12, fallbackMinute: 0 });
  if (!dt) return "";
  const { locale } = getMessageLocaleContext();
  return compact
    ? dt.toLocaleDateString(locale, { day: "numeric", month: "short" })
    : dt.toLocaleDateString(locale, { weekday: "short", day: "numeric", month: "short" });
}

function formatWidgetTodoTimeLabel(dueTime) {
  const safeTime = normalizeWidgetTodoTime(dueTime);
  if (!safeTime) return "";
  const [hour, minute] = safeTime.split(":").map((part) => Number(part));
  const dt = new Date();
  dt.setHours(hour, minute, 0, 0);
  const { locale, hour12 } = getMessageLocaleContext();
  return dt.toLocaleTimeString(locale, { hour: "2-digit", minute: "2-digit", hour12 });
}

function formatWidgetTodoReminderLabel(reminderPreset) {
  const preset = normalizeWidgetTodoReminderPreset(reminderPreset);
  if (!preset) return "";
  if (preset === "day_start") return t("widget.todo.reminder.day_start", "Morning of");
  if (preset === "at_time") return t("widget.todo.reminder.at_time", "At deadline");
  if (preset === "15m") return t("widget.todo.reminder.15m", "15 min before");
  if (preset === "1h") return t("widget.todo.reminder.1h", "1 hour before");
  if (preset === "1d") return t("widget.todo.reminder.1d", "1 day before");
  return "";
}

function getWidgetTodoRelativeDayLabel(dueDate, nowInput = new Date()) {
  const diffDays = getWidgetTodoDiffDays(dueDate, nowInput);
  if (!Number.isFinite(diffDays)) return "";
  if (diffDays === 0) return t("widget.calendar.today", "Today");
  if (diffDays === 1) return t("widget.calendar.tomorrow", "Tomorrow");
  if (diffDays === -1) return t("widget.todo.yesterday", "Yesterday");
  if (diffDays > -6 && diffDays < 6) {
    const dt = createWidgetTodoDateTime(dueDate, "", { fallbackHour: 12, fallbackMinute: 0 });
    const { locale } = getMessageLocaleContext();
    return dt ? dt.toLocaleDateString(locale, { weekday: "short" }) : "";
  }
  return formatWidgetTodoDateLabel(dueDate, { compact: true });
}

function getWidgetTodoScheduleMeta(item, nowInput = new Date()) {
  const dueDate = normalizeWidgetTodoDate(item?.dueDate);
  if (!dueDate) {
    return {
      hasSchedule: false,
      dateKey: "",
      dueMoment: null,
      dueMomentMs: 0,
      reminderAt: null,
      reminderText: "",
      shortLabel: "",
      fullLabel: "",
      chipLabel: "",
      isToday: false,
      isTomorrow: false,
      isOverdue: false,
      isDueSoon: false,
    };
  }

  const now = nowInput instanceof Date ? nowInput : new Date(nowInput);
  const dueMoment = getWidgetTodoDueDateTime(item);
  const dueMomentMs = dueMoment ? dueMoment.getTime() : 0;
  const reminderAt = getWidgetTodoReminderDateTime(item);
  const reminderText = formatWidgetTodoReminderLabel(item?.reminderPreset);
  const relativeLabel = getWidgetTodoRelativeDayLabel(dueDate, now);
  const absoluteLabel = formatWidgetTodoDateLabel(dueDate);
  const timeLabel = formatWidgetTodoTimeLabel(item?.dueTime);
  const shortLabel = timeLabel ? `${relativeLabel} ${timeLabel}` : relativeLabel;
  const fullLabel = timeLabel ? `${absoluteLabel} ${timeLabel}` : absoluteLabel;
  const diffDays = getWidgetTodoDiffDays(dueDate, now);
  const isToday = diffDays === 0;
  const isTomorrow = diffDays === 1;
  const isPastDate = diffDays < 0;
  const isPastTimed = !!item?.dueTime && dueMomentMs > 0 && dueMomentMs < now.getTime();
  const isOverdue = !item?.done && (isPastDate || isPastTimed);
  const dueSoonMs = dueMomentMs > now.getTime() ? (dueMomentMs - now.getTime()) : 0;
  const isDueSoon = !item?.done && !isOverdue && dueSoonMs > 0 && dueSoonMs <= (2 * 60 * 60 * 1000);
  const chipLabel = isOverdue
    ? t("widget.todo.badge.overdue", "Overdue")
    : isToday
    ? t("widget.todo.badge.today", "Today")
    : isTomorrow
    ? t("widget.todo.badge.tomorrow", "Tomorrow")
    : "";

  return {
    hasSchedule: true,
    dateKey: dueDate,
    dueMoment,
    dueMomentMs,
    reminderAt,
    reminderText,
    shortLabel,
    fullLabel,
    chipLabel,
    isToday,
    isTomorrow,
    isOverdue,
    isDueSoon,
  };
}

function compareWidgetTodoItemsBySchedule(a, b) {
  const aMeta = getWidgetTodoScheduleMeta(a);
  const bMeta = getWidgetTodoScheduleMeta(b);
  if (aMeta.hasSchedule && bMeta.hasSchedule) {
    if (aMeta.dueMomentMs !== bMeta.dueMomentMs) return aMeta.dueMomentMs - bMeta.dueMomentMs;
  } else if (aMeta.hasSchedule) {
    return -1;
  } else if (bMeta.hasSchedule) {
    return 1;
  }
  const aCreated = Date.parse(a?.createdAt || "") || 0;
  const bCreated = Date.parse(b?.createdAt || "") || 0;
  return aCreated - bCreated;
}

function getWidgetTodoScheduledOpenItems(items = getWidgetTodoItems()) {
  return normalizeWidgetTodoItems(items)
    .filter((item) => !item.done && normalizeWidgetTodoDate(item.dueDate))
    .sort(compareWidgetTodoItemsBySchedule);
}

function getWidgetTodoSummary(items = getWidgetTodoItems(), nowInput = new Date()) {
  const todos = normalizeWidgetTodoItems(items);
  let dueToday = 0;
  let overdue = 0;
  let scheduled = 0;
  todos.forEach((item) => {
    if (item.done || !item.dueDate) return;
    scheduled += 1;
    const meta = getWidgetTodoScheduleMeta(item, nowInput);
    if (meta.isOverdue) overdue += 1;
    else if (meta.isToday) dueToday += 1;
  });
  return { dueToday, overdue, scheduled };
}

function getWidgetTodoComposerPayload() {
  return normalizeWidgetTodoDraftState(widgetTodoDraftState);
}

function maybePromptWidgetReminderPermission(item) {
  if (!item?.dueDate || !item?.reminderPreset) return;
  void ensureWidgetReminderNotificationPermission({ prompt: true });
}

function buildWidgetTodoItemFromDraft(existingItem = null) {
  const draft = getWidgetTodoComposerPayload();
  if (!draft.text) return null;
  const nowIso = new Date().toISOString();
  const current = existingItem && typeof existingItem === "object" ? existingItem : null;
  const reminderChanged = !!current && (
    current.dueDate !== draft.dueDate
    || current.dueTime !== draft.dueTime
    || current.reminderPreset !== draft.reminderPreset
  );

  return normalizeWidgetTodoItems([{
    id: current?.id || createWidgetTodoId(),
    text: draft.text,
    done: !!current?.done,
    dueDate: draft.dueDate,
    dueTime: draft.dueTime,
    reminderPreset: draft.reminderPreset,
    createdAt: current?.createdAt || nowIso,
    updatedAt: nowIso,
    completedAt: current?.done ? (current?.completedAt || nowIso) : "",
    notifiedAt: reminderChanged ? "" : (current?.notifiedAt || ""),
  }])[0] || null;
}

function submitWidgetTodoDraft() {
  const draft = getWidgetTodoComposerPayload();
  if (!draft.text) {
    showWidgetChecklistToast(t("widgets.todo.name_required", "Type a task name."), "warn");
    focusWidgetTodoComposerInput();
    return false;
  }

  const currentItems = getWidgetTodoItems();
  const editingItem = widgetTodoEditingId
    ? currentItems.find((item) => item.id === widgetTodoEditingId) || null
    : null;
  if (!editingItem && currentItems.length >= WIDGET_TODO_MAX_ITEMS) {
    showWidgetChecklistToast(
      tf("widgets.todo.limit_toast", { max: WIDGET_TODO_MAX_ITEMS }, `Checklist limit reached (${WIDGET_TODO_MAX_ITEMS}).`),
      "warn"
    );
    return false;
  }

  const nextItem = buildWidgetTodoItemFromDraft(editingItem);
  if (!nextItem) return false;

  const nextItems = editingItem
    ? currentItems.map((item) => (item.id === editingItem.id ? nextItem : item))
    : [...currentItems, nextItem];
  saveWidgetTodoItems(nextItems);
  maybePromptWidgetReminderPermission(nextItem);
  resetWidgetTodoDraftState();
  renderWidgets();
  focusWidgetTodoComposerInput();
  return true;
}

function toggleWidgetTodoItem(itemId) {
  const id = String(itemId || "").trim();
  if (!id) return;
  const current = getWidgetTodoItems();
  const nowIso = new Date().toISOString();
  const next = current.map((item) => {
    if (item.id !== id) return item;
    const done = !item.done;
    return {
      ...item,
      done,
      updatedAt: nowIso,
      completedAt: done ? nowIso : "",
    };
  });
  saveWidgetTodoItems(next);
  maybeCelebrateWidgetTodoCompletion(current, next);
}

function removeWidgetTodoItem(itemId) {
  const id = String(itemId || "").trim();
  if (!id) return;
  const current = getWidgetTodoItems();
  const next = current.filter((item) => item.id !== id);
  saveWidgetTodoItems(next);
  maybeCelebrateWidgetTodoCompletion(current, next);
}

function clearWidgetTodoDoneItems() {
  const current = getWidgetTodoItems();
  saveWidgetTodoItems(current.filter((item) => !item.done));
}

function moveWidgetTodoItem(itemId, direction = 1) {
  const id = String(itemId || "").trim();
  if (!id) return false;
  const current = getWidgetTodoItems();
  const fromIdx = current.findIndex((item) => item.id === id);
  if (fromIdx < 0) return false;
  const toIdx = Math.max(0, Math.min(current.length - 1, fromIdx + (direction >= 0 ? 1 : -1)));
  if (toIdx === fromIdx) return false;
  const next = current.slice();
  const [moved] = next.splice(fromIdx, 1);
  next.splice(toIdx, 0, moved);
  saveWidgetTodoItems(next);
  return true;
}

function renameWidgetTodoItem(itemId, nextText) {
  const id = String(itemId || "").trim();
  if (!id) return false;
  const safeText = String(nextText || "").replace(/\s+/g, " ").trim().slice(0, WIDGET_TODO_MAX_CHARS);
  if (!safeText) return false;
  const current = getWidgetTodoItems();
  const nowIso = new Date().toISOString();
  const next = current.map((item) => (
    item.id === id
      ? { ...item, text: safeText, updatedAt: nowIso }
      : item
  ));
  saveWidgetTodoItems(next);
  return true;
}

async function ensureWidgetReminderNotificationPermission({ prompt = false } = {}) {
  if (typeof Notification === "undefined") return false;
  if (Notification.permission === "granted") return true;
  if (!prompt || Notification.permission === "denied") return false;
  if (widgetReminderNotificationPermissionAsked) return false;
  widgetReminderNotificationPermissionAsked = true;
  try {
    const result = await Notification.requestPermission();
    return result === "granted";
  } catch (_) {
    return false;
  }
}

function openPlannerFromReminder() {
  try { activateMainTab("widgets"); } catch (_) {}
  try { window.focus(); } catch (_) {}
}

function fireWidgetReminderNotification(item, scheduleMeta) {
  const title = t("widget.todo.reminder.title", "Task reminder");
  const body = scheduleMeta?.fullLabel
    ? `${item.text} ${String.fromCharCode(183)} ${scheduleMeta.fullLabel}`
    : item.text;

  showWidgetChecklistToast(`${t("widget.todo.reminder.toast", "Reminder")}: ${item.text}`, "warn");
  playUiCue("msg");

  if (typeof Notification === "undefined" || Notification.permission !== "granted") return;
  try {
    const notification = new Notification(title, {
      body,
      tag: `widget-task-${item.id}`,
      renotify: true,
    });
    notification.onclick = () => openPlannerFromReminder();
  } catch (_) {}
}

function runWidgetReminderMonitor() {
  const now = new Date();
  const nowMs = now.getTime();
  const current = getWidgetTodoItems();
  let changed = false;

  const next = current.map((item) => {
    if (item.done || !item.dueDate || !item.reminderPreset) return item;
    const reminderAt = getWidgetTodoReminderDateTime(item);
    if (!reminderAt) return item;
    const reminderMs = reminderAt.getTime();
    if (!Number.isFinite(reminderMs)) return item;
    if (reminderMs > nowMs) return item;
    if ((nowMs - reminderMs) > WIDGET_TODO_REMINDER_STALE_MS) return item;
    const notifiedMs = Date.parse(item.notifiedAt || "") || 0;
    if (notifiedMs && notifiedMs >= reminderMs) return item;
    changed = true;
    fireWidgetReminderNotification(item, getWidgetTodoScheduleMeta(item, now));
    return {
      ...item,
      notifiedAt: now.toISOString(),
      updatedAt: now.toISOString(),
    };
  });

  if (changed) saveWidgetTodoItems(next);
}

function bindWidgetReminderMonitorOnce() {
  if (widgetReminderMonitorBound) return;
  widgetReminderMonitorBound = true;
  window.addEventListener("focus", () => {
    runWidgetReminderMonitor();
    void syncWidgetTodoFromCloud({ force: false }).catch(() => false);
  });
  document.addEventListener("visibilitychange", () => {
    if (document.visibilityState !== "visible") return;
    runWidgetReminderMonitor();
    void syncWidgetTodoFromCloud({ force: false }).catch(() => false);
  });
}

function startWidgetReminderMonitor() {
  bindWidgetReminderMonitorOnce();
  if (widgetReminderMonitorTimer) clearInterval(widgetReminderMonitorTimer);
  widgetReminderMonitorTimer = window.setInterval(() => {
    runWidgetReminderMonitor();
  }, WIDGET_TODO_REMINDER_SCAN_MS);
  runWidgetReminderMonitor();
}

function buildWidgetCalendarModel(nowInput = new Date()) {
  const now = nowInput instanceof Date ? nowInput : new Date();
  const locale = getWidgetCalendarLocale();
  const weekStartsOnMonday = locale.toLowerCase().startsWith("pt");
  const year = now.getFullYear();
  const monthIdx = now.getMonth();
  const day = now.getDate();

  const monthLabel = new Intl.DateTimeFormat(locale, { month: "long" }).format(now);
  const monthShort = new Intl.DateTimeFormat(locale, { month: "short" }).format(now);
  const weekdayLong = new Intl.DateTimeFormat(locale, { weekday: "long" }).format(now);
  const weekdayShort = new Intl.DateTimeFormat(locale, { weekday: "short" }).format(now);

  const firstOfMonth = new Date(year, monthIdx, 1);
  const firstWeekdayJs = firstOfMonth.getDay();
  const firstWeekday = weekStartsOnMonday ? ((firstWeekdayJs + 6) % 7) : firstWeekdayJs;
  const daysInMonth = new Date(year, monthIdx + 1, 0).getDate();
  const daysInPrevMonth = new Date(year, monthIdx, 0).getDate();
  const totalCells = Math.ceil((firstWeekday + daysInMonth) / 7) * 7;
  const scheduledTodos = getWidgetTodoScheduledOpenItems();
  const scheduleBuckets = new Map();

  scheduledTodos.forEach((item) => {
    const meta = getWidgetTodoScheduleMeta(item, now);
    if (!meta.hasSchedule) return;
    const bucket = scheduleBuckets.get(meta.dateKey) || { count: 0, overdueCount: 0 };
    bucket.count += 1;
    if (meta.isOverdue) bucket.overdueCount += 1;
    scheduleBuckets.set(meta.dateKey, bucket);
  });

  const cells = [];
  for (let idx = 0; idx < totalCells; idx += 1) {
    const cellOffset = idx - firstWeekday;
    if (cellOffset >= 0 && cellOffset < daysInMonth) {
      const value = cellOffset + 1;
      const dateKey = `${year}-${String(monthIdx + 1).padStart(2, "0")}-${String(value).padStart(2, "0")}`;
      const bucket = scheduleBuckets.get(dateKey);
      cells.push({
        day: value,
        dateKey,
        inMonth: true,
        isToday: value === day,
        taskCount: Number(bucket?.count || 0),
        hasTasks: Number(bucket?.count || 0) > 0,
        isOverdue: Number(bucket?.overdueCount || 0) > 0,
      });
      continue;
    }

    if (cellOffset < 0) {
      const prevDay = daysInPrevMonth + cellOffset + 1;
      const prevMonthDate = new Date(year, monthIdx - 1, prevDay);
      const dateKey = getWidgetTodoTodayDateKey(prevMonthDate);
      const bucket = scheduleBuckets.get(dateKey);
      cells.push({
        day: prevDay,
        dateKey,
        inMonth: false,
        isToday: false,
        taskCount: Number(bucket?.count || 0),
        hasTasks: Number(bucket?.count || 0) > 0,
        isOverdue: Number(bucket?.overdueCount || 0) > 0,
      });
      continue;
    }

    const nextDay = cellOffset - daysInMonth + 1;
    const nextMonthDate = new Date(year, monthIdx + 1, nextDay);
    const dateKey = getWidgetTodoTodayDateKey(nextMonthDate);
    const bucket = scheduleBuckets.get(dateKey);
    cells.push({
      day: nextDay,
      dateKey,
      inMonth: false,
      isToday: false,
      taskCount: Number(bucket?.count || 0),
      hasTasks: Number(bucket?.count || 0) > 0,
      isOverdue: Number(bucket?.overdueCount || 0) > 0,
    });
  }

  const weekdayLabels = getWidgetCalendarWeekdayLabels(locale, { weekStartsOnMonday });
  const summary = getWidgetTodoSummary(scheduledTodos, now);
  const todaySummary = summary.dueToday > 0
    ? tf(
      "widget.calendar.summary.today_count",
      { count: summary.dueToday },
      summary.dueToday === 1 ? "1 task due today" : `${summary.dueToday} tasks due today`
    )
    : summary.overdue > 0
    ? tf(
      "widget.calendar.summary.overdue_count",
      { count: summary.overdue },
      summary.overdue === 1 ? "1 overdue task" : `${summary.overdue} overdue tasks`
    )
    : t("widget.calendar.no_events_today", "No events today");

  const agenda = scheduledTodos.slice(0, 5).map((item) => {
    const meta = getWidgetTodoScheduleMeta(item, now);
    return {
      id: item.id,
      label: meta.chipLabel || getWidgetTodoRelativeDayLabel(item.dueDate, now),
      day: createWidgetTodoDateTime(item.dueDate, "", { fallbackHour: 12, fallbackMinute: 0 })?.getDate() || "",
      title: item.text,
      dueLabel: meta.fullLabel,
      reminderLabel: meta.reminderText,
      isOverdue: meta.isOverdue,
    };
  });

  return {
    locale,
    year,
    day,
    monthLabel: String(monthLabel || "").trim(),
    monthShort: String(monthShort || "").trim(),
    weekdayLong: String(weekdayLong || "").trim(),
    weekdayShort: String(weekdayShort || "").trim(),
    todaySummary,
    scheduledCount: summary.scheduled,
    weekdayLabels,
    cells,
    agenda,
  };
}

async function setWidgetStatus(statusInput) {
  await setMyPresenceStatusEverywhere(statusInput, { persistAccount: true });
}

function getDefaultWidgetSize(widgetId) {
  const id = String(widgetId || "").trim();
  const fallback = "md";
  const fromMap = String(WIDGET_SIZE_DEFAULTS[id] || fallback).trim();
  const allowed = getWidgetAllowedSizes(id);
  if (allowed.includes(fromMap)) return fromMap;
  if (allowed.includes(fallback)) return fallback;
  return allowed[0] || fallback;
}

function getWidgetAllowedSizes(widgetId) {
  const id = String(widgetId || "").trim();
  const fromMap = Array.isArray(WIDGET_ALLOWED_SIZES[id]) ? WIDGET_ALLOWED_SIZES[id] : null;
  const allowed = (fromMap || WIDGET_SIZE_ORDER)
    .map((size) => String(size || "").trim().toLowerCase())
    .filter((size) => WIDGET_SIZE_ORDER.includes(size));
  if (allowed.length) return allowed;
  return WIDGET_SIZE_ORDER.slice();
}

function normalizeWidgetSize(sizeInput, fallback = "md") {
  const contextId = String(fallback || "").trim();
  const allowed = getWidgetAllowedSizes(contextId);
  const size = String(sizeInput || "").trim().toLowerCase();
  if (allowed.includes(size)) return size;
  const def = getDefaultWidgetSize(contextId || "md");
  if (allowed.includes(def)) return def;
  return allowed[0] || "md";
}

function getWidgetHighlightedSize(sizeInput) {
  const size = normalizeWidgetSize(sizeInput);
  if (size === "sm") return "md";
  if (size === "md") return "lg";
  if (size === "lg") return "xl";
  return "xl";
}

function normalizeWidgetsLayout(raw) {
  const enabled = Object.fromEntries(WIDGET_IDS.map((id) => [id, true]));
  const sizes = Object.fromEntries(WIDGET_IDS.map((id) => [id, getDefaultWidgetSize(id)]));
  const positions = {};
  const highlighted = Object.fromEntries(WIDGET_IDS.map((id) => [id, false]));
  if (raw?.enabled && typeof raw.enabled === "object") {
    WIDGET_IDS.forEach((id) => {
      if (typeof raw.enabled[id] === "boolean") enabled[id] = raw.enabled[id];
    });
  }
  if (raw?.sizes && typeof raw.sizes === "object") {
    WIDGET_IDS.forEach((id) => {
      sizes[id] = normalizeWidgetSize(raw.sizes[id], id);
    });
  }
  // Legacy pinned positions are ignored to keep grid packing stable and gap-free.
  if (raw?.highlighted && typeof raw.highlighted === "object") {
    WIDGET_IDS.forEach((id) => {
      if (typeof raw.highlighted[id] === "boolean") highlighted[id] = raw.highlighted[id];
    });
  }

  const order = [];
  if (Array.isArray(raw?.order)) {
    raw.order.forEach((id) => {
      const key = String(id || "").trim();
      if (!WIDGET_IDS.includes(key) || !enabled[key] || order.includes(key)) return;
      order.push(key);
    });
  }

  WIDGET_IDS.forEach((id) => {
    if (!enabled[id] || order.includes(id)) return;
    order.push(id);
  });

  return { order, enabled, sizes, positions, highlighted };
}

function loadWidgetsLayoutState() {
  const key = getWidgetsLayoutStorageKey();
  widgetsLayoutStorageKey = key;
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return normalizeWidgetsLayout(null);
    const parsed = JSON.parse(raw);
    return normalizeWidgetsLayout(parsed);
  } catch (_) {
    return normalizeWidgetsLayout(null);
  }
}

function saveWidgetsLayoutState() {
  if (!widgetsLayoutState) return;
  try {
    localStorage.setItem(getWidgetsLayoutStorageKey(), JSON.stringify(widgetsLayoutState));
  } catch (_) {}
}

function ensureWidgetsLayoutState() {
  const key = getWidgetsLayoutStorageKey();
  if (!widgetsLayoutState || widgetsLayoutStorageKey !== key) {
    widgetsLayoutState = loadWidgetsLayoutState();
    saveWidgetsLayoutState();
  }
}

function setWidgetEnabled(widgetId, enabled) {
  ensureWidgetsLayoutState();
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return;

  widgetsLayoutState.enabled[id] = !!enabled;
  widgetsLayoutState.sizes = widgetsLayoutState.sizes || {};
  widgetsLayoutState.positions = widgetsLayoutState.positions || {};
  if (!widgetsLayoutState.sizes[id]) {
    widgetsLayoutState.sizes[id] = getDefaultWidgetSize(id);
  }
  widgetsLayoutState.order = widgetsLayoutState.order.filter((x) => x !== id);
  if (enabled) widgetsLayoutState.order.push(id);
  if (!enabled) delete widgetsLayoutState.positions[id];
  saveWidgetsLayoutState();
}

function getWidgetSize(widgetId) {
  ensureWidgetsLayoutState();
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return "md";
  return normalizeWidgetSize(widgetsLayoutState?.sizes?.[id], id);
}

function setWidgetSize(widgetId, sizeInput) {
  ensureWidgetsLayoutState();
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return;
  widgetsLayoutState.sizes = widgetsLayoutState.sizes || {};
  widgetsLayoutState.sizes[id] = normalizeWidgetSize(sizeInput, id);
  saveWidgetsLayoutState();
}

function isWidgetHighlighted(widgetId) {
  ensureWidgetsLayoutState();
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return false;
  return !!widgetsLayoutState?.highlighted?.[id];
}

function setWidgetHighlighted(widgetId, highlightedInput) {
  ensureWidgetsLayoutState();
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return false;
  widgetsLayoutState.highlighted = widgetsLayoutState.highlighted || {};
  const next = !!highlightedInput;
  widgetsLayoutState.highlighted[id] = next;
  saveWidgetsLayoutState();
  return next;
}

function toggleWidgetHighlighted(widgetId) {
  const current = isWidgetHighlighted(widgetId);
  return setWidgetHighlighted(widgetId, !current);
}

function setExclusiveWidgetHighlighted(widgetId) {
  ensureWidgetsLayoutState();
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return false;
  widgetsLayoutState.highlighted = widgetsLayoutState.highlighted || {};
  const nextActive = !widgetsLayoutState.highlighted[id];
  WIDGET_IDS.forEach((wid) => {
    widgetsLayoutState.highlighted[wid] = false;
  });
  if (nextActive) widgetsLayoutState.highlighted[id] = true;
  saveWidgetsLayoutState();
  return nextActive;
}

function getWidgetPinnedPosition(widgetId) {
  ensureWidgetsLayoutState();
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return null;
  const row = widgetsLayoutState?.positions?.[id];
  if (!row || typeof row !== "object") return null;
  return {
    col: clampInt(row.col, 1, 12, 1),
    row: clampInt(row.row, 1, 999, 1),
  };
}

function setWidgetPinnedPosition(widgetId, colInput, rowInput, { prioritize = true } = {}) {
  ensureWidgetsLayoutState();
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return;
  widgetsLayoutState.positions = widgetsLayoutState.positions || {};
  widgetsLayoutState.positions[id] = {
    col: clampInt(colInput, 1, 12, 1),
    row: clampInt(rowInput, 1, 999, 1),
  };
  if (prioritize && Array.isArray(widgetsLayoutState.order)) {
    widgetsLayoutState.order = widgetsLayoutState.order.filter((x) => x !== id);
    widgetsLayoutState.order.unshift(id);
  }
  saveWidgetsLayoutState();
}

function getActiveWidgetIds() {
  ensureWidgetsLayoutState();
  const active = (widgetsLayoutState?.order || [])
    .filter((id) => WIDGET_IDS.includes(String(id || "").trim()))
    .filter((id) => widgetsLayoutState?.enabled?.[id]);
  if (active.length) return active;
  return WIDGET_IDS.filter((id) => widgetsLayoutState?.enabled?.[id] !== false);
}

function shiftWidgetSize(widgetId, direction = 1) {
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return false;
  const allowed = getWidgetAllowedSizes(id);
  if (allowed.length <= 1) return false;
  const current = getWidgetSize(id);
  const idx = allowed.indexOf(current);
  if (idx < 0) return false;
  const nextIdx = Math.max(0, Math.min(allowed.length - 1, idx + (direction >= 0 ? 1 : -1)));
  if (nextIdx === idx) return false;
  setWidgetSize(id, allowed[nextIdx]);
  return true;
}

function getWidgetsGridMetrics() {
  const grid = $("widgetsGrid");
  if (!grid) return { grid: null, colCount: 4, colGap: 12, rowGap: 12, cellWidth: 220, cellHeight: 164 };
  const styles = getComputedStyle(grid);
  const cols = String(styles.gridTemplateColumns || "")
    .split(" ")
    .map((x) => x.trim())
    .filter(Boolean);
  const colCount = Math.max(1, cols.length || 4);
  const colGap = Number.parseFloat(styles.columnGap || styles.gap || "12") || 12;
  const rowGap = Number.parseFloat(styles.rowGap || styles.gap || "12") || 12;
  const rect = grid.getBoundingClientRect();
  const width = rect.width || grid.clientWidth || (colCount * 220);
  const cellWidth = Math.max(120, (width - (colGap * (colCount - 1))) / colCount);
  const varRowSize = Number.parseFloat(styles.getPropertyValue("--widgets-row-size") || "");
  const autoRowSize = Number.parseFloat(styles.gridAutoRows || "");
  const cellHeight = Math.max(120, varRowSize || autoRowSize || 164);
  return { grid, colCount, colGap, rowGap, cellWidth, cellHeight };
}

function getWidgetSizeDimensions(sizeInput, colCountInput) {
  const size = normalizeWidgetSize(sizeInput);
  const colCount = Math.max(1, Number(colCountInput) || 4);
  if (colCount <= 1) return { cols: 1, rows: 1 };
  const dims = {
    sm: { cols: 1, rows: 1 },
    md: { cols: Math.min(2, colCount), rows: 1 },
    lg: { cols: Math.min(2, colCount), rows: 2 },
    xl: { cols: Math.min(4, colCount), rows: 3 },
  };
  return dims[size] || dims.md;
}

function getWidgetSizePreviewText(widgetId, sizeInput, colCountInput) {
  const id = String(widgetId || "").trim();
  const size = normalizeWidgetSize(sizeInput, id || "md");
  const colCount = Math.max(1, Number(colCountInput) || 4);
  const dims = getWidgetSizeDimensions(size, colCount);
  const sizeLabel = WIDGET_SIZE_LABELS[size] || size.toUpperCase();
  return `${sizeLabel} ${dims.cols}x${dims.rows}`;
}

function canPlaceWidgetInGrid(occupiedSet, col, row, cols, rows, colCount) {
  if (!occupiedSet) return false;
  if (col < 1 || row < 1 || cols < 1 || rows < 1) return false;
  if ((col + cols - 1) > colCount) return false;
  for (let r = row; r < row + rows; r += 1) {
    for (let c = col; c < col + cols; c += 1) {
      if (occupiedSet.has(`${c}:${r}`)) return false;
    }
  }
  return true;
}

function occupyWidgetGridCells(occupiedSet, col, row, cols, rows) {
  if (!occupiedSet) return;
  for (let r = row; r < row + rows; r += 1) {
    for (let c = col; c < col + cols; c += 1) {
      occupiedSet.add(`${c}:${r}`);
    }
  }
}

function findFirstWidgetGridSlot(occupiedSet, cols, rows, colCount, startRow = 1) {
  const maxRow = 999;
  const firstRow = Math.max(1, Number(startRow) || 1);
  for (let row = firstRow; row <= maxRow; row += 1) {
    const maxColStart = Math.max(1, colCount - cols + 1);
    for (let col = 1; col <= maxColStart; col += 1) {
      if (canPlaceWidgetInGrid(occupiedSet, col, row, cols, rows, colCount)) {
        return { col, row };
      }
    }
  }
  return { col: 1, row: firstRow };
}

function computeWidgetGridPlacements(activeIds, colCountInput, options = {}) {
  const ids = Array.isArray(activeIds) ? activeIds.slice() : [];
  const colCount = Math.max(1, Number(colCountInput) || 4);
  const sizeOverrides = options && typeof options === "object" && options.sizeOverrides && typeof options.sizeOverrides === "object"
    ? options.sizeOverrides
    : null;
  const occupied = new Set();
  const placements = {};

  ids.forEach((id) => {
    const sizeId = sizeOverrides && Object.prototype.hasOwnProperty.call(sizeOverrides, id)
      ? normalizeWidgetSize(sizeOverrides[id], id)
      : getWidgetSize(id);
    const dims = getWidgetSizeDimensions(sizeId, colCount);
    const slot = findFirstWidgetGridSlot(occupied, dims.cols, dims.rows, colCount, 1);
    placements[id] = {
      col: slot.col,
      row: slot.row,
      cols: dims.cols,
      rows: dims.rows,
      size: sizeId,
    };
    occupyWidgetGridCells(occupied, slot.col, slot.row, dims.cols, dims.rows);
  });

  return placements;
}

function applyWidgetGridPlacements(grid, activeIds, colCountInput, options = {}) {
  if (!grid) return;
  const placements = options && typeof options === "object" && options.placements && typeof options.placements === "object"
    ? options.placements
    : computeWidgetGridPlacements(activeIds, colCountInput, options);
  const cardById = new Map();
  grid.querySelectorAll(".widgetCard[data-widget-id]").forEach((card) => {
    const id = String(card.getAttribute("data-widget-id") || "").trim();
    if (id) cardById.set(id, card);
  });

  cardById.forEach((card) => {
    card.style.removeProperty("grid-column");
    card.style.removeProperty("grid-row");
  });

  Object.entries(placements).forEach(([id, slot]) => {
    const card = cardById.get(id);
    if (!card || !slot) return;
    const col = Math.max(1, Number(slot.col) || 1);
    const row = Math.max(1, Number(slot.row) || 1);
    const cols = Math.max(1, Number(slot.cols) || 1);
    const rows = Math.max(1, Number(slot.rows) || 1);
    card.style.gridColumn = `${col} / span ${cols}`;
    card.style.gridRow = `${row} / span ${rows}`;
    if (slot.size) applyWidgetCardSizeClass(card, slot.size);
  });
}

function pickWidgetSizeFromDims(targetColsInput, targetRowsInput, colCountInput, widgetId = "") {
  const colCount = Math.max(1, Number(colCountInput) || 4);
  const targetCols = Math.max(1, Math.min(colCount, Math.round(Number(targetColsInput) || 1)));
  const targetRows = Math.max(1, Math.round(Number(targetRowsInput) || 1));
  const candidates = getWidgetAllowedSizes(widgetId);
  let bestId = candidates[0] || "md";
  let bestScore = Number.POSITIVE_INFINITY;
  for (const id of candidates) {
    const dims = getWidgetSizeDimensions(id, colCount);
    const score = (Math.abs(dims.cols - targetCols) * 3) + Math.abs(dims.rows - targetRows);
    if (score < bestScore) {
      bestScore = score;
      bestId = id;
    }
  }
  return bestId;
}

function applyWidgetCardSizeClass(card, sizeInput) {
  if (!card) return;
  const widgetId = String(card.getAttribute?.("data-widget-id") || "").trim();
  const normalizedSize = widgetId
    ? normalizeWidgetSize(sizeInput, widgetId)
    : normalizeWidgetSize(sizeInput);
  WIDGET_SIZE_CLASS_NAMES.forEach((cls) => card.classList.remove(cls));
  card.classList.add(`widgetCard--size-${normalizedSize}`);
}

function prefersReducedMotion() {
  return prefersReducedMotionUi();
}

function captureWidgetCardRects(grid) {
  const map = new Map();
  if (!grid) return map;
  grid.querySelectorAll(".widgetCard[data-widget-id]").forEach((card) => {
    const id = String(card.getAttribute("data-widget-id") || "").trim();
    if (!id) return;
    const rect = card.getBoundingClientRect();
    if (!rect || rect.width <= 0 || rect.height <= 0) return;
    map.set(id, {
      left: rect.left,
      top: rect.top,
      width: rect.width,
      height: rect.height,
    });
  });
  return map;
}

function animateWidgetLayoutFromRects(grid, beforeRects, options = {}) {
  if (!grid || !(beforeRects instanceof Map) || !beforeRects.size) return;
  if (prefersReducedMotion()) return;

  const duration = Math.max(140, Number(options.duration) || 300);
  const easing = String(options.easing || "cubic-bezier(0.22, 1, 0.36, 1)");
  const includeEnter = options.includeEnter !== false;
  const cards = Array.from(grid.querySelectorAll(".widgetCard[data-widget-id]"));
  if (!cards.length) return;

  cards.forEach((card) => {
    const id = String(card.getAttribute("data-widget-id") || "").trim();
    if (!id) return;

    const to = card.getBoundingClientRect();
    if (!to || to.width <= 0 || to.height <= 0) return;

    const from = beforeRects.get(id);
    if (!from) {
      if (!includeEnter) return;
      card.classList.add("is-layout-animating");
      const enterAnim = card.animate(
        [
          { opacity: 0, transform: "scale(0.97) translateY(8px)" },
          { opacity: 1, transform: "scale(1) translateY(0)" },
        ],
        {
          duration: Math.round(duration * 0.72),
          easing,
          fill: "both",
        }
      );
      const clearEnter = () => card.classList.remove("is-layout-animating");
      enterAnim.addEventListener("finish", clearEnter, { once: true });
      enterAnim.addEventListener("cancel", clearEnter, { once: true });
      return;
    }

    const dx = from.left - to.left;
    const dy = from.top - to.top;
    const sx = from.width / Math.max(1, to.width);
    const sy = from.height / Math.max(1, to.height);
    const movementScore =
      Math.abs(dx) +
      Math.abs(dy) +
      (Math.abs(1 - sx) * 80) +
      (Math.abs(1 - sy) * 80);
    if (movementScore < 0.8) return;

    card.classList.add("is-layout-animating");
    const anim = card.animate(
      [
        {
          transformOrigin: "top left",
          transform: `translate(${dx}px, ${dy}px) scale(${sx}, ${sy})`,
        },
        {
          transformOrigin: "top left",
          transform: "translate(0, 0) scale(1, 1)",
        },
      ],
      {
        duration,
        easing,
        fill: "both",
      }
    );
    const clear = () => card.classList.remove("is-layout-animating");
    anim.addEventListener("finish", clear, { once: true });
    anim.addEventListener("cancel", clear, { once: true });
  });
}

function finishWidgetResizeDrag(commit = true) {
  if (!widgetResizeDrag) return;
  const drag = widgetResizeDrag;
  widgetResizeDrag = null;

  const card = drag.cardEl;
  const grid = card?.closest?.("#widgetsGrid") || $("widgetsGrid");
  if (card) {
    card.classList.remove("is-resizing");
    card.removeAttribute("data-resize-size");
    card.removeAttribute("data-resize-size-label");
  }

  const finalSize = normalizeWidgetSize(drag.targetSize || drag.startSize, drag.widgetId);

  if (!commit || finalSize === drag.startSize) {
    clearWidgetPreviewLayout(grid, { animate: true, duration: 200 });
    if (card) {
      applyWidgetCardSizeClass(card, drag.startSize);
      const badge = card.querySelector(".widgetCardSizeBadge");
      if (badge) badge.textContent = WIDGET_SIZE_LABELS[drag.startSize] || drag.startSize.toUpperCase();
    }
    return;
  }

  setWidgetSize(drag.widgetId, finalSize);
  renderWidgets();
}

function moveWidget(dragId, targetId = "", position = "before") {
  ensureWidgetsLayoutState();
  const from = String(dragId || "").trim();
  const to = String(targetId || "").trim();
  if (!from) return;
  widgetsLayoutState.positions = widgetsLayoutState.positions || {};
  delete widgetsLayoutState.positions[from];

  const next = widgetsLayoutState.order.filter((id) => id !== from);

  if (!to || !next.includes(to)) {
    next.push(from);
    widgetsLayoutState.order = next;
    saveWidgetsLayoutState();
    return;
  }

  const targetIndex = next.indexOf(to);
  const placeAfter = String(position || "").toLowerCase() === "after";
  const insertAt = placeAfter ? (targetIndex + 1) : targetIndex;
  next.splice(insertAt, 0, from);
  widgetsLayoutState.order = next;
  saveWidgetsLayoutState();
}

function moveWidgetToGridCell(dragId, cellInput, colCountInput = 0) {
  ensureWidgetsLayoutState();
  const id = String(dragId || "").trim();
  if (!id || !WIDGET_IDS.includes(id)) return false;
  const cell = cellInput && typeof cellInput === "object" ? cellInput : null;
  if (!cell) return false;

  const colCount = Math.max(1, Number(colCountInput) || Number(getWidgetsGridMetrics().colCount) || 4);
  const projection = projectWidgetLayoutToGridCell(id, cell, colCount);
  if (!projection?.order) return false;
  widgetsLayoutState.order = projection.order;
  if (widgetsLayoutState.positions && typeof widgetsLayoutState.positions === "object") {
    delete widgetsLayoutState.positions[id];
  }
  saveWidgetsLayoutState();
  return true;
}

function projectWidgetLayoutToGridCell(dragId, cellInput, colCountInput = 0, options = {}) {
  ensureWidgetsLayoutState();
  const id = String(dragId || "").trim();
  if (!id || !WIDGET_IDS.includes(id)) return null;
  const cell = cellInput && typeof cellInput === "object" ? cellInput : null;
  if (!cell) return null;

  const colCount = Math.max(1, Number(colCountInput) || Number(getWidgetsGridMetrics().colCount) || 4);
  const wantedCol = clampInt(cell.col, 1, colCount, 1);
  const wantedRow = clampInt(cell.row, 1, 999, 1);
  let activeIds = getActiveWidgetIds();

  if (!activeIds.length) {
    widgetsLayoutState = normalizeWidgetsLayout(null);
    saveWidgetsLayoutState();
    activeIds = getActiveWidgetIds();
  }
  const baseOrder = activeIds.filter((wid) => wid !== id);
  const sizeOverrides = options && typeof options === "object" && options.sizeOverrides && typeof options.sizeOverrides === "object"
    ? options.sizeOverrides
    : null;

  let bestOrder = null;
  let bestPlacements = null;
  let bestSlot = null;
  let bestScore = Number.POSITIVE_INFINITY;

  for (let idx = 0; idx <= baseOrder.length; idx += 1) {
    const trial = baseOrder.slice();
    trial.splice(idx, 0, id);
    const placements = computeWidgetGridPlacements(trial, colCount, { sizeOverrides });
    const slot = placements[id];
    if (!slot) continue;

    const dRow = Math.abs((Number(slot.row) || 1) - wantedRow);
    const dCol = Math.abs((Number(slot.col) || 1) - wantedCol);
    const wantedLinear = ((wantedRow - 1) * colCount) + wantedCol;
    const slotLinear = (((Number(slot.row) || 1) - 1) * colCount) + (Number(slot.col) || 1);
    const linearDelta = Math.abs(slotLinear - wantedLinear);
    const score = (dRow * 100) + (dCol * 10) + linearDelta + (idx * 0.001);
    if (score < bestScore) {
      bestScore = score;
      bestOrder = trial;
      bestPlacements = placements;
      bestSlot = slot;
    }
  }

  if (!bestOrder || !bestPlacements || !bestSlot) return null;
  return {
    order: bestOrder,
    placements: bestPlacements,
    slot: bestSlot,
    score: bestScore,
    colCount,
  };
}

function buildWidgetPlacementSignature(activeIds = [], placements = {}) {
  const ids = Array.isArray(activeIds) ? activeIds : [];
  if (!ids.length || !placements || typeof placements !== "object") return "";
  return ids.map((id) => {
    const slot = placements[id];
    if (!slot) return `${id}:0:0:0:0`;
    return `${id}:${slot.col}:${slot.row}:${slot.cols}:${slot.rows}:${slot.size || getWidgetSize(id)}`;
  }).join("|");
}

function syncWidgetPreviewLayout(grid, activeIds, placements, options = {}) {
  if (!grid) return "";
  const ids = Array.isArray(activeIds) ? activeIds.slice() : [];
  const placeholderId = String(options.dragPlaceholderId || "").trim();
  const signature = buildWidgetPlacementSignature(ids, placements);
  const placeholderKey = placeholderId || "-";
  const prevSignature = String(grid.getAttribute("data-widget-preview-signature") || "");
  const prevPlaceholder = String(grid.getAttribute("data-widget-preview-placeholder") || "");
  if (signature && prevSignature === signature && prevPlaceholder === placeholderKey) return signature;

  const beforeRects = options.animate === false ? new Map() : captureWidgetCardRects(grid);
  applyWidgetGridPlacements(grid, ids, getWidgetsGridMetrics().colCount, { placements });
  grid.querySelectorAll(".widgetCard[data-widget-id]").forEach((card) => {
    const id = String(card.getAttribute("data-widget-id") || "").trim();
    card.classList.toggle("is-drag-placeholder", !!placeholderId && id === placeholderId);
  });

  if (beforeRects.size) {
    animateWidgetLayoutFromRects(grid, beforeRects, {
      duration: Math.max(140, Number(options.duration) || 240),
      includeEnter: false,
      easing: String(options.easing || "cubic-bezier(0.2, 0.92, 0.2, 1)"),
    });
  }

  if (signature) grid.setAttribute("data-widget-preview-signature", signature);
  else grid.removeAttribute("data-widget-preview-signature");
  grid.setAttribute("data-widget-preview-placeholder", placeholderKey);
  return signature;
}

function clearWidgetPreviewLayout(grid, options = {}) {
  if (!grid) return;
  let activeIds = getActiveWidgetIds();

  if (!activeIds.length) {
    widgetsLayoutState = normalizeWidgetsLayout(null);
    saveWidgetsLayoutState();
    activeIds = getActiveWidgetIds();
  }
  if (!activeIds.length) {
    grid.querySelectorAll(".widgetCard.is-drag-placeholder")
      .forEach((card) => card.classList.remove("is-drag-placeholder"));
    grid.removeAttribute("data-widget-preview-signature");
    grid.removeAttribute("data-widget-preview-placeholder");
    return;
  }

  const metrics = getWidgetsGridMetrics();
  const placements = computeWidgetGridPlacements(activeIds, metrics.colCount);
  syncWidgetPreviewLayout(grid, activeIds, placements, {
    animate: options.animate !== false,
    duration: Math.max(140, Number(options.duration) || 220),
    easing: String(options.easing || "cubic-bezier(0.2, 0.92, 0.2, 1)"),
  });
}

function clearWidgetDropMarkers({ keepDragging = false } = {}) {
  const root = $("tabWidgets");
  if (!root) return;
  const selector = keepDragging
    ? ".widgetCard.is-drop-target"
    : ".widgetCard.is-drop-target,.widgetCard.is-dragging,.widgetCard.is-drag-placeholder";
  root.querySelectorAll(selector)
    .forEach((el) => el.classList.remove(
      "is-drop-target",
      "is-dragging",
      "is-drag-placeholder",
      "is-drop-before",
      "is-drop-after",
      "is-drop-left",
      "is-drop-right"
    ));
  const grid = $("widgetsGrid");
  if (grid) {
    grid.classList.remove("is-drop-end", "is-grid-dropping");
    const ghost = grid.querySelector(".widgetsDropGhost");
    if (ghost) ghost.remove();
    if (!keepDragging) {
      grid.removeAttribute("data-widget-preview-signature");
      grid.removeAttribute("data-widget-preview-placeholder");
    }
  }
  widgetsDropGridCell = null;
}

function getWidgetTransparentDragImage() {
  if (widgetTransparentDragImage) return widgetTransparentDragImage;
  try {
    const canvas = document.createElement("canvas");
    canvas.width = 1;
    canvas.height = 1;
    const ctx = canvas.getContext("2d");
    if (ctx) ctx.clearRect(0, 0, 1, 1);
    widgetTransparentDragImage = canvas;
    return widgetTransparentDragImage;
  } catch (_) {}
  return null;
}

function removeWidgetDragPreview() {
  if (widgetDragPreviewRaf) {
    cancelAnimationFrame(widgetDragPreviewRaf);
    widgetDragPreviewRaf = 0;
  }
  if (!widgetDragPreviewEl) return;
  const el = widgetDragPreviewEl;
  widgetDragPreviewEl = null;
  el.classList.remove("is-visible");
  setTimeout(() => {
    try { el.remove(); } catch (_) {}
  }, 120);
}

function getWidgetDragPreviewScale(widthInput) {
  const width = Math.max(120, Number(widthInput) || 120);
  if (width >= 760) return 0.44;
  if (width >= 620) return 0.52;
  if (width >= 520) return 0.6;
  if (width >= 420) return 0.72;
  return 0.84;
}

function createWidgetDragPreview(card) {
  removeWidgetDragPreview();
  if (!card) return;
  const rect = card.getBoundingClientRect();
  if (!rect || rect.width <= 0 || rect.height <= 0) return;
  const clone = card.cloneNode(true);
  clone.removeAttribute("draggable");
  clone.classList.remove(
    "is-dragging",
    "is-drop-target",
    "is-drop-before",
    "is-drop-after",
    "is-drop-left",
    "is-drop-right"
  );
  clone.classList.add("widgetDragPreview__card");

  const preview = document.createElement("div");
  preview.className = "widgetDragPreview";
  preview.style.width = `${Math.round(rect.width)}px`;
  preview.style.height = `${Math.round(rect.height)}px`;
  preview.style.setProperty("--widget-preview-scale", String(getWidgetDragPreviewScale(rect.width)));
  preview.appendChild(clone);
  document.body.appendChild(preview);
  widgetDragPreviewEl = preview;
  requestAnimationFrame(() => {
    preview.classList.add("is-visible");
  });
}

function moveWidgetDragPreview(clientXInput, clientYInput) {
  if (!widgetDragPreviewEl) return;
  const x = Number(clientXInput);
  const y = Number(clientYInput);
  if (!Number.isFinite(x) || !Number.isFinite(y)) return;
  widgetDragPreviewX = x;
  widgetDragPreviewY = y;
  if (widgetDragPreviewRaf) return;
  widgetDragPreviewRaf = requestAnimationFrame(() => {
    widgetDragPreviewRaf = 0;
    const el = widgetDragPreviewEl;
    if (!el) return;
    el.style.left = `${Math.round(widgetDragPreviewX)}px`;
    el.style.top = `${Math.round(widgetDragPreviewY)}px`;
  });
}

function cancelWidgetPointerDrag() {
  const drag = widgetPointerDrag;
  widgetPointerDrag = null;
  if (!drag) return;
  try { drag.cardEl?.releasePointerCapture?.(drag.pointerId); } catch (_) {}
}

function startWidgetPointerDrag(card, e) {
  if (!card || !e) return;
  const widgetId = String(card.getAttribute("data-widget-id") || "").trim();
  if (!widgetId) return;
  const rect = card.getBoundingClientRect();
  const grabOffsetX = Math.max(0, Math.min(rect.width || 0, Number(e.clientX) - rect.left));
  const grabOffsetY = Math.max(0, Math.min(rect.height || 0, Number(e.clientY) - rect.top));
  widgetPointerDrag = {
    pointerId: e.pointerId,
    widgetId,
    cardEl: card,
    startX: e.clientX,
    startY: e.clientY,
    grabOffsetX,
    grabOffsetY,
    active: false,
  };
  try { card.setPointerCapture(e.pointerId); } catch (_) {}
}

function isPointerInsideElement(el, clientXInput, clientYInput) {
  if (!el) return false;
  const x = Number(clientXInput);
  const y = Number(clientYInput);
  if (!Number.isFinite(x) || !Number.isFinite(y)) return false;
  const rect = el.getBoundingClientRect?.();
  if (!rect) return false;
  return x >= rect.left && x <= rect.right && y >= rect.top && y <= rect.bottom;
}

function updateWidgetPointerDrag(root, e) {
  const drag = widgetPointerDrag;
  if (!drag || e.pointerId !== drag.pointerId) return;
  const dx = e.clientX - drag.startX;
  const dy = e.clientY - drag.startY;
  const dist = Math.hypot(dx, dy);

  if (!drag.active) {
    if (dist < 6) return;
    drag.active = true;
    widgetsDragId = drag.widgetId;
    widgetsDropTargetId = "";
    widgetsDropPosition = "before";
    drag.cardEl?.classList?.add("is-dragging");
    root?.classList?.add("is-widget-dragging");
    createWidgetDragPreview(drag.cardEl);
  }

  moveWidgetDragPreview(e.clientX, e.clientY);
  const x = Number(e.clientX);
  const y = Number(e.clientY);
  const grid = $("widgetsGrid");
  const editBar = $("widgetsEditBar");
  const addPanel = $("widgetsAddPanel");

  if (grid && isPointerInsideElement(grid, x, y)) {
    const cell = getWidgetGridCellFromEvent(grid, e, drag.widgetId, drag);
    const projection = cell
      ? projectWidgetLayoutToGridCell(drag.widgetId, cell, getWidgetsGridMetrics().colCount)
      : null;
    widgetsDropTargetId = "";
    widgetsDropPosition = "before";
    clearWidgetDropMarkers({ keepDragging: true });
    widgetsDropGridCell = projection?.slot || cell;
    if (projection?.order && projection?.placements && projection?.slot) {
      syncWidgetPreviewLayout(grid, projection.order, projection.placements, {
        dragPlaceholderId: drag.widgetId,
        duration: 230,
      });
      upsertWidgetsDropGhost(grid, projection.slot, drag.widgetId);
    } else {
      clearWidgetPreviewLayout(grid, { animate: false });
      if (cell) upsertWidgetsDropGhost(grid, cell, drag.widgetId);
    }
    return;
  }

  clearWidgetPreviewLayout(grid, { animate: true, duration: 180 });
  widgetsDropGridCell = null;
  if (isPointerInsideElement(editBar, x, y) || isPointerInsideElement(addPanel, x, y)) {
    const firstCard = root.querySelector(".widgetCard[data-widget-id]");
    const firstId = firstCard?.getAttribute("data-widget-id");
    if (!firstId || firstId === drag.widgetId) {
      clearWidgetDropMarkers({ keepDragging: true });
      return;
    }
    widgetsDropTargetId = firstId;
    widgetsDropPosition = "before";
    clearWidgetDropMarkers({ keepDragging: true });
    firstCard.classList.add("is-drop-target", "is-drop-before");
    return;
  }

  widgetsDropTargetId = "";
  widgetsDropPosition = "before";
  clearWidgetDropMarkers({ keepDragging: true });
}

function finishWidgetPointerDrag(root, e, { commit = true } = {}) {
  const drag = widgetPointerDrag;
  if (!drag) return;
  if (e && e.pointerId !== drag.pointerId) return;

  const wasActive = !!drag.active;
  const widgetId = drag.widgetId;
  const grid = $("widgetsGrid");
  cancelWidgetPointerDrag();

  drag.cardEl?.classList?.remove("is-dragging");
  root?.classList?.remove("is-widget-dragging");
  removeWidgetDragPreview();

  if (wasActive && commit) {
    if (widgetsDropGridCell) {
      moveWidgetToGridCell(widgetId, widgetsDropGridCell, getWidgetsGridMetrics().colCount);
    } else if (widgetsDropTargetId && widgetsDropTargetId !== widgetId) {
      moveWidget(widgetId, widgetsDropTargetId, widgetsDropPosition || "before");
    }
    renderWidgets();
  } else {
    clearWidgetPreviewLayout(grid, { animate: wasActive });
  }

  widgetsDragId = "";
  widgetsDropTargetId = "";
  widgetsDropPosition = "before";
  widgetsDropGridCell = null;
  clearWidgetDropMarkers();
}

function getWidgetDropPositionFromEvent(card, e) {
  if (!card || !e) return { position: "before", axis: "y" };
  const rect = card.getBoundingClientRect();
  const x = Number(e.clientX) - rect.left;
  const y = Number(e.clientY) - rect.top;
  const xNorm = rect.width > 0 ? (x / rect.width) : 0.5;
  const yNorm = rect.height > 0 ? (y / rect.height) : 0.5;
  const dx = Math.abs(xNorm - 0.5);
  const dy = Math.abs(yNorm - 0.5);
  const axis = dx > dy ? "x" : "y";
  const position = axis === "x"
    ? (xNorm >= 0.5 ? "after" : "before")
    : (yNorm >= 0.5 ? "after" : "before");
  return { position, axis };
}

function getWidgetDropTargetFromGridPoint(grid, dragId, e) {
  if (!grid || !e) return { targetId: "", position: "end", axis: "y", card: null };
  const cards = Array.from(grid.querySelectorAll(".widgetCard[data-widget-id]"))
    .filter((card) => {
      const id = String(card.getAttribute("data-widget-id") || "").trim();
      return !!id && id !== String(dragId || "").trim() && !card.classList.contains("is-dragging");
    });
  if (!cards.length) return { targetId: "", position: "end", axis: "y", card: null };

  const px = Number(e.clientX) || 0;
  const py = Number(e.clientY) || 0;
  let bestCard = null;
  let bestScore = Number.POSITIVE_INFINITY;

  cards.forEach((card) => {
    const rect = card.getBoundingClientRect();
    if (!rect || rect.width <= 0 || rect.height <= 0) return;
    const cx = rect.left + (rect.width / 2);
    const cy = rect.top + (rect.height / 2);
    const inside = px >= rect.left && px <= rect.right && py >= rect.top && py <= rect.bottom;
    const dist = Math.hypot(px - cx, py - cy);
    const score = inside ? (dist - 100000) : dist;
    if (score < bestScore) {
      bestScore = score;
      bestCard = card;
    }
  });

  if (!bestCard) return { targetId: "", position: "end", axis: "y", card: null };
  const targetId = String(bestCard.getAttribute("data-widget-id") || "").trim();
  if (!targetId) return { targetId: "", position: "end", axis: "y", card: null };
  const drop = getWidgetDropPositionFromEvent(bestCard, e);
  return {
    targetId,
    position: drop.position,
    axis: drop.axis,
    card: bestCard,
  };
}

function getWidgetGridCellFromEvent(grid, e, widgetId = "", anchor = null) {
  if (!grid || !e) return null;
  const metrics = getWidgetsGridMetrics();
  const colCount = Math.max(1, Number(metrics.colCount) || 4);
  const dims = getWidgetSizeDimensions(getWidgetSize(widgetId), colCount);
  const rect = grid.getBoundingClientRect();
  const colStep = Math.max(1, metrics.cellWidth + metrics.colGap);
  const rowStep = Math.max(1, metrics.cellHeight + metrics.rowGap);
  const totalWidth = (dims.cols * metrics.cellWidth) + ((dims.cols - 1) * metrics.colGap);
  const totalHeight = (dims.rows * metrics.cellHeight) + ((dims.rows - 1) * metrics.rowGap);
  const defaultAnchorX = totalWidth * 0.5;
  const defaultAnchorY = Math.min(totalHeight * 0.4, metrics.cellHeight * 0.78);
  const anchorX = anchor && typeof anchor === "object"
    ? Math.max(0, Math.min(totalWidth, Number(anchor.grabOffsetX) || defaultAnchorX))
    : defaultAnchorX;
  const anchorY = anchor && typeof anchor === "object"
    ? Math.max(0, Math.min(totalHeight, Number(anchor.grabOffsetY) || defaultAnchorY))
    : defaultAnchorY;
  const x = (Number(e.clientX) - rect.left) - anchorX;
  const y = (Number(e.clientY) - rect.top) - anchorY;
  const rawCol = Math.round(x / colStep) + 1;
  const rawRow = Math.round(y / rowStep) + 1;
  const maxColStart = Math.max(1, colCount - dims.cols + 1);
  const col = clampInt(rawCol, 1, maxColStart, 1);
  const row = clampInt(rawRow, 1, 999, 1);
  return { col, row, cols: dims.cols, rows: dims.rows, colCount };
}

function upsertWidgetsDropGhost(grid, cell, widgetId = "") {
  if (!grid || !cell) return;
  const metrics = getWidgetsGridMetrics();
  const col = clampInt(cell.col, 1, Math.max(1, metrics.colCount - cell.cols + 1), 1);
  const row = clampInt(cell.row, 1, 999, 1);
  const left = (col - 1) * (metrics.cellWidth + metrics.colGap);
  const top = (row - 1) * (metrics.cellHeight + metrics.rowGap);
  const width = (cell.cols * metrics.cellWidth) + ((cell.cols - 1) * metrics.colGap);
  const height = (cell.rows * metrics.cellHeight) + ((cell.rows - 1) * metrics.rowGap);
  let ghost = grid.querySelector(".widgetsDropGhost");
  if (!ghost) {
    ghost = document.createElement("div");
    ghost.className = "widgetsDropGhost";
    grid.appendChild(ghost);
  }
  grid.classList.add("is-grid-dropping");
  ghost.style.left = `${Math.round(left)}px`;
  ghost.style.top = `${Math.round(top)}px`;
  ghost.style.width = `${Math.round(width)}px`;
  ghost.style.height = `${Math.round(height)}px`;
  const sizeText = getWidgetSizePreviewText(widgetId, getWidgetSize(widgetId), metrics.colCount);
  ghost.setAttribute("data-drop-label", `${sizeText} - C${col} R${row}`);
}

function getWidgetTodoIcon(kind, options = {}) {
  const iconKind = String(kind || "").trim().toLowerCase();
  const done = !!options.done;
  if (iconKind === "toggle") {
    return done
      ? `
        <svg class="widgetTodoIcon widgetTodoIcon--toggle" viewBox="0 0 16 16" aria-hidden="true">
          <path d="M3.2 8.4 6.5 11.4 12.8 4.8" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"></path>
        </svg>
      `
      : `
        <svg class="widgetTodoIcon widgetTodoIcon--toggle" viewBox="0 0 16 16" aria-hidden="true">
          <circle cx="8" cy="8" r="4.75" fill="none" stroke="currentColor" stroke-width="1.5"></circle>
        </svg>
      `;
  }
  if (iconKind === "up") {
    return `
      <svg class="widgetTodoIcon" viewBox="0 0 16 16" aria-hidden="true">
        <path d="M4.2 9.8 8 6l3.8 3.8" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"></path>
      </svg>
    `;
  }
  if (iconKind === "down") {
    return `
      <svg class="widgetTodoIcon" viewBox="0 0 16 16" aria-hidden="true">
        <path d="M4.2 6.2 8 10l3.8-3.8" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"></path>
      </svg>
    `;
  }
  if (iconKind === "edit") {
    return `
      <svg class="widgetTodoIcon" viewBox="0 0 16 16" aria-hidden="true">
        <path d="M3.3 11.7 4.1 9l5.7-5.7 2.2 2.2L6.3 11.2l-3 .5Z" fill="none" stroke="currentColor" stroke-width="1.35" stroke-linejoin="round"></path>
        <path d="M8.9 4.2 11 6.3" fill="none" stroke="currentColor" stroke-width="1.35" stroke-linecap="round"></path>
      </svg>
    `;
  }
  if (iconKind === "remove") {
    return `
      <svg class="widgetTodoIcon" viewBox="0 0 16 16" aria-hidden="true">
        <path d="M4.6 4.6 11.4 11.4M11.4 4.6 4.6 11.4" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"></path>
      </svg>
    `;
  }
  return "";
}

function buildWidgetCalendarModelLegacy(nowInput = new Date()) {
  const now = nowInput instanceof Date ? nowInput : new Date();
  const locale = getWidgetCalendarLocale();
  const weekStartsOnMonday = locale.toLowerCase().startsWith("pt");
  const year = now.getFullYear();
  const monthIdx = now.getMonth();
  const day = now.getDate();

  const monthLabel = new Intl.DateTimeFormat(locale, { month: "long" }).format(now);
  const monthShort = new Intl.DateTimeFormat(locale, { month: "short" }).format(now);
  const weekdayLong = new Intl.DateTimeFormat(locale, { weekday: "long" }).format(now);
  const weekdayShort = new Intl.DateTimeFormat(locale, { weekday: "short" }).format(now);

  const firstOfMonth = new Date(year, monthIdx, 1);
  const firstWeekdayJs = firstOfMonth.getDay();
  const firstWeekday = weekStartsOnMonday ? ((firstWeekdayJs + 6) % 7) : firstWeekdayJs;
  const daysInMonth = new Date(year, monthIdx + 1, 0).getDate();
  const daysInPrevMonth = new Date(year, monthIdx, 0).getDate();
  const totalCells = Math.ceil((firstWeekday + daysInMonth) / 7) * 7;

  const cells = [];
  for (let idx = 0; idx < totalCells; idx += 1) {
    const cellOffset = idx - firstWeekday;
    if (cellOffset >= 0 && cellOffset < daysInMonth) {
      const value = cellOffset + 1;
      cells.push({ day: value, inMonth: true, isToday: value === day });
      continue;
    }
    if (cellOffset < 0) {
      cells.push({ day: daysInPrevMonth + cellOffset + 1, inMonth: false, isToday: false });
      continue;
    }
    cells.push({ day: cellOffset - daysInMonth + 1, inMonth: false, isToday: false });
  }

  const weekdayLabels = getWidgetCalendarWeekdayLabels(locale, { weekStartsOnMonday });
  const agenda = [];
  for (let i = 0; i < 5; i += 1) {
    const d = new Date(year, monthIdx, day + i);
    const label = i === 0
      ? t("widget.calendar.today", "Today")
      : i === 1
      ? t("widget.calendar.tomorrow", "Tomorrow")
      : new Intl.DateTimeFormat(locale, { weekday: "short" }).format(d);
    agenda.push({
      label: String(label || "").trim(),
      day: d.getDate(),
    });
  }

  return {
    locale,
    year,
    day,
    monthLabel: String(monthLabel || "").trim(),
    monthShort: String(monthShort || "").trim(),
    weekdayLong: String(weekdayLong || "").trim(),
    weekdayShort: String(weekdayShort || "").trim(),
    weekdayLabels,
    cells,
    agenda,
  };
}

function getLegacyCalendarWidgetHtml(classes, id, draggable, tools) {
  const calendar = buildWidgetCalendarModelLegacy();
  if (widgetsEditMode) {
    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
        <div class="widgetCard__value widgetCard__value--small">${esc(calendar.day)}</div>
        <div class="widgetCard__meta">${esc(calendar.monthLabel)} ${esc(String(calendar.year))} â€¢ ${esc(calendar.weekdayLong)}</div>
      </article>
    `;
  }

  return `
    <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
      ${tools}
      <div class="widgetCalendarTop">
        <div class="widgetCalendarIdentity">
          <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
          <div class="widgetCalendarWeekday">${esc(calendar.weekdayShort)}</div>
          <div class="widgetCalendarDate">
            <span class="widgetCalendarDateDay">${esc(calendar.day)}</span>
            <span class="widgetCalendarDateMonth">${esc(calendar.monthShort)}</span>
          </div>
          <div class="widgetCard__meta">${esc(t("widget.calendar.no_events_today", "No events today"))}</div>
        </div>
        <div class="widgetCalendarMonthChip">${esc(calendar.monthLabel)} ${esc(String(calendar.year))}</div>
      </div>
      <div class="widgetCalendarGrid" aria-hidden="true">
        <div class="widgetCalendarWeekdays">
          ${calendar.weekdayLabels.map((label) => `<span class="widgetCalendarWeekdayCell">${esc(label)}</span>`).join("")}
        </div>
        <div class="widgetCalendarDays">
          ${calendar.cells.map((cell) => `<span class="widgetCalendarDayCell${cell.inMonth ? "" : " is-other"}${cell.isToday ? " is-today" : ""}">${esc(cell.day)}</span>`).join("")}
        </div>
      </div>
      <div class="widgetCalendarAgenda">
        <div class="widgetCalendarAgendaTitle">${esc(t("widget.calendar.up_next", "Up next"))}</div>
        <div class="widgetCalendarAgendaList">
          ${calendar.agenda.map((entry) => `<div class="widgetCalendarAgendaRow"><span class="widgetCalendarAgendaLabel">${esc(entry.label)}</span><span class="widgetCalendarAgendaDay">${esc(entry.day)}</span></div>`).join("")}
        </div>
      </div>
    </article>
  `;
}

function getLegacyChecklistWidgetHtml(classes, id, draggable, tools) {
  const todos = getWidgetTodoItems();
  const doneCount = todos.filter((x) => !!x.done).length;
  const totalCount = todos.length;
  const pct = totalCount ? Math.round((doneCount / totalCount) * 100) : 0;
  const isFull = totalCount >= WIDGET_TODO_MAX_ITEMS;
  if (widgetsEditMode) {
    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
        <div class="widgetCard__value widgetCard__value--small">${doneCount}/${totalCount}</div>
        <div class="widgetCard__meta">${esc(t("widget.meta.tasks_done", "completed tasks"))}</div>
      </article>
    `;
  }

  return `
    <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
      ${tools}
      <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
      <ul class="widgetTodoList">
        ${todos.length
          ? todos.map((item, idx) => (
            `<li class="widgetTodoItem${item.done ? " is-done" : ""}">
              <button class="widgetTodoToggle" type="button" data-widget-todo-toggle="${escAttr(item.id)}" aria-label="Marcar tarefa">${getWidgetTodoIcon("toggle", { done: item.done })}</button>
              <span class="widgetTodoText">${esc(item.text)}</span>
              <button class="widgetTodoMove" type="button" data-widget-todo-move-up="${escAttr(item.id)}" aria-label="Subir tarefa"${idx === 0 ? " disabled" : ""}>${getWidgetTodoIcon("up")}</button>
              <button class="widgetTodoMove" type="button" data-widget-todo-move-down="${escAttr(item.id)}" aria-label="Descer tarefa"${idx === (totalCount - 1) ? " disabled" : ""}>${getWidgetTodoIcon("down")}</button>
              <button class="widgetTodoEdit" type="button" data-widget-todo-edit="${escAttr(item.id)}" aria-label="Editar tarefa">${getWidgetTodoIcon("edit")}</button>
              <button class="widgetTodoRemove" type="button" data-widget-todo-remove="${escAttr(item.id)}" aria-label="Remover tarefa">${getWidgetTodoIcon("remove")}</button>
            </li>`
          )).join("")
          : `<li class="widgetTodoItem widgetTodoItem--empty"><span class="widgetTodoText">${esc(t("widget.todo.empty", "No tasks yet."))}</span></li>`
        }
      </ul>
      <div class="widgetTodoComposer">
        <input
          class="input widgetTodoInput"
          data-widget-todo-input="1"
          maxlength="${WIDGET_TODO_MAX_CHARS}"
          placeholder="${escAttr(isFull ? t("widget.todo.placeholder.limit", "Checklist is full.") : t("widget.todo.placeholder.add", "Add task..."))}"
          ${isFull ? "disabled" : ""}
        />
        <button class="btn ghost widgetCard__miniBtn" type="button" data-widget-todo-add="1"${isFull ? " disabled" : ""}>${esc(t("widget.todo.add", "Add"))}</button>
      </div>
      <div class="widgetChecklistFooter">
        <div class="widgetChecklistProgress">
          <div class="widgetChecklistProgressBar"><span style="width:${pct}%;"></span></div>
          <div class="widgetCard__meta">${doneCount}/${totalCount} ${esc(t("widget.todo.completed_suffix", "completed"))} (${pct}%)</div>
        </div>
        <button class="btn ghost widgetCard__miniBtn" type="button" data-widget-todo-clear-done="1"${doneCount ? "" : " disabled"}>${esc(t("widget.todo.clear_completed", "Clear completed"))}</button>
      </div>
    </article>
  `;
}

function widgetEditorToolsHtml(widgetId) {
  if (!widgetsEditMode) return "";
  const sizeId = getWidgetSize(widgetId);
  const sizeLabel = WIDGET_SIZE_LABELS[sizeId] || sizeId.toUpperCase();
  const canResize = getWidgetAllowedSizes(widgetId).length > 1;
  const sizeControl = canResize
    ? `<button class="widgetCardSizeBadge widgetCardSizeBadge--btn" type="button" data-widget-size-cycle="${escAttr(widgetId)}" title="${escAttr(t("widget.edit.change_size", "Change widget size"))}">${esc(sizeLabel)}</button>`
    : `<span class="widgetCardSizeBadge">${esc(sizeLabel)}</span>`;
  const resizeHandle = canResize
    ? `<button class="widgetResizeHandle" type="button" data-widget-resize-handle="${escAttr(widgetId)}" title="${escAttr(t("widget.edit.resize", "Drag to resize"))}" aria-label="${escAttr(t("widget.edit.resize", "Drag to resize"))}">&#8690;</button>`
    : "";
  return `
    <div class="widgetCard__tools">
      ${sizeControl}
      <button class="widgetCardTool widgetCardTool--drag" type="button" data-widget-drag="${escAttr(widgetId)}" title="${escAttr(t("widget.edit.drag", "Drag widget"))}" aria-label="${escAttr(t("widget.edit.drag", "Drag widget"))}">&#x2630;</button>
      <button class="widgetCardTool widgetCardTool--remove" type="button" data-widget-remove="${escAttr(widgetId)}" title="${escAttr(t("widget.edit.remove", "Remove widget"))}" aria-label="${escAttr(t("widget.edit.remove", "Remove widget"))}">&times;</button>
    </div>
    ${resizeHandle}
  `;
}

function widgetCardHtml(widgetId, stats) {
  const id = String(widgetId || "").trim();
  if (!WIDGET_IDS.includes(id)) return "";
  const baseSizeId = getWidgetSize(id);
  const isHighlighted = false;
  const sizeId = isHighlighted ? getWidgetHighlightedSize(baseSizeId) : baseSizeId;

  const classes = [
    "widgetCard",
    id === "friends" ? "widgetCard--primary" : "",
    id === "calendar" ? "widgetCard--calendar" : "",
    isHighlighted ? "is-highlighted" : "",
    `widgetCard--size-${sizeId}`,
    widgetsEditMode ? "is-editing" : "",
  ].filter(Boolean).join(" ");
  const tools = widgetEditorToolsHtml(id);
  const draggable = "false";

  if (id === "friends") {
    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
        <div class="widgetCard__value">${esc(stats.friendsCount)}</div>
        <div class="widgetCard__meta">${esc(t("widget.meta.friends_accepted", "accepted accounts"))}</div>
        ${widgetsEditMode ? "" : `<button class="btn ghost widgetCard__action" type="button" data-widget-open-tab="friends">${esc(t("widget.action.open_friends", "Open Friends"))}</button>`}
      </article>
    `;
  }

  if (id === "pending") {
    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
        <div class="widgetCard__value">${esc(stats.pendingCount)}</div>
        <div class="widgetCard__meta">${esc(t("widget.meta.friend_requests", "friend requests"))}</div>
        ${widgetsEditMode ? "" : `<button class="btn ghost widgetCard__action" type="button" data-widget-open-tab="pending">${esc(t("widget.action.open_pending", "Open Pending"))}</button>`}
      </article>
    `;
  }

  if (id === "online") {
    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
        <div class="widgetCard__value">${esc(stats.onlineCount)}</div>
        <div class="widgetCard__meta">${esc(t("widget.meta.friends_active", "friends online"))}</div>
      </article>
    `;
  }

  if (id === "unread") {
    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
        <div class="widgetCard__value">${esc(stats.unreadConversations)}</div>
        <div class="widgetCard__meta">${esc(stats.unreadMeta)}</div>
      </article>
    `;
  }

  if (id === "calendar") {
    const calendar = buildWidgetCalendarModel();
    if (widgetsEditMode) {
      return `
        <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
          ${tools}
          <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
          <div class="widgetCard__value widgetCard__value--small">${esc(calendar.day)}</div>
          <div class="widgetCard__meta">${esc(calendar.monthLabel)} ${esc(String(calendar.year))} â€¢ ${esc(calendar.weekdayLong)}</div>
        </article>
      `;
    }

    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCalendarTop">
          <div class="widgetCalendarIdentity">
            <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
            <div class="widgetCalendarWeekday">${esc(calendar.weekdayShort)}</div>
            <div class="widgetCalendarDate">
              <span class="widgetCalendarDateDay">${esc(calendar.day)}</span>
              <span class="widgetCalendarDateMonth">${esc(calendar.monthShort)}</span>
            </div>
            <div class="widgetCard__meta">${esc(calendar.todaySummary)}</div>
          </div>
          <div class="widgetCalendarMonthChip">${esc(calendar.monthLabel)} ${esc(String(calendar.year))}</div>
        </div>

        <div class="widgetCalendarGrid" aria-hidden="true">
          <div class="widgetCalendarWeekdays">
            ${calendar.weekdayLabels.map((label) => `<span class="widgetCalendarWeekdayCell">${esc(label)}</span>`).join("")}
          </div>
          <div class="widgetCalendarDays">
            ${calendar.cells.map((cell) => (
              `<span class="widgetCalendarDayCell${cell.inMonth ? "" : " is-other"}${cell.isToday ? " is-today" : ""}${cell.hasTasks ? " has-tasks" : ""}${cell.isOverdue ? " is-overdue" : ""}">
                <span class="widgetCalendarDayNumber">${esc(cell.day)}</span>
                ${cell.hasTasks ? `<span class="widgetCalendarDayMarker">${esc(Math.min(cell.taskCount, 9))}</span>` : ""}
              </span>`
            )).join("")}
          </div>
        </div>

        <div class="widgetCalendarAgenda">
          <div class="widgetCalendarAgendaTitle">${esc(t("widget.calendar.up_next", "Up next"))}</div>
          <div class="widgetCalendarAgendaList">
            ${calendar.agenda.length
              ? calendar.agenda.map((entry) => (
                `<div class="widgetCalendarAgendaRow${entry.isOverdue ? " is-overdue" : ""}">
                  <div class="widgetCalendarAgendaMain">
                    <span class="widgetCalendarAgendaLabel">${esc(entry.label)}</span>
                    <span class="widgetCalendarAgendaTask">${esc(entry.title)}</span>
                  </div>
                  <div class="widgetCalendarAgendaMeta">
                    <span class="widgetCalendarAgendaDay">${esc(entry.dueLabel || entry.day)}</span>
                    ${entry.reminderLabel ? `<span class="widgetCalendarAgendaReminder">${esc(entry.reminderLabel)}</span>` : ""}
                  </div>
                </div>`
              )).join("")
              : `<div class="widgetCalendarAgendaEmpty">${esc(t("widget.calendar.empty", "No planned tasks yet."))}</div>`
            }
          </div>
        </div>
      </article>
    `;
  }

  if (id === "notes") {
    const noteText = getWidgetNotesText();
    const noteCount = noteText.length;
    if (widgetsEditMode) {
      return `
        <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
          ${tools}
          <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
          <div class="widgetCard__value widgetCard__value--small">${noteCount}</div>
          <div class="widgetCard__meta">${esc(t("widget.meta.saved_chars", "saved characters"))}</div>
        </article>
      `;
    }

    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
        <textarea
          class="widgetNotesInput"
          data-widget-notes-input="1"
          maxlength="${WIDGET_NOTE_MAX_CHARS}"
          placeholder="${escAttr(t("widget.notes.placeholder", "Write quick notes here..."))}"
        >${esc(noteText)}</textarea>
        <div class="widgetCard__row">
          <div class="widgetCard__meta" data-widget-notes-count>${noteCount}/${WIDGET_NOTE_MAX_CHARS}</div>
          <button class="btn ghost widgetCard__miniBtn" type="button" data-widget-note-clear="1">${esc(t("widget.notes.clear", "Clear"))}</button>
        </div>
      </article>
    `;
  }

  if (id === "checklist") {
    const todos = getWidgetTodoItems();
    const doneCount = todos.filter((x) => !!x.done).length;
    const totalCount = todos.length;
    const pct = totalCount ? Math.round((doneCount / totalCount) * 100) : 0;
    const isFull = totalCount >= WIDGET_TODO_MAX_ITEMS;
    const draft = getWidgetTodoDraftState();
    const plannerSummary = getWidgetTodoSummary(todos);
    const isEditingTask = !!widgetTodoEditingId;
    const composerLocked = isFull && !isEditingTask;
    const plannerHeadline = plannerSummary.overdue > 0
      ? tf("widget.todo.summary.overdue", { count: plannerSummary.overdue }, plannerSummary.overdue === 1 ? "1 overdue task" : `${plannerSummary.overdue} overdue tasks`)
      : plannerSummary.dueToday > 0
      ? tf("widget.todo.summary.today", { count: plannerSummary.dueToday }, plannerSummary.dueToday === 1 ? "1 due today" : `${plannerSummary.dueToday} due today`)
      : plannerSummary.scheduled > 0
      ? tf("widget.todo.summary.planned", { count: plannerSummary.scheduled }, plannerSummary.scheduled === 1 ? "1 task on the calendar" : `${plannerSummary.scheduled} tasks on the calendar`)
      : t("widget.todo.summary.empty", "Add dates to surface tasks in Calendar.");
    const reminderOptions = [
      ["", t("widget.todo.reminder.none", "No reminder")],
      ["day_start", t("widget.todo.reminder.day_start", "Morning of")],
      ["at_time", t("widget.todo.reminder.at_time", "At deadline")],
      ["15m", t("widget.todo.reminder.15m", "15 min before")],
      ["1h", t("widget.todo.reminder.1h", "1 hour before")],
      ["1d", t("widget.todo.reminder.1d", "1 day before")],
    ];
    const isChecklistLg = sizeId === "lg";
    const showDoneHeroChip = !isChecklistLg || (!plannerSummary.dueToday && !plannerSummary.overdue);
    const visibleTodos = sizeId === "xl" ? todos : todos.slice(0, 2);
    const hiddenTodoCount = Math.max(0, totalCount - visibleTodos.length);
    const showPlannerFields = sizeId !== "md";
    if (widgetsEditMode) {
      return `
        <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
          ${tools}
          <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
          <div class="widgetCard__value widgetCard__value--small">${doneCount}/${totalCount}</div>
          <div class="widgetCard__meta">${esc(t("widget.meta.tasks_done", "completed tasks"))}</div>
        </article>
      `;
    }

    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetTodoHero${isChecklistLg ? " widgetTodoHero--compact" : ""}">
          <div class="widgetTodoHeroMain">
            <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
            <div class="widgetTodoHeroValue">${esc(`${doneCount}/${totalCount}`)}</div>
            <div class="widgetCard__meta">${esc(plannerHeadline)}</div>
          </div>
          <div class="widgetTodoHeroChips">
            ${showDoneHeroChip ? `<span class="widgetTodoHeroChip">${esc(tf("widget.todo.hero.done", { done: doneCount, total: totalCount }, `${doneCount}/${totalCount} done`))}</span>` : ""}
            ${plannerSummary.dueToday ? `<span class="widgetTodoHeroChip is-accent">${esc(tf("widget.todo.hero.today", { count: plannerSummary.dueToday }, plannerSummary.dueToday === 1 ? "1 today" : `${plannerSummary.dueToday} today`))}</span>` : ""}
            ${plannerSummary.overdue ? `<span class="widgetTodoHeroChip is-danger">${esc(tf("widget.todo.hero.overdue", { count: plannerSummary.overdue }, plannerSummary.overdue === 1 ? "1 overdue" : `${plannerSummary.overdue} overdue`))}</span>` : ""}
          </div>
        </div>
        <ul class="widgetTodoList">
          ${visibleTodos.length
            ? visibleTodos.map((item, idx) => (
              (() => {
                const schedule = getWidgetTodoScheduleMeta(item);
                if (isChecklistLg) {
                  const compactMeta = [schedule.shortLabel, schedule.reminderText].filter(Boolean).join(" | ");
                  return `<li class="widgetTodoItem widgetTodoItem--compact${item.done ? " is-done" : ""}${schedule.isOverdue ? " is-overdue" : ""}${schedule.isDueSoon ? " is-soon" : ""}">
                    <button class="widgetTodoToggle" type="button" data-widget-todo-toggle="${escAttr(item.id)}" aria-label="Marcar tarefa">${getWidgetTodoIcon("toggle", { done: item.done })}</button>
                    <div class="widgetTodoBody">
                      <div class="widgetTodoTextRow">
                        <span class="widgetTodoText">${esc(item.text)}</span>
                        ${schedule.chipLabel ? `<span class="widgetTodoStatusChip${schedule.isOverdue ? " is-danger" : schedule.isToday ? " is-accent" : ""}">${esc(schedule.chipLabel)}</span>` : ""}
                      </div>
                      ${compactMeta ? `<div class="widgetTodoMetaInline">${esc(compactMeta)}</div>` : ""}
                    </div>
                    <div class="widgetTodoActions">
                      <button class="widgetTodoMove" type="button" data-widget-todo-move-up="${escAttr(item.id)}" aria-label="Subir tarefa"${idx === 0 ? " disabled" : ""}>${getWidgetTodoIcon("up")}</button>
                      <button class="widgetTodoMove" type="button" data-widget-todo-move-down="${escAttr(item.id)}" aria-label="Descer tarefa"${idx === (totalCount - 1) ? " disabled" : ""}>${getWidgetTodoIcon("down")}</button>
                      <button class="widgetTodoEdit" type="button" data-widget-todo-edit="${escAttr(item.id)}" aria-label="Editar tarefa">${getWidgetTodoIcon("edit")}</button>
                      <button class="widgetTodoRemove" type="button" data-widget-todo-remove="${escAttr(item.id)}" aria-label="Remover tarefa">${getWidgetTodoIcon("remove")}</button>
                    </div>
                  </li>`;
                }

                return `<li class="widgetTodoItem${item.done ? " is-done" : ""}${schedule.isOverdue ? " is-overdue" : ""}${schedule.isDueSoon ? " is-soon" : ""}">
                  <button class="widgetTodoToggle" type="button" data-widget-todo-toggle="${escAttr(item.id)}" aria-label="Marcar tarefa">${getWidgetTodoIcon("toggle", { done: item.done })}</button>
                  <div class="widgetTodoBody">
                    <div class="widgetTodoTextRow">
                      <span class="widgetTodoText">${esc(item.text)}</span>
                      ${schedule.chipLabel ? `<span class="widgetTodoStatusChip${schedule.isOverdue ? " is-danger" : schedule.isToday ? " is-accent" : ""}">${esc(schedule.chipLabel)}</span>` : ""}
                    </div>
                    ${(schedule.hasSchedule || schedule.reminderText) ? `<div class="widgetTodoMetaRow">
                      ${schedule.hasSchedule ? `<span class="widgetTodoMetaChip">${esc(schedule.fullLabel)}</span>` : ""}
                      ${schedule.reminderText ? `<span class="widgetTodoMetaChip widgetTodoMetaChip--reminder">${esc(schedule.reminderText)}</span>` : ""}
                    </div>` : ""}
                  </div>
                  <div class="widgetTodoActions">
                    <button class="widgetTodoMove" type="button" data-widget-todo-move-up="${escAttr(item.id)}" aria-label="Subir tarefa"${idx === 0 ? " disabled" : ""}>${getWidgetTodoIcon("up")}</button>
                    <button class="widgetTodoMove" type="button" data-widget-todo-move-down="${escAttr(item.id)}" aria-label="Descer tarefa"${idx === (totalCount - 1) ? " disabled" : ""}>${getWidgetTodoIcon("down")}</button>
                    <button class="widgetTodoEdit" type="button" data-widget-todo-edit="${escAttr(item.id)}" aria-label="Editar tarefa">${getWidgetTodoIcon("edit")}</button>
                    <button class="widgetTodoRemove" type="button" data-widget-todo-remove="${escAttr(item.id)}" aria-label="Remover tarefa">${getWidgetTodoIcon("remove")}</button>
                  </div>
                </li>`;
              })()
            )).join("")
            : `<li class="widgetTodoItem widgetTodoItem--empty"><span class="widgetTodoText">${esc(t("widget.todo.empty", "No tasks yet."))}</span></li>`
          }
          ${(hiddenTodoCount > 0 && !isChecklistLg) ? `<li class="widgetTodoPreviewMore">${esc(tf("widget.todo.more_tasks", { count: hiddenTodoCount }, hiddenTodoCount === 1 ? "+1 more task" : `+${hiddenTodoCount} more tasks`))}</li>` : ""}
        </ul>
        <div class="widgetTodoComposer${showPlannerFields ? "" : " widgetTodoComposer--compact"}">
          <div class="widgetTodoComposerTop">
            <input
              class="input widgetTodoInput"
              data-widget-todo-input="1"
              maxlength="${WIDGET_TODO_MAX_CHARS}"
              value="${escAttr(draft.text)}"
              placeholder="${escAttr(composerLocked ? t("widget.todo.placeholder.limit", "Checklist is full.") : t("widget.todo.placeholder.add", "Add task..."))}"
              ${composerLocked ? "disabled" : ""}
            />
            <button class="btn ghost widgetCard__miniBtn widgetTodoSubmitBtn" type="button" data-widget-todo-add="1"${composerLocked ? " disabled" : ""}>${esc(isEditingTask ? t("widget.todo.save", "Save") : t("widget.todo.add", "Add"))}</button>
          </div>
          ${showPlannerFields ? `
            <div class="widgetTodoComposerMeta">
              <label class="widgetTodoField">
                <span class="widgetTodoFieldLabel">${esc(t("widget.todo.date", "Date"))}</span>
                <input class="input widgetTodoDateInput" type="date" data-widget-todo-due-date="1" value="${escAttr(draft.dueDate)}"${composerLocked ? " disabled" : ""} />
              </label>
              <label class="widgetTodoField">
                <span class="widgetTodoFieldLabel">${esc(t("widget.todo.time", "Time"))}</span>
                <input class="input widgetTodoTimeInput" type="time" data-widget-todo-due-time="1" value="${escAttr(draft.dueTime)}"${(!draft.dueDate || composerLocked) ? " disabled" : ""} />
              </label>
              <label class="widgetTodoField">
                <span class="widgetTodoFieldLabel">${esc(t("widget.todo.reminder", "Reminder"))}</span>
                <select class="input widgetTodoReminderSelect" data-widget-todo-reminder="1"${(!draft.dueDate || composerLocked) ? " disabled" : ""}>
                  ${reminderOptions.map(([value, label]) => `<option value="${escAttr(value)}"${draft.reminderPreset === value ? " selected" : ""}>${esc(label)}</option>`).join("")}
                </select>
              </label>
              ${isEditingTask ? `<button class="btn ghost widgetCard__miniBtn" type="button" data-widget-todo-cancel-edit="1">${esc(t("widget.todo.cancel", "Cancel"))}</button>` : ""}
            </div>
          ` : ""}
        </div>
        <div class="widgetChecklistFooter">
          <div class="widgetChecklistProgress">
            <div class="widgetChecklistProgressBar"><span style="width:${pct}%;"></span></div>
            <div class="widgetCard__meta">${doneCount}/${totalCount} ${esc(t("widget.todo.completed_suffix", "completed"))} (${pct}%)</div>
          </div>
          ${sizeId === "md" ? "" : `<button class="btn ghost widgetCard__miniBtn" type="button" data-widget-todo-clear-done="1"${doneCount ? "" : " disabled"}>${esc(t("widget.todo.clear_completed", "Clear completed"))}</button>`}
        </div>
      </article>
    `;
  }

  if (id === "quick_status") {
    const currentStatus = resolveMyPresenceStatus(state.me);
    const currentStatusLabel = getWidgetStatusLabel(currentStatus);
    if (widgetsEditMode) {
      return `
        <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
          ${tools}
          <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
          <div class="widgetCard__value widgetCard__value--small">${esc(currentStatusLabel)}</div>
          <div class="widgetCard__meta">${esc(t("widget.meta.status_now", "current status"))}</div>
        </article>
      `;
    }

    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
        <div class="widgetStatusPill" data-status="${escAttr(currentStatus)}">
          <span class="widgetStatusDot" data-status="${escAttr(currentStatus)}"></span>
          <span>${esc(currentStatusLabel)}</span>
        </div>
        <div class="widgetStatusActions">
          <button class="btn ghost widgetStatusBtn${currentStatus === "online" ? " is-on" : ""}" type="button" data-widget-set-status="online">${esc(t("status.option.online", "Online"))}</button>
          <button class="btn ghost widgetStatusBtn${currentStatus === "idle" ? " is-on" : ""}" type="button" data-widget-set-status="idle">${esc(t("status.option.idle", "Away"))}</button>
          <button class="btn ghost widgetStatusBtn${currentStatus === "dnd" ? " is-on" : ""}" type="button" data-widget-set-status="dnd">${esc(t("status.option.dnd", "Do Not Disturb"))}</button>
        </div>
      </article>
    `;
  }

  if (id === "call") {
    return `
      <article class="${classes}" data-widget-id="${escAttr(id)}" draggable="${draggable}">
        ${tools}
        <div class="widgetCard__row">
          <div>
            <div class="widgetCard__label">${esc(getWidgetLabel(id))}</div>
            <div class="widgetCard__value widgetCard__value--small">${esc(stats.callState)}</div>
            <div class="widgetCard__meta">${esc(t("widget.meta.active_dm", "Active DM"))}: ${esc(stats.activeDmName)}</div>
          </div>
          ${widgetsEditMode ? "" : `
            <div class="widgetQuickActions">
              <button class="btn ghost" type="button" data-widget-open-tab="friends">${esc(t("widget.action.open_friends", "Open Friends"))}</button>
              <button class="btn ghost" type="button" data-widget-open-tab="pending">${esc(t("widget.action.open_pending", "Open Pending"))}</button>
              <button class="btn ghost" type="button" data-widget-open-tab="add">${esc(t("widget.action.open_add", "Open Add Friend"))}</button>
            </div>
          `}
        </div>
      </article>
    `;
  }

  return "";
}

function renderWidgetsEditorUi(activeIds = []) {
  const editBtn = $("btnWidgetsEditMode");
  if (editBtn) {
    const txt = widgetsEditMode ? t("actions.finish_edit", "Finish editing") : t("actions.edit_widgets", "Edit widgets");
    editBtn.textContent = txt;
    editBtn.title = txt;
    editBtn.classList.toggle("is-on", widgetsEditMode);
  }

  const editBar = $("widgetsEditBar");
  if (editBar) {
    editBar.classList.toggle("hidden", !widgetsEditMode);
    editBar.setAttribute("aria-hidden", widgetsEditMode ? "false" : "true");
    if (widgetsEditMode) {
      editBar.innerHTML = `
        <div class="widgetsEditBar__title">${esc(t("widgets.editor.title", "Editing mode"))}</div>
        <div class="widgetsEditBar__hint">${esc(t("widgets.editor.hint", "Grab a card or the drag grip to move it. Resizable widgets snap while you drag the corner; clicking S/M/L/XL grows it and right click shrinks it. Remove or add widgets below."))}</div>
      `;
    } else {
      editBar.innerHTML = "";
    }
  }

  const addPanel = $("widgetsAddPanel");
  if (!addPanel) return;

  const activeSet = new Set(activeIds);
  const available = WIDGET_IDS.filter((id) => !activeSet.has(id));
  addPanel.classList.toggle("hidden", !widgetsEditMode);
  addPanel.setAttribute("aria-hidden", widgetsEditMode ? "false" : "true");

  if (!widgetsEditMode) {
    addPanel.innerHTML = "";
    return;
  }

  if (!available.length) {
    addPanel.innerHTML = `
      <div class="widgetsAddPanel__title">${esc(t("widgets.add.title", "Add widget"))}</div>
      <div class="widgetsAddPanel__empty">${esc(t("widgets.add.empty", "All widgets are already active."))}</div>
    `;
    return;
  }

  addPanel.innerHTML = `
    <div class="widgetsAddPanel__title">${esc(t("widgets.add.title", "Add widget"))}</div>
    <div class="widgetsAddPanel__list">
      ${available.map((id) => (
        `<button class="btn ghost widgetsAddBtn" type="button" data-widget-add="${escAttr(id)}">+ ${esc(getWidgetLabel(id))}</button>`
      )).join("")}
    </div>
  `;
}

function bindWidgetsUiOnce() {
  if (widgetsUiBound) return;
  const root = $("tabWidgets");
  if (!root) return;
  widgetsUiBound = true;

  window.addEventListener("resize", () => {
    if (widgetsResizeRaf) cancelAnimationFrame(widgetsResizeRaf);
    widgetsResizeRaf = requestAnimationFrame(() => {
      widgetsResizeRaf = 0;
      const activeTab = document.querySelector("[data-tab].active")?.getAttribute("data-tab") || "";
      if (activeTab !== "widgets") return;
      renderWidgets();
    });
  });

  $("btnWidgetsEditMode")?.addEventListener("click", () => {
    if (widgetResizeDrag) finishWidgetResizeDrag(false);
    widgetsEditMode = !widgetsEditMode;
    widgetsDragId = "";
    widgetsDropTargetId = "";
    widgetsDropPosition = "before";
    clearWidgetDropMarkers();
    renderWidgets();
  });

  root.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;

    const sizeCycleBtn = target.closest("[data-widget-size-cycle]");
    if (sizeCycleBtn) {
      e.preventDefault();
      const id = String(sizeCycleBtn.getAttribute("data-widget-size-cycle") || "").trim();
      if (!id) return;
      if (!shiftWidgetSize(id, 1)) return;
      renderWidgets();
      return;
    }

    const clearNoteBtn = target.closest("[data-widget-note-clear]");
    if (clearNoteBtn) {
      e.preventDefault();
      saveWidgetNotesText("");
      renderWidgets();
      return;
    }

    const statusBtn = target.closest("[data-widget-set-status]");
    if (statusBtn) {
      e.preventDefault();
      const nextStatus = statusBtn.getAttribute("data-widget-set-status") || "online";
      void setWidgetStatus(nextStatus);
      return;
    }

    const todoToggleBtn = target.closest("[data-widget-todo-toggle]");
    if (todoToggleBtn) {
      e.preventDefault();
      toggleWidgetTodoItem(todoToggleBtn.getAttribute("data-widget-todo-toggle"));
      renderWidgets();
      return;
    }

    const todoRemoveBtn = target.closest("[data-widget-todo-remove]");
    if (todoRemoveBtn) {
      e.preventDefault();
      removeWidgetTodoItem(todoRemoveBtn.getAttribute("data-widget-todo-remove"));
      renderWidgets();
      return;
    }

    const todoAddBtn = target.closest("[data-widget-todo-add]");
    if (todoAddBtn) {
      e.preventDefault();
      const input = todoAddBtn.closest(".widgetCard")?.querySelector?.("[data-widget-todo-input]");
      const draftText = input && typeof input.value === "string" ? input.value : "";
      patchWidgetTodoDraftState({ text: draftText });
      submitWidgetTodoDraft();
      return;
    }

    const todoCancelEditBtn = target.closest("[data-widget-todo-cancel-edit]");
    if (todoCancelEditBtn) {
      e.preventDefault();
      resetWidgetTodoDraftState();
      renderWidgets();
      focusWidgetTodoComposerInput();
      return;
    }

    const todoClearDoneBtn = target.closest("[data-widget-todo-clear-done]");
    if (todoClearDoneBtn) {
      e.preventDefault();
      clearWidgetTodoDoneItems();
      renderWidgets();
      return;
    }

    const todoUpBtn = target.closest("[data-widget-todo-move-up]");
    if (todoUpBtn) {
      e.preventDefault();
      const id = todoUpBtn.getAttribute("data-widget-todo-move-up");
      if (!id) return;
      if (!moveWidgetTodoItem(id, -1)) return;
      renderWidgets();
      return;
    }

    const todoDownBtn = target.closest("[data-widget-todo-move-down]");
    if (todoDownBtn) {
      e.preventDefault();
      const id = todoDownBtn.getAttribute("data-widget-todo-move-down");
      if (!id) return;
      if (!moveWidgetTodoItem(id, 1)) return;
      renderWidgets();
      return;
    }

    const todoEditBtn = target.closest("[data-widget-todo-edit]");
    if (todoEditBtn) {
      e.preventDefault();
      const id = todoEditBtn.getAttribute("data-widget-todo-edit");
      if (!id) return;
      if (!startWidgetTodoEditing(id)) return;
      renderWidgets();
      focusWidgetTodoComposerInput({ selectAll: true });
      return;
    }

    const removeBtn = target.closest("[data-widget-remove]");
    if (removeBtn) {
      e.preventDefault();
      const id = removeBtn.getAttribute("data-widget-remove");
      setWidgetEnabled(id, false);
      renderWidgets();
      return;
    }

    const addBtn = target.closest("[data-widget-add]");
    if (addBtn) {
      e.preventDefault();
      const id = addBtn.getAttribute("data-widget-add");
      setWidgetEnabled(id, true);
      renderWidgets();
      return;
    }

    const openBtn = target.closest("[data-widget-open-tab]");
    if (openBtn) {
      if (widgetsEditMode) return;
      e.preventDefault();
      const nextTab = openBtn.getAttribute("data-widget-open-tab") || "friends";
      activateMainTab(nextTab, { ensureFriendsMode: true });
      return;
    }

    if (widgetsEditMode) return;
    if (target.closest("button,input,textarea,select,a,[contenteditable='true']")) return;
    const card = target.closest(".widgetCard[data-widget-id]");
    if (!card) return;
    // Card body clicks should not toggle visual state.
  });

  root.addEventListener("pointerdown", (e) => {
    if (!widgetsEditMode) return;
    if (e.button !== 0) return;
    const target = eventTargetElement(e);
    if (!target) return;
    const dragHandle = target.closest("[data-widget-drag]");
    if (dragHandle) {
      const card = dragHandle.closest(".widgetCard[data-widget-id]");
      if (!card) return;
      e.preventDefault();
      e.stopPropagation();
      startWidgetPointerDrag(card, e);
      return;
    }
    if (target.closest("[data-widget-resize-handle]")) return;
    if (target.closest("[data-widget-remove]")) return;
    if (target.closest("[data-widget-size-cycle]")) return;
    if (target.closest("[data-widget-add]")) return;
    if (target.closest("button,input,textarea,select,a,[contenteditable='true']")) return;
    const card = target.closest(".widgetCard[data-widget-id]");
    if (!card) return;
    e.preventDefault();
    startWidgetPointerDrag(card, e);
  });

  root.addEventListener("pointermove", (e) => {
    updateWidgetPointerDrag(root, e);
  });

  root.addEventListener("pointerup", (e) => {
    finishWidgetPointerDrag(root, e, { commit: true });
  });

  root.addEventListener("pointercancel", (e) => {
    finishWidgetPointerDrag(root, e, { commit: false });
  });

  root.addEventListener("pointerdown", (e) => {
    if (!widgetsEditMode) return;
    const target = eventTargetElement(e);
    const handle = target?.closest?.("[data-widget-resize-handle]");
    if (!handle) return;
    const widgetId = String(handle.getAttribute("data-widget-resize-handle") || "").trim();
    if (!widgetId) return;
    const card = handle.closest(".widgetCard[data-widget-id]");
    if (!card) return;
    e.preventDefault();
    e.stopPropagation();

    const metrics = getWidgetsGridMetrics();
    const startSize = getWidgetSize(widgetId);
    const startDims = getWidgetSizeDimensions(startSize, metrics.colCount);
    widgetsDragId = "";
    clearWidgetPreviewLayout($("widgetsGrid"), { animate: false });
    clearWidgetDropMarkers();
    widgetResizeDrag = {
      pointerId: e.pointerId,
      widgetId,
      handleEl: handle,
      cardEl: card,
      startX: e.clientX,
      startY: e.clientY,
      startSize,
      startDims,
      targetSize: startSize,
      metrics,
    };
    card.classList.add("is-resizing");
    card.setAttribute("data-resize-size", startSize);
    card.setAttribute("data-resize-size-label", getWidgetSizePreviewText(widgetId, startSize, metrics.colCount));
    applyWidgetCardSizeClass(card, startSize);
    try { handle.setPointerCapture(e.pointerId); } catch (_) {}
  });

  root.addEventListener("pointermove", (e) => {
    const drag = widgetResizeDrag;
    if (!drag || e.pointerId !== drag.pointerId) return;
    e.preventDefault();
    const metrics = drag.metrics || getWidgetsGridMetrics();
    const deltaX = e.clientX - drag.startX;
    const deltaY = e.clientY - drag.startY;
    const colStep = Math.max(74, (metrics.cellWidth + metrics.colGap) * 0.45);
    const rowStep = Math.max(62, (metrics.cellHeight + metrics.rowGap) * 0.45);
    const deltaCols = Math.round(deltaX / colStep);
    const deltaRows = Math.round(deltaY / rowStep);
    const targetCols = Math.max(1, Math.min(metrics.colCount, drag.startDims.cols + deltaCols));
    const targetRows = Math.max(1, drag.startDims.rows + deltaRows);
    const nextSize = pickWidgetSizeFromDims(targetCols, targetRows, metrics.colCount, drag.widgetId);
    if (nextSize === drag.targetSize) return;
    drag.targetSize = nextSize;
    if (drag.cardEl) {
      const gridEl = drag.cardEl.closest("#widgetsGrid");
      const activeIds = getActiveWidgetIds();
      const sizeOverrides = { [drag.widgetId]: nextSize };
      const placements = computeWidgetGridPlacements(activeIds, metrics.colCount, { sizeOverrides });
      syncWidgetPreviewLayout(gridEl, activeIds, placements, {
        duration: 250,
        easing: "cubic-bezier(0.2, 0.92, 0.2, 1)",
      });
      drag.cardEl.setAttribute("data-resize-size", nextSize);
      drag.cardEl.setAttribute("data-resize-size-label", getWidgetSizePreviewText(drag.widgetId, nextSize, metrics.colCount));
      const badge = drag.cardEl.querySelector(".widgetCardSizeBadge");
      if (badge) badge.textContent = WIDGET_SIZE_LABELS[nextSize] || nextSize.toUpperCase();
    }
  });

  root.addEventListener("pointerup", (e) => {
    const drag = widgetResizeDrag;
    if (!drag || e.pointerId !== drag.pointerId) return;
    e.preventDefault();
    finishWidgetResizeDrag(true);
  });

  root.addEventListener("pointercancel", (e) => {
    const drag = widgetResizeDrag;
    if (!drag || e.pointerId !== drag.pointerId) return;
    e.preventDefault();
    finishWidgetResizeDrag(false);
  });

  root.addEventListener("input", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const notesInput = target.closest("[data-widget-notes-input]");
    if (notesInput) {
      const nextText = saveWidgetNotesText(notesInput.value);
      if (notesInput.value !== nextText) notesInput.value = nextText;
      const countEl = notesInput.closest(".widgetCard")?.querySelector?.("[data-widget-notes-count]");
      if (countEl) countEl.textContent = `${nextText.length}/${WIDGET_NOTE_MAX_CHARS}`;
      return;
    }

    const todoInput = target.closest("[data-widget-todo-input]");
    if (todoInput) {
      const nextText = getWidgetTodoDraftText(todoInput.value);
      if (todoInput.value !== nextText) todoInput.value = nextText;
      patchWidgetTodoDraftState({ text: nextText });
      return;
    }

    const todoDateInput = target.closest("[data-widget-todo-due-date]");
    if (todoDateInput) {
      patchWidgetTodoDraftState({ dueDate: todoDateInput.value });
      return;
    }

    const todoTimeInput = target.closest("[data-widget-todo-due-time]");
    if (todoTimeInput) {
      patchWidgetTodoDraftState({ dueTime: todoTimeInput.value });
    }
  });

  root.addEventListener("change", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const todoDateInput = target.closest("[data-widget-todo-due-date]");
    if (todoDateInput) {
      patchWidgetTodoDraftState({ dueDate: todoDateInput.value });
      renderWidgets();
      return;
    }

    const todoTimeInput = target.closest("[data-widget-todo-due-time]");
    if (todoTimeInput) {
      patchWidgetTodoDraftState({ dueTime: todoTimeInput.value });
      return;
    }

    const todoReminderSelect = target.closest("[data-widget-todo-reminder]");
    if (todoReminderSelect) {
      patchWidgetTodoDraftState({ reminderPreset: todoReminderSelect.value });
    }
  });

  root.addEventListener("contextmenu", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const sizeCycleBtn = target.closest("[data-widget-size-cycle]");
    if (!sizeCycleBtn) return;
    e.preventDefault();
    const id = String(sizeCycleBtn.getAttribute("data-widget-size-cycle") || "").trim();
    if (!id) return;
    if (!shiftWidgetSize(id, -1)) return;
    renderWidgets();
  });

  root.addEventListener("keydown", (e) => {
    if (e.key !== "Enter" || e.shiftKey) return;
    const target = eventTargetElement(e);
    if (!target) return;
    const todoInput = target.closest("[data-widget-todo-input]");
    if (!todoInput) return;
    e.preventDefault();
    patchWidgetTodoDraftState({ text: todoInput.value });
    submitWidgetTodoDraft();
  });

  root.addEventListener("dragstart", (e) => {
    if (!widgetsEditMode || widgetResizeDrag) return;
    const target = eventTargetElement(e);
    if (target?.closest?.("[data-widget-resize-handle]")) return;
    if (target?.closest?.("[data-widget-size-cycle]")) return;
    if (target?.closest?.("[data-widget-remove]")) return;
    const card = target?.closest?.(".widgetCard[data-widget-id]");
    if (!card) return;
    const id = card.getAttribute("data-widget-id");
    if (!id) return;
    widgetsDragId = id;
    widgetsDropTargetId = "";
    widgetsDropPosition = "before";
    widgetsDropGridCell = null;
    card.classList.add("is-dragging");
    root.classList.add("is-widget-dragging");
    createWidgetDragPreview(card);
    const rect = card.getBoundingClientRect();
    const startX = Number.isFinite(Number(e.clientX)) && Number(e.clientX) > 0
      ? Number(e.clientX)
      : Math.round(rect.left + (rect.width * 0.42));
    const startY = Number.isFinite(Number(e.clientY)) && Number(e.clientY) > 0
      ? Number(e.clientY)
      : Math.round(rect.top + (rect.height * 0.34));
    moveWidgetDragPreview(startX, startY);
    try {
      e.dataTransfer.effectAllowed = "move";
      e.dataTransfer.setData("text/plain", id);
      const transparentImg = getWidgetTransparentDragImage();
      if (transparentImg && e.dataTransfer.setDragImage) {
        e.dataTransfer.setDragImage(transparentImg, 0, 0);
      }
    } catch (_) {}
  });

  root.addEventListener("dragover", (e) => {
    if (!widgetsEditMode || !widgetsDragId) return;
    moveWidgetDragPreview(e.clientX, e.clientY);
    const x = Number(e.clientX);
    const y = Number(e.clientY);
    const grid = $("widgetsGrid");
    const editBar = $("widgetsEditBar");
    const addPanel = $("widgetsAddPanel");
    if (grid && isPointerInsideElement(grid, x, y)) {
      e.preventDefault();
      const cell = getWidgetGridCellFromEvent(grid, e, widgetsDragId);
      widgetsDropTargetId = "";
      widgetsDropPosition = "before";
      clearWidgetDropMarkers({ keepDragging: true });
      widgetsDropGridCell = cell;
      if (cell) upsertWidgetsDropGhost(grid, cell, widgetsDragId);
      try { e.dataTransfer.dropEffect = "move"; } catch (_) {}
      return;
    }

    widgetsDropGridCell = null;
    if (isPointerInsideElement(editBar, x, y) || isPointerInsideElement(addPanel, x, y)) {
      const firstCard = root.querySelector(".widgetCard[data-widget-id]");
      const firstId = firstCard?.getAttribute("data-widget-id");
      if (!firstId || firstId === widgetsDragId) return;
      e.preventDefault();
      widgetsDropTargetId = firstId;
      widgetsDropPosition = "before";
      clearWidgetDropMarkers({ keepDragging: true });
      firstCard.classList.add("is-drop-target", "is-drop-before");
      try { e.dataTransfer.dropEffect = "move"; } catch (_) {}
      return;
    }

    widgetsDropTargetId = "";
    widgetsDropPosition = "before";
    clearWidgetDropMarkers({ keepDragging: true });
  });

  root.addEventListener("drop", (e) => {
    if (!widgetsEditMode || !widgetsDragId) return;
    moveWidgetDragPreview(e.clientX, e.clientY);
    const grid = $("widgetsGrid");
    const editBar = $("widgetsEditBar");
    const addPanel = $("widgetsAddPanel");
    const x = Number(e.clientX);
    const y = Number(e.clientY);
    if (grid && isPointerInsideElement(grid, x, y)) {
      e.preventDefault();
      if (widgetsDropGridCell) {
        moveWidgetToGridCell(widgetsDragId, widgetsDropGridCell, getWidgetsGridMetrics().colCount);
      } else {
        const next = getWidgetDropTargetFromGridPoint(grid, widgetsDragId, e);
        if (next.targetId && next.targetId !== widgetsDragId) {
          moveWidget(widgetsDragId, next.targetId, next.position || "before");
        } else {
          moveWidget(widgetsDragId, "", "end");
        }
      }
      widgetsDragId = "";
      widgetsDropTargetId = "";
      widgetsDropPosition = "before";
      widgetsDropGridCell = null;
      removeWidgetDragPreview();
      clearWidgetDropMarkers();
      renderWidgets();
      return;
    }

    if (isPointerInsideElement(editBar, x, y) || isPointerInsideElement(addPanel, x, y)) {
      const firstCard = root.querySelector(".widgetCard[data-widget-id]");
      const firstId = firstCard?.getAttribute("data-widget-id");
      if (!firstId || firstId === widgetsDragId) return;
      e.preventDefault();
      moveWidget(widgetsDragId, firstId, "before");
      widgetsDragId = "";
      widgetsDropTargetId = "";
      widgetsDropPosition = "before";
      widgetsDropGridCell = null;
      removeWidgetDragPreview();
      clearWidgetDropMarkers();
      renderWidgets();
      return;
    }

    if (widgetsDropTargetId && widgetsDropTargetId !== widgetsDragId) {
      moveWidget(widgetsDragId, widgetsDropTargetId, widgetsDropPosition);
    } else {
      return;
    }

    widgetsDragId = "";
    widgetsDropTargetId = "";
    widgetsDropPosition = "before";
    widgetsDropGridCell = null;
    removeWidgetDragPreview();
    clearWidgetDropMarkers();
    renderWidgets();
  });

  root.addEventListener("dragend", () => {
    widgetsDragId = "";
    widgetsDropTargetId = "";
    widgetsDropPosition = "before";
    widgetsDropGridCell = null;
    removeWidgetDragPreview();
    root.classList.remove("is-widget-dragging");
    clearWidgetDropMarkers();
  });
}

const MAIN_NAV_HISTORY_MAX = 120;
let mainNavHistoryBack = [];
let mainNavHistoryForward = [];
let mainNavHistoryApplying = false;
let mainNavControlsBound = false;
let mainNavDesktopCommandUnsub = null;
let mainNavLastCommandKind = "";
let mainNavLastCommandAt = 0;
const MAIN_NAV_COMMAND_DEDUPE_MS = 180;

function cloneMainNavRoute(route) {
  if (!route || typeof route !== "object") return null;
  if (route.mode === "dm") {
    const conversationId = normId(route.conversationId || "");
    if (!conversationId) return null;
    return { mode: "dm", conversationId };
  }
  const allowed = new Set(["widgets", "friends", "pending", "add"]);
  const tab = allowed.has(String(route.tab || "").trim()) ? String(route.tab).trim() : "widgets";
  return { mode: "tab", tab };
}

function getMainNavRouteKey(route) {
  const r = cloneMainNavRoute(route);
  if (!r) return "";
  return r.mode === "dm"
    ? `dm:${r.conversationId}`
    : `tab:${r.tab}`;
}

function getCurrentMainNavigationRoute() {
  const dmMain = document.getElementById("dmMain");
  const dmVisible = !!dmMain && dmMain.style.display !== "none";
  const conversationId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (dmVisible && conversationId) return { mode: "dm", conversationId };
  const tab = document.querySelector("[data-tab].active")?.getAttribute("data-tab") || "widgets";
  return cloneMainNavRoute({ mode: "tab", tab });
}

function updateMainNavButtonState() {
  const backBtn = document.getElementById("btnNavBack");
  const fwdBtn = document.getElementById("btnNavForward");
  if (backBtn) backBtn.disabled = mainNavHistoryBack.length <= 1;
  if (fwdBtn) fwdBtn.disabled = mainNavHistoryForward.length === 0;
}

function captureCurrentMainNavigationRoute({ replace = false } = {}) {
  if (mainNavHistoryApplying) return;
  const route = getCurrentMainNavigationRoute();
  const key = getMainNavRouteKey(route);
  if (!key) return;

  if (!mainNavHistoryBack.length) {
    mainNavHistoryBack.push(route);
    mainNavHistoryForward = [];
    updateMainNavButtonState();
    return;
  }

  const currentKey = getMainNavRouteKey(mainNavHistoryBack[mainNavHistoryBack.length - 1]);
  if (replace) {
    if (currentKey !== key) {
      mainNavHistoryBack[mainNavHistoryBack.length - 1] = route;
    }
    mainNavHistoryForward = [];
    updateMainNavButtonState();
    return;
  }

  if (currentKey === key) {
    updateMainNavButtonState();
    return;
  }

  mainNavHistoryBack.push(route);
  if (mainNavHistoryBack.length > MAIN_NAV_HISTORY_MAX) {
    mainNavHistoryBack = mainNavHistoryBack.slice(mainNavHistoryBack.length - MAIN_NAV_HISTORY_MAX);
  }
  mainNavHistoryForward = [];
  updateMainNavButtonState();
}

function isEditableTargetForMainNav(target) {
  return !!getEditableTypingElementFromTarget(target);
}

async function applyMainNavigationRoute(route) {
  const targetRoute = cloneMainNavRoute(route);
  if (!targetRoute) return false;
  mainNavHistoryApplying = true;
  try {
    if (targetRoute.mode === "dm") {
      await showDm(targetRoute.conversationId, { autoAnswerIfPending: true });
      return true;
    }
    if (normId(activeDmId || state.activeDm?.conversationId || "")) {
      leaveActiveDmView({ captureHistory: false });
    }
    activateMainTab(targetRoute.tab || "widgets", { ensureFriendsMode: true });
    return true;
  } catch (_) {
    return false;
  } finally {
    mainNavHistoryApplying = false;
    updateMainNavButtonState();
  }
}

async function goMainNavigationBack() {
  if (mainNavHistoryApplying) return;
  if (mainNavHistoryBack.length <= 1) {
    updateMainNavButtonState();
    return;
  }

  const current = mainNavHistoryBack.pop();
  if (current) mainNavHistoryForward.push(current);
  const target = mainNavHistoryBack[mainNavHistoryBack.length - 1];
  const applied = await applyMainNavigationRoute(target);
  if (!applied) {
    const restore = mainNavHistoryForward.pop();
    if (restore) mainNavHistoryBack.push(restore);
  }
  updateMainNavButtonState();
}

async function goMainNavigationForward() {
  if (mainNavHistoryApplying) return;
  if (!mainNavHistoryForward.length) {
    updateMainNavButtonState();
    return;
  }

  const target = mainNavHistoryForward.pop();
  if (!target) {
    updateMainNavButtonState();
    return;
  }
  const applied = await applyMainNavigationRoute(target);
  if (applied) {
    mainNavHistoryBack.push(target);
    if (mainNavHistoryBack.length > MAIN_NAV_HISTORY_MAX) {
      mainNavHistoryBack = mainNavHistoryBack.slice(mainNavHistoryBack.length - MAIN_NAV_HISTORY_MAX);
    }
  } else {
    mainNavHistoryForward.push(target);
  }
  updateMainNavButtonState();
}

function shouldIgnoreDuplicateMainNavCommand(kindInput, sourceInput = "generic") {
  const kind = String(kindInput || "").trim().toLowerCase();
  if (kind !== "back" && kind !== "forward") return true;
  const source = String(sourceInput || "").trim().toLowerCase();
  // UI button clicks are intentional and should not be throttled.
  if (source === "ui") return false;
  const now = Date.now();
  if (
    mainNavLastCommandKind === kind
    && (now - mainNavLastCommandAt) <= MAIN_NAV_COMMAND_DEDUPE_MS
  ) {
    return true;
  }
  mainNavLastCommandKind = kind;
  mainNavLastCommandAt = now;
  return false;
}

function triggerMainNavigationCommand(kindInput, options = {}) {
  const kind = String(kindInput || "").trim().toLowerCase();
  const source = String(options?.source || "generic").trim().toLowerCase();
  if (shouldIgnoreDuplicateMainNavCommand(kind, source)) return;
  if (kind === "back") {
    void goMainNavigationBack();
    return;
  }
  if (kind === "forward") void goMainNavigationForward();
}

function navigateToHomeView({ captureHistory = true } = {}) {
  if (normId(activeDmId || state.activeDm?.conversationId || "")) {
    leaveActiveDmView({ captureHistory: !!captureHistory });
  }
  activateMainTab("widgets", { ensureFriendsMode: true });
  renderGroupsRail();
}

function bindMainNavigationControlsOnce() {
  if (mainNavControlsBound) return;
  mainNavControlsBound = true;

  const btnBack = document.getElementById("btnNavBack");
  const btnForward = document.getElementById("btnNavForward");
  btnBack?.addEventListener("click", () => {
    triggerMainNavigationCommand("back", { source: "ui" });
  });
  btnForward?.addEventListener("click", () => {
    triggerMainNavigationCommand("forward", { source: "ui" });
  });

  window.addEventListener("mousedown", (e) => {
    if (!e || e.defaultPrevented) return;
    if (e.button !== 3 && e.button !== 4) return;
    if (isEditableTargetForMainNav(e.target)) return;
    if (e.ctrlKey || e.shiftKey || e.altKey || e.metaKey) return;
    e.preventDefault();
    e.stopPropagation();
    if (e.button === 3) triggerMainNavigationCommand("back", { source: "mouse" });
    else triggerMainNavigationCommand("forward", { source: "mouse" });
  }, true);

  try {
    const bridge = getDesktopBridge();
    if (bridge && typeof bridge.onAppNavigationCommand === "function") {
      mainNavDesktopCommandUnsub = bridge.onAppNavigationCommand((payload) => {
        const cmd = String(payload?.command || "").trim().toLowerCase();
        if (cmd === "back" || cmd === "forward") triggerMainNavigationCommand(cmd, { source: "desktop" });
      });
    }
  } catch (_) {}

  captureCurrentMainNavigationRoute({ replace: true });
  updateMainNavButtonState();
}

function activateMainTab(tabId, { ensureFriendsMode = true } = {}) {
  const allowed = new Set(["widgets", "friends", "pending", "add"]);
  const tab = allowed.has(String(tabId || "").trim()) ? String(tabId).trim() : "widgets";

  document.querySelectorAll("[data-tab]").forEach((x) => {
    x.classList.toggle("active", x.getAttribute("data-tab") === tab);
  });

  if (ensureFriendsMode) {
    // Se vieres de uma DM, volta para o modo normal do painel central.
    setMidMode("friends");
  }

  const tabWidgets = $("tabWidgets");
  const tabFriends = $("tabFriends");
  const tabPending = $("tabPending");
  const tabAdd = $("tabAdd");
  if (tabWidgets) tabWidgets.style.display = (tab === "widgets") ? "block" : "none";
  if (tabFriends) tabFriends.style.display = (tab === "friends") ? "block" : "none";
  if (tabPending) tabPending.style.display = (tab === "pending") ? "block" : "none";
  if (tabAdd) tabAdd.style.display = (tab === "add") ? "block" : "none";

  const title = tab === "widgets"
    ? t("tab.widgets", "Widgets")
    : tab === "friends"
      ? t("tab.friends", "Friends")
      : tab === "pending"
        ? t("tab.pending", "Pending")
        : t("tab.add", "Add Friend");
  const sub = tab === "widgets"
    ? t("tab.sub.widgets", "Main dashboard with widgets.")
    : tab === "friends"
      ? t("tab.sub.friends", "List of accepted friends.")
      : tab === "pending"
        ? t("tab.sub.pending", "Received and sent friend requests.")
        : t("tab.sub.add", "Send a friend request.");

  const midTitle = $("midTitle");
  if (midTitle) midTitle.textContent = title;
  const midSub = $("midSub");
  if (midSub) midSub.textContent = sub;

  if (tab === "widgets") renderWidgets();
  if (tab === "add") {
    renderPartyPicker();
    scheduleAddFriendProfileLookup({ immediate: true, force: false });
  }
  captureCurrentMainNavigationRoute();
}

function setupTabs() {
  document.querySelectorAll("[data-tab]").forEach(p => {
    p.addEventListener("click", () => {
      const t = p.getAttribute("data-tab");
      activateMainTab(t, { ensureFriendsMode: true });
    });
  });
  bindWidgetsUiOnce();

  document.querySelectorAll("[data-left]").forEach(p => {
    p.addEventListener("click", () => {
      document.querySelectorAll("[data-left]").forEach(x => x.classList.remove("active"));
      p.classList.add("active");

      const t = p.getAttribute("data-left");
      $("leftFriends").style.display = (t === "friends") ? "block" : "none";
      $("leftDms").style.display = (t === "dms") ? "block" : "none";
      $("leftGroups").style.display = (t === "groups") ? "block" : "none";
    });
  });

  const scheduleFriendSearchRender = () => {
    if (friendSearchRenderRaf) cancelAnimationFrame(friendSearchRenderRaf);
    friendSearchRenderRaf = requestAnimationFrame(() => {
      friendSearchRenderRaf = 0;
      renderFriends({ skipPresenceRefresh: true });
    });
  };

  const bindFriendSearchInput = (id) => {
    const input = $(id);
    if (!input) return;
    input.addEventListener("input", () => {
      syncFriendSearchInputs(input.value, id);
      scheduleFriendSearchRender();
    });
  };
  bindFriendSearchInput("friendSearch");
  bindFriendSearchInput("friendSearchMain");
  syncFriendSearchInputs($("friendSearchMain")?.value || $("friendSearch")?.value || "");
  const activeTab = document.querySelector("[data-tab].active")?.getAttribute("data-tab") || "widgets";
  activateMainTab(activeTab, { ensureFriendsMode: false });
}

/* ========================= DM MODE + DOCK CALL STAGE ========================= */
let callStageRootParent = null;
let callBarRootParent = null;
let callBarSidebarParent = null;

function dockStageIntoDm(yes, { barInSidebar = false } = {}) {
  const stage = document.getElementById("callStage");
  const bar = document.getElementById("callBar");
  const dock = document.getElementById("dmCallDock");
  const leftSidebar = document.querySelector(".panel.left");
  if (!stage || !bar) return;

  if (!callStageRootParent) callStageRootParent = stage.parentElement || document.body;
  if (!callBarRootParent) callBarRootParent = bar.parentElement || document.body;
  if (!callBarSidebarParent) callBarSidebarParent = leftSidebar || null;

  const shouldDockStageInDm = !!yes && !!dock;
  const shouldDockBarInSidebar = (!!barInSidebar || !shouldDockStageInDm) && !!callBarSidebarParent;
  const shouldDockBarInDm = shouldDockStageInDm && !shouldDockBarInSidebar;
  stage.classList.toggle("is-docked-in-dm", shouldDockStageInDm);
  bar.classList.toggle("is-docked-in-dm", shouldDockBarInDm);
  bar.classList.toggle("is-docked-in-sidebar", shouldDockBarInSidebar);

  if (shouldDockStageInDm) {
    if (stage.parentElement !== dock) dock.appendChild(stage);
  } else if (stage.parentElement !== callStageRootParent) {
    callStageRootParent.appendChild(stage);
  }

  if (shouldDockBarInDm) {
    if (bar.parentElement !== dock) dock.appendChild(bar);
    return;
  }
  if (shouldDockBarInSidebar) {
    if (bar.parentElement !== callBarSidebarParent) callBarSidebarParent.appendChild(bar);
    return;
  }
  if (bar.parentElement !== callBarRootParent) callBarRootParent.appendChild(bar);
}

function setMidMode(mode) {
  const dmMain = document.getElementById("dmMain");
  if (!dmMain) return;
  const midBody = dmMain.closest(".panelBody") || document.querySelector(".midBody");
  const appShell = document.querySelector(".app");
  const activeMeta = getActiveConversationMeta(activeDmId) || state.activeDm || {};
  const isServerConversation = isServerConversationKind(activeMeta?.kind) || !!normId(activeMeta?.serverId || "");
  const callActiveNow = !!(
    inCall ||
    (
      callPc &&
      callPc.connectionState !== "closed" &&
      callPc.connectionState !== "failed"
    )
  );

  if (mode === "dm") {
    $("tabWidgets").style.display = "none";
    $("tabFriends").style.display = "none";
    $("tabPending").style.display = "none";
    $("tabAdd").style.display = "none";
    dmMain.style.display = "flex";
    midBody?.classList.add("is-dm-open");
    if (isServerConversation) appShell?.classList.remove("dm-focus");
    else appShell?.classList.add("dm-focus");
    if (callActiveNow) stageOpen = true;

    // palco dentro da DM quando estÃ¡s em chamada
    dockStageIntoDm(true);
    updateDmJumpLatestButton(document.getElementById("dmMessages"));
  } else {
    stageOpen = false;
    dmMain.style.display = "none";
    midBody?.classList.remove("is-dm-open");
    appShell?.classList.remove("dm-focus");
    stopActiveGroupDmCallStatePolling();

    const activeTab = document.querySelector("[data-tab].active")?.getAttribute("data-tab") || "widgets";
    $("tabWidgets").style.display = (activeTab === "widgets") ? "block" : "none";
    $("tabFriends").style.display = (activeTab === "friends") ? "block" : "none";
    $("tabPending").style.display = (activeTab === "pending") ? "block" : "none";
    $("tabAdd").style.display = (activeTab === "add") ? "block" : "none";

    // fora da DM, volta ao normal
    dockStageIntoDm(false);
    setDmJumpLatestVisible(false);
    setRightSidebarInteractionModeForConversation({
      serverMode: false,
      forceHidden: false,
      applyCollapsed: true,
    });
  }

  void refreshServerConversationUi({ force: false }).catch(() => {});
  refreshCallUI();
  renderGroupsRail();
  syncDmActiveListHighlight();
  renderWidgets();
}

/* ========================= FRIENDS / REQUESTS ========================= */
function isMissingRpcError(error) {
  const code = String(error?.code || "").trim().toUpperCase();
  const msg = String(error?.message || "").toLowerCase();
  if (code === "PGRST202" || code === "42883") return true;
  return msg.includes("could not find the function")
    || msg.includes("function public.")
    || msg.includes("does not exist");
}

function getSupabaseProjectRefLabel() {
  try {
    const host = new URL(String(SUPABASE_URL || "")).host || "";
    const ref = String(host.split(".")[0] || "").trim();
    return ref || "project-desconhecido";
  } catch (_) {
    return "project-desconhecido";
  }
}

function normalizeConversationLabel(value, fallback = "Group DM") {
  const raw = String(value || "").trim();
  if (!raw) return fallback;
  if (raw.length <= 72) return raw;
  return `${raw.slice(0, 72)}...`;
}

function getDefaultGroupDmName() {
  const creator = normalizeConversationLabel(
    String(state.me?.display_name || state.me?.username || state.user?.email || "").trim(),
    "Creator"
  );
  return normalizeConversationLabel(`${creator} group`, "Group DM");
}

function normalizeUuidArray(value) {
  if (!Array.isArray(value)) return [];
  const out = [];
  const seen = new Set();
  value.forEach((entry) => {
    const id = normId(entry);
    if (!id || seen.has(id)) return;
    seen.add(id);
    out.push(id);
  });
  return out;
}

function normalizeTextArray(value) {
  if (!Array.isArray(value)) return [];
  return value.map((entry) => String(entry || "").trim());
}

function normalizeGroupDmRow(row = {}) {
  const conversationId = normId(row?.conversation_id || row?.id);
  if (!conversationId) return null;
  const name = normalizeConversationLabel(row?.name, "Group DM");
  const ownerUserId = normId(row?.owner_user_id || row?.created_by || row?.owner_id || "");
  const memberIds = normalizeUuidArray(row?.member_ids);
  const memberUsernames = normalizeTextArray(row?.member_usernames);
  const memberDisplayNames = normalizeTextArray(row?.member_display_names);
  const memberAvatars = normalizeTextArray(row?.member_avatars);
  const memberCountRaw = Number(row?.member_count);
  const memberCount = Number.isFinite(memberCountRaw) && memberCountRaw > 0
    ? Math.round(memberCountRaw)
    : Math.max(memberIds.length, memberDisplayNames.length, memberUsernames.length);
  const lastMessageAtRaw = Date.parse(String(row?.last_message_at || ""));
  const lastMessageAt = Number.isFinite(lastMessageAtRaw) ? lastMessageAtRaw : 0;
  const explicitAvatarUrl = String(row?.avatar_url || row?.group_avatar_url || "").trim();
  const avatarUrl = explicitAvatarUrl || memberAvatars.find((x) => !!String(x || "").trim()) || "";
  return {
    conversationId,
    kind: "group",
    name,
    ownerUserId,
    memberCount: Math.max(0, memberCount),
    memberIds,
    memberUsernames,
    memberDisplayNames,
    memberAvatars,
    avatarUrl,
    lastMessageAt,
  };
}

function normalizeServerRow(row = {}) {
  const serverId = normId(row?.server_id || row?.id);
  const defaultConversationId = normId(row?.default_conversation_id || row?.conversation_id);
  if (!serverId || !defaultConversationId) return null;
  const name = normalizeConversationLabel(row?.name, "Server");
  const iconUrl = sanitizeServerIconUrl(row?.icon_url || "");
  const welcomeConversationId = normId(
    row?.welcome_channel_id
    || row?.welcome_conversation_id
    || ""
  );
  const ownerUserId = normId(row?.owner_user_id || "");
  const memberCountRaw = Number(row?.member_count);
  const memberCount = Number.isFinite(memberCountRaw) && memberCountRaw > 0 ? Math.round(memberCountRaw) : 1;
  return {
    serverId,
    defaultConversationId,
    welcomeConversationId,
    name,
    iconUrl,
    ownerUserId,
    memberCount,
    kind: "server",
  };
}

function sanitizeServerIconUrl(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return "";
  const lower = raw.toLowerCase();
  if (lower.includes("/server_")) return raw;
  if (lower.includes("/avatar_") || lower.includes("/group_")) return "";
  return raw;
}

function setConversationMeta(conversationId, meta = {}) {
  const id = normId(conversationId);
  if (!id) return;
  const prev = dmConversationMetaById.get(id) || {};
  dmConversationMetaById.set(id, { ...prev, ...meta, conversationId: id });
}

function getConversationMeta(conversationId) {
  const id = normId(conversationId);
  if (!id) return null;
  return dmConversationMetaById.get(id) || null;
}

function normalizeDmPrivacyState(value = "") {
  const state = String(value || "").trim().toLowerCase();
  if (state === "private_pending" || state === "private_active") return state;
  return "standard";
}

function normalizeDmPrivacyEpoch(value, fallback = 0) {
  const epoch = Math.max(0, Number(value ?? fallback) || 0);
  return Number.isFinite(epoch) ? epoch : Math.max(0, Number(fallback) || 0);
}

function buildDmPrivacyConversationSelectColumns() {
  const base = [
    "id",
    "kind",
    "dm_privacy_state",
    "dm_privacy_request_nonce",
    "dm_privacy_requested_by",
    "dm_privacy_requested_at",
    "dm_privacy_activated_at",
    "dm_privacy_disabled_at",
    "dm_privacy_disabled_by",
    "dm_privacy_epoch",
    "dm_privacy_source",
  ];
  if (dmFeatureCaps.dmPrivacyDisableRequest) {
    base.push(
      "dm_privacy_disable_request_nonce",
      "dm_privacy_disable_requested_by",
      "dm_privacy_disable_requested_at"
    );
  }
  return base.join(", ");
}

function buildDmPrivacyMeta(source = {}, { fallbackKind = "" } = {}) {
  const input = source && typeof source === "object" ? source : {};
  const rawKind = String(input.kind || fallbackKind || "").trim().toLowerCase();
  const isDirectDm = rawKind === "dm";
  if (isDirectDm && !DM_PRIVATE_RUNTIME_ENABLED) {
    return {
      dmPrivacyState: "standard",
      dmPrivacyRequestNonce: "",
      dmPrivacyRequestedBy: "",
      dmPrivacyRequestedAt: "",
      dmPrivacyActivatedAt: "",
      dmPrivacyDisabledAt: "",
      dmPrivacyDisabledBy: "",
      dmPrivacyDisableRequestNonce: "",
      dmPrivacyDisableRequestedBy: "",
      dmPrivacyDisableRequestedAt: "",
      dmPrivacyEpoch: 0,
      dmPrivacySource: "runtime_disabled",
      dmPrivacyLegacyCompat: false,
    };
  }
  const compatLegacyPrivate = !!(
    isDirectDm
    && !dmFeatureCaps.dmPrivacyState
    && dmFeatureCaps.e2eeMessages
  );
  const state = normalizeDmPrivacyState(
    input.dmPrivacyState
    || input.dm_privacy_state
    || (compatLegacyPrivate ? "private_active" : "standard")
  );
  const epoch = normalizeDmPrivacyEpoch(
    input.dmPrivacyEpoch ?? input.dm_privacy_epoch,
    state === "private_active" ? 1 : 0
  );
  return {
    dmPrivacyState: state,
    dmPrivacyRequestNonce: normId(input.dmPrivacyRequestNonce || input.dm_privacy_request_nonce || ""),
    dmPrivacyRequestedBy: normId(input.dmPrivacyRequestedBy || input.dm_privacy_requested_by || ""),
    dmPrivacyRequestedAt: String(input.dmPrivacyRequestedAt || input.dm_privacy_requested_at || "").trim(),
    dmPrivacyActivatedAt: String(input.dmPrivacyActivatedAt || input.dm_privacy_activated_at || "").trim(),
    dmPrivacyDisabledAt: String(input.dmPrivacyDisabledAt || input.dm_privacy_disabled_at || "").trim(),
    dmPrivacyDisabledBy: normId(input.dmPrivacyDisabledBy || input.dm_privacy_disabled_by || ""),
    dmPrivacyDisableRequestNonce: normId(input.dmPrivacyDisableRequestNonce || input.dm_privacy_disable_request_nonce || ""),
    dmPrivacyDisableRequestedBy: normId(input.dmPrivacyDisableRequestedBy || input.dm_privacy_disable_requested_by || ""),
    dmPrivacyDisableRequestedAt: String(input.dmPrivacyDisableRequestedAt || input.dm_privacy_disable_requested_at || "").trim(),
    dmPrivacyEpoch: epoch,
    dmPrivacySource: String(input.dmPrivacySource || input.dm_privacy_source || (compatLegacyPrivate ? "legacy_compat" : "user")).trim().toLowerCase() || "user",
    dmPrivacyLegacyCompat: compatLegacyPrivate,
  };
}

function applyConversationDmPrivacyMeta(conversationId, source = {}) {
  const convId = normId(conversationId || "");
  if (!convId) return buildDmPrivacyMeta(source);
  const cached = getConversationMeta(convId) || {};
  const active = normId(state.activeDm?.conversationId || activeDmId || "") === convId
    ? (state.activeDm || {})
    : {};
  const merged = { ...cached, ...active, ...(source && typeof source === "object" ? source : {}) };
  const meta = buildDmPrivacyMeta(merged, {
    fallbackKind: String(merged.kind || cached.kind || active.kind || "").trim().toLowerCase(),
  });
  setConversationMeta(convId, meta);
  if (normId(state.activeDm?.conversationId || activeDmId || "") === convId) {
    state.activeDm = {
      ...(state.activeDm || {}),
      ...meta,
    };
  }
  return meta;
}

function getConversationDmPrivacyMeta(conversationId = null) {
  const convId = normId(conversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return buildDmPrivacyMeta({});
  const merged = getActiveConversationMeta(convId) || getConversationMeta(convId) || {};
  return buildDmPrivacyMeta(merged, {
    fallbackKind: String(merged.kind || "").trim().toLowerCase(),
  });
}

function conversationHasPendingDisableRequest(conversationId = null) {
  if (!DM_PRIVATE_RUNTIME_ENABLED) return false;
  const meta = getConversationDmPrivacyMeta(conversationId);
  return meta.dmPrivacyState === "private_active" && !!meta.dmPrivacyDisableRequestNonce;
}

function conversationRequiresEncryptedText(conversationId = null) {
  if (!DM_PRIVATE_RUNTIME_ENABLED) return false;
  return getConversationDmPrivacyMeta(conversationId).dmPrivacyState === "private_active";
}

function activeDmRequiresEncryptedText() {
  const activeKind = String(state.activeDm?.kind || "").trim().toLowerCase();
  if (activeKind !== "dm") return false;
  return conversationRequiresEncryptedText(activeDmId || state.activeDm?.conversationId || "");
}

function isGroupConversationKind(kind) {
  return String(kind || "").trim().toLowerCase() === "group";
}

function isServerConversationKind(kind) {
  return String(kind || "").trim().toLowerCase() === "server";
}

function normalizeConversationChannelType(value) {
  return String(value || "").trim().toLowerCase() === "voice" ? "voice" : "text";
}

const SERVER_VOICE_MEDIA_MODE_META = Object.freeze({
  audio_only: Object.freeze({
    key: "audio_only",
    label: "Audio only",
    description: "Microphones only. Camera and screen share stay off.",
    participantCap: 25,
    supportsVideo: false,
    supportsScreenshare: false,
    comingSoon: false,
  }),
  video_enabled: Object.freeze({
    key: "video_enabled",
    label: "Video enabled",
    description: "Members can use microphones and cameras.",
    participantCap: 25,
    supportsVideo: true,
    supportsScreenshare: false,
    comingSoon: false,
  }),
  screenshare_enabled: Object.freeze({
    key: "screenshare_enabled",
    label: "Screen share enabled",
    description: "Members can use microphones, cameras, and screen share.",
    participantCap: 25,
    supportsVideo: true,
    supportsScreenshare: true,
    screenshareViewerCap: 20,
    comingSoon: false,
  }),
  stage_like: Object.freeze({
    key: "stage_like",
    label: "Stage-like",
    description: "Stage-like channels are coming soon.",
    participantCap: 25,
    supportsVideo: false,
    supportsScreenshare: false,
    comingSoon: true,
  }),
});

function normalizeServerVoiceMediaMode(value, fallback = "audio_only") {
  const raw = String(value || "").trim().toLowerCase();
  if (Object.prototype.hasOwnProperty.call(SERVER_VOICE_MEDIA_MODE_META, raw)) return raw;
  return Object.prototype.hasOwnProperty.call(SERVER_VOICE_MEDIA_MODE_META, fallback) ? fallback : "audio_only";
}

function getServerVoiceMediaModeMeta(value) {
  return SERVER_VOICE_MEDIA_MODE_META[normalizeServerVoiceMediaMode(value)] || SERVER_VOICE_MEDIA_MODE_META.audio_only;
}

function clampServerVoiceUserLimit(value, fallback = 0) {
  return clampInt(value, 0, 99, fallback);
}

function buildServerVoiceChannelSettingsSummary({
  mediaMode = "audio_only",
  userLimit = 0,
} = {}) {
  const modeMeta = getServerVoiceMediaModeMeta(mediaMode);
  const manualLimit = clampServerVoiceUserLimit(userLimit, 0);
  const limitText = manualLimit > 0 ? `Manual limit ${manualLimit}` : "No manual limit";
  return `${modeMeta.label} â€¢ ${limitText}`;
}

function normalizeServerCategoryName(value, fallback = "Category") {
  const next = String(value || "").trim().replace(/\s+/g, " ");
  const safeFallback = String(fallback || "Category").trim() || "Category";
  if (!next) return safeFallback;
  return next.slice(0, 60);
}

function findServerChannelContextByConversationId(conversationId = null) {
  const convId = normId(conversationId || "");
  if (!convId) return null;
  for (const [sid, channels] of serverChannelListByServerId.entries()) {
    const list = Array.isArray(channels) ? channels : [];
    const hit = list.find((ch) => normId(ch?.conversationId || "") === convId) || null;
    if (!hit) continue;
    return { serverId: normId(sid), channel: hit };
  }
  return null;
}

async function resolveServerConversationMembershipContext(conversationId, {
  allowLookup = true,
} = {}) {
  const convId = normId(conversationId || "");
  if (!convId) return null;

  const cachedCtx = findServerChannelContextByConversationId(convId) || null;
  const cachedMeta = getConversationMeta(convId) || {};
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  const activeMeta = activeConvId === convId ? (state.activeDm || {}) : {};
  const cachedServerId = normId(
    cachedCtx?.serverId
    || cachedMeta?.serverId
    || activeMeta?.serverId
    || ""
  );

  if (cachedServerId) {
    return {
      serverId: cachedServerId,
      channelId: normId(cachedCtx?.channel?.id || cachedMeta?.channelId || activeMeta?.channelId || ""),
      conversationId: convId,
      channelType: normalizeConversationChannelType(
        cachedCtx?.channel?.channelType
        || cachedMeta?.channelType
        || activeMeta?.channelType
        || "text"
      ),
      userLimit: clampServerVoiceUserLimit(
        cachedCtx?.channel?.userLimit
        ?? cachedMeta?.userLimit
        ?? activeMeta?.userLimit
        ?? 0,
        0
      ),
      mediaMode: normalizeServerVoiceMediaMode(
        cachedCtx?.channel?.mediaMode
        || cachedMeta?.mediaMode
        || activeMeta?.mediaMode
        || "audio_only"
      ),
      name: normalizeConversationLabel(
        cachedCtx?.channel?.name
        || cachedMeta?.displayName
        || activeMeta?.displayName
        || "general",
        "general"
      ),
    };
  }

  if (!allowLookup) return null;

  try {
    const { data, error } = await supabase
      .from("server_channels")
      .select("id, server_id, conversation_id, name, channel_type, user_limit, media_mode")
      .eq("conversation_id", convId)
      .maybeSingle();
    if (error || !data) return null;

    const channelId = normId(data?.id || "");
    const serverId = normId(data?.server_id || "");
    if (!serverId) return null;
    const channelType = normalizeConversationChannelType(data?.channel_type || "text");
    const displayName = normalizeConversationLabel(
      data?.name || (channelType === "voice" ? "voice-lounge" : "general"),
      channelType === "voice" ? "voice-lounge" : "general"
    );
    const serverRow = getServerRowById(serverId);
    setConversationMeta(convId, {
      kind: "server",
      isGroup: true,
      displayName,
      serverId,
      channelId,
      serverName: normalizeConversationLabel(serverRow?.name || "Server", "Server"),
      avatarUrl: String(serverRow?.iconUrl || "").trim(),
      channelType,
      userLimit: clampServerVoiceUserLimit(data?.user_limit ?? 0, 0),
      mediaMode: normalizeServerVoiceMediaMode(data?.media_mode || "audio_only"),
    });

    return {
      serverId,
      channelId,
      conversationId: convId,
      channelType,
      userLimit: clampServerVoiceUserLimit(data?.user_limit ?? 0, 0),
      mediaMode: normalizeServerVoiceMediaMode(data?.media_mode || "audio_only"),
      name: displayName,
    };
  } catch (_) {
    return null;
  }
}

function isVoiceConversationChannelType(value) {
  return normalizeConversationChannelType(value) === "voice";
}

function isGroupConversationMeta(meta = null) {
  const kind = String(meta?.kind || "").trim().toLowerCase();
  return !!meta?.isGroup && kind !== "server";
}

function isServerVoiceConversationMeta(meta = null) {
  const kind = String(meta?.kind || "").trim().toLowerCase();
  if (kind !== "server") return false;
  const channelType = normalizeConversationChannelType(meta?.channelType || meta?.channel_type || "");
  return channelType === "voice";
}

function isCallCapableGroupConversationMeta(meta = null) {
  return isGroupConversationMeta(meta) || isServerVoiceConversationMeta(meta);
}

function isServerVoiceConversationById(conversationId = null) {
  const convId = normId(conversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return false;
  const meta = getActiveConversationMeta(convId) || getConversationMeta(convId) || {};
  if (isServerVoiceConversationMeta(meta)) return true;
  const serverChannelCtx = findServerChannelContextByConversationId(convId);
  if (!serverChannelCtx) return false;
  const channelType = normalizeConversationChannelType(serverChannelCtx?.channel?.channelType || "");
  return channelType === "voice";
}

function shouldUseGroupCallSessionBackendForConversation(conversationId = null) {
  return !isServerVoiceConversationById(conversationId);
}

function getActiveConversationMeta(conversationId = null) {
  const convId = normId(conversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return null;
  const cached = getConversationMeta(convId) || {};
  const active = normId(state.activeDm?.conversationId || activeDmId || "") === convId
    ? (state.activeDm || {})
    : {};
  return { ...cached, ...active, conversationId: convId };
}

function syncConversationMetaCaches() {
  dmConversationMetaById.clear();

  (state.groupDms || []).forEach((row) => {
    if (!row?.conversationId) return;
    setConversationMeta(row.conversationId, {
      kind: "group",
      isGroup: true,
      displayName: row.name || "Group DM",
      ownerUserId: normId(row.ownerUserId || ""),
      memberCount: row.memberCount || 0,
      memberIds: row.memberIds || [],
      memberDisplayNames: row.memberDisplayNames || [],
      memberUsernames: row.memberUsernames || [],
      avatarUrl: row.avatarUrl || "",
      serverId: null,
    });
  });

  (state.servers || []).forEach((row) => {
    if (!row?.defaultConversationId) return;
    setConversationMeta(row.defaultConversationId, {
      kind: "server",
      isGroup: true,
      displayName: row.name || "Server",
      ownerUserId: normId(row.ownerUserId || ""),
      memberCount: row.memberCount || 0,
      memberIds: [],
      memberDisplayNames: [],
      memberUsernames: [],
      avatarUrl: row.iconUrl || "",
      serverId: row.serverId || null,
      serverName: row.name || "Server",
      channelType: "text",
    });
  });

  scheduleCallRealtimeSubscriptionSync(0);
}

let groupServerCollectionsLoadedAt = 0;
let groupServerMetadataHydratedAt = 0;

function invalidateGroupAndServerCollectionsCache({ resetGroupMetadata = true } = {}) {
  groupServerCollectionsLoadedAt = 0;
  if (resetGroupMetadata) {
    groupServerMetadataHydratedAt = 0;
  }
}

async function hydrateGroupConversationMetadata(rows = []) {
  const list = Array.isArray(rows) ? rows : [];
  try {
    const groupIds = list.map((g) => normId(g?.conversationId)).filter(Boolean);
    if (!groupIds.length) return;

    const ownerMap = new Map();
    const avatarMap = new Map();

    const [ownerResult, avatarResult] = await Promise.allSettled([
      supabase
        .from("conversations")
        .select("id, created_by")
        .in("id", groupIds),
      supabase
        .from("conversations")
        .select("id, avatar_url")
        .in("id", groupIds),
    ]);

    if (ownerResult.status === "fulfilled") {
      const { data: ownerRows, error: ownerErr } = ownerResult.value || {};
      if (!ownerErr && Array.isArray(ownerRows)) {
        ownerRows.forEach((r) => {
          const id = normId(r?.id);
          if (!id) return;
          ownerMap.set(id, normId(r?.created_by));
        });
      } else if (ownerErr) {
        const msg = String(ownerErr?.message || "").toLowerCase();
        if (!(msg.includes("created_by") && msg.includes("column"))) {
          console.warn("group owner hydrate failed", ownerErr);
        }
      }
    } else {
      console.warn("group owner hydrate failed", ownerResult.reason);
    }

    if (avatarResult.status === "fulfilled") {
      const { data: avatarRows, error: avatarErr } = avatarResult.value || {};
      if (!avatarErr && Array.isArray(avatarRows)) {
        avatarRows.forEach((r) => {
          const id = normId(r?.id);
          if (!id) return;
          const avatarUrl = String(r?.avatar_url || "").trim();
          avatarMap.set(id, avatarUrl);
        });
      } else if (avatarErr) {
        const msg = String(avatarErr?.message || "").toLowerCase();
        if (!(msg.includes("avatar_url") && msg.includes("column"))) {
          console.warn("group avatar hydrate failed", avatarErr);
        }
      }
    } else {
      console.warn("group avatar hydrate failed", avatarResult.reason);
    }

    state.groupDms = list.map((g) => {
      const convId = normId(g?.conversationId);
      const customAvatar = String(avatarMap.get(convId) || "").trim();
      return {
        ...g,
        ownerUserId: normId(g?.ownerUserId) || ownerMap.get(convId) || "",
        avatarUrl: customAvatar || String(g?.avatarUrl || "").trim(),
      };
    });
  } catch (e) {
    console.warn("group owner hydrate failed", e);
  }
}

async function loadGroupAndServerCollections({ force = false, hydrateGroupMetadata = true } = {}) {
  const now = Date.now();
  const cacheFresh = (
    !force
    && groupServerCollectionsLoadedAt > 0
    && (now - groupServerCollectionsLoadedAt) < GROUP_SERVER_COLLECTIONS_CACHE_MS
  );
  const shouldHydrateGroupMetadata = !!hydrateGroupMetadata && (
    force
    || !groupServerMetadataHydratedAt
    || (now - groupServerMetadataHydratedAt) >= GROUP_SERVER_METADATA_HYDRATION_MS
  );

  if (!cacheFresh) {
    const [groupsRes, serversRes] = await Promise.all([
      rpcWithTimeout("list_my_group_dms"),
      rpcWithTimeout("list_my_servers"),
    ]);
    let nextGroups = [];
    let nextServers = [];

    const { data: groupsData, error: groupsError } = groupsRes || {};
    if (!groupsError) {
      groupDmRpcAvailable = true;
      nextGroups = (groupsData || []).map(normalizeGroupDmRow).filter(Boolean);
    } else if (isMissingRpcError(groupsError)) {
      groupDmRpcAvailable = false;
    } else {
      console.warn("list_my_group_dms failed", groupsError);
    }

    const { data: serversData, error: serversError } = serversRes || {};
    if (!serversError) {
      serverRpcAvailable = true;
      nextServers = (serversData || []).map(normalizeServerRow).filter(Boolean);
    } else if (isMissingRpcError(serversError)) {
      serverRpcAvailable = false;
    } else {
      console.warn("list_my_servers failed", serversError);
    }

    state.groupDms = nextGroups;
    state.servers = nextServers;
    const validServerIds = new Set(nextServers.map((s) => normId(s?.serverId || "")).filter(Boolean));
    for (const sid of Array.from(serverChannelListByServerId.keys())) {
      if (!validServerIds.has(sid)) serverChannelListByServerId.delete(sid);
    }
    for (const sid of Array.from(serverChannelCategoryListByServerId.keys())) {
      if (!validServerIds.has(sid)) serverChannelCategoryListByServerId.delete(sid);
    }
    for (const sid of Array.from(serverChannelCategoryCollapsedByServerId.keys())) {
      if (!validServerIds.has(sid)) serverChannelCategoryCollapsedByServerId.delete(sid);
    }
    pruneServerHideMutedChannels(validServerIds);
    pruneServerMuted(validServerIds);
    for (const sid of Array.from(serverMemberListByServerId.keys())) {
      if (!validServerIds.has(sid)) serverMemberListByServerId.delete(sid);
    }
    for (const sid of Array.from(serverUnreadSenderByServerId.keys())) {
      if (!validServerIds.has(sid)) serverUnreadSenderByServerId.delete(sid);
    }
    pruneServerNotificationModes(validServerIds);
    pruneRememberedServerLastChannels(validServerIds);
    syncServerOrbOrderWithServers(nextServers, { persist: true });
    groupServerCollectionsLoadedAt = Date.now();
  }

  if (shouldHydrateGroupMetadata) {
    await hydrateGroupConversationMetadata(state.groupDms || []);
    groupServerMetadataHydratedAt = Date.now();
  }

  syncConversationMetaCaches();
}

function getGroupOrbFallbackChar(label, fallback = "G") {
  const c = String(label || "").trim().charAt(0).toUpperCase();
  return c || fallback;
}

function buildServerRailIncomingOrbHtml({
  label = "Server",
  iconUrl = "",
} = {}) {
  const safeLabel = normalizeConversationLabel(label, "Server");
  const safeIconUrl = String(iconUrl || "").trim();
  const initial = getGroupOrbFallbackChar(safeLabel, "S");
  return safeIconUrl
    ? `<img src="${esc(safeIconUrl)}" alt="" loading="lazy" />`
    : `<span class="groupOrbFolderIncomingFallback">${esc(initial)}</span>`;
}

async function openConversationById(conversationId, fallbackMeta = {}) {
  const convId = normId(conversationId);
  if (!convId) return;
  const wasServerActive = String(state.activeDm?.kind || "").trim().toLowerCase() === "server";

  const fromCache = getConversationMeta(convId) || {};
  const merged = { ...fromCache, ...(fallbackMeta || {}) };
  const isGroup = !!merged?.isGroup || merged?.kind === "group" || merged?.kind === "server";
  const isServer = String(merged?.kind || "").trim().toLowerCase() === "server";
  const displayFallback = isServer ? "Server" : (isGroup ? "Group DM" : "DM");
  const displayName = normalizeConversationLabel(
    merged?.displayName || merged?.name || displayFallback,
    displayFallback
  );
  const channelType = normalizeConversationChannelType(merged?.channelType || merged?.channel_type || "");

  state.activeDm = {
    ...(state.activeDm || {}),
    conversationId: convId,
    displayName,
    username: isGroup ? "" : String(merged?.username || ""),
    avatarUrl: String(merged?.avatarUrl || ""),
    otherUserId: isGroup ? "" : normId(merged?.otherUserId || ""),
    ownerUserId: isGroup ? normId(merged?.ownerUserId || "") : "",
    kind: isGroup ? (merged?.kind || "group") : "dm",
    isGroup,
    memberCount: Number(merged?.memberCount || 0),
    memberIds: Array.isArray(merged?.memberIds) ? merged.memberIds : [],
    memberDisplayNames: Array.isArray(merged?.memberDisplayNames) ? merged.memberDisplayNames : [],
    memberUsernames: Array.isArray(merged?.memberUsernames) ? merged.memberUsernames : [],
    serverId: normId(merged?.serverId || ""),
    serverName: String(merged?.serverName || ""),
    channelType,
  };

  if (isServer) {
    const serverCtx = findServerChannelContextByConversationId(convId);
    const sid = normId(state.activeDm?.serverId || merged?.serverId || serverCtx?.serverId || "");
    if (sid) {
      state.activeDm.serverId = sid;
      rememberServerLastChannel(sid, convId, { persist: true });
      await ensureSelfServerConversationMembership(sid, { force: false }).catch(() => {});
    }
  }

  await showDm(convId, { autoAnswerIfPending: true });
  if (isServer && channelType === "voice") {
    void requestServerVoicePresenceSnapshot(convId, { force: true });
  }
  const nowServerActive = String(state.activeDm?.kind || "").trim().toLowerCase() === "server";
  if (wasServerActive || nowServerActive) {
    await loadDmList().catch(() => {});
  } else {
    relationshipTraceMeasureSync(trace, "renderFriends:renderGroupsRail", () => {
      renderGroupsRail();
    });
  }
}

function isDesktopAsarRenderer() {
  const isDesktop = !!window?.altaraDesktop?.isDesktopApp;
  if (!isDesktop) return false;
  const href = String(window?.location?.href || window?.location?.pathname || "").toLowerCase();
  return href.includes("app.asar");
}

function getPreferredBrandLogoVariant() {
  if (document.body?.classList?.contains("theme-mode-light")) return "black";
  return "default";
}

function getBrandLogoCandidates(variantInput = "default") {
  const variant = String(variantInput || "").trim().toLowerCase() === "black" ? "black" : "default";
  const baseNames = variant === "black" ? ["iconB", "icon"] : ["icon", "iconB"];
  const candidates = [];
  const addCandidateSet = (baseName) => {
    if (!baseName) return;
    candidates.push(`build/${baseName}.jpg`);
    candidates.push(`./build/${baseName}.jpg`);
    candidates.push(`build/${baseName}.png`);
    candidates.push(`./build/${baseName}.png`);
    candidates.push(`build/${baseName}.ico`);
    candidates.push(`./build/${baseName}.ico`);
    if (isDesktopAsarRenderer()) {
      candidates.push(`../build/${baseName}.ico`);
      candidates.push(`../build/icons/${baseName}.ico`);
      candidates.push(`../${baseName}.ico`);
    }
  };
  baseNames.forEach(addCandidateSet);
  return Array.from(new Set(candidates.map((v) => String(v || "").trim()).filter(Boolean)));
}

function getHomeOrbIconCandidates() {
  return getBrandLogoCandidates(getPreferredBrandLogoVariant());
}

function bindBrandImageFallback(img, candidatesInput = []) {
  if (!(img instanceof HTMLImageElement)) return;
  const candidates = Array.from(new Set((Array.isArray(candidatesInput) ? candidatesInput : [])
    .map((value) => String(value || "").trim())
    .filter(Boolean)));
  if (!candidates.length) return;

  const signature = candidates.join("|");
  const currentSrc = String(img.getAttribute("src") || "").trim();
  const existingIdx = candidates.indexOf(currentSrc);
  let idx = existingIdx >= 0 ? existingIdx : 0;

  if (img.dataset.brandCandidateSignature !== signature || existingIdx < 0) {
    img.dataset.brandCandidateSignature = signature;
    img.setAttribute("src", candidates[idx]);
  }

  img.onerror = () => {
    idx += 1;
    if (idx >= candidates.length) {
      img.onerror = null;
      return;
    }
    img.setAttribute("src", candidates[idx]);
  };
}

function bindHomeOrbLogoFallback(railEl) {
  const rail = railEl;
  if (!rail) return;
  const img = rail.querySelector(".groupOrbAppLogoImg");
  bindBrandImageFallback(img, getHomeOrbIconCandidates());
}

function buildServerRailServerOrbHtml(serverRow = {}, {
  index = 0,
  activeConversationId = "",
  activeServerId = "",
  parentFolderId = "",
} = {}) {
  const label = normalizeConversationLabel(serverRow?.name || `server ${Number(index) + 1}`, "Server");
  const initial = getGroupOrbFallbackChar(label, "S");
  const entryConversationId = normId(serverRow?.defaultConversationId || "");
  const entryServerId = normId(serverRow?.serverId || "");
  const isActive = (!!activeConversationId && entryConversationId === activeConversationId)
    || (!!activeServerId && !!entryServerId && entryServerId === activeServerId);
  const unreadCount = getServerUnreadCount(entryServerId, entryConversationId);
  const hasUnread = unreadCount > 0;
  const unreadAttrs = hasUnread
    ? ` data-server-unread="${escAttr(String(Math.min(999, unreadCount)))}" data-notify-text="${escAttr(unreadCount > 1 ? `${unreadCount} novas mensagens` : "Nova mensagem")}"`
    : "";
  const unreadBadgeHtml = buildGroupOrbUnreadBadgeHtml(unreadCount);
  const unreadLabel = unreadCount > 1 ? `${unreadCount} novas mensagens` : "Nova mensagem";
  const ariaLabel = hasUnread ? `${label}, ${unreadLabel}` : label;
  const avatar = String(serverRow?.iconUrl || "").trim()
    ? `<img src="${esc(String(serverRow.iconUrl || "").trim())}" alt="${escAttr(label)}" />`
    : `<span class="groupOrbFallback">${esc(initial)}</span>`;
  const parentFolderAttr = parentFolderId ? ` data-server-parent-folder-id="${escAttr(parentFolderId)}"` : "";
  const topLevelAttrs = parentFolderId
    ? ""
    : ` data-server-top-level-entry="1" data-server-rail-entry-token="${escAttr(makeServerOrbOrderEntry("server", entryServerId))}"`;

  return `
    <button
      class="groupOrb groupOrb--server${parentFolderId ? " groupOrb--folder-child" : ""}${isActive ? " is-active" : ""}${hasUnread ? " has-notification" : ""}"
      type="button"
      draggable="true"
      data-open-group-conversation="${escAttr(entryConversationId)}"
      data-open-group-server-id="${escAttr(entryServerId)}"
      data-server-orb-id="${escAttr(entryServerId)}"
      title="${escAttr(label)}"
      aria-label="${escAttr(ariaLabel)}"
      ${unreadAttrs}
      ${parentFolderAttr}
      ${topLevelAttrs}
    >
      ${avatar}
      ${unreadBadgeHtml}
    </button>
  `;
}

function buildServerRailFolderHtml(folder = {}, serverRows = [], {
  activeConversationId = "",
  activeServerId = "",
} = {}) {
  const folderId = normId(folder?.id || "");
  if (!folderId) return "";
  const rows = Array.isArray(serverRows) ? serverRows.filter(Boolean) : [];
  if (rows.length < 2) return "";
  const displayName = getServerFolderDisplayName(folder, "Folder");
  const tooltip = getServerFolderTooltip(folder, rows);
  const hasActiveServer = rows.some((row) => {
    const entryConversationId = normId(row?.defaultConversationId || "");
    const entryServerId = normId(row?.serverId || "");
    return (!!activeConversationId && entryConversationId === activeConversationId)
      || (!!activeServerId && !!entryServerId && entryServerId === activeServerId);
  });
  const isOpen = openServerFolderId === folderId;
  const unreadCount = getServerFolderUnreadCount(folder);
  const hasUnread = unreadCount > 0;
  const unreadAttrs = hasUnread
    ? ` data-server-unread="${escAttr(String(Math.min(999, unreadCount)))}" data-notify-text="${escAttr(unreadCount > 1 ? `${unreadCount} novas mensagens` : "Nova mensagem")}"`
    : "";
  const unreadBadgeHtml = buildGroupOrbUnreadBadgeHtml(unreadCount);
  const unreadLabel = unreadCount > 1 ? `${unreadCount} novas mensagens` : "Nova mensagem";
  const ariaLabel = hasUnread ? `${displayName}, ${unreadLabel}` : `${displayName}, ${rows.length} servers`;
  const previewHtml = rows.slice(0, 4).map((row, idx) => {
    const label = normalizeConversationLabel(row?.name || `server ${Number(idx) + 1}`, "Server");
    const initial = getGroupOrbFallbackChar(label, "S");
    const iconUrl = String(row?.iconUrl || "").trim();
    return `
      <span class="groupOrbFolderPreviewItem" aria-hidden="true">
        ${iconUrl ? `<img src="${esc(iconUrl)}" alt="" loading="lazy" />` : `<span class="groupOrbFolderPreviewFallback">${esc(initial)}</span>`}
      </span>
    `;
  }).join("");
  const childHtml = rows
    .map((row, idx) => buildServerRailServerOrbHtml(row, {
      index: idx,
      activeConversationId,
      activeServerId,
      parentFolderId: folderId,
    }))
    .join("");

  return `
    <div class="groupOrbFolderWrap" data-server-folder-wrap="${escAttr(folderId)}">
      <button
        class="groupOrb groupOrb--folder${isOpen ? " is-open" : ""}${!isOpen && hasActiveServer ? " is-active" : ""}${hasUnread ? " has-notification" : ""}"
        type="button"
        data-server-folder-id="${escAttr(folderId)}"
        data-server-top-level-entry="1"
        data-server-rail-entry-token="${escAttr(makeServerOrbOrderEntry("folder", folderId))}"
        title="${escAttr(tooltip)}"
        aria-label="${escAttr(ariaLabel)}"
        aria-expanded="${isOpen ? "true" : "false"}"
        ${unreadAttrs}
      >
        <span class="groupOrbFolderPocket" aria-hidden="true"></span>
        <span class="groupOrbFolderIncoming" data-server-folder-incoming="${escAttr(folderId)}" aria-hidden="true">
          <span class="groupOrbFolderIncomingOrb" data-server-folder-incoming-icon="${escAttr(folderId)}"></span>
        </span>
        <span class="groupOrbFolderPreview" aria-hidden="true">${previewHtml}</span>
        ${unreadBadgeHtml}
      </button>
      ${isOpen ? `<div class="groupOrbFolderStack" data-server-folder-stack-id="${escAttr(folderId)}">${childHtml}</div>` : ""}
    </div>
  `;
}

function renderGroupsRail() {
  const rail = document.getElementById("leftGroupsRail");
  if (!rail) return;
  const trace = getRelationshipCurrentTrace();
  const traceLabel = relationshipTracePhaseStart(trace, "renderGroupsRail", {
    servers: Array.isArray(state.servers) ? state.servers.length : 0,
    friends: Array.isArray(state.friends) ? state.friends.length : 0,
    unreadDmUsers: dmUnreadByUserId.size,
  });
  try {
  closeServerFolderMenu();
  ensureDmClientStateLoaded();
  const serverUiOpen = isServerConversationUiOpen();
  const activeConversationId = serverUiOpen
    ? normId(activeDmId || state.activeDm?.conversationId || "")
    : "";
  const activeServerId = serverUiOpen
    ? normId(state.activeDm?.serverId || "")
    : "";
  const activeKind = String(state.activeDm?.kind || "").trim().toLowerCase();
  const activeDirectDmUserId = (!serverUiOpen && activeKind !== "group" && activeKind !== "server")
    ? normId(state.activeDm?.otherUserId || state.activeDm?.other_user_id || callOtherUserId || "")
    : "";
  const activeDirectDmUsername = (!activeDirectDmUserId && !serverUiOpen && activeKind === "dm")
    ? String(state.activeDm?.username || "").trim().toLowerCase()
    : "";
  const activeMainTab = String(document.querySelector("[data-tab].active")?.getAttribute("data-tab") || "widgets").trim().toLowerCase();
  const isHomeOrbActive = !normId(activeDmId || state.activeDm?.conversationId || "") && activeMainTab === "widgets";
  const orderedServerEntries = getOrderedServerRailEntries(state.servers || []);
  const unreadDmRows = Array.from(dmUnreadByUserId.entries())
    .map(([uidRaw, unreadRaw]) => ({
      userId: normId(uidRaw),
      unread: Math.max(0, Number(unreadRaw) || 0),
    }))
    .filter((entry) => !!entry.userId && entry.unread > 0 && !isDmUserHidden(entry.userId))
    .sort((a, b) => {
      if (b.unread !== a.unread) return b.unread - a.unread;
      return getDmActivityScore(b.userId) - getDmActivityScore(a.userId);
    });
  const unreadDmOrbs = unreadDmRows.map((entry) => {
    const uid = normId(entry?.userId || "");
    const friend = (state.friends || []).find((f) => normId(f?.other_user_id || f?.id) === uid) || null;
    const cached = getCachedProfile(uid) || null;
    const username = String(friend?.username || cached?.username || "").trim();
    const displayRaw = friend
      ? getFriendDisplayName(friend)
      : (cached?.display_name || cached?.username || username || "DM");
    const displayName = normalizeConversationLabel(displayRaw, username || "DM");
    const avatarUrl = String(friend?.avatar_url || cached?.avatar_url || "").trim();
    return {
      userId: uid,
      unread: entry.unread,
      username,
      displayName,
      avatarUrl,
    };
  });
  const unreadDms = unreadDmOrbs.slice(0, GROUP_ORB_LIMIT);
  const unreadDmsHtml = unreadDms.map((entry, i) => {
    const label = entry?.displayName || entry?.username || `dm ${i + 1}`;
    const initial = getGroupOrbFallbackChar(label, "D");
    const uid = normId(entry?.userId || "");
    const uname = String(entry?.username || "").trim();
    const isActive = (!!activeDirectDmUserId && uid === activeDirectDmUserId)
      || (!activeDirectDmUserId && !!activeDirectDmUsername && !!uname && uname.toLowerCase() === activeDirectDmUsername);
    const unreadCount = Math.max(1, Number(entry?.unread || 0));
    const unreadAttrs = ` data-dm-unread="${escAttr(String(Math.min(999, unreadCount)))}" data-notify-text="${escAttr(unreadCount > 1 ? `${unreadCount} novas mensagens` : "Nova mensagem")}"`;
    const avatar = entry?.avatarUrl
      ? buildAvatarMediaHtml(entry.avatarUrl, { userId: uid, alt: label, loading: "lazy" })
      : `<span class="groupOrbFallback">${esc(initial)}</span>`;
    return `
      <button
        class="groupOrb groupOrb--dm${isActive ? " is-active" : ""} has-notification"
        type="button"
        data-open-rail-dm-user-id="${escAttr(uid)}"
        data-open-rail-dm-username="${escAttr(uname)}"
        data-open-rail-dm-display="${escAttr(label)}"
        data-open-rail-dm-avatar="${escAttr(entry?.avatarUrl || "")}"
        title="${escAttr(label)}"
        aria-label="${escAttr(label)}"
        ${unreadAttrs}
      >
        ${avatar}
      </button>
    `;
  }).join("");

  const homeOrbIconSrc = getHomeOrbIconCandidates()[0] || "build/icon.jpg";
  const homeOrbHtml = `
    <button
      class="groupOrb groupOrb--app-home${isHomeOrbActive ? " is-active" : ""}"
      type="button"
      data-open-rail-home="1"
      title="Altara Home"
      aria-label="Altara Home"
    >
      <span class="groupOrbAppLogo" aria-hidden="true">
        <img class="groupOrbAppLogoImg" src="${escAttr(homeOrbIconSrc)}" alt="Altara" loading="eager" />
      </span>
    </button>
  `;
  const serverEntries = orderedServerEntries.slice(0, GROUP_ORB_LIMIT);
  const serversHtml = serverEntries.map((entry, i) => {
    if (entry?.type === "folder") {
      return buildServerRailFolderHtml(entry.folder, entry.serverRows, {
        activeConversationId,
        activeServerId,
      });
    }
    return buildServerRailServerOrbHtml(entry?.row || {}, {
      index: i,
      activeConversationId,
      activeServerId,
    });
  }).join("");

  const createServerOrb = `
    <button
      class="groupOrb groupOrb--create"
      type="button"
      data-create-server-quick="1"
      title="Criar server"
      aria-label="Criar server"
    >
      <span class="groupOrbPlus" aria-hidden="true">+</span>
    </button>
  `;

  rail.innerHTML = [
    homeOrbHtml,
    `<div class="groupOrbRailDivider" aria-hidden="true"></div>`,
    !serverEntries.length && !unreadDms.length ? `<div class="hint">Sem servers ainda.</div>` : "",
    unreadDmsHtml,
    serversHtml,
    createServerOrb,
  ].filter(Boolean).join("");
  if (serverRailDragState) rail.setAttribute("data-orb-dragging", "1");
  bindHomeOrbLogoFallback(rail);

  const homeOrbBtn = rail.querySelector("[data-open-rail-home]");
  if (homeOrbBtn) {
    const openHomeFromRail = () => {
      navigateToHomeView({ captureHistory: true });
    };
    homeOrbBtn.addEventListener("click", openHomeFromRail);
    homeOrbBtn.addEventListener("keydown", (e) => {
      if (e.key !== "Enter" && e.key !== " ") return;
      e.preventDefault();
      openHomeFromRail();
    });
  }

  rail.querySelectorAll("[data-open-rail-dm-user-id]").forEach((btn) => {
    const openFromDmOrb = async () => {
      const uid = normId(btn.getAttribute("data-open-rail-dm-user-id") || "");
      let username = String(btn.getAttribute("data-open-rail-dm-username") || "").trim();
      let displayName = String(btn.getAttribute("data-open-rail-dm-display") || "").trim();
      let avatarUrl = String(btn.getAttribute("data-open-rail-dm-avatar") || "").trim();

      const friend = (state.friends || []).find((f) => normId(f?.other_user_id || f?.id) === uid) || null;
      if (!username) username = String(friend?.username || "").trim();
      if (!displayName) displayName = normalizeConversationLabel(getFriendDisplayName(friend || {}), username || "DM");
      if (!avatarUrl) avatarUrl = String(friend?.avatar_url || "").trim();

      const cached = getCachedProfile(uid) || null;
      if (!username) username = String(cached?.username || "").trim();
      if (!displayName) displayName = normalizeConversationLabel(cached?.display_name || cached?.username || username || "DM", username || "DM");
      if (!avatarUrl) avatarUrl = String(cached?.avatar_url || "").trim();

      if ((!username || !avatarUrl) && uid) {
        try {
          const rows = await fetchProfilesByIds([uid], { includeBio: false, force: false });
          const row = rows?.[0] || getCachedProfile(uid) || null;
          if (!username) username = String(row?.username || "").trim();
          if (!displayName) displayName = normalizeConversationLabel(row?.display_name || row?.username || username || "DM", username || "DM");
          if (!avatarUrl) avatarUrl = String(row?.avatar_url || "").trim();
        } catch (_) {}
      }

      if (!username) {
        alert("Nao consegui abrir esta DM automaticamente. Abre a DM pela lista de amigos.");
        return;
      }
      await startDmWith(username, displayName || username, avatarUrl, uid || "");
    };

    btn.addEventListener("click", async () => { await openFromDmOrb(); });
    btn.addEventListener("keydown", async (e) => {
      if (e.key !== "Enter" && e.key !== " ") return;
      e.preventDefault();
      await openFromDmOrb();
    });
    btn.addEventListener("contextmenu", (e) => {
      const uid = normId(btn.getAttribute("data-open-rail-dm-user-id") || "");
      const username = String(btn.getAttribute("data-open-rail-dm-username") || "").trim();
      const displayName = String(btn.getAttribute("data-open-rail-dm-display") || username || "").trim();
      const avatarUrl = String(btn.getAttribute("data-open-rail-dm-avatar") || "").trim();
      if (!uid && !username) return;
      e.preventDefault();
      e.stopPropagation();
      openDmUserListMenuAt({
        userId: uid,
        username,
        displayName: displayName || username || "DM",
        avatarUrl,
        point: { x: e.clientX, y: e.clientY },
      });
    });
  });

  rail.querySelectorAll("[data-open-group-conversation]").forEach((btn) => {
    const openFromOrb = async () => {
      const fallbackConvId = normId(btn.getAttribute("data-open-group-conversation"));
      const serverId = normId(btn.getAttribute("data-open-group-server-id"));
      const convId = await resolveServerConversationForEntry(serverId, fallbackConvId);
      if (!convId) return;
      const convMeta = getConversationMeta(convId) || {};
      const fallbackMeta = getConversationMeta(fallbackConvId) || {};
      const serverName = normalizeConversationLabel(btn.getAttribute("title") || convMeta?.serverName || fallbackMeta?.serverName || "Server", "Server");
      const meta = {
        ...fallbackMeta,
        ...convMeta,
        kind: "server",
        isGroup: true,
        displayName: normalizeConversationLabel(convMeta?.displayName || fallbackMeta?.displayName || serverName, serverName),
        serverId: serverId || normId(convMeta?.serverId || fallbackMeta?.serverId || ""),
        serverName: convMeta?.serverName || fallbackMeta?.serverName || serverName,
        channelType: normalizeConversationChannelType(convMeta?.channelType || fallbackMeta?.channelType || "text"),
      };
      await openConversationById(convId, meta);
    };

    btn.addEventListener("click", async () => { await openFromOrb(); });
    btn.addEventListener("keydown", async (e) => {
      if (e.key !== "Enter" && e.key !== " ") return;
      e.preventDefault();
      await openFromOrb();
    });
    btn.addEventListener("contextmenu", (e) => {
      const sid = normId(btn.getAttribute("data-open-group-server-id") || "");
      if (!sid) return;
      e.preventDefault();
      openServerPanelMenuAt({
        serverId: sid,
        name: btn.getAttribute("title") || getServerRowById(sid)?.name || "Server",
        iconUrl: getServerRowById(sid)?.iconUrl || "",
      }, {
        x: e.clientX || 0,
        y: e.clientY || 0,
      }, {
        variant: "orb",
      });
    });
  });

  rail.querySelectorAll("[data-server-folder-id]").forEach((btn) => {
    const toggleFolder = () => {
      const folderId = normId(btn.getAttribute("data-server-folder-id") || "");
      if (!folderId) return;
      openServerFolderId = openServerFolderId === folderId ? "" : folderId;
      renderGroupsRail();
    };

    btn.addEventListener("click", toggleFolder);
    btn.addEventListener("keydown", (e) => {
      if (e.key !== "Enter" && e.key !== " ") return;
      e.preventDefault();
      toggleFolder();
    });
    btn.addEventListener("contextmenu", (e) => {
      const folderId = normId(btn.getAttribute("data-server-folder-id") || "");
      if (!folderId) return;
      e.preventDefault();
      e.stopPropagation();
      openServerFolderMenuAt({
        folderId,
        name: getServerFolderDisplayName(getServerFolderById(folderId), "Folder"),
      }, {
        x: e.clientX || 0,
        y: e.clientY || 0,
      });
    });
  });

  const clearDropTargets = () => {
    rail.querySelectorAll(".groupOrb, .groupOrbFolderStack, .groupOrbFolderWrap").forEach((el) => {
      el.classList.remove("is-drop-before", "is-drop-after", "is-folder-target", "is-drop-end", "is-folder-targeting");
    });
  };

  const markFolderTargetVisual = (folderId = "") => {
    const fid = normId(folderId);
    if (!fid) return;
    const folderBtn = rail.querySelector(`[data-server-folder-id="${escAttr(fid)}"]`);
    const folderWrap = rail.querySelector(`[data-server-folder-wrap="${escAttr(fid)}"]`);
    const incomingHost = rail.querySelector(`[data-server-folder-incoming-icon="${escAttr(fid)}"]`);
    if (incomingHost && serverRailDragState?.kind === "server") {
      incomingHost.innerHTML = buildServerRailIncomingOrbHtml({
        label: serverRailDragState.label || "Server",
        iconUrl: serverRailDragState.iconUrl || "",
      });
    }
    folderBtn?.classList?.add("is-folder-target");
    folderWrap?.classList?.add("is-folder-targeting");
  };

  const clearDragState = () => {
    serverRailDragState = null;
    rail.removeAttribute("data-orb-dragging");
    rail.querySelectorAll(".groupOrb").forEach((el) => {
      el.classList.remove("is-dragging");
    });
    clearDropTargets();
    clearServerRailDragGhost();
    clearServerRailFolderAutoOpen();
  };

  const getVerticalDropZone = (targetEl, event, { allowCenter = false } = {}) => {
    const rect = targetEl.getBoundingClientRect();
    if (!rect.height) return "after";
    const y = Math.max(0, Math.min(rect.height, event.clientY - rect.top));
    const ratio = y / rect.height;
    if (allowCenter && ratio > 0.36 && ratio < 0.64) return "center";
    return ratio >= 0.5 ? "after" : "before";
  };

  const resolveTargetAction = (targetEl, event) => {
    if (!serverRailDragState || !targetEl) return null;
    const dragKind = String(serverRailDragState.kind || "").trim().toLowerCase();
    const dragServerId = normId(serverRailDragState.serverId || "");
    const dragFolderId = normId(serverRailDragState.folderId || "");

    const folderId = normId(targetEl.getAttribute("data-server-folder-id") || "");
    if (folderId) {
      if (dragKind === "folder") {
        if (folderId === dragFolderId) return null;
        const zone = getVerticalDropZone(targetEl, event, { allowCenter: false });
        return {
          type: "top-level-entry",
          targetEntryToken: String(targetEl.getAttribute("data-server-rail-entry-token") || "").trim(),
          after: zone === "after",
        };
      }

      const targetEntryToken = String(targetEl.getAttribute("data-server-rail-entry-token") || "").trim();
      const zone = getVerticalDropZone(targetEl, event, { allowCenter: true });
      if (zone === "center") {
        return { type: "into-folder", folderId };
      }
      return { type: "top-level-entry", targetEntryToken, after: zone === "after" };
    }

    const targetServerId = normId(targetEl.getAttribute("data-server-orb-id") || "");
    if (!targetServerId) return null;
    const targetParentFolderId = normId(targetEl.getAttribute("data-server-parent-folder-id") || "");
    const zone = getVerticalDropZone(targetEl, event, { allowCenter: dragKind === "server" });

    if (dragKind === "folder") {
      if (targetParentFolderId) return null;
      return {
        type: "top-level-entry",
        targetEntryToken: String(targetEl.getAttribute("data-server-rail-entry-token") || "").trim(),
        after: zone === "after",
      };
    }

    if (!dragServerId || targetServerId === dragServerId) return null;

    if (targetParentFolderId) {
      if (zone === "center") {
        if (serverRailDragState.sourceFolderId && serverRailDragState.sourceFolderId === targetParentFolderId) {
          return {
            type: "folder-reorder",
            folderId: targetParentFolderId,
            targetServerId,
            after: true,
          };
        }
        return {
          type: "into-folder",
          folderId: targetParentFolderId,
          targetServerId,
          after: true,
        };
      }
      return {
        type: "folder-reorder",
        folderId: targetParentFolderId,
        targetServerId,
        after: zone === "after",
      };
    }

    const targetEntryToken = String(targetEl.getAttribute("data-server-rail-entry-token") || "").trim();
    if (zone === "center") {
      return { type: "create-folder", targetServerId };
    }
    return { type: "top-level-entry", targetEntryToken, after: zone === "after" };
  };

  const queueFolderAutoOpen = (folderId = "") => {
    const fid = normId(folderId);
    if (!fid || !serverRailDragState || String(serverRailDragState.kind || "") !== "server") {
      clearServerRailFolderAutoOpen();
      return;
    }
    if (openServerFolderId === fid) return;
    if (serverRailFolderAutoOpenTargetId === fid && serverRailFolderAutoOpenTimer) return;
    clearServerRailFolderAutoOpen();
    serverRailFolderAutoOpenTargetId = fid;
    serverRailFolderAutoOpenTimer = setTimeout(() => {
      serverRailFolderAutoOpenTimer = 0;
      if (!serverRailDragState || String(serverRailDragState.kind || "") !== "server") return;
      openServerFolderId = fid;
      renderGroupsRail();
    }, 260);
  };

  const applyDropActionVisual = (action, targetEl) => {
    clearDropTargets();
    clearServerRailFolderAutoOpen();
    if (!action || !targetEl) return;
    if (action.type === "into-folder") {
      markFolderTargetVisual(action.folderId);
      queueFolderAutoOpen(action.folderId);
      return;
    }
    if (action.type === "top-level-entry" || action.type === "folder-reorder") {
      targetEl.classList.add(action.after ? "is-drop-after" : "is-drop-before");
    }
  };

  const runResolvedDropAction = (action) => {
    if (!serverRailDragState || !action) return false;
    if (action.type === "create-folder" && serverRailDragState.kind === "server") {
      return createServerOrbFolder(serverRailDragState.serverId, action.targetServerId, { persist: true });
    }
    if (action.type === "into-folder" && serverRailDragState.kind === "server") {
      return moveServerOrbIntoFolder(serverRailDragState.serverId, action.folderId, {
        targetServerId: action.targetServerId || "",
        after: action.after !== false,
        persist: true,
      });
    }
    if (action.type === "folder-reorder" && serverRailDragState.kind === "server") {
      return moveServerOrbIntoFolder(serverRailDragState.serverId, action.folderId, {
        targetServerId: action.targetServerId || "",
        after: !!action.after,
        persist: true,
      });
    }
    if (action.type === "top-level-entry") {
      if (serverRailDragState.kind === "folder") {
        return moveServerFolderOrbInOrder(serverRailDragState.folderId, action.targetEntryToken, {
          after: !!action.after,
          persist: true,
        });
      }
      return moveServerOrbInOrder(serverRailDragState.serverId, action.targetEntryToken, {
        after: !!action.after,
        persist: true,
      });
    }
    return false;
  };

  const bindDragTarget = (targetEl) => {
    targetEl.addEventListener("dragover", (e) => {
      if (!serverRailDragState) return;
      const action = resolveTargetAction(targetEl, e);
      if (!action) return;
      e.preventDefault();
      applyDropActionVisual(action, targetEl);
      try { e.dataTransfer.dropEffect = "move"; } catch (_) {}
    });
    targetEl.addEventListener("drop", (e) => {
      if (!serverRailDragState) return;
      const action = resolveTargetAction(targetEl, e);
      if (!action) return;
      e.preventDefault();
      const changed = runResolvedDropAction(action);
      clearDragState();
      if (changed) renderGroupsRail();
    });
  };

  rail.querySelectorAll(".groupOrb--server[data-server-orb-id][draggable=\"true\"]").forEach((btn) => {
    btn.addEventListener("dragstart", (e) => {
      const sid = normId(btn.getAttribute("data-server-orb-id") || "");
      if (!sid) return;
      const row = getServerRowById(sid) || null;
      serverRailDragState = {
        kind: "server",
        serverId: sid,
        sourceFolderId: normId(btn.getAttribute("data-server-parent-folder-id") || ""),
        label: row?.name || btn.getAttribute("title") || "Server",
        iconUrl: row?.iconUrl || "",
      };
      clearDropTargets();
      rail.setAttribute("data-orb-dragging", "1");
      btn.classList.add("is-dragging");
      try {
        e.dataTransfer.effectAllowed = "move";
        e.dataTransfer.setData("text/plain", sid);
        const ghost = buildServerRailDragGhost({
          kind: "server",
          label: row?.name || btn.getAttribute("title") || "Server",
          iconUrl: row?.iconUrl || "",
        });
        if (ghost && typeof e.dataTransfer.setDragImage === "function") {
          e.dataTransfer.setDragImage(ghost, 18, 16);
        }
      } catch (_) {}
    });

    btn.addEventListener("dragend", () => {
      clearDragState();
    });

    bindDragTarget(btn);
  });

  rail.querySelectorAll("[data-server-folder-id]").forEach((btn) => {
    btn.setAttribute("draggable", "true");
    btn.addEventListener("dragstart", (e) => {
      const folderId = normId(btn.getAttribute("data-server-folder-id") || "");
      if (!folderId) return;
      const folder = getServerFolderById(folderId);
      const rows = (folder?.serverIds || [])
        .map((sid) => getServerRowById(sid))
        .filter(Boolean);
      serverRailDragState = {
        kind: "folder",
        folderId,
      };
      clearDropTargets();
      rail.setAttribute("data-orb-dragging", "1");
      btn.classList.add("is-dragging");
      try {
        e.dataTransfer.effectAllowed = "move";
        e.dataTransfer.setData("text/plain", folderId);
        const ghost = buildServerRailDragGhost({
          kind: "folder",
          label: getServerFolderDisplayName(folder, "Folder"),
          folderRows: rows,
        });
        if (ghost && typeof e.dataTransfer.setDragImage === "function") {
          e.dataTransfer.setDragImage(ghost, 24, 20);
        }
      } catch (_) {}
    });
    btn.addEventListener("dragend", () => {
      clearDragState();
    });
    bindDragTarget(btn);
  });

  rail.querySelectorAll("[data-server-folder-stack-id]").forEach((stackEl) => {
    stackEl.addEventListener("dragover", (e) => {
      if (!serverRailDragState || serverRailDragState.kind !== "server") return;
      const folderId = normId(stackEl.getAttribute("data-server-folder-stack-id") || "");
      if (!folderId) return;
      e.preventDefault();
      clearDropTargets();
      stackEl.classList.add("is-drop-end");
      try { e.dataTransfer.dropEffect = "move"; } catch (_) {}
    });
    stackEl.addEventListener("drop", (e) => {
      if (!serverRailDragState || serverRailDragState.kind !== "server") return;
      const folderId = normId(stackEl.getAttribute("data-server-folder-stack-id") || "");
      if (!folderId) return;
      e.preventDefault();
      const changed = moveServerOrbIntoFolder(serverRailDragState.serverId, folderId, { persist: true });
      clearDragState();
      if (changed) renderGroupsRail();
    });
  });

  rail.addEventListener("dragover", (e) => {
    if (!serverRailDragState) return;
    const target = eventTargetElement(e)?.closest?.(
      ".groupOrb--server[data-server-orb-id], [data-server-folder-id], [data-server-folder-stack-id]"
    ) || null;
    if (target) return;
    e.preventDefault();
    clearDropTargets();
    const lastTopLevelEntry = Array.from(rail.querySelectorAll("[data-server-top-level-entry=\"1\"]")).pop() || null;
    if (lastTopLevelEntry) lastTopLevelEntry.classList.add("is-drop-after");
    try { e.dataTransfer.dropEffect = "move"; } catch (_) {}
  });

  rail.addEventListener("drop", (e) => {
    if (!serverRailDragState) return;
    const target = eventTargetElement(e)?.closest?.(
      ".groupOrb--server[data-server-orb-id], [data-server-folder-id], [data-server-folder-stack-id]"
    ) || null;
    if (target) return;
    e.preventDefault();
    const changed = serverRailDragState.kind === "folder"
      ? moveServerOrbEntryToEnd(makeServerOrbOrderEntry("folder", serverRailDragState.folderId), { persist: true })
      : moveServerOrbToEnd(serverRailDragState.serverId, { persist: true });
    clearDragState();
    if (changed) renderGroupsRail();
  });

  const createBtn = rail.querySelector("[data-create-server-quick]");
  if (createBtn) {
    createBtn.addEventListener("click", async () => {
      await quickCreateServerFromRail();
    });
    createBtn.addEventListener("keydown", async (e) => {
      if (e.key !== "Enter" && e.key !== " ") return;
      e.preventDefault();
      await quickCreateServerFromRail();
    });
  }
  } finally {
    relationshipTracePhaseEnd(trace, traceLabel);
  }
}

async function quickCreateServerFromRail() {
  if (!serverRpcAvailable) {
    alert("A funcao create_server ainda nao existe. Aplica o patch SQL de servers.");
    return;
  }
  await openServerCreateModal();
}

function clearServerCreateIconDraft() {
  if (serverCreateIconPreviewUrl) safeRevokeObjectUrl(serverCreateIconPreviewUrl);
  serverCreateIconPreviewUrl = "";
  serverCreateIconFile = null;
  const fileInput = document.getElementById("serverCreateIconFile");
  if (fileInput) fileInput.value = "";
}

function setServerCreateIconPreviewButton(buttonEl, {
  iconUrl = "",
  label = "Server",
} = {}) {
  if (!buttonEl) return;
  const url = String(iconUrl || "").trim();
  const initial = getGroupOrbFallbackChar(label, "S");
  buttonEl.innerHTML = url
    ? `<img src="${esc(url)}" alt="${escAttr(label || "Server icon")}" />`
    : `<span class="groupDmAvatarFallback">${esc(initial)}</span>`;
  buttonEl.insertAdjacentHTML("beforeend", `<span class="serverCreateIconPlus" aria-hidden="true">+</span>`);
}

function renderServerCreateIconPreview() {
  const previewBtn = document.getElementById("serverCreateIconPreview");
  const nameInput = document.getElementById("serverCreateName");
  const label = normalizeConversationLabel(String(nameInput?.value || "").trim(), "Server");
  setServerCreateIconPreviewButton(previewBtn, {
    iconUrl: serverCreateIconPreviewUrl,
    label,
  });

  applyServerOrbNotificationDecorations();
}

function getServerUnreadCount(serverId = "", fallbackConversationId = "") {
  const sid = normId(serverId || "");
  const fallbackConvId = normId(fallbackConversationId || "");
  const seenConvIds = new Set();
  let total = 0;

  const pushUnreadForConversation = (conversationId) => {
    const convId = normId(conversationId || "");
    if (!convId || seenConvIds.has(convId)) return;
    seenConvIds.add(convId);
    const unread = Number(dmUnreadByConversationId.get(convId) || 0);
    if (Number.isFinite(unread) && unread > 0) total += unread;
  };

  if (sid) {
    const channels = serverChannelListByServerId.get(sid) || [];
    (channels || []).forEach((ch) => pushUnreadForConversation(ch?.conversationId || ""));
  }
  pushUnreadForConversation(fallbackConvId);

  return Math.max(0, total);
}

function formatGroupOrbUnreadBadgeCount(unreadCount = 0) {
  const count = Math.max(0, Number(unreadCount) || 0);
  if (!count) return "";
  return count > 99 ? "99+" : String(count);
}

function buildGroupOrbUnreadBadgeHtml(unreadCount = 0) {
  const label = formatGroupOrbUnreadBadgeCount(unreadCount);
  if (!label) return "";
  return `<span class="groupOrbUnreadBadge" aria-hidden="true">${esc(label)}</span>`;
}

function getServerUnreadSender(serverId = "") {
  const sid = normId(serverId || "");
  if (!sid) return null;
  const cached = serverUnreadSenderByServerId.get(sid) || null;
  if (!cached) return null;

  const userId = normId(cached?.userId || "");
  const profileAvatar = String(getCachedProfile(userId)?.avatar_url || "").trim();
  const avatarUrl = String(profileAvatar || cached?.avatarUrl || "").trim();
  return {
    ...cached,
    serverId: sid,
    userId,
    avatarUrl,
  };
}

function setServerUnreadSender(serverId = "", userId = "", avatarUrl = "") {
  const sid = normId(serverId || "");
  const uid = normId(userId || "");
  if (!sid || !uid) return false;

  const prev = serverUnreadSenderByServerId.get(sid) || {};
  const fallbackAvatar = String(getCachedProfile(uid)?.avatar_url || "").trim();
  const nextAvatar = String(avatarUrl || fallbackAvatar || prev?.avatarUrl || "").trim();
  const next = {
    userId: uid,
    avatarUrl: nextAvatar,
    at: Date.now(),
  };
  const changed = normId(prev?.userId || "") !== next.userId || String(prev?.avatarUrl || "") !== next.avatarUrl;
  serverUnreadSenderByServerId.set(sid, next);
  return changed;
}

function clearServerUnreadSender(serverId = "") {
  const sid = normId(serverId || "");
  if (!sid) return false;
  return serverUnreadSenderByServerId.delete(sid);
}

function resolveCachedServerIdForConversation(conversationId = "") {
  const convId = normId(conversationId || "");
  if (!convId) return "";

  const cachedMeta = getConversationMeta(convId) || {};
  let sid = normId(cachedMeta?.serverId || "");
  if (sid) return sid;

  sid = normId(findServerChannelContextByConversationId(convId)?.serverId || "");
  if (sid) return sid;

  const activeConvId = normId(state.activeDm?.conversationId || activeDmId || "");
  if (activeConvId === convId && isServerConversationKind(state.activeDm?.kind)) {
    sid = normId(state.activeDm?.serverId || "");
    if (sid) return sid;
  }

  const serverRow = (state.servers || []).find((s) => normId(s?.defaultConversationId || "") === convId) || null;
  return normId(serverRow?.serverId || "");
}

async function rememberServerUnreadSenderForConversation(conversationId = "", senderUserId = "", {
  senderAvatarUrl = "",
} = {}) {
  const convId = normId(conversationId || "");
  const uid = normId(senderUserId || "");
  if (!convId || !uid) return;
  if (uid === normId(state.user?.id || "")) return;

  let sid = resolveCachedServerIdForConversation(convId);
  if (!sid) {
    const ctx = await resolveServerConversationMembershipContext(convId, { allowLookup: true }).catch(() => null);
    sid = normId(ctx?.serverId || "");
  }
  if (!sid) return;

  const changed = setServerUnreadSender(sid, uid, senderAvatarUrl);
  if (changed) applyServerOrbNotificationDecorations();

  const current = getServerUnreadSender(sid);
  if (String(current?.avatarUrl || "").trim()) return;

  try {
    const rows = await fetchProfilesByIds([uid], { includeBio: false, force: false });
    const fetchedAvatar = String(rows?.[0]?.avatar_url || getCachedProfile(uid)?.avatar_url || "").trim();
    const avatarChanged = setServerUnreadSender(sid, uid, fetchedAvatar);
    if (avatarChanged) applyServerOrbNotificationDecorations();
  } catch (_) {}
}

function syncGroupOrbUnreadBadge(buttonEl, unreadCount = 0) {
  if (!buttonEl) return;
  buttonEl.querySelector(".groupOrbNotifyAvatar")?.remove();
  const existing = buttonEl.querySelector(".groupOrbUnreadBadge");
  const label = formatGroupOrbUnreadBadgeCount(unreadCount);
  if (!label) {
    if (existing) existing.remove();
    return;
  }

  if (existing) {
    if (existing.textContent === label) return;
    existing.textContent = label;
    return;
  }

  buttonEl.insertAdjacentHTML(
    "beforeend",
    `<span class="groupOrbUnreadBadge" aria-hidden="true">${esc(label)}</span>`
  );
}

function applyServerOrbNotificationDecorations() {
  const rail = document.getElementById("leftGroupsRail");
  if (!rail) return;

  rail.querySelectorAll(".groupOrb.groupOrb--group[data-open-group-dm-conversation]").forEach((btn) => {
    const convId = normId(btn.getAttribute("data-open-group-dm-conversation") || "");
    const unread = Math.max(0, Number(dmUnreadByConversationId.get(convId) || 0));
    const hasUnread = unread > 0;
    btn.classList.toggle("has-notification", hasUnread);
    if (hasUnread) {
      const safeUnread = Math.min(999, unread);
      btn.setAttribute("data-group-unread", String(safeUnread));
      btn.setAttribute("data-notify-text", safeUnread > 1 ? `${safeUnread} novas mensagens` : "Nova mensagem");
    } else {
      btn.removeAttribute("data-group-unread");
      btn.removeAttribute("data-notify-text");
    }
    syncGroupOrbUnreadBadge(btn, unread);
  });

  rail.querySelectorAll(".groupOrb.groupOrb--server").forEach((btn) => {
    const sid = normId(btn.getAttribute("data-open-group-server-id") || "");
    const fallbackConvId = normId(btn.getAttribute("data-open-group-conversation") || "");
    const unread = getServerUnreadCount(sid, fallbackConvId);
    const hasUnread = unread > 0;
    btn.classList.toggle("has-notification", hasUnread);
    if (hasUnread) {
      const safeUnread = Math.min(999, unread);
      btn.setAttribute("data-server-unread", String(safeUnread));
      btn.setAttribute("data-notify-text", safeUnread > 1 ? `${safeUnread} novas mensagens` : "Nova mensagem");
    } else {
      btn.removeAttribute("data-server-unread");
      btn.removeAttribute("data-notify-text");
      clearServerUnreadSender(sid);
    }
    syncGroupOrbUnreadBadge(btn, unread);
  });

  rail.querySelectorAll(".groupOrb.groupOrb--folder[data-server-folder-id]").forEach((btn) => {
    const folderId = normId(btn.getAttribute("data-server-folder-id") || "");
    const unread = getServerFolderUnreadCount(folderId);
    const hasUnread = unread > 0;
    btn.classList.toggle("has-notification", hasUnread);
    if (hasUnread) {
      const safeUnread = Math.min(999, unread);
      btn.setAttribute("data-server-unread", String(safeUnread));
      btn.setAttribute("data-notify-text", safeUnread > 1 ? `${safeUnread} novas mensagens` : "Nova mensagem");
    } else {
      btn.removeAttribute("data-server-unread");
      btn.removeAttribute("data-notify-text");
    }
    syncGroupOrbUnreadBadge(btn, unread);
  });
}

async function markServerAsRead(serverId, { forceLoadChannels = false } = {}) {
  const sid = normId(serverId);
  if (!sid) return false;

  let channels = serverChannelListByServerId.get(sid) || [];
  if (!channels.length || forceLoadChannels) {
    channels = await fetchServerChannelsForSidebar(sid, { force: forceLoadChannels }).catch(() => channels);
  }

  const fallbackServerRow = getServerRowById(sid);
  const conversationIds = normalizeUuidArray([
    ...(Array.isArray(channels) ? channels.map((ch) => normId(ch?.conversationId || "")) : []),
    normId(fallbackServerRow?.defaultConversationId || ""),
  ]);

  if (!conversationIds.length) return false;
  conversationIds.forEach((convId) => {
    dmUnreadByConversationId.delete(convId);
  });
  persistDmUnreadConversationsToStorage();
  clearServerUnreadSender(sid);

  if (normId(getActiveServerContext()?.serverId || "") === sid) {
    await refreshServerConversationUi({ force: false }).catch(() => {});
  } else {
    renderGroupsRail();
  }
  return true;
}

function closeServerCreateModal() {
  const modal = document.getElementById("serverCreateModal");
  if (!modal || modal.classList.contains("hidden")) return;
  clearServerCreateIconDraft();
  serverCreateName = "";
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");
}

async function uploadServerIconFile(file, { serverId = "" } = {}) {
  if (!file || !state.user?.id) throw new Error("Upload de icon do server invalido.");
  const contentType = String(file.type || "").trim().toLowerCase();
  if (!contentType.startsWith("image/")) {
    throw new Error("O icon do server tem de ser uma imagem.");
  }
  const fileSize = Number(file.size || 0);
  if (fileSize > SERVER_ICON_MAX_BYTES) {
    throw new Error("Icon do server demasiado grande (max 8MB).");
  }

  const ext = (String(file.name || "").split(".").pop() || "png").toLowerCase();
  const { ext: safeExt, mime } = resolveAvatarMimeAndExt(ext, file.type || "");
  const serverTag = normId(serverId) || "draft";
  const path = `${state.user.id}/server_${serverTag}_${Date.now()}.${safeExt}`;
  const upload = await supabase.storage.from("avatars").upload(path, file, {
    upsert: true,
    contentType: mime,
  });
  if (upload.error) throw upload.error;
  const { data } = supabase.storage.from("avatars").getPublicUrl(path);
  const publicUrl = String(data?.publicUrl || "").trim();
  if (!publicUrl) throw new Error("Nao consegui gerar URL publica para o icon do server.");
  return publicUrl;
}

function getServerRowById(serverId = "") {
  const sid = normId(serverId);
  if (!sid) return null;
  return (state.servers || []).find((row) => normId(row?.serverId || "") === sid) || null;
}

async function readServerWelcomeChannelFromTable(serverId = "") {
  const sid = normId(serverId || "");
  if (!sid) return { welcomeConversationId: "", defaultConversationId: "" };
  const fromRpc = async () => {
    const rpc = await readServerWelcomeChannelFromRpc(sid);
    if (!rpc) return null;
    return {
      welcomeConversationId: normId(rpc?.welcomeConversationId || ""),
      defaultConversationId: normId(rpc?.defaultConversationId || ""),
    };
  };
  try {
    const primary = await supabase
      .from("servers")
      .select("id, welcome_channel_id, default_conversation_id")
      .eq("id", sid)
      .maybeSingle();
    if (!primary?.error && primary?.data) {
      return {
        welcomeConversationId: normId(primary.data?.welcome_channel_id || ""),
        defaultConversationId: normId(primary.data?.default_conversation_id || ""),
      };
    }

    if (isMissingColumnError(primary?.error, "default_conversation_id")) {
      const withoutDefault = await supabase
        .from("servers")
        .select("id, welcome_channel_id")
        .eq("id", sid)
        .maybeSingle();
      if (!withoutDefault?.error && withoutDefault?.data) {
        return {
          welcomeConversationId: normId(withoutDefault.data?.welcome_channel_id || ""),
          defaultConversationId: "",
        };
      }
    }

    if (isMissingColumnError(primary?.error, "welcome_channel_id")) {
      const legacy = await supabase
        .from("servers")
        .select("id, welcome_conversation_id, default_conversation_id")
        .eq("id", sid)
        .maybeSingle();
      if (!legacy?.error && legacy?.data) {
        return {
          welcomeConversationId: normId(legacy.data?.welcome_conversation_id || ""),
          defaultConversationId: normId(legacy.data?.default_conversation_id || ""),
        };
      }

      if (isMissingColumnError(legacy?.error, "default_conversation_id")) {
        const legacyWithoutDefault = await supabase
          .from("servers")
          .select("id, welcome_conversation_id")
          .eq("id", sid)
          .maybeSingle();
        if (!legacyWithoutDefault?.error && legacyWithoutDefault?.data) {
          return {
            welcomeConversationId: normId(legacyWithoutDefault.data?.welcome_conversation_id || ""),
            defaultConversationId: "",
          };
        }
      }
    }
    const rpcFallback = await fromRpc();
    if (rpcFallback) return rpcFallback;
    return { welcomeConversationId: "", defaultConversationId: "" };
  } catch (_) {
    const rpcFallback = await fromRpc();
    if (rpcFallback) return rpcFallback;
    return { welcomeConversationId: "", defaultConversationId: "" };
  }
}

async function readServerWelcomeChannelFromRpc(serverId = "") {
  const sid = normId(serverId || "");
  if (!sid) return null;
  const payloads = [
    { p_server_id: sid },
    { server_id: sid },
  ];
  let lastErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("get_server_welcome_channel", payload);
    if (!res?.error) {
      const row = Array.isArray(res?.data) ? (res.data[0] || null) : (res?.data || null);
      if (!row) return { welcomeConversationId: "", defaultConversationId: "" };
      return {
        welcomeConversationId: normId(row?.welcome_channel_id || row?.welcome_conversation_id || ""),
        defaultConversationId: normId(row?.default_conversation_id || ""),
      };
    }
    if (!isMissingRpcError(res?.error)) {
      lastErr = res?.error || null;
      break;
    }
    lastErr = res?.error || null;
  }
  if (lastErr && !isMissingRpcError(lastErr)) {
    console.warn("get_server_welcome_channel rpc failed", lastErr);
  }
  return null;
}

async function saveServerWelcomeChannelViaRpc(serverId = "", conversationId = "") {
  const sid = normId(serverId || "");
  if (!sid) return { ok: false, error: { message: "server_id invalido" }, needsPatch: false };
  const nextId = normId(conversationId || "");
  const payloadValue = nextId || null;
  const payloads = [
    { p_server_id: sid, p_welcome_channel_id: payloadValue },
    { server_id: sid, welcome_channel_id: payloadValue },
    { p_server_id: sid, p_conversation_id: payloadValue },
    { server_id: sid, conversation_id: payloadValue },
  ];
  let lastErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("set_server_welcome_channel", payload);
    if (!res?.error) {
      const row = Array.isArray(res?.data) ? (res.data[0] || null) : (res?.data || null);
      const savedId = normId(row?.welcome_channel_id || row?.welcome_conversation_id || nextId);
      return { ok: true, error: null, column: "rpc:set_server_welcome_channel", value: savedId };
    }
    if (!isMissingRpcError(res?.error)) {
      lastErr = res?.error || null;
      break;
    }
    lastErr = res?.error || null;
  }
  if (lastErr && isMissingRpcError(lastErr)) {
    return { ok: false, error: lastErr, needsPatch: true };
  }
  return { ok: false, error: lastErr || { message: "rpc falhou" }, needsPatch: false };
}

async function saveServerWelcomeChannelToTable(serverId = "", conversationId = "") {
  const sid = normId(serverId || "");
  if (!sid) return { ok: false, error: { message: "server_id invalido" }, needsPatch: false };
  const nextId = normId(conversationId || "");
  const payloadValue = nextId || null;

  const primary = await supabase
    .from("servers")
    .update({ welcome_channel_id: payloadValue })
    .eq("id", sid)
    .select("id")
    .maybeSingle();
  if (!primary?.error) {
    const verify = await readServerWelcomeChannelFromTable(sid);
    const savedId = normId(verify?.welcomeConversationId || "");
    if (savedId === nextId) {
      return { ok: true, error: null, column: "welcome_channel_id", value: nextId };
    }
    const rpcFallback = await saveServerWelcomeChannelViaRpc(sid, nextId);
    if (rpcFallback?.ok) return rpcFallback;
    return {
      ok: false,
      error: {
        message: rpcFallback?.needsPatch
          ? "Falhou ao confirmar o canal de bem-vindo. Verifica permissoes do server (RLS/update)."
          : "Falhou ao confirmar o canal de bem-vindo. Verifica permissoes/RLS do server."
      },
      needsPatch: false,
    };
  }

  if (isMissingColumnError(primary.error, "welcome_channel_id")) {
    const legacy = await supabase
      .from("servers")
      .update({ welcome_conversation_id: payloadValue })
      .eq("id", sid)
      .select("id")
      .maybeSingle();
    if (!legacy?.error) {
      const verify = await readServerWelcomeChannelFromTable(sid);
      const savedId = normId(verify?.welcomeConversationId || "");
      if (savedId === nextId) {
        return { ok: true, error: null, column: "welcome_conversation_id", value: nextId };
      }
      const rpcFallback = await saveServerWelcomeChannelViaRpc(sid, nextId);
      if (rpcFallback?.ok) return rpcFallback;
      return {
        ok: false,
        error: {
          message: rpcFallback?.needsPatch
            ? "Falhou ao confirmar o canal de bem-vindo. Verifica permissoes do server (RLS/update)."
            : "Falhou ao confirmar o canal de bem-vindo. Verifica permissoes/RLS do server."
        },
        needsPatch: false,
      };
    }
    if (isMissingColumnError(legacy.error, "welcome_conversation_id")) {
      const rpcFallback = await saveServerWelcomeChannelViaRpc(sid, nextId);
      if (rpcFallback?.ok) return rpcFallback;
      return { ok: false, error: legacy.error, needsPatch: true };
    }
    const rpcFallback = await saveServerWelcomeChannelViaRpc(sid, nextId);
    if (rpcFallback?.ok) return rpcFallback;
    return {
      ok: false,
      error: legacy.error,
      needsPatch: !!rpcFallback?.needsPatch,
    };
  }

  const rpcFallback = await saveServerWelcomeChannelViaRpc(sid, nextId);
  if (rpcFallback?.ok) return rpcFallback;
  return {
    ok: false,
    error: primary.error,
    needsPatch: !!rpcFallback?.needsPatch,
  };
}

async function resolveServerWelcomeChannelConversationId(serverId = "", {
  fallbackConversationId = "",
  forceLookup = false,
} = {}) {
  const sid = normId(serverId || "");
  if (!sid) return "";

  const row = getServerRowById(sid);
  let welcomeConversationId = normId(row?.welcomeConversationId || "");
  let defaultConversationId = normId(row?.defaultConversationId || fallbackConversationId || "");

  if (forceLookup || !welcomeConversationId || !defaultConversationId) {
    const lookup = await readServerWelcomeChannelFromTable(sid);
    if (lookup?.welcomeConversationId) welcomeConversationId = normId(lookup.welcomeConversationId);
    if (lookup?.defaultConversationId) defaultConversationId = normId(lookup.defaultConversationId);
    if (row && lookup?.welcomeConversationId) row.welcomeConversationId = normId(lookup.welcomeConversationId);
  }

  const channels = await fetchServerChannelsForSidebar(sid, { force: false }).catch(() => []);
  const textChannels = (channels || []).filter((ch) => normalizeConversationChannelType(ch?.channelType || "") !== "voice");
  const textByConversationId = new Set(textChannels.map((ch) => normId(ch?.conversationId || "")).filter(Boolean));

  const candidates = [
    welcomeConversationId,
    defaultConversationId,
    normId(fallbackConversationId || ""),
  ].filter(Boolean);

  for (const candidate of candidates) {
    if (textByConversationId.has(candidate)) return candidate;
  }
  // IMPORTANT:
  // Fallback should prefer the server default channel, not an arbitrary first channel.
  return candidates[0] || "";
}

async function renderServerSettingsWelcomeChannelOptions(serverId = "") {
  const sid = normId(serverId || serverSettingsServerId || "");
  const selectEl = document.getElementById("serverSettingsWelcomeChannel");
  const hintEl = document.getElementById("serverSettingsWelcomeHint");
  if (!sid || !selectEl) return;

  selectEl.disabled = true;
  selectEl.innerHTML = `<option value="">Loading channels...</option>`;
  if (hintEl) hintEl.textContent = "Member join/leave messages are posted in this channel.";

  const channels = await fetchServerChannelsForSidebar(sid, { force: true }).catch(() => []);
  const textChannels = (channels || []).filter((ch) => normalizeConversationChannelType(ch?.channelType || "") !== "voice");
  const tableRow = await readServerWelcomeChannelFromTable(sid);
  const explicitWelcomeId = normId(
    tableRow?.welcomeConversationId
    || getServerRowById(sid)?.welcomeConversationId
    || serverSettingsWelcomeChannelId
    || ""
  );
  const defaultConversationId = normId(
    tableRow?.defaultConversationId
    || getServerRowById(sid)?.defaultConversationId
    || ""
  );
  serverSettingsWelcomeChannelId = explicitWelcomeId;

  if (!textChannels.length) {
    selectEl.innerHTML = `<option value="">No text channels available</option>`;
    selectEl.disabled = true;
    if (hintEl) hintEl.textContent = "Create a text channel first to enable welcome logs.";
    return;
  }

  const defaultChannelLabel = (() => {
    const found = textChannels.find((ch) => normId(ch?.conversationId || "") === defaultConversationId);
    const rawName = found?.name || "general";
    return `Default server chat (# ${normalizeConversationLabel(rawName, "general")})`;
  })();

  const defaultOption = `<option value="">${esc(defaultChannelLabel)}</option>`;
  const optionsHtml = textChannels.map((ch) => {
    const convId = normId(ch?.conversationId || "");
    const channelName = normalizeConversationLabel(ch?.name || "general", "general");
    const selected = convId && convId === explicitWelcomeId ? " selected" : "";
    return `<option value="${escAttr(convId)}"${selected}># ${esc(channelName)}</option>`;
  }).join("");
  selectEl.innerHTML = `${defaultOption}${optionsHtml}`;

  const optionValues = new Set(textChannels.map((ch) => normId(ch?.conversationId || "")).filter(Boolean));
  if (explicitWelcomeId && optionValues.has(explicitWelcomeId)) {
    selectEl.value = explicitWelcomeId;
  } else {
    selectEl.value = "";
    serverSettingsWelcomeChannelId = "";
  }

  selectEl.disabled = false;
  if (hintEl) hintEl.textContent = "If empty, welcome logs use the default chat created by the server.";
}

function getServerMyRole(serverId = "") {
  const sid = normId(serverId);
  if (!sid) return "";
  const meId = normId(state.user?.id || "");
  if (!meId) return "";
  const members = serverMemberListByServerId.get(sid) || [];
  const meRow = (members || []).find((m) => normId(m?.userId || "") === meId) || null;
  return String(meRow?.role || "").trim().toLowerCase();
}

function getServerCapabilityMeta(serverId = "") {
  const sid = normId(serverId);
  const meId = normId(state.user?.id || "");
  const row = getServerRowById(sid);
  const ownerUserId = normId(row?.ownerUserId || "");
  const role = getServerMyRole(sid);
  const isMember = !!(sid && row);
  const isOwner = !!(meId && ((ownerUserId && ownerUserId === meId) || role === "owner"));
  const isAdmin = role === "admin" || isOwner;
  return {
    isMember,
    isOwner,
    isAdmin,
    canInvite: isAdmin || isOwner,
    canSettings: isAdmin || isOwner,
    canLeave: isMember && !isOwner,
    canDelete: isOwner,
  };
}

function clearServerSettingsIconDraft() {
  if (serverSettingsIconPreviewUrl) safeRevokeObjectUrl(serverSettingsIconPreviewUrl);
  serverSettingsIconPreviewUrl = "";
  serverSettingsIconFile = null;
  const input = document.getElementById("serverSettingsIconFile");
  if (input) input.value = "";
}

async function inviteServerMembersRpc(serverId, memberIds = []) {
  const sid = normId(serverId);
  const ids = normalizeUuidArray(memberIds);
  if (!sid || !ids.length) return { data: null, error: { message: "server_id ou member_ids invalido" } };

  const payloads = [
    { p_server_id: sid, p_member_ids: ids },
    { server_id: sid, member_ids: ids },
  ];
  let lastMissingErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("invite_server_members", payload);
    if (!res?.error) return res;
    if (!isMissingRpcError(res.error)) return res;
    lastMissingErr = res.error;
  }
  return { data: null, error: lastMissingErr || { message: "rpc nao encontrada" } };
}

async function inviteServerMemberDirectFallback(serverId, userId) {
  const sid = normId(serverId);
  const uid = normId(userId);
  if (!sid || !uid) return { ok: false, error: { message: "server_id/user_id invalido" } };

  const rpcRes = await inviteServerMembersRpc(sid, [uid]);
  if (!rpcRes?.error) return { ok: true, via: "rpc", data: rpcRes.data };
  if (!isMissingRpcError(rpcRes.error)) return { ok: false, error: rpcRes.error };

  // Fallback without RPC: insert member directly.
  const insertPayload = { server_id: sid, user_id: uid, role: "member" };
  let directRes = await supabase
    .from("server_members")
    .upsert(insertPayload, { onConflict: "server_id,user_id", ignoreDuplicates: true });

  if (directRes?.error) {
    const roleErr = String(directRes.error?.message || "").toLowerCase();
    const roleMissing = roleErr.includes("role") && roleErr.includes("column");
    if (roleMissing) {
      directRes = await supabase
        .from("server_members")
        .upsert({ server_id: sid, user_id: uid }, { onConflict: "server_id,user_id", ignoreDuplicates: true });
    }
  }
  if (directRes?.error) return { ok: false, error: directRes.error };

  return { ok: true, via: "direct" };
}

