function getInvitableServerFriends(serverId) {
  const sid = normId(serverId);
  if (!sid) return [];
  const memberSet = new Set(
    normalizeUuidArray((serverMemberListByServerId.get(sid) || []).map((row) => normId(row?.userId || "")))
  );

  return (state.friends || [])
    .map((row) => {
      const uid = normId(row?.other_user_id || row?.id || "");
      if (!uid) return null;
      if (memberSet.has(uid)) return null;
      const username = String(row?.username || "").trim();
      const displayName = normalizeConversationLabel(row?.display_name || username || "friend", "friend");
      return {
        userId: uid,
        username,
        displayName,
        avatarUrl: String(row?.avatar_url || "").trim(),
      };
    })
    .filter(Boolean)
    .sort((a, b) => String(a.displayName || "").localeCompare(String(b.displayName || "")));
}

async function ensureDmConversationWithFriendUser(userId) {
  const friend = getFriendRowByUserId(userId) || null;
  const username = String(friend?.username || "").trim();
  if (!friend || !username) {
    return {
      conversationId: "",
      friend,
      error: { message: "friend nao encontrado" },
    };
  }

  const displayName = normalizeConversationLabel(friend?.display_name || username || "DM", "DM");
  const avatarUrl = String(friend?.avatar_url || "").trim();
  const otherUserId = normId(friend?.other_user_id || friend?.id || "");
  const { data: conversationId, error } = await supabase.rpc("create_dm", { target_username: username });
  if (error || !conversationId) {
    return {
      conversationId: "",
      friend,
      error: error || { message: "nao foi possivel abrir a DM" },
    };
  }

  setConversationMeta(conversationId, {
    kind: "dm",
    isGroup: false,
    displayName,
    username,
    otherUserId,
    avatarUrl,
    dmPrivacyState: "standard",
    dmPrivacyEpoch: 0,
  });

  return {
    conversationId,
    friend,
    error: null,
  };
}

function normalizeDmPrivacyRpcPayload(input = null) {
  if (!input || typeof input !== "object") return null;
  return {
    dm_privacy_state: input.state,
    dm_privacy_request_nonce: input.request_nonce,
    dm_privacy_requested_by: input.requested_by,
    dm_privacy_requested_at: input.requested_at,
    dm_privacy_activated_at: input.activated_at,
    dm_privacy_disabled_at: input.disabled_at,
    dm_privacy_disabled_by: input.disabled_by,
    dm_privacy_disable_request_nonce: input.disable_request_nonce,
    dm_privacy_disable_requested_by: input.disable_requested_by,
    dm_privacy_disable_requested_at: input.disable_requested_at,
    dm_privacy_epoch: input.epoch,
    dm_privacy_source: input.source,
  };
}

function isDmPrivacyRpcMissingError(error) {
  const text = String(error?.message || error || "").toLowerCase();
  return text.includes("function")
    && text.includes("private_dm");
}

function formatDmPrivacyRpcError(error, fallback = "Could not update Private DM.") {
  if (isDmPrivacyRpcMissingError(error)) {
    return "Missing DM privacy SQL. Apply the hybrid DM privacy patch and reload.";
  }
  const code = String(error?.code || error?.error || "").trim().toLowerCase();
  const map = {
    conversation_not_found: "This DM is no longer available.",
    not_direct_dm: "Private DM is only available in 1-to-1 direct messages.",
    not_one_to_one_dm: "Private DM is only available in real 1-to-1 direct messages.",
    not_conversation_member: "You no longer have access to this DM.",
    request_already_pending: "A Private DM request is already pending here.",
    request_not_pending: "There is no pending Private DM request anymore.",
    requester_cannot_accept: "The requester cannot accept their own Private DM request.",
    requester_cannot_reject: "The requester cannot reject their own Private DM request.",
    only_requester_can_cancel: "Only the requester can cancel this Private DM request.",
    stale_request: "This Private DM request changed before your action finished. Try again.",
    not_private_active: "Private DM is not active in this conversation.",
    disable_request_already_pending: "A request to turn off Private DM is already pending here.",
    disable_request_not_pending: "There is no pending request to turn off Private DM anymore.",
    disable_requester_cannot_accept: "The person who requested turning off Private DM cannot accept their own request.",
    disable_requester_cannot_reject: "The person who requested turning off Private DM cannot reject their own request.",
    only_disable_requester_can_cancel: "Only the person who requested turning off Private DM can cancel that request.",
  };
  if (code && map[code]) return map[code];
  return String(error?.message || error || fallback);
}

function isDmPrivacyRpcStateSyncError(error) {
  const code = String(error?.code || error?.error || "").trim().toLowerCase();
  return code === "stale_request"
    || code === "request_not_pending"
    || code === "disable_request_not_pending";
}

async function refreshDmPrivacyMetaFromServer(conversationId = "", { rerender = true } = {}) {
  const convId = normId(conversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!DM_PRIVATE_RUNTIME_ENABLED) {
    if (convId) {
      applyConversationDmPrivacyMeta(convId, {
        kind: "dm",
        dm_privacy_state: "standard",
        dm_privacy_request_nonce: null,
        dm_privacy_requested_by: null,
        dm_privacy_requested_at: null,
        dm_privacy_activated_at: null,
        dm_privacy_disabled_at: null,
        dm_privacy_disabled_by: null,
        dm_privacy_disable_request_nonce: null,
        dm_privacy_disable_requested_by: null,
        dm_privacy_disable_requested_at: null,
        dm_privacy_epoch: 0,
      });
    }
    if (rerender) {
      renderDmPrivacyUi();
      applyDmComposerEditUi();
    }
    return getConversationDmPrivacyMeta(convId);
  }
  if (!convId || !dmFeatureCaps.dmPrivacyState) {
    if (rerender) {
      renderDmPrivacyUi();
      applyDmComposerEditUi();
    }
    return getConversationDmPrivacyMeta(convId);
  }

  let resolvedMeta = getConversationDmPrivacyMeta(convId);
  try {
    resolvedMeta = await resolveConversationDmPrivacyMeta(convId, { force: true });
  } catch (_) {}

  if (resolvedMeta.dmPrivacyState === "private_active") {
    void ensureDmE2eeBootstrapStarted();
  }
  if (rerender) {
    renderDmPrivacyUi();
    applyDmComposerEditUi();
  }
  return resolvedMeta;
}

async function applyDmPrivacyRpcResult(result = {}, conversationId = "") {
  const convId = normId(conversationId || activeDmId || state.activeDm?.conversationId || "");
  const privacyPayload = normalizeDmPrivacyRpcPayload(result?.privacy || null);
  if (convId && privacyPayload) {
    applyConversationDmPrivacyMeta(convId, privacyPayload);
  }
  await refreshDmPrivacyMetaFromServer(convId, { rerender: true });
}

async function runDmPrivacyRpc(rpcName, payload = {}, {
  conversationId = activeDmId || state.activeDm?.conversationId || "",
  fallbackError = "Could not update Private DM.",
} = {}) {
  if (!DM_PRIVATE_RUNTIME_ENABLED) {
    throw new Error(DM_PRIVATE_RUNTIME_DISABLED_STATUS_TEXT);
  }
  const convId = normId(conversationId || "");
  const { data, error } = await rpcWithTimeout(rpcName, payload);
  if (error) {
    throw new Error(formatDmPrivacyRpcError(error, fallbackError));
  }

  const result = (data && typeof data === "object" && !Array.isArray(data)) ? data : {};
  if (result?.ok !== true) {
    const wrappedError = new Error(formatDmPrivacyRpcError(result, fallbackError));
    wrappedError.code = String(result?.error || "");
    throw wrappedError;
  }

  await applyDmPrivacyRpcResult(result, convId);
  return result;
}

