async function sendPlainTextMessageToConversation(conversationId, text, { replyToId = null } = {}) {
  const convId = normId(conversationId);
  const content = String(text || "").trim();
  if (!convId || !content || !state.user?.id) {
    return { ok: false, error: { message: "conversation_id ou content invalido" } };
  }

  const optimisticMessage = createOptimisticOutgoingMessage({
    conversationId: convId,
    content,
    replyToId,
    retryPayload: {
      kind: "text",
      conversationId: convId,
      text: content,
      replyToId: replyToId || null,
    },
  });
  if (optimisticMessage) finalizeLocalOutgoingEcho();

  let insertPayload = null;
  try {
    await ensureConversationMessageRateLimit(convId);
    insertPayload = await buildConversationMessageInsertPayload({
      conversationId: convId,
      content,
      replyToId,
    });
  } catch (error) {
    if (optimisticMessage) markOptimisticOutgoingMessageFailed(optimisticMessage.id, error);
    return { ok: false, error };
  }

  const { row, error } = await insertMessageRowAndHydrate(insertPayload, convId);
  if (error) {
    if (optimisticMessage) markOptimisticOutgoingMessageFailed(optimisticMessage.id, error);
    return { ok: false, error };
  }
  if (optimisticMessage && row) reconcileOptimisticOutgoingMessage(optimisticMessage.id, row, { keepBottom: true });
  return { ok: true, row: row || null };
}

function getCurrentUserSystemDisplayName() {
  return normalizeConversationLabel(
    String(state.me?.display_name || state.me?.username || state.user?.email || "Alguem").trim(),
    "Alguem"
  );
}

function buildServerMembershipSystemText(event = "", actorName = "") {
  const who = normalizeConversationLabel(actorName || getCurrentUserSystemDisplayName(), "Alguem");
  const ev = String(event || "").trim().toLowerCase();
  if (ev === "member_left") return `${who} saiu do servidor.`;
  if (ev === "member_joined") return `${who} entrou no servidor.`;
  return `${who} atualizou o estado do servidor.`;
}

async function sendSystemEventMessageToConversation(conversationId, {
  event = "notice",
  text = "",
  actorName = "",
} = {}) {
  const convId = normId(conversationId);
  if (!convId || !state.user?.id) {
    return { ok: false, error: { message: "conversation_id invalido" }, messageId: "" };
  }

  const payload = {
    type: "system_event",
    event: String(event || "notice").trim().toLowerCase() || "notice",
    actor: String(actorName || getCurrentUserSystemDisplayName()).trim() || "Alguem",
    text: String(text || "").trim() || buildServerMembershipSystemText(event, actorName),
  };

  let insertPayload = null;
  try {
    insertPayload = await buildConversationMessageInsertPayload({
      conversationId: convId,
      content: JSON.stringify(payload),
    });
  } catch (error) {
    return { ok: false, error, messageId: "" };
  }

  const { data, error } = await supabase
    .from("messages")
    .insert(insertPayload)
    .select("id")
    .maybeSingle();

  if (error) return { ok: false, error, messageId: "" };
  return { ok: true, messageId: normId(data?.id || "") };
}

async function announceServerMembershipEvent(serverId, {
  event = "member_joined",
  actorName = "",
  fallbackConversationId = "",
} = {}) {
  const sid = normId(serverId || "");
  if (!sid) return { ok: false, reason: "invalid_server", messageId: "", conversationId: "" };

  const conversationId = await resolveServerWelcomeChannelConversationId(sid, {
    fallbackConversationId: normId(fallbackConversationId || getServerRowById(sid)?.defaultConversationId || ""),
    forceLookup: true,
  }).catch(() => "");

  const convId = normId(conversationId || "");
  if (!convId) return { ok: false, reason: "missing_channel", messageId: "", conversationId: "" };

  const sendRes = await sendSystemEventMessageToConversation(convId, {
    event,
    actorName,
    text: buildServerMembershipSystemText(event, actorName),
  });
  if (!sendRes?.ok) {
    return { ok: false, reason: "insert_failed", error: sendRes?.error || null, messageId: "", conversationId: convId };
  }
  return { ok: true, messageId: normId(sendRes.messageId || ""), conversationId: convId };
}

async function ensureServerInviteLinkReady({ silent = false, forceRefresh = false } = {}) {
  const sid = normId(serverInviteServerId || "");
  if (!sid) {
    return { ok: false, error: { message: "server_id invalido" } };
  }

  if (!forceRefresh && !serverInviteSettingsDirty && serverInviteLinkCode && serverInviteLinkUrl) {
    return {
      ok: true,
      code: serverInviteLinkCode,
      inviteUrl: serverInviteLinkUrl,
      expiresAt: serverInviteLinkExpiresAt,
      maxUses: serverInviteLinkMaxUses,
      usesCount: serverInviteLinkUsesCount,
    };
  }

  const requestExpiresHours = normalizeServerInviteExpiresHours(serverInviteExpiresHours);
  const requestMaxUses = normalizeServerInviteMaxUses(serverInviteMaxUses);
  const requestId = ++serverInviteLinkRequestId;
  renderServerInviteModalState({
    busy: true,
    statusText: forceRefresh || serverInviteSettingsDirty
      ? "Updating invite link..."
      : "Generating invite link...",
  });
  const { data, error } = await createServerInviteLinkRpc(sid, {
    expiresHours: requestExpiresHours,
    maxUses: requestMaxUses,
  });
  if (requestId !== serverInviteLinkRequestId) {
    return { ok: false, stale: true, error: { message: "invite request superseded" } };
  }
  if (error) {
    if (error?.needsInviteCustomizationPatch) {
      renderServerInviteModalState({
        busy: false,
        statusText: "Custom invite settings need the new Supabase patch.",
      });
      if (!silent) {
        alert("SQL desatualizado no Supabase. Executa SQL/SUPABASE_PATCH_SERVER_INVITE_CUSTOMIZATION.sql e faz refresh.");
      }
      return { ok: false, error };
    }
    if (isMissingRpcError(error)) {
      renderServerInviteModalState({
        busy: false,
        statusText: "Invite link SQL is missing. Run the Supabase patch first.",
      });
      return { ok: false, error };
    }
    renderServerInviteModalState({ busy: false, statusText: "Could not generate invite link." });
    if (!silent) alert(`Erro ao criar link de convite: ${error.message}`);
    return { ok: false, error };
  }

  const row = Array.isArray(data) ? data[0] : data;
  const code = normalizeServerInviteCode(row?.invite_code || row?.code || "");
  const inviteUrl = resolveServerInviteUrl(row?.invite_url, code);
  const expiresAt = String(row?.expires_at || "").trim();
  const maxUses = normalizeServerInviteMaxUses(
    typeof row?.max_uses !== "undefined" ? row.max_uses : requestMaxUses
  );
  const usesCount = normalizeServerInviteMaxUses(
    typeof row?.uses_count !== "undefined" ? row.uses_count : 0
  );
  if (!code || !inviteUrl) {
    renderServerInviteModalState({ busy: false, statusText: "Invite link generated with missing data." });
    if (!silent) alert("Link criado mas veio sem dados validos.");
    return { ok: false, error: { message: "invite data incompleta" } };
  }

  serverInviteLinkCode = code;
  serverInviteLinkUrl = inviteUrl;
  serverInviteLinkExpiresAt = expiresAt;
  serverInviteLinkMaxUses = maxUses;
  serverInviteLinkUsesCount = usesCount;
  serverInviteSettingsDirty = false;
  return { ok: true, code, inviteUrl, expiresAt, maxUses, usesCount };
}

function renderServerInviteFriendsList() {
  const listEl = document.getElementById("serverInviteFriendsList");
  if (!listEl) return;
  const sid = normId(serverInviteServerId || "");
  if (!sid) {
    listEl.innerHTML = `<div class="hint">Open a server first.</div>`;
    return;
  }

  const query = String(serverInviteFriendSearch || "").trim().toLowerCase();
  let rows = getInvitableServerFriends(sid);
  if (query) {
    rows = rows.filter((row) => {
      const display = String(row?.displayName || "").toLowerCase();
      const username = String(row?.username || "").toLowerCase();
      return display.includes(query) || username.includes(query);
    });
  }

  if (!rows.length) {
    listEl.innerHTML = `<div class="hint">No friends available to invite.</div>`;
    return;
  }

  listEl.innerHTML = rows.map((row) => {
    const uid = normId(row?.userId || "");
    const displayName = normalizeConversationLabel(row?.displayName || row?.username || "friend", "friend");
    const username = String(row?.username || "").trim();
    const avatarUrl = String(row?.avatarUrl || "").trim();
    const isBusy = !!(serverInviteBusyUserId && serverInviteBusyUserId === uid);
    const wasInvited = !!(serverInviteLastInvitedUserId && serverInviteLastInvitedUserId === uid);
    const actionLabel = isBusy ? "Sending..." : (wasInvited ? "Sent Link" : "Send Link");
    const actionClass = wasInvited && !isBusy ? " is-ok" : "";

    return `
      <div class="serverInviteFriendRow">
        <div class="serverInviteFriendIdentity">
          <span class="serverInviteFriendAvatar">
            ${avatarUrl ? buildAvatarMediaHtml(avatarUrl, { userId: uid, alt: "avatar" }) : `<span class="groupDmAvatarFallback">${esc(getGroupOrbFallbackChar(displayName, "U"))}</span>`}
          </span>
          <span class="serverInviteFriendText">
            <span class="serverInviteFriendName">${esc(displayName)}</span>
            <span class="serverInviteFriendUsername">@${esc(username || "user")}</span>
          </span>
        </div>
        <button
          class="btn ghost serverInviteFriendAction${actionClass}"
          type="button"
          data-server-direct-invite="${escAttr(uid)}"
          ${isBusy ? "disabled" : ""}
        >${esc(actionLabel)}</button>
      </div>
    `;
  }).join("");
}

const SERVER_INVITE_QUERY_KEYS = ["server_invite", "invite", "serverInvite"];
const SERVER_INVITE_CODE_RE = /^[A-Za-z0-9_-]{6,96}$/;
const SERVER_INVITE_DEFAULT_EXPIRE_HOURS = 168;
const SERVER_INVITE_DEFAULT_MAX_USES = 0;

function normalizeServerInviteCode(value) {
  const code = String(value || "").trim().replace(/\s+/g, "");
  if (!code || !SERVER_INVITE_CODE_RE.test(code)) return "";
  return code;
}

function normalizeServerInviteExpiresHours(value) {
  const hours = Number(value);
  if (!Number.isFinite(hours)) return SERVER_INVITE_DEFAULT_EXPIRE_HOURS;
  return Math.max(0, Math.round(hours));
}

function normalizeServerInviteMaxUses(value) {
  const uses = Number(value);
  if (!Number.isFinite(uses)) return SERVER_INVITE_DEFAULT_MAX_USES;
  return Math.max(0, Math.round(uses));
}

function formatServerInviteExpirySettingLabel(hours) {
  const normalized = normalizeServerInviteExpiresHours(hours);
  if (normalized <= 0) return "Never";
  if (normalized === 1) return "1 hour";
  if (normalized % 24 === 0) {
    const days = normalized / 24;
    return days === 1 ? "1 day" : `${days} days`;
  }
  return `${normalized} hours`;
}

function formatServerInviteUsesSettingLabel(maxUses) {
  const normalized = normalizeServerInviteMaxUses(maxUses);
  if (normalized <= 0) return "No limit";
  if (normalized === 1) return "1 use";
  return `${normalized} uses`;
}

function formatServerInviteSettingsSummary(hours, maxUses) {
  return `${formatServerInviteExpirySettingLabel(hours)} â€¢ ${formatServerInviteUsesSettingLabel(maxUses)}`;
}

function resetServerInviteGeneratedLink({ markDirty = false } = {}) {
  serverInviteLinkCode = "";
  serverInviteLinkUrl = "";
  serverInviteLinkExpiresAt = "";
  serverInviteLinkMaxUses = normalizeServerInviteMaxUses(serverInviteMaxUses);
  serverInviteLinkUsesCount = 0;
  serverInviteSettingsDirty = !!markDirty;
  serverInviteLinkRequestId += 1;
}

function buildServerInviteUrlFromCode(code) {
  const inviteCode = normalizeServerInviteCode(code);
  if (!inviteCode) return "";
  if (getDesktopBridge()) {
    return `altara://invite/${encodeURIComponent(inviteCode)}`;
  }
  const origin = String(window.location?.origin || "").trim();
  const path = String(window.location?.pathname || "").trim() || "/";
  const base = origin ? `${origin}${path}` : path;
  return `${base}?server_invite=${encodeURIComponent(inviteCode)}`;
}

function resolveServerInviteUrl(rawInviteUrl, code) {
  const inviteCode = normalizeServerInviteCode(code);
  const fallback = buildServerInviteUrlFromCode(inviteCode);
  if (getDesktopBridge() && fallback) return fallback;
  const raw = String(rawInviteUrl || "").trim();
  if (!raw) return fallback;
  try {
    const url = new URL(raw, window.location?.origin || undefined);
    const extracted = extractServerInviteCodeFromUrl(url.toString());
    if (!extracted && inviteCode) {
      url.searchParams.set("server_invite", inviteCode);
    }
    return url.toString();
  } catch (_) {
    return fallback;
  }
}

function extractServerInviteCodeFromUrl(urlLike = "") {
  const raw = String(urlLike || "").trim();
  if (!raw) return "";
  try {
    const url = new URL(raw, window.location?.origin || undefined);
    for (const key of SERVER_INVITE_QUERY_KEYS) {
      const code = normalizeServerInviteCode(url.searchParams.get(key) || "");
      if (code) return code;
    }
    const segments = String(url.pathname || "")
      .split("/")
      .map((segment) => {
        try {
          return decodeURIComponent(String(segment || "").trim());
        } catch (_) {
          return String(segment || "").trim();
        }
      })
      .filter(Boolean);
    if (segments.length >= 2 && String(segments[0] || "").trim().toLowerCase() === "invite") {
      const code = normalizeServerInviteCode(segments[1]);
      if (code) return code;
    }
    const host = String(url.hostname || url.host || "").trim().toLowerCase();
    if (host === "invite" && segments.length >= 1) {
      const code = normalizeServerInviteCode(segments[0]);
      if (code) return code;
    }
  } catch (_) {
    // not an URL, ignore
  }
  return "";
}

function extractServerInviteCodeFromText(text) {
  const raw = String(text || "").trim();
  if (!raw) return "";
  const direct = normalizeServerInviteCode(raw);
  if (direct) return direct;
  const fromUrl = extractServerInviteCodeFromUrl(raw);
  if (fromUrl) return fromUrl;
  const urlMatch = raw.match(/(?:https?:\/\/|altara:\/\/)[^\s<>"']+/i);
  if (urlMatch?.[0]) {
    return extractServerInviteCodeFromUrl(urlMatch[0]);
  }
  return "";
}

function readServerInviteCodeFromWindowLocation() {
  try {
    const url = new URL(window.location.href);
    for (const key of SERVER_INVITE_QUERY_KEYS) {
      const code = normalizeServerInviteCode(url.searchParams.get(key) || "");
      if (code) return code;
    }
    const hash = String(url.hash || "");
    if (hash.includes("=")) {
      const hashBody = hash.startsWith("#") ? hash.slice(1) : hash;
      const hashParams = new URLSearchParams(hashBody.startsWith("?") ? hashBody.slice(1) : hashBody);
      for (const key of SERVER_INVITE_QUERY_KEYS) {
        const code = normalizeServerInviteCode(hashParams.get(key) || "");
        if (code) return code;
      }
    }
    const pathMatch = String(url.pathname || "").match(/\/invite\/([A-Za-z0-9_-]{6,96})/i);
    if (pathMatch?.[1]) {
      const code = normalizeServerInviteCode(pathMatch[1]);
      if (code) return code;
    }
  } catch (_) {}
  return "";
}

function clearServerInviteCodeFromWindowLocation() {
  try {
    const url = new URL(window.location.href);
    let changed = false;
    for (const key of SERVER_INVITE_QUERY_KEYS) {
      if (url.searchParams.has(key)) {
        url.searchParams.delete(key);
        changed = true;
      }
    }
    if (!changed) return;
    const nextSearch = url.searchParams.toString();
    const nextHref = `${url.pathname}${nextSearch ? `?${nextSearch}` : ""}${url.hash || ""}`;
    window.history?.replaceState?.(window.history.state || null, "", nextHref);
  } catch (_) {}
}

async function createServerInviteLinkRpc(serverId, { expiresHours = SERVER_INVITE_DEFAULT_EXPIRE_HOURS, maxUses = SERVER_INVITE_DEFAULT_MAX_USES } = {}) {
  const sid = normId(serverId);
  if (!sid) return { data: null, error: { message: "server_id invalido" } };
  const normalizedExpiresHours = normalizeServerInviteExpiresHours(expiresHours);
  const normalizedMaxUses = normalizeServerInviteMaxUses(maxUses);
  const usingDefaultSettings = normalizedExpiresHours === SERVER_INVITE_DEFAULT_EXPIRE_HOURS
    && normalizedMaxUses === SERVER_INVITE_DEFAULT_MAX_USES;
  const payloads = [
    {
      p_server_id: sid,
      p_expires_in_hours: normalizedExpiresHours,
      p_max_uses: normalizedMaxUses,
    },
    {
      server_id: sid,
      expires_in_hours: normalizedExpiresHours,
      max_uses: normalizedMaxUses,
    },
    { p_server_id: sid },
    { server_id: sid },
  ];
  let lastMissingErr = null;
  for (let index = 0; index < payloads.length; index += 1) {
    const payload = payloads[index];
    const isLegacyPayload = index >= 2;
    if (isLegacyPayload && !usingDefaultSettings) continue;
    const res = await supabase.rpc("create_server_invite_link", payload);
    if (!res?.error) return res;
    if (!isMissingRpcError(res.error)) return res;
    lastMissingErr = res.error;
  }
  if (!usingDefaultSettings && lastMissingErr) {
    return {
      data: null,
      error: {
        ...lastMissingErr,
        message: "invite customization SQL missing",
        needsInviteCustomizationPatch: true,
      },
    };
  }
  return { data: null, error: lastMissingErr || { message: "rpc nao encontrada" } };
}

