function isMissingTableError(error, tableName = "") {
  const code = String(error?.code || "").trim().toUpperCase();
  const msg = String(error?.message || "").toLowerCase();
  const details = String(error?.details || "").toLowerCase();
  const hint = String(error?.hint || "").toLowerCase();
  if (code === "42P01") {
    if (!tableName) return true;
    return msg.includes(String(tableName || "").toLowerCase());
  }
  if (code === "PGRST205") {
    if (!tableName) return true;
    const name = String(tableName || "").toLowerCase();
    return msg.includes(name) || details.includes(name) || hint.includes(name) || msg.includes("schema cache");
  }
  if (!tableName) {
    return (msg.includes("relation") && msg.includes("does not exist"))
      || msg.includes("schema cache");
  }
  const name = String(tableName || "").toLowerCase();
  return (
    (msg.includes(name) && msg.includes("does not exist"))
    || (msg.includes(name) && msg.includes("schema cache"))
    || (details.includes(name) && details.includes("schema cache"))
    || (hint.includes(name) && hint.includes("schema cache"))
    || (msg.includes("could not find the table") && msg.includes(name))
  );
}

function isAmbiguousColumnError(error, columnName = "") {
  const code = String(error?.code || "").trim().toUpperCase();
  const msg = String(error?.message || "").toLowerCase();
  if (code !== "42702" && code !== "42P09" && !msg.includes("ambiguous")) return false;
  if (!columnName) return true;
  const col = String(columnName || "").trim().toLowerCase();
  return !col || msg.includes(`"${col}"`) || msg.includes(` ${col} `) || msg.includes(col);
}

function isMissingColumnError(error, columnName = "") {
  const code = String(error?.code || "").trim().toUpperCase();
  const msg = String(error?.message || "").toLowerCase();
  if (code !== "42703" && !msg.includes("column")) return false;
  if (!columnName) return true;
  const col = String(columnName || "").trim().toLowerCase();
  return !col || msg.includes(col);
}

function normalizeServerMemberRoleValue(role = "") {
  const raw = String(role || "").trim().toLowerCase();
  if (raw === "owner" || raw === "admin") return raw;
  return "member";
}

function getServerMemberModerationRank(role = "") {
  const normalized = normalizeServerMemberRoleValue(role);
  if (normalized === "owner") return 3;
  if (normalized === "admin") return 2;
  return 1;
}

function getServerMemberRoleFromCache(serverId, userId, { members = null } = {}) {
  const sid = normId(serverId);
  const uid = normId(userId);
  if (!sid || !uid) return "member";
  const rows = Array.isArray(members) ? members : (serverMemberListByServerId.get(sid) || []);
  const memberRow = (rows || []).find((row) => normId(row?.userId || "") === uid) || null;
  if (memberRow) return normalizeServerMemberRoleValue(memberRow?.role || "member");
  const serverRow = getServerRowById(sid);
  const ownerId = normId(serverRow?.ownerUserId || "");
  if (ownerId && ownerId === uid) return "owner";
  return "member";
}

function canServerMemberModerateTarget(serverId, actorUserId, targetUserId, { members = null } = {}) {
  const sid = normId(serverId);
  const actorId = normId(actorUserId);
  const targetId = normId(targetUserId);
  if (!sid || !actorId || !targetId) return false;
  if (actorId === targetId) return false;

  const actorRole = getServerMemberRoleFromCache(sid, actorId, { members });
  const targetRole = getServerMemberRoleFromCache(sid, targetId, { members });
  const actorRank = getServerMemberModerationRank(actorRole);
  const targetRank = getServerMemberModerationRank(targetRole);
  if (actorRank < 2) return false;
  if (actorRole === "admin" && targetRank >= actorRank) return false;
  if (actorRole === "owner" && targetRole === "owner") return false;
  return true;
}

function resolveServerVoiceServerIdByConversation(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return "";
  const meta = getActiveConversationMeta(convId) || getConversationMeta(convId) || {};
  const directServerId = normId(meta?.serverId || state.activeDm?.serverId || "");
  if (directServerId) return directServerId;
  const channelCtx = findServerChannelContextByConversationId(convId) || {};
  return normId(channelCtx?.serverId || "");
}

function resolveServerVoiceMemberDisplayName(conversationId, userId, fallback = "member") {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!uid) return normalizeConversationLabel(fallback || "member", "member");
  const sid = resolveServerVoiceServerIdByConversation(convId);
  const members = sid ? (serverMemberListByServerId.get(sid) || []) : [];
  const memberRow = (members || []).find((row) => normId(row?.userId || "") === uid) || null;
  const presenceMeta = getServerVoicePresenceMemberMeta(convId, uid) || {};
  const identity = getGroupMemberIdentity(convId, uid) || {};
  const friendNickname = getDmFriendNickname(uid);
  return normalizeConversationLabel(
    friendNickname
      || fallback
      || memberRow?.displayName
      || presenceMeta?.label
      || identity?.label
      || memberRow?.username
      || "member",
    "member"
  );
}

function resolveServerVoiceMenuConversationForMember(serverId = "", userId = "") {
  const sid = normId(serverId || "");
  const uid = normId(userId || "");
  const members = sid ? (serverMemberListByServerId.get(sid) || []) : [];
  const isSameServerVoiceConv = (convId) => {
    const normalizedConvId = normId(convId || "");
    if (!normalizedConvId) return false;
    if (!isServerVoiceConversationById(normalizedConvId)) return false;
    const convServerId = normId(resolveServerVoiceServerIdByConversation(normalizedConvId));
    return !sid || (convServerId && convServerId === sid);
  };
  const memberIsActiveInConv = (convId) => {
    const normalizedConvId = normId(convId || "");
    if (!normalizedConvId || !uid) return false;
    return getServerVoiceChannelActiveMembers(normalizedConvId, members, {
      triggerReason: "resolve_server_voice_menu_conversation",
      callerFunction: "resolveServerVoiceMenuConversationForMember",
    })
      .some((member) => normId(member?.userId || "") === uid);
  };

  const primaryCandidates = normalizeUuidArray([
    callConversationId,
    activeDmId,
    state.activeDm?.conversationId,
  ]).filter(isSameServerVoiceConv);

  const activeCandidate = primaryCandidates.find(memberIsActiveInConv);
  if (activeCandidate) return activeCandidate;
  if (primaryCandidates.length) return primaryCandidates[0];

  const voiceChannels = (sid ? (serverChannelListByServerId.get(sid) || []) : [])
    .filter((ch) => normalizeConversationChannelType(ch?.channelType || "") === "voice")
    .map((ch) => normId(ch?.conversationId || ""))
    .filter(Boolean);
  const voiceCandidateWithTarget = voiceChannels.find(memberIsActiveInConv);
  if (voiceCandidateWithTarget) return voiceCandidateWithTarget;
  if (voiceChannels.length) return voiceChannels[0];

  return "";
}

function getServerVoiceMemberModerationContext({
  userId = "",
  conversationId = null,
  serverId = "",
  displayName = "",
} = {}) {
  const uid = normId(userId || "");
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!uid || !convId || !isServerVoiceConversationById(convId)) return null;
  const sid = normId(serverId || resolveServerVoiceServerIdByConversation(convId));
  if (!sid) return null;

  const meId = normId(state.user?.id || "");
  const members = serverMemberListByServerId.get(sid) || [];
  const roles = serverRoleListByServerId.get(sid) || [];
  const roleMemberMap = serverRoleMemberMapByServerId.get(sid) || new Map();
  const isSelf = !!(meId && uid === meId);
  const targetLabel = resolveServerVoiceMemberDisplayName(convId, uid, displayName || "member");
  const audioState = getParticipantAudioStateForUi(uid, convId) || {};
  const ability = canServerActorModerateTargetWithPermission({
    serverId: sid,
    actorUserId: meId,
    targetUserId: uid,
    members,
    roles,
    roleMemberMap,
  });
  const actorFlags = ability?.permissions || normalizeServerRolePermissions({});
  const canTouchTarget = !!ability?.canTouchTarget && !isSelf;
  const canDisconnect = canTouchTarget && !!actorFlags.voice_disconnect_members;
  const canMuteMic = canTouchTarget && !!actorFlags.voice_mute_microphone;
  const canDeafen = canTouchTarget && !!actorFlags.voice_deafen_members;
  const canKick = canTouchTarget && !!actorFlags.server_kick_members;
  const canBan = canTouchTarget && !!actorFlags.server_ban_members;
  const canModerate = canDisconnect || canMuteMic || canDeafen || canKick || canBan;

  return {
    serverId: sid,
    conversationId: convId,
    targetUserId: uid,
    targetDisplayName: targetLabel,
    targetRole: ability?.targetRole || "member",
    myRole: ability?.actorRole || "member",
    isSelf,
    canTouchTarget,
    canModerate: !!canModerate,
    canDisconnect,
    canMuteMic,
    canDeafen,
    canKick,
    canBan,
    micMuted: !!audioState.micMuted,
    deafened: !!audioState.deafened,
  };
}

async function canServerVoiceModeratorAffectTarget(conversationId, actorUserId, targetUserId, action = "") {
  const convId = normId(conversationId || "");
  const actorId = normId(actorUserId || "");
  const targetId = normId(targetUserId || "");
  if (!convId || !actorId || !targetId || !isServerVoiceConversationById(convId)) return false;
  const sid = resolveServerVoiceServerIdByConversation(convId);
  if (!sid) return false;

  let members = serverMemberListByServerId.get(sid) || [];
  if (!Array.isArray(members) || !members.length) {
    try {
      members = await fetchServerMembersForSidebar(sid, { force: true });
    } catch (_) {
      members = members || [];
    }
  }
  await ensureServerRolePermissionCache(sid, { force: false }).catch(() => {});
  const roles = serverRoleListByServerId.get(sid) || [];
  const roleMemberMap = serverRoleMemberMapByServerId.get(sid) || new Map();
  const ability = canServerActorModerateTargetWithPermission({
    serverId: sid,
    actorUserId: actorId,
    targetUserId: targetId,
    members,
    roles,
    roleMemberMap,
  });
  if (!ability?.canTouchTarget) return false;

  const actionName = String(action || "").trim().toLowerCase();
  if (!actionName) return true;
  const flags = ability.permissions || normalizeServerRolePermissions({});
  if (actionName === "disconnect") {
    return !!(flags.voice_disconnect_members || flags.server_kick_members || flags.server_ban_members);
  }
  if (actionName === "set_mic_muted") return !!flags.voice_mute_microphone;
  if (actionName === "set_deafened") return !!flags.voice_deafen_members;
  if (actionName === "kick") return !!flags.server_kick_members;
  if (actionName === "ban") return !!flags.server_ban_members;
  return false;
}

async function kickServerMemberFromServer(serverId, userId) {
  const sid = normId(serverId);
  const uid = normId(userId);
  if (!sid || !uid) return { ok: false, error: { message: "server_id/user_id invalido" } };

  const rpcPayloads = [
    { p_server_id: sid, p_user_id: uid },
    { server_id: sid, user_id: uid },
  ];
  const rpcNames = ["kick_server_member", "remove_server_member"];
  let lastMissingErr = null;
  for (const rpcName of rpcNames) {
    for (const payload of rpcPayloads) {
      const res = await supabase.rpc(rpcName, payload);
      if (!res?.error) return { ok: true, via: rpcName, error: null };
      if (!isMissingRpcError(res.error)) return { ok: false, error: res.error };
      lastMissingErr = res.error;
    }
  }

  const { error: deleteErr } = await supabase
    .from("server_members")
    .delete()
    .eq("server_id", sid)
    .eq("user_id", uid);
  if (deleteErr) {
    if (!lastMissingErr || !isMissingTableError(deleteErr, "server_members")) {
      return { ok: false, error: deleteErr };
    }
    return { ok: false, error: lastMissingErr };
  }

  try {
    const channels = await fetchServerChannelsForSidebar(sid, { force: false });
    const conversationIds = normalizeUuidArray((channels || []).map((ch) => normId(ch?.conversationId || "")));
    if (conversationIds.length) {
      await supabase
        .from("conversation_members")
        .delete()
        .eq("user_id", uid)
        .in("conversation_id", conversationIds);
    }
  } catch (e) {
    console.warn("server member kick conversation cleanup failed", e);
  }

  return { ok: true, via: "direct", error: null };
}

async function banServerMemberFromServer(serverId, userId, { reason = "" } = {}) {
  const sid = normId(serverId);
  const uid = normId(userId);
  if (!sid || !uid) return { ok: false, error: { message: "server_id/user_id invalido" }, banStored: false };

  const reasonText = String(reason || "").trim().slice(0, 280);
  const meId = normId(state.user?.id || "");
  const rpcPayloads = [
    { p_server_id: sid, p_user_id: uid, p_reason: reasonText || null },
    { p_server_id: sid, p_user_id: uid },
    { server_id: sid, user_id: uid, reason: reasonText || null },
    { server_id: sid, user_id: uid },
  ];
  const rpcNames = ["ban_server_member"];
  let lastMissingErr = null;
  for (const rpcName of rpcNames) {
    for (const payload of rpcPayloads) {
      const res = await supabase.rpc(rpcName, payload);
      if (!res?.error) {
        return { ok: true, via: rpcName, error: null, banStored: true };
      }
      if (!isMissingRpcError(res.error)) return { ok: false, error: res.error, banStored: false };
      lastMissingErr = res.error;
    }
  }

  let banStored = false;
  const banPayloads = [
    {
      server_id: sid,
      user_id: uid,
      banned_by: meId || null,
      reason: reasonText || null,
    },
    {
      server_id: sid,
      user_id: uid,
      reason: reasonText || null,
    },
    {
      server_id: sid,
      user_id: uid,
    },
  ];
  for (const payload of banPayloads) {
    let writeError = null;
    const upsertRes = await supabase
      .from("server_bans")
      .upsert(payload, { onConflict: "server_id,user_id", ignoreDuplicates: false });
    writeError = upsertRes?.error || null;
    if (writeError) {
      const insertRes = await supabase.from("server_bans").insert(payload);
      writeError = insertRes?.error || null;
    }
    if (!writeError) {
      banStored = true;
      break;
    }
    if (isMissingColumnError(writeError)) {
      continue;
    }
    if (!isMissingTableError(writeError, "server_bans")) {
      return { ok: false, error: writeError, banStored: false };
    }
  }

  const kickRes = await kickServerMemberFromServer(sid, uid);
  if (!kickRes?.ok) {
    return { ok: false, error: kickRes.error, banStored };
  }
  if (!banStored && lastMissingErr) {
    return { ok: true, via: "direct", error: null, banStored: false, warning: lastMissingErr };
  }
  return { ok: true, via: "direct", error: null, banStored };
}

async function listServerRolesForServer(serverId) {
  const sid = normId(serverId);
  if (!sid) return { rows: [], error: { message: "server_id invalido" } };

  const payloads = [
    { p_server_id: sid },
    { server_id: sid },
  ];
  let lastMissingErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("list_server_roles", payload);
    if (!res?.error) {
      return { rows: Array.isArray(res.data) ? res.data : [], error: null };
    }
    if (!isMissingRpcError(res.error)) {
      return { rows: [], error: res.error };
    }
    lastMissingErr = res.error;
  }

  let { data, error } = await supabase
    .from("server_roles")
    .select("id, name, color, position, created_at, permissions")
    .eq("server_id", sid)
    .order("position", { ascending: true })
    .order("created_at", { ascending: true });
  if (error && isMissingColumnError(error, "permissions")) {
    const retry = await supabase
      .from("server_roles")
      .select("id, name, color, position, created_at")
      .eq("server_id", sid)
      .order("position", { ascending: true })
      .order("created_at", { ascending: true });
    data = retry?.data;
    error = retry?.error;
  }
  if (error) {
    if (!lastMissingErr || !isMissingTableError(error, "server_roles")) {
      return { rows: [], error };
    }
    return { rows: [], error: lastMissingErr };
  }
  return { rows: Array.isArray(data) ? data : [], error: null };
}

