async function createServerRoleForServer(serverId, {
  name = "",
  color = SERVER_ROLE_DEFAULT_COLOR,
  permissions = {},
} = {}) {
  const sid = normId(serverId);
  const roleName = normalizeServerRoleName(name);
  const roleColor = normalizeServerRoleColor(color);
  const rolePermissions = normalizeServerRolePermissions(permissions || {});
  if (!sid || !roleName) return { row: null, error: { message: "server_id ou role name invalido" }, warning: null };

  const payloads = [
    { p_server_id: sid, p_name: roleName, p_color: roleColor, p_permissions: rolePermissions },
    { p_server_id: sid, p_name: roleName, p_color: roleColor },
    { server_id: sid, name: roleName, color: roleColor },
  ];
  let lastMissingErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("create_server_role", payload);
    if (!res?.error) {
      const rows = Array.isArray(res.data) ? res.data : (res.data ? [res.data] : []);
      return { row: rows[0] || null, error: null, warning: null };
    }
    if (!isMissingRpcError(res.error)) {
      return { row: null, error: res.error, warning: null };
    }
    lastMissingErr = res.error;
  }

  const { data: lastRoleRows, error: lastRoleErr } = await supabase
    .from("server_roles")
    .select("position")
    .eq("server_id", sid)
    .order("position", { ascending: false })
    .limit(1);
  if (lastRoleErr && (!lastMissingErr || !isMissingTableError(lastRoleErr, "server_roles"))) {
    return { row: null, error: lastRoleErr, warning: null };
  }
  if (lastRoleErr && lastMissingErr && isMissingTableError(lastRoleErr, "server_roles")) {
    return { row: null, error: lastMissingErr, warning: null };
  }
  const nextPosition = Number(lastRoleRows?.[0]?.position || 0) + 1;

  let data = null;
  let error = null;
  let insertRes = await supabase
    .from("server_roles")
    .insert({
      server_id: sid,
      name: roleName,
      color: roleColor,
      position: nextPosition,
      permissions: rolePermissions,
    })
    .select("id, name, color, position, created_at, permissions")
    .single();
  data = insertRes?.data || null;
  error = insertRes?.error || null;
  if (error && isMissingColumnError(error, "permissions")) {
    insertRes = await supabase
      .from("server_roles")
      .insert({
        server_id: sid,
        name: roleName,
        color: roleColor,
        position: nextPosition,
      })
      .select("id, name, color, position, created_at")
      .single();
    data = insertRes?.data || null;
    error = insertRes?.error || null;
  }
  if (error) {
    if (!lastMissingErr || !isMissingTableError(error, "server_roles")) {
      return { row: null, error, warning: null };
    }
    return { row: null, error: lastMissingErr, warning: null };
  }

  const createdRoleId = normId(data?.id || data?.role_id || "");
  let permissionWarning = null;
  if (createdRoleId && countEnabledServerRolePermissions(rolePermissions) > 0) {
    const permSaveRes = await setServerRolePermissionsForServer(sid, {
      roleId: createdRoleId,
      permissions: rolePermissions,
    });
    if (permSaveRes?.error) {
      permissionWarning = permSaveRes.error;
    } else {
      data = {
        ...(data || {}),
        permissions: permSaveRes?.row?.permissions || rolePermissions,
      };
    }
  }

  return { row: data || null, error: null, warning: permissionWarning };
}

async function setServerRolePermissionsForServer(serverId, {
  roleId = "",
  permissions = {},
} = {}) {
  const sid = normId(serverId);
  const rid = normId(roleId);
  const normalizedPermissions = normalizeServerRolePermissions(permissions || {});
  if (!sid || !rid) return { row: null, error: { message: "server_id/role_id invalido" } };

  const rpcPayloads = [
    { p_server_id: sid, p_role_id: rid, p_permissions: normalizedPermissions },
    { server_id: sid, role_id: rid, permissions: normalizedPermissions },
  ];
  let lastMissingErr = null;
  for (const payload of rpcPayloads) {
    const res = await supabase.rpc("set_server_role_permissions", payload);
    if (!res?.error) {
      const rows = Array.isArray(res.data) ? res.data : (res.data ? [res.data] : []);
      return { row: rows[0] || null, error: null };
    }
    if (!isMissingRpcError(res.error)) return { row: null, error: res.error };
    lastMissingErr = res.error;
  }

  let updateRes = await supabase
    .from("server_roles")
    .update({ permissions: normalizedPermissions })
    .eq("server_id", sid)
    .eq("id", rid)
    .select("id, name, color, position, created_at, permissions")
    .single();

  if (updateRes?.error && isMissingColumnError(updateRes.error, "permissions")) {
    if (lastMissingErr) return { row: null, error: lastMissingErr };
    return { row: null, error: updateRes.error };
  }
  if (updateRes?.error) {
    if (!lastMissingErr || !isMissingTableError(updateRes.error, "server_roles")) {
      return { row: null, error: updateRes.error };
    }
    return { row: null, error: lastMissingErr };
  }

  return { row: updateRes?.data || null, error: null };
}

async function deleteServerRoleForServer(serverId, roleId) {
  const sid = normId(serverId);
  const rid = normId(roleId);
  if (!sid || !rid) return { error: { message: "server_id ou role_id invalido" } };

  const payloads = [
    { p_server_id: sid, p_role_id: rid },
    { server_id: sid, role_id: rid },
  ];
  let lastMissingErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("delete_server_role", payload);
    if (!res?.error) return { error: null };
    if (!isMissingRpcError(res.error)) return { error: res.error };
    lastMissingErr = res.error;
  }

  const { error } = await supabase
    .from("server_roles")
    .delete()
    .eq("server_id", sid)
    .eq("id", rid);
  if (error) {
    if (!lastMissingErr || !isMissingTableError(error, "server_roles")) {
      return { error };
    }
    return { error: lastMissingErr };
  }
  return { error: null };
}

async function setServerRoleMembershipForServer(serverId, {
  roleId = "",
  userId = "",
  enabled = true,
} = {}) {
  const sid = normId(serverId);
  const rid = normId(roleId);
  const uid = normId(userId);
  if (!sid || !rid || !uid) return { error: { message: "server_id/role_id/user_id invalido" } };

  const payloads = [
    { p_server_id: sid, p_role_id: rid, p_user_id: uid, p_enabled: !!enabled },
    { server_id: sid, role_id: rid, user_id: uid, enabled: !!enabled },
  ];
  let lastMissingErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("set_server_member_role", payload);
    if (!res?.error) return { error: null };
    if (!isMissingRpcError(res.error)) return { error: res.error };
    lastMissingErr = res.error;
  }

  if (enabled) {
    const { error } = await supabase
      .from("server_role_members")
      .upsert({
        server_id: sid,
        role_id: rid,
        user_id: uid,
      }, { onConflict: "server_id,role_id,user_id", ignoreDuplicates: true });
    if (error) {
      if (!lastMissingErr || !isMissingTableError(error, "server_role_members")) {
        return { error };
      }
      return { error: lastMissingErr };
    }
    return { error: null };
  }

  const { error } = await supabase
    .from("server_role_members")
    .delete()
    .eq("server_id", sid)
    .eq("role_id", rid)
    .eq("user_id", uid);
  if (error) {
    if (!lastMissingErr || !isMissingTableError(error, "server_role_members")) {
      return { error };
    }
    return { error: lastMissingErr };
  }
  return { error: null };
}

async function openServerCreateModal() {
  if (!serverRpcAvailable) {
    alert("A funcao create_server ainda nao existe. Aplica o patch SQL de servers.");
    return;
  }
  const modal = document.getElementById("serverCreateModal");
  const nameInput = document.getElementById("serverCreateName");
  if (!modal || !nameInput) return;

  const defaultName = normalizeConversationLabel(
    `${String(state.me?.display_name || state.me?.username || "My").trim()}'s server`,
    "Server"
  );
  clearServerCreateIconDraft();
  serverCreateName = defaultName;
  nameInput.value = defaultName;
  renderServerCreateIconPreview();

  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  requestAnimationFrame(() => nameInput.focus());
}

async function submitServerCreateModal() {
  if (!serverRpcAvailable) {
    alert("A funcao create_server ainda nao existe. Aplica o patch SQL de servers.");
    return;
  }
  const nameInput = document.getElementById("serverCreateName");
  const rawName = String(nameInput?.value || "").trim();
  if (!rawName) {
    alert("Escreve um nome para o server.");
    return;
  }
  const serverName = normalizeConversationLabel(rawName, "Server");

  const { data, error } = await supabase.rpc("create_server", {
    p_name: serverName,
    p_member_ids: [],
  });
  if (error) {
    if (isMissingRpcError(error)) serverRpcAvailable = false;
    alert(`Erro ao criar server: ${error.message}`);
    return;
  }

  const row = Array.isArray(data) ? data[0] : data;
  let conversationId = normId(row?.default_conversation_id || row?.conversation_id);
  const serverId = normId(row?.server_id);
  let iconUrl = "";

  if (serverId) {
    const bootstrapRes = await ensureDefaultServerStructureForServer(serverId, {
      defaultConversationId: conversationId,
    });
    if (bootstrapRes?.error) {
      console.warn("default server structure bootstrap failed", bootstrapRes.error);
    } else {
      conversationId = normId(bootstrapRes?.textConversationId || conversationId);
    }
  }

  if (serverId && conversationId) {
    const welcomeSave = await saveServerWelcomeChannelToTable(serverId, conversationId);
    if (!welcomeSave?.ok && !welcomeSave?.needsPatch) {
      console.warn("server welcome channel default save failed", welcomeSave?.error?.message || welcomeSave?.error);
    }
  }

  if (serverId && serverCreateIconFile) {
    try {
      iconUrl = await uploadServerIconFile(serverCreateIconFile, { serverId });
      const { error: saveErr } = await supabase
        .from("servers")
        .update({ icon_url: iconUrl })
        .eq("id", serverId);
      if (saveErr) {
        const missingIconCol = String(saveErr?.message || "").toLowerCase().includes("icon_url")
          && String(saveErr?.message || "").toLowerCase().includes("column");
        if (missingIconCol) {
          alert("Server criado, mas falta a coluna icon_url no SQL da tabela servers.");
        } else {
          alert(`Server criado, mas falhou guardar icon: ${saveErr.message}`);
        }
      }
    } catch (iconErr) {
      alert(`Server criado, mas falhou upload do icon: ${iconErr?.message || iconErr}`);
    }
  }

  closeServerCreateModal();
  await refresh();

  if (!conversationId) {
    alert("Server criado. Falta abrir o canal default.");
    return;
  }

  const meta = getConversationMeta(conversationId) || {
    kind: "server",
    isGroup: true,
    displayName: serverName,
    serverId,
    serverName,
    avatarUrl: iconUrl || "",
  };
  await openConversationById(conversationId, meta);
}

function bindServerCreateModalOnce() {
  if (serverCreateModalBound) return;
  serverCreateModalBound = true;

  const modal = document.getElementById("serverCreateModal");
  const nameInput = document.getElementById("serverCreateName");
  const iconInput = document.getElementById("serverCreateIconFile");
  const iconPreview = document.getElementById("serverCreateIconPreview");
  const btnIconPick = document.getElementById("btnServerCreateIconPick");
  const btnIconClear = document.getElementById("btnServerCreateIconClear");
  const btnClose = document.getElementById("btnServerCreateClose");
  const btnCancel = document.getElementById("btnServerCreateCancel");
  const btnConfirm = document.getElementById("btnServerCreateConfirm");

  btnClose?.addEventListener("click", closeServerCreateModal);
  btnCancel?.addEventListener("click", closeServerCreateModal);

  modal?.addEventListener("click", (e) => {
    if (e.target?.dataset?.close) closeServerCreateModal();
  });

  nameInput?.addEventListener("input", () => {
    serverCreateName = normalizeConversationLabel(String(nameInput.value || "").trim(), "Server");
    renderServerCreateIconPreview();
  });

  const openPicker = () => iconInput?.click();
  iconPreview?.addEventListener("click", openPicker);
  btnIconPick?.addEventListener("click", openPicker);
  btnIconClear?.addEventListener("click", () => {
    clearServerCreateIconDraft();
    renderServerCreateIconPreview();
  });

  iconInput?.addEventListener("change", () => {
    const file = iconInput?.files?.[0] || null;
    if (!file) {
      clearServerCreateIconDraft();
      renderServerCreateIconPreview();
      return;
    }
    const contentType = String(file.type || "").toLowerCase();
    if (!contentType.startsWith("image/")) {
      alert("Escolhe uma imagem para o icon do server.");
      clearServerCreateIconDraft();
      renderServerCreateIconPreview();
      return;
    }
    if (Number(file.size || 0) > SERVER_ICON_MAX_BYTES) {
      alert("Icon do server demasiado grande (max 8MB).");
      clearServerCreateIconDraft();
      renderServerCreateIconPreview();
      return;
    }
    if (serverCreateIconPreviewUrl) safeRevokeObjectUrl(serverCreateIconPreviewUrl);
    serverCreateIconFile = file;
    serverCreateIconPreviewUrl = URL.createObjectURL(file);
    renderServerCreateIconPreview();
  });

  btnConfirm?.addEventListener("click", async () => {
    await submitServerCreateModal();
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (!modal || modal.classList.contains("hidden")) return;
    e.preventDefault();
    closeServerCreateModal();
  });
}

function clearServerChannelCreatePrivateState() {
  serverChannelCreatePrivateLoading = false;
  serverChannelCreateAllowedRoleIds.clear();
  serverChannelCreateAllowedUserIds.clear();
}

function clearServerChannelCreateEditState() {
  serverChannelCreateMode = "create";
  serverChannelCreateEditChannelId = "";
  serverChannelCreateEditConversationId = "";
  serverChannelCreateEditCategoryId = "";
}

function renderServerChannelCreatePrivateAccessUi() {
  const section = document.getElementById("serverChannelCreateAccessSection");
  const rolesListEl = document.getElementById("serverChannelCreateRoleAccessList");
  const membersListEl = document.getElementById("serverChannelCreateMemberAccessList");
  const metaEl = document.getElementById("serverChannelCreateAccessMeta");
  const typeInput = document.getElementById("serverChannelCreateType");
  const privateToggle = document.getElementById("serverChannelCreatePrivate");
  const type = String(typeInput?.value || "text").trim().toLowerCase();
  const isPrivate = !!privateToggle?.checked && type !== "category";
  if (section) section.style.display = isPrivate ? "" : "none";
  if (!rolesListEl || !membersListEl || !metaEl || !isPrivate) return;

  if (serverChannelCreatePrivateLoading) {
    rolesListEl.innerHTML = `<div class="hint">Loading roles...</div>`;
    membersListEl.innerHTML = `<div class="hint">Loading members...</div>`;
    metaEl.textContent = "Loading roles and members...";
    return;
  }

  const sid = normId(serverChannelCreateServerId || "");
  const roles = sid ? (serverRoleListByServerId.get(sid) || []) : [];
  const members = sid ? (serverMemberListByServerId.get(sid) || []) : [];
  const roleMemberMap = sid ? (serverRoleMemberMapByServerId.get(sid) || new Map()) : new Map();
  const meId = normId(state.user?.id || "");

  const validRoleIds = new Set((roles || []).map((role) => normId(role?.id || "")).filter(Boolean));
  Array.from(serverChannelCreateAllowedRoleIds).forEach((rid) => {
    if (!validRoleIds.has(rid)) serverChannelCreateAllowedRoleIds.delete(rid);
  });

  const validMemberIds = new Set((members || []).map((member) => normId(member?.userId || "")).filter(Boolean));
  Array.from(serverChannelCreateAllowedUserIds).forEach((uid) => {
    if (!validMemberIds.has(uid)) serverChannelCreateAllowedUserIds.delete(uid);
  });

  const selectedRoleCount = serverChannelCreateAllowedRoleIds.size;
  const selectedMemberCount = Array.from(serverChannelCreateAllowedUserIds)
    .filter((uid) => uid && uid !== meId)
    .length;
  metaEl.textContent = selectedRoleCount || selectedMemberCount
    ? `${selectedRoleCount} role${selectedRoleCount === 1 ? "" : "s"} â€¢ ${selectedMemberCount} member${selectedMemberCount === 1 ? "" : "s"} selected. You always keep access.`
    : "Select roles or members. You always keep access.";

  rolesListEl.innerHTML = roles.length
    ? roles.map((role) => {
      const rid = normId(role?.id || "");
      const memberCount = (roleMemberMap.get(rid) || new Set()).size;
      const checked = serverChannelCreateAllowedRoleIds.has(rid) ? " checked" : "";
      return `
        <label class="serverChannelCreateAccessRow">
          <input type="checkbox" data-server-channel-private-role="${escAttr(rid)}"${checked} />
          <span class="serverChannelCreateAccessRow__main">
            <span class="serverChannelCreateAccessRow__swatch" style="--role-color:${escAttr(role?.color || SERVER_ROLE_DEFAULT_COLOR)}" aria-hidden="true"></span>
            <span class="serverChannelCreateAccessRow__text">
              <span class="serverChannelCreateAccessRow__title">${esc(role?.name || "Role")}</span>
              <span class="serverChannelCreateAccessRow__meta">${memberCount} member${memberCount === 1 ? "" : "s"}</span>
            </span>
          </span>
        </label>
      `;
    }).join("")
    : `<div class="hint">No custom roles yet.</div>`;

  membersListEl.innerHTML = members.length
    ? members.map((member) => {
      const uid = normId(member?.userId || "");
      const displayName = normalizeConversationLabel(member?.displayName || member?.username || "member", "member");
      const username = String(member?.username || "").trim();
      const initials = (displayName.charAt(0) || username.charAt(0) || "U").toUpperCase();
      const isMe = !!(meId && uid === meId);
      const checked = isMe || serverChannelCreateAllowedUserIds.has(uid) ? " checked" : "";
      const disabled = isMe ? " disabled" : "";
      const roleTag = normalizeServerMemberRoleValue(member?.role || "member");
      const metaParts = [];
      if (username) metaParts.push(`@${username}`);
      if (roleTag !== "member") metaParts.push(roleTag);
      if (isMe) metaParts.push("You");
      const avatarHtml = String(member?.avatarUrl || "").trim()
        ? buildAvatarMediaHtml(member.avatarUrl, { userId: uid, alt: "" })
        : esc(initials);
      return `
        <label class="serverChannelCreateAccessRow${isMe ? " is-locked" : ""}">
          <input type="checkbox" data-server-channel-private-user="${escAttr(uid)}"${checked}${disabled} />
          <span class="serverChannelCreateAccessRow__main">
            <span class="serverChannelCreateAccessRow__avatar" aria-hidden="true">${avatarHtml}</span>
            <span class="serverChannelCreateAccessRow__text">
              <span class="serverChannelCreateAccessRow__title">${esc(displayName)}</span>
              <span class="serverChannelCreateAccessRow__meta">${esc(metaParts.join(" â€¢ ") || "Member")}</span>
            </span>
          </span>
        </label>
      `;
    }).join("")
    : `<div class="hint">No members found.</div>`;
}

async function ensureServerChannelCreatePrivateAccessData(serverId, { force = false } = {}) {
  const sid = normId(serverId || serverChannelCreateServerId || "");
  if (!sid) return;
  serverChannelCreatePrivateLoading = true;
  syncServerChannelCreateModalUi();
  await Promise.allSettled([
    fetchServerMembersForSidebar(sid, { force }),
    ensureServerRolePermissionCache(sid, { force }),
  ]);
  serverChannelCreatePrivateLoading = false;
  syncServerChannelCreateModalUi();
}

async function loadServerChannelEditPrivateAccessState(serverId, conversationId) {
  const sid = normId(serverId || serverChannelCreateServerId || "");
  const convId = normId(conversationId || serverChannelCreateEditConversationId || "");
  if (!sid || !convId) return;

  serverChannelCreatePrivateLoading = true;
  syncServerChannelCreateModalUi();

  const [membersRes, rolesRes, accessRes] = await Promise.allSettled([
    fetchServerMembersForSidebar(sid, { force: false }),
    ensureServerRolePermissionCache(sid, { force: false }),
    supabase
      .from("conversation_members")
      .select("user_id")
      .eq("conversation_id", convId),
  ]);

  serverChannelCreateAllowedRoleIds.clear();
  serverChannelCreateAllowedUserIds.clear();

  if (membersRes.status === "rejected") {
    console.warn("private channel edit members load failed", membersRes.reason);
  }
  if (rolesRes.status === "rejected") {
    console.warn("private channel edit roles load failed", rolesRes.reason);
  }

  if (accessRes.status === "fulfilled" && !accessRes.value?.error) {
    const accessRows = Array.isArray(accessRes.value?.data) ? accessRes.value.data : [];
    const allowedMemberIds = new Set(normalizeUuidArray(accessRows.map((row) => row?.user_id)));
    const meId = normId(state.user?.id || "");
    if (meId) allowedMemberIds.add(meId);

    const members = sid ? (serverMemberListByServerId.get(sid) || []) : [];
    const roles = sid ? (serverRoleListByServerId.get(sid) || []) : [];
    const roleMemberMap = sid ? (serverRoleMemberMapByServerId.get(sid) || new Map()) : new Map();
    const validMemberIds = new Set(members.map((member) => normId(member?.userId || "")).filter(Boolean));

    roles.forEach((role) => {
      const roleId = normId(role?.id || "");
      if (!roleId) return;
      const assignedSet = roleMemberMap.get(roleId);
      const roleMemberIds = assignedSet instanceof Set
        ? normalizeUuidArray(Array.from(assignedSet))
        : [];
      if (!roleMemberIds.length) return;
      const hasWholeRole = roleMemberIds.every((uid) => allowedMemberIds.has(uid));
      if (!hasWholeRole) return;
      serverChannelCreateAllowedRoleIds.add(roleId);
      roleMemberIds.forEach((uid) => allowedMemberIds.delete(uid));
    });

    allowedMemberIds.forEach((uid) => {
      if (!uid || uid === meId || !validMemberIds.has(uid)) return;
      serverChannelCreateAllowedUserIds.add(uid);
    });
  } else if (accessRes.status === "fulfilled" && accessRes.value?.error) {
    console.warn("private channel edit access load failed", accessRes.value.error);
  } else if (accessRes.status === "rejected") {
    console.warn("private channel edit access load failed", accessRes.reason);
  }

  serverChannelCreatePrivateLoading = false;
  syncServerChannelCreateModalUi();
}

async function createPrivateServerChannelForServer(serverId, {
  name = "",
  channelType = "text",
  categoryId = "",
  roleIds = [],
  userIds = [],
  userLimit = 0,
  mediaMode = "audio_only",
} = {}) {
  const sid = normId(serverId || "");
  const safeName = normalizeConversationLabel(
    String(name || "").trim(),
    String(channelType || "").trim().toLowerCase() === "voice" ? "voice-lounge" : "new-channel"
  );
  const safeType = String(channelType || "").trim().toLowerCase() === "voice" ? "voice" : "text";
  const safeCategoryId = normId(categoryId || "");
  const safeRoleIds = normalizeUuidArray(roleIds || []);
  const safeUserIds = normalizeUuidArray(userIds || []);
  const safeUserLimit = safeType === "voice" ? clampServerVoiceUserLimit(userLimit, 0) : 0;
  const safeMediaMode = safeType === "voice"
    ? normalizeServerVoiceMediaMode(mediaMode, "audio_only")
    : "audio_only";
  if (!sid) return { row: null, error: { message: "server_id invalido" } };

  const payloads = [
    {
      p_server_id: sid,
      p_name: safeName,
      p_channel_type: safeType,
      p_category_id: safeCategoryId || null,
      p_role_ids: safeRoleIds,
      p_user_ids: safeUserIds,
      p_user_limit: safeUserLimit,
      p_media_mode: safeMediaMode,
    },
    {
      server_id: sid,
      name: safeName,
      channel_type: safeType,
      category_id: safeCategoryId || null,
      role_ids: safeRoleIds,
      user_ids: safeUserIds,
      user_limit: safeUserLimit,
      media_mode: safeMediaMode,
    },
  ];
  let lastMissingErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("create_private_server_channel", payload);
    if (!res?.error) {
      const rows = Array.isArray(res.data) ? res.data : (res.data ? [res.data] : []);
      return { row: rows[0] || null, error: null };
    }
    if (!isMissingRpcError(res.error)) {
      return { row: null, error: res.error };
    }
    lastMissingErr = res.error;
  }
  return { row: null, error: lastMissingErr || { message: "private channel rpc missing" } };
}

async function updateServerChannelForServer(serverId, {
  channelId = "",
  name = "",
  channelType = "text",
  categoryId = "",
  isPrivate = false,
  roleIds = [],
  userIds = [],
  userLimit = 0,
  mediaMode = "audio_only",
} = {}) {
  const sid = normId(serverId || "");
  const cid = normId(channelId || "");
  const safeType = String(channelType || "").trim().toLowerCase() === "voice" ? "voice" : "text";
  const safeName = normalizeConversationLabel(
    String(name || "").trim(),
    safeType === "voice" ? "voice-lounge" : "new-channel"
  );
  const safeCategoryId = normId(categoryId || "");
  const safeRoleIds = normalizeUuidArray(roleIds || []);
  const safeUserIds = normalizeUuidArray(userIds || []);
  const safeUserLimit = safeType === "voice" ? clampServerVoiceUserLimit(userLimit, 0) : 0;
  const safeMediaMode = safeType === "voice"
    ? normalizeServerVoiceMediaMode(mediaMode, "audio_only")
    : "audio_only";
  if (!sid || !cid) return { row: null, error: { message: "dados invalidos para editar canal" } };

  const payloads = [
    {
      p_server_id: sid,
      p_channel_id: cid,
      p_name: safeName,
      p_category_id: safeCategoryId || null,
      p_is_private: !!isPrivate,
      p_role_ids: safeRoleIds,
      p_user_ids: safeUserIds,
      p_user_limit: safeUserLimit,
      p_media_mode: safeMediaMode,
    },
    {
      server_id: sid,
      channel_id: cid,
      name: safeName,
      category_id: safeCategoryId || null,
      is_private: !!isPrivate,
      role_ids: safeRoleIds,
      user_ids: safeUserIds,
      user_limit: safeUserLimit,
      media_mode: safeMediaMode,
    },
  ];

  let lastMissingErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("update_server_channel_settings", payload);
    if (!res?.error) {
      const rows = Array.isArray(res.data) ? res.data : (res.data ? [res.data] : []);
      return { row: rows[0] || null, error: null };
    }
    if (!isMissingRpcError(res.error)) {
      return { row: null, error: res.error };
    }
    lastMissingErr = res.error;
  }

  return { row: null, error: lastMissingErr || { message: "update channel rpc missing" } };
}

function closeServerChannelCreateModal() {
  const modal = document.getElementById("serverChannelCreateModal");
  if (!modal || modal.classList.contains("hidden")) return;
  serverChannelCreateServerId = "";
  serverChannelCreateServerName = "";
  serverChannelCreateServerIcon = "";
  clearServerChannelCreatePrivateState();
  clearServerChannelCreateEditState();
  delete modal.dataset.serverName;
  delete modal.dataset.categoryContextName;
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");
}

function renderServerChannelCreateCategoryOptions(serverId, {
  selectedId = "",
} = {}) {
  const sid = normId(serverId || "");
  const inputEl = document.getElementById("serverChannelCreateCategory");
  const selectEl = document.getElementById("serverChannelCreateCategorySelect");
  if (!inputEl) return "";
  const rows = sid ? (serverChannelCategoryListByServerId.get(sid) || []) : [];
  const normalizedSelectedId = normId(selectedId || "");
  const selectedRow = rows.find((cat) => normId(cat?.id || "") === normalizedSelectedId) || null;
  if (selectEl) {
    selectEl.innerHTML = "";
    const baseOption = document.createElement("option");
    baseOption.value = "";
    baseOption.textContent = "No Category";
    baseOption.dataset.categoryName = "";
    selectEl.appendChild(baseOption);
    rows.forEach((cat) => {
      const option = document.createElement("option");
      const categoryId = normId(cat?.id || "");
      const categoryName = normalizeServerCategoryName(cat?.name || "Category", "Category");
      option.value = categoryId;
      option.textContent = categoryName;
      option.dataset.categoryName = categoryName;
      selectEl.appendChild(option);
    });
    selectEl.value = selectedRow ? normalizedSelectedId : "";
  }
  inputEl.value = selectedRow ? normalizedSelectedId : "";
  inputEl.dataset.categoryName = selectedRow ? normalizeServerCategoryName(selectedRow?.name || "Category") : "";
  return inputEl.dataset.categoryName || "";
}

function syncServerChannelCreateModalUi({
  seedDefaultName = false,
} = {}) {
  const modal = document.getElementById("serverChannelCreateModal");
  const typeSection = document.getElementById("serverChannelCreateTypeSection");
  const typeInput = document.getElementById("serverChannelCreateType");
  const categoryInput = document.getElementById("serverChannelCreateCategory");
  const categorySection = document.getElementById("serverChannelCreateCategorySection");
  const categorySelect = document.getElementById("serverChannelCreateCategorySelect");
  const nameInput = document.getElementById("serverChannelCreateName");
  const subEl = document.getElementById("serverChannelCreateSub");
  const titleEl = document.getElementById("serverChannelCreateTitle");
  const nameLabel = document.getElementById("serverChannelCreateNameLabel");
  const privateSection = document.getElementById("serverChannelCreatePrivateSection");
  const privateToggle = document.getElementById("serverChannelCreatePrivate");
  const accessSection = document.getElementById("serverChannelCreateAccessSection");
  const voiceSettingsSection = document.getElementById("serverChannelCreateVoiceSettingsSection");
  const userLimitSection = document.getElementById("serverChannelCreateUserLimitSection");
  const userLimitInput = document.getElementById("serverChannelCreateUserLimit");
  const mediaModeSection = document.getElementById("serverChannelCreateMediaModeSection");
  const mediaModeSelect = document.getElementById("serverChannelCreateMediaMode");
  const voiceHintEl = document.getElementById("serverChannelCreateVoiceMetaHint");
  const prefixEl = document.getElementById("serverChannelCreateNamePrefix");
  const btnConfirm = document.getElementById("btnServerChannelCreateConfirm");
  const typeRadios = Array.from(document.querySelectorAll('input[name="serverChannelCreateTypeRadio"]'));
  if (!typeInput || !nameInput) return;
  const isEditMode = String(serverChannelCreateMode || "create").trim().toLowerCase() === "edit";
  const type = String(typeInput.value || "text").trim().toLowerCase();
  const isCategory = type === "category";
  const isVoice = type === "voice";
  const isPrivate = !!privateToggle?.checked && !isCategory;
  const defaultName = isVoice
    ? "voice-lounge"
    : isCategory
      ? "new-category"
      : "new-channel";
  const currentName = String(nameInput.value || "").trim().toLowerCase();
  const shouldSeedDefaultName = !currentName
    || currentName === "new-channel"
    || currentName === "voice-lounge"
    || currentName === "new-category";
  const selectedCategoryOption = categorySelect?.selectedOptions?.[0] || null;
  const selectedCategoryId = normId(categorySelect?.value || categoryInput?.value || "");
  const selectedCategoryName = selectedCategoryOption
    ? String(selectedCategoryOption.dataset.categoryName || "").trim()
    : String(categoryInput?.dataset?.categoryName || "").trim();
  const serverName = String(modal?.dataset?.serverName || serverChannelCreateServerName || "Server").trim() || "Server";
  const selectedMediaMode = normalizeServerVoiceMediaMode(mediaModeSelect?.value || "audio_only", "audio_only");
  const selectedUserLimit = clampServerVoiceUserLimit(userLimitInput?.value || 0, 0);
  const mediaModeMeta = getServerVoiceMediaModeMeta(selectedMediaMode);
  const showVoiceFields = !!(isVoice && !isCategory);

  if (modal) {
    modal.classList.toggle("is-category-mode", isCategory);
    modal.classList.toggle("is-edit-mode", isEditMode);
  }
  if (typeSection) typeSection.classList.toggle("is-readonly", isEditMode);
  typeRadios.forEach((radio) => {
    radio.checked = String(radio?.value || "").trim().toLowerCase() === type;
    radio.disabled = isEditMode;
  });
  if (categoryInput) {
    categoryInput.value = selectedCategoryId;
    categoryInput.dataset.categoryName = isCategory ? "" : selectedCategoryName;
  }

  nameInput.placeholder = defaultName;
  if (seedDefaultName && shouldSeedDefaultName) nameInput.value = defaultName;

  if (titleEl) {
    titleEl.textContent = isCategory
      ? (isEditMode ? "Edit Category" : "Create Category")
      : (isEditMode ? "Edit Channel" : "Create Channel");
  }
  if (subEl) subEl.textContent = `in ${isCategory ? serverName : (selectedCategoryName || serverName)}`;
  if (categorySection) categorySection.style.display = isCategory ? "none" : "";
  if (voiceSettingsSection) voiceSettingsSection.style.display = showVoiceFields ? "" : "none";
  if (userLimitSection) userLimitSection.style.display = showVoiceFields ? "" : "none";
  if (mediaModeSection) mediaModeSection.style.display = showVoiceFields ? "" : "none";
  if (privateSection) privateSection.style.display = isCategory ? "none" : "";
  if (accessSection) accessSection.style.display = isPrivate ? "" : "none";
  if (nameLabel) {
    nameLabel.textContent = isCategory ? "Category Name" : "Channel Name";
  }
  if (prefixEl) {
    prefixEl.innerHTML = isCategory ? "+" : isVoice ? "&#127911;" : "#";
    prefixEl.classList.toggle("is-voice", isVoice);
    prefixEl.classList.toggle("is-category", isCategory);
  }
  if (btnConfirm) {
    btnConfirm.textContent = isCategory
      ? (isEditMode ? "Save Changes" : "Create Category")
      : (isEditMode ? "Save Changes" : "Create Channel");
    btnConfirm.disabled = !String(nameInput.value || "").trim() || serverChannelCreatePrivateLoading;
  }
  if (mediaModeSelect) {
    const currentValue = normalizeServerVoiceMediaMode(mediaModeSelect.value || selectedMediaMode, selectedMediaMode);
    const stageOption = mediaModeSelect.querySelector('option[value="stage_like"]');
    if (stageOption) stageOption.disabled = currentValue !== "stage_like";
    mediaModeSelect.value = currentValue;
  }
  if (userLimitInput) {
    userLimitInput.value = String(showVoiceFields ? selectedUserLimit : 0);
  }
  if (voiceHintEl) {
    if (!showVoiceFields) {
      voiceHintEl.textContent = "";
    } else {
      const manualText = selectedUserLimit > 0
        ? `Manual limit: ${selectedUserLimit}.`
        : "Manual limit: 0 (uses the technical cap only).";
      const capText = `Technical participant cap: ${mediaModeMeta.participantCap}.`;
      const futureText = mediaModeMeta.comingSoon ? " Stage-like channels are coming soon." : "";
      voiceHintEl.textContent = `${mediaModeMeta.description} ${manualText} ${capText}${futureText}`.trim();
    }
  }
  renderServerChannelCreatePrivateAccessUi();
}

async function openServerChannelCreateModal(serverCtx = null, {
  defaultType = "text",
  defaultCategoryId = "",
} = {}) {
  const modal = document.getElementById("serverChannelCreateModal");
  const typeInput = document.getElementById("serverChannelCreateType");
  const nameInput = document.getElementById("serverChannelCreateName");
  const categoryInput = document.getElementById("serverChannelCreateCategory");
  const userLimitInput = document.getElementById("serverChannelCreateUserLimit");
  const mediaModeSelect = document.getElementById("serverChannelCreateMediaMode");
  const subEl = document.getElementById("serverChannelCreateSub");
  const titleEl = document.getElementById("serverChannelCreateTitle");
  const privateToggle = document.getElementById("serverChannelCreatePrivate");
  if (!modal || !typeInput || !nameInput || !subEl) return;

  const ctx = serverCtx || getActiveServerContext();
  const sid = normId(ctx?.serverId || "");
  if (!sid) {
    alert("Abre um server primeiro para criar canais.");
    return;
  }
  const caps = getServerCapabilityMeta(sid);
  if (!caps.canSettings) {
    alert("Sem permissao para criar canais neste server.");
    return;
  }

  const serverName = normalizeConversationLabel(ctx?.name || "Server", "Server");
  clearServerChannelCreateEditState();
  serverChannelCreateServerId = sid;
  serverChannelCreateServerName = serverName;
  serverChannelCreateServerIcon = String(ctx?.iconUrl || "").trim();
  modal.dataset.serverName = serverName;

  const nextType = String(defaultType || "").trim().toLowerCase() === "voice"
    ? "voice"
    : String(defaultType || "").trim().toLowerCase() === "category"
      ? "category"
      : "text";
  const nextCategoryId = normId(defaultCategoryId || "");

  typeInput.value = nextType;
  clearServerChannelCreatePrivateState();
  nameInput.value = nextType === "voice"
    ? "voice-lounge"
    : nextType === "category"
      ? "new-category"
      : "new-channel";
  nameInput.disabled = false;
  nameInput.readOnly = false;
  nameInput.removeAttribute("disabled");
  nameInput.removeAttribute("readonly");
  await fetchServerChannelCategoriesForSidebar(sid, { force: false }).catch(() => []);
  const categoryContextLabel = renderServerChannelCreateCategoryOptions(sid, {
    selectedId: nextType === "category" ? "" : nextCategoryId,
  });
  modal.dataset.categoryContextName = categoryContextLabel || "";
  if (categoryInput && nextType === "category") categoryInput.value = "";
  if (privateToggle) privateToggle.checked = false;
  if (userLimitInput) userLimitInput.value = "0";
  if (mediaModeSelect) {
    const stageOption = mediaModeSelect.querySelector('option[value="stage_like"]');
    if (stageOption) stageOption.disabled = true;
    mediaModeSelect.value = "audio_only";
  }
  syncServerChannelCreateModalUi({ seedDefaultName: true });

  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  requestAnimationFrame(() => {
    try {
      nameInput.focus({ preventScroll: true });
      const end = String(nameInput.value || "").length;
      nameInput.setSelectionRange(end, end);
    } catch (_) {
      nameInput.focus();
    }
  });
}

async function openServerChannelEditModal(serverCtx = null, channelCtx = null) {
  const modal = document.getElementById("serverChannelCreateModal");
  const typeInput = document.getElementById("serverChannelCreateType");
  const nameInput = document.getElementById("serverChannelCreateName");
  const categoryInput = document.getElementById("serverChannelCreateCategory");
  const userLimitInput = document.getElementById("serverChannelCreateUserLimit");
  const mediaModeSelect = document.getElementById("serverChannelCreateMediaMode");
  const privateToggle = document.getElementById("serverChannelCreatePrivate");
  if (!modal || !typeInput || !nameInput) return;

  const ctx = serverCtx || getActiveServerContext();
  const sid = normId(channelCtx?.serverId || ctx?.serverId || "");
  if (!sid) {
    alert("Abre um server primeiro para editar canais.");
    return;
  }

  const caps = getServerCapabilityMeta(sid);
  if (!caps.canSettings) {
    alert("Sem permissao para editar canais neste server.");
    return;
  }

  const row = await resolveServerChannelForServer(sid, {
    channelId: channelCtx?.channelId || "",
    conversationId: channelCtx?.conversationId || "",
  });
  if (!row?.conversationId) {
    alert("Nao foi possivel encontrar esse canal.");
    return;
  }

  const serverRow = getServerRowById(sid) || {};
  const serverName = normalizeConversationLabel(
    ctx?.name || serverRow?.name || serverChannelCreateServerName || "Server",
    "Server"
  );

  serverChannelCreateMode = "edit";
  serverChannelCreateServerId = sid;
  serverChannelCreateServerName = serverName;
  serverChannelCreateServerIcon = String(ctx?.iconUrl || serverRow?.iconUrl || "").trim();
  serverChannelCreateEditChannelId = normId(row?.id || channelCtx?.channelId || "");
  serverChannelCreateEditConversationId = normId(row?.conversationId || channelCtx?.conversationId || "");
  modal.dataset.serverName = serverName;

  typeInput.value = normalizeConversationChannelType(row?.channelType || channelCtx?.channelType || "text");
  clearServerChannelCreatePrivateState();
  nameInput.value = normalizeConversationLabel(
    row?.name || channelCtx?.label || (typeInput.value === "voice" ? "voice-lounge" : "general"),
    typeInput.value === "voice" ? "voice-lounge" : "general"
  );
  nameInput.disabled = false;
  nameInput.readOnly = false;
  nameInput.removeAttribute("disabled");
  nameInput.removeAttribute("readonly");

  await fetchServerChannelCategoriesForSidebar(sid, { force: false }).catch(() => []);
  const categoryContextLabel = renderServerChannelCreateCategoryOptions(sid, {
    selectedId: normId(row?.categoryId || channelCtx?.categoryId || ""),
  });
  modal.dataset.categoryContextName = categoryContextLabel || "";
  if (categoryInput) {
    categoryInput.value = normId(row?.categoryId || channelCtx?.categoryId || "");
    categoryInput.dataset.categoryName = categoryContextLabel || "";
  }
  if (privateToggle) privateToggle.checked = !!row?.isPrivate;
  const editMediaMode = typeInput.value === "voice"
    ? normalizeServerVoiceMediaMode(row?.mediaMode || row?.media_mode || "audio_only", "audio_only")
    : "audio_only";
  const editUserLimit = typeInput.value === "voice"
    ? clampServerVoiceUserLimit(row?.userLimit ?? row?.user_limit ?? 0, 0)
    : 0;
  if (userLimitInput) userLimitInput.value = String(editUserLimit);
  if (mediaModeSelect) {
    const stageOption = mediaModeSelect.querySelector('option[value="stage_like"]');
    if (stageOption) stageOption.disabled = editMediaMode !== "stage_like";
    mediaModeSelect.value = editMediaMode;
  }
  syncServerChannelCreateModalUi();

  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  requestAnimationFrame(() => {
    try {
      nameInput.focus({ preventScroll: true });
      nameInput.select();
    } catch (_) {
      nameInput.focus();
    }
  });

  if (privateToggle?.checked) {
    void loadServerChannelEditPrivateAccessState(sid, row.conversationId);
  }
}

