function closeServerFolderMenu() {
  const menu = document.getElementById("serverFolderMenu");
  if (!menu) return;
  menu.classList.remove("is-open");
  menu.innerHTML = "";
  serverFolderMenuTargetId = "";
}

function ensureServerFolderMenu() {
  let menu = document.getElementById("serverFolderMenu");
  if (!menu) {
    menu = document.createElement("div");
    menu.id = "serverFolderMenu";
    menu.className = "msgMenu";
    document.body.appendChild(menu);
  }

  if (serverFolderMenuBound) return menu;
  serverFolderMenuBound = true;

  document.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    if (!menu.classList.contains("is-open")) return;
    if (target.closest("#serverFolderMenu")) return;
    closeServerFolderMenu();
  });
  window.addEventListener("resize", closeServerFolderMenu);
  window.addEventListener("scroll", closeServerFolderMenu, true);
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeServerFolderMenu();
  });

  menu.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const actionBtn = target.closest("[data-server-folder-act]");
    if (!actionBtn || actionBtn.disabled) return;
    e.preventDefault();

    const action = String(actionBtn.getAttribute("data-server-folder-act") || "").trim().toLowerCase();
    const folderId = normId(actionBtn.getAttribute("data-server-folder-id") || serverFolderMenuTargetId);
    if (!folderId) return;
    const folder = getServerFolderById(folderId);
    const folderName = getServerFolderDisplayName(folder, "Folder");

    closeServerFolderMenu();

    if (action === "rename") {
      const nextRaw = await requestServerFolderRename(folderName, String(folder?.name || ""));
      if (nextRaw === null) return;
      const changed = renameServerOrbFolder(folderId, nextRaw, { persist: true });
      if (changed) renderGroupsRail();
      return;
    }
    if (action === "mark_read") {
      await markServerFolderAsRead(folderId);
      renderGroupsRail();
      return;
    }
    if (action === "dissolve") {
      const changed = dissolveServerOrbFolder(folderId, { persist: true });
      if (changed) renderGroupsRail();
    }
  });

  return menu;
}

function openServerFolderMenuAt(folderCtx, point) {
  const folderId = normId(folderCtx?.folderId || "");
  if (!folderId || !point) return;
  closeMessageMenu();
  closeDmListMenus();
  closeServerPanelMenu();

  const folder = getServerFolderById(folderId);
  if (!folder) return;

  const menu = ensureServerFolderMenu();
  const folderName = getServerFolderDisplayName(folder, "Folder");
  const serverCount = Math.max(0, Number(folder?.serverIds?.length || 0));

  menu.innerHTML = [
    `<button class="msgMenu__item" data-server-folder-act="mark_read" data-server-folder-id="${escAttr(folderId)}"><span class="msgMenu__itemMain"><span>Mark Folder As Read</span><span class="msgMenu__itemHint">${esc(serverCount === 1 ? "1 server" : `${serverCount} servers`)}</span></span></button>`,
    `<button class="msgMenu__item" data-server-folder-act="rename" data-server-folder-id="${escAttr(folderId)}"><span class="msgMenu__itemMain"><span>Rename Folder</span><span class="msgMenu__itemHint">${esc(folderName)}</span></span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item msgMenu__item--danger" data-server-folder-act="dissolve" data-server-folder-id="${escAttr(folderId)}"><span>Dissolve Folder</span></button>`,
  ].join("");

  menu.classList.add("is-open");
  serverFolderMenuTargetId = folderId;
  positionMenuAtPoint(menu, point, { width: 248, minHeight: 148 });
}

function closeServerChannelItemMenu() {
  const menu = document.getElementById("serverChannelItemMenu");
  if (!menu) return;
  menu.classList.remove("is-open");
  menu.innerHTML = "";
  delete menu.dataset.submenuSide;
  serverChannelItemMenuTarget = null;
  serverChannelItemMenuBusy = false;
}

async function runServerChannelItemMenuAction(action, context = null) {
  const ctx = context || serverChannelItemMenuTarget;
  const act = String(action || "").trim().toLowerCase();
  if (!ctx || !act || serverChannelItemMenuBusy) return;

  if (act === "mark_read") {
    const convId = normId(ctx.conversationId || "");
    if (convId) clearDmUnreadForConversation(convId);
    return;
  }

  if (act === "copy_channel_id") {
    const convId = normId(ctx.conversationId || "");
    if (convId) await copyTextWithPromptFallback(convId, "Channel ID");
    return;
  }

  if (act === "copy_category_id") {
    const catId = normId(ctx.categoryId || "");
    if (catId) await copyTextWithPromptFallback(catId, "Category ID");
    return;
  }

  serverChannelItemMenuBusy = true;
  try {
    if (act === "edit_channel") {
      const serverRow = getServerRowById(ctx.serverId) || {};
      await openServerChannelEditModal({
        serverId: ctx.serverId,
        name: serverRow?.name || serverChannelCreateServerName || "Server",
        iconUrl: String(serverRow?.iconUrl || "").trim(),
      }, ctx);
      return;
    }
    if (act === "delete_channel") {
      await deleteServerChannelById(ctx.serverId, {
        channelId: ctx.channelId,
        conversationId: ctx.conversationId,
        channelName: ctx.label,
        channelType: ctx.channelType,
      });
      return;
    }
    if (act === "edit_category") {
      const serverRow = getServerRowById(ctx.serverId) || {};
      await openServerCategoryEditModal({
        serverId: ctx.serverId,
        name: serverRow?.name || serverChannelCreateServerName || "Server",
        iconUrl: String(serverRow?.iconUrl || "").trim(),
      }, ctx);
      return;
    }
    if (act === "delete_category") {
      await deleteServerChannelCategoryById(ctx.serverId, {
        categoryId: ctx.categoryId,
        categoryName: ctx.label,
      });
    }
  } finally {
    serverChannelItemMenuBusy = false;
  }
}

