function openServerChannelItemMenuAt(context, point) {
  const itemType = String(context?.itemType || "").trim().toLowerCase();
  const sid = normId(context?.serverId || "");
  if (!sid || !point) return;
  if (itemType !== "channel" && itemType !== "category") return;

  closeMessageMenu();
  closeDmListMenus();

  const menu = ensureServerChannelItemMenu();
  const caps = getServerCapabilityMeta(sid);
  const canManage = !!caps.canSettings;

  if (itemType === "channel") {
    const convId = normId(context?.conversationId || "");
    const canEdit = canManage && !!(normId(context?.channelId || "") || convId);
    const canDelete = canManage && !!(normId(context?.channelId || "") || convId);
    menu.innerHTML = [
      `<button class="msgMenu__item${convId ? "" : " is-disabled"}" data-server-channel-item-act="mark_read" ${convId ? "" : "disabled"}><span>Mark As Read</span></button>`,
      `<div class="msgMenu__divider"></div>`,
      `<button class="msgMenu__item${canEdit ? "" : " is-disabled"}" data-server-channel-item-act="edit_channel" ${canEdit ? "" : "disabled"}><span>Edit Channel</span></button>`,
      `<button class="msgMenu__item msgMenu__item--danger${canDelete ? "" : " is-disabled"}" data-server-channel-item-act="delete_channel" ${canDelete ? "" : "disabled"}><span>Delete Channel</span></button>`,
      `<div class="msgMenu__divider"></div>`,
      `<button class="msgMenu__item${convId ? "" : " is-disabled"}" data-server-channel-item-act="copy_channel_id" ${convId ? "" : "disabled"}><span>Copy Channel ID</span><span class="msgMenu__kbd">ID</span></button>`,
    ].join("");
    serverChannelItemMenuTarget = {
      itemType: "channel",
      serverId: sid,
      channelId: normId(context?.channelId || ""),
      conversationId: convId,
      channelType: normalizeConversationChannelType(context?.channelType || "text"),
      categoryId: normId(context?.categoryId || ""),
      isPrivate: !!context?.isPrivate,
      label: normalizeConversationLabel(
        context?.label || (normalizeConversationChannelType(context?.channelType || "text") === "voice" ? "voice-lounge" : "general"),
        normalizeConversationChannelType(context?.channelType || "text") === "voice" ? "voice-lounge" : "general"
      ),
    };
    menu.classList.add("is-open");
    positionMenuAtPoint(menu, point, { width: 246, minHeight: 168 });
    return;
  }

  const catId = normId(context?.categoryId || "");
  const canEditCategory = canManage && !!catId;
  const canDeleteCategory = canManage && !!catId;
  menu.innerHTML = [
    `<button class="msgMenu__item${canEditCategory ? "" : " is-disabled"}" data-server-channel-item-act="edit_category" ${canEditCategory ? "" : "disabled"}><span>Edit Category</span></button>`,
    `<button class="msgMenu__item msgMenu__item--danger${canDeleteCategory ? "" : " is-disabled"}" data-server-channel-item-act="delete_category" ${canDeleteCategory ? "" : "disabled"}><span>Delete Category</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item${catId ? "" : " is-disabled"}" data-server-channel-item-act="copy_category_id" ${catId ? "" : "disabled"}><span>Copy Category ID</span><span class="msgMenu__kbd">ID</span></button>`,
  ].join("");
  serverChannelItemMenuTarget = {
    itemType: "category",
    serverId: sid,
    categoryId: catId,
    label: normalizeServerCategoryName(context?.label || "Category", "Category"),
  };
  menu.classList.add("is-open");
  positionMenuAtPoint(menu, point, { width: 246, minHeight: 132 });
}

function closeServerVoiceMemberMenu(options = null) {
  const menu = document.getElementById("serverVoiceMemberMenu");
  if (!menu) return;
  const force = !!(options && typeof options === "object" && options.force);
  if (!force && menu.classList.contains("is-open")) {
    const activeEl = document.activeElement;
    const focusInside = activeEl instanceof HTMLElement && menu.contains(activeEl);
    if (serverVoiceMemberMenuHovering || focusInside) return;
  }
  menu.classList.remove("is-open");
  menu.innerHTML = "";
  serverVoiceMemberMenuTarget = null;
  serverVoiceMemberMenuBusy = false;
  serverVoiceMemberMenuHovering = false;
}

function applyLocalServerVoiceMemberRemoval(conversationId, userId) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid) return;
  removeServerVoicePresenceMember(convId, uid);
  removeCallParticipantAudioState(convId, uid);
  removeCallParticipantShareState(convId, uid);
  const activeConvId = normId(callConversationId || activeDmId || "");
  if (activeConvId && activeConvId === convId) {
    removeGroupCallActiveMember(uid);
    closeRelayVideoSendPeer(uid);
    closeRelayVideoRecvPeer(uid);
    refreshCallUI();
  }
  refreshServerVoiceChannelBadges();
}

async function refreshServerMemberModerationUi(serverId) {
  const sid = normId(serverId || "");
  if (!sid) return;
  serverMemberListByServerId.delete(sid);
  serverRoleMemberMapByServerId.delete(sid);
  await fetchServerMembersForSidebar(sid, { force: true }).catch(() => {});
  await ensureServerRolePermissionCache(sid, { force: true }).catch(() => {});
  await loadGroupAndServerCollections({ force: true, hydrateGroupMetadata: true }).catch(() => {});
  renderGroupsRail();
  await refreshServerConversationUi({ force: true }).catch(() => {});
}

async function sendServerVoiceModerationSignal({
  conversationId,
  targetUserId,
  action = "",
  value = null,
} = {}) {
  const convId = normId(conversationId || "");
  const uid = normId(targetUserId || "");
  const modAction = String(action || "").trim().toLowerCase();
  if (!convId || !uid || !modAction) return { ok: false, error: { message: "dados invalidos para moderacao" } };

  const payload = {
    signal: "server_voice_mod",
    group_call: true,
    mod_action: modAction,
    target_user_id: uid,
    mod_ts: Date.now(),
    from_label: state.me?.display_name || state.me?.username || t("call.someone", "someone"),
    from_avatar: state.me?.avatar_url || null,
  };
  if (typeof value === "boolean") payload.mod_value = !!value;
  const res = await sendCallSignal("ice", payload, uid, convId);
  if (res?.error) return { ok: false, error: res.error };
  return { ok: true, error: null };
}

async function runServerVoiceMemberMenuAction(action, context) {
  const ctx = context || serverVoiceMemberMenuTarget;
  if (!ctx || serverVoiceMemberMenuBusy) return;

  const convId = normId(ctx.conversationId || "");
  const sid = normId(ctx.serverId || "");
  const uid = normId(ctx.targetUserId || "");
  const label = normalizeConversationLabel(ctx.targetDisplayName || "member", "member");
  if (!convId || !sid || !uid) return;
  const isSelfTarget = !!ctx.isSelf;

  const canRunAction = (() => {
    if (isSelfTarget) {
      return action === "disconnect" || action === "toggle_mic" || action === "toggle_deafen";
    }
    if (action === "disconnect") return !!ctx.canDisconnect;
    if (action === "toggle_mic") return !!ctx.canMuteMic;
    if (action === "toggle_deafen") return !!ctx.canDeafen;
    if (action === "kick") return !!ctx.canKick;
    if (action === "ban") return !!ctx.canBan;
    return false;
  })();
  if (!canRunAction) return;

  serverVoiceMemberMenuBusy = true;
  try {
    if (isSelfTarget) {
      if (action === "disconnect") {
        if (isLocalServerVoiceCallContextActive(convId)) {
          await hangupCurrentCallByUser("?? SaÃ­ste da chamada.");
        } else {
          applyLocalServerVoiceMemberRemoval(convId, uid);
          refreshCallUI();
        }
        return;
      }
      if (action === "toggle_mic") {
        toggleMic();
        return;
      }
      if (action === "toggle_deafen") {
        toggleDeafen();
        return;
      }
    }

    if (action === "disconnect") {
      const signalRes = await sendServerVoiceModerationSignal({
        conversationId: convId,
        targetUserId: uid,
        action: "disconnect",
      });
      if (!signalRes?.ok) {
        alert(`Erro a remover da chamada: ${signalRes?.error?.message || "falha desconhecida"}`);
        return;
      }
      applyLocalServerVoiceMemberRemoval(convId, uid);
      setCallStatus(`? ${label} foi removido da chamada.`, true);
      setTimeout(() => {
        if (inCall) setCallStatus("", false);
      }, 1700);
      return;
    }

    if (action === "toggle_mic") {
      const audioState = getParticipantAudioStateForUi(uid, convId) || {};
      const nextMuted = !audioState.micMuted;
      const signalRes = await sendServerVoiceModerationSignal({
        conversationId: convId,
        targetUserId: uid,
        action: "set_mic_muted",
        value: nextMuted,
      });
      if (!signalRes?.ok) {
        alert(`Erro a atualizar microfone: ${signalRes?.error?.message || "falha desconhecida"}`);
        return;
      }
      setCallParticipantAudioState(convId, uid, {
        micMuted: nextMuted,
        seenAt: Date.now(),
      });
      refreshServerVoiceChannelBadges();
      refreshCallUI();
      setCallStatus(`??? ${label}: microfone ${nextMuted ? "silenciado" : "reativado"}.`, true);
      setTimeout(() => {
        if (inCall) setCallStatus("", false);
      }, 1400);
      return;
    }

    if (action === "toggle_deafen") {
      const audioState = getParticipantAudioStateForUi(uid, convId) || {};
      const nextDeafened = !audioState.deafened;
      const signalRes = await sendServerVoiceModerationSignal({
        conversationId: convId,
        targetUserId: uid,
        action: "set_deafened",
        value: nextDeafened,
      });
      if (!signalRes?.ok) {
        alert(`Erro a atualizar fones: ${signalRes?.error?.message || "falha desconhecida"}`);
        return;
      }
      setCallParticipantAudioState(convId, uid, {
        deafened: nextDeafened,
        seenAt: Date.now(),
      });
      refreshServerVoiceChannelBadges();
      refreshCallUI();
      setCallStatus(`?? ${label}: fones ${nextDeafened ? "silenciados" : "reativados"}.`, true);
      setTimeout(() => {
        if (inCall) setCallStatus("", false);
      }, 1400);
      return;
    }

    if (action === "kick") {
      const ok = await requestAppConfirm(`Kick ${label} do server?`, {
        title: "Server Voice Controls",
        okText: t("dialog.confirm.ok", "Confirm"),
        cancelText: t("dialog.confirm.cancel", "Cancel"),
        danger: true,
      });
      if (!ok) return;
      await sendServerVoiceModerationSignal({
        conversationId: convId,
        targetUserId: uid,
        action: "disconnect",
      }).catch(() => {});

      const kickRes = await kickServerMemberFromServer(sid, uid);
      if (!kickRes?.ok) {
        alert(`Erro ao kickar membro: ${kickRes?.error?.message || "falha desconhecida"}`);
        return;
      }

      applyLocalServerVoiceMemberRemoval(convId, uid);
      await refreshServerMemberModerationUi(sid);
      setCallStatus(`? ${label} foi expulso do server.`, true);
      setTimeout(() => {
        if (inCall) setCallStatus("", false);
      }, 1700);
      return;
    }

    if (action === "ban") {
      const ok = await requestAppConfirm(`Banir ${label} do server?`, {
        title: "Server Voice Controls",
        okText: t("dialog.confirm.ok", "Confirm"),
        cancelText: t("dialog.confirm.cancel", "Cancel"),
        danger: true,
      });
      if (!ok) return;
      await sendServerVoiceModerationSignal({
        conversationId: convId,
        targetUserId: uid,
        action: "disconnect",
      }).catch(() => {});

      const banRes = await banServerMemberFromServer(sid, uid, { reason: "voice_mod_menu" });
      if (!banRes?.ok) {
        alert(`Erro ao banir membro: ${banRes?.error?.message || "falha desconhecida"}`);
        return;
      }

      applyLocalServerVoiceMemberRemoval(convId, uid);
      await refreshServerMemberModerationUi(sid);
      if (banRes?.banStored) {
        setCallStatus(`?? ${label} foi banido do server.`, true);
      } else {
        setCallStatus(`?? ${label} foi removido do server (ban sem tabela persistente).`, true);
      }
      setTimeout(() => {
        if (inCall) setCallStatus("", false);
      }, 1900);
    }
  } finally {
    serverVoiceMemberMenuBusy = false;
  }
}

function ensureServerVoiceMemberMenu() {
  let menu = document.getElementById("serverVoiceMemberMenu");
  if (!menu) {
    menu = document.createElement("div");
    menu.id = "serverVoiceMemberMenu";
    menu.className = "msgMenu msgMenu--server-voice";
    document.body.appendChild(menu);
  }
  menu.classList.add("msgMenu--server-voice");

  if (serverVoiceMemberMenuBound) return menu;
  serverVoiceMemberMenuBound = true;

  document.addEventListener("pointerdown", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    if (!menu.classList.contains("is-open")) return;
    if (target.closest("#serverVoiceMemberMenu")) return;
    const pointerType = String(e?.pointerType || "").trim().toLowerCase();
    const shouldCloseFromPointer = e?.button === 0 || pointerType === "touch" || pointerType === "pen";
    if (!shouldCloseFromPointer) return;
    closeServerVoiceMemberMenu();
  }, true);
  window.addEventListener("resize", closeServerVoiceMemberMenu);
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeServerVoiceMemberMenu();
  });

  menu.addEventListener("pointerdown", (e) => {
    e.stopPropagation();
  });

  menu.addEventListener("pointerenter", () => {
    serverVoiceMemberMenuHovering = true;
  });

  menu.addEventListener("pointerleave", () => {
    serverVoiceMemberMenuHovering = false;
  });

  menu.addEventListener("focusin", () => {
    serverVoiceMemberMenuHovering = true;
  });

  menu.addEventListener("focusout", () => {
    const activeEl = document.activeElement;
    serverVoiceMemberMenuHovering = !!(activeEl instanceof HTMLElement && menu.contains(activeEl));
  });

  menu.addEventListener("click", async (e) => {
    e.stopPropagation();
    const target = eventTargetElement(e);
    if (!target) return;
    const actionBtn = target.closest("[data-server-voice-member-act]");
    if (!actionBtn || actionBtn.disabled) return;
    e.preventDefault();
    const action = String(actionBtn.getAttribute("data-server-voice-member-act") || "").trim().toLowerCase();
    const context = serverVoiceMemberMenuTarget;
    closeServerVoiceMemberMenu({ force: true });
    await runServerVoiceMemberMenuAction(action, context);
  });

  menu.addEventListener("contextmenu", (e) => {
    e.preventDefault();
    e.stopPropagation();
  });

  menu.addEventListener("input", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const slider = target.closest("[data-server-voice-member-volume-slider=\"1\"]");
    if (!slider) return;
    const uid = normId(slider.getAttribute("data-server-voice-member-id") || "");
    if (!uid) return;
    const rawPct = Number(slider.value);
    const safePct = Math.max(0, Math.min(200, Number.isFinite(rawPct) ? rawPct : 100));
    const nextFactor = clampUserVoiceVolume(safePct / 100);
    const ctx = serverVoiceMemberMenuTarget || {};
    setRemoteUserVoiceVolume(uid, nextFactor, true, {
      tileId: String(ctx.tileId || buildStageParticipantTileId(uid, "primary")).trim(),
      tileType: normalizeStageTileType(ctx.tileType || "primary"),
      isLocalUser: !!ctx.isSelf,
      triggerReason: "server_voice_member_menu_volume_slider",
      callerFunction: "ensureServerVoiceMemberMenu.input",
    });
    const valueEl = menu.querySelector(`[data-server-voice-member-volume-value="${uid}"]`);
    if (valueEl) valueEl.textContent = `${Math.round(nextFactor * 100)}%`;
  });

  menu.addEventListener("change", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const toggle = target.closest("[data-server-voice-member-playback-mute-toggle=\"1\"]");
    if (!toggle) return;
    const uid = normId(toggle.getAttribute("data-server-voice-member-id") || "");
    if (!uid) return;
    const nextMuted = !!toggle.checked;
    const ctx = serverVoiceMemberMenuTarget || {};
    setRemoteUserVoiceMuted(uid, nextMuted, true, {
      tileId: String(ctx.tileId || buildStageParticipantTileId(uid, "primary")).trim(),
      tileType: normalizeStageTileType(ctx.tileType || "primary"),
      isLocalUser: !!ctx.isSelf,
      triggerReason: "server_voice_member_menu_playback_mute_toggle",
      callerFunction: "ensureServerVoiceMemberMenu.change",
    });
    const valueEl = menu.querySelector(`[data-server-voice-member-playback-mute-value="${uid}"]`);
    if (valueEl) valueEl.textContent = nextMuted ? "Muted" : "Unmuted";
  });

  return menu;
}

function openServerVoiceMemberMenuAt(context, point) {
  const ctx = context || null;
  if (!ctx || !point) return false;
  const uid = normId(ctx.targetUserId || "");
  const convId = normId(ctx.conversationId || "");
  if (!uid || !convId) return false;

  closeMessageMenu();
  closeCallAudioMenu();
  closeDmListMenus();

  const menu = ensureServerVoiceMemberMenu();
  const displayName = normalizeConversationLabel(ctx.targetDisplayName || "member", "member");
  const selfControlsEnabled = !!ctx.isSelf;
  const canAct = !!ctx.canModerate && !ctx.isSelf;
  const canDisconnect = selfControlsEnabled ? true : !!ctx.canDisconnect;
  const canMuteMic = selfControlsEnabled ? true : !!ctx.canMuteMic;
  const canDeafen = selfControlsEnabled ? true : !!ctx.canDeafen;
  const canKick = !!ctx.canKick && !ctx.isSelf;
  const canBan = !!ctx.canBan && !ctx.isSelf;
  const roleText = normalizeServerMemberRoleValue(ctx.targetRole || "member");
  const roleLabel = roleText === "owner" ? "Owner" : roleText === "admin" ? "Admin" : "Member";
  const micActionLabel = ctx.micMuted ? "Unmute Microphone" : "Mute Microphone";
  const deafenActionLabel = ctx.deafened ? "Unmute Headphones" : "Mute Headphones";
  const micStateOn = !ctx.micMuted;
  const deafenStateOn = !ctx.deafened;
  const userVoicePct = Math.round(clampUserVoiceVolume(getRemoteUserVoiceVolume(uid)) * 100);
  const playbackMuted = !!getRemoteUserVoiceMuted(uid);
  const disabledHint = ctx.isSelf
    ? ""
    : (canAct ? "" : "Sem permissÃµes para moderar este membro.");

  menu.innerHTML = [
    `<div class="msgMenu__meta">${esc(displayName)} â€¢ ${esc(roleLabel)}</div>`,
    `<div class="serverVoiceMemberMenuVolume" data-server-voice-member-volume-wrap="1">
      <div class="serverVoiceMemberMenuVolume__head">
        <span>User Volume</span>
        <span class="serverVoiceMemberMenuVolume__value" data-server-voice-member-volume-value="${escAttr(uid)}">${userVoicePct}%</span>
      </div>
      <input
        class="serverVoiceMemberMenuVolume__slider"
        type="range"
        min="0"
        max="200"
        step="1"
        value="${userVoicePct}"
        data-server-voice-member-volume-slider="1"
        data-server-voice-member-id="${escAttr(uid)}"
      />
      <label class="serverVoiceMemberMenuVolume__toggle">
        <input
          type="checkbox"
          data-server-voice-member-playback-mute-toggle="1"
          data-server-voice-member-id="${escAttr(uid)}"
          ${playbackMuted ? "checked" : ""}
        />
        <span>Mute User Audio</span>
        <span class="serverVoiceMemberMenuVolume__value" data-server-voice-member-playback-mute-value="${escAttr(uid)}">${playbackMuted ? "Muted" : "Unmuted"}</span>
      </label>
    </div>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item${canDisconnect ? "" : " is-disabled"}" data-server-voice-member-act="disconnect" ${canDisconnect ? "" : "disabled"}><span>Disconnect From Call</span></button>`,
    `<button class="msgMenu__item${canMuteMic ? "" : " is-disabled"}" data-server-voice-member-act="toggle_mic" ${canMuteMic ? "" : "disabled"}><span>${esc(micActionLabel)}</span><span class="serverVoiceMemberMenu__state${micStateOn ? " is-on" : " is-off"}">${micStateOn ? "ON" : "OFF"}</span></button>`,
    `<button class="msgMenu__item${canDeafen ? "" : " is-disabled"}" data-server-voice-member-act="toggle_deafen" ${canDeafen ? "" : "disabled"}><span>${esc(deafenActionLabel)}</span><span class="serverVoiceMemberMenu__state${deafenStateOn ? " is-on" : " is-off"}">${deafenStateOn ? "ON" : "OFF"}</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item msgMenu__item--danger${canKick ? "" : " is-disabled"}" data-server-voice-member-act="kick" ${canKick ? "" : "disabled"}><span>Kick From Server</span></button>`,
    `<button class="msgMenu__item msgMenu__item--danger${canBan ? "" : " is-disabled"}" data-server-voice-member-act="ban" ${canBan ? "" : "disabled"}><span>Ban From Server</span></button>`,
    disabledHint ? `<div class="msgMenu__meta">${esc(disabledHint)}</div>` : "",
  ].join("");

  menu.classList.add("is-open");
  serverVoiceMemberMenuTarget = { ...ctx };
  positionMenuAtPoint(menu, point, { width: 262, minHeight: 230 });
  logStageMediaUiEvent("context_menu.opened", {
    tileId: String(ctx.tileId || buildStageParticipantTileId(uid, "primary")).trim(),
    tileType: normalizeStageTileType(ctx.tileType || "primary"),
    participantId: uid,
    mediaType: normalizeStageContextMediaType(ctx.mediaType || "voice", ctx.tileType || "primary"),
    isLocalUser: !!ctx.isLocalUser,
    persistedKey: buildRemoteVoicePersistedKey(uid, "volume"),
    triggerReason: "server_voice_member_menu",
    callerFunction: "openServerVoiceMemberMenuAt",
  });
  return true;
}

function tryOpenServerVoiceMemberMenuAt(userId, conversationId, point, {
  displayName = "",
  serverId = "",
  tileId = "",
  tileType = "primary",
  mediaType = "voice",
  isLocalUser = false,
} = {}) {
  const uid = normId(userId || "");
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  if (!uid || !convId || !point) return false;
  if (!isServerVoiceConversationById(convId)) return false;
  const context = getServerVoiceMemberModerationContext({
    userId: uid,
    conversationId: convId,
    serverId,
    displayName,
  });
  if (!context) return false;
  return openServerVoiceMemberMenuAt({
    ...context,
    tileId: String(tileId || buildStageParticipantTileId(uid, tileType)).trim(),
    tileType: normalizeStageTileType(tileType || "primary"),
    mediaType: normalizeStageContextMediaType(mediaType, tileType),
    isLocalUser: !!isLocalUser,
  }, point);
}

function renderServerInviteModalState({ busy = false, statusText = "" } = {}) {
  const linkInput = document.getElementById("serverInviteLinkInput");
  const metaEl = document.getElementById("serverInviteMeta");
  const btnCopy = document.getElementById("btnServerInviteCopy");
  const btnConfirm = document.getElementById("btnServerInviteConfirm");
  const expireSelect = document.getElementById("serverInviteExpireSelect");
  const maxUsesSelect = document.getElementById("serverInviteMaxUsesSelect");
  const settingsSummaryEl = document.getElementById("serverInviteSettingsSummary");
  const host = String(window.location?.hostname || "").trim().toLowerCase();
  const isLocalHost = host === "127.0.0.1" || host === "localhost";
  const isDesktopLink = String(serverInviteLinkUrl || "").trim().toLowerCase().startsWith("altara://");
  const settingsSummary = formatServerInviteSettingsSummary(serverInviteExpiresHours, serverInviteMaxUses);

  if (linkInput) linkInput.value = serverInviteLinkUrl || "";
  if (expireSelect) expireSelect.value = String(normalizeServerInviteExpiresHours(serverInviteExpiresHours));
  if (maxUsesSelect) maxUsesSelect.value = String(normalizeServerInviteMaxUses(serverInviteMaxUses));
  if (settingsSummaryEl) settingsSummaryEl.textContent = settingsSummary;
  if (metaEl) {
    if (statusText) metaEl.textContent = statusText;
    else if (serverInviteSettingsDirty) metaEl.textContent = serverInviteLinkUrl
      ? `Updating link to ${settingsSummary}. The current visible link is outdated until the new one finishes generating.`
      : `Settings changed to ${settingsSummary}. Generating a fresh link now.`;
    else if (serverInviteLinkUrl) metaEl.textContent = isDesktopLink
      ? `Invite link ready. ${settingsSummary}. Share this Altara link. It opens the app directly on computers with Altara installed.`
      : isLocalHost
      ? `Invite link ready. ${settingsSummary}. On 127.0.0.1/localhost, only users who can open this address can join.`
      : `Invite link ready. ${settingsSummary}. Share this link in DM or anywhere else. Whoever opens it can join.`;
    else metaEl.textContent = "Generate a new link to invite people to this server.";
  }
  if (btnCopy) btnCopy.disabled = busy || !serverInviteLinkUrl || serverInviteSettingsDirty;
  if (btnConfirm) {
    btnConfirm.disabled = busy || !normId(serverInviteServerId || "");
    btnConfirm.textContent = busy
      ? "Generating..."
      : serverInviteSettingsDirty
      ? "Generate Updated Link"
      : (serverInviteLinkUrl ? "Generate New Link" : "Generate Link");
  }
  renderServerInviteFriendsList();
}

function closeServerInviteModal() {
  const modal = document.getElementById("serverInviteModal");
  if (!modal || modal.classList.contains("hidden")) return;
  serverInviteServerId = "";
  serverInviteExpiresHours = SERVER_INVITE_DEFAULT_EXPIRE_HOURS;
  serverInviteMaxUses = SERVER_INVITE_DEFAULT_MAX_USES;
  resetServerInviteGeneratedLink();
  serverInviteFriendSearch = "";
  serverInviteBusyUserId = "";
  serverInviteLastInvitedUserId = "";
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");
}

async function openServerInviteModal(serverCtx = null) {
  const ctx = serverCtx || getActiveServerContext();
  const sid = normId(ctx?.serverId || "");
  if (!sid) return;

  const caps = getServerCapabilityMeta(sid);
  if (!caps.canInvite) {
    alert("Sem permissao para criar convites para este server.");
    return;
  }

  const modal = document.getElementById("serverInviteModal");
  const subEl = document.getElementById("serverInviteSub");
  const linkInput = document.getElementById("serverInviteLinkInput");
  const searchInput = document.getElementById("serverInviteFriendSearch");
  if (!modal || !subEl || !linkInput) return;

  serverInviteServerId = sid;
  serverInviteExpiresHours = SERVER_INVITE_DEFAULT_EXPIRE_HOURS;
  serverInviteMaxUses = SERVER_INVITE_DEFAULT_MAX_USES;
  resetServerInviteGeneratedLink();
  serverInviteFriendSearch = "";
  serverInviteBusyUserId = "";
  serverInviteLastInvitedUserId = "";
  subEl.textContent = `Create and share a link for ${normalizeConversationLabel(ctx?.name || "Server", "Server")}.`;
  if (searchInput) searchInput.value = "";
  await fetchServerMembersForSidebar(sid, { force: true }).catch(() => {});
  renderServerInviteModalState({ busy: true, statusText: "Generating invite link..." });

  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  requestAnimationFrame(() => linkInput.focus());

  await submitServerInviteModal();
}

async function copyServerInviteLinkFromModal() {
  const link = String(serverInviteLinkUrl || "").trim();
  if (!link) return;
  const copied = await copyTextWithPromptFallback(link, "Invite Link");
  renderServerInviteModalState({
    busy: false,
    statusText: copied ? "Invite link copied." : "Copy failed. Copy manually from the field.",
  });
}

async function submitServerDirectInvite(userId) {
  const sid = normId(serverInviteServerId || "");
  const uid = normId(userId || "");
  if (!sid || !uid) return;
  if (serverInviteBusyUserId) return;

  const friend = getFriendRowByUserId(uid) || {};
  const targetLabel = normalizeConversationLabel(friend?.display_name || friend?.username || "friend", "friend");

  serverInviteBusyUserId = uid;
  serverInviteLastInvitedUserId = "";
  renderServerInviteModalState({ busy: false, statusText: `Preparing invite for ${targetLabel}...` });

  const inviteReady = await ensureServerInviteLinkReady({ silent: true });
  if (!inviteReady?.ok) {
    serverInviteBusyUserId = "";
    const errText = String(inviteReady?.error?.message || "Failed to generate invite link.");
    renderServerInviteModalState({ busy: false, statusText: `Invite failed: ${errText}` });
    alert(`Erro ao criar link de convite: ${errText}`);
    return;
  }

  renderServerInviteModalState({ busy: false, statusText: `Sending invite link to ${targetLabel}...` });
  const dmRes = await ensureDmConversationWithFriendUser(uid);
  serverInviteBusyUserId = "";
  if (dmRes?.error || !dmRes?.conversationId) {
    const errText = String(dmRes?.error?.message || "Failed to open DM.");
    renderServerInviteModalState({ busy: false, statusText: `Invite failed: ${errText}` });
    alert(`Erro ao abrir DM: ${errText}`);
    return;
  }

  const sendRes = await sendPlainTextMessageToConversation(dmRes.conversationId, inviteReady.inviteUrl);
  if (!sendRes?.ok) {
    const errText = isMessageSendRateLimitError(sendRes?.error)
      ? buildMessageSendRateLimitWarning(getMessageSendRateLimitRetryAfterSeconds(sendRes?.error))
      : String(sendRes?.error?.message || "Failed to send invite link.");
    renderServerInviteModalState({ busy: false, statusText: `Invite failed: ${errText}` });
    alert(isMessageSendRateLimitError(sendRes?.error) ? errText : `Erro ao enviar link: ${errText}`);
    return;
  }

  serverInviteLastInvitedUserId = uid;
  touchDmActivity(uid, { at: Date.now(), unread: false });
  clearDmUnreadForUser(uid);
  await loadGroupAndServerCollections({ force: true, hydrateGroupMetadata: false }).catch(() => {});
  await loadDmList().catch(() => {});
  renderGroupsRail();
  renderServerInviteModalState({ busy: false, statusText: `Invite link sent to ${targetLabel}. They can join when they click it.` });
}

async function submitServerInviteModal({ silent = false, force = false } = {}) {
  const inviteReady = await ensureServerInviteLinkReady({ silent, forceRefresh: force });
  if (!inviteReady?.ok) return;
  renderServerInviteModalState({
    busy: false,
    statusText: force ? "Updated invite link ready." : "Invite link ready.",
  });
}

async function joinServerFromInviteCode(code, {
  openConversation = true,
  showFeedback = true,
} = {}) {
  const inviteCode = extractServerInviteCodeFromText(code);
  if (!inviteCode) {
    if (showFeedback) alert("Codigo de convite invalido.");
    return { ok: false, error: { message: "codigo de convite invalido" } };
  }

  const { data, error } = await joinServerByInviteCodeRpc(inviteCode);
  if (error) {
    if (isMissingRpcError(error)) {
      if (showFeedback) alert("Falta SQL no Supabase: executa SQL/SUPABASE_PATCH_SERVER_INVITE_LINKS.sql");
      return { ok: false, error };
    }
    const emsg = String(error?.message || "").toLowerCase();
    if (emsg.includes("server_id") && emsg.includes("ambiguous")) {
      if (showFeedback) alert("Hotfix SQL em falta no Supabase. Executa SQL/SUPABASE_HOTFIX_SERVER_INVITE_AMBIGUOUS.sql e faz refresh.");
      return { ok: false, error };
    }
    if (showFeedback) alert(`Erro ao entrar no server: ${error.message}`);
    return { ok: false, error };
  }

  const row = Array.isArray(data) ? data[0] : data;
  const serverId = normId(row?.server_id || row?.id || "");
  const conversationId = normId(
    row?.default_conversation_id
    || row?.conversation_id
    || row?.channel_id
    || row?.default_channel_id
    || ""
  );
  const alreadyMember = !!(row?.already_member || row?.already_in_server);
  const serverName = normalizeConversationLabel(
    row?.server_name || row?.name || getServerRowById(serverId)?.name || "Server",
    "Server"
  );

  if (serverId) {
    serverMemberListByServerId.delete(serverId);
    serverChannelListByServerId.delete(serverId);
    serverChannelCategoryListByServerId.delete(serverId);
    serverChannelCategoryCollapsedByServerId.delete(serverId);
    serverRoleListByServerId.delete(serverId);
    serverRoleMemberMapByServerId.delete(serverId);
  }

  await loadGroupAndServerCollections({ force: true, hydrateGroupMetadata: true }).catch(() => {});
  await loadDmList().catch(() => {});
  renderGroupsRail();

  if (serverId && !alreadyMember) {
    await announceServerMembershipEvent(serverId, {
      event: "member_joined",
      actorName: getCurrentUserSystemDisplayName(),
      fallbackConversationId: conversationId,
    }).catch(() => {});
  }

  const conversationToOpen = serverId
    ? await resolveServerConversationForEntry(serverId, conversationId)
    : conversationId;

  if (openConversation && conversationToOpen) {
    await openConversationById(conversationToOpen, {
      kind: "server",
      isGroup: true,
      displayName: serverName,
      serverId,
      serverName,
      channelType: "text",
    }).catch(() => {});
  }

  if (showFeedback) {
    if (alreadyMember) alert(`Ja estavas no server ${serverName}.`);
    else alert(`Entraste no server ${serverName}.`);
  }
  return { ok: true, serverId, conversationId, alreadyMember };
}

async function consumeServerInviteFromUrlIfPresent({ showFeedback = false } = {}) {
  const code = readServerInviteCodeFromWindowLocation();
  if (!code) return false;
  clearServerInviteCodeFromWindowLocation();
  await joinServerFromInviteCode(code, { openConversation: true, showFeedback });
  return true;
}

function queueExternalServerInviteCode(rawValue = "") {
  const code = extractServerInviteCodeFromText(rawValue);
  if (!code) return "";
  if (pendingExternalServerInviteCode === code) return code;
  pendingExternalServerInviteCode = code;
  return code;
}

function extractAuthRedirectSuffixFromDeepLink(rawValue = "") {
  const raw = String(rawValue || "").trim();
  if (!raw) return "";
  try {
    const url = new URL(raw);
    if (String(url.protocol || "").trim().toLowerCase() !== "altara:") return "";

    const host = String(url.hostname || url.host || "").trim().toLowerCase();
    const segments = String(url.pathname || "")
      .split("/")
      .map((segment) => {
        try {
          return decodeURIComponent(String(segment || "").trim()).toLowerCase();
        } catch (_) {
          return String(segment || "").trim().toLowerCase();
        }
      })
      .filter(Boolean);
    const isRecoveryPath = (
      (host === "auth" && segments[0] === "recovery")
      || host === "recovery"
      || (segments[0] === "auth" && segments[1] === "recovery")
      || segments[0] === "recovery"
    );
    const isConfirmPath = (
      (host === "auth" && (segments[0] === "confirm" || segments[0] === "callback" || segments[0] === "verify"))
      || host === "confirm"
      || host === "callback"
      || (segments[0] === "auth" && (segments[1] === "confirm" || segments[1] === "callback" || segments[1] === "verify"))
      || segments[0] === "confirm"
      || segments[0] === "callback"
      || segments[0] === "verify"
    );

    const searchParams = new URLSearchParams(String(url.search || ""));
    const hashBody = String(url.hash || "").startsWith("#")
      ? String(url.hash || "").slice(1)
      : String(url.hash || "");
    const hashParams = new URLSearchParams(hashBody.startsWith("?") ? hashBody.slice(1) : hashBody);
    const hasAuthPayload = !!(
      searchParams.get("code")
      || searchParams.get("access_token")
      || searchParams.get("token_hash")
      || searchParams.get("token")
      || hashParams.get("code")
      || hashParams.get("access_token")
      || hashParams.get("token_hash")
      || hashParams.get("token")
      || String(searchParams.get("type") || "").trim().toLowerCase() === "recovery"
      || String(hashParams.get("type") || "").trim().toLowerCase() === "recovery"
    );
    const authType = String(searchParams.get("type") || hashParams.get("type") || "").trim().toLowerCase();
    const isConfirmType = (
      authType === "signup"
      || authType === "magiclink"
      || authType === "invite"
      || authType === "email"
      || authType === "email_change"
    );
    if (!hasAuthPayload) return "";
    if (!isRecoveryPath && !isConfirmPath && !isConfirmType && authType !== "recovery") return "";

    if (!searchParams.get("type") && !hashParams.get("type") && isRecoveryPath) {
      searchParams.set("type", "recovery");
    }
    const searchText = searchParams.toString();
    return `${searchText ? `?${searchText}` : ""}${url.hash || ""}`;
  } catch (_) {
    return "";
  }
}

async function consumeInitialDesktopDeepLinkIfPresent() {
  const bridge = getDesktopBridge();
  if (!bridge || typeof bridge.getPendingDeepLink !== "function") return false;
  try {
    const payload = await awaitWithTimeout(
      Promise.resolve(bridge.getPendingDeepLink()),
      2500,
      "desktop pending deep link"
    );
    const rawUrl = String(payload?.url || payload || "").trim();
    if (!rawUrl) return false;

    const recoverySuffix = extractAuthRedirectSuffixFromDeepLink(rawUrl);
    if (recoverySuffix) {
      try {
        window.location.replace(`./login.html${recoverySuffix}`);
      } catch (_) {}
      return true;
    }

    queueExternalServerInviteCode(rawUrl);
  } catch (_) {}
  return false;
}

async function consumePendingExternalServerInviteCodeIfPresent({ showFeedback = false } = {}) {
  const code = normalizeServerInviteCode(pendingExternalServerInviteCode);
  if (!code) return false;
  pendingExternalServerInviteCode = "";
  await joinServerFromInviteCode(code, { openConversation: true, showFeedback });
  return true;
}

function bindServerInviteDeepLinksOnce() {
  if (serverInviteDeepLinkBound) return;
  serverInviteDeepLinkBound = true;

  const bridge = getDesktopBridge();
  if (!bridge) return;

  const maybeConsume = async ({ showFeedback = true } = {}) => {
    if (!appBootCompleted || !state.user?.id) return false;
    return consumePendingExternalServerInviteCodeIfPresent({ showFeedback });
  };

  if (typeof bridge.onDeepLink === "function") {
    serverInviteDeepLinkUnsub = bridge.onDeepLink(async (payload) => {
      const rawUrl = String(payload?.url || payload || "").trim();
      const recoverySuffix = extractAuthRedirectSuffixFromDeepLink(rawUrl);
      if (recoverySuffix) {
        try {
          window.location.replace(`./login.html${recoverySuffix}`);
        } catch (_) {}
        return;
      }
      const queuedCode = queueExternalServerInviteCode(rawUrl);
      if (!queuedCode) return;
      await maybeConsume({ showFeedback: true });
    });
  }

  if (typeof bridge.getPendingDeepLink === "function") {
    Promise.resolve(bridge.getPendingDeepLink())
      .then(async (payload) => {
        const rawUrl = String(payload?.url || payload || "").trim();
        const recoverySuffix = extractAuthRedirectSuffixFromDeepLink(rawUrl);
        if (recoverySuffix) {
          try {
            window.location.replace(`./login.html${recoverySuffix}`);
          } catch (_) {}
          return;
        }
        const queuedCode = queueExternalServerInviteCode(rawUrl);
        if (!queuedCode) return;
        await maybeConsume({ showFeedback: true });
      })
      .catch(() => {});
  }
}

function bindServerInviteModalOnce() {
  if (serverInviteModalBound) return;
  serverInviteModalBound = true;

  const modal = document.getElementById("serverInviteModal");
  const linkInput = document.getElementById("serverInviteLinkInput");
  const expireSelect = document.getElementById("serverInviteExpireSelect");
  const maxUsesSelect = document.getElementById("serverInviteMaxUsesSelect");
  const searchInput = document.getElementById("serverInviteFriendSearch");
  const friendsList = document.getElementById("serverInviteFriendsList");
  const btnClose = document.getElementById("btnServerInviteClose");
  const btnCancel = document.getElementById("btnServerInviteCancel");
  const btnConfirm = document.getElementById("btnServerInviteConfirm");
  const btnCopy = document.getElementById("btnServerInviteCopy");

  btnClose?.addEventListener("click", closeServerInviteModal);
  btnCancel?.addEventListener("click", closeServerInviteModal);
  btnConfirm?.addEventListener("click", async () => {
    await submitServerInviteModal({ force: true });
  });
  btnCopy?.addEventListener("click", async () => {
    await copyServerInviteLinkFromModal();
  });

  linkInput?.addEventListener("focus", () => {
    try { linkInput.select(); } catch (_) {}
  });

  searchInput?.addEventListener("input", () => {
    serverInviteFriendSearch = String(searchInput.value || "").trim();
    renderServerInviteFriendsList();
  });

  expireSelect?.addEventListener("change", () => {
    serverInviteExpiresHours = normalizeServerInviteExpiresHours(expireSelect.value);
    serverInviteSettingsDirty = true;
    renderServerInviteModalState({ busy: true, statusText: "Updating invite link..." });
    void submitServerInviteModal({ silent: true, force: true });
  });

  maxUsesSelect?.addEventListener("change", () => {
    serverInviteMaxUses = normalizeServerInviteMaxUses(maxUsesSelect.value);
    serverInviteSettingsDirty = true;
    renderServerInviteModalState({ busy: true, statusText: "Updating invite link..." });
    void submitServerInviteModal({ silent: true, force: true });
  });

  friendsList?.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const btn = target.closest("[data-server-direct-invite]");
    if (!btn || btn.disabled) return;
    e.preventDefault();
    const uid = normId(btn.getAttribute("data-server-direct-invite") || "");
    if (!uid) return;
    await submitServerDirectInvite(uid);
  });

  modal?.addEventListener("click", (e) => {
    if (e.target?.dataset?.close) closeServerInviteModal();
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (!modal || modal.classList.contains("hidden")) return;
    e.preventDefault();
    closeServerInviteModal();
  });
}

function normalizeServerRoleRow(row = {}) {
  const roleId = normId(row?.id || row?.role_id || "");
  if (!roleId) return null;
  const roleName = normalizeServerRoleName(row?.name || "New role") || "New role";
  const roleColor = normalizeServerRoleColor(row?.color || row?.role_color || SERVER_ROLE_DEFAULT_COLOR);
  const rolePermissions = normalizeServerRolePermissions(row?.permissions || row?.role_permissions || row?.permission_flags || {});
  const positionRaw = Number(
    typeof row?.position !== "undefined" ? row.position : row?.role_position
  );
  const position = Number.isFinite(positionRaw) ? Math.round(positionRaw) : 0;
  const createdAt = Date.parse(String(row?.created_at || "")) || 0;
  return {
    id: roleId,
    name: roleName,
    color: roleColor,
    permissions: rolePermissions,
    position,
    createdAt,
  };
}

function normalizeServerRoleMemberRow(row = {}) {
  const roleId = normId(row?.role_id || row?.id || "");
  const userId = normId(row?.user_id || "");
  if (!roleId || !userId) return null;
  return {
    roleId,
    userId,
    assignedAt: Date.parse(String(row?.assigned_at || "")) || 0,
  };
}

function buildServerRoleMemberMap(rows = []) {
  const out = new Map();
  (rows || []).forEach((row) => {
    const normalized = normalizeServerRoleMemberRow(row);
    if (!normalized) return;
    if (!out.has(normalized.roleId)) out.set(normalized.roleId, new Set());
    out.get(normalized.roleId).add(normalized.userId);
  });
  return out;
}

function applyServerRoleMemberAssignment(serverId, roleId, userId, enabled) {
  const sid = normId(serverId);
  const rid = normId(roleId);
  const uid = normId(userId);
  if (!sid || !rid || !uid) return;
  if (!serverRoleMemberMapByServerId.has(sid)) {
    serverRoleMemberMapByServerId.set(sid, new Map());
  }
  const roleMap = serverRoleMemberMapByServerId.get(sid);
  if (!roleMap.has(rid)) roleMap.set(rid, new Set());
  const memberSet = roleMap.get(rid);
  if (enabled) {
    memberSet.add(uid);
  } else {
    memberSet.delete(uid);
  }
}

function applyServerRolePermissionsAssignment(serverId, roleId, permissions = {}) {
  const sid = normId(serverId);
  const rid = normId(roleId);
  if (!sid || !rid) return;
  const roleList = serverRoleListByServerId.get(sid) || [];
  const normalized = normalizeServerRolePermissions(permissions || {});
  const nextList = roleList.map((role) => {
    if (normId(role?.id || "") !== rid) return role;
    return {
      ...role,
      permissions: normalized,
    };
  });
  serverRoleListByServerId.set(sid, nextList);
}

async function ensureServerRolePermissionCache(serverId, { force = false } = {}) {
  const sid = normId(serverId);
  if (!sid) return { ok: false, error: { message: "server_id invalido" } };
  if (!force && serverRoleListByServerId.has(sid) && serverRoleMemberMapByServerId.has(sid)) {
    return { ok: true, error: null };
  }

  const [rolesRes, roleMembersRes] = await Promise.all([
    listServerRolesForServer(sid),
    listServerRoleMembersForServer(sid),
  ]);
  const loadError = rolesRes?.error || roleMembersRes?.error || null;
  if (loadError) return { ok: false, error: loadError };

  const roles = (rolesRes?.rows || [])
    .map(normalizeServerRoleRow)
    .filter(Boolean)
    .sort((a, b) => (
      Number(a.position || 0) - Number(b.position || 0)
        || Number(a.createdAt || 0) - Number(b.createdAt || 0)
        || String(a.name || "").localeCompare(String(b.name || ""))
    ));
  serverRoleListByServerId.set(sid, roles);
  serverRoleMemberMapByServerId.set(sid, buildServerRoleMemberMap(roleMembersRes?.rows || []));
  return { ok: true, error: null };
}

function getServerRolePermissionsForUser(serverId, userId, {
  members = null,
  roles = null,
  roleMemberMap = null,
} = {}) {
  const sid = normId(serverId);
  const uid = normId(userId);
  if (!sid || !uid) return normalizeServerRolePermissions({});

  const baseRole = getServerMemberRoleFromCache(sid, uid, { members });
  if (baseRole === "owner" || baseRole === "admin") {
    return normalizeServerRolePermissions(SERVER_ROLE_PERMISSION_PRESETS.staff || {});
  }

  const roleList = Array.isArray(roles) ? roles : (serverRoleListByServerId.get(sid) || []);
  const roleMap = roleMemberMap instanceof Map ? roleMemberMap : (serverRoleMemberMapByServerId.get(sid) || new Map());
  const merged = {};
  SERVER_ROLE_PERMISSION_KEYS.forEach((key) => { merged[key] = false; });

  roleList.forEach((role) => {
    const rid = normId(role?.id || "");
    if (!rid) return;
    const assignedSet = roleMap.get(rid);
    if (!(assignedSet instanceof Set) || !assignedSet.has(uid)) return;
    const flags = normalizeServerRolePermissions(role?.permissions || {});
    SERVER_ROLE_PERMISSION_KEYS.forEach((key) => {
      if (flags[key]) merged[key] = true;
    });
  });

  return normalizeServerRolePermissions(merged);
}

function canServerActorModerateTargetWithPermission({
  serverId = "",
  actorUserId = "",
  targetUserId = "",
  members = null,
  roles = null,
  roleMemberMap = null,
} = {}) {
  const sid = normId(serverId);
  const actorId = normId(actorUserId);
  const targetId = normId(targetUserId);
  const emptyFlags = normalizeServerRolePermissions({});
  if (!sid || !actorId || !targetId || actorId === targetId) {
    return {
      canTouchTarget: false,
      permissions: emptyFlags,
      actorRole: "member",
      targetRole: "member",
    };
  }

  const actorRole = getServerMemberRoleFromCache(sid, actorId, { members });
  const targetRole = getServerMemberRoleFromCache(sid, targetId, { members });
  const actorIsOwner = actorRole === "owner";
  const actorIsAdmin = actorRole === "admin" || actorIsOwner;

  const canTouchTarget = actorIsOwner
    ? targetRole !== "owner"
    : actorIsAdmin
      ? targetRole === "member"
      : targetRole === "member";

  const actorFlags = getServerRolePermissionsForUser(sid, actorId, {
    members,
    roles,
    roleMemberMap,
  });
  const permissions = normalizeServerRolePermissions({
    ...actorFlags,
    voice_disconnect_members: actorIsAdmin || !!actorFlags.voice_disconnect_members,
    voice_mute_microphone: actorIsAdmin || !!actorFlags.voice_mute_microphone,
    voice_deafen_members: actorIsAdmin || !!actorFlags.voice_deafen_members,
    server_kick_members: actorIsAdmin || !!actorFlags.server_kick_members,
    server_ban_members: actorIsAdmin || !!actorFlags.server_ban_members,
    view_all_channels: actorIsAdmin || !!actorFlags.view_all_channels,
  });

  return {
    canTouchTarget,
    permissions,
    actorRole,
    targetRole,
  };
}

function clearServerSettingsRolesState() {
  serverSettingsRoleSelectedId = "";
  serverSettingsRolesLoading = false;
  serverSettingsRolesMutating = false;
  serverSettingsRolePermissionsMutating = false;
  serverSettingsRoleCreatePreset = "custom";
  serverSettingsRolesMetaMessage = "";
  serverSettingsRolesMetaIsError = false;
  serverSettingsRoleMemberBusy.clear();
  const roleNameInput = document.getElementById("serverSettingsRoleName");
  const roleColorInput = document.getElementById("serverSettingsRoleColor");
  const rolePresetInput = document.getElementById("serverSettingsRolePreset");
  if (roleNameInput) roleNameInput.value = "";
  if (roleColorInput) roleColorInput.value = SERVER_ROLE_DEFAULT_COLOR;
  if (rolePresetInput) rolePresetInput.value = "custom";
}

function setServerSettingsRolesMeta(message = "", { error = false } = {}) {
  serverSettingsRolesMetaMessage = String(message || "").trim();
  serverSettingsRolesMetaIsError = !!(serverSettingsRolesMetaMessage && error);
}

function renderServerSettingsRolesUi() {
  const listEl = document.getElementById("serverSettingsRolesList");
  const membersEl = document.getElementById("serverSettingsRoleMembers");
  const metaEl = document.getElementById("serverSettingsRolesMeta");
  const createBtn = document.getElementById("btnServerSettingsRoleCreate");
  const roleNameInput = document.getElementById("serverSettingsRoleName");
  const roleColorInput = document.getElementById("serverSettingsRoleColor");
  const rolePresetInput = document.getElementById("serverSettingsRolePreset");
  const sid = normId(serverSettingsServerId || "");

  if (createBtn) {
    const createDisabled = !sid || serverSettingsRolesLoading || serverSettingsRolesMutating || serverSettingsRolePermissionsMutating;
    createBtn.disabled = createDisabled;
  }
  if (roleNameInput) {
    roleNameInput.disabled = !sid || serverSettingsRolesLoading || serverSettingsRolesMutating || serverSettingsRolePermissionsMutating;
  }
  if (roleColorInput) {
    roleColorInput.disabled = !sid || serverSettingsRolesLoading || serverSettingsRolesMutating || serverSettingsRolePermissionsMutating;
  }
  if (rolePresetInput) {
    rolePresetInput.disabled = !sid || serverSettingsRolesLoading || serverSettingsRolesMutating || serverSettingsRolePermissionsMutating;
    const safePreset = serverSettingsRoleCreatePreset === "staff" ? "staff" : "custom";
    if (rolePresetInput.value !== safePreset) rolePresetInput.value = safePreset;
  }

  if (!listEl || !membersEl || !metaEl) return;

  if (!sid) {
    listEl.innerHTML = `<div class="hint">Open a server to manage roles.</div>`;
    membersEl.innerHTML = `<div class="hint">Select a role to manage members.</div>`;
    metaEl.textContent = "Create custom roles and assign members.";
    metaEl.classList.remove("error");
    return;
  }

  const roleList = serverRoleListByServerId.get(sid) || [];
  const memberList = serverMemberListByServerId.get(sid) || [];
  const roleMemberMap = serverRoleMemberMapByServerId.get(sid) || new Map();

  if (!roleList.some((r) => r.id === serverSettingsRoleSelectedId)) {
    serverSettingsRoleSelectedId = roleList[0]?.id || "";
  }
  const selectedRole = roleList.find((r) => r.id === serverSettingsRoleSelectedId) || null;
  const selectedCount = selectedRole ? (roleMemberMap.get(selectedRole.id)?.size || 0) : 0;
  const fallbackMeta = serverSettingsRolesLoading
    ? "Loading roles..."
    : (roleList.length
      ? `${roleList.length} role${roleList.length === 1 ? "" : "s"} â€¢ ${selectedCount} member${selectedCount === 1 ? "" : "s"} selected`
      : "No custom roles yet.");
  const activeMeta = serverSettingsRolesMetaMessage || fallbackMeta;
  metaEl.textContent = activeMeta;
  metaEl.classList.toggle("error", !!(serverSettingsRolesMetaMessage && serverSettingsRolesMetaIsError));

  if (serverSettingsRolesLoading && !roleList.length) {
    listEl.innerHTML = `<div class="hint">Loading roles...</div>`;
    membersEl.innerHTML = `<div class="hint">Loading members...</div>`;
    return;
  }

  listEl.innerHTML = roleList.length
    ? roleList.map((role) => {
      const count = roleMemberMap.get(role.id)?.size || 0;
      const selected = role.id === serverSettingsRoleSelectedId;
      const permCount = countEnabledServerRolePermissions(role?.permissions || {});
      return `
        <div class="serverSettingsRoleRow">
          <button
            class="serverSettingsRolePick${selected ? " active" : ""}"
            type="button"
            data-server-settings-role-pick="${escAttr(role.id)}"
            title="${escAttr(role.name)}"
          >
            <span class="serverSettingsRoleSwatch" style="--role-color:${escAttr(role.color)}"></span>
            <span class="serverSettingsRoleName">${esc(role.name)}</span>
            <span class="serverSettingsRolePermsBadge" title="${permCount} permission${permCount === 1 ? "" : "s"}">${permCount}P</span>
            <span class="serverSettingsRoleCount">${count}</span>
          </button>
          <button
            class="btn ghost serverSettingsRoleDelete"
            type="button"
            data-server-settings-role-delete="${escAttr(role.id)}"
            ${serverSettingsRolesMutating ? "disabled" : ""}
          >Delete</button>
        </div>
      `;
    }).join("")
    : `<div class="hint">No custom roles yet. Create one above.</div>`;

  if (!selectedRole) {
    membersEl.innerHTML = roleList.length
      ? `<div class="hint">Select a role to assign members.</div>`
      : `<div class="hint">Create a role first, then assign members.</div>`;
    return;
  }

  if (!memberList.length) {
    membersEl.innerHTML = `<div class="hint">No members found in this server.</div>`;
    return;
  }

  const assignedSet = roleMemberMap.get(selectedRole.id) || new Set();
  const selectedRolePermissions = normalizeServerRolePermissions(selectedRole?.permissions || {});
  const permissionsBusy = !!(serverSettingsRolePermissionsMutating || serverSettingsRolesMutating);
  const permissionRowsHtml = SERVER_ROLE_PERMISSION_META.map((perm) => {
    const checked = !!selectedRolePermissions[perm.key];
    return `
      <label class="serverSettingsRolePermRow">
        <input
          type="checkbox"
          data-server-settings-role-perm-toggle="1"
          data-server-settings-role-id="${escAttr(selectedRole.id)}"
          data-server-settings-role-perm-key="${escAttr(perm.key)}"
          ${checked ? "checked" : ""}
          ${permissionsBusy ? "disabled" : ""}
        />
        <span class="serverSettingsRolePermText">
          <span class="serverSettingsRolePermName">${esc(perm.label)}</span>
          <span class="serverSettingsRolePermHint">${esc(perm.hint || "")}</span>
        </span>
      </label>
    `;
  }).join("");

  const memberRowsHtml = memberList.map((member) => {
    const userId = normId(member?.userId || "");
    const username = String(member?.username || "").trim();
    const displayName = String(member?.displayName || username || "Member").trim();
    const avatarUrl = String(member?.avatarUrl || "").trim();
    const busyKey = `${selectedRole.id}:${userId}`;
    const isBusy = serverSettingsRoleMemberBusy.has(busyKey) || serverSettingsRolesMutating || serverSettingsRolePermissionsMutating;
    const isChecked = assignedSet.has(userId);
    const baseRoleTag = member?.role === "owner"
      ? "OWNER"
      : (member?.role === "admin" ? "ADMIN" : "");
    return `
      <label class="serverSettingsRoleMemberRow">
        <input
          type="checkbox"
          data-server-settings-role-member-toggle="1"
          data-server-settings-role-id="${escAttr(selectedRole.id)}"
          data-server-settings-user-id="${escAttr(userId)}"
          ${isChecked ? "checked" : ""}
          ${isBusy ? "disabled" : ""}
        />
        <span class="serverSettingsRoleMemberAvatar">
          ${avatarUrl ? buildAvatarMediaHtml(avatarUrl, { userId, alt: "avatar" }) : `<span class="groupDmAvatarFallback">${esc(getGroupOrbFallbackChar(displayName, "U"))}</span>`}
        </span>
        <span class="serverSettingsRoleMemberText">
          <span class="serverSettingsRoleMemberName">${esc(displayName)}${member?.isMe ? " (You)" : ""}</span>
          <span class="serverSettingsRoleMemberMeta">@${esc(username || "user")}${baseRoleTag ? ` â€¢ ${esc(baseRoleTag)}` : ""}</span>
        </span>
      </label>
    `;
  }).join("");

  membersEl.innerHTML = `
    <div class="serverSettingsRolePermsPanel">
      <div class="serverSettingsRolePermsHead">
        <p class="serverSettingsRoleMembersHead">Permissions</p>
        <div class="serverSettingsRolePermsActions">
          <button
            class="btn ghost"
            type="button"
            data-server-settings-role-perm-preset="staff"
            data-server-settings-role-id="${escAttr(selectedRole.id)}"
            ${permissionsBusy ? "disabled" : ""}
          >Apply STAFF</button>
          <button
            class="btn ghost"
            type="button"
            data-server-settings-role-perm-preset="custom"
            data-server-settings-role-id="${escAttr(selectedRole.id)}"
            ${permissionsBusy ? "disabled" : ""}
          >Clear</button>
        </div>
      </div>
      ${permissionRowsHtml}
    </div>
    <div class="msgMenu__divider"></div>
    <p class="serverSettingsRoleMembersHead">${esc(selectedRole.name)} â€¢ ${assignedSet.size} member${assignedSet.size === 1 ? "" : "s"}</p>
    ${memberRowsHtml}
  `;
}

async function loadServerSettingsRolesForModal(serverId, { force = false } = {}) {
  const sid = normId(serverId);
  if (!sid) return;
  const isStillActive = () => normId(serverSettingsServerId || "") === sid;
  if (!isStillActive()) return;

  if (!force
      && serverRoleListByServerId.has(sid)
      && serverRoleMemberMapByServerId.has(sid)
      && serverMemberListByServerId.has(sid)) {
    renderServerSettingsRolesUi();
    return;
  }

  serverSettingsRolesLoading = true;
  setServerSettingsRolesMeta("", { error: false });
  renderServerSettingsRolesUi();

  let rolesRes = { rows: [], error: null };
  let roleMembersRes = { rows: [], error: null };
  try {
    [, rolesRes, roleMembersRes] = await Promise.all([
      fetchServerMembersForSidebar(sid, { force }),
      listServerRolesForServer(sid),
      listServerRoleMembersForServer(sid),
    ]);
  } catch (err) {
    rolesRes = { rows: [], error: err };
    roleMembersRes = { rows: [], error: null };
  }

  if (!isStillActive()) return;

  const roles = (rolesRes?.rows || [])
    .map(normalizeServerRoleRow)
    .filter(Boolean)
    .sort((a, b) => (
      Number(a.position || 0) - Number(b.position || 0)
        || Number(a.createdAt || 0) - Number(b.createdAt || 0)
        || String(a.name || "").localeCompare(String(b.name || ""))
    ));
  serverRoleListByServerId.set(sid, roles);
  serverRoleMemberMapByServerId.set(sid, buildServerRoleMemberMap(roleMembersRes?.rows || []));
  if (!roles.some((r) => r.id === serverSettingsRoleSelectedId)) {
    serverSettingsRoleSelectedId = roles[0]?.id || "";
  }

  serverSettingsRolesLoading = false;
  const loadError = rolesRes?.error || roleMembersRes?.error || null;
  if (loadError) {
    const missingSql = isMissingRpcError(loadError)
      || isMissingTableError(loadError, "server_roles")
      || isMissingTableError(loadError, "server_role_members");
    if (missingSql) {
      setServerSettingsRolesMeta("Missing SQL patch: run SQL/SUPABASE_PATCH_SERVER_ROLES.sql", { error: true });
    } else {
      setServerSettingsRolesMeta(`Failed to load roles: ${loadError.message || loadError}`, { error: true });
    }
  } else {
    setServerSettingsRolesMeta("", { error: false });
  }
  renderServerSettingsRolesUi();
}

async function submitServerSettingsRoleCreate() {
  const sid = normId(serverSettingsServerId || "");
  if (!sid || serverSettingsRolesMutating) return;
  const roleNameInput = document.getElementById("serverSettingsRoleName");
  const roleColorInput = document.getElementById("serverSettingsRoleColor");
  const rolePresetInput = document.getElementById("serverSettingsRolePreset");
  const roleName = normalizeServerRoleName(roleNameInput?.value || "");
  const roleColor = normalizeServerRoleColor(roleColorInput?.value || SERVER_ROLE_DEFAULT_COLOR);
  const presetName = String(rolePresetInput?.value || serverSettingsRoleCreatePreset || "custom").trim().toLowerCase();
  const rolePermissions = resolveServerRolePermissionPreset(presetName);
  if (!roleName) {
    setServerSettingsRolesMeta("Write a role name first.", { error: true });
    renderServerSettingsRolesUi();
    roleNameInput?.focus();
    return;
  }

  serverSettingsRolesMutating = true;
  setServerSettingsRolesMeta("Creating role...", { error: false });
  renderServerSettingsRolesUi();

  const { row, error, warning } = await createServerRoleForServer(sid, {
    name: roleName,
    color: roleColor,
    permissions: rolePermissions,
  });

  serverSettingsRolesMutating = false;
  if (normId(serverSettingsServerId || "") !== sid) return;
  if (error) {
    const missingSql = isMissingRpcError(error) || isMissingTableError(error, "server_roles");
    if (missingSql) {
      setServerSettingsRolesMeta("Missing SQL patch: run SQL/SUPABASE_PATCH_SERVER_ROLES.sql", { error: true });
    } else {
      setServerSettingsRolesMeta(`Failed to create role: ${error.message || error}`, { error: true });
    }
    renderServerSettingsRolesUi();
    return;
  }

  if (roleNameInput) roleNameInput.value = "";
  if (roleColorInput) roleColorInput.value = roleColor;
  if (rolePresetInput) rolePresetInput.value = serverSettingsRoleCreatePreset || "custom";
  serverSettingsRoleSelectedId = normId(row?.id || row?.role_id || "") || serverSettingsRoleSelectedId;

  await loadServerSettingsRolesForModal(sid, { force: true });
  if (normId(serverSettingsServerId || "") !== sid) return;
  const warnMissingPermPatch = !!(
    warning
    && (isMissingRpcError(warning) || isMissingColumnError(warning, "permissions") || isMissingTableError(warning, "server_roles"))
  );
  if (warnMissingPermPatch) {
    setServerSettingsRolesMeta(
      `Role "${roleName}" created, but permissions SQL patch is missing (run SQL/SUPABASE_PATCH_SERVER_ROLE_PERMISSIONS.sql).`,
      { error: true }
    );
  } else {
    setServerSettingsRolesMeta(`Role "${roleName}" created.`, { error: false });
  }
  renderServerSettingsRolesUi();
}

async function submitServerSettingsRoleDelete(roleId) {
  const sid = normId(serverSettingsServerId || "");
  const rid = normId(roleId);
  if (!sid || !rid || serverSettingsRolesMutating) return;
  const roleList = serverRoleListByServerId.get(sid) || [];
  const role = roleList.find((r) => r.id === rid) || null;
  const roleName = normalizeServerRoleName(role?.name || "Role") || "Role";
  const ok = await requestAppConfirm(`Delete role "${roleName}"?`, {
    title: "Server Roles",
    okText: t("dialog.confirm.ok", "Confirm"),
    cancelText: t("dialog.confirm.cancel", "Cancel"),
    danger: true,
  });
  if (!ok) return;

  serverSettingsRolesMutating = true;
  setServerSettingsRolesMeta("Deleting role...", { error: false });
  renderServerSettingsRolesUi();

  const { error } = await deleteServerRoleForServer(sid, rid);

  serverSettingsRolesMutating = false;
  if (normId(serverSettingsServerId || "") !== sid) return;
  if (error) {
    const missingSql = isMissingRpcError(error) || isMissingTableError(error, "server_roles");
    if (missingSql) {
      setServerSettingsRolesMeta("Missing SQL patch: run SQL/SUPABASE_PATCH_SERVER_ROLES.sql", { error: true });
    } else {
      setServerSettingsRolesMeta(`Failed to delete role: ${error.message || error}`, { error: true });
    }
    renderServerSettingsRolesUi();
    return;
  }

  if (serverSettingsRoleSelectedId === rid) serverSettingsRoleSelectedId = "";
  await loadServerSettingsRolesForModal(sid, { force: true });
  if (normId(serverSettingsServerId || "") !== sid) return;
  setServerSettingsRolesMeta(`Role "${roleName}" deleted.`, { error: false });
  renderServerSettingsRolesUi();
}

async function submitServerSettingsRolePermissionsSave(roleId, nextPermissions = {}) {
  const sid = normId(serverSettingsServerId || "");
  const rid = normId(roleId || "");
  if (!sid || !rid) return false;
  if (serverSettingsRolePermissionsMutating || serverSettingsRolesMutating) return false;

  const normalizedPermissions = normalizeServerRolePermissions(nextPermissions || {});
  serverSettingsRolePermissionsMutating = true;
  setServerSettingsRolesMeta("Saving role permissions...", { error: false });
  renderServerSettingsRolesUi();

  const { row, error } = await setServerRolePermissionsForServer(sid, {
    roleId: rid,
    permissions: normalizedPermissions,
  });

  serverSettingsRolePermissionsMutating = false;
  if (normId(serverSettingsServerId || "") !== sid) return false;
  if (error) {
    const missingSql = isMissingRpcError(error)
      || isMissingTableError(error, "server_roles")
      || isMissingColumnError(error, "permissions");
    if (missingSql) {
      setServerSettingsRolesMeta("Missing SQL patch: run SQL/SUPABASE_PATCH_SERVER_ROLE_PERMISSIONS.sql", { error: true });
    } else {
      setServerSettingsRolesMeta(`Failed to save role permissions: ${error.message || error}`, { error: true });
    }
    renderServerSettingsRolesUi();
    return false;
  }

  applyServerRolePermissionsAssignment(sid, rid, row?.permissions || normalizedPermissions);
  setServerSettingsRolesMeta("Role permissions updated.", { error: false });
  renderServerSettingsRolesUi();
  return true;
}

async function submitServerSettingsRolePermissionToggle(roleId, permissionKey, enabled) {
  const sid = normId(serverSettingsServerId || "");
  const rid = normId(roleId || "");
  const pKey = String(permissionKey || "").trim();
  if (!sid || !rid || !SERVER_ROLE_PERMISSION_KEYS.includes(pKey)) return;
  const roleList = serverRoleListByServerId.get(sid) || [];
  const role = roleList.find((entry) => normId(entry?.id || "") === rid) || null;
  if (!role) return;
  const nextPermissions = normalizeServerRolePermissions(role?.permissions || {});
  nextPermissions[pKey] = !!enabled;
  await submitServerSettingsRolePermissionsSave(rid, nextPermissions);
}

async function submitServerSettingsRolePermissionPreset(roleId, presetName) {
  const sid = normId(serverSettingsServerId || "");
  const rid = normId(roleId || "");
  if (!sid || !rid) return;
  const nextPermissions = resolveServerRolePermissionPreset(presetName || "custom");
  await submitServerSettingsRolePermissionsSave(rid, nextPermissions);
}

async function submitServerSettingsRoleMemberToggle(roleId, userId, enabled) {
  const sid = normId(serverSettingsServerId || "");
  const rid = normId(roleId);
  const uid = normId(userId);
  if (!sid || !rid || !uid) return;

  const busyKey = `${rid}:${uid}`;
  if (serverSettingsRoleMemberBusy.has(busyKey)) return;
  serverSettingsRoleMemberBusy.add(busyKey);
  renderServerSettingsRolesUi();

  const { error } = await setServerRoleMembershipForServer(sid, {
    roleId: rid,
    userId: uid,
    enabled: !!enabled,
  });

  serverSettingsRoleMemberBusy.delete(busyKey);
  if (normId(serverSettingsServerId || "") !== sid) return;
  if (error) {
    const missingSql = isMissingRpcError(error) || isMissingTableError(error, "server_role_members");
    if (missingSql) {
      setServerSettingsRolesMeta("Missing SQL patch: run SQL/SUPABASE_PATCH_SERVER_ROLES.sql", { error: true });
    } else {
      setServerSettingsRolesMeta(`Failed to update role: ${error.message || error}`, { error: true });
    }
    renderServerSettingsRolesUi();
    return;
  }

  applyServerRoleMemberAssignment(sid, rid, uid, !!enabled);
  setServerSettingsRolesMeta("", { error: false });
  renderServerSettingsRolesUi();
}

function renderServerSettingsIconPreview() {
  const previewBtn = document.getElementById("serverSettingsIconPreview");
  const nameInput = document.getElementById("serverSettingsName");
  const label = normalizeConversationLabel(String(nameInput?.value || "").trim(), "Server");
  const effectiveIcon = serverSettingsIconPreviewUrl || (serverSettingsIconRemoved ? "" : serverSettingsIconUrl);
  setServerCreateIconPreviewButton(previewBtn, { iconUrl: effectiveIcon, label });
}

function closeServerSettingsModal() {
  const modal = document.getElementById("serverSettingsModal");
  if (!modal || modal.classList.contains("hidden")) return;
  serverSettingsServerId = "";
  serverSettingsName = "";
  serverSettingsIconUrl = "";
  serverSettingsWelcomeChannelId = "";
  serverSettingsIconRemoved = false;
  clearServerSettingsIconDraft();
  clearServerSettingsRolesState();
  renderServerSettingsRolesUi();
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");
}

async function openServerSettingsModal(serverCtx = null) {
  const ctx = serverCtx || getActiveServerContext();
  const sid = normId(ctx?.serverId || "");
  if (!sid) return;

  const caps = getServerCapabilityMeta(sid);
  if (!caps.canSettings) {
    alert("Sem permissao para configurar este server.");
    return;
  }

  const modal = document.getElementById("serverSettingsModal");
  const nameInput = document.getElementById("serverSettingsName");
  const subEl = document.getElementById("serverSettingsSub");
  if (!modal || !nameInput || !subEl) return;

  const row = getServerRowById(sid);
  const serverName = normalizeConversationLabel(ctx?.name || row?.name || "Server", "Server");
  const serverIcon = String(row?.iconUrl || ctx?.iconUrl || "").trim();

  serverSettingsServerId = sid;
  serverSettingsName = serverName;
  serverSettingsIconUrl = serverIcon;
  // Keep current explicit selection only; real fallback is resolved against server default channel.
  serverSettingsWelcomeChannelId = normId(row?.welcomeConversationId || "");
  serverSettingsIconRemoved = false;
  clearServerSettingsIconDraft();
  clearServerSettingsRolesState();
  serverSettingsRolesLoading = true;
  setServerSettingsRolesMeta("", { error: false });

  nameInput.value = serverName;
  subEl.textContent = `Editing ${serverName}.`;
  renderServerSettingsIconPreview();
  renderServerSettingsRolesUi();

  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  requestAnimationFrame(() => {
    const bodyEl = modal.querySelector(".serverCreateBody");
    if (bodyEl) bodyEl.scrollTop = 0;
    nameInput.focus();
  });
  void renderServerSettingsWelcomeChannelOptions(sid);
  void loadServerSettingsRolesForModal(sid, { force: true });
}

async function deleteServerChannelById(serverId, {
  channelId = "",
  conversationId = "",
  channelName = "channel",
  channelType = "text",
  skipConfirm = false,
} = {}) {
  const sid = normId(serverId || "");
  let cid = normId(channelId || "");
  const convId = normId(conversationId || "");
  if (!sid || (!cid && !convId)) return;

  const caps = getServerCapabilityMeta(sid);
  if (!caps.canSettings) {
    alert("Sem permissao para apagar canais neste server.");
    return;
  }

  if (!cid && convId) {
    try {
      const lookup = await supabase
        .from("server_channels")
        .select("id")
        .eq("server_id", sid)
        .eq("conversation_id", convId)
        .maybeSingle();
      if (!lookup?.error) cid = normId(lookup?.data?.id || "");
    } catch (_) {}
  }

  const safeName = normalizeConversationLabel(
    channelName || (String(channelType || "").trim().toLowerCase() === "voice" ? "voice-lounge" : "general"),
    String(channelType || "").trim().toLowerCase() === "voice" ? "voice-lounge" : "general"
  );

  if (!skipConfirm) {
    const ok = await requestAppConfirm(`Delete channel "${safeName}"?`, {
      title: "Server Channels",
      okText: t("dialog.confirm.ok", "Confirm"),
      cancelText: t("dialog.confirm.cancel", "Cancel"),
      danger: true,
    });
    if (!ok) return;
  }

  let rpcError = null;
  if (cid) {
    const rpcRes = await deleteServerChannelRpc(sid, cid);
    rpcError = rpcRes?.error || null;
  } else {
    rpcError = { message: "channel_id em falta para RPC" };
  }

  let deletedViaDirectFallback = false;
  if (rpcError && isMissingRpcError(rpcError)) {
    let deleteQuery = supabase
      .from("server_channels")
      .delete()
      .eq("server_id", sid);
    if (cid) deleteQuery = deleteQuery.eq("id", cid);
    else if (convId) deleteQuery = deleteQuery.eq("conversation_id", convId);
    const delRes = await deleteQuery;
    if (delRes?.error) {
      alert(`Erro ao apagar canal: ${delRes.error?.message || delRes.error}`);
      return;
    }
    deletedViaDirectFallback = true;
  } else if (rpcError) {
    alert(`Erro ao apagar canal: ${rpcError.message || rpcError}`);
    return;
  }

  if (deletedViaDirectFallback && convId) {
    try { await supabase.from("messages").delete().eq("conversation_id", convId); } catch (_) {}
    try { await supabase.from("conversation_members").delete().eq("conversation_id", convId); } catch (_) {}
    try { await supabase.from("conversations").delete().eq("id", convId); } catch (_) {}
  }

  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  const wasActiveDeletedChannel = !!convId && activeConvId === convId;

  if (convId) {
    dmUnreadByConversationId.delete(convId);
    persistDmUnreadConversationsToStorage();
    serverConversationMemberIdsByConversationId.delete(convId);
    if (normId(callConversationId || "") === convId && inCall) {
      await hangupCurrentCallByUser("?? This channel was deleted.");
    }
  }

  serverChannelListByServerId.delete(sid);
  serverChannelCategoryListByServerId.delete(sid);
  await refreshServerConversationUi({ force: true }).catch(() => {});

  if (wasActiveDeletedChannel) {
    const channels = await fetchServerChannelsForSidebar(sid, { force: true }).catch(() => []);
    const nextChannel = (channels || []).find((ch) => normalizeConversationChannelType(ch?.channelType || "") !== "voice")
      || (channels || [])[0]
      || null;
    const serverRow = getServerRowById(sid);
    const serverName = normalizeConversationLabel(serverRow?.name || state.activeDm?.serverName || "Server", "Server");
    const serverIcon = String(serverRow?.iconUrl || "").trim();

    if (nextChannel?.conversationId) {
      const nextType = normalizeConversationChannelType(nextChannel?.channelType || "text");
      await openConversationById(nextChannel.conversationId, {
        kind: "server",
        isGroup: true,
        displayName: normalizeConversationLabel(
          nextChannel.name || (nextType === "voice" ? "voice-lounge" : "general"),
          nextType === "voice" ? "voice-lounge" : "general"
        ),
        serverId: sid,
        serverName,
        avatarUrl: serverIcon,
        channelType: nextType,
      });
    } else {
      activeDmId = null;
      state.activeDm = null;
      setMidMode("friends");
      syncDmActiveListHighlight();
      renderGroupsRail();
      setRightSidebarToServerMembers({ active: false });
    }
  }
}

async function deleteServerChannelCategoryById(serverId, {
  categoryId = "",
  categoryName = "Category",
  skipConfirm = false,
} = {}) {
  const sid = normId(serverId || "");
  const cid = normId(categoryId || "");
  if (!sid || !cid) return;

  const caps = getServerCapabilityMeta(sid);
  if (!caps.canSettings) {
    alert("Sem permissao para apagar categorias neste server.");
    return;
  }

  const safeName = normalizeServerCategoryName(categoryName || "Category", "Category");
  if (!skipConfirm) {
    const ok = await requestAppConfirm(`Delete category "${safeName}"? Channels inside will move to "No Category".`, {
      title: "Server Channels",
      okText: t("dialog.confirm.ok", "Confirm"),
      cancelText: t("dialog.confirm.cancel", "Cancel"),
      danger: true,
    });
    if (!ok) return;
  }

  const rpcRes = await deleteServerChannelCategoryRpc(sid, cid);
  const rpcError = rpcRes?.error || null;
  if (rpcError && !isMissingRpcError(rpcError)) {
    alert(`Erro ao apagar categoria: ${rpcError.message || rpcError}`);
    return;
  }

  if (rpcError && isMissingRpcError(rpcError)) {
    const fallback = await supabase
      .from("server_channel_categories")
      .delete()
      .eq("id", cid)
      .eq("server_id", sid);
    if (fallback?.error) {
      alert(`Erro ao apagar categoria: ${fallback.error?.message || fallback.error}`);
      return;
    }
  }

  const collapsed = serverChannelCategoryCollapsedByServerId.get(sid);
  if (collapsed instanceof Set) collapsed.delete(cid);
  serverChannelCategoryListByServerId.delete(sid);
  serverChannelListByServerId.delete(sid);
  await refreshServerConversationUi({ force: true }).catch(() => {});
}

async function deleteServerById(serverId, { serverName = "Server" } = {}) {
  const sid = normId(serverId);
  if (!sid) return;
  const caps = getServerCapabilityMeta(sid);
  if (!caps.canDelete) {
    alert("So o dono do server pode apagar.");
    return;
  }

  const safeName = normalizeConversationLabel(serverName, "Server");
  const ok = await requestAppConfirm(`Apagar o server "${safeName}"?\n\nIsto remove canais e mensagens desse server.`, {
    title: "Server Settings",
    okText: t("dialog.confirm.ok", "Confirm"),
    cancelText: t("dialog.confirm.cancel", "Cancel"),
    danger: true,
  });
  if (!ok) return;

  const { error } = await deleteServerRpc(sid);
  if (error) {
    if (isMissingRpcError(error)) {
      alert("Falta SQL no Supabase: executa SQL/SUPABASE_PATCH_SERVER_MANAGEMENT.sql");
      return;
    }
    alert(`Erro ao apagar server: ${error.message}`);
    return;
  }

  const wasActiveServer = normId(state.activeDm?.serverId || "") === sid;
  forgetServerLastChannel(sid, { persist: true });
  serverChannelListByServerId.delete(sid);
  serverChannelCategoryListByServerId.delete(sid);
  serverChannelCategoryCollapsedByServerId.delete(sid);
  serverMemberListByServerId.delete(sid);
  serverRoleListByServerId.delete(sid);
  serverRoleMemberMapByServerId.delete(sid);
  await refresh();

  if (wasActiveServer) {
    activeDmId = null;
    setMidMode("friends");
    syncDmActiveListHighlight();
    renderGroupsRail();
    setRightSidebarToServerMembers({ active: false });
  }
}

async function leaveServerById(serverId, { serverName = "Server" } = {}) {
  const sid = normId(serverId);
  if (!sid) return;

  const caps = getServerCapabilityMeta(sid);
  if (!caps.canLeave) {
    if (caps.isOwner) {
      alert("O dono nao pode sair. Apaga o server ou transfere ownership.");
    } else {
      alert("Sem permissao para sair deste server.");
    }
    return;
  }

  const safeName = normalizeConversationLabel(serverName, "Server");
  const ok = await requestAppConfirm(`Sair do server "${safeName}"?`, {
    title: "Server Settings",
    okText: t("dialog.confirm.ok", "Confirm"),
    cancelText: t("dialog.confirm.cancel", "Cancel"),
  });
  if (!ok) return;

  let leaveSystemMessageId = "";
  const leaveEventRes = await announceServerMembershipEvent(sid, {
    event: "member_left",
    actorName: getCurrentUserSystemDisplayName(),
    fallbackConversationId: normId(getServerRowById(sid)?.defaultConversationId || ""),
  }).catch(() => ({ ok: false }));
  if (leaveEventRes?.ok) {
    leaveSystemMessageId = normId(leaveEventRes.messageId || "");
  }

  const { error } = await leaveServerRpc(sid);
  if (error) {
    if (leaveSystemMessageId) {
      try {
        await supabase
          .from("messages")
          .delete()
          .eq("id", leaveSystemMessageId)
          .eq("user_id", state.user?.id || "");
      } catch (_) {}
    }
    const msg = String(error?.message || "").toLowerCase();
    if (isMissingRpcError(error)) {
      alert("Falta SQL no Supabase: executa SQL/SUPABASE_PATCH_SERVER_INVITE_LINKS.sql");
      return;
    }
    if (msg.includes("owner_must_delete_server") || msg.includes("dono") || msg.includes("owner")) {
      alert("O dono nao pode sair. Apaga o server ou transfere ownership.");
      return;
    }
    alert(`Erro ao sair do server: ${error.message}`);
    return;
  }

  const wasActiveServer = normId(state.activeDm?.serverId || "") === sid;
  forgetServerLastChannel(sid, { persist: true });
  serverChannelListByServerId.delete(sid);
  serverChannelCategoryListByServerId.delete(sid);
  serverChannelCategoryCollapsedByServerId.delete(sid);
  serverMemberListByServerId.delete(sid);
  serverRoleListByServerId.delete(sid);
  serverRoleMemberMapByServerId.delete(sid);
  await refresh();

  if (wasActiveServer) {
    activeDmId = null;
    state.activeDm = null;
    setMidMode("friends");
    syncDmActiveListHighlight();
    renderGroupsRail();
    setRightSidebarToServerMembers({ active: false });
  }
}

async function submitServerSettingsModal() {
  const sid = normId(serverSettingsServerId || "");
  if (!sid) {
    await requestAppAlert("Nao consegui identificar o server. Fecha e abre as definicoes novamente.", {
      title: "Server Settings",
      okText: "OK",
    });
    return false;
  }

  const nameInput = document.getElementById("serverSettingsName");
  const welcomeSelect = document.getElementById("serverSettingsWelcomeChannel");
  const saveBtn = document.getElementById("btnServerSettingsSave");
  const saveBtnPrevText = String(saveBtn?.textContent || "Save");
  if (saveBtn) {
    saveBtn.disabled = true;
    saveBtn.textContent = "Saving...";
  }

  try {
    const nextName = normalizeConversationLabel(String(nameInput?.value || "").trim(), "Server");
    if (!nextName) {
      await requestAppAlert("Escreve um nome valido para o server.", {
        title: "Server Settings",
        okText: "OK",
      });
      return false;
    }

    let nextIcon = serverSettingsIconRemoved ? "" : String(serverSettingsIconUrl || "").trim();
    if (serverSettingsIconFile) {
      try {
        nextIcon = await uploadServerIconFile(serverSettingsIconFile, { serverId: sid });
      } catch (err) {
        await requestAppAlert(`Falhou upload do icon: ${err?.message || err}`, {
          title: "Server Settings",
          okText: "OK",
        });
        return false;
      }
    }
    nextIcon = sanitizeServerIconUrl(nextIcon);

    let nextWelcomeChannelId = normId(
      welcomeSelect?.value
      || serverSettingsWelcomeChannelId
      || ""
    );
    // Empty means "use default server chat".
    serverSettingsWelcomeChannelId = nextWelcomeChannelId;

    let saveError = null;
    const rpcRes = await updateServerProfileRpc(sid, { name: nextName, iconUrl: nextIcon });
    if (rpcRes?.error && !isMissingRpcError(rpcRes.error)) {
      saveError = rpcRes.error;
    } else if (rpcRes?.error && isMissingRpcError(rpcRes.error)) {
      const payload = { name: nextName, icon_url: nextIcon || null };
      const { error } = await supabase.from("servers").update(payload).eq("id", sid);
      saveError = error || null;
    }

    if (saveError) {
      await requestAppAlert(`Erro ao guardar server: ${saveError.message || saveError}`, {
        title: "Server Settings",
        okText: "OK",
      });
      return false;
    }

  const welcomeSave = await saveServerWelcomeChannelToTable(sid, nextWelcomeChannelId || "");
  if (!welcomeSave?.ok) {
    if (welcomeSave?.needsPatch) {
      await requestAppAlert(
        `Falta SQL no Supabase (proj: ${getSupabaseProjectRefLabel()}): executa SQL/SUPABASE_PATCH_SERVER_WELCOME_CHANNEL.sql`,
        {
          title: "Server Settings",
          okText: "OK",
        }
      );
    } else {
      await requestAppAlert(
        `Server guardado, mas falhou guardar o canal de bem-vindo: ${welcomeSave?.error?.message || welcomeSave?.error || "erro desconhecido"}`,
        { title: "Server Settings", okText: "OK" }
      );
    }
    return false;
  }

  const postCheck = await readServerWelcomeChannelFromTable(sid).catch(() => null);
  const postSavedId = normId(postCheck?.welcomeConversationId || "");
  if (postSavedId !== normId(nextWelcomeChannelId || "")) {
    await requestAppAlert(
      `Server guardado, mas o canal de bem-vindo nao persistiu (proj: ${getSupabaseProjectRefLabel()}).`,
      {
        title: "Server Settings",
        okText: "OK",
      }
    );
    return false;
  }

  const row = getServerRowById(sid);
  if (row) row.welcomeConversationId = normId(welcomeSave?.value || nextWelcomeChannelId || "");

    closeServerSettingsModal();
    serverChannelListByServerId.delete(sid);
    serverChannelCategoryListByServerId.delete(sid);
    await loadGroupAndServerCollections({ force: true, hydrateGroupMetadata: true }).catch(() => {});
    renderGroupsRail();
    await refreshServerConversationUi({ force: true }).catch(() => {});
    await loadDmList().catch(() => {});
    return true;
  } catch (err) {
    await requestAppAlert(`Falhou ao guardar server settings: ${err?.message || err}`, {
      title: "Server Settings",
      okText: "OK",
    });
    return false;
  } finally {
    if (saveBtn) {
      saveBtn.disabled = false;
      saveBtn.textContent = saveBtnPrevText;
    }
  }
}

function bindServerSettingsModalOnce() {
  if (serverSettingsModalBound) return;
  serverSettingsModalBound = true;

  const modal = document.getElementById("serverSettingsModal");
  const nameInput = document.getElementById("serverSettingsName");
  const iconInput = document.getElementById("serverSettingsIconFile");
  const iconPreview = document.getElementById("serverSettingsIconPreview");
  const btnIconPick = document.getElementById("btnServerSettingsIconPick");
  const btnIconClear = document.getElementById("btnServerSettingsIconClear");
  const btnClose = document.getElementById("btnServerSettingsClose");
  const btnCancel = document.getElementById("btnServerSettingsCancel");
  const btnSave = document.getElementById("btnServerSettingsSave");
  const welcomeSelect = document.getElementById("serverSettingsWelcomeChannel");
  const roleNameInput = document.getElementById("serverSettingsRoleName");
  const rolePresetInput = document.getElementById("serverSettingsRolePreset");
  const btnRoleCreate = document.getElementById("btnServerSettingsRoleCreate");
  const roleList = document.getElementById("serverSettingsRolesList");
  const roleMembers = document.getElementById("serverSettingsRoleMembers");

  btnClose?.addEventListener("click", closeServerSettingsModal);
  btnCancel?.addEventListener("click", closeServerSettingsModal);
  btnSave?.addEventListener("click", async () => {
    await submitServerSettingsModal();
  });

  modal?.addEventListener("click", (e) => {
    if (e.target?.dataset?.close) closeServerSettingsModal();
  });

  nameInput?.addEventListener("input", () => {
    serverSettingsName = normalizeConversationLabel(String(nameInput.value || "").trim(), "Server");
    renderServerSettingsIconPreview();
  });
  welcomeSelect?.addEventListener("change", () => {
    serverSettingsWelcomeChannelId = normId(welcomeSelect.value || "");
  });

  btnRoleCreate?.addEventListener("click", async () => {
    await submitServerSettingsRoleCreate();
  });

  rolePresetInput?.addEventListener("change", () => {
    const next = String(rolePresetInput.value || "custom").trim().toLowerCase();
    serverSettingsRoleCreatePreset = next === "staff" ? "staff" : "custom";
  });

  roleNameInput?.addEventListener("keydown", async (e) => {
    if (e.key !== "Enter") return;
    e.preventDefault();
    await submitServerSettingsRoleCreate();
  });

  roleList?.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const pickBtn = target.closest("[data-server-settings-role-pick]");
    if (pickBtn) {
      e.preventDefault();
      const rid = normId(pickBtn.getAttribute("data-server-settings-role-pick") || "");
      if (!rid) return;
      serverSettingsRoleSelectedId = rid;
      setServerSettingsRolesMeta("", { error: false });
      renderServerSettingsRolesUi();
      return;
    }
    const deleteBtn = target.closest("[data-server-settings-role-delete]");
    if (deleteBtn) {
      e.preventDefault();
      const rid = normId(deleteBtn.getAttribute("data-server-settings-role-delete") || "");
      if (!rid) return;
      await submitServerSettingsRoleDelete(rid);
    }
  });

  roleMembers?.addEventListener("change", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const permCheckbox = target.closest("[data-server-settings-role-perm-toggle=\"1\"]");
    if (permCheckbox) {
      const rid = normId(permCheckbox.getAttribute("data-server-settings-role-id") || "");
      const pKey = String(permCheckbox.getAttribute("data-server-settings-role-perm-key") || "").trim();
      if (!rid || !pKey) return;
      await submitServerSettingsRolePermissionToggle(rid, pKey, !!permCheckbox.checked);
      return;
    }
    const checkbox = target.closest("[data-server-settings-role-member-toggle=\"1\"]");
    if (!checkbox) return;
    const rid = normId(checkbox.getAttribute("data-server-settings-role-id") || "");
    const uid = normId(checkbox.getAttribute("data-server-settings-user-id") || "");
    if (!rid || !uid) return;
    await submitServerSettingsRoleMemberToggle(rid, uid, !!checkbox.checked);
  });

  roleMembers?.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const presetBtn = target.closest("[data-server-settings-role-perm-preset]");
    if (!presetBtn || presetBtn.disabled) return;
    e.preventDefault();
    const rid = normId(presetBtn.getAttribute("data-server-settings-role-id") || "");
    const presetName = String(presetBtn.getAttribute("data-server-settings-role-perm-preset") || "custom").trim().toLowerCase();
    if (!rid) return;
    await submitServerSettingsRolePermissionPreset(rid, presetName);
  });

  const openPicker = () => iconInput?.click();
  iconPreview?.addEventListener("click", openPicker);
  btnIconPick?.addEventListener("click", openPicker);
  btnIconClear?.addEventListener("click", () => {
    serverSettingsIconRemoved = true;
    clearServerSettingsIconDraft();
    renderServerSettingsIconPreview();
  });

  iconInput?.addEventListener("change", () => {
    const file = iconInput?.files?.[0] || null;
    if (!file) {
      clearServerSettingsIconDraft();
      renderServerSettingsIconPreview();
      return;
    }
    const contentType = String(file.type || "").toLowerCase();
    if (!contentType.startsWith("image/")) {
      alert("Escolhe uma imagem para o icon do server.");
      clearServerSettingsIconDraft();
      renderServerSettingsIconPreview();
      return;
    }
    if (Number(file.size || 0) > SERVER_ICON_MAX_BYTES) {
      alert("Icon do server demasiado grande (max 8MB).");
      clearServerSettingsIconDraft();
      renderServerSettingsIconPreview();
      return;
    }
    if (serverSettingsIconPreviewUrl) safeRevokeObjectUrl(serverSettingsIconPreviewUrl);
    serverSettingsIconFile = file;
    serverSettingsIconPreviewUrl = URL.createObjectURL(file);
    serverSettingsIconRemoved = false;
    renderServerSettingsIconPreview();
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (!modal || modal.classList.contains("hidden")) return;
    e.preventDefault();
    closeServerSettingsModal();
  });

  renderServerSettingsRolesUi();
}

function getActiveServerContext() {
  const activeConversationId = normId(activeDmId || "");
  if (!activeConversationId) return null;

  const activeKind = String(state.activeDm?.kind || "").trim().toLowerCase();
  if (activeKind !== "server") return null;

  const directServerId = normId(state.activeDm?.serverId || "");
  let serverRow = null;
  if (directServerId) {
    serverRow = (state.servers || []).find((s) => normId(s?.serverId || "") === directServerId) || null;
  }
  if (!serverRow) {
    serverRow = (state.servers || []).find((s) => normId(s?.defaultConversationId || "") === activeConversationId) || null;
  }

  const serverId = normId(serverRow?.serverId || directServerId);
  if (!serverId) return null;

  const name = normalizeConversationLabel(
    serverRow?.name || state.activeDm?.serverName || state.activeDm?.displayName || "Server",
    "Server"
  );

  return {
    serverId,
    name,
    iconUrl: String(serverRow?.iconUrl || "").trim(),
    ownerUserId: normId(serverRow?.ownerUserId || ""),
    defaultConversationId: normId(serverRow?.defaultConversationId || activeConversationId),
    memberCount: Number(serverRow?.memberCount || state.activeDm?.memberCount || 0),
  };
}

async function queryServerChannelsWithFallbacks(buildQuery, {
  single = false,
} = {}) {
  const variants = [
    {
      select: "id, server_id, conversation_id, name, position, created_at, channel_type, category_id, is_private, user_limit, media_mode",
      hasChannelTypeColumn: true,
      hasCategoryIdColumn: true,
      hasIsPrivateColumn: true,
      hasUserLimitColumn: true,
      hasMediaModeColumn: true,
    },
    {
      select: "id, server_id, conversation_id, name, position, created_at, channel_type, category_id, is_private",
      hasChannelTypeColumn: true,
      hasCategoryIdColumn: true,
      hasIsPrivateColumn: true,
      hasUserLimitColumn: false,
      hasMediaModeColumn: false,
    },
    {
      select: "id, server_id, conversation_id, name, position, created_at, channel_type, category_id",
      hasChannelTypeColumn: true,
      hasCategoryIdColumn: true,
      hasIsPrivateColumn: false,
      hasUserLimitColumn: false,
      hasMediaModeColumn: false,
    },
    {
      select: "id, server_id, conversation_id, name, position, created_at, channel_type, is_private",
      hasChannelTypeColumn: true,
      hasCategoryIdColumn: false,
      hasIsPrivateColumn: true,
      hasUserLimitColumn: false,
      hasMediaModeColumn: false,
    },
    {
      select: "id, server_id, conversation_id, name, position, created_at, channel_type",
      hasChannelTypeColumn: true,
      hasCategoryIdColumn: false,
      hasIsPrivateColumn: false,
      hasUserLimitColumn: false,
      hasMediaModeColumn: false,
    },
    {
      select: "id, server_id, conversation_id, name, position, created_at",
      hasChannelTypeColumn: false,
      hasCategoryIdColumn: false,
      hasIsPrivateColumn: false,
      hasUserLimitColumn: false,
      hasMediaModeColumn: false,
    },
  ];

  let lastError = null;
  for (const variant of variants) {
    try {
      let query = buildQuery(variant.select);
      if (single) query = query.maybeSingle();
      const result = await query;
      if (!result?.error) {
        return {
          data: result?.data ?? (single ? null : []),
          error: null,
          ...variant,
        };
      }
      lastError = result.error;
      const missingSchemaColumn = isMissingColumnError(lastError, "channel_type")
        || isMissingColumnError(lastError, "category_id")
        || isMissingColumnError(lastError, "is_private")
        || isMissingColumnError(lastError, "user_limit")
        || isMissingColumnError(lastError, "media_mode");
      if (!missingSchemaColumn) break;
    } catch (e) {
      lastError = e;
      const missingSchemaColumn = isMissingColumnError(lastError, "channel_type")
        || isMissingColumnError(lastError, "category_id")
        || isMissingColumnError(lastError, "is_private")
        || isMissingColumnError(lastError, "user_limit")
        || isMissingColumnError(lastError, "media_mode");
      if (!missingSchemaColumn) break;
    }
  }

  return {
    data: single ? null : [],
    error: lastError,
    hasChannelTypeColumn: false,
    hasCategoryIdColumn: false,
    hasIsPrivateColumn: false,
    hasUserLimitColumn: false,
    hasMediaModeColumn: false,
  };
}

function normalizeServerChannelSidebarRow(row, serverId, {
  hasChannelTypeColumn = true,
  hasCategoryIdColumn = true,
  hasIsPrivateColumn = true,
  hasUserLimitColumn = true,
  hasMediaModeColumn = true,
} = {}) {
  const sid = normId(serverId || row?.server_id || row?.serverId || "");
  const conversationId = normId(row?.conversation_id || row?.conversationId || "");
  if (!sid || !conversationId) return null;
  const rawType = hasChannelTypeColumn
    ? (row?.channel_type || row?.channelType || "")
    : (row?.channelType || "");
  const channelType = String(rawType || "").trim().toLowerCase() === "voice" ? "voice" : "text";
  const defaultName = channelType === "voice" ? "voice-lounge" : "general";
  const rawPrivate = hasIsPrivateColumn ? (row?.is_private ?? row?.isPrivate ?? false) : (row?.isPrivate ?? false);
  const rawUserLimit = hasUserLimitColumn ? (row?.user_limit ?? row?.userLimit ?? 0) : (row?.userLimit ?? 0);
  const rawMediaMode = hasMediaModeColumn ? (row?.media_mode || row?.mediaMode || "audio_only") : (row?.mediaMode || "audio_only");
  return {
    id: normId(row?.id || ""),
    serverId: sid,
    conversationId,
    name: normalizeConversationLabel(row?.name || defaultName, defaultName),
    channelType,
    categoryId: hasCategoryIdColumn ? normId(row?.category_id || row?.categoryId || "") : normId(row?.categoryId || ""),
    position: Number(row?.position || 0),
    createdAt: Date.parse(String(row?.created_at || row?.createdAt || "")) || Number(row?.createdAt || 0) || 0,
    isPrivate: rawPrivate === true || String(rawPrivate || "").trim().toLowerCase() === "true",
    userLimit: channelType === "voice" ? clampServerVoiceUserLimit(rawUserLimit, 0) : 0,
    mediaMode: channelType === "voice" ? normalizeServerVoiceMediaMode(rawMediaMode, "audio_only") : "audio_only",
  };
}

async function resolveServerChannelForServer(serverId, {
  channelId = "",
  conversationId = "",
} = {}) {
  const sid = normId(serverId || "");
  const cid = normId(channelId || "");
  const convId = normId(conversationId || "");
  if (!sid || (!cid && !convId)) return null;

  const fromCache = (serverChannelListByServerId.get(sid) || []).find((row) => (
    (cid && normId(row?.id || "") === cid)
    || (convId && normId(row?.conversationId || "") === convId)
  )) || null;
  if (fromCache) return fromCache;

  const fetched = await fetchServerChannelsForSidebar(sid, { force: false }).catch(() => []);
  const fromFetched = (fetched || []).find((row) => (
    (cid && normId(row?.id || "") === cid)
    || (convId && normId(row?.conversationId || "") === convId)
  )) || null;
  if (fromFetched) return fromFetched;

  const queryRes = await queryServerChannelsWithFallbacks((select) => {
    let query = supabase
      .from("server_channels")
      .select(select)
      .eq("server_id", sid);
    if (cid) query = query.eq("id", cid);
    else query = query.eq("conversation_id", convId);
    return query;
  }, { single: true });

  if (queryRes?.error || !queryRes?.data) return null;
  return normalizeServerChannelSidebarRow(queryRes.data, sid, queryRes);
}

async function fetchServerChannelsForSidebar(serverId, { force = false } = {}) {
  const sid = normId(serverId);
  if (!sid) return [];
  if (!force && serverChannelListByServerId.has(sid)) {
    return serverChannelListByServerId.get(sid) || [];
  }

  let rows = [];
  const queryRes = await queryServerChannelsWithFallbacks((select) => (
    supabase
      .from("server_channels")
      .select(select)
      .eq("server_id", sid)
      .order("position", { ascending: true })
      .order("created_at", { ascending: true })
  ));
  if (queryRes?.error) {
    console.warn("server channels list failed", queryRes.error);
  } else {
    rows = Array.isArray(queryRes?.data) ? queryRes.data : [];
  }

  const normalized = rows
    .map((row) => normalizeServerChannelSidebarRow(row, sid, queryRes))
    .filter(Boolean);

  if (!normalized.length) {
    const fallbackRow = (state.servers || []).find((s) => normId(s?.serverId || "") === sid) || null;
    const fallbackConvId = normId(fallbackRow?.defaultConversationId || "");
    if (fallbackConvId) {
      normalized.push({
        id: "",
        serverId: sid,
        conversationId: fallbackConvId,
        name: "general",
        channelType: "text",
        categoryId: "",
        position: 0,
        createdAt: 0,
        isPrivate: false,
        userLimit: 0,
        mediaMode: "audio_only",
      });
    }
  }

  normalized.sort((a, b) => (
    Number(a.position || 0) - Number(b.position || 0)
      || Number(a.createdAt || 0) - Number(b.createdAt || 0)
      || String(a.name || "").localeCompare(String(b.name || ""))
  ));

  const rememberedConvId = getRememberedServerLastChannel(sid);
  if (rememberedConvId) {
    const stillExists = normalized.some((ch) => normId(ch?.conversationId || "") === rememberedConvId);
    if (!stillExists) forgetServerLastChannel(sid, { persist: true });
  }

  serverChannelListByServerId.set(sid, normalized);
  scheduleCallRealtimeSubscriptionSync(0);

  const matchedServerRow = (state.servers || []).find((s) => normId(s?.serverId || "") === sid) || null;
  const serverName = normalizeConversationLabel(
    matchedServerRow?.name || state.activeDm?.serverName || "Server",
    "Server"
  );
  const serverOwnerUserId = normId(matchedServerRow?.ownerUserId || "");
  normalized.forEach((ch) => {
    setConversationMeta(ch.conversationId, {
      kind: "server",
      isGroup: true,
      displayName: normalizeConversationLabel(ch.name, "general"),
      serverId: sid,
      serverName,
      ownerUserId: serverOwnerUserId,
      avatarUrl: String(matchedServerRow?.iconUrl || "").trim(),
      channelType: ch.channelType || "text",
      userLimit: clampServerVoiceUserLimit(ch?.userLimit ?? 0, 0),
      mediaMode: normalizeServerVoiceMediaMode(ch?.mediaMode || "audio_only", "audio_only"),
    });
  });

  return normalized;
}

async function fetchServerChannelCategoriesForSidebar(serverId, { force = false } = {}) {
  const sid = normId(serverId || "");
  if (!sid) return [];
  if (!force && serverChannelCategoryListByServerId.has(sid)) {
    return serverChannelCategoryListByServerId.get(sid) || [];
  }

  let rows = [];
  try {
    const { data, error } = await supabase
      .from("server_channel_categories")
      .select("id, server_id, name, position, created_at")
      .eq("server_id", sid)
      .order("position", { ascending: true })
      .order("created_at", { ascending: true });
    if (error) {
      const missingTable = isMissingTableError(error, "server_channel_categories");
      if (!missingTable) {
        console.warn("server channel categories list failed", error);
      }
    } else {
      rows = Array.isArray(data) ? data : [];
    }
  } catch (e) {
    console.warn("server channel categories list failed", e);
  }

  const normalized = (rows || []).map((row) => {
    const id = normId(row?.id || "");
    if (!id) return null;
    return {
      id,
      serverId: sid,
      name: normalizeServerCategoryName(row?.name || "Category"),
      position: Number(row?.position || 0),
      createdAt: Date.parse(String(row?.created_at || "")) || 0,
    };
  }).filter(Boolean);

  normalized.sort((a, b) => (
    Number(a.position || 0) - Number(b.position || 0)
      || Number(a.createdAt || 0) - Number(b.createdAt || 0)
      || String(a.name || "").localeCompare(String(b.name || ""))
  ));

  serverChannelCategoryListByServerId.set(sid, normalized);
  return normalized;
}

async function fetchServerMembersForSidebar(serverId, { force = false } = {}) {
  const sid = normId(serverId);
  if (!sid) return [];
  if (!force && serverMemberListByServerId.has(sid)) {
    return serverMemberListByServerId.get(sid) || [];
  }

  let rows = [];
  let usedEmbeddedProfiles = false;
  try {
    const { data, error } = await supabase
      .from("server_members")
      .select("user_id, role, joined_at, profiles:user_id(id, username, display_name, avatar_url, name_color)")
      .eq("server_id", sid)
      .order("joined_at", { ascending: true });
    if (!error && Array.isArray(data)) {
      rows = data;
      usedEmbeddedProfiles = true;
    }
  } catch (_) {}

  if (!rows.length) {
    try {
      const { data, error } = await supabase
        .from("server_members")
        .select("user_id, role, joined_at")
        .eq("server_id", sid)
        .order("joined_at", { ascending: true });
      if (error) {
        console.warn("server members list failed", error);
      } else {
        rows = Array.isArray(data) ? data : [];
      }
    } catch (e) {
      console.warn("server members list failed", e);
    }
  }

  const memberIds = normalizeUuidArray(rows.map((row) => normId(row?.user_id || "")));
  let profileRows = [];
  if (memberIds.length) {
    try {
      profileRows = await fetchProfilesByIds(memberIds, { includeBio: false, force: false });
    } catch (_) {
      profileRows = [];
    }
  }
  const profileById = new Map();
  (profileRows || []).forEach((p) => {
    const uid = normId(p?.id || "");
    if (!uid) return;
    profileById.set(uid, p);
  });

  const meId = normId(state.user?.id || "");
  const roleOrder = { owner: 0, admin: 1, member: 2 };
  const members = rows.map((row) => {
    const uid = normId(row?.user_id || "");
    if (!uid) return null;
    const embedded = usedEmbeddedProfiles && row?.profiles && typeof row.profiles === "object"
      ? row.profiles
      : null;
    const profile = profileById.get(uid) || embedded || {};
    const role = String(row?.role || "member").trim().toLowerCase();
    return {
      userId: uid,
      role: role === "owner" || role === "admin" ? role : "member",
      joinedAt: Date.parse(String(row?.joined_at || "")) || 0,
      username: String(profile?.username || "").trim(),
      displayName: String(profile?.display_name || profile?.username || "").trim(),
      avatarUrl: String(profile?.avatar_url || "").trim(),
      nameColor: normalizeNameColor(profile?.name_color || ""),
      isMe: !!(meId && uid === meId),
    };
  }).filter(Boolean);

  members.sort((a, b) => {
    const roleDiff = (roleOrder[a.role] ?? 9) - (roleOrder[b.role] ?? 9);
    if (roleDiff) return roleDiff;
    const nameA = String(a.displayName || a.username || "").toLowerCase();
    const nameB = String(b.displayName || b.username || "").toLowerCase();
    if (nameA && nameB && nameA !== nameB) return nameA.localeCompare(nameB);
    return Number(a.joinedAt || 0) - Number(b.joinedAt || 0);
  });

  serverMemberListByServerId.set(sid, members);
  return members;
}

function getServerConversationMemberIdsCache(conversationId) {
  const convId = normId(conversationId || "");
  if (!convId) return [];
  return Array.isArray(serverConversationMemberIdsByConversationId.get(convId))
    ? serverConversationMemberIdsByConversationId.get(convId)
    : [];
}

async function resolveServerConversationAccessMeta(conversationId) {
  const convId = normId(conversationId || "");
  if (!convId) return null;

  const cachedCtx = findServerChannelContextByConversationId(convId);
  if (cachedCtx?.serverId) {
    return {
      serverId: normId(cachedCtx.serverId || ""),
      isPrivate: !!cachedCtx?.channel?.isPrivate,
    };
  }

  const queryRes = await queryServerChannelsWithFallbacks((select) => (
    supabase
      .from("server_channels")
      .select(select)
      .eq("conversation_id", convId)
  ), { single: true });
  if (queryRes?.error || !queryRes?.data) return null;

  const normalized = normalizeServerChannelSidebarRow(
    queryRes.data,
    queryRes.data?.server_id || queryRes.data?.serverId || "",
    queryRes
  );
  if (!normalized?.serverId) return null;

  return {
    serverId: normId(normalized.serverId || ""),
    isPrivate: !!normalized.isPrivate,
  };
}

async function confirmServerConversationAccessLoss(conversationId, {
  force = true,
} = {}) {
  const convId = normId(conversationId || "");
  const meId = normId(state.user?.id || "");
  const base = {
    conversationId: convId || null,
    userId: meId || null,
    serverId: null,
    isPrivate: null,
  };
  if (!convId || !meId) {
    return {
      ...base,
      confirmedLost: false,
      reason: "invalid_context",
    };
  }

  const accessMeta = await resolveServerConversationAccessMeta(convId).catch(() => null);
  const serverId = normId(accessMeta?.serverId || resolveCachedServerIdForConversation(convId) || "");
  const isPrivate = accessMeta?.isPrivate === true;
  const detailsBase = {
    ...base,
    serverId: serverId || null,
    isPrivate,
  };

  if (!serverId) {
    return {
      ...detailsBase,
      confirmedLost: false,
      reason: "server_context_missing",
    };
  }

  // Public server channels are governed by server_members, not conversation_members.
  // A conversation_members DELETE is not enough evidence to kick an active voice room.
  if (!isPrivate) {
    return {
      ...detailsBase,
      confirmedLost: false,
      reason: "public_channel_access_not_confirmed",
    };
  }

  let membershipRow = null;
  let membershipError = null;
  try {
    ({ data: membershipRow, error: membershipError } = await supabase
      .from("conversation_members")
      .select("user_id")
      .eq("conversation_id", convId)
      .eq("user_id", meId)
      .maybeSingle());
  } catch (error) {
    membershipError = error;
  }

  let visibleChannels = [];
  let visibilityError = null;
  try {
    visibleChannels = await fetchServerChannelsForSidebar(serverId, { force: !!force });
  } catch (error) {
    visibilityError = error;
  }

  const hasConversationMembership = membershipError
    ? null
    : !!normId(membershipRow?.user_id || "");
  const channelVisible = Array.isArray(visibleChannels)
    ? visibleChannels.some((channel) => normId(channel?.conversationId || "") === convId)
    : null;

  if (membershipError || visibilityError) {
    return {
      ...detailsBase,
      confirmedLost: false,
      reason: "private_channel_access_check_failed",
      hasConversationMembership,
      channelVisible,
      visibleChannelCount: Array.isArray(visibleChannels) ? visibleChannels.length : null,
      membershipCheckError: membershipError ? (membershipError?.message || String(membershipError)) : null,
      channelVisibilityError: visibilityError ? (visibilityError?.message || String(visibilityError)) : null,
    };
  }

  if (hasConversationMembership) {
    return {
      ...detailsBase,
      confirmedLost: false,
      reason: "private_channel_membership_still_present",
      hasConversationMembership,
      channelVisible,
      visibleChannelCount: visibleChannels.length,
    };
  }

  const confirmedLost = channelVisible === false;
  return {
    ...detailsBase,
    confirmedLost,
    reason: confirmedLost
      ? "private_channel_access_lost_confirmed"
      : "private_channel_visibility_still_present",
    hasConversationMembership,
    channelVisible,
    visibleChannelCount: visibleChannels.length,
  };
}

async function fetchServerConversationMemberIds(conversationId, { force = false } = {}) {
  const convId = normId(conversationId || "");
  if (!convId) return [];
  if (!force) {
    if (serverConversationMemberIdsByConversationId.has(convId)) {
      return getServerConversationMemberIdsCache(convId);
    }
  }

  const accessMeta = await resolveServerConversationAccessMeta(convId).catch(() => null);
  if (accessMeta?.serverId && !accessMeta.isPrivate) {
    const serverMembers = await fetchServerMembersForSidebar(accessMeta.serverId, { force }).catch(() => []);
    const memberIds = normalizeUuidArray(serverMembers.map((row) => normId(row?.userId || "")));
    serverConversationMemberIdsByConversationId.set(convId, memberIds);
    return memberIds;
  }

  const { data, error } = await supabase
    .from("conversation_members")
    .select("user_id")
    .eq("conversation_id", convId);

  if (error || !Array.isArray(data)) {
    if (error) console.warn("server conversation members fetch failed", error);
    return getServerConversationMemberIdsCache(convId);
  }

  const memberIds = normalizeUuidArray(data.map((row) => normId(row?.user_id || "")));
  serverConversationMemberIdsByConversationId.set(convId, memberIds);
  return memberIds;
}

function setRightSidebarToServerMembers({
  active = false,
  title = "Members",
  count = 0,
} = {}) {
  const forceHidden = !!(rightSidebarForceHiddenForServerVoiceStage && isServerConversationUiOpen());
  const showMembersPanel = !!(active && !forceHidden);
  const titleEl = document.querySelector(".rightTitleRow .hTitle");
  const countEl = document.getElementById("onlineCount");
  const membersPanel = document.getElementById("serverMembersPanel");
  const activeNowEl = document.getElementById("activeNow");
  const offlineListEl = document.getElementById("offlineList");
  const labels = Array.from(document.querySelectorAll(".rightBody .rightSectionLabel"));

  if (titleEl) titleEl.textContent = showMembersPanel ? String(title || "Members") : "Active Now";
  if (countEl) {
    countEl.textContent = String(Math.max(0, Number(count || 0)));
    countEl.style.display = showMembersPanel ? "inline-flex" : "";
  }

  if (membersPanel) {
    membersPanel.classList.toggle("hidden", !showMembersPanel);
    membersPanel.setAttribute("aria-hidden", showMembersPanel ? "false" : "true");
  }
  if (activeNowEl) activeNowEl.style.display = showMembersPanel ? "none" : "";
  if (offlineListEl) offlineListEl.style.display = showMembersPanel ? "none" : "none";
  labels.forEach((el) => {
    el.style.display = showMembersPanel ? "none" : "";
  });
}

function getPresenceStatusForServerMember(userId) {
  const uid = normId(userId);
  if (!uid) return "offline";
  if (uid === normId(state.user?.id || "")) {
    return resolveMyPresenceStatus(state.me);
  }
  const hit = (presenceList || []).find((p) => normId(p?.id || "") === uid);
  const liveStatus = readPresenceStatusValue(hit?.status);
  if (liveStatus && liveStatus !== "offline") {
    return normalizePresenceStatus(liveStatus);
  }
  const cachedProfile = getCachedProfile(uid);
  return normalizePresenceStatus(
    resolveAccountPresenceStatus(cachedProfile, liveStatus || "offline")
  );
}

function getServerVoicePresenceEntry(conversationId, { create = false } = {}) {
  const convId = normId(conversationId || "");
  if (!convId) return null;
  let entry = serverVoicePresenceByConversation.get(convId) || null;
  if (!entry && create) {
    entry = {
      memberIds: [],
      authoritativeMemberIds: [],
      seenAtByUser: new Map(),
      metaByUser: new Map(),
      leaveGraceUntilByUser: new Map(),
    };
    serverVoicePresenceByConversation.set(convId, entry);
  }
  return entry;
}

function clearServerVoicePresenceCache(conversationId, {
  triggerReason = "",
  callerFunction = "",
  sourceType = "local_control_plane_cache",
} = {}) {
  const convId = normId(conversationId || "");
  if (!convId) return;
  const entry = getServerVoicePresenceEntry(convId, { create: false });
  const previousOccupantIds = normalizeUuidArray(entry?.memberIds || []);
  logServerVoiceOccupancyEvent("occupancy.snapshot_cleared", convId, [], {
    triggerReason: String(triggerReason || "").trim() || "presence_cache_cleared",
    callerFunction: String(callerFunction || "").trim() || "clearServerVoicePresenceCache",
    sourceType,
    previousOccupantIds,
  });
  serverVoicePresenceByConversation.delete(convId);
}

function pruneServerVoicePresence(conversationId) {
  const convId = normId(conversationId || "");
  if (!convId) return [];
  const entry = getServerVoicePresenceEntry(convId, { create: false });
  if (!entry) return [];
  const now = Date.now();
  const authoritativeSet = new Set(
    normalizeUuidArray((getAuthoritativeServerVoicePresenceMembers(convId) || []).map((member) => member?.userId || ""))
  );
  const nextIds = normalizeUuidArray(entry.memberIds).filter((uid) => {
    if (!uid) return false;
    const graceUntil = Number(entry.leaveGraceUntilByUser?.get?.(uid) || 0);
    if (Number.isFinite(graceUntil) && graceUntil > now) return true;
    if (Number.isFinite(graceUntil) && graceUntil > 0) return false;
    if (authoritativeSet.has(uid)) return true;
    const seenAt = Number(entry.seenAtByUser.get(uid) || 0);
    return Number.isFinite(seenAt) && (now - seenAt) <= SERVER_VOICE_PRESENCE_STALE_MS;
  });
  const keep = new Set(nextIds);
  entry.memberIds = nextIds;
  entry.authoritativeMemberIds = normalizeUuidArray(entry.authoritativeMemberIds).filter((uid) => keep.has(uid));
  Array.from(entry.seenAtByUser.keys()).forEach((uid) => {
    if (!keep.has(uid)) entry.seenAtByUser.delete(uid);
  });
  Array.from(entry.metaByUser.keys()).forEach((uid) => {
    if (!keep.has(uid)) entry.metaByUser.delete(uid);
  });
  Array.from(entry.leaveGraceUntilByUser?.keys?.() || []).forEach((uid) => {
    if (!keep.has(uid)) entry.leaveGraceUntilByUser.delete(uid);
  });
  if (!entry.memberIds.length) {
    clearServerVoicePresenceCache(convId, {
      triggerReason: "presence_pruned_empty",
      callerFunction: "pruneServerVoicePresence",
      sourceType: "local_control_plane_cache",
    });
    return [];
  }
  return entry.memberIds.slice();
}

function addServerVoicePresenceMember(conversationId, userId, { label = "", avatar = "", seenAt = null } = {}) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid) return;
  const entry = getServerVoicePresenceEntry(convId, { create: true });
  if (!entry) return;
  entry.memberIds = normalizeUuidArray([...(entry.memberIds || []), uid]);
  entry.authoritativeMemberIds = normalizeUuidArray([...(entry.authoritativeMemberIds || []), uid]);
  const now = Date.now();
  const ts = Number(seenAt);
  const safeTs = (Number.isFinite(ts) && ts > 0 && ts <= (now + 30 * 1000)) ? ts : now;
  entry.seenAtByUser.set(uid, safeTs);
  entry.leaveGraceUntilByUser?.delete?.(uid);
  const prevMeta = entry.metaByUser.get(uid) || {};
  const nextLabel = String(label || "").trim() || prevMeta.label || "";
  const nextAvatar = String(avatar || "").trim() || prevMeta.avatar || "";
  if (nextLabel || nextAvatar) {
    entry.metaByUser.set(uid, { label: nextLabel, avatar: nextAvatar });
  }
}

function removeServerVoicePresenceMember(conversationId, userId) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid) return;
  const entry = getServerVoicePresenceEntry(convId, { create: false });
  if (!entry) return;
  entry.memberIds = normalizeUuidArray((entry.memberIds || []).filter((id) => id !== uid));
  entry.authoritativeMemberIds = normalizeUuidArray((entry.authoritativeMemberIds || []).filter((id) => id !== uid));
  entry.seenAtByUser.delete(uid);
  entry.metaByUser.delete(uid);
  entry.leaveGraceUntilByUser?.delete?.(uid);
  if (!entry.memberIds.length) {
    clearServerVoicePresenceCache(convId, {
      triggerReason: "presence_member_removed_last",
      callerFunction: "removeServerVoicePresenceMember",
      sourceType: "local_control_plane_cache",
    });
  }
}

function getServerVoicePresenceMemberIds(conversationId) {
  const authoritativeMembers = getAuthoritativeServerVoicePresenceMembers(conversationId);
  if (authoritativeMembers !== null) {
    syncServerVoicePresenceFallbackFromMembers(conversationId, authoritativeMembers);
    return pruneServerVoicePresence(conversationId);
  }
  return pruneServerVoicePresence(conversationId);
}

function getServerVoicePresenceMemberMeta(conversationId, userId) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid) return null;
  const authoritativeMembers = getAuthoritativeServerVoicePresenceMembers(conversationId);
  if (authoritativeMembers !== null) {
    const hit = authoritativeMembers.find((member) => member.userId === uid) || null;
    if (hit) {
      return {
        label: hit.label || "",
        avatar: hit.avatar || "",
      };
    }
  }
  const entry = getServerVoicePresenceEntry(convId, { create: false });
  if (!entry) return null;
  return entry.metaByUser.get(uid) || null;
}

function getCallParticipantAudioStateEntry(conversationId, { create = false } = {}) {
  const convId = normId(conversationId || "");
  if (!convId) return null;
  let entry = callParticipantAudioStateByConversation.get(convId) || null;
  if (!entry && create) {
    entry = new Map();
    callParticipantAudioStateByConversation.set(convId, entry);
  }
  return entry;
}

function setCallParticipantAudioState(conversationId, userId, {
  micMuted: micMutedValue = null,
  deafened: deafenedValue = null,
  seenAt = null,
} = {}) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid) return null;
  const entry = getCallParticipantAudioStateEntry(convId, { create: true });
  if (!entry) return null;

  const hadPrev = entry.has(uid);
  const prev = entry.get(uid) || {};
  const hasMicMuted = micMutedValue != null;
  const hasDeafened = deafenedValue != null;
  const nextMicMuted = hasMicMuted ? !!micMutedValue : !!prev.micMuted;
  const nextDeafened = hasDeafened ? !!deafenedValue : !!prev.deafened;
  const now = Date.now();
  const ts = Number(seenAt);
  const safeSeenAt = (Number.isFinite(ts) && ts > 0 && ts <= (now + 30 * 1000)) ? ts : now;
  const next = {
    micMuted: nextMicMuted,
    deafened: nextDeafened,
    seenAt: safeSeenAt,
  };
  entry.set(uid, next);
  const changed = !hadPrev
    || !!prev.micMuted !== !!next.micMuted
    || !!prev.deafened !== !!next.deafened;
  if (changed && isServerVoiceConversationById(convId)) {
    const source = uid === normId(state.user?.id || "") ? "local_state_store" : "remote_state_store";
    logServerVoiceParticipantAudioStateIfChanged(convId, uid, {
      reason: source,
    });
    recordServerVoiceParticipantAudioStateChange(convId, uid, next, {
      source,
      reason: source,
    });
  }
  return next;
}

function getCallParticipantAudioState(conversationId, userId) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid) return null;
  const entry = getCallParticipantAudioStateEntry(convId, { create: false });
  if (!entry) return null;
  const row = entry.get(uid) || null;
  if (!row) return null;
  const now = Date.now();
  const seenAt = Number(row.seenAt || 0);
  if (Number.isFinite(seenAt) && seenAt > 0 && (now - seenAt) > CALL_PARTICIPANT_AUDIO_STATE_STALE_MS) {
    entry.delete(uid);
    if (!entry.size) callParticipantAudioStateByConversation.delete(convId);
    return null;
  }
  return {
    micMuted: !!row.micMuted,
    deafened: !!row.deafened,
    seenAt: seenAt > 0 ? seenAt : now,
  };
}

function removeCallParticipantAudioState(conversationId, userId) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid) return;
  const entry = getCallParticipantAudioStateEntry(convId, { create: false });
  if (!entry) return;
  entry.delete(uid);
  const debugEntry = serverVoiceLastParticipantAudioStateSignatureByConversation.get(convId) || null;
  debugEntry?.delete?.(uid);
  if (debugEntry && !debugEntry.size) {
    serverVoiceLastParticipantAudioStateSignatureByConversation.delete(convId);
  }
  const historyStore = serverVoiceParticipantAudioStateHistoryByConversation.get(convId) || null;
  historyStore?.delete?.(uid);
  if (historyStore && !historyStore.size) {
    serverVoiceParticipantAudioStateHistoryByConversation.delete(convId);
  }
  if (!entry.size) callParticipantAudioStateByConversation.delete(convId);
}

function clearCallParticipantAudioStates(conversationId = null) {
  const convId = normId(conversationId || "");
  if (!convId) {
    callParticipantAudioStateByConversation.clear();
    serverVoiceLastParticipantAudioStateSignatureByConversation.clear();
    serverVoiceParticipantAudioStateHistoryByConversation.clear();
    serverVoiceParticipantLifecycleHistoryByConversation.clear();
    return;
  }
  callParticipantAudioStateByConversation.delete(convId);
  serverVoiceLastParticipantAudioStateSignatureByConversation.delete(convId);
  serverVoiceParticipantAudioStateHistoryByConversation.delete(convId);
  serverVoiceParticipantLifecycleHistoryByConversation.delete(convId);
}

