async function uploadGroupAvatarFile(file, { conversationId = "" } = {}) {
  if (!file || !state.user?.id) throw new Error("Upload de foto do grupo invalido.");
  const contentType = String(file.type || "").trim().toLowerCase();
  if (!contentType.startsWith("image/")) {
    throw new Error("A foto do grupo tem de ser uma imagem.");
  }
  const fileSize = Number(file.size || 0);
  if (fileSize > GROUP_AVATAR_MAX_BYTES) {
    throw new Error("Foto do grupo demasiado grande (max 8MB).");
  }

  const ext = (String(file.name || "").split(".").pop() || "png").toLowerCase();
  const { ext: safeExt, mime } = resolveAvatarMimeAndExt(ext, file.type || "");
  const convTag = normId(conversationId) || "draft";
  const path = `${state.user.id}/group_${convTag}_${Date.now()}.${safeExt}`;
  const upload = await supabase.storage.from("avatars").upload(path, file, {
    upsert: true,
    contentType: mime,
  });
  if (upload.error) throw upload.error;
  const { data } = supabase.storage.from("avatars").getPublicUrl(path);
  const publicUrl = String(data?.publicUrl || "").trim();
  if (!publicUrl) throw new Error("Nao consegui gerar URL publica para a foto do grupo.");
  return publicUrl;
}

async function updateGroupDmProfileRpc(conversationId, {
  name = null,
  avatarUrl = null,
} = {}) {
  const convId = normId(conversationId);
  if (!convId) return { data: null, error: { message: "conversation_id invalido" } };

  const normalizedName = (() => {
    const raw = String(name ?? "").trim();
    return raw ? normalizeConversationLabel(raw, "Group DM") : null;
  })();
  const normalizedAvatar = (() => {
    const raw = String(avatarUrl ?? "").trim();
    return raw || null;
  })();

  const payloads = [
    {
      p_conversation_id: convId,
      p_name: normalizedName,
      p_avatar_url: normalizedAvatar,
    },
    {
      conversation_id: convId,
      name: normalizedName,
      avatar_url: normalizedAvatar,
    },
  ];

  let lastMissingErr = null;
  for (const payload of payloads) {
    const res = await supabase.rpc("update_group_dm_profile", payload);
    if (!res?.error) return res;
    if (!isMissingRpcError(res.error)) return res;
    lastMissingErr = res.error;
  }

  return { data: null, error: lastMissingErr || { message: "rpc nao encontrada" } };
}

async function resolveDmGroupBasePeer() {
  if (!activeDmId) return null;
  if (state.activeDm?.isGroup || state.activeDm?.kind === "group" || state.activeDm?.kind === "server") return null;

  let peerId = normId(state.activeDm?.otherUserId || state.activeDm?.other_user_id || callOtherUserId || "");
  let label = String(state.activeDm?.displayName || state.activeDm?.username || callOtherLabel || "").trim();
  let username = String(state.activeDm?.username || "").trim();

  if (!peerId) {
    peerId = await resolveConversationPeerUserId(activeDmId);
  }

  if (peerId) {
    const friend = (state.friends || []).find((f) => normId(f?.other_user_id || f?.id) === peerId) || null;
    const cached = getCachedProfile(peerId) || {};
    label = label || friend?.display_name || cached?.display_name || friend?.username || cached?.username || t("call.friend", "friend");
    username = username || friend?.username || cached?.username || "";

    state.activeDm = {
      ...(state.activeDm || {}),
      otherUserId: peerId,
      other_user_id: peerId,
      username: state.activeDm?.username || username,
      displayName: state.activeDm?.displayName || label,
    };
  }

  if (!peerId) return null;
  return {
    userId: peerId,
    label: normalizeConversationLabel(label || t("call.friend", "friend"), t("call.friend", "friend")),
    username: username || "",
  };
}

function getDmGroupCreateCandidates() {
  const meId = normId(state.user?.id || "");
  const basePeerId = normId(dmCreateGroupBasePeerId);
  const query = String(dmCreateGroupSearch || "").trim().toLowerCase();
  const seen = new Set();
  const out = [];

  (state.friends || []).forEach((f) => {
    const uid = normId(f?.other_user_id || f?.id);
    if (!uid || uid === meId || uid === basePeerId || seen.has(uid)) return;
    seen.add(uid);

    const username = String(f?.username || "").trim();
    const displayName = String(f?.display_name || username || "").trim();
    const avatarUrl = String(f?.avatar_url || "").trim();

    const searchable = `${displayName} ${username}`.toLowerCase();
    if (query && !searchable.includes(query)) return;

    out.push({
      userId: uid,
      username,
      displayName: displayName || username || "user",
      avatarUrl,
    });
  });

  return out.sort((a, b) => {
    const an = String(a.displayName || a.username || "").toLowerCase();
    const bn = String(b.displayName || b.username || "").toLowerCase();
    return an.localeCompare(bn);
  });
}

function renderDmGroupCreatePicker() {
  const listEl = document.getElementById("dmCreateGroupPicker");
  const metaEl = document.getElementById("dmCreateGroupMeta");
  const baseEl = document.getElementById("dmCreateGroupBase");
  const confirmBtn = document.getElementById("btnDmCreateGroupConfirm");
  if (!listEl || !metaEl || !baseEl || !confirmBtn) return;

  const basePeerId = normId(dmCreateGroupBasePeerId);
  if (!basePeerId) {
    listEl.innerHTML = `<div class="hint">Nao consegui identificar a pessoa desta DM.</div>`;
    metaEl.textContent = "Selecionados: 1/10";
    metaEl.dataset.tone = "warn";
    baseEl.textContent = "Abre uma DM direta com uma pessoa para criar Group DM.";
    confirmBtn.disabled = true;
    return;
  }

  baseEl.textContent = `Inclui automaticamente: ${dmCreateGroupBasePeerLabel || "pessoa desta DM"}`;

  const friends = getDmGroupCreateCandidates();
  const validIds = new Set(friends.map((f) => f.userId));
  for (const id of Array.from(dmCreateGroupSelectedIds)) {
    if (!validIds.has(id)) dmCreateGroupSelectedIds.delete(id);
  }

  if (!friends.length) {
    listEl.innerHTML = `<div class="hint">Nao tens mais amigos disponiveis para adicionar.</div>`;
  } else {
    listEl.innerHTML = friends.map((f) => {
      const selected = dmCreateGroupSelectedIds.has(f.userId);
      const avatar = f.avatarUrl
        ? buildAvatarMediaHtml(f.avatarUrl, { userId: f.userId, alt: f.displayName })
        : `<span class="partyPickAvatarFallback">${esc(String(f.displayName || f.username || "?").trim().charAt(0).toUpperCase() || "?")}</span>`;
      return `
        <button
          class="partyPickItem${selected ? " is-on" : ""}"
          type="button"
          data-dm-group-friend-id="${escAttr(f.userId)}"
          aria-pressed="${selected ? "true" : "false"}"
        >
          <span class="partyPickAvatar">${avatar}</span>
          <span class="partyPickMain">
            <span class="partyPickName">${esc(f.displayName)}</span>
            <span class="partyPickHandle">@${esc(f.username || "")}</span>
          </span>
          <span class="partyPickCheck" aria-hidden="true">${selected ? "?" : "+"}</span>
        </button>
      `;
    }).join("");
  }

  const totalForGroup = 2 + dmCreateGroupSelectedIds.size; // tu + pessoa da DM + selecionados
  const overLimit = totalForGroup > GROUP_DM_MAX_MEMBERS;
  metaEl.textContent = overLimit
    ? `Selecionados: ${totalForGroup}/${GROUP_DM_MAX_MEMBERS} (limite excedido)`
    : `Selecionados: ${totalForGroup}/${GROUP_DM_MAX_MEMBERS} (tu + pessoa da DM)`;
  metaEl.dataset.tone = overLimit ? "warn" : "ok";

  renderDmCreateGroupAvatarPreview();

  confirmBtn.disabled = dmCreateGroupSelectedIds.size < 1 || overLimit;
  confirmBtn.title = groupDmRpcAvailable
    ? "Criar Group DM"
    : "Aplica o patch SQL de groups/servers para ativar";
}

async function openDmGroupCreateModal() {
  const modal = document.getElementById("dmCreateGroupModal");
  const search = document.getElementById("dmCreateGroupSearch");
  const nameInput = document.getElementById("dmCreateGroupName");
  if (!modal) return;
  if (!activeDmId) return;
  if (state.activeDm?.isGroup || state.activeDm?.kind === "group" || state.activeDm?.kind === "server") return;

  if (!Array.isArray(state.friends) || !state.friends.length) {
    const { data, error } = await supabase.rpc("list_my_friends");
    if (!error) state.friends = await hydrateFriendRowsWithProfiles(data || []);
  }

  const peer = await resolveDmGroupBasePeer();
  if (!peer?.userId) {
    alert("Nao consegui identificar a pessoa desta DM.");
    return;
  }

  dmCreateGroupBasePeerId = peer.userId;
  dmCreateGroupBasePeerLabel = peer.label || peer.username || t("call.friend", "friend");
  dmCreateGroupSearch = "";
  dmCreateGroupSelectedIds.clear();
  dmCreateGroupName = "";
  clearDmCreateGroupAvatarDraft();

  if (search) search.value = "";
  if (nameInput) nameInput.value = "";
  renderDmGroupCreatePicker();

  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  requestAnimationFrame(() => search?.focus());
}

function bindDmGroupCreateModalOnce() {
  if (dmCreateGroupModalBound) return;
  dmCreateGroupModalBound = true;

  const modal = document.getElementById("dmCreateGroupModal");
  const nameInput = document.getElementById("dmCreateGroupName");
  const search = document.getElementById("dmCreateGroupSearch");
  const avatarInput = document.getElementById("dmCreateGroupAvatarFile");
  const avatarPreview = document.getElementById("dmCreateGroupAvatarPreview");
  const btnAvatarPick = document.getElementById("btnDmCreateGroupAvatarPick");
  const btnAvatarClear = document.getElementById("btnDmCreateGroupAvatarClear");
  const picker = document.getElementById("dmCreateGroupPicker");
  const btnOpen = document.getElementById("btnDmCreateGroup");
  const btnClose = document.getElementById("btnDmCreateGroupClose");
  const btnCancel = document.getElementById("btnDmCreateGroupCancel");
  const btnConfirm = document.getElementById("btnDmCreateGroupConfirm");

  btnOpen?.addEventListener("click", async () => {
    await openDmGroupCreateModal();
  });

  btnClose?.addEventListener("click", closeDmCreateGroupModal);
  btnCancel?.addEventListener("click", closeDmCreateGroupModal);

  modal?.addEventListener("click", (e) => {
    if (e.target?.dataset?.close) closeDmCreateGroupModal();
  });

  search?.addEventListener("input", () => {
    dmCreateGroupSearch = String(search.value || "").trim();
    renderDmGroupCreatePicker();
  });

  nameInput?.addEventListener("input", () => {
    dmCreateGroupName = normalizeConversationLabel(String(nameInput.value || "").trim(), "Group DM");
    renderDmCreateGroupAvatarPreview();
  });

  const openCreateAvatarPicker = () => {
    avatarInput?.click();
  };
  avatarPreview?.addEventListener("click", openCreateAvatarPicker);
  btnAvatarPick?.addEventListener("click", openCreateAvatarPicker);
  btnAvatarClear?.addEventListener("click", () => {
    clearDmCreateGroupAvatarDraft();
    renderDmCreateGroupAvatarPreview();
  });
  avatarInput?.addEventListener("change", () => {
    const file = avatarInput?.files?.[0] || null;
    if (!file) {
      clearDmCreateGroupAvatarDraft();
      renderDmCreateGroupAvatarPreview();
      return;
    }
    const contentType = String(file.type || "").toLowerCase();
    if (!contentType.startsWith("image/")) {
      alert("Escolhe uma imagem para a foto do grupo.");
      clearDmCreateGroupAvatarDraft();
      renderDmCreateGroupAvatarPreview();
      return;
    }
    if (Number(file.size || 0) > GROUP_AVATAR_MAX_BYTES) {
      alert("Foto do grupo demasiado grande (max 8MB).");
      clearDmCreateGroupAvatarDraft();
      renderDmCreateGroupAvatarPreview();
      return;
    }
    if (dmCreateGroupAvatarPreviewUrl) safeRevokeObjectUrl(dmCreateGroupAvatarPreviewUrl);
    dmCreateGroupAvatarFile = file;
    dmCreateGroupAvatarPreviewUrl = URL.createObjectURL(file);
    renderDmCreateGroupAvatarPreview();
  });

  picker?.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    const item = target?.closest("[data-dm-group-friend-id]");
    if (!item) return;
    const uid = normId(item.getAttribute("data-dm-group-friend-id"));
    if (!uid) return;

    if (dmCreateGroupSelectedIds.has(uid)) dmCreateGroupSelectedIds.delete(uid);
    else dmCreateGroupSelectedIds.add(uid);
    renderDmGroupCreatePicker();
  });

  btnConfirm?.addEventListener("click", async () => {
    const basePeerId = normId(dmCreateGroupBasePeerId);
    if (!basePeerId) {
      alert("Nao consegui identificar a pessoa da DM atual.");
      return;
    }

    const memberIds = Array.from(new Set([
      basePeerId,
      ...Array.from(dmCreateGroupSelectedIds).map((id) => normId(id)).filter(Boolean),
    ])).filter(Boolean);

    if (memberIds.length < 2) {
      alert("Escolhe pelo menos 1 amigo para adicionar ao Group DM.");
      return;
    }
    if (memberIds.length + 1 > GROUP_DM_MAX_MEMBERS) {
      alert(`Group DM suporta no maximo ${GROUP_DM_MAX_MEMBERS} pessoas (inclui-te).`);
      return;
    }

    const rawName = String(nameInput?.value || "").trim();
    const groupName = rawName ? normalizeConversationLabel(rawName, "Group DM") : getDefaultGroupDmName();

    const { data, error } = await supabase.rpc("create_group_dm", {
      p_member_ids: memberIds,
      p_name: groupName,
    });
    if (error) {
      if (isMissingRpcError(error)) {
        groupDmRpcAvailable = false;
        alert("A funcao create_group_dm ainda nao existe no SQL.");
      } else {
        alert(`Erro ao criar Group DM: ${error.message}`);
      }
      renderDmGroupCreatePicker();
      return;
    }

    const conversationId = normId(data);

    if (conversationId && dmCreateGroupAvatarFile) {
      try {
        const avatarPublicUrl = await uploadGroupAvatarFile(dmCreateGroupAvatarFile, { conversationId });
        const { error: editErr } = await updateGroupDmProfileRpc(conversationId, {
          name: groupName,
          avatarUrl: avatarPublicUrl,
        });
        if (editErr) {
          if (isMissingRpcError(editErr)) {
            alert("Falta SQL no Supabase: executa o patch de editar Group DM (nome/foto).");
          } else {
            alert(`Group criado, mas falhou guardar a foto: ${editErr.message}`);
          }
        }
      } catch (avatarErr) {
        alert(`Group criado, mas falhou upload da foto: ${avatarErr?.message || avatarErr}`);
      }
    }

    closeDmCreateGroupModal();
    dmCreateGroupSelectedIds.clear();
    dmCreateGroupSearch = "";
    dmCreateGroupName = "";

    try {
      invalidateGroupAndServerCollectionsCache();
      await refresh();
    } catch (e) {
      console.warn("refresh failed after dm create_group_dm", e);
      await loadDmList().catch(() => {});
      renderFriends({ skipPresenceRefresh: true, skipGroupsRail: true });
      renderPending({ skipWidgets: true, skipAddFriendLookup: true });
      renderGroupsRail();
      renderWidgets();
      updatePresenceRender();
    }
    if (!conversationId) {
      alert("Group DM criado, mas nao consegui abrir automaticamente.");
      return;
    }

    const meta = getConversationMeta(conversationId) || {
      kind: "group",
      isGroup: true,
      displayName: groupName || "Group DM",
    };
    await openConversationById(conversationId, meta);
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (!modal || modal.classList.contains("hidden")) return;
    e.preventDefault();
    closeDmCreateGroupModal();
  });
}

function clearDmGroupEditAvatarDraft({ keepCurrentAvatar = false } = {}) {
  if (dmGroupEditAvatarPreviewUrl) {
    safeRevokeObjectUrl(dmGroupEditAvatarPreviewUrl);
  }
  dmGroupEditAvatarPreviewUrl = "";
  dmGroupEditAvatarFile = null;
  dmGroupEditAvatarRemoved = false;
  if (!keepCurrentAvatar) dmGroupEditAvatarUrl = "";
  const fileInput = document.getElementById("dmGroupEditAvatarFile");
  if (fileInput) fileInput.value = "";
}

function closeDmGroupEditModal() {
  const modal = document.getElementById("dmGroupEditModal");
  if (!modal || modal.classList.contains("hidden")) return;
  clearDmGroupEditAvatarDraft({ keepCurrentAvatar: false });
  dmGroupEditConversationId = "";
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");
}

function renderDmGroupEditAvatarPreview() {
  const previewBtn = document.getElementById("dmGroupEditAvatarPreview");
  const nameInput = document.getElementById("dmGroupEditName");
  const fallbackLabel = normalizeConversationLabel(
    state.activeDm?.displayName || "Group DM",
    "Group DM"
  );
  const label = normalizeConversationLabel(String(nameInput?.value || "").trim(), fallbackLabel);
  const avatarUrl = dmGroupEditAvatarRemoved
    ? ""
    : (dmGroupEditAvatarPreviewUrl || dmGroupEditAvatarUrl || "");
  setGroupAvatarPreviewButton(previewBtn, { avatarUrl, label });
}

async function openDmGroupEditModal() {
  const modal = document.getElementById("dmGroupEditModal");
  const nameInput = document.getElementById("dmGroupEditName");
  const convId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (!modal || !convId) return;

  const activeMeta = getActiveConversationMeta(convId) || {};
  const isGroup = isGroupConversationMeta(activeMeta);
  if (!isGroup) return;

  const groupMeta = getGroupMembershipActionMeta(convId);
  if (!groupMeta.isOwner) {
    alert("So o dono pode editar este group dm.");
    return;
  }

  let rawName = "";
  let rawAvatar = "";
  try {
    const { data: convRow, error: convErr } = await supabase
      .from("conversations")
      .select("name, avatar_url")
      .eq("id", convId)
      .maybeSingle();

    if (!convErr && convRow) {
      rawName = String(convRow?.name || "").trim();
      rawAvatar = String(convRow?.avatar_url || "").trim();
    } else if (convErr) {
      const msg = String(convErr?.message || "").toLowerCase();
      const avatarColumnMissing = msg.includes("avatar_url") && msg.includes("column");
      if (!avatarColumnMissing) console.warn("group edit preload failed", convErr);
      else rawName = String(convRow?.name || "").trim();
    }
  } catch (_) {}

  if (!rawName) {
    const fromRow = (state.groupDms || []).find((g) => normId(g?.conversationId) === convId) || null;
    const fallbackName = String(fromRow?.name || activeMeta?.displayName || state.activeDm?.displayName || "").trim();
    rawName = fallbackName === "Group DM" ? "" : fallbackName;
  }
  if (!rawAvatar) {
    const fromRow = (state.groupDms || []).find((g) => normId(g?.conversationId) === convId) || null;
    rawAvatar = String(fromRow?.avatarUrl || activeMeta?.avatarUrl || state.activeDm?.avatarUrl || "").trim();
  }

  dmGroupEditConversationId = convId;
  dmGroupEditAvatarUrl = rawAvatar;
  clearDmGroupEditAvatarDraft({ keepCurrentAvatar: true });
  if (nameInput) nameInput.value = rawName;
  renderDmGroupEditAvatarPreview();

  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  requestAnimationFrame(() => nameInput?.focus());
}

function bindDmGroupEditModalOnce() {
  if (dmGroupEditModalBound) return;
  dmGroupEditModalBound = true;

  const modal = document.getElementById("dmGroupEditModal");
  const btnClose = document.getElementById("btnDmGroupEditClose");
  const btnCancel = document.getElementById("btnDmGroupEditCancel");
  const btnSave = document.getElementById("btnDmGroupEditSave");
  const nameInput = document.getElementById("dmGroupEditName");
  const avatarInput = document.getElementById("dmGroupEditAvatarFile");
  const avatarPreview = document.getElementById("dmGroupEditAvatarPreview");
  const btnAvatarPick = document.getElementById("btnDmGroupEditAvatarPick");
  const btnAvatarClear = document.getElementById("btnDmGroupEditAvatarClear");

  btnClose?.addEventListener("click", closeDmGroupEditModal);
  btnCancel?.addEventListener("click", closeDmGroupEditModal);

  modal?.addEventListener("click", (e) => {
    if (e.target?.dataset?.close) closeDmGroupEditModal();
  });

  nameInput?.addEventListener("input", () => {
    renderDmGroupEditAvatarPreview();
  });

  const openEditAvatarPicker = () => avatarInput?.click();
  avatarPreview?.addEventListener("click", openEditAvatarPicker);
  btnAvatarPick?.addEventListener("click", openEditAvatarPicker);
  btnAvatarClear?.addEventListener("click", () => {
    dmGroupEditAvatarRemoved = true;
    dmGroupEditAvatarFile = null;
    if (dmGroupEditAvatarPreviewUrl) {
      safeRevokeObjectUrl(dmGroupEditAvatarPreviewUrl);
      dmGroupEditAvatarPreviewUrl = "";
    }
    if (avatarInput) avatarInput.value = "";
    renderDmGroupEditAvatarPreview();
  });

  avatarInput?.addEventListener("change", () => {
    const file = avatarInput?.files?.[0] || null;
    if (!file) {
      if (dmGroupEditAvatarPreviewUrl) {
        safeRevokeObjectUrl(dmGroupEditAvatarPreviewUrl);
        dmGroupEditAvatarPreviewUrl = "";
      }
      dmGroupEditAvatarFile = null;
      renderDmGroupEditAvatarPreview();
      return;
    }
    const contentType = String(file.type || "").toLowerCase();
    if (!contentType.startsWith("image/")) {
      alert("Escolhe uma imagem para a foto do grupo.");
      if (avatarInput) avatarInput.value = "";
      return;
    }
    if (Number(file.size || 0) > GROUP_AVATAR_MAX_BYTES) {
      alert("Foto do grupo demasiado grande (max 8MB).");
      if (avatarInput) avatarInput.value = "";
      return;
    }

    if (dmGroupEditAvatarPreviewUrl) safeRevokeObjectUrl(dmGroupEditAvatarPreviewUrl);
    dmGroupEditAvatarPreviewUrl = URL.createObjectURL(file);
    dmGroupEditAvatarFile = file;
    dmGroupEditAvatarRemoved = false;
    renderDmGroupEditAvatarPreview();
  });

  btnSave?.addEventListener("click", async () => {
    const convId = normId(dmGroupEditConversationId || activeDmId || state.activeDm?.conversationId || "");
    if (!convId) {
      alert("Nao consegui identificar o grupo para editar.");
      return;
    }

    const groupMeta = getGroupMembershipActionMeta(convId);
    if (!groupMeta.isOwner) {
      alert("So o dono pode editar este group dm.");
      return;
    }

    const rawName = String(nameInput?.value || "").trim();
    const nextName = rawName ? normalizeConversationLabel(rawName, "Group DM") : null;

    let avatarForRpc = dmGroupEditAvatarUrl || null;
    if (dmGroupEditAvatarRemoved) avatarForRpc = "";
    if (dmGroupEditAvatarFile) {
      try {
        avatarForRpc = await uploadGroupAvatarFile(dmGroupEditAvatarFile, { conversationId: convId });
      } catch (avatarErr) {
        alert(`Falhou upload da foto do grupo: ${avatarErr?.message || avatarErr}`);
        return;
      }
    }

    const prevText = String(btnSave.textContent || "Guardar");
    btnSave.disabled = true;
    btnSave.textContent = "A guardar...";
    const { error } = await updateGroupDmProfileRpc(convId, {
      name: nextName,
      avatarUrl: avatarForRpc,
    });
    btnSave.disabled = false;
    btnSave.textContent = prevText;

    if (error) {
      if (isMissingRpcError(error)) {
        alert("Falta SQL no Supabase: executa o patch de editar Group DM (nome/foto).");
      } else {
        alert(`Erro a editar Group DM: ${error.message}`);
      }
      return;
    }

    const finalName = normalizeConversationLabel(nextName || "Group DM", "Group DM");
    const finalAvatar = String(avatarForRpc || "").trim();
    state.groupDms = (state.groupDms || []).map((row) => {
      if (normId(row?.conversationId) !== convId) return row;
      return {
        ...row,
        name: finalName,
        avatarUrl: finalAvatar,
      };
    });
    syncConversationMetaCaches();
    setConversationMeta(convId, {
      kind: "group",
      isGroup: true,
      displayName: finalName,
      avatarUrl: finalAvatar,
      ownerUserId: groupMeta.ownerUserId || "",
    });

    if (normId(activeDmId || state.activeDm?.conversationId || "") === convId) {
      state.activeDm = {
        ...(state.activeDm || {}),
        displayName: finalName,
        avatarUrl: finalAvatar,
      };
      const titleEl = document.getElementById("dmTitle");
      if (titleEl) titleEl.textContent = finalName;
      applyDmTitleNameStyle();
    }

    closeDmGroupEditModal();

    try {
      await loadDmList();
    } catch (_) {
      renderGroupsRail();
      syncDmActiveListHighlight();
    }
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (!modal || modal.classList.contains("hidden")) return;
    e.preventDefault();
    closeDmGroupEditModal();
  });
}

function renderWidgets() {
  const trace = getRelationshipCurrentTrace();
  const traceLabel = relationshipTracePhaseStart(trace, "renderWidgets");
  try {
  const widgetRoot = $("tabWidgets");
  const grid = $("widgetsGrid");
  if (!widgetRoot || !grid) return;
  widgetRoot.classList.toggle("is-edit-mode", !!widgetsEditMode);
  if (widgetResizeDrag) finishWidgetResizeDrag(false);
  if (widgetPointerDrag) {
    cancelWidgetPointerDrag();
    removeWidgetDragPreview();
  }
  if (widgetsDragId || widgetsDropGridCell || widgetsDropTargetId) {
    widgetsDragId = "";
    widgetsDropTargetId = "";
    widgetsDropPosition = "before";
    widgetsDropGridCell = null;
    removeWidgetDragPreview();
    widgetRoot.classList.remove("is-widget-dragging");
    clearWidgetDropMarkers();
  }
  const beforeRects = captureWidgetCardRects(grid);
  bindWidgetsUiOnce();
  ensureWidgetsLayoutState();

  const friends = Array.isArray(state.friends) ? state.friends : [];
  const incoming = Array.isArray(state.incoming) ? state.incoming : [];
  const outgoing = Array.isArray(state.outgoing) ? state.outgoing : [];
  const messageIncoming = Array.isArray(state.messageIncoming) ? state.messageIncoming : [];
  const messageOutgoing = Array.isArray(state.messageOutgoing) ? state.messageOutgoing : [];

  const friendsCount = friends.length;
  const pendingCount = incoming.length + outgoing.length + messageIncoming.length + messageOutgoing.length;
  const onlineCount = friends.reduce((acc, f) => {
    const uid = normId(f?.other_user_id || f?.id);
    if (!uid) return acc;
    const status = getPresenceStatusForUser(uid);
    return (status === "online" || status === "idle" || status === "dnd") ? (acc + 1) : acc;
  }, 0);

  const unreadConversations = Array.from(dmUnreadByUserId.values())
    .filter((n) => Number(n) > 0)
    .length
    + Array.from(dmUnreadByConversationId.values()).filter((n) => Number(n) > 0).length;
  const unreadMessages = Array.from(dmUnreadByUserId.values())
    .reduce((acc, n) => acc + Math.max(0, Number(n) || 0), 0)
    + Array.from(dmUnreadByConversationId.values()).reduce((acc, n) => acc + Math.max(0, Number(n) || 0), 0);
  const unreadMeta = unreadMessages === 1
    ? "1 mensagem por ler"
    : `${unreadMessages} mensagens por ler`;

  const callActive = !!(
    inCall ||
    isServerVoiceTransportSessionActive(callConversationId || activeDmId || state.activeDm?.conversationId || "") ||
    (
      callPc &&
      callPc.connectionState !== "closed" &&
      callPc.connectionState !== "failed"
    )
  );
  const activeDmName = state.activeDm?.displayName || state.activeDm?.username || "nenhuma";
  const callState = callActive ? "Chamada ativa" : "Sem chamada ativa";

  const stats = {
    friendsCount,
    pendingCount,
    onlineCount,
    unreadConversations,
    unreadMessages,
    unreadMeta,
    callActive,
    callState,
    activeDmName,
  };

  let activeIds = getActiveWidgetIds();

  if (!activeIds.length) {
    widgetsLayoutState = normalizeWidgetsLayout(null);
    saveWidgetsLayoutState();
    activeIds = getActiveWidgetIds();
  }

  if (!activeIds.length) {
    grid.innerHTML = `<div class="hint">Sem widgets ativos. Entra no modo de ediÃ§Ã£o para adicionar.</div>`;
  } else {
    grid.innerHTML = activeIds.map((id) => {
      try {
        return widgetCardHtml(id, stats);
      } catch (error) {
        console.error("widgets: render failed", id, error);
        return `
          <article class="widgetCard widgetCard--size-sm">
            <div class="widgetCard__label">${esc(getWidgetLabel(id) || id)}</div>
            <div class="widgetCard__meta">${esc(t("widget.error.load", "Widget failed to load."))}</div>
          </article>
        `;
      }
    }).join("");
    const gridMetrics = getWidgetsGridMetrics();
    applyWidgetGridPlacements(grid, activeIds, gridMetrics.colCount);
    animateWidgetLayoutFromRects(grid, beforeRects, {
      duration: widgetsEditMode ? 340 : 300,
      includeEnter: true,
      easing: "cubic-bezier(0.2, 0.92, 0.2, 1)",
    });
  }

  renderWidgetsEditorUi(activeIds);
  renderDesktopInboxPanel();
  } finally {
    relationshipTracePhaseEnd(trace, traceLabel);
  }
}

function buildFriendCollectionsFingerprint(
  friendsRows = [],
  incomingRows = [],
  outgoingRows = [],
  messageIncomingRows = [],
  messageOutgoingRows = []
) {
  const friendKeys = (Array.isArray(friendsRows) ? friendsRows : [])
    .map((row) => {
      const id = normId(row?.other_user_id || row?.id || "");
      if (!id) return "";
      const since = String(row?.since || row?.created_at || "").trim();
      return `${id}|${since}`;
    })
    .filter(Boolean)
    .sort();

  const incomingKeys = (Array.isArray(incomingRows) ? incomingRows : [])
    .map((row) => {
      const rid = normId(row?.request_id || row?.id || "");
      if (!rid) return "";
      const uid = normId(row?.from_user_id || row?.user_id || "");
      return `${rid}|${uid}`;
    })
    .filter(Boolean)
    .sort();

  const outgoingKeys = (Array.isArray(outgoingRows) ? outgoingRows : [])
    .map((row) => {
      const rid = normId(row?.request_id || row?.id || "");
      if (!rid) return "";
      const uid = normId(row?.to_user_id || row?.user_id || "");
      return `${rid}|${uid}`;
    })
    .filter(Boolean)
    .sort();

  const messageIncomingKeys = (Array.isArray(messageIncomingRows) ? messageIncomingRows : [])
    .map((row) => {
      const rid = normId(row?.request_id || row?.id || "");
      if (!rid) return "";
      const uid = normId(row?.from_user_id || row?.user_id || "");
      return `${rid}|${uid}`;
    })
    .filter(Boolean)
    .sort();

  const messageOutgoingKeys = (Array.isArray(messageOutgoingRows) ? messageOutgoingRows : [])
    .map((row) => {
      const rid = normId(row?.request_id || row?.id || "");
      if (!rid) return "";
      const uid = normId(row?.to_user_id || row?.user_id || "");
      return `${rid}|${uid}`;
    })
    .filter(Boolean)
    .sort();

  return `${friendKeys.join(",")}::${incomingKeys.join(",")}::${outgoingKeys.join(",")}::${messageIncomingKeys.join(",")}::${messageOutgoingKeys.join(",")}`;
}

async function applyFriendCollectionsData({
  friendsRows = [],
  incomingRows = [],
  outgoingRows = [],
  messageIncomingRows = [],
  messageOutgoingRows = [],
  messageContactsRows = null,
  sourceFingerprint = "",
  hydrateProfiles = true,
  syncFriendPreferences = true,
  syncGifFavorites = true,
  reloadDmList = true,
  skipGroupServerCollections = false,
  skipMessageContactsFetch = false,
  preserveDmActivityHydration = false,
} = {}) {
  const trace = getRelationshipCurrentTrace();
  relationshipTraceMeasureSync(trace, "applyFriendCollectionsData:assign", () => {
    state.friends = Array.isArray(friendsRows) ? friendsRows : [];
    state.incoming = Array.isArray(incomingRows) ? incomingRows : [];
    state.outgoing = Array.isArray(outgoingRows) ? outgoingRows : [];
    state.messageIncoming = Array.isArray(messageIncomingRows) ? messageIncomingRows : [];
    state.messageOutgoing = Array.isArray(messageOutgoingRows) ? messageOutgoingRows : [];
    if (Array.isArray(messageContactsRows)) {
      state.dmContacts = messageContactsRows;
    }
  });
  if (hydrateProfiles) {
    state.friends = await relationshipTraceMeasureAsync(trace, "applyFriendCollectionsData:hydrate_friends", () => (
      awaitWithTimeout(
        hydrateFriendRowsWithProfiles(state.friends),
        PROFILES_FETCH_TIMEOUT_MS,
        "hydrate friends profiles"
      ).catch(() => state.friends)
    ));
    if (Array.isArray(messageContactsRows)) {
      state.dmContacts = await relationshipTraceMeasureAsync(trace, "applyFriendCollectionsData:hydrate_contacts", () => (
        awaitWithTimeout(
          hydrateFriendRowsWithProfiles(state.dmContacts),
          PROFILES_FETCH_TIMEOUT_MS,
          "hydrate message contacts"
        ).catch(() => state.dmContacts)
      ));
    }
  } else {
    state.friends = hydrateRelationshipRowsFromCache(state.friends);
    if (Array.isArray(messageContactsRows)) {
      state.dmContacts = hydrateRelationshipRowsFromCache(state.dmContacts);
    }
  }
  dmConversationPeerCache.clear();
  const relationIds = new Set([
    ...(state.friends || []).map((f) => normId(f?.other_user_id || f?.id)).filter(Boolean),
    ...(Array.isArray(messageContactsRows) ? (state.dmContacts || []).map((row) => normId(row?.other_user_id || row?.id)).filter(Boolean) : []),
  ]);
  pruneDmClientState(relationIds);
  if (syncFriendPreferences) {
    await relationshipTraceMeasureAsync(trace, "applyFriendCollectionsData:friend_preferences_sync", () => (
      awaitWithTimeout(
        syncDmFriendPreferencesFromCloud(state.friends),
        FRIEND_SYNC_TIMEOUT_MS,
        "friend preferences sync"
      ).catch(() => {})
    ));
  }
  if (syncGifFavorites) {
    await relationshipTraceMeasureAsync(trace, "applyFriendCollectionsData:gif_favorites_sync", () => (
      awaitWithTimeout(
        syncGifFavoritesFromCloud({ force: false }),
        FRIEND_SYNC_TIMEOUT_MS,
        "gif favorites sync"
      ).catch(() => {})
    ));
  }
  if (!preserveDmActivityHydration) {
    dmActivityHydratedFromServer = false;
  }

  const fp = String(sourceFingerprint || "").trim()
    || buildFriendCollectionsFingerprint(friendsRows, incomingRows, outgoingRows, messageIncomingRows, messageOutgoingRows);
  if (fp) friendRequestsSyncFingerprint = fp;

  relationshipTraceMeasureSync(trace, "applyFriendCollectionsData:renderFriends", () => {
    renderFriends({ skipPresenceRefresh: true, skipGroupsRail: true });
  });
  relationshipTraceMeasureSync(trace, "applyFriendCollectionsData:renderPending", () => {
    renderPending({ skipWidgets: true, skipAddFriendLookup: true });
  });
  relationshipTraceMeasureSync(trace, "applyFriendCollectionsData:renderGroupsRail", () => {
    renderGroupsRail();
  });
  relationshipTraceMeasureSync(trace, "applyFriendCollectionsData:renderWidgets", () => {
    renderWidgets();
  });
  relationshipTraceMeasureSync(trace, "applyFriendCollectionsData:scheduleAddFriendProfileLookup", () => {
    scheduleAddFriendProfileLookup({ immediate: false, force: false });
  });
  if (reloadDmList) {
    await relationshipTraceMeasureAsync(trace, "applyFriendCollectionsData:loadDmList", () => (
      awaitWithTimeout(loadDmList({
        preloadedFriends: state.friends,
        preloadedContacts: Array.isArray(messageContactsRows) ? state.dmContacts : null,
        skipProfileHydration: true,
        skipFriendPreferencesSync: true,
        skipGifFavoritesSync: true,
        skipGroupServerCollections,
        skipMessageContactsFetch,
        skipActivityHydration: preserveDmActivityHydration,
      }), RPC_SOFT_TIMEOUT_MS, "load dm list").catch(() => {})
    ));
  } else {
    relationshipTraceMeasureSync(trace, "applyFriendCollectionsData:reorderDmList", () => {
      reorderDmListByActivity();
    });
  }
  renderPartyPicker();
  updatePresenceRender();
}

async function refresh({ lightweight = false } = {}) {
  const trace = getRelationshipCurrentTrace();
  const batchResults = await relationshipTraceMeasureAsync(
    trace,
    "refresh:rpcBatch",
    () => Promise.all([
      rpcWithTimeout("list_my_friends"),
      rpcWithTimeout("incoming_friend_requests"),
      rpcWithTimeout("outgoing_friend_requests"),
      rpcWithTimeout("incoming_message_requests"),
      rpcWithTimeout("outgoing_message_requests"),
      ...(lightweight ? [listMyMessageContactsRpc()] : []),
    ])
  );
  const [
    friends,
    incoming,
    outgoing,
    messageIncoming,
    messageOutgoing,
    messageContacts,
  ] = Array.isArray(batchResults) ? batchResults : [];
  const authErrors = [friends?.error, incoming?.error, outgoing?.error, messageIncoming?.error, messageOutgoing?.error]
    .filter((err) => err && isAuthSessionMissingError(err));

  if (authErrors.length) {
    try { await supabase.auth.signOut({ scope: "local" }); } catch (_) {}
    window.location.replace("./login.html");
    return;
  }

  setDebug({
    friends: { error: friends.error, count: friends.data?.length },
    incoming: { error: incoming.error, count: incoming.data?.length },
    outgoing: { error: outgoing.error, count: outgoing.data?.length },
    message_incoming: { error: messageIncoming.error, count: messageIncoming.data?.length },
    message_outgoing: { error: messageOutgoing.error, count: messageOutgoing.data?.length },
  });

  const safeMessageIncoming = messageIncoming?.error && isMissingRpcError(messageIncoming.error)
    ? []
    : (Array.isArray(messageIncoming?.data) ? messageIncoming.data : []);
  const safeMessageOutgoing = messageOutgoing?.error && isMissingRpcError(messageOutgoing.error)
    ? []
    : (Array.isArray(messageOutgoing?.data) ? messageOutgoing.data : []);

  const sourceFp = buildFriendCollectionsFingerprint(
    Array.isArray(friends.data) ? friends.data : [],
    Array.isArray(incoming.data) ? incoming.data : [],
    Array.isArray(outgoing.data) ? outgoing.data : [],
    safeMessageIncoming,
    safeMessageOutgoing,
  );
  try {
    await relationshipTraceMeasureAsync(trace, "refresh:applyFriendCollectionsData", () => (
      awaitWithTimeout(applyFriendCollectionsData({
        friendsRows: Array.isArray(friends.data) ? friends.data : [],
        incomingRows: Array.isArray(incoming.data) ? incoming.data : [],
        outgoingRows: Array.isArray(outgoing.data) ? outgoing.data : [],
        messageIncomingRows: safeMessageIncoming,
        messageOutgoingRows: safeMessageOutgoing,
        messageContactsRows: lightweight && !messageContacts?.error && Array.isArray(messageContacts?.data)
          ? messageContacts.data
          : null,
        sourceFingerprint: sourceFp,
        hydrateProfiles: !lightweight,
        syncFriendPreferences: !lightweight,
        syncGifFavorites: !lightweight,
        reloadDmList: true,
        skipGroupServerCollections: lightweight,
        skipMessageContactsFetch: lightweight && !messageContacts?.error,
        preserveDmActivityHydration: lightweight,
      }), RPC_SOFT_TIMEOUT_MS + 6000, "apply friend collections")
    ));
  } catch (e) {
    console.warn("applyFriendCollectionsData timeout/fail", e);
    state.friends = Array.isArray(friends.data) ? friends.data : [];
    state.incoming = Array.isArray(incoming.data) ? incoming.data : [];
    state.outgoing = Array.isArray(outgoing.data) ? outgoing.data : [];
    state.messageIncoming = safeMessageIncoming;
    state.messageOutgoing = safeMessageOutgoing;
    if (lightweight && !messageContacts?.error && Array.isArray(messageContacts?.data)) {
      state.dmContacts = hydrateRelationshipRowsFromCache(messageContacts.data);
    }
    renderFriends({ skipPresenceRefresh: true, skipGroupsRail: true });
    renderPending({ skipWidgets: true, skipAddFriendLookup: true });
    renderGroupsRail();
    renderWidgets();
    updatePresenceRender();
    scheduleAddFriendProfileLookup({ immediate: false, force: false });
  }
}

async function sendFriendRequest(usernameOverride = "", { preserveInput = true } = {}) {
  const input = $("addUsername");
  const uname = String(usernameOverride || input?.value || "").trim();
  if (!uname) {
    await requestAppAlert("Escreve um username.", {
      title: t("add.title", "Add friend"),
      okText: "OK",
    });
    return;
  }
  const trace = beginRelationshipActionTrace("send_friend_request", { username: uname });

  // â”€â”€ TRUE OPTIMISTIC: patch state + render BEFORE the network call â”€â”€
  const knownUserId = findKnownUserIdByUsername(uname);
  const optimisticProfile = getOptimisticRelationshipProfile({ userId: knownUserId, username: uname });
  const snapshot = relationshipTraceMeasureSync(trace, "snapshotRelationshipState", () => snapshotRelationshipState());
  const tempReqId = "_opt_" + Date.now();
  const optimisticOutgoing = {
    request_id: tempReqId,
    to_user_id: normId(optimisticProfile?.id || ""),
    username: uname,
    display_name: optimisticProfile?.display_name || uname,
    avatar_url: optimisticProfile?.avatar_url || null,
    created_at: new Date().toISOString(),
    _optimistic: true,
  };
  relationshipTraceMeasureSync(trace, "optimisticPatch", () => {
    state.outgoing = [optimisticOutgoing, ...(state.outgoing || [])];
    if (!preserveInput && input) input.value = "";
  });
  renderRelationshipUiNow({
    rerenderPending: true,
    affectedUserId: normId(optimisticProfile?.id || ""),
    affectedUsername: uname,
  });
  relationshipTraceSchedulePaint(trace, "optimisticPaint");
  // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

  const { data, error } = await relationshipTraceMeasureAsync(trace, "rpc:send_friend_request", () => (
    supabase.rpc("send_friend_request", { target_username: uname })
  ));
  setDebug({ send_friend_request: { error, data } });
  if (error) {
    restoreRelationshipState(snapshot, {
      rerenderPending: true,
      affectedUserId: normId(optimisticProfile?.id || ""),
      affectedUsername: uname,
    });
    relationshipTraceSchedulePaint(trace, "rollbackPaint");
    endRelationshipTrace(trace, "rpc_error", { message: String(error?.message || error || "") });
    await requestAppAlert("Falhou: " + error.message, {
      title: t("add.title", "Add friend"),
      okText: "OK",
    });
    return;
  }

  // Update the temp row with the real request_id from the server
  const realReqId = normId(String(data || ""));
  relationshipTraceMeasureSync(trace, "successPatch", () => {
    state.outgoing = (state.outgoing || []).map((r) =>
      r.request_id === tempReqId ? { ...r, request_id: realReqId, _optimistic: false } : r
    );
  });
  renderRelationshipUiNow({
    rerenderPending: true,
    affectedUserId: normId(optimisticProfile?.id || ""),
    affectedUsername: uname,
  });
  relationshipTraceSchedulePaint(trace, "successPaint");

  deferRelationshipTraceToReconcile(trace, { delayMs: 180 });
  scheduleRelationshipReconcile(180, trace);
  scheduleAddFriendProfileLookup({ immediate: true, force: true });
}

async function listMyMessageContactsRpc() {
  const res = await rpcWithTimeout("list_my_message_contacts");
  if (res?.error && isMissingRpcError(res.error)) return { data: [], error: null, missingSql: true };
  return { data: Array.isArray(res?.data) ? res.data : [], error: res?.error || null, missingSql: false };
}

async function sendMessageRequest(username, { silent = false } = {}) {
  const uname = String(username || "").trim();
  if (!uname) return { ok: false, error: { message: "username em falta" }, conversationId: "" };
  const trace = beginRelationshipActionTrace("send_message_request", { username: uname });

  const currentCardUserId = normId(userCardCurrentUserId || "");
  const currentCardMatches = currentCardUserId
    && String(userCardCurrentUsername || "").trim().toLowerCase() === uname.toLowerCase();
  const knownUserId = findKnownUserIdByUsername(uname) || (currentCardMatches ? currentCardUserId : "");
  const optimisticProfile = getOptimisticRelationshipProfile({ userId: knownUserId, username: uname });
  const snapshot = relationshipTraceMeasureSync(trace, "snapshotRelationshipState", () => snapshotRelationshipState());
  const tempReqId = `_opt_msg_${Date.now()}`;
  relationshipTraceMeasureSync(trace, "optimisticPatch", () => {
    state.messageOutgoing = [
      {
        request_id: tempReqId,
        to_user_id: normId(optimisticProfile?.id || ""),
        username: uname,
        display_name: optimisticProfile?.display_name || uname,
        avatar_url: optimisticProfile?.avatar_url || null,
        created_at: new Date().toISOString(),
        _optimistic: true,
      },
      ...(state.messageOutgoing || []),
    ];
  });
  renderRelationshipUiNow({
    rerenderPending: true,
    affectedUserId: normId(optimisticProfile?.id || ""),
    affectedUsername: uname,
  });
  relationshipTraceSchedulePaint(trace, "optimisticPaint");

  const res = await relationshipTraceMeasureAsync(trace, "rpc:send_message_request", () => (
    rpcWithTimeout("send_message_request", { target_username: uname })
  ));
  if (res?.error) {
    restoreRelationshipState(snapshot, {
      rerenderPending: true,
      affectedUserId: normId(optimisticProfile?.id || ""),
      affectedUsername: uname,
    });
    relationshipTraceSchedulePaint(trace, "rollbackPaint");
    endRelationshipTrace(trace, "rpc_error", { message: String(res?.error?.message || res?.error || "") });
    if (!silent) {
      if (isMissingRpcError(res.error)) {
        await requestAppAlert("Falta SQL no Supabase: aplica o patch de message requests.", {
          title: "Message Requests",
          okText: "OK",
        });
      } else {
        await requestAppAlert(`Falhou o pedido de mensagem: ${res.error.message}`, {
          title: "Message Requests",
          okText: "OK",
        });
      }
    }
    return { ok: false, error: res.error, conversationId: "" };
  }

  const row = Array.isArray(res?.data) ? (res.data[0] || null) : (res?.data || null);
  const status = String(row?.status || "").trim().toLowerCase();
  const conversationId = normId(row?.conversation_id || "");
  relationshipTraceMeasureSync(trace, "successPatch", () => {
    if (status === "accepted" && conversationId) {
      optimisticRemoveMessageOutgoing(tempReqId);
      upsertDmContactRow({
        other_user_id: normId(optimisticProfile?.id || ""),
        username: uname,
        display_name: optimisticProfile?.display_name || uname,
        avatar_url: optimisticProfile?.avatar_url || null,
        conversation_id: conversationId,
        _optimistic: false,
      });
    } else {
      state.messageOutgoing = (state.messageOutgoing || []).map((entry) =>
        String(entry?.request_id || "").trim() === tempReqId
          ? {
            ...entry,
            request_id: String(row?.request_id || "").trim() || tempReqId,
            conversation_id: conversationId || normId(entry?.conversation_id || ""),
            _optimistic: false,
          }
          : entry
      );
    }
  });
  renderRelationshipUiNow({
    rerenderPending: true,
    affectedUserId: normId(optimisticProfile?.id || ""),
    affectedUsername: uname,
  });
  relationshipTraceSchedulePaint(trace, "successPaint");
  deferRelationshipTraceToReconcile(trace, { delayMs: 180, status, conversationId });
  scheduleRelationshipReconcile(180, trace);
  return {
    ok: true,
    error: null,
    requestId: String(row?.request_id || "").trim(),
    status,
    conversationId,
  };
}

async function acceptMessageReq(requestId, { silent = false } = {}) {
  const rid = String(requestId || "").trim();
  if (!rid) return { ok: false, error: { message: "request_id invalido" }, conversationId: "" };
  const trace = beginRelationshipActionTrace("accept_message_request", { requestId: rid });

  const incomingRow = (state.messageIncoming || []).find(
    (r) => String(r?.request_id || r?.id || "").trim() === rid
  ) || null;
  const targetUid = normId(incomingRow?.from_user_id || "");
  const snapshot = relationshipTraceMeasureSync(trace, "snapshotRelationshipState", () => snapshotRelationshipState());
  relationshipTraceMeasureSync(trace, "optimisticPatch", () => {
    optimisticRemoveMessageIncoming(rid);
    if (incomingRow) {
      upsertDmContactRow({
        other_user_id: targetUid,
        username: String(incomingRow?.username || "").trim(),
        display_name: String(incomingRow?.display_name || incomingRow?.username || "").trim(),
        avatar_url: incomingRow?.avatar_url || null,
        conversation_id: normId(incomingRow?.conversation_id || ""),
        _optimistic: true,
      });
    }
  });
  renderRelationshipUiNow({
    rerenderPending: true,
    affectedUserId: targetUid,
    affectedUsername: String(incomingRow?.username || "").trim(),
  });
  relationshipTraceSchedulePaint(trace, "optimisticPaint");

  const res = await relationshipTraceMeasureAsync(trace, "rpc:accept_message_request", () => (
    rpcWithTimeout("accept_message_request", { request_id: rid })
  ));
  if (res?.error) {
    restoreRelationshipState(snapshot, {
      rerenderPending: true,
      affectedUserId: targetUid,
      affectedUsername: String(incomingRow?.username || "").trim(),
    });
    relationshipTraceSchedulePaint(trace, "rollbackPaint");
    endRelationshipTrace(trace, "rpc_error", { message: String(res?.error?.message || res?.error || "") });
    if (!silent) {
      if (isMissingRpcError(res.error)) {
        await requestAppAlert("Falta SQL no Supabase: aplica o patch de message requests.", {
          title: "Message Requests",
          okText: "OK",
        });
      } else {
        await requestAppAlert(`Falhou a aceitar o pedido: ${res.error.message}`, {
          title: "Message Requests",
          okText: "OK",
        });
      }
    }
    return { ok: false, error: res.error, conversationId: "" };
  }

  const conversationId = normId(Array.isArray(res?.data) ? res.data[0]?.conversation_id || res.data[0] : res?.data?.conversation_id || res?.data);
  relationshipTraceMeasureSync(trace, "successPatch", () => {
    if (targetUid) {
      upsertDmContactRow({
        other_user_id: targetUid,
        username: String(incomingRow?.username || "").trim(),
        display_name: String(incomingRow?.display_name || incomingRow?.username || "").trim(),
        avatar_url: incomingRow?.avatar_url || null,
        conversation_id: conversationId,
        _optimistic: false,
      });
    }
  });
  renderRelationshipUiNow({
    rerenderPending: true,
    affectedUserId: targetUid,
    affectedUsername: String(incomingRow?.username || "").trim(),
  });
  relationshipTraceSchedulePaint(trace, "successPaint");
  deferRelationshipTraceToReconcile(trace, { delayMs: 180, conversationId });
  scheduleRelationshipReconcile(180, trace);
  return { ok: true, error: null, conversationId };
}

