async function acceptReq(id) {
  const rid = normId(id || "");
  if (!rid) return;
  const trace = beginRelationshipActionTrace("accept_friend_request", { requestId: rid });

  const incomingRow = (state.incoming || []).find(
    (r) => normId(r?.request_id || r?.id || "") === rid
  );
  const targetUid = normId(incomingRow?.from_user_id || "");
  const snapshot = relationshipTraceMeasureSync(trace, "snapshotRelationshipState", () => snapshotRelationshipState());

  relationshipTraceMeasureSync(trace, "optimisticPatch", () => {
    if (incomingRow) {
      optimisticRemoveIncoming(rid);
      const optimisticFriend = {
        other_user_id: targetUid,
        username: incomingRow.username || "",
        display_name: incomingRow.display_name || incomingRow.username || "",
        avatar_url: incomingRow.avatar_url || null,
        since: new Date().toISOString(),
        _optimistic: true,
      };
      state.friends = [optimisticFriend, ...(state.friends || [])];
    }
  });
  renderRelationshipUiNow({
    rerenderFriends: true,
    rerenderPending: true,
    affectedUserId: targetUid,
    affectedUsername: String(incomingRow?.username || "").trim(),
  });
  relationshipTraceSchedulePaint(trace, "optimisticPaint");

  const { error } = await relationshipTraceMeasureAsync(trace, "rpc:accept_friend_request", () => (
    supabase.rpc("accept_friend_request", { request_id: rid })
  ));
  if (error) {
    restoreRelationshipState(snapshot, {
      rerenderFriends: true,
      rerenderPending: true,
      affectedUserId: targetUid,
      affectedUsername: String(incomingRow?.username || "").trim(),
    });
    relationshipTraceSchedulePaint(trace, "rollbackPaint");
    endRelationshipTrace(trace, "rpc_error", { message: String(error?.message || error || "") });
    alert("Erro: " + error.message);
    return;
  }

  deferRelationshipTraceToReconcile(trace, { delayMs: 180 });
  scheduleRelationshipReconcile(180, trace);
}

async function rejectReq(id) {
  const rid = normId(id || "");
  if (!rid) return;
  const trace = beginRelationshipActionTrace("reject_friend_request", { requestId: rid });

  const incomingRow = (state.incoming || []).find(
    (r) => normId(r?.request_id || r?.id || "") === rid
  ) || null;
  const snapshot = relationshipTraceMeasureSync(trace, "snapshotRelationshipState", () => snapshotRelationshipState());
  relationshipTraceMeasureSync(trace, "optimisticPatch", () => {
    optimisticRemoveIncoming(rid);
  });
  renderRelationshipUiNow({
    rerenderPending: true,
    affectedUserId: normId(incomingRow?.from_user_id || ""),
    affectedUsername: String(incomingRow?.username || "").trim(),
  });
  relationshipTraceSchedulePaint(trace, "optimisticPaint");

  const { error } = await relationshipTraceMeasureAsync(trace, "rpc:reject_friend_request", () => (
    supabase.rpc("reject_friend_request", { request_id: rid })
  ));
  if (error) {
    restoreRelationshipState(snapshot, {
      rerenderPending: true,
      affectedUserId: normId(incomingRow?.from_user_id || ""),
      affectedUsername: String(incomingRow?.username || "").trim(),
    });
    relationshipTraceSchedulePaint(trace, "rollbackPaint");
    endRelationshipTrace(trace, "rpc_error", { message: String(error?.message || error || "") });
    alert("Erro: " + error.message);
    return;
  }
  deferRelationshipTraceToReconcile(trace, { delayMs: 180 });
  scheduleRelationshipReconcile(180, trace);
}

async function cancelReq(id) {
  const rid = normId(id || "");
  if (!rid) return;
  const trace = beginRelationshipActionTrace("cancel_friend_request", { requestId: rid });

  const outgoingRow = (state.outgoing || []).find(
    (r) => normId(r?.request_id || r?.id || "") === rid
  ) || null;
  const snapshot = relationshipTraceMeasureSync(trace, "snapshotRelationshipState", () => snapshotRelationshipState());
  relationshipTraceMeasureSync(trace, "optimisticPatch", () => {
    optimisticRemoveOutgoing(rid);
  });
  renderRelationshipUiNow({
    rerenderPending: true,
    affectedUserId: normId(outgoingRow?.to_user_id || ""),
    affectedUsername: String(outgoingRow?.username || "").trim(),
  });
  relationshipTraceSchedulePaint(trace, "optimisticPaint");

  const { error } = await relationshipTraceMeasureAsync(trace, "rpc:cancel_friend_request", () => (
    supabase.rpc("cancel_friend_request", { request_id: rid })
  ));
  if (error) {
    restoreRelationshipState(snapshot, {
      rerenderPending: true,
      affectedUserId: normId(outgoingRow?.to_user_id || ""),
      affectedUsername: String(outgoingRow?.username || "").trim(),
    });
    relationshipTraceSchedulePaint(trace, "rollbackPaint");
    endRelationshipTrace(trace, "rpc_error", { message: String(error?.message || error || "") });
    alert("Erro: " + error.message);
    return;
  }
  deferRelationshipTraceToReconcile(trace, { delayMs: 180 });
  scheduleRelationshipReconcile(180, trace);
}

