function setDmFriendNickname(userId, nickname = "", { persist = true, syncCloud = true } = {}) {
  ensureDmClientStateLoaded();
  const uid = normId(userId);
  if (!uid) return false;
  const next = normalizeDmFriendPreferenceNickname(nickname);
  const prev = String(dmFriendNicknameByUserId.get(uid) || "").trim();
  if (next === prev) return false;
  if (!next) dmFriendNicknameByUserId.delete(uid);
  else dmFriendNicknameByUserId.set(uid, next);
  if (persist) persistDmFriendNicknamesToStorage();
  if (syncCloud) queueDmFriendPreferenceCloudWrite(uid);
  if (dmProfilePanelOpen && uid === getActiveDmPeerUserId()) {
    try { refreshDmProfilePanel(); } catch (_) {}
  }
  if (normId(userCardCurrentUserId || "") === uid) {
    try { refreshOpenUserCard(); } catch (_) {}
  }
  try {
    const serverCtx = getActiveServerContext();
    const sid = normId(serverCtx?.serverId || "");
    if (sid) {
      const cachedMembers = serverMemberListByServerId.get(sid) || [];
      void renderServerMembersRightPanel(serverCtx, cachedMembers);
      refreshServerVoiceChannelBadges();
    }
  } catch (_) {}
  return true;
}

