let activeDmId = null;
let dmChannel = null;
let dmReactionsChannel = null;
let globalDmMessageChannel = null;
let globalDmMessageRestartTimer = null;
const dmMessageConversationAccessCacheByConversation = new Map();
const dmMessageConversationAccessLookupInFlightByConversation = new Map();
const DM_MESSAGE_CONVERSATION_ACCESS_CACHE_MS = 60 * 1000;
let dmMessagesCache = [];
let dmMessageIds = new Set();
const dmActivityByUserId = new Map();
const dmUnreadByUserId = new Map();
const dmUnreadByConversationId = new Map();
const dmHiddenByUserId = new Set();
const dmMutedUserIds = new Set();
const dmMutedConversationIds = new Set();
const dmMutedUserUntilById = new Map();
const dmMutedConversationUntilById = new Map();
const dmPinnedGroupConversationIds = new Set();
const dmBestFriendUserIds = new Set();
