const DM_MUTE_DURATION_OPTIONS = [
  { key: "5m", label: "5 minutos", ms: 5 * 60 * 1000 },
  { key: "1h", label: "1 hora", ms: 60 * 60 * 1000 },
  { key: "8h", label: "8 horas", ms: 8 * 60 * 60 * 1000 },
  { key: "24h", label: "24 horas", ms: 24 * 60 * 60 * 1000 },
  { key: "forever", label: "Para sempre", ms: 0 },
];

function positionMenuAtPoint(menu, point, {
  width = 248,
  minHeight = 72,
} = {}) {
  if (!menu || !point) return;
  const vw = window.innerWidth || document.documentElement.clientWidth || 0;
  const vh = window.innerHeight || document.documentElement.clientHeight || 0;
  const menuWidth = Math.max(180, width);
  const renderedHeight = menu.offsetHeight;
  const menuHeight = Math.max(minHeight, renderedHeight || minHeight);
  let left = Number(point.x || 0);
  let top = Number(point.y || 0);
  if (left + menuWidth > vw - 8) left = Math.max(8, vw - menuWidth - 8);
  if (top + menuHeight > vh - 8) top = Math.max(8, vh - menuHeight - 8);
  menu.style.left = `${Math.round(left)}px`;
  menu.style.top = `${Math.round(top)}px`;
  // offsetHeight is 0 when the menu is first shown (not yet painted).
  // Re-clamp after the browser renders the element so it doesn't go off-screen.
  if (!renderedHeight) {
    requestAnimationFrame(() => {
      const h = menu.offsetHeight;
      if (!h) return;
      const vw2 = window.innerWidth || document.documentElement.clientWidth || 0;
      const vh2 = window.innerHeight || document.documentElement.clientHeight || 0;
      let l = Number(point.x || 0);
      let t = Number(point.y || 0);
      if (l + menuWidth > vw2 - 8) l = Math.max(8, vw2 - menuWidth - 8);
      if (t + h > vh2 - 8) t = Math.max(8, vh2 - h - 8);
      menu.style.left = `${Math.round(l)}px`;
      menu.style.top = `${Math.round(t)}px`;
    });
  }
}

async function copyTextWithPromptFallback(text, label = "Valor") {
  const value = String(text || "").trim();
  if (!value) return false;
  try {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(value);
      return true;
    }
  } catch (_) {}
  prompt(`Copia ${label}:`, value);
  return true;
}

function getMuteUntilText(untilMs) {
  const until = normalizeMuteUntilValue(untilMs);
  if (!until) return "Mute ativo para sempre";
  const delta = Math.max(0, until - Date.now());
  const min = Math.ceil(delta / 60000);
  if (min < 60) return `Mute ativo (${min} min restantes)`;
  const h = Math.ceil(min / 60);
  if (h < 24) return `Mute ativo (${h}h restantes)`;
  const d = Math.ceil(h / 24);
  return `Mute ativo (${d}d restantes)`;
}

function ensureDmMuteDurationMenu() {
  let menu = document.getElementById("dmMuteDurationMenu");
  if (!menu) {
    menu = document.createElement("div");
    menu.id = "dmMuteDurationMenu";
    menu.className = "msgMenu msgMenu--submenu";
    document.body.appendChild(menu);
  }

  if (dmMuteDurationMenuBound) return menu;
  dmMuteDurationMenuBound = true;

  document.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    if (!menu.classList.contains("is-open")) return;
    if (target.closest("#dmMuteDurationMenu")) return;
    closeDmMuteDurationMenu();
  });

  window.addEventListener("resize", closeDmMuteDurationMenu);
  window.addEventListener("scroll", closeDmMuteDurationMenu, true);
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeDmMuteDurationMenu();
  });

  menu.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const actionBtn = target.closest("[data-mute-duration-act]");
    if (!actionBtn || actionBtn.disabled) return;
    e.preventDefault();

    const action = String(actionBtn.getAttribute("data-mute-duration-act") || "").trim().toLowerCase();
    const targetType = String(actionBtn.getAttribute("data-mute-target-type") || "").trim().toLowerCase();
    const targetId = normId(actionBtn.getAttribute("data-mute-target-id") || "");
    const durationMs = Number(actionBtn.getAttribute("data-mute-duration-ms") || 0);
    closeDmMuteDurationMenu();
    if (!targetId) return;

    if (targetType === "conversation") {
      if (action === "unmute") {
        setDmConversationMuted(targetId, false, { persist: true });
      } else if (action === "set") {
        setDmConversationMuted(targetId, true, {
          persist: true,
          untilMs: durationMs > 0 ? (Date.now() + durationMs) : 0,
        });
      }
      void loadDmList().catch(() => {});
      return;
    }

    if (targetType === "user") {
      if (action === "unmute") {
        setDmUserMuted(targetId, false, { persist: true });
      } else if (action === "set") {
        setDmUserMuted(targetId, true, {
          persist: true,
          untilMs: durationMs > 0 ? (Date.now() + durationMs) : 0,
        });
      }
      void loadDmList().catch(() => {});
    }
  });

  return menu;
}

function openDmMuteDurationMenuAt(point, {
  targetType = "conversation",
  targetId = "",
} = {}) {
  const id = normId(targetId);
  if (!point || !id) return;
  const type = (targetType === "user") ? "user" : "conversation";
  const muted = type === "user" ? isDmUserMuted(id) : isDmConversationMuted(id);
  const until = type === "user"
    ? normalizeMuteUntilValue(dmMutedUserUntilById.get(id))
    : normalizeMuteUntilValue(dmMutedConversationUntilById.get(id));
  const menu = ensureDmMuteDurationMenu();

  menu.innerHTML = [
    muted ? `<button class="msgMenu__item" data-mute-duration-act="unmute" data-mute-target-type="${escAttr(type)}" data-mute-target-id="${escAttr(id)}"><span>Desativar mute</span></button>` : "",
    muted ? `<div class="msgMenu__divider"></div>` : "",
    muted ? `<div class="msgMenu__meta">${esc(getMuteUntilText(until))}</div>` : "",
    muted ? `<div class="msgMenu__divider"></div>` : "",
    ...DM_MUTE_DURATION_OPTIONS.map((opt) => (
      `<button class="msgMenu__item" data-mute-duration-act="set" data-mute-target-type="${escAttr(type)}" data-mute-target-id="${escAttr(id)}" data-mute-duration-ms="${escAttr(opt.ms)}"><span>${esc(opt.label)}</span></button>`
    )),
  ].filter(Boolean).join("");

  menu.classList.add("is-open");
  dmMuteDurationMenuTarget = { targetType: type, targetId: id };
  positionMenuAtPoint(menu, point, { width: 198, minHeight: 180 });
}

function ensureGroupDmListMenu() {
  let menu = document.getElementById("dmGroupListMenu");
  if (!menu) {
    menu = document.createElement("div");
    menu.id = "dmGroupListMenu";
    menu.className = "msgMenu";
    document.body.appendChild(menu);
  }

  if (dmGroupListMenuBound) return menu;
  dmGroupListMenuBound = true;

  document.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    if (!menu.classList.contains("is-open")) return;
    if (target.closest("#dmGroupListMenu")) return;
    if (target.closest("#dmMuteDurationMenu")) return;
    closeGroupDmListMenu();
  });

  window.addEventListener("resize", closeDmListMenus);
  window.addEventListener("scroll", closeDmListMenus, true);
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeDmListMenus();
  });

  menu.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const actionBtn = target.closest("[data-group-list-act]");
    if (!actionBtn || actionBtn.disabled) return;
    e.preventDefault();

    const action = String(actionBtn.getAttribute("data-group-list-act") || "").trim().toLowerCase();
    const convId = normId(actionBtn.getAttribute("data-group-list-conversation") || "");
    const groupName = String(actionBtn.getAttribute("data-group-list-name") || "Group DM");
    if (!convId) return;

    if (action === "mark_read") {
      closeDmListMenus();
      clearDmUnreadForConversation(convId);
      return;
    }
    if (action === "edit" || action === "invites") {
      closeDmListMenus();
      const row = (state.groupDms || []).find((g) => normId(g?.conversationId) === convId) || null;
      const meta = {
        kind: "group",
        isGroup: true,
        displayName: groupName || "Group DM",
        ownerUserId: normId(row?.ownerUserId || ""),
      };
      await openConversationById(convId, meta);
      await openDmGroupEditModal();
      return;
    }
    if (action === "mute_open") {
      const rect = actionBtn.getBoundingClientRect();
      openDmMuteDurationMenuAt(
        { x: Math.round(rect.right + 6), y: Math.round(rect.top - 2) },
        { targetType: "conversation", targetId: convId }
      );
      return;
    }
    if (action === "unmute") {
      closeDmListMenus();
      toggleDmConversationMuted(convId, { forceMuted: false, rerender: true });
      return;
    }
    if (action === "pin") {
      closeDmListMenus();
      toggleDmGroupPinned(convId, { forcePinned: true, rerender: true });
      return;
    }
    if (action === "unpin") {
      closeDmListMenus();
      toggleDmGroupPinned(convId, { forcePinned: false, rerender: true });
      return;
    }
    if (action === "copy_channel_id") {
      closeDmListMenus();
      await copyTextWithPromptFallback(convId, "Channel ID");
      return;
    }
    if (action === "delete" || action === "leave") {
      closeDmListMenus();
      await handleGroupDmMembershipAction(convId, {
        requestedAction: action,
        groupName,
      });
    }
  });

  menu.addEventListener("mouseover", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const actionBtn = target.closest("[data-group-list-act='mute_open']");
    if (!actionBtn || actionBtn.disabled) return;
    const convId = normId(actionBtn.getAttribute("data-group-list-conversation") || "");
    if (!convId) return;
    const rect = actionBtn.getBoundingClientRect();
    openDmMuteDurationMenuAt(
      { x: Math.round(rect.right + 6), y: Math.round(rect.top - 2) },
      { targetType: "conversation", targetId: convId }
    );
  });

  menu.addEventListener("focusin", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const actionBtn = target.closest("[data-group-list-act='mute_open']");
    if (!actionBtn || actionBtn.disabled) return;
    const convId = normId(actionBtn.getAttribute("data-group-list-conversation") || "");
    if (!convId) return;
    const rect = actionBtn.getBoundingClientRect();
    openDmMuteDurationMenuAt(
      { x: Math.round(rect.right + 6), y: Math.round(rect.top - 2) },
      { targetType: "conversation", targetId: convId }
    );
  });

  return menu;
}

function openGroupDmListMenuAt(conversationId, point, { groupName = "Group DM" } = {}) {
  const convId = normId(conversationId);
  if (!convId || !point) return;
  closeMessageMenu();
  closeGroupMemberMenu();
  closeDmUserListMenu();
  closeDmMuteDurationMenu();
  const menu = ensureGroupDmListMenu();
  const membership = getGroupMembershipActionMeta(convId);
  const isPinned = isDmGroupPinned(convId);
  const isMuted = isDmConversationMuted(convId);
  const canEditGroup = !!membership?.isOwner;
  const pinAction = isPinned ? "unpin" : "pin";
  const pinLabel = isPinned ? "Desafixar grupo" : "Fixar grupo no topo";
  const manageAction = membership?.action === "delete" ? "delete" : "leave";
  const manageLabel = manageAction === "delete" ? "Apagar grupo" : "Sair do grupo";

  menu.innerHTML = [
    `<button class="msgMenu__item" data-group-list-act="mark_read" data-group-list-conversation="${escAttr(convId)}" data-group-list-name="${escAttr(groupName)}"><span>Mark As Read</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item${canEditGroup ? "" : " is-disabled"}" data-group-list-act="invites" data-group-list-conversation="${escAttr(convId)}" data-group-list-name="${escAttr(groupName)}" ${canEditGroup ? "" : "disabled"}><span>Invites</span></button>`,
    `<button class="msgMenu__item${canEditGroup ? "" : " is-disabled"}" data-group-list-act="edit" data-group-list-conversation="${escAttr(convId)}" data-group-list-name="${escAttr(groupName)}" ${canEditGroup ? "" : "disabled"}><span>Edit Group</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item is-disabled" type="button" disabled><span class="msgMenu__itemMain"><span>Invite to Listen Along</span><span class="msgMenu__itemHint">Spotify</span></span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item" data-group-list-act="mute_open" data-group-list-conversation="${escAttr(convId)}" data-group-list-name="${escAttr(groupName)}"><span class="msgMenu__itemMain"><span>Mute Conversation</span>${isMuted ? '<span class="msgMenu__itemHint">Mute ativo</span>' : ''}</span><span>&#x203A;</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item" data-group-list-act="${escAttr(pinAction)}" data-group-list-conversation="${escAttr(convId)}" data-group-list-name="${escAttr(groupName)}"><span>${esc(pinLabel)}</span><span>&#x1F4CC;</span></button>`,
    `<button class="msgMenu__item${manageAction === "delete" ? " msgMenu__item--danger" : ""}" data-group-list-act="${escAttr(manageAction)}" data-group-list-conversation="${escAttr(convId)}" data-group-list-name="${escAttr(groupName)}"><span>${esc(manageLabel)}</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item" data-group-list-act="copy_channel_id" data-group-list-conversation="${escAttr(convId)}" data-group-list-name="${escAttr(groupName)}"><span>Copy Channel ID</span><span class="msgMenu__kbd">ID</span></button>`,
  ].join("");

  menu.classList.add("is-open");
  dmGroupListMenuTargetConversationId = convId;
  positionMenuAtPoint(menu, point, { width: 260, minHeight: 220 });
}

function getFriendRowByUserId(userId) {
  const uid = normId(userId);
  if (!uid) return null;
  return (state.friends || []).find((f) => normId(f?.other_user_id || f?.id) === uid) || null;
}

function getFriendRowByUsername(username = "") {
  const uname = String(username || "").trim().toLowerCase();
  if (!uname) return null;
  return (state.friends || []).find((f) => String(f?.username || "").trim().toLowerCase() === uname) || null;
}

function getMessageContactRowByUserId(userId) {
  const uid = normId(userId);
  if (!uid) return null;
  return (state.dmContacts || []).find((row) => normId(row?.other_user_id || row?.id) === uid) || null;
}

function getMessageContactRowByUsername(username = "") {
  const uname = String(username || "").trim().toLowerCase();
  if (!uname) return null;
  return (state.dmContacts || []).find((row) => String(row?.username || "").trim().toLowerCase() === uname) || null;
}

function getIncomingMessageRequestByUserId(userId) {
  const uid = normId(userId);
  if (!uid) return null;
  return (state.messageIncoming || []).find((row) => normId(row?.from_user_id || row?.user_id || row?.id) === uid) || null;
}

function getOutgoingMessageRequestByUserId(userId) {
  const uid = normId(userId);
  if (!uid) return null;
  return (state.messageOutgoing || []).find((row) => normId(row?.to_user_id || row?.user_id || row?.id) === uid) || null;
}

async function ensureFriendConversationId(userId, username = "") {
  const uid = normId(userId);
  if (!uid && !username) return "";
  let uname = String(username || "").trim();
  if (!uname && uid) {
    const row = getFriendRowByUserId(uid) || getMessageContactRowByUserId(uid);
    uname = String(row?.username || "").trim();
  }
  if (!uname) return "";
  const { data, error } = await supabase.rpc("create_dm", { target_username: uname });
  if (error) throw error;
  return normId(data);
}

