function requestDmFriendNickname(seedName = "user", currentValue = "") {
  const bridge = window?.altaraDesktop;
  const isDesktopApp = !!bridge && bridge.isDesktopApp === true;

  if (!isDesktopApp) {
    try {
      return Promise.resolve(window.prompt(`Nickname for ${seedName}`, currentValue || ""));
    } catch (_) {
      return Promise.resolve(null);
    }
  }

  const modal = ensureDmFriendNicknameModal();
  const titleEl = document.getElementById("dmFriendNicknameTitle");
  const inputEl = document.getElementById("dmFriendNicknameInput");
  const btnClose = document.getElementById("btnDmFriendNicknameClose");
  const btnCancel = document.getElementById("btnDmFriendNicknameCancel");
  const btnSave = document.getElementById("btnDmFriendNicknameSave");
  if (!modal || !inputEl || !btnClose || !btnCancel || !btnSave) return Promise.resolve(null);

  if (dmFriendNicknameModalBound !== true) {
    dmFriendNicknameModalBound = true;
    modal.addEventListener("click", (e) => {
      const target = eventTargetElement(e);
      if (!target) return;
      if (target.dataset?.close) {
        closeDmFriendNicknameModal(null);
      }
    });
    btnClose.addEventListener("click", () => closeDmFriendNicknameModal(null));
    btnCancel.addEventListener("click", () => closeDmFriendNicknameModal(null));
    btnSave.addEventListener("click", () => closeDmFriendNicknameModal(String(inputEl.value || "")));
    inputEl.addEventListener("keydown", (e) => {
      if (e.key === "Escape") {
        e.preventDefault();
        closeDmFriendNicknameModal(null);
        return;
      }
      if (e.key === "Enter") {
        e.preventDefault();
        closeDmFriendNicknameModal(String(inputEl.value || ""));
      }
    });
  }

  if (typeof titleEl?.textContent === "string") {
    titleEl.textContent = `Change Nickname - ${seedName}`;
  }
  inputEl.value = String(currentValue || "");
  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  requestAnimationFrame(() => {
    try {
      inputEl.focus();
      inputEl.select();
    } catch (_) {}
  });

  return new Promise((resolve) => {
    dmFriendNicknamePromptResolver = resolve;
  });
}

