function closeAppConfirmModal(result = false) {
  const modal = ensureAppConfirmModal();
  if (!modal) return;
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");

  const promptMode = appConfirmPromptMode;
  const { wrap, input, hint } = getAppConfirmInputControls();
  const inputValue = input instanceof HTMLTextAreaElement ? String(input.value || "").trim() : "";
  if (wrap instanceof HTMLElement) {
    wrap.hidden = true;
    wrap.style.display = "none";
  }
  if (hint instanceof HTMLElement) hint.textContent = "";
  if (input instanceof HTMLTextAreaElement) {
    input.value = "";
    input.placeholder = "";
    input.disabled = false;
  }

  const resolver = appConfirmPromptResolver;
  appConfirmPromptResolver = null;
  appConfirmPromptOptions = {};
  if (typeof resolver === "function") {
    try {
      resolver(promptMode === "prompt" ? (result ? inputValue : null) : !!result);
    } catch (_) {}
  }
}

function requestAppConfirm(message = "", options = {}) {
  const requestedMode = String(options?.mode || "confirm").trim().toLowerCase();
  const mode = requestedMode === "alert"
    ? "alert"
    : (requestedMode === "prompt" ? "prompt" : "confirm");
  const modal = ensureAppConfirmModal();
  const titleEl = document.getElementById("appConfirmTitle");
  const messageEl = document.getElementById("appConfirmMessage");
  const btnClose = document.getElementById("btnAppConfirmClose");
  const btnCancel = document.getElementById("btnAppConfirmCancel");
  const btnOk = document.getElementById("btnAppConfirmOk");
  const { wrap: inputWrap, label: inputLabel, input: inputEl, hint: inputHint } = getAppConfirmInputControls();

  if (!modal || !titleEl || !messageEl || !btnClose || !btnCancel || !btnOk) {
    try {
      if (mode === "prompt") {
        const nativePrompt = typeof window !== "undefined" && typeof window.prompt === "function"
          ? window.prompt.bind(window)
          : null;
        if (!nativePrompt) return Promise.resolve(null);
        const fallbackValue = nativePrompt(String(message || ""), String(options?.defaultValue || ""));
        if (fallbackValue === null) return Promise.resolve(null);
        const nextValue = String(fallbackValue || "").trim();
        if (options?.requireValue && !nextValue) return Promise.resolve(null);
        return Promise.resolve(nextValue);
      }
      if (mode === "alert") {
        const nativeAlert = appNativeAlertFn
          || (typeof window !== "undefined" && typeof window.alert === "function"
            ? window.alert.bind(window)
            : null);
        if (nativeAlert) nativeAlert(String(message || ""));
        return Promise.resolve(true);
      }
      return Promise.resolve(window.confirm(String(message || "")));
    } catch (_) {
      return Promise.resolve(mode === "prompt" ? null : mode === "alert");
    }
  }

  const showCancel = mode !== "alert";
  const danger = options?.danger === true;
  const titleText = String(options?.title || "").trim()
    || (mode === "alert"
      ? t("dialog.confirm.title", "Confirm action")
      : t("dialog.confirm.title", "Confirm action"));
  const okText = String(options?.okText || "").trim()
    || (mode === "alert" ? t("dialog.notice.ok", "OK") : t("dialog.confirm.ok", "Confirm"));
  const cancelText = String(options?.cancelText || "").trim() || t("dialog.confirm.cancel", "Cancel");

  if (appConfirmModalBound !== true) {
    appConfirmModalBound = true;
    modal.addEventListener("click", (e) => {
      const target = eventTargetElement(e);
      if (!target) return;
      if (target.dataset?.appConfirmClose) {
        closeAppConfirmModal(appConfirmPromptMode === "alert");
      }
    });
    btnClose.addEventListener("click", () => closeAppConfirmModal(appConfirmPromptMode === "alert"));
    btnCancel.addEventListener("click", () => closeAppConfirmModal(false));
    btnOk.addEventListener("click", () => {
      const { input } = getAppConfirmInputControls();
      if (appConfirmPromptMode === "prompt" && appConfirmPromptOptions?.requireValue) {
        const nextValue = input instanceof HTMLTextAreaElement ? String(input.value || "").trim() : "";
        if (!nextValue) {
          try { input?.focus?.(); } catch (_) {}
          return;
        }
      }
      closeAppConfirmModal(true);
    });
    modal.addEventListener("keydown", (e) => {
      if (e.key === "Escape") {
        e.preventDefault();
        closeAppConfirmModal(appConfirmPromptMode === "alert");
        return;
      }
      if (e.key === "Enter") {
        const { input } = getAppConfirmInputControls();
        if (appConfirmPromptMode === "prompt") {
          if (input instanceof HTMLTextAreaElement && !e.ctrlKey && !e.metaKey) return;
          e.preventDefault();
          if (appConfirmPromptOptions?.requireValue) {
            const nextValue = input instanceof HTMLTextAreaElement ? String(input.value || "").trim() : "";
            if (!nextValue) {
              try { input?.focus?.(); } catch (_) {}
              return;
            }
          }
          closeAppConfirmModal(true);
          return;
        }
        e.preventDefault();
        closeAppConfirmModal(true);
      }
    });
  }

  if (typeof appConfirmPromptResolver === "function") {
    try {
      appConfirmPromptResolver(appConfirmPromptMode === "prompt" ? null : false);
    } catch (_) {}
    appConfirmPromptResolver = null;
  }

  appConfirmPromptMode = mode;
  appConfirmPromptOptions = { ...(options || {}) };
  titleEl.textContent = titleText;
  messageEl.textContent = String(message || "");
  btnOk.textContent = okText;
  btnCancel.textContent = cancelText;
  btnCancel.style.display = showCancel ? "" : "none";
  btnClose.style.display = showCancel ? "" : "none";
  btnOk.classList.toggle("danger", danger);
  btnOk.classList.toggle("primary", !danger);
  if (inputWrap instanceof HTMLElement) {
    const showPromptInput = mode === "prompt";
    inputWrap.hidden = !showPromptInput;
    inputWrap.style.display = showPromptInput ? "" : "none";
  }
  if (inputLabel instanceof HTMLElement) {
    inputLabel.textContent = String(options?.label || "").trim() || t("moderation.prompt.label", "Message");
  }
  if (inputHint instanceof HTMLElement) {
    inputHint.textContent = mode === "prompt"
      ? String(options?.hint || "").trim()
      : "";
  }
  if (inputEl instanceof HTMLTextAreaElement) {
    inputEl.value = mode === "prompt" ? String(options?.defaultValue || "") : "";
    inputEl.placeholder = mode === "prompt" ? String(options?.placeholder || "") : "";
    inputEl.maxLength = Math.max(0, Number(options?.maxLength) || 4000);
    inputEl.disabled = false;
  }

  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");

  requestAnimationFrame(() => {
    if (mode === "prompt" && inputEl instanceof HTMLTextAreaElement) {
      try {
        inputEl.focus();
        inputEl.setSelectionRange(inputEl.value.length, inputEl.value.length);
        return;
      } catch (_) {}
    }
    try { btnOk.focus(); } catch (_) {}
  });

  return new Promise((resolve) => {
    appConfirmPromptResolver = resolve;
  });
}

function requestAppAlert(message = "", options = {}) {
  return requestAppConfirm(message, { ...(options || {}), mode: "alert" });
}

function requestAppPrompt(message = "", options = {}) {
  return requestAppConfirm(message, { ...(options || {}), mode: "prompt" });
}

function installAppAlertShim() {
  if (appAlertShimInstalled) return;
  appAlertShimInstalled = true;
  if (typeof window === "undefined") return;

  try {
    if (typeof window.alert === "function") {
      appNativeAlertFn = window.alert.bind(window);
    }
  } catch (_) {
    appNativeAlertFn = null;
  }

  try {
    window.alert = (message = "") => {
      const text = String(message ?? "");
      if (typeof requestAppAlert === "function") {
        void requestAppAlert(text, {
          okText: t("dialog.notice.ok", "OK"),
        });
        return;
      }
      try { appNativeAlertFn?.(text); } catch (_) {}
    };
  } catch (_) {}
}

installAppAlertShim();

function ensureDmUserListMenu() {
  const clearSubmenuHoverCloseTimer = () => {
    if (dmUserListSubmenuHoverTimer) {
      clearTimeout(dmUserListSubmenuHoverTimer);
      dmUserListSubmenuHoverTimer = null;
    }
  };

  const scheduleSubmenuHoverClose = () => {
    if (dmUserListSubmenuHoverTimer) return;
    dmUserListSubmenuHoverTimer = setTimeout(() => {
      dmUserListSubmenuHoverTimer = null;
      const mainMenu = document.getElementById("dmUserListMenu");
      if (!mainMenu || !mainMenu.classList.contains("is-open")) return;
      closeDmMuteDurationMenu();
      closeDmUserRoleMenu();
    }, 130);
  };

  const getDmUserListSubmenuSide = () => {
    const mainMenu = document.getElementById("dmUserListMenu");
    return String(mainMenu?.dataset?.submenuSide || "right").trim().toLowerCase() === "left"
      ? "left"
      : "right";
  };

  const getDmUserListSubmenuBootstrapPoint = (actionBtn, {
    submenuWidth = 220,
    gap = 2,
  } = {}) => {
    const rect = actionBtn?.getBoundingClientRect?.();
    if (!rect) return { x: 0, y: 0 };
    const side = getDmUserListSubmenuSide();
    const x = side === "left"
      ? Math.round(rect.left - Number(submenuWidth || 220) - Number(gap || 2))
      : Math.round(rect.right + Number(gap || 2));
    const y = Math.round(rect.top - 2);
    return { x, y };
  };

  const alignDmUserListSubmenuToAction = (submenuMenu, actionBtn, {
    fallbackWidth = 220,
    minHeight = 72,
    gap = 2,
  } = {}) => {
    if (!submenuMenu || !actionBtn) return;
    const rect = actionBtn.getBoundingClientRect?.();
    if (!rect) return;
    const side = getDmUserListSubmenuSide();
    const measuredWidth = Math.max(
      180,
      Math.round(
        submenuMenu.offsetWidth
          || submenuMenu.getBoundingClientRect?.().width
          || Number(fallbackWidth || 220)
      )
    );
    const point = {
      x: side === "left"
        ? Math.round(rect.left - measuredWidth - Number(gap || 2))
        : Math.round(rect.right + Number(gap || 2)),
      y: Math.round(rect.top - 2),
    };
    positionMenuAtPoint(submenuMenu, point, { width: measuredWidth, minHeight });
  };

  const openDmUserMuteSubmenuFromAction = (actionBtn, {
    targetId = "",
  } = {}) => {
    const uid = normId(targetId || "");
    if (!actionBtn || !uid) return;
    closeDmUserRoleMenu();
    const point = getDmUserListSubmenuBootstrapPoint(actionBtn, { submenuWidth: 198, gap: 2 });
    openDmMuteDurationMenuAt(point, { targetType: "user", targetId: uid });
    const muteMenu = document.getElementById("dmMuteDurationMenu");
    alignDmUserListSubmenuToAction(muteMenu, actionBtn, {
      fallbackWidth: 198,
      minHeight: 180,
      gap: 2,
    });
  };

  const openDmUserRoleSubmenuFromAction = async (actionBtn, {
    serverId = "",
    userId = "",
    username = "",
    displayName = "",
    avatarUrl = "",
  } = {}) => {
    const sid = normId(serverId || "");
    const uid = normId(userId || "");
    if (!actionBtn || !sid || !uid) return false;
    closeDmMuteDurationMenu();
    const point = getDmUserListSubmenuBootstrapPoint(actionBtn, { submenuWidth: 232, gap: 2 });
    const opened = await openDmUserRoleMenuAt(point, {
      serverId: sid,
      userId: uid,
      username,
      displayName,
      avatarUrl,
    });
    if (!opened) return false;
    const roleMenu = document.getElementById("dmUserRoleMenu");
    alignDmUserListSubmenuToAction(roleMenu, actionBtn, {
      fallbackWidth: 232,
      minHeight: 120,
      gap: 2,
    });
    return true;
  };

  function getDmUserRoleMenuMeta(serverId, targetUserId) {
    const sid = normId(serverId || "");
    const uid = normId(targetUserId || "");
    const base = {
      canOpen: false,
      reason: "",
      hasRoles: false,
      isSelf: false,
      canTouchTarget: false,
    };
    if (!sid || !uid) return base;

    const roleList = serverRoleListByServerId.get(sid) || [];
    const hasRoles = Array.isArray(roleList) && roleList.length > 0;
    const meId = normId(state.user?.id || "");
    const isSelf = !!(meId && uid === meId);
    const caps = getServerCapabilityMeta(sid);
    const moderation = canServerActorModerateTargetWithPermission({
      serverId: sid,
      actorUserId: meId,
      targetUserId: uid,
    });
    const canTouchTarget = !!(isSelf || moderation?.canTouchTarget);
    const canOpen = !!(caps.canSettings && hasRoles && canTouchTarget);

    let reason = "";
    if (!caps.canSettings) reason = "Sem permissao para gerir roles.";
    else if (!hasRoles) reason = "Sem roles custom neste server.";
    else if (!canTouchTarget) reason = "Nao podes gerir roles deste membro.";

    return { canOpen, reason, hasRoles, isSelf, canTouchTarget };
  }

  function buildDmUserRoleMenuHtml(context = {}) {
    const sid = normId(context.serverId || "");
    const uid = normId(context.targetUserId || "");
    const displayName = normalizeConversationLabel(
      context.displayName || context.username || "member",
      "member"
    );
    const roleList = (serverRoleListByServerId.get(sid) || []).slice();
    const roleMap = serverRoleMemberMapByServerId.get(sid) || new Map();
    const meta = getDmUserRoleMenuMeta(sid, uid);
    const disabledAll = !meta.canOpen || dmUserRoleMenuBusy;

    const rows = roleList.map((role) => {
      const rid = normId(role?.id || "");
      if (!rid) return "";
      const assignedSet = roleMap.get(rid);
      const assigned = !!(assignedSet instanceof Set && assignedSet.has(uid));
      const roleName = normalizeServerRoleName(role?.name || "Role") || "Role";
      const roleColor = normalizeServerRoleColor(role?.color || SERVER_ROLE_DEFAULT_COLOR);
      return `
        <button
          class="msgMenu__item${disabledAll ? " is-disabled" : ""}"
          data-user-role-act="toggle_role"
          data-user-role-server-id="${escAttr(sid)}"
          data-user-role-user-id="${escAttr(uid)}"
          data-user-role-role-id="${escAttr(rid)}"
          ${disabledAll ? "disabled" : ""}
        >
          <span class="msgMenuRoleMain">
            <span class="msgMenuRoleSwatch" style="--role-color:${escAttr(roleColor)}"></span>
            <span>${esc(roleName)}</span>
          </span>
          <span class="msgMenuRoleCheck${assigned ? " is-on" : ""}" aria-hidden="true">${assigned ? "&#10003;" : ""}</span>
        </button>
      `;
    }).filter(Boolean);

    return [
      `<div class="msgMenu__meta">${esc(displayName)} â€¢ Roles</div>`,
      `<div class="msgMenu__divider"></div>`,
      rows.length
        ? rows.join("")
        : `<div class="msgMenu__meta">Sem roles custom neste server.</div>`,
      (!meta.canOpen && meta.reason)
        ? `<div class="msgMenu__meta">${esc(meta.reason)}</div>`
        : "",
    ].join("");
  }

  function ensureDmUserRoleMenu() {
    let menu = document.getElementById("dmUserRoleMenu");
    if (!menu) {
      menu = document.createElement("div");
      menu.id = "dmUserRoleMenu";
      menu.className = "msgMenu msgMenu--submenu";
      document.body.appendChild(menu);
    }

    if (dmUserRoleMenuBound) return menu;
    dmUserRoleMenuBound = true;

    document.addEventListener("click", (e) => {
      const target = eventTargetElement(e);
      if (!target) return;
      if (!menu.classList.contains("is-open")) return;
      if (target.closest("#dmUserRoleMenu")) return;
      closeDmUserRoleMenu();
    });
    window.addEventListener("resize", closeDmUserRoleMenu);
    window.addEventListener("scroll", closeDmUserRoleMenu, true);
    document.addEventListener("keydown", (e) => {
      if (e.key === "Escape") closeDmUserRoleMenu();
    });

    menu.addEventListener("click", async (e) => {
      const target = eventTargetElement(e);
      if (!target) return;
      const actionBtn = target.closest("[data-user-role-act]");
      if (!actionBtn || actionBtn.disabled) return;
      e.preventDefault();

      const action = String(actionBtn.getAttribute("data-user-role-act") || "").trim().toLowerCase();
      if (action !== "toggle_role") return;
      if (dmUserRoleMenuBusy) return;

      const sid = normId(actionBtn.getAttribute("data-user-role-server-id") || "");
      const uid = normId(actionBtn.getAttribute("data-user-role-user-id") || "");
      const rid = normId(actionBtn.getAttribute("data-user-role-role-id") || "");
      if (!sid || !uid || !rid) return;

      const roleMap = serverRoleMemberMapByServerId.get(sid) || new Map();
      const assignedSet = roleMap.get(rid);
      const isAssigned = !!(assignedSet instanceof Set && assignedSet.has(uid));

      dmUserRoleMenuBusy = true;
      const res = await setServerRoleMembershipForServer(sid, {
        roleId: rid,
        userId: uid,
        enabled: !isAssigned,
      });
      dmUserRoleMenuBusy = false;

      if (res?.error) {
        alert(`Erro a atualizar role: ${res.error?.message || res.error}`);
        if (dmUserRoleMenuTarget) {
          menu.innerHTML = buildDmUserRoleMenuHtml(dmUserRoleMenuTarget);
        }
        return;
      }

      applyServerRoleMemberAssignment(sid, rid, uid, !isAssigned);
      if (dmUserRoleMenuTarget) {
        menu.innerHTML = buildDmUserRoleMenuHtml(dmUserRoleMenuTarget);
      }

      const activeCtx = getActiveServerContext();
      if (normId(activeCtx?.serverId || "") === sid) {
        const members = serverMemberListByServerId.get(sid) || [];
        void renderServerMembersRightPanel(activeCtx, members);
      }
      if (normId(serverSettingsServerId || "") === sid) {
        renderServerSettingsRolesUi();
      }
    });

    return menu;
  }

  async function openDmUserRoleMenuAt(point, {
    serverId = "",
    userId = "",
    username = "",
    displayName = "",
    avatarUrl = "",
  } = {}) {
    const sid = normId(serverId || "");
    const uid = normId(userId || "");
    if (!sid || !uid || !point) return false;
    await ensureServerRolePermissionCache(sid, { force: false }).catch(() => {});
    const menu = ensureDmUserRoleMenu();
    dmUserRoleMenuTarget = {
      serverId: sid,
      targetUserId: uid,
      username: String(username || "").trim(),
      displayName: String(displayName || "").trim(),
      avatarUrl: String(avatarUrl || "").trim(),
    };
    menu.innerHTML = buildDmUserRoleMenuHtml(dmUserRoleMenuTarget);
    menu.classList.add("is-open");
    positionMenuAtPoint(menu, point, { width: 232, minHeight: 120 });
    return true;
  }

  let menu = document.getElementById("dmUserListMenu");
  if (!menu) {
    menu = document.createElement("div");
    menu.id = "dmUserListMenu";
    menu.className = "msgMenu";
    document.body.appendChild(menu);
  }

  if (dmUserListMenuBound) return menu;
  dmUserListMenuBound = true;

  document.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    if (!menu.classList.contains("is-open")) return;
    if (target.closest("#dmUserListMenu")) return;
    if (target.closest("#dmMuteDurationMenu")) return;
    if (target.closest("#dmUserRoleMenu")) return;
    closeDmUserListMenu();
  });

  document.addEventListener("mousemove", (e) => {
    if (!menu.classList.contains("is-open")) {
      clearSubmenuHoverCloseTimer();
      return;
    }
    const target = eventTargetElement(e);
    const insideAnyMenu = !!(
      target
      && (
        target.closest("#dmUserListMenu")
        || target.closest("#dmMuteDurationMenu")
        || target.closest("#dmUserRoleMenu")
      )
    );
    if (insideAnyMenu) clearSubmenuHoverCloseTimer();
    else scheduleSubmenuHoverClose();
  });

  window.addEventListener("resize", closeDmListMenus);
  window.addEventListener("scroll", closeDmListMenus, true);
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeDmListMenus();
  });

  menu.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const actionBtn = target.closest("[data-user-list-act]");
    if (!actionBtn || actionBtn.disabled) return;
    e.preventDefault();

    const action = String(actionBtn.getAttribute("data-user-list-act") || "").trim().toLowerCase();
    const uid = normId(actionBtn.getAttribute("data-user-list-id") || "");
    const uname = String(actionBtn.getAttribute("data-user-list-username") || "").trim();
    const row = getFriendRowByUserId(uid) || getFriendRowByUsername(uname) || null;
    const resolvedUid = normId(uid || row?.other_user_id || row?.id || "");
    const resolvedUname = String(uname || row?.username || "").trim();
    const display = String(actionBtn.getAttribute("data-user-list-display") || row?.display_name || uname || "User");
    const avatar = String(actionBtn.getAttribute("data-user-list-avatar") || row?.avatar_url || "").trim();
    const serverIdAttr = normId(actionBtn.getAttribute("data-user-list-server-id") || "");
    let serverVoiceConvId = normId(actionBtn.getAttribute("data-user-list-server-voice-conv") || "");
    if (!resolvedUid && !resolvedUname) return;

    if (action === "mark_read") {
      closeDmListMenus();
      clearDmUnreadForUser(resolvedUid);
      return;
    }
    if (action === "profile") {
      closeDmListMenus();
      const anchorPoint = { x: e.clientX || 0, y: e.clientY || 0 };
      await openUserCardModal(resolvedUid, {
        username: resolvedUname,
        display_name: display,
        avatar_url: avatar,
      }, {
        point: anchorPoint,
        conversationId: serverVoiceConvId,
        conversationLabel: String(state.activeDm?.displayName || "").trim(),
        serverId: serverIdAttr,
        kind: serverIdAttr ? "server" : "",
        presentation: "overlay",
      });
      return;
    }
    if (action === "start_call") {
      closeDmListMenus();
      const conversationId = await startDmWith(resolvedUname, display, avatar || null, resolvedUid);
      if (conversationId) await startCall(conversationId, resolvedUid, display || resolvedUname || t("call.friend", "friend"));
      return;
    }
    if (action === "toggle_bestfriend") {
      closeDmListMenus();
      toggleDmBestFriend(resolvedUid, { rerender: false });
      renderFriends();
      void loadDmList().catch(() => { reorderDmListByActivity(); });
      return;
    }
    if (action === "edit_nickname") {
      closeDmListMenus();
      if (!resolvedUid) return;
      const currentNickname = getDmFriendNickname(resolvedUid);
      const seedName = display || resolvedUname || "user";
      const nextRaw = await requestDmFriendNickname(seedName, currentNickname || "");
      if (nextRaw === null) return;
      setDmFriendNickname(resolvedUid, nextRaw, { persist: true, syncCloud: true });
      renderFriends();
      void loadDmList().catch(() => { reorderDmListByActivity(); });
      return;
    }
    if (action === "close_dm") {
      closeDmListMenus();
      hideDmUser(resolvedUid, { rerender: true });
      return;
    }
    if (action === "remove_friend") {
      if (!resolvedUid) return;
      closeDmListMenus();
      const label = display || resolvedUname || "este amigo";
      const ok = await requestAppConfirm(`Remover ${label} dos amigos?`, {
        title: "Friends",
        okText: t("dialog.confirm.ok", "Confirm"),
        cancelText: t("dialog.confirm.cancel", "Cancel"),
        danger: true,
      });
      if (!ok) return;
      const trace = beginRelationshipActionTrace("remove_friend", {
        userId: resolvedUid,
        username: resolvedUname,
      });

      // â”€â”€ TRUE OPTIMISTIC: patch immediately after confirm, before RPC â”€â”€
      const snapshot = relationshipTraceMeasureSync(trace, "snapshotRelationshipState", () => (
        snapshotRelationshipState({ targetUserId: resolvedUid })
      ));
      relationshipTraceMeasureSync(trace, "optimisticPatch", () => {
        optimisticRemoveFriendById(resolvedUid);
        hideDmUser(resolvedUid, { rerender: false });
        clearDmUnreadForUser(resolvedUid);
      });
      renderRelationshipUiNow({
        rerenderFriends: true,
        rerenderPending: true,
        affectedUserId: resolvedUid,
        affectedUsername: resolvedUname,
      });
      relationshipTraceSchedulePaint(trace, "optimisticPaint");
      // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

      const { error } = await relationshipTraceMeasureAsync(trace, "rpc:remove_friend", () => (
        removeFriendRpc(resolvedUid)
      ));
      if (error) {
        restoreRelationshipState(snapshot, {
          rerenderFriends: true,
          rerenderPending: true,
          rerenderDmList: true,
          affectedUserId: resolvedUid,
          affectedUsername: resolvedUname,
        });
        relationshipTraceSchedulePaint(trace, "rollbackPaint");
        endRelationshipTrace(trace, "rpc_error", { message: String(error?.message || error || "") });
        if (isMissingRpcError(error)) {
          const proj = getSupabaseProjectRefLabel();
          await requestAppAlert(
            `Falta SQL para remover amigos no Supabase (proj: ${proj}).\n` +
            "Executa o patch SQL: SQL/SUPABASE_PATCH_FRIEND_BLOCK_REMOVE.sql\n" +
            "e depois recarrega a app.",
            { title: "Friends", okText: t("dialog.notice.ok", "OK") }
          );
        } else {
          await requestAppAlert(`Erro ao remover amigo: ${error.message || error}`, {
            title: "Friends",
            okText: t("dialog.notice.ok", "OK"),
          });
        }
        return;
      }
      deferRelationshipTraceToReconcile(trace, { delayMs: 180 });
      scheduleRelationshipReconcile(180, trace);
      return;
    }
    if (action === "block_user") {
      if (!resolvedUid) return;
      closeDmListMenus();
      const label = display || resolvedUname || "este utilizador";
      const ok = await requestAppConfirm(`Bloquear ${label}?\nIsto remove a amizade e pedidos entre voces.`, {
        title: "Block User",
        okText: t("dialog.confirm.ok", "Confirm"),
        cancelText: t("dialog.confirm.cancel", "Cancel"),
        danger: true,
      });
      if (!ok) return;
      const trace = beginRelationshipActionTrace("block_user", {
        userId: resolvedUid,
        username: resolvedUname,
      });

      // â”€â”€ TRUE OPTIMISTIC: patch immediately after confirm, before RPC â”€â”€
      const snapshot = relationshipTraceMeasureSync(trace, "snapshotRelationshipState", () => (
        snapshotRelationshipState({ targetUserId: resolvedUid, includeBlockedUsers: true })
      ));
      relationshipTraceMeasureSync(trace, "optimisticPatch", () => {
        optimisticRemoveFriendById(resolvedUid);
        upsertBlockedUserRow({
          userId: resolvedUid,
          username: resolvedUname,
          displayName: display || resolvedUname || "User",
          avatarUrl: avatar || null,
          createdAt: new Date().toISOString(),
        });
        hideDmUser(resolvedUid, { rerender: false });
        clearDmUnreadForUser(resolvedUid);
      });
      renderRelationshipUiNow({
        rerenderFriends: true,
        rerenderPending: true,
        rerenderBlockedSettings: settingsActiveTab === "blocked-users",
        affectedUserId: resolvedUid,
        affectedUsername: resolvedUname,
      });
      relationshipTraceSchedulePaint(trace, "optimisticPaint");
      // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

      const { error } = await relationshipTraceMeasureAsync(trace, "rpc:block_user", () => (
        blockUserRpc(resolvedUid)
      ));
      if (error) {
        restoreRelationshipState(snapshot, {
          rerenderFriends: true,
          rerenderPending: true,
          rerenderBlockedSettings: settingsActiveTab === "blocked-users",
          rerenderDmList: true,
          affectedUserId: resolvedUid,
          affectedUsername: resolvedUname,
        });
        relationshipTraceSchedulePaint(trace, "rollbackPaint");
        endRelationshipTrace(trace, "rpc_error", { message: String(error?.message || error || "") });
        const missingSql = isMissingRpcError(error) || isMissingTableError(error, "user_blocks");
        if (missingSql) {
          const proj = getSupabaseProjectRefLabel();
          await requestAppAlert(
            `Falta SQL para bloqueios no Supabase (proj: ${proj}).\n` +
            "Executa o patch SQL: SQL/SUPABASE_PATCH_FRIEND_BLOCK_REMOVE.sql\n" +
            "e depois recarrega a app.",
            { title: "Block User", okText: t("dialog.notice.ok", "OK") }
          );
        } else {
          await requestAppAlert(`Erro ao bloquear utilizador: ${error.message || error}`, {
            title: "Block User",
            okText: t("dialog.notice.ok", "OK"),
          });
        }
        return;
      }
      deferRelationshipTraceToReconcile(trace, { delayMs: 180 });
      scheduleRelationshipReconcile(180, trace);
      return;
    }
    if (action === "report_user") {
      if (!resolvedUid) return;
      closeDmListMenus();
      openReportUserModal(resolvedUid, resolvedUname, display);
      return;
    }
    if (action === "mute_open") {
      openDmUserMuteSubmenuFromAction(actionBtn, { targetId: resolvedUid });
      return;
    }
    if (action === "open_server_roles_menu") {
      if (!resolvedUid || !serverIdAttr) return;
      await openDmUserRoleSubmenuFromAction(actionBtn, {
        serverId: serverIdAttr,
        userId: resolvedUid,
        username: resolvedUname,
        displayName: display,
        avatarUrl: avatar,
      });
      return;
    }
    if (action === "open_server_voice_menu") {
      if (!resolvedUid || !serverIdAttr) return;
      if (!serverVoiceConvId) {
        serverVoiceConvId = resolveServerVoiceMenuConversationForMember(serverIdAttr, resolvedUid);
      }
      if (!serverVoiceConvId) {
        closeDmListMenus();
        alert("Nao encontrei canal de voz neste server para abrir os controlos.");
        return;
      }
      await ensureServerRolePermissionCache(serverIdAttr, { force: false }).catch(() => {});
      const submenuPoint = getDmUserListSubmenuBootstrapPoint(actionBtn, { submenuWidth: 262, gap: 2 });
      closeDmListMenus();
      tryOpenServerVoiceMemberMenuAt(resolvedUid, serverVoiceConvId, {
        x: submenuPoint.x,
        y: submenuPoint.y,
      }, {
        displayName: display,
        serverId: serverIdAttr,
      });
      return;
    }
    if (action === "copy_user_id") {
      closeDmListMenus();
      await copyTextWithPromptFallback(resolvedUid, "User ID");
      return;
    }
    if (action === "copy_channel_id") {
      closeDmListMenus();
      try {
        const convId = await ensureFriendConversationId(resolvedUid, resolvedUname);
        if (convId) await copyTextWithPromptFallback(convId, "Channel ID");
      } catch (err) {
        alert(`Erro a copiar channel id: ${err?.message || err}`);
      }
      return;
    }
  });

  menu.addEventListener("mouseover", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    clearSubmenuHoverCloseTimer();
    const roleBtn = target.closest("[data-user-list-act='open_server_roles_menu']");
    if (roleBtn && !roleBtn.disabled) {
      const uid = normId(roleBtn.getAttribute("data-user-list-id") || "");
      const sid = normId(roleBtn.getAttribute("data-user-list-server-id") || "");
      const username = String(roleBtn.getAttribute("data-user-list-username") || "").trim();
      const display = String(roleBtn.getAttribute("data-user-list-display") || username).trim();
      const avatar = String(roleBtn.getAttribute("data-user-list-avatar") || "").trim();
      if (uid && sid) {
        void openDmUserRoleSubmenuFromAction(roleBtn, {
          serverId: sid,
          userId: uid,
          username,
          displayName: display,
          avatarUrl: avatar,
        });
      }
      return;
    }
    if (target.closest("[data-user-list-act]")) {
      closeDmUserRoleMenu();
      closeDmMuteDurationMenu();
    }
    const actionBtn = target.closest("[data-user-list-act='mute_open']");
    if (!actionBtn || actionBtn.disabled) return;
    const uid = normId(actionBtn.getAttribute("data-user-list-id") || "");
    if (!uid) return;
    openDmUserMuteSubmenuFromAction(actionBtn, { targetId: uid });
  });

  menu.addEventListener("focusin", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    clearSubmenuHoverCloseTimer();
    const roleBtn = target.closest("[data-user-list-act='open_server_roles_menu']");
    if (roleBtn && !roleBtn.disabled) {
      const uid = normId(roleBtn.getAttribute("data-user-list-id") || "");
      const sid = normId(roleBtn.getAttribute("data-user-list-server-id") || "");
      const username = String(roleBtn.getAttribute("data-user-list-username") || "").trim();
      const display = String(roleBtn.getAttribute("data-user-list-display") || username).trim();
      const avatar = String(roleBtn.getAttribute("data-user-list-avatar") || "").trim();
      if (uid && sid) {
        void openDmUserRoleSubmenuFromAction(roleBtn, {
          serverId: sid,
          userId: uid,
          username,
          displayName: display,
          avatarUrl: avatar,
        });
      }
      return;
    }
    if (target.closest("[data-user-list-act]")) {
      closeDmUserRoleMenu();
      closeDmMuteDurationMenu();
    }
    const actionBtn = target.closest("[data-user-list-act='mute_open']");
    if (!actionBtn || actionBtn.disabled) return;
    const uid = normId(actionBtn.getAttribute("data-user-list-id") || "");
    if (!uid) return;
    openDmUserMuteSubmenuFromAction(actionBtn, { targetId: uid });
  });

  return menu;
}

function openDmUserListMenuAt({
  userId,
  username = "",
  displayName = "",
  avatarUrl = "",
  point,
  serverVoiceMenu = null,
} = {}) {
  const uid = normId(userId);
  if ((!uid && !username) || !point) return;
  closeMessageMenu();
  closeGroupMemberMenu();
  closeGroupDmListMenu();
  closeDmMuteDurationMenu();
  closeDmUserRoleMenu();
  const menu = ensureDmUserListMenu();
  const muted = isDmUserMuted(uid);
  const bestFriend = isDmBestFriend(uid);
  const currentNickname = getDmFriendNickname(uid);
  const muteLabel = `Mute @${displayName || username || "user"}`;
  const bestFriendLabel = bestFriend ? "Remove Best Friend" : "Mark As Best Friend";
  const nickLabel = currentNickname ? `Change Friend Nickname (${currentNickname})` : "Change Friend Nickname";
  const serverVoiceServerId = normId(serverVoiceMenu?.serverId || "");
  const serverVoiceConversationId = normId(serverVoiceMenu?.conversationId || "");
  const canOpenServerVoiceMenu = !!serverVoiceServerId;
  const submenuSide = serverVoiceServerId ? "left" : "right";
  const submenuChevron = submenuSide === "left" ? "&#x2039;" : "&#x203A;";
  const roleList = serverVoiceServerId ? (serverRoleListByServerId.get(serverVoiceServerId) || []) : [];
  const meId = normId(state.user?.id || "");
  const friendRow = getFriendRowByUserId(uid) || getFriendRowByUsername(username) || null;
  const isFriend = !!friendRow;
  const isSelfTarget = !!uid && uid === meId;
  const canRemoveFriend = !!uid && isFriend && !isSelfTarget;
  const canBlockUser = !!uid && !isSelfTarget;
  let removeFriendHint = "";
  if (!canRemoveFriend) {
    if (isSelfTarget) removeFriendHint = "Nao podes remover a tua propria conta.";
    else if (!isFriend) removeFriendHint = "Este utilizador nao esta na tua lista de amigos.";
    else removeFriendHint = "Nao e possivel remover este utilizador agora.";
  }
  let blockUserHint = "";
  if (!canBlockUser) {
    if (isSelfTarget) blockUserHint = "Nao podes bloquear a tua propria conta.";
    else blockUserHint = "Nao e possivel bloquear este utilizador agora.";
  }
  const caps = getServerCapabilityMeta(serverVoiceServerId);
  const roleModeration = canServerActorModerateTargetWithPermission({
    serverId: serverVoiceServerId,
    actorUserId: meId,
    targetUserId: uid,
  });
  const canOpenServerRolesMenu = !!(
    serverVoiceServerId
    && caps?.canSettings
    && roleList.length
    && (uid === meId || roleModeration?.canTouchTarget)
  );
  let roleMenuHint = "";
  if (serverVoiceServerId && !canOpenServerRolesMenu) {
    if (!caps?.canSettings) roleMenuHint = "Sem permissao para gerir roles.";
    else if (!roleList.length) roleMenuHint = "Sem roles custom.";
    else roleMenuHint = "Nao podes gerir roles deste membro.";
  }

  menu.innerHTML = [
    `<button class="msgMenu__item" data-user-list-act="mark_read" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}"><span>Mark As Read</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item" data-user-list-act="profile" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}"><span>Profile</span></button>`,
    `<button class="msgMenu__item" data-user-list-act="start_call" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}"><span>Start a Call</span></button>`,
    `<button class="msgMenu__item" data-user-list-act="toggle_bestfriend" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}"><span>${esc(bestFriendLabel)}</span><span>&#x1F4CC;</span></button>`,
    `<button class="msgMenu__item is-disabled" type="button" disabled><span class="msgMenu__itemMain"><span>Add Note</span><span class="msgMenu__itemHint">Only visible to you</span></span></button>`,
    `<button class="msgMenu__item" data-user-list-act="edit_nickname" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}"><span>${esc(nickLabel)}</span></button>`,
    `<button class="msgMenu__item" data-user-list-act="close_dm" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}"><span>Close DM</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item is-disabled" type="button" disabled><span class="msgMenu__itemMain"><span>Invite to Listen Along</span><span class="msgMenu__itemHint">Spotify</span></span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item is-disabled" type="button" disabled><span>Apps</span><span>${submenuChevron}</span></button>`,
    `<button class="msgMenu__item is-disabled" type="button" disabled><span>Invite to Server</span><span>${submenuChevron}</span></button>`,
    `<button class="msgMenu__item${canRemoveFriend ? "" : " is-disabled"}" data-user-list-act="remove_friend" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}" ${canRemoveFriend ? "" : "disabled"}><span class="msgMenu__itemMain"><span>Remove Friend</span>${removeFriendHint ? `<span class="msgMenu__itemHint">${esc(removeFriendHint)}</span>` : ""}</span></button>`,
    `<button class="msgMenu__item is-disabled" type="button" disabled><span>Ignore</span></button>`,
    `<button class="msgMenu__item msgMenu__item--danger${canBlockUser ? "" : " is-disabled"}" data-user-list-act="report_user" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}" ${canBlockUser ? "" : "disabled"}><span class="msgMenu__itemMain"><span>Report</span></span></button>`,
    `<button class="msgMenu__item msgMenu__item--danger${canBlockUser ? "" : " is-disabled"}" data-user-list-act="block_user" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}" ${canBlockUser ? "" : "disabled"}><span class="msgMenu__itemMain"><span>Block</span>${blockUserHint ? `<span class="msgMenu__itemHint">${esc(blockUserHint)}</span>` : ""}</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item" data-user-list-act="mute_open" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}"><span class="msgMenu__itemMain"><span>${esc(muteLabel)}</span>${muted ? '<span class="msgMenu__itemHint">Mute ativo</span>' : ''}</span><span>${submenuChevron}</span></button>`,
    serverVoiceServerId
      ? `<button class="msgMenu__item${canOpenServerRolesMenu ? "" : " is-disabled"}" data-user-list-act="open_server_roles_menu" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}" data-user-list-server-id="${escAttr(serverVoiceServerId)}" ${canOpenServerRolesMenu ? "" : "disabled"}><span class="msgMenu__itemMain"><span>Roles</span>${roleMenuHint ? `<span class="msgMenu__itemHint">${esc(roleMenuHint)}</span>` : ""}</span><span>${submenuChevron}</span></button>`
      : "",
    `<button class="msgMenu__item${canOpenServerVoiceMenu ? "" : " is-disabled"}" data-user-list-act="open_server_voice_menu" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}" data-user-list-server-id="${escAttr(serverVoiceServerId)}" data-user-list-server-voice-conv="${escAttr(serverVoiceConversationId)}" ${canOpenServerVoiceMenu ? "" : "disabled"}><span>Server Voice Controls</span><span>${submenuChevron}</span></button>`,
    `<div class="msgMenu__divider"></div>`,
    `<button class="msgMenu__item" data-user-list-act="copy_user_id" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}"><span>Copy User ID</span><span class="msgMenu__kbd">ID</span></button>`,
    `<button class="msgMenu__item" data-user-list-act="copy_channel_id" data-user-list-id="${escAttr(uid)}" data-user-list-username="${escAttr(username)}" data-user-list-display="${escAttr(displayName)}" data-user-list-avatar="${escAttr(avatarUrl)}"><span>Copy Channel ID</span><span class="msgMenu__kbd">ID</span></button>`,
  ].join("");

  menu.classList.add("is-open");
  menu.dataset.submenuSide = submenuSide;
  dmUserListMenuTargetUserId = uid;
  positionMenuAtPoint(menu, point, { width: 262, minHeight: 280 });
}

function renderDmGroupMembersPanel(members = [], { loading = false } = {}) {
  const panel = document.getElementById("dmProfilePanel");
  const titleEl = document.querySelector("#dmProfilePanel .dmProfilePanel__title");
  const bannerEl = document.getElementById("dmProfileBanner");
  const avatarEl = document.getElementById("dmProfileAvatar");
  const bodyEl = document.querySelector("#dmProfilePanel .dmProfilePanel__body");
  const footerEl = document.querySelector("#dmProfilePanel .dmProfilePanel__footer");
  const nameEl = document.getElementById("dmProfileName");
  const handleEl = document.getElementById("dmProfileHandle");
  const statusWrap = document.querySelector("#dmProfilePanel .dmProfilePresence");
  const bioWrap = document.querySelector("#dmProfilePanel .dmProfileSection");
  const widgetsPreviewEl = document.getElementById("dmProfileWidgetsPreview");
  const btnOpen = document.getElementById("btnDmProfileOpenCard");
  if (!panel || !bodyEl) return;

  let membersBody = document.getElementById("dmGroupMembersBody");
  if (!membersBody) {
    membersBody = document.createElement("div");
    membersBody.id = "dmGroupMembersBody";
    membersBody.className = "dmGroupMembersBody";
    membersBody.style.display = "none";
    bodyEl.appendChild(membersBody);
  }

  const list = Array.isArray(members) ? members : [];
  const count = list.length;
  panel.classList.add("is-group-members");
  if (titleEl) titleEl.textContent = `Members - ${count}`;
  if (bannerEl) bannerEl.style.display = "none";
  if (avatarEl) avatarEl.style.display = "none";
  if (nameEl) nameEl.style.display = "none";
  if (handleEl) handleEl.style.display = "none";
  if (statusWrap) statusWrap.style.display = "none";
  if (bioWrap) bioWrap.style.display = "none";
  if (widgetsPreviewEl) {
    widgetsPreviewEl.classList.add("hidden");
    widgetsPreviewEl.setAttribute("aria-hidden", "true");
    widgetsPreviewEl.innerHTML = "";
  }
  if (footerEl) footerEl.style.display = "none";
  if (btnOpen) btnOpen.style.display = "none";
  membersBody.style.display = "block";

  if (loading) {
    membersBody.innerHTML = `<div class="hint">${t("app.loading", "Loading...")}</div>`;
    return;
  }

  if (!list.length) {
    membersBody.innerHTML = `<div class="hint">${t("dm.no_members", "No members to show.")}</div>`;
    return;
  }

  const meId = normId(state.user?.id || "");
  membersBody.innerHTML = `
    <div class="dmGroupMembersList">
      ${list.map((m) => {
    const uid = normId(m?.userId || "");
    const isMe = uid === meId;
    const status = getPresenceStatusForUser(uid) || "offline";
    const nameColorAttrs = buildUserNameColorAttrs(uid, m?.nameColor || "");
    const avatarHtml = m?.avatarUrl
      ? buildAvatarMediaHtml(m.avatarUrl, { userId: uid, alt: m.displayName || m.username || "avatar", loading: "lazy" })
      : `<span class="groupDmAvatarFallback">${esc(String(m?.displayName || m?.username || "?").trim().charAt(0).toUpperCase() || "?")}</span>`;
    return `
        <button
          class="dmGroupMemberRow${isMe ? " is-me" : ""}"
          type="button"
          data-group-member-id="${escAttr(uid)}"
          title="${escAttr(isMe ? t("usercard.you", "You") : t("group.right_click_ring", "Right-click to ring"))}"
        >
          <span class="dmGroupMemberRow__avatar">${avatarHtml}<span class="statusDot" data-status="${escAttr(status)}"></span></span>
          <span class="dmGroupMemberRow__text">
            <span class="dmGroupMemberRow__name${nameColorAttrs.cls}"${nameColorAttrs.style}>${esc(m?.displayName || m?.username || t("call.member", "member"))}${isMe ? t("group.you_suffix", " (you)") : ""}</span>
            <span class="dmGroupMemberRow__handle">@${esc(m?.username || "user")}</span>
          </span>
        </button>
      `;
  }).join("")}
    </div>
  `;
}

function buildDmProfileWidgetsPreviewHtml(widgets = [], {
  loading = false,
  error = "",
} = {}) {
  const safeWidgets = Array.isArray(widgets) ? widgets.filter((widget) => !!widget) : [];
  const previewWidgets = safeWidgets
    .map((widget) => {
      const items = Array.isArray(widget?.items) ? widget.items : [];
      const featured = getProfileWidgetFeaturedItem(widget);
      const item = featured || items[0] || null;
      return { widget, item, itemCount: items.length };
    })
    .filter((entry) => entry.item || entry.itemCount)
    .slice(0, 2);

  if (!previewWidgets.length) {
    if (loading) {
      return `
        <section class="dmProfileWidgetsPreviewShell" aria-label="${escAttr(t("profile.widgets.eyebrow", "Widgets"))}">
          <div class="dmProfileWidgetsPreviewTitle">${esc(t("profile.widgets.eyebrow", "Widgets"))}</div>
          <div class="dmProfileWidgetsPreviewLoading">${esc(t("profile.widgets.loading.text", "Fetching profile interests."))}</div>
        </section>
      `;
    }
    if (error) {
      return `
        <section class="dmProfileWidgetsPreviewShell" aria-label="${escAttr(t("profile.widgets.eyebrow", "Widgets"))}">
          <div class="dmProfileWidgetsPreviewTitle">${esc(t("profile.widgets.eyebrow", "Widgets"))}</div>
          <div class="dmProfileWidgetsPreviewLoading">${esc(error)}</div>
        </section>
      `;
    }
    return "";
  }

  return `
    <section class="dmProfileWidgetsPreviewShell" aria-label="${escAttr(t("profile.widgets.eyebrow", "Widgets"))}">
      <div class="dmProfileWidgetsPreviewTitle">${esc(t("profile.widgets.eyebrow", "Widgets"))}</div>
      <div class="dmProfileWidgetPreviewList">
        ${previewWidgets.map(({ widget, item, itemCount }) => {
    const typeLabel = getProfileWidgetTypeLabel(widget?.widget_type || "");
    const title = normalizeProfileWidgetTitle(item?.title || widget?.title || "") || t("profile.widgets.item.untitled", "Untitled");
    const coverUrl = normalizeCatalogCoverUrl(item?.cover_url || "");
    const metaText = itemCount > 1
      ? t("profile.widgets.preview.more", "{count} items").replace("{count}", String(itemCount))
      : (normalizeProfileWidgetTitle(widget?.title || "") || typeLabel);
    const mediaHtml = coverUrl
      ? `<img src="${escAttr(coverUrl)}" alt="" loading="lazy" />`
      : `<span>${esc(String(title).charAt(0).toUpperCase() || "?")}</span>`;
    return `
          <button class="dmProfileWidgetPreviewCard" type="button" data-dm-profile-widget-preview="1">
            <span class="dmProfileWidgetPreviewMedia">${mediaHtml}</span>
            <span class="dmProfileWidgetPreviewBody">
              <span class="dmProfileWidgetPreviewBadge">${esc(typeLabel)}</span>
              <span class="dmProfileWidgetPreviewName">${esc(title)}</span>
              <span class="dmProfileWidgetPreviewMeta">${esc(metaText)}</span>
            </span>
          </button>
        `;
  }).join("")}
      </div>
    </section>
  `;
}

function renderDmProfileWidgetsPreview(userId = "", widgets = [], {
  loading = false,
  error = "",
} = {}) {
  const el = document.getElementById("dmProfileWidgetsPreview");
  if (!el) return;
  const uid = normId(userId || "");
  const html = buildDmProfileWidgetsPreviewHtml(widgets, { loading, error });
  el.innerHTML = html;
  el.dataset.userId = uid;
  el.classList.toggle("hidden", !html);
  el.setAttribute("aria-hidden", html ? "false" : "true");
}

async function openDmGroupMembersPanel({ force = false } = {}) {
  if (!activeDmId) return;
  const convId = normId(activeDmId);
  if (!convId) return;
  bindDmProfilePanelOnce();

  dmPinsPanelOpen = false;
  dmProfilePanelOpen = true;
  setDmSidePanelMode("profile");
  syncDmPinsPanelState();
  renderDmGroupMembersPanel([], { loading: true });

  const members = await fetchGroupConversationMembers(convId, { force });
  if (!dmProfilePanelOpen || normId(activeDmId) !== convId) return;
  renderDmGroupMembersPanel(members, { loading: false });
}

function renderDmProfilePanel(profile = {}, { loading = false } = {}) {
  const uid = String(profile?.id || "").trim();
  const canonicalName = profile?.display_name || profile?.username || "User";
  const username = profile?.username || "user";
  const bio = String(profile?.bio || "").trim();
  const avatarFallback = state.activeDm?.avatarUrl || state.activeDm?.avatar_url || getCachedProfile(uid)?.avatar_url || getCachedProfile(uid)?.avatarUrl || "";
  const avatarUrl = resolveProfileAvatarUrl(profile?.avatar_url || profile?.avatarUrl || "", avatarFallback) || "";
  const status = uid ? getPresenceStatusForUser(uid) : "offline";
  const nameColor = resolveUserNameColor(uid, profile?.name_color);
  const tileColor = resolveCallTileColor(uid, profile?.call_tile_color);
  const bannerUrl = resolveUserBannerUrl(uid, profile?.banner_url || profile?.theme_settings?.banner_url || "");
  const selfId = normId(state.user?.id || "");
  const isSelf = !!(uid && selfId && uid === selfId);
  const friendNickname = isSelf ? "" : getDmFriendNickname(uid);
  const hasFriendNickname = !!friendNickname;
  const name = hasFriendNickname ? friendNickname : canonicalName;
  const initial = String(name || "?").trim().charAt(0).toUpperCase() || "?";

  const bannerEl = document.getElementById("dmProfileBanner");
  const avatarEl = document.getElementById("dmProfileAvatar");
  const nameEl = document.getElementById("dmProfileName");
  const handleEl = document.getElementById("dmProfileHandle");
  const statusDotEl = document.getElementById("dmProfileStatusDot");
  const statusTextEl = document.getElementById("dmProfileStatusText");
  const bioEl = document.getElementById("dmProfileBio");
  const panel = document.getElementById("dmProfilePanel");
  const titleEl = document.querySelector("#dmProfilePanel .dmProfilePanel__title");
  const footerEl = document.querySelector("#dmProfilePanel .dmProfilePanel__footer");
  const membersBody = document.getElementById("dmGroupMembersBody");
  const statusWrap = document.querySelector("#dmProfilePanel .dmProfilePresence");
  const bioWrap = document.querySelector("#dmProfilePanel .dmProfileSection");
  const widgetsPreviewEl = document.getElementById("dmProfileWidgetsPreview");
  const btnOpen = document.getElementById("btnDmProfileOpenCard");

  if (panel) panel.classList.remove("is-group-members");
  if (titleEl) titleEl.textContent = "Profile";
  if (bannerEl) bannerEl.style.display = "";
  if (avatarEl) avatarEl.style.display = "";
  if (nameEl) nameEl.style.display = "";
  if (handleEl) handleEl.style.display = "";
  if (statusWrap) statusWrap.style.display = "";
  if (bioWrap) bioWrap.style.display = "";
  if (widgetsPreviewEl) widgetsPreviewEl.style.display = "";
  if (footerEl) footerEl.style.display = "";
  if (btnOpen) btnOpen.style.display = "";
  if (membersBody) {
    membersBody.style.display = "none";
    membersBody.innerHTML = "";
  }

  if (bannerEl) {
    const base = tileColor || "#344976";
    const start = mixHex(base, "#111827", 0.74);
    const end = mixHex(base, "#0b1018", 0.9);
    const glow = rgbaFromHex(base, 0.24);
    applyBannerStyle(bannerEl, bannerUrl, start, end, glow, {
      overlay: "none",
      userId: uid,
      profile,
    });
    bannerEl.classList.toggle("has-image", !!normalizeBannerUrl(bannerUrl));
  }
  if (avatarEl) {
    avatarEl.innerHTML = avatarUrl
      ? buildAvatarMediaHtml(avatarUrl, { userId: uid, profile, alt: "avatar", loading: "lazy", controlledGif: true })
      : `<span class="msg__avatarFallback">${esc(initial)}</span>`;
    queueManagedGifPlaybackSync(avatarEl);
  }
  if (nameEl) {
    nameEl.textContent = name;
    nameEl.classList.toggle("is-nickname", hasFriendNickname);
    nameEl.classList.toggle("userNameCustom", !!nameColor);
    if (nameColor) nameEl.style.setProperty("--user-name-color", nameColor);
    else nameEl.style.removeProperty("--user-name-color");
  }
  if (handleEl) {
    if (hasFriendNickname) {
      const canonicalLower = String(canonicalName || "").trim().toLowerCase();
      const usernameLower = String(username || "").trim().toLowerCase();
      const showCanonical = !!(canonicalLower && canonicalLower !== usernameLower);
      if (showCanonical && username) handleEl.textContent = `${canonicalName} â€¢ @${username}`;
      else if (showCanonical) handleEl.textContent = canonicalName;
      else handleEl.textContent = `@${username || "user"}`;
      handleEl.classList.add("is-nickname");
    } else {
      handleEl.textContent = `@${username || "user"}`;
      handleEl.classList.remove("is-nickname");
    }
  }
  if (statusDotEl) statusDotEl.setAttribute("data-status", status || "offline");
  if (statusTextEl) statusTextEl.textContent = dmStatusLabel(status);
  if (bioEl) bioEl.textContent = bio || (loading ? t("app.loading", "Loading...") : t("dm.no_bio", "No bio."));
  renderDmProfileWidgetsPreview(uid, getCachedProfileWidgetsForUser(uid), { loading });
}

function refreshDmProfilePanel() {
  if (!dmProfilePanelOpen || !activeDmId) return;
  const activeMeta = getActiveConversationMeta(activeDmId) || {};
  const isServerConversation = isServerConversationKind(activeMeta?.kind) || !!normId(activeMeta?.serverId || "");
  if (isServerConversation) {
    dmProfilePanelOpen = false;
    if (!dmPinsPanelOpen) setDmSidePanelMode("none");
    syncDmPinsPanelState();
    return;
  }
  if (isGroupConversationMeta(activeMeta)) {
    const members = getGroupConversationMembersCache(activeDmId);
    renderDmGroupMembersPanel(members, { loading: !members.length });
    return;
  }
  const seed = getDmPeerProfileSeed();
  if (!seed) return;
  renderDmProfilePanel(seed, { loading: false });
}

async function openDmProfilePanel({ force = false } = {}) {
  if (!activeDmId) return;
  const activeMeta = getActiveConversationMeta(activeDmId) || {};
  const isServerConversation = isServerConversationKind(activeMeta?.kind) || !!normId(activeMeta?.serverId || "");
  if (isServerConversation) {
    dmProfilePanelOpen = false;
    if (!dmPinsPanelOpen) setDmSidePanelMode("none");
    syncDmPinsPanelState();
    return;
  }
  if (isGroupConversationMeta(activeMeta)) {
    await openDmGroupMembersPanel({ force });
    return;
  }
  bindDmProfilePanelOnce();

  dmPinsPanelOpen = false;
  dmProfilePanelOpen = true;
  setDmSidePanelMode("profile");
  syncDmPinsPanelState();

  const seed = getDmPeerProfileSeed();
  if (!seed) return;

  renderDmProfilePanel(seed, { loading: true });

  const requestId = ++dmProfilePanelRequestSeq;
  const uid = seed.id;
  const [fetched, widgetsResult] = await Promise.all([
    fetchProfilesByIds([uid], { includeBio: true, force: true }).catch(() => []),
    fetchProfileWidgetsForUser(uid, { force: !!force })
      .then((rows) => ({ rows, error: null }))
      .catch((error) => ({ rows: getCachedProfileWidgetsForUser(uid), error })),
  ]);
  if (requestId !== dmProfilePanelRequestSeq) return;
  if (!dmProfilePanelOpen || uid !== getActiveDmPeerUserId()) return;

  const profile = fetched?.[0] || getCachedProfile(uid) || seed;
  renderDmProfilePanel(profile, { loading: false });
  if (widgetsResult?.error) {
    renderDmProfileWidgetsPreview(uid, widgetsResult.rows || [], {
      loading: false,
      error: toProfileWidgetError(widgetsResult.error, t("profile.widgets.error.load", "Could not load widgets.")),
    });
  }
}

function closeDmProfilePanel() {
  closeGroupMemberMenu();
  dmProfilePanelOpen = false;
  if (!dmPinsPanelOpen) setDmSidePanelMode("none");
  syncDmPinsPanelState();
}

function syncDmPinsPanelState() {
  const pinsPanel = document.getElementById("dmPinsPanel");
  const profilePanel = document.getElementById("dmProfilePanel");
  const pinsBtn = document.getElementById("btnDmPins");
  const profileBtn = document.getElementById("btnDmProfilePanel");
  const dmMain = document.getElementById("dmMain");
  const activeMeta = getActiveConversationMeta(activeDmId) || {};
  const isServerConversation = isServerConversationKind(activeMeta?.kind) || !!normId(activeMeta?.serverId || "");
  if (isServerConversation && dmProfilePanelOpen) {
    dmProfilePanelOpen = false;
  }
  const canShowPins = !!(dmFeatureCaps.advancedMessages && activeDmId && dmPinsPanelOpen);
  const canShowProfile = !!(activeDmId && dmProfilePanelOpen && !isServerConversation);

  if (pinsPanel) {
    pinsPanel.classList.toggle("hidden", !canShowPins);
    pinsPanel.setAttribute("aria-hidden", canShowPins ? "false" : "true");
  }
  if (profilePanel) {
    profilePanel.classList.toggle("hidden", !canShowProfile);
    profilePanel.setAttribute("aria-hidden", canShowProfile ? "false" : "true");
  }
  if (pinsBtn) {
    pinsBtn.classList.toggle("is-on", canShowPins);
    pinsBtn.setAttribute("aria-pressed", canShowPins ? "true" : "false");
  }
  if (profileBtn) {
    if (isServerConversation) {
      const membersOpen = !isRightSidebarCollapsed();
      profileBtn.classList.add("is-members-mode");
      profileBtn.classList.toggle("is-on", membersOpen);
      profileBtn.setAttribute("aria-pressed", membersOpen ? "true" : "false");
    } else {
      profileBtn.classList.remove("is-members-mode");
      profileBtn.classList.toggle("is-on", canShowProfile);
      profileBtn.setAttribute("aria-pressed", canShowProfile ? "true" : "false");
    }
  }
  if (dmMain) dmMain.classList.toggle("sidepanel-open", canShowPins || canShowProfile);
}

function closeDmPinsModal() {
  dmPinsPanelOpen = false;
  if (!dmProfilePanelOpen) setDmSidePanelMode("none");
  syncDmPinsPanelState();
}

function dmPinPreviewHtml(m) {
  const parsed = safeParseMessageContent(m?.content);

  if (parsed.type === "gif") {
    const url = String(parsed.url || "").trim();
    if (url) {
      return `
        <div class="dmPinPreview dmPinPreview--media">
          <img class="dmPinPreviewMedia dmPinPreviewMedia--image" src="${esc(url)}" alt="GIF" loading="lazy" />
        </div>
      `;
    }
    return `<div class="dmPinPreview dmPinPreview--text">${esc(getMessagePreviewText(m))}</div>`;
  }

  if (parsed.type === "attachment" || parsed.type === "attachments") {
    const attachments = extractParsedAttachments(parsed);
    const att = attachments.length ? attachments[0] : null;
    if (!att) return `<div class="dmPinPreview dmPinPreview--text">${esc(getMessagePreviewText(m))}</div>`;

    const meta = attachmentMetaLabel(att);
    const displayName = formatAttachmentDisplayName(att.name || "ficheiro", att.kind);
    const spoilerCls = att.spoiler ? " dmPinPreview--spoiler" : "";
    const badgeParts = [];
    if (att.spoiler) badgeParts.push("Blur");
    if (attachments.length > 1) badgeParts.push(`+${attachments.length - 1}`);
    const spoilerBadge = badgeParts.length ? `<span class="dmPinPreview__badge">${esc(badgeParts.join(" "))}</span>` : "";

    if (att.kind === "image") {
      return `
        <div class="dmPinPreview dmPinPreview--media${spoilerCls}">
          <img class="dmPinPreviewMedia dmPinPreviewMedia--image" src="${esc(att.url)}" alt="${escAttr(displayName)}" loading="lazy" />
          ${spoilerBadge}
        </div>
      `;
    }

    if (att.kind === "video") {
      return `
        <div class="dmPinPreview dmPinPreview--media${spoilerCls}">
          <video class="dmPinPreviewMedia dmPinPreviewMedia--video" src="${esc(att.url)}" preload="metadata" playsinline muted></video>
          ${spoilerBadge}
        </div>
      `;
    }

    if (att.kind === "audio") {
      return `
        <div class="dmPinPreview dmPinPreview--file">
          <span class="dmPinPreview__icon" aria-hidden="true">&#x1F3B5;</span>
          <span class="dmPinPreview__fileText">
            <span class="dmPinPreview__fileName">${esc(displayName)}</span>
            <span class="dmPinPreview__fileMeta">${esc(meta)}</span>
          </span>
        </div>
      `;
    }

    return `
      <div class="dmPinPreview dmPinPreview--file">
        <span class="dmPinPreview__icon" aria-hidden="true">&#x1F4CE;</span>
        <span class="dmPinPreview__fileText">
          <span class="dmPinPreview__fileName">${esc(displayName)}</span>
          <span class="dmPinPreview__fileMeta">${esc(meta)}</span>
        </span>
      </div>
    `;
  }

  if (isSystemChipMessage(parsed)) {
    return `<div class="dmPinPreview dmPinPreview--text">${esc(getSystemEventDisplayText(m, parsed))}</div>`;
  }

  return `<div class="dmPinPreview dmPinPreview--text">${esc(getMessagePreviewText(m))}</div>`;
}

function renderDmPinsList(items) {
  const list = document.getElementById("dmPinsList");
  if (!list) return;

  if (!Array.isArray(items) || !items.length) {
    list.innerHTML = `<div class="hint">${t("dm.no_pins", "No pinned messages.")}</div>`;
    return;
  }

  list.innerHTML = items.map((m) => {
    const mid = String(m?.id || "");
    if (!mid) return "";
    const name = getMessageAuthorName(m);
    const stamp = getMessageStamp(m?.pinned_at || m?.created_at || new Date().toISOString());
    const parsed = safeParseMessageContent(m?.content);
    const parsedAttachments = (parsed.type === "attachment" || parsed.type === "attachments")
      ? extractParsedAttachments(parsed)
      : [];
    const firstAttachment = parsedAttachments.length ? parsedAttachments[0] : null;
    const kind = parsed.type === "gif"
      ? "GIF"
      : ((parsed.type === "attachment" || parsed.type === "attachments")
        ? (parsedAttachments.length > 1
          ? `${parsedAttachments.length} anexos`
          : (firstAttachment?.kind === "image"
            ? "Imagem"
            : (firstAttachment?.kind === "video"
              ? "Video"
              : (firstAttachment?.kind === "audio" ? "Audio" : "Ficheiro"))))
        : (parsed.type === "call_event"
          ? "Chamada"
          : (parsed.type === "system_event" ? "Sistema" : "Texto")));
    const previewHtml = dmPinPreviewHtml(m);
    return `
      <button class="dmPinRow" type="button" data-dm-pin-open="${escAttr(mid)}">
        <div class="dmPinRow__meta">
          <span class="dmPinRow__name">${esc(name)}</span>
          <span>${esc(stamp)}</span>
          <span>- ${esc(kind)}</span>
        </div>
        <div class="dmPinRow__preview">${previewHtml}</div>
      </button>
    `;
  }).join("");
}

async function ensureDmMessageInCache(messageId) {
  const mid = normId(messageId);
  if (!mid || !activeDmId) return null;

  const existing = getMessageById(mid);
  if (existing) return existing;

  const { data, error } = await supabase
    .from("messages")
    .select(dmMessageSelectColumns())
    .eq("id", mid)
    .single();

  if (error || !data || normId(data.conversation_id) !== normId(activeDmId)) {
    return null;
  }

  const [resolvedRow] = await hydrateDmRowsForDisplay([data], { conversationId: activeDmId });
  const hydratedRow = resolvedRow || data;

  dmMessagesCache.push(hydratedRow);
  dmMessagesCache.sort((a, b) => new Date(a?.created_at || 0) - new Date(b?.created_at || 0));
  if (hydratedRow.id) dmMessageIds.add(normId(hydratedRow.id));
  cacheProfileRow({
    id: hydratedRow?.user_id,
    username: hydratedRow?.profiles?.username,
    display_name: hydratedRow?.profiles?.display_name,
    avatar_url: hydratedRow?.profiles?.avatar_url,
    name_color: hydratedRow?.profiles?.name_color,
  });
  void fetchProfilesByIds([hydratedRow?.user_id], { includeBio: false });
  renderMessagesFromCache({ keepBottom: false });
  return hydratedRow;
}

async function openDmPinsModal() {
  if (!activeDmId) return;
  bindDmPinsModalOnce();

  dmProfilePanelOpen = false;
  dmPinsPanelOpen = true;
  setDmSidePanelMode("pins");
  syncDmPinsPanelState();

  const list = document.getElementById("dmPinsList");
  if (!list) return;
  list.innerHTML = `<div class="hint">A carregar pins...</div>`;

  let items = [];
  if (dmFeatureCaps.advancedMessages) {
    const { data, error } = await supabase
      .from("messages")
      .select(dmMessageSelectColumns())
      .eq("conversation_id", activeDmId)
      .eq("is_pinned", true)
      .order("pinned_at", { ascending: false })
      .order("created_at", { ascending: false })
      .limit(DM_PIN_LIMIT);
    if (!error && Array.isArray(data)) items = await hydrateDmRowsForDisplay(data, { conversationId: activeDmId });
    else if (error) console.warn("load pinned messages failed", error);
  }

  if (!items.length) items = getPinnedMessagesFromCache();

  renderDmPinsList(items);
}

function bindDmPinsModalOnce() {
  if (dmPinsBound) return;
  dmPinsBound = true;

  document.getElementById("btnDmPinsClose")?.addEventListener("click", closeDmPinsModal);

  document.getElementById("dmPinsList")?.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const btn = target.closest("[data-dm-pin-open]");
    if (!btn) return;
    const mid = btn.getAttribute("data-dm-pin-open");
    if (!mid) return;

    await ensureDmMessageInCache(mid);
    jumpToMessage(mid);
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    const userCardModal = document.getElementById("userCardModal");
    if (userCardModal && !userCardModal.classList.contains("hidden")) return;
    if (!dmPinsPanelOpen) return;
    closeDmPinsModal();
  });
}

function bindDmProfilePanelOnce() {
  if (dmProfilePanelBound) return;
  dmProfilePanelBound = true;

  document.getElementById("btnDmProfileClose")?.addEventListener("click", closeDmProfilePanel);
  const openFullProfileFromDmPanel = async (ev = null) => {
    const uid = getActiveDmPeerUserId();
    if (!uid) return;
    const anchorEl = ev?.currentTarget || ev?.target || document.getElementById("dmProfileAvatar") || null;
    await openUserCardModal(uid, { username: state.activeDm?.username || "" }, {
      anchorEl,
      conversationId: normId(activeDmId || state.activeDm?.conversationId || ""),
      conversationLabel: String(state.activeDm?.displayName || state.activeDm?.username || "").trim(),
      serverId: normId(state.activeDm?.serverId || ""),
      kind: normId(state.activeDm?.serverId || "") ? "server" : String(state.activeDm?.kind || "").trim().toLowerCase(),
      presentation: "overlay",
      initialTab: "widgets",
    });
  };
  const bindProfileOpenTarget = (el) => {
    if (!el) return;
    const isButton = el.tagName === "BUTTON";
    if (!isButton) {
      el.classList.add("is-clickable");
      el.setAttribute("role", "button");
      if (!el.hasAttribute("tabindex")) el.setAttribute("tabindex", "0");
    }
    el.addEventListener("click", openFullProfileFromDmPanel);
    if (!isButton) {
      el.addEventListener("keydown", (e) => {
        if (e.key !== "Enter" && e.key !== " ") return;
        e.preventDefault();
        void openFullProfileFromDmPanel(e);
      });
    }
  };

  bindProfileOpenTarget(document.getElementById("btnDmProfileOpenCard"));
  bindProfileOpenTarget(document.getElementById("dmProfileAvatar"));
  bindProfileOpenTarget(document.getElementById("dmProfileName"));
  bindProfileOpenTarget(document.getElementById("dmProfileHandle"));
  bindProfileOpenTarget(document.getElementById("dmTitle"));

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    const userCardModal = document.getElementById("userCardModal");
    if (userCardModal && !userCardModal.classList.contains("hidden")) return;
    if (!dmProfilePanelOpen) return;
    closeDmProfilePanel();
  });

  const panelBody = document.querySelector("#dmProfilePanel .dmProfilePanel__body");
  panelBody?.addEventListener("click", async (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const widgetPreview = target.closest("[data-dm-profile-widget-preview]");
    if (widgetPreview) {
      const uid = getActiveDmPeerUserId();
      if (!uid) return;
      await openUserCardModal(uid, { username: state.activeDm?.username || "" }, {
        conversationId: normId(activeDmId || state.activeDm?.conversationId || ""),
        conversationLabel: String(state.activeDm?.displayName || state.activeDm?.username || "").trim(),
        serverId: normId(state.activeDm?.serverId || ""),
        kind: normId(state.activeDm?.serverId || "") ? "server" : String(state.activeDm?.kind || "").trim().toLowerCase(),
        presentation: "overlay",
        initialTab: "widgets",
      });
      return;
    }
    const row = target.closest("[data-group-member-id]");
    if (!row) return;
    const uid = normId(row.getAttribute("data-group-member-id") || "");
    if (!uid) return;
    const member = findGroupMemberInfo(activeDmId, uid) || {};
    const anchorEl = row;
    await openUserCardModal(uid, {
      username: member?.username || "",
      display_name: member?.displayName || "",
      avatar_url: member?.avatarUrl || "",
      name_color: member?.nameColor || "",
    }, {
      anchorEl,
      conversationId: normId(activeDmId || state.activeDm?.conversationId || ""),
      conversationLabel: String(state.activeDm?.displayName || "").trim(),
      serverId: normId(state.activeDm?.serverId || ""),
      kind: normId(state.activeDm?.serverId || "") ? "server" : "group",
    });
  });

  panelBody?.addEventListener("contextmenu", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const row = target.closest("[data-group-member-id]");
    if (!row) return;
    const uid = normId(row.getAttribute("data-group-member-id") || "");
    if (!uid) return;
    const meId = normId(state.user?.id || "");
    const canRing = uid !== meId;
    e.preventDefault();
    openGroupMemberMenuAt(uid, { x: e.clientX, y: e.clientY }, { canRing });
  });
}

function getUserCardAnchorRect() {
  if (userCardAnchorEl && document.body?.contains(userCardAnchorEl) && typeof userCardAnchorEl.getBoundingClientRect === "function") {
    const rect = userCardAnchorEl.getBoundingClientRect();
    if ((rect.width > 0 && rect.height > 0) || Number.isFinite(rect.left) || Number.isFinite(rect.top)) {
      userCardLastAnchorRect = {
        left: Number(rect.left || 0),
        right: Number(rect.right || 0),
        top: Number(rect.top || 0),
        bottom: Number(rect.bottom || 0),
        width: Number(rect.width || 0),
        height: Number(rect.height || 0),
      };
      return rect;
    }
  }
  if (userCardAnchorPoint && Number.isFinite(Number(userCardAnchorPoint.x)) && Number.isFinite(Number(userCardAnchorPoint.y))) {
    const x = Number(userCardAnchorPoint.x);
    const y = Number(userCardAnchorPoint.y);
    userCardLastAnchorRect = { left: x, right: x, top: y, bottom: y, width: 0, height: 0 };
    return userCardLastAnchorRect;
  }
  if (userCardLastAnchorRect) return userCardLastAnchorRect;
  return null;
}

function positionUserCardModal() {
  const modal = document.getElementById("userCardModal");
  const card = modal?.querySelector(".userCardCard");
  if (!modal || !card || modal.classList.contains("hidden")) return;

  const vw = window.innerWidth || document.documentElement.clientWidth || 0;
  const vh = window.innerHeight || document.documentElement.clientHeight || 0;
  const margin = 8;
  const gap = 10;
  const rect = userCardPresentationMode === "overlay" ? null : getUserCardAnchorRect();

  const cardWidth = Math.min(card.offsetWidth || 780, Math.max(280, vw - margin * 2));
  const cardHeight = Math.min(card.offsetHeight || 560, Math.max(220, vh - margin * 2));

  let left = Math.round((vw - cardWidth) / 2);
  let top = Math.round((vh - cardHeight) / 2);

  if (rect) {
    left = Math.round(rect.right + gap);
    const anchorMidY = Number(rect.top || 0) + (Number(rect.height || 0) / 2);
    top = Math.round(anchorMidY - (cardHeight * 0.34));

    if (left + cardWidth > vw - margin) left = Math.round(rect.left - cardWidth - gap);
    if (left < margin) {
      left = Math.round(Math.min(Math.max(margin, Number(rect.left || 0)), vw - cardWidth - margin));
    }
  }

  left = Math.max(margin, Math.min(left, vw - cardWidth - margin));
  top = Math.max(margin, Math.min(top, vh - cardHeight - margin));

  card.style.left = `${left}px`;
  card.style.top = `${top}px`;
}

function queueUserCardModalPosition() {
  requestAnimationFrame(() => positionUserCardModal());
}

function applyUserCardModalPresentation(modeInput = "anchored") {
  const modal = document.getElementById("userCardModal");
  if (!modal) return;
  const mode = String(modeInput || "").trim().toLowerCase() === "overlay"
    ? "overlay"
    : "anchored";
  userCardPresentationMode = mode;
  modal.classList.toggle("userCardModal--overlay", mode === "overlay");
}

function applyUserCardModalLayout(modeInput = "full") {
  const modal = document.getElementById("userCardModal");
  if (!modal) return;
  const mode = String(modeInput || "").trim().toLowerCase() === "preview"
    ? "preview"
    : "full";
  userCardLayoutMode = mode;
  modal.classList.toggle("userCardModal--preview", mode === "preview");
}

function closeUserCardModal() {
  const modal = document.getElementById("userCardModal");
  if (!modal) return;
  const card = modal.querySelector(".userCardCard");
  if (card) {
    card.style.removeProperty("left");
    card.style.removeProperty("top");
  }
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");
  userCardCurrentUserId = null;
  userCardCurrentUsername = "";
  userCardAnchorEl = null;
  userCardAnchorPoint = null;
  userCardLastAnchorRect = null;
  userCardCurrentContext = null;
  userCardCurrentInsights = null;
  userCardInsightsLoading = false;
  userCardWidgetsLoading = false;
  userCardWidgetsError = "";
  userCardWidgetsMutating = false;
  userCardWidgetRefreshToken += 1;
  userCardActiveTab = "widgets";
  applyUserCardModalPresentation("anchored");
  applyUserCardModalLayout("full");
  closeProfileWidgetInlineSearchPopover({ refresh: false });
  closeProfileWidgetModal();
  closeProfileWidgetItemModal();
}

function normalizeUserCardContext(contextInput = {}) {
  const context = (contextInput && typeof contextInput === "object") ? contextInput : {};
  const conversationId = normId(context.conversationId || "");
  const serverId = normId(context.serverId || "");
  const conversationMeta = conversationId ? (getConversationMeta(conversationId) || {}) : {};
  const serverRow = serverId ? (getServerRowById(serverId) || {}) : null;
  const canUseLiveConversationLabel = !!(conversationId || serverId);

  let kind = String(context.kind || conversationMeta?.kind || "").trim().toLowerCase();
  if (!kind && serverId) kind = "server";
  if (kind !== "server" && kind !== "group") kind = "dm";

  const conversationLabel = String(
    context.conversationLabel
    || conversationMeta?.displayName
    || (kind === "server" ? serverRow?.name : "")
    || (canUseLiveConversationLabel ? state.activeDm?.displayName : "")
    || (canUseLiveConversationLabel ? state.activeDm?.username : "")
    || ""
  ).trim();

  return {
    conversationId,
    serverId,
    kind,
    conversationLabel,
    serverName: String(context.serverName || serverRow?.name || "").trim(),
  };
}

function formatUserCardDate(valueInput = "") {
  const raw = String(valueInput || "").trim();
  if (!raw) return "";
  const ms = Date.parse(raw);
  if (!Number.isFinite(ms) || ms <= 0) return "";
  const { locale } = getMessageLocaleContext();
  try {
    return new Date(ms).toLocaleDateString(locale, {
      day: "2-digit",
      month: "short",
      year: "numeric",
    });
  } catch (_) {
    return raw;
  }
}

function getUserCardRelationMeta(userId) {
  const uid = normId(userId);
  const selfId = normId(state.user?.id || "");
  if (!uid) return { label: "", tone: "" };
  if (uid === selfId) {
    return { label: "", tone: "self", since: "", isSelf: true, kind: "self" };
  }
  if (isUserBlockedLocally(uid)) {
    return { label: t("relationship.blocked", "Blocked"), tone: "pending", since: "", isSelf: false, kind: "blocked" };
  }

  const friend = getFriendRowByUserId(uid) || null;
  if (friend) {
    const bestFriend = isDmBestFriend(uid);
    return {
      label: bestFriend ? t("usercard.best_friend", "Best friend") : t("usercard.friend_rel", "Friend"),
      tone: bestFriend ? "best" : "friend",
      since: String(friend?.since || friend?.created_at || "").trim(),
      isSelf: false,
      kind: "friend",
    };
  }

  const incoming = (state.incoming || []).find((row) => normId(row?.from_user_id || row?.user_id || row?.id || "") === uid) || null;
  if (incoming) {
    return {
      label: "Pedido recebido",
      tone: "pending",
      since: String(incoming?.created_at || "").trim(),
      isSelf: false,
      kind: "friend_request",
    };
  }

  const outgoing = (state.outgoing || []).find((row) => normId(row?.to_user_id || row?.user_id || row?.id || "") === uid) || null;
  if (outgoing) {
    return {
      label: "Pedido enviado",
      tone: "pending",
      since: String(outgoing?.created_at || "").trim(),
      isSelf: false,
      kind: "friend_request",
    };
  }

  const incomingMessage = getIncomingMessageRequestByUserId(uid) || null;
  if (incomingMessage) {
    return {
      label: "Msg recebida",
      tone: "pending",
      since: String(incomingMessage?.created_at || "").trim(),
      isSelf: false,
      kind: "message_request",
    };
  }

  const outgoingMessage = getOutgoingMessageRequestByUserId(uid) || null;
  if (outgoingMessage) {
    return {
      label: "Msg enviada",
      tone: "pending",
      since: String(outgoingMessage?.created_at || "").trim(),
      isSelf: false,
      kind: "message_request",
    };
  }

  return { label: "", tone: "", since: "", isSelf: false, kind: "" };
}

function getUserCardMessageActionMeta(userId, username = "") {
  const uid = normId(userId);
  const uname = String(username || "").trim();
  const selfId = normId(state.user?.id || "");
  if (!uid || uid === selfId) {
    return { label: "", disabled: true, action: "none", requestId: "" };
  }
  if (isUserBlockedLocally(uid)) {
    return { label: t("relationship.blocked", "Blocked"), disabled: true, action: "blocked", requestId: "" };
  }
  if (getFriendRowByUserId(uid) || getMessageContactRowByUserId(uid)) {
    return { label: t("usercard.message", "Message"), disabled: !uname, action: "open_dm", requestId: "" };
  }
  const incomingMessage = getIncomingMessageRequestByUserId(uid);
  if (incomingMessage) {
    return {
      label: t("msg.action.reply", "Reply"),
      disabled: false,
      action: "accept_message_request",
      requestId: String(incomingMessage?.request_id || "").trim(),
    };
  }
  const outgoingMessage = getOutgoingMessageRequestByUserId(uid);
  if (outgoingMessage) {
    return {
      label: t("msg.action.request_pending", "Request sent"),
      disabled: true,
      action: "pending_message_request",
      requestId: String(outgoingMessage?.request_id || "").trim(),
    };
  }
  return { label: t("msg.action.send_request", "Message request"), disabled: !uname, action: "send_message_request", requestId: "" };
}

function getUserCardActivityKindLabel(messageRow) {
  const parsed = safeParseMessageContent(messageRow?.content);
  if (parsed.type === "gif") return "GIF";
  if (parsed.type === "attachment" || parsed.type === "attachments") {
    const attachments = extractParsedAttachments(parsed);
    if (!attachments.length) return t("usercard.msg.kind.attachment", "Attachment");
    if (attachments.length === 1) {
      const only = attachments[0];
      if (isGifLikeAttachment(only)) return "GIF";
      return attachmentKindLabel(only.kind) || "Media";
    }
    return "Media";
  }
  if (parsed.type === "call_event") return "Call";
  if (parsed.type === "system_event") return t("usercard.msg.kind.system", "System");
  return t("usercard.msg.kind.message", "Message");
}

function extractUserCardLatestMediaFromMessage(messageRow) {
  if (!messageRow) return null;
  const parsed = safeParseMessageContent(messageRow?.content);
  if (parsed.type === "gif") {
    const safeUrl = String(parsed?.url || "").trim();
    if (!safeUrl) return null;
    return {
      kind: "gif",
      url: safeUrl,
      createdAt: String(messageRow?.created_at || "").trim(),
      label: "GIF",
      name: "",
    };
  }
  if (parsed.type !== "attachment" && parsed.type !== "attachments") return null;

  const attachments = extractParsedAttachments(parsed);
  const mediaAttachment = attachments.find((att) => {
    const kind = String(att?.kind || "").trim().toLowerCase();
    return kind === "image" || kind === "video";
  }) || null;
  if (!mediaAttachment?.url) return null;

  const isGif = isGifLikeAttachment(mediaAttachment) || isGifLikeUrl(mediaAttachment.url);
  return {
    kind: isGif ? "gif" : String(mediaAttachment.kind || "image").trim().toLowerCase(),
    url: String(mediaAttachment.url || "").trim(),
    createdAt: String(messageRow?.created_at || "").trim(),
    label: isGif ? "GIF" : (attachmentKindLabel(mediaAttachment.kind) || "Media"),
    name: String(mediaAttachment.name || "").trim(),
  };
}

function buildUserCardFactHtml(label, value, { mono = false } = {}) {
  const safeLabel = String(label || "").trim();
  const safeValue = String(value || "").trim();
  if (!safeLabel || !safeValue) return "";
  return `
    <div class="userCardFact">
      <div class="userCardFact__label">${esc(safeLabel)}</div>
      <div class="userCardFact__value${mono ? " userCardFact__value--mono" : ""}">${esc(safeValue)}</div>
    </div>
  `;
}

function buildUserCardActivityPanelHtml(profile = {}, insights = {}, { loading = false, context = null } = {}) {
  const name = String(profile?.display_name || profile?.username || t("usercard.this_person", "this person")).trim();
  const recentMessages = Array.isArray(insights?.recentMessages) ? insights.recentMessages : [];
  const sourceKind = String(context?.kind || "").trim().toLowerCase();
  const sourceLabel = String(context?.conversationLabel || "").trim();
  let subtitle = t("usercard.activity.subtitle.default", "Recent messages you share with this account.");
  if (sourceKind === "server" && sourceLabel) subtitle = t("usercard.activity.subtitle.server", "Recent in {source}.").replace("{source}", sourceLabel);
  else if (sourceKind === "group" && sourceLabel) subtitle = t("usercard.activity.subtitle.group", "Recent in {source}.").replace("{source}", sourceLabel);
  else if (sourceKind === "dm") subtitle = t("usercard.activity.subtitle.dm", "What {name} sent here most recently.").replace("{name}", name);

  if (loading && !recentMessages.length) {
    return `
      <div class="userCardPanelIntro">
        <div class="userCardPanelEyebrow">${esc(t("usercard.activity.eyebrow", "Activity"))}</div>
        <div class="userCardPanelTitle">${esc(t("usercard.activity.loading.title", "Loading activity..."))}</div>
        <div class="userCardPanelText">${esc(t("usercard.activity.loading.text", "Looking for recent messages and moments from this person."))}</div>
      </div>
    `;
  }

  if (!recentMessages.length) {
    return `
      <div class="userCardPanelIntro">
        <div class="userCardPanelEyebrow">${esc(t("usercard.activity.eyebrow", "Activity"))}</div>
        <div class="userCardPanelTitle">${esc(t("usercard.activity.empty.title", "Nothing recent yet"))}</div>
        <div class="userCardPanelText">${esc(subtitle)}</div>
      </div>
      <div class="userCardEmptyState">
        <strong>${esc(t("usercard.activity.empty.strong", "Nothing recent to show"))}</strong>
        <span>${esc(t("usercard.activity.empty.span", "When this person sends something you can see, it'll show up here."))}</span>
      </div>
    `;
  }

  return `
    <div class="userCardPanelIntro">
      <div class="userCardPanelEyebrow">${esc(t("usercard.activity.eyebrow", "Activity"))}</div>
      <div class="userCardPanelTitle">${esc(t("usercard.activity.latest.title", "Most recent"))}</div>
      <div class="userCardPanelText">${esc(subtitle)}</div>
    </div>
    <div class="userCardTimeline">
      ${recentMessages.map((item) => `
        <article class="userCardTimelineItem">
          <div class="userCardTimelineDot" aria-hidden="true"></div>
          <div>
            <div class="userCardTimelineMeta">
              <span class="userCardTimelineKind">${esc(item.kind || t("usercard.msg.kind.message", "Message"))}</span>
              <span>${esc(getMessageStamp(item.createdAt || new Date().toISOString()))}</span>
            </div>
            <div class="userCardTimelineText">${esc(item.preview || t("usercard.msg.preview.empty", "(no content)"))}</div>
          </div>
        </article>
      `).join("")}
    </div>
  `;
}

function buildUserCardMediaPanelHtml(profile = {}, insights = {}, { loading = false } = {}) {
  const latestMedia = insights?.latestMedia || null;
  if (loading && !latestMedia) {
    return `
      <div class="userCardPanelIntro">
        <div class="userCardPanelEyebrow">Media</div>
        <div class="userCardPanelTitle">A ver a ultima foto...</div>
        <div class="userCardPanelText">Se esta pessoa tiver mandado imagens, GIFs ou video, vai aparecer aqui.</div>
      </div>
    `;
  }

  if (!latestMedia?.url) {
    return `
      <div class="userCardPanelIntro">
        <div class="userCardPanelEyebrow">Media</div>
        <div class="userCardPanelTitle">Ainda sem foto recente</div>
        <div class="userCardPanelText">Nao apanhei nenhuma imagem ou GIF recente desta pessoa que tu possas ver.</div>
      </div>
      <div class="userCardEmptyState">
        <strong>Sem media para mostrar</strong>
        <span>Assim que aparecer uma foto, GIF ou video recente, esta aba fica preenchida.</span>
      </div>
    `;
  }

  const safeUrl = String(latestMedia.url || "").trim();
  const isVideo = latestMedia.kind === "video";
  const isGif = latestMedia.kind === "gif" || isGifLikeUrl(safeUrl);
  const previewHtml = isVideo
    ? `<video class="userCardMediaAsset" src="${esc(safeUrl)}" preload="metadata" muted playsinline></video>`
    : `<img class="userCardMediaAsset" src="${esc(safeUrl)}" alt="ultima media"${isGif ? ' data-managed-gif-media="1"' : ""} loading="lazy" />`;

  return `
    <div class="userCardPanelIntro">
      <div class="userCardPanelEyebrow">Media</div>
      <div class="userCardPanelTitle">Ultima foto visivel</div>
      <div class="userCardPanelText">O atalho rapido para veres a ultima media recente desta pessoa.</div>
    </div>
    <a class="userCardMediaCard" href="${escAttr(safeUrl)}" target="_blank" rel="noopener noreferrer">
      <div class="userCardMediaPreview">
        ${previewHtml}
      </div>
      <div class="userCardMediaMeta">
        <div class="userCardChipRow">
          <span class="userCardChip">${esc(latestMedia.label || "Media")}</span>
          ${latestMedia.name ? `<span class="userCardChip">${esc(latestMedia.name)}</span>` : ""}
        </div>
        <div class="userCardMediaTitle">${esc(isVideo ? "Ultimo video encontrado" : "Ultima imagem encontrada")}</div>
        <div class="userCardMediaSubtitle">${esc(getMessageStamp(latestMedia.createdAt || new Date().toISOString()))}</div>
      </div>
    </a>
  `;
}

function buildUserCardSharedPanelHtml(profile = {}, insights = {}, { relation = null, context = null } = {}) {
  const sharedServers = Array.isArray(insights?.sharedServers) ? insights.sharedServers : [];
  const sharedGroups = Array.isArray(insights?.sharedGroups) ? insights.sharedGroups : [];
  const currentServerMembership = insights?.currentServerMembership || null;
  const chipHtml = [];
  if (relation?.label) chipHtml.push(`<span class="userCardChip">${esc(relation.label)}</span>`);
  if (currentServerMembership?.role) chipHtml.push(`<span class="userCardChip">${esc(currentServerMembership.role)}</span>`);
  if (currentServerMembership?.joinedAt) chipHtml.push(`<span class="userCardChip">aqui desde ${esc(formatUserCardDate(new Date(currentServerMembership.joinedAt).toISOString()))}</span>`);

  const cards = [];
  if (chipHtml.length) {
    cards.push(`
      <div class="userCardSharedCard">
        <div class="userCardSharedTitle">Resumo rapido</div>
        <div class="userCardChipRow">${chipHtml.join("")}</div>
      </div>
    `);
  }

  if (sharedServers.length) {
    cards.push(`
      <div class="userCardSharedCard">
        <div class="userCardSharedTitle">Servers em comum carregados</div>
        <div class="userCardServerList">
          ${sharedServers.map((server) => {
            const name = String(server?.name || "Server").trim();
            const iconUrl = String(server?.iconUrl || "").trim();
            const initial = name.charAt(0).toUpperCase() || "S";
            const sub = [
              server?.isCurrent ? t("usercard.current_server", "current server") : t("usercard.recently_loaded", "recently loaded"),
              server?.memberCount ? (server.memberCount === 1 ? t("dm.group_member_count_one", "1 member") : t("dm.group_member_count", "{n} members").replace("{n}", server.memberCount)) : "",
            ].filter(Boolean).join(" â€¢ ");
            return `
              <div class="userCardServerItem">
                <div class="userCardServerOrb">
                  ${iconUrl ? `<img src="${esc(iconUrl)}" alt="${escAttr(name)}" />` : `<span>${esc(initial)}</span>`}
                </div>
                <div class="userCardServerMeta">
                  <div class="userCardServerName">${esc(name)}</div>
                  <div class="userCardServerSub">${esc(sub || "server partilhado")}</div>
                </div>
              </div>
            `;
          }).join("")}
        </div>
      </div>
    `);
  }

  if (sharedGroups.length) {
    cards.push(`
      <div class="userCardSharedCard">
        <div class="userCardSharedTitle">Grupos em comum</div>
        <div class="userCardChipRow">
          ${sharedGroups.map((group) => `<span class="userCardChip">${esc(group?.name || "Group DM")}</span>`).join("")}
        </div>
      </div>
    `);
  }

  if (!cards.length) {
    const label = String(context?.conversationLabel || "").trim();
    return `
      <div class="userCardPanelIntro">
        <div class="userCardPanelEyebrow">Ligacoes</div>
        <div class="userCardPanelTitle">Pouco contexto partilhado</div>
        <div class="userCardPanelText">Ainda nao carreguei muitos sitios em comum com esta conta.</div>
      </div>
      <div class="userCardEmptyState">
        <strong>Sem ligacoes detalhadas</strong>
        <span>${esc(label ? `Se continuares a abrir ${label} e os membros, este painel vai ganhar mais contexto.` : "Abre chats, grupos ou servers com esta pessoa para o card ficar ainda mais rico.")}</span>
      </div>
    `;
  }

  return `
    <div class="userCardPanelIntro">
      <div class="userCardPanelEyebrow">Ligacoes</div>
      <div class="userCardPanelTitle">Contexto em comum</div>
      <div class="userCardPanelText">Tudo o que a app ja sabe sobre a ligacao entre voces.</div>
    </div>
    <div class="userCardSharedStack">${cards.join("")}</div>
  `;
}

function normalizeProfileWidgetType(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  return PROFILE_WIDGET_TYPES.includes(raw) ? raw : "custom";
}

function normalizeProfileWidgetCreateType(value = "") {
  const type = normalizeProfileWidgetType(value);
  return PROFILE_WIDGET_CREATE_TYPES.includes(type) ? type : "games";
}

function normalizeProfileWidgetStatus(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  return PROFILE_WIDGET_STATUSES.includes(raw) ? raw : "favorite";
}

function normalizeProfileWidgetVisibility(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  return PROFILE_WIDGET_VISIBILITY.includes(raw) ? raw : "public";
}

function normalizeProfileWidgetNote(value = "") {
  const raw = String(value ?? "");
  return raw.length > PROFILE_WIDGET_LIMITS.noteMax
    ? raw.slice(0, PROFILE_WIDGET_LIMITS.noteMax)
    : raw;
}

function normalizeProfileWidgetTitle(value = "") {
  const raw = String(value || "").trim();
  return raw.slice(0, PROFILE_WIDGET_LIMITS.titleMax);
}

function normalizeProfileWidgetTags(input = []) {
  const arr = Array.isArray(input) ? input : [];
  const out = [];
  arr.forEach((entry) => {
    if (out.length >= PROFILE_WIDGET_LIMITS.tagsMax) return;
    const tag = String(entry || "").trim();
    if (!tag) return;
    if (tag.length > PROFILE_WIDGET_LIMITS.tagLenMax) return;
    out.push(tag);
  });
  return out;
}

function parseProfileWidgetTagsInput(input = "") {
  const raw = String(input || "");
  if (!raw) return [];
  return normalizeProfileWidgetTags(
    raw.split(",").map((part) => String(part || "").trim())
  );
}

function normalizeCatalogType(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  return PROFILE_WIDGET_CATALOG_ALLOWED_TYPES.includes(raw) ? raw : "custom";
}

function catalogTypeFromWidgetType(widgetTypeInput = "") {
  const widgetType = normalizeProfileWidgetType(widgetTypeInput);
  return PROFILE_WIDGET_TO_CATALOG_TYPE[widgetType] || "custom";
}

function normalizeCatalogSource(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  if (!raw) return "local";
  if (["rawg", "tmdb", "tvmaze", "omdb", "deezer", "spotify", "apple_music", "anilist", "local", "mock"].includes(raw)) return raw;
  return "local";
}

function normalizeProfileWidgetItemMetadata(input = {}) {
  const src = input && typeof input === "object" && !Array.isArray(input)
    ? input
    : {};
  const out = {};

  const sourceRaw = String(src.source || src.catalog_source || "").trim().toLowerCase();
  const source = sourceRaw && ["rawg", "tmdb", "tvmaze", "omdb", "deezer", "spotify", "apple_music", "anilist", "local", "mock"].includes(sourceRaw)
    ? sourceRaw
    : "";
  const sourceId = String(src.source_id || src.catalog_source_id || "").trim().slice(0, 80);
  const catalogTypeRaw = String(src.catalog_type || src.type || "").trim().toLowerCase();
  const catalogType = catalogTypeRaw && PROFILE_WIDGET_CATALOG_ALLOWED_TYPES.includes(catalogTypeRaw)
    ? catalogTypeRaw
    : "";

  if (source) out.source = source;
  if (sourceId) out.source_id = sourceId;
  if (catalogType) out.catalog_type = catalogType;

  const platforms = Array.isArray(src.platforms)
    ? src.platforms
      .map((entry) => String(entry || "").trim())
      .filter(Boolean)
      .slice(0, 12)
    : [];
  const genres = Array.isArray(src.genres)
    ? src.genres
      .map((entry) => String(entry || "").trim())
      .filter(Boolean)
      .slice(0, 12)
    : [];
  if (platforms.length) out.platforms = platforms;
  if (genres.length) out.genres = genres;

  const release = String(src.released || "").trim().slice(0, 32);
  if (release) out.released = release;
  const slug = String(src.slug || "").trim().slice(0, 120);
  if (slug) out.slug = slug;

  const releaseYearRaw = Number(src.release_year);
  if (Number.isFinite(releaseYearRaw) && releaseYearRaw >= 1900 && releaseYearRaw <= 2100) {
    out.release_year = Math.round(releaseYearRaw);
  }

  const rating = Number(src.rating);
  if (Number.isFinite(rating)) out.rating = Math.max(0, Math.min(5, Number(rating.toFixed(2))));
  const rawgRating = Number(src.rawg_rating);
  if (Number.isFinite(rawgRating)) out.rawg_rating = Math.max(0, Math.min(5, Number(rawgRating.toFixed(2))));

  const imdbId = String(src.imdb || src.imdb_id || "").trim().slice(0, 32);
  if (imdbId) out.imdb = imdbId;
  const omdbType = String(src.omdb_type || "").trim().toLowerCase();
  if (omdbType === "movie" || omdbType === "series" || omdbType === "episode") out.omdb_type = omdbType;
  const yearText = String(src.year_text || "").trim().slice(0, 24);
  if (yearText) out.year_text = yearText;
  const anilistFormat = String(src.anilist_format || "").trim().slice(0, 32);
  if (anilistFormat) out.anilist_format = anilistFormat;
  const anilistStatus = String(src.anilist_status || "").trim().slice(0, 32);
  if (anilistStatus) out.anilist_status = anilistStatus;
  const averageScore = Number(src.average_score);
  if (Number.isFinite(averageScore)) out.average_score = Math.max(0, Math.min(100, Math.round(averageScore)));
  const trackTitle = String(src.track_title || "").trim().slice(0, 120);
  if (trackTitle) out.track_title = trackTitle;
  const artistName = String(src.artist || src.artist_name || "").trim().slice(0, 120);
  if (artistName) out.artist = artistName;
  const artistId = String(src.artist_id || "").trim().slice(0, 40);
  if (artistId) out.artist_id = artistId;
  const artistUrl = normalizeCatalogExternalUrl(src.artist_url || "");
  if (artistUrl) out.artist_url = artistUrl;
  const albumTitle = String(src.album || src.album_title || "").trim().slice(0, 120);
  if (albumTitle) out.album = albumTitle;
  const albumId = String(src.album_id || "").trim().slice(0, 40);
  if (albumId) out.album_id = albumId;
  const previewUrl = normalizeCatalogExternalUrl(src.preview_url || src.preview || "");
  if (previewUrl) out.preview_url = previewUrl;
  const durationSeconds = Number(src.duration_seconds ?? src.duration);
  if (Number.isFinite(durationSeconds) && durationSeconds > 0) out.duration_seconds = clampInt(durationSeconds, 1, 36000, 1);
  const deezerRank = Number(src.deezer_rank ?? src.rank);
  if (Number.isFinite(deezerRank) && deezerRank > 0) out.deezer_rank = Math.min(Math.round(deezerRank), 1000000000);

  return out;
}

function normalizeCatalogCoverUrl(value = "") {
  const safe = normalizeBannerUrl(value || "");
  if (!safe) return "";
  const lower = safe.toLowerCase();
  if (lower.startsWith("data:")) return "";
  return safe;
}

function normalizeCatalogExternalUrl(value = "") {
  const safe = normalizeBannerUrl(value || "");
  if (!safe) return "";
  const lower = safe.toLowerCase();
  if (lower.startsWith("data:")) return "";
  return safe;
}

function normalizeCatalogSearchResultRow(row = {}) {
  const title = normalizeProfileWidgetTitle(row?.title || "");
  const sourceId = String(row?.source_id || "").trim();
  if (!title) return null;
  if (!sourceId) return null;
  const releaseYearRaw = Number(row?.release_year);
  const releaseYear = Number.isFinite(releaseYearRaw) && releaseYearRaw >= 1900 && releaseYearRaw <= 2100
    ? Math.round(releaseYearRaw)
    : null;
  return {
    source: normalizeCatalogSource(row?.source || ""),
    source_id: sourceId,
    type: normalizeCatalogType(row?.type || ""),
    title,
    cover_url: normalizeCatalogCoverUrl(row?.cover_url || ""),
    release_year: releaseYear,
    external_url: normalizeCatalogExternalUrl(row?.external_url || ""),
    metadata: normalizeProfileWidgetItemMetadata(row?.metadata || {}),
    result_origin: String(row?.result_origin || "").trim().toLowerCase() === "external" ? "external" : "local",
  };
}

function getCatalogSourceLabel(sourceInput = "") {
  const source = normalizeCatalogSource(sourceInput);
  if (source === "mock") return "MOCK";
  if (source === "rawg") return "RAWG";
  if (source === "tmdb") return "TMDB";
  if (source === "omdb") return "OMDb";
  if (source === "tvmaze") return "TVMaze";
  if (source === "deezer") return "Deezer";
  if (source === "spotify") return "Spotify";
  if (source === "apple_music") return "Apple Music";
  if (source === "anilist") return "AniList";
  return "Local";
}

function normalizeProfileWidgetItemRow(row = {}) {
  const ratingRaw = row?.rating;
  const rating = Number.isFinite(Number(ratingRaw))
    ? clampInt(ratingRaw, 1, 5, 1)
    : null;
  return {
    id: normId(row?.id || ""),
    widget_id: normId(row?.widget_id || ""),
    user_id: normId(row?.user_id || ""),
    title: normalizeProfileWidgetTitle(row?.title || ""),
    cover_url: normalizeCatalogCoverUrl(row?.cover_url || ""),
    external_url: normalizeCatalogExternalUrl(row?.external_url || ""),
    status: normalizeProfileWidgetStatus(row?.status || ""),
    rating,
    note: normalizeProfileWidgetNote(row?.note || ""),
    tags: normalizeProfileWidgetTags(row?.tags || []),
    mood: String(row?.mood || "").trim(),
    is_featured: !!row?.is_featured,
    position: clampInt(row?.position, 0, 9999, 0),
    metadata: normalizeProfileWidgetItemMetadata(row?.metadata || {}),
    created_at: String(row?.created_at || "").trim(),
    updated_at: String(row?.updated_at || "").trim(),
  };
}

function normalizeProfileWidgetRow(row = {}) {
  const itemsRaw = Array.isArray(row?.items) ? row.items : [];
  const items = itemsRaw
    .map((item) => normalizeProfileWidgetItemRow(item))
    .filter((item) => !!item.id && !!item.title)
    .sort((a, b) => (
      Number(a.position || 0) - Number(b.position || 0)
      || (Date.parse(a.created_at || 0) || 0) - (Date.parse(b.created_at || 0) || 0)
    ));

  return {
    id: normId(row?.id || ""),
    user_id: normId(row?.user_id || ""),
    widget_type: normalizeProfileWidgetType(row?.widget_type || ""),
    title: normalizeProfileWidgetTitle(row?.title || ""),
    position: clampInt(
      typeof row?.position !== "undefined" ? row.position : row?.widget_position,
      0,
      9999,
      0
    ),
    is_enabled: row?.is_enabled !== false,
    visibility: normalizeProfileWidgetVisibility(row?.visibility || ""),
    created_at: String(row?.created_at || "").trim(),
    updated_at: String(row?.updated_at || "").trim(),
    items,
  };
}

function cloneProfileWidgetsList(list = []) {
  return (Array.isArray(list) ? list : []).map((widget) => ({
    ...widget,
    items: Array.isArray(widget?.items)
      ? widget.items.map((item) => ({
        ...item,
        tags: Array.isArray(item?.tags) ? item.tags.slice() : [],
        metadata: normalizeProfileWidgetItemMetadata(item?.metadata || {}),
      }))
      : [],
  }));
}

function getCachedProfileWidgetsForUser(userId) {
  const uid = normId(userId || "");
  if (!uid) return [];
  return cloneProfileWidgetsList(userCardWidgetsCache.get(uid) || []);
}

