function formatProfileWidgetStars(ratingInput = null) {
  if (!Number.isFinite(Number(ratingInput))) return "";
  const rating = clampInt(ratingInput, 1, 5, 1);
  return `${"★".repeat(rating)}${"☆".repeat(5 - rating)}`;
}

function getProfileWidgetFeaturedItem(widget) {
  if (!widget || !Array.isArray(widget.items) || !widget.items.length) return null;
  return widget.items.find((item) => !!item?.is_featured) || widget.items[0] || null;
}

function isProfileWidgetRpcUnavailable(error) {
  const code = String(error?.code || "").trim().toLowerCase();
  const msg = String(error?.message || "").trim().toLowerCase();
  return code === "42883"
    || code === "pgrst202"
    || msg.includes("list_profile_widgets")
    || msg.includes("create_profile_widget")
    || msg.includes("profile_widgets");
}

function toProfileWidgetError(error, fallbackMessage = "") {
  const fallback = String(fallbackMessage || "").trim() || t("profile.widgets.error.generic", "Could not load profile widgets.");
  if (!error) return fallback;
  if (isProfileWidgetRpcUnavailable(error)) {
    return t(
      "profile.widgets.error.sql_missing",
      "Profile Widgets SQL patch is missing. Apply SQL/SUPABASE_PATCH_PROFILE_INTEREST_WIDGETS.sql."
    );
  }
  return String(error?.message || fallback).trim() || fallback;
}

async function fetchProfileWidgetsForUser(targetUserId, { force = false } = {}) {
  const uid = normId(targetUserId || "");
  if (!uid) return [];
  if (!force && userCardWidgetsCache.has(uid)) {
    return getCachedProfileWidgetsForUser(uid);
  }

  const { data, error } = await supabase.rpc("list_profile_widgets", {
    target_user_id: uid,
  });
  if (error) throw error;

  const widgets = (Array.isArray(data) ? data : [])
    .map((row) => normalizeProfileWidgetRow(row))
    .filter((row) => !!row.id)
    .sort((a, b) => (
      Number(a.position || 0) - Number(b.position || 0)
      || (Date.parse(a.created_at || 0) || 0) - (Date.parse(b.created_at || 0) || 0)
    ));

  userCardWidgetsCache.set(uid, widgets);
  return getCachedProfileWidgetsForUser(uid);
}

async function createProfileWidgetRpc(widgetTypeInput, titleInput) {
  const widgetType = normalizeProfileWidgetType(widgetTypeInput);
  const title = normalizeProfileWidgetTitle(titleInput);
  if (!title) throw new Error(t("profile.widgets.error.title_required", "Title is required."));
  const { data, error } = await supabase.rpc("create_profile_widget", {
    p_widget_type: widgetType,
    p_title: title,
  });
  if (error) throw error;
  return normalizeProfileWidgetRow(data || {});
}

