function dedupeCatalogSearchResults(list = []) {
  const out = [];
  const seen = new Set();
  (Array.isArray(list) ? list : []).forEach((entry) => {
    const item = normalizeCatalogSearchResultRow(entry || {});
    if (!item || !item.title) return;
    const key = `${item.source}::${item.source_id}`;
    if (seen.has(key)) return;
    seen.add(key);
    out.push(item);
  });
  return out;
}

function getProfileWidgetCatalogModalElements() {
  return {
    searchWrap: document.getElementById("profileWidgetCatalogSearch"),
    queryInput: document.getElementById("profileWidgetItemCatalogQuery"),
    results: document.getElementById("profileWidgetCatalogResults"),
    status: document.getElementById("profileWidgetCatalogStatus"),
    addManualBtn: document.getElementById("btnProfileWidgetItemAddManual"),
    manualFields: document.getElementById("profileWidgetItemManualFields"),
  };
}

function setProfileWidgetCatalogUiState({
  loading = false,
  error = "",
  info = "",
} = {}) {
  const els = getProfileWidgetCatalogModalElements();
  if (!els.status) return;
  const statusText = String(error || info || "").trim();
  els.status.textContent = statusText;
  els.status.classList.toggle("is-error", !!error);
  els.status.classList.toggle("is-loading", !!loading);
  if (!loading && !statusText) {
    els.status.textContent = "";
  }
}

function clearProfileWidgetCatalogSearchUi() {
  const els = getProfileWidgetCatalogModalElements();
  if (els.results) {
    els.results.innerHTML = "";
    els.results.dataset.catalogPayload = "[]";
  }
  setProfileWidgetCatalogUiState({ loading: false, error: "", info: "" });
}

function getProfileWidgetCatalogTypeForModal(widgetIdInput = "") {
  const wid = normId(widgetIdInput || "");
  if (!wid) return "custom";
  const widget = findCurrentUserCardWidget(wid);
  return catalogTypeFromWidgetType(widget?.widget_type || "custom");
}

function setProfileWidgetManualFieldsVisible(visible = true) {
  const els = getProfileWidgetCatalogModalElements();
  if (!els.manualFields) return;
  els.manualFields.classList.toggle("hidden", !visible);
  els.manualFields.setAttribute("aria-hidden", visible ? "false" : "true");
}

function setProfileWidgetItemBaseFieldsVisible(visible = true) {
  ["profileWidgetItemTitleField", "profileWidgetItemCoverUrlField", "profileWidgetItemExternalUrlField"].forEach((id) => {
    const el = document.getElementById(id);
    if (!el) return;
    el.classList.toggle("hidden", !visible);
    el.setAttribute("aria-hidden", visible ? "false" : "true");
  });
}

function renderProfileWidgetItemReadonlyPreview(item = null, { visible = false } = {}) {
  const wrap = document.getElementById("profileWidgetItemReadonlyPreview");
  const mediaEl = document.getElementById("profileWidgetItemReadonlyPreviewMedia");
  const titleEl = document.getElementById("profileWidgetItemReadonlyPreviewTitle");
  const metaEl = document.getElementById("profileWidgetItemReadonlyPreviewMeta");
  if (!wrap || !mediaEl || !titleEl || !metaEl) return;

  if (!visible || !item) {
    wrap.classList.add("hidden");
    wrap.setAttribute("aria-hidden", "true");
    mediaEl.innerHTML = "";
    titleEl.textContent = "";
    metaEl.textContent = "";
    metaEl.style.display = "";
    return;
  }

  const title = normalizeProfileWidgetTitle(item?.title || "") || t("profile.widgets.item.untitled", "Untitled");
  const coverUrl = normalizeCatalogCoverUrl(item?.cover_url || "");
  const meta = normalizeProfileWidgetItemMetadata(item?.metadata || {});
  const sourceLabel = meta?.source ? getCatalogSourceLabel(meta.source) : "";
  let releaseYear = Number(meta?.release_year);
  if (!Number.isFinite(releaseYear)) {
    const released = String(meta?.released || "").trim();
    if (/^\d{4}/.test(released)) releaseYear = Number(released.slice(0, 4));
  }
  const safeYear = Number.isFinite(releaseYear)
    ? String(clampInt(releaseYear, 1900, 2100, 1900))
    : "";
  const metaParts = [safeYear, sourceLabel].filter(Boolean);
  const initial = String(title || "?").trim().charAt(0).toUpperCase() || "?";
  mediaEl.innerHTML = coverUrl
    ? `<img src="${escAttr(coverUrl)}" alt="${escAttr(title)}" loading="lazy" />`
    : `<div class="profileWidgetItemReadonlyPreviewFallback">${esc(initial)}</div>`;
  titleEl.textContent = title;
  metaEl.textContent = metaParts.join(" • ");
  metaEl.style.display = metaParts.length ? "" : "none";
  wrap.classList.remove("hidden");
  wrap.setAttribute("aria-hidden", "false");
}

function buildCatalogSearchResultCardHtml(item = {}, idx = 0) {
  const title = normalizeProfileWidgetTitle(item?.title || "");
  if (!title) return "";
  const coverUrl = normalizeCatalogCoverUrl(item?.cover_url || "");
  const year = Number.isFinite(Number(item?.release_year))
    ? String(clampInt(item.release_year, 1900, 2100, 1900))
    : "";
  const source = normalizeCatalogSource(item?.source || "");
  const sourceLabel = getCatalogSourceLabel(source);
  const key = `${source}::${String(item?.source_id || "").trim()}`;
  const initial = title.charAt(0).toUpperCase() || "?";
  const mediaHtml = coverUrl
    ? `<img src="${escAttr(coverUrl)}" alt="${escAttr(title)}" loading="lazy" />`
    : `<div class="userCardWidgetItemFallback">${esc(initial)}</div>`;

  return `
    <article class="profileWidgetCatalogResult" data-catalog-key="${escAttr(key)}">
      <div class="profileWidgetCatalogResultMedia">${mediaHtml}</div>
      <div class="profileWidgetCatalogResultBody">
        <div class="profileWidgetCatalogResultTitle">${esc(title)}</div>
        <div class="profileWidgetCatalogResultMeta">
          ${year ? `<span class="userCardWidgetBadge">${esc(year)}</span>` : ""}
          <span class="userCardWidgetBadge">${esc(sourceLabel)}</span>
          ${item?.result_origin === "external" ? `<span class="userCardWidgetBadge">${esc(t("profile.widgets.catalog.online", "Online"))}</span>` : ""}
        </div>
      </div>
      <div class="profileWidgetCatalogResultActions">
        <button class="userCardWidgetBtn" type="button" data-catalog-add="${escAttr(String(idx))}">${esc(t("profile.widgets.catalog.add", "Add"))}</button>
      </div>
    </article>
  `;
}

function renderProfileWidgetCatalogSearchResults(results = [], {
  onlineError = "",
} = {}) {
  const els = getProfileWidgetCatalogModalElements();
  if (!els.results) return;
  const safeResults = dedupeCatalogSearchResults(results).slice(0, PROFILE_WIDGET_CATALOG_SEARCH_LIMIT);
  profileWidgetItemCatalogSelected = null;
  if (!safeResults.length) {
    els.results.dataset.catalogPayload = "[]";
    els.results.innerHTML = `
      <div class="profileWidgetCatalogEmpty">
        ${esc(t("profile.widgets.catalog.empty", "No results found."))}
      </div>
    `;
    setProfileWidgetCatalogUiState({
      loading: false,
      error: onlineError ? t("profile.widgets.catalog.error.online_only", "Couldn't load online results.") : "",
      info: onlineError ? "" : t("profile.widgets.catalog.empty_hint", "Try another search or add manually."),
    });
    return;
  }

  els.results.dataset.catalogPayload = JSON.stringify(safeResults);
  els.results.innerHTML = safeResults.map((item, idx) => buildCatalogSearchResultCardHtml(item, idx)).join("");
  setProfileWidgetCatalogUiState({
    loading: false,
    error: onlineError ? t("profile.widgets.catalog.error.online_only", "Couldn't load online results.") : "",
    info: onlineError ? "" : "",
  });
}

function getCatalogSearchCacheKey(catalogType, query, limit) {
  const safeType = normalizeCatalogType(catalogType || "");
  const safeQuery = String(query || "").trim().toLowerCase();
  const safeLimit = clampInt(limit, 1, 20, PROFILE_WIDGET_CATALOG_SEARCH_LIMIT);
  return `${safeType}::${safeQuery}::${safeLimit}`;
}

