function shouldSuppressNotificationSoundForStatus(kind, name) {
  if (!shouldMuteNotificationSoundsNow()) return false;
  const cueName = String(name || "").trim().toLowerCase();
  if (!cueName) return false;
  if (kind === "sfx") return DND_MUTED_SFX_NAMES.has(cueName);
  if (kind === "ui") return DND_MUTED_UI_CUE_NAMES.has(cueName);
  return false;
}

