const CALL_CUE_CLOUD_SYNC_COOLDOWN_MS = 12_000;
const CALL_CUE_CLOUD_MAX_DATA_URL_CHARS = 1_500_000;
const CUSTOM_CALL_SOUNDS_ENABLED = false;
