const CALL_CUE_CUSTOMIZABLE_NAMES = new Set(CALL_CUE_CUSTOMIZABLE_META.map((item) => item.cue));
const callCustomCueSrcByName = new Map();
const callCustomCueAudioByName = new Map();
let callCueCloudAvailable = null;
let callCueCloudLastSyncAt = 0;
let callCueCloudSyncInFlight = null;
const callUiCueSessionId = `cue_${Math.random().toString(36).slice(2)}_${Date.now().toString(36)}`;
const LOCAL_CALL_CUE_ECHO_GUARD_MS = 7000;
const localCallCueEchoGuardUntilByCue = new Map();
const LOCAL_REMOTE_CALL_CUE_SUPPRESS_MS = 7000;
const localRemoteCallCueSuppressUntilByCue = new Map();
const LOCAL_CALL_CUE_EVENT_TTL_MS = 15000;
const localCallCueEventIdsUntil = new Map();
const REMOTE_CALL_CUE_EVENT_DEDUPE_TTL_MS = 20000;
const REMOTE_CALL_CUE_MAX_AGE_MS = 4500;
const seenRemoteCallCueEventIdsUntil = new Map();
const CALL_CUE_SPAM_DEDUPE_TTL_MS = 12000;
const CALL_CUE_SPAM_REPEAT_MS = 420;
const CALL_CUE_SPAM_EMITTER_MS = 140;
const CALL_CUE_SPAM_CONVERSATION_MS = 85;
const recentCallCueSpamKeysUntil = new Map();
let uiAudioCtx = null;

function getUiAudioCtx() {
  if (uiAudioCtx) return uiAudioCtx;
  const Ctor = window.AudioContext || window.webkitAudioContext;
  if (!Ctor) return null;
  try {
    uiAudioCtx = new Ctor();
  } catch (_) {
    uiAudioCtx = null;
  }
  return uiAudioCtx;
}

function resumeUiAudioCtx() {
  const ctx = getUiAudioCtx();
  if (!ctx) return;
  if (ctx.state === "suspended") ctx.resume().catch(() => {});
}

function loadCustomCallCuesFromStorageLegacy() {
  callCustomCueSrcByName.clear();
  try {
    const raw = localStorage.getItem(CALL_CUE_CUSTOM_STORAGE_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object") return;
    for (const [key, value] of Object.entries(parsed)) {
      const cue = String(key || "").trim();
      const src = String(value || "").trim();
      if (!CALL_CUE_CUSTOMIZABLE_NAMES.has(cue)) continue;
      if (!src.startsWith("data:audio/")) continue;
      callCustomCueSrcByName.set(cue, src);
    }
  } catch (_) {}
}

function saveCustomCallCuesToStorageLegacy() {
  try {
    const payload = {};
    for (const [cue, src] of callCustomCueSrcByName.entries()) {
      if (!CALL_CUE_CUSTOMIZABLE_NAMES.has(cue)) continue;
      if (!String(src || "").startsWith("data:audio/")) continue;
      payload[cue] = src;
    }
    localStorage.setItem(CALL_CUE_CUSTOM_STORAGE_KEY, JSON.stringify(payload));
    return true;
  } catch (_) {
    return false;
  }
}

function estimateDataUrlBytes(dataUrl) {
  const raw = String(dataUrl || "");
  const comma = raw.indexOf(",");
  if (comma < 0) return 0;
  const b64 = raw.slice(comma + 1);
  return Math.max(0, Math.floor((b64.length * 3) / 4));
}

function getCustomCallCueSrcLegacy(cueName) {
  const cue = String(cueName || "").trim();
  if (!CALL_CUE_CUSTOMIZABLE_NAMES.has(cue)) return "";
  return String(callCustomCueSrcByName.get(cue) || "");
}

function setCustomCallCueSrcLegacy(cueName, dataUrl, { allowLocalFailure = false } = {}) {
  const cue = String(cueName || "").trim();
  const src = String(dataUrl || "").trim();
  if (!CALL_CUE_CUSTOMIZABLE_NAMES.has(cue)) return false;
  const prev = String(callCustomCueSrcByName.get(cue) || "");
  if (src) callCustomCueSrcByName.set(cue, src);
  else callCustomCueSrcByName.delete(cue);
  callCustomCueAudioByName.delete(cue);
  if (saveCustomCallCuesToStorage()) return true;
  if (allowLocalFailure) return true;
  if (prev) callCustomCueSrcByName.set(cue, prev);
  else callCustomCueSrcByName.delete(cue);
  return false;
}

function resetAllCustomCallCueSrcLegacy() {
  callCustomCueSrcByName.clear();
  callCustomCueAudioByName.clear();
  return saveCustomCallCuesToStorage();
}

function getCustomCallCueAudioLegacy(cueName) {
  const cue = String(cueName || "").trim();
  const src = getCustomCallCueSrc(cue);
  if (!cue || !src) return null;
  const cached = callCustomCueAudioByName.get(cue) || null;
  if (cached && String(cached.src || "") === src) return cached;
  const audio = new Audio(src);
  audio.preload = "auto";
  audio.loop = false;
  audio.__failed = false;
  audio.addEventListener("error", () => { audio.__failed = true; });
  callCustomCueAudioByName.set(cue, audio);
  return audio;
}

loadCustomCallCuesFromStorage();

function isMissingCallCueCloudTableError(error) {
  const code = String(error?.code || "").trim().toLowerCase();
  const msg = String(error?.message || "").trim().toLowerCase();
  const details = String(error?.details || "").trim().toLowerCase();
  if (!code && !msg && !details) return false;
  if (code === "42p01" || code === "pgrst205") return true;
  return (
    (msg.includes(CALL_CUE_CLOUD_TABLE) && (msg.includes("not exist") || msg.includes("schema cache")))
    || (details.includes(CALL_CUE_CLOUD_TABLE) && details.includes("not exist"))
  );
}

function normalizeCallCueCloudDataUrl(value) {
  const src = String(value || "").trim();
  if (!src.startsWith("data:audio/")) return "";
  if (src.length > CALL_CUE_CLOUD_MAX_DATA_URL_CHARS) return "";
  return src;
}

function snapshotCustomCallCueMap() {
  return new Map(callCustomCueSrcByName);
}

function restoreCustomCallCueMap(snapshot) {
  callCustomCueSrcByName.clear();
  if (snapshot instanceof Map) {
    snapshot.forEach((src, cue) => {
      const cueName = String(cue || "").trim();
      const dataUrl = normalizeCallCueCloudDataUrl(src);
      if (!CALL_CUE_CUSTOMIZABLE_NAMES.has(cueName) || !dataUrl) return;
      callCustomCueSrcByName.set(cueName, dataUrl);
    });
  }
  callCustomCueAudioByName.clear();
}

async function syncCustomCallCuesFromCloudLegacy({ force = false } = {}) {
  const meId = normId(state?.user?.id || "");
  if (!meId) return false;
  if (!force && callCueCloudSyncInFlight) return callCueCloudSyncInFlight;
  const nowMs = Date.now();
  if (!force && (nowMs - Number(callCueCloudLastSyncAt || 0)) < CALL_CUE_CLOUD_SYNC_COOLDOWN_MS) return false;

  const localByCue = new Map();
  CALL_CUE_CUSTOMIZABLE_NAMES.forEach((cue) => {
    const src = normalizeCallCueCloudDataUrl(callCustomCueSrcByName.get(cue));
    if (src) localByCue.set(cue, src);
  });

  const run = (async () => {
    const { data, error } = await supabase
      .from(CALL_CUE_CLOUD_TABLE)
      .select("cue_name,audio_data")
      .eq("user_id", meId);

    if (error) {
      if (isMissingCallCueCloudTableError(error)) {
        callCueCloudAvailable = false;
        callCueCloudLastSyncAt = Date.now();
        return false;
      }
      console.warn("call cues: cloud sync read failed", error);
      return false;
    }

    callCueCloudAvailable = true;
    const remoteByCue = new Map();
    (Array.isArray(data) ? data : []).forEach((row) => {
      const cue = String(row?.cue_name || "").trim();
      if (!CALL_CUE_CUSTOMIZABLE_NAMES.has(cue)) return;
      const src = normalizeCallCueCloudDataUrl(row?.audio_data);
      if (!src) return;
      remoteByCue.set(cue, src);
    });

    let changed = false;
    remoteByCue.forEach((remoteSrc, cue) => {
      const prev = normalizeCallCueCloudDataUrl(callCustomCueSrcByName.get(cue));
      if (prev === remoteSrc) return;
      callCustomCueSrcByName.set(cue, remoteSrc);
      callCustomCueAudioByName.delete(cue);
      changed = true;
    });
    if (changed) saveCustomCallCuesToStorage();

    const rowsToBackfill = [];
    localByCue.forEach((src, cue) => {
      if (remoteByCue.has(cue)) return;
      rowsToBackfill.push({
        user_id: meId,
        cue_name: cue,
        audio_data: src,
        byte_size: estimateDataUrlBytes(src),
      });
    });
    if (rowsToBackfill.length) {
      const { error: backfillErr } = await supabase
        .from(CALL_CUE_CLOUD_TABLE)
        .upsert(rowsToBackfill, { onConflict: "user_id,cue_name" });
      if (backfillErr) {
        if (isMissingCallCueCloudTableError(backfillErr)) {
          callCueCloudAvailable = false;
        } else {
          console.warn("call cues: cloud backfill failed", backfillErr);
        }
      }
    }

    callCueCloudLastSyncAt = Date.now();
    return changed || rowsToBackfill.length > 0;
  })();

  callCueCloudSyncInFlight = run;
  try {
    return await run;
  } finally {
    if (callCueCloudSyncInFlight === run) callCueCloudSyncInFlight = null;
  }
}

async function writeCustomCallCueToCloudLegacy(cueName) {
  const meId = normId(state?.user?.id || "");
  const cue = String(cueName || "").trim();
  if (!meId || !CALL_CUE_CUSTOMIZABLE_NAMES.has(cue)) return false;
  if (callCueCloudAvailable === false) return false;
  const src = normalizeCallCueCloudDataUrl(callCustomCueSrcByName.get(cue));

  if (src) {
    const { error } = await supabase
      .from(CALL_CUE_CLOUD_TABLE)
      .upsert({
        user_id: meId,
        cue_name: cue,
        audio_data: src,
        byte_size: estimateDataUrlBytes(src),
      }, { onConflict: "user_id,cue_name" });
    if (error) {
      if (isMissingCallCueCloudTableError(error)) {
        callCueCloudAvailable = false;
        return false;
      }
      console.warn("call cues: cloud upsert failed", error);
      return false;
    }
  } else {
    const { error } = await supabase
      .from(CALL_CUE_CLOUD_TABLE)
      .delete()
      .eq("user_id", meId)
      .eq("cue_name", cue);
    if (error) {
      if (isMissingCallCueCloudTableError(error)) {
        callCueCloudAvailable = false;
        return false;
      }
      console.warn("call cues: cloud delete failed", error);
      return false;
    }
  }

  callCueCloudAvailable = true;
  callCueCloudLastSyncAt = Date.now();
  return true;
}

async function resetCustomCallCuesInCloudLegacy() {
  const meId = normId(state?.user?.id || "");
  if (!meId) return false;
  if (callCueCloudAvailable === false) return false;
  const { error } = await supabase
    .from(CALL_CUE_CLOUD_TABLE)
    .delete()
    .eq("user_id", meId);
  if (error) {
    if (isMissingCallCueCloudTableError(error)) {
      callCueCloudAvailable = false;
      return false;
    }
    console.warn("call cues: cloud reset failed", error);
    return false;
  }
  callCueCloudAvailable = true;
  callCueCloudLastSyncAt = Date.now();
  return true;
}

function loadCustomCallCuesFromStorage() {
  callCustomCueSrcByName.clear();
  callCustomCueAudioByName.clear();
  try { localStorage.removeItem(CALL_CUE_CUSTOM_STORAGE_KEY); } catch (_) {}
}

function saveCustomCallCuesToStorage() {
  callCustomCueSrcByName.clear();
  callCustomCueAudioByName.clear();
  try { localStorage.removeItem(CALL_CUE_CUSTOM_STORAGE_KEY); } catch (_) {}
  return true;
}

function getCustomCallCueSrc(cueName) {
  void cueName;
  return "";
}

function setCustomCallCueSrc(cueName, dataUrl, { allowLocalFailure = false } = {}) {
  void cueName;
  void dataUrl;
  void allowLocalFailure;
  return false;
}

function resetAllCustomCallCueSrc() {
  callCustomCueSrcByName.clear();
  callCustomCueAudioByName.clear();
  try { localStorage.removeItem(CALL_CUE_CUSTOM_STORAGE_KEY); } catch (_) {}
  return true;
}

function getCustomCallCueAudio(cueName) {
  void cueName;
  return null;
}

async function syncCustomCallCuesFromCloud({ force = false } = {}) {
  void force;
  callCueCloudAvailable = false;
  callCueCloudSyncInFlight = null;
  callCueCloudLastSyncAt = Date.now();
  return false;
}

async function writeCustomCallCueToCloud(cueName) {
  void cueName;
  callCueCloudAvailable = false;
  return false;
}

async function resetCustomCallCuesInCloud() {
  callCueCloudAvailable = false;
  return false;
}

function markLocalCallCueEchoGuard(cueName) {
  const cue = String(cueName || "").trim().toLowerCase();
  if (!CALL_REMOTE_CUE_NAMES.has(cue)) return;
  localCallCueEchoGuardUntilByCue.set(cue, Date.now() + LOCAL_CALL_CUE_ECHO_GUARD_MS);
}

function shouldIgnoreUiCueAsLocalEcho(cueName) {
  const cue = String(cueName || "").trim().toLowerCase();
  if (!CALL_REMOTE_CUE_NAMES.has(cue)) return false;
  const until = Number(localCallCueEchoGuardUntilByCue.get(cue) || 0);
  if (!Number.isFinite(until) || until <= 0) return false;
  if (Date.now() > until) {
    localCallCueEchoGuardUntilByCue.delete(cue);
    return false;
  }
  return true;
}

function markLocalRemoteCallCueSuppress(cueName) {
  const cue = String(cueName || "").trim().toLowerCase();
  if (!CALL_REMOTE_CUE_NAMES.has(cue)) return;
  const remoteCue = String(CALL_REMOTE_CUE_VARIANTS[cue] || "").trim();
  if (!remoteCue) return;
  localRemoteCallCueSuppressUntilByCue.set(remoteCue, Date.now() + LOCAL_REMOTE_CALL_CUE_SUPPRESS_MS);
}

function rememberLocalCallCueEventId(eventId) {
  const id = String(eventId || "").trim();
  if (!id) return;
  const now = Date.now();
  localCallCueEventIdsUntil.set(id, now + LOCAL_CALL_CUE_EVENT_TTL_MS);
  for (const [key, until] of localCallCueEventIdsUntil.entries()) {
    if (!Number.isFinite(until) || until <= now) localCallCueEventIdsUntil.delete(key);
  }
}

function isLocalCallCueEventId(eventId) {
  const id = String(eventId || "").trim();
  if (!id) return false;
  const now = Date.now();
  const until = Number(localCallCueEventIdsUntil.get(id) || 0);
  if (!Number.isFinite(until) || until <= now) {
    if (localCallCueEventIdsUntil.has(id)) localCallCueEventIdsUntil.delete(id);
    return false;
  }
  return true;
}

function rememberSeenRemoteCallCueEventId(eventId) {
  const id = String(eventId || "").trim();
  if (!id) return;
  const now = Date.now();
  seenRemoteCallCueEventIdsUntil.set(id, now + REMOTE_CALL_CUE_EVENT_DEDUPE_TTL_MS);
  for (const [key, until] of seenRemoteCallCueEventIdsUntil.entries()) {
    if (!Number.isFinite(until) || until <= now) seenRemoteCallCueEventIdsUntil.delete(key);
  }
}

function hasSeenRemoteCallCueEventId(eventId) {
  const id = String(eventId || "").trim();
  if (!id) return false;
  const now = Date.now();
  const until = Number(seenRemoteCallCueEventIdsUntil.get(id) || 0);
  if (!Number.isFinite(until) || until <= now) {
    if (seenRemoteCallCueEventIdsUntil.has(id)) seenRemoteCallCueEventIdsUntil.delete(id);
    return false;
  }
  return true;
}

function shouldSuppressRemoteCallCue(cueName) {
  const cue = String(cueName || "").trim();
  if (!cue || !cue.startsWith("remote_")) return false;
  const until = Number(localRemoteCallCueSuppressUntilByCue.get(cue) || 0);
  if (!Number.isFinite(until) || until <= 0) return false;
  if (Date.now() > until) {
    localRemoteCallCueSuppressUntilByCue.delete(cue);
    return false;
  }
  return true;
}

function shouldSuppressCallCueSpam(cueName, { conversationId = "", emitterUserId = "", source = "remote" } = {}) {
  const cue = String(cueName || "").trim().toLowerCase();
  if (!cue || !CALL_CUE_CUSTOMIZABLE_NAMES.has(cue)) return false;

  const now = Date.now();
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const emitterId = normId(emitterUserId || "");
  const src = String(source || "remote").trim().toLowerCase() || "remote";
  const convKey = `conv:${src}:${convId || "na"}`;
  const emitterKey = emitterId ? `emitter:${src}:${convId || "na"}:${emitterId}` : "";
  const cueKey = `cue:${src}:${convId || "na"}:${emitterId || "local"}:${cue}`;

  const cueUntil = Number(recentCallCueSpamKeysUntil.get(cueKey) || 0);
  if (Number.isFinite(cueUntil) && cueUntil > now) return true;

  if (emitterKey) {
    const emitterUntil = Number(recentCallCueSpamKeysUntil.get(emitterKey) || 0);
    if (Number.isFinite(emitterUntil) && emitterUntil > now) return true;
  }

  const convUntil = Number(recentCallCueSpamKeysUntil.get(convKey) || 0);
  if (Number.isFinite(convUntil) && convUntil > now) return true;

  recentCallCueSpamKeysUntil.set(cueKey, now + CALL_CUE_SPAM_REPEAT_MS);
  if (emitterKey) recentCallCueSpamKeysUntil.set(emitterKey, now + CALL_CUE_SPAM_EMITTER_MS);
  recentCallCueSpamKeysUntil.set(convKey, now + CALL_CUE_SPAM_CONVERSATION_MS);

  for (const [key, until] of recentCallCueSpamKeysUntil.entries()) {
    if (!Number.isFinite(until) || until <= now || (until - now) > CALL_CUE_SPAM_DEDUPE_TTL_MS) {
      recentCallCueSpamKeysUntil.delete(key);
    }
  }
  return false;
}

function playUiCueFallback(name, depth = 0) {
  const ctx = getUiAudioCtx();
  if (!ctx) return;
  if (ctx.state === "suspended") {
    ctx.resume()
      .then(() => {
        if (depth < 2) {
          setTimeout(() => playUiCueFallback(name, depth + 1), 16);
        }
      })
      .catch(() => {});
    return;
  }

  const cueMap = {
    msg: [[1046, 0.0, 0.05, 0.028], [1318, 0.055, 0.06, 0.026]],
    group_dm: [[740, 0.0, 0.055, 0.028], [988, 0.06, 0.07, 0.026]],
    call_join: [[840, 0.0, 0.05, 0.028], [1120, 0.055, 0.06, 0.026]],
    mic_on: [[900, 0.0, 0.055, 0.03]],
    mic_off: [[520, 0.0, 0.06, 0.03]],
    deafen_on: [[440, 0.0, 0.065, 0.03]],
    deafen_off: [[760, 0.0, 0.058, 0.03]],
    share_on: [[640, 0.0, 0.055, 0.028], [980, 0.06, 0.08, 0.026]],
    share_off: [[980, 0.0, 0.055, 0.028], [640, 0.06, 0.08, 0.026]],
    camera_on: [[720, 0.0, 0.05, 0.026], [860, 0.052, 0.055, 0.024]],
    camera_off: [[860, 0.0, 0.05, 0.026], [720, 0.052, 0.055, 0.024]],
    remote_share_on: [[560, 0.0, 0.045, 0.024], [840, 0.05, 0.06, 0.023]],
    remote_share_off: [[820, 0.0, 0.045, 0.024], [560, 0.052, 0.062, 0.023]],
    remote_camera_on: [[610, 0.0, 0.04, 0.024], [760, 0.045, 0.05, 0.022], [930, 0.1, 0.05, 0.021]],
    remote_camera_off: [[930, 0.0, 0.042, 0.024], [760, 0.045, 0.05, 0.022], [610, 0.098, 0.054, 0.021]],
    remote_mic_on: [[820, 0.0, 0.046, 0.022], [980, 0.048, 0.048, 0.02]],
    remote_mic_off: [[680, 0.0, 0.048, 0.022], [520, 0.052, 0.05, 0.02]],
    remote_deafen_on: [[420, 0.0, 0.062, 0.024], [360, 0.066, 0.07, 0.022]],
    remote_deafen_off: [[520, 0.0, 0.048, 0.022], [700, 0.05, 0.056, 0.021]],
  };
  const seq = cueMap[name];
  if (!seq || !seq.length) return;

  const now = ctx.currentTime + 0.004;
  seq.forEach(([freq, delay, dur, vol]) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = "sine";
    osc.frequency.setValueAtTime(Number(freq) || 700, now + delay);

    gain.gain.setValueAtTime(0.0001, now + delay);
    gain.gain.exponentialRampToValueAtTime(Math.max(0.0002, Number(vol) || 0.025), now + delay + 0.012);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + delay + dur);

    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(now + delay);
    osc.stop(now + delay + dur + 0.02);
  });
}

function playUiCue(name, depth = 0) {
  if (shouldSuppressNotificationSoundForStatus("ui", name)) return;
  if (shouldSuppressRemoteCallCue(name)) return;
  resumeUiAudioCtx();
  const customAudio = getCustomCallCueAudio(name);
  const candidates = customAudio
    ? [customAudio, ...(UI_SFX[name] || [])]
    : (UI_SFX[name] || []);
  for (const audio of candidates) {
    if (!audio || audio.__failed) continue;
    try {
      audio.muted = false;
      audio.volume = 1;
      audio.currentTime = 0;
      const p = audio.play();
      if (p?.catch) {
        p.catch((err) => {
          const raw = String(err?.name || err?.message || "").toLowerCase();
          const missingSrc = !!audio.error || raw.includes("notsupported") || raw.includes("notfound") || raw.includes("decode");
          const blockedByPolicy = raw.includes("notallowed") || raw.includes("autoplay") || raw.includes("interrupted");
          if (missingSrc) {
            audio.__failed = true;
            if (depth < 8) playUiCue(name, depth + 1);
            else playUiCueFallback(name);
            return;
          }
          if (blockedByPolicy) {
            audioUnlocked = false;
            void unlockAudioOnce();
          }
          playUiCueFallback(name);
        });
      }
      return;
    } catch (err) {
      const raw = String(err?.name || err?.message || "").toLowerCase();
      const missingSrc = !!audio.error || raw.includes("notsupported") || raw.includes("notfound") || raw.includes("decode");
      const blockedByPolicy = raw.includes("notallowed") || raw.includes("autoplay") || raw.includes("interrupted");
      if (missingSrc) audio.__failed = true;
      if (blockedByPolicy) {
        audioUnlocked = false;
        void unlockAudioOnce();
      }
    }
  }
  playUiCueFallback(name);
}

function playAndBroadcastLocalCallCue(cueName) {
  const cue = String(cueName || "").trim().toLowerCase();
  if (!cue) return;
  const convId = normId(callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  const meId = normId(state.user?.id || "");
  if (shouldSuppressCallCueSpam(cue, { conversationId: convId, emitterUserId: meId, source: "local" })) return;
  markLocalRemoteCallCueSuppress(cue);
  playUiCue(cue);
  logMediaSfxPlayed(cue, {
    participantId: meId,
    tileType: cue.includes("share") ? "screenshare" : "primary",
    isLocalUser: true,
    triggerReason: "local_call_ui_cue",
    callerFunction: "playAndBroadcastLocalCallCue",
  });
  void sendCallUiCueSignal(cue);
}

function isExpectedRemoteUiCueEmitter(userId, conversationId) {
  const uid = normId(userId || "");
  const convId = normId(conversationId || "");
  const meId = normId(state.user?.id || "");
  const activeConvId = normId(callConversationId || "");
  if (!uid || !convId || !meId || uid === meId) return false;
  if (!inCall || !activeConvId || convId !== activeConvId) return false;

  if (!groupCallMode) {
    const pcConnState = String(callPc?.connectionState || "").toLowerCase();
    const pcIceState = String(callPc?.iceConnectionState || "").toLowerCase();
    const badConn = pcConnState === "failed" || pcConnState === "closed" || pcConnState === "disconnected";
    const badIce = pcIceState === "failed" || pcIceState === "closed" || pcIceState === "disconnected";
    if (badConn || badIce) return false;
    const peerIds = normalizeUuidArray([callMediaPeerUserId, callOtherUserId]);
    return peerIds.includes(uid);
  }

  const remoteEffectiveIds = normalizeUuidArray(getEffectiveGroupCallActiveUserIds(convId))
    .filter((id) => id && id !== meId);
  if (remoteEffectiveIds.includes(uid)) return true;

  if (isServerVoiceConversationById(convId)) {
    const voicePresenceIds = normalizeUuidArray(getServerVoicePresenceMemberIds(convId))
      .filter((id) => id && id !== meId);
    if (voicePresenceIds.includes(uid)) return true;
  }

  return false;
}

let audioUnlocked = false;
let audioUnlockInFlight = false;
async function unlockAudioOnce() {
  if (audioUnlocked || audioUnlockInFlight) return;
  audioUnlockInFlight = true;
  resumeUiAudioCtx();
  let anySuccess = false;
  const uiSfxAll = Object.values(UI_SFX).flat();
  for (const a of [...Object.values(SFX), ...uiSfxAll]) {
    const prevVolume = Number.isFinite(a?.volume) ? a.volume : 1;
    const prevMuted = !!a?.muted;
    try {
      a.muted = false;
      a.volume = 0.0001;
      const p = a.play();
      if (p?.then) {
        try {
          await p;
          anySuccess = true;
        } catch (_) {}
        try { a.pause(); a.currentTime = 0; } catch (_) {}
        try { a.volume = prevVolume; } catch (_) {}
        try { a.muted = prevMuted; } catch (_) {}
      } else {
        anySuccess = true;
        try { a.pause(); a.currentTime = 0; } catch (_) {}
        try { a.volume = prevVolume; } catch (_) {}
        try { a.muted = prevMuted; } catch (_) {}
      }
    } catch (_) {
      try { a.volume = prevVolume; } catch (_) {}
      try { a.muted = prevMuted; } catch (_) {}
    }
  }
  const ctx = getUiAudioCtx();
  if (ctx?.state === "running") anySuccess = true;
  audioUnlocked = anySuccess;
  audioUnlockInFlight = false;
}
const requestAudioUnlock = () => { void unlockAudioOnce(); };
window.addEventListener("pointerdown", requestAudioUnlock, true);
window.addEventListener("keydown", requestAudioUnlock, true);
window.addEventListener("touchstart", requestAudioUnlock, { passive: true, capture: true });
window.addEventListener("focus", () => {
  resumeUiAudioCtx();
  if (!audioUnlocked) requestAudioUnlock();
});
document.addEventListener("visibilitychange", () => {
  if (document.visibilityState !== "visible") return;
  resumeUiAudioCtx();
  if (!audioUnlocked) requestAudioUnlock();
});

function playSfx(name) {
  if (shouldSuppressNotificationSoundForStatus("sfx", name)) return;
  const a = SFX[name];
  if (!a) return;
  try { a.currentTime = 0; a.play().catch(() => {}); } catch (_) {}
}
function stopSfx(name) {
  const a = SFX[name];
  if (!a) return;
  try { a.pause(); a.currentTime = 0; } catch (_) {}
}

function resetCallEventState() {
  callEventConversationId = null;
  callEventPeerUserId = null;
  callEventInitiatorUserId = null;
  callEventStartAtMs = 0;
  callEventConnectedAtMs = 0;
  callEventStartLogged = false;
  callEventEndLogged = false;
  callEventMessageId = null;
  callEventStartInsertPromise = null;
}

function rememberCallEventContext({
  conversationId = null,
  peerUserId = null,
  initiatorUserId = null,
  startedAtMs = null,
} = {}) {
  const convId = normId(conversationId);
  const peerId = normId(peerUserId);
  const initiatorId = normId(initiatorUserId);
  if (convId) callEventConversationId = convId;
  if (peerId) callEventPeerUserId = peerId;
  if (initiatorId) callEventInitiatorUserId = initiatorId;

  const ts = Number(startedAtMs);
  if (Number.isFinite(ts) && ts > 0) {
    if (!callEventStartAtMs || ts < callEventStartAtMs) callEventStartAtMs = ts;
  }
}

async function insertCallEventMessage({
  event = "started",
  phase = "",
  durationMs = null,
  startedAtMs = null,
  endedAtMs = null,
} = {}) {
  if (!state.user?.id) return false;
  const conversationId = normId(
    callEventConversationId ||
    callConversationId ||
    activeDmId ||
    pendingCallInfo?.conversationId
  );
  if (!conversationId) return false;

  const payload = {
    type: "call_event",
    event: String(event || "started") === "ended" ? "ended" : "started",
  };
  if (phase) payload.phase = String(phase);

  const startedTs = Number(startedAtMs);
  if (Number.isFinite(startedTs) && startedTs > 0) {
    payload.started_at = new Date(startedTs).toISOString();
  }

  const endedTs = Number(endedAtMs);
  if (Number.isFinite(endedTs) && endedTs > 0) {
    payload.ended_at = new Date(endedTs).toISOString();
  }

  const dur = Number(durationMs);
  if (Number.isFinite(dur) && dur >= 0) {
    payload.duration_ms = Math.round(dur);
  }

  let insertPayload = null;
  try {
    insertPayload = await buildConversationMessageInsertPayload({
      conversationId,
      content: JSON.stringify(payload),
    });
  } catch (error) {
    console.warn("call event message build failed", error?.message || error);
    return false;
  }

  const { error } = await supabase.from("messages").insert(insertPayload);
  if (error) {
    console.warn("call event message insert failed", error?.message || error);
    return false;
  }

  if (payload.event === "started") {
    const resolvedId = await resolveLatestOpenCallEventMessageId(conversationId);
    if (resolvedId) callEventMessageId = resolvedId;
  }

  return true;
}

async function resolveLatestOpenCallEventMessageId(conversationId) {
  const convId = normId(conversationId);
  if (!convId || !state.user?.id) return "";

  const isDirectDm = await isDirectDmConversationId(convId);
  const { data, error } = await supabase
    .from("messages")
    .select(isDirectDm ? dmMessageSelectColumns() : "id, content, created_at")
    .eq("conversation_id", convId)
    .eq("user_id", state.user.id)
    .order("created_at", { ascending: false })
    .limit(80);

  if (error) {
    console.warn("call event message resolve failed", error?.message || error);
    return "";
  }

  const rows = isDirectDm
    ? await hydrateDmRowsForDisplay(Array.isArray(data) ? data : [], { conversationId: convId })
    : (Array.isArray(data) ? data : []);

  for (const row of rows) {
    const parsed = safeParseMessageContent(row?.content);
    if (parsed.type !== "call_event") continue;
    if (parsed.event === "ended") continue;
    const id = normId(row?.id);
    if (id) return id;
  }
  return "";
}

async function updateCallEventMessage(messageId, {
  event = "ended",
  phase = "",
  durationMs = null,
  startedAtMs = null,
  endedAtMs = null,
} = {}) {
  const mid = normId(messageId);
  if (!mid || !state.user?.id) return false;

  const conversationId = normId(
    callEventConversationId ||
    callConversationId ||
    activeDmId ||
    pendingCallInfo?.conversationId
  );
  if (!conversationId) return false;

  const payload = {
    type: "call_event",
    event: String(event || "started") === "ended" ? "ended" : "started",
  };
  if (phase) payload.phase = String(phase);

  const startedTs = Number(startedAtMs);
  if (Number.isFinite(startedTs) && startedTs > 0) {
    payload.started_at = new Date(startedTs).toISOString();
  }

  const endedTs = Number(endedAtMs);
  if (Number.isFinite(endedTs) && endedTs > 0) {
    payload.ended_at = new Date(endedTs).toISOString();
  }

  const dur = Number(durationMs);
  if (Number.isFinite(dur) && dur >= 0) {
    payload.duration_ms = Math.round(dur);
  }

  let updatePayload = null;
  try {
    updatePayload = await buildConversationMessageUpdatePayload({
      conversationId,
      content: JSON.stringify(payload),
      existingMessage: getMessageById(mid),
    });
  } catch (error) {
    console.warn("call event message build update failed", error?.message || error);
    return false;
  }

  const { error } = await supabase
    .from("messages")
    .update(updatePayload)
    .eq("id", mid)
    .eq("conversation_id", conversationId)
    .eq("user_id", state.user.id);

  if (error) {
    console.warn("call event message update failed", error?.message || error);
    return false;
  }
  return true;
}

function tryLogCallStartEvent(phase = "ringing") {
  const meId = normId(state.user?.id);
  if (!meId) return;
  const initiator = normId(callEventInitiatorUserId || meId);
  if (initiator !== meId) return;
  if (callEventStartLogged) return;

  if (!callEventStartAtMs) callEventStartAtMs = Date.now();
  callEventStartLogged = true;
  callEventStartInsertPromise = insertCallEventMessage({
    event: "started",
    phase,
    startedAtMs: callEventStartAtMs,
  }).then((ok) => {
    if (!ok) callEventStartLogged = false;
  }).finally(() => {
    callEventStartInsertPromise = null;
  });
}

function tryLogCallEndEvent() {
  const meId = normId(state.user?.id);
  const initiator = normId(callEventInitiatorUserId);
  if (!meId || !initiator || meId !== initiator) return;
  if (callEventEndLogged) return;

  const endedAtMs = Date.now();
  const startedAtMs = callEventConnectedAtMs || callEventStartAtMs || endedAtMs;
  const durationMs = Math.max(0, endedAtMs - startedAtMs);
  callEventEndLogged = true;
  void (async () => {
    if (callEventStartInsertPromise) {
      try { await callEventStartInsertPromise; } catch (_) {}
    }

    const conversationId = normId(
      callEventConversationId ||
      callConversationId ||
      activeDmId ||
      pendingCallInfo?.conversationId
    );

    let targetMessageId = normId(callEventMessageId);
    if (!targetMessageId && conversationId) {
      targetMessageId = await resolveLatestOpenCallEventMessageId(conversationId);
      if (targetMessageId) callEventMessageId = targetMessageId;
    }

    let ok = false;
    if (targetMessageId) {
      ok = await updateCallEventMessage(targetMessageId, {
        event: "ended",
        durationMs,
        startedAtMs,
        endedAtMs,
      });
    } else {
      // Fallback: if we cannot resolve the initial call-event message,
      // still store a final call-event status.
      ok = await insertCallEventMessage({
        event: "ended",
        durationMs,
        startedAtMs,
        endedAtMs,
      });
    }

    if (!ok) callEventEndLogged = false;
  })();
}

function getShareQualityValue() {
  const ui = document.getElementById("shareQuality");
  const raw = String(ui?.value || localStorage.getItem(SHARE_QUALITY_KEY) || SHARE_QUALITY_DEFAULT).trim();
  if (SHARE_QUALITY_ALLOWED.has(raw)) return raw;
  return SHARE_QUALITY_DEFAULT;
}

function normalizeShareProfileValue(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  return SHARE_PROFILE_ALLOWED.has(raw) ? raw : SHARE_PROFILE_DEFAULT;
}

function getShareProfileValue() {
  const ui = document.getElementById("shareProfile");
  return normalizeShareProfileValue(ui?.value || localStorage.getItem(SHARE_PROFILE_KEY) || SHARE_PROFILE_DEFAULT);
}

function getShareProfileLabel(value = getShareProfileValue()) {
  const profile = normalizeShareProfileValue(value);
  if (profile === "clarity") return t("call.share.profile.clarity", "Clarity");
  if (profile === "fluid") return t("call.share.profile.fluid", "Fluid");
  return t("call.share.profile.balanced", "Balanced");
}

function getShareAudioEnabled() {
  const raw = localStorage.getItem(SHARE_AUDIO_KEY);
  return raw ? raw === "1" : true;
}

function normalizeShareSourceKind(value) {
  const raw = String(value || "").trim().toLowerCase();
  if (raw === "screen" || raw === "monitor") return "screen";
  if (raw === "window" || raw === "application" || raw === "app" || raw === "browser") return "window";
  return "";
}

function inferShareSourceKindFromSourceId(sourceId) {
  const raw = String(sourceId || "").trim().toLowerCase();
  if (raw.startsWith("screen:")) return "screen";
  if (raw.startsWith("window:")) return "window";
  return "";
}

function inferShareSourceKindFromTrack(track = null) {
  const settings = track?.getSettings?.() || {};
  const surface = normalizeShareSourceKind(settings?.displaySurface || "");
  if (surface) return surface;
  const label = String(track?.label || "").toLowerCase();
  if (/window|application|app|browser/.test(label)) return "window";
  if (/screen|display|monitor|desktop/.test(label)) return "screen";
  return "";
}

function getCurrentShareSourceKind() {
  const activeKind = normalizeShareSourceKind(desktopShareActiveSourceKind || "");
  if (activeKind) return activeKind;
  return inferShareSourceKindFromTrack(getLiveScreenTrack()) || "screen";
}

function getShareSourceKindLabel(value = "") {
  const kind = normalizeShareSourceKind(value || "");
  if (kind === "window") return t("call.share.source.window", "App");
  return t("call.share.source.screen", "Screen");
}

function getCurrentShareSourceName() {
  const explicitName = String(desktopShareActiveSourceName || "").trim();
  if (explicitName) return explicitName;
  const liveLabel = String(getLiveScreenTrack()?.label || "").trim();
  if (liveLabel) return liveLabel;
  return "";
}

function getShareCursorModeForSourceKind(sourceKind = "") {
  const kind = normalizeShareSourceKind(sourceKind || "");
  if (kind === "screen") return "always";
  return "motion";
}

function getShareVideoHintForSourceKind(sourceKind = "") {
  const profile = getShareProfileValue();
  if (profile === "clarity") return "detail";
  if (profile === "fluid") return "motion";
  const kind = normalizeShareSourceKind(sourceKind || "");
  if (kind === "window") return "motion";
  return "detail";
}

function getShareRemoteViewerCount(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  if (!groupCallMode || !convId) return 1;
  const meId = normId(state.user?.id || "");
  const activeIds = normalizeUuidArray(getEffectiveGroupCallActiveUserIds(convId))
    .filter((uid) => uid && uid !== meId);
  if (activeIds.length) return activeIds.length;
  const fallbackIds = getCallSignalTargetIds(convId, { includeGroupMembers: true })
    .filter((uid) => uid && uid !== meId);
  return fallbackIds.length || 1;
}

function shouldUseSharePerformanceMode(sourceKind = "", { requestedQuality = "" } = {}) {
  if (getShareProfileValue() !== "balanced") return false;
  // Respect the user's quality choice â€” only auto-limit when many remote viewers
  const requested = String(requestedQuality || getShareQualityValue() || "").trim();
  if (requested === "1080p60" || requested === "1080p30") return false;
  const remoteViewers = getShareRemoteViewerCount();
  return remoteViewers >= SHARE_AUTO_PERF_REMOTE_VIEWERS_THRESHOLD;
}

function getEffectiveShareQualityValue(value = getShareQualityValue(), sourceKind = "") {
  const raw = String(value || "").trim();
  const normalized = SHARE_QUALITY_ALLOWED.has(raw) ? raw : SHARE_QUALITY_DEFAULT;
  const profile = getShareProfileValue();
  if (profile === "fluid" && (normalized === "2160p60" || normalized === "source")) {
    return "1080p60";
  }
  // Keep requested profile unless auto-performance is needed on heavy profiles.
  if (!shouldUseSharePerformanceMode(sourceKind, { requestedQuality: normalized })) return normalized;
  if (normalized === "2160p60" || normalized === "source") return "1080p60";
  return normalized;
}

function applySharePrefsToUi() {
  const rawQ = String(localStorage.getItem(SHARE_QUALITY_KEY) || SHARE_QUALITY_DEFAULT).trim();
  const q = SHARE_QUALITY_ALLOWED.has(rawQ) ? rawQ : SHARE_QUALITY_DEFAULT;
  if (rawQ !== q) localStorage.setItem(SHARE_QUALITY_KEY, q);
  const qualityUi = document.getElementById("shareQuality");
  if (qualityUi) qualityUi.value = q;
  const profile = normalizeShareProfileValue(localStorage.getItem(SHARE_PROFILE_KEY) || SHARE_PROFILE_DEFAULT);
  localStorage.setItem(SHARE_PROFILE_KEY, profile);
  const profileUi = document.getElementById("shareProfile");
  if (profileUi) profileUi.value = profile;
  // Sync picker quality buttons if picker is open
  document.querySelectorAll("[data-desktop-share-quality]").forEach((btn) => {
    btn.classList.toggle("is-active", btn.getAttribute("data-desktop-share-quality") === q);
  });
  document.querySelectorAll("[data-desktop-share-profile]").forEach((btn) => {
    btn.classList.toggle("is-active", normalizeShareProfileValue(btn.getAttribute("data-desktop-share-profile") || "") === profile);
  });
  document.querySelectorAll("[data-call-share-profile]").forEach((btn) => {
    btn.classList.toggle("is-active", normalizeShareProfileValue(btn.getAttribute("data-call-share-profile") || "") === profile);
  });
  // Sync picker audio toggle only when picker is closed (when open, user controls it directly)
  if (!isDesktopSharePickerOpen()) {
    const pickerAudio = document.getElementById("desktopSharePickerAudioToggle");
    if (pickerAudio instanceof HTMLInputElement) {
      const a = localStorage.getItem(SHARE_AUDIO_KEY);
      const fullScreenActive = isScreenSharing && getCurrentShareSourceKind() === "screen";
      pickerAudio.checked = fullScreenActive ? false : (a == null ? true : a === "1");
      pickerAudio.disabled = fullScreenActive;
    }
  }
}

function getActiveShareHasAudio() {
  return !!screenStream?.getAudioTracks?.().some((track) => track && track.readyState === "live");
}

async function setShareProfileValue(nextValue, { applyLive = true } = {}) {
  const nextProfile = normalizeShareProfileValue(nextValue);
  const prevProfile = getShareProfileValue();
  localStorage.setItem(SHARE_PROFILE_KEY, nextProfile);
  applySharePrefsToUi();
  if (nextProfile === prevProfile) return nextProfile;
  if (applyLive && isScreenSharing && isCallMediaSessionActive()) {
    await applyShareSettingsLive("quality");
    await sendShareStateSignal(true, "share");
    refreshCallUI();
  }
  return nextProfile;
}

function clampVolume01(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return 1;
  if (n < 0) return 0;
  if (n > 1) return 1;
  return n;
}

function readStoredVolume(key, fallback = 1) {
  const raw = Number(localStorage.getItem(key));
  if (!Number.isFinite(raw)) return clampVolume01(fallback);
  return clampVolume01(raw);
}

function formatVolumePct(value) {
  return `${Math.round(clampVolume01(value) * 100)}%`;
}

function clampVoiceMicGain(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return VOICE_MIC_GAIN_DEFAULT;
  if (n < 0) return 0;
  if (n > VOICE_MIC_GAIN_MAX) return VOICE_MIC_GAIN_MAX;
  return n;
}

function clampVoiceSensitivityPct(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return 50;
  if (n < 0) return 0;
  if (n > 100) return 100;
  return n;
}

function normalizeVoiceInputProfile(value) {
  const raw = String(value || "").trim().toLowerCase();
  if (!VOICE_INPUT_PROFILE_ALLOWED.has(raw)) return "custom";
  return raw;
}

function normalizeVoiceNoiseSuppressionMode(value) {
  const raw = String(value || "").trim().toLowerCase();
  if (raw === "aggressive") return "standard";
  if (!VOICE_NOISE_SUPPRESSION_ALLOWED.has(raw)) return "standard";
  return raw;
}

function computeLocalSpeakingThresholdFromSensitivityPct(value) {
  // More sensitivity => lower threshold => voice activates easier.
  const pct = clampVoiceSensitivityPct(value);
  const minThreshold = 0.004;
  const maxThreshold = 0.04;
  return maxThreshold - ((pct / 100) * (maxThreshold - minThreshold));
}

function recomputeLocalSpeakingThreshold() {
  callSpeakingLevelLocal = voiceAutoSensitivity
    ? CALL_SPEAKING_LEVEL_LOCAL_DEFAULT
    : computeLocalSpeakingThresholdFromSensitivityPct(voiceSensitivityPct);
}

function loadVoiceVideoPrefs() {
  voiceInputDeviceId = String(localStorage.getItem(VOICE_INPUT_DEVICE_KEY) || "").trim();
  voiceOutputDeviceId = String(localStorage.getItem(VOICE_OUTPUT_DEVICE_KEY) || "").trim();
  const micGainRaw = String(localStorage.getItem(VOICE_MIC_GAIN_KEY) || "").trim();
  voiceMicGain = micGainRaw === "" ? VOICE_MIC_GAIN_DEFAULT : clampVoiceMicGain(micGainRaw);
  const micGainMigrated = String(localStorage.getItem(VOICE_MIC_GAIN_MIGRATION_V2_KEY) || "").trim() === "1";
  if (!micGainMigrated) {
    const parsedMicGain = Number(micGainRaw);
    const hasLegacyDefaultGain = micGainRaw === "" || (Number.isFinite(parsedMicGain) && Math.abs(parsedMicGain - 1) < 0.001);
    if (hasLegacyDefaultGain) {
      voiceMicGain = VOICE_MIC_GAIN_DEFAULT;
      saveVoiceVideoPref(VOICE_MIC_GAIN_KEY, voiceMicGain);
    }
    saveVoiceVideoPref(VOICE_MIC_GAIN_MIGRATION_V2_KEY, "1");
  }
  const speakerRaw = String(localStorage.getItem(VOICE_SPEAKER_MASTER_VOLUME_KEY) || "").trim();
  voiceSpeakerMasterVolume = speakerRaw === "" ? 1 : clampVolume01(speakerRaw);
  const autoRaw = String(localStorage.getItem(VOICE_AUTO_SENSITIVITY_KEY) || "").trim();
  voiceAutoSensitivity = autoRaw === "" ? true : autoRaw === "1";
  const sensitivityRaw = String(localStorage.getItem(VOICE_SENSITIVITY_KEY) || "").trim();
  voiceSensitivityPct = sensitivityRaw === "" ? 50 : clampVoiceSensitivityPct(sensitivityRaw);
  voiceInputProfile = "custom";
  const echoRaw = String(localStorage.getItem(VOICE_ECHO_CANCELLATION_KEY) || "").trim();
  voiceEchoCancellation = echoRaw === "" ? true : echoRaw === "1";
  const noiseRaw = String(localStorage.getItem(VOICE_NOISE_SUPPRESSION_MODE_KEY) || "").trim();
  voiceNoiseSuppressionMode = normalizeVoiceNoiseSuppressionMode(noiseRaw || "standard");
  const agcRaw = String(localStorage.getItem(VOICE_AUTO_GAIN_CONTROL_KEY) || "").trim();
  voiceAutoGainControl = agcRaw === "" ? true : agcRaw === "1";
  recomputeLocalSpeakingThreshold();
}

function saveVoiceVideoPref(key, value) {
  try { localStorage.setItem(key, String(value)); } catch (_) {}
}

function setVoiceInputDeviceId(deviceId, persist = true) {
  voiceInputDeviceId = String(deviceId || "").trim();
  if (persist) saveVoiceVideoPref(VOICE_INPUT_DEVICE_KEY, voiceInputDeviceId);
  const convId = getInspectableServerVoiceConversationId();
  if (convId && isServerVoiceConversationById(convId)) {
    void logServerVoiceDeviceInventory("device.input.selected", convId, {
      selectedInputDeviceId: voiceInputDeviceId || "default",
      persist: !!persist,
    });
  }
}

function setVoiceOutputDeviceId(deviceId, persist = true) {
  voiceOutputDeviceId = String(deviceId || "").trim();
  if (persist) saveVoiceVideoPref(VOICE_OUTPUT_DEVICE_KEY, voiceOutputDeviceId);
  applyPreferredOutputDeviceToCallAudioEls();
  const convId = getInspectableServerVoiceConversationId();
  if (convId && isServerVoiceConversationById(convId)) {
    void logServerVoiceDeviceInventory("device.output.selected", convId, {
      selectedOutputDeviceId: voiceOutputDeviceId || "default",
      persist: !!persist,
    });
  }
}

function applyVoiceMicGainLive() {
  const gain = clampVoiceMicGain(voiceMicGain);
  if (!localMicGainNode) return;
  try {
    const now = localMicAudioCtx?.currentTime || 0;
    localMicGainNode.gain.cancelScheduledValues?.(now);
    localMicGainNode.gain.setTargetAtTime(gain, now, 0.015);
  } catch (_) {
    try { localMicGainNode.gain.value = gain; } catch (_) {}
  }
}

function setVoiceMicGain(next, persist = true) {
  voiceMicGain = clampVoiceMicGain(next);
  if (persist) saveVoiceVideoPref(VOICE_MIC_GAIN_KEY, voiceMicGain);
  applyVoiceMicGainLive();
  applyVoiceMicTestGainLive();
}

function setVoiceSpeakerMasterVolume(next, persist = true) {
  voiceSpeakerMasterVolume = clampVolume01(next);
  if (persist) saveVoiceVideoPref(VOICE_SPEAKER_MASTER_VOLUME_KEY, voiceSpeakerMasterVolume);
  applyRemoteAudioVolumes();
}

function setVoiceAutoSensitivity(next, persist = true) {
  voiceAutoSensitivity = !!next;
  if (persist) saveVoiceVideoPref(VOICE_AUTO_SENSITIVITY_KEY, voiceAutoSensitivity ? "1" : "0");
  recomputeLocalSpeakingThreshold();
  applyLocalMicNoiseGateLive({ forceOpen: !!micMuted });
}

function setVoiceSensitivityPct(next, persist = true) {
  voiceSensitivityPct = clampVoiceSensitivityPct(next);
  if (persist) saveVoiceVideoPref(VOICE_SENSITIVITY_KEY, voiceSensitivityPct);
  recomputeLocalSpeakingThreshold();
  applyLocalMicNoiseGateLive({ forceOpen: !!micMuted });
}

function setVoiceInputProfile(next, persist = true) {
  voiceInputProfile = normalizeVoiceInputProfile(next);
  if (persist) saveVoiceVideoPref(VOICE_INPUT_PROFILE_KEY, voiceInputProfile);
}

function setVoiceEchoCancellation(next, persist = true) {
  voiceEchoCancellation = !!next;
  if (persist) saveVoiceVideoPref(VOICE_ECHO_CANCELLATION_KEY, voiceEchoCancellation ? "1" : "0");
}

function setVoiceNoiseSuppressionMode(next, persist = true) {
  voiceNoiseSuppressionMode = normalizeVoiceNoiseSuppressionMode(next);
  if (persist) saveVoiceVideoPref(VOICE_NOISE_SUPPRESSION_MODE_KEY, voiceNoiseSuppressionMode);
  applyLocalMicNoiseGateLive({ forceOpen: !!micMuted });
}

function setVoiceAutoGainControl(next, persist = true) {
  voiceAutoGainControl = !!next;
  if (persist) saveVoiceVideoPref(VOICE_AUTO_GAIN_CONTROL_KEY, voiceAutoGainControl ? "1" : "0");
}

function applyVoiceInputProfilePreset(profile, { persist = true } = {}) {
  const normalized = normalizeVoiceInputProfile(profile);
  setVoiceInputProfile(normalized, persist);
  if (normalized === "voice_isolation") {
    setVoiceEchoCancellation(true, persist);
    setVoiceNoiseSuppressionMode("aggressive", persist);
    setVoiceAutoGainControl(true, persist);
    setVoiceAutoSensitivity(true, persist);
    return;
  }
  if (normalized === "studio") {
    setVoiceEchoCancellation(false, persist);
    setVoiceNoiseSuppressionMode("off", persist);
    setVoiceAutoGainControl(false, persist);
    setVoiceAutoSensitivity(false, persist);
  }
}

function markVoiceInputProfileCustom(persist = true) {
  if (voiceInputProfile === "custom") return;
  setVoiceInputProfile("custom", persist);
}

function getVoiceInputAudioConstraintsBase({ forceServerVoiceSafe = false } = {}) {
  const inspectedServerVoiceConvId = getInspectableServerVoiceConversationId();
  const serverVoiceSafetyActive = !!(
    forceServerVoiceSafe
    || (
      inspectedServerVoiceConvId
      && isLocalServerVoiceCallContextActive(inspectedServerVoiceConvId)
    )
  );
  const echoCancellationEnabled = serverVoiceSafetyActive ? true : !!voiceEchoCancellation;
  const noiseSuppressionMode = normalizeVoiceNoiseSuppressionMode(voiceNoiseSuppressionMode);
  const noiseSuppressionEnabled = serverVoiceSafetyActive ? true : (noiseSuppressionMode !== "off");
  const autoGainControlEnabled = serverVoiceSafetyActive ? true : !!voiceAutoGainControl;
  return {
    channelCount: { ideal: 1, max: 2 },
    sampleRate: { ideal: 48000 },
    sampleSize: { ideal: 16 },
    echoCancellation: echoCancellationEnabled ? { ideal: true } : false,
    noiseSuppression: noiseSuppressionEnabled ? { ideal: true } : false,
    autoGainControl: autoGainControlEnabled ? { ideal: true } : false,
  };
}

async function requestVoiceInputStream() {
  const convId = getInspectableServerVoiceConversationId();
  const forceServerVoiceSafe = !!(convId && isServerVoiceConversationById(convId));
  const audioConstraintsBase = getVoiceInputAudioConstraintsBase({ forceServerVoiceSafe });
  const hasPreferredInput = !!voiceInputDeviceId;
  const audioConstraints = hasPreferredInput
    ? { ...audioConstraintsBase, deviceId: { exact: voiceInputDeviceId } }
    : { ...audioConstraintsBase };

  let rawStream = null;
  try {
    rawStream = await navigator.mediaDevices.getUserMedia({ audio: audioConstraints, video: false });
  } catch (err) {
    if (convId && isServerVoiceConversationById(convId)) {
      logServerVoiceLocalMediaDebug("track.local.create_error", convId, {
        error: String(err?.message || err || "getUserMedia_failed"),
        requestedPreferredInputDeviceId: hasPreferredInput ? (String(voiceInputDeviceId || "").trim() || null) : null,
        ...getServerVoiceAudioConstraintDebugState({ forceServerVoiceSafe }),
      });
    }
    if (!hasPreferredInput) throw err;
    // Fallback to default device if selected device no longer exists.
    setVoiceInputDeviceId("", true);
    rawStream = await navigator.mediaDevices.getUserMedia({ audio: audioConstraintsBase, video: false });
  }
  if (convId && isServerVoiceConversationById(convId)) {
    const rawTrack = rawStream?.getAudioTracks?.()?.[0] || null;
    logServerVoiceLocalMediaDebug("track.created", convId, {
      requestedPreferredInputDeviceId: hasPreferredInput ? (String(voiceInputDeviceId || "").trim() || null) : null,
      ...getServerVoiceAudioConstraintDebugState({ forceServerVoiceSafe }),
      ...describeServerVoiceAudioTrack(rawTrack),
      ...describeServerVoiceAudioTrackSettings(rawTrack),
    });
  }
  return rawStream;
}

function buildAggressiveVoiceNoiseChain(ctx, sourceNode) {
  if (!ctx || !sourceNode) return sourceNode || null;
  const hpNode = ctx.createBiquadFilter();
  hpNode.type = "highpass";
  hpNode.frequency.value = 82;
  hpNode.Q.value = 0.58;
  const lpNode = ctx.createBiquadFilter();
  lpNode.type = "lowpass";
  lpNode.frequency.value = 8400;
  lpNode.Q.value = 0.62;
  const compNode = ctx.createDynamicsCompressor();
  // Keep aggressive mode clear but avoid "mic sounds off" artifacts.
  compNode.threshold.value = -30;
  compNode.knee.value = 21;
  compNode.ratio.value = 2.8;
  compNode.attack.value = 0.008;
  compNode.release.value = 0.15;
  const makeupNode = ctx.createGain();
  makeupNode.gain.value = 1.14;
  sourceNode.connect(hpNode);
  hpNode.connect(lpNode);
  lpNode.connect(compNode);
  compNode.connect(makeupNode);
  return makeupNode;
}

function getLocalMicNoiseGateProfile() {
  const mode = normalizeVoiceNoiseSuppressionMode(voiceNoiseSuppressionMode);
  const baseThreshold = Math.max(0.0036, Math.min(0.032, Number(callSpeakingLevelLocal || CALL_SPEAKING_LEVEL_LOCAL_DEFAULT) * 0.72));
  if (mode === "standard") {
    return {
      enabled: true,
      openThreshold: baseThreshold * 1.08,
      closeThreshold: baseThreshold * 0.7,
      closedGain: 0.12,
      openTau: 0.026,
      closeTau: 0.17,
    };
  }
  return {
    enabled: false,
    openThreshold: 0,
    closeThreshold: 0,
    closedGain: 1,
    openTau: 0.03,
    closeTau: 0.12,
  };
}

function sampleLocalMicGateLevel() {
  if (!localMicGateAnalyserNode || !localMicGateMeterData) return 0;
  try {
    localMicGateAnalyserNode.getByteTimeDomainData(localMicGateMeterData);
  } catch (_) {
    return 0;
  }
  let sum = 0;
  const data = localMicGateMeterData;
  for (let i = 0; i < data.length; i += 1) {
    const centered = (Number(data[i]) - 128) / 128;
    sum += centered * centered;
  }
  return Math.sqrt(sum / Math.max(1, data.length));
}

function applyLocalMicNoiseGateLive({ forceOpen = false } = {}) {
  if (!localMicGateGainNode) return;
  const gateProfile = getLocalMicNoiseGateProfile();
  let targetGain = 1;
  let tau = gateProfile.openTau;
  if (!forceOpen && gateProfile.enabled) {
    const level = sampleLocalMicGateLevel();
    if (localMicGateOpen) {
      if (level < gateProfile.closeThreshold) localMicGateOpen = false;
    } else if (level > gateProfile.openThreshold) {
      localMicGateOpen = true;
    }
    targetGain = localMicGateOpen ? 1 : gateProfile.closedGain;
    tau = localMicGateOpen ? gateProfile.openTau : gateProfile.closeTau;
  } else {
    localMicGateOpen = true;
  }
  try {
    const now = localMicAudioCtx?.currentTime || 0;
    localMicGateGainNode.gain.cancelScheduledValues?.(now);
    localMicGateGainNode.gain.setTargetAtTime(targetGain, now, Math.max(0.01, tau));
  } catch (_) {
    try { localMicGateGainNode.gain.value = targetGain; } catch (_) {}
  }
}

function setLocalMicNoiseGateTimer(enabled) {
  if (!enabled) {
    if (localMicGateTimer) {
      clearInterval(localMicGateTimer);
      localMicGateTimer = null;
    }
    return;
  }
  if (localMicGateTimer) return;
  localMicGateTimer = setInterval(() => {
    applyLocalMicNoiseGateLive({ forceOpen: !!micMuted });
  }, LOCAL_MIC_GATE_POLL_MS);
  applyLocalMicNoiseGateLive({ forceOpen: !!micMuted });
}

function setVoiceMicTestMeterLevel(level = 0) {
  const meterFill = document.getElementById("settingsVoiceMicTestMeterFill");
  const clamped = Math.max(0, Math.min(1, Number(level) || 0));
  voiceMicTestMeterLevel = clamped;
  if (meterFill) meterFill.style.width = `${Math.round(clamped * 100)}%`;
}

function renderVoiceMicTestUi() {
  const btn = document.getElementById("settingsVoiceMicTestBtn");
  const hint = document.getElementById("settingsVoiceMicTestHint");
  if (btn) {
    btn.textContent = voiceMicTestRunning
      ? t("settings.voice.mic_test_stop", "Stop Test")
      : t("settings.voice.mic_test_start", "Mic Test");
    btn.disabled = !!voiceMicTestStartInFlight;
    btn.classList.toggle("is-on", !!voiceMicTestRunning);
  }
  if (!hint) return;
  let hintText = "";
  if (voiceMicTestHasError) {
    hintText = t("settings.voice.mic_test_hint_error", "Could not start microphone test. Check microphone permission/device.");
  } else if (voiceMicTestRunning) {
    hintText = t("settings.voice.mic_test_hint_running", "Testing microphone... if you use headphones, you should hear yourself clearly.");
  } else {
    hintText = t("settings.voice.mic_test_hint_idle", "Click Mic Test and speak to check your voice.");
  }
  hint.textContent = hintText;
  hint.classList.toggle("is-error", !!voiceMicTestHasError);
}

function stopVoiceMicTest({ clearError = true } = {}) {
  if (voiceMicTestMeterRaf) {
    cancelAnimationFrame(voiceMicTestMeterRaf);
    voiceMicTestMeterRaf = 0;
  }
  try { voiceMicTestSourceNode?.disconnect?.(); } catch (_) {}
  try { voiceMicTestGainNode?.disconnect?.(); } catch (_) {}
  try { voiceMicTestAnalyserNode?.disconnect?.(); } catch (_) {}
  voiceMicTestSourceNode = null;
  voiceMicTestGainNode = null;
  voiceMicTestAnalyserNode = null;
  voiceMicTestMeterData = null;
  try {
    if (voiceMicTestAudioEl) {
      voiceMicTestAudioEl.pause?.();
      voiceMicTestAudioEl.srcObject = null;
    }
  } catch (_) {}
  voiceMicTestAudioEl = null;
  if (voiceMicTestPlaybackStream && voiceMicTestPlaybackStream !== voiceMicTestRawStream) {
    try { voiceMicTestPlaybackStream.getTracks?.().forEach((t) => t.stop?.()); } catch (_) {}
  }
  voiceMicTestPlaybackStream = null;
  if (voiceMicTestRawStream) {
    try { voiceMicTestRawStream.getTracks?.().forEach((t) => t.stop?.()); } catch (_) {}
  }
  voiceMicTestRawStream = null;
  if (voiceMicTestAudioCtx) {
    try { voiceMicTestAudioCtx.close?.().catch?.(() => {}); } catch (_) {}
  }
  voiceMicTestAudioCtx = null;
  voiceMicTestRunning = false;
  if (clearError) voiceMicTestHasError = false;
  setVoiceMicTestMeterLevel(0);
  renderVoiceMicTestUi();
}

function applyVoiceMicTestGainLive() {
  if (!voiceMicTestGainNode) return;
  const gain = clampVoiceMicGain(voiceMicGain);
  try {
    const now = voiceMicTestAudioCtx?.currentTime || 0;
    voiceMicTestGainNode.gain.cancelScheduledValues?.(now);
    voiceMicTestGainNode.gain.setTargetAtTime(gain, now, 0.015);
  } catch (_) {
    try { voiceMicTestGainNode.gain.value = gain; } catch (_) {}
  }
}

function tickVoiceMicTestMeter() {
  if (!voiceMicTestRunning || !voiceMicTestAnalyserNode || !voiceMicTestMeterData) {
    voiceMicTestMeterRaf = 0;
    return;
  }
  try {
    voiceMicTestAnalyserNode.getByteTimeDomainData(voiceMicTestMeterData);
    let sum = 0;
    for (let i = 0; i < voiceMicTestMeterData.length; i += 1) {
      const centered = (voiceMicTestMeterData[i] - 128) / 128;
      sum += centered * centered;
    }
    const rms = Math.sqrt(sum / Math.max(1, voiceMicTestMeterData.length));
    const boosted = Math.max(0, Math.min(1, rms * 3.4));
    const smooth = Math.max(boosted, voiceMicTestMeterLevel * 0.86);
    setVoiceMicTestMeterLevel(smooth);
  } catch (_) {
    setVoiceMicTestMeterLevel(0);
  }
  voiceMicTestMeterRaf = requestAnimationFrame(tickVoiceMicTestMeter);
}

async function startVoiceMicTest({ restart = false } = {}) {
  if (voiceMicTestStartInFlight) return;
  if (voiceMicTestRunning && !restart) return;
  voiceMicTestStartInFlight = true;
  voiceMicTestHasError = false;
  renderVoiceMicTestUi();
  try {
    if (voiceMicTestRunning) stopVoiceMicTest({ clearError: true });

    const rawStream = await requestVoiceInputStream();
    const Ctor = window.AudioContext || window.webkitAudioContext;
    const ctx = Ctor ? new Ctor() : null;
    let playbackStream = rawStream;
    let sourceNode = null;
    let chainTail = null;
    let gainNode = null;
    let analyserNode = null;
    if (ctx) {
      sourceNode = ctx.createMediaStreamSource(rawStream);
      const noiseMode = normalizeVoiceNoiseSuppressionMode(voiceNoiseSuppressionMode);
      chainTail = sourceNode;
      if (noiseMode === "aggressive") {
        chainTail = buildAggressiveVoiceNoiseChain(ctx, chainTail) || chainTail;
      }
      gainNode = ctx.createGain();
      gainNode.gain.value = clampVoiceMicGain(voiceMicGain);
      chainTail.connect(gainNode);
      analyserNode = ctx.createAnalyser();
      analyserNode.fftSize = 1024;
      analyserNode.smoothingTimeConstant = 0.82;
      gainNode.connect(analyserNode);
      const destNode = ctx.createMediaStreamDestination();
      gainNode.connect(destNode);
      playbackStream = destNode.stream || rawStream;
      try { await ctx.resume?.(); } catch (_) {}
    }

    const audioEl = document.createElement("audio");
    audioEl.autoplay = true;
    audioEl.playsInline = true;
    audioEl.muted = false;
    audioEl.volume = clampVolume01(voiceSpeakerMasterVolume);
    audioEl.srcObject = playbackStream;
    void applyPreferredOutputDeviceToAudioEl(audioEl);
    await audioEl.play?.().catch(() => {});

    voiceMicTestRawStream = rawStream;
    voiceMicTestPlaybackStream = playbackStream;
    voiceMicTestAudioCtx = ctx;
    voiceMicTestAudioEl = audioEl;
    voiceMicTestSourceNode = sourceNode;
    voiceMicTestGainNode = gainNode;
    voiceMicTestAnalyserNode = analyserNode;
    voiceMicTestMeterData = analyserNode ? new Uint8Array(analyserNode.fftSize) : null;
    voiceMicTestRunning = true;
    voiceMicTestHasError = false;
    setVoiceMicTestMeterLevel(0);
    if (voiceMicTestMeterRaf) cancelAnimationFrame(voiceMicTestMeterRaf);
    voiceMicTestMeterRaf = requestAnimationFrame(tickVoiceMicTestMeter);
  } catch (err) {
    console.warn("mic test start failed", err);
    stopVoiceMicTest({ clearError: false });
    voiceMicTestHasError = true;
  } finally {
    voiceMicTestStartInFlight = false;
    renderVoiceMicTestUi();
  }
}

async function restartVoiceMicTestCaptureFromSettings() {
  if (!voiceMicTestRunning) return;
  await startVoiceMicTest({ restart: true });
}

async function toggleVoiceMicTest() {
  if (voiceMicTestRunning) {
    stopVoiceMicTest({ clearError: true });
    return;
  }
  await startVoiceMicTest({ restart: false });
}

async function applyPreferredOutputDeviceToAudioEl(audioEl) {
  if (!audioEl || typeof audioEl.setSinkId !== "function") return;
  const preferredSinkId = String(voiceOutputDeviceId || "").trim() || "default";
  try {
    await audioEl.setSinkId(preferredSinkId);
  } catch (error) {
    const convId = getInspectableServerVoiceConversationId();
    if (convId && isServerVoiceConversationById(convId)) {
      logServerVoiceLocalMediaDebug("device.output.apply_error", convId, {
        preferredSinkId,
        error: String(error?.message || error || "setSinkId_failed"),
      });
    }
    try { await audioEl.setSinkId("default"); } catch (_) {}
  }
}

function applyPreferredOutputDeviceToCallAudioEls() {
  const fallbackAudio = document.getElementById("callRemoteAudio");
  if (fallbackAudio) void applyPreferredOutputDeviceToAudioEl(fallbackAudio);
  for (const entry of remoteAudioTrackEls.values()) {
    const audioEl = entry?.audioEl || null;
    if (!audioEl) continue;
    void applyPreferredOutputDeviceToAudioEl(audioEl);
  }
  if (voiceMicTestAudioEl) void applyPreferredOutputDeviceToAudioEl(voiceMicTestAudioEl);
}

function cleanupLocalMicProcessing(keepRawStream = false) {
  setLocalMicNoiseGateTimer(false);
  try { localMicSourceNode?.disconnect?.(); } catch (_) {}
  try { localMicCompressorNode?.disconnect?.(); } catch (_) {}
  try { localMicGateGainNode?.disconnect?.(); } catch (_) {}
  try { localMicGateAnalyserNode?.disconnect?.(); } catch (_) {}
  try { localMicGainNode?.disconnect?.(); } catch (_) {}
  localMicSourceNode = null;
  localMicCompressorNode = null;
  localMicGateGainNode = null;
  localMicGateAnalyserNode = null;
  localMicGateMeterData = null;
  localMicGateOpen = true;
  localMicGainNode = null;
  localMicDestNode = null;
  if (!keepRawStream && callLocalRawAudioStream && callLocalRawAudioStream !== callLocalStream) {
    try { callLocalRawAudioStream.getTracks().forEach((t) => t.stop()); } catch (_) {}
    callLocalRawAudioStream = null;
  }
  if (localMicAudioCtx) {
    try { localMicAudioCtx.close?.().catch?.(() => {}); } catch (_) {}
    localMicAudioCtx = null;
  }
}

function stopLocalAudioCapture() {
  const convId = getInspectableServerVoiceConversationId();
  try {
    if (callLocalStream) callLocalStream.getTracks().forEach((t) => t.stop());
  } catch (_) {}
  if (callLocalRawAudioStream && callLocalRawAudioStream !== callLocalStream) {
    try { callLocalRawAudioStream.getTracks().forEach((t) => t.stop()); } catch (_) {}
  }
  callLocalStream = null;
  callLocalRawAudioStream = null;
  localMicTrack = null;
  cleanupLocalMicProcessing(false);
  if (convId) serverVoiceLastLocalMicStateSignatureByConversation.delete(convId);
}

function buildLocalMicStream(rawStream) {
  const stream = rawStream;
  const rawTrack = stream?.getAudioTracks?.()[0] || null;
  if (!rawTrack) return stream;
  cleanupLocalMicProcessing(true);
  const Ctor = window.AudioContext || window.webkitAudioContext;
  if (!Ctor) return stream;
  try {
    const ctx = new Ctor();
    const source = ctx.createMediaStreamSource(stream);
    const gainNode = ctx.createGain();
    gainNode.gain.value = clampVoiceMicGain(voiceMicGain);
    const compressorNode = ctx.createDynamicsCompressor();
    compressorNode.threshold.value = -28;
    compressorNode.knee.value = 18;
    compressorNode.ratio.value = 2.6;
    compressorNode.attack.value = 0.006;
    compressorNode.release.value = 0.17;
    const gateGainNode = ctx.createGain();
    gateGainNode.gain.value = 1;
    const gateAnalyserNode = ctx.createAnalyser();
    gateAnalyserNode.fftSize = 512;
    gateAnalyserNode.smoothingTimeConstant = 0.8;
    const dest = ctx.createMediaStreamDestination();
    const noiseMode = normalizeVoiceNoiseSuppressionMode(voiceNoiseSuppressionMode);
    let chainTail = source;
    if (noiseMode === "aggressive") {
      // Extra local cleanup when user chooses aggressive suppression.
      chainTail = buildAggressiveVoiceNoiseChain(ctx, chainTail) || chainTail;
    }
    chainTail.connect(compressorNode);
    compressorNode.connect(gateAnalyserNode);
    compressorNode.connect(gateGainNode);
    gateGainNode.connect(gainNode);
    gainNode.connect(dest);
    localMicAudioCtx = ctx;
    localMicSourceNode = source;
    localMicCompressorNode = compressorNode;
    localMicGateGainNode = gateGainNode;
    localMicGateAnalyserNode = gateAnalyserNode;
    localMicGateMeterData = new Uint8Array(gateAnalyserNode.fftSize);
    localMicGateOpen = true;
    localMicGainNode = gainNode;
    localMicDestNode = dest;
    setLocalMicNoiseGateTimer(true);
    const outTrack = dest.stream.getAudioTracks?.()[0] || null;
    if (!outTrack) {
      cleanupLocalMicProcessing(true);
      return stream;
    }
    try { outTrack.contentHint = "speech"; } catch (_) {}
    return new MediaStream([outTrack]);
  } catch (_) {
    cleanupLocalMicProcessing(true);
    return stream;
  }
}

function updateVoiceVideoRangeLabels() {
  const micSlider = document.getElementById("settingsVoiceMicVolume");
  syncRangeDefaultMarker(micSlider, 100);
  const speakerSlider = document.getElementById("settingsVoiceSpeakerVolume");
  syncRangeDefaultMarker(speakerSlider, 100);
  const sensitivitySlider = document.getElementById("settingsVoiceSensitivity");
  syncRangeDefaultMarker(sensitivitySlider, 50);

  const micValue = document.getElementById("settingsVoiceMicVolumeValue");
  if (micValue) micValue.textContent = `${Math.round(clampVoiceMicGain(voiceMicGain) * 100)}%`;
  const speakerValue = document.getElementById("settingsVoiceSpeakerVolumeValue");
  if (speakerValue) speakerValue.textContent = `${Math.round(clampVolume01(voiceSpeakerMasterVolume) * 100)}%`;
  const sensitivityValue = document.getElementById("settingsVoiceSensitivityValue");
  if (sensitivityValue) sensitivityValue.textContent = `${Math.round(clampVoiceSensitivityPct(voiceSensitivityPct))}%`;
}

function normalizeCallKeybindAction(actionInput = "") {
  const action = String(actionInput || "").trim();
  if (!CALL_KEYBIND_ACTIONS.includes(action)) return "";
  return action;
}

function normalizeCallKeybindToken(tokenInput = "") {
  const rawValue = String(tokenInput || "");
  if (!rawValue) return "";
  if (rawValue === " ") return "space";
  const raw = rawValue.trim().toLowerCase();
  if (!raw) return "";
  if (raw === "spacebar") return "space";
  const map = {
    "+": "plus",
    control: "ctrl",
    option: "alt",
    command: "meta",
    cmd: "meta",
    os: "meta",
    win: "meta",
    esc: "escape",
    return: "enter",
    arrowup: "up",
    arrowdown: "down",
    arrowleft: "left",
    arrowright: "right",
  };
  const mapped = map[raw];
  if (mapped) return mapped;
  if (raw === "dead" || raw === "process" || raw === "unidentified") return "";
  if (raw.length === 1) return raw;
  return raw.replace(/\s+/g, "");
}

function isCallKeybindModifierToken(tokenInput = "") {
  const token = String(tokenInput || "").trim().toLowerCase();
  return token === "ctrl" || token === "alt" || token === "shift" || token === "meta";
}

function normalizeCallKeybindCombo(comboInput = "") {
  const raw = String(comboInput || "").trim();
  if (!raw) return "";
  const parts = raw
    .split("+")
    .map((part) => normalizeCallKeybindToken(part))
    .filter(Boolean);
  if (!parts.length) return "";

  const mods = new Set();
  const keys = new Set();
  parts.forEach((part) => {
    if (isCallKeybindModifierToken(part)) mods.add(part);
    else keys.add(part);
  });
  if (!keys.size) return "";
  if (keys.has("escape")) return "";
  const orderedMods = ["ctrl", "alt", "shift", "meta"].filter((mod) => mods.has(mod));
  const orderedKeys = Array.from(keys).sort((a, b) => a.localeCompare(b));
  return [...orderedMods, ...orderedKeys].join("+");
}

function isCallKeybindComboAllowed(comboInput = "") {
  const combo = normalizeCallKeybindCombo(comboInput);
  if (!combo) return false;
  const parts = combo.split("+").filter(Boolean);
  if (!parts.length) return false;
  const keys = parts.filter((part) => !isCallKeybindModifierToken(part));
  if (!keys.length) return false;
  return !keys.includes("escape");
}

function normalizeCallKeybindsInput(rawInput = null) {
  const raw = rawInput && typeof rawInput === "object" ? rawInput : {};
  const out = {};
  const used = new Set();

  CALL_KEYBIND_ACTIONS.forEach((action) => {
    const fallback = normalizeCallKeybindCombo(CALL_KEYBIND_DEFAULTS[action]);
    let combo = normalizeCallKeybindCombo(raw[action]);
    if (!isCallKeybindComboAllowed(combo)) combo = fallback;
    if (!combo || used.has(combo)) {
      combo = !used.has(fallback) ? fallback : "";
    }
    out[action] = combo;
    if (combo) used.add(combo);
  });

  return out;
}

function getCallKeybindStorageKey() {
  const uid = normId(state?.user?.id || "");
  return `${CALL_KEYBINDS_STORAGE_KEY_PREFIX}:${uid || "guest"}`;
}

function loadCallKeybindPrefs() {
  let parsed = null;
  try {
    const raw = localStorage.getItem(getCallKeybindStorageKey());
    if (raw) parsed = JSON.parse(raw);
  } catch (_) {}
  callKeybinds = normalizeCallKeybindsInput(parsed);
  return callKeybinds;
}

function saveCallKeybindPrefs() {
  try {
    localStorage.setItem(getCallKeybindStorageKey(), JSON.stringify(callKeybinds));
    return true;
  } catch (_) {
    return false;
  }
}

function setCallKeybindForAction(actionInput = "", comboInput = "", { persist = true } = {}) {
  const action = normalizeCallKeybindAction(actionInput);
  if (!action) return false;
  const combo = normalizeCallKeybindCombo(comboInput);
  if (!combo) {
    callKeybinds[action] = "";
    if (persist) saveCallKeybindPrefs();
    return true;
  }
  if (!isCallKeybindComboAllowed(combo)) return false;
  const conflictAction = getCallKeybindActionFromCombo(combo);
  if (conflictAction && conflictAction !== action) return false;
  callKeybinds[action] = combo;
  if (persist) saveCallKeybindPrefs();
  return true;
}

function formatCallKeybindComboForDisplay(comboInput = "") {
  const combo = normalizeCallKeybindCombo(comboInput);
  if (!combo) return t("settings.keybind.none", "Not set");
  const tokenLabel = (tokenInput) => {
    const token = String(tokenInput || "").trim().toLowerCase();
    if (!token) return "";
    if (token === "ctrl") return "Ctrl";
    if (token === "alt") return "Alt";
    if (token === "shift") return "Shift";
    if (token === "meta") return "Meta";
    if (token === "escape") return "Esc";
    if (token === "pageup") return "PageUp";
    if (token === "pagedown") return "PageDown";
    if (token === "space") return "Space";
    if (token === "plus") return "+";
    if (token.length === 1) return token.toUpperCase();
    return token.charAt(0).toUpperCase() + token.slice(1);
  };
  return combo
    .split("+")
    .map((token) => tokenLabel(token))
    .filter(Boolean)
    .join(" + ");
}

function syncCallKeybindModifierTokensFromKeyboardEvent(tokenSet, ev) {
  if (!(tokenSet instanceof Set) || !ev) return tokenSet;
  if (ev.ctrlKey) tokenSet.add("ctrl"); else tokenSet.delete("ctrl");
  if (ev.altKey) tokenSet.add("alt"); else tokenSet.delete("alt");
  if (ev.shiftKey) tokenSet.add("shift"); else tokenSet.delete("shift");
  if (ev.metaKey) tokenSet.add("meta"); else tokenSet.delete("meta");
  return tokenSet;
}

function getCallKeybindComboFromKeyboardEvent(ev, extraTokensInput = null) {
  if (!ev || ev.isComposing) return "";
  const extraTokens = extraTokensInput instanceof Set
    ? Array.from(extraTokensInput)
    : (Array.isArray(extraTokensInput) ? extraTokensInput : []);
  const tokenSet = new Set(extraTokens.map((token) => normalizeCallKeybindToken(token)).filter(Boolean));
  syncCallKeybindModifierTokensFromKeyboardEvent(tokenSet, ev);
  const key = normalizeCallKeybindToken(ev.key);
  if (key) tokenSet.add(key);
  return normalizeCallKeybindCombo(Array.from(tokenSet).join("+"));
}

function normalizeAppKeybindAction(actionInput = "") {
  const action = String(actionInput || "").trim();
  if (!APP_KEYBIND_ACTIONS.includes(action)) return "";
  return action;
}

function appKeybindActionAllowsModifierOnly(actionInput = "") {
  return normalizeAppKeybindAction(actionInput) === "zoomUi";
}

function normalizeAppKeybindCombo(comboInput = "", { allowModifierOnly = false } = {}) {
  const raw = String(comboInput || "").trim();
  if (!raw) return "";
  const parts = raw
    .split("+")
    .map((part) => normalizeCallKeybindToken(part))
    .filter(Boolean);
  if (!parts.length) return "";

  const mods = new Set();
  const keys = new Set();
  parts.forEach((part) => {
    if (isCallKeybindModifierToken(part)) mods.add(part);
    else keys.add(part);
  });
  if (keys.has("escape")) return "";
  if (allowModifierOnly) {
    if (!mods.size && !keys.size) return "";
    if (keys.size) return "";
  } else if (!keys.size) {
    return "";
  }
  const orderedMods = ["ctrl", "alt", "shift", "meta"].filter((mod) => mods.has(mod));
  const orderedKeys = Array.from(keys).sort((a, b) => a.localeCompare(b));
  return [...orderedMods, ...orderedKeys].join("+");
}

function isAppKeybindComboAllowed(actionInput = "", comboInput = "") {
  const action = normalizeAppKeybindAction(actionInput);
  if (!action) return false;
  const allowModifierOnly = appKeybindActionAllowsModifierOnly(action);
  const combo = normalizeAppKeybindCombo(comboInput, { allowModifierOnly });
  if (!combo) return false;
  const parts = combo.split("+").filter(Boolean);
  if (!parts.length) return false;
  const keys = parts.filter((part) => !isCallKeybindModifierToken(part));
  if (allowModifierOnly) return !keys.length;
  return !!keys.length;
}

function normalizeAppKeybindsInput(rawInput = null) {
  const raw = rawInput && typeof rawInput === "object" ? rawInput : {};
  const out = {};
  const used = new Set();

  APP_KEYBIND_ACTIONS.forEach((action) => {
    const allowModifierOnly = appKeybindActionAllowsModifierOnly(action);
    const fallback = normalizeAppKeybindCombo(APP_KEYBIND_DEFAULTS[action], { allowModifierOnly });
    let combo = normalizeAppKeybindCombo(raw[action], { allowModifierOnly });
    if (!isAppKeybindComboAllowed(action, combo)) combo = fallback;
    if (!combo || used.has(combo)) {
      combo = !used.has(fallback) ? fallback : "";
    }
    out[action] = combo;
    if (combo) used.add(combo);
  });

  return out;
}

function getAppKeybindStorageKey() {
  const uid = normId(state?.user?.id || "");
  return `${APP_KEYBINDS_STORAGE_KEY_PREFIX}:${uid || "guest"}`;
}

function loadAppKeybindPrefs() {
  let parsed = null;
  try {
    const raw = localStorage.getItem(getAppKeybindStorageKey());
    if (raw) parsed = JSON.parse(raw);
  } catch (_) {}
  appKeybinds = normalizeAppKeybindsInput(parsed);
  return appKeybinds;
}

function saveAppKeybindPrefs() {
  try {
    localStorage.setItem(getAppKeybindStorageKey(), JSON.stringify(appKeybinds));
    return true;
  } catch (_) {
    return false;
  }
}

function getAppKeybindActionFromCombo(comboInput = "", { allowModifierOnly = false } = {}) {
  const combo = normalizeAppKeybindCombo(comboInput, { allowModifierOnly });
  if (!combo) return "";
  for (const action of APP_KEYBIND_ACTIONS) {
    const actionAllowModifierOnly = appKeybindActionAllowsModifierOnly(action);
    if (allowModifierOnly !== actionAllowModifierOnly) continue;
    if (normalizeAppKeybindCombo(appKeybinds[action], { allowModifierOnly: actionAllowModifierOnly }) === combo) return action;
  }
  return "";
}

function setAppKeybindForAction(actionInput = "", comboInput = "", { persist = true } = {}) {
  const action = normalizeAppKeybindAction(actionInput);
  if (!action) return false;
  const allowModifierOnly = appKeybindActionAllowsModifierOnly(action);
  const combo = normalizeAppKeybindCombo(comboInput, { allowModifierOnly });
  if (!combo) {
    // App keybinds always fall back to product defaults instead of staying empty.
    const fallback = normalizeAppKeybindCombo(APP_KEYBIND_DEFAULTS[action], { allowModifierOnly });
    appKeybinds[action] = fallback || "";
    if (persist) saveAppKeybindPrefs();
    return true;
  }
  if (!isAppKeybindComboAllowed(action, combo)) return false;
  const conflictAction = getAppKeybindActionFromCombo(combo, { allowModifierOnly });
  if (conflictAction && conflictAction !== action) return false;
  appKeybinds[action] = combo;
  if (persist) saveAppKeybindPrefs();
  return true;
}

function formatAppKeybindComboForDisplay(comboInput = "") {
  let combo = normalizeAppKeybindCombo(comboInput, { allowModifierOnly: false });
  if (!combo) combo = normalizeAppKeybindCombo(comboInput, { allowModifierOnly: true });
  if (!combo) return t("settings.keybind.none", "Not set");
  const tokenLabel = (tokenInput) => {
    const token = String(tokenInput || "").trim().toLowerCase();
    if (!token) return "";
    if (token === "ctrl") return "Ctrl";
    if (token === "alt") return "Alt";
    if (token === "shift") return "Shift";
    if (token === "meta") return "Meta";
    if (token === "escape") return "Esc";
    if (token === "pageup") return "PageUp";
    if (token === "pagedown") return "PageDown";
    if (token === "space") return "Space";
    if (token === "plus") return "+";
    if (token === "up") return "Arrow Up";
    if (token === "down") return "Arrow Down";
    if (token === "left") return "Arrow Left";
    if (token === "right") return "Arrow Right";
    if (token === "contextmenu") return "Menu Key";
    if (token.length === 1) return token.toUpperCase();
    return token.charAt(0).toUpperCase() + token.slice(1);
  };
  return combo
    .split("+")
    .map((token) => tokenLabel(token))
    .filter(Boolean)
    .join(" + ");
}

function formatAppKeybindForDisplay(actionInput = "") {
  const action = normalizeAppKeybindAction(actionInput);
  if (!action) return t("settings.keybind.none", "Not set");
  const allowModifierOnly = appKeybindActionAllowsModifierOnly(action);
  const combo = normalizeAppKeybindCombo(appKeybinds[action], { allowModifierOnly });
  if (!combo) return t("settings.keybind.none", "Not set");
  if (action === "zoomUi") {
    const wheelLabel = t("settings.keybind.app.zoom.value", "Alt + Mouse Wheel");
    const normalizedWheelLabel = String(wheelLabel || "").trim();
    if (normalizedWheelLabel) {
      if (combo === "alt") return normalizedWheelLabel;
      const fallbackTail = normalizedWheelLabel.toLowerCase().includes("mouse wheel")
        ? "Mouse Wheel"
        : normalizedWheelLabel.toLowerCase().includes("roda do rato")
          ? "Roda do rato"
          : "Mouse Wheel";
      return `${formatAppKeybindComboForDisplay(combo)} + ${fallbackTail}`;
    }
    return `${formatAppKeybindComboForDisplay(combo)} + Mouse Wheel`;
  }
  return formatAppKeybindComboForDisplay(combo);
}

function getAppKeybindComboFromKeyboardEvent(ev, extraTokensInput = null, { allowModifierOnly = false } = {}) {
  if (!ev || ev.isComposing) return "";
  const extraTokens = extraTokensInput instanceof Set
    ? Array.from(extraTokensInput)
    : (Array.isArray(extraTokensInput) ? extraTokensInput : []);
  const tokenSet = new Set(extraTokens.map((token) => normalizeCallKeybindToken(token)).filter(Boolean));
  syncCallKeybindModifierTokensFromKeyboardEvent(tokenSet, ev);
  const key = normalizeCallKeybindToken(ev.key);
  if (key) tokenSet.add(key);
  return normalizeAppKeybindCombo(Array.from(tokenSet).join("+"), { allowModifierOnly });
}

function getAppKeybindComboFromWheelEvent(ev) {
  if (!ev) return "";
  const tokenSet = new Set();
  syncCallKeybindModifierTokensFromKeyboardEvent(tokenSet, ev);
  return normalizeAppKeybindCombo(Array.from(tokenSet).join("+"), { allowModifierOnly: true });
}

function doesKeyboardEventMatchAppKeybindAction(actionInput = "", ev) {
  const action = normalizeAppKeybindAction(actionInput);
  if (!action || !ev || ev.isComposing) return false;
  if (ev.repeat) return false;
  const allowModifierOnly = appKeybindActionAllowsModifierOnly(action);
  if (allowModifierOnly) return false;
  const configuredCombo = normalizeAppKeybindCombo(appKeybinds[action], { allowModifierOnly });
  if (!configuredCombo) return false;
  const eventCombo = getAppKeybindComboFromKeyboardEvent(ev, null, { allowModifierOnly });
  return !!eventCombo && eventCombo === configuredCombo;
}

function doesWheelEventMatchAppZoomKeybind(ev) {
  if (!ev) return false;
  const configuredCombo = normalizeAppKeybindCombo(appKeybinds.zoomUi, { allowModifierOnly: true });
  if (!configuredCombo) return false;
  const eventCombo = getAppKeybindComboFromWheelEvent(ev);
  return !!eventCombo && eventCombo === configuredCombo;
}

function cancelAppKeybindCapture({ clearError = true } = {}) {
  appKeybindCaptureAction = "";
  appKeybindCapturePressedTokens.clear();
  appKeybindCaptureLastCombo = "";
  if (clearError) appKeybindCaptureError = "";
  renderAppKeybindSettingsUi();
}

function startAppKeybindCapture(actionInput = "") {
  const action = normalizeAppKeybindAction(actionInput);
  if (!action) return;
  if (callKeybindCaptureAction) cancelCallKeybindCapture({ clearError: true });
  appKeybindCapturePressedTokens.clear();
  appKeybindCaptureLastCombo = "";
  appKeybindCaptureAction = action;
  appKeybindCaptureError = "";
  renderAppKeybindSettingsUi();
}

function clearCallKeybindPressedRuntimeState() {
  callKeybindPressedTokens.clear();
  callKeybindLastTriggeredCombo = "";
}

function getCallKeybindActionFromCombo(comboInput = "") {
  const combo = normalizeCallKeybindCombo(comboInput);
  if (!combo) return "";
  for (const action of CALL_KEYBIND_ACTIONS) {
    if (normalizeCallKeybindCombo(callKeybinds[action]) === combo) return action;
  }
  return "";
}

function cancelCallKeybindCapture({ clearError = true } = {}) {
  callKeybindCaptureAction = "";
  callKeybindCapturePressedTokens.clear();
  callKeybindCaptureLastCombo = "";
  if (clearError) callKeybindCaptureError = "";
  renderCallKeybindSettingsUi();
}

function startCallKeybindCapture(actionInput = "") {
  const action = normalizeCallKeybindAction(actionInput);
  if (!action) return;
  if (appKeybindCaptureAction) cancelAppKeybindCapture({ clearError: true });
  clearCallKeybindPressedRuntimeState();
  callKeybindCapturePressedTokens.clear();
  callKeybindCaptureLastCombo = "";
  callKeybindCaptureAction = action;
  callKeybindCaptureError = "";
  renderCallKeybindSettingsUi();
}

function renderCallKeybindSettingsUi() {
  const micBtn = document.getElementById("btnSettingsCallKeybindMic");
  const micResetBtn = document.getElementById("btnSettingsCallKeybindMicReset");
  const deafenBtn = document.getElementById("btnSettingsCallKeybindDeafen");
  const deafenResetBtn = document.getElementById("btnSettingsCallKeybindDeafenReset");
  const captureHint = document.getElementById("settingsCallKeybindCaptureHint");
  const micCapturing = callKeybindCaptureAction === "toggleMic";
  const deafenCapturing = callKeybindCaptureAction === "toggleDeafen";
  const anyCapturing = !!(micCapturing || deafenCapturing);
  const waitingText = t("settings.keybind.capture.waiting", "Press your new shortcut now (Esc to cancel).");

  if (micBtn) {
    micBtn.textContent = micCapturing
      ? waitingText
      : formatCallKeybindComboForDisplay(callKeybinds.toggleMic);
    micBtn.classList.toggle("is-capturing", micCapturing);
    micBtn.setAttribute("aria-pressed", micCapturing ? "true" : "false");
  }
  if (deafenBtn) {
    deafenBtn.textContent = deafenCapturing
      ? waitingText
      : formatCallKeybindComboForDisplay(callKeybinds.toggleDeafen);
    deafenBtn.classList.toggle("is-capturing", deafenCapturing);
    deafenBtn.setAttribute("aria-pressed", deafenCapturing ? "true" : "false");
  }
  if (micResetBtn) micResetBtn.disabled = micCapturing;
  if (deafenResetBtn) deafenResetBtn.disabled = deafenCapturing;

  if (captureHint) {
    const message = callKeybindCaptureError
      || (anyCapturing
        ? waitingText
        : t("settings.keybind.capture.hint", "These shortcuts work anywhere in the app."));
    captureHint.textContent = message;
    captureHint.classList.toggle("is-error", !!callKeybindCaptureError);
  }
}

function bindCallKeybindSettingsUiOnce() {
  if (callKeybindSettingsUiBound) return;
  callKeybindSettingsUiBound = true;

  const micBtn = document.getElementById("btnSettingsCallKeybindMic");
  const micResetBtn = document.getElementById("btnSettingsCallKeybindMicReset");
  const deafenBtn = document.getElementById("btnSettingsCallKeybindDeafen");
  const deafenResetBtn = document.getElementById("btnSettingsCallKeybindDeafenReset");

  micBtn?.addEventListener("click", () => {
    if (callKeybindCaptureAction === "toggleMic") {
      cancelCallKeybindCapture({ clearError: true });
      return;
    }
    startCallKeybindCapture("toggleMic");
  });
  deafenBtn?.addEventListener("click", () => {
    if (callKeybindCaptureAction === "toggleDeafen") {
      cancelCallKeybindCapture({ clearError: true });
      return;
    }
    startCallKeybindCapture("toggleDeafen");
  });

  micResetBtn?.addEventListener("click", () => {
    const ok = setCallKeybindForAction("toggleMic", CALL_KEYBIND_DEFAULTS.toggleMic, { persist: true });
    if (!ok) {
      callKeybindCaptureError = t(
        "settings.keybind.capture.in_use",
        "That shortcut is already used by another call action.",
      );
      renderCallKeybindSettingsUi();
      return;
    }
    if (callKeybindCaptureAction === "toggleMic") {
      callKeybindCaptureAction = "";
      callKeybindCapturePressedTokens.clear();
      callKeybindCaptureLastCombo = "";
    }
    callKeybindCaptureError = "";
    renderCallKeybindSettingsUi();
  });
  deafenResetBtn?.addEventListener("click", () => {
    const ok = setCallKeybindForAction("toggleDeafen", CALL_KEYBIND_DEFAULTS.toggleDeafen, { persist: true });
    if (!ok) {
      callKeybindCaptureError = t(
        "settings.keybind.capture.in_use",
        "That shortcut is already used by another call action.",
      );
      renderCallKeybindSettingsUi();
      return;
    }
    if (callKeybindCaptureAction === "toggleDeafen") {
      callKeybindCaptureAction = "";
      callKeybindCapturePressedTokens.clear();
      callKeybindCaptureLastCombo = "";
    }
    callKeybindCaptureError = "";
    renderCallKeybindSettingsUi();
  });

  document.addEventListener("keydown", (ev) => {
    if (!callKeybindCaptureAction) return;
    if (ev.isComposing) return;
    const keyToken = normalizeCallKeybindToken(ev.key);
    const targetEl = eventTargetElement(ev) || document.activeElement || null;
    const targetBtn = targetEl && typeof targetEl.closest === "function"
      ? targetEl.closest("#settingsCallKeybindsSection button")
      : null;
    const activeCaptureBtn = callKeybindCaptureAction === "toggleMic" ? micBtn : deafenBtn;

    // Keep keyboard navigation usable while capture mode is active.
    if (keyToken === "tab") return;
    if (
      (keyToken === "enter" || keyToken === "space")
      && targetBtn
      && activeCaptureBtn
      && targetBtn !== activeCaptureBtn
    ) {
      return;
    }
    if (keyToken === "escape") {
      ev.preventDefault();
      ev.stopPropagation();
      cancelCallKeybindCapture({ clearError: true });
      return;
    }
    if (!keyToken) return;

    syncCallKeybindModifierTokensFromKeyboardEvent(callKeybindCapturePressedTokens, ev);
    callKeybindCapturePressedTokens.add(keyToken);
    const previewCombo = normalizeCallKeybindCombo(Array.from(callKeybindCapturePressedTokens).join("+"));
    if (previewCombo) callKeybindCaptureLastCombo = previewCombo;
    callKeybindCaptureError = "";

    ev.preventDefault();
    ev.stopPropagation();
  }, true);

  document.addEventListener("keyup", (ev) => {
    if (!callKeybindCaptureAction) return;
    if (ev.isComposing) return;
    const keyToken = normalizeCallKeybindToken(ev.key);
    if (!keyToken || keyToken === "tab" || keyToken === "escape") return;
    const targetEl = eventTargetElement(ev) || document.activeElement || null;
    const targetBtn = targetEl && typeof targetEl.closest === "function"
      ? targetEl.closest("#settingsCallKeybindsSection button")
      : null;
    const activeCaptureBtn = callKeybindCaptureAction === "toggleMic" ? micBtn : deafenBtn;
    if (
      (keyToken === "enter" || keyToken === "space")
      && targetBtn
      && activeCaptureBtn
      && targetBtn !== activeCaptureBtn
    ) {
      return;
    }

    const combo = callKeybindCaptureLastCombo
      || getCallKeybindComboFromKeyboardEvent(ev, callKeybindCapturePressedTokens);
    callKeybindCapturePressedTokens.delete(keyToken);
    syncCallKeybindModifierTokensFromKeyboardEvent(callKeybindCapturePressedTokens, ev);
    if (isCallKeybindModifierToken(keyToken)) return;

    ev.preventDefault();
    ev.stopPropagation();
    if (!isCallKeybindComboAllowed(combo)) {
      callKeybindCapturePressedTokens.clear();
      callKeybindCaptureLastCombo = "";
      callKeybindCaptureError = t(
        "settings.keybind.capture.invalid",
        "That key cannot be used as a bind.",
      );
      renderCallKeybindSettingsUi();
      return;
    }

    const conflictAction = getCallKeybindActionFromCombo(combo);
    if (conflictAction && conflictAction !== callKeybindCaptureAction) {
      callKeybindCapturePressedTokens.clear();
      callKeybindCaptureLastCombo = "";
      callKeybindCaptureError = t(
        "settings.keybind.capture.in_use",
        "That shortcut is already used by another call action.",
      );
      renderCallKeybindSettingsUi();
      return;
    }

    const saved = setCallKeybindForAction(callKeybindCaptureAction, combo, { persist: true });
    if (!saved) {
      callKeybindCapturePressedTokens.clear();
      callKeybindCaptureLastCombo = "";
      callKeybindCaptureError = t(
        "settings.keybind.capture.invalid",
        "That key cannot be used as a bind.",
      );
      renderCallKeybindSettingsUi();
      return;
    }
    callKeybindCaptureAction = "";
    callKeybindCapturePressedTokens.clear();
    callKeybindCaptureLastCombo = "";
    callKeybindCaptureError = "";
    renderCallKeybindSettingsUi();
  }, true);

  renderCallKeybindSettingsUi();
}

function renderAppKeybindSettingsUi() {
  const togglePanelsBtn = document.getElementById("btnSettingsAppKeybindTogglePanels");
  const togglePanelsResetBtn = document.getElementById("btnSettingsAppKeybindTogglePanelsReset");
  const zoomBtn = document.getElementById("btnSettingsAppKeybindUiZoom");
  const zoomResetBtn = document.getElementById("btnSettingsAppKeybindUiZoomReset");
  const dmEditBtn = document.getElementById("btnSettingsAppKeybindDmEdit");
  const dmEditResetBtn = document.getElementById("btnSettingsAppKeybindDmEditReset");
  const captureHint = document.getElementById("settingsAppKeybindHint");
  const waitingText = t("settings.keybind.capture.waiting", "Press your new shortcut now (Esc to cancel).");
  const activeAction = normalizeAppKeybindAction(appKeybindCaptureAction);
  const anyCapturing = !!activeAction;

  const applyBtnState = (btn, action, displayText) => {
    if (!btn) return;
    const capturing = activeAction === action;
    btn.textContent = capturing ? waitingText : displayText;
    btn.classList.toggle("is-capturing", capturing);
    btn.setAttribute("aria-pressed", capturing ? "true" : "false");
  };

  applyBtnState(togglePanelsBtn, "togglePanels", formatAppKeybindForDisplay("togglePanels"));
  applyBtnState(zoomBtn, "zoomUi", formatAppKeybindForDisplay("zoomUi"));
  applyBtnState(dmEditBtn, "dmEditLast", formatAppKeybindForDisplay("dmEditLast"));

  if (togglePanelsResetBtn) togglePanelsResetBtn.disabled = activeAction === "togglePanels";
  if (zoomResetBtn) zoomResetBtn.disabled = activeAction === "zoomUi";
  if (dmEditResetBtn) dmEditResetBtn.disabled = activeAction === "dmEditLast";

  if (captureHint) {
    const message = appKeybindCaptureError
      || (anyCapturing
        ? waitingText
        : t("settings.keybind.app.capture.hint", "These app shortcuts work anywhere in the app."));
    captureHint.textContent = message;
    captureHint.classList.toggle("is-error", !!appKeybindCaptureError);
  }
}

function bindAppKeybindSettingsUiOnce() {
  if (appKeybindSettingsUiBound) return;
  appKeybindSettingsUiBound = true;

  const togglePanelsBtn = document.getElementById("btnSettingsAppKeybindTogglePanels");
  const togglePanelsResetBtn = document.getElementById("btnSettingsAppKeybindTogglePanelsReset");
  const zoomBtn = document.getElementById("btnSettingsAppKeybindUiZoom");
  const zoomResetBtn = document.getElementById("btnSettingsAppKeybindUiZoomReset");
  const dmEditBtn = document.getElementById("btnSettingsAppKeybindDmEdit");
  const dmEditResetBtn = document.getElementById("btnSettingsAppKeybindDmEditReset");

  const btnForAction = (action) => {
    if (action === "togglePanels") return togglePanelsBtn;
    if (action === "zoomUi") return zoomBtn;
    if (action === "dmEditLast") return dmEditBtn;
    return null;
  };

  const toggleCapture = (action) => {
    if (appKeybindCaptureAction === action) {
      cancelAppKeybindCapture({ clearError: true });
      return;
    }
    startAppKeybindCapture(action);
  };

  togglePanelsBtn?.addEventListener("click", () => toggleCapture("togglePanels"));
  zoomBtn?.addEventListener("click", () => toggleCapture("zoomUi"));
  dmEditBtn?.addEventListener("click", () => toggleCapture("dmEditLast"));

  const clearAction = (action) => {
    const allowModifierOnly = appKeybindActionAllowsModifierOnly(action);
    const fallbackCombo = normalizeAppKeybindCombo(APP_KEYBIND_DEFAULTS[action], { allowModifierOnly });
    const ok = setAppKeybindForAction(action, fallbackCombo, { persist: true });
    if (!ok) {
      appKeybindCaptureError = t(
        "settings.keybind.app.capture.in_use",
        "That shortcut is already used by another app action.",
      );
      renderAppKeybindSettingsUi();
      return;
    }
    if (appKeybindCaptureAction === action) {
      appKeybindCaptureAction = "";
      appKeybindCapturePressedTokens.clear();
      appKeybindCaptureLastCombo = "";
    }
    appKeybindCaptureError = "";
    renderAppKeybindSettingsUi();
  };

  togglePanelsResetBtn?.addEventListener("click", () => clearAction("togglePanels"));
  zoomResetBtn?.addEventListener("click", () => clearAction("zoomUi"));
  dmEditResetBtn?.addEventListener("click", () => clearAction("dmEditLast"));

  document.addEventListener("keydown", (ev) => {
    if (!appKeybindCaptureAction) return;
    if (ev.isComposing) return;
    const action = normalizeAppKeybindAction(appKeybindCaptureAction);
    if (!action) return;
    const allowModifierOnly = appKeybindActionAllowsModifierOnly(action);
    const keyToken = normalizeCallKeybindToken(ev.key);
    const targetEl = eventTargetElement(ev) || document.activeElement || null;
    const targetBtn = targetEl && typeof targetEl.closest === "function"
      ? targetEl.closest("#settingsAppKeybindsSection button")
      : null;
    const activeCaptureBtn = btnForAction(action);

    if (keyToken === "tab") return;
    if (
      (keyToken === "enter" || keyToken === "space")
      && targetBtn
      && activeCaptureBtn
      && targetBtn !== activeCaptureBtn
    ) {
      return;
    }
    if (keyToken === "escape") {
      ev.preventDefault();
      ev.stopPropagation();
      cancelAppKeybindCapture({ clearError: true });
      return;
    }
    if (!keyToken) return;

    syncCallKeybindModifierTokensFromKeyboardEvent(appKeybindCapturePressedTokens, ev);
    appKeybindCapturePressedTokens.add(keyToken);
    const previewCombo = normalizeAppKeybindCombo(
      Array.from(appKeybindCapturePressedTokens).join("+"),
      { allowModifierOnly },
    );
    if (previewCombo) appKeybindCaptureLastCombo = previewCombo;
    appKeybindCaptureError = "";

    ev.preventDefault();
    ev.stopPropagation();
  }, true);

  document.addEventListener("keyup", (ev) => {
    if (!appKeybindCaptureAction) return;
    if (ev.isComposing) return;
    const action = normalizeAppKeybindAction(appKeybindCaptureAction);
    if (!action) return;
    const allowModifierOnly = appKeybindActionAllowsModifierOnly(action);
    const keyToken = normalizeCallKeybindToken(ev.key);
    if (!keyToken || keyToken === "tab" || keyToken === "escape") return;
    const targetEl = eventTargetElement(ev) || document.activeElement || null;
    const targetBtn = targetEl && typeof targetEl.closest === "function"
      ? targetEl.closest("#settingsAppKeybindsSection button")
      : null;
    const activeCaptureBtn = btnForAction(action);
    if (
      (keyToken === "enter" || keyToken === "space")
      && targetBtn
      && activeCaptureBtn
      && targetBtn !== activeCaptureBtn
    ) {
      return;
    }

    const combo = appKeybindCaptureLastCombo
      || getAppKeybindComboFromKeyboardEvent(ev, appKeybindCapturePressedTokens, { allowModifierOnly });
    appKeybindCapturePressedTokens.delete(keyToken);
    syncCallKeybindModifierTokensFromKeyboardEvent(appKeybindCapturePressedTokens, ev);
    if (isCallKeybindModifierToken(keyToken) && !allowModifierOnly) return;

    ev.preventDefault();
    ev.stopPropagation();
    if (!isAppKeybindComboAllowed(action, combo)) {
      appKeybindCapturePressedTokens.clear();
      appKeybindCaptureLastCombo = "";
      appKeybindCaptureError = allowModifierOnly
        ? t(
          "settings.keybind.app.capture.invalid_zoom",
          "Zoom bind must use modifier keys only (Ctrl / Alt / Shift / Meta).",
        )
        : t(
          "settings.keybind.app.capture.invalid",
          "That key cannot be used as an app bind.",
        );
      renderAppKeybindSettingsUi();
      return;
    }

    const conflictAction = getAppKeybindActionFromCombo(combo, { allowModifierOnly });
    if (conflictAction && conflictAction !== action) {
      appKeybindCapturePressedTokens.clear();
      appKeybindCaptureLastCombo = "";
      appKeybindCaptureError = t(
        "settings.keybind.app.capture.in_use",
        "That shortcut is already used by another app action.",
      );
      renderAppKeybindSettingsUi();
      return;
    }

    const saved = setAppKeybindForAction(action, combo, { persist: true });
    if (!saved) {
      appKeybindCapturePressedTokens.clear();
      appKeybindCaptureLastCombo = "";
      appKeybindCaptureError = t(
        "settings.keybind.app.capture.invalid",
        "That key cannot be used as an app bind.",
      );
      renderAppKeybindSettingsUi();
      return;
    }
    appKeybindCaptureAction = "";
    appKeybindCapturePressedTokens.clear();
    appKeybindCaptureLastCombo = "";
    appKeybindCaptureError = "";
    renderAppKeybindSettingsUi();
  }, true);

  renderAppKeybindSettingsUi();
}

function bindCallKeybindHotkeysOnce() {
  if (callKeybindGlobalHotkeysBound) return;
  callKeybindGlobalHotkeysBound = true;

  document.addEventListener("keydown", (ev) => {
    if (ev.isComposing) return;
    const keyToken = normalizeCallKeybindToken(ev.key);
    if (!keyToken) return;
    syncCallKeybindModifierTokensFromKeyboardEvent(callKeybindPressedTokens, ev);
    callKeybindPressedTokens.add(keyToken);
    if (callKeybindCaptureAction || appKeybindCaptureAction) return;
    if (ev.defaultPrevented || ev.repeat) return;
    const target = eventTargetElement(ev);
    if (getEditableTypingElementFromTarget(target || document.activeElement)) return;
    if (isTextInputFocused()) return;

    const combo = normalizeCallKeybindCombo(Array.from(callKeybindPressedTokens).join("+"));
    if (!combo) return;
    const action = getCallKeybindActionFromCombo(combo);
    if (!action) return;
    if (combo === callKeybindLastTriggeredCombo) return;

    ev.preventDefault();
    ev.stopPropagation();
    callKeybindLastTriggeredCombo = combo;
    if (action === "toggleMic") {
      toggleMic();
      return;
    }
    if (action === "toggleDeafen") {
      toggleDeafen();
    }
  }, true);

  document.addEventListener("keyup", (ev) => {
    if (ev.isComposing) return;
    const keyToken = normalizeCallKeybindToken(ev.key);
    if (keyToken) callKeybindPressedTokens.delete(keyToken);
    syncCallKeybindModifierTokensFromKeyboardEvent(callKeybindPressedTokens, ev);
    callKeybindLastTriggeredCombo = "";
  }, true);

  window.addEventListener("blur", clearCallKeybindPressedRuntimeState, true);
  document.addEventListener("visibilitychange", () => {
    if (document.hidden) clearCallKeybindPressedRuntimeState();
  });
}

function normalizeDesktopBehaviorSettingsInput(rawInput = null) {
  const raw = rawInput && typeof rawInput === "object" ? rawInput : {};
  return {
    closeToTrayOnClose: raw.closeToTrayOnClose !== false,
    launchOnStartup: raw.launchOnStartup !== false,
    reducedMotion: raw.reducedMotion === true,
    pauseGifsWhenUnfocused: raw.pauseGifsWhenUnfocused === true,
    gifsPlayOnHover: raw.gifsPlayOnHover === true,
    hardwareAcceleration: raw.hardwareAcceleration !== false,
    hardwareAccelerationSupported: raw.hardwareAccelerationSupported !== false,
    hardwareAccelerationCurrent: raw.hardwareAccelerationCurrent !== false,
    hardwareAccelerationRequiresRestart: raw.hardwareAccelerationRequiresRestart === true,
    closeToTraySupported: raw.closeToTraySupported !== false,
    closeToTrayLocked: raw.closeToTrayLocked === true,
    launchOnStartupSupported: raw.launchOnStartupSupported !== false,
  };
}

function readAccountPerformanceSettings(themeInput = null) {
  const theme = normalizeThemeSettings(themeInput ?? state.me?.theme_settings ?? {});
  return {
    reducedMotion: normalizeThemeBool(theme.reduce_motion, THEME_DEFAULT_OPTIONS.reduce_motion),
    pauseGifsWhenUnfocused: normalizeThemeBool(
      theme.pause_gifs_when_unfocused,
      THEME_DEFAULT_OPTIONS.pause_gifs_when_unfocused
    ),
    gifsPlayOnHover: normalizeThemeBool(
      theme.gifs_play_on_hover,
      THEME_DEFAULT_OPTIONS.gifs_play_on_hover
    ),
  };
}

function getEffectiveDesktopBehaviorSettings(settingsInput = null, themeInput = null) {
  const localSettings = normalizeDesktopBehaviorSettingsInput({
    ...desktopBehaviorSettingsCache,
    ...(settingsInput || {}),
  });
  if (!state.user) return localSettings;
  return {
    ...localSettings,
    ...readAccountPerformanceSettings(themeInput),
  };
}

function buildAccountPerformanceThemePatchFromDesktopBehaviorPatch(patch = {}) {
  const out = {};
  if (typeof patch.reducedMotion === "boolean") {
    out.reduce_motion = patch.reducedMotion;
  }
  if (typeof patch.pauseGifsWhenUnfocused === "boolean") {
    out.pause_gifs_when_unfocused = patch.pauseGifsWhenUnfocused;
  }
  if (typeof patch.gifsPlayOnHover === "boolean") {
    out.gifs_play_on_hover = patch.gifsPlayOnHover;
  }
  return out;
}

function readStoredDesktopBehaviorSettingsCache() {
  try {
    const raw = String(localStorage.getItem(DESKTOP_BEHAVIOR_SETTINGS_CACHE_KEY) || "").trim();
    if (!raw) return null;
    return normalizeDesktopBehaviorSettingsInput(JSON.parse(raw));
  } catch (_) {
    return null;
  }
}

function persistDesktopBehaviorSettingsCache(settingsInput = null) {
  try {
    const settings = normalizeDesktopBehaviorSettingsInput({
      ...desktopBehaviorSettingsCache,
      ...(settingsInput || {}),
    });
    localStorage.setItem(DESKTOP_BEHAVIOR_SETTINGS_CACHE_KEY, JSON.stringify({
      closeToTrayOnClose: !!settings.closeToTrayOnClose,
      launchOnStartup: !!settings.launchOnStartup,
      closeToTraySupported: settings.closeToTraySupported !== false,
      closeToTrayLocked: !!settings.closeToTrayLocked,
      launchOnStartupSupported: settings.launchOnStartupSupported !== false,
      hardwareAccelerationSupported: settings.hardwareAccelerationSupported !== false,
      hardwareAccelerationCurrent: settings.hardwareAccelerationCurrent !== false,
      hardwareAccelerationRequiresRestart: !!settings.hardwareAccelerationRequiresRestart,
      hardwareAcceleration: !!settings.hardwareAcceleration,
      reducedMotion: !!settings.reducedMotion,
      pauseGifsWhenUnfocused: !!settings.pauseGifsWhenUnfocused,
      gifsPlayOnHover: !!settings.gifsPlayOnHover,
    }));
  } catch (_) {}
}

function applyDesktopBehaviorSettingsEffects(settingsInput = null, { themeInput = null } = {}) {
  const settings = getEffectiveDesktopBehaviorSettings(settingsInput, themeInput);
  applyGlobalMotionMode();
  bindDesktopGifPlaybackLifecycleOnce();
  bindManagedGifPlaybackObserverOnce();
  syncAllMessageGifPlaybackStates();
  persistDesktopBehaviorSettingsCache(settings);
}

function applyDesktopBehaviorSettingsToUi(settingsInput = null, { themeInput = null } = {}) {
  const section = document.getElementById("settingsDesktopBehaviorSection");
  const closeToTrayToggle = document.getElementById("settingsDesktopCloseToTray");
  const launchOnStartupToggle = document.getElementById("settingsDesktopLaunchOnStartup");
  const performanceSection = document.getElementById("settingsDesktopPerformanceSection");
  const reducedMotionToggle = document.getElementById("settingsReduceMotion");
  const pauseGifsToggle = document.getElementById("settingsPauseGifsWhenUnfocused");
  const hoverGifsToggle = document.getElementById("settingsGifsPlayOnHover");
  const hardwareAccelerationToggle = document.getElementById("settingsHardwareAcceleration");
  const hardwareAccelerationHint = document.getElementById("settingsHardwareAccelerationHint");
  const hint = document.getElementById("settingsDesktopBehaviorHint");
  const bridge = getDesktopBridge();
  const desktopReady = !!(
    bridge
    && typeof bridge.getDesktopBehaviorSettings === "function"
    && typeof bridge.setDesktopBehaviorSettings === "function"
  );

  if (section) {
    section.classList.toggle("hidden", !desktopReady);
  }
  if (performanceSection) {
    performanceSection.classList.toggle("hidden", !desktopReady);
  }

  const settings = getEffectiveDesktopBehaviorSettings({
    ...desktopBehaviorSettingsCache,
    ...(settingsInput || {}),
  }, themeInput);
  desktopBehaviorSettingsCache = settings;
  applyDesktopBehaviorSettingsEffects(settings, { themeInput });

  if (closeToTrayToggle) {
    closeToTrayToggle.checked = !!settings.closeToTrayOnClose;
    closeToTrayToggle.disabled = !desktopReady || !settings.closeToTraySupported || !!settings.closeToTrayLocked || !!desktopBehaviorSettingsUpdateInFlight;
  }
  if (launchOnStartupToggle) {
    launchOnStartupToggle.checked = !!settings.launchOnStartup;
    launchOnStartupToggle.disabled = !desktopReady || !settings.launchOnStartupSupported || !!desktopBehaviorSettingsUpdateInFlight;
  }
  if (reducedMotionToggle) {
    reducedMotionToggle.checked = !!settings.reducedMotion;
    reducedMotionToggle.disabled = !desktopReady || !!desktopBehaviorSettingsUpdateInFlight;
  }
  if (pauseGifsToggle) {
    pauseGifsToggle.checked = !!settings.pauseGifsWhenUnfocused;
    pauseGifsToggle.disabled = !desktopReady || !!desktopBehaviorSettingsUpdateInFlight;
  }
  if (hoverGifsToggle) {
    hoverGifsToggle.checked = !!settings.gifsPlayOnHover;
    hoverGifsToggle.disabled = !desktopReady || !!desktopBehaviorSettingsUpdateInFlight;
  }
  if (hardwareAccelerationToggle) {
    hardwareAccelerationToggle.checked = !!settings.hardwareAcceleration;
    hardwareAccelerationToggle.disabled = !desktopReady || !settings.hardwareAccelerationSupported || !!desktopBehaviorSettingsUpdateInFlight;
  }
  if (hardwareAccelerationHint) {
    hardwareAccelerationHint.textContent = settings.hardwareAccelerationRequiresRestart
      ? t("settings.desktop.hardware_acceleration_hint_restart", "Restart Altara to apply this hardware acceleration change.")
      : t("settings.desktop.hardware_acceleration_hint", "Uses the GPU to help render the desktop app. Can reduce CPU on some PCs.");
  }
  if (hint) {
    hint.textContent = t("settings.desktop.hint.desktop_only", "Desktop app only.");
    hint.classList.toggle("hidden", desktopReady);
  }
}

async function fetchDesktopBehaviorSettings({ force = false } = {}) {
  const bridge = getDesktopBridge();
  const desktopReady = !!(
    bridge
    && typeof bridge.getDesktopBehaviorSettings === "function"
    && typeof bridge.setDesktopBehaviorSettings === "function"
  );

  if (!desktopReady) {
    desktopBehaviorSettingsLoaded = true;
    desktopBehaviorSettingsCache = getEffectiveDesktopBehaviorSettings(desktopBehaviorSettingsCache);
    applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
    return desktopBehaviorSettingsCache;
  }

  if (!force && desktopBehaviorSettingsLoaded) {
    applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
    return desktopBehaviorSettingsCache;
  }
  if (desktopBehaviorSettingsFetchInFlight) return desktopBehaviorSettingsFetchInFlight;

  desktopBehaviorSettingsFetchInFlight = Promise.resolve()
    .then(() => bridge.getDesktopBehaviorSettings())
    .then((raw) => {
      desktopBehaviorSettingsCache = getEffectiveDesktopBehaviorSettings(raw);
      desktopBehaviorSettingsLoaded = true;
      applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
      return desktopBehaviorSettingsCache;
    })
    .catch((err) => {
      console.warn("desktop behavior settings fetch failed", err);
      desktopBehaviorSettingsLoaded = true;
      applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
      return desktopBehaviorSettingsCache;
    })
    .finally(() => {
      desktopBehaviorSettingsFetchInFlight = null;
    });

  return desktopBehaviorSettingsFetchInFlight;
}

async function saveDesktopBehaviorSettingsPatch(patch = {}) {
  const bridge = getDesktopBridge();
  const desktopReady = !!(
    bridge
    && typeof bridge.getDesktopBehaviorSettings === "function"
    && typeof bridge.setDesktopBehaviorSettings === "function"
  );
  const normalizedPatch = {};
  if (typeof patch.closeToTrayOnClose === "boolean" && !desktopBehaviorSettingsCache?.closeToTrayLocked) {
    normalizedPatch.closeToTrayOnClose = patch.closeToTrayOnClose;
  }
  if (typeof patch.launchOnStartup === "boolean") {
    normalizedPatch.launchOnStartup = patch.launchOnStartup;
  }
  if (typeof patch.hardwareAcceleration === "boolean") {
    normalizedPatch.hardwareAcceleration = patch.hardwareAcceleration;
  }
  const accountThemePatch = buildAccountPerformanceThemePatchFromDesktopBehaviorPatch(patch);
  const hasLocalPatch = Object.keys(normalizedPatch).length > 0;
  const hasAccountPatch = Object.keys(accountThemePatch).length > 0;
  if (!hasLocalPatch && !hasAccountPatch) return desktopBehaviorSettingsCache;
  if (!desktopReady && !hasAccountPatch) return desktopBehaviorSettingsCache;
  if (hasAccountPatch && !state.user) return desktopBehaviorSettingsCache;

  if (desktopBehaviorSettingsUpdateInFlight) {
    await desktopBehaviorSettingsUpdateInFlight.catch(() => {});
  }

  const previousSettings = getEffectiveDesktopBehaviorSettings(desktopBehaviorSettingsCache);
  let fallbackSettingsOnError = previousSettings;

  desktopBehaviorSettingsUpdateInFlight = Promise.resolve()
    .then(async () => {
      let nextSettings = { ...previousSettings };

      if (hasLocalPatch) {
        const result = await bridge.setDesktopBehaviorSettings(normalizedPatch);
        const payload = result?.settings || result || {};
        nextSettings = normalizeDesktopBehaviorSettingsInput({
          ...nextSettings,
          ...payload,
        });
        fallbackSettingsOnError = getEffectiveDesktopBehaviorSettings(nextSettings, state.me?.theme_settings);
      }

      if (hasAccountPatch) {
        const saved = await persistThemeSettings(accountThemePatch, { showSuccess: false, showError: false });
        if (!saved) throw new Error("account performance settings save failed");
        nextSettings = getEffectiveDesktopBehaviorSettings(nextSettings, state.me?.theme_settings);
        fallbackSettingsOnError = nextSettings;
      }

      desktopBehaviorSettingsCache = getEffectiveDesktopBehaviorSettings(nextSettings);
      desktopBehaviorSettingsLoaded = true;
      applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
      return desktopBehaviorSettingsCache;
    })
    .catch((err) => {
      console.warn("desktop behavior settings save failed", err);
      desktopBehaviorSettingsCache = getEffectiveDesktopBehaviorSettings(fallbackSettingsOnError, state.me?.theme_settings);
      applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
      return desktopBehaviorSettingsCache;
    })
    .finally(() => {
      desktopBehaviorSettingsUpdateInFlight = null;
      applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
    });

  const optimisticTheme = hasAccountPatch
    ? normalizeThemeSettings({
      ...(state.me?.theme_settings || {}),
      ...accountThemePatch,
    })
    : null;

  applyDesktopBehaviorSettingsToUi({
    ...desktopBehaviorSettingsCache,
    ...normalizedPatch,
    ...(typeof patch.reducedMotion === "boolean" ? { reducedMotion: patch.reducedMotion } : {}),
    ...(typeof patch.pauseGifsWhenUnfocused === "boolean" ? { pauseGifsWhenUnfocused: patch.pauseGifsWhenUnfocused } : {}),
    ...(typeof patch.gifsPlayOnHover === "boolean" ? { gifsPlayOnHover: patch.gifsPlayOnHover } : {}),
  }, {
    themeInput: optimisticTheme,
  });
  return desktopBehaviorSettingsUpdateInFlight;
}

async function renderDesktopBehaviorSettingsUi({ force = false } = {}) {
  await fetchDesktopBehaviorSettings({ force });
}

function bindDesktopBehaviorSettingsUiOnce() {
  if (desktopBehaviorSettingsUiBound) return;
  desktopBehaviorSettingsUiBound = true;

  const closeToTrayToggle = document.getElementById("settingsDesktopCloseToTray");
  const launchOnStartupToggle = document.getElementById("settingsDesktopLaunchOnStartup");
  const reducedMotionToggle = document.getElementById("settingsReduceMotion");
  const pauseGifsToggle = document.getElementById("settingsPauseGifsWhenUnfocused");
  const hoverGifsToggle = document.getElementById("settingsGifsPlayOnHover");
  const hardwareAccelerationToggle = document.getElementById("settingsHardwareAcceleration");

  closeToTrayToggle?.addEventListener("change", async (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    await saveDesktopBehaviorSettingsPatch({ closeToTrayOnClose: !!target.checked });
  });

  launchOnStartupToggle?.addEventListener("change", async (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    await saveDesktopBehaviorSettingsPatch({ launchOnStartup: !!target.checked });
  });

  reducedMotionToggle?.addEventListener("change", async (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    await saveDesktopBehaviorSettingsPatch({ reducedMotion: !!target.checked });
  });

  pauseGifsToggle?.addEventListener("change", async (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    await saveDesktopBehaviorSettingsPatch({ pauseGifsWhenUnfocused: !!target.checked });
  });

  hoverGifsToggle?.addEventListener("change", async (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    await saveDesktopBehaviorSettingsPatch({ gifsPlayOnHover: !!target.checked });
  });

  hardwareAccelerationToggle?.addEventListener("change", async (ev) => {
    const target = ev.target;
    if (!(target instanceof HTMLInputElement)) return;
    const desired = !!target.checked;
    const previous = !!desktopBehaviorSettingsCache?.hardwareAcceleration;
    const next = await saveDesktopBehaviorSettingsPatch({ hardwareAcceleration: desired });
    if (previous === desired) return;
    if (next?.hardwareAccelerationRequiresRestart) {
      await requestAppAlert(
        t(
          "settings.desktop.hardware_acceleration_restart_alert",
          "Restart Altara completely to apply the new hardware acceleration mode."
        ),
        {
          title: t("settings.section.performance", "Performance"),
          okText: "OK",
        }
      );
    }
  });
}

async function enumerateVoiceDevicesSafe() {
  if (!navigator.mediaDevices?.enumerateDevices) return [];
  try {
    const list = await navigator.mediaDevices.enumerateDevices();
    return Array.isArray(list) ? list : [];
  } catch (_) {
    return [];
  }
}

function renderVoiceDeviceSelect(selectEl, devices, {
  selectedDeviceId = "",
  kind = "audioinput",
  defaultLabel = "",
  emptyLabel = "",
  fallbackPrefix = "",
} = {}) {
  if (!selectEl) return;
  const rows = Array.isArray(devices) ? devices.filter((d) => String(d?.kind || "") === kind) : [];
  const options = [];
  options.push(`<option value="">${esc(defaultLabel || "Default")}</option>`);
  rows.forEach((device, idx) => {
    const id = String(device?.deviceId || "").trim();
    if (!id) return;
    const label = String(device?.label || "").trim() || `${fallbackPrefix} ${idx + 1}`;
    options.push(`<option value="${escAttr(id)}">${esc(label)}</option>`);
  });
  if (rows.length === 0) {
    options.push(`<option value="" disabled>${esc(emptyLabel || "No devices found")}</option>`);
  }
  selectEl.innerHTML = options.join("");
  const validSelected = rows.some((device) => String(device?.deviceId || "").trim() === selectedDeviceId);
  selectEl.value = validSelected ? selectedDeviceId : "";
}

async function renderVoiceVideoSettingsUi() {
  const micSelect = document.getElementById("settingsVoiceInput");
  const speakerSelect = document.getElementById("settingsVoiceOutput");
  const micVolume = document.getElementById("settingsVoiceMicVolume");
  const speakerVolume = document.getElementById("settingsVoiceSpeakerVolume");
  const autoSensitivity = document.getElementById("settingsVoiceAutoSensitivity");
  const sensitivity = document.getElementById("settingsVoiceSensitivity");
  const echoToggle = document.getElementById("settingsVoiceEchoCancellation");
  const noiseSelect = document.getElementById("settingsVoiceNoiseSuppression");
  const autoGainToggle = document.getElementById("settingsVoiceAutoGainControl");
  if (!micSelect && !speakerSelect) return;

  const devices = await enumerateVoiceDevicesSafe();
  renderVoiceDeviceSelect(micSelect, devices, {
    selectedDeviceId: voiceInputDeviceId,
    kind: "audioinput",
    defaultLabel: t("settings.voice.input_default", "Default microphone"),
    emptyLabel: t("settings.voice.input_none", "No microphone found"),
    fallbackPrefix: t("settings.voice.input", "Microphone"),
  });
  renderVoiceDeviceSelect(speakerSelect, devices, {
    selectedDeviceId: voiceOutputDeviceId,
    kind: "audiooutput",
    defaultLabel: t("settings.voice.output_default", "Default speaker"),
    emptyLabel: t("settings.voice.output_none", "No speaker found"),
    fallbackPrefix: t("settings.voice.output", "Speaker"),
  });

  if (micVolume) micVolume.value = String(Math.round(clampVoiceMicGain(voiceMicGain) * 100));
  if (speakerVolume) speakerVolume.value = String(Math.round(clampVolume01(voiceSpeakerMasterVolume) * 100));
  if (autoSensitivity) autoSensitivity.checked = !!voiceAutoSensitivity;
  if (sensitivity) {
    sensitivity.value = String(Math.round(clampVoiceSensitivityPct(voiceSensitivityPct)));
    sensitivity.disabled = !!voiceAutoSensitivity;
  }
  if (echoToggle) echoToggle.checked = !!voiceEchoCancellation;
  if (noiseSelect) noiseSelect.value = normalizeVoiceNoiseSuppressionMode(voiceNoiseSuppressionMode);
  if (autoGainToggle) autoGainToggle.checked = !!voiceAutoGainControl;
  if (echoToggle) echoToggle.disabled = false;
  if (noiseSelect) noiseSelect.disabled = false;
  if (autoGainToggle) autoGainToggle.disabled = false;
  updateVoiceVideoRangeLabels();
  renderVoiceMicTestUi();

  if (speakerSelect && typeof HTMLMediaElement !== "undefined") {
    const sinkSupported = typeof HTMLMediaElement.prototype.setSinkId === "function";
    speakerSelect.disabled = !sinkSupported;
  }
  void renderDesktopBehaviorSettingsUi({ force: false });
}

async function refreshLocalMicCaptureFromSettings() {
  if (!inCall || !callPc) return;
  try {
    stopLocalAudioCapture();
    const stream = await getLocalAudioStream();
    await bindLocalMicToPeer(stream);
  } catch (e) {
    console.warn("refresh local mic capture failed", e);
  }
}

function clampUserVoiceVolume(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return 1;
  if (n < 0) return 0;
  if (n > 2) return 2;
  return n;
}

function clampRemoteAudioPlaybackGain(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return 1;
  if (n < 0) return 0;
  if (n > REMOTE_AUDIO_GAIN_MAX) return REMOTE_AUDIO_GAIN_MAX;
  return n;
}

function persistRemoteUserVoiceVolumePrefs() {
  try {
    const out = {};
    for (const [uid, factor] of remoteUserVoiceVolumeByUserId.entries()) {
      const userId = normId(uid || "");
      if (!userId) continue;
      const safe = clampUserVoiceVolume(factor);
      if (Math.abs(safe - 1) < 0.001) continue;
      out[userId] = safe;
    }
    localStorage.setItem(REMOTE_USER_VOICE_VOLUME_KEY, JSON.stringify(out));
  } catch (_) {}
}

function loadRemoteUserVoiceVolumePrefs() {
  remoteUserVoiceVolumeByUserId.clear();
  try {
    const raw = String(localStorage.getItem(REMOTE_USER_VOICE_VOLUME_KEY) || "").trim();
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object") return;
    Object.entries(parsed).forEach(([uid, factor]) => {
      const userId = normId(uid || "");
      if (!userId) return;
      remoteUserVoiceVolumeByUserId.set(userId, clampUserVoiceVolume(factor));
    });
  } catch (_) {}
}

function getRemoteUserVoiceVolume(userId) {
  const uid = normId(userId || "");
  if (!uid) return 1;
  return clampUserVoiceVolume(remoteUserVoiceVolumeByUserId.get(uid));
}

function setRemoteUserVoiceVolume(userId, factor, persist = true, opts = {}) {
  const uid = normId(userId || "");
  if (!uid) return 1;
  const safe = clampUserVoiceVolume(factor);
  if (Math.abs(safe - 1) < 0.001) {
    remoteUserVoiceVolumeByUserId.delete(uid);
  } else {
    remoteUserVoiceVolumeByUserId.set(uid, safe);
  }
  if (persist) persistRemoteUserVoiceVolumePrefs();
  applyRemoteAudioVolumes();
  const tileType = normalizeStageTileType(opts?.tileType || "primary");
  logStageMediaUiEvent("participant_audio.volume_changed", {
    tileId: String(opts?.tileId || buildStageParticipantTileId(uid, tileType)).trim(),
    tileType,
    participantId: uid,
    mediaType: "voice",
    isLocalUser: !!opts?.isLocalUser,
    persistedKey: buildRemoteVoicePersistedKey(uid, "volume"),
    nextVolumeFactor: safe,
    triggerReason: String(opts?.triggerReason || "").trim() || "participant_voice_volume_update",
    callerFunction: String(opts?.callerFunction || "").trim() || "setRemoteUserVoiceVolume",
  });
  return safe;
}

