function clearStageScreenshareInitialAttachRetryState(tileId = "") {
  const resolvedTileId = String(tileId || "").trim();
  if (!resolvedTileId) {
    return {
      cleared: false,
      tileId: "",
      timerCount: 0,
      conversationId: "",
      participantId: "",
    };
  }
  const retryState = stageScreenshareInitialAttachRetryStateByTileId.get(resolvedTileId);
  if (!retryState) {
    return {
      cleared: false,
      tileId: resolvedTileId,
      timerCount: 0,
      conversationId: "",
      participantId: "",
    };
  }
  const timerCount = Array.isArray(retryState?.timers) ? retryState.timers.length : 0;
  (retryState.timers || []).forEach((timerId) => {
    try { clearTimeout(timerId); } catch (_) {}
  });
  stageScreenshareInitialAttachRetryStateByTileId.delete(resolvedTileId);
  return {
    cleared: true,
    tileId: resolvedTileId,
    timerCount,
    conversationId: normId(retryState?.conversationId || ""),
    participantId: normId(retryState?.participantId || ""),
  };
}

function clearStageScreenshareInitialAttachRetryStatesByConversation(conversationId = null) {
  const convId = normId(conversationId || "");
  if (!convId) {
    Array.from(stageScreenshareInitialAttachRetryStateByTileId.keys()).forEach((tileId) => {
      clearStageScreenshareInitialAttachRetryState(tileId);
    });
    return;
  }
  Array.from(stageScreenshareInitialAttachRetryStateByTileId.entries()).forEach(([tileId, retryState]) => {
    const retryConvId = normId(retryState?.conversationId || "");
    if (!retryConvId || retryConvId !== convId) return;
    clearStageScreenshareInitialAttachRetryState(tileId);
  });
}

function markStageScreenshareForceRemovedOwner(conversationId = "", participantId = "") {
  const convId = normId(conversationId || "");
  const uid = normId(participantId || "");
  if (!convId || !uid) return;
  const existing = stageScreenshareForceRemovedOwnersByConversation.get(convId);
  const nextSet = existing instanceof Set ? existing : new Set();
  nextSet.add(uid);
  stageScreenshareForceRemovedOwnersByConversation.set(convId, nextSet);
}

function clearStageScreenshareForceRemovedOwner(conversationId = "", participantId = "") {
  const convId = normId(conversationId || "");
  if (!convId) return;
  if (!participantId) {
    stageScreenshareForceRemovedOwnersByConversation.delete(convId);
    return;
  }
  const uid = normId(participantId || "");
  const existing = stageScreenshareForceRemovedOwnersByConversation.get(convId);
  if (!(existing instanceof Set)) return;
  existing.delete(uid);
  if (!existing.size) {
    stageScreenshareForceRemovedOwnersByConversation.delete(convId);
    return;
  }
  stageScreenshareForceRemovedOwnersByConversation.set(convId, existing);
}

function isStageScreenshareForceRemovedOwner(conversationId = "", participantId = "") {
  const convId = normId(conversationId || "");
  const uid = normId(participantId || "");
  if (!convId || !uid) return false;
  const existing = stageScreenshareForceRemovedOwnersByConversation.get(convId);
  return !!(existing instanceof Set && existing.has(uid));
}

function markStageScreenshareReplacingOwner(conversationId = "", participantId = "") {
  const convId = normId(conversationId || "");
  const uid = normId(participantId || "");
  if (!convId || !uid) return;
  const existing = stageScreenshareReplacingOwnersByConversation.get(convId);
  const nextSet = existing instanceof Set ? existing : new Set();
  nextSet.add(uid);
  stageScreenshareReplacingOwnersByConversation.set(convId, nextSet);
}

function clearStageScreenshareReplacingOwner(conversationId = "", participantId = "") {
  const convId = normId(conversationId || "");
  if (!convId) return;
  if (!participantId) {
    stageScreenshareReplacingOwnersByConversation.delete(convId);
    clearStageScreenshareReplacementState(convId);
    return;
  }
  const uid = normId(participantId || "");
  const existing = stageScreenshareReplacingOwnersByConversation.get(convId);
  if (!(existing instanceof Set)) {
    clearStageScreenshareReplacementState(convId, uid);
    return;
  }
  existing.delete(uid);
  if (!existing.size) {
    stageScreenshareReplacingOwnersByConversation.delete(convId);
    clearStageScreenshareReplacementState(convId, uid);
    return;
  }
  stageScreenshareReplacingOwnersByConversation.set(convId, existing);
  clearStageScreenshareReplacementState(convId, uid);
}

function isStageScreenshareReplacingOwner(conversationId = "", participantId = "") {
  const convId = normId(conversationId || "");
  const uid = normId(participantId || "");
  if (!convId || !uid) return false;
  const existing = stageScreenshareReplacingOwnersByConversation.get(convId);
  return !!(existing instanceof Set && existing.has(uid));
}

function hasStageScreenshareReplacingOwners(conversationId = "") {
  const convId = normId(conversationId || "");
  if (!convId) return false;
  const existing = stageScreenshareReplacingOwnersByConversation.get(convId);
  return !!(existing instanceof Set && existing.size > 0);
}

function buildStageScreenshareReplacementStateKey(conversationId = "", participantId = "") {
  const convId = normId(conversationId || "");
  const uid = normId(participantId || "");
  if (!convId || !uid) return "";
  return `${convId}:${uid}`;
}

function setStageScreenshareReplacementState(conversationId = "", participantId = "", patch = {}) {
  const stateKey = buildStageScreenshareReplacementStateKey(conversationId, participantId);
  if (!stateKey) return null;
  const prev = stageScreenshareReplacementStateByOwnerKey.get(stateKey);
  const prevState = prev && typeof prev === "object" && !Array.isArray(prev) ? prev : {};
  const nextState = {
    conversationId: normId(conversationId || prevState.conversationId || ""),
    participantId: normId(participantId || prevState.participantId || ""),
    oldTrackSid: normId(patch?.oldTrackSid || prevState.oldTrackSid || ""),
    newTrackSid: normId(patch?.newTrackSid || prevState.newTrackSid || ""),
    renderReason: String(patch?.renderReason || prevState.renderReason || "").trim() || "",
    updatedAt: Date.now(),
    ...(patch && typeof patch === "object" && !Array.isArray(patch) ? patch : {}),
  };
  stageScreenshareReplacementStateByOwnerKey.set(stateKey, nextState);
  return nextState;
}

function getStageScreenshareReplacementState(conversationId = "", participantId = "") {
  const stateKey = buildStageScreenshareReplacementStateKey(conversationId, participantId);
  if (!stateKey) return null;
  return stageScreenshareReplacementStateByOwnerKey.get(stateKey) || null;
}

function clearStageScreenshareReplacementState(conversationId = "", participantId = "") {
  const convId = normId(conversationId || "");
  if (!convId) return;
  if (!participantId) {
    Array.from(stageScreenshareReplacementStateByOwnerKey.keys()).forEach((stateKey) => {
      if (String(stateKey || "").startsWith(`${convId}:`)) {
        stageScreenshareReplacementStateByOwnerKey.delete(stateKey);
      }
    });
    return;
  }
  const stateKey = buildStageScreenshareReplacementStateKey(convId, participantId);
  if (!stateKey) return;
  stageScreenshareReplacementStateByOwnerKey.delete(stateKey);
}

function logScreenshareStopCleanupEvent(event, {
  conversationId = "",
  streamOwnerId = "",
  tileId = "",
  reason = "",
  ...extra
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const ownerId = normId(streamOwnerId || "");
  const resolvedTileId = String(tileId || buildStageParticipantTileId(ownerId, "screenshare") || "").trim();
  const focusedTileId = String(stageFocusedTileId || "").trim();
  logScreenshareTileRenderEvent(event, {
    tileId: resolvedTileId,
    participantId: ownerId,
    activeShareOwnerId: ownerId,
    renderReason: String(reason || "").trim() || null,
    hasExistingVideoElement: false,
    fallbackReason: String(reason || "").trim() || null,
    conversationId: convId || null,
    streamOwnerId: ownerId || null,
    focusedTileId: focusedTileId || null,
    reason: String(reason || "").trim() || null,
    ...(extra && typeof extra === "object" && !Array.isArray(extra) ? extra : {}),
  });
}

function cleanupStoppedScreenshareStageTile({
  conversationId = "",
  streamOwnerId = "",
  reason = "screenshare_stopped",
  clearWatchState = true,
  triggerReason = "screenshare_stop_cleanup",
  callerFunction = "cleanupStoppedScreenshareStageTile",
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const ownerId = normId(streamOwnerId || "");
  if (!convId || !ownerId) return false;
  const tileId = buildStageParticipantTileId(ownerId, "screenshare");
  const focusedTileId = String(stageFocusedTileId || "").trim();
  logScreenshareStopCleanupEvent("screenshare.tile_remove_requested", {
    conversationId: convId,
    streamOwnerId: ownerId,
    tileId,
    reason,
    triggerReason: String(triggerReason || "").trim() || "screenshare_stop_cleanup",
    callerFunction: String(callerFunction || "").trim() || "cleanupStoppedScreenshareStageTile",
  });

  let retryClearedCount = 0;
  const primaryRetryCleanup = clearStageScreenshareInitialAttachRetryState(tileId);
  if (primaryRetryCleanup?.cleared) {
    retryClearedCount += 1;
    logScreenshareStopCleanupEvent("screenshare.cleanup_stale_attach_retry", {
      conversationId: convId,
      streamOwnerId: ownerId,
      tileId: primaryRetryCleanup.tileId || tileId,
      reason,
      triggerReason: String(triggerReason || "").trim() || "screenshare_stop_cleanup",
      callerFunction: String(callerFunction || "").trim() || "cleanupStoppedScreenshareStageTile",
      retryTimerCount: Number(primaryRetryCleanup.timerCount || 0),
    });
  }
  Array.from(stageScreenshareInitialAttachRetryStateByTileId.entries()).forEach(([retryTileId, retryState]) => {
    const retryConvId = normId(retryState?.conversationId || "");
    const retryOwnerId = normId(retryState?.participantId || "");
    if (retryConvId !== convId || retryOwnerId !== ownerId) return;
    const retryCleanup = clearStageScreenshareInitialAttachRetryState(retryTileId);
    if (!retryCleanup?.cleared) return;
    retryClearedCount += 1;
    logScreenshareStopCleanupEvent("screenshare.cleanup_stale_attach_retry", {
      conversationId: convId,
      streamOwnerId: ownerId,
      tileId: retryCleanup.tileId || retryTileId,
      reason,
      triggerReason: String(triggerReason || "").trim() || "screenshare_stop_cleanup",
      callerFunction: String(callerFunction || "").trim() || "cleanupStoppedScreenshareStageTile",
      retryTimerCount: Number(retryCleanup.timerCount || 0),
    });
  });

  const graceState = stageScreenshareGraceStateByConversation.get(convId) || null;
  if (normId(graceState?.ownerId || "") === ownerId) {
    stageScreenshareGraceStateByConversation.delete(convId);
  }
  markStageScreenshareForceRemovedOwner(convId, ownerId);
  if (clearWatchState) {
    const ownerScopedStreamKey = buildRemoteStreamPreferenceKey({
      conversationId: convId,
      participantId: ownerId,
    });
    const legacyOwnerScopedStreamPrefix = `${ownerScopedStreamKey}:`;
    Array.from(remoteShareWatchEnabledByStreamKey.keys()).forEach((key) => {
      const streamKey = String(key || "").trim();
      if (!streamKey) return;
      if (streamKey === ownerScopedStreamKey || streamKey.startsWith(legacyOwnerScopedStreamPrefix)) {
        remoteShareWatchEnabledByStreamKey.delete(key);
      }
    });
  }

  const focusedIdentity = parseStageParticipantTileId(focusedTileId || "");
  const focusedScreenshareForOwner = !!(
    normalizeStageTileType(focusedIdentity.tileType || "") === "screenshare"
    && normId(focusedIdentity.participantId || "") === ownerId
  );
  const memberFocusForOwnerShare = !!(
    stageFocus === "member"
    && normId(stageFocusMemberId || "") === ownerId
    && normalizeRelayMediaKind(stageFocusMemberMediaType || "") === "share"
  );
  if (focusedScreenshareForOwner || memberFocusForOwnerShare) {
    stageLayoutMode = "grid";
    if (focusedScreenshareForOwner) stageFocusedTileId = "";
    if (memberFocusForOwnerShare) {
      stageFocus = "remote";
      stageFocusMemberId = "";
      stageFocusMemberTrackId = "";
      stageFocusMemberMediaType = "";
      if (!focusedScreenshareForOwner) stageFocusedTileId = "";
    }
    stageFocusTransitionExpiresAt = 0;
    stageFocusTransitionTargetTileId = "";
    logScreenshareStopCleanupEvent("screenshare.focus_cleared_after_stop", {
      conversationId: convId,
      streamOwnerId: ownerId,
      tileId,
      reason,
      triggerReason: String(triggerReason || "").trim() || "screenshare_stop_cleanup",
      callerFunction: String(callerFunction || "").trim() || "cleanupStoppedScreenshareStageTile",
      focusedTileIdBeforeClear: focusedTileId || null,
      focusedTileIdAfterClear: String(stageFocusedTileId || "").trim() || null,
    });
  }

  const stage = document.getElementById("callStage");
  const tileCandidates = [];
  if (stage) {
    stage.querySelectorAll(".participantTile, .stageGridTile").forEach((tileEl) => {
      const tileIdentity = getStageTileIdentityFromEl(tileEl);
      if (normalizeStageTileType(tileIdentity.tileType || "") !== "screenshare") return;
      if (normId(tileIdentity.participantId || "") !== ownerId) return;
      tileCandidates.push(tileEl);
    });
  }
  const directTile = findStageTileElById(tileId);
  if (directTile && !tileCandidates.includes(directTile)) tileCandidates.push(directTile);

  let removedCount = 0;
  tileCandidates.forEach((tileEl) => {
    const tileIdentity = getStageTileIdentityFromEl(tileEl);
    const resolvedTileId = String(tileIdentity.tileId || tileId || "").trim();
    const videoEl = tileEl.querySelector(".stageGridVideo, .participantVideo");
    const hadVideo = !!(videoEl?.srcObject || tileEl.classList.contains("has-video"));
    if (videoEl) {
      stopMemberTileFrameProbe(videoEl);
      try {
        videoEl.pause?.();
        videoEl.srcObject = null;
        videoEl.removeAttribute?.("src");
        videoEl.load?.();
      } catch (_) {}
    }
    tileEl.removeAttribute("data-call-video-track-id");
    tileEl.removeAttribute("data-call-track-identity");
    tileEl.removeAttribute("data-call-video-hold-until");
    tileEl.removeAttribute("data-call-video-seen");
    tileEl.removeAttribute("data-call-screenshare-missing-until");
    tileEl.removeAttribute("data-call-screenshare-gap-started-at");
    tileEl.removeAttribute("data-call-screenshare-reconnecting");
    tileEl.removeAttribute("data-call-screenshare-fallback-blocked");
    tileEl.removeAttribute("data-call-screenshare-focus-preserved-serial");
    tileEl.removeAttribute("data-call-screenshare-focus-skip-serial");
    tileEl.removeAttribute("data-call-keep-mounted");
    tileEl.classList.remove("has-video");
    tileEl.classList.remove("is-share-reconnecting");
    tileEl.classList.remove("is-watch-gated");
    tileEl.classList.remove("is-share-loading");
    tileEl.classList.remove("has-watch-snapshot");
    clearCallTileWatchSnapshot(tileEl);
    setCallTileWatchPrompt(tileEl, false);
    setCallTileLoadingPrompt(tileEl, false);
    logScreenshareStopCleanupEvent("screenshare.black_tile_cleanup", {
      conversationId: convId,
      streamOwnerId: ownerId,
      tileId: resolvedTileId || tileId,
      reason,
      triggerReason: String(triggerReason || "").trim() || "screenshare_stop_cleanup",
      callerFunction: String(callerFunction || "").trim() || "cleanupStoppedScreenshareStageTile",
      hadVideo: !!hadVideo,
    });
    try { tileEl.remove(); } catch (_) {}
    removedCount += 1;
  });

  logScreenshareStopCleanupEvent("screenshare.tile_removed_after_stop", {
    conversationId: convId,
    streamOwnerId: ownerId,
    tileId,
    reason,
    triggerReason: String(triggerReason || "").trim() || "screenshare_stop_cleanup",
    callerFunction: String(callerFunction || "").trim() || "cleanupStoppedScreenshareStageTile",
    removedCount,
    retryClearedCount,
  });
  refreshCallUI();
  return !!(removedCount > 0 || retryClearedCount > 0 || focusedScreenshareForOwner || memberFocusForOwnerShare);
}

function collectStageTilesSnapshotForScreenshareRestart() {
  const stage = document.getElementById("callStage");
  const knownTileIds = collectKnownStageTileIds(stage);
  const visibleTileIds = collectVisibleStageTileIds(stage);
  const domTileCount = stage
    ? stage.querySelectorAll(".participantTile, .stageGridTile").length
    : 0;
  return {
    knownTileIds,
    visibleTileIds,
    tileCount: knownTileIds.length,
    visibleTileCount: visibleTileIds.length,
    domTileCount,
  };
}

function logScreenshareRestartEvent(event, {
  conversationId = "",
  participantId = "",
  oldTileId = "",
  newTileId = "",
  activeShareOwnerId = "",
  tileCountBefore = 0,
  tileCountAfter = 0,
  triggerReason = "screenshare_restart",
  callerFunction = "logScreenshareRestartEvent",
  ...extra
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || "");
  const resolvedOldTileId = String(oldTileId || buildStageParticipantTileId(uid, "screenshare") || "").trim();
  const resolvedNewTileId = String(newTileId || buildStageParticipantTileId(uid, "screenshare") || "").trim();
  const focusedTileId = String(stageFocusedTileId || "").trim();
  writeStructuredServerVoiceConsoleLog("[server-voice stage]", event, {
    conversationId: convId || null,
    participantId: uid || null,
    oldTileId: resolvedOldTileId || null,
    newTileId: resolvedNewTileId || null,
    activeShareOwnerId: normId(activeShareOwnerId || "") || null,
    tileCountBefore: Math.max(0, Number(tileCountBefore || 0)),
    tileCountAfter: Math.max(0, Number(tileCountAfter || 0)),
    focusedTileId: focusedTileId || null,
    triggerReason: String(triggerReason || "").trim() || "screenshare_restart",
    callerFunction: String(callerFunction || "").trim() || "logScreenshareRestartEvent",
    ...(extra && typeof extra === "object" && !Array.isArray(extra) ? extra : {}),
  }, {
    level: "info",
    channel: "server-voice-stage",
  });
}

function shouldEmitScreenshareDomOuterHtmlSummary() {
  try {
    if (typeof window !== "undefined" && window?.__ALTARA_DEBUG_SCREENSHARE_OUTERHTML === true) return true;
  } catch (_) {}
  try {
    const raw = String(localStorage.getItem(SCREENSHARE_DOM_OUTERHTML_DEBUG_KEY) || "").trim().toLowerCase();
    return raw === "1" || raw === "true" || raw === "on";
  } catch (_) {
    return false;
  }
}

function sanitizeScreenshareDomOuterHtmlSummary(rawHtml = "") {
  const raw = String(rawHtml || "");
  if (!raw) return "";
  let sanitized = raw;
  sanitized = sanitized.replace(/data:[^"']+/gi, "[data-uri]");
  sanitized = sanitized.replace(/\s(src|srcset|poster)=["'][^"']*["']/gi, (match, attr) => ` ${String(attr || "").toLowerCase()}="[stripped]"`);
  sanitized = sanitized.replace(/\sstyle=["'][^"']*background-image\s*:[^;"']+[^"']*["']/gi, ' style="[background-image-stripped]"');
  const maxLen = 6400;
  if (sanitized.length > maxLen) {
    return `${sanitized.slice(0, maxLen)}...[truncated]`;
  }
  return sanitized;
}

function collectMediaElementSrcTrackIds(mediaEl = null) {
  const out = [];
  if (!(mediaEl instanceof HTMLMediaElement)) return out;
  const srcObject = mediaEl.srcObject;
  if (!srcObject || typeof srcObject.getTracks !== "function") return out;
  srcObject.getTracks().forEach((track) => {
    const tid = normId(track?.id || track?.sid || "");
    if (tid && !out.includes(tid)) out.push(tid);
  });
  return out;
}

function collectScreenshareMediaContainerAuditSnapshot(container = null) {
  if (!(container instanceof HTMLElement)) {
    return {
      mediaChildCount: 0,
      videoCount: 0,
      canvasCount: 0,
      imgCount: 0,
      backgroundImagePresent: false,
      childClassNames: [],
      childDataset: [],
      srcObjectTrackIds: [],
    };
  }
  const allMediaNodes = Array.from(container.querySelectorAll("video,canvas,img"));
  const videoNodes = allMediaNodes.filter((node) => node instanceof HTMLVideoElement);
  const canvasNodes = allMediaNodes.filter((node) => node instanceof HTMLCanvasElement);
  const imgNodes = allMediaNodes.filter((node) => (
    node instanceof HTMLImageElement
    && !node.closest(".stageGridAvatar, .participantAvatar")
  ));
  const mediaChildCount = videoNodes.length + canvasNodes.length + imgNodes.length;
  const backgroundImagePresent = !!(
    String(container.style.getPropertyValue("--call-watch-snapshot-image") || "").trim()
    || (
      String(container.style.backgroundImage || "").trim()
      && String(container.style.backgroundImage || "").trim().toLowerCase() !== "none"
    )
  );
  const childClassNames = Array.from(container.children || []).map((child) => {
    const className = String(child?.className || "").trim();
    return className || String(child?.tagName || "").trim().toLowerCase();
  });
  const childDataset = Array.from(container.children || []).map((child) => {
    const datasetEntries = Object.entries(child?.dataset || {}).map(([key, value]) => `${String(key || "").trim()}:${String(value || "").trim()}`);
    return `${String(child?.tagName || "node").trim().toLowerCase()}${datasetEntries.length ? `(${datasetEntries.join(",")})` : ""}`;
  });
  const srcObjectTrackIds = [];
  videoNodes.forEach((videoEl) => {
    collectMediaElementSrcTrackIds(videoEl).forEach((tid) => {
      if (!srcObjectTrackIds.includes(tid)) srcObjectTrackIds.push(tid);
    });
  });
  return {
    mediaChildCount,
    videoCount: videoNodes.length,
    canvasCount: canvasNodes.length,
    imgCount: imgNodes.length,
    backgroundImagePresent,
    childClassNames,
    childDataset,
    srcObjectTrackIds,
  };
}

function logScreenshareMediaContainerEvent(event, {
  conversationId = "",
  participantId = "",
  tileId = "",
  oldTrackSid = "",
  newTrackSid = "",
  renderReason = "",
  fallbackReason = "",
  container = null,
  ...extra
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || "");
  const resolvedTileId = String(tileId || buildStageParticipantTileId(uid, "screenshare") || "").trim();
  const audit = collectScreenshareMediaContainerAuditSnapshot(container);
  logScreenshareTileRenderEvent(event, {
    tileId: resolvedTileId,
    participantId: uid,
    trackSid: normId(newTrackSid || ""),
    trackIdentity: normId(newTrackSid || ""),
    activeShareOwnerId: uid,
    renderReason: String(renderReason || "").trim() || null,
    hasExistingVideoElement: audit.videoCount > 0,
    fallbackReason: String(fallbackReason || "").trim() || null,
    conversationId: convId || null,
    oldTrackSid: normId(oldTrackSid || "") || null,
    newTrackSid: normId(newTrackSid || "") || null,
    mediaChildCount: audit.mediaChildCount,
    videoCount: audit.videoCount,
    canvasCount: audit.canvasCount,
    imgCount: audit.imgCount,
    backgroundImagePresent: !!audit.backgroundImagePresent,
    childClassNames: audit.childClassNames,
    childDataset: audit.childDataset,
    srcObjectTrackIds: audit.srcObjectTrackIds,
    ...(extra && typeof extra === "object" && !Array.isArray(extra) ? extra : {}),
  });
  if (container instanceof HTMLElement && shouldEmitScreenshareDomOuterHtmlSummary()) {
    const summary = sanitizeScreenshareDomOuterHtmlSummary(container.outerHTML || "");
    if (summary) {
      logScreenshareTileRenderEvent("screenshare.media_container_outerhtml_summary", {
        tileId: resolvedTileId,
        participantId: uid,
        trackSid: normId(newTrackSid || ""),
        trackIdentity: normId(newTrackSid || ""),
        activeShareOwnerId: uid,
        renderReason: String(renderReason || "").trim() || null,
        hasExistingVideoElement: audit.videoCount > 0,
        fallbackReason: null,
        conversationId: convId || null,
        oldTrackSid: normId(oldTrackSid || "") || null,
        newTrackSid: normId(newTrackSid || "") || null,
        outerHtmlSummary: summary,
      });
    }
  }
}

function createStageTileVideoElementForMediaContainer(tile = null) {
  if (!(tile instanceof HTMLElement)) return null;
  const isGridTile = tile.classList.contains("stageGridTile");
  const videoEl = document.createElement("video");
  videoEl.className = isGridTile ? "stageGridVideo" : "participantVideo";
  videoEl.autoplay = true;
  videoEl.muted = true;
  videoEl.playsInline = true;
  return videoEl;
}

function ensureStageTileVideoElementForMediaContainer(tile = null) {
  if (!(tile instanceof HTMLElement)) return null;
  const isGridTile = tile.classList.contains("stageGridTile");
  const selector = isGridTile ? ".stageGridVideo" : ".participantVideo";
  let videoEl = tile.querySelector(selector);
  if (videoEl instanceof HTMLVideoElement) return videoEl;
  videoEl = createStageTileVideoElementForMediaContainer(tile);
  if (!(videoEl instanceof HTMLVideoElement)) return null;
  const firstChild = tile.firstElementChild;
  if (firstChild) {
    try {
      tile.insertBefore(videoEl, firstChild);
    } catch (_) {
      tile.appendChild(videoEl);
    }
  } else {
    tile.appendChild(videoEl);
  }
  return videoEl;
}

function detachMediaElementSrcObjectForScreenshareReplace(mediaEl = null, {
  participantId = "",
  tileId = "",
  oldTrackSid = "",
  newTrackSid = "",
  renderReason = "",
  force = false,
} = {}) {
  if (!(mediaEl instanceof HTMLMediaElement)) return { detached: false, matchedOldTrack: false, trackIds: [] };
  const trackIds = collectMediaElementSrcTrackIds(mediaEl);
  const normalizedOldTrackSid = normId(oldTrackSid || "");
  const matchedOldTrack = !!(
    normalizedOldTrackSid
    && trackIds.some((trackId) => normId(trackId) === normalizedOldTrackSid)
  );
  const shouldDetach = !!(
    force
    || matchedOldTrack
    || !!mediaEl.srcObject
    || !!String(mediaEl.getAttribute?.("src") || "").trim()
  );
  if (!shouldDetach) {
    return {
      detached: false,
      matchedOldTrack,
      trackIds,
    };
  }
  try {
    mediaEl.pause?.();
    mediaEl.srcObject = null;
    mediaEl.removeAttribute?.("src");
    mediaEl.load?.();
  } catch (_) {
    try { mediaEl.srcObject = null; } catch (_) {}
  }
  logScreenshareMediaContainerEvent("screenshare.old_track_detached_from_element", {
    participantId,
    tileId,
    oldTrackSid: normalizedOldTrackSid || null,
    newTrackSid,
    renderReason: String(renderReason || "").trim() || "screenshare_replace_detach_media_element",
    fallbackReason: matchedOldTrack ? "matched_old_track" : (force ? "forced_detach" : "srcobject_present"),
    container: mediaEl.closest(".participantTile, .stageGridTile") || mediaEl,
    targetTag: String(mediaEl.tagName || "").trim().toLowerCase(),
    targetClassName: String(mediaEl.className || "").trim() || null,
    srcObjectTrackIds: trackIds,
  });
  return {
    detached: true,
    matchedOldTrack,
    trackIds,
  };
}

function clearLegacyScreensharePanelMediaChildren({
  conversationId = "",
  participantId = "",
  oldTrackSid = "",
  newTrackSid = "",
  renderReason = "",
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || "");
  const stage = document.getElementById("callStage");
  if (!stage) return { cleared: false, panelCount: 0, mediaChildRemovedCount: 0 };
  const panels = Array.from(stage.querySelectorAll(".serverVoiceScreensharePanel"));
  if (!panels.length) return { cleared: false, panelCount: 0, mediaChildRemovedCount: 0 };
  let mediaChildRemovedCount = 0;
  panels.forEach((panelEl, index) => {
    const panelTileId = `legacy_panel:${uid || "unknown"}:${index + 1}`;
    const panelVideoEls = Array.from(panelEl.querySelectorAll("video,audio"));
    logScreenshareMediaContainerEvent("screenshare.media_container_audit_before_replace", {
      conversationId: convId,
      participantId: uid,
      tileId: panelTileId,
      oldTrackSid,
      newTrackSid,
      renderReason: String(renderReason || "").trim() || "screenshare_replace_legacy_panel_audit_before",
      container: panelEl,
      containerType: "legacy_screenshare_panel",
    });
    panelVideoEls.forEach((mediaEl) => {
      const detachResult = detachMediaElementSrcObjectForScreenshareReplace(mediaEl, {
        participantId: uid,
        tileId: panelTileId,
        oldTrackSid,
        newTrackSid,
        renderReason: String(renderReason || "").trim() || "screenshare_replace_legacy_panel_detach",
        force: true,
      });
      if (detachResult.detached) mediaChildRemovedCount += 1;
    });
    const inlineBackground = String(panelEl.style.backgroundImage || "").trim();
    if (inlineBackground && inlineBackground.toLowerCase() !== "none") {
      panelEl.style.removeProperty("background-image");
      logScreenshareMediaContainerEvent("screenshare.media_child_removed", {
        conversationId: convId,
        participantId: uid,
        tileId: panelTileId,
        oldTrackSid,
        newTrackSid,
        renderReason: String(renderReason || "").trim() || "screenshare_replace_legacy_panel_clear_background",
        container: panelEl,
        removedNodeType: "inline_background_image",
      });
    }
    panelEl.hidden = true;
    panelEl.setAttribute("aria-hidden", "true");
    logScreenshareMediaContainerEvent("screenshare.media_container_cleared", {
      conversationId: convId,
      participantId: uid,
      tileId: panelTileId,
      oldTrackSid,
      newTrackSid,
      renderReason: String(renderReason || "").trim() || "screenshare_replace_legacy_panel_cleared",
      container: panelEl,
      containerType: "legacy_screenshare_panel",
      mediaChildRemovedCount,
    });
  });
  return {
    cleared: mediaChildRemovedCount > 0,
    panelCount: panels.length,
    mediaChildRemovedCount,
  };
}

function clearScreenshareTileMediaContainer(tile = null, {
  conversationId = "",
  participantId = "",
  tileId = "",
  oldTrackSid = "",
  newTrackSid = "",
  renderReason = "",
  removeVideoElements = true,
} = {}) {
  if (!(tile instanceof HTMLElement)) {
    return {
      cleared: false,
      removedMediaNodes: 0,
      detachedMediaNodes: 0,
      tileId: String(tileId || "").trim(),
      participantId: normId(participantId || ""),
      oldTrackSid: normId(oldTrackSid || ""),
      newTrackSid: normId(newTrackSid || ""),
      beforeAudit: collectScreenshareMediaContainerAuditSnapshot(null),
      afterAudit: collectScreenshareMediaContainerAuditSnapshot(null),
    };
  }
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || getStageTileIdentityFromEl(tile).participantId || tile.getAttribute("data-call-user-id") || "");
  const resolvedTileId = String(tileId || getStageTileIdentityFromEl(tile).tileId || tile.getAttribute("data-call-tile-id") || "").trim();
  const beforeAudit = collectScreenshareMediaContainerAuditSnapshot(tile);
  logScreenshareMediaContainerEvent("screenshare.media_container_audit_before_replace", {
    conversationId: convId,
    participantId: uid,
    tileId: resolvedTileId,
    oldTrackSid,
    newTrackSid,
    renderReason: String(renderReason || "").trim() || "screenshare_replace_tile_audit_before",
    container: tile,
    containerType: "screenshare_tile",
  });

  const mediaNodes = Array.from(tile.querySelectorAll("video,canvas,img"));
  let removedMediaNodes = 0;
  let detachedMediaNodes = 0;
  mediaNodes.forEach((nodeEl) => {
    if (nodeEl instanceof HTMLMediaElement) {
      const detachResult = detachMediaElementSrcObjectForScreenshareReplace(nodeEl, {
        participantId: uid,
        tileId: resolvedTileId,
        oldTrackSid,
        newTrackSid,
        renderReason: String(renderReason || "").trim() || "screenshare_replace_tile_detach",
        force: true,
      });
      if (detachResult.detached) detachedMediaNodes += 1;
      if (!removeVideoElements && nodeEl.classList.contains("stageGridVideo")) return;
      if (!removeVideoElements && nodeEl.classList.contains("participantVideo")) return;
    }
    if (nodeEl instanceof HTMLImageElement) {
      const insideAvatar = !!nodeEl.closest(".stageGridAvatar, .participantAvatar");
      if (insideAvatar) return;
    }
    const nodeTag = String(nodeEl.tagName || "").trim().toLowerCase();
    const nodeClass = String(nodeEl.className || "").trim() || null;
    try { nodeEl.remove(); } catch (_) {}
    removedMediaNodes += 1;
    logScreenshareMediaContainerEvent("screenshare.media_child_removed", {
      conversationId: convId,
      participantId: uid,
      tileId: resolvedTileId,
      oldTrackSid,
      newTrackSid,
      renderReason: String(renderReason || "").trim() || "screenshare_replace_tile_remove_media_child",
      container: tile,
      removedNodeType: nodeTag,
      removedNodeClass: nodeClass,
    });
  });

  tile.removeAttribute("data-call-video-track-id");
  tile.removeAttribute("data-call-track-identity");
  tile.removeAttribute("data-call-video-hold-until");
  tile.removeAttribute("data-call-video-seen");
  tile.removeAttribute("data-call-screenshare-missing-until");
  tile.removeAttribute("data-call-screenshare-gap-started-at");
  tile.removeAttribute("data-call-screenshare-reconnecting");
  tile.removeAttribute("data-call-screenshare-fallback-blocked");
  tile.removeAttribute("data-call-screenshare-focus-preserved-serial");
  tile.removeAttribute("data-call-screenshare-focus-skip-serial");
  tile.removeAttribute("data-call-keep-mounted");
  tile.classList.remove("has-video");
  tile.classList.remove("is-share-reconnecting");
  tile.classList.remove("is-watch-gated");
  tile.classList.remove("is-share-loading");
  tile.classList.remove("has-watch-snapshot");
  clearCallTileWatchSnapshot(tile);
  setCallTileWatchPrompt(tile, false);
  setCallTileLoadingPrompt(tile, false);
  tile.style.removeProperty("--call-watch-snapshot-image");
  tile.style.removeProperty("background-image");
  Array.from(tile.querySelectorAll("[style]")).forEach((styledEl) => {
    const inlineBg = String(styledEl.style?.backgroundImage || "").trim();
    if (inlineBg && inlineBg.toLowerCase() !== "none") {
      styledEl.style.removeProperty("background-image");
      logScreenshareMediaContainerEvent("screenshare.media_child_removed", {
        conversationId: convId,
        participantId: uid,
        tileId: resolvedTileId,
        oldTrackSid,
        newTrackSid,
        renderReason: String(renderReason || "").trim() || "screenshare_replace_remove_inline_background",
        container: tile,
        removedNodeType: "inline_background_image",
        removedNodeClass: String(styledEl.className || "").trim() || null,
      });
    }
  });

  const afterAudit = collectScreenshareMediaContainerAuditSnapshot(tile);
  logScreenshareMediaContainerEvent("screenshare.media_container_cleared", {
    conversationId: convId,
    participantId: uid,
    tileId: resolvedTileId,
    oldTrackSid,
    newTrackSid,
    renderReason: String(renderReason || "").trim() || "screenshare_replace_tile_cleared",
    container: tile,
    removedMediaNodes,
    detachedMediaNodes,
  });
  return {
    cleared: !!(removedMediaNodes > 0 || detachedMediaNodes > 0),
    removedMediaNodes,
    detachedMediaNodes,
    tileId: resolvedTileId,
    participantId: uid,
    oldTrackSid: normId(oldTrackSid || ""),
    newTrackSid: normId(newTrackSid || ""),
    beforeAudit,
    afterAudit,
  };
}

function clearScreenshareMediaContainersForParticipant({
  conversationId = "",
  participantId = "",
  oldTrackSid = "",
  newTrackSid = "",
  renderReason = "screenshare_replace",
  clearLegacyPanel = true,
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || "");
  const stage = document.getElementById("callStage");
  const tileId = buildStageParticipantTileId(uid, "screenshare");
  if (!convId || !uid || !stage) {
    return {
      tileCount: 0,
      clearedTileCount: 0,
      removedMediaNodes: 0,
      detachedMediaNodes: 0,
      legacyPanelCleared: false,
      tileId,
    };
  }
  const candidateTiles = Array.from(stage.querySelectorAll(".participantTile, .stageGridTile"))
    .filter((tileEl) => isScreenshareStageTileCandidateForParticipant(tileEl, uid));
  let clearedTileCount = 0;
  let removedMediaNodes = 0;
  let detachedMediaNodes = 0;
  candidateTiles.forEach((tileEl) => {
    const identity = getStageTileIdentityFromEl(tileEl);
    const resolvedTileId = String(identity.tileId || tileEl.getAttribute("data-call-tile-id") || tileId || "").trim();
    const clearResult = clearScreenshareTileMediaContainer(tileEl, {
      conversationId: convId,
      participantId: uid,
      tileId: resolvedTileId,
      oldTrackSid,
      newTrackSid,
      renderReason,
      removeVideoElements: true,
    });
    if (clearResult.cleared) clearedTileCount += 1;
    removedMediaNodes += Number(clearResult.removedMediaNodes || 0);
    detachedMediaNodes += Number(clearResult.detachedMediaNodes || 0);
  });
  const legacyPanelResult = clearLegacyPanel
    ? clearLegacyScreensharePanelMediaChildren({
      conversationId: convId,
      participantId: uid,
      oldTrackSid,
      newTrackSid,
      renderReason: `${String(renderReason || "").trim() || "screenshare_replace"}_legacy_panel_clear`,
    })
    : { cleared: false, panelCount: 0, mediaChildRemovedCount: 0 };
  return {
    tileCount: candidateTiles.length,
    clearedTileCount,
    removedMediaNodes,
    detachedMediaNodes,
    legacyPanelCleared: !!legacyPanelResult?.cleared,
    legacyPanelCount: Number(legacyPanelResult?.panelCount || 0),
    legacyPanelMediaChildRemovedCount: Number(legacyPanelResult?.mediaChildRemovedCount || 0),
    tileId,
  };
}

function auditScreenshareMediaContainerAfterAttach({
  conversationId = "",
  participantId = "",
  tile = null,
  tileId = "",
  oldTrackSid = "",
  newTrackSid = "",
  renderReason = "",
} = {}) {
  if (!(tile instanceof HTMLElement)) return;
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || getStageTileIdentityFromEl(tile).participantId || tile.getAttribute("data-call-user-id") || "");
  const resolvedTileId = String(tileId || getStageTileIdentityFromEl(tile).tileId || tile.getAttribute("data-call-tile-id") || "").trim();
  const stage = document.getElementById("callStage");
  const normalizedOldTrackSid = normId(oldTrackSid || "");
  const normalizedNewTrackSid = normId(newTrackSid || "");
  const audit = collectScreenshareMediaContainerAuditSnapshot(tile);
  logScreenshareMediaContainerEvent("screenshare.media_container_audit_after_attach", {
    conversationId: convId,
    participantId: uid,
    tileId: resolvedTileId,
    oldTrackSid: normalizedOldTrackSid,
    newTrackSid: normalizedNewTrackSid,
    renderReason: String(renderReason || "").trim() || "screenshare_attach_audit_after",
    container: tile,
    containerType: "screenshare_tile",
  });

  const hasExpectedTrack = !!(
    normalizedNewTrackSid
    && audit.srcObjectTrackIds.some((trackId) => normId(trackId) === normalizedNewTrackSid)
  );
  const hasOldTrackInTile = !!(
    normalizedOldTrackSid
    && audit.srcObjectTrackIds.some((trackId) => normId(trackId) === normalizedOldTrackSid)
  );
  const stageSiblingTrackIds = [];
  Array.from(stage?.querySelectorAll?.(".serverVoiceScreensharePanel video, .serverVoiceScreensharePanel audio") || []).forEach((mediaEl) => {
    collectMediaElementSrcTrackIds(mediaEl).forEach((tid) => {
      if (!stageSiblingTrackIds.includes(tid)) stageSiblingTrackIds.push(tid);
    });
  });
  const hasOldTrackInLegacyPanel = !!(
    normalizedOldTrackSid
    && stageSiblingTrackIds.some((trackId) => normId(trackId) === normalizedOldTrackSid)
  );
  const siblingStageTrackIds = [];
  Array.from(stage?.querySelectorAll?.(".participantTile video, .stageGridTile video") || []).forEach((mediaEl) => {
    if (mediaEl === tile.querySelector(".stageGridVideo, .participantVideo")) return;
    collectMediaElementSrcTrackIds(mediaEl).forEach((tid) => {
      if (!siblingStageTrackIds.includes(tid)) siblingStageTrackIds.push(tid);
    });
  });
  const hasOldTrackInSiblingStageVideo = !!(
    normalizedOldTrackSid
    && siblingStageTrackIds.some((trackId) => normId(trackId) === normalizedOldTrackSid)
  );
  let parentBackgroundImagePresent = false;
  let parentNode = tile.parentElement;
  while (parentNode instanceof HTMLElement) {
    const inlineBg = String(parentNode.style?.backgroundImage || "").trim().toLowerCase();
    if (inlineBg && inlineBg !== "none") {
      parentBackgroundImagePresent = true;
      break;
    }
    if (parentNode.id === "callStage" || parentNode.classList.contains("callStageViewport")) break;
    parentNode = parentNode.parentElement;
  }
  const mismatchReasons = [];
  if (audit.videoCount !== 1) mismatchReasons.push(`video_count_${audit.videoCount}`);
  if (audit.canvasCount > 0) mismatchReasons.push(`canvas_count_${audit.canvasCount}`);
  if (!hasExpectedTrack && normalizedNewTrackSid) mismatchReasons.push("new_track_not_attached");
  if (hasOldTrackInTile) mismatchReasons.push("old_track_still_in_tile");
  if (hasOldTrackInLegacyPanel) mismatchReasons.push("old_track_still_in_legacy_panel");
  if (hasOldTrackInSiblingStageVideo) mismatchReasons.push("old_track_still_in_sibling_stage_video");
  if (audit.backgroundImagePresent) mismatchReasons.push("background_image_present");
  if (parentBackgroundImagePresent) mismatchReasons.push("parent_background_image_present");
  if (mismatchReasons.length) {
    logScreenshareMediaContainerEvent("screenshare.stale_media_artifact_detected", {
      conversationId: convId,
      participantId: uid,
      tileId: resolvedTileId,
      oldTrackSid: normalizedOldTrackSid,
      newTrackSid: normalizedNewTrackSid,
      renderReason: String(renderReason || "").trim() || "screenshare_attach_stale_artifact_detected",
      fallbackReason: mismatchReasons.join("|"),
      container: tile,
      siblingTrackIds: stageSiblingTrackIds,
      siblingStageTrackIds,
    });
  }
}

function resetScreenshareGridTileDomState(tileEl) {
  if (!(tileEl instanceof HTMLElement)) return;
  const videoEl = tileEl.querySelector(".stageGridVideo, .participantVideo");
  if (videoEl) {
    stopMemberTileFrameProbe(videoEl);
    try {
      videoEl.pause?.();
      videoEl.srcObject = null;
      videoEl.removeAttribute?.("src");
      videoEl.load?.();
    } catch (_) {}
  }
  tileEl.removeAttribute("data-call-video-track-id");
  tileEl.removeAttribute("data-call-track-identity");
  tileEl.removeAttribute("data-call-video-hold-until");
  tileEl.removeAttribute("data-call-video-seen");
  tileEl.removeAttribute("data-call-screenshare-missing-until");
  tileEl.removeAttribute("data-call-screenshare-gap-started-at");
  tileEl.removeAttribute("data-call-screenshare-reconnecting");
  tileEl.removeAttribute("data-call-screenshare-fallback-blocked");
  tileEl.removeAttribute("data-call-screenshare-focus-preserved-serial");
  tileEl.removeAttribute("data-call-screenshare-focus-skip-serial");
  tileEl.removeAttribute("data-call-keep-mounted");
  tileEl.removeAttribute("data-call-active-share-owner-id");
  tileEl.classList.remove("has-video");
  tileEl.classList.remove("is-share-reconnecting");
  tileEl.classList.remove("is-watch-gated");
  tileEl.classList.remove("is-share-loading");
  tileEl.classList.remove("has-watch-snapshot");
  clearCallTileWatchSnapshot(tileEl);
  setCallTileWatchPrompt(tileEl, false);
  setCallTileLoadingPrompt(tileEl, false);
}

function isScreenshareStageTileCandidateForParticipant(tileEl, participantId = "") {
  if (!(tileEl instanceof HTMLElement)) return false;
  const uid = normId(participantId || "");
  const identity = getStageTileIdentityFromEl(tileEl);
  const tileOwnerId = normId(identity.participantId || tileEl.getAttribute("data-call-user-id") || "");
  if (!tileOwnerId || (uid && tileOwnerId !== uid)) return false;
  const entryKey = String(tileEl.getAttribute("data-call-entry-key") || "").trim().toLowerCase();
  const mediaType = normalizeRelayMediaKind(tileEl.getAttribute("data-call-media-type") || "");
  const tileType = normalizeStageTileType(identity.tileType || tileEl.getAttribute("data-call-tile-type") || "");
  const tileId = String(identity.tileId || tileEl.getAttribute("data-call-tile-id") || "").trim().toLowerCase();
  return !!(
    tileType === "screenshare"
    || mediaType === "share"
    || entryKey.endsWith(":screenshare")
    || tileId.startsWith("participant_screenshare:")
  );
}

function scoreScreenshareStageTileCandidate(tileEl, {
  preferredTrackIdentity = "",
} = {}) {
  if (!(tileEl instanceof HTMLElement)) {
    return {
      score: Number.NEGATIVE_INFINITY,
      trackIdentity: "",
    };
  }
  const preferredTrackId = normId(preferredTrackIdentity || "");
  const trackIdentity = normId(
    tileEl.getAttribute("data-call-video-track-id")
    || tileEl.getAttribute("data-call-track-identity")
    || ""
  );
  const tileId = String(tileEl.getAttribute("data-call-tile-id") || "").trim();
  const isFocused = !!(tileId && String(stageFocusedTileId || "").trim() === tileId);
  const keepMounted = tileEl.getAttribute("data-call-keep-mounted") === "1";
  const hasVideoClass = tileEl.classList.contains("has-video");
  const reconnecting = tileEl.classList.contains("is-share-reconnecting");
  let score = 0;
  if (preferredTrackId && trackIdentity && preferredTrackId === trackIdentity) score += 12;
  if (trackIdentity) score += 6;
  if (hasVideoClass) score += 3;
  if (isFocused) score += 2;
  if (reconnecting) score -= 1;
  if (keepMounted) score -= 2;
  return {
    score,
    trackIdentity,
  };
}

function pruneScreenshareStageTilesForParticipant({
  conversationId = "",
  participantId = "",
  removeAll = false,
  preferredTrackIdentity = "",
  reason = "screenshare_dom_prune",
  triggerReason = "screenshare_dom_prune",
  callerFunction = "pruneScreenshareStageTilesForParticipant",
  oldTrackSid = "",
  newTrackSid = "",
  logDomCount = true,
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || "");
  const stage = document.getElementById("callStage");
  const focusedTileId = String(stageFocusedTileId || "").trim();
  if (!convId || !uid || !stage) {
    return {
      removedCount: 0,
      candidateCount: 0,
      remainingCount: 0,
      removedTileIds: [],
      keptTileId: "",
      focusedTileId,
    };
  }
  const candidates = Array.from(stage.querySelectorAll(".participantTile, .stageGridTile"))
    .filter((tileEl) => isScreenshareStageTileCandidateForParticipant(tileEl, uid));
  if (!candidates.length) {
    if (logDomCount) {
      logServerVoiceStageTilesEvent("stage.screenshare_tile_dom_count", convId, {
        participantId: uid,
        oldTrackSid: normId(oldTrackSid || "") || null,
        newTrackSid: normId(newTrackSid || preferredTrackIdentity || "") || null,
        tileCountBefore: 0,
        tileCountAfter: 0,
        focusedTileId: focusedTileId || null,
        renderReason: String(reason || "").trim() || "screenshare_dom_prune",
        triggerReason: String(triggerReason || "").trim() || "screenshare_dom_prune",
        callerFunction: String(callerFunction || "").trim() || "pruneScreenshareStageTilesForParticipant",
      });
    }
    return {
      removedCount: 0,
      candidateCount: 0,
      remainingCount: 0,
      removedTileIds: [],
      keptTileId: "",
      focusedTileId,
    };
  }

  const preferredTrackId = normId(preferredTrackIdentity || newTrackSid || "");
  let keepTile = null;
  let keptTileId = "";
  if (!removeAll) {
    const scored = candidates
      .map((tileEl) => ({
        tileEl,
        ...scoreScreenshareStageTileCandidate(tileEl, {
          preferredTrackIdentity: preferredTrackId,
        }),
      }))
      .sort((left, right) => {
        if (right.score !== left.score) return right.score - left.score;
        return 0;
      });
    keepTile = scored[0]?.tileEl || candidates[0] || null;
    if (keepTile) {
      keepTile.removeAttribute("data-call-keep-mounted");
      const identity = getStageTileIdentityFromEl(keepTile);
      keptTileId = String(identity.tileId || keepTile.getAttribute("data-call-tile-id") || "").trim();
    }
  }

  const totalBefore = candidates.length;
  let removedCount = 0;
  const removedTileIds = [];
  candidates.forEach((tileEl) => {
    if (!removeAll && keepTile && tileEl === keepTile) return;
    const identity = getStageTileIdentityFromEl(tileEl);
    const tileId = String(identity.tileId || buildStageParticipantTileId(uid, "screenshare") || "").trim();
    const tileTrackSid = normId(
      tileEl.getAttribute("data-call-video-track-id")
      || tileEl.getAttribute("data-call-track-identity")
      || ""
    );
    resetScreenshareGridTileDomState(tileEl);
    try { tileEl.remove(); } catch (_) {}
    removedCount += 1;
    if (tileId) removedTileIds.push(tileId);
    logScreenshareRestartEvent("screenshare.duplicate_tile_pruned", {
      conversationId: convId,
      participantId: uid,
      oldTileId: tileId || buildStageParticipantTileId(uid, "screenshare"),
      newTileId: keptTileId || buildStageParticipantTileId(uid, "screenshare"),
      activeShareOwnerId: uid,
      tileCountBefore: totalBefore,
      tileCountAfter: Math.max(0, totalBefore - removedCount),
      oldTrackSid: tileTrackSid || normId(oldTrackSid || "") || null,
      newTrackSid: preferredTrackId || normId(newTrackSid || "") || null,
      focusedTileId: focusedTileId || null,
      renderReason: String(reason || "").trim() || "screenshare_dom_prune",
      triggerReason: String(triggerReason || "").trim() || "screenshare_dom_prune",
      callerFunction: String(callerFunction || "").trim() || "pruneScreenshareStageTilesForParticipant",
      removedTileId: tileId || null,
    });
  });

  const remainingCount = Math.max(0, totalBefore - removedCount);
  if (logDomCount) {
    logServerVoiceStageTilesEvent("stage.screenshare_tile_dom_count", convId, {
      participantId: uid,
      oldTrackSid: normId(oldTrackSid || "") || null,
      newTrackSid: preferredTrackId || normId(newTrackSid || "") || null,
      tileCountBefore: totalBefore,
      tileCountAfter: remainingCount,
      focusedTileId: focusedTileId || null,
      renderReason: String(reason || "").trim() || "screenshare_dom_prune",
      triggerReason: String(triggerReason || "").trim() || "screenshare_dom_prune",
      callerFunction: String(callerFunction || "").trim() || "pruneScreenshareStageTilesForParticipant",
      removedCount,
      removedTileIds,
      keptTileId: keptTileId || null,
    });
  }
  return {
    removedCount,
    candidateCount: totalBefore,
    remainingCount,
    removedTileIds,
    keptTileId,
    focusedTileId,
  };
}

function enforceScreenshareStageTileDomInvariant(conversationId = "", {
  reason = "render_group_stage_members",
  triggerReason = "render_group_stage_members",
  callerFunction = "renderGroupCallStageMembers",
  oldTrackSid = "",
  newTrackSid = "",
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const stage = document.getElementById("callStage");
  if (!convId || !stage) {
    return {
      participantCount: 0,
      prunedCount: 0,
    };
  }
  const byParticipant = new Map();
  stage.querySelectorAll(".participantTile, .stageGridTile").forEach((tileEl) => {
    if (!isScreenshareStageTileCandidateForParticipant(tileEl)) return;
    const identity = getStageTileIdentityFromEl(tileEl);
    const uid = normId(identity.participantId || tileEl.getAttribute("data-call-user-id") || "");
    if (!uid) return;
    const existing = byParticipant.get(uid);
    if (existing) {
      existing.push(tileEl);
      return;
    }
    byParticipant.set(uid, [tileEl]);
  });

  let prunedCount = 0;
  const activeShare = shouldUseServerVoiceLiveKitTransport(convId)
    ? getServerVoiceActiveScreenshare(convId)
    : null;
  const activeOwnerId = normId(activeShare?.ownerUserId || "");
  const activeVideoTrack = pickLiveVideoTrackFromStream(activeShare?.stream || null, { allowMuted: true })
    || getAnyVideoTrackFromStream(activeShare?.stream || null)
    || null;
  const activeTrackIdentity = normId(
    activeVideoTrack?.sid
    || activeVideoTrack?.id
    || activeShare?.trackSid
    || ""
  );
  for (const [uid, tiles] of byParticipant.entries()) {
    const beforeCount = tiles.length;
    const preferredTrackIdentity = uid === activeOwnerId
      ? activeTrackIdentity
      : "";
    if (beforeCount > 1) {
      const pruned = pruneScreenshareStageTilesForParticipant({
        conversationId: convId,
        participantId: uid,
        removeAll: false,
        preferredTrackIdentity,
        reason: "screenshare_dom_invariant_after_render",
        triggerReason,
        callerFunction,
        oldTrackSid,
        newTrackSid,
        logDomCount: true,
      });
      prunedCount += Number(pruned?.removedCount || 0);
      continue;
    }
    logServerVoiceStageTilesEvent("stage.screenshare_tile_dom_count", convId, {
      participantId: uid,
      oldTrackSid: normId(oldTrackSid || "") || null,
      newTrackSid: normId(newTrackSid || preferredTrackIdentity || "") || null,
      tileCountBefore: beforeCount,
      tileCountAfter: beforeCount,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: String(reason || "").trim() || "render_group_stage_members",
      triggerReason: String(triggerReason || "").trim() || "render_group_stage_members",
      callerFunction: String(callerFunction || "").trim() || "renderGroupCallStageMembers",
    });
  }

  return {
    participantCount: byParticipant.size,
    prunedCount,
  };
}

function pruneScreenshareGridTilesForParticipant({
  conversationId = "",
  participantId = "",
  removeAll = false,
  reason = "screenshare_restart_cleanup",
  triggerReason = "screenshare_restart_cleanup",
  callerFunction = "pruneScreenshareGridTilesForParticipant",
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || "");
  const grid = document.getElementById("callStageGrid");
  if (!convId || !uid || !grid) {
    return {
      removedCount: 0,
      candidateCount: 0,
      remainingCount: 0,
      removedTileIds: [],
    };
  }
  const candidates = [];
  const expectedEntryKey = `${uid}:screenshare`;
  grid.querySelectorAll("[data-call-grid-entry='1'], [data-call-extra='1'], .stageGridTile").forEach((tileEl) => {
    if (!(tileEl instanceof HTMLElement)) return;
    const identity = getStageTileIdentityFromEl(tileEl);
    const tileOwnerId = normId(identity.participantId || tileEl.getAttribute("data-call-user-id") || "");
    if (tileOwnerId !== uid) return;
    const entryKey = String(tileEl.getAttribute("data-call-entry-key") || "").trim().toLowerCase();
    const mediaType = normalizeRelayMediaKind(tileEl.getAttribute("data-call-media-type") || "");
    const tileType = normalizeStageTileType(identity.tileType || tileEl.getAttribute("data-call-tile-type") || "");
    const looksScreenshare = !!(
      tileType === "screenshare"
      || mediaType === "share"
      || entryKey === expectedEntryKey
      || entryKey.endsWith(":screenshare")
    );
    if (!looksScreenshare) return;
    candidates.push(tileEl);
  });
  if (!candidates.length) {
    return {
      removedCount: 0,
      candidateCount: 0,
      remainingCount: 0,
      removedTileIds: [],
    };
  }
  let keepTile = null;
  if (!removeAll) {
    const scored = candidates
      .map((tileEl) => {
        const hasTrack = !!normId(tileEl.getAttribute("data-call-video-track-id") || "");
        const hasVideoClass = tileEl.classList.contains("has-video");
        const keepMounted = tileEl.getAttribute("data-call-keep-mounted") === "1";
        const score = (hasTrack ? 3 : 0) + (hasVideoClass ? 2 : 0) - (keepMounted ? 1 : 0);
        return { tileEl, score };
      })
      .sort((a, b) => b.score - a.score);
    keepTile = scored[0]?.tileEl || candidates[0];
    if (keepTile) keepTile.removeAttribute("data-call-keep-mounted");
  }

  let removedCount = 0;
  const removedTileIds = [];
  candidates.forEach((tileEl) => {
    if (!removeAll && keepTile && tileEl === keepTile) return;
    const identity = getStageTileIdentityFromEl(tileEl);
    const tileId = String(identity.tileId || buildStageParticipantTileId(uid, "screenshare") || "").trim();
    resetScreenshareGridTileDomState(tileEl);
    try { tileEl.remove(); } catch (_) {}
    removedCount += 1;
    if (tileId) removedTileIds.push(tileId);
  });

  if (removedCount > 0) {
    logScreenshareStopCleanupEvent("screenshare.old_tile_pruned", {
      conversationId: convId,
      streamOwnerId: uid,
      tileId: buildStageParticipantTileId(uid, "screenshare"),
      reason: String(reason || "").trim() || "screenshare_restart_cleanup",
      triggerReason: String(triggerReason || "").trim() || "screenshare_restart_cleanup",
      callerFunction: String(callerFunction || "").trim() || "pruneScreenshareGridTilesForParticipant",
      removedCount,
      removedTileIds,
    });
  }
  const remainingCount = Math.max(0, candidates.length - removedCount);
  return {
    removedCount,
    candidateCount: candidates.length,
    remainingCount,
    removedTileIds,
  };
}

async function restartServerVoiceScreenshareWithStageCleanup(conversationId = null, {
  triggerReason = "screenshare_restart",
  callerFunction = "restartServerVoiceScreenshareWithStageCleanup",
  restoreFocusIfPreviouslyFocused = true,
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  if (!convId) return false;
  const layer = getActiveServerVoiceScreenshareLayer(convId);
  if (!layer || typeof layer.startShare !== "function" || typeof layer.stopShare !== "function") {
    throw new Error("server_voice_screenshare_layer_unavailable");
  }
  const meId = normId(state.user?.id || "");
  if (!meId) throw new Error("screenshare_restart_user_unavailable");
  const oldTileId = buildStageParticipantTileId(meId, "screenshare");
  const newTileId = buildStageParticipantTileId(meId, "screenshare");
  const before = collectStageTilesSnapshotForScreenshareRestart();
  const activeShareBefore = getServerVoiceActiveScreenshare(convId);
  const activeShareOwnerBefore = normId(activeShareBefore?.ownerUserId || "");
  const activeTrackBefore = pickLiveVideoTrackFromStream(activeShareBefore?.stream || null, { allowMuted: true })
    || getAnyVideoTrackFromStream(activeShareBefore?.stream || null)
    || null;
  const oldTrackSid = normId(activeTrackBefore?.sid || activeTrackBefore?.id || activeShareBefore?.trackSid || "");
  const focusedIdentity = parseStageParticipantTileId(String(stageFocusedTileId || "").trim());
  const focusedScreenshareForLocalOwner = !!(
    normalizeStageTileType(focusedIdentity.tileType || "") === "screenshare"
    && normId(focusedIdentity.participantId || "") === meId
  );
  const memberFocusForLocalOwnerShare = !!(
    stageFocus === "member"
    && normId(stageFocusMemberId || "") === meId
    && normalizeRelayMediaKind(stageFocusMemberMediaType || "") === "share"
  );
  const shouldRestoreFocus = !!(
    restoreFocusIfPreviouslyFocused
    && (focusedScreenshareForLocalOwner || memberFocusForLocalOwnerShare)
  );

  logScreenshareRestartEvent("screenshare.restart_requested", {
    conversationId: convId,
    participantId: meId,
    oldTileId,
    newTileId,
    activeShareOwnerId: activeShareOwnerBefore || meId,
    tileCountBefore: before.tileCount,
    tileCountAfter: before.tileCount,
    knownTileIdsBefore: before.knownTileIds,
    visibleTileIdsBefore: before.visibleTileIds,
    domTileCountBefore: before.domTileCount,
    focusedScreenshareForLocalOwner,
    memberFocusForLocalOwnerShare,
    triggerReason,
    callerFunction,
  });
  markStageScreenshareReplacingOwner(convId, meId);
  setStageScreenshareReplacementState(convId, meId, {
    oldTrackSid,
    newTrackSid: "",
    renderReason: String(triggerReason || "").trim() || "screenshare_restart",
    phase: "replace_started",
  });
  logScreenshareRestartEvent("screenshare.replace_started", {
    conversationId: convId,
    participantId: meId,
    oldTileId,
    newTileId,
    activeShareOwnerId: activeShareOwnerBefore || meId,
    tileCountBefore: before.tileCount,
    tileCountAfter: before.tileCount,
    oldTrackSid: oldTrackSid || null,
    newTrackSid: null,
    focusedTileId: String(stageFocusedTileId || "").trim() || null,
    renderReason: "replace_started",
    triggerReason,
    callerFunction,
  });

  try {
    if (focusedScreenshareForLocalOwner || memberFocusForLocalOwnerShare) {
      stageLayoutMode = "grid";
      stageFocusTransitionExpiresAt = 0;
      stageFocusTransitionTargetTileId = "";
      stageFocusedTileId = "";
      if (memberFocusForLocalOwnerShare) {
        stageFocus = "remote";
        stageFocusMemberId = "";
        stageFocusMemberTrackId = "";
        stageFocusMemberMediaType = "";
      }
      refreshCallUI();
    }

    clearScreenshareMediaContainersForParticipant({
      conversationId: convId,
      participantId: meId,
      oldTrackSid,
      newTrackSid: "",
      renderReason: "screenshare_replace_pre_stop_media_container_clear",
      clearLegacyPanel: true,
    });
    const preStopPrune = pruneScreenshareStageTilesForParticipant({
      conversationId: convId,
      participantId: meId,
      removeAll: true,
      reason: "screenshare_replace_pre_stop_hide_old_tile",
      triggerReason: `${triggerReason}_replace_pre_stop`,
      callerFunction: "restartServerVoiceScreenshareWithStageCleanup",
      oldTrackSid,
      newTrackSid: "",
      logDomCount: true,
    });
    logScreenshareRestartEvent("screenshare.replace_old_dom_pruned", {
      conversationId: convId,
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerBefore || meId,
      tileCountBefore: Number(preStopPrune?.candidateCount || 0),
      tileCountAfter: Number(preStopPrune?.remainingCount || 0),
      oldTrackSid: oldTrackSid || null,
      newTrackSid: null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_pre_stop_hide_old_tile",
      triggerReason,
      callerFunction,
    });
    refreshCallUI();
    await new Promise((resolve) => setTimeout(resolve, 0));

    logScreenshareRestartEvent("screenshare.restart_cleanup_started", {
      conversationId: convId,
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerBefore || meId,
      tileCountBefore: before.tileCount,
      tileCountAfter: before.tileCount,
      oldTrackSid: oldTrackSid || null,
      newTrackSid: null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_cleanup_started",
      triggerReason,
      callerFunction,
    });

    if (layer.isLocalShareActive?.()) {
      await layer.stopShare?.({
        triggerReason: `${triggerReason}_restart_stop`,
      });
    }
    logScreenshareRestartEvent("screenshare.replace_old_track_detached", {
      conversationId: convId,
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerBefore || meId,
      tileCountBefore: before.tileCount,
      tileCountAfter: before.tileCount,
      oldTrackSid: oldTrackSid || null,
      newTrackSid: null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_old_track_detached",
      triggerReason,
      callerFunction,
    });
    cleanupStoppedScreenshareStageTile({
      conversationId: convId,
      streamOwnerId: meId,
      reason: "screenshare_restart_cleanup",
      clearWatchState: true,
      triggerReason: `${triggerReason}_restart_cleanup`,
      callerFunction: "restartServerVoiceScreenshareWithStageCleanup",
    });
    const forcedPruneGrid = pruneScreenshareGridTilesForParticipant({
      conversationId: convId,
      participantId: meId,
      removeAll: true,
      reason: "screenshare_restart_cleanup",
      triggerReason: `${triggerReason}_restart_cleanup`,
      callerFunction: "restartServerVoiceScreenshareWithStageCleanup",
    });
    const forcedPruneStage = pruneScreenshareStageTilesForParticipant({
      conversationId: convId,
      participantId: meId,
      removeAll: true,
      reason: "screenshare_restart_cleanup_stage",
      triggerReason: `${triggerReason}_restart_cleanup`,
      callerFunction: "restartServerVoiceScreenshareWithStageCleanup",
      oldTrackSid,
      newTrackSid: "",
      logDomCount: true,
    });
    logScreenshareRestartEvent("screenshare.replace_old_dom_pruned", {
      conversationId: convId,
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerBefore || meId,
      tileCountBefore: Math.max(
        Number(forcedPruneGrid?.candidateCount || 0),
        Number(forcedPruneStage?.candidateCount || 0),
      ),
      tileCountAfter: Number(forcedPruneStage?.remainingCount || 0),
      oldTrackSid: oldTrackSid || null,
      newTrackSid: null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_cleanup_prune",
      triggerReason,
      callerFunction,
      removedByGridPrune: Number(forcedPruneGrid?.removedCount || 0),
      removedByStagePrune: Number(forcedPruneStage?.removedCount || 0),
    });
    refreshCallUI();
    await new Promise((resolve) => setTimeout(resolve, 0));
    const afterCleanup = collectStageTilesSnapshotForScreenshareRestart();
    logScreenshareRestartEvent("screenshare.restart_cleanup_completed", {
      conversationId: convId,
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerBefore || meId,
      tileCountBefore: before.tileCount,
      tileCountAfter: afterCleanup.tileCount,
      knownTileIdsAfterCleanup: afterCleanup.knownTileIds,
      visibleTileIdsAfterCleanup: afterCleanup.visibleTileIds,
      domTileCountAfterCleanup: afterCleanup.domTileCount,
      removedByForcePrune: Number(forcedPruneGrid?.removedCount || 0) + Number(forcedPruneStage?.removedCount || 0),
      oldTrackSid: oldTrackSid || null,
      newTrackSid: null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_cleanup_completed",
      triggerReason,
      callerFunction,
    });

    logScreenshareRestartEvent("screenshare.old_tile_removed", {
      conversationId: convId,
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerBefore || meId,
      tileCountBefore: before.tileCount,
      tileCountAfter: afterCleanup.tileCount,
      oldTileStillPresent: !!afterCleanup.knownTileIds.includes(oldTileId),
      oldTrackSid: oldTrackSid || null,
      newTrackSid: null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_old_tile_removed",
      triggerReason,
      callerFunction,
    });
    logScreenshareRestartEvent("screenshare.replace_layout_recomputed", {
      conversationId: convId,
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerBefore || meId,
      tileCountBefore: before.tileCount,
      tileCountAfter: afterCleanup.tileCount,
      oldTrackSid: oldTrackSid || null,
      newTrackSid: null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_layout_recomputed_after_cleanup",
      visibleTileIds: afterCleanup.visibleTileIds,
      triggerReason,
      callerFunction,
    });

    const graceState = stageScreenshareGraceStateByConversation.get(convId) || null;
    if (normId(graceState?.ownerId || "") === meId) {
      stageScreenshareGraceStateByConversation.delete(convId);
    }
    clearScreenshareMediaContainersForParticipant({
      conversationId: convId,
      participantId: meId,
      oldTrackSid,
      newTrackSid: "",
      renderReason: "screenshare_replace_pre_start_media_container_clear",
      clearLegacyPanel: true,
    });
    clearStageScreenshareForceRemovedOwner(convId, meId);
    await layer.startShare?.({
      triggerReason: `${triggerReason}_restart_start`,
    });
    refreshCallUI();
    await new Promise((resolve) => setTimeout(resolve, 0));

    const activeShareAfterStart = getServerVoiceActiveScreenshare(convId);
    const activeTrackAfterStart = pickLiveVideoTrackFromStream(activeShareAfterStart?.stream || null, { allowMuted: true })
      || getAnyVideoTrackFromStream(activeShareAfterStart?.stream || null)
      || null;
    const newTrackSid = normId(
      activeTrackAfterStart?.sid
      || activeTrackAfterStart?.id
      || activeShareAfterStart?.trackSid
      || ""
    );
    setStageScreenshareReplacementState(convId, meId, {
      oldTrackSid,
      newTrackSid,
      renderReason: String(triggerReason || "").trim() || "screenshare_restart",
      phase: "replace_new_track_detected",
    });
    const postStartPrune = pruneScreenshareStageTilesForParticipant({
      conversationId: convId,
      participantId: meId,
      removeAll: false,
      preferredTrackIdentity: newTrackSid,
      reason: "screenshare_restart_post_start_dedupe",
      triggerReason: `${triggerReason}_restart_post_start`,
      callerFunction: "restartServerVoiceScreenshareWithStageCleanup",
      oldTrackSid,
      newTrackSid,
      logDomCount: true,
    });
    const invariantResult = enforceScreenshareStageTileDomInvariant(convId, {
      reason: "screenshare_restart_post_start_invariant",
      triggerReason: `${triggerReason}_restart_post_start`,
      callerFunction: "restartServerVoiceScreenshareWithStageCleanup",
      oldTrackSid,
      newTrackSid,
    });
    refreshCallUI();

    if (shouldRestoreFocus) {
      const transitionSerial = beginStageFocusTransition({
        tileId: newTileId,
        tileType: "screenshare",
        participantId: meId,
        nextLayoutMode: "focus",
        triggerReason: `${triggerReason}_restore_focus`,
        callerFunction: "restartServerVoiceScreenshareWithStageCleanup",
      });
      setStageFocus(`member:${meId}`, {
        tileId: newTileId,
        tileType: "screenshare",
        participantId: meId,
        triggerReason: `${triggerReason}_restore_focus`,
        callerFunction: "restartServerVoiceScreenshareWithStageCleanup",
      });
      const activeShare = getServerVoiceActiveScreenshare(convId);
      const activeTrack = pickLiveVideoTrackFromStream(activeShare?.stream || null, { allowMuted: true })
        || getAnyVideoTrackFromStream(activeShare?.stream || null)
        || null;
      stageFocusMemberTrackId = normId(activeTrack?.id || activeTrack?.sid || activeShare?.trackSid || "");
      stageFocusMemberMediaType = "share";
      stageLayoutMode = "focus";
      refreshCallUI();
      completeStageFocusTransition({
        transitionSerial,
        tileId: newTileId,
        tileType: "screenshare",
        participantId: meId,
        triggerReason: `${triggerReason}_restore_focus`,
        callerFunction: "restartServerVoiceScreenshareWithStageCleanup",
      });
    }

    const activeShareAfter = getServerVoiceActiveScreenshare(convId);
    const activeShareOwnerAfter = normId(activeShareAfter?.ownerUserId || "");
    const afterStart = collectStageTilesSnapshotForScreenshareRestart();
    logScreenshareRestartEvent("screenshare.new_tile_rendered", {
      conversationId: convId,
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerAfter || meId,
      tileCountBefore: before.tileCount,
      tileCountAfter: afterStart.tileCount,
      newTilePresent: !!afterStart.knownTileIds.includes(newTileId),
      knownTileIdsAfter: afterStart.knownTileIds,
      visibleTileIdsAfter: afterStart.visibleTileIds,
      domTileCountAfter: afterStart.domTileCount,
      oldTrackSid: oldTrackSid || null,
      newTrackSid: newTrackSid || null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_new_tile_rendered",
      triggerReason,
      callerFunction,
    });
    logScreenshareRestartEvent("screenshare.replace_new_track_rendered", {
      conversationId: convId,
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerAfter || meId,
      tileCountBefore: Number(postStartPrune?.candidateCount || 0),
      tileCountAfter: Number(postStartPrune?.remainingCount || afterStart.tileCount),
      oldTrackSid: oldTrackSid || null,
      newTrackSid: newTrackSid || null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_new_track_rendered",
      triggerReason,
      callerFunction,
      duplicateTilesPruned: Number(invariantResult?.prunedCount || 0),
    });
    logServerVoiceStageTilesEvent("stage.tiles_snapshot_after_restart", convId, {
      participantId: meId,
      oldTileId,
      newTileId,
      activeShareOwnerId: activeShareOwnerAfter || meId,
      tileCountBefore: before.tileCount,
      tileCountAfter: afterStart.tileCount,
      visibleTileIds: afterStart.visibleTileIds,
      knownTileIds: afterStart.knownTileIds,
      domTileCountBefore: before.domTileCount,
      domTileCountAfter: afterStart.domTileCount,
      oldTrackSid: oldTrackSid || null,
      newTrackSid: newTrackSid || null,
      focusedTileId: String(stageFocusedTileId || "").trim() || null,
      renderReason: "replace_final_snapshot",
      triggerReason: String(triggerReason || "").trim() || "screenshare_restart",
      callerFunction: String(callerFunction || "").trim() || "restartServerVoiceScreenshareWithStageCleanup",
    });
    return !!layer.isLocalShareActive?.();
  } finally {
    clearStageScreenshareReplacingOwner(convId, meId);
  }
}

function resolveScreenshareTrackForInitialAttach({
  conversationId = "",
  participantId = "",
  expectedTrackIdentity = "",
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || "");
  if (!convId || !uid) {
    return {
      track: null,
      activeShareOwnerId: "",
      trackIdentity: normId(expectedTrackIdentity || ""),
    };
  }
  let track = null;
  let activeShareOwnerId = "";
  if (shouldUseServerVoiceLiveKitTransport(convId)) {
    const activeShare = getServerVoiceActiveScreenshare(convId);
    activeShareOwnerId = normId(activeShare?.ownerUserId || "");
    if (activeShareOwnerId && activeShareOwnerId === uid) {
      track = pickLiveVideoTrackFromStream(activeShare?.stream || null, { allowMuted: true })
        || getAnyVideoTrackFromStream(activeShare?.stream || null)
        || null;
    }
  } else {
    const preferredRemoteShareState = getPreferredRemoteShareState(convId);
    const meId = normId(state.user?.id || "");
    const localShareOwnerId = isScreenSharing ? meId : "";
    activeShareOwnerId = normId(preferredRemoteShareState?.userId || localShareOwnerId || "");
    if (activeShareOwnerId && activeShareOwnerId === uid) {
      if (uid === meId) {
        track = isLiveVideoTrack(getLiveScreenTrack(), { allowMuted: true }) ? getLiveScreenTrack() : null;
      } else {
        track = isLiveVideoTrack(remoteVideoTrackRef, { allowMuted: true }) ? remoteVideoTrackRef : null;
      }
    }
  }
  const trackIdentity = normId(
    track?.sid
    || track?.id
    || track?.mediaStreamTrack?.id
    || expectedTrackIdentity
    || ""
  );
  return {
    track,
    activeShareOwnerId,
    trackIdentity,
  };
}

function findStageScreenshareTileElForInitialAttach(tileId = "", participantId = "") {
  const resolvedTileId = String(tileId || "").trim();
  const uid = normId(participantId || "");
  const byTileId = resolvedTileId ? findStageTileElById(resolvedTileId) : null;
  if (byTileId) return byTileId;
  const stage = document.getElementById("callStage");
  if (!stage || !uid) return null;
  const tiles = stage.querySelectorAll(".participantTile, .stageGridTile");
  for (const tile of tiles) {
    const identity = getStageTileIdentityFromEl(tile);
    if (identity.participantId !== uid) continue;
    if (normalizeStageTileType(identity.tileType || "") !== "screenshare") continue;
    return tile;
  }
  return null;
}

async function attemptStageScreenshareInitialAttach({
  conversationId = "",
  participantId = "",
  tileId = "",
  expectedTrackIdentity = "",
  renderReason = "initial_attach",
  attemptIndex = 0,
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || "");
  const resolvedTileId = String(tileId || buildStageParticipantTileId(uid, "screenshare") || "").trim();
  const currentConvId = normId(callConversationId || activeDmId || "");
  if (!convId || !uid || !resolvedTileId || (currentConvId && convId !== currentConvId)) {
    return {
      ok: false,
      reason: "conversation_inactive",
      tileId: resolvedTileId,
      participantId: uid,
      trackIdentity: normId(expectedTrackIdentity || ""),
      activeShareOwnerId: "",
      hasExistingVideoElement: false,
      blackDetected: false,
    };
  }

  refreshCallUI();
  const tileEl = findStageScreenshareTileElForInitialAttach(resolvedTileId, uid);
  const preAttachVideoEl = tileEl?.querySelector?.(".stageGridVideo") || null;
  const hasExistingVideoElement = !!(
    preAttachVideoEl?.srcObject
    && !!getAnyVideoTrackFromStream(preAttachVideoEl.srcObject || null)
  );
  const trackInfo = resolveScreenshareTrackForInitialAttach({
    conversationId: convId,
    participantId: uid,
    expectedTrackIdentity,
  });
  const activeShareOwnerId = normId(trackInfo.activeShareOwnerId || "");
  const resolvedTrackIdentity = normId(trackInfo.trackIdentity || expectedTrackIdentity || "");
  const track = trackInfo.track || null;

  if (!tileEl) {
    return {
      ok: false,
      reason: "tile_not_found",
      tileId: resolvedTileId,
      participantId: uid,
      trackIdentity: resolvedTrackIdentity,
      activeShareOwnerId,
      hasExistingVideoElement,
      blackDetected: true,
    };
  }
  if (!track) {
    return {
      ok: false,
      reason: "track_missing",
      tileId: resolvedTileId,
      participantId: uid,
      trackIdentity: resolvedTrackIdentity,
      activeShareOwnerId,
      hasExistingVideoElement,
      blackDetected: true,
    };
  }

  tileEl.setAttribute(
    "data-call-render-reason",
    String(renderReason || "initial_attach").trim() || "initial_attach"
  );
  syncGroupCallMemberTileVideo(tileEl, track);

  const videoEl = tileEl.querySelector(".stageGridVideo");
  const attachedTrack = getAnyVideoTrackFromStream(videoEl?.srcObject || null);
  const attachedTrackIdentity = normId(
    attachedTrack?.sid
    || attachedTrack?.id
    || ""
  );
  const tileTrackIdentity = normId(
    tileEl.getAttribute("data-call-video-track-id")
    || tileEl.getAttribute("data-call-track-identity")
    || ""
  );
  const expectedIdentity = normId(resolvedTrackIdentity || "");
  const hasAttachedStream = !!(
    videoEl?.srcObject
    && !!getAnyVideoTrackFromStream(videoEl.srcObject || null)
  );
  const trackIdentityMatches = !!(
    hasAttachedStream
    && (
      !expectedIdentity
      || attachedTrackIdentity === expectedIdentity
      || tileTrackIdentity === expectedIdentity
    )
  );
  if (!hasAttachedStream || !trackIdentityMatches) {
    return {
      ok: false,
      reason: hasAttachedStream ? "attached_track_mismatch" : "video_not_attached",
      tileId: resolvedTileId,
      participantId: uid,
      trackIdentity: expectedIdentity || attachedTrackIdentity || tileTrackIdentity || resolvedTrackIdentity,
      activeShareOwnerId,
      hasExistingVideoElement,
      blackDetected: true,
    };
  }

  let playError = null;
  try {
    const playPromise = videoEl?.play?.();
    if (playPromise && typeof playPromise.then === "function") {
      await playPromise;
    }
  } catch (error) {
    playError = error;
  }
  if (playError) {
    return {
      ok: false,
      reason: "autoplay_blocked",
      tileId: resolvedTileId,
      participantId: uid,
      trackIdentity: expectedIdentity || attachedTrackIdentity || tileTrackIdentity || resolvedTrackIdentity,
      activeShareOwnerId,
      hasExistingVideoElement,
      blackDetected: true,
      errorMessage: String(playError?.message || playError || "autoplay_blocked"),
    };
  }

  const hasFrame = hasRenderableVideoFrame(videoEl);
  if (!hasFrame && attemptIndex === 0) {
    return {
      ok: false,
      reason: "frame_not_renderable_yet",
      tileId: resolvedTileId,
      participantId: uid,
      trackIdentity: expectedIdentity || attachedTrackIdentity || tileTrackIdentity || resolvedTrackIdentity,
      activeShareOwnerId,
      hasExistingVideoElement,
      blackDetected: true,
    };
  }

  return {
    ok: true,
    reason: "attached",
    tileId: resolvedTileId,
    participantId: uid,
    trackIdentity: expectedIdentity || attachedTrackIdentity || tileTrackIdentity || resolvedTrackIdentity,
    activeShareOwnerId,
    hasExistingVideoElement,
    blackDetected: false,
  };
}

function scheduleStageScreenshareInitialAttach({
  conversationId = "",
  participantId = "",
  trackIdentity = "",
  triggerReason = "screenshare_track_received",
  callerFunction = "scheduleStageScreenshareInitialAttach",
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const uid = normId(participantId || "");
  if (!convId || !uid) return;
  const tileId = buildStageParticipantTileId(uid, "screenshare");
  if (!tileId) return;
  clearStageScreenshareInitialAttachRetryState(tileId);

  const retryState = {
    tileId,
    conversationId: convId,
    participantId: uid,
    expectedTrackIdentity: normId(trackIdentity || ""),
    triggerReason: String(triggerReason || "").trim() || "screenshare_track_received",
    callerFunction: String(callerFunction || "").trim() || "scheduleStageScreenshareInitialAttach",
    timers: [],
    blackLogged: false,
  };
  stageScreenshareInitialAttachRetryStateByTileId.set(tileId, retryState);
  logScreenshareTileRenderEvent("screenshare.initial_attach_requested", {
    tileId,
    participantId: uid,
    trackIdentity: retryState.expectedTrackIdentity || "",
    activeShareOwnerId: uid,
    renderReason: retryState.triggerReason,
    hasExistingVideoElement: false,
    fallbackReason: "",
    callerFunction: retryState.callerFunction,
  });

  const retryDelays = [0, ...STAGE_SCREENSHARE_INITIAL_ATTACH_RETRY_DELAYS_MS];
  retryDelays.forEach((retryDelayMs, attemptIndex) => {
    const timerId = setTimeout(() => {
      void (async () => {
        const activeRetryState = stageScreenshareInitialAttachRetryStateByTileId.get(tileId);
        if (activeRetryState !== retryState) return;
        if (attemptIndex > 0) {
          logScreenshareTileRenderEvent("screenshare.attach_retry_after_render", {
            tileId,
            participantId: uid,
            trackIdentity: retryState.expectedTrackIdentity || "",
            activeShareOwnerId: uid,
            renderReason: retryState.triggerReason,
            hasExistingVideoElement: false,
            fallbackReason: "retry_after_render",
            callerFunction: retryState.callerFunction,
            retryDelayMs,
            attemptIndex: attemptIndex + 1,
          });
        }
        const result = await attemptStageScreenshareInitialAttach({
          conversationId: convId,
          participantId: uid,
          tileId,
          expectedTrackIdentity: retryState.expectedTrackIdentity,
          renderReason: `${retryState.triggerReason}_initial_attach_attempt_${attemptIndex + 1}`,
          attemptIndex,
        });
        if (result.ok) {
          logScreenshareTileRenderEvent("screenshare.initial_attach_completed", {
            tileId: result.tileId || tileId,
            participantId: result.participantId || uid,
            trackIdentity: result.trackIdentity || retryState.expectedTrackIdentity,
            activeShareOwnerId: result.activeShareOwnerId || uid,
            renderReason: retryState.triggerReason,
            hasExistingVideoElement: !!result.hasExistingVideoElement,
            fallbackReason: "",
            callerFunction: retryState.callerFunction,
            attemptIndex: attemptIndex + 1,
          });
          clearStageScreenshareInitialAttachRetryState(tileId);
          return;
        }
        if (result.blackDetected && !retryState.blackLogged) {
          retryState.blackLogged = true;
          logScreenshareTileRenderEvent("screenshare.initial_black_tile_detected", {
            tileId: result.tileId || tileId,
            participantId: result.participantId || uid,
            trackIdentity: result.trackIdentity || retryState.expectedTrackIdentity,
            activeShareOwnerId: result.activeShareOwnerId || uid,
            renderReason: retryState.triggerReason,
            hasExistingVideoElement: !!result.hasExistingVideoElement,
            fallbackReason: result.reason || "black_tile_detected",
            callerFunction: retryState.callerFunction,
            attemptIndex: attemptIndex + 1,
          });
        }
        if (result.reason === "autoplay_blocked") {
          logScreenshareTileRenderEvent("screenshare.initial_attach_failed", {
            tileId: result.tileId || tileId,
            participantId: result.participantId || uid,
            trackIdentity: result.trackIdentity || retryState.expectedTrackIdentity,
            activeShareOwnerId: result.activeShareOwnerId || uid,
            renderReason: retryState.triggerReason,
            hasExistingVideoElement: !!result.hasExistingVideoElement,
            fallbackReason: "autoplay_blocked",
            callerFunction: retryState.callerFunction,
            attemptIndex: attemptIndex + 1,
            errorMessage: result.errorMessage || null,
          });
        }
        const finalAttempt = attemptIndex >= (retryDelays.length - 1);
        if (finalAttempt) {
          logScreenshareTileRenderEvent("screenshare.initial_attach_failed", {
            tileId: result.tileId || tileId,
            participantId: result.participantId || uid,
            trackIdentity: result.trackIdentity || retryState.expectedTrackIdentity,
            activeShareOwnerId: result.activeShareOwnerId || uid,
            renderReason: retryState.triggerReason,
            hasExistingVideoElement: !!result.hasExistingVideoElement,
            fallbackReason: result.reason || "initial_attach_failed",
            callerFunction: retryState.callerFunction,
            attemptIndex: attemptIndex + 1,
            errorMessage: result.errorMessage || null,
          });
          clearStageScreenshareInitialAttachRetryState(tileId);
        }
      })();
    }, Math.max(0, Number(retryDelayMs) || 0));
    retryState.timers.push(timerId);
  });
}

function assertStageFocusMatchesClickedTile({
  tileId = "",
  tileType = "",
  participantId = "",
  triggerReason = "focus_assert",
  callerFunction = "assertStageFocusMatchesClickedTile",
} = {}) {
  const clickedTileId = String(tileId || "").trim();
  if (!clickedTileId) return true;
  const resultingFocusedTileId = String(stageFocusedTileId || "").trim();
  if (clickedTileId === resultingFocusedTileId) return true;
  logStageTileEvent("stage.focus_mismatch_detected", {
    tileId: clickedTileId,
    tileType,
    participantId,
    triggerReason: String(triggerReason || "").trim() || "focus_assert",
    callerFunction: String(callerFunction || "").trim() || "assertStageFocusMatchesClickedTile",
    resultingFocusedTileId: resultingFocusedTileId || null,
  });
  return false;
}

function toggleFocusParticipant(target, slot = "primary", opts = {}) {
  const next = target === "self" ? "self" : "remote";
  const nextSlot = slot === "aux" ? "aux" : "primary";
  const participantId = normId(opts?.participantId || resolveStageParticipantIdForFocusTarget(next, nextSlot));
  const tileType = normalizeStageTileType(opts?.tileType || resolveStageTileTypeForFocusTarget(next, nextSlot));
  const tileId = String(opts?.tileId || buildStageParticipantTileId(participantId, tileType)).trim();
  const triggerReason = String(opts?.triggerReason || "").trim() || "toggle_focus_participant";
  const callerFunction = String(opts?.callerFunction || "").trim() || "toggleFocusParticipant";
  const focusStateChanged = stageFocus !== next || stageFocusedTileId !== tileId;
  logStageTileEvent("stage.focus_target", {
    tileId,
    tileType,
    participantId,
    triggerReason,
    callerFunction,
  });
  const sameTileAlreadyFocused = !!(
    stageLayoutMode === "focus"
    && stageFocus === next
    && stageFocusedTileId
    && tileId
    && stageFocusedTileId === tileId
  );
  if (sameTileAlreadyFocused) {
    logStageTileEvent("stage.focus_click_ignored_same_tile", {
      tileId,
      tileType,
      participantId,
      triggerReason,
      callerFunction,
      layoutMode: stageLayoutMode,
    });
    return false;
  }
  if (next === "self") stageFocusSelfSlot = nextSlot;
  else stageFocusRemoteSlot = nextSlot;
  stageFocus = next;
  if (tileId) stageFocusedTileId = tileId;
  stageLayoutMode = "focus";
  if (focusStateChanged || stageLayoutMode === "focus") {
    logStageTileEvent("stage.focus_changed", {
      tileId,
      tileType,
      participantId,
      triggerReason: "toggle_focus_participant_on",
      callerFunction,
      layoutMode: stageLayoutMode,
    });
  }
  return true;
}

function getShareVideoConstraints(sourceKind = "") {
  const requested = getShareQualityValue();
  const q = getEffectiveShareQualityValue(requested, sourceKind);
  const profile = getShareProfileValue();
  const autoPerformance = shouldUseSharePerformanceMode(sourceKind, { requestedQuality: requested });
  const targetFps = q === "1080p30" ? 30 : (autoPerformance ? 30 : 60);
  if (q === "1080p30") {
    return { width: { ideal: 1920, max: 1920 }, height: { ideal: 1080, max: 1080 }, frameRate: { ideal: 30, max: 30 } };
  }
  if (q === "1080p60") {
    return { width: { ideal: 1920, max: 1920 }, height: { ideal: 1080, max: 1080 }, frameRate: { ideal: targetFps, max: targetFps } };
  }
  if (q === "2160p60") {
    return { width: { ideal: 3840, max: 3840 }, height: { ideal: 2160, max: 2160 }, frameRate: { ideal: targetFps, max: targetFps } };
  }
  // Source: deixa o browser manter resoluÃ§Ã£o nativa da janela/ecrÃ£.
  if (profile === "clarity") return { frameRate: { ideal: 60, max: 60 } };
  return { frameRate: { ideal: targetFps, max: targetFps } };
}

function getShareAudioConstraints() {
  return {
    channelCount: { ideal: 2 },
    sampleRate: { ideal: 48000 },
    sampleSize: { ideal: 16 },
    echoCancellation: false,
    noiseSuppression: false,
    autoGainControl: false,
  };
}

function getShareTargetDimensions(value = getShareQualityValue(), sourceKind = "") {
  const q = getEffectiveShareQualityValue(value, sourceKind);
  if (q === "1080p30" || q === "1080p60") return { width: 1920, height: 1080 };
  if (q === "2160p60") return { width: 3840, height: 2160 };
  return null; // source
}

function getShareScaleResolutionDownBy(track = null, qualityValue = getShareQualityValue(), sourceKind = "") {
  const target = getShareTargetDimensions(qualityValue, sourceKind);
  if (!target) return 1;
  const settings = track?.getSettings?.() || {};
  const srcW = Number(settings?.width) || 0;
  const srcH = Number(settings?.height) || 0;
  if (!(srcW > 0 && srcH > 0)) return 1;
  const rawScale = Math.max(srcW / target.width, srcH / target.height, 1);
  if (!Number.isFinite(rawScale) || rawScale <= 1) return 1;
  return Math.round(rawScale * 100) / 100;
}

function getDesktopBridge() {
  try {
    const bridge = window?.altaraDesktop;
    if (!bridge || bridge.isDesktopApp !== true) return null;
    return bridge;
  } catch (_) {
    return null;
  }
}

function decodeBase64UrlJsonSegment(segmentInput = "") {
  const segment = String(segmentInput || "").trim();
  if (!segment) return null;
  const normalized = segment.replace(/-/g, "+").replace(/_/g, "/");
  const padding = normalized.length % 4;
  const padded = normalized + (padding ? "=".repeat(4 - padding) : "");
  try {
    return JSON.parse(atob(padded));
  } catch (_) {
    return null;
  }
}

function getSupabaseAccessTokenDiagnostics(tokenInput = "") {
  const token = String(tokenInput || "").trim();
  if (!token || !token.includes(".")) {
    return {
      jwtAlgorithm: null,
      jwtType: null,
      jwtIssuer: null,
      jwtRole: null,
      jwtSubject: null,
      jwtExpiresAt: null,
    };
  }
  const [headerSegment = "", payloadSegment = ""] = token.split(".");
  const header = decodeBase64UrlJsonSegment(headerSegment);
  const payload = decodeBase64UrlJsonSegment(payloadSegment);
  const expiresAtSeconds = Number(payload?.exp || 0);
  return {
    jwtAlgorithm: String(header?.alg || "").trim() || null,
    jwtType: String(header?.typ || "").trim() || null,
    jwtIssuer: String(payload?.iss || "").trim() || null,
    jwtRole: String(payload?.role || "").trim() || null,
    jwtSubject: String(payload?.sub || "").trim() || null,
    jwtExpiresAt: expiresAtSeconds > 0
      ? new Date(expiresAtSeconds * 1000).toISOString()
      : null,
  };
}

function getSupabaseAuthRuntimeContextDetails() {
  const bridge = getDesktopBridge();
  const protocol = String(window.location?.protocol || "").trim();
  const host = String(window.location?.host || "").trim();
  const hostname = String(window.location?.hostname || "").trim().toLowerCase();
  const origin = String(window.location?.origin || "").trim();
  const href = String(window.location?.href || "").trim();
  return {
    isDesktopApp: !!bridge,
    isLocalHost: hostname === "127.0.0.1" || hostname === "localhost",
    locationProtocol: protocol || null,
    locationHost: host || null,
    locationOrigin: origin || null,
    locationHref: href || null,
  };
}

async function restoreSupabaseSessionFromStorage() {
  const storedSession = readAuthSessionFromStorage();
  if (!storedSession?.accessToken || !storedSession?.refreshToken) {
    return {
      restored: false,
      session: null,
      storedSession,
      error: null,
    };
  }
  try {
    const { data, error } = await supabase.auth.setSession({
      access_token: storedSession.accessToken,
      refresh_token: storedSession.refreshToken,
    });
    const session = data?.session || null;
    if (!error && session?.access_token) {
      setAuthAccessToken(session.access_token || "");
      return {
        restored: true,
        session,
        storedSession,
        error: null,
      };
    }
    return {
      restored: false,
      session,
      storedSession,
      error: error || new Error("supabase_set_session_failed"),
    };
  } catch (error) {
    return {
      restored: false,
      session: null,
      storedSession,
      error,
    };
  }
}

function buildSupabaseFunctionAuthLogDetails(authState = {}, extra = null) {
  const details = {
    edgeFunctionName: String(authState.edgeFunctionName || "").trim() || null,
    functionPath: String(authState.functionPath || "").trim() || null,
    hasSession: !!authState.hasSession,
    hasAccessToken: !!authState.hasAccessToken,
    currentUserId: normId(authState.currentUserId || "") || null,
    "auth client source/path": String(
      authState.authClientSourcePath
      || SUPABASE_AUTH_CLIENT_SOURCE_PATH
      || ""
    ).trim() || null,
    stateUserId: normId(authState.stateUserId || "") || null,
    storedUserId: normId(authState.storedUserId || "") || null,
    hasStoredAccessToken: !!authState.hasStoredAccessToken,
    hasStoredRefreshToken: !!authState.hasStoredRefreshToken,
    storedSessionKey: String(authState.storedSessionKey || "").trim() || null,
    refreshAttempted: !!authState.refreshAttempted,
    refreshedSession: !!authState.refreshedSession,
    restoreAttempted: !!authState.restoreAttempted,
    restoredFromStorage: !!authState.restoredFromStorage,
    sessionMissingWithStoredToken: !!authState.sessionMissingWithStoredToken,
    contextHint: String(authState.contextHint || "").trim() || null,
    isDesktopApp: !!authState.isDesktopApp,
    isLocalHost: !!authState.isLocalHost,
    locationProtocol: String(authState.locationProtocol || "").trim() || null,
    locationHost: String(authState.locationHost || "").trim() || null,
    locationOrigin: String(authState.locationOrigin || "").trim() || null,
    locationHref: String(authState.locationHref || "").trim() || null,
    jwtAlgorithm: String(authState.jwtAlgorithm || "").trim() || null,
    jwtType: String(authState.jwtType || "").trim() || null,
    jwtIssuer: String(authState.jwtIssuer || "").trim() || null,
    jwtRole: String(authState.jwtRole || "").trim() || null,
    jwtSubject: String(authState.jwtSubject || "").trim() || null,
    jwtExpiresAt: String(authState.jwtExpiresAt || "").trim() || null,
  };
  if (authState.sessionError) details.sessionError = describeServerVoiceError(authState.sessionError).errorMessage;
  if (authState.refreshError) details.refreshError = describeServerVoiceError(authState.refreshError).errorMessage;
  if (authState.restoreError) details.restoreError = describeServerVoiceError(authState.restoreError).errorMessage;
  if (extra && typeof extra === "object" && !Array.isArray(extra)) {
    Object.assign(details, extra);
  }
  return details;
}

function logSupabaseFunctionAuthState(authState = {}, {
  prefix = "[auth]",
  event = "auth_state",
  channel = "auth",
  level = "info",
  extra = null,
} = {}) {
  writeStructuredServerVoiceConsoleLog(
    prefix,
    event,
    buildSupabaseFunctionAuthLogDetails(authState, extra),
    { level, channel },
  );
}

function createSupabaseFunctionAuthMissingError(edgeFunctionName, authState = null) {
  const resolvedFunctionName = String(edgeFunctionName || "").trim() || "edge-function";
  const error = new Error(`Supabase auth session missing before ${resolvedFunctionName} invoke.`);
  error.code = "SUPABASE_AUTH_REQUIRED";
  error.edgeFunctionName = resolvedFunctionName;
  error.functionPath = String(authState?.functionPath || "").trim() || null;
  return error;
}

async function ensureSupabaseFunctionInvokeAuthReady({
  edgeFunctionName = "",
  functionPath = "",
  requireUser = true,
  logPrefix = "[auth]",
  logEvent = "auth_state",
  logChannel = "auth",
  failEvent = "auth_missing",
  failLevel = "warn",
  allowStorageRestore = true,
} = {}) {
  const resolvedFunctionName = String(edgeFunctionName || "").trim() || "edge-function";
  const resolvedFunctionPath = String(
    functionPath
    || (resolvedFunctionName ? `/functions/v1/${resolvedFunctionName}` : "")
    || ""
  ).trim() || null;
  const runtimeDetails = getSupabaseAuthRuntimeContextDetails();
  const storedSession = readAuthSessionFromStorage();
  const stateUserId = normId(state.user?.id || "") || "";

  let session = null;
  let accessToken = "";
  let currentUserId = "";
  let sessionError = null;
  let refreshError = null;
  let restoreError = null;
  let refreshAttempted = false;
  let refreshedSession = false;
  let restoreAttempted = false;
  let restoredFromStorage = false;

  try {
    const sessionResult = await supabase.auth.getSession();
    sessionError = sessionResult?.error || null;
    session = sessionResult?.data?.session || null;
  } catch (error) {
    sessionError = error;
  }

  accessToken = String(session?.access_token || "").trim();
  currentUserId = normId(session?.user?.id || "") || "";

  if (!session || !accessToken || (requireUser && !currentUserId)) {
    refreshAttempted = true;
    try {
      const refreshResult = await supabase.auth.refreshSession();
      refreshError = refreshResult?.error || null;
      if (!refreshResult?.error && refreshResult?.data?.session) {
        session = refreshResult.data.session;
        refreshedSession = true;
      }
    } catch (error) {
      refreshError = error;
    }
    accessToken = String(session?.access_token || "").trim();
    currentUserId = normId(session?.user?.id || "") || "";
  }

  const sessionMissingWithStoredToken = !!(
    (!session || !accessToken || (requireUser && !currentUserId))
    && storedSession?.accessToken
  );

  if (
    (!session || !accessToken || (requireUser && !currentUserId))
    && allowStorageRestore
    && storedSession?.accessToken
    && storedSession?.refreshToken
  ) {
    restoreAttempted = true;
    const restoreResult = await restoreSupabaseSessionFromStorage();
    restoreError = restoreResult?.error || null;
    if (restoreResult?.restored && restoreResult?.session) {
      session = restoreResult.session;
      restoredFromStorage = true;
    }
    accessToken = String(session?.access_token || "").trim();
    currentUserId = normId(session?.user?.id || "") || "";
  }

  setAuthAccessToken(accessToken || "");

  const jwtDiagnostics = getSupabaseAccessTokenDiagnostics(accessToken || storedSession?.accessToken || "");
  const contextHint = sessionMissingWithStoredToken
    ? "stored_session_present_but_client_session_missing"
    : (
      (!session || !accessToken)
      && (runtimeDetails.isDesktopApp || runtimeDetails.isLocalHost)
        ? "renderer_context_missing_session"
        : ""
    );
  const authState = {
    edgeFunctionName: resolvedFunctionName,
    functionPath: resolvedFunctionPath,
    hasSession: !!session,
    hasAccessToken: !!accessToken,
    currentUserId: currentUserId || null,
    authClientSourcePath: SUPABASE_AUTH_CLIENT_SOURCE_PATH,
    stateUserId: stateUserId || null,
    storedUserId: normId(storedSession?.userId || "") || null,
    hasStoredAccessToken: !!storedSession?.accessToken,
    hasStoredRefreshToken: !!storedSession?.refreshToken,
    storedSessionKey: storedSession?.storageKey || null,
    refreshAttempted,
    refreshedSession,
    restoreAttempted,
    restoredFromStorage,
    sessionMissingWithStoredToken,
    contextHint: contextHint || null,
    sessionError,
    refreshError,
    restoreError,
    ...runtimeDetails,
    ...jwtDiagnostics,
  };

  logSupabaseFunctionAuthState(authState, {
    prefix: logPrefix,
    event: logEvent,
    channel: logChannel,
    level: "info",
  });

  if (authState.hasSession && authState.hasAccessToken && (!requireUser || authState.currentUserId)) {
    return {
      ok: true,
      authState,
    };
  }

  const error = createSupabaseFunctionAuthMissingError(resolvedFunctionName, authState);
  logSupabaseFunctionAuthState(authState, {
    prefix: logPrefix,
    event: failEvent,
    channel: logChannel,
    level: failLevel,
    extra: {
      fatal: false,
      reasonCode: "supabase_auth_missing",
      errorMessage: error.message,
    },
  });
  return {
    ok: false,
    authState,
    error,
  };
}

function dispatchDesktopThumbarCallAction(actionInput = "") {
  const action = String(actionInput || "").trim().toLowerCase();
  if (!action) return;
  if (action === "toggle_mic") {
    if (!inCall) return;
    toggleMic();
    return;
  }
  if (action === "toggle_deafen") {
    if (!inCall) return;
    toggleDeafen();
    return;
  }
  if (action === "hangup") {
    if (!inCall) return;
    Promise.resolve(hangupCurrentCallByUser("?? Desligaste.")).catch(() => {});
  }
}

try {
  if (typeof window !== "undefined") {
    window.__altaraDesktopCallThumbarAction = (action) => {
      dispatchDesktopThumbarCallAction(action);
    };
  }
} catch (_) {}

function bindDesktopCallThumbarOnce() {
  if (desktopCallThumbarBound) return;
  desktopCallThumbarBound = true;
  const bridge = getDesktopBridge();
  if (!bridge || typeof bridge.onCallThumbarCommand !== "function") return;
  try {
    desktopCallThumbarUnsub = bridge.onCallThumbarCommand((payload) => {
      dispatchDesktopThumbarCallAction(payload?.action);
    });
  } catch (_) {
    desktopCallThumbarUnsub = null;
  }
}

function pushDesktopCallThumbarState(force = false) {
  const bridge = getDesktopBridge();
  if (!bridge || typeof bridge.setCallThumbarState !== "function") return;
  const payload = {
    inCall: !!inCall,
    micMuted: !!micMuted,
    deafened: !!deafened,
  };
  const signature = JSON.stringify(payload);
  if (!force && signature === desktopCallThumbarLastSignature) return;
  desktopCallThumbarLastSignature = signature;
  try {
    bridge.setCallThumbarState(payload);
  } catch (_) {}
}

function normalizeRtcConfigInput(rawInput) {
  const raw = rawInput && typeof rawInput === "object" ? rawInput : {};
  const out = {
    ...DEFAULT_RTC_CONFIG,
    iceServers: [],
  };
  const servers = Array.isArray(raw.iceServers) ? raw.iceServers : [];
  servers.forEach((entry) => {
    if (!entry || typeof entry !== "object") return;
    const urlsRaw = Array.isArray(entry.urls) ? entry.urls : [entry.urls];
    const urls = urlsRaw
      .map((url) => String(url || "").trim())
      .filter((url) => /^stuns?:/i.test(url) || /^turns?:/i.test(url));
    if (!urls.length) return;
    const next = { urls };
    const username = String(entry.username || "").trim();
    const credential = String(entry.credential || "").trim();
    if (username) next.username = username;
    if (credential) next.credential = credential;
    out.iceServers.push(next);
  });
  if (!out.iceServers.length) {
    out.iceServers = DEFAULT_RTC_CONFIG.iceServers.map((server) => ({
      ...server,
      urls: Array.isArray(server?.urls) ? server.urls.slice() : [server?.urls].filter(Boolean),
    }));
  }

  const policy = String(raw.iceTransportPolicy || "").trim().toLowerCase();
  out.iceTransportPolicy = policy === "relay" ? "relay" : "all";
  out.iceCandidatePoolSize = clampInt(raw.iceCandidatePoolSize, 0, 10, 0);
  return out;
}

async function initRtcConfigFromDesktop() {
  const bridge = getDesktopBridge();
  if (!bridge || typeof bridge.getRtcConfig !== "function") return;
  try {
    const remoteConfig = await awaitWithTimeout(
      bridge.getRtcConfig(),
      3500,
      "desktop rtc config"
    );
    const next = normalizeRtcConfigInput(remoteConfig);
    RTC_CONFIG = next;
    const hasTurn = next.iceServers.some((server) => {
      const urls = Array.isArray(server?.urls) ? server.urls : [server?.urls];
      return urls.some((url) => /^turns?:/i.test(String(url || "").trim()));
    });
    const transport = String(next.iceTransportPolicy || "all").toLowerCase();
    console.info(`[rtc] config loaded (${hasTurn ? "stun+turn" : "stun-only"}, transport=${transport})`);
    if (remoteConfig?.forceRelayRequested && !remoteConfig?.forceRelayApplied) {
      console.warn("[rtc] ALTARA_FORCE_RELAY requested but no TURN server is configured.");
    }
  } catch (err) {
    console.warn("[rtc] failed to load desktop RTC config, using default.", err);
  }
}

function getRtcConfigExpiryFromPayload(payload) {
  const expIso = String(payload?.expiresAt || payload?.expires_at || "").trim();
  if (expIso) {
    const fromIso = Date.parse(expIso);
    if (Number.isFinite(fromIso) && fromIso > 0) return fromIso;
  }
  const ttlSec = clampInt(payload?.ttlSeconds ?? payload?.ttl_seconds, 1, 86400, 3600);
  return Date.now() + (ttlSec * 1000);
}

function shouldDisableTurnFunctionAfterError(error) {
  const msg = String(error?.message || error || "").toLowerCase();
  if (!msg) return false;
  return (
    msg.includes("404")
    || msg.includes("not found")
    || msg.includes("function not found")
    || msg.includes("failed to send a request to the edge function")
    || msg.includes("invalid functions url")
  );
}

function normalizeRtcRegionToken(value) {
  const token = String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[_\s]+/g, "-")
    .replace(/[^a-z0-9-]/g, "");
  if (token === "auto" || token === "automatic") return "";
  if (!token) return "";
  const aliases = {
    na: "us",
    "north-america": "us",
    usa: "us",
    useast: "us-east",
    uswest: "us-west",
    europe: "eu",
    latam: "sa",
    "south-america": "sa",
    asia: "apac",
    australia: "oce",
    oceania: "oce",
  };
  return aliases[token] || token;
}

function inferRtcRegionFromTimezone(timeZoneInput) {
  const tz = String(timeZoneInput || "").trim();
  if (!tz) return "";
  if (/^America\/(Argentina|Asuncion|Bogota|Caracas|Cayenne|Fortaleza|Godthab|Guayaquil|La_Paz|Lima|Maceio|Manaus|Montevideo|Paramaribo|Recife|Rio_Branco|Santiago|Sao_Paulo)/i.test(tz)) {
    return "sa";
  }
  if (/^America\/(Adak|Anchorage|Boise|Cambridge_Bay|Chihuahua|Creston|Dawson|Denver|Edmonton|Fort_Nelson|Inuvik|Juneau|Los_Angeles|Mazatlan|Metlakatla|Phoenix|Sitka|Tijuana|Vancouver|Whitehorse|Winnipeg|Yellowknife)/i.test(tz)) {
    return "us-west";
  }
  if (/^America\//i.test(tz)) return "us-east";
  if (/^(Europe|Africa|Atlantic)\//i.test(tz)) return "eu";
  if (/^Asia\//i.test(tz)) return "apac";
  if (/^(Australia|Pacific)\//i.test(tz)) return "oce";
  return "";
}

function inferRtcRegionFromLocale(localeInput) {
  const locale = String(localeInput || "").trim();
  if (!locale) return "";
  const parts = locale.replace("_", "-").split("-");
  if (parts.length < 2) return "";
  const cc = String(parts[parts.length - 1] || "").trim().toUpperCase();
  if (!/^[A-Z]{2}$/.test(cc)) return "";

  if (["US", "CA", "MX"].includes(cc)) return "us";
  if (["AR", "BO", "BR", "CL", "CO", "EC", "GY", "PE", "PY", "SR", "UY", "VE"].includes(cc)) return "sa";
  if (["AU", "FJ", "NC", "NZ", "PG", "SB", "VU"].includes(cc)) return "oce";
  if (["BD", "BN", "CN", "HK", "ID", "IN", "JP", "KH", "KR", "LA", "LK", "MM", "MN", "MO", "MY", "NP", "PH", "PK", "SG", "TH", "TW", "VN"].includes(cc)) return "apac";
  if (["AD", "AL", "AT", "BA", "BE", "BG", "BY", "CH", "CY", "CZ", "DE", "DK", "EE", "ES", "FI", "FO", "FR", "GB", "GG", "GI", "GR", "HR", "HU", "IE", "IM", "IS", "IT", "JE", "LI", "LT", "LU", "LV", "MC", "MD", "ME", "MK", "MT", "NL", "NO", "PL", "PT", "RO", "RS", "SE", "SI", "SK", "SM", "UA", "VA", "XK"].includes(cc)) return "eu";
  return "";
}

function detectRtcPreferredRegionHint() {
  const now = Date.now();
  if (rtcPreferredRegionCached && (now - rtcPreferredRegionCachedAtMs) < RTC_PREFERRED_REGION_CACHE_MS) {
    return rtcPreferredRegionCached;
  }
  let next = "";
  try {
    const tz = Intl?.DateTimeFormat?.().resolvedOptions?.().timeZone || "";
    next = inferRtcRegionFromTimezone(tz);
  } catch (_) {}
  if (!next) {
    try {
      next = inferRtcRegionFromLocale(navigator?.language || "");
    } catch (_) {}
  }
  rtcPreferredRegionCached = normalizeRtcRegionToken(next);
  rtcPreferredRegionCachedAtMs = now;
  return rtcPreferredRegionCached;
}

async function refreshRtcTurnCredentials({ force = false } = {}) {
  if (!rtcTurnFunctionSupported) return false;
  if (!state.user?.id) return false;
  const now = Date.now();
  if (!force && rtcTurnCredentialsExpiresAtMs && (now + RTC_TURN_REFRESH_SKEW_MS) < rtcTurnCredentialsExpiresAtMs) {
    return true;
  }
  if (!force && (now - rtcTurnLastFetchAtMs) < RTC_TURN_FETCH_COOLDOWN_MS) return false;
  if (rtcTurnFetchInFlight) return rtcTurnFetchInFlight;

  rtcTurnFetchInFlight = (async () => {
    rtcTurnLastFetchAtMs = Date.now();
    let regionHint = "";
    let localeHint = "";
    let timezoneHint = "";
    const edgeFunctionName = "turn-credentials";
    const functionPath = `/functions/v1/${edgeFunctionName}`;
    try {
      regionHint = detectRtcPreferredRegionHint();
      localeHint = String(navigator?.language || "").trim();
      timezoneHint = String(Intl?.DateTimeFormat?.().resolvedOptions?.().timeZone || "").trim();
    } catch (_) {}
    try {
      const authReady = await ensureSupabaseFunctionInvokeAuthReady({
        edgeFunctionName,
        functionPath,
        requireUser: true,
        logPrefix: "[rtc auth]",
        logEvent: "turn_credentials.auth_state",
        logChannel: "rtc",
        failEvent: "turn_credentials.auth_missing",
      });
      if (!authReady.ok) return false;
      const { data, error } = await supabase.functions.invoke(edgeFunctionName, {
        body: {
          reason: "webrtc_call",
          preferred_region: regionHint || undefined,
          locale: localeHint || undefined,
          timezone: timezoneHint || undefined,
        },
      });
      if (error) {
        if (shouldDisableTurnFunctionAfterError(error)) rtcTurnFunctionSupported = false;
        throw error;
      }
      const next = normalizeRtcConfigInput(data || {});
      RTC_CONFIG = next;
      rtcTurnCredentialsExpiresAtMs = getRtcConfigExpiryFromPayload(data || {});
      const hasTurn = next.iceServers.some((server) => {
        const urls = Array.isArray(server?.urls) ? server.urls : [server?.urls];
        return urls.some((url) => /^turns?:/i.test(String(url || "").trim()));
      });
      const transport = String(next.iceTransportPolicy || "all").toLowerCase();
      console.info(`[rtc] ephemeral config loaded (${hasTurn ? "stun+turn" : "stun-only"}, transport=${transport})`);
      return true;
    } catch (err) {
      const invokeErrorDetails = await inspectServerVoiceFunctionInvokeError(err);
      writeStructuredServerVoiceConsoleLog("[rtc]", "turn_credentials.request_failed", {
        stage: "turn_credentials",
        edgeFunctionName,
        functionPath,
        fatal: false,
        preferredRegion: regionHint || null,
        locale: localeHint || null,
        timezone: timezoneHint || null,
        ...describeServerVoiceError(err),
        ...invokeErrorDetails,
      }, {
        level: "warn",
        channel: "rtc",
      });
      const activeConvId = normId(serverVoiceTransportConversationId || callConversationId || activeDmId || "");
      const activeServerVoiceConvId = activeConvId && isServerVoiceConversationById(activeConvId)
        ? activeConvId
        : "";
      logServerVoiceJoinFailureSummary(activeServerVoiceConvId || null, {
        kind: "rtc_config_failed",
        event: "turn_credentials.request_failed",
        conversationId: activeServerVoiceConvId || null,
        edgeFunctionName,
        functionPath,
        fatal: false,
        preferredRegion: regionHint || null,
        locale: localeHint || null,
        timezone: timezoneHint || null,
        ...describeServerVoiceError(err),
        ...invokeErrorDetails,
      }, {
        level: "warn",
        persist: !!activeServerVoiceConvId,
      });
      return false;
    } finally {
      rtcTurnFetchInFlight = null;
    }
  })();

  return rtcTurnFetchInFlight;
}

async function ensureRtcConfigFreshForCall() {
  const now = Date.now();
  if (rtcTurnCredentialsExpiresAtMs && (now + RTC_TURN_REFRESH_SKEW_MS) < rtcTurnCredentialsExpiresAtMs) {
    return true;
  }
  return refreshRtcTurnCredentials({ force: false });
}

