function setDesktopUpdatingOverlayMode(modeInput = "") {
  const { root } = getDesktopUpdatingOverlayEls();
  if (!root) return;
  const mode = String(modeInput || "").trim().toLowerCase();
  root.classList.toggle("is-boot", mode === "boot");
  root.classList.toggle("is-installing", mode === "installing");
}

function ensureDesktopUpdatingOverlayLogo() {
  const { logo } = getDesktopUpdatingOverlayEls();
  bindBrandImageFallback(logo, getBrandLogoCandidates(getPreferredBrandLogoVariant()));
}

function setDesktopUpdatingOverlayVisible(yes) {
  const { root } = getDesktopUpdatingOverlayEls();
  if (!root) return;
  const show = !!yes;
  root.classList.toggle("hidden", !show);
  root.setAttribute("aria-hidden", show ? "false" : "true");
}

function setDesktopBootOverlayVisible(yes) {
  desktopBootOverlayVisible = !!yes;
  renderDesktopUpdatingOverlay(desktopUpdateState || {});
}

function renderDesktopUpdatingOverlay(stateInput = null) {
  const { title, text } = getDesktopUpdatingOverlayEls();
  const bridge = getDesktopBridge();
  const canUse = canUseDesktopUpdateActions(bridge);
  const state = stateInput && typeof stateInput === "object" ? stateInput : (desktopUpdateState || {});
  const status = String(state?.status || "").trim().toLowerCase();
  const showBoot = !!bridge && desktopBootOverlayVisible;
  const showInstalling = canUse && status === "installing";
  const mode = showInstalling ? "installing" : (showBoot ? "boot" : "");
  const show = !!mode;

  ensureDesktopUpdatingOverlayLogo();
  setDesktopUpdatingOverlayMode(mode);
  if (title) {
    title.textContent = mode === "boot"
      ? t("desktop.boot.overlay.title", "Starting...")
      : t("desktop.update.overlay.title", "Altara is updating...");
  }
  if (text) {
    text.textContent = mode === "boot"
      ? t("desktop.boot.overlay.text", "Preparing your space.")
      : t("desktop.update.overlay.text", "We're installing the latest version. The app will reopen in a moment.");
  }
  setDesktopUpdatingOverlayVisible(show);
  if (show && desktopInstallWelcomeVisible) {
    setDesktopInstallWelcomeVisible(false, { markSeen: false });
  }
}

function getDesktopInstallWelcomeEls() {
  return {
    root: document.getElementById("desktopInstallWelcomeOverlay"),
    title: document.getElementById("desktopInstallWelcomeTitle"),
    lineOne: document.getElementById("desktopInstallWelcomeLineOne"),
    lineTwo: document.getElementById("desktopInstallWelcomeLineTwo"),
    btnContinue: document.getElementById("btnDesktopInstallWelcomeContinue"),
  };
}

function hasSeenDesktopInstallWelcome() {
  try {
    return localStorage.getItem(DESKTOP_INSTALL_WELCOME_STORAGE_KEY) === "1";
  } catch (_) {
    return false;
  }
}

function markDesktopInstallWelcomeSeen() {
  try {
    localStorage.setItem(DESKTOP_INSTALL_WELCOME_STORAGE_KEY, "1");
  } catch (_) {}
}

async function resolveDesktopInstallWelcomeEligibility() {
  if (desktopInstallWelcomeEligibility !== null) return !!desktopInstallWelcomeEligibility;
  const bridge = getDesktopBridge();
  if (!bridge || typeof bridge.getMeta !== "function") {
    desktopInstallWelcomeEligibility = false;
    return false;
  }
  if (hasSeenDesktopInstallWelcome()) {
    desktopInstallWelcomeEligibility = false;
    return false;
  }
  try {
    const meta = await bridge.getMeta();
    desktopInstallWelcomeEligibility = !!meta?.freshInstallLaunch;
  } catch (_) {
    desktopInstallWelcomeEligibility = false;
  }
  return !!desktopInstallWelcomeEligibility;
}

function renderDesktopInstallWelcomeTexts() {
  const { title, lineOne, lineTwo, btnContinue } = getDesktopInstallWelcomeEls();
  if (title) title.textContent = t("desktop.install_welcome.title", "Where friends stay close.");
  if (lineOne) lineOne.textContent = t("desktop.install_welcome.line1", "From late-night laughs to voice calls that feel real.");
  if (lineTwo) lineTwo.textContent = t("desktop.install_welcome.line2", "Keep your memories alive, one message at a time.");
  if (btnContinue) btnContinue.textContent = t("desktop.install_welcome.cta", "Enter Altara");
}

function setDesktopInstallWelcomeVisible(yes, { markSeen = true, markSeenOnShow = true } = {}) {
  const { root, btnContinue } = getDesktopInstallWelcomeEls();
  if (!root) return;
  const show = !!yes;
  desktopInstallWelcomeVisible = show;
  root.classList.toggle("hidden", !show);
  root.setAttribute("aria-hidden", show ? "false" : "true");
  document.body?.classList?.toggle("desktop-install-welcome-open", show);
  if (show) {
    if (markSeenOnShow) markDesktopInstallWelcomeSeen();
    desktopInstallWelcomeEligibility = false;
    renderDesktopInstallWelcomeTexts();
    requestAnimationFrame(() => {
      try { btnContinue?.focus?.({ preventScroll: true }); } catch (_) { btnContinue?.focus?.(); }
    });
    return;
  }
  if (markSeen) markDesktopInstallWelcomeSeen();
}

function bindDesktopInstallWelcomeOnce() {
  if (desktopInstallWelcomeBound) return;
  desktopInstallWelcomeBound = true;
  const { root, btnContinue } = getDesktopInstallWelcomeEls();
  if (!root) return;

  btnContinue?.addEventListener("click", () => {
    setDesktopInstallWelcomeVisible(false, { markSeen: true });
  });

  root.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (!desktopInstallWelcomeVisible || !(target instanceof Element)) return;
    // Clicking the overlay root (outside the card) dismisses it.
    // __backdrop and __noise now have pointer-events:none so clicks on the
    // background reach the root element directly.
    const card = root.querySelector(".desktopInstallWelcomeOverlay__card");
    if (card && card.contains(target)) return; // click was inside the card
    setDesktopInstallWelcomeVisible(false, { markSeen: true });
  });

  document.addEventListener("keydown", (e) => {
    if (!desktopInstallWelcomeVisible) return;
    if (e.key === "Escape" || e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      e.stopPropagation();
      setDesktopInstallWelcomeVisible(false, { markSeen: true });
    }
  }, true);
}

async function maybeShowDesktopInstallWelcome() {
  const shouldShow = await resolveDesktopInstallWelcomeEligibility();
  if (!shouldShow) return;
  bindDesktopInstallWelcomeOnce();
  setDesktopInstallWelcomeVisible(true, { markSeen: false, markSeenOnShow: true });
}

function canUseDesktopUpdateActions(bridge = null) {
  const resolvedBridge = bridge || getDesktopBridge();
  return !!(
    resolvedBridge
    && typeof resolvedBridge.getUpdateState === "function"
    && typeof resolvedBridge.checkForUpdates === "function"
  );
}

function buildDesktopUpdateSettingsStatusText(stateInput = null) {
  const state = stateInput && typeof stateInput === "object" ? stateInput : (desktopUpdateState || {});
  const status = String(state?.status || "").trim().toLowerCase();
  const version = String(state?.updateVersion || state?.version || "").trim();
  const pctRaw = Number(state?.progress);
  const pct = Number.isFinite(pctRaw) ? Math.max(0, Math.min(100, Math.round(pctRaw))) : 0;
  const message = String(state?.message || "").trim();

  if (status === "checking") {
    return t("settings.desktop.update.status.checking", "Checking for updates...");
  }
  if (status === "up-to-date") {
    return version
      ? tf("settings.desktop.update.status.up_to_date", { version }, "You already have the latest version ({version}).")
      : t("settings.desktop.update.status.up_to_date_no_version", "You already have the latest version.");
  }
  if (status === "available") {
    return version
      ? tf("settings.desktop.update.status.available", { version }, "Update {version} is available. Click Download update.")
      : t("settings.desktop.update.status.available_no_version", "An update is available. Click Download update.");
  }
  if (status === "downloading") {
    return tf("settings.desktop.update.status.downloading", { percent: pct }, "Downloading update... {percent}%");
  }
  if (status === "downloaded") {
    return version
      ? tf("settings.desktop.update.status.downloaded", { version }, "Update {version} is ready. Click Restart & Update.")
      : t("settings.desktop.update.status.downloaded_no_version", "Update is ready. Click Restart & Update.");
  }
  if (status === "installing") {
    return t("settings.desktop.update.status.installing", "Restarting to install update...");
  }
  if (status === "error") {
    return message || t("settings.desktop.update.status.error", "Update failed. Try again.");
  }
  if (status === "disabled" || state?.enabled === false || state?.configured === false) {
    return t("settings.desktop.update.status.disabled", "Auto-update is not available in this build.");
  }
  return t("settings.desktop.update.status.idle", "Click check to verify if this app is up to date.");
}

function renderDesktopUpdateSettingsUi(stateInput = null) {
  const state = stateInput && typeof stateInput === "object" ? stateInput : (desktopUpdateState || {});
  const {
    section,
    status,
    btnCheck,
    btnDownload,
    btnInstall,
  } = getDesktopUpdateSettingsEls();
  if (!section) return;

  const bridge = getDesktopBridge();
  const canUse = canUseDesktopUpdateActions(bridge);
  section.classList.toggle("hidden", !canUse);
  if (!canUse) return;

  const stateStatus = String(state?.status || "").trim().toLowerCase();
  const pctRaw = Number(state?.progress);
  const pct = Number.isFinite(pctRaw) ? Math.max(0, Math.min(100, Math.round(pctRaw))) : 0;

  if (status) {
    status.textContent = buildDesktopUpdateSettingsStatusText(state);
  }

  if (btnCheck) {
    btnCheck.disabled = stateStatus === "checking" || stateStatus === "installing";
    btnCheck.textContent = stateStatus === "checking"
      ? t("settings.desktop.update.checking", "Checking...")
      : t("settings.desktop.update.check", "Check for updates");
  }

  if (btnDownload) {
    const showDownload = stateStatus === "available" || stateStatus === "downloading";
    btnDownload.classList.toggle("hidden", !showDownload);
    btnDownload.disabled = stateStatus === "downloading";
    btnDownload.textContent = stateStatus === "downloading"
      ? tf("settings.desktop.update.status.downloading", { percent: pct }, "Downloading update... {percent}%")
      : t("settings.desktop.update.download", "Download update");
  }

  if (btnInstall) {
    const showInstall = stateStatus === "downloaded" || stateStatus === "installing";
    btnInstall.classList.toggle("hidden", !showInstall);
    btnInstall.disabled = stateStatus === "installing";
    btnInstall.textContent = stateStatus === "installing"
      ? t("settings.desktop.update.installing", "Installing...")
      : t("settings.desktop.update.install", "Restart & Update");
  }
}

function setDesktopUpdatePromptVisible(yes) {
  const { root } = getDesktopUpdateEls();
  if (!root) return;
  const show = !!yes;
  root.classList.toggle("hidden", !show);
  root.setAttribute("aria-hidden", show ? "false" : "true");
}

function buildDesktopUpdateDisplayText(state) {
  const status = String(state?.status || "").trim().toLowerCase();
  const version = String(state?.updateVersion || "").trim();
  const pctRaw = Number(state?.progress);
  const pct = Number.isFinite(pctRaw) ? Math.max(0, Math.min(100, Math.round(pctRaw))) : 0;

  if (status === "available") {
    return version
      ? `Update ${version} disponivel. Clica em Download.`
      : "Update disponivel. Clica em Download.";
  }
  if (status === "downloading") {
    return version
      ? `A transferir update ${version}... ${pct}%`
      : `A transferir update... ${pct}%`;
  }
  if (status === "downloaded") {
    return version
      ? `Update ${version} pronta. Clica em Restart & Update.`
      : "Update pronta. Clica em Restart & Update.";
  }
  if (status === "installing") {
    return "A reiniciar para instalar update...";
  }
  if (status === "error") {
    const msg = String(state?.message || "").trim();
    return msg || "Erro no update. Tenta novamente.";
  }
  return String(state?.message || "").trim() || "Update";
}

function buildDesktopUpdateDismissKey(state) {
  const status = String(state?.status || "").trim().toLowerCase();
  const version = String(state?.updateVersion || "").trim();
  if (!status) return "";
  return `${status}:${version}`;
}

function renderDesktopUpdatePrompt(stateInput = null) {
  const state = stateInput && typeof stateInput === "object" ? stateInput : (desktopUpdateState || {});
  desktopUpdateState = state;
  renderDesktopUpdatingOverlay(state);

  const { root, text, progressWrap, progressBar, btnDownload, btnInstall, btnDismiss } = getDesktopUpdateEls();
  if (!root || !text || !btnDownload || !btnInstall || !btnDismiss) return;

  const bridge = getDesktopBridge();
  if (!bridge) {
    setDesktopUpdatePromptVisible(false);
    return;
  }

  const status = String(state?.status || "").trim().toLowerCase();
  const enabled = !!state?.enabled;
  const configured = !!state?.configured;
  const dismissKey = buildDesktopUpdateDismissKey(state);
  if (dismissKey && dismissKey !== desktopUpdateDismissedKey) {
    desktopUpdateDismissedKey = "";
  }
  if (dismissKey && desktopUpdateDismissedKey === dismissKey) {
    setDesktopUpdatePromptVisible(false);
    return;
  }

  const show =
    enabled
    && configured
    && (
      status === "available"
      || status === "downloading"
      || status === "downloaded"
      || status === "installing"
      || status === "error"
    );

  if (!show) {
    setDesktopUpdatePromptVisible(false);
    return;
  }

  text.textContent = buildDesktopUpdateDisplayText(state);
  btnDownload.classList.add("hidden");
  btnInstall.classList.add("hidden");
  btnDismiss.disabled = false;
  btnDismiss.textContent = "x";

  // Progress bar: show only while downloading
  const pctRaw = Number(state?.progress);
  const pct = Number.isFinite(pctRaw) ? Math.max(0, Math.min(100, Math.round(pctRaw))) : 0;
  const showProgress = status === "downloading";
  if (progressWrap) progressWrap.classList.toggle("hidden", !showProgress);
  if (progressBar) {
    progressBar.style.width = `${pct}%`;
    progressBar.setAttribute("aria-valuenow", String(pct));
  }

  if (status === "available") {
    btnDownload.classList.remove("hidden");
    btnDownload.disabled = false;
    btnDownload.textContent = t("desktop.update.btn.download", "Download");
  } else if (status === "downloading") {
    btnDownload.classList.remove("hidden");
    btnDownload.disabled = true;
    btnDownload.textContent = t("desktop.update.btn.downloading", "A transferir...");
  } else if (status === "downloaded") {
    btnInstall.classList.remove("hidden");
    btnInstall.disabled = false;
    btnInstall.textContent = t("desktop.update.btn.install", "Reiniciar & Atualizar");
  } else if (status === "installing") {
    btnInstall.classList.remove("hidden");
    btnInstall.disabled = true;
    btnInstall.textContent = t("desktop.update.btn.installing", "A instalar...");
    btnDismiss.disabled = true;
  } else if (status === "error") {
    btnDownload.classList.remove("hidden");
    btnDownload.disabled = false;
    btnDownload.textContent = t("desktop.update.btn.retry", "Tentar novamente");
  }

  setDesktopUpdatePromptVisible(true);
}

function bindDesktopUpdateUiOnce() {
  if (desktopUpdateUiBound) return;
  desktopUpdateUiBound = true;

  const { btnDownload, btnInstall, btnDismiss } = getDesktopUpdateEls();
  const {
    btnCheck: settingsBtnCheck,
    btnDownload: settingsBtnDownload,
    btnInstall: settingsBtnInstall,
  } = getDesktopUpdateSettingsEls();
  const bridge = getDesktopBridge();
  if (!canUseDesktopUpdateActions(bridge)) {
    setDesktopUpdatePromptVisible(false);
    renderDesktopUpdateSettingsUi({});
    renderDesktopUpdatingOverlay({});
    return;
  }

  btnDownload?.addEventListener("click", async () => {
    const status = String(desktopUpdateState?.status || "").trim().toLowerCase();
    try {
      if (status === "available" && typeof bridge.downloadUpdate === "function") {
        await bridge.downloadUpdate();
      } else {
        await bridge.checkForUpdates?.();
      }
    } catch (_) {}
  });

  settingsBtnCheck?.addEventListener("click", async () => {
    try {
      await bridge.checkForUpdates?.();
    } catch (_) {}
  });

  settingsBtnDownload?.addEventListener("click", async () => {
    if (String(desktopUpdateState?.status || "").trim().toLowerCase() !== "available") return;
    try {
      await bridge.downloadUpdate?.();
    } catch (_) {}
  });

  btnInstall?.addEventListener("click", async () => {
    try {
      await bridge.installDownloadedUpdate?.();
    } catch (_) {}
  });

  settingsBtnInstall?.addEventListener("click", async () => {
    if (String(desktopUpdateState?.status || "").trim().toLowerCase() !== "downloaded") return;
    try {
      await bridge.installDownloadedUpdate?.();
    } catch (_) {}
  });

  btnDismiss?.addEventListener("click", () => {
    desktopUpdateDismissedKey = buildDesktopUpdateDismissKey(desktopUpdateState || {});
    setDesktopUpdatePromptVisible(false);
  });

  const applyDesktopUpdateStateToUi = (payload) => {
    renderDesktopUpdatePrompt(payload || {});
    renderDesktopUpdateSettingsUi(payload || {});
  };

  try {
    bridge.onUpdateState?.((payload) => {
      applyDesktopUpdateStateToUi(payload || {});
    });
  } catch (_) {}

  bridge.getUpdateState?.()
    .then((state) => {
      applyDesktopUpdateStateToUi(state || {});
    })
    .catch(() => {
      setDesktopUpdatePromptVisible(false);
      renderDesktopUpdateSettingsUi({});
      renderDesktopUpdatingOverlay({});
    });
}

function getDesktopSharePickerEls() {
  return {
    modal: document.getElementById("desktopSharePickerModal"),
    grid: document.getElementById("desktopSharePickerGrid"),
    meta: document.getElementById("desktopSharePickerMeta"),
    audioToggle: document.getElementById("desktopSharePickerAudioToggle"),
  };
}

function isDesktopSharePickerOpen() {
  const { modal } = getDesktopSharePickerEls();
  return !!(modal && !modal.classList.contains("hidden"));
}

function logDesktopSharePickerUiEvent(eventName = "", details = {}) {
  const name = String(eventName || "").trim();
  if (!name) return;
  const conversationId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
  logServerVoiceDebug(name, {
    conversationId: conversationId || null,
    pickerMode: isServerVoiceDesktopSharePickerMode() ? "server_voice" : "legacy",
    ...((details && typeof details === "object" && !Array.isArray(details)) ? details : {}),
  });
}

function normalizeDesktopSharePickerUpdatedSourceIds(values = []) {
  const out = [];
  const seen = new Set();
  (Array.isArray(values) ? values : []).forEach((value) => {
    const id = String(value || "").trim();
    if (!id || seen.has(id)) return;
    seen.add(id);
    out.push(id);
  });
  return out;
}

function stopDesktopSharePickerAutoRefresh({
  reason = "auto_refresh_stopped",
  pickerOpenOverride = null,
  updatedSourceIds = [],
} = {}) {
  if (!desktopSharePickerRefreshTimer) return;
  clearInterval(desktopSharePickerRefreshTimer);
  desktopSharePickerRefreshTimer = null;
  const pickerOpen = typeof pickerOpenOverride === "boolean"
    ? pickerOpenOverride
    : isDesktopSharePickerOpen();
  const sourceCount = Array.isArray(desktopSharePickerSources) ? desktopSharePickerSources.length : 0;
  logDesktopSharePickerUiEvent("screenshare.preview_auto_refresh_stopped", {
    reason: String(reason || "").trim() || "auto_refresh_stopped",
    pickerOpen: !!pickerOpen,
    sourceCount,
    updatedSourceIds: normalizeDesktopSharePickerUpdatedSourceIds(updatedSourceIds),
  });
}

function startDesktopSharePickerAutoRefresh({
  reason = "picker_opened",
} = {}) {
  stopDesktopSharePickerAutoRefresh({
    reason: "auto_refresh_restarted",
  });
  const sourceCount = Array.isArray(desktopSharePickerSources) ? desktopSharePickerSources.length : 0;
  logDesktopSharePickerUiEvent("screenshare.preview_auto_refresh_started", {
    reason: String(reason || "").trim() || "picker_opened",
    pickerOpen: isDesktopSharePickerOpen(),
    sourceCount,
    updatedSourceIds: [],
  });
  desktopSharePickerRefreshTimer = setInterval(() => {
    const pickerOpen = isDesktopSharePickerOpen();
    const sourceCountTick = Array.isArray(desktopSharePickerSources) ? desktopSharePickerSources.length : 0;
    const reasonForTick = !pickerOpen
      ? "auto_interval_skipped_picker_closed"
      : (desktopSharePickerBusy ? "auto_interval_skipped_busy" : "auto_interval_10s");
    logDesktopSharePickerUiEvent("screenshare.preview_auto_refresh_tick", {
      reason: reasonForTick,
      pickerOpen: !!pickerOpen,
      sourceCount: sourceCountTick,
      updatedSourceIds: [],
    });
    if (!pickerOpen) return;
    if (desktopSharePickerBusy) return;
    logDesktopSharePickerUiEvent("screenshare.preview_snapshot_refresh", {
      triggerReason: "auto_interval_10s",
    });
    void reloadDesktopSharePickerSources({
      silent: true,
      triggerReason: "auto_interval_10s",
    });
  }, DESKTOP_SHARE_PICKER_AUTO_REFRESH_MS);
}

function normalizeDesktopShareSource(raw) {
  const src = raw && typeof raw === "object" ? raw : {};
  const id = String(src.id || "").trim();
  if (!id) return null;
  const name = String(src.name || "").trim() || "Source";
  const rawKind = String(src.kind || "").trim().toLowerCase();
  const kind = rawKind === "screen" ? "screen" : "window";
  return {
    id,
    name,
    kind,
    thumbnailDataUrl: String(src.thumbnailDataUrl || "").trim(),
    appIconDataUrl: String(src.appIconDataUrl || "").trim(),
  };
}

function getDesktopShareSourceSignature(list) {
  const arr = Array.isArray(list) ? list : [];
  return arr
    .map((src) => {
      const id = String(src?.id || "").trim();
      const kind = String(src?.kind || "").trim();
      const name = String(src?.name || "").trim();
      const thumbnail = String(src?.thumbnailDataUrl || "").trim();
      const icon = String(src?.appIconDataUrl || "").trim();
      const thumbnailSig = `${thumbnail.length}:${thumbnail.slice(-32)}`;
      const iconSig = `${icon.length}:${icon.slice(-24)}`;
      return `${id}|${kind}|${name}|${thumbnailSig}|${iconSig}`;
    })
    .join("::");
}

function collectDesktopShareUpdatedSourceIds(previousList = [], nextList = []) {
  const previousMap = new Map();
  const nextMap = new Map();
  (Array.isArray(previousList) ? previousList : []).forEach((src) => {
    const id = String(src?.id || "").trim();
    if (!id || previousMap.has(id)) return;
    previousMap.set(id, src);
  });
  (Array.isArray(nextList) ? nextList : []).forEach((src) => {
    const id = String(src?.id || "").trim();
    if (!id || nextMap.has(id)) return;
    nextMap.set(id, src);
  });
  const updated = [];
  const candidateIds = new Set([...previousMap.keys(), ...nextMap.keys()]);
  candidateIds.forEach((id) => {
    const prev = previousMap.get(id) || null;
    const next = nextMap.get(id) || null;
    if (!prev || !next) {
      updated.push(id);
      return;
    }
    const prevSignature = getDesktopShareSourceSignature([prev]);
    const nextSignature = getDesktopShareSourceSignature([next]);
    if (prevSignature !== nextSignature) updated.push(id);
  });
  return normalizeDesktopSharePickerUpdatedSourceIds(updated);
}

function getDesktopSharePickerFilteredSources() {
  const tab = desktopSharePickerTab === "window" ? "window" : "screen";
  return desktopSharePickerSources.filter((src) => src.kind === tab);
}

const SERVER_VOICE_SCREENSHARE_PICKER_QUALITY_OPTIONS = Object.freeze(["720p", "1080p", "2160p", "source"]);
const SERVER_VOICE_SCREENSHARE_PICKER_FPS_OPTIONS = Object.freeze(["30", "60"]);
const SERVER_VOICE_SCREENSHARE_PICKER_STREAM_OPTIONS = Object.freeze([
  "720p30",
  "720p60",
  "1080p30",
  "1080p60",
  "2160p30",
  "2160p60",
  "source",
]);

function normalizeDesktopSharePickerServerVoiceQualityPreset(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  if (SERVER_VOICE_SCREENSHARE_PICKER_QUALITY_OPTIONS.includes(raw)) return raw;
  return SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET;
}

function normalizeDesktopSharePickerServerVoiceFpsPreset(value = "") {
  const raw = String(value || "").trim().toLowerCase();
  if (SERVER_VOICE_SCREENSHARE_PICKER_FPS_OPTIONS.includes(raw)) return raw;
  return SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET;
}

function normalizeDesktopSharePickerServerVoiceStreamPreset(value = "", fallbackFpsPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET) {
  const raw = String(value || "").trim().toLowerCase();
  if (SERVER_VOICE_SCREENSHARE_PICKER_STREAM_OPTIONS.includes(raw)) return raw;
  const fallbackFps = normalizeDesktopSharePickerServerVoiceFpsPreset(fallbackFpsPreset);
  return deriveDesktopSharePickerServerVoiceStreamPresetFromQualityAndFps(
    SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET,
    fallbackFps,
  );
}

function deriveDesktopSharePickerServerVoiceQualityAndFpsFromStreamPreset(
  streamPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_STREAM_PRESET,
  fallbackFpsPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET,
) {
  const preset = normalizeDesktopSharePickerServerVoiceStreamPreset(streamPreset, fallbackFpsPreset);
  if (preset === "720p30") return { qualityPreset: "720p", fpsPreset: "30" };
  if (preset === "720p60") return { qualityPreset: "720p", fpsPreset: "60" };
  if (preset === "1080p30") return { qualityPreset: "1080p", fpsPreset: "30" };
  if (preset === "1080p60") return { qualityPreset: "1080p", fpsPreset: "60" };
  if (preset === "2160p30") return { qualityPreset: "2160p", fpsPreset: "30" };
  if (preset === "2160p60") return { qualityPreset: "2160p", fpsPreset: "60" };
  return {
    qualityPreset: "source",
    fpsPreset: normalizeDesktopSharePickerServerVoiceFpsPreset(fallbackFpsPreset),
  };
}

function deriveDesktopSharePickerServerVoiceStreamPresetFromQualityAndFps(
  qualityPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET,
  fpsPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET,
) {
  const quality = normalizeDesktopSharePickerServerVoiceQualityPreset(qualityPreset);
  const fps = normalizeDesktopSharePickerServerVoiceFpsPreset(fpsPreset);
  if (quality === "source") return "source";
  if (quality === "720p") return fps === "30" ? "720p30" : "720p60";
  if (quality === "2160p") return fps === "30" ? "2160p30" : "2160p60";
  return fps === "30" ? "1080p30" : "1080p60";
}

function commitDesktopSharePickerServerVoiceStreamPreset(
  nextStreamPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_STREAM_PRESET,
  fallbackFpsPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET,
) {
  const { qualityPreset, fpsPreset } = deriveDesktopSharePickerServerVoiceQualityAndFpsFromStreamPreset(
    nextStreamPreset,
    fallbackFpsPreset,
  );
  desktopSharePickerServerVoiceQualityPreset = normalizeDesktopSharePickerServerVoiceQualityPreset(qualityPreset);
  desktopSharePickerServerVoiceFpsPreset = normalizeDesktopSharePickerServerVoiceFpsPreset(
    fpsPreset,
  );
  desktopSharePickerServerVoiceStreamPreset = deriveDesktopSharePickerServerVoiceStreamPresetFromQualityAndFps(
    desktopSharePickerServerVoiceQualityPreset,
    desktopSharePickerServerVoiceFpsPreset,
  );
  return {
    streamPreset: desktopSharePickerServerVoiceStreamPreset,
    qualityPreset: desktopSharePickerServerVoiceQualityPreset,
    fpsPreset: desktopSharePickerServerVoiceFpsPreset,
  };
}

function commitDesktopSharePickerServerVoiceQualityAndFps(
  nextQualityPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET,
  nextFpsPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET,
) {
  const qualityPreset = normalizeDesktopSharePickerServerVoiceQualityPreset(nextQualityPreset);
  const fpsPreset = normalizeDesktopSharePickerServerVoiceFpsPreset(nextFpsPreset);
  const streamPreset = deriveDesktopSharePickerServerVoiceStreamPresetFromQualityAndFps(qualityPreset, fpsPreset);
  desktopSharePickerServerVoiceQualityPreset = qualityPreset;
  desktopSharePickerServerVoiceFpsPreset = fpsPreset;
  desktopSharePickerServerVoiceStreamPreset = streamPreset;
  return {
    streamPreset,
    qualityPreset,
    fpsPreset,
  };
}

function readServerVoiceScreensharePresetStorageValue(storageKey = "", fallbackValue = "") {
  const key = String(storageKey || "").trim();
  if (!key) return fallbackValue;
  try {
    const stored = localStorage.getItem(key);
    if (stored == null) return fallbackValue;
    const normalized = String(stored || "").trim();
    return normalized || fallbackValue;
  } catch (_) {
    return fallbackValue;
  }
}

function writeServerVoiceScreensharePresetStorageValue(storageKey = "", value = "") {
  const key = String(storageKey || "").trim();
  if (!key) return;
  try {
    localStorage.setItem(key, String(value || "").trim());
  } catch (_) {}
}

function normalizeServerVoiceScreenshareAudioEnabled(value = null) {
  if (typeof value === "boolean") return value;
  const normalized = String(value || "").trim().toLowerCase();
  return normalized === "1" || normalized === "true" || normalized === "on";
}

function resolveServerVoiceScreensharePresetState(rawPreferences = null, {
  conversationId = null,
  source = "unknown",
  reason = "preset_resolve",
  logLoaded = false,
  callerFunction = "resolveServerVoiceScreensharePresetState",
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const prefs = rawPreferences && typeof rawPreferences === "object" ? rawPreferences : {};
  const storedQuality = readServerVoiceScreensharePresetStorageValue(
    SERVER_VOICE_SCREENSHARE_QUALITY_STORAGE_KEY,
    SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET,
  );
  const storedFps = readServerVoiceScreensharePresetStorageValue(
    SERVER_VOICE_SCREENSHARE_FPS_STORAGE_KEY,
    SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET,
  );
  const storedStream = readServerVoiceScreensharePresetStorageValue(
    SERVER_VOICE_SCREENSHARE_STREAM_PRESET_STORAGE_KEY,
    deriveDesktopSharePickerServerVoiceStreamPresetFromQualityAndFps(storedQuality, storedFps),
  );
  const preferredQuality = normalizeDesktopSharePickerServerVoiceQualityPreset(
    prefs?.qualityPreset ?? storedQuality ?? SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET,
  );
  const preferredFps = normalizeDesktopSharePickerServerVoiceFpsPreset(
    prefs?.fpsPreset ?? storedFps ?? SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET,
  );
  const preferredStream = normalizeDesktopSharePickerServerVoiceStreamPreset(
    prefs?.streamPreset
      ?? storedStream
      ?? deriveDesktopSharePickerServerVoiceStreamPresetFromQualityAndFps(preferredQuality, preferredFps),
    preferredFps,
  );
  const derived = deriveDesktopSharePickerServerVoiceQualityAndFpsFromStreamPreset(preferredStream, preferredFps);
  const qualityPreset = normalizeDesktopSharePickerServerVoiceQualityPreset(derived.qualityPreset || preferredQuality);
  const fpsPreset = normalizeDesktopSharePickerServerVoiceFpsPreset(derived.fpsPreset || preferredFps);
  const streamPreset = deriveDesktopSharePickerServerVoiceStreamPresetFromQualityAndFps(qualityPreset, fpsPreset);
  const storedAudioEnabled = normalizeServerVoiceScreenshareAudioEnabled(
    readServerVoiceScreensharePresetStorageValue(SERVER_VOICE_SCREENSHARE_AUDIO_STORAGE_KEY, "0"),
  );
  const shareAudioEnabled = typeof prefs?.shareAudioEnabled === "boolean"
    ? !!prefs.shareAudioEnabled
    : storedAudioEnabled;
  const normalizedState = {
    streamPreset,
    streamPresetOptions: [...SERVER_VOICE_SCREENSHARE_PICKER_STREAM_OPTIONS],
    qualityPreset,
    fpsPreset,
    qualityPresetOptions: [...SERVER_VOICE_SCREENSHARE_PICKER_QUALITY_OPTIONS],
    fpsPresetOptions: [...SERVER_VOICE_SCREENSHARE_PICKER_FPS_OPTIONS],
    shareAudioEnabled: !!shareAudioEnabled,
    preferredSourceId: String(prefs?.preferredSourceId || "").trim() || null,
    preferredSourceKind: String(prefs?.preferredSourceKind || "").trim() || null,
    preferredSourceName: String(prefs?.preferredSourceName || "").trim() || null,
  };
  if (logLoaded) {
    logServerVoiceDebug("screenshare.preset_loaded", {
      conversationId: convId || null,
      quality: normalizedState.qualityPreset,
      fps: normalizedState.fpsPreset,
      streamPreset: normalizedState.streamPreset,
      source: String(source || "").trim() || "unknown",
      reason: String(reason || "").trim() || "preset_resolve",
      callerFunction: String(callerFunction || "").trim() || "resolveServerVoiceScreensharePresetState",
      shareAudioEnabled: !!normalizedState.shareAudioEnabled,
    });
  }
  return normalizedState;
}

async function persistServerVoiceScreensharePresetState(conversationId = null, presetState = null, {
  source = "unknown",
  reason = "preset_saved",
  callerFunction = "persistServerVoiceScreensharePresetState",
  syncLayer = true,
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const normalizedState = resolveServerVoiceScreensharePresetState(presetState, {
    conversationId: convId,
    source: String(source || "").trim() || "unknown",
    reason: String(reason || "").trim() || "preset_saved",
    logLoaded: false,
    callerFunction: String(callerFunction || "").trim() || "persistServerVoiceScreensharePresetState",
  });
  writeServerVoiceScreensharePresetStorageValue(
    SERVER_VOICE_SCREENSHARE_STREAM_PRESET_STORAGE_KEY,
    normalizedState.streamPreset,
  );
  writeServerVoiceScreensharePresetStorageValue(
    SERVER_VOICE_SCREENSHARE_QUALITY_STORAGE_KEY,
    normalizedState.qualityPreset,
  );
  writeServerVoiceScreensharePresetStorageValue(
    SERVER_VOICE_SCREENSHARE_FPS_STORAGE_KEY,
    normalizedState.fpsPreset,
  );
  writeServerVoiceScreensharePresetStorageValue(
    SERVER_VOICE_SCREENSHARE_AUDIO_STORAGE_KEY,
    normalizedState.shareAudioEnabled ? "1" : "0",
  );
  if (syncLayer && convId) {
    const layer = getActiveServerVoiceScreenshareLayer(convId);
    if (layer && typeof layer.setStreamPreset === "function") {
      try {
        await layer.setStreamPreset(normalizedState.streamPreset, {
          triggerReason: `${String(reason || "").trim() || "preset_saved"}_persist_sync`,
          applyLive: false,
        });
      } catch (_) {}
    }
    if (layer && typeof layer.setShareAudioEnabled === "function") {
      try {
        await layer.setShareAudioEnabled(!!normalizedState.shareAudioEnabled, {
          triggerReason: `${String(reason || "").trim() || "preset_saved"}_persist_sync`,
          applyLive: false,
        });
      } catch (_) {}
    }
  }
  logServerVoiceDebug("screenshare.preset_saved", {
    conversationId: convId || null,
    quality: normalizedState.qualityPreset,
    fps: normalizedState.fpsPreset,
    streamPreset: normalizedState.streamPreset,
    source: String(source || "").trim() || "unknown",
    reason: String(reason || "").trim() || "preset_saved",
    callerFunction: String(callerFunction || "").trim() || "persistServerVoiceScreensharePresetState",
    shareAudioEnabled: !!normalizedState.shareAudioEnabled,
  });
  return normalizedState;
}

function syncDesktopSharePickerQualityUi() {
  const quality = getShareQualityValue();
  document.querySelectorAll("[data-desktop-share-quality]").forEach((btn) => {
    const q = String(btn.getAttribute("data-desktop-share-quality") || "").trim();
    btn.classList.toggle("is-active", q === quality);
  });
}

function isServerVoiceDesktopSharePickerMode() {
  return desktopSharePickerMode === "server_voice";
}

function syncDesktopSharePickerServerVoicePresetUi() {
  const isServerVoiceMode = isServerVoiceDesktopSharePickerMode();
  const presetValueEl = document.getElementById("desktopSharePickerServerVoicePresetValue");
  const qualityPreset = normalizeDesktopSharePickerServerVoiceQualityPreset(
    desktopSharePickerServerVoiceQualityPreset || SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET
  );
  const fpsPreset = normalizeDesktopSharePickerServerVoiceFpsPreset(
    desktopSharePickerServerVoiceFpsPreset || SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET,
  );
  const streamPreset = deriveDesktopSharePickerServerVoiceStreamPresetFromQualityAndFps(
    qualityPreset,
    fpsPreset,
  );
  desktopSharePickerServerVoiceQualityPreset = qualityPreset;
  desktopSharePickerServerVoiceFpsPreset = fpsPreset;
  desktopSharePickerServerVoiceStreamPreset = streamPreset;

  document.querySelectorAll("[data-desktop-share-server-quality]").forEach((btn) => {
    const value = normalizeDesktopSharePickerServerVoiceQualityPreset(
      btn.getAttribute("data-desktop-share-server-quality") || "",
    );
    btn.classList.toggle("is-active", value === qualityPreset);
  });
  document.querySelectorAll("[data-desktop-share-server-fps]").forEach((btn) => {
    const valueRaw = String(btn.getAttribute("data-desktop-share-server-fps") || "").trim().toLowerCase();
    const value = SERVER_VOICE_SCREENSHARE_PICKER_FPS_OPTIONS.includes(valueRaw) ? valueRaw : "30";
    btn.classList.toggle("is-active", value === fpsPreset);
    if (btn instanceof HTMLButtonElement) btn.disabled = false;
    btn.classList.remove("is-disabled");
  });
  if (presetValueEl) {
    presetValueEl.textContent = formatServerVoiceScreenshareStreamPresetLabel(streamPreset);
    presetValueEl.hidden = !isServerVoiceMode;
  }
  const renderSignature = isServerVoiceMode
    ? `${streamPreset}|${qualityPreset}|${fpsPreset}|${desktopSharePickerServerVoiceWithAudio ? 1 : 0}`
    : "";
  if (!isServerVoiceMode) {
    desktopSharePickerServerVoicePresetRenderSignature = "";
    return;
  }
  if (renderSignature === desktopSharePickerServerVoicePresetRenderSignature) return;
  desktopSharePickerServerVoicePresetRenderSignature = renderSignature;
  logServerVoiceDebug("screenshare.preset_rendered", {
    conversationId: normId(callConversationId || activeDmId || "") || null,
    quality: qualityPreset,
    fps: fpsPreset,
    streamPreset,
    source: "desktop_picker_ui",
    reason: "picker_ui_sync",
    callerFunction: "syncDesktopSharePickerServerVoicePresetUi",
    shareAudioEnabled: !!desktopSharePickerServerVoiceWithAudio,
  });
}

function syncDesktopSharePickerFooterActionsUi() {
  const startBtn = document.getElementById("desktopSharePickerStartBtn");
  const stopBtn = document.getElementById("desktopSharePickerStopBtn");
  if (!startBtn || !stopBtn) return;
  const isServerVoiceMode = isServerVoiceDesktopSharePickerMode();
  if (!isServerVoiceMode) {
    startBtn.hidden = true;
    startBtn.style.display = "none";
    startBtn.disabled = true;
    stopBtn.hidden = true;
    stopBtn.style.display = "none";
    stopBtn.disabled = true;
    return;
  }
  const localShareActive = !!desktopSharePickerServerVoiceLocalShareActive;
  const sourceOnly = !!desktopSharePickerServerVoiceSourceOnly;
  startBtn.hidden = true;
  startBtn.style.display = "none";
  startBtn.disabled = true;
  startBtn.textContent = sourceOnly ? "Select Source" : (localShareActive ? "Change Stream" : "Start Streaming");
  stopBtn.hidden = !localShareActive;
  stopBtn.style.display = localShareActive ? "" : "none";
  stopBtn.disabled = !localShareActive;
}

function syncDesktopSharePickerModeUi() {
  const isServerVoiceMode = isServerVoiceDesktopSharePickerMode();
  const audioWrap = document.querySelector(".desktopSharePickerAudio");
  const legacyQualityWrap = document.querySelector(".desktopSharePickerQuality");
  const serverVoiceControls = document.getElementById("desktopSharePickerServerVoiceControls");
  const hintEl = document.getElementById("desktopSharePickerHint");
  if (audioWrap instanceof HTMLElement) {
    audioWrap.hidden = false;
    audioWrap.style.display = "";
  }
  if (legacyQualityWrap instanceof HTMLElement) {
    legacyQualityWrap.hidden = isServerVoiceMode;
    legacyQualityWrap.style.display = isServerVoiceMode ? "none" : "";
  }
  if (serverVoiceControls instanceof HTMLElement) {
    serverVoiceControls.hidden = !isServerVoiceMode;
    serverVoiceControls.style.display = isServerVoiceMode ? "" : "none";
  }
  if (hintEl) {
    if (isServerVoiceMode) {
      hintEl.textContent = desktopSharePickerServerVoiceSourceOnly
        ? "Select a source and click Select Source."
        : desktopSharePickerServerVoiceLocalShareActive
        ? "Pick a source to change stream, or tune quality/FPS/audio and keep current source."
        : "Select what to share, tune quality/FPS/audio, then click Start Streaming.";
    } else {
      hintEl.textContent = t("call.share.picker.hint", "Select a window or screen to share");
    }
  }
  syncDesktopSharePickerServerVoicePresetUi();
  syncDesktopSharePickerFooterActionsUi();
}

function syncDesktopSharePickerAudioToggle() {
  // Audio is always selectable â€” user decides whether they want it
  const audioToggle = document.getElementById("desktopSharePickerAudioToggle");
  if (!(audioToggle instanceof HTMLInputElement)) return;
  audioToggle.disabled = false;
}

function syncDesktopSharePickerAudioToggleForMode() {
  const audioToggle = document.getElementById("desktopSharePickerAudioToggle");
  if (!(audioToggle instanceof HTMLInputElement)) return;
  if (isServerVoiceDesktopSharePickerMode()) {
    audioToggle.checked = !!desktopSharePickerServerVoiceWithAudio;
    audioToggle.disabled = false;
    return;
  }
  audioToggle.disabled = false;
}

function renderDesktopSharePickerSources() {
  const { modal, grid, meta } = getDesktopSharePickerEls();
  if (!modal || !grid || !meta) return;
  if (!isDesktopSharePickerOpen()) return;
  syncDesktopSharePickerModeUi();
  syncDesktopSharePickerAudioToggleForMode();

  const filtered = getDesktopSharePickerFilteredSources();
  const hasSelected = filtered.some((src) => src.id === desktopSharePickerSelectedSourceId);
  if (!hasSelected) desktopSharePickerSelectedSourceId = "";

  if (desktopSharePickerBusy && desktopSharePickerBusyUi) {
    grid.innerHTML = `<div class="hint">${t("share.loading", "Loading share sources...")}</div>`;
    meta.textContent = t("share.searching", "Searching windows and screens...");
    applySharePrefsToUi();
    return;
  }

  if (!filtered.length) {
    grid.innerHTML = '<div class="hint">' + t("share.no_sources", "No sources in this category.") + '</div>';
    meta.textContent = t("share.no_sources_hint", "No sources found. Click Refresh.");
    applySharePrefsToUi();
    return;
  }

  const html = filtered.map((src) => {
    const selected = src.id === desktopSharePickerSelectedSourceId;
    const iconFallback = getGroupOrbFallbackChar(src.name, src.kind === "screen" ? "S" : "A");
    const iconHtml = src.appIconDataUrl
      ? `<img class="desktopSharePickerItem__icon" src="${esc(src.appIconDataUrl)}" alt="" />`
      : `<span class="desktopSharePickerItem__iconFallback">${esc(iconFallback)}</span>`;
    const thumbHtml = src.thumbnailDataUrl
      ? `<img class="desktopSharePickerItem__thumb" src="${esc(src.thumbnailDataUrl)}" alt="${escAttr(src.name)}" />`
      : `<div class="desktopSharePickerItem__thumbFallback">${src.kind === "screen" ? "Screen" : "Window"}</div>`;
    const quickShareLabel = isServerVoiceDesktopSharePickerMode()
      ? (
        desktopSharePickerServerVoiceSourceOnly
          ? "Select Source"
          : (desktopSharePickerServerVoiceLocalShareActive ? "Change Stream" : "Start Streaming")
      )
      : t("share.share_screen_btn", "Share Screen");
    const quickShareHtml = `
      <button
        class="desktopSharePickerItem__shareBtn"
        type="button"
        data-desktop-share-quick-share="${escAttr(src.id)}"
        aria-label="${escAttr(t("share.select.aria", "Share {name}").replace("{name}", src.name))}"
      >${esc(quickShareLabel)}</button>
    `;
    return `
      <div
        class="desktopSharePickerItem${selected ? " is-selected" : ""}"
        role="button"
        tabindex="0"
        aria-label="${escAttr(t("share.select.aria", "Share {name}").replace("{name}", src.name))}"
        data-desktop-share-source-id="${escAttr(src.id)}"
      >
        <div class="desktopSharePickerItem__thumbWrap">
          ${thumbHtml}
          ${quickShareHtml}
        </div>
        <div class="desktopSharePickerItem__meta">
          ${iconHtml}
          <span class="desktopSharePickerItem__name">${esc(src.name)}</span>
        </div>
      </div>
    `;
  }).join("");

  grid.innerHTML = html;
  if (isServerVoiceDesktopSharePickerMode()) {
    if (desktopSharePickerSelectedSourceId) {
      meta.textContent = desktopSharePickerServerVoiceSourceOnly
        ? "Source selected. Use the source card action to apply."
        : (desktopSharePickerServerVoiceLocalShareActive
          ? "Source selected. Use the source card action to change stream."
          : "Source selected. Use the source card action to start streaming.");
    } else {
      meta.textContent = desktopSharePickerServerVoiceSourceOnly
        ? "Select a source to continue."
        : "Choose a source, stream quality, FPS, and audio, then start from the source card.";
    }
  } else {
    meta.textContent = desktopSharePickerSelectedSourceId
      ? t("share.hint.selected", "Click Share Screen on the preview to start, or double-click the card.")
      : t("share.hint.select", "Select a source and hover over it to share.");
  }
  if (grid) {
    grid.querySelectorAll("[data-desktop-share-source-id]").forEach((card) => {
      const sourceId = String(card.getAttribute("data-desktop-share-source-id") || "").trim();
      if (!sourceId) return;
      const logHoverShown = () => {
        if (desktopSharePickerHoverActionLoggedSourceIds.has(sourceId)) return;
        desktopSharePickerHoverActionLoggedSourceIds.add(sourceId);
        logDesktopSharePickerUiEvent("screenshare.source_hover_action_shown", {
          sourceId,
          sourceName: String(
            desktopSharePickerSources.find((src) => src.id === sourceId)?.name || "",
          ).trim() || null,
          qualityPreset: desktopSharePickerServerVoiceQualityPreset || null,
          fpsPreset: desktopSharePickerServerVoiceFpsPreset || null,
          withAudio: !!desktopSharePickerServerVoiceWithAudio,
        });
      };
      card.addEventListener("mouseenter", logHoverShown, { passive: true });
      card.addEventListener("focusin", logHoverShown);
    });
  }
  applySharePrefsToUi();
}

async function reloadDesktopSharePickerSources({
  silent = false,
  triggerReason = "",
} = {}) {
  const bridge = getDesktopBridge();
  const { meta } = getDesktopSharePickerEls();
  if (!bridge) return;
  if (desktopSharePickerBusy) return;
  const normalizedTriggerReason = String(triggerReason || "").trim() || (silent ? "auto_refresh" : "manual_refresh");

  const previousSources = Array.isArray(desktopSharePickerSources)
    ? [...desktopSharePickerSources]
    : [];
  const prevSignature = getDesktopShareSourceSignature(previousSources);
  const prevSelectedSourceId = desktopSharePickerSelectedSourceId;
  let shouldRender = !silent;
  let updatedSourceIds = [];

  logDesktopSharePickerUiEvent("screenshare.preview_snapshot_requested", {
    triggerReason: normalizedTriggerReason,
    silent: !!silent,
    tab: desktopSharePickerTab,
    previousCount: Array.isArray(desktopSharePickerSources) ? desktopSharePickerSources.length : 0,
  });

  desktopSharePickerBusy = true;
  desktopSharePickerBusyUi = !silent;
  if (!silent) renderDesktopSharePickerSources();
  try {
    const list = await bridge.getDisplaySources({ thumbnailSize: 720 });
    const normalized = (Array.isArray(list) ? list : [])
      .map(normalizeDesktopShareSource)
      .filter(Boolean);
    normalized.sort((a, b) => {
      const rank = (kind) => (kind === "screen" ? 0 : 1);
      const diff = rank(a.kind) - rank(b.kind);
      if (diff) return diff;
      return a.name.localeCompare(b.name, undefined, { sensitivity: "base" });
    });
    const nextSignature = getDesktopShareSourceSignature(normalized);
    updatedSourceIds = collectDesktopShareUpdatedSourceIds(previousSources, normalized);
    desktopSharePickerSources = normalized;
    if (!desktopSharePickerSources.some((src) => src.id === desktopSharePickerSelectedSourceId)) {
      desktopSharePickerSelectedSourceId = "";
    }
    if (silent) {
      const selectedChanged = prevSelectedSourceId !== desktopSharePickerSelectedSourceId;
      shouldRender = (prevSignature !== nextSignature) || selectedChanged || updatedSourceIds.length > 0;
    }
    logDesktopSharePickerUiEvent("screenshare.preview_snapshot_updated", {
      triggerReason: normalizedTriggerReason,
      reason: normalizedTriggerReason,
      silent: !!silent,
      tab: desktopSharePickerTab,
      pickerOpen: isDesktopSharePickerOpen(),
      sourceCount: normalized.length,
      changed: prevSignature !== nextSignature,
      selectedSourceId: desktopSharePickerSelectedSourceId || null,
      updatedSourceIds,
    });
  } catch (e) {
    console.warn("desktop share sources failed", e);
    if (!silent) {
      desktopSharePickerSources = [];
      desktopSharePickerSelectedSourceId = "";
      if (meta) meta.textContent = "Falhou ao listar janelas/ecrÃ£s. Tenta novamente.";
    }
    if (silent) shouldRender = false;
  } finally {
    desktopSharePickerBusy = false;
    desktopSharePickerBusyUi = false;
    if (shouldRender) renderDesktopSharePickerSources();
  }
}

function resolveDesktopSharePicker(result = null) {
  const resolver = desktopSharePickerResolve;
  desktopSharePickerResolve = null;
  if (typeof resolver === "function") {
    try { resolver(result); } catch (_) {}
  }
}

function closeDesktopSharePicker(result = null) {
  const { modal } = getDesktopSharePickerEls();
  if (modal) {
    modal.classList.add("hidden");
    modal.setAttribute("aria-hidden", "true");
  }
  stopDesktopSharePickerAutoRefresh({
    reason: "picker_closed",
    pickerOpenOverride: false,
    updatedSourceIds: [],
  });
  desktopSharePickerBusy = false;
  desktopSharePickerBusyUi = false;
  desktopSharePickerSources = [];
  desktopSharePickerSelectedSourceId = "";
  desktopSharePickerLastClickSourceId = "";
  desktopSharePickerLastClickAt = 0;
  desktopSharePickerMode = "legacy";
  desktopSharePickerServerVoiceQualityPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET;
  desktopSharePickerServerVoiceFpsPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET;
  desktopSharePickerServerVoiceStreamPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_STREAM_PRESET;
  desktopSharePickerServerVoiceWithAudio = false;
  desktopSharePickerServerVoiceLocalShareActive = false;
  desktopSharePickerServerVoiceSourceOnly = false;
  desktopSharePickerHoverActionLoggedSourceIds = new Set();
  desktopSharePickerServerVoicePresetRenderSignature = "";
  resolveDesktopSharePicker(result);
}

function confirmDesktopSharePickerSelection(action = "confirm") {
  const { audioToggle } = getDesktopSharePickerEls();
  const normalizedActionRaw = String(action || "").trim().toLowerCase();
  const normalizedAction = normalizedActionRaw === "stop" ? "stop" : "confirm";
  const source = desktopSharePickerSources.find((src) => src.id === desktopSharePickerSelectedSourceId) || null;
  const isServerVoiceMode = isServerVoiceDesktopSharePickerMode();
  const withAudio = isServerVoiceDesktopSharePickerMode()
    ? !!desktopSharePickerServerVoiceWithAudio
    : !!audioToggle?.checked;
  if (!isServerVoiceDesktopSharePickerMode()) {
    localStorage.setItem(SHARE_AUDIO_KEY, withAudio ? "1" : "0");
  }
  if (!isServerVoiceMode && !source) return false;
  if (isServerVoiceMode) {
    const streamPreset = deriveDesktopSharePickerServerVoiceStreamPresetFromQualityAndFps(
      desktopSharePickerServerVoiceQualityPreset,
      desktopSharePickerServerVoiceFpsPreset,
    );
    const actionName = normalizedAction === "stop"
      ? "stop"
      : (desktopSharePickerServerVoiceLocalShareActive ? "change" : "start");
    if (desktopSharePickerServerVoiceSourceOnly && normalizedAction !== "stop" && !source) return false;
    closeDesktopSharePicker({
      action: desktopSharePickerServerVoiceSourceOnly ? "select_source" : actionName,
      sourceId: source?.id || "",
      sourceKind: source?.kind || "",
      sourceName: source?.name || "",
      withAudio,
      qualityPreset: normalizeDesktopSharePickerServerVoiceQualityPreset(
        desktopSharePickerServerVoiceQualityPreset,
      ),
      fpsPreset: normalizeDesktopSharePickerServerVoiceFpsPreset(
        desktopSharePickerServerVoiceFpsPreset,
      ),
      streamPreset,
      localShareActive: !!desktopSharePickerServerVoiceLocalShareActive,
      sourceOnly: !!desktopSharePickerServerVoiceSourceOnly,
    });
    return true;
  }
  closeDesktopSharePicker({
    sourceId: source.id,
    sourceKind: source.kind,
    sourceName: source.name,
    withAudio,
  });
  return true;
}

function bindDesktopSharePickerOnce() {
  if (desktopSharePickerBound) return;
  desktopSharePickerBound = true;

  const { modal } = getDesktopSharePickerEls();
  if (!modal) return;

  // Save audio preference immediately on checkbox change so applySharePrefsToUi can't reset it
  const audioToggle = document.getElementById("desktopSharePickerAudioToggle");
  if (audioToggle instanceof HTMLInputElement) {
    audioToggle.addEventListener("change", () => {
      if (isServerVoiceDesktopSharePickerMode()) {
        desktopSharePickerServerVoiceWithAudio = !!audioToggle.checked;
        return;
      }
      localStorage.setItem(SHARE_AUDIO_KEY, audioToggle.checked ? "1" : "0");
      syncCallShareMenuUi(); // keep share menu in sync
    });
  }

  modal.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;

    if (target.closest("[data-desktop-share-close]") || target.closest("[data-desktop-share-cancel]")) {
      e.preventDefault();
      closeDesktopSharePicker(null);
      return;
    }

    const tabBtn = target.closest("[data-desktop-share-tab]");
    if (tabBtn) {
      e.preventDefault();
      const nextTabRaw = String(tabBtn.getAttribute("data-desktop-share-tab") || "").trim().toLowerCase();
      desktopSharePickerTab = nextTabRaw === "window" ? "window" : "screen";
      document.querySelectorAll("[data-desktop-share-tab]").forEach((btn) => {
        const tab = String(btn.getAttribute("data-desktop-share-tab") || "").trim().toLowerCase();
        const isActive = tab === desktopSharePickerTab;
        btn.classList.toggle("is-active", isActive);
      });
      syncDesktopSharePickerAudioToggleForMode();
      renderDesktopSharePickerSources();
      return;
    }

    const refreshBtn = target.closest("[data-desktop-share-refresh]");
    if (refreshBtn) {
      e.preventDefault();
      logDesktopSharePickerUiEvent("screenshare.preview_snapshot_refresh", {
        triggerReason: "manual_refresh_button",
      });
      void reloadDesktopSharePickerSources({
        triggerReason: "manual_refresh_button",
      });
      return;
    }

    const profileBtn = target.closest("[data-desktop-share-profile]");
    if (profileBtn) {
      e.preventDefault();
      const nextProfileRaw = String(profileBtn.getAttribute("data-desktop-share-profile") || "").trim();
      void setShareProfileValue(nextProfileRaw, { applyLive: false });
      return;
    }

    const qualityBtn = target.closest("[data-desktop-share-quality]");
    if (qualityBtn) {
      e.preventDefault();
      if (isServerVoiceDesktopSharePickerMode()) return;
      const nextQRaw = String(qualityBtn.getAttribute("data-desktop-share-quality") || "").trim();
      const nextQ = SHARE_QUALITY_ALLOWED.has(nextQRaw) ? nextQRaw : SHARE_QUALITY_DEFAULT;
      localStorage.setItem(SHARE_QUALITY_KEY, nextQ);
      const shareQualityInput = document.getElementById("shareQuality");
      if (shareQualityInput) shareQualityInput.value = nextQ;
      syncDesktopSharePickerQualityUi();
      return;
    }

    const serverQualityBtn = target.closest("[data-desktop-share-server-quality]");
    if (serverQualityBtn) {
      e.preventDefault();
      if (!isServerVoiceDesktopSharePickerMode()) return;
      const nextQuality = String(
        serverQualityBtn.getAttribute("data-desktop-share-server-quality") || "",
      ).trim().toLowerCase();
      const committed = commitDesktopSharePickerServerVoiceQualityAndFps(
        nextQuality,
        desktopSharePickerServerVoiceFpsPreset,
      );
      logServerVoiceDebug("screenshare.preset_selected", {
        conversationId: normId(callConversationId || activeDmId || ""),
        triggerReason: "desktop_picker_quality_selected",
        callerFunction: "bindDesktopSharePickerOnce",
        streamPreset: committed.streamPreset,
        qualityPreset: committed.qualityPreset,
        fpsPreset: committed.fpsPreset,
        shareAudioEnabled: !!desktopSharePickerServerVoiceWithAudio,
      });
      void persistServerVoiceScreensharePresetState(
        normId(callConversationId || activeDmId || ""),
        {
          streamPreset: committed.streamPreset,
          qualityPreset: committed.qualityPreset,
          fpsPreset: committed.fpsPreset,
          shareAudioEnabled: !!desktopSharePickerServerVoiceWithAudio,
        },
        {
          source: "desktop_picker_quality_button",
          reason: "desktop_picker_quality_selected",
          callerFunction: "bindDesktopSharePickerOnce",
          syncLayer: true,
        }
      );
      syncDesktopSharePickerServerVoicePresetUi();
      renderDesktopSharePickerSources();
      return;
    }

    const serverFpsBtn = target.closest("[data-desktop-share-server-fps]");
    if (serverFpsBtn) {
      e.preventDefault();
      if (!isServerVoiceDesktopSharePickerMode()) return;
      if (serverFpsBtn instanceof HTMLButtonElement && serverFpsBtn.disabled) return;
      const nextFps = String(serverFpsBtn.getAttribute("data-desktop-share-server-fps") || "").trim().toLowerCase();
      const committed = commitDesktopSharePickerServerVoiceQualityAndFps(
        desktopSharePickerServerVoiceQualityPreset,
        nextFps,
      );
      logServerVoiceDebug("screenshare.preset_selected", {
        conversationId: normId(callConversationId || activeDmId || ""),
        triggerReason: "desktop_picker_fps_selected",
        callerFunction: "bindDesktopSharePickerOnce",
        streamPreset: committed.streamPreset,
        qualityPreset: committed.qualityPreset,
        fpsPreset: committed.fpsPreset,
        shareAudioEnabled: !!desktopSharePickerServerVoiceWithAudio,
      });
      void persistServerVoiceScreensharePresetState(
        normId(callConversationId || activeDmId || ""),
        {
          streamPreset: committed.streamPreset,
          qualityPreset: committed.qualityPreset,
          fpsPreset: committed.fpsPreset,
          shareAudioEnabled: !!desktopSharePickerServerVoiceWithAudio,
        },
        {
          source: "desktop_picker_fps_button",
          reason: "desktop_picker_fps_selected",
          callerFunction: "bindDesktopSharePickerOnce",
          syncLayer: true,
        }
      );
      syncDesktopSharePickerServerVoicePresetUi();
      renderDesktopSharePickerSources();
      return;
    }

    const pickerActionBtn = target.closest("[data-desktop-share-act]");
    if (pickerActionBtn) {
      e.preventDefault();
      const action = String(pickerActionBtn.getAttribute("data-desktop-share-act") || "").trim().toLowerCase();
      if (action === "stop") {
        confirmDesktopSharePickerSelection("stop");
        return;
      }
      if (action === "confirm") {
        confirmDesktopSharePickerSelection("confirm");
        return;
      }
    }

    const quickShareBtn = target.closest("[data-desktop-share-quick-share]");
    if (quickShareBtn) {
      e.preventDefault();
      const sourceId = String(quickShareBtn.getAttribute("data-desktop-share-quick-share") || "").trim();
      if (!sourceId) return;
      const source = desktopSharePickerSources.find((src) => src.id === sourceId) || null;
      logDesktopSharePickerUiEvent("screenshare.source_start_clicked", {
        triggerReason: "source_card_hover_action",
        sourceId,
        sourceKind: source?.kind || null,
        sourceName: source?.name || null,
        qualityPreset: desktopSharePickerServerVoiceQualityPreset || null,
        fpsPreset: desktopSharePickerServerVoiceFpsPreset || null,
        withAudio: isServerVoiceDesktopSharePickerMode()
          ? !!desktopSharePickerServerVoiceWithAudio
          : !!(document.getElementById("desktopSharePickerAudioToggle")?.checked),
      });
      desktopSharePickerSelectedSourceId = sourceId;
      renderDesktopSharePickerSources();
      confirmDesktopSharePickerSelection();
      return;
    }

    const sourceBtn = target.closest("[data-desktop-share-source-id]");
    if (sourceBtn) {
      e.preventDefault();
      const sourceId = String(sourceBtn.getAttribute("data-desktop-share-source-id") || "").trim();
      if (!sourceId) return;
      const now = Date.now();
      const isFastDoubleClick = (
        sourceId === desktopSharePickerLastClickSourceId
        && (now - desktopSharePickerLastClickAt) <= 380
      );
      desktopSharePickerLastClickSourceId = sourceId;
      desktopSharePickerLastClickAt = now;
      desktopSharePickerSelectedSourceId = sourceId;
      renderDesktopSharePickerSources();
      if (isFastDoubleClick && !isServerVoiceDesktopSharePickerMode()) {
        confirmDesktopSharePickerSelection();
      }
      return;
    }
  });

  modal.addEventListener("keydown", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    if (target.closest("[data-desktop-share-quick-share]")) return;
    const sourceBtn = target.closest("[data-desktop-share-source-id]");
    if (!sourceBtn) return;
    if (e.key !== "Enter" && e.key !== " ") return;
    e.preventDefault();
    const sourceId = String(sourceBtn.getAttribute("data-desktop-share-source-id") || "").trim();
    if (!sourceId) return;
    if (!isServerVoiceDesktopSharePickerMode() && desktopSharePickerSelectedSourceId === sourceId) {
      confirmDesktopSharePickerSelection();
      return;
    }
    desktopSharePickerSelectedSourceId = sourceId;
    renderDesktopSharePickerSources();
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (!isDesktopSharePickerOpen()) return;
    e.preventDefault();
    closeDesktopSharePicker(null);
  });
}

async function openDesktopSharePicker({
  withAudio = true,
  mode = "legacy",
  qualityPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET,
  fpsPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET,
  streamPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_STREAM_PRESET,
  localShareActive = false,
  sourceOnly = false,
} = {}) {
  if (!canUseDesktopSharePicker()) return null;
  bindDesktopSharePickerOnce();

  const { modal, audioToggle } = getDesktopSharePickerEls();
  if (!modal) return null;
  if (desktopSharePickerResolve) resolveDesktopSharePicker(null);

  desktopSharePickerTab = "screen";
  const pickerMode = String(mode || "").trim().toLowerCase();
  desktopSharePickerMode = pickerMode === "server_voice" ? "server_voice" : "legacy";
  if (desktopSharePickerMode === "server_voice") {
    const normalizedStreamPreset = String(streamPreset || "").trim().toLowerCase();
    if (normalizedStreamPreset) {
      commitDesktopSharePickerServerVoiceStreamPreset(normalizedStreamPreset, fpsPreset);
    } else {
      commitDesktopSharePickerServerVoiceQualityAndFps(qualityPreset, fpsPreset);
    }
  } else {
    desktopSharePickerServerVoiceQualityPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_QUALITY_PRESET;
    desktopSharePickerServerVoiceFpsPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_FPS_PRESET;
    desktopSharePickerServerVoiceStreamPreset = SERVER_VOICE_SCREENSHARE_DEFAULT_STREAM_PRESET;
  }
  desktopSharePickerServerVoiceWithAudio = !!withAudio;
  desktopSharePickerServerVoiceLocalShareActive = !!localShareActive;
  desktopSharePickerServerVoiceSourceOnly = !!sourceOnly;
  desktopSharePickerSelectedSourceId = "";
  desktopSharePickerSources = [];
  desktopSharePickerBusy = false;
  desktopSharePickerBusyUi = false;
  desktopSharePickerLastClickSourceId = "";
  desktopSharePickerLastClickAt = 0;
  desktopSharePickerHoverActionLoggedSourceIds = new Set();
  desktopSharePickerServerVoicePresetRenderSignature = "";
  if (audioToggle) {
    if (desktopSharePickerMode === "server_voice") {
      audioToggle.checked = !!desktopSharePickerServerVoiceWithAudio;
      audioToggle.disabled = false;
    } else {
      audioToggle.checked = getShareAudioEnabled(); // always from localStorage â€” stays in sync with menu
      audioToggle.disabled = false;
    }
  }
  document.querySelectorAll("[data-desktop-share-tab]").forEach((btn) => {
    const tab = String(btn.getAttribute("data-desktop-share-tab") || "").trim().toLowerCase();
    btn.classList.toggle("is-active", tab === desktopSharePickerTab);
  });
  applySharePrefsToUi();
  syncDesktopSharePickerModeUi();
  syncDesktopSharePickerAudioToggleForMode();

  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  renderDesktopSharePickerSources();
  logDesktopSharePickerUiEvent("screenshare.preview_snapshot_refresh", {
    triggerReason: "picker_open_initial",
  });
  void reloadDesktopSharePickerSources({
    triggerReason: "picker_open_initial",
  });
  startDesktopSharePickerAutoRefresh({
    reason: "picker_opened",
  });

  return new Promise((resolve) => {
    desktopSharePickerResolve = resolve;
  });
}

function isShareCaptureCancelledError(error) {
  if (!error) return false;
  if (error.__sharePickerCancelled) return true;
  const name = String(error?.name || "").trim().toLowerCase();
  if (name === "aborterror" || name === "notallowederror") return true;
  const msg = String(error?.message || "").trim().toLowerCase();
  return (
    msg.includes("cancel")
    || msg.includes("dismiss")
    || msg.includes("aborted")
    || msg.includes("not allowed")
    || msg.includes("permission denied")
  );
}

async function captureDisplayStreamWithDesktopSource(sourceId, withAudio, options = {}) {
  const sid = String(sourceId || "").trim();
  if (!sid) throw new Error("Fonte de partilha invÃ¡lida.");

  const sourceKind = normalizeShareSourceKind(
    options?.sourceKind
    || inferShareSourceKindFromSourceId(sid)
    || "window"
  );
  const shareVideo = getShareVideoConstraints(sourceKind);
  const cursorMode = getShareCursorModeForSourceKind(sourceKind);
  const maxWidth = Number(shareVideo?.width?.max || shareVideo?.width?.ideal);
  const maxHeight = Number(shareVideo?.height?.max || shareVideo?.height?.ideal);
  const maxFramerate = Number(shareVideo?.frameRate?.max || shareVideo?.frameRate?.ideal || 60);

  const mandatoryVideo = {
    chromeMediaSource: "desktop",
    chromeMediaSourceId: sid,
  };
  if (Number.isFinite(maxWidth) && maxWidth > 0) mandatoryVideo.maxWidth = Math.round(maxWidth);
  if (Number.isFinite(maxHeight) && maxHeight > 0) mandatoryVideo.maxHeight = Math.round(maxHeight);
  if (Number.isFinite(maxFramerate) && maxFramerate > 0) mandatoryVideo.maxFrameRate = Math.round(maxFramerate);

  const constraints = {
    video: {
      mandatory: mandatoryVideo,
      optional: cursorMode ? [{ cursor: cursorMode }] : [],
    },
    audio: false,
  };

  if (withAudio) {
    constraints.audio = {
      mandatory: {
        chromeMediaSource: "desktop",
        chromeMediaSourceId: sid,
      },
    };
  }

  const stream = await navigator.mediaDevices.getUserMedia(constraints);
  const videoTrack = stream?.getVideoTracks?.()[0] || null;
  if (videoTrack) {
    try {
      await videoTrack.applyConstraints({
        ...getShareVideoConstraints(sourceKind),
        cursor: cursorMode,
      });
    } catch (_) {}
  }
  try {
    Object.defineProperty(stream, "__desktopSourceId", {
      value: sid,
      configurable: true,
      enumerable: false,
      writable: true,
    });
  } catch (_) {
    try { stream.__desktopSourceId = sid; } catch (_) {}
  }
  try {
    Object.defineProperty(stream, "__desktopSourceKind", {
      value: sourceKind,
      configurable: true,
      enumerable: false,
      writable: true,
    });
  } catch (_) {
    try { stream.__desktopSourceKind = sourceKind; } catch (_) {}
  }
  const sourceName = String(options?.sourceName || "").trim();
  if (sourceName) {
    try {
      Object.defineProperty(stream, "__desktopSourceName", {
        value: sourceName,
        configurable: true,
        enumerable: false,
        writable: true,
      });
    } catch (_) {
      try { stream.__desktopSourceName = sourceName; } catch (_) {}
    }
  }
  return stream;
}

async function requestDisplayStreamForSharing(withAudio, options = {}) {
  const forcedSourceId = String(options?.sourceIdOverride || "").trim();
  const forcedSourceKind = normalizeShareSourceKind(options?.sourceKindOverride || "");
  if (forcedSourceId && canUseDesktopSharePicker()) {
    return captureDisplayStreamWithDesktopSource(forcedSourceId, !!withAudio, { sourceKind: forcedSourceKind });
  }
  if (canUseDesktopSharePicker()) {
    const picked = await openDesktopSharePicker({ withAudio: !!withAudio });
    if (!picked?.sourceId) {
      let cancelErr = null;
      try {
        cancelErr = new DOMException("A partilha foi cancelada.", "AbortError");
      } catch (_) {
        cancelErr = new Error("A partilha foi cancelada.");
        cancelErr.name = "AbortError";
      }
      cancelErr.__sharePickerCancelled = true;
      throw cancelErr;
    }
    return captureDisplayStreamWithDesktopSource(picked.sourceId, !!picked.withAudio, {
      sourceKind: picked.sourceKind,
      sourceName: picked.sourceName,
    });
  }

  // Web picker does not expose the source kind before capture.
  // "motion" avoids the "ghost cursor" effect in games while keeping cursor visibility when useful.
  const cursorMode = "motion";
  const videoConstraints = {
    ...getShareVideoConstraints(),
    cursor: cursorMode,
  };
  return navigator.mediaDevices.getDisplayMedia({
    video: videoConstraints,
    audio: withAudio ? getShareAudioConstraints() : false,
  });
}

function getShareMaxBitrate(sourceKind = "") {
  const requested = getShareQualityValue();
  const q = getEffectiveShareQualityValue(requested, sourceKind);
  const profile = getShareProfileValue();
  const autoPerformance = shouldUseSharePerformanceMode(sourceKind, { requestedQuality: requested });
  if (autoPerformance) {
    if (requested === "source") return 6_000_000;
    if (requested === "2160p60") return 5_000_000;
    return 4_500_000;
  }
  if (profile === "clarity") {
    if (q === "1080p30") return 4_500_000;
    if (q === "1080p60") return 7_000_000;
    if (q === "2160p60") return 18_000_000;
    if (q === "source") return 24_000_000;
  }
  if (profile === "fluid") {
    if (q === "1080p30") return 3_500_000;
    if (q === "1080p60") return 4_500_000;
    if (q === "2160p60") return 6_000_000;
    if (q === "source") return 6_000_000;
  }
  if (q === "1080p30") return 3_500_000;
  if (q === "1080p60") return 5_000_000;
  if (q === "2160p60") return 14_000_000;
  if (q === "source") return 20_000_000;
  return 5_000_000;
}

function getShareMaxFramerate(sourceKind = "") {
  const requested = getShareQualityValue();
  const q = getEffectiveShareQualityValue(requested, sourceKind);
  const profile = getShareProfileValue();
  const autoPerformance = shouldUseSharePerformanceMode(sourceKind, { requestedQuality: requested });
  if (autoPerformance) return 30;
  if (profile === "clarity") return q === "1080p30" ? 30 : 60;
  if (profile === "fluid") return q === "1080p30" ? 30 : 60;
  if (q === "1080p30") return 30;
  if (q === "1080p60") return 60;
  if (q === "2160p60") return 60;
  if (q === "source") return 60;
  return 60;
}

function getShareQualityLabel(value = getShareQualityValue(), sourceKind = "") {
  const requested = SHARE_QUALITY_ALLOWED.has(String(value || "").trim())
    ? String(value || "").trim()
    : SHARE_QUALITY_DEFAULT;
  const q = getEffectiveShareQualityValue(requested, sourceKind);
  if (shouldUseSharePerformanceMode(sourceKind, { requestedQuality: requested }) && requested !== "1080p60") {
    if (normalizeShareSourceKind(sourceKind || "") === "window") {
      return "1080p 30fps (auto jogo)";
    }
    return "1080p 30fps (auto estabilidade)";
  }
  if (q === "1080p30") return "1080p 30fps";
  if (q === "2160p60") return "4K 60fps";
  if (q === "source") return "Source 60fps";
  return "1080p 60fps";
}

function getShareTrackSettingsLabel(track = null) {
  const settings = track?.getSettings?.() || {};
  const width = clampInt(settings?.width, 0, 10000, 0);
  const height = clampInt(settings?.height, 0, 10000, 0);
  const fpsRaw = Number(settings?.frameRate);
  const fps = Number.isFinite(fpsRaw) && fpsRaw > 0 ? Math.round(fpsRaw) : 0;
  if (width > 0 && height > 0 && fps > 0) return `${width}x${height} @ ${fps}fps`;
  if (width > 0 && height > 0) return `${width}x${height}`;
  if (fps > 0) return `${fps}fps`;
  return "";
}

function getShareQualityLimitLabel(track = null, qualityValue = getShareQualityValue(), sourceKind = "") {
  const requested = SHARE_QUALITY_ALLOWED.has(String(qualityValue || "").trim())
    ? String(qualityValue || "").trim()
    : SHARE_QUALITY_DEFAULT;
  const q = getEffectiveShareQualityValue(requested, sourceKind);
  const autoPerformance = shouldUseSharePerformanceMode(sourceKind, { requestedQuality: requested });
  if (autoPerformance && requested !== "1080p60") {
    return normalizeShareSourceKind(sourceKind || "") === "window"
      ? " • modo jogo automÃ¡tico"
      : " • modo estabilidade automÃ¡tico";
  }
  if (q !== "2160p60") return "";
  const settings = track?.getSettings?.() || {};
  const width = Number(settings?.width) || 0;
  const height = Number(settings?.height) || 0;
  if (width <= 0 || height <= 0) return "";
  if (width >= 3200 || height >= 1800) return "";
  return " • fonte nÃ£o Ã© 4K";
}

function getShareVideoSender() {
  const videoTransceiver = callPrimaryVideoTransceiver || callPc?.getTransceivers?.()[0] || null;
  const sender =
    callVideoSender ||
    videoTransceiver?.sender ||
    callPc?.getSenders?.().find((s) => s.track && s.track.kind === "video") ||
    callPc?.getSenders?.().find((s) => s.track == null) ||
    null;
  if (sender) callVideoSender = sender;
  return sender;
}

function getCameraVideoSender() {
  const cameraTransceiver = callCameraVideoTransceiver || callPc?.getTransceivers?.()[1] || null;
  const sender = callCameraSender || cameraTransceiver?.sender || null;
  if (sender) callCameraSender = sender;
  return sender;
}

function getLiveScreenTrack() {
  return screenStream?.getVideoTracks?.().find((t) => t.readyState === "live") || null;
}

function ensureMixedVideoEl() {
  const v = document.createElement("video");
  v.autoplay = true;
  v.muted = true;
  v.playsInline = true;
  v.style.display = "none";
  return v;
}

function drawVideoCover(ctx, source, x, y, w, h) {
  const vw = Math.max(1, Number(source?.videoWidth) || w || 1);
  const vh = Math.max(1, Number(source?.videoHeight) || h || 1);
  const scale = Math.max(w / vw, h / vh);
  const sw = Math.max(1, Math.round(w / scale));
  const sh = Math.max(1, Math.round(h / scale));
  const sx = Math.max(0, Math.round((vw - sw) / 2));
  const sy = Math.max(0, Math.round((vh - sh) / 2));
  ctx.drawImage(source, sx, sy, sw, sh, x, y, w, h);
}

function drawRoundedRectPath(ctx, x, y, w, h, radius) {
  const r = Math.max(0, Math.min(radius, Math.floor(Math.min(w, h) / 2)));
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y);
  ctx.arcTo(x + w, y, x + w, y + r, r);
  ctx.lineTo(x + w, y + h - r);
  ctx.arcTo(x + w, y + h, x + w - r, y + h, r);
  ctx.lineTo(x + r, y + h);
  ctx.arcTo(x, y + h, x, y + h - r, r);
  ctx.lineTo(x, y + r);
  ctx.arcTo(x, y, x + r, y, r);
  ctx.closePath();
}

function stopMixedVideoComposer() {
  if (mixedVideoFrameReq) {
    try { cancelAnimationFrame(mixedVideoFrameReq); } catch (_) {}
  }
  mixedVideoFrameReq = null;

  try {
    if (mixedVideoScreenEl) {
      mixedVideoScreenEl.pause?.();
      mixedVideoScreenEl.srcObject = null;
    }
  } catch (_) {}
  try {
    if (mixedVideoCameraEl) {
      mixedVideoCameraEl.pause?.();
      mixedVideoCameraEl.srcObject = null;
    }
  } catch (_) {}
  mixedVideoScreenEl = null;
  mixedVideoCameraEl = null;

  try {
    if (mixedVideoStream) mixedVideoStream.getTracks?.().forEach((t) => t.stop());
  } catch (_) {}
  mixedVideoStream = null;
  mixedVideoTrack = null;
  mixedVideoCanvas = null;
  mixedVideoCtx = null;
}

function renderMixedVideoFrame() {
  mixedVideoFrameReq = null;
  if (
    !mixedVideoCanvas ||
    !mixedVideoCtx ||
    !mixedVideoScreenEl ||
    !mixedVideoCameraEl ||
    !isScreenSharing ||
    !isCameraOn
  ) {
    return;
  }

  const screenTrack = getLiveScreenTrack();
  const cameraTrack = getLiveCameraTrack();
  if (!screenTrack || !cameraTrack) {
    mixedVideoFrameReq = requestAnimationFrame(renderMixedVideoFrame);
    return;
  }

  const screenSettings = screenTrack.getSettings?.() || {};
  const nextW = Math.max(640, Math.min(3840, Number(screenSettings.width) || mixedVideoCanvas.width || 1920));
  const nextH = Math.max(360, Math.min(2160, Number(screenSettings.height) || mixedVideoCanvas.height || 1080));
  if (mixedVideoCanvas.width !== nextW || mixedVideoCanvas.height !== nextH) {
    mixedVideoCanvas.width = nextW;
    mixedVideoCanvas.height = nextH;
  }

  const ctx = mixedVideoCtx;
  const cw = mixedVideoCanvas.width;
  const ch = mixedVideoCanvas.height;
  if (!cw || !ch) return;

  ctx.clearRect(0, 0, cw, ch);
  ctx.fillStyle = "#000";
  ctx.fillRect(0, 0, cw, ch);
  if (mixedVideoScreenEl.readyState >= 2) {
    try { drawVideoCover(ctx, mixedVideoScreenEl, 0, 0, cw, ch); } catch (_) {}
  }

  if (mixedVideoCameraEl.readyState >= 2) {
    const pad = Math.max(14, Math.round(cw * 0.02));
    const pipWidth = Math.max(220, Math.round(cw * 0.22));
    const pipHeight = Math.max(124, Math.round(pipWidth * (9 / 16)));
    const pipX = Math.max(0, cw - pipWidth - pad);
    const pipY = Math.max(0, ch - pipHeight - pad);
    const radius = Math.max(8, Math.round(pipWidth * 0.045));

    ctx.save();
    drawRoundedRectPath(ctx, pipX, pipY, pipWidth, pipHeight, radius);
    ctx.clip();
    try { drawVideoCover(ctx, mixedVideoCameraEl, pipX, pipY, pipWidth, pipHeight); } catch (_) {}
    ctx.restore();

    ctx.save();
    ctx.lineWidth = Math.max(2, Math.round(cw * 0.0022));
    ctx.strokeStyle = "rgba(255,255,255,0.92)";
    drawRoundedRectPath(ctx, pipX, pipY, pipWidth, pipHeight, radius);
    ctx.stroke();
    ctx.restore();
  }

  mixedVideoFrameReq = requestAnimationFrame(renderMixedVideoFrame);
}

function syncMixedVideoComposer() {
  const screenTrack = getLiveScreenTrack();
  const cameraTrack = getLiveCameraTrack();
  if (!screenTrack || !cameraTrack || !isScreenSharing || !isCameraOn) {
    stopMixedVideoComposer();
    return null;
  }

  if (!mixedVideoCanvas) {
    mixedVideoCanvas = document.createElement("canvas");
    mixedVideoCtx = mixedVideoCanvas.getContext("2d", { alpha: false });
    mixedVideoScreenEl = ensureMixedVideoEl();
    mixedVideoCameraEl = ensureMixedVideoEl();
  }
  if (!mixedVideoCtx || !mixedVideoScreenEl || !mixedVideoCameraEl) {
    stopMixedVideoComposer();
    return null;
  }

  const screenSettings = screenTrack.getSettings?.() || {};
  const nextW = Math.max(640, Math.min(3840, Number(screenSettings.width) || 1920));
  const nextH = Math.max(360, Math.min(2160, Number(screenSettings.height) || 1080));
  if (mixedVideoCanvas.width !== nextW || mixedVideoCanvas.height !== nextH) {
    mixedVideoCanvas.width = nextW;
    mixedVideoCanvas.height = nextH;
  }

  const bindTrackToVideo = (videoEl, track) => {
    const currentTrack = videoEl?.srcObject?.getVideoTracks?.()?.[0] || null;
    if (currentTrack?.id && currentTrack.id === track.id) return;
    const stream = new MediaStream();
    try { stream.addTrack(track); } catch (_) {}
    videoEl.srcObject = stream;
    try { videoEl.play().catch(() => {}); } catch (_) {}
  };

  bindTrackToVideo(mixedVideoScreenEl, screenTrack);
  bindTrackToVideo(mixedVideoCameraEl, cameraTrack);

  if (!mixedVideoStream || !mixedVideoTrack || mixedVideoTrack.readyState !== "live") {
    mixedVideoStream = mixedVideoCanvas.captureStream(Math.min(60, getShareMaxFramerate(getCurrentShareSourceKind())));
    mixedVideoTrack = mixedVideoStream?.getVideoTracks?.()?.[0] || null;
    try {
      if (mixedVideoTrack) mixedVideoTrack.contentHint = getShareVideoHintForSourceKind(getCurrentShareSourceKind());
    } catch (_) {}
  }

  if (!mixedVideoFrameReq) mixedVideoFrameReq = requestAnimationFrame(renderMixedVideoFrame);
  return mixedVideoTrack;
}

function getPreferredOutgoingVideoTrack() {
  const screenTrack = isScreenSharing ? getLiveScreenTrack() : null;
  const cameraTrack = isCameraOn ? getLiveCameraTrack() : null;
  stopMixedVideoComposer();
  if (screenTrack) return screenTrack;
  if (cameraTrack) return cameraTrack;
  return null;
}

function getSecondaryOutgoingVideoTrack() {
  if (!isScreenSharing || !isCameraOn) return null;
  return getLiveCameraTrack();
}

async function syncPreferredOutgoingVideoTrackOnSender(sender = null) {
  const activeSender = sender || getShareVideoSender();
  if (!activeSender) return null;
  const desiredTrack = getPreferredOutgoingVideoTrack();
  const currentTrack = activeSender.track || null;
  if (
    (currentTrack?.id || "") !== (desiredTrack?.id || "") ||
    (!!currentTrack !== !!desiredTrack)
  ) {
    await activeSender.replaceTrack(desiredTrack);
  }
  if (desiredTrack && isScreenSharing) {
    await applyShareSenderQuality(activeSender);
  }
  return desiredTrack;
}

async function syncSecondaryOutgoingVideoTrackOnSender(sender = null) {
  const activeSender = sender || getCameraVideoSender();
  if (!activeSender) return null;
  const desiredTrack = getSecondaryOutgoingVideoTrack();
  const currentTrack = activeSender.track || null;
  if (
    (currentTrack?.id || "") !== (desiredTrack?.id || "") ||
    (!!currentTrack !== !!desiredTrack)
  ) {
    await activeSender.replaceTrack(desiredTrack);
  }
  if (!desiredTrack) return null;
  try {
    const params = activeSender.getParameters?.() || {};
    if (!params.encodings || !params.encodings.length) params.encodings = [{}];
    params.encodings[0].maxBitrate = 4_000_000;
    params.encodings[0].maxFramerate = 30;
    await activeSender.setParameters?.(params);
  } catch (_) {}
  return desiredTrack;
}

async function applyShareEncodingProfileToSender(sender = null, { sourceKind = "", track = null } = {}) {
  const activeSender = sender || null;
  if (!activeSender) return;
  const qualityValue = getShareQualityValue();
  const profile = getShareProfileValue();
  const normalizedSourceKind = normalizeShareSourceKind(sourceKind || getCurrentShareSourceKind());
  const autoPerformance = shouldUseSharePerformanceMode(normalizedSourceKind, { requestedQuality: qualityValue });
  const effectiveQualityValue = getEffectiveShareQualityValue(qualityValue, normalizedSourceKind);
  const activeTrack = track || activeSender.track || null;
  const scaleDownBy = getShareScaleResolutionDownBy(activeTrack, qualityValue, normalizedSourceKind);
  const p = activeSender.getParameters?.() || {};
  if (profile === "clarity") {
    p.degradationPreference = "maintain-resolution";
  } else if (profile === "fluid") {
    p.degradationPreference = "maintain-framerate";
  } else {
    p.degradationPreference = (normalizedSourceKind === "window" || autoPerformance)
      ? "maintain-framerate"
      : "maintain-resolution";
  }
  if (!p.encodings || !p.encodings.length) p.encodings = [{}];
  p.encodings[0].maxBitrate = getShareMaxBitrate(normalizedSourceKind);
  p.encodings[0].maxFramerate = getShareMaxFramerate(normalizedSourceKind);
  if (effectiveQualityValue === "source" || scaleDownBy <= 1) {
    delete p.encodings[0].scaleResolutionDownBy;
  } else {
    p.encodings[0].scaleResolutionDownBy = scaleDownBy;
  }
  await activeSender.setParameters?.(p);
}

async function applyShareSenderQuality(sender = null) {
  const activeSender = sender || getShareVideoSender();
  if (!activeSender) return;
  try {
    await applyShareEncodingProfileToSender(activeSender, {
      sourceKind: getCurrentShareSourceKind(),
      track: activeSender.track || null,
    });
  } catch (e) {
    console.warn("set share quality params failed", e);
  }
}

function getRelayPrimaryVideoSender(entry = null) {
  const pc = entry?.pc || null;
  if (!pc) return null;
  const senders = (pc.getSenders?.() || []).filter((sender) => sender && (!sender.track || sender.track.kind === "video"));
  if (!senders.length) return null;
  const primaryTrackId = String(entry?.primaryTrackId || "");
  if (primaryTrackId) {
    const match = senders.find((sender) => String(sender?.track?.id || "") === primaryTrackId);
    if (match) return match;
  }
  return senders[0] || null;
}

async function applyRelayShareSenderQuality(conversationId = null) {
  if (!relayVideoSendPeersByUser.size) return;
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const sourceKind = getCurrentShareSourceKind();
  const tasks = [];
  relayVideoSendPeersByUser.forEach((entry) => {
    if (!entry?.pc) return;
    if (convId && normId(entry.conversationId || "") !== convId) return;
    const primarySender = getRelayPrimaryVideoSender(entry);
    if (!primarySender) return;
    tasks.push(applyShareEncodingProfileToSender(primarySender, {
      sourceKind,
      track: primarySender.track || null,
    }));
  });
  if (!tasks.length) return;
  await Promise.allSettled(tasks);
}

function bindScreenShareTrackHandlers(videoTrack, audioTrack) {
  if (videoTrack) {
    videoTrack.onended = () => {
      const activeVideoTrack = screenStream?.getVideoTracks?.()[0] || null;
      if (!isScreenSharing) return;
      if (!activeVideoTrack || activeVideoTrack.id !== videoTrack.id) return;
      stopScreenShare().catch?.(() => {});
    };
  }
  if (audioTrack) {
    audioTrack.onended = async () => {
      if (!isScreenSharing) return;
      const activeAudioTrack = screenStream?.getAudioTracks?.()[0] || null;
      if (!activeAudioTrack || activeAudioTrack.id !== audioTrack.id) return;
      try {
        if (callShareAudioSender) await callShareAudioSender.replaceTrack(null);
      } catch (_) {}
      try {
        screenStream?.removeTrack?.(audioTrack);
      } catch (_) {}
      refreshCallUI();
    };
  }
}

async function replaceDisplayStreamForSharing(withAudio, reason = "share_update", options = {}) {
  const wasAlreadySharing = !!(isScreenSharing && screenStream);
  let nextStream = null;
  try {
    nextStream = await requestDisplayStreamForSharing(withAudio, options);
  } catch (e) {
    if (isShareCaptureCancelledError(e)) throw e;
    if (!withAudio) throw e;
    nextStream = await requestDisplayStreamForSharing(false, options);
  }
  const nextVideoTrack = nextStream.getVideoTracks()[0];
  if (!nextVideoTrack) {
    try { nextStream.getTracks().forEach((t) => t.stop()); } catch (_) {}
    throw new Error("Sem track de vÃ­deo no ecrÃ£ partilhado.");
  }
  const nextSourceKind = normalizeShareSourceKind(
    options?.sourceKindOverride
    || nextStream?.__desktopSourceKind
    || inferShareSourceKindFromTrack(nextVideoTrack)
    || inferShareSourceKindFromSourceId(nextStream?.__desktopSourceId || "")
    || "window"
  );
  const shareVideoConstraints = {
    ...getShareVideoConstraints(nextSourceKind),
    cursor: getShareCursorModeForSourceKind(nextSourceKind),
  };
  try {
    Object.defineProperty(nextStream, "__desktopSourceKind", {
      value: nextSourceKind,
      configurable: true,
      enumerable: false,
      writable: true,
    });
  } catch (_) {
    try { nextStream.__desktopSourceKind = nextSourceKind; } catch (_) {}
  }
  try { await nextVideoTrack.applyConstraints(shareVideoConstraints); } catch (_) {}
  try { nextVideoTrack.contentHint = getShareVideoHintForSourceKind(nextSourceKind); } catch (_) {}
  const nextAudioTrack = nextStream.getAudioTracks()[0] || null;
  try { if (nextAudioTrack) nextAudioTrack.contentHint = "music"; } catch (_) {}

  const sender = getShareVideoSender();
  if (!sender) {
    try { nextStream.getTracks().forEach((t) => t.stop()); } catch (_) {}
    throw new Error("Canal de vÃ­deo nÃ£o estÃ¡ pronto para partilha.");
  }
  let createdShareAudioSender = false;

  if (!isScreenSharing) {
    originalVideoTrack = getLiveCameraTrack() || sender.track || null;
  }

  const prevStream = screenStream;
  screenStream = nextStream;
  isScreenSharing = true;
  const activeDesktopSourceId = String(nextStream?.__desktopSourceId || "").trim();
  const activeDesktopSourceKind = normalizeShareSourceKind(nextSourceKind || nextStream?.__desktopSourceKind || "");
  const activeDesktopSourceName = String(
    nextStream?.__desktopSourceName
    || options?.sourceNameOverride
    || nextVideoTrack?.label
    || ""
  ).trim();
  desktopShareActiveSourceId = activeDesktopSourceId;
  desktopShareActiveSourceKind = activeDesktopSourceKind;
  desktopShareActiveSourceName = activeDesktopSourceName;
  bindScreenShareTrackHandlers(nextVideoTrack, nextAudioTrack);

  const outgoingTrack = await syncPreferredOutgoingVideoTrackOnSender(sender);
  await syncSecondaryOutgoingVideoTrackOnSender();
  if (!outgoingTrack) {
    if (prevStream !== nextStream) screenStream = prevStream;
    isScreenSharing = !!getLiveScreenTrack();
    try { nextStream.getTracks().forEach((t) => t.stop()); } catch (_) {}
    setLocalSharePreviewStream(getPreferredLocalPreviewStream());
    throw new Error("Falhou ao ligar o vÃ­deo da partilha.");
  }

  if (nextAudioTrack) {
    if (callShareAudioSender) {
      await callShareAudioSender.replaceTrack(nextAudioTrack);
    } else {
      const shareAudioStream = new MediaStream();
      try { shareAudioStream.addTrack(nextAudioTrack); } catch (_) {}
      callShareAudioSender = callPc.addTrack(nextAudioTrack, shareAudioStream);
      createdShareAudioSender = true;
    }
    await applyAudioSenderQuality(callShareAudioSender, { music: true });
  } else if (callShareAudioSender) {
    await callShareAudioSender.replaceTrack(null);
  }

  // Swap local preview after sender update so source changes look seamless.
  setLocalSharePreviewStream(screenStream);

  if (prevStream && prevStream !== nextStream) {
    try {
      prevStream.getTracks().forEach((t) => {
        t.onended = null;
        t.stop();
      });
    } catch (_) {}
  }

  await sendShareStateSignal(true, "share");
  await syncRelayVideoBroadcastTargets(callConversationId || activeDmId || "");
  const shouldRenegotiate = !!(
    !wasAlreadySharing
    || createdShareAudioSender
  );
  const skipRenegotiate = !shouldRenegotiate;
  if (!skipRenegotiate) {
    await renegotiateCall(reason);
  }
  refreshCallUI();
  const activeConvId = normId(callConversationId || activeDmId || "");
  if (activeConvId) {
    void syncRelayAudioPeers(activeConvId, { force: true });
  }
}

async function applyShareSettingsLive(mode = "all") {
  if (!isScreenSharing || !inCall || !callPc) return;
  if (isApplyingShareSettings) return;
  isApplyingShareSettings = true;

  try {
    const wantsAudio = getShareAudioEnabled();
    const currentAudioTrack = screenStream?.getAudioTracks?.()[0] || null;
    const sourceKind = getCurrentShareSourceKind();
    let qualityApplied = true;
    let qualityReacquired = false;

    // Enabling system audio on web usually requires a new getDisplayMedia prompt.
    if (mode !== "quality" && wantsAudio && !currentAudioTrack) {
      try {
        const options = (canUseDesktopSharePicker() && desktopShareActiveSourceId)
          ? { sourceIdOverride: desktopShareActiveSourceId, sourceKindOverride: desktopShareActiveSourceKind }
          : {};
        await replaceDisplayStreamForSharing(true, "share_audio_on", options);
        return;
      } catch (err) {
        setCallStatus(t("call.share.audio_reselect_needed", "Could not enable audio without re-selecting the window/screen."), true);
        setTimeout(() => setCallStatus("", false), 2200);
      }
    }

    const screenTrack = screenStream?.getVideoTracks?.()[0] || null;
    if (screenTrack) {
      try {
        await screenTrack.applyConstraints({
          ...getShareVideoConstraints(sourceKind),
          cursor: getShareCursorModeForSourceKind(sourceKind),
        });
      } catch (e) {
        qualityApplied = false;
        console.warn("share quality applyConstraints failed", e);
      }
      try { screenTrack.contentHint = getShareVideoHintForSourceKind(sourceKind); } catch (_) {}
    }

    if (
      mode === "quality"
      && !qualityApplied
      && canUseDesktopSharePicker()
      && desktopShareActiveSourceId
    ) {
      try {
        await replaceDisplayStreamForSharing(wantsAudio, "share_change", {
          sourceIdOverride: desktopShareActiveSourceId,
          sourceKindOverride: desktopShareActiveSourceKind,
        });
        qualityApplied = true;
        qualityReacquired = true;
      } catch (recaptureErr) {
        console.warn("share quality recapture failed", recaptureErr);
      }
    }

    await applyShareSenderQuality();
    await applyRelayShareSenderQuality(callConversationId || activeDmId || "");

    if (mode === "quality") {
      const qualityValue = getShareQualityValue();
      const activeTrack = screenStream?.getVideoTracks?.()[0] || null;
      const limitLabel = getShareQualityLimitLabel(activeTrack, qualityValue, sourceKind);
      const snapshot = getLocalShareStateSnapshot(true);
      const appliedLabel = getShareTrackSettingsLabel(activeTrack);
      const qualityLabel = [getShareProfileLabel(), buildShareMetaText(snapshot, {
        includeSource: false,
        includeProfile: false,
        includeQuality: true,
        includeApplied: false,
        includeAudio: true,
      })].filter(Boolean).join(" • ");
      const qualitySuffix = qualityApplied ? "" : " • " + t("call.share.quality_limited", "(limited by browser)");
      const appliedSuffix = appliedLabel ? ` • ${appliedLabel}` : "";
      const recaptureSuffix = qualityReacquired ? " • " + t("call.share.quality_recaptured", "updated") : "";
      setCallStatus(t("call.share.quality_updated", "Share quality: {quality}").replace("{quality}", qualityLabel + appliedSuffix + limitLabel + recaptureSuffix + qualitySuffix), true);
      setTimeout(() => setCallStatus("", false), 1500);
    }

    if (mode !== "quality") {
      if (!wantsAudio) {
        if (currentAudioTrack) {
          try { currentAudioTrack.stop(); } catch (_) {}
          try { screenStream?.removeTrack?.(currentAudioTrack); } catch (_) {}
        }
        if (callShareAudioSender) await callShareAudioSender.replaceTrack(null);
        await renegotiateCall("share_audio_off");
      } else if (currentAudioTrack) {
        try { currentAudioTrack.contentHint = "music"; } catch (_) {}
        let createdSender = false;
        if (callShareAudioSender) {
          await callShareAudioSender.replaceTrack(currentAudioTrack);
        } else {
          const shareAudioStream = new MediaStream();
          try { shareAudioStream.addTrack(currentAudioTrack); } catch (_) {}
          callShareAudioSender = callPc.addTrack(currentAudioTrack, shareAudioStream);
          createdSender = true;
        }
        await applyAudioSenderQuality(callShareAudioSender, { music: true });
        if (createdSender) await renegotiateCall("share_audio_on");
      }
    }

    refreshCallUI();
  } finally {
    isApplyingShareSettings = false;
  }
}

function setStageFocus(nextFocus, opts = {}) {
  const raw = String(nextFocus || "").trim();
  const prevFocus = String(stageFocus || "").trim();
  const prevMemberId = normId(stageFocusMemberId || "");
  const prevFocusedTileId = String(stageFocusedTileId || "").trim();
  const prevFocusedIdentity = parseStageParticipantTileId(prevFocusedTileId);
  const requestedTileId = String(opts?.tileId || "").trim();
  const requestedParticipantId = normId(opts?.participantId || "");
  const requestedTileType = String(opts?.tileType || "").trim().toLowerCase();
  const preservedMemberId = raw === "member" ? normId(stageFocusMemberId || "") : "";
  const nextMemberId = raw.startsWith("member:") ? normId(raw.slice(7)) : preservedMemberId;
  if (nextMemberId) {
    stageFocus = "member";
    stageFocusMemberId = nextMemberId;
    if (nextMemberId !== prevMemberId) {
      stageFocusMemberTrackId = "";
      stageFocusMemberMediaType = "";
    }
  } else if (raw === "self") {
    stageFocus = "self";
    stageFocusMemberId = "";
    stageFocusMemberTrackId = "";
    stageFocusMemberMediaType = "";
  } else {
    stageFocus = "remote";
    stageFocusMemberId = "";
    stageFocusMemberTrackId = "";
    stageFocusMemberMediaType = "";
  }

  const preserveExistingTileId = !!(
    !requestedTileId
    && prevFocusedTileId
    && (
      raw === prevFocus
      || (
        raw.startsWith("member:")
        && prevFocus === "member"
        && nextMemberId
        && nextMemberId === prevMemberId
      )
    )
  );
  const fallbackFocusedIdentity = resolveFocusedTileIdentityFromCurrentStageFocus();
  const requestedIdParsed = parseStageParticipantTileId(requestedTileId);
  const resolvedParticipantId = normId(
    requestedParticipantId
    || requestedIdParsed.participantId
    || (preserveExistingTileId ? prevFocusedIdentity.participantId : "")
    || fallbackFocusedIdentity.participantId
    || ""
  );
  const resolvedTileType = normalizeStageTileType(
    requestedTileType
    || requestedIdParsed.tileType
    || (preserveExistingTileId ? prevFocusedIdentity.tileType : "")
    || fallbackFocusedIdentity.tileType
    || "primary"
  );
  const resolvedTileId = String(
    requestedTileId
    || (preserveExistingTileId ? prevFocusedTileId : "")
    || buildStageParticipantTileId(resolvedParticipantId, resolvedTileType)
    || fallbackFocusedIdentity.tileId
    || ""
  ).trim();
  stageFocusedTileId = resolvedTileId;
  if (requestedTileId && stageFocusedTileId && stageFocusedTileId !== requestedTileId) {
    assertStageFocusMatchesClickedTile({
      tileId: requestedTileId,
      tileType: requestedTileType || requestedIdParsed.tileType || resolvedTileType,
      participantId: requestedParticipantId || requestedIdParsed.participantId || resolvedParticipantId,
      triggerReason: String(opts?.triggerReason || "").trim() || "set_stage_focus_requested_tile_mismatch",
      callerFunction: String(opts?.callerFunction || "").trim() || "setStageFocus",
    });
  }

  const stage = document.getElementById("callStage");
  stage?.classList.toggle("focus-self", stageFocus === "self");
  stage?.classList.toggle("focus-remote", stageFocus === "remote");
  stage?.classList.toggle("focus-member", stageFocus === "member");
  if (stage) {
    stage.setAttribute("data-focused-tile-id", stageFocusedTileId || "");
    stage.setAttribute("data-focused-tile-type", resolvedTileType || "");
    stage.setAttribute("data-focused-participant-id", resolvedParticipantId || "");
  }

  const tileRemote = document.getElementById("tileRemote");
  const tileRemoteAux = document.getElementById("tileRemoteAux");
  const tileSelf = document.getElementById("tileSelf");
  const tileSelfAux = document.getElementById("tileSelfAux");
  const gridRemote = document.getElementById("gridRemote");
  const gridRemoteAux = document.getElementById("gridRemoteAux");
  const gridSelf = document.getElementById("gridSelf");
  const gridSelfAux = document.getElementById("gridSelfAux");
  const remotePrimaryActiveFallback = stageFocus === "remote" && stageFocusRemoteSlot !== "aux";
  const remoteAuxActiveFallback = stageFocus === "remote" && stageFocusRemoteSlot === "aux";
  const selfPrimaryActiveFallback = stageFocus === "self" && stageFocusSelfSlot !== "aux";
  const selfAuxActiveFallback = stageFocus === "self" && stageFocusSelfSlot === "aux";

  const getElementFocusState = (el, fallback) => {
    const identity = getStageTileIdentityFromEl(el);
    if (stageFocusedTileId && identity.tileId) {
      return identity.tileId === stageFocusedTileId;
    }
    return !!fallback;
  };

  tileRemote?.classList.toggle("is-active", getElementFocusState(tileRemote, remotePrimaryActiveFallback));
  tileRemoteAux?.classList.toggle("is-active", getElementFocusState(tileRemoteAux, remoteAuxActiveFallback));
  tileSelf?.classList.toggle("is-active", getElementFocusState(tileSelf, selfPrimaryActiveFallback));
  tileSelfAux?.classList.toggle("is-active", getElementFocusState(tileSelfAux, selfAuxActiveFallback));
  gridRemote?.classList.toggle("is-active", getElementFocusState(gridRemote, remotePrimaryActiveFallback));
  gridRemoteAux?.classList.toggle("is-active", getElementFocusState(gridRemoteAux, remoteAuxActiveFallback));
  gridSelf?.classList.toggle("is-active", getElementFocusState(gridSelf, selfPrimaryActiveFallback));
  gridSelfAux?.classList.toggle("is-active", getElementFocusState(gridSelfAux, selfAuxActiveFallback));

  const focusedMemberId = normId(stageFocusMemberId || "");
  const focusedMemberTrackId = normId(stageFocusMemberTrackId || "");
  const focusedMemberMediaTypeRaw = String(stageFocusMemberMediaType || "").trim().toLowerCase();
  const focusedMemberMediaType = focusedMemberMediaTypeRaw === "base"
    ? "base"
    : normalizeRelayMediaKind(focusedMemberMediaTypeRaw || "");
  document.querySelectorAll(".stageGridTile[data-call-extra='1'], .stageGridTile[data-call-grid-entry='1']").forEach((el) => {
    const identity = getStageTileIdentityFromEl(el);
    const uid = normId(el.getAttribute("data-call-user-id") || "");
    const trackId = normId(el.getAttribute("data-call-video-track-id") || "");
    const mediaTypeRaw = String(el.getAttribute("data-call-media-type") || "").trim().toLowerCase();
    const mediaType = mediaTypeRaw === "base" ? "base" : normalizeRelayMediaKind(mediaTypeRaw);
    let isActive = false;
    if (stageFocusedTileId && identity.tileId) {
      isActive = identity.tileId === stageFocusedTileId;
    } else {
      const isFocusedMember = stageFocus === "member" && !!uid && uid === focusedMemberId;
      isActive = isFocusedMember;
      if (isFocusedMember && focusedMemberTrackId) {
        isActive = !!trackId && trackId === focusedMemberTrackId;
        if (!isActive && focusedMemberMediaType) {
          isActive = mediaType === focusedMemberMediaType;
        }
      } else if (isFocusedMember && focusedMemberMediaType) {
        isActive = mediaType === focusedMemberMediaType;
      }
    }
    el.classList.toggle("is-active", isActive);
  });

  const focusChanged = prevFocus !== stageFocus || prevFocusedTileId !== stageFocusedTileId;
  if (focusChanged) {
    const focusedIdentity = parseStageParticipantTileId(stageFocusedTileId);
    logStageTileEvent("stage.focus_changed", {
      tileId: stageFocusedTileId || "",
      tileType: focusedIdentity.tileType || resolvedTileType,
      participantId: focusedIdentity.participantId || resolvedParticipantId,
      triggerReason: String(opts?.triggerReason || "").trim() || "set_stage_focus",
      callerFunction: String(opts?.callerFunction || "").trim() || "setStageFocus",
      previousFocus: prevFocus || null,
      nextFocus: stageFocus || null,
      previousFocusedTileId: prevFocusedTileId || null,
      nextFocusedTileId: stageFocusedTileId || null,
    });
  }
}

function clearExtraCallStageMembers() {
  const grid = document.getElementById("callStageGrid");
  if (!grid) return;
  const convId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (convId) clearServerVoiceStageTileDerivationState(convId);
  const viewport = document.querySelector("#callStage .callStageViewport");
  if (stageFocus === "member") {
    stageFocus = "remote";
    stageFocusMemberId = "";
    stageFocusMemberTrackId = "";
    stageFocusMemberMediaType = "";
    stageFocusedTileId = "";
  }
  stageFocusTransitionExpiresAt = 0;
  stageFocusTransitionTargetTileId = "";
  grid.querySelectorAll("[data-call-extra='1'], [data-call-grid-entry='1']").forEach((el) => {
    try {
      const videoEl = el.querySelector(".stageGridVideo");
      if (videoEl) {
        videoEl.pause?.();
        videoEl.srcObject = null;
        videoEl.removeAttribute?.("src");
        videoEl.load?.();
      }
    } catch (_) {}
    el.remove();
  });
  grid.style.setProperty("--call-grid-cols", "2");
  grid.style.setProperty("--call-grid-rows", "1");
  grid.setAttribute("data-tile-count", "0");
  grid.setAttribute("data-grid-rows", "1");
  grid.setAttribute("data-last-fill", "0");
  grid.setAttribute("data-odd-last", "0");
  grid.setAttribute("aria-label", "Participantes");
  viewport?.removeAttribute("data-stage-tile-count");
}

function getCallStageGridCols(totalTiles) {
  const count = Math.max(1, Number(totalTiles) || 1);
  if (count <= 1) return 1;
  if (count <= 3) return count;
  if (count <= 4) return 2;
  if (count <= 9) return 3;
  return 4;
}

function getCallStageGridRows(totalTiles, cols) {
  const count = Math.max(1, Number(totalTiles) || 1);
  const safeCols = Math.max(1, Number(cols) || 1);
  return Math.max(1, Math.ceil(count / safeCols));
}

function isCallStageGridTileVisible(tile) {
  if (!tile) return false;
  if (tile.hidden) return false;
  if (String(tile.style?.display || "").trim().toLowerCase() === "none") return false;
  return true;
}

function syncCallStageGridLayoutAttrs(grid = null, viewport = null) {
  const gridEl = grid || document.getElementById("callStageGrid");
  if (!gridEl) return;
  const viewportEl = viewport || document.querySelector("#callStage .callStageViewport");
  const totalTiles = Math.max(
    1,
    Array.from(gridEl.querySelectorAll(".stageGridTile")).filter(isCallStageGridTileVisible).length,
  );
  const cols = getCallStageGridCols(totalTiles);
  const rows = getCallStageGridRows(totalTiles, cols);
  gridEl.style.setProperty("--call-grid-cols", String(cols));
  gridEl.style.setProperty("--call-grid-rows", String(rows));
  const rect = gridEl.getBoundingClientRect?.() || null;
  const style = window.getComputedStyle ? window.getComputedStyle(gridEl) : null;
  const gap = Number.parseFloat(style?.columnGap || style?.gap || "10") || 10;
  const rowGap = Number.parseFloat(style?.rowGap || style?.gap || "10") || gap;
  const paddingX = (Number.parseFloat(style?.paddingLeft || "0") || 0) + (Number.parseFloat(style?.paddingRight || "0") || 0);
  const paddingY = (Number.parseFloat(style?.paddingTop || "0") || 0) + (Number.parseFloat(style?.paddingBottom || "0") || 0);
  const gridWidth = Math.max(0, Number(rect?.width || 0) - paddingX - (gap * Math.max(0, cols - 1)));
  const gridHeight = Math.max(0, Number(rect?.height || 0) - paddingY - (rowGap * Math.max(0, rows - 1)));
  const cellWidth = gridWidth > 0 ? (gridWidth / cols) : 0;
  const rowHeight = gridHeight > 0 ? (gridHeight / rows) : 0;
  const ratioWidth = 16 / 9;
  const tileWidth = Math.floor(Math.min(
    cellWidth || 640,
    rowHeight ? rowHeight * ratioWidth : (cellWidth || 640),
  ));
  if (tileWidth > 0) {
    gridEl.style.setProperty("--call-grid-tile-width", `${Math.max(220, tileWidth)}px`);
  } else {
    gridEl.style.removeProperty("--call-grid-tile-width");
  }
  gridEl.setAttribute("data-tile-count", String(totalTiles));
  gridEl.setAttribute("data-grid-rows", String(Math.min(rows, 5)));
  const rem = totalTiles % cols;
  let lastFillMode = "0";
  if (cols === 2 && totalTiles > cols && rem === 1) {
    lastFillMode = "1";
  } else if (cols === 3 && totalTiles > cols && rem === 2) {
    lastFillMode = "2";
  }
  gridEl.setAttribute("data-last-fill", lastFillMode);
  gridEl.setAttribute("data-odd-last", lastFillMode === "1" ? "1" : "0");
  gridEl.setAttribute("aria-label", `Participantes (${totalTiles})`);
  viewportEl?.setAttribute("data-stage-tile-count", String(totalTiles));
}

function syncCallFocusStageLayoutAttrs(viewport = null) {
  const viewportEl = viewport || document.querySelector("#callStage .callStageViewport");
  if (!viewportEl) return;
  const rect = viewportEl.getBoundingClientRect?.() || null;
  const width = Number(rect?.width || 0);
  const height = Number(rect?.height || 0);
  if (!(width > 0 && height > 0)) {
    viewportEl.style.removeProperty("--call-focus-tile-width");
    return;
  }
  const stage = document.getElementById("callStage");
  const reserveBottom = stage?.classList.contains("is-private-call-ui") ? 82 : 8;
  const availableWidth = Math.max(0, width - 16);
  const availableHeight = Math.max(0, height - reserveBottom - 16);
  const tileWidth = Math.floor(Math.min(availableWidth, availableHeight * (16 / 9)));
  if (tileWidth > 0) {
    viewportEl.style.setProperty("--call-focus-tile-width", `${Math.max(280, tileWidth)}px`);
  } else {
    viewportEl.style.removeProperty("--call-focus-tile-width");
  }
}

function getEffectiveGroupCallActiveUserIds(conversationId) {
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return [];
  const meId = normId(state.user?.id || "");
  const sameConversation = normId(callConversationId || "") === convId;
  const useLiveKitTransport = shouldUseServerVoiceLiveKitTransport(convId);
  const localCallContext = !!(
    sameConversation && (
      inCall ||
      pendingOffer ||
      pendingGroupRingInfo ||
      ringTimeout ||
      (callPc && callPc.connectionState !== "closed" && callPc.connectionState !== "failed")
    )
  );
  const suppressed = useLiveKitTransport ? null : getSuppressedGroupDmConnectedSet(convId, false);

  const seen = new Set();
  const out = [];
  const push = (value) => {
    const uid = normId(value);
    if (suppressed && suppressed.has(uid)) return;
    if (!uid || seen.has(uid)) return;
    seen.add(uid);
    out.push(uid);
  };

  if (useLiveKitTransport) {
    getServerVoiceInCallParticipants(convId, {
      triggerReason: "effective_group_call_active_ids",
      callerFunction: "getEffectiveGroupCallActiveUserIds",
    }).forEach((participant) => push(participant?.userId || ""));
    return out;
  }

  const presenceConvId = normId(groupCallActiveMembersConversationId || "");
  if (!presenceConvId || presenceConvId === convId) {
    normalizeUuidArray(groupCallActiveMemberIds).forEach(push);
  }

  const session = getCachedGroupDmCallState(convId);
  const isSessionActive = !!(
    session?.active
    && String(session?.status || "") === "active"
  );
  if (isSessionActive && localCallContext) {
    normalizeUuidArray(session?.connectedUserIds || []).forEach(push);
  }

  // Safety net: always keep self while local call context is active.
  // LiveKit server voice remote membership is transport-driven.
  if (localCallContext) {
    if (meId) push(meId);
    if (!isServerVoiceConversationById(convId)) {
      const currentPeerId = normId(callMediaPeerUserId || callOtherUserId || "");
      if (currentPeerId) push(currentPeerId);
    }
  }

  return out;
}

function hydrateActiveCallMemberProfiles(conversationId, memberIds = []) {
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return;
  const meId = normId(state.user?.id || "");
  const ids = normalizeUuidArray(memberIds).filter((uid) => uid && uid !== meId);
  if (!ids.length) return;

  const fingerprint = `${convId}:${ids.slice().sort().join(",")}`;
  const now = Date.now();
  if (callMemberProfilesHydrateInFlight && callMemberProfilesHydrateFingerprint === fingerprint) return;
  if (
    callMemberProfilesHydrateFingerprint === fingerprint
    && (now - callMemberProfilesHydrateAt) < CALL_MEMBER_PROFILES_HYDRATE_THROTTLE_MS
  ) {
    return;
  }

  callMemberProfilesHydrateInFlight = true;
  callMemberProfilesHydrateFingerprint = fingerprint;
  callMemberProfilesHydrateAt = now;

  void fetchProfilesByIds(ids, { includeBio: false, force: true })
    .then(() => {
      const activeConv = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
      if (activeConv === convId) refreshCallUI();
    })
    .catch(() => {})
    .finally(() => {
      callMemberProfilesHydrateInFlight = false;
    });
}

function sortGroupCallMemberIdsForLayout(conversationId, ids = []) {
  const unique = normalizeUuidArray(ids);
  if (!unique.length) return [];
  return unique.slice().sort((a, b) => String(a || "").localeCompare(String(b || "")));
}

function resolveGroupCallPrimaryRemoteMember(conversationId) {
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return null;
  const presenceConvId = normId(groupCallActiveMembersConversationId || "");
  const meId = normId(state.user?.id || "");
  const activeIds = sortGroupCallMemberIdsForLayout(
    convId,
    getEffectiveGroupCallActiveUserIds(convId).filter((id) => id && id !== meId)
  );
  if (!activeIds.length && presenceConvId && presenceConvId !== convId) return null;
  if (!activeIds.length) return null;
  const uid = activeIds.find((id) => id && id !== meId) || "";
  if (!uid) return null;
  const member = getGroupMemberIdentity(convId, uid);
  return {
    userId: uid,
    label: member?.label || t("call.member", "member"),
    avatar: member?.avatar || null,
  };
}

function getGroupCallStageExtraMemberIds(conversationId) {
  const convId = normId(conversationId || "");
  if (!convId) return [];
  const presenceConvId = normId(groupCallActiveMembersConversationId || "");
  const meId = normId(state.user?.id || "");
  const preferredRemote = resolveGroupCallPrimaryRemoteMember(convId);
  const remoteId = normId(preferredRemote?.userId || "");
  const activeIds = sortGroupCallMemberIdsForLayout(
    convId,
    getEffectiveGroupCallActiveUserIds(convId)
  );
  if (!activeIds.length && presenceConvId && presenceConvId !== convId) return [];

  const seen = new Set();
  const all = [];
  const push = (value) => {
    const uid = normId(value);
    if (!uid || seen.has(uid)) return;
    seen.add(uid);
    all.push(uid);
  };

  activeIds.forEach(push);
  if (groupCallMode && meId) push(meId);
  if (remoteId && activeIds.includes(remoteId)) push(remoteId);

  return all.filter((uid) => uid !== meId && uid !== remoteId);
}

function collectGroupCallRemoteVideoTracksByUser() {
  const byUser = new Map();
  const convId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (convId && shouldUseServerVoiceLiveKitTransport(convId)) {
    return getServerVoiceRemoteCameraVideoTracksByUser(convId);
  }
  const meId = normId(state.user?.id || "");
  const directOwnerId = groupCallMode ? "" : normId(callMediaPeerUserId || callOtherUserId || "");
  const upsertTrack = (ownerUserId, track, { secondary = false, mediaKind = "" } = {}) => {
    const uid = normId(ownerUserId || "");
    if (!uid || uid === meId || !isLiveVideoTrack(track, { allowMuted: true })) return;
    const key = secondary ? "secondary" : "primary";
    const kindKey = secondary ? "secondaryKind" : "primaryKind";
    const normalizedKind = normalizeRelayMediaKind(mediaKind || "");
    const entry = byUser.get(uid) || { primary: null, secondary: null, primaryKind: "", secondaryKind: "" };
    const prev = entry[key];
    const nextLiveUnmuted = isLiveVideoTrack(track, { allowMuted: false });
    const prevLiveUnmuted = isLiveVideoTrack(prev, { allowMuted: false });
    if (!prev || (!prevLiveUnmuted && nextLiveUnmuted)) {
      entry[key] = track;
      if (normalizedKind) entry[kindKey] = normalizedKind;
      byUser.set(uid, entry);
    } else if (prev?.readyState !== "live" && track?.readyState === "live") {
      entry[key] = track;
      if (normalizedKind) entry[kindKey] = normalizedKind;
      byUser.set(uid, entry);
    } else if (normalizedKind && !entry[kindKey]) {
      entry[kindKey] = normalizedKind;
      byUser.set(uid, entry);
    }
  };

  if (!groupCallMode && remoteVideoTrackRef) {
    upsertTrack(remotePrimarySourceUserId || directOwnerId, remoteVideoTrackRef, { secondary: false, mediaKind: "" });
  }
  if (!groupCallMode && remoteCameraTrackRef) {
    upsertTrack(remoteAuxSourceUserId || directOwnerId, remoteCameraTrackRef, { secondary: true, mediaKind: "camera" });
  }

  const directTransceivers = callPc?.getTransceivers?.() || [];
  for (let idx = 0; idx < directTransceivers.length; idx++) {
    const tx = directTransceivers[idx];
    const track = tx?.receiver?.track || null;
    if (!track || track.kind !== "video") continue;
    const isSecondary = callCameraVideoTransceiver ? (tx === callCameraVideoTransceiver) : idx === 1;
    upsertTrack(directOwnerId, track, { secondary: isSecondary, mediaKind: isSecondary ? "camera" : "" });
  }

  for (const [relayUserId, relayEntry] of relayVideoRecvPeersByUser.entries()) {
    const primaryOwnerId = getRelayRecvEntryTrackOwner(relayEntry, relayUserId, "primary");
    const secondaryOwnerId = getRelayRecvEntryTrackOwner(relayEntry, relayUserId, "secondary");
    const primaryMediaKind = normalizeRelayMediaKind(relayEntry?.primaryMediaKind || "");
    const secondaryMediaKind = normalizeRelayMediaKind(relayEntry?.secondaryMediaKind || "");
    const allowSecondary = !!relayEntry?.hasSecondary;
    const relayTransceivers = relayEntry?.pc?.getTransceivers?.() || [];
    if (relayTransceivers.length) {
      for (let idx = 0; idx < relayTransceivers.length; idx++) {
        const track = relayTransceivers[idx]?.receiver?.track || null;
        if (!track || track.kind !== "video") continue;
        if (idx === 1 && !allowSecondary) continue;
        const ownerId = idx === 1 ? secondaryOwnerId : primaryOwnerId;
        if (!ownerId) continue;
        const kind = idx === 1
          ? (secondaryMediaKind || "camera")
          : (primaryMediaKind || "");
        upsertTrack(ownerId, track, { secondary: idx === 1, mediaKind: kind });
      }
      continue;
    }
    if (!primaryOwnerId) continue;
    const receivers = relayEntry?.pc?.getReceivers?.() || [];
    for (const receiver of receivers) {
      const track = receiver?.track || null;
      if (!track || track.kind !== "video") continue;
      upsertTrack(primaryOwnerId, track, { secondary: false, mediaKind: primaryMediaKind || "" });
    }
  }

  return byUser;
}

function pickBestGroupCallMemberVideoTrack(videoEntry) {
  if (!videoEntry) return null;
  const primary = isLiveVideoTrack(videoEntry.primary, { allowMuted: false }) ? videoEntry.primary : null;
  const secondary = isLiveVideoTrack(videoEntry.secondary, { allowMuted: false }) ? videoEntry.secondary : null;
  const primaryUnmuted = isLiveVideoTrack(primary, { allowMuted: false }) ? primary : null;
  const secondaryUnmuted = isLiveVideoTrack(secondary, { allowMuted: false }) ? secondary : null;
  return primaryUnmuted || secondaryUnmuted || null;
}

function pickFocusedGroupCallMemberVideoTrack(videoEntry, opts = {}) {
  if (!videoEntry) return null;
  const preferredTrackId = normId(opts?.trackId || "");
  const preferredMediaType = normalizeRelayMediaKind(opts?.mediaType || "");
  const allowMutedFallback = !!opts?.allowMutedFallback;
  const strictPreferredMediaType = !!opts?.strictPreferredMediaType;
  const primaryStrict = isLiveVideoTrack(videoEntry.primary, { allowMuted: false }) ? videoEntry.primary : null;
  const secondaryStrict = isLiveVideoTrack(videoEntry.secondary, { allowMuted: false }) ? videoEntry.secondary : null;
  const primary = primaryStrict || (
    allowMutedFallback && isLiveVideoTrack(videoEntry.primary, { allowMuted: true })
      ? videoEntry.primary
      : null
  );
  const secondary = secondaryStrict || (
    allowMutedFallback && isLiveVideoTrack(videoEntry.secondary, { allowMuted: true })
      ? videoEntry.secondary
      : null
  );
  const primaryId = normId(primary?.id || "");
  const secondaryId = normId(secondary?.id || "");
  const primaryKind = normalizeRelayMediaKind(videoEntry.primaryKind || "");
  const secondaryKind = normalizeRelayMediaKind(videoEntry.secondaryKind || "");
  const trackKindMatchesPreferredType = (trackKind = "") => {
    if (!strictPreferredMediaType || !preferredMediaType) return true;
    if (preferredMediaType === "share") return trackKind === "share";
    if (preferredMediaType === "camera") return trackKind === "camera";
    if (preferredMediaType === "video") return trackKind !== "share";
    return true;
  };

  if (preferredTrackId) {
    if (primary && primaryId === preferredTrackId && trackKindMatchesPreferredType(primaryKind)) return primary;
    if (secondary && secondaryId === preferredTrackId && trackKindMatchesPreferredType(secondaryKind)) return secondary;
  }

  if (preferredMediaType === "share") {
    if (primary && primaryKind === "share") return primary;
    if (secondary && secondaryKind === "share") return secondary;
  } else if (preferredMediaType === "camera") {
    if (secondary && secondaryKind === "camera") return secondary;
    if (primary && primaryKind === "camera") return primary;
  } else if (preferredMediaType === "video") {
    if (primary && primaryKind !== "share") return primary;
    if (secondary && secondaryKind !== "share") return secondary;
  }

  if (strictPreferredMediaType && preferredMediaType) {
    return null;
  }

  return primaryStrict || secondaryStrict || (allowMutedFallback ? (primary || secondary) : null) || null;
}

function syncGroupCallMemberTileVideo(tile, track = null) {
  if (!tile) return;
  let videoEl = tile.querySelector(".stageGridVideo, .participantVideo");
  if (!(videoEl instanceof HTMLVideoElement)) {
    videoEl = ensureStageTileVideoElementForMediaContainer(tile);
  }
  if (!videoEl) return;
  const convId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
  const nowTs = Date.now();
  const meId = normId(state.user?.id || "");
  const tileIdentity = getStageTileIdentityFromEl(tile);
  const tileId = String(tileIdentity.tileId || tile.getAttribute("data-call-tile-id") || "").trim();
  const tileType = normalizeStageTileType(
    tileIdentity.tileType
    || tile.getAttribute("data-call-tile-type")
    || ""
  );
  const isScreenshareTile = tileType === "screenshare";
  const tileUserId = normId(tileIdentity.participantId || tile.getAttribute("data-call-user-id") || "");
  const tileMediaType = normalizeRelayMediaKind(tile.getAttribute("data-call-media-type") || "");
  const isSelfShareTile = !!(tileUserId && meId && tileUserId === meId && tileMediaType === "share");
  const resolveTrackIdentity = (candidateTrack = null) => normId(
    candidateTrack?.sid
    || candidateTrack?.id
    || candidateTrack?.mediaStreamTrack?.id
    || ""
  );
  const nextTrack = isLiveVideoTrack(track, { allowMuted: isSelfShareTile }) ? track : null;
  const nextTrackId = resolveTrackIdentity(nextTrack);
  let currentTrackId = normId(tile.getAttribute("data-call-video-track-id") || "");
  let attachedStreamTrackId = resolveTrackIdentity(getAnyVideoTrackFromStream(videoEl.srcObject || null));
  let effectiveCurrentTrackId = currentTrackId || attachedStreamTrackId;
  let hasExistingVideoElement = !!(videoEl.srcObject && !!getAnyVideoTrackFromStream(videoEl.srcObject || null));
  const refreshVideoAttachmentSnapshot = () => {
    currentTrackId = normId(tile.getAttribute("data-call-video-track-id") || "");
    attachedStreamTrackId = resolveTrackIdentity(getAnyVideoTrackFromStream(videoEl?.srcObject || null));
    effectiveCurrentTrackId = currentTrackId || attachedStreamTrackId;
    hasExistingVideoElement = !!(videoEl?.srcObject && !!getAnyVideoTrackFromStream(videoEl.srcObject || null));
  };
  const renderReason = String(tile.getAttribute("data-call-render-reason") || "").trim() || "sync_group_member_tile_video";
  const screenshareMissingUntilAttr = "data-call-screenshare-missing-until";
  const screenshareGapStartedAtAttr = "data-call-screenshare-gap-started-at";
  const screenshareReconnectAttr = "data-call-screenshare-reconnecting";
  const screenshareFallbackBlockedAttr = "data-call-screenshare-fallback-blocked";
  const screenshareFocusPreservedSerialAttr = "data-call-screenshare-focus-preserved-serial";
  const screenshareFocusSkippedSerialAttr = "data-call-screenshare-focus-skip-serial";
  const holdUntilAttr = "data-call-video-hold-until";
  const seenFrameAttr = "data-call-video-seen";
  let activeShareOwnerId = "";
  let activeShareTrack = null;
  if (convId && shouldUseServerVoiceLiveKitTransport(convId)) {
    const activeShare = getServerVoiceActiveScreenshare(convId);
    activeShareOwnerId = normId(activeShare?.ownerUserId || "");
    activeShareTrack = pickLiveVideoTrackFromStream(activeShare?.stream || null, { allowMuted: true })
      || getAnyVideoTrackFromStream(activeShare?.stream || null)
      || null;
  } else {
    const preferredRemoteShareState = getPreferredRemoteShareState(convId);
    const localShareOwnerId = isScreenSharing ? meId : "";
    activeShareOwnerId = normId(preferredRemoteShareState?.userId || localShareOwnerId || "");
    if (tileUserId && activeShareOwnerId && tileUserId === activeShareOwnerId) {
      if (tileUserId === meId) {
        activeShareTrack = isLiveVideoTrack(getLiveScreenTrack(), { allowMuted: true })
          ? getLiveScreenTrack()
          : null;
      } else {
        activeShareTrack = isLiveVideoTrack(remoteVideoTrackRef, { allowMuted: true })
          ? remoteVideoTrackRef
          : null;
      }
    }
  }
  if (!activeShareTrack && isScreenshareTile && nextTrack) {
    activeShareTrack = nextTrack;
  }
  const screenshareOwnerForceRemoved = !!(
    convId
    && isScreenshareTile
    && tileUserId
    && isStageScreenshareForceRemovedOwner(convId, tileUserId)
  );
  const screenshareOwnerReplacing = !!(
    convId
    && isScreenshareTile
    && tileUserId
    && isStageScreenshareReplacingOwner(convId, tileUserId)
  );
  const screenshareReplacementState = screenshareOwnerReplacing
    ? getStageScreenshareReplacementState(convId, tileUserId)
    : null;
  const replacementOldTrackSid = normId(
    screenshareReplacementState?.oldTrackSid
    || effectiveCurrentTrackId
    || ""
  );
  const replacementNewTrackSid = normId(
    screenshareReplacementState?.newTrackSid
    || nextTrackId
    || ""
  );
  if (!activeShareOwnerId && !screenshareOwnerForceRemoved) {
    activeShareOwnerId = normId(tile.getAttribute("data-call-active-share-owner-id") || "");
  }
  const activeShareTrackId = resolveTrackIdentity(activeShareTrack);
  const activeShareExistsForTile = !!(
    isScreenshareTile
    && tileUserId
    && activeShareOwnerId
    && tileUserId === activeShareOwnerId
  );
  const activeShareTrackExistsForTile = !!(activeShareExistsForTile && activeShareTrackId);
  const screenshareStreamIdentity = normId(
    nextTrackId
    || effectiveCurrentTrackId
    || activeShareTrackId
    || tile.getAttribute("data-call-track-identity")
    || tile.getAttribute("data-call-video-track-id")
    || ""
  );
  const screenshareStreamPreferenceKey = isScreenshareTile
    ? buildRemoteStreamPreferenceKey({
      conversationId: convId,
      participantId: tileUserId,
      trackSid: screenshareStreamIdentity,
      trackIdentity: screenshareStreamIdentity,
    })
    : "";
  const screenshareWatchPromptActive = !!(
    isScreenshareTile
    && convId
    && tileUserId
    && tileUserId !== meId
    && isRemoteShareWatchPromptActive(convId, screenshareStreamPreferenceKey)
  );
  const getActiveFocusTransitionSerial = () => (
    isScreenshareTile
      ? getStageFocusTransitionSerialForTile(tileId || buildStageParticipantTileId(tileUserId, tileType))
      : 0
  );
  const logScreenshareFocusAttachPreservedIfNeeded = ({
    renderReason: focusRenderReason = "focus_transition",
    fallbackReason: focusFallbackReason = "focus_transition_grace",
  } = {}) => {
    if (!isScreenshareTile) return;
    const transitionSerial = getActiveFocusTransitionSerial();
    if (!transitionSerial) return;
    const alreadyLoggedSerial = Number(tile.getAttribute(screenshareFocusPreservedSerialAttr) || "0");
    if (alreadyLoggedSerial === transitionSerial) return;
    tile.setAttribute(screenshareFocusPreservedSerialAttr, String(transitionSerial));
    logScreenshareTileRenderEvent("screenshare.focus_attach_preserved", {
      tileId,
      participantId: tileUserId,
      trackIdentity: nextTrackId || effectiveCurrentTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
      activeShareOwnerId,
      renderReason: focusRenderReason,
      hasExistingVideoElement,
      fallbackReason: focusFallbackReason,
      transitionSerial,
      tileType,
    });
  };
  const logScreenshareFocusRerenderSkippedIfNeeded = ({
    renderReason: focusRenderReason = "focus_transition_same_track",
    fallbackReason: focusFallbackReason = "focus_transition_same_track_noop",
  } = {}) => {
    if (!isScreenshareTile) return;
    const transitionSerial = getActiveFocusTransitionSerial();
    if (!transitionSerial) return;
    const alreadyLoggedSerial = Number(tile.getAttribute(screenshareFocusSkippedSerialAttr) || "0");
    if (alreadyLoggedSerial === transitionSerial) return;
    tile.setAttribute(screenshareFocusSkippedSerialAttr, String(transitionSerial));
    logScreenshareTileRenderEvent("screenshare.focus_rerender_skipped_same_track", {
      tileId,
      participantId: tileUserId,
      trackIdentity: nextTrackId || effectiveCurrentTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
      activeShareOwnerId,
      renderReason: focusRenderReason,
      hasExistingVideoElement,
      fallbackReason: focusFallbackReason,
      transitionSerial,
      tileType,
    });
  };
  const clearScreenshareTransientState = () => {
    tile.removeAttribute(screenshareMissingUntilAttr);
    tile.removeAttribute(screenshareGapStartedAtAttr);
    tile.removeAttribute(screenshareReconnectAttr);
    tile.removeAttribute(screenshareFallbackBlockedAttr);
    tile.removeAttribute("data-call-keep-mounted");
    tile.classList.remove("is-share-reconnecting");
  };
  if (screenshareOwnerReplacing) {
    clearScreenshareTransientState();
  }
  const logScreenshareMismatchIfNeeded = (renderedContentType, fallbackReason = "") => {
    if (!isScreenshareTile || !activeShareTrackExistsForTile) return;
    if (String(renderedContentType || "").trim().toLowerCase() === "screenshare") return;
    logScreenshareTileRenderEvent("screenshare.tile_render_mismatch_detected", {
      tileId,
      participantId: tileUserId,
      trackIdentity: activeShareTrackId || nextTrackId || effectiveCurrentTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
      activeShareOwnerId,
      renderReason,
      hasExistingVideoElement,
      fallbackReason: String(fallbackReason || "").trim() || "active_share_rendered_non_screenshare",
      renderedContentType: String(renderedContentType || "").trim().toLowerCase() || "avatar",
      tileType,
    });
  };
  const markScreenshareTemporarilyMissing = ({
    renderReason: missingRenderReason = "track_missing",
    fallbackReason = "transient_missing_track",
  } = {}) => {
    if (!isScreenshareTile) return;
    if (screenshareOwnerReplacing) return;
    const existingMissingUntil = Number(tile.getAttribute(screenshareMissingUntilAttr) || "0");
    const nowForMissing = Date.now();
    const nextMissingUntil = existingMissingUntil > nowForMissing
      ? existingMissingUntil
      : (nowForMissing + STAGE_SCREENSHARE_TRANSIENT_MISSING_GRACE_MS);
    tile.setAttribute(screenshareMissingUntilAttr, String(nextMissingUntil));
    tile.setAttribute(screenshareReconnectAttr, "1");
    tile.setAttribute("data-call-keep-mounted", "1");
    tile.classList.add("has-video");
    tile.classList.add("is-share-reconnecting");
    if (!tile.getAttribute(screenshareGapStartedAtAttr)) {
      tile.setAttribute(screenshareGapStartedAtAttr, String(Date.now()));
      logScreenshareTileRenderEvent("screenshare.tile_track_temporarily_missing", {
        tileId,
        participantId: tileUserId,
        trackIdentity: nextTrackId || effectiveCurrentTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
        activeShareOwnerId,
        renderReason: missingRenderReason,
        hasExistingVideoElement,
        fallbackReason,
      });
    }
    if (activeShareExistsForTile && tile.getAttribute(screenshareFallbackBlockedAttr) !== "1") {
      tile.setAttribute(screenshareFallbackBlockedAttr, "1");
      logScreenshareTileRenderEvent("screenshare.tile_fallback_blocked_active_share", {
        tileId,
        participantId: tileUserId,
        trackIdentity: nextTrackId || effectiveCurrentTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
        activeShareOwnerId,
        renderReason: missingRenderReason,
        hasExistingVideoElement,
        fallbackReason,
      });
    }
  };
  if (isScreenshareTile) {
    logScreenshareTileRenderEvent("screenshare.tile_render_requested", {
      tileId,
      participantId: tileUserId,
      trackIdentity: nextTrackId || effectiveCurrentTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
      activeShareOwnerId,
      renderReason,
      hasExistingVideoElement,
      fallbackReason: "",
      tileType,
    });
  }

  const updateVisibility = () => {
    const hasTrack = hasRenderableVideoFrame(videoEl);
    if (hasTrack) {
      tile.classList.add("has-video");
      tile.removeAttribute(holdUntilAttr);
      if (isSelfShareTile) {
        tile.setAttribute(seenFrameAttr, "1");
        localShareTileSeenFrame = true;
      }
      if (isScreenshareTile) {
        if (tile.getAttribute(screenshareGapStartedAtAttr)) {
          logScreenshareTileRenderEvent("screenshare.tile_track_restored", {
            tileId,
            participantId: tileUserId,
            trackIdentity: nextTrackId || effectiveCurrentTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
            activeShareOwnerId,
            renderReason: "renderable_frame_restored",
            hasExistingVideoElement,
            fallbackReason: "",
          });
        }
        clearScreenshareTransientState();
        logScreenshareMismatchIfNeeded("screenshare", "");
      }
      return;
    }
    const seenSelfShare = isSelfShareTile
      && isScreenSharing
      && (tile.getAttribute(seenFrameAttr) === "1" || localShareTileSeenFrame);
    if (seenSelfShare) return;
    if (isScreenshareTile) {
      const missingUntil = Number(tile.getAttribute(screenshareMissingUntilAttr) || "0");
      const focusTransitionSerial = getActiveFocusTransitionSerial();
      if (!screenshareOwnerReplacing && (activeShareExistsForTile || missingUntil > Date.now() || focusTransitionSerial)) {
        const fallbackReason = activeShareExistsForTile
          ? "transient_frame_gap"
          : (focusTransitionSerial ? "focus_transition_transient_frame_gap" : "screenshare_transient_gap_grace");
        const renderReason = activeShareExistsForTile
          ? "renderable_frame_missing"
          : (focusTransitionSerial ? "focus_transition_frame_gap" : "screenshare_grace_window");
        markScreenshareTemporarilyMissing({
          renderReason,
          fallbackReason,
        });
        if (focusTransitionSerial) {
          logScreenshareFocusRerenderSkippedIfNeeded({
            renderReason: "focus_transition_frame_gap",
            fallbackReason,
          });
          logScreenshareFocusAttachPreservedIfNeeded({
            renderReason: "focus_transition_frame_gap",
            fallbackReason,
          });
        }
        logScreenshareMismatchIfNeeded("screenshare", fallbackReason);
        return;
      }
    }
    const holdUntil = Number(tile.getAttribute(holdUntilAttr) || "0");
    if (isSelfShareTile && holdUntil > Date.now()) return;
    tile.classList.remove("has-video");
    if (isScreenshareTile) {
      clearScreenshareTransientState();
      logScreenshareMismatchIfNeeded("avatar", "frame_missing_avatar_fallback");
    }
  };

  if (screenshareWatchPromptActive) {
    if (effectiveCurrentTrackId || videoEl.srcObject) {
      stopMemberTileFrameProbe(videoEl);
      try {
        videoEl.pause?.();
        videoEl.srcObject = null;
        videoEl.removeAttribute?.("src");
        videoEl.load?.();
      } catch (_) {}
    }
    tile.removeAttribute("data-call-video-track-id");
    tile.classList.remove("has-video");
    if (screenshareOwnerReplacing) {
      tile.removeAttribute("data-call-keep-mounted");
    } else {
      tile.setAttribute("data-call-keep-mounted", "1");
    }
    return;
  }

  if (!nextTrackId) {
    const seenSelfShare = isSelfShareTile
      && isScreenSharing
      && (tile.getAttribute(seenFrameAttr) === "1" || localShareTileSeenFrame);
    if (seenSelfShare) return;
    if (isSelfShareTile && isScreenSharing && (effectiveCurrentTrackId || videoEl.srcObject)) {
      const existingHoldUntil = Number(tile.getAttribute(holdUntilAttr) || "0");
      if (!existingHoldUntil) {
        tile.setAttribute(holdUntilAttr, String(Date.now() + 2600));
        return;
      }
      if (existingHoldUntil > Date.now()) return;
    }
    if (isScreenshareTile) {
      const missingUntil = Number(tile.getAttribute(screenshareMissingUntilAttr) || "0");
      const withinGraceWindow = missingUntil > nowTs;
      const focusTransitionSerial = getActiveFocusTransitionSerial();
      if (!screenshareOwnerReplacing && (activeShareExistsForTile || withinGraceWindow || focusTransitionSerial)) {
        const fallbackReason = activeShareExistsForTile
          ? "active_share_track_temporarily_missing"
          : (focusTransitionSerial ? "focus_transition_track_temporarily_missing" : "screenshare_transient_gap_grace");
        const renderReason = activeShareExistsForTile
          ? "active_share_missing_track"
          : (focusTransitionSerial ? "focus_transition_missing_track" : "screenshare_grace_window");
        markScreenshareTemporarilyMissing({
          renderReason,
          fallbackReason,
        });
        if (focusTransitionSerial) {
          logScreenshareFocusAttachPreservedIfNeeded({
            renderReason: "focus_transition_missing_track",
            fallbackReason,
          });
        }
        logScreenshareMismatchIfNeeded("screenshare", fallbackReason);
        return;
      }
    }
    const hadRenderableStateBeforeDetach = !!(
      effectiveCurrentTrackId
      || videoEl.srcObject
      || tile.classList.contains("has-video")
      || tile.getAttribute(screenshareReconnectAttr) === "1"
    );
    stopMemberTileFrameProbe(videoEl);
    if (effectiveCurrentTrackId || videoEl.srcObject) {
      try {
        videoEl.pause?.();
        videoEl.srcObject = null;
        videoEl.removeAttribute?.("src");
        videoEl.load?.();
      } catch (_) {}
    }
    tile.removeAttribute("data-call-video-track-id");
    tile.removeAttribute(holdUntilAttr);
    tile.removeAttribute(seenFrameAttr);
    tile.classList.remove("has-video");
    if (isScreenshareTile) {
      if (hadRenderableStateBeforeDetach) {
        logScreenshareTileRenderEvent("screenshare.tile_removed_after_confirmed_stop", {
          tileId,
          participantId: tileUserId,
          trackIdentity: effectiveCurrentTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
          activeShareOwnerId,
          renderReason: "confirmed_share_stop",
          hasExistingVideoElement,
          fallbackReason: activeShareExistsForTile ? "unexpected_active_share_detach" : "confirmed_share_stop",
        });
      }
      clearScreenshareTransientState();
      logScreenshareMismatchIfNeeded("avatar", activeShareExistsForTile ? "unexpected_active_share_detach" : "confirmed_share_stop");
    }
    return;
  }

  if (isScreenshareTile && screenshareOwnerReplacing && convId && tileUserId) {
    const replacementTileId = String(tileId || buildStageParticipantTileId(tileUserId, "screenshare") || "").trim();
    const stage = document.getElementById("callStage");
    const participantScreenshareTiles = Array.from(stage?.querySelectorAll?.(".participantTile, .stageGridTile") || [])
      .filter((candidateTile) => isScreenshareStageTileCandidateForParticipant(candidateTile, tileUserId));
    if (participantScreenshareTiles.length !== 1) {
      logScreenshareMediaContainerEvent("screenshare.stale_media_artifact_detected", {
        conversationId: convId,
        participantId: tileUserId,
        tileId: replacementTileId,
        oldTrackSid: replacementOldTrackSid,
        newTrackSid: replacementNewTrackSid || nextTrackId,
        renderReason: "screenshare_replace_pre_attach_tile_count_assertion",
        fallbackReason: `unexpected_tile_count_${participantScreenshareTiles.length}`,
        container: tile,
      });
      pruneScreenshareStageTilesForParticipant({
        conversationId: convId,
        participantId: tileUserId,
        removeAll: false,
        preferredTrackIdentity: replacementNewTrackSid || nextTrackId,
        reason: "screenshare_replace_pre_attach_tile_count_assertion",
        triggerReason: "screenshare_replace_pre_attach",
        callerFunction: "syncGroupCallMemberTileVideo",
        oldTrackSid: replacementOldTrackSid,
        newTrackSid: replacementNewTrackSid || nextTrackId,
        logDomCount: true,
      });
    }
    const clearTrackMarker = String(tile.getAttribute("data-call-screenshare-replace-cleared-track") || "").trim();
    if (clearTrackMarker !== nextTrackId) {
      const clearResult = clearScreenshareTileMediaContainer(tile, {
        conversationId: convId,
        participantId: tileUserId,
        tileId: replacementTileId,
        oldTrackSid: replacementOldTrackSid,
        newTrackSid: replacementNewTrackSid || nextTrackId,
        renderReason: "screenshare_replace_pre_attach_tile_media_clear",
        removeVideoElements: true,
      });
      if (clearResult?.afterAudit?.mediaChildCount > 0) {
        logScreenshareMediaContainerEvent("screenshare.stale_media_artifact_detected", {
          conversationId: convId,
          participantId: tileUserId,
          tileId: replacementTileId,
          oldTrackSid: replacementOldTrackSid,
          newTrackSid: replacementNewTrackSid || nextTrackId,
          renderReason: "screenshare_replace_pre_attach_container_not_empty",
          fallbackReason: `non_zero_media_children_${Number(clearResult?.afterAudit?.mediaChildCount || 0)}`,
          container: tile,
        });
      }
      videoEl = ensureStageTileVideoElementForMediaContainer(tile) || videoEl;
      tile.setAttribute("data-call-screenshare-replace-cleared-track", nextTrackId);
      refreshVideoAttachmentSnapshot();
      logScreenshareMediaContainerEvent("screenshare.media_container_audit_before_replace", {
        conversationId: convId,
        participantId: tileUserId,
        tileId: replacementTileId,
        oldTrackSid: replacementOldTrackSid,
        newTrackSid: replacementNewTrackSid || nextTrackId,
        renderReason: "screenshare_replace_pre_attach_after_clear_before_attach",
        container: tile,
      });
    }
  } else {
    tile.removeAttribute("data-call-screenshare-replace-cleared-track");
  }

  if (!videoEl.muted) videoEl.muted = true;
  const sameTrackAlreadyAttached = !!(
    nextTrackId
    && effectiveCurrentTrackId
    && nextTrackId === effectiveCurrentTrackId
    && videoEl.srcObject
  );
  if (sameTrackAlreadyAttached) {
    if (isScreenshareTile) {
      logScreenshareTileRenderEvent("screenshare.tile_video_attach_skipped_same_track", {
        tileId,
        participantId: tileUserId,
        trackIdentity: nextTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
        activeShareOwnerId,
        renderReason,
        hasExistingVideoElement,
        fallbackReason: "",
      });
      const focusTransitionSerial = getActiveFocusTransitionSerial();
      if (focusTransitionSerial) {
        logScreenshareFocusRerenderSkippedIfNeeded({
          renderReason: "focus_transition_same_track",
          fallbackReason: "focus_transition_same_track_noop",
        });
        logScreenshareFocusAttachPreservedIfNeeded({
          renderReason: "focus_transition_same_track",
          fallbackReason: "focus_transition_same_track_noop",
        });
      }
    }
  } else if (effectiveCurrentTrackId !== nextTrackId || !videoEl.srcObject) {
    stopMemberTileFrameProbe(videoEl);
    if (isSelfShareTile && effectiveCurrentTrackId && tile.classList.contains("has-video")) {
      tile.setAttribute(holdUntilAttr, String(Date.now() + 2200));
      tile.setAttribute(seenFrameAttr, "1");
      localShareTileSeenFrame = true;
    } else if (isSelfShareTile && (tile.classList.contains("has-video") || localShareTileSeenFrame)) {
      tile.setAttribute(seenFrameAttr, "1");
      localShareTileSeenFrame = true;
    } else if (!isSelfShareTile) {
      tile.removeAttribute(holdUntilAttr);
    }
    videoEl.srcObject = createSingleTrackVideoStream(nextTrack);
    tile.setAttribute("data-call-video-track-id", nextTrackId);
    tile.setAttribute("data-call-track-identity", nextTrackId);
    if (isScreenshareTile) {
      logScreenshareTileRenderEvent("screenshare.tile_video_attached", {
        tileId,
        participantId: tileUserId,
        trackIdentity: nextTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
        activeShareOwnerId,
        renderReason,
        hasExistingVideoElement,
        fallbackReason: "",
      });
    }
  }
  if (isScreenshareTile) {
    if (tile.getAttribute(screenshareGapStartedAtAttr)) {
      logScreenshareTileRenderEvent("screenshare.tile_track_restored", {
        tileId,
        participantId: tileUserId,
        trackIdentity: nextTrackId || activeShareTrackId || normId(tile.getAttribute("data-call-track-identity") || ""),
        activeShareOwnerId,
        renderReason: "track_attached_after_gap",
        hasExistingVideoElement,
        fallbackReason: "",
      });
    }
    clearScreenshareTransientState();
  }

  videoEl.onloadeddata = updateVisibility;
  videoEl.onplaying = updateVisibility;
  videoEl.onresize = updateVisibility;
  videoEl.ontimeupdate = updateVisibility;
  try { videoEl.play?.().catch?.(() => {}); } catch (_) {}
  updateVisibility();
  startMemberTileFrameProbe(videoEl, tile, nextTrackId);
  if (isScreenshareTile) {
    const replacementStateAfterAttach = getStageScreenshareReplacementState(convId, tileUserId) || null;
    auditScreenshareMediaContainerAfterAttach({
      conversationId: convId,
      participantId: tileUserId,
      tile,
      tileId,
      oldTrackSid: normId(replacementStateAfterAttach?.oldTrackSid || replacementOldTrackSid || ""),
      newTrackSid: normId(
        nextTrackId
        || replacementStateAfterAttach?.newTrackSid
        || replacementNewTrackSid
        || activeShareTrackId
        || ""
      ),
      renderReason: screenshareOwnerReplacing
        ? "screenshare_replace_post_attach_validation"
        : "screenshare_attach_post_validation",
    });
  }
  if (isScreenshareTile) {
    logScreenshareMismatchIfNeeded("screenshare", "");
  }
}

function clearServerVoiceStageTileDerivationState(conversationId = null) {
  const convId = normId(conversationId || "");
  if (!convId) return;
  stageTileSnapshotSignatureByConversation.delete(convId);
  stageTileIdentitySnapshotSignatureByConversation.delete(convId);
  stageLayoutRecomputeSignatureByConversation.delete(convId);
  stageLayoutDimensionsSnapshotSignatureByConversation.delete(convId);
  stagePrimaryTileModeByConversation.delete(convId);
  stageScreenshareTileUsersByConversation.delete(convId);
  stageScreenshareGraceStateByConversation.delete(convId);
  stageScreenshareForceRemovedOwnersByConversation.delete(convId);
  stageScreenshareReplacingOwnersByConversation.delete(convId);
  clearStageScreenshareReplacementState(convId);
  clearStageScreenshareInitialAttachRetryStatesByConversation(convId);
}

function logServerVoiceStageTilesEvent(event, conversationId, details = {}) {
  const convId = normId(conversationId || "");
  if (!convId) return;
  writeStructuredServerVoiceConsoleLog("[server-voice stage]", event, {
    conversationId: convId,
    ...(details && typeof details === "object" && !Array.isArray(details) ? details : { value: details ?? null }),
  }, {
    level: "info",
    channel: "server-voice-stage",
  });
}

function emitServerVoiceStageTileDerivationLogs(conversationId, entries = [], {
  triggerReason = "stage_entries_derived",
  callerFunction = "renderGroupCallStageMembers",
} = {}) {
  const convId = normId(conversationId || "");
  if (!convId) return;
  const normalizedEntries = (Array.isArray(entries) ? entries : [])
    .map((entry) => {
      const userId = normId(entry?.userId || "");
      const key = String(entry?.key || "").trim();
      const tileType = String(entry?.tileType || "").trim().toLowerCase();
      const mediaType = normalizeRelayMediaKind(entry?.mediaType || "") || (String(entry?.mediaType || "").trim().toLowerCase() === "base" ? "base" : "");
      const trackId = normId(entry?.track?.id || "");
      const primaryModeRaw = String(entry?.primaryMode || "").trim().toLowerCase();
      const primaryMode = primaryModeRaw === "camera"
        ? "camera"
        : (primaryModeRaw === "video" ? "video" : "avatar");
      if (!userId || !key) return null;
      return {
        userId,
        key,
        tileType: tileType || "primary",
        mediaType: mediaType || "base",
        trackId,
        primaryMode,
      };
    })
    .filter(Boolean);
  const participantIds = normalizeUuidArray(normalizedEntries.map((entry) => entry.userId));
  const tileDescriptors = normalizedEntries.map((entry) => (
    `${entry.userId}:${entry.tileType}:${entry.mediaType}:${entry.primaryMode}:${entry.trackId || "none"}`
  ));
  const nextSignature = tileDescriptors.join("|");
  const prevSignature = String(stageTileSnapshotSignatureByConversation.get(convId) || "");
  if (nextSignature !== prevSignature) {
    stageTileSnapshotSignatureByConversation.set(convId, nextSignature);
    logServerVoiceStageTilesEvent("stage.tiles_snapshot", convId, {
      triggerReason: String(triggerReason || "").trim() || null,
      callerFunction: String(callerFunction || "").trim() || "renderGroupCallStageMembers",
      participantIds,
      participantCount: participantIds.length,
      tileCount: normalizedEntries.length,
      tileDescriptors,
    });
  }

  const previousPrimaryModes = stagePrimaryTileModeByConversation.get(convId) instanceof Map
    ? stagePrimaryTileModeByConversation.get(convId)
    : new Map();
  const nextPrimaryModes = new Map();
  normalizedEntries.forEach((entry) => {
    if (entry.tileType !== "primary") return;
    nextPrimaryModes.set(entry.userId, entry.primaryMode === "camera" ? "camera" : (entry.primaryMode === "video" ? "video" : "avatar"));
  });
  const primaryModeUserIds = Array.from(new Set([
    ...Array.from(previousPrimaryModes.keys()),
    ...Array.from(nextPrimaryModes.keys()),
  ]));
  primaryModeUserIds.forEach((userId) => {
    const prevMode = String(previousPrimaryModes.get(userId) || "").trim().toLowerCase() || "";
    const nextMode = String(nextPrimaryModes.get(userId) || "").trim().toLowerCase() || "";
    if (prevMode === nextMode) return;
    logServerVoiceStageTilesEvent("stage.primary_tile_mode_changed", convId, {
      triggerReason: String(triggerReason || "").trim() || null,
      callerFunction: String(callerFunction || "").trim() || "renderGroupCallStageMembers",
      userId,
      previousMode: prevMode || null,
      nextMode: nextMode || null,
      participantIds,
      tileCount: normalizedEntries.length,
    });
  });
  stagePrimaryTileModeByConversation.set(convId, nextPrimaryModes);

  const previousScreenshareUsers = stageScreenshareTileUsersByConversation.get(convId) instanceof Set
    ? stageScreenshareTileUsersByConversation.get(convId)
    : new Set();
  const nextScreenshareUsers = new Set(
    normalizedEntries
      .filter((entry) => entry.tileType === "screenshare")
      .map((entry) => entry.userId)
  );
  nextScreenshareUsers.forEach((userId) => {
    if (previousScreenshareUsers.has(userId)) return;
    logServerVoiceStageTilesEvent("stage.screenshare_tile_added", convId, {
      triggerReason: String(triggerReason || "").trim() || null,
      callerFunction: String(callerFunction || "").trim() || "renderGroupCallStageMembers",
      userId,
      screenshareUserIds: normalizeUuidArray(Array.from(nextScreenshareUsers)),
      participantIds,
      tileCount: normalizedEntries.length,
    });
  });
  previousScreenshareUsers.forEach((userId) => {
    if (nextScreenshareUsers.has(userId)) return;
    logServerVoiceStageTilesEvent("stage.screenshare_tile_removed", convId, {
      triggerReason: String(triggerReason || "").trim() || null,
      callerFunction: String(callerFunction || "").trim() || "renderGroupCallStageMembers",
      userId,
      screenshareUserIds: normalizeUuidArray(Array.from(nextScreenshareUsers)),
      participantIds,
      tileCount: normalizedEntries.length,
    });
  });
  stageScreenshareTileUsersByConversation.set(convId, nextScreenshareUsers);
}

function renderGroupCallStageMembers() {
  const grid = document.getElementById("callStageGrid");
  if (!grid) return;
  const stageViewport = document.querySelector("#callStage .callStageViewport");
  const convId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
  const useParticipantStageModel = !!(groupCallMode || isPrivateDmLiveKitTransportConversation(convId));
  if (!useParticipantStageModel) {
    if (convId) clearServerVoiceStageTileDerivationState(convId);
    clearExtraCallStageMembers();
    stageViewport?.removeAttribute("data-stage-tile-count");
    const gridRemote = document.getElementById("gridRemote");
    const gridRemoteAux = document.getElementById("gridRemoteAux");
    const gridSelf = document.getElementById("gridSelf");
    const gridSelfAux = document.getElementById("gridSelfAux");
    if (gridRemote) {
      gridRemote.hidden = false;
      gridRemote.style.display = "";
      gridRemote.disabled = false;
    }
    if (gridRemoteAux) {
      gridRemoteAux.style.display = "";
      gridRemoteAux.disabled = false;
    }
    if (gridSelf) {
      gridSelf.hidden = false;
      gridSelf.style.display = "";
      gridSelf.disabled = false;
    }
    if (gridSelfAux) {
      gridSelfAux.style.display = "";
      gridSelfAux.disabled = false;
    }
    return;
  }
  if (!convId) return;

  const meId = normId(state.user?.id || "");
  const serverVoiceAudioOnlyMode = shouldUseServerVoiceLiveKitTransport(convId);
  const remoteVideoByUser = serverVoiceAudioOnlyMode
    ? getServerVoiceRemoteCameraVideoTracksByUser(convId)
    : collectGroupCallRemoteVideoTracksByUser();
  const localServerVoiceCameraTrack = serverVoiceAudioOnlyMode && isLiveVideoTrack(getServerVoiceLocalCameraTrack(convId), { allowMuted: true })
    ? getServerVoiceLocalCameraTrack(convId)
    : null;
  const localPrimaryTrack = serverVoiceAudioOnlyMode
    ? localServerVoiceCameraTrack
    : (isLiveVideoTrack(getPreferredOutgoingVideoTrack(), { allowMuted: true })
      ? getPreferredOutgoingVideoTrack()
      : null);
  const localSecondaryTrack = serverVoiceAudioOnlyMode
    ? null
    : (isLiveVideoTrack(getSecondaryOutgoingVideoTrack(), { allowMuted: true })
      ? getSecondaryOutgoingVideoTrack()
      : null);

  let memberIds = sortGroupCallMemberIdsForLayout(convId, getEffectiveGroupCallActiveUserIds(convId));
  if (meId && !memberIds.includes(meId)) memberIds.push(meId);
  if (!memberIds.length && meId) memberIds = [meId];

  const describeLocalPrimaryMediaSuffix = (uid, track, hasSecondary) => {
    if (!track) return t("call.feed.video", "Video");
    if (uid === meId) {
      if (serverVoiceAudioOnlyMode) return t("call.feed.camera", "Camera");
      const screenId = String(getLiveScreenTrack()?.id || "");
      const cameraId = String(getLiveCameraTrack()?.id || "");
      const tid = String(track.id || "");
      if (screenId && tid && tid === screenId) return t("call.feed.share", "Share");
      if (cameraId && tid && tid === cameraId) return t("call.feed.camera", "Camera");
      if (isScreenSharing) return t("call.feed.share", "Share");
      if (isCameraOn && !isScreenSharing) return t("call.feed.camera", "Camera");
      return t("call.feed.video", "Video");
    }
    return t("call.feed.video", "Video");
  };

  const entries = [];
  const serverVoiceActiveScreenshare = serverVoiceAudioOnlyMode
    ? getServerVoiceActiveScreenshare(convId)
    : null;
  const serverVoiceActiveShareOwnerId = serverVoiceAudioOnlyMode
    ? normId(serverVoiceActiveScreenshare?.ownerUserId || "")
    : "";
  const serverVoiceActiveShareTrack = serverVoiceAudioOnlyMode
    ? (
      pickLiveVideoTrackFromStream(serverVoiceActiveScreenshare?.stream || null, { allowMuted: true })
      || getAnyVideoTrackFromStream(serverVoiceActiveScreenshare?.stream || null)
      || null
    )
    : null;
  const serverVoiceActiveShareTrackIdentity = normId(
    serverVoiceActiveShareTrack?.sid
    || serverVoiceActiveShareTrack?.id
    || serverVoiceActiveScreenshare?.trackSid
    || ""
  );
  const nowMs = Date.now();
  const previousScreenshareGraceState = stageScreenshareGraceStateByConversation.get(convId) || {};
  let serverVoiceGraceOwnerId = normId(previousScreenshareGraceState?.ownerId || "");
  let serverVoiceGraceTrackIdentity = normId(previousScreenshareGraceState?.trackIdentity || "");
  let serverVoiceGraceExpiresAt = Number(previousScreenshareGraceState?.expiresAt || 0);
  if (serverVoiceActiveShareOwnerId) {
    serverVoiceGraceOwnerId = serverVoiceActiveShareOwnerId;
    serverVoiceGraceTrackIdentity = serverVoiceActiveShareTrackIdentity || serverVoiceGraceTrackIdentity;
    serverVoiceGraceExpiresAt = nowMs + STAGE_SCREENSHARE_TRANSIENT_MISSING_GRACE_MS;
    stageScreenshareGraceStateByConversation.set(convId, {
      ownerId: serverVoiceGraceOwnerId,
      trackIdentity: serverVoiceGraceTrackIdentity,
      expiresAt: serverVoiceGraceExpiresAt,
    });
  } else if (!serverVoiceGraceOwnerId || serverVoiceGraceExpiresAt <= nowMs) {
    serverVoiceGraceOwnerId = "";
    serverVoiceGraceTrackIdentity = "";
    serverVoiceGraceExpiresAt = 0;
    stageScreenshareGraceStateByConversation.delete(convId);
  }
  const serverVoiceLocalScreenshareActive = !!(serverVoiceAudioOnlyMode && isServerVoiceLocalScreenshareActive(convId));
  if (serverVoiceAudioOnlyMode) {
    memberIds.forEach((uid) => {
      const identity = getGroupMemberIdentity(convId, uid);
      const baseLabel = identity?.label || t("call.member", "member");
      const transportStatusLabel = getServerVoiceTransportParticipantStatusLabel(convId, uid, { includeSelf: true });
      const stageBaseLabel = transportStatusLabel ? `${baseLabel} • ${transportStatusLabel}` : baseLabel;
      const baseAvatar = identity?.avatar || null;
      const remoteEntry = uid !== meId ? (remoteVideoByUser.get(uid) || {}) : {};
      const remotePrimaryTrack = isLiveVideoTrack(remoteEntry.primary, { allowMuted: true }) ? remoteEntry.primary : null;
      const remoteSecondaryTrack = isLiveVideoTrack(remoteEntry.secondary, { allowMuted: true }) ? remoteEntry.secondary : null;
      let primaryTrack = uid === meId
        ? (isLiveVideoTrack(localServerVoiceCameraTrack, { allowMuted: true }) ? localServerVoiceCameraTrack : null)
        : (remotePrimaryTrack || remoteSecondaryTrack || null);
      let screenshareTrack = (
        serverVoiceActiveShareOwnerId
        && uid === serverVoiceActiveShareOwnerId
        && isLiveVideoTrack(serverVoiceActiveShareTrack, { allowMuted: true })
      )
        ? serverVoiceActiveShareTrack
        : null;
      if (screenshareTrack && primaryTrack && String(screenshareTrack.id || "") === String(primaryTrack.id || "")) {
        screenshareTrack = null;
      }
      const hadForceRemovedScreenshareTile = isStageScreenshareForceRemovedOwner(convId, uid);
      if (screenshareTrack && hadForceRemovedScreenshareTile) {
        clearStageScreenshareForceRemovedOwner(convId, uid);
      }
      const suppressScreenshareTileAfterStop = isStageScreenshareForceRemovedOwner(convId, uid);
      const keepScreenshareTileForActiveOwner = !!(serverVoiceActiveShareOwnerId && uid === serverVoiceActiveShareOwnerId);
      const keepScreenshareTileForGrace = !!(
        serverVoiceGraceOwnerId
        && uid === serverVoiceGraceOwnerId
        && serverVoiceGraceExpiresAt > nowMs
      );
      const keepScreenshareTileForLocalStableSlot = !!(uid === meId && serverVoiceLocalScreenshareActive);
      const showScreenshareTile = !!(
        !suppressScreenshareTileAfterStop
        && (
          screenshareTrack
          || keepScreenshareTileForActiveOwner
          || keepScreenshareTileForGrace
          || keepScreenshareTileForLocalStableSlot
        )
      );
      const screenshareRenderReason = screenshareTrack
        ? "active_share_track"
        : (
          keepScreenshareTileForActiveOwner
            ? "active_share_owner_missing_track"
            : (
              keepScreenshareTileForGrace
                ? "active_share_owner_grace_window"
                : (keepScreenshareTileForLocalStableSlot ? "local_share_slot_stable" : "share_slot_hidden")
            )
        );
      const primaryMode = primaryTrack ? "camera" : "avatar";
      entries.push({
        key: `${uid}:primary`,
        userId: uid,
        speakingUserId: primaryTrack
          ? (resolveOutgoingVideoTrackOwnerUserId(primaryTrack, { fallbackUserId: uid }) || uid)
          : uid,
        label: primaryTrack
          ? `${stageBaseLabel} • ${t("call.feed.camera", "Camera")}`
          : stageBaseLabel,
        avatar: baseAvatar,
        track: primaryTrack,
        mediaType: primaryTrack ? "camera" : "base",
        tileType: "primary",
        primaryMode,
      });
      if (showScreenshareTile) {
        entries.push({
          key: `${uid}:screenshare`,
          userId: uid,
          speakingUserId: screenshareTrack
            ? (resolveOutgoingVideoTrackOwnerUserId(screenshareTrack, { fallbackUserId: uid }) || uid)
            : uid,
          label: `${stageBaseLabel} • ${t("call.feed.share", "Share")}`,
          avatar: baseAvatar,
          track: screenshareTrack || null,
          mediaType: "share",
          tileType: "screenshare",
          primaryMode: "",
          activeShareOwnerId: serverVoiceActiveShareOwnerId || serverVoiceGraceOwnerId || "",
          trackIdentity: normId(
            screenshareTrack?.sid
            || screenshareTrack?.id
            || serverVoiceActiveShareTrackIdentity
            || serverVoiceGraceTrackIdentity
            || ""
          ),
          renderReason: screenshareRenderReason,
        });
      }
    });
    emitServerVoiceStageTileDerivationLogs(convId, entries, {
      triggerReason: "render_stage_members",
      callerFunction: "renderGroupCallStageMembers",
    });
  } else {
    clearServerVoiceStageTileDerivationState(convId);
    memberIds.forEach((uid) => {
      const identity = getGroupMemberIdentity(convId, uid);
      const baseLabel = identity?.label || t("call.member", "member");
      const transportStatusLabel = shouldUseServerVoiceLiveKitTransport(convId)
        ? getServerVoiceTransportParticipantStatusLabel(convId, uid, { includeSelf: true })
        : "";
      const stageBaseLabel = transportStatusLabel ? `${baseLabel} • ${transportStatusLabel}` : baseLabel;
      const baseAvatar = identity?.avatar || null;

      entries.push({
        key: `${uid}:base`,
        userId: uid,
        speakingUserId: uid,
        label: stageBaseLabel,
        avatar: baseAvatar,
        track: null,
        mediaType: "base",
      });

      let primaryTrack = null;
      let secondaryTrack = null;
      if (uid === meId) {
        primaryTrack = localPrimaryTrack;
        secondaryTrack = localSecondaryTrack;
      } else {
        const remoteEntry = remoteVideoByUser.get(uid) || {};
        const allowMutedRemoteCamera = !!serverVoiceAudioOnlyMode;
        primaryTrack = isLiveVideoTrack(remoteEntry.primary, { allowMuted: allowMutedRemoteCamera }) ? remoteEntry.primary : null;
        secondaryTrack = isLiveVideoTrack(remoteEntry.secondary, { allowMuted: allowMutedRemoteCamera }) ? remoteEntry.secondary : null;
      }
      if (primaryTrack && secondaryTrack && String(primaryTrack.id || "") === String(secondaryTrack.id || "")) {
        secondaryTrack = null;
      }
      if (!primaryTrack && secondaryTrack) {
        const keepShareSlotForLocal = !!(uid === meId && isScreenSharing);
        if (!keepShareSlotForLocal) {
          primaryTrack = secondaryTrack;
          secondaryTrack = null;
        }
      }

      if (primaryTrack) {
        let primaryKind = "";
        if (uid === meId) {
          if (serverVoiceAudioOnlyMode) {
            primaryKind = "camera";
          } else {
            const screenId = String(getLiveScreenTrack()?.id || "");
            const cameraId = String(getLiveCameraTrack()?.id || "");
            const tid = String(primaryTrack?.id || "");
            if (screenId && tid && tid === screenId) primaryKind = "share";
            else if (cameraId && tid && tid === cameraId) primaryKind = "camera";
          }
        } else {
          const remoteEntry = remoteVideoByUser.get(uid) || {};
          primaryKind = normalizeRelayMediaKind(remoteEntry.primaryKind || "");
        }
        let suffix = relayMediaKindToLabel(primaryKind);
        if (!primaryKind) {
          suffix = describeLocalPrimaryMediaSuffix(uid, primaryTrack, !!secondaryTrack);
        }
        entries.push({
          key: `${uid}:primary`,
          userId: uid,
          speakingUserId: resolveOutgoingVideoTrackOwnerUserId(primaryTrack, { fallbackUserId: uid }) || uid,
          label: `${baseLabel} • ${suffix}`,
          avatar: baseAvatar,
          track: primaryTrack,
          mediaType: normalizeRelayMediaKind(primaryKind || (suffix.toLowerCase().includes("partilha") ? "share" : "video")) || "video",
        });
      } else if (!serverVoiceAudioOnlyMode && uid === meId && isScreenSharing) {
        // Keep local share slot stable while swapping source/quality to avoid avatar flicker.
        entries.push({
          key: `${uid}:primary`,
          userId: uid,
          speakingUserId: uid,
          label: `${baseLabel} • Partilha`,
          avatar: baseAvatar,
          track: null,
          mediaType: "share",
        });
      }
      if (secondaryTrack) {
        let secondaryKind = "camera";
        if (uid !== meId) {
          const remoteEntry = remoteVideoByUser.get(uid) || {};
          secondaryKind = normalizeRelayMediaKind(remoteEntry.secondaryKind || "camera") || "camera";
        }
        entries.push({
          key: `${uid}:secondary`,
          userId: uid,
          speakingUserId: resolveOutgoingVideoTrackOwnerUserId(secondaryTrack, { fallbackUserId: uid }) || uid,
          label: `${baseLabel} • ${relayMediaKindToLabel(secondaryKind)}`,
          avatar: baseAvatar,
          track: secondaryTrack,
          mediaType: secondaryKind,
        });
      }
    });
  }

  const existingTiles = new Map();
  const duplicateExistingTiles = [];
  grid.querySelectorAll("[data-call-grid-entry='1'], [data-call-extra='1']").forEach((el) => {
    const key = String(el.getAttribute("data-call-entry-key") || "").trim();
    if (!key) return;
    const prevForKey = existingTiles.get(key);
    if (prevForKey && prevForKey !== el) {
      duplicateExistingTiles.push(prevForKey);
    }
    existingTiles.set(key, el);
  });
  duplicateExistingTiles.forEach((dupTile) => {
    try {
      syncGroupCallMemberTileVideo(dupTile, null);
    } catch (_) {}
    try { dupTile.remove(); } catch (_) {}
  });

  entries.forEach((entry) => {
    const entryMediaType = normalizeRelayMediaKind(entry.mediaType || "");
    const entryTileType = normalizeStageTileType(
      String(entry.tileType || "").trim().toLowerCase()
      || (entryMediaType === "share" ? "screenshare" : "primary")
    );
    const hasExistingEntryTile = !!existingTiles.get(entry.key);
    if (entryTileType === "screenshare" && !hasExistingEntryTile) {
      pruneScreenshareStageTilesForParticipant({
        conversationId: convId,
        participantId: entry.userId,
        removeAll: true,
        reason: "screenshare_pre_render_hard_prune",
        triggerReason: "render_group_stage_member_tile",
        callerFunction: "renderGroupCallStageMembers",
        oldTrackSid: normId(entry.trackIdentity || entry.track?.sid || entry.track?.id || ""),
        newTrackSid: normId(entry.trackIdentity || entry.track?.sid || entry.track?.id || ""),
        logDomCount: true,
      });
    }
    let tile = existingTiles.get(entry.key) || null;
    if (tile) existingTiles.delete(entry.key);
    if (!tile) {
      tile = document.createElement("button");
      tile.className = "stageGridTile stageGridTile--member";
      tile.type = "button";
      tile.setAttribute("data-call-grid-entry", "1");
      tile.innerHTML = `
        <video class="stageGridVideo" autoplay muted playsinline></video>
        <div class="stageGridAvatar"></div>
        <div class="stageGridLabel"></div>
      `;
      tile.addEventListener("contextmenu", async (ev) => {
        if (ev.defaultPrevented) return;
        if (!inCall) return;
        ev.preventDefault();
        ev.stopPropagation();
        closeCallAudioMenu();
        closeServerVoiceMemberMenu();
        const memberUserId = normId(tile.getAttribute("data-call-user-id") || "");
        const memberLabel = String(tile.getAttribute("data-call-user-label") || "").trim();
        const memberTrackIdentity = normId(tile.getAttribute("data-call-track-identity") || "");
        const memberMediaType = normalizeRelayMediaKind(tile.getAttribute("data-call-media-type") || "");
        const watchConvId = normId(callConversationId || activeDmId || convId || "");
        const resolvedIntent = logStageContextMenuTileTypeResolved(
          normalizeStageContextMenuIntent(
            resolveStageContextMenuTileIntent(ev.currentTarget, {
              fallbackMode: memberMediaType === "share" ? REMOTE_AUDIO_TYPE_SHARE : REMOTE_AUDIO_TYPE_VOICE,
            }),
            {
              fallbackParticipantId: memberUserId,
              fallbackTileType: memberMediaType === "share" ? "screenshare" : "primary",
              fallbackMediaType: memberMediaType || "voice",
              fallbackTrackIdentity: memberTrackIdentity,
            }
          ),
          {
            triggerReason: "stage_grid_tile_contextmenu",
            callerFunction: "renderGroupCallStageMembers.contextmenu",
            menuTarget: "member_tile",
          }
        );
        if (resolvedIntent.tileType === "screenshare") {
          const openedStreamMenu = openCallAudioMenuAt(ev.clientX, ev.clientY, REMOTE_AUDIO_TYPE_SHARE, {
            ...resolvedIntent,
            conversationId: watchConvId,
            streamOwnerId: resolvedIntent.participantId,
            activeShareOwnerId: normId(tile.getAttribute("data-call-active-share-owner-id") || ""),
          });
          if (!openedStreamMenu) {
            logContextMenuRoutingFailed({
              tileId: resolvedIntent.tileId,
              tileType: resolvedIntent.tileType,
              participantId: resolvedIntent.participantId,
              isOwner: !!(resolvedIntent.participantId && meId && resolvedIntent.participantId === meId),
              clientX: ev.clientX,
              clientY: ev.clientY,
              menuType: "stream_menu",
              reason: "stream_menu_not_opened",
              callerFunction: "renderGroupCallStageMembers.contextmenu",
            });
          }
          return;
        }
        if (resolvedIntent.participantId) {
          const sid = resolveServerVoiceServerIdByConversation(watchConvId);
          if (sid) {
            await fetchServerMembersForSidebar(sid, { force: false }).catch(() => {});
            await ensureServerRolePermissionCache(sid, { force: false }).catch(() => {});
          }
          const opened = tryOpenServerVoiceMemberMenuAt(resolvedIntent.participantId, watchConvId, {
            x: ev.clientX,
            y: ev.clientY,
          }, {
            displayName: memberLabel,
            tileId: resolvedIntent.tileId,
            tileType: resolvedIntent.tileType,
            mediaType: resolvedIntent.mediaType,
            isLocalUser: resolvedIntent.isLocalUser,
          });
          if (opened) return;
        }
        const openedVoiceMenu = openCallAudioMenuAt(ev.clientX, ev.clientY, REMOTE_AUDIO_TYPE_VOICE, {
          ...resolvedIntent,
          conversationId: watchConvId,
        });
        if (!openedVoiceMenu) {
          logContextMenuRoutingFailed({
            tileId: resolvedIntent.tileId,
            tileType: resolvedIntent.tileType,
            participantId: resolvedIntent.participantId,
            isOwner: false,
            clientX: ev.clientX,
            clientY: ev.clientY,
            menuType: "participant_audio_menu",
            reason: "voice_audio_menu_not_opened",
            callerFunction: "renderGroupCallStageMembers.contextmenu",
          });
        }
      });
      grid.appendChild(tile);
    }

    tile.setAttribute("data-call-entry-key", entry.key);
    tile.setAttribute("data-call-user-id", entry.userId);
    tile.setAttribute("data-call-speaking-user-id", normId(entry.speakingUserId || entry.userId || ""));
    tile.setAttribute("data-call-media-type", entry.mediaType);
    tile.setAttribute(
      "data-call-render-reason",
      String(entry.renderReason || "render_group_stage_member_tile").trim() || "render_group_stage_member_tile"
    );
    tile.setAttribute("data-call-active-share-owner-id", normId(entry.activeShareOwnerId || ""));
    tile.setAttribute("data-call-track-identity", normId(entry.trackIdentity || entry.track?.sid || entry.track?.id || ""));
    const entryTileIdentity = applyStageTileIdentityToEl(tile, {
      participantId: entry.userId,
      tileType: entryTileType,
    });
    tile.classList.toggle("stageGridTile--media", !!entry.track);
    tile.onclick = (ev) => {
      if (ev && typeof ev.button === "number" && ev.button !== 0) return;
      const memberIdentity = getStageTileIdentityFromEl(tile);
      const memberUserId = normId(memberIdentity.participantId || tile.getAttribute("data-call-user-id") || "");
      if (!memberUserId) return;
      const memberTileId = String(memberIdentity.tileId || entryTileIdentity.tileId || "").trim();
      const memberTileType = normalizeStageTileType(memberIdentity.tileType || entryTileType || "primary");
      const memberTrackId = normId(tile.getAttribute("data-call-video-track-id") || "");
      const rawMemberMediaType = String(tile.getAttribute("data-call-media-type") || "").trim().toLowerCase();
      const memberMediaType = rawMemberMediaType === "base"
        ? "base"
        : normalizeRelayMediaKind(rawMemberMediaType);
      ev?.preventDefault?.();
      ev?.stopPropagation?.();
      logStageTileEvent("stage.tile_clicked", {
        tileId: memberTileId,
        tileType: memberTileType,
        participantId: memberUserId,
        triggerReason: "member_tile_click",
        callerFunction: "renderGroupCallStageMembers.onclick",
      });
      const watchConvId = normId(callConversationId || activeDmId || convId || "");
      if (
        memberMediaType === "share"
        && memberUserId !== meId
        && isRemoteShareWatchPromptActive(watchConvId)
      ) {
        logStageTileEvent("stage.focus_target", {
          tileId: memberTileId,
          tileType: memberTileType,
          participantId: memberUserId,
          triggerReason: "watch_prompt_member_share",
          callerFunction: "renderGroupCallStageMembers.onclick",
          action: "watch_stream",
        });
        startWatchingRemoteShare(watchConvId);
        return;
      }
      logStageTileEvent("stage.focus_target", {
        tileId: memberTileId,
        tileType: memberTileType,
        participantId: memberUserId,
        triggerReason: "member_tile_focus",
        callerFunction: "renderGroupCallStageMembers.onclick",
        memberTrackId: memberTrackId || null,
        memberMediaType: memberMediaType || null,
      });
      const sameTileAlreadyFocused = !!(
        stageLayoutMode === "focus"
        && stageFocus === "member"
        && stageFocusedTileId
        && memberTileId
        && stageFocusedTileId === memberTileId
      );
      if (sameTileAlreadyFocused) {
        logStageTileEvent("stage.focus_click_ignored_same_tile", {
          tileId: memberTileId,
          tileType: memberTileType,
          participantId: memberUserId,
          triggerReason: "member_tile_focus",
          callerFunction: "renderGroupCallStageMembers.onclick",
          layoutMode: stageLayoutMode,
        });
        if (memberTileType === "screenshare") {
          const tileVideoEl = tile.querySelector(".stageGridVideo");
          const hasExistingVideoElement = !!(
            tileVideoEl?.srcObject
            && !!getAnyVideoTrackFromStream(tileVideoEl.srcObject || null)
          );
          const trackIdentity = memberTrackId || normId(tile.getAttribute("data-call-track-identity") || "");
          logScreenshareTileRenderEvent("screenshare.focus_rerender_skipped_same_track", {
            tileId: memberTileId,
            participantId: memberUserId,
            trackIdentity,
            activeShareOwnerId: normId(tile.getAttribute("data-call-active-share-owner-id") || ""),
            renderReason: "member_tile_click_same_tile",
            hasExistingVideoElement,
            fallbackReason: "focus_click_same_tile_noop",
          });
          logScreenshareTileRenderEvent("screenshare.focus_attach_preserved", {
            tileId: memberTileId,
            participantId: memberUserId,
            trackIdentity,
            activeShareOwnerId: normId(tile.getAttribute("data-call-active-share-owner-id") || ""),
            renderReason: "member_tile_click_same_tile",
            hasExistingVideoElement,
            fallbackReason: "focus_click_same_tile_noop",
          });
        }
        return;
      }
      const transitionSerial = beginStageFocusTransition({
        tileId: memberTileId,
        tileType: memberTileType,
        participantId: memberUserId,
        nextLayoutMode: "focus",
        triggerReason: "member_tile_focus",
        callerFunction: "renderGroupCallStageMembers.onclick",
      });
      setStageFocus(`member:${memberUserId}`, {
        tileId: memberTileId,
        tileType: memberTileType,
        participantId: memberUserId,
        triggerReason: "member_tile_focus",
        callerFunction: "renderGroupCallStageMembers.onclick",
      });
      stageFocusMemberTrackId = memberTrackId;
      stageFocusMemberMediaType = memberMediaType;
      stageLayoutMode = "focus";
      refreshCallUI();
      completeStageFocusTransition({
        transitionSerial,
        tileId: memberTileId,
        tileType: memberTileType,
        participantId: memberUserId,
        triggerReason: "member_tile_focus",
        callerFunction: "renderGroupCallStageMembers.onclick",
      });
      assertStageFocusMatchesClickedTile({
        tileId: memberTileId,
        tileType: memberTileType,
        participantId: memberUserId,
        triggerReason: "member_tile_click_post_refresh",
        callerFunction: "renderGroupCallStageMembers.onclick",
      });
    };

    const avatarEl = tile.querySelector(".stageGridAvatar");
    if (avatarEl) setAvatar(avatarEl, entry.avatar || null);
    const labelEl = tile.querySelector(".stageGridLabel");
    if (labelEl) {
      const parsed = splitCallParticipantLabelAndSuffix(entry.label || t("call.member", "member"));
      tile.setAttribute("data-call-user-label", parsed.label || t("call.member", "member"));
      setCallParticipantLabel(labelEl, parsed.label, entry.userId, {
        conversationId: convId,
        suffix: parsed.suffix,
      });
    }
    applyUserNameColorToEl(labelEl, entry.userId, "");
    applyCallTileColorToEl(tile, entry.userId, "");
    syncGroupCallMemberTileVideo(tile, entry.track || null);
  });

  for (const staleTile of existingTiles.values()) {
    syncGroupCallMemberTileVideo(staleTile, null);
    const staleIdentity = getStageTileIdentityFromEl(staleTile);
    const staleTileType = normalizeStageTileType(
      staleIdentity.tileType
      || staleTile.getAttribute("data-call-tile-type")
      || (normalizeRelayMediaKind(staleTile.getAttribute("data-call-media-type") || "") === "share" ? "screenshare" : "primary")
    );
    const staleParticipantId = normId(staleIdentity.participantId || staleTile.getAttribute("data-call-user-id") || "");
    const replacingScreenshareTile = !!(
      staleTileType === "screenshare"
      && convId
      && staleParticipantId
      && isStageScreenshareReplacingOwner(convId, staleParticipantId)
    );
    if (replacingScreenshareTile) {
      staleTile.removeAttribute("data-call-keep-mounted");
    }
    if (!replacingScreenshareTile && staleTile.getAttribute("data-call-keep-mounted") === "1") {
      continue;
    }
    staleTile.remove();
  }
  enforceScreenshareStageTileDomInvariant(convId, {
    reason: "render_group_stage_members",
    triggerReason: "render_group_stage_members",
    callerFunction: "renderGroupCallStageMembers",
  });

  const gridRemote = document.getElementById("gridRemote");
  const gridRemoteAux = document.getElementById("gridRemoteAux");
  const gridSelf = document.getElementById("gridSelf");
  const gridSelfAux = document.getElementById("gridSelfAux");
  if (gridRemote) {
    gridRemote.hidden = true;
    gridRemote.style.display = "none";
    gridRemote.disabled = true;
  }
  if (gridRemoteAux) {
    gridRemoteAux.hidden = true;
    gridRemoteAux.style.display = "none";
    gridRemoteAux.disabled = true;
  }
  if (gridSelf) {
    gridSelf.hidden = true;
    gridSelf.style.display = "none";
    gridSelf.disabled = true;
  }
  if (gridSelfAux) {
    gridSelfAux.hidden = true;
    gridSelfAux.style.display = "none";
    gridSelfAux.disabled = true;
  }

  syncCallStageGridLayoutAttrs(grid, stageViewport);
}

function setLocalSharePreviewStream(stream) {
  const preview = document.getElementById("callLocalPreview");
  const thumb = document.getElementById("callSelfThumb");
  const grid = document.getElementById("callSelfGridVideo");
  const stage = document.getElementById("callStage");
  const tileSelf = document.getElementById("tileSelf");
  const tileGridSelf = document.getElementById("gridSelf");
  if (!preview) return;
  const focusSelfAux = stageFocus === "self" && stageFocusSelfSlot === "aux";

  const hasStream = !!(stream && stream.getVideoTracks && stream.getVideoTracks().length);
  if (hasStream) {
    const incomingTrackId = getAnyVideoTrackFromStream(stream)?.id || "";
    const currentPreviewTrackId = getAnyVideoTrackFromStream(preview?.srcObject || null)?.id || "";
    const currentThumbTrackId = getAnyVideoTrackFromStream(thumb?.srcObject || null)?.id || "";
    const currentGridTrackId = getAnyVideoTrackFromStream(grid?.srcObject || null)?.id || "";

    const samePreviewTrack = !!(incomingTrackId && currentPreviewTrackId && incomingTrackId === currentPreviewTrackId);
    const sameThumbTrack = !!(incomingTrackId && currentThumbTrackId && incomingTrackId === currentThumbTrackId);
    const sameGridTrack = !!(incomingTrackId && currentGridTrackId && incomingTrackId === currentGridTrackId);

    const stableStream = (samePreviewTrack ? (preview?.srcObject || null) : null)
      || (sameThumbTrack ? (thumb?.srcObject || null) : null)
      || (sameGridTrack ? (grid?.srcObject || null) : null)
      || stream;

    if (!focusSelfAux && !samePreviewTrack && preview.srcObject !== stableStream) {
      preview.srcObject = stableStream;
    }
    if (!sameThumbTrack && thumb && thumb.srcObject !== stableStream) thumb.srcObject = stableStream;
    if (!sameGridTrack && grid && grid.srcObject !== stableStream) grid.srcObject = stableStream;
  } else {
    if (!focusSelfAux) {
      try {
        preview.pause?.();
        preview.srcObject = null;
        preview.removeAttribute?.("src");
        preview.load?.();
      } catch (_) {
        preview.srcObject = null;
      }
    }
    try {
      if (thumb) {
        thumb.pause?.();
        thumb.srcObject = null;
        thumb.removeAttribute?.("src");
        thumb.load?.();
      }
    } catch (_) {}
    try {
      if (grid) {
        grid.pause?.();
        grid.srcObject = null;
        grid.removeAttribute?.("src");
        grid.load?.();
      }
    } catch (_) {}
  }
  tileSelf?.classList.toggle("has-video", hasStream);
  tileGridSelf?.classList.toggle("has-video", hasStream);
  setLocalCameraAuxPreviewStream(getPreferredLocalAuxPreviewStream());
  const hasAnySelfVideo = !!(getPreferredLocalPreviewStream() || getPreferredLocalAuxPreviewStream());
  stage?.classList.toggle("has-video-self", !!(preview?.srcObject && preview.srcObject.getVideoTracks?.().length));
  if (!hasAnySelfVideo && stageFocus === "self") setStageFocus("remote");
  if (hasAnySelfVideo && stageFocus !== "remote" && stageFocus !== "self") setStageFocus("remote");
  if (hasStream) {
    if (!focusSelfAux) {
      try { preview.play().catch(() => {}); } catch (_) {}
    }
    try { thumb?.play?.().catch?.(() => {}); } catch (_) {}
    try { grid?.play?.().catch?.(() => {}); } catch (_) {}
  }
}

function setLocalCameraAuxPreviewStream(stream) {
  const preview = document.getElementById("callLocalPreview");
  const stage = document.getElementById("callStage");
  const thumb = document.getElementById("callSelfAuxThumb");
  const grid = document.getElementById("callSelfAuxGridVideo");
  const tile = document.getElementById("tileSelfAux");
  const gridTile = document.getElementById("gridSelfAux");
  if (!thumb && !grid && !tile && !gridTile && !preview) return;
  const focusSelfAux = stageFocus === "self" && stageFocusSelfSlot === "aux";

  const hasStream = !!(stream && stream.getVideoTracks && stream.getVideoTracks().length);
  if (!hasStream) {
    try {
      if (thumb) {
        thumb.pause?.();
        thumb.srcObject = null;
        thumb.removeAttribute?.("src");
        thumb.load?.();
      }
    } catch (_) {}
    try {
      if (grid) {
        grid.pause?.();
        grid.srcObject = null;
        grid.removeAttribute?.("src");
        grid.load?.();
      }
    } catch (_) {}
    tile?.classList.remove("has-video");
    gridTile?.classList.remove("has-video");
    if (focusSelfAux && preview) {
      try {
        preview.pause?.();
        preview.srcObject = null;
        preview.removeAttribute?.("src");
        preview.load?.();
      } catch (_) {
        preview.srcObject = null;
      }
    }
    stage?.classList.toggle("has-video-self", !!(preview?.srcObject && preview.srcObject.getVideoTracks?.().length));
    return;
  }

  const incomingTrackId = getAnyVideoTrackFromStream(stream)?.id || "";
  const currentThumbTrackId = getAnyVideoTrackFromStream(thumb?.srcObject || null)?.id || "";
  const currentGridTrackId = getAnyVideoTrackFromStream(grid?.srcObject || null)?.id || "";
  const sameThumbTrack = !!(incomingTrackId && currentThumbTrackId && incomingTrackId === currentThumbTrackId);
  const sameGridTrack = !!(incomingTrackId && currentGridTrackId && incomingTrackId === currentGridTrackId);
  if (!sameThumbTrack && thumb && thumb.srcObject !== stream) thumb.srcObject = stream;
  if (!sameGridTrack && grid && grid.srcObject !== stream) grid.srcObject = stream;
  if (focusSelfAux && preview) {
    const currentStageTrackId = getAnyVideoTrackFromStream(preview.srcObject || null)?.id || "";
    if (!currentStageTrackId || currentStageTrackId !== incomingTrackId) {
      preview.srcObject = stream;
    }
    try { preview.play?.().catch?.(() => {}); } catch (_) {}
  }
  tile?.classList.add("has-video");
  gridTile?.classList.add("has-video");
  stage?.classList.toggle("has-video-self", !!(preview?.srcObject && preview.srcObject.getVideoTracks?.().length));
  try { thumb?.play?.().catch?.(() => {}); } catch (_) {}
  try { grid?.play?.().catch?.(() => {}); } catch (_) {}
}

function getLiveCameraTrack() {
  return cameraStream?.getVideoTracks?.().find((t) => t.readyState === "live") || null;
}

function getPreferredLocalPreviewStream() {
  if (isScreenSharing && screenStream?.getVideoTracks?.().length) return screenStream;
  return getLiveCameraTrack() ? cameraStream : null;
}

function getPreferredLocalAuxPreviewStream() {
  if (!isScreenSharing || !isCameraOn) return null;
  return getLiveCameraTrack() ? cameraStream : null;
}

function stopCameraLocalTracks() {
  if (!cameraStream) return;
  try {
    cameraStream.getTracks().forEach((t) => {
      t.onended = null;
      t.stop();
    });
  } catch (_) {}
  cameraStream = null;
}

function isCallMediaSessionActive() {
  const transportConvId = normId(callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  if (isServerVoiceTransportSessionActive(transportConvId)) return true;
  const connState = String(callPc?.connectionState || "").toLowerCase();
  const iceState = String(callPc?.iceConnectionState || "").toLowerCase();
  const peerUsable = !!(
    callPc
    && connState !== "closed"
    && connState !== "failed"
    && iceState !== "closed"
    && iceState !== "failed"
  );
  if (!peerUsable) return false;
  if (inCall) return true;
  return !!(
    connState === "connected"
    || connState === "connecting"
    || iceState === "connected"
    || iceState === "completed"
    || iceState === "checking"
  );
}

async function startCamera() {
  if (!isCallMediaSessionActive()) return alert("Tens de estar numa chamada.");
  const convId = normId(callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  if (shouldUseServerVoiceLiveKitTransport(convId)) {
    setCallStatus("Server voice is audio-only for now. Microphone audio stays live.", true);
    return;
  }

  const sender = getShareVideoSender();
  if (!sender) return alert("Canal de vÃ­deo ainda nÃ£o estÃ¡ pronto.");
  const cameraSender = getCameraVideoSender();
  const hadVideoBefore = !!getCurrentBroadcastVideoTrack();
  const wasScreenSharing = !!isScreenSharing;

  try {
    if (!cameraStream || !getLiveCameraTrack()) {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: {
          width: { ideal: 1920, max: 3840 },
          height: { ideal: 1080, max: 2160 },
          frameRate: { ideal: 60, max: 60 },
        },
        audio: false,
      });
      stopCameraLocalTracks();
      cameraStream = stream;
    }

    const track = getLiveCameraTrack();
    if (!track) throw new Error("Sem track de vÃ­deo da cÃ¢mara.");

    track.onended = () => {
      stopCamera({ silent: true }).catch(() => {});
    };

    isCameraOn = true;
    if (!wasScreenSharing) originalVideoTrack = track;
    const outgoingTrack = await syncPreferredOutgoingVideoTrackOnSender(sender);
    const secondaryTrack = await syncSecondaryOutgoingVideoTrackOnSender(cameraSender);
    if (!outgoingTrack && !secondaryTrack) throw new Error("Falhou ao enviar a cÃ¢mara.");
    setLocalSharePreviewStream(getPreferredLocalPreviewStream());
    await sendShareStateSignal(true, wasScreenSharing ? "share" : "camera");
    await syncRelayVideoBroadcastTargets(callConversationId || activeDmId || "");
    if (!hadVideoBefore || wasScreenSharing) await renegotiateCall("camera_on");
    refreshCallUI();
    playAndBroadcastLocalCallCue("camera_on");
  } catch (e) {
    console.error(e);
    setCallStatus(t("call.camera.error", "Failed to start camera.") + " " + (e?.message || String(e)), true);
  }
}

async function stopCamera(opts = {}) {
  const { silent = false } = opts;
  const sender = getShareVideoSender();
  const cameraSender = getCameraVideoSender();
  const liveTrack = getLiveCameraTrack();
  const wasScreenSharing = !!isScreenSharing;

  if (originalVideoTrack && liveTrack && originalVideoTrack.id === liveTrack.id) {
    originalVideoTrack = null;
  }

  isCameraOn = false;
  stopCameraLocalTracks();

  let keepVideoOn = false;
  if (sender) {
    try {
      const outgoingTrack = await syncPreferredOutgoingVideoTrackOnSender(sender);
      await syncSecondaryOutgoingVideoTrackOnSender(cameraSender);
      keepVideoOn = !!(outgoingTrack && outgoingTrack.readyState === "live");
    } catch (e) {
      if (!silent) console.warn("stopCamera replaceTrack failed", e);
    }
  } else {
    keepVideoOn = !!getCurrentBroadcastVideoTrack();
  }
  if (!keepVideoOn || wasScreenSharing) await renegotiateCall("camera_off");
  await sendShareStateSignal(keepVideoOn, keepVideoOn ? (isScreenSharing ? "share" : "camera") : "none");
  await syncRelayVideoBroadcastTargets(callConversationId || activeDmId || "");

  setLocalSharePreviewStream(getPreferredLocalPreviewStream());
  refreshCallUI();
  markLocalRemoteCallCueSuppress("camera_off");
  if (!silent) {
    playUiCue("camera_off");
    logMediaSfxPlayed("camera_off", {
      participantId: normId(state.user?.id || ""),
      tileType: "primary",
      isLocalUser: true,
      triggerReason: "local_call_ui_cue",
      callerFunction: "stopCamera",
    });
  }
  void sendCallUiCueSignal("camera_off");
}

async function toggleCamera() {
  if (isCameraOn) await stopCamera();
  else await startCamera();
}

