function showOverlay(show) {
  const { overlay } = getCallEls();
  if (!overlay) return;
  overlay.style.display = show ? "flex" : "none";
  overlay.setAttribute("aria-hidden", show ? "false" : "true");
}

function setCallStatus(text, show = true, { publicHint = false } = {}) {
  const { callStatus } = getCallEls();
  if (!callStatus) return;
  callStatus.style.display = show ? "block" : "none";
  callStatus.textContent = text || "";
  callPublicJoinHintVisible = !!(show && publicHint);
}

function setCallButtons(mode) {
  const { btnCall, btnAnswer, btnHangup } = getCallEls();

  if (!currentConversationCallEnabled) {
    if (btnCall) {
      btnCall.disabled = true;
      btnCall.style.display = "none";
    }
    if (btnAnswer) {
      btnAnswer.disabled = true;
      btnAnswer.style.display = "none";
    }
    if (btnHangup) {
      btnHangup.disabled = true;
      btnHangup.style.display = "none";
    }
    return;
  }

  if (btnCall) {
    btnCall.disabled = (mode === "inCall" || mode === "ringing");
    btnCall.style.display = "inline-flex";
  }

  if (btnHangup) {
    const showHang = (mode === "inCall" || mode === "ringing" || mode === "incoming");
    btnHangup.style.display = showHang ? "inline-flex" : "none";
    btnHangup.disabled = !showHang;
  }

  if (btnAnswer) {
    const showAns = (mode === "incoming");
    btnAnswer.style.display = showAns ? "inline-flex" : "none";
    btnAnswer.disabled = !showAns;
  }
}

