function bindCallShareMenuOnce() {
  if (callShareMenuBound) return;
  callShareMenuBound = true;

  const menu = document.getElementById("callShareMenu");
  if (!menu) return;

  menu.addEventListener("contextmenu", (ev) => { ev.preventDefault(); });
  menu.addEventListener("click", async (ev) => {
    ev.stopPropagation();
    ev.preventDefault();
    const activeConvId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
    const isServerVoiceScreenshareMode = !!(activeConvId && shouldUseServerVoiceLiveKitTransport(activeConvId));
    const actEl = ev.target?.closest?.("[data-call-share-act]");
    const act = String(actEl?.getAttribute?.("data-call-share-act") || "").trim().toLowerCase();
    if (!act) return;
    const serverVoiceLocalShareActive = !!(isServerVoiceScreenshareMode && isServerVoiceLocalScreenshareActive(activeConvId));
    if (!isCallMediaSessionActive() && !isScreenSharing && !serverVoiceLocalShareActive) {
      closeCallShareMenu();
      return;
    }
    if (isServerVoiceScreenshareMode) {
      try {
        if (act === "toggle-audio") {
          const previousPrefs = getServerVoiceScreensharePreferences(activeConvId, {
            reason: "owner_stream_menu_toggle_audio_before",
            source: "owner_stream_menu",
            logLoaded: false,
            callerFunction: "bindCallShareMenuOnce",
          });
          const previousShareAudioEnabled = !!previousPrefs?.shareAudioEnabled;
          const nextPrefs = await toggleServerVoiceScreenshareStreamAudio(activeConvId, {
            triggerReason: "server_voice_share_menu_audio_toggle",
            callerFunction: "bindCallShareMenuOnce",
          });
          const nextShareAudioEnabled = !!nextPrefs?.shareAudioEnabled;
          if (serverVoiceLocalShareActive) {
            logServerVoiceDebug("screenshare.share_audio_restart_required", {
              conversationId: activeConvId || null,
              triggerReason: "server_voice_share_menu_audio_toggle",
              callerFunction: "bindCallShareMenuOnce",
              reason: "owner_toggle_while_streaming",
              previousShareAudioEnabled,
              nextShareAudioEnabled,
            });
            logServerVoiceDebug("screenshare.share_audio_used_for_capture", {
              conversationId: activeConvId || null,
              triggerReason: "server_voice_share_menu_audio_toggle",
              callerFunction: "bindCallShareMenuOnce",
              source: "owner_menu_toggle_restart",
              action: "restart",
              shareAudioEnabled: nextShareAudioEnabled,
              localShareActive: true,
            });
            await restartServerVoiceScreenshareWithStageCleanup(activeConvId, {
              triggerReason: "server_voice_share_menu_audio_toggle_restart",
              callerFunction: "bindCallShareMenuOnce",
              restoreFocusIfPreviouslyFocused: true,
            });
            logServerVoiceDebug("screenshare.share_audio_restart_completed", {
              conversationId: activeConvId || null,
              triggerReason: "server_voice_share_menu_audio_toggle",
              callerFunction: "bindCallShareMenuOnce",
              reason: "owner_toggle_while_streaming",
              previousShareAudioEnabled,
              nextShareAudioEnabled,
            });
            setCallStatus("Share audio updated and stream restarted.", true);
            setTimeout(() => setCallStatus("", false), 2200);
          } else {
            setCallStatus("Share audio preference saved for the next stream.", false);
            setTimeout(() => setCallStatus("", false), 1800);
          }
          syncCallShareMenuUi();
          return;
        }
        if (act === "stop") {
          if (serverVoiceLocalShareActive) {
            await toggleServerVoiceScreenshare(activeConvId, {
              triggerReason: "server_voice_share_menu_primary_stop",
            });
            closeCallShareMenu();
          } else {
            await toggleServerVoiceScreenshare(activeConvId, {
              triggerReason: "server_voice_share_menu_primary_start",
            });
            closeCallShareMenu();
          }
          return;
        }
        if (act === "change") {
          const selectedSource = await selectServerVoiceScreenshareSource(activeConvId, {
            triggerReason: "server_voice_share_menu_source_select",
          });
          if (!selectedSource) {
            syncCallShareMenuUi();
            return;
          }
          if (serverVoiceLocalShareActive) {
            const prefs = getServerVoiceScreensharePreferences(activeConvId, {
              reason: "owner_stream_menu_change_stream",
              source: "owner_stream_menu",
              logLoaded: false,
              callerFunction: "bindCallShareMenuOnce",
            });
            logServerVoiceDebug("screenshare.share_audio_used_for_capture", {
              conversationId: activeConvId || null,
              triggerReason: "server_voice_share_menu_change_restart",
              callerFunction: "bindCallShareMenuOnce",
              source: "owner_menu_change_stream",
              action: "restart",
              shareAudioEnabled: !!prefs?.shareAudioEnabled,
              localShareActive: true,
            });
            await restartServerVoiceScreenshareWithStageCleanup(activeConvId, {
              triggerReason: "server_voice_share_menu_change_restart",
              callerFunction: "bindCallShareMenuOnce",
              restoreFocusIfPreviouslyFocused: true,
            });
            closeCallShareMenu();
            return;
          }
          syncCallShareMenuUi();
          return;
        }
        if (act === "quality") {
          await openServerVoiceScreenshareFullPicker(activeConvId, {
            triggerReason: "server_voice_share_menu_quality",
            callerFunction: "bindCallShareMenuOnce",
          });
          return;
        }
        if (act === "popout") {
          await toggleCallPictureInPicture();
          closeCallShareMenu();
          return;
        }
        if (act === "more-options") {
          setCallStatus("More stream options are coming soon.", true);
          setTimeout(() => setCallStatus("", false), 1700);
          return;
        }
      } catch (error) {
        const errorText = String(error?.message || error || "Unable to update screenshare settings.").trim() || "Unable to update screenshare settings.";
        setCallStatus(errorText, true);
        setTimeout(() => setCallStatus("", false), 2200);
      }
      return;
    }
    if (act === "toggle-audio") {
      const newAudio = !getShareAudioEnabled();
      localStorage.setItem(SHARE_AUDIO_KEY, newAudio ? "1" : "0");
      syncCallShareMenuUi();
      // sync picker checkbox if open
      const pickerAudioEl = document.getElementById("desktopSharePickerAudioToggle");
      if (pickerAudioEl instanceof HTMLInputElement) pickerAudioEl.checked = newAudio;
      await applyShareSettingsLive("audio");
      return;
    }
    if (act === "stop") {
      closeCallShareMenu();
      await stopScreenShare();
      return;
    }
    if (act === "change") {
      closeCallShareMenu();
      await startScreenShare();
      return;
    }
    if (act === "quality") {
      closeCallShareMenu();
      await startScreenShare();
      return;
    }
    if (act === "popout") {
      await toggleCallPictureInPicture();
      closeCallShareMenu();
      return;
    }
    if (act === "more-options") {
      setCallStatus("More stream options are coming soon.", true);
      setTimeout(() => setCallStatus("", false), 1700);
      return;
    }
  });

  window.addEventListener("pointerdown", (ev) => {
    const shareMenu = document.getElementById("callShareMenu");
    if (!shareMenu || !shareMenu.classList.contains("is-open")) return;
    if (ev.target instanceof Node && shareMenu.contains(ev.target)) return;
    closeCallShareMenu();
  }, { capture: true });
  window.addEventListener("scroll", closeCallShareMenu, { passive: true });
  window.addEventListener("resize", closeCallShareMenu);
  document.addEventListener("keydown", (ev) => {
    if (ev.key === "Escape") closeCallShareMenu();
  });
}

function resolveRemoteAudioType(track, ev = null, opts = {}) {
  const explicitTrackSourceType = resolveRemoteAudioTypeFromTrackSource(
    opts?.trackSource
    || opts?.publicationSource
    || track?.source
    || ""
  );
  if (explicitTrackSourceType) return explicitTrackSourceType;
  const label = String(track?.label || "").toLowerCase();
  const hint = String(track?.contentHint || "").toLowerCase();
  const streamHasVideo = !!(ev?.streams || []).some((s) => s?.getVideoTracks?.().length);
  const labelLooksShare = /screen|desktop|system|window|tab|application|monitor|loopback|share|captur|partilh/.test(label);
  const labelLooksMic = /mic|micro|voice|input/.test(label);

  if (hint.includes("music")) return REMOTE_AUDIO_TYPE_SHARE;
  if (labelLooksShare || streamHasVideo) return REMOTE_AUDIO_TYPE_SHARE;

  const liveVoice = Array.from(remoteAudioTrackEls.values()).some((entry) => (
    entry?.type === REMOTE_AUDIO_TYPE_VOICE && entry?.track?.readyState === "live"
  ));
  const liveShare = Array.from(remoteAudioTrackEls.values()).some((entry) => (
    entry?.type === REMOTE_AUDIO_TYPE_SHARE && entry?.track?.readyState === "live"
  ));

  if (remoteIsSharing) {
    if (!liveShare && !liveVoice) return REMOTE_AUDIO_TYPE_VOICE;
    if (!liveShare && liveVoice) return REMOTE_AUDIO_TYPE_SHARE;
    if (liveShare && !liveVoice) return REMOTE_AUDIO_TYPE_VOICE;
  }

  if (labelLooksMic && !labelLooksShare) return REMOTE_AUDIO_TYPE_VOICE;
  if (!liveVoice) return REMOTE_AUDIO_TYPE_VOICE;
  if (remoteIsSharing && !liveShare) return REMOTE_AUDIO_TYPE_SHARE;
  return REMOTE_AUDIO_TYPE_VOICE;
}

function reconcileRemoteAudioTypes() {
  const entries = Array.from(remoteAudioTrackEls.values());
  if (!entries.length) return;

  const live = entries.filter((entry) => entry?.track?.readyState !== "ended");
  if (!live.length) return;
  const convId = normId(callConversationId || activeDmId || "");
  const isServerVoiceCall = !!(convId && isServerVoiceConversationById(convId));
  if (isServerVoiceCall) {
    live.forEach((entry) => {
      if (!entry) return;
      const explicitType = resolveRemoteAudioTypeFromTrackSource(
        entry?.trackSource
        || entry?.track?.source
        || ""
      );
      if (explicitType) {
        entry.type = explicitType;
        entry.typeLocked = true;
        return;
      }
      entry.type = resolveRemoteAudioEntryType(entry);
    });
    applyRemoteAudioVolumes();
    syncCallAudioMenuUi();
    return;
  }

  if (!remoteIsSharing) {
    live.forEach((entry) => { entry.type = REMOTE_AUDIO_TYPE_VOICE; });
    applyRemoteAudioVolumes();
    syncCallAudioMenuUi();
    return;
  }

  if (live.length === 1) {
    const single = live[0];
    single.type = single.type === REMOTE_AUDIO_TYPE_SHARE
      ? REMOTE_AUDIO_TYPE_SHARE
      : REMOTE_AUDIO_TYPE_VOICE;
    applyRemoteAudioVolumes();
    syncCallAudioMenuUi();
    return;
  }

  let hasVoice = live.some((entry) => entry.type === REMOTE_AUDIO_TYPE_VOICE);
  let hasShare = live.some((entry) => entry.type === REMOTE_AUDIO_TYPE_SHARE);

  if (!hasShare && live.length >= 2) {
    const candidate = [...live].reverse().find((entry) => entry.type !== REMOTE_AUDIO_TYPE_SHARE);
    if (candidate) {
      candidate.type = REMOTE_AUDIO_TYPE_SHARE;
      hasShare = true;
    }
  }

  if (!hasVoice && live.length) {
    const candidate = live.find((entry) => entry.type !== REMOTE_AUDIO_TYPE_VOICE) || live[0];
    if (candidate) candidate.type = REMOTE_AUDIO_TYPE_VOICE;
  }

  applyRemoteAudioVolumes();
  syncCallAudioMenuUi();
}

async function ensureRemoteAudio() {
  const { remoteAudio } = getCallEls();
  if (remoteAudio) return remoteAudio;

  const a = document.createElement("audio");
  a.autoplay = true;
  a.playsInline = true;
  a.style.display = "none";
  document.body.appendChild(a);
  return a;
}

function muteAllRemoteAudioTracks(muted) {
  deafened = !!muted;
  applyRemoteAudioVolumes();
}

function bindPendingRemoteAudioPlayUnlockOnce() {
  if (pendingRemoteAudioPlayUnlockBound) return;
  pendingRemoteAudioPlayUnlockBound = true;

  const flush = () => {
    void flushPendingRemoteAudioPlayback();
  };
  window.addEventListener("pointerdown", flush, { capture: true, passive: true });
  window.addEventListener("touchstart", flush, { capture: true, passive: true });
  window.addEventListener("keydown", flush, true);
  document.addEventListener("visibilitychange", () => {
    if (document.visibilityState === "visible") flush();
  });
}

function queuePendingRemoteAudioPlayback(audioEl) {
  if (!audioEl) return;
  pendingRemoteAudioPlayEls.add(audioEl);
  bindPendingRemoteAudioPlayUnlockOnce();
}

function attemptRemoteAudioPlayback(audioEl, { queueOnFail = true } = {}) {
  if (!audioEl || !audioEl.srcObject) return;
  const previousMuted = !!audioEl.muted;
  try { audioEl.muted = true; } catch (_) {}

  let playPromise = null;
  try {
    playPromise = audioEl.play?.();
  } catch (_) {
    playPromise = null;
  }

  const onSuccess = () => {
    pendingRemoteAudioPlayEls.delete(audioEl);
    applyRemoteAudioVolumes();
  };
  const onFailure = () => {
    try { audioEl.muted = previousMuted; } catch (_) {}
    if (queueOnFail) queuePendingRemoteAudioPlayback(audioEl);
  };

  if (playPromise && typeof playPromise.then === "function") {
    playPromise.then(onSuccess).catch(onFailure);
    return;
  }
  onSuccess();
}

async function flushPendingRemoteAudioPlayback() {
  if (!pendingRemoteAudioPlayEls.size) return;
  const entries = Array.from(pendingRemoteAudioPlayEls.values());
  for (const audioEl of entries) {
    if (!audioEl || !audioEl.isConnected || !audioEl.srcObject) {
      pendingRemoteAudioPlayEls.delete(audioEl);
      continue;
    }
    attemptRemoteAudioPlayback(audioEl, { queueOnFail: true });
  }
}

function closeRemoteAudioProcessingNodes(entry) {
  if (!entry || typeof entry !== "object") return;
  try { entry.gainSourceNode?.disconnect?.(); } catch (_) {}
  try { entry.gainNode?.disconnect?.(); } catch (_) {}
  entry.gainSourceNode = null;
  entry.gainNode = null;
  entry.gainDestNode = null;
  if (entry.gainCtx) {
    try { entry.gainCtx.close?.().catch?.(() => {}); } catch (_) {}
    entry.gainCtx = null;
  }
}

function removeRemoteAudioTrackEl(trackId, { reason = "cleanup" } = {}) {
  const key = normId(trackId || "");
  const entry = remoteAudioTrackEls.get(key);
  const audioEl = entry?.audioEl || entry;
  if (!audioEl) return;
  const convId = normId(entry?.conversationId || callConversationId || activeDmId || "");
  const ownerUserId = normId(entry?.ownerUserId || "");
  const source = String(entry?.source || "").trim().toLowerCase();
  const track = entry?.track || null;
  const trackSid = String(entry?.trackSid || "").trim() || null;
  const domCountBefore = convId && ownerUserId ? countServerVoiceRemoteAudioDomElements(ownerUserId, convId) : 0;
  pendingRemoteAudioPlayEls.delete(audioEl);
  closeRemoteAudioProcessingNodes(entry);
  try {
    if (entry?.rawStream && track) entry.rawStream.removeTrack?.(track);
  } catch (_) {}
  if (track && typeof track.removeEventListener === "function") {
    try {
      if (typeof entry?.onTrackMute === "function") track.removeEventListener("mute", entry.onTrackMute);
      if (typeof entry?.onTrackUnmute === "function") track.removeEventListener("unmute", entry.onTrackUnmute);
      if (typeof entry?.onTrackEnded === "function") track.removeEventListener("ended", entry.onTrackEnded);
    } catch (_) {}
  }
  if (track) {
    try { if (track.onmute === entry?.onTrackMute) track.onmute = null; } catch (_) {}
    try { if (track.onunmute === entry?.onTrackUnmute) track.onunmute = null; } catch (_) {}
    try { if (track.onended === entry?.onTrackEnded) track.onended = null; } catch (_) {}
  }
  try {
    audioEl.pause?.();
    audioEl.srcObject = null;
    audioEl.remove?.();
  } catch (_) {}
  remoteAudioTrackEls.delete(key);
  for (const relayEntry of relayAudioPeersByUser.values()) {
    try { relayEntry?.remoteTrackIds?.delete?.(key); } catch (_) {}
  }
  releaseCallSpeakingMeter(key);
  if (convId && ownerUserId && isServerVoiceConversationById(convId)) {
    logServerVoiceDebug("track.unsubscribed", {
      conversationId: convId,
      peerUserId: ownerUserId || null,
      source,
      reason: String(reason || "").trim() || null,
      trackId: key || null,
      trackSid,
      domAudioElementsBefore: domCountBefore || 0,
      ...describeServerVoiceAudioTrack(track),
    });
    logServerVoiceDebug("track.detached", {
      conversationId: convId,
      peerUserId: ownerUserId || null,
      source,
      reason: String(reason || "").trim() || null,
      trackId: key || null,
      trackSid,
      domAudioElementsAfter: countServerVoiceRemoteAudioDomElements(ownerUserId, convId),
    });
    logServerVoiceParticipantAudioStateIfChanged(convId, ownerUserId, {
      reason: "remote_track_detached",
      source,
      track,
    });
  }
  if (source === "livekit" && convId && ownerUserId) {
    logServerVoiceDebug("remote_track_lost", {
      conversationId: convId,
      peerUserId: ownerUserId || null,
      trackId: key || null,
      trackSid,
      reason: String(reason || "").trim() || null,
    });
    markServerVoiceTransportRemoteAudioDetached(convId, ownerUserId, key, trackSid);
    reconcileServerVoiceTransportRemoteTrackDiagnostics(convId, { trigger: "detach" });
  }
  reconcileRemoteAudioTypes();
}

function hasLiveRemoteAudioTrackFromOwner(ownerUserId, { source = "", type = "" } = {}) {
  const uid = normId(ownerUserId || "");
  if (!uid) return false;
  const wantedSource = String(source || "").trim().toLowerCase();
  const wantedType = type === REMOTE_AUDIO_TYPE_SHARE ? REMOTE_AUDIO_TYPE_SHARE : (type === REMOTE_AUDIO_TYPE_VOICE ? REMOTE_AUDIO_TYPE_VOICE : "");
  for (const entry of remoteAudioTrackEls.values()) {
    if (!entry) continue;
    const entryOwner = normId(entry?.ownerUserId || "");
    if (!entryOwner || entryOwner !== uid) continue;
    if (wantedSource) {
      const entrySource = String(entry?.source || "").trim().toLowerCase();
      if (entrySource !== wantedSource) continue;
    }
    if (wantedType) {
      const entryType = resolveRemoteAudioEntryPlaybackDomain(entry);
      if (entryType !== wantedType) continue;
    }
    const trackLive = isLiveAudioTrack(entry?.track || null);
    if (trackLive) return true;
  }
  return false;
}

function attachRemoteAudioTrack(track, ev = null, opts = {}) {
  if (!track || track.kind !== "audio") return;
  const trackId = track.id || String(Math.random());
  const trackSid = String(opts?.trackSid || "").trim() || null;
  const trackSource = normalizeRemoteAudioTrackSource(
    opts?.trackSource
    || opts?.publicationSource
    || track?.source
    || ""
  );
  const type = resolveRemoteAudioType(track, ev, {
    ...opts,
    trackSource,
    trackSid,
  });
  const mediaDomain = type === REMOTE_AUDIO_TYPE_SHARE ? REMOTE_AUDIO_TYPE_SHARE : REMOTE_AUDIO_TYPE_VOICE;
  const typeLocked = !!resolveRemoteAudioTypeFromTrackSource(trackSource);
  const ownerUserId = normId(
    opts?.ownerUserId || callMediaPeerUserId || callOtherUserId || pendingCallInfo?.fromUserId || ""
  );
  const source = String(opts?.source || "").trim().toLowerCase() || "direct";
  const attachedAt = Date.now();
  const convId = normId(callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  const streamPreferenceKey = type === REMOTE_AUDIO_TYPE_SHARE
    ? resolveStableRemoteStreamPreferenceKey("", {
      conversationId: convId,
      participantId: ownerUserId,
      trackSid,
      trackId,
      logResolution: true,
      triggerReason: "remote_stream_audio_attach",
      callerFunction: "attachRemoteAudioTrack",
    })
    : "";
  const isServerVoiceCall = !!(convId && isServerVoiceConversationById(convId));
  if (remoteAudioTrackEls.has(trackId)) {
    if (isServerVoiceCall && ownerUserId) {
      logServerVoiceDebug("track.subscribed", {
        conversationId: convId,
        peerUserId: ownerUserId || null,
        source,
        trackId: String(track.id || "") || null,
        duplicateTrackId: true,
      });
    }
    return;
  }

  let ownerEntries = [];
  const domAudioElementsBeforeAttach = isServerVoiceCall && ownerUserId
    ? countServerVoiceRemoteAudioDomElements(ownerUserId, convId)
    : 0;
  if (isServerVoiceCall && ownerUserId) {
    ownerEntries = Array.from(remoteAudioTrackEls.entries()).filter(([existingTrackId, existingEntry]) => {
      if (!existingEntry || existingTrackId === trackId) return false;
      return normId(existingEntry?.ownerUserId || "") === ownerUserId
        && normId(existingEntry?.conversationId || convId) === convId
        && resolveRemoteAudioEntryPlaybackDomain(existingEntry) === mediaDomain;
    });
    if (ownerEntries.length > 0 || domAudioElementsBeforeAttach > 1) {
      logServerVoiceDebug("remote_audio.duplicate_detected", {
        conversationId: convId,
        peerUserId: ownerUserId || null,
        source,
        mediaDomain,
        trackId: String(track.id || "") || null,
        trackSid,
        duplicateTrackIds: ownerEntries.map(([existingTrackId]) => existingTrackId).filter(Boolean),
        duplicateSources: ownerEntries.map(([, existingEntry]) => String(existingEntry?.source || "").trim().toLowerCase()).filter(Boolean),
        domAudioElementsBefore: domAudioElementsBeforeAttach,
      });
    }
    const highestExistingPriority = ownerEntries.reduce((maxPriority, [, existingEntry]) => {
      return Math.max(maxPriority, getServerVoiceRemoteAudioSourcePriority(existingEntry?.source || ""));
    }, 0);
    const nextPriority = getServerVoiceRemoteAudioSourcePriority(source);
    if (highestExistingPriority > nextPriority) {
      logServerVoiceDebug("track.subscribed", {
        conversationId: convId,
        peerUserId: ownerUserId || null,
        source,
        mediaDomain,
        trackId: String(track.id || "") || null,
        attachSkipped: true,
        skipReason: "lower_priority_source",
        existingSources: ownerEntries.map(([, existingEntry]) => String(existingEntry?.source || "").trim().toLowerCase()).filter(Boolean),
      });
      return;
    }
    ownerEntries.forEach(([existingTrackId]) => {
      removeRemoteAudioTrackEl(existingTrackId, {
        reason: `owner_replaced_by_${source || "audio"}`,
      });
    });
  }

  const audioEl = document.createElement("audio");
  audioEl.autoplay = true;
  audioEl.playsInline = true;
  audioEl.style.display = "none";
  audioEl.muted = !!deafened || (type === REMOTE_AUDIO_TYPE_SHARE ? !!remoteShareMuted : !!remoteVoiceMuted);
  audioEl.dataset.remoteAudioOwner = ownerUserId || "";
  audioEl.dataset.remoteAudioTrackId = String(trackId || "");
  audioEl.dataset.remoteAudioTrackSid = trackSid || "";
  audioEl.dataset.remoteAudioConversation = convId || "";
  audioEl.dataset.remoteAudioSource = source || "direct";
  audioEl.dataset.remoteAudioStreamKey = streamPreferenceKey || "";
  audioEl.dataset.remoteAudioTrackSource = trackSource || "";
  audioEl.dataset.remoteAudioType = mediaDomain;

  const rawStream = new MediaStream();
  try { rawStream.addTrack(track); } catch (_) {}

  audioEl.srcObject = rawStream;
  document.body.appendChild(audioEl);
  void applyPreferredOutputDeviceToAudioEl(audioEl);
  const onTrackMute = () => {
    if (convId && ownerUserId && isServerVoiceConversationById(convId)) {
      logServerVoiceDebug("track.remote.muted", {
        conversationId: convId,
        peerUserId: ownerUserId || null,
        source,
        trackId: String(track.id || "") || null,
      });
      logServerVoiceParticipantAudioStateIfChanged(convId, ownerUserId, {
        reason: "remote_track_muted",
        source,
        track,
      });
    }
  };
  const onTrackUnmute = () => {
    if (convId && ownerUserId && isServerVoiceConversationById(convId)) {
      logServerVoiceDebug("track.remote.unmuted", {
        conversationId: convId,
        peerUserId: ownerUserId || null,
        source,
        trackId: String(track.id || "") || null,
      });
      logServerVoiceParticipantAudioStateIfChanged(convId, ownerUserId, {
        reason: "remote_track_unmuted",
        source,
        track,
      });
    }
    void unlockAudioOnce();
    attemptRemoteAudioPlayback(audioEl, { queueOnFail: true });
  };
  const onTrackEnded = () => removeRemoteAudioTrackEl(trackId, { reason: "track_ended" });
  if (typeof track.addEventListener === "function") {
    try { track.addEventListener("mute", onTrackMute); } catch (_) {}
    try { track.addEventListener("unmute", onTrackUnmute); } catch (_) {}
    try { track.addEventListener("ended", onTrackEnded, { once: true }); } catch (_) {}
  } else {
    try { track.onmute = onTrackMute; } catch (_) {}
    try { track.onunmute = onTrackUnmute; } catch (_) {}
    try { track.onended = onTrackEnded; } catch (_) {}
  }
  remoteAudioTrackEls.set(trackId, {
    id: trackId,
    type,
    typeLocked,
    trackSource,
    mediaDomain,
    track,
    ownerUserId,
    source,
    conversationId: convId,
    attachedAt,
    trackSid,
    streamPreferenceKey,
    rawStream,
    audioEl,
    onTrackMute,
    onTrackUnmute,
    onTrackEnded,
  });
  if (convId && ownerUserId && isServerVoiceConversationById(convId)) {
    logServerVoiceDebug("track.subscribed", {
      conversationId: convId,
      peerUserId: ownerUserId || null,
      source,
      trackId: String(track.id || "") || null,
      trackSid,
      domAudioElementsBefore: domAudioElementsBeforeAttach,
      ...describeServerVoiceAudioTrack(track),
    });
    touchServerVoicePeerDebug(convId, ownerUserId, {
      lastRemoteAudioTrackAt: attachedAt,
      lastRemoteTrackSource: source,
    });
    logServerVoiceDebug("track.attached", {
      conversationId: convId,
      peerUserId: ownerUserId || null,
      source,
      trackId: String(track.id || "") || null,
      trackSid,
      audioElementMuted: !!audioEl.muted,
      remoteAudioType: type || null,
      remoteAudioTrackSource: trackSource || null,
      outputDeviceId: String(voiceOutputDeviceId || "").trim() || "default",
      domAudioElementsAfter: countServerVoiceRemoteAudioDomElements(ownerUserId, convId),
    });
    logServerVoiceDebug("track.attach.remote_audio", {
      conversationId: convId,
      peerUserId: ownerUserId || null,
      source,
      trackId: String(track.id || "") || null,
      trackSid,
      audioElementMuted: !!audioEl.muted,
      remoteAudioType: type || null,
      remoteAudioTrackSource: trackSource || null,
      outputDeviceId: String(voiceOutputDeviceId || "").trim() || "default",
      deafened: !!deafened,
      remoteVoiceMuted: !!remoteVoiceMuted,
      remoteShareMuted: !!remoteShareMuted,
    });
    logServerVoiceParticipantAudioStateIfChanged(convId, ownerUserId, {
      reason: "remote_track_attached",
      source,
      track,
      domAudioElementsAfter: countServerVoiceRemoteAudioDomElements(ownerUserId, convId),
    });
  }
  if (source === "livekit" && convId && ownerUserId) {
    markServerVoiceTransportRemoteAudioAttached(
      convId,
      ownerUserId,
      String(track.id || "") || null,
      trackSid,
    );
    reconcileServerVoiceTransportRemoteTrackDiagnostics(convId, { trigger: "attach" });
  }
  registerCallSpeakingMeter(track, ownerUserId, { local: false });
  reconcileRemoteAudioTypes();
  if (mediaDomain === REMOTE_AUDIO_TYPE_SHARE && streamPreferenceKey) {
    logStreamAudioSettingsEvent("stream_audio.settings_applied_on_attach", {
      streamKey: streamPreferenceKey,
      participantId: ownerUserId,
      conversationId: convId,
      volume: getRemoteStreamVolume(streamPreferenceKey),
      muted: getRemoteStreamMuted(streamPreferenceKey),
      attenuationEnabled: getRemoteStreamAttenuationEnabled(streamPreferenceKey),
      attenuationStrength: getRemoteStreamAttenuationStrength(streamPreferenceKey),
      triggerReason: "remote_stream_audio_attach",
      callerFunction: "attachRemoteAudioTrack",
      trackSid: trackSid || null,
      source,
    });
  }
  if (isServerVoiceCall && ownerUserId) {
    const duplicateEntries = Array.from(remoteAudioTrackEls.entries()).filter(([existingTrackId, existingEntry]) => {
      if (!existingEntry || existingTrackId === trackId) return false;
      return normId(existingEntry?.ownerUserId || "") === ownerUserId
        && normId(existingEntry?.conversationId || convId) === convId
        && resolveRemoteAudioEntryPlaybackDomain(existingEntry) === mediaDomain;
    });
    duplicateEntries.forEach(([existingTrackId]) => {
      removeRemoteAudioTrackEl(existingTrackId, {
        reason: "post_attach_duplicate_prune",
      });
    });
    const finalDomCount = countServerVoiceRemoteAudioDomElements(ownerUserId, convId);
    const finalDomainCount = Array.from(remoteAudioTrackEls.values()).filter((candidateEntry) => (
      candidateEntry
      && normId(candidateEntry?.ownerUserId || "") === ownerUserId
      && normId(candidateEntry?.conversationId || convId) === convId
      && resolveRemoteAudioEntryPlaybackDomain(candidateEntry) === mediaDomain
    )).length;
    if (finalDomainCount > 1) {
      logServerVoiceDebug("remote_audio.duplicate_dom_detected", {
        conversationId: convId,
        peerUserId: ownerUserId || null,
        source,
        mediaDomain,
        trackId: String(track.id || "") || null,
        trackSid,
        domainAudioElementsAfterPrune: finalDomainCount,
        domAudioElementsAfterPrune: finalDomCount,
      });
    }
  }

  const tryPlay = () => {
    void unlockAudioOnce();
    attemptRemoteAudioPlayback(audioEl, { queueOnFail: true });
  };
  tryPlay();
  setTimeout(tryPlay, 240);
}

function clearRemoteAudioTrackEls() {
  const ids = Array.from(remoteAudioTrackEls.keys());
  ids.forEach((id) => removeRemoteAudioTrackEl(id, { reason: "clear_all_remote_audio" }));
  syncCallAudioMenuUi();
}

async function applyAudioSenderQuality(sender, { music = false } = {}) {
  if (!sender) return;
  try {
    const params = sender.getParameters?.() || {};
    if (!params.encodings || !params.encodings.length) params.encodings = [{}];
    params.encodings[0].maxBitrate = music ? 256_000 : 96_000;
    params.encodings[0].dtx = false;
    await sender.setParameters?.(params);
  } catch (e) {
    console.warn("set audio quality params failed", e);
  }
}

function isLiveAudioTrack(track) {
  return !!(
    track
    && track.kind === "audio"
    && String(track.readyState || "").toLowerCase() !== "ended"
  );
}

function getLocalRawMicTrack() {
  const tracks = callLocalRawAudioStream?.getAudioTracks?.() || [];
  return tracks.find((t) => isLiveAudioTrack(t)) || tracks[0] || null;
}

function getProcessedMicTrack() {
  if (!callLocalStream || callLocalStream === callLocalRawAudioStream) return null;
  const tracks = callLocalStream?.getAudioTracks?.() || [];
  return tracks.find((t) => isLiveAudioTrack(t)) || tracks[0] || null;
}

function getBestLocalMicTrack() {
  return getProcessedMicTrack() || getLocalRawMicTrack() || null;
}

function setLocalMicFallbackToRawTrack() {
  const rawTrack = getLocalRawMicTrack();
  if (!rawTrack) return null;
  callLocalStream = callLocalRawAudioStream || callLocalStream;
  localMicTrack = rawTrack;
  cleanupLocalMicProcessing(true);
  return rawTrack;
}

async function ensureLocalMicProcessingState({ allowFallbackToRaw = true } = {}) {
  const ctx = localMicAudioCtx || null;
  if (!ctx) {
    const bestTrack = getBestLocalMicTrack();
    if (bestTrack) localMicTrack = bestTrack;
    return bestTrack;
  }

  const now = Date.now();
  const state = String(ctx.state || "").trim().toLowerCase();
  if (state !== "running" && now >= callLocalAudioCtxResumeAtMs) {
    callLocalAudioCtxResumeAtMs = now + CALL_LOCAL_AUDIO_CTX_RESUME_COOLDOWN_MS;
    try { await ctx.resume?.(); } catch (_) {}
  }

  const nextState = String((localMicAudioCtx?.state || ctx.state || "")).trim().toLowerCase();
  if (nextState === "running") {
    const processedTrack = getProcessedMicTrack();
    if (processedTrack) {
      localMicTrack = processedTrack;
      return processedTrack;
    }
  }

  if (allowFallbackToRaw) {
    const fallbackTrack = setLocalMicFallbackToRawTrack();
    if (fallbackTrack) return fallbackTrack;
  }

  const bestTrack = getBestLocalMicTrack();
  if (bestTrack) localMicTrack = bestTrack;
  return bestTrack;
}

function setCallLocalAudioHealthWatch(enabled) {
  if (!enabled) {
    if (callLocalAudioHealthTimer) {
      clearInterval(callLocalAudioHealthTimer);
      callLocalAudioHealthTimer = null;
    }
    callLocalAudioHealthTickInFlight = false;
    return;
  }
  if (callLocalAudioHealthTimer) return;
  callLocalAudioHealthTimer = setInterval(() => {
    void runCallLocalAudioHealthTick();
  }, CALL_LOCAL_AUDIO_HEALTH_POLL_MS);
  void runCallLocalAudioHealthTick();
}

async function ensureOutgoingLocalMicHealthy() {
  if (!callPc) return false;

  let track = await ensureLocalMicProcessingState({ allowFallbackToRaw: true });
  if (!isLiveAudioTrack(track)) {
    try {
      const stream = await getLocalAudioStream();
      const streamTracks = stream?.getAudioTracks?.() || [];
      track = streamTracks.find((t) => isLiveAudioTrack(t)) || getBestLocalMicTrack();
    } catch (_) {
      track = getBestLocalMicTrack();
    }
  }
  if (!isLiveAudioTrack(track)) return false;

  localMicTrack = track;
  try { localMicTrack.contentHint = "speech"; } catch (_) {}

  let sender = callMicSender || null;
  if (!sender && callPc?.getSenders) {
    sender = callPc.getSenders().find((s) => s?.track?.kind === "audio") || null;
  }
  if (sender) callMicSender = sender;

  const senderTrack = sender?.track || null;
  const senderTrackId = String(senderTrack?.id || "");
  const localTrackId = String(track?.id || "");
  const senderHasLiveTrack = isLiveAudioTrack(senderTrack);
  const needsRebind = !sender || !senderHasLiveTrack || senderTrackId !== localTrackId;

  if (needsRebind) {
    const baseStream = callLocalStream || callLocalRawAudioStream || new MediaStream([track]);
    if (sender) {
      await sender.replaceTrack(track);
      callMicSender = sender;
    } else {
      callMicSender = callPc.addTrack(track, baseStream);
    }
    await applyAudioSenderQuality(callMicSender, { music: false });

    const convId = normId(callConversationId || activeDmId || "");
    const peerUserId = normId(callMediaPeerUserId || callOtherUserId || pendingCallInfo?.fromUserId || "");
    if (convId && isServerVoiceConversationById(convId)) {
      if (peerUserId) {
        touchServerVoicePeerDebug(convId, peerUserId, {
          lastLocalTrackPublishedAt: Date.now(),
        });
      }
      logServerVoiceLocalMediaDebug("track.published", convId, {
        peerUserId: peerUserId || null,
        transport: "direct",
        reason: "health_rebind",
        senderTrackId: String(callMicSender?.track?.id || "") || null,
        ...describeServerVoiceAudioTrack(callMicSender?.track || localMicTrack || null),
        ...describeServerVoiceAudioTrackSettings(callMicSender?.track || localMicTrack || null),
      });
      logServerVoiceLocalMediaDebug("track.publish.direct", convId, {
        peerUserId: peerUserId || null,
        reason: "health_rebind",
        senderTrackId: String(callMicSender?.track?.id || "") || null,
      });
      logServerVoiceLocalMicStateIfChanged(convId, {
        reason: "health_rebind",
      });
    }
    if (groupCallMode && convId) {
      void syncRelayAudioPeers(convId, { force: true });
    }
  }

  if (localMicTrack.enabled !== !micMuted) {
    try { localMicTrack.enabled = !micMuted; } catch (_) {}
  }
  applyMicMute();
  return needsRebind;
}

async function runCallLocalAudioHealthTick() {
  if (callLocalAudioHealthTickInFlight) return;
  if (!inCall || !callPc) return;
  callLocalAudioHealthTickInFlight = true;
  try {
    await ensureOutgoingLocalMicHealthy();
  } catch (e) {
    console.warn("local mic health tick failed", e);
  } finally {
    callLocalAudioHealthTickInFlight = false;
  }
}

async function getLocalAudioStream() {
  if (callLocalStream) return callLocalStream;
  const rawStream = await requestVoiceInputStream();

  callLocalRawAudioStream = rawStream;
  callLocalStream = buildLocalMicStream(rawStream);
  localMicTrack = getBestLocalMicTrack() || rawStream.getAudioTracks?.()[0] || null;
  await ensureLocalMicProcessingState({ allowFallbackToRaw: true });
  localMicTrack = getBestLocalMicTrack() || localMicTrack;
  try { if (localMicTrack) localMicTrack.contentHint = "speech"; } catch (_) {}
  applyVoiceMicGainLive();
  const convId = getInspectableServerVoiceConversationId();
  if (convId && isServerVoiceConversationById(convId)) {
    logServerVoiceLocalMediaDebug("track.local.created", convId, {
      rawTrackId: String(callLocalRawAudioStream?.getAudioTracks?.()?.[0]?.id || "") || null,
      processedTrackId: String(localMicTrack?.id || "") || null,
    });
  }
  return callLocalStream || rawStream;
}

async function bindLocalMicToPeer(stream) {
  if (!callPc || !stream) return;
  await ensureLocalMicProcessingState({ allowFallbackToRaw: true });
  const micTrack = getBestLocalMicTrack() || stream.getAudioTracks?.()[0] || null;
  if (!micTrack) throw new Error("Microfone indisponivel.");
  localMicTrack = micTrack;
  try { localMicTrack.contentHint = "speech"; } catch (_) {}
  registerCallSpeakingMeter(localMicTrack, state.user?.id, { local: true });
  // Always keep local mic track aligned with current mute state.
  localMicTrack.enabled = !micMuted;

  if (callMicSender) {
    await callMicSender.replaceTrack(localMicTrack);
  } else {
    const senderStream = callLocalStream || callLocalRawAudioStream || stream;
    callMicSender = callPc.addTrack(localMicTrack, senderStream);
  }
  await applyAudioSenderQuality(callMicSender, { music: false });
  const convId = normId(callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  const peerUserId = normId(callMediaPeerUserId || callOtherUserId || pendingCallInfo?.fromUserId || "");
  if (convId && isServerVoiceConversationById(convId)) {
    if (peerUserId) {
      touchServerVoicePeerDebug(convId, peerUserId, {
        lastLocalTrackPublishedAt: Date.now(),
      });
    }
    logServerVoiceLocalMediaDebug("track.published", convId, {
      peerUserId: peerUserId || null,
      transport: "direct",
      reason: "bind_local_mic",
      senderTrackId: String(callMicSender?.track?.id || "") || null,
      ...describeServerVoiceAudioTrack(callMicSender?.track || localMicTrack || null),
      ...describeServerVoiceAudioTrackSettings(callMicSender?.track || localMicTrack || null),
    });
    logServerVoiceLocalMediaDebug("track.publish.direct", convId, {
      peerUserId: peerUserId || null,
      reason: "bind_local_mic",
      senderTrackId: String(callMicSender?.track?.id || "") || null,
    });
    logServerVoiceLocalMicStateIfChanged(convId, {
      reason: "bind_local_mic",
    });
  }
}

function clearTimers() {
  if (ringTimeout) { clearTimeout(ringTimeout); ringTimeout = null; }
  if (disconnectGraceTimeout) { clearTimeout(disconnectGraceTimeout); disconnectGraceTimeout = null; }
  if (groupRingAcceptJoinFallbackTimer) { clearTimeout(groupRingAcceptJoinFallbackTimer); groupRingAcceptJoinFallbackTimer = null; }
  if (groupCallSoloTimeout) { clearTimeout(groupCallSoloTimeout); groupCallSoloTimeout = null; }
  if (groupCallReconnectTimer) { clearTimeout(groupCallReconnectTimer); groupCallReconnectTimer = null; }
  if (channelConnectProbeTimer) { clearTimeout(channelConnectProbeTimer); channelConnectProbeTimer = null; }
  channelConnectProbeTargetUserId = "";
  groupCallReconnectInFlight = false;
  mediaPeerSwitchInFlight = false;
  mediaPeerSwitchTargetUserId = "";
  mediaPeerSwitchAtMs = 0;
}

async function teardownLegacyServerVoiceMeshState(conversationId = null, { reason = "" } = {}) {
  const convId = normId(conversationId || "");
  if (!convId || !isServerVoiceConversationById(convId)) return false;

  const sameCallConversation = normId(callConversationId || "") === convId;
  const pendingConversationId = normId(pendingCallInfo?.conversationId || "");
  const samePendingConversation = pendingConversationId === convId;
  const pendingGroupRingConversationId = normId(pendingGroupRingInfo?.conversationId || "");
  const samePendingGroupRingConversation = pendingGroupRingConversationId === convId;
  const pendingGroupAutoJoinConversationId = normId(pendingGroupRingAutoJoin?.conversationId || "");
  const samePendingGroupAutoJoinConversation = pendingGroupAutoJoinConversationId === convId;
  const relayAudioPeerIds = collectServerVoicePeerIdsForConversation(relayAudioPeersByUser, convId);
  const relayVideoSendPeerIds = collectServerVoicePeerIdsForConversation(relayVideoSendPeersByUser, convId);
  const relayVideoRecvPeerIds = collectServerVoicePeerIdsForConversation(relayVideoRecvPeersByUser, convId);
  const hasLegacyDirectPeer = !!(
    callPc
    && (
      sameCallConversation
      || samePendingConversation
      || (!callConversationId && !pendingConversationId)
    )
  );
  const legacyRemoteTrackIds = Array.from(remoteAudioTrackEls.entries())
    .filter(([, entry]) => {
      if (!entry) return false;
      if (normId(entry?.conversationId || "") !== convId) return false;
      return String(entry?.source || "").trim().toLowerCase() !== "livekit";
    })
    .map(([trackId]) => trackId)
    .filter(Boolean);
  const hasLegacyMeshState = !!(
    hasLegacyDirectPeer
    || relayAudioPeerIds.length
    || relayVideoSendPeerIds.length
    || relayVideoRecvPeerIds.length
    || legacyRemoteTrackIds.length
    || samePendingConversation
    || samePendingGroupRingConversation
    || samePendingGroupAutoJoinConversation
    || normId(activeCallRealtimeConversationId || "") === convId
  );
  if (!hasLegacyMeshState) return false;

  logServerVoiceDebug("legacy_mesh_reset", {
    conversationId: convId,
    reason: String(reason || "").trim() || null,
    directPeerActive: hasLegacyDirectPeer,
    relayAudioPeerIds,
    relayVideoSendPeerIds,
    relayVideoRecvPeerIds,
    remoteTrackIds: legacyRemoteTrackIds,
    activeRealtimeJoined: normId(activeCallRealtimeConversationId || "") === convId,
  });

  clearTimers();
  stopGroupCallPresenceHeartbeat();
  stopServerVoiceConsistencyMonitor();
  setCallLocalAudioHealthWatch(false);

  if (normId(activeCallRealtimeConversationId || "") === convId) {
    try {
      await teardownActiveCallRealtimeChannel();
    } catch (_) {}
  }

  try {
    if (hasLegacyDirectPeer) {
      callPc.onicecandidate = null;
      callPc.oniceconnectionstatechange = null;
      callPc.ontrack = null;
      callPc.onconnectionstatechange = null;
      callPc.close();
    }
  } catch (_) {}
  if (hasLegacyDirectPeer) {
    callPc = null;
  }

  relayAudioPeerIds.forEach((uid) => closeRelayAudioPeer(uid));
  relayVideoSendPeerIds.forEach((uid) => closeRelayVideoSendPeer(uid));
  relayVideoRecvPeerIds.forEach((uid) => closeRelayVideoRecvPeer(uid));

  legacyRemoteTrackIds.forEach((trackId) => {
    removeRemoteAudioTrackEl(trackId, { reason: "legacy_mesh_reset" });
  });

  try {
    if (screenStream) screenStream.getTracks().forEach((track) => track.stop());
  } catch (_) {}
  screenStream = null;
  stopCameraLocalTracks();
  stopMixedVideoComposer();
  originalVideoTrack = null;
  isScreenSharing = false;
  isCameraOn = false;
  callVideoSender = null;
  callCameraSender = null;
  callPrimaryVideoTransceiver = null;
  callCameraVideoTransceiver = null;
  callMicSender = null;
  callShareAudioSender = null;
  remoteIsSharing = false;
  remoteShareMediaMode = "none";
  clearRemoteShareWatchState();
  remoteVideoTrackRef = null;
  remoteCameraTrackRef = null;
  remotePrimarySourceUserId = "";
  remoteAuxSourceUserId = "";
  setRemoteVideoStream(null);
  setRemoteCameraStream(null);
  clearExtraCallStageMembers();
  setLocalSharePreviewStream(null);

  pendingOffer = null;
  if (samePendingConversation) pendingCallInfo = null;
  if (samePendingGroupRingConversation) pendingGroupRingInfo = null;
  if (samePendingGroupAutoJoinConversation) pendingGroupRingAutoJoin = null;
  pendingRenegotiateReason = "";
  queuedIceCandidates = queuedIceCandidates
    .map((entry) => normalizeQueuedDirectIceEntry(entry))
    .filter((entry) => entry && entry.conversationId !== convId);
  callOtherUserId = null;
  callMediaPeerUserId = null;
  groupCallOfferTargetUserId = null;
  inCall = false;
  groupCallMode = false;
  groupCallMemberIds = [];
  setGroupCallActiveMembers([]);
  clearCallParticipantAudioStates(convId);
  clearCallParticipantShareStates(convId);
  clearServerVoicePresenceCache(convId, {
    triggerReason: "teardown_legacy_mesh_state",
    callerFunction: "teardownLegacyServerVoiceMeshState",
    sourceType: "local_control_plane_cache",
  });

  return true;
}

async function recoverGroupCallAfterPeerDrop(conversationId, message = "A ligaÃ§Ã£o caiu. A reconectar...") {
  const convId = normId(conversationId || "");
  if (!convId) {
    if (inCall) await endCallUI("A chamada terminou.");
    return;
  }
  if (shouldUseServerVoiceLiveKitTransport(convId)) {
    logServerVoiceDebug("room.recover.skipped_mesh", {
      conversationId: convId,
      reason: String(message || "").trim() || null,
      transport: SERVER_VOICE_TRANSPORT_KIND,
    });
    refreshCallUI();
    return;
  }
  if (channelConnectProbeTimer) {
    clearTimeout(channelConnectProbeTimer);
    channelConnectProbeTimer = null;
  }
  channelConnectProbeTargetUserId = "";
  if (groupCallReconnectInFlight) return;
  groupCallReconnectInFlight = true;
  if (groupCallReconnectTimer) {
    clearTimeout(groupCallReconnectTimer);
    groupCallReconnectTimer = null;
  }
  const isServerVoiceCall = isServerVoiceConversationById(convId);
  if (isServerVoiceCall) {
    noteServerVoiceRecoveryEvent(convId, "direct_reconnect", {
      reason: String(message || "").trim() || null,
    });
    startServerVoiceConsistencyMonitor(convId);
    logServerVoiceDebug("reconnect.start", {
      conversationId: convId,
      reason: String(message || "").trim() || null,
      previousPeerUserId: normId(callMediaPeerUserId || callOtherUserId || "") || null,
    });
  }
  const shouldSoftRecover = !!(groupCallMode && (isServerVoiceCall || hasActiveGroupCallRemoteParticipant(convId)));
  if (shouldSoftRecover) {
    try {
      if (callPc) {
        callPc.onicecandidate = null;
        callPc.oniceconnectionstatechange = null;
        callPc.ontrack = null;
        callPc.onconnectionstatechange = null;
        callPc.close();
      }
    } catch (_) {}
    callPc = null;
    // Keep local audio capture alive so relay peers can continue sending audio
    // during the brief window while the direct peer reconnects.
    // stopLocalAudioCapture() â€” intentionally skipped for group call soft recovery.
    callVideoSender = null;
    callCameraSender = null;
    callPrimaryVideoTransceiver = null;
    callCameraVideoTransceiver = null;
    callMicSender = null;
    callShareAudioSender = null;
    pendingOffer = null;
    pendingCallInfo = null;
    queuedIceCandidates = [];
    callOtherUserId = null;
    callMediaPeerUserId = null;
    groupCallOfferTargetUserId = null;
    // Keep relay audio peers alive â€” they may still be carrying audio for other pairs.
    // closeAllRelayAudioPeers() â€” intentionally skipped for group call soft recovery.
    // Refresh relay senders in case the mic track ref changed.
    void syncRelayAudioPeers(convId);
    inCall = true;
    setCallButtons("inCall");
    if (message) setCallStatus(message, true);
    refreshCallUI();
  } else {
    await endCallUI(message);
  }
  groupCallReconnectInFlight = true;

  groupCallReconnectTimer = setTimeout(async () => {
    groupCallReconnectTimer = null;
    try {
      await refreshGroupDmCallState(convId, { rerender: false });
      const meId = normId(state.user?.id || "");
      const suppressed = getSuppressedGroupDmConnectedSet(convId, false);
      const targetIds = normalizeUuidArray(getEffectiveGroupCallActiveUserIds(convId))
        .filter((uid) => uid && uid !== meId && !(suppressed && suppressed.has(uid)));
      if (!targetIds.length) {
        if (!isServerVoiceCall && groupCallMode) {
          await enterGroupSoloCall("? Continuas na call do grupo.");
        } else if (isServerVoiceCall) {
          logServerVoiceDebug("reconnect.wait_remote", {
            conversationId: convId,
            reason: "no_targets",
          });
          scheduleServerVoiceConsistencyPass(convId, {
            reason: "reconnect_wait_remote",
            delayMs: 420,
          });
        }
        refreshCallUI();
        return;
      }
      if (isServerVoiceCall) {
        logServerVoiceDebug("reconnect.retry_direct_offer", {
          conversationId: convId,
          targetUserId: targetIds[0] || null,
        });
      }
      await startGroupOfferToMember(targetIds[0], convId, { channelMode: isServerVoiceCall });
    } catch (e) {
      console.warn("group call auto-rejoin failed", e);
    } finally {
      groupCallReconnectInFlight = false;
    }
  }, 280);
}

function scheduleDisconnectGraceEnd() {
  if (disconnectGraceTimeout) return;
  // In group calls, use a much shorter grace so relay audio can fill the gap quickly.
  // 1:1 calls keep the longer window to survive transient network blips.
  const graceMs = (groupCallMode && callConversationId) ? 3000 : DISCONNECT_GRACE_MS;
  disconnectGraceTimeout = setTimeout(() => {
    disconnectGraceTimeout = null;
    if (!callPc || !inCall) return;
    const connState = callPc.connectionState;
    const iceState = callPc.iceConnectionState;
    const stillDown =
      connState === "disconnected" ||
      connState === "failed" ||
      connState === "closed" ||
      iceState === "disconnected" ||
      iceState === "failed" ||
      iceState === "closed";
    if (stillDown) {
      const convId = normId(callConversationId || activeDmId || "");
      const wasGroup = !!(groupCallMode && convId);
      if (wasGroup) {
        void recoverGroupCallAfterPeerDrop(convId, "A ligaÃ§Ã£o caiu. A reconectar...");
        return;
      }
      endCallUI("A ligaÃ§Ã£o caiu. SaÃ­ste da chamada.");
    }
  }, graceMs);
}

function normalizeQueuedDirectIceEntry(entry, fallbackMeta = {}) {
  if (!entry) return null;
  const normalizedFallback = (fallbackMeta && typeof fallbackMeta === "object" && !Array.isArray(fallbackMeta))
    ? fallbackMeta
    : {};
  const candidateInit = Object.prototype.hasOwnProperty.call(entry || {}, "candidateInit")
    ? entry.candidateInit
    : entry;
  if (!candidateInit) return null;
  return {
    candidateInit,
    peerUserId: normId(entry?.peerUserId || normalizedFallback.fromUserId || ""),
    conversationId: normId(entry?.conversationId || normalizedFallback.conversationId || ""),
    receivedAt: Number(entry?.receivedAt || Date.now()),
  };
}

function getDirectIceCandidatePeerHints(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  const meId = normId(state.user?.id || "");
  return normalizeUuidArray([
    callMediaPeerUserId,
    callOtherUserId,
    groupCallOfferTargetUserId,
    pendingCallInfo?.fromUserId,
    getPreferredDirectSignalPeerUserId(convId),
  ]).filter((uid) => uid && uid !== meId);
}

function pruneQueuedIceCandidates({ conversationId = null, keepPeerUserIds = null, reason = "" } = {}) {
  if (!queuedIceCandidates.length) return 0;
  const convId = normId(conversationId || callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  const keepSet = Array.isArray(keepPeerUserIds)
    ? new Set(normalizeUuidArray(keepPeerUserIds))
    : null;
  const now = Date.now();
  let dropped = 0;
  const nextQueue = [];
  queuedIceCandidates.forEach((rawEntry) => {
    const entry = normalizeQueuedDirectIceEntry(rawEntry);
    if (!entry?.candidateInit) return;
    const entryPeerId = normId(entry.peerUserId || "");
    const entryConvId = normId(entry.conversationId || "");
    const expired = (now - Number(entry.receivedAt || 0)) > DIRECT_ICE_QUEUE_STALE_MS;
    const wrongConversation = !!(convId && entryConvId && entryConvId !== convId);
    const wrongPeer = !!(keepSet && entryPeerId && !keepSet.has(entryPeerId));
    if (expired || wrongConversation || wrongPeer) {
      dropped += 1;
      return;
    }
    nextQueue.push(entry);
  });
  queuedIceCandidates = nextQueue;
  if (dropped && convId && isServerVoiceConversationById(convId)) {
    logServerVoiceDebug("ice.queue.prune.direct", {
      conversationId: convId,
      reason: String(reason || "").trim() || null,
      keepPeerUserIds: keepSet ? Array.from(keepSet) : [],
      dropped,
      queueSize: queuedIceCandidates.length,
    });
  }
  return dropped;
}

function queueIceCandidate(candidate, meta = {}) {
  const entry = normalizeQueuedDirectIceEntry({
    candidateInit: candidate,
    peerUserId: meta?.fromUserId || "",
    conversationId: meta?.conversationId || "",
    receivedAt: Date.now(),
  });
  if (!entry?.candidateInit) return;
  pruneQueuedIceCandidates({
    conversationId: entry.conversationId || null,
    reason: "queue",
  });
  const dedupeKey = `${entry.conversationId}|${entry.peerUserId}|${String(entry.candidateInit?.candidate || "")}|${String(entry.candidateInit?.sdpMid || "")}|${String(entry.candidateInit?.sdpMLineIndex ?? "")}`;
  const duplicate = queuedIceCandidates.some((rawEntry) => {
    const current = normalizeQueuedDirectIceEntry(rawEntry);
    if (!current?.candidateInit) return false;
    const currentKey = `${current.conversationId}|${current.peerUserId}|${String(current.candidateInit?.candidate || "")}|${String(current.candidateInit?.sdpMid || "")}|${String(current.candidateInit?.sdpMLineIndex ?? "")}`;
    return currentKey === dedupeKey;
  });
  if (duplicate) return;
  if (queuedIceCandidates.length >= DIRECT_ICE_QUEUE_MAX) {
    queuedIceCandidates.splice(0, queuedIceCandidates.length - DIRECT_ICE_QUEUE_MAX + 1);
  }
  queuedIceCandidates.push(entry);
  if (entry.conversationId && isServerVoiceConversationById(entry.conversationId)) {
    logServerVoiceDebug("ice.queue.direct", {
      conversationId: entry.conversationId,
      peerUserId: entry.peerUserId || null,
      queueSize: queuedIceCandidates.length,
    });
  }
}

async function flushQueuedIceCandidates({ conversationId = null, peerUserId = null } = {}) {
  if (!callPc || !callPc.remoteDescription || !queuedIceCandidates.length) return;
  const convId = normId(conversationId || callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  const expectedPeerIds = normalizeUuidArray([
    peerUserId,
    ...getDirectIceCandidatePeerHints(convId),
  ]);
  const queue = queuedIceCandidates.map((entry) => normalizeQueuedDirectIceEntry(entry)).filter(Boolean);
  queuedIceCandidates = [];
  let applied = 0;
  let deferred = 0;
  let dropped = 0;
  const deferredQueue = [];
  const now = Date.now();
  for (const entry of queue) {
    const ageMs = now - Number(entry.receivedAt || 0);
    if (ageMs > DIRECT_ICE_QUEUE_STALE_MS) {
      dropped += 1;
      continue;
    }
    const entryConvId = normId(entry.conversationId || "");
    if (convId && entryConvId && entryConvId !== convId) {
      dropped += 1;
      continue;
    }
    const entryPeerId = normId(entry.peerUserId || "");
    if (expectedPeerIds.length && entryPeerId && !expectedPeerIds.includes(entryPeerId)) {
      deferredQueue.push(entry);
      deferred += 1;
      continue;
    }
    try {
      await callPc.addIceCandidate(new RTCIceCandidate(entry.candidateInit));
      applied += 1;
    } catch (e) {
      dropped += 1;
      console.warn("ICE flush failed", e);
    }
  }
  queuedIceCandidates = deferredQueue;
  if (convId && isServerVoiceConversationById(convId) && (applied || deferred || dropped)) {
    logServerVoiceDebug("ice.flush.direct", {
      conversationId: convId,
      peerUserId: normId(peerUserId || callMediaPeerUserId || callOtherUserId || "") || null,
      applied,
      deferred,
      dropped,
      queueSize: queuedIceCandidates.length,
    });
  }
}

async function addOrQueueIceCandidate(candidate, meta = {}) {
  if (!candidate) return;
  const convId = normId(meta?.conversationId || callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  const fromUserId = normId(meta?.fromUserId || "");
  if (convId && fromUserId && isServerVoiceConversationById(convId)) {
    touchServerVoicePeerDebug(convId, fromUserId, {
      lastIceReceivedAt: Date.now(),
    });
  }
  const expectedPeerIds = getDirectIceCandidatePeerHints(convId);
  const shouldDeferForPeerMismatch = !!(
    fromUserId
    && expectedPeerIds.length
    && !expectedPeerIds.includes(fromUserId)
  );
  if (!callPc || !callPc.remoteDescription || shouldDeferForPeerMismatch) {
    queueIceCandidate(candidate, meta);
    return;
  }

  try {
    await callPc.addIceCandidate(new RTCIceCandidate(candidate));
  } catch (e) {
    console.warn("ICE add failed", e);
    queueIceCandidate(candidate, meta);
    if (convId && isServerVoiceConversationById(convId)) {
      logServerVoiceDebug("ice.add_error.direct", {
        conversationId: convId,
        peerUserId: fromUserId || null,
        error: e?.message || String(e || "unknown"),
      });
    }
  }
}

async function disconnectMinimalServerVoiceTransport({
  conversationId = null,
  reason = "manual",
  controller = null,
} = {}) {
  const convId = normId(conversationId || controller?.conversationId || serverVoiceTransportConversationId || "");
  const activeController = controller
    || getActiveServerVoiceTransportController(convId)
    || ((convId && normId(serverVoiceTransportConversationId || "") === convId) ? serverVoiceTransportController : null);
  await detachServerVoiceScreenshareLayer(convId, {
    stopLocalShare: true,
    clearUiState: true,
    triggerReason: `transport_disconnect:${String(reason || "").trim() || "manual"}`,
  });
  await detachServerVoiceCameraLayer(convId, {
    stopLocalCamera: true,
    triggerReason: `transport_disconnect:${String(reason || "").trim() || "manual"}`,
  });
  try {
    if (activeController && typeof activeController.disconnect === "function") {
      await activeController.disconnect({ reason: String(reason || "").trim() || "manual" });
    }
  } catch (_) {}
  clearServerVoiceTransportRemoteAudioTracks(convId);
  if (convId) {
    clearServerVoiceTransportSnapshot(convId);
    clearServerVoiceJoinAttemptInFlight(convId);
    clearServerVoiceActiveJoinAttempt(convId);
  }
  if (
    !convId
    || serverVoiceTransportController === activeController
    || normId(serverVoiceTransportConversationId || "") === convId
  ) {
    serverVoiceTransportController = null;
    serverVoiceTransportConversationId = "";
  }
  clearPrivateCallLiveKitState(convId, { clearPendingInvite: false });
  clearGroupDmCallLiveKitState(convId);
  return !!activeController;
}

function resetMinimalServerVoiceUiState(conversationId = null, {
  clearStatus = false,
} = {}) {
  const convId = normId(conversationId || callConversationId || serverVoiceTransportConversationId || "");
  const cleanupMeId = normId(state.user?.id || "");
  void detachServerVoiceScreenshareLayer(convId, {
    stopLocalShare: false,
    clearUiState: true,
    triggerReason: "reset_ui_state",
  });
  void detachServerVoiceCameraLayer(convId, {
    stopLocalCamera: false,
    triggerReason: "reset_ui_state",
  });

  clearTimers();
  setCallLocalAudioHealthWatch(false);
  stopLocalAudioCapture();
  clearServerVoiceTransportRemoteAudioTracks(convId);
  clearCallSpeakingMeters({ clearUi: true });
  closeCallAudioMenu();
  closeCallShareMenu();
  closeServerVoiceMemberMenu();
  closeGroupMemberMenu();
  try {
    const fallbackAudio = document.getElementById("callRemoteAudio");
    if (fallbackAudio) {
      fallbackAudio.pause?.();
      fallbackAudio.srcObject = null;
    }
  } catch (_) {}

  if (convId && cleanupMeId) {
    removeCallParticipantAudioState(convId, cleanupMeId);
    removeCallParticipantShareState(convId, cleanupMeId);
    clearCallParticipantAudioStates(convId);
    clearCallParticipantShareStates(convId);
    clearServerVoiceTransportSnapshot(convId);
    clearServerVoiceJoinAttemptInFlight(convId);
    clearServerVoiceActiveJoinAttempt(convId);
  }

  if (!convId || normId(serverVoiceTransportConversationId || "") === convId) {
    serverVoiceTransportController = null;
    serverVoiceTransportConversationId = "";
  }
  clearPrivateCallLiveKitState(convId, { clearPendingInvite: true });
  clearGroupDmCallLiveKitState(convId);

  pendingOffer = null;
  pendingGroupRingInfo = null;
  pendingGroupRingAutoJoin = null;
  groupCallOfferTargetUserId = null;
  callConversationId = null;
  callOtherUserId = null;
  callMediaPeerUserId = null;
  callOtherAvatar = null;
  callOtherLabel = "";
  inCall = false;
  groupCallMode = false;
  groupCallMemberIds = [];
  setGroupCallActiveMembers([]);
  stageOpen = false;
  stageLayoutMode = "grid";
  stageFocus = "remote";
  stageFocusRemoteSlot = "primary";
  stageFocusSelfSlot = "primary";
  stageFocusMemberId = "";
  stageFocusMemberTrackId = "";
  stageFocusMemberMediaType = "";
  stageFocusedTileId = "";
  stageFocusTransitionExpiresAt = 0;
  stageFocusTransitionTargetTileId = "";
  setRemoteVideoStream(null);
  setRemoteCameraStream(null);
  clearExtraCallStageMembers();
  setLocalSharePreviewStream(null);
  setStageFocus("remote");
  resetCallEventState();
  setCallButtons("idle");
  if (clearStatus) {
    setCallStatus("", false);
  }
  refreshServerVoiceChannelBadges();
  refreshCallUI();
}

async function stopMinimalServerVoiceSession({
  conversationId = null,
  reason = "manual",
  controller = null,
  clearStatus = false,
  teardownRealtime = false,
} = {}) {
  const convId = normId(conversationId || controller?.conversationId || callConversationId || serverVoiceTransportConversationId || "");
  await disconnectMinimalServerVoiceTransport({
    conversationId: convId,
    reason,
    controller,
  });
  if (teardownRealtime && normId(activeCallRealtimeConversationId || "") === convId) {
    try {
      await teardownActiveCallRealtimeChannel();
    } catch (_) {}
  }
  resetMinimalServerVoiceUiState(convId, { clearStatus });
}

function cleanupPeer() {
  const cleanupConvId = normId(callConversationId || activeDmId || "");
  void detachServerVoiceScreenshareLayer(cleanupConvId, {
    stopLocalShare: false,
    clearUiState: true,
    triggerReason: "cleanup_peer",
  });
  void detachServerVoiceCameraLayer(cleanupConvId, {
    stopLocalCamera: false,
    triggerReason: "cleanup_peer",
  });
  if (cleanupConvId && shouldUseServerVoiceLiveKitTransport(cleanupConvId)) {
    void disconnectMinimalServerVoiceTransport({
      conversationId: cleanupConvId,
      reason: "cleanup_peer_server_voice",
    });
    resetMinimalServerVoiceUiState(cleanupConvId, { clearStatus: false });
    clearPrivateCallLiveKitState(cleanupConvId, { clearPendingInvite: true });
    clearGroupDmCallLiveKitState(cleanupConvId);
    return;
  }
  const cleanupMeId = normId(state.user?.id || "");
  if (cleanupConvId && cleanupMeId) {
    removeCallParticipantAudioState(cleanupConvId, cleanupMeId);
    removeCallParticipantShareState(cleanupConvId, cleanupMeId);
    if (!isServerVoiceConversationById(cleanupConvId)) {
      clearCallParticipantAudioStates(cleanupConvId);
      clearCallParticipantShareStates(cleanupConvId);
    }
  }

  clearTimers();
  stopServerVoiceConsistencyMonitor();
  setCallLocalAudioHealthWatch(false);
  stopRemoteVideoWatchdog();
  stopCallWatchSnapshotTimer();
  callWatchSnapshotsVisible = false;
  callShareLoadingVisible = false;
  callWatchSnapshotLastCaptureAt = 0;
  const cleanupStage = document.getElementById("callStage");
  cleanupStage?.querySelectorAll?.(".participantTile, .stageGridTile")?.forEach?.((tile) => {
    clearCallTileWatchSnapshot(tile);
    setCallTileLoadingPrompt(tile, false);
  });
  ensureCallPingPolling(false);

  try {
    if (callPc) {
      callPc.onicecandidate = null;
      callPc.oniceconnectionstatechange = null;
      callPc.ontrack = null;
      callPc.onconnectionstatechange = null;
      callPc.close();
    }
  } catch (_) {}
  callPc = null;

  stopLocalAudioCapture();

  // screenshare cleanup
  try {
    if (screenStream) screenStream.getTracks().forEach(t => t.stop());
  } catch (_) {}
  screenStream = null;
  stopCameraLocalTracks();
  stopMixedVideoComposer();
  originalVideoTrack = null;
  isScreenSharing = false;
  localShareTileSeenFrame = false;
  isCameraOn = false;
  callVideoSender = null;
  callCameraSender = null;
  callPrimaryVideoTransceiver = null;
  callCameraVideoTransceiver = null;
  callMicSender = null;
  callShareAudioSender = null;
  remoteIsSharing = false;
  remoteShareMediaMode = "none";
  clearRemoteShareWatchState();
  remoteVideoTrackRef = null;
  remoteCameraTrackRef = null;
  remotePrimarySourceUserId = "";
  remoteAuxSourceUserId = "";
  remoteCameraLastActiveAt = 0;
  remoteGroupPeerLastSeenAt = 0;
  remoteGroupPrimaryStableConversationId = "";
  remoteGroupPrimaryStableUserId = "";
  callMemberProfilesHydrateInFlight = false;
  callMemberProfilesHydrateFingerprint = "";
  callMemberProfilesHydrateAt = 0;
  remoteCompositeStream = null;
  clearRemoteAudioTrackEls();
  clearCallSpeakingMeters({ clearUi: true });
  closeAllRelayVideoPeers();
  closeAllRelayAudioPeers();
  closeCallAudioMenu();
  closeCallShareMenu();
  closeServerVoiceMemberMenu();
  try {
    const fallbackAudio = document.getElementById("callRemoteAudio");
    if (fallbackAudio) {
      fallbackAudio.pause?.();
      fallbackAudio.srcObject = null;
    }
  } catch (_) {}
  stageFocus = "remote";
  stageFocusRemoteSlot = "primary";
  stageFocusSelfSlot = "primary";
  stageFocusMemberId = "";
  stageFocusMemberTrackId = "";
  stageFocusMemberMediaType = "";
  stageFocusedTileId = "";
  stageFocusTransitionExpiresAt = 0;
  stageFocusTransitionTargetTileId = "";
  stageLayoutMode = "grid";
  callConversationId = null;
  callMediaPeerUserId = null;
  setRemoteVideoStream(null);
  setRemoteCameraStream(null);
  clearExtraCallStageMembers();
  setLocalSharePreviewStream(null);
  setStageFocus("remote");

  pendingOffer = null;
  pendingGroupRingInfo = null;
  pendingGroupRingAutoJoin = null;
  pendingRenegotiateReason = "";
  queuedIceCandidates = [];
  inCall = false;
  groupCallMode = false;
  groupCallMemberIds = [];
  setGroupCallActiveMembers([]);
  stopGroupCallPresenceHeartbeat();
  groupCallOfferTargetUserId = null;
  if (cleanupConvId) clearServerVoiceTransportSnapshot(cleanupConvId);
  if (!cleanupConvId || normId(serverVoiceTransportConversationId || "") === cleanupConvId) {
    serverVoiceTransportController = null;
    serverVoiceTransportConversationId = "";
  }
  if (cleanupConvId) {
    clearServerVoiceJoinAttemptInFlight(cleanupConvId);
    clearServerVoiceActiveJoinAttempt(cleanupConvId);
  }
  clearPrivateCallLiveKitState(cleanupConvId, { clearPendingInvite: true });
  clearGroupDmCallLiveKitState(cleanupConvId);
  closeGroupMemberMenu();
  resetCallEventState();
}

async function endCallUI(msg = null, {
  triggeredBy = "endCallUI",
  reasonCode = "cleanup.end_call_ui",
  joinAttemptId = null,
  controller = null,
  controllerId = null,
  level = "warn",
} = {}) {
  const endConvId = normId(callConversationId || activeDmId || "");
  const pendingCleanupContext = endConvId ? consumePendingServerVoiceCleanupContext(endConvId) : null;
  const explicitTriggeredBy = String(triggeredBy || "").trim();
  const explicitReasonCode = String(reasonCode || "").trim();
  const explicitLevel = String(level || "").trim();
  const resolvedTriggeredBy = explicitTriggeredBy && explicitTriggeredBy !== "endCallUI"
    ? explicitTriggeredBy
    : (String(pendingCleanupContext?.triggeredBy || "").trim() || explicitTriggeredBy || "endCallUI");
  const resolvedReasonCode = explicitReasonCode && explicitReasonCode !== "cleanup.end_call_ui"
    ? explicitReasonCode
    : (String(pendingCleanupContext?.reasonCode || "").trim() || explicitReasonCode || "cleanup.end_call_ui");
  const resolvedJoinAttemptId = joinAttemptId || pendingCleanupContext?.joinAttemptId || null;
  const resolvedController = controller || pendingCleanupContext?.controller || null;
  const resolvedControllerId = controllerId || pendingCleanupContext?.controllerId || null;
  const resolvedLevel = explicitLevel && explicitLevel !== "warn"
    ? explicitLevel
    : (String(pendingCleanupContext?.level || "").trim() || explicitLevel || "warn");
  const privateLifecycle = getPrivateCallLifecycleState();
  const privateLifecycleConvId = normId(privateLifecycle.conversationId || "");
  const privateLifecycleOtherUserId = normId(privateLifecycle.otherUserId || "");
  const privateCallContext = !!(
    endConvId
    && shouldRoutePrivateDmCallViaLiveKit(endConvId)
    && !isServerVoiceConversationById(endConvId)
    && !isGroupCallConversation(endConvId)
  );
  if (endConvId && shouldUseServerVoiceLiveKitTransport(endConvId)) {
    const privateCallActive = isPrivateDmLiveKitTransportConversation(endConvId);
    if (privateCallActive) {
      logPrivateCallDebug("private_call.leave_started", {
        conversationId: endConvId,
        triggeredBy: resolvedTriggeredBy || "endCallUI",
        reasonCode: resolvedReasonCode || "cleanup.end_call_ui",
      });
    }
    tryLogCallEndEvent();
    stopSfx("ring");
    stopSfx("incoming");
    playUiCue("call_leave");
    await stopMinimalServerVoiceSession({
      conversationId: endConvId,
      reason: resolvedReasonCode || "end_call_ui",
      controller: resolvedController,
      clearStatus: false,
      teardownRealtime: true,
    });
    if (msg) {
      setCallStatus(msg, true);
      setTimeout(() => setCallStatus("", false), 1400);
    } else {
      setCallStatus("", false);
    }
    if (privateCallActive) {
      logPrivateCallDebug("private_call.leave_completed", {
        conversationId: endConvId,
        triggeredBy: resolvedTriggeredBy || "endCallUI",
        reasonCode: resolvedReasonCode || "cleanup.end_call_ui",
      });
    }
    if (privateCallContext) {
      setPrivateCallLifecycleState(PRIVATE_CALL_STATES.ENDED, {
        conversationId: endConvId,
        otherUserId: privateLifecycleOtherUserId || callOtherUserId || callMediaPeerUserId || "",
        reason: `end_call_ui:${resolvedReasonCode || "cleanup.end_call_ui"}`,
      });
      logPrivateCallStage("private_call.ended", {
        conversationId: endConvId,
        otherUserId: privateLifecycleOtherUserId || callOtherUserId || callMediaPeerUserId || "",
        roomName: `${PRIVATE_CALL_LIVEKIT_ROOM_PREFIX}${endConvId}`,
        stage: PRIVATE_CALL_STATES.ENDED,
        triggerReason: resolvedTriggeredBy || "endCallUI",
      });
    }
    refreshCallUI();
    return;
  }
  if (endConvId && isServerVoiceConversationById(endConvId)) {
    logServerVoiceCleanupTrigger("cleanup.end_call_ui", {
      conversationId: endConvId,
      reasonCode: resolvedReasonCode,
      triggeredBy: resolvedTriggeredBy,
      joinAttemptId: resolvedJoinAttemptId,
      controller: resolvedController,
      controllerId: resolvedControllerId,
      message: String(msg || "").trim() || null,
      inCall: !!inCall,
      groupCallMode: !!groupCallMode,
      level: resolvedLevel,
    });
  }
  tryLogCallEndEvent();

  stopSfx("ring");
  stopSfx("incoming");
  playUiCue("call_leave");
  await disconnectActiveServerVoiceTransport({
    conversationId: callConversationId || activeDmId || "",
    reason: "end_call_ui",
    reasonCode: resolvedReasonCode,
    triggeredBy: resolvedTriggeredBy,
    joinAttemptId: resolvedJoinAttemptId,
    controller: resolvedController,
    controllerId: resolvedControllerId,
  });
  await teardownActiveCallRealtimeChannel();

  cleanupPeer();
  setCallButtons("idle");

  if (msg) {
    setCallStatus(msg, true);
    setTimeout(() => setCallStatus("", false), 1400);
  } else {
    setCallStatus("", false);
  }

  if (privateCallContext || (privateLifecycleConvId && privateLifecycleConvId === endConvId)) {
    setPrivateCallLifecycleState(PRIVATE_CALL_STATES.ENDED, {
      conversationId: endConvId || privateLifecycleConvId,
      otherUserId: privateLifecycleOtherUserId || callOtherUserId || callMediaPeerUserId || "",
      reason: `end_call_ui_legacy:${resolvedReasonCode || "cleanup.end_call_ui"}`,
    });
    logPrivateCallStage("private_call.ended", {
      conversationId: endConvId || privateLifecycleConvId,
      otherUserId: privateLifecycleOtherUserId || callOtherUserId || callMediaPeerUserId || "",
      roomName: `${PRIVATE_CALL_LIVEKIT_ROOM_PREFIX}${endConvId || privateLifecycleConvId}`,
      stage: PRIVATE_CALL_STATES.ENDED,
      triggerReason: resolvedTriggeredBy || "endCallUI",
    });
  }

  refreshCallUI();
}

function hasActiveCallSignalContext() {
  return !!(
    inCall ||
    pendingOffer ||
    pendingCallInfo ||
    ringTimeout ||
    groupCallMode ||
    groupDmCallLiveKitJoinInFlight ||
    pendingGroupRingInfo ||
    pendingGroupRingAutoJoin ||
    (callPc && callPc.connectionState !== "closed" && callPc.connectionState !== "failed")
  );
}

const callRealtimeChannelsByConversationId = new Map();
let activeCallRealtimeConversationId = "";
let callRealtimeSyncTimer = null;
let callRealtimeMembershipDescriptorsByConversation = new Map();
let callRealtimeMembershipDescriptorsLoadedAt = 0;
let callRealtimeMembershipDescriptorsInFlight = null;
const CALL_REALTIME_MEMBERSHIP_CACHE_MS = 30 * 1000;

function readServerVoiceDebugLoggingFlag() {
  try {
    if (typeof window !== "undefined" && window.__ALTARA_SERVER_VOICE_DEBUG__ === true) return true;
  } catch (_) {}
  try {
    return String(localStorage.getItem(SERVER_VOICE_DEBUG_STORAGE_KEY) || "").trim() === "1";
  } catch (_) {}
  return false;
}

function syncServerVoiceDebugWindowBindings(enabled = readServerVoiceDebugLoggingFlag()) {
  try {
    if (typeof window === "undefined") return;
    if (enabled) {
      if (!serverVoiceDebugBindingsActive || typeof window.__ALTARA_SERVER_VOICE_SNAPSHOT__ !== "function") {
        window.__ALTARA_SERVER_VOICE_SNAPSHOT__ = (conversationId = null) => buildServerVoiceDebugSnapshot(conversationId);
        serverVoiceDebugBindingsActive = true;
      }
      return;
    }
    if (serverVoiceDebugBindingsActive || typeof window.__ALTARA_SERVER_VOICE_SNAPSHOT__ === "function") {
      try { delete window.__ALTARA_SERVER_VOICE_SNAPSHOT__; } catch (_) {
        try { window.__ALTARA_SERVER_VOICE_SNAPSHOT__ = undefined; } catch (_) {}
      }
    }
    serverVoiceDebugBindingsActive = false;
  } catch (_) {}
}

function isServerVoiceDebugLoggingEnabled() {
  const enabled = readServerVoiceDebugLoggingFlag();
  syncServerVoiceDebugWindowBindings(enabled);
  return enabled;
}

function sanitizeServerVoiceStructuredLogValue(value, depth = 0, seen = null) {
  if (value == null) return null;
  if (depth > 6) return "[max_depth]";
  const valueType = typeof value;
  if (valueType === "string" || valueType === "number" || valueType === "boolean") return value;
  if (valueType === "bigint") return String(value);
  if (valueType === "function") return `[function ${String(value.name || "anonymous")}]`;
  if (value instanceof Error) {
    return {
      name: String(value.name || "").trim() || null,
      message: String(value.message || "").trim() || String(value).trim() || null,
      stack: typeof value.stack === "string"
        ? value.stack.split("\n").map((line) => line.trim()).filter(Boolean).slice(0, 8)
        : null,
    };
  }
  if (Array.isArray(value)) return value.map((entry) => sanitizeServerVoiceStructuredLogValue(entry, depth + 1, seen));
  if (value instanceof Date) return value.toISOString();
  if (!value || valueType !== "object") return String(value);
  const nextSeen = seen instanceof WeakSet ? seen : new WeakSet();
  if (nextSeen.has(value)) return "[circular]";
  nextSeen.add(value);
  const output = {};
  Object.keys(value)
    .sort((a, b) => a.localeCompare(b))
    .forEach((key) => {
      const nextValue = sanitizeServerVoiceStructuredLogValue(value[key], depth + 1, nextSeen);
      if (typeof nextValue !== "undefined") output[key] = nextValue;
    });
  return output;
}

function extractEdgeFunctionNameFromUrl(url = "") {
  const raw = String(url || "").trim();
  if (!raw) return null;
  try {
    const pathname = new URL(raw).pathname || "";
    const segments = pathname.split("/").map((segment) => String(segment || "").trim()).filter(Boolean);
    return segments.length ? (segments[segments.length - 1] || null) : null;
  } catch (_) {
    const normalized = raw.replace(/[?#].*$/, "");
    const segments = normalized.split("/").map((segment) => String(segment || "").trim()).filter(Boolean);
    return segments.length ? (segments[segments.length - 1] || null) : null;
  }
}

function buildStructuredServerVoiceLogRecord(event, details = {}, {
  channel = "server-voice",
} = {}) {
  const payload = details && typeof details === "object" && !Array.isArray(details)
    ? { ...details }
    : { value: details ?? null };
  const httpStatusRaw = payload.httpStatus ?? payload.edgeStatus ?? payload.payloadStatus ?? null;
  const httpStatus = Number.isFinite(Number(httpStatusRaw)) && Number(httpStatusRaw) > 0
    ? Number(httpStatusRaw)
    : null;
  const responseBodyText = (
    payload.responseBodyText
    ?? payload.edgeResponseText
    ?? payload.responseText
    ?? null
  );
  const responseJson = payload.responseJson
    ?? payload.edgeResponseJson
    ?? payload.payload
    ?? null;
  const edgeFunctionName = String(
    payload.edgeFunctionName
    || payload.functionName
    || payload.edgeFunction
    || extractEdgeFunctionNameFromUrl(payload.edgeResponseUrl || payload.responseUrl || payload.functionUrl || "")
    || "",
  ).trim() || null;
  const reservedKeys = new Set([
    "at",
    "channel",
    "event",
    "stage",
    "kind",
    "sourceEvent",
    "joinAttemptId",
    "controllerId",
    "conversationId",
    "serverId",
    "channelId",
    "edgeFunctionName",
    "functionName",
    "edgeFunction",
    "functionPath",
    "functionUrl",
    "responseUrl",
    "edgeResponseUrl",
    "httpStatus",
    "edgeStatus",
    "payloadStatus",
    "statusText",
    "edgeStatusText",
    "responseBodyText",
    "edgeResponseText",
    "responseText",
    "responseJson",
    "edgeResponseJson",
    "payload",
    "errorCode",
    "edgeErrorCode",
    "payloadErrorCode",
    "errorMessage",
    "edgeErrorMessage",
    "payloadMessage",
    "payloadReason",
    "reasonCode",
    "triggeredBy",
    "fatal",
    "roomConnectionState",
    "roomJoinPhase",
    "roomConnected",
    "localTrackPublished",
  ]);
  const extraDetails = {};
  Object.keys(payload)
    .sort((a, b) => a.localeCompare(b))
    .forEach((key) => {
      if (reservedKeys.has(key)) return;
      const nextValue = sanitizeServerVoiceStructuredLogValue(payload[key]);
      if (typeof nextValue !== "undefined") extraDetails[key] = nextValue;
    });
  const record = {
    at: new Date().toISOString(),
    channel: String(channel || "server-voice").trim() || "server-voice",
    event: String(event || "").trim() || "event",
    stage: String(payload.stage || event || "").trim() || "event",
    kind: String(payload.kind || "").trim() || null,
    sourceEvent: String(payload.sourceEvent || "").trim() || null,
    joinAttemptId: String(payload.joinAttemptId || "").trim() || null,
    controllerId: String(payload.controllerId || "").trim() || null,
    conversationId: normId(payload.conversationId || "") || null,
    serverId: normId(payload.serverId || "") || null,
    channelId: normId(payload.channelId || "") || null,
    edgeFunctionName,
    functionPath: String(
      payload.functionPath
      || (edgeFunctionName ? `/functions/v1/${edgeFunctionName}` : "")
      || "",
    ).trim() || null,
    responseUrl: String(payload.edgeResponseUrl || payload.responseUrl || payload.functionUrl || "").trim() || null,
    httpStatus,
    statusText: String(payload.statusText || payload.edgeStatusText || "").trim() || null,
    responseBodyText: responseBodyText == null ? null : String(responseBodyText),
    responseJson: sanitizeServerVoiceStructuredLogValue(responseJson),
    errorCode: String(
      payload.errorCode
      || payload.edgeErrorCode
      || payload.payloadErrorCode
      || payload.errorName
      || "",
    ).trim() || null,
    errorMessage: String(
      payload.errorMessage
      || payload.edgeErrorMessage
      || payload.payloadMessage
      || payload.payloadReason
      || "",
    ).trim() || null,
    reasonCode: String(payload.reasonCode || "").trim() || null,
    triggeredBy: String(payload.triggeredBy || "").trim() || null,
    fatal: typeof payload.fatal === "boolean" ? payload.fatal : null,
    roomConnectionState: String(payload.roomConnectionState || "").trim() || null,
    roomJoinPhase: String(payload.roomJoinPhase || "").trim() || null,
    roomConnected: typeof payload.roomConnected === "boolean" ? payload.roomConnected : null,
    localTrackPublished: typeof payload.localTrackPublished === "boolean" ? payload.localTrackPublished : null,
  };
  if (Object.keys(extraDetails).length) record.details = extraDetails;
  return record;
}

function writeStructuredServerVoiceConsoleLog(prefix, event, details = {}, {
  level = "info",
  channel = "server-voice",
} = {}) {
  const normalizedLevel = ["debug", "info", "warn", "error"].includes(String(level || "").trim().toLowerCase())
    ? String(level || "").trim().toLowerCase()
    : "info";
  const record = buildStructuredServerVoiceLogRecord(event, details, { channel });
  let serialized = "";
  try {
    serialized = JSON.stringify(record);
  } catch (_) {
    serialized = JSON.stringify({
      at: new Date().toISOString(),
      channel,
      event: String(event || "").trim() || "event",
      errorMessage: "failed_to_serialize_log_record",
    });
  }
  try {
    console[normalizedLevel](`${String(prefix || "").trim() || "[server-voice]"} ${serialized}`);
  } catch (_) {}
  return record;
}

function normalizeServerVoiceJoinFailureKind(kind = "", {
  event = "",
  stage = "",
  reasonCode = "",
} = {}) {
  const requested = String(kind || "").trim().toLowerCase();
  if (["token_failed", "rtc_config_failed", "room_connect_failed", "publish_failed", "cleanup_triggered", "unknown"].includes(requested)) {
    return requested;
  }
  const normalizedEvent = String(event || "").trim().toLowerCase();
  const normalizedStage = String(stage || "").trim().toLowerCase();
  const normalizedReasonCode = String(reasonCode || "").trim().toLowerCase();
  if (normalizedEvent.startsWith("token.") || normalizedStage.includes("token")) return "token_failed";
  if (normalizedEvent.includes("turn_credentials") || normalizedEvent.includes("rtc.") || normalizedStage.includes("rtc")) return "rtc_config_failed";
  if (normalizedEvent.includes("room.connect_failed") || normalizedStage === "room_connect") return "room_connect_failed";
  if (normalizedEvent.includes("publish_failed") || normalizedStage.includes("publish")) return "publish_failed";
  if (normalizedEvent.startsWith("cleanup.") || normalizedReasonCode.startsWith("cleanup.") || normalizedReasonCode.includes("disconnect")) return "cleanup_triggered";
  return "unknown";
}

function getServerVoiceJoinFailureSummary(conversationId = null) {
  const convId = normId(conversationId || "");
  if (!convId) return null;
  return serverVoiceJoinFailureSummaryByConversation.get(convId) || null;
}

function setServerVoiceJoinFailureSummary(conversationId, summary = null) {
  const convId = normId(conversationId || "");
  if (!convId) return;
  if (!summary || typeof summary !== "object") {
    serverVoiceJoinFailureSummaryByConversation.delete(convId);
    return;
  }
  serverVoiceJoinFailureSummaryByConversation.set(convId, sanitizeServerVoiceStructuredLogValue(summary));
}

function clearServerVoiceJoinFailureSummary(conversationId = null) {
  const convId = normId(conversationId || "");
  if (!convId) return;
  serverVoiceJoinFailureSummaryByConversation.delete(convId);
}

function logServerVoiceJoinFailureSummary(conversationId, details = {}, {
  level = "error",
  persist = true,
} = {}) {
  const convId = normId(conversationId || details?.conversationId || "");
  const summary = {
    ...(details && typeof details === "object" && !Array.isArray(details) ? details : { value: details ?? null }),
    at: new Date().toISOString(),
    conversationId: convId || normId(details?.conversationId || "") || null,
  };
  summary.sourceEvent = String(summary.event || "").trim() || null;
  summary.kind = normalizeServerVoiceJoinFailureKind(summary.kind, {
    event: summary.sourceEvent || summary.event || "join.failure_summary",
    stage: summary.stage || "",
    reasonCode: summary.reasonCode || "",
  });
  summary.fatal = typeof summary.fatal === "boolean" ? summary.fatal : (summary.kind !== "rtc_config_failed");
  if (persist && convId) setServerVoiceJoinFailureSummary(convId, summary);
  logServerVoiceJoinLifecycle("join.failure_summary", summary, { level });
  return summary;
}

function logServerVoiceDebug(event, details = {}) {
  if (!isServerVoiceDebugLoggingEnabled()) return;
  writeStructuredServerVoiceConsoleLog("[server-voice]", event, details, {
    level: "debug",
    channel: "server-voice",
  });
}

function describeServerVoiceError(error) {
  const rawMessage = error?.message || error?.error_description || error?.description || String(error || "unknown_error");
  const message = String(rawMessage || "unknown_error").trim() || "unknown_error";
  const name = String(error?.name || error?.code || "").trim() || null;
  const stack = typeof error?.stack === "string"
    ? error.stack
      .split("\n")
      .map((line) => String(line || "").trim())
      .filter(Boolean)
      .slice(0, 3)
      .join(" | ")
    : null;
  return {
    errorName: name,
    errorMessage: message,
    errorStack: stack,
  };
}

async function inspectServerVoiceFunctionInvokeError(error) {
  const details = {
    edgeStatus: null,
    edgeStatusText: null,
    edgeResponseUrl: null,
    edgeResponseText: null,
    edgeResponseJson: null,
    edgeErrorCode: null,
    edgeErrorMessage: null,
  };
  const candidates = [
    error?.context,
    error?.response,
    error?.cause?.context,
    error?.cause?.response,
  ];
  for (const candidate of candidates) {
    if (!candidate || typeof candidate !== "object") continue;
    const hasStatus = Number.isFinite(Number(candidate?.status)) && Number(candidate?.status) > 0;
    const canReadText = typeof candidate?.text === "function";
    if (!hasStatus && !canReadText) continue;
    details.edgeStatus = hasStatus ? Number(candidate.status) : null;
    details.edgeStatusText = String(candidate?.statusText || "").trim() || null;
    details.edgeResponseUrl = String(candidate?.url || "").trim() || null;
    let rawBody = "";
    try {
      const responseLike = typeof candidate.clone === "function" ? candidate.clone() : candidate;
      rawBody = await responseLike.text();
    } catch (_) {
      rawBody = "";
    }
    const trimmedBody = String(rawBody || "").trim();
    details.edgeResponseText = trimmedBody || null;
    details.edgeResponseJson = safeParseServerVoiceJson(trimmedBody);
    details.edgeErrorCode = String(
      details.edgeResponseJson?.error
      || details.edgeResponseJson?.code
      || error?.code
      || "",
    ).trim() || null;
    details.edgeErrorMessage = String(
      details.edgeResponseJson?.message
      || details.edgeResponseJson?.reason
      || details.edgeResponseJson?.error_description
      || "",
    ).trim() || null;
    return details;
  }
  const directStatus = Number(error?.status || error?.statusCode || error?.cause?.status || 0);
  if (Number.isFinite(directStatus) && directStatus > 0) details.edgeStatus = directStatus;
  details.edgeStatusText = String(error?.statusText || error?.cause?.statusText || "").trim() || null;
  details.edgeErrorCode = String(error?.code || error?.error || "").trim() || null;
  details.edgeErrorMessage = String(
    error?.error_description
    || error?.description
    || "",
  ).trim() || null;
  return details;
}

function createServerVoiceJoinAttemptId(conversationId = null) {
  const convId = normId(conversationId || "");
  serverVoiceJoinAttemptCounter += 1;
  return `${convId || "voice"}:${Date.now()}:${serverVoiceJoinAttemptCounter}`;
}

function createServerVoiceTransportControllerId(conversationId = null) {
  const convId = normId(conversationId || "");
  serverVoiceTransportControllerCounter += 1;
  return `${convId || "voice"}:controller:${Date.now()}:${serverVoiceTransportControllerCounter}`;
}

function markServerVoiceJoinAttemptStarted(conversationId, joinAttemptId) {
  const convId = normId(conversationId || "");
  const attemptId = String(joinAttemptId || "").trim();
  if (!convId || !attemptId) return;
  serverVoiceJoinInFlightByConversation.set(convId, attemptId);
  serverVoiceActiveJoinAttemptIdByConversation.set(convId, attemptId);
}

function clearServerVoiceJoinAttemptInFlight(conversationId, joinAttemptId = null) {
  const convId = normId(conversationId || "");
  if (!convId) return;
  const expectedAttemptId = String(joinAttemptId || "").trim();
  const currentAttemptId = String(serverVoiceJoinInFlightByConversation.get(convId) || "").trim();
  if (!expectedAttemptId || currentAttemptId === expectedAttemptId) {
    serverVoiceJoinInFlightByConversation.delete(convId);
  }
}

function clearServerVoiceActiveJoinAttempt(conversationId, joinAttemptId = null) {
  const convId = normId(conversationId || "");
  if (!convId) return;
  const expectedAttemptId = String(joinAttemptId || "").trim();
  const currentAttemptId = String(serverVoiceActiveJoinAttemptIdByConversation.get(convId) || "").trim();
  if (!expectedAttemptId || currentAttemptId === expectedAttemptId) {
    serverVoiceActiveJoinAttemptIdByConversation.delete(convId);
  }
}

function isServerVoiceJoinAttemptCurrent(conversationId, joinAttemptId) {
  const convId = normId(conversationId || "");
  const attemptId = String(joinAttemptId || "").trim();
  if (!convId || !attemptId) return false;
  return String(serverVoiceActiveJoinAttemptIdByConversation.get(convId) || "").trim() === attemptId;
}

function setPendingServerVoiceCleanupContext(conversationId, details = {}) {
  const convId = normId(conversationId || "");
  if (!convId || !isServerVoiceConversationById(convId)) return;
  serverVoicePendingCleanupContextByConversation.set(convId, {
    ...(details && typeof details === "object" && !Array.isArray(details) ? details : {}),
  });
}

function consumePendingServerVoiceCleanupContext(conversationId) {
  const convId = normId(conversationId || "");
  if (!convId) return null;
  const context = serverVoicePendingCleanupContextByConversation.get(convId) || null;
  serverVoicePendingCleanupContextByConversation.delete(convId);
  return context;
}

function getServerVoiceControllerSnapshot(controller = null, conversationId = null) {
  if (controller?.getSnapshot) {
    try {
      const snapshot = controller.getSnapshot();
      if (snapshot && typeof snapshot === "object") return snapshot;
    } catch (_) {}
  }
  const convId = normId(conversationId || controller?.conversationId || serverVoiceTransportConversationId || "");
  if (!convId) return null;
  return getServerVoiceTransportSnapshot(convId);
}

function describeServerVoiceCleanupContext({
  conversationId = null,
  joinAttemptId = null,
  controller = null,
  controllerId = null,
} = {}) {
  const convId = normId(conversationId || controller?.conversationId || callConversationId || activeDmId || serverVoiceTransportConversationId || "");
  const snapshot = getServerVoiceControllerSnapshot(controller, convId);
  const activeController = getActiveServerVoiceTransportController(convId);
  const activeSnapshot = getServerVoiceTransportSnapshot(convId);
  const derivedControllerId = String(
    controllerId
    || controller?.controllerId
    || snapshot?.controllerId
    || activeSnapshot?.controllerId
    || "",
  ).trim() || null;
  const derivedJoinAttemptId = String(
    joinAttemptId
    || snapshot?.joinAttemptId
    || activeSnapshot?.joinAttemptId
    || serverVoiceActiveJoinAttemptIdByConversation.get(convId)
    || "",
  ).trim() || null;
  return {
    joinAttemptId: derivedJoinAttemptId,
    controllerId: derivedControllerId,
    controllerIsActive: !!(
      convId
      && controller
      && activeController
      && activeController === controller
      && normId(serverVoiceTransportConversationId || "") === convId
    ),
    activeTransportConversationId: normId(serverVoiceTransportConversationId || "") || null,
    roomConnectionState: String(snapshot?.connectionState || activeSnapshot?.connectionState || "").trim().toLowerCase() || null,
    roomJoinPhase: String(snapshot?.joinPhase || activeSnapshot?.joinPhase || "").trim().toLowerCase() || null,
    roomConnected: snapshot?.local?.roomConnected ?? activeSnapshot?.local?.roomConnected ?? null,
    roomDisconnectRequested: snapshot?.disconnectRequested ?? activeSnapshot?.disconnectRequested ?? null,
    localTrackPublished: snapshot?.local?.audioTrackPublished ?? activeSnapshot?.local?.audioTrackPublished ?? null,
  };
}

function logServerVoiceCleanupTrigger(event, {
  conversationId = null,
  reasonCode = "",
  triggeredBy = "",
  joinAttemptId = null,
  controller = null,
  controllerId = null,
  level = "warn",
  ...details
} = {}) {
  const convId = normId(conversationId || controller?.conversationId || callConversationId || activeDmId || serverVoiceTransportConversationId || "");
  if (!convId || !isServerVoiceConversationById(convId)) return;
  logServerVoiceJoinLifecycle(event, {
    conversationId: convId,
    reasonCode: String(reasonCode || "").trim() || null,
    triggeredBy: String(triggeredBy || "").trim() || null,
    ...describeServerVoiceCleanupContext({
      conversationId: convId,
      joinAttemptId,
      controller,
      controllerId,
    }),
    ...details,
  }, { level });
  const normalizedReasonCode = String(reasonCode || "").trim().toLowerCase();
  const shouldPersistFailure = !(
    normalizedReasonCode === "cleanup.disconnect.switch_channel"
    || normalizedReasonCode === "cleanup.disconnect.user_leave"
    || normalizedReasonCode === "cleanup.disconnect.explicit_leave"
  );
  if (shouldPersistFailure) {
    logServerVoiceJoinFailureSummary(convId, {
      kind: "cleanup_triggered",
      event,
      joinAttemptId: joinAttemptId || null,
      controllerId: String(controllerId || controller?.controllerId || "").trim() || null,
      conversationId: convId,
      reasonCode: String(reasonCode || "").trim() || null,
      triggeredBy: String(triggeredBy || "").trim() || null,
      ...describeServerVoiceCleanupContext({
        conversationId: convId,
        joinAttemptId,
        controller,
        controllerId,
      }),
      ...details,
    }, { level, persist: true });
  }
}

function safeParseServerVoiceJson(raw = "") {
  const text = String(raw || "").trim();
  if (!text) return null;
  try {
    return JSON.parse(text);
  } catch (_) {
    return null;
  }
}

function decodeServerVoiceBase64Url(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return "";
  const normalized = raw
    .replace(/-/g, "+")
    .replace(/_/g, "/")
    .padEnd(Math.ceil(raw.length / 4) * 4, "=");
  if (typeof atob === "function") return atob(normalized);
  if (typeof Buffer !== "undefined") return Buffer.from(normalized, "base64").toString("utf8");
  throw new Error("base64_decode_unavailable");
}

function decodeServerVoiceJwtPayload(token = "") {
  const raw = String(token || "").trim();
  const parts = raw.split(".");
  if (parts.length !== 3) return null;
  try {
    return safeParseServerVoiceJson(decodeServerVoiceBase64Url(parts[1])) || null;
  } catch (_) {
    return null;
  }
}

function inspectServerVoiceLiveKitJoinPayload(joinPayload = {}, {
  expectedConversationId = "",
  expectedServerId = "",
  expectedChannelId = "",
  expectedMediaMode = "",
} = {}) {
  const payloadConversationId = normId(joinPayload?.conversationId || "");
  const payloadServerId = normId(joinPayload?.serverId || "");
  const payloadChannelId = normId(joinPayload?.channelId || "");
  const payloadRoomName = String(joinPayload?.roomName || "").trim() || "";
  const expectedRoomName = expectedConversationId ? `server-voice:${expectedConversationId}` : "";
  const payloadUrl = String(joinPayload?.url || "").trim();
  const payloadToken = String(joinPayload?.token || "").trim();
  const decodedToken = decodeServerVoiceJwtPayload(payloadToken);
  const tokenGrant = decodedToken?.video && typeof decodedToken.video === "object"
    ? decodedToken.video
    : {};
  const tokenMetadata = decodedToken?.metadata && typeof decodedToken.metadata === "string"
    ? safeParseServerVoiceJson(decodedToken.metadata)
    : null;
  const tokenConversationId = normId(
    tokenMetadata?.conversationId
    || decodedToken?.conversation_id
    || decodedToken?.conversationId
    || "",
  );
  const tokenServerId = normId(
    tokenMetadata?.serverId
    || decodedToken?.server_id
    || decodedToken?.serverId
    || "",
  );
  const tokenChannelId = normId(
    tokenMetadata?.channelId
    || decodedToken?.channel_id
    || decodedToken?.channelId
    || "",
  );
  const tokenMediaMode = String(
    tokenMetadata?.mediaMode
    || decodedToken?.media_mode
    || decodedToken?.mediaMode
    || "",
  ).trim() || "";
  const tokenRoomGrant = String(tokenGrant?.room || "").trim() || "";
  const tokenIdentity = normId(decodedToken?.sub || decodedToken?.identity || "");
  const expSec = Number(decodedToken?.exp || 0);
  const tokenExpiresAt = Number.isFinite(expSec) && expSec > 0
    ? new Date(expSec * 1000).toISOString()
    : null;
  const tokenExpiresInMs = Number.isFinite(expSec) && expSec > 0
    ? (expSec * 1000) - Date.now()
    : null;
  let urlProtocol = null;
  let urlHost = null;
  let urlValid = false;
  if (payloadUrl) {
    try {
      const parsedUrl = new URL(payloadUrl);
      urlProtocol = String(parsedUrl.protocol || "").replace(/:$/, "") || null;
      urlHost = String(parsedUrl.host || "").trim() || null;
      urlValid = !!(urlProtocol && ["ws", "wss", "http", "https"].includes(urlProtocol));
    } catch (_) {
      urlValid = false;
    }
  }
  return {
    urlValid,
    urlProtocol,
    urlHost,
    tokenParsed: !!decodedToken,
    tokenIdentity: tokenIdentity || null,
    tokenRoomGrant: tokenRoomGrant || null,
    tokenConversationId: tokenConversationId || null,
    tokenServerId: tokenServerId || null,
    tokenChannelId: tokenChannelId || null,
    tokenMediaMode: tokenMediaMode || null,
    tokenExpiresAt,
    tokenExpiresInMs: tokenExpiresInMs == null ? null : tokenExpiresInMs,
    tokenExpired: tokenExpiresInMs == null ? null : tokenExpiresInMs <= 15000,
    expectedRoomName: expectedRoomName || null,
    roomNameMatchesConversation: !expectedRoomName ? null : payloadRoomName === expectedRoomName,
    roomGrantMatches: !payloadRoomName || !tokenRoomGrant ? null : tokenRoomGrant === payloadRoomName,
    mappingConversationMatches: !expectedConversationId ? null : payloadConversationId === expectedConversationId,
    mappingServerMatches: !expectedServerId ? null : payloadServerId === expectedServerId,
    mappingChannelMatches: !expectedChannelId ? null : payloadChannelId === expectedChannelId,
    mappingMediaModeMatches: !expectedMediaMode ? null : String(joinPayload?.mediaMode || "").trim() === expectedMediaMode,
    tokenConversationMatches: !expectedConversationId || !tokenConversationId ? null : tokenConversationId === expectedConversationId,
    tokenServerMatches: !expectedServerId || !tokenServerId ? null : tokenServerId === expectedServerId,
    tokenChannelMatches: !expectedChannelId || !tokenChannelId ? null : tokenChannelId === expectedChannelId,
    tokenMediaModeMatches: !expectedMediaMode || !tokenMediaMode ? null : tokenMediaMode === expectedMediaMode,
  };
}

function validateServerVoiceLiveKitJoinPayload(joinPayload = {}, expected = {}) {
  const diagnostics = inspectServerVoiceLiveKitJoinPayload(joinPayload, expected);
  if (!String(joinPayload?.url || "").trim()) {
    throw new Error("LiveKit join payload is missing a room URL.");
  }
  if (!diagnostics.urlValid) {
    throw new Error("LiveKit join payload returned an invalid room URL.");
  }
  if (!String(joinPayload?.token || "").trim()) {
    throw new Error("LiveKit join payload is missing a token.");
  }
  if (!diagnostics.tokenParsed) {
    throw new Error("LiveKit token is malformed or unreadable.");
  }
  if (!String(joinPayload?.roomName || "").trim()) {
    throw new Error("LiveKit join payload is missing a room name.");
  }
  if (diagnostics.roomNameMatchesConversation === false) {
    throw new Error("LiveKit room name does not match the requested conversation.");
  }
  if (!diagnostics.tokenRoomGrant) {
    throw new Error("LiveKit token is missing a room grant.");
  }
  if (diagnostics.roomGrantMatches === false) {
    throw new Error("LiveKit token room grant does not match the requested room.");
  }
  if (diagnostics.tokenExpired === true) {
    throw new Error("LiveKit token is expired or expires too soon.");
  }
  if (diagnostics.mappingConversationMatches === false) {
    throw new Error("LiveKit join payload conversationId does not match the requested conversation.");
  }
  if (diagnostics.mappingServerMatches === false) {
    throw new Error("LiveKit join payload serverId does not match the requested server.");
  }
  if (diagnostics.mappingChannelMatches === false) {
    throw new Error("LiveKit join payload channelId does not match the requested channel.");
  }
  if (diagnostics.tokenConversationMatches === false) {
    throw new Error("LiveKit token metadata conversationId does not match the requested conversation.");
  }
  if (diagnostics.tokenServerMatches === false) {
    throw new Error("LiveKit token metadata serverId does not match the requested server.");
  }
  if (diagnostics.tokenChannelMatches === false) {
    throw new Error("LiveKit token metadata channelId does not match the requested channel.");
  }
  if (diagnostics.mappingMediaModeMatches === false || diagnostics.tokenMediaModeMatches === false) {
    throw new Error("LiveKit join payload media mode does not match the expected channel mode.");
  }
  return diagnostics;
}

function logServerVoiceJoinLifecycle(event, details = {}, { level = "info" } = {}) {
  writeStructuredServerVoiceConsoleLog("[server-voice join]", event, details, {
    level,
    channel: "server-voice join",
  });
  logServerVoiceDebug(event, details);
}

function describeServerVoiceAudioTrack(track) {
  if (!track || track.kind !== "audio") {
    return {
      trackId: null,
      trackReadyState: null,
      trackEnabled: null,
      trackMuted: null,
      trackLabel: null,
    };
  }
  return {
    trackId: String(track.id || "") || null,
    trackReadyState: String(track.readyState || "").trim().toLowerCase() || null,
    trackEnabled: !!track.enabled,
    trackMuted: !!track.muted,
    trackLabel: String(track.label || "").trim() || null,
  };
}

function getServerVoiceLocalMediaDebugState(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  const sameConversation = !!(convId && normId(callConversationId || activeDmId || pendingCallInfo?.conversationId || "") === convId);
  const bestTrack = getBestLocalMicTrack() || localMicTrack || null;
  const rawTrack = getLocalRawMicTrack() || null;
  const sender = sameConversation
    ? (
        callMicSender
        || callPc?.getSenders?.().find((s) => s?.track?.kind === "audio")
        || null
      )
    : null;
  const senderTrack = sender?.track || null;
  return {
    micMuted: !!micMuted,
    deafened: !!deafened,
    inputDeviceId: String(voiceInputDeviceId || "").trim() || "default",
    outputDeviceId: String(voiceOutputDeviceId || "").trim() || "default",
    localTrackSource: bestTrack && rawTrack && String(bestTrack.id || "") === String(rawTrack.id || "")
      ? "raw"
      : "processed",
    ...Object.fromEntries(Object.entries(describeServerVoiceAudioTrack(bestTrack)).map(([key, value]) => [`local${key.charAt(0).toUpperCase()}${key.slice(1)}`, value])),
    rawTrackId: String(rawTrack?.id || "") || null,
    rawTrackReadyState: String(rawTrack?.readyState || "").trim().toLowerCase() || null,
    senderTrackId: String(senderTrack?.id || "") || null,
    senderTrackReadyState: String(senderTrack?.readyState || "").trim().toLowerCase() || null,
    senderTrackEnabled: senderTrack ? !!senderTrack.enabled : null,
    senderTransportState: String(sender?.transport?.state || "").trim().toLowerCase() || null,
  };
}

function logServerVoiceLocalMediaDebug(event, conversationId = null, details = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  if (!convId || !isServerVoiceConversationById(convId)) return;
  logServerVoiceDebug(event, {
    conversationId: convId,
    ...getServerVoiceLocalMediaDebugState(convId),
    ...((details && typeof details === "object" && !Array.isArray(details)) ? details : { value: details ?? null }),
  });
}

function describeServerVoiceAudioTrackSettings(track) {
  if (!track || track.kind !== "audio" || typeof track.getSettings !== "function") {
    return {
      settingsDeviceId: null,
      settingsEchoCancellation: null,
      settingsNoiseSuppression: null,
      settingsAutoGainControl: null,
      settingsSampleRate: null,
      settingsChannelCount: null,
    };
  }
  let settings = {};
  try {
    settings = track.getSettings() || {};
  } catch (_) {
    settings = {};
  }
  return {
    settingsDeviceId: String(settings?.deviceId || "").trim() || null,
    settingsEchoCancellation: typeof settings?.echoCancellation === "boolean" ? settings.echoCancellation : null,
    settingsNoiseSuppression: typeof settings?.noiseSuppression === "boolean" ? settings.noiseSuppression : null,
    settingsAutoGainControl: typeof settings?.autoGainControl === "boolean" ? settings.autoGainControl : null,
    settingsSampleRate: Number.isFinite(Number(settings?.sampleRate)) ? Number(settings.sampleRate) : null,
    settingsChannelCount: Number.isFinite(Number(settings?.channelCount)) ? Number(settings.channelCount) : null,
  };
}

function getServerVoiceAudioConstraintDebugState({ forceServerVoiceSafe = false } = {}) {
  const effective = getVoiceInputAudioConstraintsBase({ forceServerVoiceSafe });
  const noiseSuppressionMode = normalizeVoiceNoiseSuppressionMode(voiceNoiseSuppressionMode);
  return {
    voiceInputProfile: String(voiceInputProfile || "custom").trim() || "custom",
    requestedEchoCancellation: !!voiceEchoCancellation,
    requestedNoiseSuppression: noiseSuppressionMode !== "off",
    requestedNoiseSuppressionMode: noiseSuppressionMode,
    requestedAutoGainControl: !!voiceAutoGainControl,
    effectiveEchoCancellation: effective.echoCancellation !== false,
    effectiveNoiseSuppression: effective.noiseSuppression !== false,
    effectiveAutoGainControl: effective.autoGainControl !== false,
    forceServerVoiceSafe: !!forceServerVoiceSafe,
  };
}

function getServerVoiceRemoteAudioSourcePriority(source = "") {
  const key = String(source || "").trim().toLowerCase();
  return Number(SERVER_VOICE_REMOTE_AUDIO_SOURCE_PRIORITY[key] || 0);
}

function countServerVoiceRemoteAudioDomElements(ownerUserId, conversationId = null) {
  const uid = normId(ownerUserId || "");
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  if (!uid || !convId || typeof document === "undefined") return 0;
  return Array.from(document.querySelectorAll("audio[data-remote-audio-owner]")).filter((node) => {
    if (!(node instanceof HTMLAudioElement)) return false;
    return normId(node.dataset.remoteAudioOwner || "") === uid
      && normId(node.dataset.remoteAudioConversation || "") === convId;
  }).length;
}

function logServerVoiceLocalMicStateIfChanged(conversationId = null, {
  reason = "",
  ...details
} = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || pendingCallInfo?.conversationId || "");
  if (!convId || !isServerVoiceConversationById(convId)) return;
  const snapshot = getServerVoiceLocalMediaDebugState(convId);
  const signature = JSON.stringify({
    micMuted: !!snapshot.micMuted,
    deafened: !!snapshot.deafened,
    localTrackId: snapshot.localTrackId || null,
    localTrackEnabled: snapshot.localTrackEnabled,
    localTrackMuted: snapshot.localTrackMuted,
    senderTrackId: snapshot.senderTrackId || null,
    senderTrackEnabled: snapshot.senderTrackEnabled,
    inputDeviceId: snapshot.inputDeviceId || "default",
    outputDeviceId: snapshot.outputDeviceId || "default",
  });
  if (serverVoiceLastLocalMicStateSignatureByConversation.get(convId) === signature) return;
  serverVoiceLastLocalMicStateSignatureByConversation.set(convId, signature);
  logServerVoiceLocalMediaDebug("mic.state", convId, {
    reason: String(reason || "").trim() || null,
    ...details,
  });
}

function logServerVoiceParticipantAudioStateIfChanged(conversationId, userId, {
  reason = "",
  source = "",
  track = null,
  ...details
} = {}) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid || !isServerVoiceConversationById(convId)) return;
  let store = serverVoiceLastParticipantAudioStateSignatureByConversation.get(convId) || null;
  if (!store) {
    store = new Map();
    serverVoiceLastParticipantAudioStateSignatureByConversation.set(convId, store);
  }
  const participantAudioState = getCallParticipantAudioState(convId, uid) || null;
  const signature = JSON.stringify({
    micMuted: participantAudioState?.micMuted ?? null,
    deafened: participantAudioState?.deafened ?? null,
    remoteTrackId: String(track?.id || "") || null,
    remoteTrackMuted: track?.kind === "audio" ? !!track?.muted : null,
    remoteTrackEnabled: track?.kind === "audio" ? !!track?.enabled : null,
    source: String(source || "").trim().toLowerCase() || null,
  });
  if (store.get(uid) === signature) return;
  store.set(uid, signature);
  logServerVoiceDebug("participant.audio_state", {
    conversationId: convId,
    peerUserId: uid,
    reason: String(reason || "").trim() || null,
    source: String(source || "").trim().toLowerCase() || null,
    micMuted: participantAudioState?.micMuted ?? null,
    deafened: participantAudioState?.deafened ?? null,
    seenAt: participantAudioState?.seenAt || null,
    ...Object.fromEntries(Object.entries(describeServerVoiceAudioTrack(track)).map(([key, value]) => [`remote${key.charAt(0).toUpperCase()}${key.slice(1)}`, value])),
    ...details,
  });
}

function getServerVoiceParticipantHistoryStore(rootMap, conversationId, {
  create = false,
} = {}) {
  const convId = normId(conversationId || "");
  if (!convId || !isServerVoiceConversationById(convId)) return null;
  let store = rootMap.get(convId) || null;
  if (!store && create) {
    store = new Map();
    rootMap.set(convId, store);
  }
  return store;
}

function recordServerVoiceParticipantLifecycleEvent(conversationId, userId, eventName, {
  source = "",
  ...details
} = {}) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  const event = String(eventName || "").trim().toLowerCase();
  if (!convId || !uid || !event || !isServerVoiceConversationById(convId)) return;
  const store = getServerVoiceParticipantHistoryStore(serverVoiceParticipantLifecycleHistoryByConversation, convId, {
    create: true,
  });
  if (!store) return;
  const now = Date.now();
  const history = Array.isArray(store.get(uid)) ? store.get(uid) : [];
  const nextHistory = history
    .filter((entry) => entry && (now - Number(entry.at || 0)) <= SERVER_VOICE_PARTICIPANT_FLICKER_WINDOW_MS)
    .concat([{
      at: now,
      event,
      source: String(source || "").trim().toLowerCase() || null,
      ...((details && typeof details === "object" && !Array.isArray(details)) ? details : {}),
    }]);
  store.set(uid, nextHistory);
  const recent = nextHistory.slice(-SERVER_VOICE_PARTICIPANT_FLICKER_EVENT_THRESHOLD);
  if (recent.length < SERVER_VOICE_PARTICIPANT_FLICKER_EVENT_THRESHOLD) return;
  const alternating = recent.every((entry, index) => index === 0 || entry.event !== recent[index - 1].event);
  const uniqueEvents = new Set(recent.map((entry) => entry.event));
  if (!alternating || uniqueEvents.size < 2) return;
  logServerVoiceDebug("participant.presence_flicker_detected", {
    conversationId: convId,
    peerUserId: uid,
    source: String(source || "").trim().toLowerCase() || null,
    eventCount: nextHistory.length,
    recentEvents: recent.map((entry) => ({
      at: new Date(Number(entry.at || now)).toISOString(),
      event: entry.event,
      source: entry.source || null,
    })),
  });
}

function recordServerVoiceParticipantAudioStateChange(conversationId, userId, nextState = null, {
  source = "",
  reason = "",
} = {}) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid || !isServerVoiceConversationById(convId)) return;
  const store = getServerVoiceParticipantHistoryStore(serverVoiceParticipantAudioStateHistoryByConversation, convId, {
    create: true,
  });
  if (!store) return;
  const now = Date.now();
  const statePayload = nextState && typeof nextState === "object" && !Array.isArray(nextState)
    ? nextState
    : {};
  const signature = JSON.stringify({
    micMuted: statePayload?.micMuted ?? null,
    deafened: statePayload?.deafened ?? null,
  });
  const history = Array.isArray(store.get(uid)) ? store.get(uid) : [];
  const recentHistory = history.filter((entry) => entry && (now - Number(entry.at || 0)) <= SERVER_VOICE_AUDIO_STATE_OSCILLATION_WINDOW_MS);
  const previous = recentHistory[recentHistory.length - 1] || null;
  if (previous?.signature === signature) {
    store.set(uid, recentHistory);
    return;
  }
  const nextHistory = recentHistory.concat([{
    at: now,
    signature,
    micMuted: statePayload?.micMuted ?? null,
    deafened: statePayload?.deafened ?? null,
    source: String(source || "").trim().toLowerCase() || null,
    reason: String(reason || "").trim() || null,
  }]);
  store.set(uid, nextHistory);
  const recent = nextHistory.slice(-SERVER_VOICE_AUDIO_STATE_OSCILLATION_THRESHOLD);
  if (recent.length < SERVER_VOICE_AUDIO_STATE_OSCILLATION_THRESHOLD) return;
  const alternating = recent.every((entry, index) => index === 0 || entry.signature !== recent[index - 1].signature);
  const uniqueStates = new Set(recent.map((entry) => entry.signature));
  if (!alternating || uniqueStates.size < 2) return;
  logServerVoiceDebug("participant.audio_state_oscillation_detected", {
    conversationId: convId,
    peerUserId: uid,
    source: String(source || "").trim().toLowerCase() || null,
    reason: String(reason || "").trim() || null,
    transitionCount: nextHistory.length,
    recentStates: recent.map((entry) => ({
      at: new Date(Number(entry.at || now)).toISOString(),
      micMuted: entry.micMuted,
      deafened: entry.deafened,
      source: entry.source || null,
      reason: entry.reason || null,
    })),
  });
}

async function logServerVoiceDeviceInventory(event, conversationId = null, details = {}) {
  const convId = normId(conversationId || getInspectableServerVoiceConversationId());
  if (!convId || !isServerVoiceConversationById(convId)) return;
  const devices = await enumerateVoiceDevicesSafe();
  const audioInputCount = devices.filter((device) => String(device?.kind || "") === "audioinput").length;
  const audioOutputCount = devices.filter((device) => String(device?.kind || "") === "audiooutput").length;
  logServerVoiceLocalMediaDebug(event, convId, {
    audioInputCount,
    audioOutputCount,
    ...details,
  });
}

function logPrivateCallDebug(event, details = {}, { level = "log" } = {}) {
  const eventName = String(event || "").trim();
  if (!eventName) return;
  const payload = details && typeof details === "object" && !Array.isArray(details)
    ? { ...details }
    : { value: details ?? null };
  const logLevel = String(level || "log").trim().toLowerCase();
  const method = logLevel === "error" ? "error" : (logLevel === "warn" ? "warn" : "log");
  try {
    console[method]("[private-call]", JSON.stringify({
      at: new Date().toISOString(),
      event: eventName,
      ...payload,
    }));
  } catch (_) {}
}

function logGroupCallDebug(event, details = {}, { level = "log" } = {}) {
  const eventName = String(event || "").trim();
  if (!eventName) return;
  const payload = details && typeof details === "object" && !Array.isArray(details)
    ? { ...details }
    : { value: details ?? null };
  const logLevel = String(level || "log").trim().toLowerCase();
  const method = logLevel === "error" ? "error" : (logLevel === "warn" ? "warn" : "log");
  try {
    console[method]("[group-call]", JSON.stringify({
      at: new Date().toISOString(),
      event: eventName,
      ...payload,
    }));
  } catch (_) {}
}

function parseGroupCallErrorPayload(value) {
  if (value && typeof value === "object" && !Array.isArray(value)) return value;
  if (typeof value !== "string") return null;
  const parsed = safeParseServerVoiceJson(value);
  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return null;
  return parsed;
}

function buildGroupCallTokenRequestUrl() {
  const base = String(SUPABASE_URL || "").trim().replace(/\/+$/, "");
  if (!base) return "/functions/v1/livekit-token";
  return `${base}/functions/v1/livekit-token`;
}

function isGroupDmJoinDeniedFull({
  responseStatus = null,
  responseBody = null,
  message = "",
} = {}) {
  const status = normalizePrivateCallResponseStatus(responseStatus);
  const payload = parseGroupCallErrorPayload(responseBody);
  const errorCode = String(payload?.error || payload?.code || "").trim().toLowerCase();
  const reasonCode = String(payload?.reason || "").trim().toLowerCase();
  const payloadMessage = String(payload?.message || "").trim().toLowerCase();
  const summary = `${String(message || "").trim().toLowerCase()} ${payloadMessage}`.trim();
  if (status !== 409) return false;
  if (errorCode === "channel_full") return true;
  if (reasonCode === "technical_cap" || reasonCode === "manual_limit") return true;
  return summary.includes("participant cap") || summary.includes("call is full");
}

function normalizePrivateCallResponseStatus(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? Math.trunc(parsed) : null;
}

function normalizePrivateCallResponseBody(value) {
  if (value == null) return null;
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (!trimmed) return null;
    return trimmed.length > 3000 ? `${trimmed.slice(0, 3000)}...` : trimmed;
  }
  try {
    const serialized = JSON.stringify(value);
    if (!serialized) return null;
    return serialized.length > 3000 ? `${serialized.slice(0, 3000)}...` : serialized;
  } catch (_) {
    const fallback = String(value || "").trim();
    if (!fallback) return null;
    return fallback.length > 3000 ? `${fallback.slice(0, 3000)}...` : fallback;
  }
}

function buildPrivateCallStageLogDetails({
  conversationId = null,
  otherUserId = "",
  roomName = "",
  stage = "",
  errorMessage = "",
  responseStatus = null,
  responseBody = null,
} = {}) {
  const convId = normId(
    conversationId
    || callConversationId
    || activeDmId
    || state.activeDm?.conversationId
    || ""
  );
  const meId = normId(state.user?.id || "");
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  const activePeerId = activeConvId && activeConvId === convId
    ? normId(state.activeDm?.otherUserId || state.activeDm?.other_user_id || "")
    : "";
  const resolvedOtherUserId = normId(
    otherUserId
    || callOtherUserId
    || callMediaPeerUserId
    || activePeerId
    || ""
  );
  const resolvedRoomName = String(
    roomName
    || (convId ? `${PRIVATE_CALL_LIVEKIT_ROOM_PREFIX}${convId}` : "")
    || ""
  ).trim();
  return {
    currentUserId: meId || null,
    conversationId: convId || null,
    dmId: convId || null,
    privateConversationId: convId || null,
    otherUserId: resolvedOtherUserId || null,
    roomName: resolvedRoomName || null,
    stage: String(stage || "").trim() || null,
    errorMessage: String(errorMessage || "").trim() || null,
    responseStatus: normalizePrivateCallResponseStatus(responseStatus),
    responseBody: normalizePrivateCallResponseBody(responseBody),
  };
}

function logPrivateCallStage(event, details = {}, { level = "log" } = {}) {
  const eventName = String(event || "").trim();
  if (!eventName) return;
  const payload = details && typeof details === "object" && !Array.isArray(details)
    ? { ...details }
    : {};
  logPrivateCallDebug(eventName, {
    ...buildPrivateCallStageLogDetails(payload),
    ...payload,
  }, { level });
}

function getPrivateCallErrorDiagnostics(error) {
  const err = error && typeof error === "object" ? error : null;
  const errorMessage = err?.message
    ? String(err.message || "").trim()
    : String(error || "").trim();
  const responseStatus = normalizePrivateCallResponseStatus(
    err?.responseStatus
    ?? err?.status
    ?? err?.code
    ?? err?.context?.status
    ?? null
  );
  const responseBody = normalizePrivateCallResponseBody(
    err?.responseBody
    ?? err?.details
    ?? err?.body
    ?? err?.context?.body
    ?? null
  );
  return {
    errorMessage: errorMessage || "unknown_error",
    responseStatus,
    responseBody,
  };
}

function normalizePrivateCallFailureDiagnostics(details = {}) {
  const payload = details && typeof details === "object" && !Array.isArray(details)
    ? { ...details }
    : {};
  const stageDetails = buildPrivateCallStageLogDetails(payload);
  return {
    ...stageDetails,
    stage: String(payload?.stage || stageDetails.stage || "").trim() || "unknown_stage",
    errorMessage: String(payload?.errorMessage || stageDetails.errorMessage || "").trim() || "unknown_error",
    responseStatus: normalizePrivateCallResponseStatus(payload?.responseStatus ?? stageDetails.responseStatus),
    responseBody: normalizePrivateCallResponseBody(payload?.responseBody ?? stageDetails.responseBody),
    roomName: String(payload?.roomName || stageDetails.roomName || "").trim() || null,
    conversationId: normId(payload?.conversationId || stageDetails.conversationId || "") || null,
    dmId: normId(payload?.dmId || stageDetails.dmId || payload?.conversationId || "") || null,
    privateConversationId: normId(
      payload?.privateConversationId
      || stageDetails.privateConversationId
      || payload?.conversationId
      || ""
    ) || null,
    otherUserId: normId(payload?.otherUserId || stageDetails.otherUserId || "") || null,
  };
}

function rememberPrivateCallFailureDiagnostics(details = {}) {
  const normalized = normalizePrivateCallFailureDiagnostics(details);
  privateCallLastFailureDiagnostics = normalized;
  return normalized;
}

function getPrivateCallFailureDiagnostics() {
  return privateCallLastFailureDiagnostics
    ? { ...privateCallLastFailureDiagnostics }
    : null;
}

function clearPrivateCallFailureDiagnostics() {
  privateCallLastFailureDiagnostics = null;
}

function emitPrivateCallFailureVisible(details = {}, { level = "error" } = {}) {
  const normalized = rememberPrivateCallFailureDiagnostics(details);
  const method = String(level || "error").trim().toLowerCase() === "warn" ? "warn" : "error";
  try {
    console[method]("[private-call][failure-visible]", normalized);
  } catch (_) {}
  return normalized;
}

function buildPrivateCallFailureUiText(details = {}) {
  const normalized = normalizePrivateCallFailureDiagnostics(details);
  const stage = String(normalized.stage || "").trim() || "unknown_stage";
  const status = normalized.responseStatus != null ? ` | status ${normalized.responseStatus}` : "";
  const errorMessage = String(normalized.errorMessage || "").trim() || "unknown_error";
  return `Falhou ao iniciar chamada (${stage}${status}): ${errorMessage}`;
}

function isPrivateDmConversationById(conversationId = null) {
  const convId = normId(conversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return false;
  if (isServerVoiceConversationById(convId)) return false;
  const meta = getActiveConversationMeta(convId) || getConversationMeta(convId) || {};
  const kind = String(meta?.kind || "").trim().toLowerCase();
  if (kind) return kind === "dm";
  if (isCallCapableGroupConversationMeta(meta) || isGroupConversationKind(kind) || isServerConversationKind(kind)) {
    return false;
  }
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (
    activeConvId
    && activeConvId === convId
    && String(state.activeDm?.kind || "").trim().toLowerCase() === "dm"
  ) {
    return true;
  }
  const hasDmContactMatch = (state.dmContacts || []).some((row) => (
    normId(row?.conversationId || row?.conversation_id || "") === convId
  ));
  if (hasDmContactMatch) return true;
  return !isGroupCallConversation(convId);
}

function shouldRoutePrivateDmCallViaLiveKit(conversationId = null) {
  if (!PRIVATE_CALL_LIVEKIT_ENABLED) return false;
  const convId = normId(conversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return false;
  return isPrivateDmConversationById(convId);
}

function isPrivateDmLiveKitTransportConversation(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return false;
  if (!shouldRoutePrivateDmCallViaLiveKit(convId)) return false;
  const activeLiveKitConvId = normId(privateCallLiveKitConversationId || "");
  return !!(activeLiveKitConvId && activeLiveKitConvId === convId);
}

function shouldRouteGroupDmCallViaLiveKit(conversationId = null) {
  if (!GROUP_DM_CALL_LIVEKIT_ENABLED) return false;
  const convId = normId(conversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId || isServerVoiceConversationById(convId)) return false;
  const meta = getActiveConversationMeta(convId) || getConversationMeta(convId) || {};
  const kind = String(meta?.kind || "").trim().toLowerCase();
  if (kind === "group") return true;
  if (isGroupConversationMeta(meta)) return true;
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (activeConvId && activeConvId === convId) {
    const activeKind = String(state.activeDm?.kind || "").trim().toLowerCase();
    if (activeKind === "group") return true;
  }
  return false;
}

function isGroupDmLiveKitTransportConversation(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return false;
  if (!shouldRouteGroupDmCallViaLiveKit(convId)) return false;
  const activeLiveKitConvId = normId(groupDmCallLiveKitConversationId || "");
  return !!(activeLiveKitConvId && activeLiveKitConvId === convId);
}

function getGroupDmLiveKitRoomName(conversationId = null) {
  const convId = normId(conversationId || activeDmId || state.activeDm?.conversationId || "");
  return convId ? `${GROUP_DM_CALL_LIVEKIT_ROOM_PREFIX}${convId}` : "";
}

function nextPrivateCallLiveKitJoinAttemptId(conversationId = null) {
  privateCallLiveKitJoinAttemptCounter += 1;
  const convId = normId(conversationId || "private");
  return `${convId || "private"}:join:${Date.now()}:${privateCallLiveKitJoinAttemptCounter}`;
}

function nextGroupDmCallLiveKitJoinAttemptId(conversationId = null) {
  groupDmCallLiveKitJoinAttemptCounter += 1;
  const convId = normId(conversationId || "group");
  return `${convId || "group"}:join:${Date.now()}:${groupDmCallLiveKitJoinAttemptCounter}`;
}

function normalizePrivateCallLifecycleState(value = "", fallback = PRIVATE_CALL_STATES.IDLE) {
  const normalized = String(value || "").trim().toLowerCase();
  if (!normalized) return fallback;
  return Object.values(PRIVATE_CALL_STATES).includes(normalized) ? normalized : fallback;
}

function setPrivateCallLifecycleState(nextState, {
  conversationId = null,
  otherUserId = "",
  reason = "",
} = {}) {
  const normalizedState = normalizePrivateCallLifecycleState(nextState, PRIVATE_CALL_STATES.IDLE);
  const convId = normId(
    conversationId
    || privateCallStateConversationId
    || callConversationId
    || activeDmId
    || ""
  );
  const peerUserId = normId(
    otherUserId
    || privateCallStateOtherUserId
    || callOtherUserId
    || callMediaPeerUserId
    || ""
  );
  privateCallState = normalizedState;
  if (normalizedState === PRIVATE_CALL_STATES.IDLE) {
    privateCallStateConversationId = "";
    privateCallStateOtherUserId = "";
  } else {
    privateCallStateConversationId = convId;
    privateCallStateOtherUserId = peerUserId;
  }
  logPrivateCallDebug("private_call.state_changed", {
    conversationId: privateCallStateConversationId || convId || null,
    peerUserId: privateCallStateOtherUserId || peerUserId || null,
    state: normalizedState,
    reason: String(reason || "").trim() || null,
  });
  return {
    state: normalizedState,
    conversationId: privateCallStateConversationId || "",
    otherUserId: privateCallStateOtherUserId || "",
  };
}

function getPrivateCallLifecycleState() {
  return {
    state: normalizePrivateCallLifecycleState(privateCallState, PRIVATE_CALL_STATES.IDLE),
    conversationId: normId(privateCallStateConversationId || ""),
    otherUserId: normId(privateCallStateOtherUserId || ""),
  };
}

function isPrivateCallRingingOrConnectingState(value = privateCallState) {
  const stateValue = normalizePrivateCallLifecycleState(value, PRIVATE_CALL_STATES.IDLE);
  return (
    stateValue === PRIVATE_CALL_STATES.OUTGOING_RINGING
    || stateValue === PRIVATE_CALL_STATES.INCOMING_RINGING
    || stateValue === PRIVATE_CALL_STATES.CONNECTING
  );
}

function clearPrivateCallLiveKitState(conversationId = null, { clearPendingInvite = false } = {}) {
  const convId = normId(conversationId || "");
  if (!convId || normId(privateCallLiveKitConversationId || "") === convId) {
    privateCallLiveKitConversationId = "";
    privateCallJoinInFlight = false;
  }
  const pendingInviteConvId = normId(pendingPrivateCallLiveKitInvite?.conversationId || "");
  if (clearPendingInvite || !convId || (pendingInviteConvId && pendingInviteConvId === convId)) {
    pendingPrivateCallLiveKitInvite = null;
  }
  const stateConvId = normId(privateCallStateConversationId || "");
  if (!convId || (stateConvId && stateConvId === convId)) {
    setPrivateCallLifecycleState(PRIVATE_CALL_STATES.IDLE, {
      conversationId: convId || stateConvId,
      otherUserId: "",
      reason: "clear_private_livekit_state",
    });
  }
  if (!convId || !privateCallLastFailureDiagnostics || normId(privateCallLastFailureDiagnostics?.conversationId || "") === convId) {
    clearPrivateCallFailureDiagnostics();
  }
}

function clearGroupDmCallLiveKitState(conversationId = null) {
  const convId = normId(conversationId || "");
  if (!convId || normId(groupDmCallLiveKitConversationId || "") === convId) {
    groupDmCallLiveKitConversationId = "";
    groupDmCallLiveKitJoinInFlight = false;
  }
}

function shouldUseServerVoiceLiveKitTransport(conversationId = null) {
  if (!SERVER_VOICE_LIVEKIT_JOIN_ENABLED) return false;
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId || SERVER_VOICE_TRANSPORT_KIND !== "livekit") return false;
  if (isServerVoiceConversationById(convId)) return true;
  if (isGroupDmLiveKitTransportConversation(convId)) return true;
  return isPrivateDmLiveKitTransportConversation(convId);
}

function getServerVoiceTransportSnapshot(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return null;
  return serverVoiceTransportSnapshotByConversation.get(convId) || null;
}

function getServerVoiceTransportInChannelIdsFromSnapshot(conversationId, snapshot = null) {
  const convId = normId(conversationId || "");
  if (!convId || !snapshot || typeof snapshot !== "object") return [];
  const meId = normId(state.user?.id || "");
  const connectionState = String(snapshot?.connectionState || "").trim().toLowerCase();
  const participantsByUser = snapshot?.participantsByUser && typeof snapshot.participantsByUser === "object"
    ? snapshot.participantsByUser
    : {};
  const participantIds = normalizeUuidArray(Object.keys(participantsByUser || {}));
  const visibleIds = [];
  const localConnected = !!(
    snapshot?.local?.roomConnected === true
    || snapshot?.connected === true
    || connectionState === "connected"
    || connectionState === "reconnecting"
    || connectionState === "signalreconnecting"
    || !!String(serverVoiceJoinInFlightByConversation.get(convId) || "").trim()
    || connectionState === "connecting"
  );
  if (meId && localConnected) visibleIds.push(meId);
  participantIds.forEach((uid) => {
    if (!uid || uid === meId) return;
    const participantState = participantsByUser?.[uid] || null;
    if (isServerVoiceTransportParticipantInChannel(convId, uid, participantState)) {
      visibleIds.push(uid);
    }
  });
  return normalizeUuidArray(visibleIds);
}

function removeServerVoiceUiCachedParticipantState(conversationId, userId) {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId || !uid) return;
  const visibilityEntry = getServerVoiceUiVisibilityEntry(convId, { create: false });
  if (visibilityEntry) {
    visibilityEntry.visibleIds = normalizeUuidArray(visibilityEntry.visibleIds || []).filter((id) => id !== uid);
    visibilityEntry.seenAtByUser.delete(uid);
    visibilityEntry.leaveGraceUntilByUser.delete(uid);
  }
  const lastVisibleSet = serverVoiceLastVisibleMembersByConversation.get(convId) || null;
  if (lastVisibleSet instanceof Set) {
    lastVisibleSet.delete(uid);
    if (!lastVisibleSet.size) serverVoiceLastVisibleMembersByConversation.delete(convId);
  }
  removeServerVoicePresenceMember(convId, uid);
  removeCallParticipantAudioState(convId, uid);
  removeCallParticipantShareState(convId, uid);
  if (normId(groupCallActiveMembersConversationId || "") === convId) {
    setGroupCallActiveMembers(
      normalizeUuidArray(groupCallActiveMemberIds).filter((id) => id !== uid),
      convId
    );
  }
}

function reconcileServerVoiceUiTransportSnapshotLeave(conversationId, previousSnapshot = null, nextSnapshot = null) {
  const convId = normId(conversationId || "");
  if (!convId || !nextSnapshot || typeof nextSnapshot !== "object") return;
  const previousVisibleIds = getServerVoiceTransportInChannelIdsFromSnapshot(convId, previousSnapshot);
  const nextVisibleIds = getServerVoiceTransportInChannelIdsFromSnapshot(convId, nextSnapshot);
  const nextVisibleSet = new Set(nextVisibleIds);
  const removedIds = previousVisibleIds.filter((uid) => uid && !nextVisibleSet.has(uid));
  if (!removedIds.length) {
    if (nextVisibleIds.length) clearServerVoiceUiForcedRemovedIds(convId, nextVisibleIds);
    return;
  }

  const meId = normId(state.user?.id || "");
  const remoteRemovedIds = removedIds.filter((uid) => uid && uid !== meId);
  const nextConnectionState = String(nextSnapshot?.connectionState || "").trim().toLowerCase();
  const nextJoinPhase = String(nextSnapshot?.joinPhase || "").trim().toLowerCase();
  const roomDisconnected = !!(
    nextSnapshot?.local?.roomConnected !== true
    && (
      nextConnectionState === "disconnected"
      || nextConnectionState === "failed"
      || nextConnectionState === "closed"
      || nextJoinPhase === "disconnected"
      || nextJoinPhase === "disconnected_unexpected"
    )
  );
  const localRemoved = !!(meId && removedIds.includes(meId));
  if (roomDisconnected && localRemoved) {
    preserveServerVoiceRemoteParticipantsAfterLocalLeave(convId, {
      triggerReason: "transport_snapshot_local_disconnect",
      previousVisibleParticipantIds: previousVisibleIds,
    });
    if (nextVisibleIds.length) clearServerVoiceUiForcedRemovedIds(convId, nextVisibleIds);
    return;
  }
  if (!roomDisconnected && remoteRemovedIds.length > 1) {
    logServerVoiceUiParticipantsEvent("ui.render_source_mismatch", convId, nextVisibleIds, "transport_snapshot_update", {
      callerFunction: "setServerVoiceTransportSnapshot",
      reason: "batched_multi_leave_ignored_while_connected",
      previousVisibleParticipantIds: previousVisibleIds,
      removedIds,
      roomDisconnected,
    });
    return;
  }

  const forcedEntry = getServerVoiceUiForcedRemovedEntry(convId, { create: true });
  removedIds.forEach((uid) => {
    if (!uid) return;
    forcedEntry?.add?.(uid);
    logServerVoiceUiParticipantsEvent("ui.participant_leave_detected", convId, nextVisibleIds, "transport_snapshot_update", {
      callerFunction: "setServerVoiceTransportSnapshot",
      peerUserId: uid,
      roomDisconnected,
      previousVisibleParticipantIds: previousVisibleIds,
    });
    removeServerVoiceUiCachedParticipantState(convId, uid);
    const visibleAfterCleanup = getServerVoiceInCallParticipantIds(convId, {
      triggerReason: "transport_snapshot_leave_cleanup",
      callerFunction: "setServerVoiceTransportSnapshot",
    });
    logServerVoiceUiParticipantsEvent("ui.participant_removed_from_visible_list", convId, visibleAfterCleanup, "transport_snapshot_update", {
      callerFunction: "setServerVoiceTransportSnapshot",
      peerUserId: uid,
      source: "transport_leave_cleanup",
    });
  });
  if (nextVisibleIds.length) clearServerVoiceUiForcedRemovedIds(convId, nextVisibleIds);
}

function setServerVoiceTransportSnapshot(conversationId, snapshot = null) {
  const convId = normId(conversationId || snapshot?.conversationId || "");
  if (!convId) return null;
  const previousSnapshot = serverVoiceTransportSnapshotByConversation.get(convId) || null;
  if (!snapshot || typeof snapshot !== "object" || Array.isArray(snapshot)) {
    clearServerVoiceTransportSnapshot(convId, {
      triggerReason: "set_transport_snapshot_null",
      preserveRemoteParticipants: true,
    });
    return null;
  }
  const nextSnapshot = {
    ...snapshot,
    conversationId: convId,
    transport: String(snapshot.transport || SERVER_VOICE_TRANSPORT_KIND || "livekit").trim() || "livekit",
  };
  serverVoiceTransportSnapshotByConversation.set(convId, nextSnapshot);
  reconcileServerVoiceUiTransportSnapshotLeave(convId, previousSnapshot, nextSnapshot);
  return nextSnapshot;
}

function clearServerVoiceTransportSnapshot(conversationId = null, {
  triggerReason = "",
  preserveRemoteParticipants = true,
} = {}) {
  const convId = normId(conversationId || "");
  if (!convId) {
    serverVoiceTransportSnapshotByConversation.clear();
    serverVoiceUiForcedRemovedByConversation.clear();
    serverVoiceUiVisibilityByConversation.clear();
    serverVoiceLastVisibleMembersByConversation.clear();
    serverVoiceUiPreserveRemoteAfterLocalLeaveByConversation.clear();
    clearServerVoiceTransportParticipantDiagnostics();
    return;
  }
  const previousSnapshot = serverVoiceTransportSnapshotByConversation.get(convId) || null;
  const visibilityEntry = getServerVoiceUiVisibilityEntry(convId, { create: false });
  const previousVisibleIds = normalizeUuidArray([
    ...getServerVoiceTransportInChannelIdsFromSnapshot(convId, previousSnapshot),
    ...normalizeUuidArray(visibilityEntry?.visibleIds || []),
  ]);
  const localUserId = normId(state.user?.id || "");
  const remoteParticipantIds = previousVisibleIds.filter((uid) => uid && uid !== localUserId);
  let preservedRemoteIds = [];
  if (preserveRemoteParticipants && (previousVisibleIds.includes(localUserId) || remoteParticipantIds.length)) {
    preservedRemoteIds = preserveServerVoiceRemoteParticipantsAfterLocalLeave(convId, {
      triggerReason: String(triggerReason || "").trim() || "clear_transport_snapshot",
      previousVisibleParticipantIds: previousVisibleIds,
    });
  }
  serverVoiceTransportSnapshotByConversation.delete(convId);
  clearServerVoiceTransportParticipantDiagnostics(convId);
  if (preservedRemoteIds.length) return;
  serverVoiceUiForcedRemovedByConversation.delete(convId);
  serverVoiceUiVisibilityByConversation.delete(convId);
  serverVoiceLastVisibleMembersByConversation.delete(convId);
  serverVoiceUiPreserveRemoteAfterLocalLeaveByConversation.delete(convId);
}

function getActiveServerVoiceTransportController(conversationId = null) {
  const convId = normId(conversationId || serverVoiceTransportConversationId || "");
  if (!convId || !serverVoiceTransportController) return null;
  if (normId(serverVoiceTransportConversationId || "") !== convId) return null;
  return serverVoiceTransportController;
}

function getActiveServerVoiceScreenshareLayer(conversationId = null) {
  const convId = normId(conversationId || serverVoiceScreenshareConversationId || "");
  if (!convId || !serverVoiceScreenshareLayer) return null;
  if (normId(serverVoiceScreenshareConversationId || "") !== convId) return null;
  return serverVoiceScreenshareLayer;
}

function getActiveServerVoiceCameraLayer(conversationId = null) {
  const convId = normId(conversationId || serverVoiceCameraConversationId || "");
  if (!convId || !serverVoiceCameraLayer) return null;
  if (normId(serverVoiceCameraConversationId || "") !== convId) return null;
  return serverVoiceCameraLayer;
}

function getServerVoiceCameraState(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const layer = getActiveServerVoiceCameraLayer(convId);
  if (!layer || typeof layer.getState !== "function") return null;
  return layer.getState();
}

function isServerVoiceLocalCameraActive(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const layer = getActiveServerVoiceCameraLayer(convId);
  if (!layer || typeof layer.isLocalCameraActive !== "function") return false;
  return !!layer.isLocalCameraActive();
}

function getServerVoiceLocalCameraTrack(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const layer = getActiveServerVoiceCameraLayer(convId);
  if (!layer || typeof layer.getLocalVideoTrack !== "function") return null;
  const track = layer.getLocalVideoTrack();
  return isLiveVideoTrack(track, { allowMuted: true }) ? track : null;
}

function getServerVoiceRemoteCameraVideoTracksByUser(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const layer = getActiveServerVoiceCameraLayer(convId);
  if (!layer || typeof layer.getRemoteVideoTracksByUser !== "function") return new Map();
  const byUser = layer.getRemoteVideoTracksByUser();
  return byUser instanceof Map ? byUser : new Map();
}

function getServerVoiceCameraPreferences(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const layer = getActiveServerVoiceCameraLayer(convId);
  const fallback = {
    preferredDeviceId: "",
    activeDeviceId: "",
  };
  if (!layer || typeof layer.getPreferences !== "function") return fallback;
  const prefs = layer.getPreferences?.() || {};
  return {
    preferredDeviceId: normId(prefs?.preferredDeviceId || ""),
    activeDeviceId: normId(prefs?.activeDeviceId || ""),
  };
}

async function listServerVoiceCameraDevices(conversationId = null) {
  const convId = normId(conversationId || callConversationId || activeDmId || "");
  const layer = getActiveServerVoiceCameraLayer(convId);
  if (layer && typeof layer.listVideoInputDevices === "function") {
    const listed = await layer.listVideoInputDevices();
    return Array.isArray(listed) ? listed : [];
  }
  const devices = await enumerateVoiceDevicesSafe();
  return (Array.isArray(devices) ? devices : [])
    .filter((device) => String(device?.kind || "").trim().toLowerCase() === "videoinput")
    .map((device, index) => ({
      deviceId: normId(device?.deviceId || ""),
      label: String(device?.label || "").trim() || `Camera ${index + 1}`,
      groupId: normId(device?.groupId || ""),
      kind: "videoinput",
      index,
    }))
    .filter((device) => !!device.deviceId);
}

