async function resolveGroupDmConversationIdByCallId(callId) {
  const cid = normId(callId || "");
  if (!cid) return "";
  const fromCache = normId(groupDmCallConversationByCallId.get(cid) || "");
  if (fromCache) return fromCache;
  if (!(await ensureGroupDmCallBackendAvailability())) return "";
  const { data, error } = await supabase
    .from("group_dm_call_sessions")
    .select("conversation_id")
    .eq("id", cid)
    .maybeSingle();
  if (error) {
    console.warn("resolve call conversation id failed", error);
    return "";
  }
  const convId = normId(data?.conversation_id || "");
  if (convId) groupDmCallConversationByCallId.set(cid, convId);
  return convId;
}

function onGlobalGroupDmCallSessionChanged(row, eventType = "update") {
  const convId = normId(row?.conversation_id || "");
  if (!convId) return;
  const status = String(row?.status || "").trim().toLowerCase();
  if (eventType === "insert" && status === "active") {
    try {
      window.dispatchEvent(new CustomEvent("call_started", {
        detail: {
          callId: normId(row?.id || ""),
          groupId: convId,
          group_call: true,
        },
      }));
    } catch (_) {}
  } else if (status === "ended" || eventType === "delete") {
    try {
      window.dispatchEvent(new CustomEvent("call_ended", {
        detail: {
          callId: normId(row?.id || ""),
          groupId: convId,
          group_call: true,
        },
      }));
    } catch (_) {}
  }
  scheduleGroupDmCallStateRefresh(convId, 80);
}

function onGlobalGroupDmCallParticipantChanged(row) {
  const callId = normId(row?.call_id || "");
  if (!callId) return;
  void (async () => {
    const convId = await resolveGroupDmConversationIdByCallId(callId);
    if (!convId) return;
    try {
      window.dispatchEvent(new CustomEvent("participants_update", {
        detail: {
          callId,
          groupId: convId,
          userId: normId(row?.user_id || ""),
          state: normalizeGroupDmJoinState(row?.join_state),
          group_call: true,
        },
      }));
    } catch (_) {}
    scheduleGroupDmCallStateRefresh(convId, 80);
  })();
}

function startGlobalGroupDmCallStateListener() {
  if (!state.user?.id) return;
  if (globalGroupDmCallRestartTimer) {
    clearTimeout(globalGroupDmCallRestartTimer);
    globalGroupDmCallRestartTimer = null;
  }
  if (globalGroupDmCallSessionChannel) {
    supabase.removeChannel(globalGroupDmCallSessionChannel);
    globalGroupDmCallSessionChannel = null;
  }
  if (globalGroupDmCallParticipantChannel) {
    supabase.removeChannel(globalGroupDmCallParticipantChannel);
    globalGroupDmCallParticipantChannel = null;
  }

  void ensureGroupDmCallBackendAvailability().then((enabled) => {
    if (!enabled) return;

    globalGroupDmCallSessionChannel = supabase
      .channel("global-group-dm-call-sessions:" + state.user.id)
      .on("postgres_changes", {
        event: "INSERT",
        schema: "public",
        table: "group_dm_call_sessions",
      }, (payload) => {
        onGlobalGroupDmCallSessionChanged(payload?.new || null, "insert");
      })
      .on("postgres_changes", {
        event: "UPDATE",
        schema: "public",
        table: "group_dm_call_sessions",
      }, (payload) => {
        onGlobalGroupDmCallSessionChanged(payload?.new || payload?.old || null, "update");
      })
      .on("postgres_changes", {
        event: "DELETE",
        schema: "public",
        table: "group_dm_call_sessions",
      }, (payload) => {
        onGlobalGroupDmCallSessionChanged(payload?.old || null, "delete");
      })
      .subscribe((status) => {
        if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
          if (globalGroupDmCallRestartTimer || !state.user?.id) return;
          globalGroupDmCallRestartTimer = setTimeout(() => {
            globalGroupDmCallRestartTimer = null;
            startGlobalGroupDmCallStateListener();
          }, 1200);
        }
      });

    globalGroupDmCallParticipantChannel = supabase
      .channel("global-group-dm-call-participants:" + state.user.id)
      .on("postgres_changes", {
        event: "INSERT",
        schema: "public",
        table: "group_dm_call_participants",
      }, (payload) => {
        onGlobalGroupDmCallParticipantChanged(payload?.new || null);
      })
      .on("postgres_changes", {
        event: "UPDATE",
        schema: "public",
        table: "group_dm_call_participants",
      }, (payload) => {
        onGlobalGroupDmCallParticipantChanged(payload?.new || payload?.old || null);
      })
      .on("postgres_changes", {
        event: "DELETE",
        schema: "public",
        table: "group_dm_call_participants",
      }, (payload) => {
        onGlobalGroupDmCallParticipantChanged(payload?.old || null);
      })
      .subscribe((status) => {
        if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
          if (globalGroupDmCallRestartTimer || !state.user?.id) return;
          globalGroupDmCallRestartTimer = setTimeout(() => {
            globalGroupDmCallRestartTimer = null;
            startGlobalGroupDmCallStateListener();
          }, 1200);
        }
      });
  });
}

let globalFriendRequestRefreshPending = false;
let globalFriendRequestRefreshPendingTrace = null;

function scheduleGlobalFriendRequestRefresh(delayMs = 150, { trace = null } = {}) {
  if (!state.user?.id) return;
  if (trace && !trace.ended) {
    globalFriendRequestRefreshPendingTrace = trace;
    relationshipTraceLog(trace, "globalFriendRequestRefresh:scheduled", { delayMs: Math.max(0, Number(delayMs) || 0) });
  }
  // If a refresh is already running, mark that another is needed and let the
  // finally-block re-schedule it, rather than silently dropping the event.
  if (globalFriendRequestRefreshInFlight) {
    globalFriendRequestRefreshPending = true;
    return;
  }
  if (globalFriendRequestRefreshTimer) clearTimeout(globalFriendRequestRefreshTimer);
  globalFriendRequestRefreshTimer = setTimeout(async () => {
    const refreshTrace = globalFriendRequestRefreshPendingTrace && !globalFriendRequestRefreshPendingTrace.ended
      ? globalFriendRequestRefreshPendingTrace
      : (trace && !trace.ended ? trace : null);
    globalFriendRequestRefreshPendingTrace = null;
    globalFriendRequestRefreshTimer = null;
    if (!state.user?.id) return;
    if (globalFriendRequestRefreshInFlight) {
      globalFriendRequestRefreshPending = true;
      if (refreshTrace && !refreshTrace.ended) globalFriendRequestRefreshPendingTrace = refreshTrace;
      return;
    }
    globalFriendRequestRefreshInFlight = true;
    globalFriendRequestRefreshPending = false;
    const prevReconcileTrace = relationshipReconcileTrace;
    if (refreshTrace && !refreshTrace.ended) {
      relationshipReconcileTrace = refreshTrace;
      relationshipTraceLog(refreshTrace, "reconcile:start");
    }
    try {
      await refresh({ lightweight: true });
    } catch (e) {
      console.warn("friend requests realtime refresh failed", e);
      if (refreshTrace && !refreshTrace.ended) {
        endRelationshipTrace(refreshTrace, "reconcile_error", {
          message: String(e?.message || e || "unknown reconcile error"),
        });
      }
    } finally {
      if (refreshTrace && !refreshTrace.ended) {
        endRelationshipTrace(refreshTrace, "reconciled");
      } else if (relationshipReconcileTrace === refreshTrace) {
        relationshipReconcileTrace = prevReconcileTrace || null;
      }
      globalFriendRequestRefreshInFlight = false;
      // If another event arrived while we were refreshing, do one more pass.
      if (globalFriendRequestRefreshPending && state.user?.id) {
        globalFriendRequestRefreshPending = false;
        scheduleGlobalFriendRequestRefresh(200);
      }
    }
  }, Math.max(0, Number(delayMs) || 0));
}

function onGlobalFriendRequestChanged(row, eventType = "UPDATE") {
  if (!state.user?.id) return;
  if (!row || typeof row !== "object") {
    scheduleGlobalFriendRequestRefresh(100);
    return;
  }
  const me = normId(state.user.id);
  const fromId = normId(row?.from_user_id || "");
  const toId = normId(row?.to_user_id || "");
  const requestId = normId(row?.request_id || row?.id || "");
  if (!fromId && !toId) {
    scheduleGlobalFriendRequestRefresh(100);
    return;
  }
  if (fromId !== me && toId !== me) return;
  const otherUserId = fromId === me ? toId : fromId;
  const optimisticProfile = getOptimisticRelationshipProfile({ userId: otherUserId });
  const affectedUsername = String(optimisticProfile?.username || row?.username || "").trim();
  const safeEventType = String(eventType || "UPDATE").trim().toUpperCase();
  const status = String(row?.status || (safeEventType === "DELETE" ? "" : "pending")).trim().toLowerCase();

  if (requestId && (safeEventType === "DELETE" || status === "rejected" || status === "cancelled" || status === "canceled")) {
    optimisticRemoveIncoming(requestId);
    optimisticRemoveOutgoing(requestId);
    renderRelationshipUiNow({
      rerenderPending: true,
      affectedUserId: otherUserId,
      affectedUsername,
    });
    if (otherUserId) {
      scheduleRelationshipRealtimeProfileHydration([otherUserId], {
        rerenderPending: true,
        affectedUserId: otherUserId,
        affectedUsername,
      });
    }
    scheduleGlobalFriendRequestRefresh(100);
    return;
  }

  if (status === "accepted") {
    if (requestId) {
      optimisticRemoveIncoming(requestId);
      optimisticRemoveOutgoing(requestId);
    }
    if (otherUserId) {
      upsertFriendRow({
        other_user_id: otherUserId,
        username: String(optimisticProfile?.username || row?.username || "").trim(),
        display_name: String(optimisticProfile?.display_name || row?.display_name || optimisticProfile?.username || row?.username || "User").trim() || "User",
        avatar_url: optimisticProfile?.avatar_url || row?.avatar_url || null,
        since: String(row?.updated_at || row?.created_at || new Date().toISOString()).trim(),
      });
    }
    renderRelationshipUiNow({
      rerenderFriends: true,
      rerenderPending: true,
      affectedUserId: otherUserId,
      affectedUsername,
    });
    queueLightweightDmListRenderFromState();
    if (otherUserId) {
      scheduleRelationshipRealtimeProfileHydration([otherUserId], {
        rerenderFriends: true,
        rerenderPending: true,
        affectedUserId: otherUserId,
        affectedUsername,
      });
    }
    scheduleGlobalFriendRequestRefresh(100);
    return;
  }

  if (toId === me) {
    upsertIncomingFriendRequestRow(row);
  } else if (fromId === me) {
    upsertOutgoingFriendRequestRow(row);
  }
  renderRelationshipUiNow({
    rerenderPending: true,
    affectedUserId: otherUserId,
    affectedUsername,
  });
  if (otherUserId) {
    scheduleRelationshipRealtimeProfileHydration([otherUserId], {
      rerenderPending: true,
      affectedUserId: otherUserId,
      affectedUsername,
    });
  }
  scheduleGlobalFriendRequestRefresh(100);
}

