function startGlobalFriendRequestListener() {
  if (!state.user?.id) return;
  if (globalFriendRequestRestartTimer) {
    clearTimeout(globalFriendRequestRestartTimer);
    globalFriendRequestRestartTimer = null;
  }
  if (globalFriendRequestChannel) {
    supabase.removeChannel(globalFriendRequestChannel);
    globalFriendRequestChannel = null;
  }

  // Use explicit per-user filters so Supabase delivers events reliably even when
  // the row only satisfies one half of the RLS OR-condition (from_user_id OR to_user_id).
  // We need two filter passes: one for rows where we are the sender, one for recipient.
  const userId = state.user.id;
  const handleFR = (eventType) => (payload) => {
    const row = payload?.new || payload?.old || null;
    onGlobalFriendRequestChanged(row, eventType);
  };
  globalFriendRequestChannel = supabase
    .channel("global-friend-requests:" + userId)
    // Rows where I sent the request
    .on("postgres_changes", { event: "INSERT", schema: "public", table: "friend_requests", filter: `from_user_id=eq.${userId}` }, handleFR("INSERT"))
    .on("postgres_changes", { event: "UPDATE", schema: "public", table: "friend_requests", filter: `from_user_id=eq.${userId}` }, handleFR("UPDATE"))
    .on("postgres_changes", { event: "DELETE", schema: "public", table: "friend_requests", filter: `from_user_id=eq.${userId}` }, handleFR("DELETE"))
    // Rows where I received the request
    .on("postgres_changes", { event: "INSERT", schema: "public", table: "friend_requests", filter: `to_user_id=eq.${userId}` }, handleFR("INSERT"))
    .on("postgres_changes", { event: "UPDATE", schema: "public", table: "friend_requests", filter: `to_user_id=eq.${userId}` }, handleFR("UPDATE"))
    .on("postgres_changes", { event: "DELETE", schema: "public", table: "friend_requests", filter: `to_user_id=eq.${userId}` }, handleFR("DELETE"))
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
        if (globalFriendRequestRestartTimer || !state.user?.id) return;
        globalFriendRequestRestartTimer = setTimeout(() => {
          globalFriendRequestRestartTimer = null;
          startGlobalFriendRequestListener();
        }, 1200);
      }
    });
}

function startGlobalMessageRequestListener() {
  if (!state.user?.id) return;
  if (globalMessageRequestRestartTimer) {
    clearTimeout(globalMessageRequestRestartTimer);
    globalMessageRequestRestartTimer = null;
  }
  if (globalMessageRequestChannel) {
    supabase.removeChannel(globalMessageRequestChannel);
    globalMessageRequestChannel = null;
  }

  const mrUserId = state.user.id;
  const handleMR = (eventType) => (payload) => {
    const row = payload?.new || payload?.old || null;
    onGlobalMessageRequestChanged(row, eventType);
  };
  globalMessageRequestChannel = supabase
    .channel("global-message-requests:" + mrUserId)
    .on("postgres_changes", { event: "INSERT", schema: "public", table: "message_requests", filter: `from_user_id=eq.${mrUserId}` }, handleMR("INSERT"))
    .on("postgres_changes", { event: "UPDATE", schema: "public", table: "message_requests", filter: `from_user_id=eq.${mrUserId}` }, handleMR("UPDATE"))
    .on("postgres_changes", { event: "DELETE", schema: "public", table: "message_requests", filter: `from_user_id=eq.${mrUserId}` }, handleMR("DELETE"))
    .on("postgres_changes", { event: "INSERT", schema: "public", table: "message_requests", filter: `to_user_id=eq.${mrUserId}` }, handleMR("INSERT"))
    .on("postgres_changes", { event: "UPDATE", schema: "public", table: "message_requests", filter: `to_user_id=eq.${mrUserId}` }, handleMR("UPDATE"))
    .on("postgres_changes", { event: "DELETE", schema: "public", table: "message_requests", filter: `to_user_id=eq.${mrUserId}` }, handleMR("DELETE"))
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
        if (globalMessageRequestRestartTimer || !state.user?.id) return;
        globalMessageRequestRestartTimer = setTimeout(() => {
          globalMessageRequestRestartTimer = null;
          startGlobalMessageRequestListener();
        }, 1200);
      }
    });
}

// â”€â”€â”€ USER BLOCKS REALTIME â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Blocks are the only relationship table with no realtime subscription.
// Without this, blocking/unblocking only takes effect after a full restart.
//
// What we handle:
//  INSERT â†’ A just blocked someone: remove them from A's friends/DM lists live
//  DELETE â†’ A just unblocked someone: re-render so they can appear again

function onGlobalModerationActionChanged(row, eventType = "UPDATE") {
  if (!state.user?.id) return;
  const actionId = normId(row?.id || "");
  if (eventType === "DELETE") {
    if (!actionId) return;
    moderationInboxReplyPendingActionIds.delete(actionId);
    removeModerationInboxAction(actionId, { render: true });
    scheduleModerationInboxRefresh(120, { render: true });
    return;
  }

  const action = normalizeOwnerModerationActionRow(row);
  if (!action?.id || action.targetUserId !== normId(state.user.id)) return;
  upsertModerationInboxAction(action, { render: true });
  if (!shouldModerationActionRequireResponse(action)) {
    moderationInboxReplyPendingActionIds.delete(action.id);
  }
  scheduleModerationInboxRefresh(120, { render: true });
  if (action.actionType === "ban") {
    void refreshMyModerationState({ enforceBan: true });
  } else if (action.actionType === "unban") {
    void refreshMyModerationState({ enforceBan: false });
  }
}

function startGlobalModerationActionListener() {
  if (!state.user?.id) return;
  if (globalModerationActionRestartTimer) {
    clearTimeout(globalModerationActionRestartTimer);
    globalModerationActionRestartTimer = null;
  }
  if (globalModerationActionChannel) {
    supabase.removeChannel(globalModerationActionChannel);
    globalModerationActionChannel = null;
  }

  const moderationUserId = state.user.id;
  const handleModeration = (eventType) => (payload) => {
    const row = payload?.new || payload?.old || null;
    onGlobalModerationActionChanged(row, eventType);
  };
  globalModerationActionChannel = supabase
    .channel("global-moderation-actions:" + moderationUserId)
    .on("postgres_changes", { event: "INSERT", schema: "public", table: "moderation_actions", filter: `target_user_id=eq.${moderationUserId}` }, handleModeration("INSERT"))
    .on("postgres_changes", { event: "UPDATE", schema: "public", table: "moderation_actions", filter: `target_user_id=eq.${moderationUserId}` }, handleModeration("UPDATE"))
    .on("postgres_changes", { event: "DELETE", schema: "public", table: "moderation_actions", filter: `target_user_id=eq.${moderationUserId}` }, handleModeration("DELETE"))
    .subscribe((status) => {
      if (status === "SUBSCRIBED") {
        scheduleModerationInboxRefresh(0, { render: true });
        return;
      }
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
        if (globalModerationActionRestartTimer || !state.user?.id) return;
        globalModerationActionRestartTimer = setTimeout(() => {
          globalModerationActionRestartTimer = null;
          startGlobalModerationActionListener();
        }, 1200);
      }
    });
}

function onGlobalUserBlockChanged(row, eventType) {
  if (!state.user?.id || !row || typeof row !== "object") return;
  const me = normId(state.user.id);
  const blocker = normId(row?.blocker_user_id || "");
  const blocked = normId(row?.blocked_user_id || "");

  // Only handle rows where WE are the blocker (RLS guarantees this anyway).
  if (blocker !== me) return;

  if (eventType === "INSERT" && blocked) {
    const optimisticProfile = getOptimisticRelationshipProfile({ userId: blocked });
    // Optimistically remove the blocked user from in-memory friend/DM state
    // so the UI feels instant. The full refresh settles any edge cases.
    state.friends = (state.friends || []).filter((f) => {
      const fid = normId(f?.other_user_id || f?.id || "");
      return fid !== blocked;
    });
    state.incoming = (state.incoming || []).filter((r) => normId(r?.from_user_id || "") !== blocked);
    state.outgoing = (state.outgoing || []).filter((r) => normId(r?.to_user_id || "") !== blocked);
    state.messageIncoming = (state.messageIncoming || []).filter((r) => normId(r?.from_user_id || "") !== blocked);
    state.messageOutgoing = (state.messageOutgoing || []).filter((r) => normId(r?.to_user_id || "") !== blocked);
    upsertBlockedUserRow({
      userId: blocked,
      username: String(optimisticProfile?.username || "").trim(),
      displayName: String(optimisticProfile?.display_name || optimisticProfile?.username || "User").trim() || "User",
      avatarUrl: String(optimisticProfile?.avatar_url || "").trim(),
      createdAt: String(row?.created_at || new Date().toISOString()).trim(),
    });
    renderFriends({ skipPresenceRefresh: true });
    renderPending();
    if (settingsActiveTab === "blocked-users") renderBlockedUsersSettingsRowsFromState();
  } else if (eventType === "DELETE" && blocked) {
    removeBlockedUserRowById(blocked);
    if (settingsActiveTab === "blocked-users") renderBlockedUsersSettingsRowsFromState();
  }

  // Always schedule a reconcile pass to settle any server-side edge cases.
  scheduleGlobalFriendRequestRefresh(200);
}

function startGlobalUserBlocksListener() {
  if (!state.user?.id) return;
  if (globalUserBlocksRestartTimer) {
    clearTimeout(globalUserBlocksRestartTimer);
    globalUserBlocksRestartTimer = null;
  }
  if (globalUserBlocksChannel) {
    supabase.removeChannel(globalUserBlocksChannel);
    globalUserBlocksChannel = null;
  }

  const ubUserId = state.user.id;
  globalUserBlocksChannel = supabase
    .channel("global-user-blocks:" + ubUserId)
    // Only listen for rows where I am the blocker (matches the RLS policy exactly).
    .on("postgres_changes", { event: "INSERT", schema: "public", table: "user_blocks", filter: `blocker_user_id=eq.${ubUserId}` }, (payload) => {
      onGlobalUserBlockChanged(payload?.new || null, "INSERT");
    })
    .on("postgres_changes", { event: "DELETE", schema: "public", table: "user_blocks", filter: `blocker_user_id=eq.${ubUserId}` }, (payload) => {
      onGlobalUserBlockChanged(payload?.old || null, "DELETE");
    })
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
        if (globalUserBlocksRestartTimer || !state.user?.id) return;
        globalUserBlocksRestartTimer = setTimeout(() => {
          globalUserBlocksRestartTimer = null;
          startGlobalUserBlocksListener();
        }, 1200);
      }
    });
}
// â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

async function runFriendRequestsSyncFallback() {
  if (friendRequestsSyncFallbackInFlight || !state.user?.id) return;
  if (typeof navigator !== "undefined" && navigator.onLine === false) return;
  friendRequestsSyncFallbackInFlight = true;
  try {
    const [friends, incoming, outgoing, messageIncoming, messageOutgoing] = await Promise.all([
      supabase.rpc("list_my_friends"),
      supabase.rpc("incoming_friend_requests"),
      supabase.rpc("outgoing_friend_requests"),
      supabase.rpc("incoming_message_requests"),
      supabase.rpc("outgoing_message_requests"),
    ]);
    const missingIncomingMessageRpc = isMissingRpcError(messageIncoming?.error);
    const missingOutgoingMessageRpc = isMissingRpcError(messageOutgoing?.error);
    if (friends.error || incoming.error || outgoing.error) return;
    if (messageIncoming.error && !missingIncomingMessageRpc) return;
    if (messageOutgoing.error && !missingOutgoingMessageRpc) return;

    const safeMessageIncoming = missingIncomingMessageRpc ? [] : (messageIncoming.data || []);
    const safeMessageOutgoing = missingOutgoingMessageRpc ? [] : (messageOutgoing.data || []);

    const nextFp = buildFriendCollectionsFingerprint(
      friends.data || [],
      incoming.data || [],
      outgoing.data || [],
      safeMessageIncoming,
      safeMessageOutgoing,
    );
    if (!nextFp || nextFp === friendRequestsSyncFingerprint) return;

    const contactsRes = await listMyMessageContactsRpc().catch(() => ({ data: [], error: null }));

    await applyFriendCollectionsData({
      friendsRows: friends.data || [],
      incomingRows: incoming.data || [],
      outgoingRows: outgoing.data || [],
      messageIncomingRows: safeMessageIncoming,
      messageOutgoingRows: safeMessageOutgoing,
      messageContactsRows: !contactsRes?.error && Array.isArray(contactsRes?.data) ? contactsRes.data : null,
      sourceFingerprint: nextFp,
      hydrateProfiles: false,
      syncFriendPreferences: false,
      syncGifFavorites: false,
      reloadDmList: true,
      skipGroupServerCollections: true,
      skipMessageContactsFetch: !contactsRes?.error,
      preserveDmActivityHydration: true,
    });
  } catch (_) {
    // best-effort fallback
  } finally {
    friendRequestsSyncFallbackInFlight = false;
  }
}

function isFallbackSyncVisible() {
  if (typeof document === "undefined") return true;
  return document.visibilityState !== "hidden";
}

function getFallbackSyncIntervalMs(kind) {
  const key = String(kind || "").trim();
  const map = isFallbackSyncVisible()
    ? FALLBACK_SYNC_VISIBLE_INTERVAL_MS
    : FALLBACK_SYNC_HIDDEN_INTERVAL_MS;
  const raw = Number(map?.[key]);
  if (!Number.isFinite(raw) || raw < 1000) return 15000;
  return raw;
}

function startFriendRequestsSyncFallback() {
  if (friendRequestsSyncFallbackTimer) clearTimeout(friendRequestsSyncFallbackTimer);
  const tick = async () => {
    await runFriendRequestsSyncFallback();
    friendRequestsSyncFallbackTimer = setTimeout(() => {
      void tick();
    }, getFallbackSyncIntervalMs("friendRequests"));
  };
  friendRequestsSyncFallbackTimer = setTimeout(() => {
    void tick();
  }, getFallbackSyncIntervalMs("friendRequests"));
  void runFriendRequestsSyncFallback();
}

async function onGlobalConversationMembershipInserted(row) {
  if (!row || !state.user?.id) return;
  const convId = normId(row.conversation_id);
  if (!convId) return;
  clearDmMessageConversationAccessCache(convId);
  serverConversationMemberIdsByConversationId.delete(convId);

  const activeServerCtx = getActiveServerContext();
  const activeServerId = normId(activeServerCtx?.serverId || "");
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (activeServerId && activeConvId && activeConvId === convId) {
    const activeMembers = serverMemberListByServerId.get(activeServerId) || [];
    await renderServerMembersRightPanel(activeServerCtx, activeMembers, {
      forceChannelMembers: true,
    }).catch(() => {});
  }

  const myId = normId(state.user.id);
  if (normId(row.user_id) !== myId) return;

  const serverMembershipCtx = await resolveServerConversationMembershipContext(convId, { allowLookup: true });
  if (serverMembershipCtx?.serverId) {
    const sid = normId(serverMembershipCtx.serverId || "");
    if (sid) {
      serverChannelListByServerId.delete(sid);
      serverChannelCategoryListByServerId.delete(sid);
      const activeServerId = normId(getActiveServerContext()?.serverId || "");
      if (activeServerId && activeServerId === sid) {
        await refreshServerConversationUi({ force: true }).catch(() => {});
      }
    }
    return;
  }

  const prevGroupIds = new Set(
    (state.groupDms || [])
      .map((g) => normId(g?.conversationId))
      .filter(Boolean)
  );

  invalidateGroupAndServerCollectionsCache();
  await loadDmList();

  const nextGroupIds = new Set(
    (state.groupDms || [])
      .map((g) => normId(g?.conversationId))
      .filter(Boolean)
  );

  const becameVisibleNow = nextGroupIds.has(convId) && !prevGroupIds.has(convId);
  if (becameVisibleNow && !isDmConversationActivelyViewed(convId)) {
    playUiCue("group_dm");
  }
}

async function onGlobalConversationMembershipDeleted(row) {
  if (!row || !state.user?.id) return;
  const convId = normId(row.conversation_id);
  if (!convId) return;
  clearDmMessageConversationAccessCache(convId);
  serverConversationMemberIdsByConversationId.delete(convId);

  const activeServerCtx = getActiveServerContext();
  const activeServerId = normId(activeServerCtx?.serverId || "");
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (activeServerId && activeConvId && activeConvId === convId) {
    const activeMembers = serverMemberListByServerId.get(activeServerId) || [];
    await renderServerMembersRightPanel(activeServerCtx, activeMembers, {
      forceChannelMembers: true,
    }).catch(() => {});
  }

  const myId = normId(state.user.id);
  if (normId(row.user_id) !== myId) return;

  const serverMembershipCtx = await resolveServerConversationMembershipContext(convId, { allowLookup: false });
  if (serverMembershipCtx?.serverId) {
    const sid = normId(serverMembershipCtx.serverId || "");
    const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
    const wasActiveDeletedChannel = activeConvId === convId;
    const activeServerVoiceTransport = !!(
      shouldUseServerVoiceLiveKitTransport(convId)
      && (
        normId(callConversationId || "") === convId
        || isServerVoiceTransportSessionActive(convId)
      )
    );
    const accessLossConfirmation = activeServerVoiceTransport
      ? await confirmServerConversationAccessLoss(convId, { force: true })
      : null;
    const shouldPreserveActiveServerVoiceContext = !!(
      activeServerVoiceTransport
      && accessLossConfirmation
      && !accessLossConfirmation.confirmedLost
    );
    dmUnreadByConversationId.delete(convId);
    persistDmUnreadConversationsToStorage();
    applyDmNotificationDecorations();

    if (normId(callConversationId || "") === convId && inCall) {
      if (shouldPreserveActiveServerVoiceContext) {
        logServerVoiceCleanupTrigger("cleanup.access_lost.skipped", {
          conversationId: convId,
          reasonCode: `cleanup.access_lost.${String(accessLossConfirmation?.reason || "not_confirmed").trim() || "not_confirmed"}`,
          triggeredBy: "onGlobalConversationMembershipDeleted",
          serverId: sid || null,
          channelId: normId(serverMembershipCtx?.channelId || "") || null,
          ...accessLossConfirmation,
          level: "warn",
        });
      } else {
        if (activeServerVoiceTransport) {
          logServerVoiceCleanupTrigger("cleanup.access_lost.confirmed", {
            conversationId: convId,
            reasonCode: `cleanup.access_lost.${String(accessLossConfirmation?.reason || "conversation_members_deleted").trim() || "conversation_members_deleted"}`,
            triggeredBy: "onGlobalConversationMembershipDeleted",
            serverId: sid || null,
            channelId: normId(serverMembershipCtx?.channelId || "") || null,
            ...accessLossConfirmation,
            level: "error",
          });
        }
        await hangupCurrentCallByUser("?? You no longer have access to this channel.");
      }
    }

    if (sid) {
      serverChannelListByServerId.delete(sid);
      serverChannelCategoryListByServerId.delete(sid);
      await refreshServerConversationUi({ force: true }).catch(() => {});
    }

    if (shouldPreserveActiveServerVoiceContext) return;
    if (!wasActiveDeletedChannel) return;

    const channels = sid
      ? await fetchServerChannelsForSidebar(sid, { force: true }).catch(() => [])
      : [];
    const nextChannel = (channels || []).find((ch) => normalizeConversationChannelType(ch?.channelType || "") !== "voice")
      || (channels || [])[0]
      || null;
    const serverRow = getServerRowById(sid);
    const serverName = normalizeConversationLabel(serverRow?.name || state.activeDm?.serverName || "Server", "Server");
    const serverIcon = String(serverRow?.iconUrl || "").trim();

    if (nextChannel?.conversationId) {
      const nextType = normalizeConversationChannelType(nextChannel?.channelType || "text");
      await openConversationById(nextChannel.conversationId, {
        kind: "server",
        isGroup: true,
        displayName: normalizeConversationLabel(
          nextChannel.name || (nextType === "voice" ? "voice-lounge" : "general"),
          nextType === "voice" ? "voice-lounge" : "general"
        ),
        serverId: sid,
        serverName,
        avatarUrl: serverIcon,
        channelType: nextType,
      });
      return;
    }

    activeDmId = null;
    state.activeDm = null;
    setMidMode("friends");
    syncDmActiveListHighlight();
    renderGroupsRail();
    setRightSidebarToServerMembers({ active: false });
    return;
  }

  dmUnreadByConversationId.delete(convId);
  persistDmUnreadConversationsToStorage();
  applyDmNotificationDecorations();

  if (normId(activeDmId || state.activeDm?.conversationId || "") === convId) {
    const backBtn = document.getElementById("btnBackToFriends");
    if (backBtn) {
      try { backBtn.click(); } catch (_) {}
    } else {
      activeDmId = null;
      state.activeDm = null;
      setMidMode("friends");
    }
  }

  invalidateGroupAndServerCollectionsCache();
  await loadDmList();
}

function startGlobalDmMembershipListener() {
  if (!state.user?.id) return;
  if (globalDmMembershipRestartTimer) {
    clearTimeout(globalDmMembershipRestartTimer);
    globalDmMembershipRestartTimer = null;
  }
  if (globalDmMembershipChannel) {
    supabase.removeChannel(globalDmMembershipChannel);
    globalDmMembershipChannel = null;
  }

  globalDmMembershipChannel = supabase
    .channel("global-dm-memberships:" + state.user.id)
    .on("postgres_changes", {
      event: "INSERT",
      schema: "public",
      table: "conversation_members",
    }, async (payload) => {
      try {
        await onGlobalConversationMembershipInserted(payload?.new || null);
      } catch (e) {
        console.warn("dm membership realtime insert failed", e);
      }
    })
    .on("postgres_changes", {
      event: "DELETE",
      schema: "public",
      table: "conversation_members",
    }, async (payload) => {
      try {
        await onGlobalConversationMembershipDeleted(payload?.old || null);
      } catch (e) {
        console.warn("dm membership realtime delete failed", e);
      }
    })
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
        if (globalDmMembershipRestartTimer || !state.user?.id) return;
        globalDmMembershipRestartTimer = setTimeout(() => {
          globalDmMembershipRestartTimer = null;
          startGlobalDmMembershipListener();
        }, 1200);
      }
    });
}

function buildDmCollectionsFingerprint() {
  const groupKeys = (state.groupDms || [])
    .map((g) => {
      const convId = normId(g?.conversationId);
      if (!convId) return "";
      const members = Number(g?.memberCount || 0);
      const ts = Number(g?.lastMessageAt || 0);
      const name = normalizeConversationLabel(g?.name || "Group DM", "Group DM");
      const avatar = String(g?.avatarUrl || "").trim();
      return `${convId}|${members}|${ts}|${name}|${avatar}`;
    })
    .filter(Boolean)
    .sort();

  const serverKeys = (state.servers || [])
    .map((s) => {
      const convId = normId(s?.defaultConversationId);
      if (!convId) return "";
      const sid = normId(s?.serverId || "");
      const members = Number(s?.memberCount || 0);
      const name = normalizeConversationLabel(s?.name || "Server", "Server");
      const icon = String(s?.iconUrl || "").trim();
      return `${sid}|${convId}|${members}|${name}|${icon}`;
    })
    .filter(Boolean)
    .sort();

  return `${groupKeys.join(",")}::${serverKeys.join(",")}`;
}

function buildActiveServerChannelSyncFingerprint(serverId, channels = [], categories = [], {
  activeConversationId = "",
  visibleMemberIds = [],
} = {}) {
  const sid = normId(serverId || "");
  if (!sid) return "";
  const channelKeys = (Array.isArray(channels) ? channels : [])
    .map((ch) => {
      const conversationId = normId(ch?.conversationId || "");
      if (!conversationId) return "";
      const channelId = normId(ch?.id || "");
      const categoryId = normId(ch?.categoryId || "");
      const channelType = normalizeConversationChannelType(ch?.channelType || "text");
      const name = normalizeConversationLabel(
        ch?.name || (channelType === "voice" ? "voice-lounge" : "general"),
        channelType === "voice" ? "voice-lounge" : "general"
      );
      return [
        channelId,
        conversationId,
        channelType,
        categoryId,
        Number(ch?.position || 0),
        Number(ch?.createdAt || 0),
        name,
        ch?.isPrivate ? "1" : "0",
      ].join("|");
    })
    .filter(Boolean)
    .sort();

  const categoryKeys = (Array.isArray(categories) ? categories : [])
    .map((cat) => {
      const categoryId = normId(cat?.id || "");
      if (!categoryId) return "";
      return [
        categoryId,
        Number(cat?.position || 0),
        Number(cat?.createdAt || 0),
        normalizeServerCategoryName(cat?.name || "Category"),
      ].join("|");
    })
    .filter(Boolean)
    .sort();

  const activeConvId = normId(activeConversationId || "");
  const memberKeys = normalizeUuidArray(visibleMemberIds || []).sort();
  return `${sid}::${activeConvId}::${memberKeys.join(",")}::${channelKeys.join(",")}::${categoryKeys.join(",")}`;
}

async function moveAwayFromUnavailableActiveServerChannel(serverId, channels = []) {
  const sid = normId(serverId || getActiveServerContext()?.serverId || "");
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (!sid || !activeConvId) return false;

  const visibleChannels = Array.isArray(channels) ? channels : [];
  const stillVisible = visibleChannels.some((ch) => normId(ch?.conversationId || "") === activeConvId);
  if (stillVisible) return false;

  dmUnreadByConversationId.delete(activeConvId);
  persistDmUnreadConversationsToStorage();
  applyDmNotificationDecorations();

  const activeServerVoiceTransport = !!(
    shouldUseServerVoiceLiveKitTransport(activeConvId)
    && (
      normId(callConversationId || "") === activeConvId
      || isServerVoiceTransportSessionActive(activeConvId)
    )
  );
  const accessLossConfirmation = activeServerVoiceTransport
    ? await confirmServerConversationAccessLoss(activeConvId, { force: true })
    : null;
  if (activeServerVoiceTransport && !accessLossConfirmation?.confirmedLost) {
    logServerVoiceCleanupTrigger("cleanup.access_lost.skipped", {
      conversationId: activeConvId,
      reasonCode: `cleanup.access_lost.${String(accessLossConfirmation?.reason || "visibility_not_confirmed").trim() || "visibility_not_confirmed"}`,
      triggeredBy: "moveAwayFromUnavailableActiveServerChannel",
      serverId: sid || null,
      visibleChannelCount: visibleChannels.length,
      ...accessLossConfirmation,
      level: "warn",
    });
    return false;
  }

  if (normId(callConversationId || "") === activeConvId && inCall) {
    if (activeServerVoiceTransport) {
      logServerVoiceCleanupTrigger("cleanup.access_lost.confirmed", {
        conversationId: activeConvId,
        reasonCode: `cleanup.access_lost.${String(accessLossConfirmation?.reason || "visibility_confirmed").trim() || "visibility_confirmed"}`,
        triggeredBy: "moveAwayFromUnavailableActiveServerChannel",
        serverId: sid || null,
        visibleChannelCount: visibleChannels.length,
        ...accessLossConfirmation,
        level: "error",
      });
    }
    await hangupCurrentCallByUser("?? You no longer have access to this channel.");
  }

  const nextChannel = visibleChannels.find((ch) => normalizeConversationChannelType(ch?.channelType || "") !== "voice")
    || visibleChannels[0]
    || null;
  const serverRow = getServerRowById(sid);
  const serverName = normalizeConversationLabel(serverRow?.name || state.activeDm?.serverName || "Server", "Server");
  const serverIcon = String(serverRow?.iconUrl || "").trim();

  if (nextChannel?.conversationId) {
    const nextType = normalizeConversationChannelType(nextChannel?.channelType || "text");
    await openConversationById(nextChannel.conversationId, {
      kind: "server",
      isGroup: true,
      displayName: normalizeConversationLabel(
        nextChannel.name || (nextType === "voice" ? "voice-lounge" : "general"),
        nextType === "voice" ? "voice-lounge" : "general"
      ),
      serverId: sid,
      serverName,
      avatarUrl: serverIcon,
      channelType: nextType,
    });
    return true;
  }

  activeDmId = null;
  state.activeDm = null;
  setMidMode("friends");
  syncDmActiveListHighlight();
  renderGroupsRail();
  setRightSidebarToServerMembers({ active: false });
  return true;
}

function syncActiveConversationHeaderFromMeta() {
  const convId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (!convId) return;
  const cachedMeta = getConversationMeta(convId) || {};
  const activeKind = String(state.activeDm?.kind || cachedMeta?.kind || "").trim().toLowerCase();
  if (activeKind !== "group" && activeKind !== "server") return;

  const fallback = activeKind === "server" ? "Server" : "Group DM";
  const nextTitle = normalizeConversationLabel(
    cachedMeta?.displayName || state.activeDm?.displayName || fallback,
    fallback
  );

  state.activeDm = {
    ...(state.activeDm || {}),
    displayName: nextTitle,
    avatarUrl: String(cachedMeta?.avatarUrl || state.activeDm?.avatarUrl || "").trim(),
    kind: activeKind,
    isGroup: true,
  };
  setConversationMeta(convId, {
    displayName: nextTitle,
    avatarUrl: state.activeDm?.avatarUrl || "",
    kind: activeKind,
    isGroup: true,
  });

  const titleEl = document.getElementById("dmTitle");
  if (titleEl && titleEl.textContent !== nextTitle) {
    titleEl.textContent = nextTitle;
    applyDmTitleNameStyle();
  }
}

async function runDmCollectionsSyncFallback() {
  if (dmCollectionsSyncFallbackInFlight || !state.user?.id) return;
  if (typeof navigator !== "undefined" && navigator.onLine === false) return;
  dmCollectionsSyncFallbackInFlight = true;
  try {
    const prevFp = dmCollectionsSyncFingerprint || buildDmCollectionsFingerprint();
    await loadGroupAndServerCollections({ force: false, hydrateGroupMetadata: false });
    const nextFp = buildDmCollectionsFingerprint();
    dmCollectionsSyncFingerprint = nextFp;
    if (nextFp === prevFp) return;
    await loadDmList();
    syncActiveConversationHeaderFromMeta();
  } catch (_) {
    // best-effort fallback
  } finally {
    dmCollectionsSyncFallbackInFlight = false;
  }
}

async function runActiveServerChannelSyncFallback() {
  if (serverActiveChannelSyncFallbackInFlight || !state.user?.id) return;
  if (typeof navigator !== "undefined" && navigator.onLine === false) return;

  const serverCtx = getActiveServerContext();
  const sid = normId(serverCtx?.serverId || "");
  if (!sid) {
    serverActiveChannelSyncServerId = "";
    serverActiveChannelSyncFingerprint = "";
    return;
  }

  serverActiveChannelSyncFallbackInFlight = true;
  try {
    const [channels, categories] = await Promise.all([
      fetchServerChannelsForSidebar(sid, { force: true }).catch(() => []),
      fetchServerChannelCategoriesForSidebar(sid, { force: true }).catch(() => []),
    ]);
    const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
    const visibleMemberIds = activeConvId
      ? await fetchServerConversationMemberIds(activeConvId, { force: false }).catch(() => [])
      : [];
    const nextFingerprint = buildActiveServerChannelSyncFingerprint(sid, channels, categories, {
      activeConversationId: activeConvId,
      visibleMemberIds,
    });
    const prevServerId = serverActiveChannelSyncServerId;
    const prevFingerprint = serverActiveChannelSyncFingerprint;
    serverActiveChannelSyncServerId = sid;
    serverActiveChannelSyncFingerprint = nextFingerprint;

    const activeStillVisible = !activeConvId
      || (channels || []).some((ch) => normId(ch?.conversationId || "") === activeConvId);

    if (prevServerId === sid && prevFingerprint === nextFingerprint && activeStillVisible) return;

    await refreshServerConversationUi({ force: true }).catch(() => {});
    if (!activeStillVisible) {
      await moveAwayFromUnavailableActiveServerChannel(sid, channels);
    }
  } finally {
    serverActiveChannelSyncFallbackInFlight = false;
  }
}

function startDmCollectionsSyncFallback() {
  if (dmCollectionsSyncFallbackTimer) clearTimeout(dmCollectionsSyncFallbackTimer);
  const tick = async () => {
    await runDmCollectionsSyncFallback();
    dmCollectionsSyncFallbackTimer = setTimeout(() => {
      void tick();
    }, getFallbackSyncIntervalMs("dmCollections"));
  };
  dmCollectionsSyncFallbackTimer = setTimeout(() => {
    void tick();
  }, getFallbackSyncIntervalMs("dmCollections"));
  void runDmCollectionsSyncFallback();
}

function startActiveServerChannelSyncFallback() {
  if (serverActiveChannelSyncFallbackTimer) clearTimeout(serverActiveChannelSyncFallbackTimer);
  const tick = async () => {
    await runActiveServerChannelSyncFallback();
    serverActiveChannelSyncFallbackTimer = setTimeout(() => {
      void tick();
    }, getFallbackSyncIntervalMs("activeServerChannels"));
  };
  serverActiveChannelSyncFallbackTimer = setTimeout(() => {
    void tick();
  }, getFallbackSyncIntervalMs("activeServerChannels"));
  void runActiveServerChannelSyncFallback();
}

async function onGlobalConversationUpdated(row) {
  if (!row || !state.user?.id) return;
  const convId = normId(row?.id || row?.conversation_id || "");
  if (!convId) return;

  const cachedMeta = getConversationMeta(convId) || {};
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  const activeMeta = activeConvId === convId ? (state.activeDm || {}) : {};
  const kind = String(
    row?.kind
    || activeMeta?.kind
    || cachedMeta?.kind
    || ""
  ).trim().toLowerCase();
  const looksLikeDirectDmUpdate = kind === "dm" || (
    dmFeatureCaps.dmPrivacyState
    && (
      Object.prototype.hasOwnProperty.call(row, "dm_privacy_state")
      || Object.prototype.hasOwnProperty.call(row, "dm_privacy_request_nonce")
      || Object.prototype.hasOwnProperty.call(row, "dm_privacy_disable_request_nonce")
    )
    && (isDirectDmConversationKind(activeMeta?.kind || "") || isDirectDmConversationKind(cachedMeta?.kind || ""))
  );

  if (looksLikeDirectDmUpdate && DM_PRIVATE_RUNTIME_ENABLED) {
    if (dmFeatureCaps.dmPrivacyState) {
      let privacyMeta = applyConversationDmPrivacyMeta(convId, {
        ...cachedMeta,
        ...activeMeta,
        ...(row && typeof row === "object" ? row : {}),
        kind: "dm",
      });
      const isActiveDirectDm = (
        activeConvId === convId
        && isDirectDmConversationKind(state.activeDm?.kind || "")
      );
      if (isActiveDirectDm) {
        privacyMeta = await refreshDmPrivacyMetaFromServer(convId, { rerender: false });
        if (privacyMeta.dmPrivacyState === "private_active") {
          void ensureDmE2eeBootstrapStarted();
        }
        renderDmPrivacyUi();
        applyDmComposerEditUi();
      }
    }
    return;
  }
  if (kind && kind !== "group") return;

  const isTrackedConversation = (state.groupDms || []).some((g) => normId(g?.conversationId) === convId)
    || (state.servers || []).some((s) => normId(s?.defaultConversationId) === convId)
    || normId(activeDmId || state.activeDm?.conversationId || "") === convId;
  if (!isTrackedConversation) return;

  await runDmCollectionsSyncFallback();
  syncActiveConversationHeaderFromMeta();
}

function startGlobalConversationListener() {
  if (!state.user?.id) return;
  if (globalConversationRestartTimer) {
    clearTimeout(globalConversationRestartTimer);
    globalConversationRestartTimer = null;
  }
  if (globalConversationChannel) {
    supabase.removeChannel(globalConversationChannel);
    globalConversationChannel = null;
  }

  globalConversationChannel = supabase
    .channel("global-conversations:" + state.user.id)
    .on("postgres_changes", {
      event: "UPDATE",
      schema: "public",
      table: "conversations",
    }, async (payload) => {
      try {
        await onGlobalConversationUpdated(payload?.new || null);
      } catch (e) {
        console.warn("conversations realtime update failed", e);
      }
    })
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
        if (globalConversationRestartTimer || !state.user?.id) return;
        globalConversationRestartTimer = setTimeout(() => {
          globalConversationRestartTimer = null;
          startGlobalConversationListener();
        }, 1200);
      }
    });
}

async function onGlobalServerChannelTableChanged(row) {
  if (!row || !state.user?.id) return;
  const serverId = normId(row?.server_id || "");
  if (!serverId) return;

  const isTrackedServer = (state.servers || []).some((s) => normId(s?.serverId || "") === serverId);
  if (!isTrackedServer) return;

  serverChannelListByServerId.delete(serverId);
  serverChannelCategoryListByServerId.delete(serverId);
  const activeCtx = getActiveServerContext();
  const activeServerId = normId(activeCtx?.serverId || "");
  if (!activeServerId || activeServerId !== serverId) return;

  await refreshServerConversationUi({ force: true }).catch(() => {});
}

async function flushServerRoleRealtimeRefresh(serverId) {
  const sid = normId(serverId || "");
  if (!sid || !state.user?.id) return;
  const isTrackedServer = (state.servers || []).some((s) => normId(s?.serverId || "") === sid);
  if (!isTrackedServer) return;

  serverRoleListByServerId.delete(sid);
  serverRoleMemberMapByServerId.delete(sid);
  serverMemberListByServerId.delete(sid);

  const activeCtx = getActiveServerContext();
  const activeServerId = normId(activeCtx?.serverId || "");
  if (activeServerId && activeServerId === sid) {
    await refreshServerConversationUi({ force: true }).catch(() => {});
  }

  const settingsModal = document.getElementById("serverSettingsModal");
  const settingsOpen = !!(settingsModal && !settingsModal.classList.contains("hidden"));
  if (settingsOpen && normId(serverSettingsServerId || "") === sid) {
    await loadServerSettingsRolesForModal(sid, { force: true }).catch(() => {});
  }
}

function queueServerRoleRealtimeRefresh(serverId) {
  const sid = normId(serverId || "");
  if (!sid) return;
  if (serverRoleRealtimeRefreshTimersByServerId.has(sid)) return;
  const timer = setTimeout(async () => {
    serverRoleRealtimeRefreshTimersByServerId.delete(sid);
    await flushServerRoleRealtimeRefresh(sid);
  }, 120);
  serverRoleRealtimeRefreshTimersByServerId.set(sid, timer);
}

