function buildProfileRealtimeFingerprint(profilePatch) {
  const uid = normId(profilePatch?.id || "");
  if (!uid) return "";
  const banner = normalizeBannerUrl(
    profilePatch?.banner_url ||
    profilePatch?.theme_settings?.banner_url ||
    ""
  );
  const status = readPresenceStatusValue(profilePatch?.status)
    || readPresenceStatusValue(profilePatch?.theme_settings?.presence_status)
    || "";
  const payload = [
    uid,
    String(profilePatch?.username || "").trim(),
    String(profilePatch?.display_name || "").trim(),
    normalizePronouns(profilePatch?.pronouns || ""),
    String(profilePatch?.avatar_url || "").trim(),
    String(profilePatch?.bio || "").trim(),
    normalizeNameColor(profilePatch?.name_color || ""),
    normalizeCallTileColor(profilePatch?.call_tile_color || ""),
    banner,
    status,
  ];
  return payload.join("|");
}

function collectProfileSyncTargetIds() {
  const ids = new Set();
  const pushId = (v) => {
    const id = normId(v);
    if (id) ids.add(id);
  };

  pushId(state.user?.id);
  pushId(callOtherUserId);
  pushId(state.activeDm?.otherUserId || state.activeDm?.other_user_id);
  pushId(userCardCurrentUserId);
  normalizeUuidArray(groupCallActiveMemberIds).forEach(pushId);
  (state.friends || []).forEach((f) => pushId(f?.other_user_id || f?.id));
  (state.incoming || []).forEach((r) => pushId(r?.other_user_id || r?.user_id || r?.id));
  (state.outgoing || []).forEach((r) => pushId(r?.other_user_id || r?.user_id || r?.id));
  (state.messageIncoming || []).forEach((r) => pushId(r?.other_user_id || r?.user_id || r?.id));
  (state.messageOutgoing || []).forEach((r) => pushId(r?.other_user_id || r?.user_id || r?.id));
  (state.dmContacts || []).forEach((r) => pushId(r?.other_user_id || r?.id));

  return Array.from(ids);
}

function isProfileRealtimeRelevant(userId) {
  const uid = normId(userId);
  if (!uid) return false;
  const meId = normId(state.user?.id || "");
  if (uid === meId) return true;
  if (uid === normId(callOtherUserId || "")) return true;
  if (uid === normId(userCardCurrentUserId || "")) return true;
  if (uid === normId(state.activeDm?.otherUserId || state.activeDm?.other_user_id || "")) return true;
  if ((state.friends || []).some((f) => normId(f?.other_user_id || f?.id) === uid)) return true;
  if ((state.incoming || []).some((r) => normId(r?.other_user_id || r?.user_id || r?.id) === uid)) return true;
  if ((state.outgoing || []).some((r) => normId(r?.other_user_id || r?.user_id || r?.id) === uid)) return true;
  if ((state.messageIncoming || []).some((r) => normId(r?.other_user_id || r?.user_id || r?.id) === uid)) return true;
  if ((state.messageOutgoing || []).some((r) => normId(r?.other_user_id || r?.user_id || r?.id) === uid)) return true;
  if ((state.dmContacts || []).some((r) => normId(r?.other_user_id || r?.id) === uid)) return true;
  return false;
}

function mergeRealtimeProfileIntoRow(row, profilePatch) {
  if (!row || typeof row !== "object") return row;
  const next = { ...row };
  if (typeof profilePatch.username !== "undefined") next.username = profilePatch.username;
  if (typeof profilePatch.display_name !== "undefined") next.display_name = profilePatch.display_name;
  if (typeof profilePatch.pronouns !== "undefined") next.pronouns = normalizePronouns(profilePatch.pronouns);
  if (typeof profilePatch.avatar_url !== "undefined") next.avatar_url = profilePatch.avatar_url || null;
  if (typeof profilePatch.status !== "undefined") next.status = normalizePresenceStatus(profilePatch.status);
  if (typeof profilePatch.name_color !== "undefined") next.name_color = normalizeNameColor(profilePatch.name_color);
  if (typeof profilePatch.call_tile_color !== "undefined") next.call_tile_color = normalizeCallTileColor(profilePatch.call_tile_color);
  if (typeof profilePatch.banner_url !== "undefined" || typeof profilePatch.theme_settings !== "undefined") {
    const nextBanner = normalizeBannerUrl(
      profilePatch.banner_url ||
      profilePatch.theme_settings?.banner_url ||
      next.banner_url ||
      ""
    );
    next.banner_url = nextBanner;
  }
  return next;
}

function applyRealtimeProfileUpdate(profileRow) {
  const uid = normId(profileRow?.id);
  if (!uid) return;
  if (!isProfileRealtimeRelevant(uid)) return;
  const patchedStatus = readPresenceStatusValue(profileRow?.status)
    || readPresenceStatusValue(profileRow?.theme_settings?.presence_status);

  const profilePatch = {
    id: uid,
    username: profileRow?.username,
    display_name: profileRow?.display_name,
    pronouns: profileRow?.pronouns,
    bio: profileRow?.bio,
    avatar_url: profileRow?.avatar_url,
    name_color: profileRow?.name_color,
    call_tile_color: profileRow?.call_tile_color,
    banner_url: profileRow?.banner_url,
    theme_settings: profileRow?.theme_settings,
    ...(patchedStatus ? { status: patchedStatus } : {}),
  };
  const fingerprint = buildProfileRealtimeFingerprint(profilePatch);
  if (fingerprint && profileRealtimeFingerprints.get(uid) === fingerprint) return;
  if (fingerprint) profileRealtimeFingerprints.set(uid, fingerprint);
  cacheProfileRow(profilePatch);

  state.friends = (state.friends || []).map((f) => {
    if (normId(f?.other_user_id || f?.id) !== uid) return f;
    return mergeRealtimeProfileIntoRow(f, profilePatch);
  });
  state.incoming = (state.incoming || []).map((r) => {
    if (normId(r?.other_user_id || r?.user_id || r?.id) !== uid) return r;
    return mergeRealtimeProfileIntoRow(r, profilePatch);
  });
  state.outgoing = (state.outgoing || []).map((r) => {
    if (normId(r?.other_user_id || r?.user_id || r?.id) !== uid) return r;
    return mergeRealtimeProfileIntoRow(r, profilePatch);
  });
  state.messageIncoming = (state.messageIncoming || []).map((r) => {
    if (normId(r?.other_user_id || r?.user_id || r?.id) !== uid) return r;
    return mergeRealtimeProfileIntoRow(r, profilePatch);
  });
  state.messageOutgoing = (state.messageOutgoing || []).map((r) => {
    if (normId(r?.other_user_id || r?.user_id || r?.id) !== uid) return r;
    return mergeRealtimeProfileIntoRow(r, profilePatch);
  });
  state.dmContacts = (state.dmContacts || []).map((r) => {
    if (normId(r?.other_user_id || r?.id) !== uid) return r;
    return mergeRealtimeProfileIntoRow(r, profilePatch);
  });

  const meId = normId(state.user?.id || "");
  if (uid === meId) {
    const currentMe = getCurrentMeProfileSnapshot();
    const nextMeStatus = resolveAccountPresenceStatus(
      {
        ...currentMe,
        ...mergeDefinedObjectFields({}, profilePatch),
      },
      currentMe?.status || getStoredMyStatus() || getMyStatus()
    );
    state.me = mergeDefinedObjectFields(currentMe, profilePatch);
    state.me.name_color = normalizeNameColor(profilePatch.name_color ?? currentMe?.name_color);
    state.me.call_tile_color = normalizeCallTileColor(profilePatch.call_tile_color ?? currentMe?.call_tile_color);
    state.me.status = nextMeStatus;
    setMyStatus(nextMeStatus);
    cacheProfileRow(state.me);
    applyMeHeaderNameStyle();
    if (document.getElementById("meName")) {
      document.getElementById("meName").textContent = state.me.display_name || state.me.username || "...";
    }
    if (document.getElementById("meTag")) {
      document.getElementById("meTag").textContent = state.me.username ? `@${state.me.username}` : "@...";
    }
    applyMeHeaderBannerStyle();
    const settingsPronouns = document.getElementById("pronouns");
    if (settingsPronouns) settingsPronouns.value = normalizePronouns(state.me.pronouns || "");
    const settingsPronounsLine = document.getElementById("pronounsLine");
    if (settingsPronounsLine) {
      const pronounsValue = normalizePronouns(state.me.pronouns || "");
      settingsPronounsLine.textContent = pronounsValue;
      settingsPronounsLine.hidden = !pronounsValue;
    }
    if (typeof profilePatch.avatar_url !== "undefined") {
      setAvatar(document.getElementById("meAvatar"), getCurrentMeAvatarUrl(), state.user?.id || "");
    }
    if (typeof profilePatch.theme_settings !== "undefined") {
      applyAppearanceSettings(loadAppearanceSettings({ force: true }));
      syncNotificationBehaviorSettingsUi(state.me.theme_settings);
      applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
    }
    applyMeStatusDot(nextMeStatus);
    try { presence?.setStatus?.(nextMeStatus); } catch (_) {}
  }

  const activePeerId = normId(state.activeDm?.otherUserId || state.activeDm?.other_user_id || "");
  if (activePeerId && uid === activePeerId) {
    state.activeDm = {
      ...(state.activeDm || {}),
      ...(typeof profilePatch.username !== "undefined"
        ? { username: profilePatch.username || state.activeDm?.username || "" }
        : {}),
      ...(typeof profilePatch.display_name !== "undefined"
        ? { displayName: profilePatch.display_name || profilePatch.username || state.activeDm?.displayName || state.activeDm?.username || "" }
        : {}),
      ...(typeof profilePatch.avatar_url !== "undefined"
        ? { avatarUrl: profilePatch.avatar_url || null }
        : {}),
      ...(typeof profilePatch.name_color !== "undefined"
        ? { name_color: normalizeNameColor(profilePatch.name_color) }
        : {}),
      ...(typeof profilePatch.call_tile_color !== "undefined"
        ? { call_tile_color: normalizeCallTileColor(profilePatch.call_tile_color) }
        : {}),
      ...(typeof profilePatch.banner_url !== "undefined" || typeof profilePatch.theme_settings !== "undefined"
        ? { banner_url: normalizeBannerUrl(profilePatch.banner_url || profilePatch.theme_settings?.banner_url || state.activeDm?.banner_url || "") }
        : {}),
    };
  }

  renderFriends({ skipPresenceRefresh: true });
  renderPending();
  updatePresenceRender();
  if (activeDmId) {
    applyDmTitleNameStyle();
    refreshDmProfilePanel();
  }
  if (userCardCurrentUserId && normId(userCardCurrentUserId) === uid) refreshOpenUserCard();
  void loadDmList().catch(() => {});
}

async function runProfileSyncFallback() {
  if (profileSyncFallbackInFlight || !state.user?.id) return;
  if (typeof navigator !== "undefined" && navigator.onLine === false) return;
  const targetIds = collectProfileSyncTargetIds();
  if (!targetIds.length) return;

  profileSyncFallbackInFlight = true;
  try {
    const includeBio = !!(dmProfilePanelOpen || userCardCurrentUserId);
    const now = Date.now();
    const forceRefresh = (
      !profileFallbackLastForceSyncAt
      || (now - profileFallbackLastForceSyncAt) >= PROFILE_FALLBACK_FORCE_REFRESH_MS
    );
    if (forceRefresh) profileFallbackLastForceSyncAt = now;
    const rows = await fetchProfilesByIds(targetIds, { includeBio, force: forceRefresh });
    (rows || []).forEach((row) => applyRealtimeProfileUpdate(row));
  } catch (_) {
    // fallback sync is best-effort
  } finally {
    profileSyncFallbackInFlight = false;
  }
}

function startProfileSyncFallback() {
  if (profileSyncFallbackTimer) clearTimeout(profileSyncFallbackTimer);
  const tick = async () => {
    await runProfileSyncFallback();
    profileSyncFallbackTimer = setTimeout(() => {
      void tick();
    }, getFallbackSyncIntervalMs("profiles"));
  };
  profileSyncFallbackTimer = setTimeout(() => {
    void tick();
  }, getFallbackSyncIntervalMs("profiles"));
  void runProfileSyncFallback();
}

function startGlobalProfileListener() {
  if (!state.user?.id) return;
  if (globalProfileRestartTimer) {
    clearTimeout(globalProfileRestartTimer);
    globalProfileRestartTimer = null;
  }
  if (globalProfileChannel) {
    supabase.removeChannel(globalProfileChannel);
    globalProfileChannel = null;
  }

  globalProfileChannel = supabase
    .channel("global-profiles:" + state.user.id)
    .on("postgres_changes", {
      event: "UPDATE",
      schema: "public",
      table: "profiles",
    }, async (payload) => {
      applyRealtimeProfileUpdate(payload?.new || null);
    })
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
        if (globalProfileRestartTimer || !state.user?.id) return;
        globalProfileRestartTimer = setTimeout(() => {
          globalProfileRestartTimer = null;
          startGlobalProfileListener();
        }, 1200);
      }
    });
}

async function getConversationKindForNotificationRouting(conversationId) {
  const convId = normId(conversationId);
  if (!convId) return "";

  let kind = String(getConversationMeta(convId)?.kind || "").trim().toLowerCase();
  if (!kind && normId(state.activeDm?.conversationId || activeDmId || "") === convId) {
    kind = String(state.activeDm?.kind || "").trim().toLowerCase();
  }
  if (!kind && (state.groupDms || []).some((g) => normId(g?.conversationId) === convId)) {
    kind = "group";
  }
  if (!kind && (state.servers || []).some((s) => normId(s?.defaultConversationId) === convId)) {
    kind = "server";
  }
  if (kind === "dm" || kind === "group" || kind === "server") return kind;

  try {
    const { data: convRow, error: convErr } = await supabase
      .from("conversations")
      .select("kind")
      .eq("id", convId)
      .maybeSingle();
    if (!convErr && convRow) {
      let dbKind = String(convRow?.kind || "").trim().toLowerCase();
      if (dbKind === "group") {
        try {
          const { data: scRows, error: scErr } = await supabase
            .from("server_channels")
            .select("conversation_id")
            .eq("conversation_id", convId)
            .limit(1);
          if (!scErr && Array.isArray(scRows) && scRows.length > 0) dbKind = "server";
        } catch (_) {}
      }
      if (dbKind === "dm" || dbKind === "group" || dbKind === "server") {
        setConversationMeta(convId, { kind: dbKind, isGroup: dbKind !== "dm" });
        return dbKind;
      }
    }
  } catch (_) {}

  return "";
}

function clearDmMessageConversationAccessCache(conversationId = null) {
  const convId = normId(conversationId || "");
  if (!convId) {
    dmMessageConversationAccessCacheByConversation.clear();
    dmMessageConversationAccessLookupInFlightByConversation.clear();
    return;
  }
  dmMessageConversationAccessCacheByConversation.delete(convId);
  dmMessageConversationAccessLookupInFlightByConversation.delete(convId);
}

function hasLocalDmMessageConversationAccessHint(conversationId) {
  const convId = normId(conversationId || "");
  const meId = normId(state.user?.id || "");
  if (!convId || !meId) return false;

  if (normId(activeDmId || state.activeDm?.conversationId || "") === convId) return true;
  if ((state.dmContacts || []).some((row) => normId(row?.conversation_id || row?.conversationId || "") === convId)) return true;
  if ((state.groupDms || []).some((row) => normId(row?.conversationId || "") === convId)) return true;

  const meta = getConversationMeta(convId) || {};
  const metaMemberIds = normalizeUuidArray(meta?.memberIds);
  if (metaMemberIds.includes(meId)) return true;

  const serverCtx = findServerChannelContextByConversationId(convId);
  const serverId = normId(serverCtx?.serverId || meta?.serverId || "");
  if (!serverId) return false;
  const serverMembers = Array.isArray(serverMemberListByServerId.get(serverId))
    ? (serverMemberListByServerId.get(serverId) || [])
    : [];
  return serverMembers.some((row) => normId(row?.userId || row?.id || "") === meId);
}

async function canCurrentUserAccessMessageConversation(conversationId, { force = false } = {}) {
  const convId = normId(conversationId || "");
  const meId = normId(state.user?.id || "");
  if (!convId || !meId) return false;

  if (hasLocalDmMessageConversationAccessHint(convId)) {
    dmMessageConversationAccessCacheByConversation.set(convId, {
      allowed: true,
      checkedAt: Date.now(),
    });
    return true;
  }

  if (!force) {
    const cached = dmMessageConversationAccessCacheByConversation.get(convId) || null;
    if (cached) {
      const age = Date.now() - Number(cached.checkedAt || 0);
      if (age >= 0 && age <= DM_MESSAGE_CONVERSATION_ACCESS_CACHE_MS) {
        return !!cached.allowed;
      }
    }
  }

  const inFlight = dmMessageConversationAccessLookupInFlightByConversation.get(convId);
  if (inFlight) return inFlight;

  const lookupPromise = (async () => {
    let allowed = false;

    try {
      const { data: membershipRow, error: membershipError } = await supabase
        .from("conversation_members")
        .select("user_id")
        .eq("conversation_id", convId)
        .eq("user_id", meId)
        .maybeSingle();

      if (!membershipError && normId(membershipRow?.user_id || "") === meId) {
        allowed = true;
      }

      if (!allowed) {
        const { data: serverChannelRow, error: serverChannelError } = await supabase
          .from("server_channels")
          .select("server_id")
          .eq("conversation_id", convId)
          .maybeSingle();

        const serverId = serverChannelError ? "" : normId(serverChannelRow?.server_id || "");
        if (serverId) {
          const { data: serverMemberRow, error: serverMemberError } = await supabase
            .from("server_members")
            .select("user_id")
            .eq("server_id", serverId)
            .eq("user_id", meId)
            .maybeSingle();
          if (!serverMemberError && normId(serverMemberRow?.user_id || "") === meId) {
            allowed = true;
          }
        }
      }
    } catch (_) {
      allowed = false;
    }

    dmMessageConversationAccessCacheByConversation.set(convId, {
      allowed: !!allowed,
      checkedAt: Date.now(),
    });
    return !!allowed;
  })();

  dmMessageConversationAccessLookupInFlightByConversation.set(convId, lookupPromise);
  try {
    return await lookupPromise;
  } finally {
    dmMessageConversationAccessLookupInFlightByConversation.delete(convId);
  }
}

function cacheResolvedConversationPeerUserId(conversationId, userId = "") {
  const convId = normId(conversationId || "");
  const uid = normId(userId || "");
  if (!convId) return;
  if (!uid) {
    dmConversationPeerCache.delete(convId);
    return;
  }
  dmConversationPeerCache.set(convId, uid);
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  if (activeConvId && activeConvId === convId) {
    state.activeDm = {
      ...(state.activeDm || {}),
      otherUserId: uid,
      other_user_id: uid,
    };
  }
  setConversationMeta(convId, {
    otherUserId: uid,
    other_user_id: uid,
  });
}

function collectDmMemberIdsForPeerResolution(conversationId = null) {
  const convId = normId(conversationId || "");
  if (!convId) return [];
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  const activeMeta = activeConvId && activeConvId === convId ? (state.activeDm || {}) : {};
  const cachedMeta = getConversationMeta(convId) || {};
  return normalizeUuidArray([
    ...(Array.isArray(activeMeta?.memberIds) ? activeMeta.memberIds : []),
    ...(Array.isArray(cachedMeta?.memberIds) ? cachedMeta.memberIds : []),
  ]);
}

function collectDmPeerFallbackCandidates(conversationId = null, fallbackSenderUserId = "") {
  const convId = normId(conversationId || "");
  const meId = normId(state.user?.id || "");
  const activeConvId = normId(activeDmId || state.activeDm?.conversationId || "");
  const activePeerUserId = activeConvId && activeConvId === convId
    ? normId(state.activeDm?.otherUserId || state.activeDm?.other_user_id || "")
    : "";
  const cachedMeta = getConversationMeta(convId) || {};
  const cachedPeerUserId = normId(cachedMeta?.otherUserId || cachedMeta?.other_user_id || "");
  const contactMatch = (state.dmContacts || []).find((row) => (
    normId(row?.conversation_id || row?.conversationId || "") === convId
  )) || null;
  const contactPeerUserId = normId(contactMatch?.other_user_id || contactMatch?.otherUserId || contactMatch?.id || "");
  return normalizeUuidArray([
    fallbackSenderUserId,
    callMediaPeerUserId,
    callOtherUserId,
    activePeerUserId,
    cachedPeerUserId,
    contactPeerUserId,
  ]).filter((uid) => uid && uid !== meId);
}

function logPrivateCallOtherUserResolution(event, {
  conversationId = null,
  members = [],
  currentUserId = "",
  resolvedUserId = "",
  reason = "",
  source = "",
  triggerReason = "",
  duplicateCount = 0,
} = {}, { level = "log" } = {}) {
  const convId = normId(conversationId || callConversationId || activeDmId || state.activeDm?.conversationId || "");
  const meId = normId(currentUserId || state.user?.id || "");
  const resolvedId = normId(resolvedUserId || "");
  logPrivateCallStage(event, {
    conversationId: convId,
    otherUserId: resolvedId || "",
    stage: "other_user_resolution",
    errorMessage: String(reason || "").trim() || "",
    responseStatus: null,
    responseBody: null,
    members: normalizeUuidArray(Array.isArray(members) ? members : []),
    currentUserId: meId || null,
    resolvedUserId: resolvedId || null,
    reason: String(reason || "").trim() || null,
    source: String(source || "").trim() || null,
    triggerReason: String(triggerReason || "").trim() || null,
    duplicateCount: Math.max(0, Number(duplicateCount || 0) || 0),
  }, { level });
}

async function resolveConversationPeerUserId(conversationId, fallbackSenderUserId = "", options = {}) {
  const opts = options && typeof options === "object" ? options : {};
  const convId = normId(conversationId);
  const privateCallDebug = !!opts.privateCallDebug;
  const triggerReason = String(opts.triggerReason || "").trim() || "peer_resolution";
  if (!convId || !state.user?.id) {
    if (privateCallDebug) {
      logPrivateCallOtherUserResolution("private_call.other_user_failed", {
        conversationId: convId,
        members: [],
        currentUserId: normId(state.user?.id || ""),
        resolvedUserId: "",
        reason: !convId ? "missing_conversation_id" : "missing_current_user_id",
        source: "preflight",
        triggerReason,
      }, { level: "warn" });
    }
    return null;
  }
  const convKind = await getConversationKindForNotificationRouting(convId);
  if (convKind === "group" || convKind === "server") {
    if (privateCallDebug) {
      logPrivateCallOtherUserResolution("private_call.other_user_failed", {
        conversationId: convId,
        members: [],
        currentUserId: normId(state.user?.id || ""),
        resolvedUserId: "",
        reason: "conversation_not_dm",
        source: "conversation_kind_guard",
        triggerReason,
      }, { level: "warn" });
    }
    return null;
  }
  const meId = normId(state.user.id);
  const senderId = normId(fallbackSenderUserId);
  const senderPeer = senderId && senderId !== meId ? senderId : "";
  const fallbackCandidates = collectDmPeerFallbackCandidates(convId, senderPeer);

  if (privateCallDebug) {
    logPrivateCallOtherUserResolution("private_call.current_user_id", {
      conversationId: convId,
      members: fallbackCandidates,
      currentUserId: meId,
      resolvedUserId: "",
      source: "resolver_start",
      triggerReason,
    });
  }

  const cachedPeer = normId(dmConversationPeerCache.get(convId) || "");
  if (cachedPeer && cachedPeer !== meId) {
    if (privateCallDebug) {
      logPrivateCallOtherUserResolution("private_call.other_user_resolved", {
        conversationId: convId,
        members: normalizeUuidArray([cachedPeer, ...fallbackCandidates]),
        currentUserId: meId,
        resolvedUserId: cachedPeer,
        source: "cache",
        triggerReason,
      });
    }
    return cachedPeer;
  }
  if (dmConversationPeerCache.has(convId) && !cachedPeer) {
    dmConversationPeerCache.delete(convId);
  }

  const localMemberIds = collectDmMemberIdsForPeerResolution(convId);
  const localOthers = localMemberIds.filter((uid) => uid && uid !== meId);
  if (privateCallDebug) {
    logPrivateCallOtherUserResolution("private_call.dm_members", {
      conversationId: convId,
      members: normalizeUuidArray([...localMemberIds, ...fallbackCandidates]),
      currentUserId: meId,
      resolvedUserId: "",
      source: "local_state",
      triggerReason,
    });
    logPrivateCallStage("private_call.dm_members_loaded", {
      conversationId: convId,
      otherUserId: "",
      stage: "dm_members_loaded",
      members: normalizeUuidArray([...localMemberIds, ...fallbackCandidates]),
      source: "local_state",
      triggerReason,
    });
  }
  if (localOthers.length === 1) {
    const resolvedLocalPeer = localOthers[0];
    cacheResolvedConversationPeerUserId(convId, resolvedLocalPeer);
    if (privateCallDebug) {
      logPrivateCallOtherUserResolution("private_call.other_user_resolved", {
        conversationId: convId,
        members: normalizeUuidArray([...localMemberIds, ...fallbackCandidates]),
        currentUserId: meId,
        resolvedUserId: resolvedLocalPeer,
        source: "local_member_ids",
        triggerReason,
      });
    }
    return resolvedLocalPeer;
  }
  if (localOthers.length > 1) {
    const preferredLocalPeer = localOthers.find((uid) => fallbackCandidates.includes(uid)) || localOthers[0] || "";
    if (preferredLocalPeer) {
      cacheResolvedConversationPeerUserId(convId, preferredLocalPeer);
      if (privateCallDebug) {
        logPrivateCallOtherUserResolution("private_call.other_user_resolved", {
          conversationId: convId,
          members: normalizeUuidArray([...localMemberIds, ...fallbackCandidates]),
          currentUserId: meId,
          resolvedUserId: preferredLocalPeer,
          reason: "multiple_members_preferred_match",
          source: "local_member_ids",
          triggerReason,
        });
      }
      return preferredLocalPeer;
    }
  }

  const { data, error } = await supabase
    .from("conversation_members")
    .select("user_id")
    .eq("conversation_id", convId);

  if (error || !Array.isArray(data)) {
    const fallbackPeer = fallbackCandidates[0] || "";
    if (fallbackPeer) {
      cacheResolvedConversationPeerUserId(convId, fallbackPeer);
      if (privateCallDebug) {
        logPrivateCallOtherUserResolution("private_call.other_user_resolved", {
          conversationId: convId,
          members: normalizeUuidArray([...localMemberIds, ...fallbackCandidates]),
          currentUserId: meId,
          resolvedUserId: fallbackPeer,
          reason: "membership_lookup_failed_using_fallback",
          source: "fallback_candidate",
          triggerReason,
        }, { level: "warn" });
      }
      return fallbackPeer;
    }
    cacheResolvedConversationPeerUserId(convId, "");
    if (privateCallDebug) {
      logPrivateCallOtherUserResolution("private_call.other_user_failed", {
        conversationId: convId,
        members: normalizeUuidArray([...localMemberIds, ...fallbackCandidates]),
        currentUserId: meId,
        resolvedUserId: "",
        reason: error ? "membership_lookup_failed" : "membership_data_missing",
        source: "conversation_members_query",
        triggerReason,
      }, { level: "warn" });
    }
    return null;
  }

  const rawMemberIds = data.map((row) => normId(row?.user_id)).filter(Boolean);
  const memberIds = normalizeUuidArray(rawMemberIds);
  const duplicateCount = Math.max(0, rawMemberIds.length - memberIds.length);
  const memberOthers = memberIds.filter((uid) => uid && uid !== meId);
  const debugMembers = normalizeUuidArray([...memberIds, ...fallbackCandidates]);

  if (privateCallDebug) {
    logPrivateCallOtherUserResolution("private_call.dm_members", {
      conversationId: convId,
      members: debugMembers,
      currentUserId: meId,
      resolvedUserId: "",
      source: "conversation_members_query",
      triggerReason,
      duplicateCount,
    });
    logPrivateCallStage("private_call.dm_members_loaded", {
      conversationId: convId,
      otherUserId: "",
      stage: "dm_members_loaded",
      members: debugMembers,
      source: "conversation_members_query",
      triggerReason,
      duplicateCount,
    });
  }

  let resolvedPeer = "";
  let resolutionReason = "";
  if (memberOthers.length === 1) {
    resolvedPeer = memberOthers[0];
    resolutionReason = duplicateCount > 0 ? "duplicate_ids_collapsed" : "single_other_member";
  } else if (memberOthers.length > 1) {
    resolvedPeer = memberOthers.find((uid) => fallbackCandidates.includes(uid)) || memberOthers[0] || "";
    resolutionReason = "multiple_other_members_preferred_match";
  } else if (fallbackCandidates.length) {
    resolvedPeer = fallbackCandidates[0];
    if (!memberIds.length) resolutionReason = "zero_users_found_using_fallback";
    else if (memberIds.length === 1 && memberIds[0] === meId) resolutionReason = "only_current_user_found_using_fallback";
    else resolutionReason = "other_member_missing_using_fallback";
  }

  if (resolvedPeer) {
    cacheResolvedConversationPeerUserId(convId, resolvedPeer);
    if (privateCallDebug) {
      logPrivateCallOtherUserResolution("private_call.other_user_resolved", {
        conversationId: convId,
        members: debugMembers,
        currentUserId: meId,
        resolvedUserId: resolvedPeer,
        reason: resolutionReason,
        source: "conversation_members_resolution",
        triggerReason,
        duplicateCount,
      });
    }
    return resolvedPeer;
  }

  cacheResolvedConversationPeerUserId(convId, "");
  let failureReason = "other_user_not_found";
  if (!memberIds.length) failureReason = "zero_users_found";
  else if (memberIds.length === 1 && memberIds[0] === meId) failureReason = "only_current_user_found";
  else if (!memberIds.includes(meId)) failureReason = "current_user_not_in_members";
  if (duplicateCount > 0) failureReason = `${failureReason}.duplicate_ids_collapsed`;
  if (privateCallDebug) {
    logPrivateCallOtherUserResolution("private_call.other_user_failed", {
      conversationId: convId,
      members: debugMembers,
      currentUserId: meId,
      resolvedUserId: "",
      reason: failureReason,
      source: "conversation_members_resolution",
      triggerReason,
      duplicateCount,
    }, { level: "warn" });
  }
  return null;
}

async function resolvePrivateCallOtherUserId(conversationId, {
  fallbackUserId = "",
  triggerReason = "",
} = {}) {
  return resolveConversationPeerUserId(conversationId, fallbackUserId, {
    privateCallDebug: true,
    triggerReason: String(triggerReason || "").trim() || "private_call_resolver",
  });
}

async function onGlobalDmMessageInserted(row) {
  if (!row || !state.user?.id) return;

  const convId = normId(row.conversation_id);
  if (!convId) return;
  const hasConversationAccess = await canCurrentUserAccessMessageConversation(convId);
  if (!hasConversationAccess) {
    return;
  }
  const myId = normId(state.user.id);
  const fromId = normId(row.user_id);
  if (fromId && fromId === myId) {
    clearDmUnreadForConversation(convId);
    if (normId(activeDmId || state.activeDm?.conversationId || "") === convId) {
      clearDmUnreadForActiveConversation();
    }
    return;
  }

  // Active DM updates are usually handled by the dedicated dmChannel.
  // Keep this only when the channel exists; otherwise allow global fallback.
  if (convId === normId(activeDmId) && dmChannel) return;

  const parsed = safeParseMessageContent(row?.content);
  const isSystemEvent = isSystemChipMessage(parsed);
  const atMs = Date.parse(String(row?.created_at || "")) || Date.now();
  const conversationKind = await getConversationKindForNotificationRouting(convId);
  if (conversationKind === "group" || conversationKind === "server") {
    const activeViewed = isDmConversationActivelyViewed(convId);
    if (!activeViewed && !isSystemEvent) {
      const count = Number(dmUnreadByConversationId.get(convId) || 0);
      dmUnreadByConversationId.set(convId, Math.min(99, count + 1));
      persistDmUnreadConversationsToStorage();
      if (conversationKind === "server") {
        void rememberServerUnreadSenderForConversation(convId, fromId, {
          senderAvatarUrl: String(row?.profiles?.avatar_url || "").trim(),
        });
      }
      if (!isDmConversationMuted(convId)) playUiCue("msg");
    }

    if (conversationKind === "group") {
      let changed = false;
      state.groupDms = (state.groupDms || []).map((g) => {
        if (normId(g?.conversationId) !== convId) return g;
        const prev = Number(g?.lastMessageAt || 0);
        const next = Math.max(prev, atMs);
        if (next <= prev) return g;
        changed = true;
        return { ...g, lastMessageAt: next };
      });
      if (changed) syncConversationMetaCaches();
    }

    scheduleDmChromeRender({
      decorations: true,
      widgets: true,
    });
    return;
  }

  const peerUserId = await resolveConversationPeerUserId(convId, row.user_id);
  if (!peerUserId) return;

  const activeViewed = isDmConversationActivelyViewed(convId);
  touchDmActivity(peerUserId, { at: atMs, unread: !activeViewed && !isSystemEvent });
  void fetchProfilesByIds([peerUserId], { includeBio: false, force: false })
    .then(() => {
      if (Number(dmUnreadByUserId.get(peerUserId) || 0) > 0) {
        scheduleDmChromeRender({ groupsRail: true });
      }
    })
    .catch(() => {});
  if (!activeViewed && !isSystemEvent && !isDmUserMuted(peerUserId)) playUiCue("msg");

  // If item is missing for some reason, refresh DM list to render it.
  if (!getDmItemByUserId(peerUserId)) {
    await loadDmList();
  }
}

function startGlobalDmMessageListener() {
  if (!state.user?.id) return;
  clearDmMessageConversationAccessCache();
  if (globalDmMessageRestartTimer) {
    clearTimeout(globalDmMessageRestartTimer);
    globalDmMessageRestartTimer = null;
  }
  if (globalDmMessageChannel) {
    supabase.removeChannel(globalDmMessageChannel);
    globalDmMessageChannel = null;
  }

  globalDmMessageChannel = supabase
    .channel("global-dm-messages:" + state.user.id)
    .on("postgres_changes", {
      event: "INSERT",
      schema: "public",
      table: "messages"
    }, async (payload) => {
      await onGlobalDmMessageInserted(payload?.new || null);
    })
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR" || status === "TIMED_OUT" || status === "CLOSED") {
        if (globalDmMessageRestartTimer || !state.user?.id) return;
        globalDmMessageRestartTimer = setTimeout(() => {
          globalDmMessageRestartTimer = null;
          startGlobalDmMessageListener();
        }, 1200);
      }
    });
}

function leaveActiveDmView({ captureHistory = true } = {}) {
  activeDmId = null;
  currentConversationCallEnabled = true;
  setMidMode("friends");
  setRightSidebarInteractionModeForConversation({ serverMode: false, applyCollapsed: true });
  renderGroupsRail();
  queueLightweightDmListRenderFromState();
  stopDmOpenAutoScroll();
  stopDmReactionsSync();
  dmReplyTarget = null;
  dmEditTarget = null;
  renderDmReplyBar();
  dmPinsPanelOpen = false;
  dmProfilePanelOpen = false;
  syncDmPinsPanelState();
  closeMessageMenu();
  closeDmListMenus();
  closeEmojiPicker();
  closeUserCardModal();
  closeDmCreateGroupModal();
  closeDmGroupEditModal();
  closeServerInviteModal();
  closeServerSettingsModal();
  closeDmAttachmentModal();
  clearPendingDmAttachments();
  resetDmDragDropState();
  if (dmChannel) {
    supabase.removeChannel(dmChannel);
    dmChannel = null;
  }
  if (dmReactionsChannel) {
    supabase.removeChannel(dmReactionsChannel);
    dmReactionsChannel = null;
  }
  setCallStatus("", false);
  refreshCallUI();
  if (captureHistory) captureCurrentMainNavigationRoute();
}

/* ========================= DM VIEW + realtime messages ========================= */
async function showDm(conversationId, opts = {}) {
  if (!state.user) return;
  const showRequestSeq = ++dmShowRequestSeq;
  const isShowRequestStale = () => showRequestSeq !== dmShowRequestSeq;

  await ensureDmFeatureCaps();
  if (isShowRequestStale()) return;

  const convIdNorm = normId(conversationId);
  const cachedMeta = getConversationMeta(convIdNorm) || {};
  const prevActiveDm = (state.activeDm && typeof state.activeDm === "object") ? state.activeDm : {};
  const prevActiveConversationId = normId(prevActiveDm?.conversationId || "");
  const keepPrevConversationState = !!(
    convIdNorm
    && prevActiveConversationId
    && convIdNorm === prevActiveConversationId
  );
  state.activeDm = {
    ...(keepPrevConversationState ? prevActiveDm : {}),
    ...(cachedMeta || {}),
    conversationId: convIdNorm || conversationId,
  };
  let resolvedKind = String(
    (keepPrevConversationState ? prevActiveDm?.kind : "")
    || cachedMeta?.kind
    || ""
  ).trim().toLowerCase();
  let resolvedOwnerUserId = normId(
    (keepPrevConversationState ? prevActiveDm?.ownerUserId : "")
    || cachedMeta?.ownerUserId
    || ""
  );
  let resolvedServerByDb = false;
  let resolvedChannelType = normalizeConversationChannelType(
    (keepPrevConversationState ? prevActiveDm?.channelType : "")
    || cachedMeta?.channelType
    || cachedMeta?.channel_type
    || ""
  );
  let resolvedUserLimit = clampServerVoiceUserLimit(
    (keepPrevConversationState ? prevActiveDm?.userLimit : undefined)
    ?? cachedMeta?.userLimit
    ?? 0,
    0
  );
  let resolvedMediaMode = normalizeServerVoiceMediaMode(
    (keepPrevConversationState ? prevActiveDm?.mediaMode : "")
    || cachedMeta?.mediaMode
    || "audio_only",
    "audio_only"
  );
  let resolvedDmPrivacyMeta = buildDmPrivacyMeta({
    ...(cachedMeta || {}),
    ...(keepPrevConversationState ? prevActiveDm : {}),
  }, {
    fallbackKind: String(
      (keepPrevConversationState ? prevActiveDm?.kind : "")
      || cachedMeta?.kind
      || "dm"
    ).trim().toLowerCase(),
  });

  if (convIdNorm) {
    try {
      const conversationSelect = (dmFeatureCaps.dmPrivacyState && DM_PRIVATE_RUNTIME_ENABLED)
        ? `kind, created_by, ${buildDmPrivacyConversationSelectColumns().replace(/^id,\s*/, "")}`
        : "kind, created_by";
      const { data: convRow, error: convErr } = await supabase
        .from("conversations")
        .select(conversationSelect)
        .eq("id", convIdNorm)
        .maybeSingle();

      if (!convErr && convRow) {
        const dbKind = String(convRow?.kind || "").trim().toLowerCase();
        const dbOwner = normId(convRow?.created_by || "");
        let isServerChannel = false;
        let dbServerChannelType = "";
        let dbServerUserLimit = 0;
        let dbServerMediaMode = "audio_only";

        if (dbKind === "group") {
          let scResult = await supabase
            .from("server_channels")
            .select("conversation_id, channel_type, user_limit, media_mode")
            .eq("conversation_id", convIdNorm)
            .limit(1);

          if (scResult?.error) {
            const scMsg = String(scResult.error?.message || "").toLowerCase();
            const missingChannelTypeColumn = scMsg.includes("channel_type") && scMsg.includes("column");
            if (missingChannelTypeColumn) {
              scResult = await supabase
                .from("server_channels")
                .select("conversation_id, user_limit, media_mode")
                .eq("conversation_id", convIdNorm)
                .limit(1);
            }
          }

          const scErr = scResult?.error || null;
          const scRows = Array.isArray(scResult?.data) ? scResult.data : [];
          if (!scErr && scRows.length > 0) {
            isServerChannel = true;
            dbServerChannelType = normalizeConversationChannelType(scRows[0]?.channel_type || "");
            dbServerUserLimit = clampServerVoiceUserLimit(scRows[0]?.user_limit ?? 0, 0);
            dbServerMediaMode = normalizeServerVoiceMediaMode(scRows[0]?.media_mode || "audio_only", "audio_only");
          }
        }

        resolvedKind = isServerChannel ? "server" : (dbKind || resolvedKind);
        if (isServerChannel) {
          resolvedServerByDb = true;
          resolvedChannelType = dbServerChannelType || resolvedChannelType || "text";
          resolvedUserLimit = resolvedChannelType === "voice" ? dbServerUserLimit : 0;
          resolvedMediaMode = resolvedChannelType === "voice" ? dbServerMediaMode : "audio_only";
        } else if (dbKind === "dm") {
          resolvedChannelType = "text";
          resolvedUserLimit = 0;
          resolvedMediaMode = "audio_only";
        }
        if (dbOwner) resolvedOwnerUserId = dbOwner;
        if (dmFeatureCaps.dmPrivacyState && DM_PRIVATE_RUNTIME_ENABLED && dbKind === "dm") {
          resolvedDmPrivacyMeta = applyConversationDmPrivacyMeta(convIdNorm, {
            ...convRow,
            kind: dbKind || resolvedKind || "dm",
          });
        }
      }
    } catch (_) {}
  }

  if (!resolvedKind) resolvedKind = "dm";
  if (resolvedKind !== "dm" && resolvedKind !== "group" && resolvedKind !== "server") {
    resolvedKind = "dm";
  }
  if (resolvedKind === "server" && !resolvedServerByDb) {
    const localServerCtx = findServerChannelContextByConversationId(convIdNorm || conversationId);
    const isKnownServerDefaultConversation = !!(state.servers || []).some(
      (s) => normId(s?.defaultConversationId || "") === convIdNorm
    );
    if (!normId(localServerCtx?.serverId || "") && !isKnownServerDefaultConversation) {
      resolvedKind = "dm";
      resolvedChannelType = "text";
    }
  }
  const isGroupConversation = resolvedKind === "group" || resolvedKind === "server";
  const isServerConversation = resolvedKind === "server";
  const isServerVoiceConversation = isServerConversation && isVoiceConversationChannelType(resolvedChannelType);
  currentConversationCallEnabled = !isServerConversation || isServerVoiceConversation;

  state.activeDm = {
    ...(state.activeDm || {}),
    kind: resolvedKind,
    isGroup: isGroupConversation,
    ownerUserId: resolvedOwnerUserId || "",
    channelType: resolvedChannelType,
    userLimit: isServerVoiceConversation ? resolvedUserLimit : 0,
    mediaMode: isServerVoiceConversation ? resolvedMediaMode : "audio_only",
    serverId: isServerConversation ? normId(state.activeDm?.serverId || cachedMeta?.serverId || "") : "",
    serverName: isServerConversation ? String(state.activeDm?.serverName || cachedMeta?.serverName || "") : "",
  };
  if (isServerConversation) {
    const contextByConversation = findServerChannelContextByConversationId(convIdNorm || conversationId);
    const sid = normId(
      state.activeDm?.serverId
      || cachedMeta?.serverId
      || contextByConversation?.serverId
      || ""
    );
    if (sid && convIdNorm) {
      state.activeDm.serverId = sid;
      rememberServerLastChannel(sid, convIdNorm, { persist: true });
    }
  } else {
    state.activeDm.serverId = "";
    state.activeDm.serverName = "";
  }
  setConversationMeta(convIdNorm || conversationId, {
    kind: resolvedKind,
    isGroup: isGroupConversation,
    ownerUserId: resolvedOwnerUserId || "",
    channelType: resolvedChannelType,
    userLimit: isServerVoiceConversation ? resolvedUserLimit : 0,
    mediaMode: isServerVoiceConversation ? resolvedMediaMode : "audio_only",
  });
  if (isGroupConversation || isServerConversation) {
    clearDmUnreadForConversation(convIdNorm || conversationId);
  }
  if (isShowRequestStale()) return;

  stopDmOpenAutoScroll();
  stopDmReactionsSync();
  activeDmId = conversationId;
  dmOpenAutoScrollUserInterrupted = false;
  dmOpenAutoScrollStartedAt = Date.now();
  dmOpenAutoScrollUntil = Date.now() + DM_OPEN_AUTOSCROLL_MS;
  dmOpenAutoScrollArmed = true;
  setMidMode("dm");
  setRightSidebarInteractionModeForConversation({
    serverMode: isServerConversation,
    forceHidden: !isServerConversation,
    applyCollapsed: true,
  });
  captureCurrentMainNavigationRoute();

  dmMessagesCache = [];
  dmMessageIds = new Set();
  dmHistoryHasMore = false;
  dmHistoryLoadingOlder = false;
  dmHistoryOldestCreatedAt = "";
  clearReactionCaches();
  dmReplyTarget = null;
  dmEditTarget = null;
  renderDmReplyBar();
  closeMessageMenu();
  closeDmListMenus();
  closeEmojiPicker();
  closeUserCardModal();
  closeDmCreateGroupModal();
  closeDmGroupEditModal();
  closeServerInviteModal();
  closeServerSettingsModal();
  closeDmAttachmentModal();
  clearPendingDmAttachments();
  resetDmDragDropState();

  if (dmChannel) {
    supabase.removeChannel(dmChannel);
    dmChannel = null;
  }
  if (dmReactionsChannel) {
    supabase.removeChannel(dmReactionsChannel);
    dmReactionsChannel = null;
  }

  let dmPeerUserId = isGroupConversation ? "" : normId(state.activeDm?.otherUserId || state.activeDm?.other_user_id || "");
  let dmPeerLabel = state.activeDm?.displayName || state.activeDm?.username || callOtherLabel || (isGroupConversation ? "Group DM" : "");
  let dmPeerAvatar = state.activeDm?.avatarUrl || callOtherAvatar || null;

  if (!isGroupConversation) {
    if (opts.forceOtherUserId) dmPeerUserId = normId(opts.forceOtherUserId || "");
    if (opts.forceOtherLabel) dmPeerLabel = opts.forceOtherLabel;
    if (opts.forceOtherAvatar) dmPeerAvatar = opts.forceOtherAvatar;
  }

  if (!isGroupConversation && !dmPeerUserId) {
    dmPeerUserId = await resolvePrivateCallOtherUserId(conversationId, {
      triggerReason: "show_dm_initial_peer_resolution",
    });
    if (dmPeerUserId) {
      const friend = (state.friends || []).find((f) => normId(f?.other_user_id || f?.id) === dmPeerUserId) || null;
      const cachedProfile = getCachedProfile(dmPeerUserId) || null;
      dmPeerLabel = normalizeConversationLabel(
        dmPeerLabel
        || friend?.display_name
        || friend?.username
        || cachedProfile?.display_name
        || cachedProfile?.username
        || "amigo",
        "amigo"
      );
      dmPeerAvatar = String(
        dmPeerAvatar
        || friend?.avatar_url
        || cachedProfile?.avatar_url
        || ""
      ).trim() || null;
      state.activeDm = {
        ...(state.activeDm || {}),
        otherUserId: dmPeerUserId,
        other_user_id: dmPeerUserId,
      };
    }
  }
  if (isShowRequestStale()) return;

  if (!isGroupConversation && dmPeerUserId) {
    const [otherProfile] = await fetchProfilesByIds([dmPeerUserId], { includeBio: false, force: false });
    if (otherProfile) {
      dmPeerLabel = otherProfile.display_name || otherProfile.username || dmPeerLabel;
      dmPeerAvatar = String(otherProfile.avatar_url || "").trim() || null;
      state.activeDm = {
        ...(state.activeDm || {}),
        otherUserId: dmPeerUserId,
        username: otherProfile.username || state.activeDm?.username || "",
        displayName: otherProfile.display_name || state.activeDm?.displayName || dmPeerLabel,
        avatarUrl: String(otherProfile.avatar_url || "").trim(),
        name_color: normalizeNameColor(otherProfile.name_color),
        call_tile_color: normalizeCallTileColor(otherProfile.call_tile_color),
        banner_url: normalizeBannerUrl(otherProfile.banner_url || otherProfile.theme_settings?.banner_url || state.activeDm?.banner_url || ""),
      };
    }
    clearDmUnreadForUser(dmPeerUserId);
  }
  if (isShowRequestStale()) return;

  if (!isGroupConversation) {
    if (!inCall && dmPeerUserId) {
      callOtherUserId = dmPeerUserId;
      callMediaPeerUserId = dmPeerUserId;
      callOtherLabel = dmPeerLabel || callOtherLabel;
      callOtherAvatar = dmPeerAvatar || callOtherAvatar || null;
    } else if (opts.forceOtherUserId) {
      callOtherUserId = dmPeerUserId || callOtherUserId;
      callMediaPeerUserId = dmPeerUserId || callMediaPeerUserId || callOtherUserId;
      callOtherLabel = dmPeerLabel || callOtherLabel;
      callOtherAvatar = dmPeerAvatar || callOtherAvatar || null;
    }
  } else if (!inCall) {
    callOtherUserId = null;
    callMediaPeerUserId = null;
    callOtherLabel = dmPeerLabel || "Group DM";
    callOtherAvatar = null;
  }

  void fetchProfilesByIds([state.user.id], { includeBio: false }).catch(() => {});
  if (isShowRequestStale()) return;

  const activeGroupRow = isGroupConversation && !isServerConversation
    ? ((state.groupDms || []).find((g) => normId(g?.conversationId) === convIdNorm) || null)
    : null;
  const activeGroupOwnerUserId = normId(
    state.activeDm?.ownerUserId
    || cachedMeta?.ownerUserId
    || activeGroupRow?.ownerUserId
    || ""
  );

  const finalTitle = normalizeConversationLabel(
    state.activeDm?.displayName || state.activeDm?.username || dmPeerLabel || callOtherLabel || (isGroupConversation ? "Group DM" : "DM"),
    isGroupConversation ? "Group DM" : "DM"
  );
  const finalConversationKind = isServerConversation ? "server" : (isGroupConversation ? "group" : "dm");
  const finalServerId = isServerConversation ? normId(state.activeDm?.serverId || "") : "";
  const finalServerName = isServerConversation ? String(state.activeDm?.serverName || "") : "";
  if (finalConversationKind === "dm" && DM_PRIVATE_RUNTIME_ENABLED) {
    resolvedDmPrivacyMeta = await resolveConversationDmPrivacyMeta(convIdNorm || conversationId);
  }
  document.getElementById("dmTitle").textContent = finalTitle;
  state.activeDm = {
    ...(state.activeDm || {}),
    ...(finalConversationKind === "dm" ? resolvedDmPrivacyMeta : {}),
    conversationId: convIdNorm || conversationId,
    displayName: finalTitle,
    kind: finalConversationKind,
    isGroup: !!isGroupConversation,
    ownerUserId: isGroupConversation ? activeGroupOwnerUserId : "",
    otherUserId: isGroupConversation ? "" : (state.activeDm?.otherUserId || dmPeerUserId || ""),
    channelType: normalizeConversationChannelType(state.activeDm?.channelType || resolvedChannelType || ""),
    serverId: finalServerId,
    serverName: finalServerName,
  };
  setConversationMeta(convIdNorm || conversationId, {
    kind: finalConversationKind,
    isGroup: !!isGroupConversation,
    displayName: finalTitle,
    ownerUserId: isGroupConversation ? activeGroupOwnerUserId : "",
    otherUserId: isGroupConversation ? "" : (state.activeDm?.otherUserId || dmPeerUserId || ""),
    username: isGroupConversation ? "" : (state.activeDm?.username || ""),
    avatarUrl: state.activeDm?.avatarUrl || "",
    memberCount: Number(state.activeDm?.memberCount || 0),
    memberIds: Array.isArray(state.activeDm?.memberIds) ? state.activeDm.memberIds : [],
    memberDisplayNames: Array.isArray(state.activeDm?.memberDisplayNames) ? state.activeDm.memberDisplayNames : [],
    memberUsernames: Array.isArray(state.activeDm?.memberUsernames) ? state.activeDm.memberUsernames : [],
    serverId: finalServerId,
    serverName: finalServerName,
    channelType: normalizeConversationChannelType(state.activeDm?.channelType || resolvedChannelType || ""),
    ...(finalConversationKind === "dm" ? resolvedDmPrivacyMeta : {}),
  });
  if (isCallCapableGroupConversationMeta(state.activeDm)) {
    void fetchGroupConversationMembers(convIdNorm || conversationId, { force: false });
  }
  if (finalConversationKind === "dm" && DM_PRIVATE_RUNTIME_ENABLED) {
    void ensureDmE2eeBootstrapStarted();
  }
  applyDmTitleNameStyle();
  syncDmActiveListHighlight();
  renderGroupsRail();
  applyDmComposerEditUi();
  await refreshServerConversationUi({ force: isServerConversation }).catch(() => {});
  if (isShowRequestStale()) return;
  const preferredPanelMode = getDmSidePanelMode();
  const btnDmCreateGroup = document.getElementById("btnDmCreateGroup");
  const btnDmGroupEdit = document.getElementById("btnDmGroupEdit");
  const btnDmProfilePanel = document.getElementById("btnDmProfilePanel");
  const btnDmGroupManage = document.getElementById("btnDmGroupManage");
  const btnDmPins = document.getElementById("btnDmPins");
  const groupMembershipMeta = (isGroupConversation && !isServerConversation)
    ? getGroupMembershipActionMeta(convIdNorm || conversationId)
    : null;
  if (btnDmCreateGroup) {
    btnDmCreateGroup.style.display = isGroupConversation ? "none" : "";
    btnDmCreateGroup.disabled = isGroupConversation;
  }
  if (btnDmGroupEdit) {
    const canShowGroupEdit = !!groupMembershipMeta?.isOwner;
    if (!canShowGroupEdit) {
      btnDmGroupEdit.style.display = "none";
      btnDmGroupEdit.disabled = true;
      btnDmGroupEdit.onclick = null;
    } else {
      btnDmGroupEdit.style.display = "";
      btnDmGroupEdit.disabled = false;
      btnDmGroupEdit.title = t("dm.edit_group", "Edit group");
      btnDmGroupEdit.setAttribute("aria-label", t("dm.edit_group", "Edit group"));
      btnDmGroupEdit.onclick = async () => {
        await openDmGroupEditModal();
      };
    }
  }
  if (btnDmProfilePanel) {
    const profileLabel = isGroupConversation ? t("dm.members", "Members") : t("dm.profile", "Profile");
    const profileSr = btnDmProfilePanel.querySelector(".sr-only");
    if (isServerConversation) {
      const membersLabel = t("dm.members", "Members");
      const membersOpen = !rightSidebarForceHiddenForServerVoiceStage && !isRightSidebarCollapsed();
      btnDmProfilePanel.style.display = "";
      btnDmProfilePanel.disabled = false;
      btnDmProfilePanel.classList.add("is-members-mode");
      btnDmProfilePanel.classList.toggle("is-on", membersOpen);
      btnDmProfilePanel.setAttribute("aria-pressed", membersOpen ? "true" : "false");
      btnDmProfilePanel.title = membersLabel;
      btnDmProfilePanel.setAttribute("aria-label", membersLabel);
      if (profileSr) profileSr.textContent = membersLabel;
      btnDmProfilePanel.onclick = async () => {
        const shell = getSidebarShellEl();
        shell?.classList?.remove("dm-focus");
        if (rightSidebarForceHiddenForServerVoiceStage) {
          rightSidebarCollapsedServerMode = true;
          setRightSidebarCollapsed(true, { persist: false });
          return;
        }
        const nextCollapsed = !isRightSidebarCollapsed();
        rightSidebarCollapsedServerMode = nextCollapsed;
        setRightSidebarCollapsed(nextCollapsed, { persist: false });
        if (!isRightSidebarCollapsed()) {
          await refreshServerConversationUi({ force: false }).catch(() => {});
        }
      };
    } else {
      btnDmProfilePanel.classList.remove("is-members-mode");
      btnDmProfilePanel.style.display = "";
      btnDmProfilePanel.disabled = false;
      btnDmProfilePanel.title = profileLabel;
      btnDmProfilePanel.setAttribute("aria-label", profileLabel);
      if (profileSr) profileSr.textContent = profileLabel;
      btnDmProfilePanel.onclick = async () => {
        if (dmProfilePanelOpen) closeDmProfilePanel();
        else await openDmProfilePanel({ force: isGroupConversation });
      };
    }
  }
  if (btnDmGroupManage) {
    const groupMeta = groupMembershipMeta || getGroupMembershipActionMeta(convIdNorm || conversationId);
    const canShowGroupManage = isGroupConversation && !isServerConversation && !groupMeta?.isOwner;
    if (!canShowGroupManage) {
      btnDmGroupManage.style.display = "none";
      btnDmGroupManage.disabled = true;
      btnDmGroupManage.classList.remove("is-owner");
      btnDmGroupManage.onclick = null;
    } else {
      btnDmGroupManage.style.display = "";
      btnDmGroupManage.disabled = false;
      btnDmGroupManage.title = groupMeta.actionLabel;
      btnDmGroupManage.setAttribute("aria-label", groupMeta.actionLabel);
      btnDmGroupManage.classList.remove("danger");
      btnDmGroupManage.classList.add("ghost");
      btnDmGroupManage.classList.remove("is-owner");
      const groupManageSr = btnDmGroupManage.querySelector(".sr-only");
      if (groupManageSr) groupManageSr.textContent = groupMeta.actionLabel;
      btnDmGroupManage.onclick = async () => {
        await handleGroupDmMembershipAction(convIdNorm || conversationId, {
          requestedAction: groupMeta.action,
          groupName: finalTitle || "Group DM",
        });
      };
    }
  }
  if (btnDmPins) {
    btnDmPins.style.display = dmFeatureCaps.advancedMessages ? "" : "none";
    btnDmPins.onclick = async () => {
      if (dmPinsPanelOpen) closeDmPinsModal();
      else await openDmPinsModal();
    };
  }
  renderDmPrivacyUi();
  dmProfilePanelOpen = !isServerConversation && preferredPanelMode === "profile";
  dmPinsPanelOpen = dmFeatureCaps.advancedMessages && preferredPanelMode === "pins";
  syncDmPinsPanelState();
  if (!dmPinsPanelOpen) renderDmPinsList(getPinnedMessagesFromCache());

  // back
  const btnBack = document.getElementById("btnBackToFriends");
  btnBack.onclick = () => {
    leaveActiveDmView({ captureHistory: true });
  };

  await fetchMessages(conversationId);
  if (isShowRequestStale()) return;
  startDmReactionsSync(conversationId);
  if (dmPinsPanelOpen) await openDmPinsModal();
  else if (dmProfilePanelOpen) await openDmProfilePanel();
  if (isShowRequestStale()) return;
  if (!isServerConversation) {
    focusDmComposerSoon();
  }

  dmChannel = supabase
    .channel("dm:" + conversationId)
    .on("postgres_changes", {
      event: "INSERT",
      schema: "public",
      table: "messages",
      filter: `conversation_id=eq.${conversationId}`
    }, async (payload) => {
      if (payload?.new?.id) {
        const { data: row } = await supabase
          .from("messages")
          .select(dmMessageSelectColumns())
          .eq("id", payload.new.id)
          .single();
        const [resolvedRow] = await hydrateDmRowsForDisplay([row || payload.new], { conversationId });
        appendMessage(resolvedRow || row || payload.new);
      } else {
        const [resolvedRow] = await hydrateDmRowsForDisplay([payload.new], { conversationId });
        appendMessage(resolvedRow || payload.new);
      }
    })
    .on("postgres_changes", {
      event: "UPDATE",
      schema: "public",
      table: "messages",
      filter: `conversation_id=eq.${conversationId}`
    }, async (payload) => {
      const row = payload?.new;
      if (!row?.id) return;
      const idx = dmMessagesCache.findIndex((m) => String(m?.id || "") === String(row.id));
      if (idx < 0) return;

      const [resolvedRow] = await hydrateDmRowsForDisplay([row], { conversationId });
      dmMessagesCache[idx] = { ...dmMessagesCache[idx], ...(resolvedRow || row) };
      const merged = dmMessagesCache[idx];
      cacheProfileRow({
        id: merged?.user_id,
        username: merged?.profiles?.username,
        display_name: merged?.profiles?.display_name,
        avatar_url: merged?.profiles?.avatar_url,
        name_color: merged?.profiles?.name_color,
      });
      void fetchProfilesByIds([merged?.user_id], { includeBio: false });
      renderMessagesFromCache({ keepBottom: true });
      if (dmReplyTarget?.id === String(row.id) || dmEditTarget?.id === String(row.id)) renderDmReplyBar();
    })
    .on("postgres_changes", {
      event: "DELETE",
      schema: "public",
      table: "messages",
    }, (payload) => {
      const oldRow = payload?.old || {};
      const msgId = oldRow?.id;
      if (!msgId) return;

      const oldConv = oldRow?.conversation_id || null;
      if (oldConv && normId(oldConv) !== normId(activeDmId)) return;
      if (!oldConv && !dmMessageIds.has(normId(msgId))) return;

      removeMessageFromCacheAndUi(msgId);
    })
    .subscribe((status) => {
      if (status === "CHANNEL_ERROR") {
        console.warn("dm messages realtime channel error:", conversationId);
      }
    });

  if (dmFeatureCaps.messageReactions) {
    dmReactionsChannel = supabase
      .channel("dm-reactions:" + conversationId)
      .on("postgres_changes", {
        event: "INSERT",
        schema: "public",
        table: "message_reactions",
        filter: `conversation_id=eq.${conversationId}`
      }, (payload) => {
        const r = payload?.new;
        if (!r?.message_id || !r?.emoji || !r?.user_id) return;
        if (!dmMessageIds.has(normId(r.message_id))) return;
        applyReactionDelta(r.message_id, r.emoji, r.user_id, true);
        updateMessageReactionsUi(r.message_id);
      })
      .on("postgres_changes", {
        event: "DELETE",
        schema: "public",
        table: "message_reactions",
        filter: `conversation_id=eq.${conversationId}`
      }, (payload) => {
        const r = payload?.old;
        if (!r?.message_id || !r?.emoji || !r?.user_id) return;
        if (!dmMessageIds.has(normId(r.message_id))) return;
        applyReactionDelta(r.message_id, r.emoji, r.user_id, false);
        updateMessageReactionsUi(r.message_id);
      })
      .subscribe((status) => {
        if (status === "CHANNEL_ERROR") {
          console.warn("dm reactions realtime channel error:", conversationId);
        }
      });
  }

  // call buttons
  const { btnCall, btnHangup, btnAnswer } = getCallEls();
  const callConversationMeta = getActiveConversationMeta(conversationId) || getConversationMeta(conversationId) || {};
  const isCallCapableGroupConversation = isCallCapableGroupConversationMeta(callConversationMeta);
  const useSessionBackend = shouldUseGroupCallSessionBackendForConversation(conversationId);
  const sameConversationAsActiveCall = !!(
    inCall &&
    normId(callConversationId || "") === normId(conversationId || "")
  );
  if (isCallCapableGroupConversation && useSessionBackend) {
    await refreshGroupDmCallState(conversationId, { rerender: false });
    startActiveGroupDmCallStatePolling(conversationId);
  } else {
    clearCachedGroupDmCallState(conversationId);
    stopActiveGroupDmCallStatePolling();
  }

  setCallButtons(currentConversationCallEnabled && sameConversationAsActiveCall ? "inCall" : "idle");
  setCallStatus("", false);

  if (btnCall) {
    btnCall.onclick = async () => {
      if (!currentConversationCallEnabled) return;
      if (isCallCapableGroupConversation) {
        const hasPendingGroupRing = !!(
          pendingGroupRingInfo &&
          normId(pendingGroupRingInfo?.conversationId) === normId(conversationId)
        );
        if (hasPendingGroupRing) {
          await acceptPendingGroupRing();
          return;
        }
        const joinability = getGroupCallJoinability(conversationId);
        const joinExistingOnly = isServerVoiceConversationMeta(callConversationMeta)
          ? true
          : !!joinability.joinablePublicCall;
        await startGroupCall(conversationId, { joinExistingOnly });
        return;
      }
      let resolvedPeerUserId = normId(
        callOtherUserId
        || state.activeDm?.otherUserId
        || state.activeDm?.other_user_id
        || ""
      );
      if (!resolvedPeerUserId) {
        resolvedPeerUserId = await resolvePrivateCallOtherUserId(conversationId, {
          triggerReason: "dm_call_button_click",
        });
      }
      if (!resolvedPeerUserId) return alert("NÃ£o consegui resolver o ID do amigo para a chamada.");
      callOtherUserId = resolvedPeerUserId;
      callMediaPeerUserId = resolvedPeerUserId;
      await startCall(conversationId, resolvedPeerUserId, callOtherLabel);
    };
  }

  if (btnHangup) {
    btnHangup.onclick = async () => {
      const sameCallNow = !!(
        inCall &&
        normId(callConversationId || "") === normId(conversationId || activeDmId || "")
      );
      if (!sameCallNow) return;
      await hangupCurrentCallByUser("?? Desligaste.");
    };
  }

  if (btnAnswer) {
    btnAnswer.onclick = async () => {
      if (!currentConversationCallEnabled) return;
      const hasPendingGroupRing = !!(
        pendingGroupRingInfo &&
        normId(pendingGroupRingInfo?.conversationId) === normId(conversationId)
      );
      if (hasPendingGroupRing) {
        await acceptPendingGroupRing();
        return;
      }
      await answerCall();
    };
  }

  const incomingOfferForConversation = !!(
    pendingOffer &&
    pendingCallInfo?.conversationId === conversationId
  );
  const incomingGroupRingForConversation = !!(
    pendingGroupRingInfo &&
    normId(pendingGroupRingInfo?.conversationId) === normId(conversationId)
  );
  if (currentConversationCallEnabled && (incomingOfferForConversation || incomingGroupRingForConversation)) {
    setCallButtons("incoming");
    if (incomingGroupRingForConversation) {
      setCallStatus(`?? Chamada de grupo a entrar de ${pendingGroupRingInfo?.fromLabel || callOtherLabel || t("call.friend", "friend")}`, true);
    } else {
      setCallStatus(`?? Chamada a entrar de ${callOtherLabel || t("call.friend", "friend")}`, true);
    }
  } else {
    syncPublicGroupCallJoinHint(conversationId);
  }

  // garante palco na DM
  dockStageIntoDm(true);
  refreshCallUI();
  scrollDmToLatest();
}

/* ========================= INIT + Call UI bindings ========================= */
function bindCallUIButtons() {
  if (callUiButtonsBound) return;
  callUiButtonsBound = true;

  const {
    btnMicToggle, btnDeafenToggle, btnHeaderMicToggle, btnHeaderDeafenToggle, btnServerVoiceReconnect, btnCallEndStage, btnPopoutStage, btnExitFullscreen,
    btnServerVoiceCopyDiagnostics,
    btnServerVoiceReconnectSmall, btnMicToggleSmall, btnDeafenToggleSmall, btnCallEndSmall,
    btnShareScreen, btnShareScreenStage, btnShareScreenStageMenu, btnShareScreenSmall, btnShareScreenSmallMenu,
    btnCamera, btnCameraStage, btnCameraStageMenu, btnCameraSmall, btnCameraSmallMenu, btnFullscreenStage,
    tileRemote, tileRemoteAux, tileSelf, tileSelfAux, gridRemote, gridRemoteAux, gridSelf, gridSelfAux,
    remoteTileAvatar, remoteAuxTileAvatar, remoteTileLabel, remoteAuxTileLabel, remoteGridAvatar, remoteAuxGridAvatar, remoteGridLabel, remoteAuxGridLabel,
    remoteVideo, remoteThumb, remoteAuxThumb, remoteGridVideo, remoteAuxGridVideo,
    stageViewport, stagePlaceholder, stageAvatar, stageLabel, remoteWatchGate, remoteWatchPreview, btnWatchRemoteStream, dmStageResizeGrip, stage
  } = getCallEls();

  applySharePrefsToUi();
  applyDmStageHeightPref();
  loadCallAudioVolumePrefs();
  bindCallAudioMenuOnce();
  bindCallShareMenuOnce();
  bindCallCameraMenuOnce();
  ensureCallWatchSnapshotTimer();

  btnMicToggle?.addEventListener("click", toggleMic);
  btnDeafenToggle?.addEventListener("click", toggleDeafen);
  btnHeaderMicToggle?.addEventListener("click", toggleMic);
  btnHeaderDeafenToggle?.addEventListener("click", toggleDeafen);

  btnCallEndStage?.addEventListener("click", async () => {
    await hangupCurrentCallByUser("?? Desligaste.");
  });
  btnServerVoiceReconnect?.addEventListener("click", async () => {
    const convId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
    if (!convId || !shouldUseServerVoiceLiveKitTransport(convId)) return;
    await reconnectServerVoiceAudio(convId, { reason: "manual_stage_reconnect" });
  });
  btnServerVoiceCopyDiagnostics?.addEventListener("click", async () => {
    const convId = getInspectableServerVoiceConversationId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
    if (!convId || !shouldUseServerVoiceLiveKitTransport(convId)) return;
    await copyServerVoiceCallDiagnostics(convId);
  });

  btnExitFullscreen?.addEventListener("click", (ev) => {
    ev.stopPropagation();
    if (document.fullscreenElement) {
      document.exitFullscreen?.().catch?.(() => {});
      return;
    }
    toggleViewportFullscreen();
  });
  btnPopoutStage?.addEventListener("click", async (ev) => {
    ev.stopPropagation();
    await toggleCallPictureInPicture();
  });
  btnMicToggleSmall?.addEventListener("click", toggleMic);
  btnDeafenToggleSmall?.addEventListener("click", toggleDeafen);

  btnCallEndSmall?.addEventListener("click", async () => {
    await hangupCurrentCallByUser("?? Desligaste.");
  });
  btnServerVoiceReconnectSmall?.addEventListener("click", async () => {
    const convId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
    if (!convId || !shouldUseServerVoiceLiveKitTransport(convId)) return;
    await reconnectServerVoiceAudio(convId, { reason: "manual_bar_reconnect" });
  });

  const openShareMenuFromAnchor = (anchorEl = null, {
    triggerReason = "manual_open",
    callerFunction = "openShareMenuFromAnchor",
    logContextMenuOpen = false,
    source = "unknown",
    clientPoint = null,
    context = null,
  } = {}) => {
    const anchor = anchorEl || btnShareScreenStage || btnShareScreenSmall || null;
    const activeConvId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
    const isServerVoiceScreenshareMode = !!(activeConvId && shouldUseServerVoiceLiveKitTransport(activeConvId));
    const localShareActive = isServerVoiceScreenshareMode
      ? !!isServerVoiceLocalScreenshareActive(activeConvId)
      : !!isScreenSharing;
    const rect = anchor?.getBoundingClientRect?.() || null;
    if (logContextMenuOpen && isServerVoiceScreenshareMode) {
      logServerVoiceDebug("screenshare.context_menu_opened", {
        conversationId: activeConvId || null,
        triggerReason: String(triggerReason || "").trim() || "manual_open",
        callerFunction: String(callerFunction || "").trim() || "openShareMenuFromAnchor",
        source: String(source || "").trim() || "unknown",
        localShareActive,
        anchorId: String(anchor?.id || "").trim() || null,
      });
    }
    return openCallShareMenuAt(rect, {
      triggerReason: String(triggerReason || "").trim() || "manual_open",
      callerFunction: String(callerFunction || "").trim() || "openShareMenuFromAnchor",
      point: clientPoint,
      context,
    });
  };

  const shareHandler = async (ev = null) => {
    if (!isCallMediaSessionActive()) return;
    const activeConvId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
    if (shouldUseServerVoiceLiveKitTransport(activeConvId)) {
      const buttonId = String(ev?.currentTarget?.id || "").trim() || "unknown";
      const localShareActive = !!isServerVoiceLocalScreenshareActive(activeConvId);
      logServerVoiceDebug("screenshare.main_button_left_click", {
        conversationId: activeConvId || null,
        triggerReason: "server_voice_main_button_left_click",
        callerFunction: "shareHandler",
        buttonId,
        localShareActive,
      });
      try {
        if (localShareActive) {
          await toggleServerVoiceScreenshare(activeConvId, {
            triggerReason: "server_voice_main_button_quick_stop",
          });
          logServerVoiceDebug("screenshare.quick_stop_triggered", {
            conversationId: activeConvId || null,
            triggerReason: "server_voice_main_button_left_click",
            callerFunction: "shareHandler",
            buttonId,
            localShareActiveBeforeStop: true,
            localShareActiveAfterStop: !!isServerVoiceLocalScreenshareActive(activeConvId),
          });
          return;
        }
        await openServerVoiceScreenshareFullPicker(activeConvId, {
          triggerReason: "server_voice_share_button",
          callerFunction: "shareHandler",
        });
      } catch (error) {
        const errorText = String(error?.message || error || "Unable to open stream picker.").trim() || "Unable to open stream picker.";
        setCallStatus(errorText, true);
        setTimeout(() => setCallStatus("", false), 2200);
      }
      return;
    }
    if (isScreenSharing) {
      const anchor = ev?.currentTarget instanceof HTMLElement ? ev.currentTarget : null;
      openShareMenuFromAnchor(anchor, {
        triggerReason: "legacy_share_button_when_active",
        callerFunction: "shareHandler",
      });
      return;
    }
    if (callShareToggleInFlight) return;
    callShareToggleInFlight = true;
    try {
      await startScreenShare();
    } finally {
      callShareToggleInFlight = false;
    }
  };
  const openCameraMenuFromAnchor = async (anchorEl = null, {
    triggerReason = "manual_open",
    callerFunction = "openCameraMenuFromAnchor",
    source = "unknown",
  } = {}) => {
    const anchor = anchorEl || btnCameraStage || btnCameraSmall || null;
    const rect = anchor?.getBoundingClientRect?.() || null;
    await openCallCameraMenuAt(rect, {
      triggerReason: String(triggerReason || "").trim() || "manual_open",
      callerFunction: String(callerFunction || "").trim() || "openCameraMenuFromAnchor",
      source: String(source || "").trim() || "unknown",
    });
  };

  const cameraMainButtonHandler = async (ev = null) => {
    if (!isCallMediaSessionActive()) return;
    if (callCameraToggleInFlight) return;
    const activeConvId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
    if (shouldUseServerVoiceLiveKitTransport(activeConvId)) {
      const buttonId = String(ev?.currentTarget?.id || "").trim() || "unknown";
      const wasActive = !!isServerVoiceLocalCameraActive(activeConvId);
      logServerVoiceDebug("camera.main_button_left_click", {
        conversationId: activeConvId || null,
        triggerReason: "server_voice_camera_main_button_left_click",
        callerFunction: "cameraMainButtonHandler",
        buttonId,
        localCameraActive: wasActive,
      });
      callCameraToggleInFlight = true;
      try {
        const nextActive = await toggleServerVoiceCamera(activeConvId, {
          triggerReason: "server_voice_camera_main_button_left_click",
        });
        logServerVoiceDebug("camera.quick_toggle_triggered", {
          conversationId: activeConvId || null,
          triggerReason: "server_voice_camera_main_button_left_click",
          callerFunction: "cameraMainButtonHandler",
          buttonId,
          localCameraActiveBeforeToggle: wasActive,
          localCameraActiveAfterToggle: !!nextActive,
        });
      } catch (error) {
        const errorText = String(error?.message || error || "Failed to toggle camera.").trim() || "Failed to toggle camera.";
        setCallStatus(errorText, true);
        setTimeout(() => {
          if (isServerVoiceTransportSessionActive(activeConvId)) {
            setCallStatus("", false);
          }
        }, 2200);
      } finally {
        callCameraToggleInFlight = false;
      }
      return;
    }
    callCameraToggleInFlight = true;
    try {
      await toggleCamera();
    } finally {
      callCameraToggleInFlight = false;
    }
  };

  const cameraMenuButtonHandler = (ev) => {
    if (ev.defaultPrevented) return;
    const activeConvId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
    const isServerVoiceCameraMode = !!(activeConvId && shouldUseServerVoiceLiveKitTransport(activeConvId));
    if (!isServerVoiceCameraMode) return;
    ev.preventDefault();
    ev.stopPropagation();
    const targetEl = ev.currentTarget instanceof HTMLElement ? ev.currentTarget : null;
    const targetId = String(targetEl?.id || "").trim() || "unknown";
    const isRightClick = ev.type === "contextmenu";
    const isArrowButton = targetId === "btnCameraStageMenu" || targetId === "btnCameraSmallMenu";
    const localCameraActive = !!isServerVoiceLocalCameraActive(activeConvId);
    if (isRightClick) {
      logServerVoiceDebug("camera.main_button_right_click", {
        conversationId: activeConvId || null,
        triggerReason: "server_voice_camera_main_button_right_click",
        callerFunction: "cameraMenuButtonHandler",
        buttonId: targetId,
        localCameraActive,
      });
    }
    if (!isRightClick && !isArrowButton) return;
    void openCameraMenuFromAnchor(targetEl, {
      triggerReason: isRightClick
        ? "server_voice_camera_main_button_right_click"
        : "server_voice_camera_arrow_click",
      callerFunction: "cameraMenuButtonHandler",
      source: isRightClick ? "main_button_right_click" : "camera_arrow_click",
    }).catch(() => {});
  };

  const shareMenuButtonHandler = (ev) => {
    if (ev.defaultPrevented) return;
    const activeConvId = normId(callConversationId || activeDmId || state.activeDm?.conversationId || "");
    const isServerVoiceScreenshareMode = !!(activeConvId && shouldUseServerVoiceLiveKitTransport(activeConvId));
    if (isServerVoiceScreenshareMode) {
      ev.preventDefault();
      ev.stopPropagation();
      const targetEl = ev.currentTarget instanceof HTMLElement ? ev.currentTarget : null;
      const targetId = String(targetEl?.id || "").trim() || "unknown";
      const isRightClick = ev.type === "contextmenu";
      const isArrowButton = targetId === "btnShareScreenStageMenu" || targetId === "btnShareScreenSmallMenu";
      const localShareActive = !!isServerVoiceLocalScreenshareActive(activeConvId);
      if (isRightClick) {
        logServerVoiceDebug("screenshare.main_button_right_click", {
          conversationId: activeConvId || null,
          triggerReason: "server_voice_main_button_right_click",
          callerFunction: "shareMenuButtonHandler",
          buttonId: targetId,
          localShareActive,
        });
      }
      const shouldOpenContextMenu = isRightClick || isArrowButton;
      if (shouldOpenContextMenu) {
        openShareMenuFromAnchor(targetEl, {
          triggerReason: isRightClick
            ? "server_voice_main_button_right_click"
            : "server_voice_share_arrow_click",
          callerFunction: "shareMenuButtonHandler",
          logContextMenuOpen: true,
          source: isRightClick ? "main_button_right_click" : "share_arrow_click",
          clientPoint: isRightClick ? { x: ev.clientX, y: ev.clientY } : null,
        });
        return;
      }
      void openServerVoiceScreenshareFullPicker(activeConvId, {
        triggerReason: "server_voice_share_menu_button",
        callerFunction: "shareMenuButtonHandler",
      }).catch((error) => {
        const errorText = String(error?.message || error || "Unable to open stream picker.").trim() || "Unable to open stream picker.";
        setCallStatus(errorText, true);
        setTimeout(() => setCallStatus("", false), 2200);
      });
      return;
    }
    if (!isScreenSharing) return;
    ev.preventDefault();
    ev.stopPropagation();
    const anchor = ev.currentTarget instanceof HTMLElement ? ev.currentTarget : null;
    openShareMenuFromAnchor(anchor, {
      triggerReason: "share_menu_button",
      callerFunction: "shareMenuButtonHandler",
      clientPoint: ev.type === "contextmenu" ? { x: ev.clientX, y: ev.clientY } : null,
    });
  };

  btnShareScreen?.addEventListener("click", shareHandler);
  btnShareScreenStage?.addEventListener("click", shareHandler);
  btnShareScreenSmall?.addEventListener("click", shareHandler);
  btnShareScreenStageMenu?.addEventListener("click", shareMenuButtonHandler);
  btnShareScreenSmallMenu?.addEventListener("click", shareMenuButtonHandler);
  btnShareScreen?.addEventListener("contextmenu", shareMenuButtonHandler);
  btnShareScreenStage?.addEventListener("contextmenu", shareMenuButtonHandler);
  btnShareScreenSmall?.addEventListener("contextmenu", shareMenuButtonHandler);
  btnShareScreenStageMenu?.addEventListener("contextmenu", shareMenuButtonHandler);
  btnShareScreenSmallMenu?.addEventListener("contextmenu", shareMenuButtonHandler);
  btnCamera?.addEventListener("click", cameraMainButtonHandler);
  btnCameraStage?.addEventListener("click", cameraMainButtonHandler);
  btnCameraSmall?.addEventListener("click", cameraMainButtonHandler);
  btnCamera?.addEventListener("contextmenu", cameraMenuButtonHandler);
  btnCameraStage?.addEventListener("contextmenu", cameraMenuButtonHandler);
  btnCameraSmall?.addEventListener("contextmenu", cameraMenuButtonHandler);
  btnCameraStageMenu?.addEventListener("click", cameraMenuButtonHandler);
  btnCameraSmallMenu?.addEventListener("click", cameraMenuButtonHandler);
  btnCameraStageMenu?.addEventListener("contextmenu", cameraMenuButtonHandler);
  btnCameraSmallMenu?.addEventListener("contextmenu", cameraMenuButtonHandler);
  btnFullscreenStage?.addEventListener("click", (ev) => {
    ev.stopPropagation();
    toggleViewportFullscreen();
  });
  if (!callPictureInPictureBound) {
    callPictureInPictureBound = true;
    [remoteVideo, remoteThumb, remoteAuxThumb, remoteGridVideo, remoteAuxGridVideo].forEach((videoEl) => {
      bindCallPictureInPictureVideoEvents(videoEl);
    });
  }

  const openVoiceAudioMenuHandler = async (ev) => {
    if (ev.defaultPrevented) return;
    if (!inCall) return;
    ev.preventDefault();
    ev.stopPropagation();
    closeCallAudioMenu();
    closeCallShareMenu();
    closeCallCameraMenu();
    closeServerVoiceMemberMenu();
    const convId = normId(callConversationId || activeDmId || "");
    const target = eventTargetElement(ev);
    const tileIntent = logStageContextMenuTileTypeResolved(
      normalizeStageContextMenuIntent(
        resolveStageContextMenuTileIntent(target, {
          fallbackMode: REMOTE_AUDIO_TYPE_VOICE,
        }),
        {
          fallbackParticipantId: normId(target?.closest?.("[data-call-user-id]")?.getAttribute?.("data-call-user-id") || ""),
          fallbackTileType: "primary",
          fallbackMediaType: "voice",
          fallbackTrackIdentity: normId(
            target?.closest?.("[data-call-track-identity], [data-call-video-track-id]")?.getAttribute?.("data-call-track-identity")
            || target?.closest?.("[data-call-track-identity], [data-call-video-track-id]")?.getAttribute?.("data-call-video-track-id")
            || ""
          ),
        }
      ),
      {
        triggerReason: "stage_voice_contextmenu",
        callerFunction: "bindCallUIButtons.openVoiceAudioMenuHandler",
        menuTarget: "stage_tile",
      }
    );
    if (tileIntent.tileType === "screenshare") {
      const openedStreamMenu = openCallAudioMenuAt(ev.clientX, ev.clientY, REMOTE_AUDIO_TYPE_SHARE, {
        ...tileIntent,
        conversationId: convId,
        streamOwnerId: tileIntent.participantId,
        activeShareOwnerId: normId(target?.closest?.("[data-call-active-share-owner-id]")?.getAttribute?.("data-call-active-share-owner-id") || ""),
      });
      if (!openedStreamMenu) {
        logContextMenuRoutingFailed({
          tileId: tileIntent.tileId,
          tileType: tileIntent.tileType,
          participantId: tileIntent.participantId,
          isOwner: !!(tileIntent.participantId && state.user?.id && normId(tileIntent.participantId) === normId(state.user?.id)),
          clientX: ev.clientX,
          clientY: ev.clientY,
          menuType: "stream_menu",
          reason: "stream_menu_not_opened",
          callerFunction: "bindCallUIButtons.openVoiceAudioMenuHandler",
        });
      }
      return;
    }
    const sid = resolveServerVoiceServerIdByConversation(convId);
    if (sid) {
      await fetchServerMembersForSidebar(sid, { force: false }).catch(() => {});
      await ensureServerRolePermissionCache(sid, { force: false }).catch(() => {});
    }
    const inSelfTile = !!(
      target
      && [tileSelf, tileSelfAux, gridSelf, gridSelfAux].some((el) => el && (el === target || el.contains?.(target)))
    );
    const tileTargetUserId = normId(target?.closest?.("[data-call-user-id]")?.getAttribute?.("data-call-user-id") || "");
    const tileTargetLabel = String(target?.closest?.("[data-call-user-label]")?.getAttribute?.("data-call-user-label") || "").trim();
    const focusedUserId = normId(stageFocus === "member" ? stageFocusMemberId : "");
    const remoteFallbackUserId = inSelfTile ? "" : normId(callMediaPeerUserId || callOtherUserId || "");
    const moderationTargetUserId = tileIntent.participantId || tileTargetUserId || focusedUserId || remoteFallbackUserId;
    const openedModerationMenu = tryOpenServerVoiceMemberMenuAt(moderationTargetUserId, convId, {
      x: ev.clientX,
      y: ev.clientY,
    }, {
      displayName: tileTargetLabel,
      tileId: tileIntent.tileId,
      tileType: tileIntent.tileType,
      mediaType: tileIntent.mediaType,
      isLocalUser: tileIntent.isLocalUser,
    });
    if (openedModerationMenu) return;
    const openedVoiceMenu = openCallAudioMenuAt(ev.clientX, ev.clientY, REMOTE_AUDIO_TYPE_VOICE, {
      ...tileIntent,
      conversationId: convId,
    });
    if (!openedVoiceMenu) {
      logContextMenuRoutingFailed({
        tileId: tileIntent.tileId,
        tileType: tileIntent.tileType,
        participantId: tileIntent.participantId,
        isOwner: false,
        clientX: ev.clientX,
        clientY: ev.clientY,
        menuType: "participant_audio_menu",
        reason: "voice_audio_menu_not_opened",
        callerFunction: "bindCallUIButtons.openVoiceAudioMenuHandler",
      });
    }
  };
  const openShareAudioMenuHandler = (ev) => {
    if (ev.defaultPrevented) return;
    if (!inCall) return;
    ev.preventDefault();
    ev.stopPropagation();
    closeCallAudioMenu();
    closeCallShareMenu();
    closeCallCameraMenu();
    closeServerVoiceMemberMenu();
    const target = eventTargetElement(ev);
    const tileIntent = logStageContextMenuTileTypeResolved(
      normalizeStageContextMenuIntent(
        resolveStageContextMenuTileIntent(target, {
          fallbackMode: REMOTE_AUDIO_TYPE_SHARE,
        }),
        {
          fallbackParticipantId: normId(target?.closest?.("[data-call-user-id]")?.getAttribute?.("data-call-user-id") || ""),
          fallbackTileType: "screenshare",
          fallbackMediaType: "screenshare",
          fallbackTrackIdentity: normId(
            target?.closest?.("[data-call-track-identity], [data-call-video-track-id]")?.getAttribute?.("data-call-track-identity")
            || target?.closest?.("[data-call-track-identity], [data-call-video-track-id]")?.getAttribute?.("data-call-video-track-id")
            || ""
          ),
        }
      ),
      {
        triggerReason: "stage_share_contextmenu",
        callerFunction: "bindCallUIButtons.openShareAudioMenuHandler",
        menuTarget: "stage_tile",
      }
    );
    if (tileIntent.tileType === "screenshare") {
      const convId = normId(callConversationId || activeDmId || "");
      const openedStreamMenu = openCallAudioMenuAt(ev.clientX, ev.clientY, REMOTE_AUDIO_TYPE_SHARE, {
        ...tileIntent,
        conversationId: convId,
        streamOwnerId: tileIntent.participantId,
        activeShareOwnerId: normId(target?.closest?.("[data-call-active-share-owner-id]")?.getAttribute?.("data-call-active-share-owner-id") || ""),
      });
      if (!openedStreamMenu) {
        logContextMenuRoutingFailed({
          tileId: tileIntent.tileId,
          tileType: tileIntent.tileType,
          participantId: tileIntent.participantId,
          isOwner: !!(tileIntent.participantId && state.user?.id && normId(tileIntent.participantId) === normId(state.user?.id)),
          clientX: ev.clientX,
          clientY: ev.clientY,
          menuType: "stream_menu",
          reason: "stream_menu_not_opened",
          callerFunction: "bindCallUIButtons.openShareAudioMenuHandler",
        });
      }
      return;
    }
    const convId = normId(callConversationId || activeDmId || "");
    const tileTargetLabel = String(target?.closest?.("[data-call-user-label]")?.getAttribute?.("data-call-user-label") || "").trim();
    const openedModerationMenu = tryOpenServerVoiceMemberMenuAt(tileIntent.participantId, convId, {
      x: ev.clientX,
      y: ev.clientY,
    }, {
      displayName: tileTargetLabel,
      tileId: tileIntent.tileId,
      tileType: tileIntent.tileType,
      mediaType: tileIntent.mediaType,
      isLocalUser: tileIntent.isLocalUser,
    });
    if (openedModerationMenu) return;
    const openedVoiceMenu = openCallAudioMenuAt(ev.clientX, ev.clientY, REMOTE_AUDIO_TYPE_VOICE, {
      ...tileIntent,
      conversationId: convId,
    });
    if (!openedVoiceMenu) {
      logContextMenuRoutingFailed({
        tileId: tileIntent.tileId,
        tileType: tileIntent.tileType,
        participantId: tileIntent.participantId,
        isOwner: false,
        clientX: ev.clientX,
        clientY: ev.clientY,
        menuType: "participant_audio_menu",
        reason: "voice_audio_menu_not_opened",
        callerFunction: "bindCallUIButtons.openShareAudioMenuHandler",
      });
    }
  };
  [
    tileRemote,
    tileRemoteAux,
    gridRemote,
    gridRemoteAux,
    stagePlaceholder,
    stageAvatar,
    stageLabel,
    remoteTileAvatar,
    remoteAuxTileAvatar,
    remoteTileLabel,
    remoteAuxTileLabel,
    remoteGridAvatar,
    remoteAuxGridAvatar,
    remoteGridLabel,
    remoteAuxGridLabel,
  ].forEach((el) => {
    el?.addEventListener("contextmenu", openVoiceAudioMenuHandler);
  });
  [
    remoteVideo,
    remoteThumb,
    remoteAuxThumb,
    remoteGridVideo,
    remoteAuxGridVideo,
    remoteWatchGate,
    remoteWatchPreview,
  ].forEach((el) => {
    el?.addEventListener("contextmenu", openShareAudioMenuHandler);
  });

  btnWatchRemoteStream?.addEventListener("click", (ev) => {
    ev.stopPropagation();
    const convId = normId(callConversationId || activeDmId || "");
    if (!convId) return;
    startWatchingRemoteShare(convId);
  });

  const handleFixedStageTileClick = (ev, {
    target = "remote",
    slot = "primary",
    allowWatchPrompt = false,
    syncRemote = false,
    syncLocal = false,
    source = "fixed_stage_tile",
  } = {}) => {
    ev?.preventDefault?.();
    ev?.stopPropagation?.();
    const targetEl = ev?.currentTarget instanceof HTMLElement ? ev.currentTarget : null;
    const identity = getStageTileIdentityFromEl(targetEl);
    const participantId = normId(identity.participantId || resolveStageParticipantIdForFocusTarget(target, slot));
    const tileType = normalizeStageTileType(identity.tileType || resolveStageTileTypeForFocusTarget(target, slot));
    const tileId = String(identity.tileId || buildStageParticipantTileId(participantId, tileType)).trim();
    logStageTileEvent("stage.tile_clicked", {
      tileId,
      tileType,
      participantId,
      triggerReason: source,
      callerFunction: "bindCallUIButtons.handleFixedStageTileClick",
    });
    const convId = normId(callConversationId || activeDmId || "");
    if (allowWatchPrompt && isRemoteShareWatchPromptActive(convId)) {
      logStageTileEvent("stage.focus_target", {
        tileId,
        tileType,
        participantId,
        triggerReason: `${source}_watch_prompt`,
        callerFunction: "bindCallUIButtons.handleFixedStageTileClick",
        action: "watch_stream",
      });
      startWatchingRemoteShare(convId);
      return;
    }
    logStageTileEvent("stage.focus_target", {
      tileId,
      tileType,
      participantId,
      triggerReason: `${source}_focus`,
      callerFunction: "bindCallUIButtons.handleFixedStageTileClick",
    });
    const sameTileAlreadyFocused = !!(
      stageLayoutMode === "focus"
      && stageFocusedTileId
      && tileId
      && stageFocusedTileId === tileId
    );
    if (sameTileAlreadyFocused) {
      logStageTileEvent("stage.focus_click_ignored_same_tile", {
        tileId,
        tileType,
        participantId,
        triggerReason: `${source}_focus`,
        callerFunction: "bindCallUIButtons.handleFixedStageTileClick",
        layoutMode: stageLayoutMode,
      });
      if (tileType === "screenshare") {
        const tileVideoEl = targetEl?.querySelector(".stageGridVideo, .participantVideo");
        const hasExistingVideoElement = !!(
          tileVideoEl?.srcObject
          && !!getAnyVideoTrackFromStream(tileVideoEl.srcObject || null)
        );
        const trackIdentity = normId(
          targetEl?.getAttribute?.("data-call-video-track-id")
          || targetEl?.getAttribute?.("data-call-track-identity")
          || ""
        );
        logScreenshareTileRenderEvent("screenshare.focus_rerender_skipped_same_track", {
          tileId,
          participantId,
          trackIdentity,
          activeShareOwnerId: normId(targetEl?.getAttribute?.("data-call-active-share-owner-id") || ""),
          renderReason: `${source}_same_tile_click`,
          hasExistingVideoElement,
          fallbackReason: "focus_click_same_tile_noop",
        });
        logScreenshareTileRenderEvent("screenshare.focus_attach_preserved", {
          tileId,
          participantId,
          trackIdentity,
          activeShareOwnerId: normId(targetEl?.getAttribute?.("data-call-active-share-owner-id") || ""),
          renderReason: `${source}_same_tile_click`,
          hasExistingVideoElement,
          fallbackReason: "focus_click_same_tile_noop",
        });
      }
      return;
    }
    const transitionSerial = beginStageFocusTransition({
      tileId,
      tileType,
      participantId,
      nextLayoutMode: "focus",
      triggerReason: `${source}_focus`,
      callerFunction: "bindCallUIButtons.handleFixedStageTileClick",
    });
    const focusChanged = toggleFocusParticipant(target, slot, {
      tileId,
      tileType,
      participantId,
      triggerReason: `${source}_focus`,
      callerFunction: "bindCallUIButtons.handleFixedStageTileClick",
    });
    if (!focusChanged) {
      completeStageFocusTransition({
        transitionSerial,
        tileId,
        tileType,
        participantId,
        triggerReason: `${source}_focus_noop`,
        callerFunction: "bindCallUIButtons.handleFixedStageTileClick",
      });
      return;
    }
    if (syncRemote) syncRemoteVideoFromPeer();
    if (syncLocal) setLocalSharePreviewStream(getPreferredLocalPreviewStream());
    refreshCallUI();
    completeStageFocusTransition({
      transitionSerial,
      tileId,
      tileType,
      participantId,
      triggerReason: `${source}_focus`,
      callerFunction: "bindCallUIButtons.handleFixedStageTileClick",
    });
    assertStageFocusMatchesClickedTile({
      tileId,
      tileType,
      participantId,
      triggerReason: `${source}_post_refresh`,
      callerFunction: "bindCallUIButtons.handleFixedStageTileClick",
    });
  };

  tileRemote?.addEventListener("click", (ev) => {
    handleFixedStageTileClick(ev, {
      target: "remote",
      slot: "primary",
      allowWatchPrompt: true,
      syncRemote: true,
      source: "tile_remote_primary_click",
    });
  });
  tileRemoteAux?.addEventListener("click", (ev) => {
    handleFixedStageTileClick(ev, {
      target: "remote",
      slot: "aux",
      syncRemote: true,
      source: "tile_remote_aux_click",
    });
  });
  tileSelf?.addEventListener("click", (ev) => {
    handleFixedStageTileClick(ev, {
      target: "self",
      slot: "primary",
      syncLocal: true,
      source: "tile_self_primary_click",
    });
  });
  tileSelfAux?.addEventListener("click", (ev) => {
    handleFixedStageTileClick(ev, {
      target: "self",
      slot: "aux",
      syncLocal: true,
      source: "tile_self_aux_click",
    });
  });
  gridRemote?.addEventListener("click", (ev) => {
    handleFixedStageTileClick(ev, {
      target: "remote",
      slot: "primary",
      allowWatchPrompt: true,
      syncRemote: true,
      source: "grid_remote_primary_click",
    });
  });
  gridRemoteAux?.addEventListener("click", (ev) => {
    handleFixedStageTileClick(ev, {
      target: "remote",
      slot: "aux",
      syncRemote: true,
      source: "grid_remote_aux_click",
    });
  });
  gridSelf?.addEventListener("click", (ev) => {
    handleFixedStageTileClick(ev, {
      target: "self",
      slot: "primary",
      syncLocal: true,
      source: "grid_self_primary_click",
    });
  });
  gridSelfAux?.addEventListener("click", (ev) => {
    handleFixedStageTileClick(ev, {
      target: "self",
      slot: "aux",
      syncLocal: true,
      source: "grid_self_aux_click",
    });
  });

  stageViewport?.addEventListener("contextmenu", (ev) => {
    if (ev.defaultPrevented) return;
    if (!inCall) return;
    if (stageLayoutMode !== "focus") return;
    const target = eventTargetElement(ev);
    const blockedByControl = !!target?.closest?.(
      "#btnFullscreenStage, .callStageViewportFsBtn, .callStageControls, .callStageTop, .callStageTopActions, .serverVoiceDebugOverlay, .callWatchBtn, #btnWatchRemoteStream"
    );
    if (blockedByControl) return;
    const withinTile = !!target?.closest?.(".participantTile, .stageGridTile");
    if (withinTile) return;
    const focusedIdentity = parseStageParticipantTileId(stageFocusedTileId || "");
    if (!focusedIdentity.tileId) {
      logContextMenuRoutingFailed({
        tileId: "",
        tileType: "",
        participantId: "",
        isOwner: false,
        clientX: ev.clientX,
        clientY: ev.clientY,
        menuType: "focused_stage_context_menu",
        reason: "focused_stage_missing_tile_identity",
        callerFunction: "bindCallUIButtons.stageViewport.contextmenu",
      });
      return;
    }
    openShareAudioMenuHandler(ev);
  });

  stageViewport?.addEventListener("click", (ev) => {
    const target = eventTargetElement(ev);
    const clickedInteractiveInsideTile = !!target?.closest?.(
      ".participantTile, .stageGridTile, .callTileWatchCta, .callTileLoadingCta, #btnFullscreenStage, .callStageViewportFsBtn, #remoteWatchGate, .callWatchBtn"
    );
    if (clickedInteractiveInsideTile) return;
    // Clicar no palco em destaque volta para grelha (2 pessoas), com ou sem vÃ­deo.
    if (stageLayoutMode === "focus") {
      const focusedIdentity = parseStageParticipantTileId(stageFocusedTileId || "");
      const transitionSerial = beginStageFocusTransition({
        tileId: stageFocusedTileId || focusedIdentity.tileId,
        tileType: focusedIdentity.tileType || "primary",
        participantId: focusedIdentity.participantId || "",
        nextLayoutMode: "grid",
        triggerReason: "stage_viewport_background_click",
        callerFunction: "bindCallUIButtons.stageViewport.onclick",
      });
      stageLayoutMode = "grid";
      refreshCallUI();
      completeStageFocusTransition({
        transitionSerial,
        tileId: stageFocusedTileId || focusedIdentity.tileId,
        tileType: focusedIdentity.tileType || "primary",
        participantId: focusedIdentity.participantId || "",
        triggerReason: "stage_viewport_background_click",
        callerFunction: "bindCallUIButtons.stageViewport.onclick",
      });
    }
  });

  document.addEventListener("fullscreenchange", refreshCallUI);
  window.addEventListener("resize", () => {
    syncCallStageGridLayoutAttrs();
    syncCallFocusStageLayoutAttrs();
  });

  dmStageResizeGrip?.addEventListener("pointerdown", (ev) => {
    if (!ev.isPrimary) return;
    dmStageResizeActive = true;
    dmStageResizeStartY = ev.clientY;
    dmStageResizeStartVh = getDmStageHeightVhValue();
    dmStageResizeGrip.setPointerCapture?.(ev.pointerId);
    ev.preventDefault();
  });

  const onResizeMove = (ev) => {
    if (!dmStageResizeActive) return;
    const deltaPx = ev.clientY - dmStageResizeStartY;
    const viewportPx = Math.max(window.innerHeight, 1);
    const deltaVh = (deltaPx / viewportPx) * 100;
    setDmStageHeightVh(dmStageResizeStartVh + deltaVh);
    refreshCallUI();
  };
  const stopResize = (ev) => {
    if (!dmStageResizeActive) return;
    dmStageResizeActive = false;
    if (ev?.pointerId != null) {
      dmStageResizeGrip?.releasePointerCapture?.(ev.pointerId);
    }
  };
  window.addEventListener("pointermove", onResizeMove);
  window.addEventListener("pointerup", stopResize);
  window.addEventListener("pointercancel", stopResize);
}

/* ========================= AVATAR EDITOR (integrado) ========================= */
const AE = {
  img: null,
  scale: 1,
  minScale: 1,
  maxScale: 3,
  ox: 0,
  oy: 0,
  dragging: false,
  drag: { x: 0, y: 0, ox: 0, oy: 0 },
  user: null,
  ext: "png",
  isGif: false,
  sourceFile: null,
  previewUrl: "",
  _dragBound: false,
};
const BE = {
  img: null,
  scale: 1,
  minScale: 1,
  maxScale: 3,
  ox: 0,
  oy: 0,
  dragging: false,
  drag: { x: 0, y: 0, ox: 0, oy: 0 },
  user: null,
  ext: "png",
  isGif: false,
  sourceFile: null,
  previewUrl: "",
  cropRatio: 4, // 4:1
  _dragBound: false,
};

function clearEditorAnimatedPreview(stateObj) {
  if (!stateObj || typeof stateObj !== "object") return;
  safeRevokeObjectUrl(stateObj.previewUrl || "");
  stateObj.previewUrl = "";
  stateObj.sourceFile = null;
  stateObj.isGif = false;
}

function ensureEditorGifUi(prefix = "avatar") {
  const canvas = document.getElementById(`${prefix}EditorCanvas`);
  const wrap = canvas?.parentElement || null;
  let viewport = document.getElementById(`${prefix}EditorGifViewport`);
  if (!viewport && wrap) {
    viewport = document.createElement("div");
    viewport.id = `${prefix}EditorGifViewport`;
    viewport.className = "editorGifViewport";
    viewport.hidden = true;
    wrap.appendChild(viewport);
  }
  let preview = document.getElementById(`${prefix}EditorGifPreview`);
  if (!preview && viewport) {
    preview = document.createElement("img");
    preview.id = `${prefix}EditorGifPreview`;
    preview.className = "editorGifPreview";
    preview.alt = "";
    preview.hidden = true;
    viewport.appendChild(preview);
  } else if (preview && viewport && preview.parentElement !== viewport) {
    viewport.appendChild(preview);
  }

  const resetBtn = document.getElementById(`${prefix}EditorReset`);
  const applyBtn = document.getElementById(`${prefix}EditorApply`);
  const controlsRow = resetBtn?.parentElement || applyBtn?.parentElement || null;
  let hint = document.getElementById(`${prefix}EditorGifHint`);
  if (!hint && controlsRow?.parentElement) {
    hint = document.createElement("div");
    hint.id = `${prefix}EditorGifHint`;
    hint.className = "editorGifHint";
    hint.hidden = true;
    controlsRow.insertAdjacentElement("afterend", hint);
  }

  const zoom = document.getElementById(`${prefix}EditorZoom`);
  const ring = prefix === "avatar"
    ? (canvas?.parentElement?.querySelector?.(".avatar-editor__ring") || null)
    : null;

  return {
    wrap,
    viewport,
    canvas,
    preview,
    hint,
    zoom,
    resetBtn,
    applyBtn,
    ring,
  };
}

function setEditorGifMode(prefix = "avatar", enabled = false, {
  previewUrl = "",
  label = "",
  hintText = "",
} = {}) {
  const ui = ensureEditorGifUi(prefix);
  if (!ui.wrap) return;

  ui.wrap.classList.toggle("is-gif-mode", !!enabled);
  if (prefix === "avatar") ui.wrap.classList.toggle("is-avatar-gif-mode", !!enabled);
  if (ui.viewport) {
    ui.viewport.hidden = !enabled;
    ui.viewport.style.display = enabled ? "block" : "none";
  }
  if (ui.preview) {
    ui.preview.hidden = !enabled;
    ui.preview.style.display = enabled ? "block" : "none";
    if (enabled && previewUrl) {
      ui.preview.src = previewUrl;
      ui.preview.alt = label || `${prefix} preview`;
    } else {
      ui.preview.removeAttribute("src");
      ui.preview.alt = "";
      ui.preview.removeAttribute("style");
      ui.preview.style.display = "none";
    }
  }
  if (ui.canvas) {
    ui.canvas.hidden = false;
    ui.canvas.style.display = "block";
    ui.canvas.style.visibility = enabled ? "hidden" : "visible";
    ui.canvas.style.pointerEvents = enabled ? "none" : "";
  }
  if (ui.hint) {
    ui.hint.hidden = !enabled;
    ui.hint.textContent = enabled
      ? (hintText || "Os GIFs mantem a animacao e sao enviados sem crop.")
      : "";
  }
  if (ui.ring) ui.ring.hidden = false;
}

function clampValue(v, min, max) {
  if (!Number.isFinite(v)) return min;
  if (v < min) return min;
  if (v > max) return max;
  return v;
}

function syncCanvasSize(canvas) {
  const rect = canvas.getBoundingClientRect();
  const dpr = window.devicePixelRatio || 1;
  const targetW = Math.max(1, Math.round(rect.width * dpr));
  const targetH = Math.max(1, Math.round(rect.height * dpr));
  if (canvas.width !== targetW || canvas.height !== targetH) {
    canvas.width = targetW;
    canvas.height = targetH;
  }
  return { cssW: rect.width, cssH: rect.height, dpr };
}

function showAvatarEditor() {
  const m = document.getElementById("avatarEditorModal");
  if (!m) return;
  m.classList.remove("hidden");
  m.setAttribute("aria-hidden", "false");
}

function hideAvatarEditor() {
  const m = document.getElementById("avatarEditorModal");
  if (!m) return;
  m.classList.add("hidden");
  m.setAttribute("aria-hidden", "true");
  setEditorGifMode("avatar", false);
  clearEditorAnimatedPreview(AE);
  AE.img = null;
  AE.user = null;
}

function showBannerEditor() {
  const m = document.getElementById("bannerEditorModal");
  if (!m) return;
  m.classList.remove("hidden");
  m.setAttribute("aria-hidden", "false");
}

function hideBannerEditor() {
  const m = document.getElementById("bannerEditorModal");
  if (!m) return;
  m.classList.add("hidden");
  m.setAttribute("aria-hidden", "true");
  setEditorGifMode("banner", false);
  clearEditorAnimatedPreview(BE);
  BE.img = null;
  BE.user = null;
}

function getAvatarCropMetrics(info) {
  const cx = info.cssW / 2;
  const cy = info.cssH / 2;
  const r = Math.min(info.cssW, info.cssH) * 0.42;
  return {
    cx,
    cy,
    r,
    left: cx - r,
    right: cx + r,
    top: cy - r,
    bottom: cy + r,
    size: r * 2,
  };
}

function clampAvatarOffsets() {
  const canvas = document.getElementById("avatarEditorCanvas");
  const targetEl = (AE.isGif ? ensureEditorGifUi("avatar").wrap : canvas) || canvas;
  if (!targetEl || !AE.img) return;

  const info = AE.isGif
    ? (() => {
      const rect = targetEl.getBoundingClientRect();
      return { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height), dpr: window.devicePixelRatio || 1 };
    })()
    : syncCanvasSize(targetEl);
  const crop = getAvatarCropMetrics(info);
  const iw = AE.img.naturalWidth || AE.img.width;
  const ih = AE.img.naturalHeight || AE.img.height;

  const requiredScale = Math.max(crop.size / iw, crop.size / ih);
  if (AE.scale < requiredScale) AE.scale = requiredScale;
  if (AE.minScale < requiredScale) AE.minScale = requiredScale;

  const w = iw * AE.scale;
  const h = ih * AE.scale;
  const minOx = crop.right - w;
  const maxOx = crop.left;
  const minOy = crop.bottom - h;
  const maxOy = crop.top;

  AE.ox = clampValue(AE.ox, minOx, maxOx);
  AE.oy = clampValue(AE.oy, minOy, maxOy);
}

function fitToCover() {
  const canvas = document.getElementById("avatarEditorCanvas");
  const targetEl = (AE.isGif ? ensureEditorGifUi("avatar").wrap : canvas) || canvas;
  if (!targetEl || !AE.img) return;

  const info = AE.isGif
    ? (() => {
      const rect = targetEl.getBoundingClientRect();
      return { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height), dpr: window.devicePixelRatio || 1 };
    })()
    : syncCanvasSize(targetEl);
  const cw = info.cssW, ch = info.cssH;
  const iw = AE.img.naturalWidth || AE.img.width;
  const ih = AE.img.naturalHeight || AE.img.height;
  const crop = getAvatarCropMetrics(info);
  const cover = Math.max(crop.size / iw, crop.size / ih);

  AE.scale = cover;
  AE.minScale = cover;
  AE.maxScale = cover * 4;
  AE.ox = crop.cx - (iw * AE.scale) / 2;
  AE.oy = crop.cy - (ih * AE.scale) / 2;
  clampAvatarOffsets();

  const zoom = document.getElementById("avatarEditorZoom");
  if (zoom) {
    zoom.min = String(AE.minScale);
    zoom.max = String(AE.maxScale);
    zoom.step = "0.001";
    zoom.value = String(AE.scale);
  }
}

function drawAvatarEditor() {
  const canvas = document.getElementById("avatarEditorCanvas");
  if (!canvas) return;
  if (!AE.img) return;
  if (AE.isGif) {
    const ui = ensureEditorGifUi("avatar");
    const host = ui.wrap;
    const viewport = ui.viewport;
    const preview = ui.preview;
    if (!host || !viewport || !preview) return;
    const rect = host.getBoundingClientRect();
    const crop = getAvatarCropMetrics({ cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height), dpr: window.devicePixelRatio || 1 });
    const iw = AE.img.naturalWidth || AE.img.width;
    const ih = AE.img.naturalHeight || AE.img.height;
    viewport.style.left = `${crop.left}px`;
    viewport.style.top = `${crop.top}px`;
    viewport.style.width = `${crop.size}px`;
    viewport.style.height = `${crop.size}px`;
    preview.style.position = "absolute";
    preview.style.left = `${AE.ox - crop.left}px`;
    preview.style.top = `${AE.oy - crop.top}px`;
    preview.style.width = `${iw * AE.scale}px`;
    preview.style.height = `${ih * AE.scale}px`;
    preview.style.maxWidth = "none";
    preview.style.maxHeight = "none";
    preview.style.objectFit = "fill";
    host.style.setProperty("--avatar-editor-ring-size", `${crop.size}px`);
    return;
  }

  const ctx = canvas.getContext("2d");
  const info = syncCanvasSize(canvas);
  const crop = getAvatarCropMetrics(info);

  ctx.setTransform(info.dpr, 0, 0, info.dpr, 0, 0);
  ctx.clearRect(0, 0, info.cssW, info.cssH);

  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = "high";

  const iw = AE.img.naturalWidth || AE.img.width;
  const ih = AE.img.naturalHeight || AE.img.height;

  ctx.fillStyle = "rgba(0,0,0,0.25)";
  ctx.fillRect(0, 0, info.cssW, info.cssH);

  ctx.save();
  ctx.beginPath();
  ctx.arc(crop.cx, crop.cy, crop.r, 0, Math.PI * 2);
  ctx.closePath();
  ctx.clip();
  ctx.drawImage(AE.img, AE.ox, AE.oy, iw * AE.scale, ih * AE.scale);
  ctx.restore();

  ctx.beginPath();
  ctx.arc(crop.cx, crop.cy, crop.r, 0, Math.PI * 2);
  ctx.strokeStyle = "rgba(255,255,255,0.9)";
  ctx.lineWidth = 4;
  ctx.stroke();
}

function onZoom() {
  const canvas = document.getElementById("avatarEditorCanvas");
  const zoom = document.getElementById("avatarEditorZoom");
  if (!canvas || !zoom) return;

  const newScale = clampValue(parseFloat(zoom.value), AE.minScale, AE.maxScale);
  const oldScale = AE.scale || newScale;
  if (!Number.isFinite(newScale) || newScale <= 0 || !Number.isFinite(oldScale) || oldScale <= 0) return;

  const info = AE.isGif
    ? (() => {
      const rect = (ensureEditorGifUi("avatar").wrap || canvas).getBoundingClientRect();
      return { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height), dpr: window.devicePixelRatio || 1 };
    })()
    : syncCanvasSize(canvas);
  const crop = getAvatarCropMetrics(info);
  const cx = crop.cx;
  const cy = crop.cy;

  AE.ox = cx - (cx - AE.ox) * (newScale / oldScale);
  AE.oy = cy - (cy - AE.oy) * (newScale / oldScale);
  AE.scale = newScale;
  clampAvatarOffsets();

  zoom.value = String(AE.scale);
  drawAvatarEditor();
}

function bindDrag() {
  const canvas = document.getElementById("avatarEditorCanvas");
  const surface = canvas?.parentElement || ensureEditorGifUi("avatar").wrap || null;
  if (!surface || AE._dragBound) return;
  AE._dragBound = true;

  const getPoint = (ev) => {
    const rect = surface.getBoundingClientRect();
    const clientX = ev.touches ? ev.touches[0].clientX : ev.clientX;
    const clientY = ev.touches ? ev.touches[0].clientY : ev.clientY;
    return { x: clientX - rect.left, y: clientY - rect.top };
  };

  const onDown = (ev) => {
    AE.dragging = true;
    const p = getPoint(ev);
    AE.drag.x = p.x; AE.drag.y = p.y;
    AE.drag.ox = AE.ox; AE.drag.oy = AE.oy;
  };

  const onMove = (ev) => {
    if (!AE.dragging) return;
    const p = getPoint(ev);
    AE.ox = AE.drag.ox + (p.x - AE.drag.x);
    AE.oy = AE.drag.oy + (p.y - AE.drag.y);
    clampAvatarOffsets();
    drawAvatarEditor();
  };

  const onUp = () => { AE.dragging = false; };

  surface.addEventListener("mousedown", onDown);
  window.addEventListener("mousemove", onMove);
  window.addEventListener("mouseup", onUp);

  surface.addEventListener("touchstart", onDown, { passive: true });
  window.addEventListener("touchmove", onMove, { passive: true });
  window.addEventListener("touchend", onUp);
}

function fileToDataURL(file) {
  return new Promise((res, rej) => {
    const r = new FileReader();
    r.onload = () => res(r.result);
    r.onerror = () => rej(new Error("FileReader falhou"));
    r.readAsDataURL(file);
  });
}

function loadImageFromUrl(url) {
  return new Promise((res, rej) => {
    const img = new Image();
    img.onload = () => res(img);
    img.onerror = () => rej(new Error("Nao consegui ler a imagem"));
    img.src = String(url || "");
  });
}

async function loadImageFromFile(file) {
  const dataUrl = await fileToDataURL(file);
  const img = new Image();
  img.src = dataUrl;
  await new Promise((res, rej) => {
    img.onload = () => res();
    img.onerror = () => rej(new Error("Nao consegui ler a imagem"));
  });
  return img;
}

async function openAvatarEditor(file, user, { gifMode = false } = {}) {
  clearEditorAnimatedPreview(AE);
  AE.user = user;
  AE.ext = (file.name.split(".").pop() || "png").toLowerCase();
  AE.isGif = !!gifMode;
  AE.sourceFile = file || null;
  if (AE.isGif) {
    AE.ext = "gif";
    AE.img = null;
    try { AE.previewUrl = URL.createObjectURL(file); } catch (_) { AE.previewUrl = ""; }
    AE.img = await loadImageFromUrl(AE.previewUrl);
    setEditorGifMode("avatar", true, {
      previewUrl: AE.previewUrl,
      label: "Avatar GIF",
      hintText: "Os GIFs mantem a animacao e usam o mesmo zoom e drag do editor normal.",
    });
    showAvatarEditor();
    requestAnimationFrame(() => {
      bindDrag();
      fitToCover();
      drawAvatarEditor();
    });
    return;
  }
  if (!/(png|jpg|jpeg|webp)$/i.test(AE.ext)) AE.ext = "png";
  setEditorGifMode("avatar", false);
  AE.img = await loadImageFromFile(file);
  showAvatarEditor();

  requestAnimationFrame(() => {
    bindDrag();
    fitToCover();
    drawAvatarEditor();
  });
}

async function exportAvatarBlob(size = 512) {
  const src = document.getElementById("avatarEditorCanvas");
  if (!src || !AE.img) throw new Error("Editor nÃ£o pronto");
  const rect = src.getBoundingClientRect();
  const info = { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height) };
  const crop = getAvatarCropMetrics(info);

  const out = document.createElement("canvas");
  out.width = size;
  out.height = size;
  const ctx = out.getContext("2d");

  ctx.clearRect(0, 0, size, size);
  ctx.save();
  ctx.beginPath();
  ctx.arc(size / 2, size / 2, size / 2, 0, Math.PI * 2);
  ctx.closePath();
  ctx.clip();

  const iw = AE.img.naturalWidth || AE.img.width;
  const ih = AE.img.naturalHeight || AE.img.height;
  const s = size / crop.size;

  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = "high";
  ctx.drawImage(
    AE.img,
    (AE.ox - crop.left) * s,
    (AE.oy - crop.top) * s,
    iw * AE.scale * s,
    ih * AE.scale * s
  );

  ctx.restore();

  const mime = (AE.ext === "jpg" || AE.ext === "jpeg") ? "image/jpeg" : "image/png";
  return new Promise((res) => out.toBlob((b) => res(b), mime, 0.92));
}

function getBannerCropMetrics(info) {
  const maxW = Math.max(120, info.cssW);
  const maxH = Math.max(80, info.cssH);
  let w = maxW;
  let h = w / BE.cropRatio;
  if (h > maxH) {
    h = maxH;
    w = h * BE.cropRatio;
  }
  const x = (info.cssW - w) / 2;
  const y = (info.cssH - h) / 2;
  return {
    x, y, w, h,
    left: x,
    top: y,
    right: x + w,
    bottom: y + h,
    cx: x + (w / 2),
    cy: y + (h / 2),
  };
}

function clampBannerOffsets() {
  const canvas = document.getElementById("bannerEditorCanvas");
  const targetEl = (BE.isGif ? ensureEditorGifUi("banner").wrap : canvas) || canvas;
  if (!targetEl || !BE.img) return;

  const info = BE.isGif
    ? (() => {
      const rect = targetEl.getBoundingClientRect();
      return { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height), dpr: window.devicePixelRatio || 1 };
    })()
    : syncCanvasSize(targetEl);
  const crop = getBannerCropMetrics(info);
  const iw = BE.img.naturalWidth || BE.img.width;
  const ih = BE.img.naturalHeight || BE.img.height;

  const requiredScale = Math.max(crop.w / iw, crop.h / ih);
  if (BE.scale < requiredScale) BE.scale = requiredScale;
  if (BE.minScale < requiredScale) BE.minScale = requiredScale;

  const w = iw * BE.scale;
  const h = ih * BE.scale;
  const minOx = crop.right - w;
  const maxOx = crop.left;
  const minOy = crop.bottom - h;
  const maxOy = crop.top;

  BE.ox = clampValue(BE.ox, minOx, maxOx);
  BE.oy = clampValue(BE.oy, minOy, maxOy);
}

function fitBannerToCrop() {
  const canvas = document.getElementById("bannerEditorCanvas");
  const targetEl = (BE.isGif ? ensureEditorGifUi("banner").wrap : canvas) || canvas;
  if (!targetEl || !BE.img) return;

  const info = BE.isGif
    ? (() => {
      const rect = targetEl.getBoundingClientRect();
      return { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height), dpr: window.devicePixelRatio || 1 };
    })()
    : syncCanvasSize(targetEl);
  const crop = getBannerCropMetrics(info);
  const iw = BE.img.naturalWidth || BE.img.width;
  const ih = BE.img.naturalHeight || BE.img.height;
  const cover = Math.max(crop.w / iw, crop.h / ih);

  BE.scale = cover;
  BE.minScale = cover;
  BE.maxScale = cover * 4;
  BE.ox = crop.cx - (iw * BE.scale) / 2;
  BE.oy = crop.cy - (ih * BE.scale) / 2;
  clampBannerOffsets();

  const zoom = document.getElementById("bannerEditorZoom");
  if (zoom) {
    zoom.min = String(BE.minScale);
    zoom.max = String(BE.maxScale);
    zoom.step = "0.001";
    zoom.value = String(BE.scale);
  }
}

function roundedRectPath(ctx, x, y, w, h, r) {
  const rr = Math.max(0, Math.min(r, w * 0.5, h * 0.5));
  ctx.beginPath();
  ctx.moveTo(x + rr, y);
  ctx.lineTo(x + w - rr, y);
  ctx.quadraticCurveTo(x + w, y, x + w, y + rr);
  ctx.lineTo(x + w, y + h - rr);
  ctx.quadraticCurveTo(x + w, y + h, x + w - rr, y + h);
  ctx.lineTo(x + rr, y + h);
  ctx.quadraticCurveTo(x, y + h, x, y + h - rr);
  ctx.lineTo(x, y + rr);
  ctx.quadraticCurveTo(x, y, x + rr, y);
  ctx.closePath();
}

function drawBannerEditor() {
  const canvas = document.getElementById("bannerEditorCanvas");
  if (!canvas) return;
  if (!BE.img) return;
  if (BE.isGif) {
    const ui = ensureEditorGifUi("banner");
    const host = ui.wrap;
    const viewport = ui.viewport;
    const preview = ui.preview;
    if (!host || !viewport || !preview) return;
    const rect = host.getBoundingClientRect();
    const crop = getBannerCropMetrics({ cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height), dpr: window.devicePixelRatio || 1 });
    const iw = BE.img.naturalWidth || BE.img.width;
    const ih = BE.img.naturalHeight || BE.img.height;
    viewport.style.left = `${crop.x}px`;
    viewport.style.top = `${crop.y}px`;
    viewport.style.width = `${crop.w}px`;
    viewport.style.height = `${crop.h}px`;
    preview.style.position = "absolute";
    preview.style.left = `${BE.ox - crop.x}px`;
    preview.style.top = `${BE.oy - crop.y}px`;
    preview.style.width = `${iw * BE.scale}px`;
    preview.style.height = `${ih * BE.scale}px`;
    preview.style.maxWidth = "none";
    preview.style.maxHeight = "none";
    preview.style.objectFit = "fill";
    return;
  }
  const ctx = canvas.getContext("2d");
  const info = syncCanvasSize(canvas);
  const crop = getBannerCropMetrics(info);

  ctx.setTransform(info.dpr, 0, 0, info.dpr, 0, 0);
  ctx.clearRect(0, 0, info.cssW, info.cssH);

  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = "high";

  const iw = BE.img.naturalWidth || BE.img.width;
  const ih = BE.img.naturalHeight || BE.img.height;

  ctx.fillStyle = "rgba(0,0,0,0.28)";
  ctx.fillRect(0, 0, info.cssW, info.cssH);

  ctx.save();
  roundedRectPath(ctx, crop.x, crop.y, crop.w, crop.h, 12);
  ctx.clip();
  ctx.drawImage(BE.img, BE.ox, BE.oy, iw * BE.scale, ih * BE.scale);
  ctx.restore();

  roundedRectPath(ctx, crop.x, crop.y, crop.w, crop.h, 12);
  ctx.strokeStyle = "rgba(255,255,255,0.92)";
  ctx.lineWidth = 3;
  ctx.stroke();
}

function onBannerZoom() {
  const canvas = document.getElementById("bannerEditorCanvas");
  const zoom = document.getElementById("bannerEditorZoom");
  if (!canvas || !zoom) return;

  const newScale = clampValue(parseFloat(zoom.value), BE.minScale, BE.maxScale);
  const oldScale = BE.scale || newScale;
  if (!Number.isFinite(newScale) || newScale <= 0 || !Number.isFinite(oldScale) || oldScale <= 0) return;

  const info = BE.isGif
    ? (() => {
      const rect = (ensureEditorGifUi("banner").wrap || canvas).getBoundingClientRect();
      return { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height), dpr: window.devicePixelRatio || 1 };
    })()
    : syncCanvasSize(canvas);
  const crop = getBannerCropMetrics(info);
  const cx = crop.cx;
  const cy = crop.cy;

  BE.ox = cx - (cx - BE.ox) * (newScale / oldScale);
  BE.oy = cy - (cy - BE.oy) * (newScale / oldScale);
  BE.scale = newScale;
  clampBannerOffsets();

  zoom.value = String(BE.scale);
  drawBannerEditor();
}

function bindBannerDrag() {
  const canvas = document.getElementById("bannerEditorCanvas");
  const surface = canvas?.parentElement || ensureEditorGifUi("banner").wrap || null;
  if (!surface || BE._dragBound) return;
  BE._dragBound = true;

  const getPoint = (ev) => {
    const rect = surface.getBoundingClientRect();
    const clientX = ev.touches ? ev.touches[0].clientX : ev.clientX;
    const clientY = ev.touches ? ev.touches[0].clientY : ev.clientY;
    return { x: clientX - rect.left, y: clientY - rect.top };
  };

  const onDown = (ev) => {
    BE.dragging = true;
    const p = getPoint(ev);
    BE.drag.x = p.x;
    BE.drag.y = p.y;
    BE.drag.ox = BE.ox;
    BE.drag.oy = BE.oy;
  };

  const onMove = (ev) => {
    if (!BE.dragging) return;
    const p = getPoint(ev);
    BE.ox = BE.drag.ox + (p.x - BE.drag.x);
    BE.oy = BE.drag.oy + (p.y - BE.drag.y);
    clampBannerOffsets();
    drawBannerEditor();
  };

  const onUp = () => { BE.dragging = false; };

  surface.addEventListener("mousedown", onDown);
  window.addEventListener("mousemove", onMove);
  window.addEventListener("mouseup", onUp);

  surface.addEventListener("touchstart", onDown, { passive: true });
  window.addEventListener("touchmove", onMove, { passive: true });
  window.addEventListener("touchend", onUp);
}

async function openBannerEditor(file, user, { gifMode = false } = {}) {
  clearEditorAnimatedPreview(BE);
  BE.user = user;
  BE.ext = (file.name.split(".").pop() || "png").toLowerCase();
  BE.isGif = !!gifMode;
  BE.sourceFile = file || null;
  if (BE.isGif) {
    BE.ext = "gif";
    BE.img = null;
    try { BE.previewUrl = URL.createObjectURL(file); } catch (_) { BE.previewUrl = ""; }
    BE.img = await loadImageFromUrl(BE.previewUrl);
    setEditorGifMode("banner", true, {
      previewUrl: BE.previewUrl,
      label: "Banner GIF",
      hintText: "Os GIFs mantem a animacao e usam o mesmo zoom e drag do editor normal.",
    });
    showBannerEditor();
    requestAnimationFrame(() => {
      bindBannerDrag();
      fitBannerToCrop();
      drawBannerEditor();
    });
    return;
  }
  if (!/(png|jpg|jpeg|webp)$/i.test(BE.ext)) BE.ext = "png";
  setEditorGifMode("banner", false);
  BE.img = await loadImageFromFile(file);
  showBannerEditor();

  requestAnimationFrame(() => {
    bindBannerDrag();
    fitBannerToCrop();
    drawBannerEditor();
  });
}

async function exportBannerBlob(width = 1600) {
  const src = document.getElementById("bannerEditorCanvas");
  if (!src || !BE.img) throw new Error("Editor de banner nao pronto");
  const rect = src.getBoundingClientRect();
  const info = { cssW: Math.max(1, rect.width), cssH: Math.max(1, rect.height) };
  const crop = getBannerCropMetrics(info);
  const outW = clampInt(width, 800, 2400, 1600);
  const outH = Math.round(outW / BE.cropRatio);

  const out = document.createElement("canvas");
  out.width = outW;
  out.height = outH;
  const ctx = out.getContext("2d");
  ctx.clearRect(0, 0, outW, outH);

  const iw = BE.img.naturalWidth || BE.img.width;
  const ih = BE.img.naturalHeight || BE.img.height;
  const s = outW / crop.w;

  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = "high";
  ctx.drawImage(
    BE.img,
    (BE.ox - crop.x) * s,
    (BE.oy - crop.y) * s,
    iw * BE.scale * s,
    ih * BE.scale * s
  );

  const mime = BE.ext === "jpg" || BE.ext === "jpeg"
    ? "image/jpeg"
    : (BE.ext === "webp" ? "image/webp" : "image/png");
  return new Promise((res) => out.toBlob((b) => res(b), mime, 0.92));
}

function resolveAvatarMimeAndExt(ext = "", contentTypeOverride = "") {
  const rawExt = String(ext || "").trim().toLowerCase();
  const rawType = String(contentTypeOverride || "").trim().toLowerCase();
  if (rawType === "image/gif" || rawExt === "gif") return { ext: "gif", mime: "image/gif" };
  if (rawType === "image/webp" || rawExt === "webp") return { ext: "webp", mime: "image/webp" };
  if (rawType === "image/jpeg" || rawExt === "jpg" || rawExt === "jpeg") return { ext: "jpg", mime: "image/jpeg" };
  return { ext: "png", mime: "image/png" };
}

async function uploadAvatarBlob(blob, user, ext, contentTypeOverride = "", crop = undefined) {
  const { ext: safeExt, mime } = resolveAvatarMimeAndExt(ext, contentTypeOverride);
  const path = `${user.id}/avatar_${Date.now()}.${safeExt}`;

  const up = await supabase.storage.from("avatars").upload(path, blob, {
    upsert: true,
    contentType: mime,
  });

  setProfileDebug({ upload: up });
  if (up.error) throw up.error;

  const { data } = supabase.storage.from("avatars").getPublicUrl(path);
  const url = data.publicUrl;

  const saved = await saveAvatarUrlForUser(user.id, url, crop);

  if (state.me && state.user?.id === user.id) {
    state.me.avatar_url = url;
    if (saved?.theme_settings) state.me.theme_settings = normalizeThemeSettings(saved.theme_settings);
    cacheProfileRow(state.me);
  }

  document.getElementById("avatarPreview").innerHTML = buildAvatarMediaHtml(url, { userId: user.id, alt: "avatar", controlledGif: true });
  queueManagedGifPlaybackSync(document.getElementById("avatarPreview"));
  setAvatar(document.getElementById("settingsUserAvatar"), url, user.id);

  if (state.me && state.user?.id === user.id) {
    setAvatar($("meAvatar"), url, user.id);
    refreshDmProfilePanel();
    refreshOpenUserCard();
  }
}

async function uploadAvatarFileDirect(file, user) {
  if (!file || !user?.id) throw new Error("Upload de avatar invalido.");
  const ext = (String(file.name || "").split(".").pop() || "gif").toLowerCase();
  await uploadAvatarBlob(file, user, ext, file.type || "");
}

function buildThemeWithBannerCrop(themeInput, crop = null) {
  const next = normalizeThemeSettings(themeInput || {});
  if (crop) next.banner_crop = normalizeMediaCropSnapshot(crop, "banner");
  else delete next.banner_crop;
  return normalizeThemeSettings(next);
}

function buildThemeWithAvatarCrop(themeInput, crop = null) {
  const next = normalizeThemeSettings(themeInput || {});
  if (crop) next.avatar_crop = normalizeMediaCropSnapshot(crop, "avatar");
  else delete next.avatar_crop;
  return normalizeThemeSettings(next);
}

async function saveAvatarUrlForUser(userId, avatarUrl, crop = undefined) {
  const uid = String(userId || "").trim();
  if (!uid) throw new Error("Utilizador invalido para guardar avatar.");
  const normalizedUrl = String(avatarUrl || "").trim();
  const normalizedCrop = crop === undefined ? undefined : normalizeMediaCropSnapshot(crop, "avatar");
  const currentTheme = normalizeThemeSettings(state.me?.theme_settings || {});
  const nextTheme = crop === undefined ? currentTheme : buildThemeWithAvatarCrop(currentTheme, normalizedCrop);
  const updatePayload = crop === undefined
    ? { avatar_url: normalizedUrl || null }
    : { avatar_url: normalizedUrl || null, theme_settings: nextTheme };

  const { error } = await supabase.from("profiles").update(updatePayload).eq("id", uid);
  setProfileDebug({ avatar_url_save: { error, url: normalizedUrl } });
  if (error) throw error;
  return {
    avatar_url: normalizedUrl,
    theme_settings: crop === undefined ? null : nextTheme,
  };
}

async function saveBannerUrlForUser(userId, bannerUrl, crop = undefined) {
  const uid = String(userId || "").trim();
  if (!uid) throw new Error("Utilizador invalido para guardar banner.");
  const normalizedUrl = normalizeBannerUrl(bannerUrl);
  const normalizedCrop = crop === undefined ? undefined : normalizeMediaCropSnapshot(crop, "banner");

  const tryBannerColumn = profileBannerUrlSupported !== false;
  if (tryBannerColumn) {
    const currentTheme = normalizeThemeSettings(state.me?.theme_settings || {});
    const themeForColumn = crop === undefined ? currentTheme : buildThemeWithBannerCrop(currentTheme, normalizedCrop);
    const updatePayload = crop === undefined
      ? { banner_url: normalizedUrl || null }
      : { banner_url: normalizedUrl || null, theme_settings: themeForColumn };
    const { error } = await supabase
      .from("profiles")
      .update(updatePayload)
      .eq("id", uid);

    setProfileDebug({ banner_url_save: { via: "banner_url", error, url: normalizedUrl } });

    if (!error) {
      if (profileBannerUrlSupported === null) profileBannerUrlSupported = true;
      return { via: "banner_url", banner_url: normalizedUrl, theme_settings: crop === undefined ? null : themeForColumn };
    }

    const msg = String(error?.message || "").toLowerCase();
    if (!(msg.includes("banner_url") && msg.includes("column"))) throw error;
    profileBannerUrlSupported = false;
  }

  const currentTheme = normalizeThemeSettings(state.me?.theme_settings || {});
  const nextTheme = buildThemeWithBannerCrop({
    ...currentTheme,
    banner_url: normalizedUrl,
  }, normalizedCrop);
  const { error: themeError } = await supabase
    .from("profiles")
    .update({ theme_settings: nextTheme })
    .eq("id", uid);

  setProfileDebug({ banner_url_save: { via: "theme_settings", error: themeError, url: normalizedUrl } });

  if (themeError) {
    const msg = String(themeError?.message || "").toLowerCase();
    if (msg.includes("theme_settings") && msg.includes("column")) {
      throw new Error("Falta a coluna theme_settings no Supabase para guardar o banner.");
    }
    throw themeError;
  }

  return { via: "theme_settings", banner_url: "", theme_settings: nextTheme };
}

async function uploadBannerBlob(blob, user, ext, contentTypeOverride = "", crop = undefined) {
  if (!blob || !user?.id) throw new Error("Upload de banner invalido.");
  const { ext: safeExt, mime } = resolveAvatarMimeAndExt(ext, contentTypeOverride);
  const path = `${user.id}/banner_${Date.now()}.${safeExt}`;

  const upload = await supabase.storage.from("avatars").upload(path, blob, {
    upsert: true,
    contentType: mime,
  });
  setProfileDebug({ banner_upload: upload });
  if (upload.error) throw upload.error;

  const { data } = supabase.storage.from("avatars").getPublicUrl(path);
  const url = normalizeBannerUrl(data?.publicUrl || "");
  if (!url) throw new Error("Nao consegui gerar URL publica para o banner.");

  const saved = await saveBannerUrlForUser(user.id, url, crop);

  state.me = state.me || {};
  state.me.id = state.me.id || user.id;
  if (saved.via === "theme_settings") {
    state.me.banner_url = "";
    state.me.theme_settings = normalizeThemeSettings(saved.theme_settings || { ...(state.me.theme_settings || {}), banner_url: url });
  } else {
    state.me.banner_url = url;
    state.me.theme_settings = normalizeThemeSettings(saved.theme_settings || { ...(state.me.theme_settings || {}), banner_url: url });
  }
  cacheProfileRow(state.me);

  const settingsBanner = document.getElementById("settingsIdentityBanner");
  if (settingsBanner) {
    const base = normalizeCallTileColor(state.me.call_tile_color) || "#1b2230";
    const left = mixHex(base, "#77c5ff", 0.1);
    const right = mixHex(base, "#05080d", 0.55);
    const glow = rgbaFromHex(base, 0.22);
    const resolvedBannerUrl = resolveUserBannerUrl(user.id, url);
    applyBannerStyle(settingsBanner, resolvedBannerUrl, left, right, glow, { userId: user.id });
    if (!resolvedBannerUrl) settingsBanner.style.background = `linear-gradient(135deg, ${left}, ${right} 78%)`;
  }

  const activeTheme = applyAppearanceSettings(appearanceSettingsCache || loadAppearanceSettings());
  writeThemeToForm(activeTheme);
  applyMeHeaderBannerStyle();
  refreshDmProfilePanel();
  refreshOpenUserCard();
}

async function uploadBannerFile(file, user) {
  if (!file || !user?.id) throw new Error("Upload de banner invalido.");
  const contentType = String(file.type || "").trim().toLowerCase();
  if (!contentType.startsWith("image/")) {
    throw new Error("Banner invalido. Escolhe uma imagem.");
  }
  const ext = (String(file.name || "").split(".").pop() || "png").toLowerCase();
  await uploadBannerBlob(file, user, ext, file.type || "");
}

async function applyBanner() {
  const btnApply = document.getElementById("bannerEditorApply");
  if (!BE.user || !btnApply || (!BE.img && !(BE.isGif && BE.sourceFile))) return;

  btnApply.disabled = true;
  btnApply.textContent = "A guardar...";

  try {
    if (BE.isGif && BE.sourceFile) {
      const bannerCrop = captureBannerEditorCropSnapshot();
      await uploadBannerBlob(BE.sourceFile, BE.user, "gif", BE.sourceFile.type || "image/gif", bannerCrop);
    } else {
      const bannerCrop = captureBannerEditorCropSnapshot();
      const sourceFile = BE.sourceFile;
      if (!sourceFile) throw new Error("Ficheiro original do banner indisponivel.");
      await uploadBannerBlob(sourceFile, BE.user, BE.ext, sourceFile.type || "", bannerCrop);
    }
    hideBannerEditor();
  } catch (e) {
    console.error(e);
    await requestAppAlert("Erro no banner: " + (e?.message ?? e), {
      title: "Banner",
      okText: t("dialog.notice.ok", "OK"),
    });
  } finally {
    btnApply.disabled = false;
    btnApply.textContent = "Apply";
  }
}

async function applyAvatar() {
  const btnApply = document.getElementById("avatarEditorApply");
  if (!AE.user || !btnApply || (!AE.img && !(AE.isGif && AE.sourceFile))) return;

  btnApply.disabled = true;
  btnApply.textContent = "A guardar...";

  try {
    if (AE.isGif && AE.sourceFile) {
      const avatarCrop = captureAvatarEditorCropSnapshot();
      await uploadAvatarBlob(AE.sourceFile, AE.user, "gif", AE.sourceFile.type || "image/gif", avatarCrop);
    } else {
      const blob = await exportAvatarBlob(512);
      const editedExt = blob?.type === "image/jpeg" ? "jpg" : "png";
      await uploadAvatarBlob(blob, AE.user, editedExt, blob?.type || "", null);
    }
    hideAvatarEditor();
  } catch (e) {
    console.error(e);
    await requestAppAlert("Erro no avatar: " + (e?.message ?? e), {
      title: "Avatar",
      okText: t("dialog.notice.ok", "OK"),
    });
  } finally {
    btnApply.disabled = false;
    btnApply.textContent = "Apply";
  }
}

/* ========================= PRESENCE (Discord-like) ========================= */
import { createPresenceSystem } from "./presence.js";
import { renderPresenceUI } from "./presence-ui.js";
import { getMyStatus, getStoredMyStatus, setMyStatus } from "./statusstore.js";

let presence = null;
let presenceList = [];
let meStatusMenuBound = false;
let meStatusPersistQueue = Promise.resolve();

function closeMeStatusMenu() {
  const menu = document.getElementById("meStatusMenu");
  if (!menu) return;
  menu.classList.remove("is-open");
}

function ensureMeStatusMenu() {
  let menu = document.getElementById("meStatusMenu");
  if (!menu) {
    menu = document.createElement("div");
    menu.id = "meStatusMenu";
    menu.className = "msgMenu msgMenu--submenu meStatusMenu";
    document.body.appendChild(menu);
  }
  menu.classList.add("meStatusMenu");
  if (meStatusMenuBound) return menu;
  meStatusMenuBound = true;

  document.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    if (!menu.classList.contains("is-open")) return;
    if (target.closest("#meStatusMenu")) return;
    closeMeStatusMenu();
  });

  window.addEventListener("resize", closeMeStatusMenu);
  window.addEventListener("scroll", closeMeStatusMenu, true);
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeMeStatusMenu();
  });

  menu.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const btn = target.closest("[data-me-status]");
    if (!btn || btn.disabled) return;
    e.preventDefault();
    const nextStatus = String(btn.getAttribute("data-me-status") || "").trim().toLowerCase();
    closeMeStatusMenu();
    void setMyPresenceStatusEverywhere(nextStatus, { persistAccount: true });
  });

  return menu;
}

let meProfilePopoutBound = false;
let meProfilePopoutWidgetsRequestSeq = 0;

function isMeProfilePopoutDebugEnabled() {
  try {
    return typeof isProfileMediaDebugEnabled === "function" && isProfileMediaDebugEnabled();
  } catch (_) {
    return false;
  }
}

function logMeProfilePopoutDebug(eventName = "", details = {}) {
  if (!isMeProfilePopoutDebugEnabled()) return;
  console.info("[user-popout]", String(eventName || "user_popout.event"), details || {});
}

function getMeProfilePopoutStatusLabel(statusInput = "") {
  const status = normalizePresenceStatus(statusInput || getMyStatus());
  if (status === "idle") return t("status.option.idle", "Away");
  if (status === "dnd") return t("status.option.dnd", "Do Not Disturb");
  if (status === "invisible") return t("status.option.invisible", "Invisible");
  return t("status.option.online", "Online");
}

function ensureMeProfilePopout() {
  let popout = document.getElementById("meProfilePopout");
  if (!popout) {
    popout = document.createElement("div");
    popout.id = "meProfilePopout";
    popout.className = "meProfilePopout";
    popout.setAttribute("aria-hidden", "true");
    document.body.appendChild(popout);
  }
  return popout;
}

function getMeProfilePopoutAvatarHtml(profile = null) {
  const uid = normId(profile?.id || state.user?.id || "");
  const avatarUrl = getCurrentMeAvatarUrl();
  if (avatarUrl) {
    return buildAvatarMediaHtml(avatarUrl, {
      userId: uid,
      profile: profile || state.me || null,
      alt: "avatar",
      controlledGif: true,
    });
  }
  const renderedFallback = document.querySelector("#meAvatar .meAvatarFallback, #meAvatar .profileAvatarFallback");
  if (renderedFallback) return renderedFallback.outerHTML;
  const seed = profile?.display_name || profile?.username || state.me?.display_name || state.me?.username || "User";
  return getAvatarFallbackHtml(uid, seed, "avatar", "meProfilePopout__avatarFallback");
}

function buildMeProfilePopoutWidgetPreviewHtml(userId = "", { loading = false } = {}) {
  const widgets = getCachedProfileWidgetsForUser(userId).slice(0, 3);
  const previews = [];
  for (const widget of widgets) {
    const title = normalizeProfileWidgetTitle(widget?.title || "") || t("profile.widgets.card.title", "Widget");
    const items = Array.isArray(widget?.items) ? widget.items : [];
    const firstItem = getProfileWidgetFeaturedItem(widget) || items.find((item) => normalizeProfileWidgetTitle(item?.title || "")) || null;
    const coverUrl = normalizeCatalogCoverUrl(firstItem?.cover_url || "");
    previews.push({
      title: firstItem ? normalizeProfileWidgetTitle(firstItem.title) : title,
      meta: firstItem ? title : t("profile.widgets.preview", "Profile widget"),
      type: getProfileWidgetTypeLabel(widget?.widget_type || "") || t("profile.widgets.card.title", "Widget"),
      coverUrl,
    });
    if (previews.length >= 2) break;
  }

  if (!previews.length) {
    const message = loading
      ? t("profile.widgets.loading.title", "Loading widgets...")
      : t("profile.widgets.empty.preview", "Open the full profile to explore widgets.");
    return `
      <div class="meProfilePopout__emptyPreview">
        <div class="meProfilePopout__emptyTitle">${esc(message)}</div>
      </div>
    `;
  }

  return `
    <div class="meProfilePopout__widgetList">
      ${previews.map((item) => {
        const initial = String(item.title || "?").trim().charAt(0).toUpperCase() || "?";
        const mediaHtml = item.coverUrl
          ? `<img src="${escAttr(item.coverUrl)}" alt="" loading="lazy" decoding="async" draggable="false" />`
          : esc(initial);
        return `
          <button class="meProfilePopout__widgetCard" type="button" data-me-popout-act="view-full">
            <span class="meProfilePopout__widgetMedia" aria-hidden="true">${mediaHtml}</span>
            <span class="meProfilePopout__widgetBody">
              <span class="meProfilePopout__widgetType">${esc(item.type)}</span>
              <span class="meProfilePopout__widgetName">${esc(item.title)}</span>
              <span class="meProfilePopout__widgetMeta">${esc(item.meta)}</span>
            </span>
          </button>
        `;
      }).join("")}
    </div>
  `;
}

function buildMeProfilePopoutHtml() {
  const profile = getCurrentMeProfileSnapshot();
  const uid = normId(profile?.id || state.user?.id || "");
  const hasWidgetCache = userCardWidgetsCache.has(uid);
  const displayName = profile?.display_name || profile?.username || "User";
  const username = profile?.username || "";
  const pronouns = normalizePronouns(profile?.pronouns || "");
  const handleText = username ? `@${username}` : "@user";
  const handleLine = pronouns ? `${handleText} · ${pronouns}` : handleText;
  const bio = String(profile?.bio || "").trim();
  const status = resolveMyPresenceStatus(profile);
  const statusLabel = getMeProfilePopoutStatusLabel(status);

  return `
    <div class="meProfilePopout__scroll">
      <div class="meProfilePopout__banner" aria-hidden="true">
        <span class="meProfilePopout__bannerSheen"></span>
      </div>
      <div class="meProfilePopout__profile">
        <div class="meProfilePopout__head">
          <button class="meProfilePopout__avatar" type="button" data-me-popout-act="view-full" aria-label="${escAttr(t("dm.view_full_profile", "View Full Profile"))}">
            ${getMeProfilePopoutAvatarHtml(profile)}
            <span class="statusDot userCardAvatarStatusDot" data-status-dot="${escAttr(uid)}" data-status="${escAttr(status || "offline")}" aria-label="${escAttr(statusLabel)}"></span>
          </button>
          <button class="meProfilePopout__identity" type="button" data-me-popout-act="view-full" aria-label="${escAttr(t("dm.view_full_profile", "View Full Profile"))}">
            <div class="meProfilePopout__name">${esc(displayName)}</div>
            <div class="meProfilePopout__handle">${esc(handleLine)}</div>
          </button>
        </div>
        <div class="meProfilePopout__body">
          <div class="meProfilePopout__statusLine">
            <button class="meProfilePopout__statusText" type="button" data-me-popout-act="status" aria-label="${escAttr(t("settings.section.status", "Status"))}: ${escAttr(statusLabel)}">
              <span class="dotMini" data-status-mini="${escAttr(status)}"></span>
              <span data-me-popout-status-label="1">${esc(statusLabel)}</span>
            </button>
            <button class="meProfilePopout__statusAction" type="button" data-me-popout-act="status">${esc(t("settings.section.status", "Status"))}</button>
          </div>
          <section class="meProfilePopout__about">
            <div class="meProfilePopout__sectionLabel">${esc(t("profile.about", "About"))}</div>
            <div class="meProfilePopout__bio">${esc(bio || t("dm.no_bio", "No bio."))}</div>
          </section>
          <section class="meProfilePopout__widgets">
            <div class="meProfilePopout__sectionTop">
              <div class="meProfilePopout__sectionLabel">${esc(t("profile.widgets.title", "Widgets"))}</div>
            </div>
            <div data-me-popout-widgets-preview>
              ${buildMeProfilePopoutWidgetPreviewHtml(uid, { loading: !hasWidgetCache })}
            </div>
          </section>
        </div>
      </div>
      <div class="meProfilePopout__actions">
        <button class="meProfilePopout__action" type="button" data-me-popout-act="edit">${esc(t("profile.edit", "Edit Profile"))}</button>
        <button class="meProfilePopout__action" type="button" data-me-popout-act="settings">${esc(t("settings.title", "Settings"))}</button>
      </div>
    </div>
  `;
}

function renderMeProfilePopoutWidgetsPreview({ loading = false } = {}) {
  const popout = document.getElementById("meProfilePopout");
  if (!popout || !popout.classList.contains("is-open")) return;
  const uid = normId(state.user?.id || "");
  const host = popout.querySelector("[data-me-popout-widgets-preview]");
  if (!uid || !host) return;
  host.innerHTML = buildMeProfilePopoutWidgetPreviewHtml(uid, { loading });
}

async function refreshMeProfilePopoutWidgetsPreview({ force = true } = {}) {
  const uid = normId(state.user?.id || "");
  if (!uid) return;
  const requestId = ++meProfilePopoutWidgetsRequestSeq;
  const hasCachedWidgets = getCachedProfileWidgetsForUser(uid).length > 0;
  renderMeProfilePopoutWidgetsPreview({ loading: !hasCachedWidgets });
  try {
    await fetchProfileWidgetsForUser(uid, { force: !!force });
  } catch (_) {
    // Keep the compact popout quiet; the full profile owns detailed widget errors.
  }
  if (requestId !== meProfilePopoutWidgetsRequestSeq) return;
  const popout = document.getElementById("meProfilePopout");
  if (!popout || !popout.classList.contains("is-open")) return;
  renderMeProfilePopoutWidgetsPreview({ loading: false });
  positionMeProfilePopout();
}

function applyMeProfilePopoutBannerStyle(profileInput = null) {
  const bannerEl = document.querySelector("#meProfilePopout .meProfilePopout__banner");
  if (!bannerEl) return;
  const profile = profileInput || getCurrentMeProfileSnapshot();
  const theme = normalizeThemeSettings(profile?.theme_settings || {});
  const base = normalizeHexColor(
    theme.surface_secondary || theme.surface || profile?.call_tile_color || "#24211d",
    "#24211d"
  );
  const start = mixHex(base, "#24211d", 0.36);
  const end = mixHex(base, "#101010", 0.78);
  const glow = rgbaFromHex(base, 0.16);
  const bannerUrl = getCurrentMeBannerUrl(theme);
  applyBannerStyle(bannerEl, bannerUrl, start, end, glow, {
    userId: profile?.id || state.user?.id || "",
    profile,
    overlay: "linear-gradient(180deg, rgba(0, 0, 0, 0.06), rgba(0, 0, 0, 0.38))",
  });
}

function positionMeProfilePopout() {
  const popout = document.getElementById("meProfilePopout");
  const dock = document.getElementById("meProfileCard");
  if (!popout || !dock || !popout.classList.contains("is-open")) return;
  const rect = dock.getBoundingClientRect();
  const vw = window.innerWidth || document.documentElement.clientWidth || 0;
  const vh = window.innerHeight || document.documentElement.clientHeight || 0;
  const margin = 12;
  const dockWidth = Math.round(rect.width || 0);
  const width = Math.min(316, Math.max(220, dockWidth || 260), Math.max(220, vw - (margin * 2)));
  const left = Math.max(margin, Math.min(Math.round(rect.left || margin), Math.max(margin, vw - width - margin)));
  const availableAboveDock = Math.max(260, Math.round((rect.top || vh) - margin - 8));
  const maxHeight = Math.max(260, Math.min(452, availableAboveDock, vh - (margin * 2)));
  popout.style.setProperty("--me-popout-left", `${left}px`);
  popout.style.setProperty("--me-popout-width", `${width}px`);
  popout.style.setProperty("--me-popout-max-height", `${maxHeight}px`);

  const measuredHeight = Math.min(popout.getBoundingClientRect().height || maxHeight, maxHeight);
  const preferredBottom = Math.round(vh - (rect.top || 0) + 8);
  const maxBottom = Math.max(margin, vh - measuredHeight - margin);
  const bottom = Math.max(margin, Math.min(preferredBottom, maxBottom));
  popout.style.setProperty("--me-popout-bottom", `${bottom}px`);
}

function closeMeProfilePopout() {
  const popout = document.getElementById("meProfilePopout");
  if (!popout) return;
  popout.classList.remove("is-open");
  popout.setAttribute("aria-hidden", "true");
}

function getMeUserCardSeed() {
  const profile = getCurrentMeProfileSnapshot();
  return {
    id: profile?.id || state.user?.id || "",
    username: profile?.username || state.me?.username || "",
    display_name: profile?.display_name || state.me?.display_name || state.me?.username || "",
    avatar_url: profile?.avatar_url || state.me?.avatar_url || "",
    banner_url: profile?.banner_url || profile?.theme_settings?.banner_url || state.me?.banner_url || "",
    pronouns: profile?.pronouns || state.me?.pronouns || "",
    bio: profile?.bio || state.me?.bio || "",
    name_color: profile?.name_color || state.me?.name_color || "",
    call_tile_color: profile?.call_tile_color || state.me?.call_tile_color || "",
    theme_settings: profile?.theme_settings || state.me?.theme_settings || null,
    created_at: profile?.created_at || state.me?.created_at || null,
  };
}

async function openMeFullProfileFromPopout() {
  const uid = normId(state.user?.id || "");
  if (!uid) return;
  logMeProfilePopoutDebug("user_popout.view_full_profile_clicked", { userId: uid });
  closeMeProfilePopout();
  await openUserCardModal(uid, getMeUserCardSeed(), {
    presentation: "overlay",
    kind: "self",
    initialTab: "widgets",
  });
  setUserCardActiveTab("widgets");
}

function openMeProfilePopout() {
  const uid = normId(state.user?.id || "");
  if (!uid) return;
  closeMessageMenu();
  closeDmListMenus();
  closeMeStatusMenu();
  const popout = ensureMeProfilePopout();
  popout.innerHTML = buildMeProfilePopoutHtml();
  popout.classList.add("is-open");
  popout.setAttribute("aria-hidden", "false");
  queueManagedGifPlaybackSync(popout);
  applyMeProfilePopoutBannerStyle();
  positionMeProfilePopout();
  void refreshMeProfilePopoutWidgetsPreview({ force: true });
  logMeProfilePopoutDebug("user_popout.opened", { userId: uid });
}

function bindMeProfilePopoutDockOnce() {
  if (meProfilePopoutBound) return;
  meProfilePopoutBound = true;
  const dock = document.getElementById("meProfileCard");
  const statusBtn = document.getElementById("meStatusBtn");
  const controls = document.querySelectorAll("#btnHeaderMicToggle, #btnHeaderDeafenToggle, #btnHeaderSettings");

  controls.forEach((control) => {
    control.addEventListener("click", (e) => {
      e.stopPropagation();
    });
  });

  statusBtn?.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    openMeStatusMenuForElement(statusBtn, { placement: "above" });
  });

  statusBtn?.addEventListener("contextmenu", (e) => {
    e.preventDefault();
    e.stopPropagation();
    openMeStatusMenuForElement(statusBtn, { placement: "above" });
  });

  statusBtn?.addEventListener("keydown", (e) => {
    if (e.key !== "ContextMenu" && !(e.shiftKey && e.key === "F10")) return;
    e.preventDefault();
    e.stopPropagation();
    openMeStatusMenuForElement(statusBtn, { placement: "above" });
  });

  dock?.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    if (target?.closest?.(".meControls, #btnHeaderMicToggle, #btnHeaderDeafenToggle, #btnHeaderSettings, #meStatusBtn")) return;
    e.preventDefault();
    logMeProfilePopoutDebug("user_dock.clicked", { targetId: target?.id || "", targetClass: String(target?.className || "") });
    openMeProfilePopout();
  });

  const popout = ensureMeProfilePopout();
  popout.addEventListener("click", (e) => {
    const target = eventTargetElement(e);
    const actionBtn = target?.closest?.("[data-me-popout-act]");
    if (!actionBtn) return;
    e.preventDefault();
    e.stopPropagation();
    const action = String(actionBtn.getAttribute("data-me-popout-act") || "").trim();
    if (action === "view-full") {
      void openMeFullProfileFromPopout();
      return;
    }
    if (action === "status") {
      openMeStatusMenuForElement(actionBtn, { placement: "side" });
      return;
    }
    if (action === "edit" || action === "settings") {
      closeMeProfilePopout();
      openProfileOverlay();
    }
  });

  document.addEventListener("pointerdown", (e) => {
    const target = eventTargetElement(e);
    if (!target) return;
    const currentPopout = document.getElementById("meProfilePopout");
    if (!currentPopout || !currentPopout.classList.contains("is-open")) return;
    if (target.closest("#meProfilePopout")) return;
    if (target.closest("#meProfileCard")) return;
    closeMeProfilePopout();
  });
  window.addEventListener("resize", positionMeProfilePopout);
  window.addEventListener("scroll", positionMeProfilePopout, true);
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeMeProfilePopout();
  });
}

function positionMeStatusMenuNearAnchor(menu, anchorRect, {
  width = 236,
  minHeight = 218,
  placement = "side",
} = {}) {
  if (!menu || !anchorRect) return;
  const margin = 8;
  const menuWidth = Math.max(180, width);

  const place = () => {
    const vw = window.innerWidth || document.documentElement.clientWidth || 0;
    const vh = window.innerHeight || document.documentElement.clientHeight || 0;
    const renderedHeight = menu.offsetHeight;
    const menuHeight = Math.max(minHeight, renderedHeight || minHeight);
    let left = Math.round(anchorRect.left || margin);
    let top = Math.round(anchorRect.bottom || margin) + margin;

    if (placement === "above") {
      left = Math.round(anchorRect.left || margin);
      top = Math.round((anchorRect.top || margin) - menuHeight - margin);
    } else {
      const rightLeft = Math.round((anchorRect.right || 0) + margin);
      const leftLeft = Math.round((anchorRect.left || 0) - menuWidth - margin);
      left = rightLeft + menuWidth <= vw - margin ? rightLeft : leftLeft;
      top = Math.round((anchorRect.top || margin) - 6);
    }

    if (left + menuWidth > vw - margin) left = Math.max(margin, vw - menuWidth - margin);
    if (left < margin) left = margin;
    if (top + menuHeight > vh - margin) top = Math.max(margin, vh - menuHeight - margin);
    if (top < margin) top = margin;
    menu.style.left = `${left}px`;
    menu.style.top = `${top}px`;
  };

  place();
  requestAnimationFrame(place);
}

function openMeStatusMenuForElement(anchorEl, options = {}) {
  const rect = anchorEl?.getBoundingClientRect?.();
  if (!rect) return;
  openMeStatusMenuAt(
    { x: Math.round(rect.left || 0), y: Math.round(rect.bottom || 0) },
    { ...options, anchorRect: rect }
  );
}

function openMeStatusMenuAt(point, options = {}) {
  if (!point) return;
  closeMessageMenu();
  closeDmListMenus();
  const menu = ensureMeStatusMenu();
  const currentStatus = resolveMyPresenceStatus(state.me);
  const statusOptions = [
    ["online", t("status.option.online", "Online")],
    ["idle", t("status.option.idle", "Away")],
    ["dnd", t("status.option.dnd", "Do Not Disturb")],
    ["invisible", t("status.option.invisible", "Invisible")],
  ];

  menu.innerHTML = [
    `<div class="msgMenu__meta meStatusMenu__meta">${esc(t("settings.section.status", "Status"))}</div>`,
    ...statusOptions.map(([value, label]) => {
      const isOn = currentStatus === value;
      return `
        <button
          class="msgMenu__item meStatusMenu__item${isOn ? " is-active" : ""}"
          type="button"
          role="menuitemradio"
          aria-checked="${isOn ? "true" : "false"}"
          data-me-status="${escAttr(value)}"
          data-status="${escAttr(value)}"
        >
          <span class="meStatusMenu__main">
            <span class="meStatusMenu__dot" data-status="${escAttr(value)}" aria-hidden="true"></span>
            <span class="meStatusMenu__label">${esc(label)}</span>
          </span>
          <span class="meStatusMenu__indicator" aria-hidden="true"></span>
        </button>
      `;
    }),
  ].join("");
  menu.setAttribute("role", "menu");
  menu.setAttribute("aria-label", t("settings.section.status", "Status"));
  menu.classList.add("is-open");
  if (options?.anchorRect) {
    positionMeStatusMenuNearAnchor(menu, options.anchorRect, {
      width: 236,
      minHeight: 218,
      placement: options.placement || "side",
    });
  } else {
    positionMenuAtPoint(menu, point, { width: 236, minHeight: 218 });
  }
}

async function persistMyPresenceStatusToAccount(statusInput) {
  const status = normalizePresenceStatus(statusInput);
  const uid = normId(state.user?.id || "");
  if (!uid) return false;

  if (profileStatusSupported !== false) {
    const { error } = await supabase
      .from("profiles")
      .update({ status })
      .eq("id", uid);
    if (!error) {
      profileStatusSupported = true;
      cacheProfileRow({ id: uid, status });
      return true;
    }
    const msg = String(error?.message || "").toLowerCase();
    const missingStatusColumn = msg.includes("status") && msg.includes("column");
    if (!missingStatusColumn) {
      console.warn("status save failed:", error?.message || error);
      return false;
    }
    profileStatusSupported = false;
  }

  const nextTheme = normalizeThemeSettings({
    ...(state.me?.theme_settings || {}),
    presence_status: status,
  });
  const { error: themeError } = await supabase
    .from("profiles")
    .update({ theme_settings: nextTheme })
    .eq("id", uid);
  if (themeError) {
    console.warn("status save fallback failed:", themeError?.message || themeError);
    return false;
  }

  state.me = state.me || {};
  state.me.theme_settings = nextTheme;
  cacheProfileRow({ id: uid, status, theme_settings: nextTheme });
  return true;
}

function queueMyPresenceStatusPersist(statusInput) {
  const status = normalizePresenceStatus(statusInput);
  meStatusPersistQueue = meStatusPersistQueue
    .catch(() => {})
    .then(() => persistMyPresenceStatusToAccount(status));
  return meStatusPersistQueue;
}

async function setMyPresenceStatusEverywhere(statusInput, { persistAccount = true } = {}) {
  const status = normalizePresenceStatus(statusInput);
  state.me = state.me || {};
  state.me.status = setMyStatus(status);
  if (state.user?.id) cacheProfileRow({ id: state.user.id, status });
  applyMeStatusDot(status);

  const statusSelect = document.getElementById("presenceStatus");
  if (statusSelect && statusSelect.value !== status) statusSelect.value = status;

  updatePresenceRender();
  try { await presence?.setStatus?.(status); } catch (_) {}
  if (persistAccount) void queueMyPresenceStatusPersist(status);
  return status;
}

function getMePresencePayload() {
  return {
    id: state.user?.id,
    username: state.me?.username || "user",
    display_name: state.me?.display_name || state.me?.username || "User",
    avatar_url: getCurrentMeAvatarUrl() || null,
    name_color: normalizeNameColor(state.me?.name_color),
    call_tile_color: normalizeCallTileColor(state.me?.call_tile_color),
    status: resolveMyPresenceStatus(state.me),
  };
}

function ensureMeStatusDot() {
  const meAvatar = document.getElementById("meAvatar");
  if (!meAvatar) return;

  if (!meAvatar.querySelector(".statusDot")) {
    meAvatar.insertAdjacentHTML("beforeend", `<span class="statusDot statusDot--me" data-status-dot-me="1" data-status="online"></span>`);
  }
}

function applyMeStatusDot(status) {
  const resolved = normalizePresenceStatus(status || getMyStatus());
  const dot = document.querySelector('[data-status-dot-me="1"]');
  if (dot) dot.setAttribute("data-status", resolved);

  document.querySelectorAll("[data-status-mini]").forEach((mini) => {
    mini.setAttribute("data-status-mini", resolved);
  });

  document.querySelectorAll("[data-me-popout-status-label]").forEach((el) => {
    el.textContent = getMeProfilePopoutStatusLabel(resolved);
  });

  document.querySelectorAll(".meProfilePopout__statusText[data-me-popout-act='status']").forEach((el) => {
    el.setAttribute("aria-label", `${t("settings.section.status", "Status")}: ${getMeProfilePopoutStatusLabel(resolved)}`);
  });

  const label = document.getElementById("meStatusLabel");
  if (label) {
    if (resolved === "dnd") label.textContent = "ocupado";
    else if (resolved === "idle") label.textContent = "ausente";
    else if (resolved === "invisible") label.textContent = "invisivel";
    else if (resolved === "offline") label.textContent = "offline";
    else label.textContent = "online";
  }

  const dockStatusBtn = document.getElementById("meStatusBtn");
  if (dockStatusBtn) {
    dockStatusBtn.setAttribute(
      "aria-label",
      `${t("settings.section.status", "Status")}: ${getMeProfilePopoutStatusLabel(resolved)}`
    );
  }
}

function syncProfilesFromPresenceList(list = []) {
  const rows = (list || [])
    .map((u) => {
      const id = String(u?.id || "").trim();
      if (!id) return null;
      return {
        id,
        username: u?.username || null,
        display_name: u?.display_name || null,
        avatar_url: u?.avatar_url || null,
        name_color: normalizeNameColor(u?.name_color),
        call_tile_color: normalizeCallTileColor(u?.call_tile_color),
      };
    })
    .filter(Boolean);

  if (!rows.length) return;
  cacheProfileRows(rows);

  const otherId = String(callOtherUserId || "").trim();
  if (!otherId) return;
  const hit = rows.find((x) => x.id === otherId);
  if (!hit) return;

  if (hit.display_name || hit.username) {
    callOtherLabel = hit.display_name || hit.username || callOtherLabel;
  }
  if (hit.avatar_url) callOtherAvatar = hit.avatar_url;

  state.activeDm = {
    ...(state.activeDm || {}),
    otherUserId: otherId,
    ...(hit.username ? { username: hit.username } : {}),
    ...(hit.display_name ? { displayName: hit.display_name } : {}),
    ...(hit.avatar_url ? { avatarUrl: hit.avatar_url } : {}),
    name_color: normalizeNameColor(hit.name_color),
    call_tile_color: normalizeCallTileColor(hit.call_tile_color),
  };
  applyDmTitleNameStyle();
}

function injectStatusSelectorIntoProfileOverlay() {
  const wrapId = "presenceStatusWrap";
  const slot = document.getElementById("settingsStatusSlot");
  if (!slot) return;
  if (document.getElementById(wrapId)) {
    const selExisting = document.getElementById("presenceStatus");
    if (selExisting) selExisting.value = resolveMyPresenceStatus(state.me);
    applyLanguageToStaticUi();
    return;
  }

  const html = `
    <div id="${wrapId}" class="settingsField">
      <label class="label" for="presenceStatus">${esc(t("settings.section.status", "Status"))}</label>
      <select id="presenceStatus" class="input">
        <option value="online">${esc(t("status.option.online", "Online"))}</option>
        <option value="idle">${esc(t("status.option.idle", "Away"))}</option>
        <option value="dnd">${esc(t("status.option.dnd", "Do Not Disturb"))}</option>
        <option value="invisible">${esc(t("status.option.invisible", "Invisible"))}</option>
      </select>
      <div class="settingsHint">${esc(t("settings.status.hint", "This status is saved in real time to your account."))}</div>
    </div>
  `;
  slot.insertAdjacentHTML("beforeend", html);

  const sel = document.getElementById("presenceStatus");
  if (sel) sel.value = resolveMyPresenceStatus(state.me);

  sel?.addEventListener("change", (e) => {
    const v = normalizePresenceStatus(e?.target?.value);
    void setMyPresenceStatusEverywhere(v, { persistAccount: true });
  });
  applyLanguageToStaticUi();
}

function setStatusDotsForUser(userId, status) {
  const raw = String(userId || "");
  if (!raw) return;

  let dots = [];
  try {
    const escaped = (typeof CSS !== "undefined" && typeof CSS.escape === "function")
      ? CSS.escape(raw)
      : raw.replace(/["\\]/g, "\\$&");
    dots = Array.from(document.querySelectorAll(`[data-status-dot="${escaped}"]`));
  } catch (_) {
    dots = Array.from(document.querySelectorAll("[data-status-dot]"))
      .filter((dot) => dot.getAttribute("data-status-dot") === raw);
  }

  const resolved = normalizePresenceStatus(status || "offline");
  dots.forEach((dot) => dot.setAttribute("data-status", resolved));
}

function applyPresenceStatusDots(snapshot = []) {
  Array.from(document.querySelectorAll("[data-status-dot]")).forEach((dot) => {
    dot.setAttribute("data-status", "offline");
  });

  (Array.isArray(snapshot) ? snapshot : []).forEach((entry) => {
    const uid = normId(entry?.id || entry?.user_id || "");
    if (!uid) return;
    setStatusDotsForUser(uid, normalizePresenceStatus(entry?.status || "offline"));
  });
}

function updatePresenceRender() {
  const trace = getRelationshipCurrentTrace();
  const traceLabel = relationshipTracePhaseStart(trace, "updatePresenceRender");
  try {
  const dmListEl = document.getElementById("dmList");
  const offlineListEl = document.getElementById("offlineList");
  const activeNowEl = document.getElementById("activeNow");
  const onlineCountEl = document.getElementById("onlineCount");
  const searchInputEl = document.getElementById("searchInput");
  const dmMain = document.getElementById("dmMain");
  const dmVisible = !!dmMain && dmMain.style.display !== "none";
  const activeConversationId = normId(activeDmId || state.activeDm?.conversationId || "");
  const activeCallConversationId = normId(callConversationId || "");
  const callPcActive = !!(
    callPc
    && callPc.connectionState !== "closed"
    && callPc.connectionState !== "failed"
  );
  const activeServerVoiceTransport = !!(
    activeConversationId
    && isServerVoiceTransportSessionActive(activeConversationId)
  );
  const shouldHideActiveNowInCall = !!(
    activeConversationId
    && (
      activeServerVoiceTransport
      || (
        activeCallConversationId === activeConversationId
        && (
          inCall
          || groupCallMode
          || groupDmCallLiveKitJoinInFlight
          || callPcActive
        )
      )
    )
  );
  const serverCtx = dmVisible ? getActiveServerContext() : null;

  if (serverCtx) {
    const serverName = normalizeConversationLabel(serverCtx?.name || "Server", "Server");
    setRightSidebarToServerMembers({
      active: true,
      title: `${serverName} Members`,
      count: Number(serverCtx?.memberCount || 0),
    });
    applyPresenceStatusDots(presenceList);

    ensureMeStatusDot();
    applyMeStatusDot(getMePresencePayload().status || "online");
    applyDmTitleNameStyle();
    refreshOpenUserCard();
    refreshDmProfilePanel();
    renderWidgets();
    void refreshServerConversationUi({ force: false }).catch(() => {});
    return;
  }

  setRightSidebarToServerMembers({ active: false });

  // Hide Offline section from the right panel (keep only Active Now).
  const offlineLabelEl = offlineListEl?.previousElementSibling || null;
  if (offlineLabelEl && (offlineLabelEl.classList?.contains("rightSectionLabel") || offlineLabelEl.classList?.contains("sectionTitle"))) {
    offlineLabelEl.style.display = "none";
  }
  if (offlineListEl) {
    offlineListEl.innerHTML = "";
    offlineListEl.style.display = "none";
  }

  if (!activeNowEl && !offlineListEl && !dmListEl) return;

  if (activeNowEl) {
    if (shouldHideActiveNowInCall) {
      activeNowEl.innerHTML = "";
      activeNowEl.style.display = "none";
      if (onlineCountEl) onlineCountEl.textContent = "0";
    } else {
      activeNowEl.style.display = "";
    }
  }

  renderPresenceUI({
    list: presenceList,
    me: getMePresencePayload(),
    friends: state.friends || [],
    dmListEl,
    offlineListEl: null,
    activeNowEl: shouldHideActiveNowInCall ? null : activeNowEl,
    onlineCountEl,
    searchValue: searchInputEl?.value || "",
    onUserClick: async (u) => {
      if (u?.username) await openDm(u.username);
    },
    onStatusDot: (userId, status) => {
      setStatusDotsForUser(userId, status);
    }
  });

  const usersInActiveCall = new Set();
  if (activeConversationId) {
    if (isServerVoiceConversationById(activeConversationId)) {
      getServerVoiceChannelOccupantIds(activeConversationId, {
        triggerReason: "presence_active_now_filter",
        callerFunction: "updatePresenceRender",
      }).forEach((uid) => {
        const normalized = normId(uid || "");
        if (normalized) usersInActiveCall.add(normalized);
      });
    } else if (normId(callConversationId || "") === activeConversationId) {
      getEffectiveGroupCallActiveUserIds(activeConversationId).forEach((uid) => {
        const normalized = normId(uid || "");
        if (normalized) usersInActiveCall.add(normalized);
      });
    }
  }

  // Enforce: Active Now only shows online/idle/dnd entries.
  if (activeNowEl && !shouldHideActiveNowInCall) {
    const rows = Array.from(activeNowEl.querySelectorAll(".presenceRow"));
    rows.forEach((row) => {
      const rowUserId = normId(row.getAttribute("data-presence-user") || "");
      const inActiveCall = !!(rowUserId && usersInActiveCall.has(rowUserId));
      const stateText = String(row.querySelector(".presenceState")?.textContent || "").trim().toLowerCase();
      const dotStatus = String(row.querySelector(".statusDot")?.getAttribute("data-status") || "").trim().toLowerCase();
      const isActive = dotStatus === "online" || dotStatus === "idle" || dotStatus === "dnd";
      if (inActiveCall || !isActive || stateText === "offline" || stateText === "invisible") {
        row.remove();
      }
    });

    const activeRows = activeNowEl.querySelectorAll(".presenceRow").length;
    if (!activeRows) activeNowEl.innerHTML = `<div class="hint">NinguÃ©m online agora.</div>`;
    if (onlineCountEl) onlineCountEl.textContent = String(activeRows);
  }

  ensureMeStatusDot();
  applyMeStatusDot(getMePresencePayload().status || "online");
  applyDmTitleNameStyle();
  refreshOpenUserCard();
  refreshDmProfilePanel();
  renderWidgets();
  } finally {
    relationshipTracePhaseEnd(trace, traceLabel);
  }
}

async function startPresence() {
  if (!state.user || !state.me) return;

  ensureMeStatusDot();

  presence = createPresenceSystem({
    supabase,
    getMe: () => getMePresencePayload(),
    onPresenceList: (list) => {
      presenceList = list || [];
      syncProfilesFromPresenceList(presenceList);
      updatePresenceRender();
      const hasActiveCallUi = !!(
        inCall
        || groupCallMode
        || normId(callConversationId || "")
        || (
          callPc
          && callPc.connectionState !== "closed"
          && callPc.connectionState !== "failed"
        )
      );
      if (hasActiveCallUi) refreshCallUI();
    },
    onError: (e) => console.warn("presence error", e),
  });

  presence.start();

  const searchInputEl = document.getElementById("searchInput");
  searchInputEl?.addEventListener("input", updatePresenceRender);

  document.addEventListener("visibilitychange", () => {
    if (!presence || document.visibilityState !== "visible") return;
    const persisted = resolveMyPresenceStatus(state.me);
    state.me.status = persisted;
    presence.setStatus(persisted);
    void runProfileSyncFallback();
  });

  const persisted = resolveMyPresenceStatus(state.me);
  state.me.status = persisted;
  setMyStatus(persisted);
  presence.setStatus(persisted);
}

/* ========================= INIT ========================= */
(async function init() {
  setDesktopBootOverlayVisible(!!getDesktopBridge());
  initGlobalMotionMode();
  state.user = await requireAuth("./login.html");
  if (!state.user) {
    setDesktopBootOverlayVisible(false);
    return;
  }
  if (await consumeInitialDesktopDeepLinkIfPresent()) {
    setDesktopBootOverlayVisible(false);
    return;
  }
  const bootUserId = normId(state.user?.id || "");
  if (!bootUserId) {
    try { await supabase.auth.signOut({ scope: "local" }); } catch (_) {}
    setDesktopBootOverlayVisible(false);
    window.location.replace("./login.html");
    return;
  }
  setAppLanguage(readStoredAppLanguage(), { persist: false, rerender: false, syncForm: false });
  const initialModerationState = await refreshMyModerationState({
    timeoutMs: PROFILE_BOOT_TIMEOUT_MS,
  });
  if (await enforceModerationAccessGate(initialModerationState)) {
    setDesktopBootOverlayVisible(false);
    return;
  }
  consumeDmE2eeLoginSyncNotice();
  await initRtcConfigFromDesktop();
  void refreshRtcTurnCredentials({ force: false });
  bindUiZoomWheelShortcutOnce();
  const meAvatarEl = $("meAvatar");
  try {
    bindMeProfilePopoutDockOnce();
  } catch (error) {
    console.error("me profile dock binding failed", error);
  }
  meAvatarEl?.addEventListener("contextmenu", (e) => {
    e.preventDefault();
    openMeStatusMenuAt({ x: e.clientX, y: e.clientY });
  });
  meAvatarEl?.addEventListener("keydown", (e) => {
    if (e.key === "ContextMenu" || (e.shiftKey && e.key === "F10")) {
      e.preventDefault();
      const rect = meAvatarEl.getBoundingClientRect();
      openMeStatusMenuAt({
        x: Math.round(rect.left + Math.min(rect.width, 140) * 0.74),
        y: Math.round(rect.top + Math.max(rect.height, 56) * 0.82),
      });
      return;
    }
    if (e.key !== "Enter" && e.key !== " ") return;
    e.preventDefault();
    openMeProfilePopout();
  });

  $("btnHeaderSettings")?.addEventListener("click", openProfileOverlay);
  $("btnSendRequest")?.addEventListener("click", sendFriendRequest);
  $("addUsername")?.addEventListener("input", () => {
    scheduleAddFriendProfileLookup({ immediate: false, force: false });
  });
  $("addUsername")?.addEventListener("keydown", (e) => {
    if (e.isComposing) return;
    if (e.key !== "Enter") return;
    e.preventDefault();
    void sendFriendRequest();
  });

  const initialRefreshPromise = awaitWithTimeout(
    refresh(),
    RPC_SOFT_TIMEOUT_MS + 4000,
    "initial refresh"
  ).catch((err) => {
    console.warn("initial refresh failed", err);
  });

  try {
    state.me = await awaitWithTimeout(
      getMyProfile(state.user.id),
      PROFILE_BOOT_TIMEOUT_MS,
      "getMyProfile"
    );
    state.me.name_color = normalizeNameColor(state.me.name_color);
    state.me.call_tile_color = normalizeCallTileColor(state.me.call_tile_color);
    state.me.status = resolveMyPresenceStatus(state.me);
    setMyStatus(state.me.status);
    cacheProfileRow(state.me);
    const theme = applyAppearanceSettings(loadAppearanceSettings({ force: true }));
    applyDesktopBehaviorSettingsToUi(desktopBehaviorSettingsCache);
    setAppLanguage(theme.app_language, { persist: true, rerender: false, syncForm: false });
    $("meName").textContent = state.me.display_name || state.me.username;
    applyMeHeaderNameStyle();
    $("meTag").textContent = "@" + state.me.username;
    setAvatar($("meAvatar"), getCurrentMeAvatarUrl(), state.user?.id || "");
    applyMeHeaderBannerStyle();
    applyMeStatusDot(state.me.status);
  } catch (e) {
    console.warn(e);
    const fallbackStatus = resolveMyPresenceStatus(state.me);
    state.me = {
      ...(state.me || {}),
      status: fallbackStatus,
    };
    setMyStatus(fallbackStatus);
    applyAppearanceSettings(loadAppearanceSettings());
    setAppLanguage(readStoredAppLanguage(), { persist: true, rerender: false, syncForm: false });
    $("meName").textContent = "Sem profile";
    applyMeHeaderNameStyle();
    $("meTag").textContent = bootUserId.slice(0, 8) || "uid";
    applyMeHeaderBannerStyle();
    applyMeStatusDot(fallbackStatus);
  }

  void ensureDmFeatureCaps()
    .then((caps) => {
      if (DM_PRIVATE_RUNTIME_ENABLED && caps?.e2eeMessages) return ensureDmE2eeBootstrapStarted();
      return null;
    })
    .catch((error) => {
      console.warn("dm e2ee boot preflight failed", error?.message || error);
    });

  setupTabs();
  bindMainNavigationControlsOnce();
  bindPartyPickerOnce();
  bindServerCreateModalOnce();
  bindServerChannelCreateModalOnce();
  bindServerInviteModalOnce();
  bindServerInviteDeepLinksOnce();
  bindServerSettingsModalOnce();
  bindDmGroupCreateModalOnce();
  bindDmGroupEditModalOnce();
  bindLeftSidebarResizerOnce();
  bindRightSidebarResizerOnce();
  bindRightSidebarOverlayOnce();
  wireDmComposer();
  bindGifPickerOnce();
  bindUserCardModalOnce();
  bindEmojiPickerOnce();
  setDesktopBootOverlayVisible(false);

  await initialRefreshPromise;
  await refreshMyModerationInboxEntries({ render: true });
  await refreshMyModerationState({ enforceBan: true });
  if (state.moderationState?.isBanned) {
    setDesktopBootOverlayVisible(false);
    return;
  }
  startModerationPolling();
  appBootCompleted = true;
  await consumeServerInviteFromUrlIfPresent({ showFeedback: true });
  await consumePendingExternalServerInviteCodeIfPresent({ showFeedback: true });

  startGlobalCallListener();
  startGlobalGroupDmCallStateListener();
  startGlobalDmMessageListener();
  startGlobalDmMembershipListener();
  startGlobalConversationListener();
  startGlobalServerChannelTableListener();
  startGlobalServerRoleTablesListener();
  startGlobalProfileListener();
  startGlobalFriendRequestListener();
  startGlobalMessageRequestListener();
  startGlobalModerationActionListener();
  startGlobalUserBlocksListener();
  startFriendRequestsSyncFallback();
  startProfileSyncFallback();
  startDmCollectionsSyncFallback();
  startActiveServerChannelSyncFallback();
  bindCallUIButtons();
  bindDesktopSharePickerOnce();
  bindDesktopUpdateUiOnce();
  bindDesktopCallThumbarOnce();
  refreshCallUI();

  const { oDecline } = getCallEls();
  if (oDecline) {
    oDecline.onclick = async () => {
      const ringInfo = pendingGroupRingInfo ? { ...pendingGroupRingInfo } : null;
      showOverlay(false);
      pendingOffer = null;
      pendingCallInfo = null;
      pendingGroupRingInfo = null;
      pendingGroupRingAutoJoin = null;
      clearTimers();
      stopSfx("incoming");
      if (ringInfo?.fromUserId && ringInfo?.conversationId) {
        await declineGroupDmCallSession(ringInfo.conversationId, "declined");
        await sendCallSignal("ice", {
          signal: "group_ring_decline",
          group_call: true,
          reason: "declined",
        }, ringInfo.fromUserId, ringInfo.conversationId);
      }
    };
  }

  await startPresence();
  window.setTimeout(() => {
    void syncWidgetTodoFromCloud({ force: false }).catch(() => false);
    try { startWidgetReminderMonitor(); } catch (_) {}
  }, 900);
  void maybeShowDesktopInstallWelcome();

  window.openDm = openDm;
  window.showDm = showDm;
  window.startDmWith = startDmWith;
  window.setTenorApiKey = setTenorApiKey;
  window.getTenorApiKey = getTenorApiKey;
})().catch((err) => {
  console.error("app init failed", err);
  setDesktopBootOverlayVisible(false);
});
